   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Created by GitHub Copilot in SSMS - review carefully before executing
CREATE   PROCEDURE [dbo].[usp_sy_InsertResponse]  
    @SurveyJson NVARCHAR(MAX),  
    @UserId BIGINT = 0,  
    @FormId BIGINT = 0,  
    @FormSharedet_Id BIGINT = 0,  
    @EntityId BIGINT = 0,  
    @EntityName NVARCHAR(MAX) = '',  
    @EntityType NVARCHAR(20) = '',  
    @RespondedURL NVARCHAR(MAX) = ''  
AS  
BEGIN  
  --declare   @SurveyJson NVARCHAR(MAX) =  N'{"question2_country":"+91","question1":"Testuserrtyyenquiry05012026dd","question2":"8907761050"}',
 
  --  @UserId BIGINT = 0,  
  --  @FormId BIGINT = 10239,  
  --  @FormSharedet_Id BIGINT= 0,  
  --  @EntityId BIGINT = 0,  
  --  @EntityName NVARCHAR(MAX) = N'',  
  --  @EntityType NVARCHAR(20) = N'',  
  --  @RespondedURL NVARCHAR(MAX) = N'https://localhost:44353/UserCRMCampaign/DynamicForms/fillsurvey.aspx?formid=U2FsdGVkX19'
    SET NOCOUNT ON;  

    DECLARE @Result NVARCHAR(MAX);  
    DECLARE @MoreSettings NVARCHAR(MAX);  
    DECLARE @MappingType NVARCHAR(100);  
    DECLARE @ParentID BIGINT = NULL;  
    DECLARE @CreatedBy NVARCHAR(50) = '';  
    DECLARE @custom CUSTOMENQUIRY;  

    BEGIN TRY  
        DECLARE @SharedResponseJson NVARCHAR(MAX);  

        IF (@FormSharedet_Id <> 0)  
        BEGIN  
            SELECT @SharedResponseJson = ContentJson  
            FROM dbo.tbl_sy_FormMaster  
            WHERE Form_Id = @FormId;  

            INSERT INTO dbo.tbl_sy_FormShareDetails(Form_Id, SharedContentJson, Entity_Id, EntityType, EntityName, SharedURL, CreatedBy)  
            VALUES(@FormId, @SharedResponseJson, @EntityId, @EntityType, @EntityName, '', @UserId);  

            SET @FormSharedet_Id = SCOPE_IDENTITY();  
        END  
        ELSE  
        BEGIN  
            SELECT @FormId = Form_id,  
                   @EntityName = EntityName,  
                   @EntityId = [Entity_Id]  
            FROM dbo.tbl_sy_FormShareDetails  
            WHERE FormSharedet_Id = @FormSharedet_Id;  
        END  

        SELECT @MoreSettings = MoreSettings, @ParentID = CreatedBy  
        FROM dbo.tbl_sy_FormMaster  
        WHERE Form_Id = @FormId;  

        IF (ISNULL(@MoreSettings, '') != '')  
        BEGIN  
            SELECT @MappingType = JSON_VALUE(@MoreSettings, '$.MappingType');  
            SET @MappingType = 'Enquiry'  
            IF (@MappingType = 'Enquiry')  
            BEGIN  
                DECLARE @PersonName NVARCHAR(100)=NULL,@PersonImage NVARCHAR(200)='',  
                        @CompanyName NVARCHAR(100)=NULL,@MobileNo NVARCHAR(100)=NULL,@MobileNo1 NVARCHAR(100)=NULL,@MobileNo2 NVARCHAR(100)=NULL,  
                        @EmailID NVARCHAR(100)=NULL,@EmailID1 NVARCHAR(100)=NULL,@EmailID2 NVARCHAR(100)=NULL,  
                        @City NVARCHAR(50)=NULL,@State NVARCHAR(50)=NULL,@Country NVARCHAR(50)=NULL,@CountryCode NVARCHAR(50)=NULL,  
                        @CountryCode1 NVARCHAR(50)=NULL,@CountryCode2 NVARCHAR(50)=NULL,@ResidentialAddress NVARCHAR(500)=NULL,  
                        @OfficeAddress NVARCHAR(500)=NULL,@PinCode BIGINT=NULL,@SourceName NVARCHAR(MAX)='',  
                        @MediumName NVARCHAR(MAX)='',@CampaignName NVARCHAR(MAX)='',@InitialRemarks NVARCHAR(1000)=NULL;  

                IF OBJECT_ID('tempdb..#ResponseData') IS NOT NULL DROP TABLE #ResponseData;  
                IF OBJECT_ID('tempdb..#CustomFieldsData') IS NOT NULL DROP TABLE #CustomFieldsData;  
                IF OBJECT_ID('tempdb..#SettingData') IS NOT NULL DROP TABLE #SettingData;  

              CREATE TABLE #ResponseData
(
    [key] NVARCHAR(500),
    [value] NVARCHAR(MAX),
    [type] INT
);

INSERT INTO #ResponseData
(
    [key],
    [value],
    [type]
)
SELECT
    [key],
    CASE
        WHEN [type] IN (4,5)
            THEN JSON_QUERY([value])
        ELSE CAST([value] AS NVARCHAR(MAX))
    END,
    [type]
FROM OPENJSON(@SurveyJson);


                CREATE TABLE #CustomFieldsData  
                (  
                    EntityField NVARCHAR(100),  
                    FormField NVARCHAR(100),  
                    Status NVARCHAR(100),  
                    Label NVARCHAR(255)  
                );  

                CREATE TABLE #SettingData  
                (  
                    EntityField NVARCHAR(100),  
                    FormField NVARCHAR(100),  
                    Status NVARCHAR(100)  
                );  

                INSERT INTO #CustomFieldsData (EntityField, FormField, Status, Label)  
                SELECT EntityField, FormField, Status, NULL  
                FROM OPENJSON(@MoreSettings, '$.CustomFields')  
                WITH (  
                    EntityField NVARCHAR(100) '$.EntityField',  
                    FormField NVARCHAR(100) '$.FormField',  
                    Status NVARCHAR(100) '$.Status'  
                );  

                INSERT INTO #SettingData (EntityField, FormField, Status)  
                SELECT EntityField, FormField, Status  
                FROM OPENJSON(@MoreSettings, '$.MandatoryFields')  
                WITH (  
                    EntityField NVARCHAR(100) '$.EntityField',  
                    FormField NVARCHAR(100) '$.FormField',  
                    Status NVARCHAR(100) '$.Status'  
                );  

                IF NOT EXISTS (SELECT 1 FROM #CustomFieldsData)  
                BEGIN  
                    INSERT INTO #CustomFieldsData (EntityField, FormField, Status, Label)  
                    SELECT ISNULL(entityField,''), ISNULL(formField,''), ISNULL([status],''), ISNULL(label,'')  
                    FROM OPENJSON(@MoreSettings, '$.custom')  
                    WITH (  
                        entityField NVARCHAR(100) '$.entityField',  
                        formField NVARCHAR(100) '$.formField',  
                        [status] NVARCHAR(100) '$.status',  
                        label NVARCHAR(255) '$.label'  
                    );  
                END  

                IF NOT EXISTS (SELECT 1 FROM #SettingData)  
                BEGIN  
                    INSERT INTO #SettingData (EntityField, FormField, Status)  
                    SELECT  
                        CASE WHEN ISNULL(entityField,'') <> '' THEN entityField  
                             WHEN LOWER(ISNULL(label,'')) LIKE '%email%' THEN 'EmailID'  
                             WHEN LOWER(ISNULL(label,'')) LIKE '%mobile%' THEN 'MobileNo'  
                             WHEN LOWER(ISNULL(label,'')) LIKE '%company%' OR LOWER(ISNULL(label,'')) LIKE '%companyname%' OR LOWER(ISNULL(label,'')) LIKE '%company name%' THEN 'CompanyName'  
                             WHEN LOWER(ISNULL(label,'')) LIKE '%first name%'  
                                  OR LOWER(ISNULL(label,'')) LIKE '%firstname%'  
                                  OR LOWER(ISNULL(label,'')) LIKE '%person name%'  
                                  OR LOWER(ISNULL(label,'')) LIKE '%name%' THEN 'PersonName'
                             ELSE '' END,  
                        ISNULL(formField,''), ISNULL(CASE WHEN locked IS NOT NULL THEN CAST(locked AS NVARCHAR(10)) WHEN [status] IS NOT NULL THEN [status] ELSE '' END,'')  
                    FROM OPENJSON(@MoreSettings, '$.preMapped')  
                    WITH (  
                        label NVARCHAR(255) '$.label',  
                        formField NVARCHAR(100) '$.formField',  
                        locked NVARCHAR(10) '$.locked',  
                        entityField NVARCHAR(100) '$.entityField',  
                        [status] NVARCHAR(100) '$.status'  
                    )  
                    WHERE ISNULL(formField,'') <> '';  

                    INSERT INTO #SettingData (EntityField, FormField, Status)  
                    SELECT  
                        CASE WHEN ISNULL(entityField,'') <> '' THEN entityField  
                             WHEN LOWER(ISNULL(label,'')) LIKE '%email%' THEN 'EmailID'  
                             WHEN LOWER(ISNULL(label,'')) LIKE '%mobile%' THEN 'MobileNo'  
                             WHEN LOWER(ISNULL(label,'')) LIKE '%company%' OR LOWER(ISNULL(label,'')) LIKE '%companyname%' OR LOWER(ISNULL(label,'')) LIKE '%company name%' THEN 'CompanyName'  
                             WHEN LOWER(ISNULL(label,'')) LIKE '%first name%'  
                                  OR LOWER(ISNULL(label,'')) LIKE '%firstname%'  
                                  OR LOWER(ISNULL(label,'')) LIKE '%person name%'  
                                  OR LOWER(ISNULL(label,'')) LIKE '%name%' THEN 'PersonName'
                             ELSE '' END,  
                        ISNULL(formField,''), ISNULL(CASE WHEN locked IS NOT NULL THEN CAST(locked AS NVARCHAR(10)) WHEN [status] IS NOT NULL THEN [status] ELSE '' END,'')  
                    FROM OPENJSON(@MoreSettings, '$.standard')  
                    WITH (  
                        label NVARCHAR(255) '$.label',  
                        formField NVARCHAR(100) '$.formField',  
                        locked NVARCHAR(10) '$.locked',  
                        entityField NVARCHAR(100) '$.entityField',  
                        [status] NVARCHAR(100) '$.status'  
                    )  
                    WHERE ISNULL(formField,'') <> '';  
                END  

                -- Build custom fields table-valued param  
          INSERT INTO @custom
(
    fieldID,
    fieldvalue
)
SELECT
(
    SELECT TOP 1 field_ID
    FROM dbo.customfields
    WHERE ParentID = @ParentID
    AND fieldname = TRIM(REPLACE(s.EntityField,'Aa',''))
    AND isActive = 1
),
CASE
    WHEN r.[type] IN (4,5)
        THEN JSON_QUERY(r.[value])
    ELSE CAST(r.[value] AS NVARCHAR(MAX))
END
FROM #ResponseData r
INNER JOIN #CustomFieldsData s
ON r.[key] COLLATE SQL_Latin1_General_CP1_CI_AS =
   s.FormField COLLATE SQL_Latin1_General_CP1_CI_AS
WHERE ISNULL(s.EntityField,'') <> '';

                -- Map fields
                DECLARE @PersonNameFormField NVARCHAR(100), @CompanyNameFormField NVARCHAR(100), @EmailIDFormField NVARCHAR(100);
                DECLARE @MobileNoFormField NVARCHAR(100), @MobileNo1FormField NVARCHAR(100), @MobileNo2FormField NVARCHAR(100);
                DECLARE @CountryCodeFormField NVARCHAR(100), @CountryCode1FormField NVARCHAR(100), @CountryCode2FormField NVARCHAR(100);

                -- Get preMapped and standard mobile fields (case-insensitive status check)
                SELECT @MobileNoFormField = FormField FROM #SettingData WHERE EntityField = 'MobileNo' AND LOWER(Status) = 'true';
                SELECT TOP 1 @MobileNo1FormField = FormField FROM #SettingData WHERE EntityField = 'MobileNo' AND (LOWER(Status) <> 'true' OR ISNULL(Status,'' ) = '') AND ISNULL(FormField,'') <> @MobileNoFormField;
                SELECT TOP 1 @MobileNo2FormField = FormField FROM #SettingData WHERE EntityField = 'MobileNo' AND (LOWER(Status) <> 'true' OR ISNULL(Status,'' ) = '') AND ISNULL(FormField,'') NOT IN (@MobileNoFormField, @MobileNo1FormField);

                -- Pair country codes with mobile fields
                SET @CountryCodeFormField = @MobileNoFormField + '_country';
                SET @CountryCode1FormField = @MobileNo1FormField + '_country';
                SET @CountryCode2FormField = @MobileNo2FormField + '_country';

                SELECT @PersonNameFormField = FormField FROM #SettingData WHERE EntityField = 'PersonName';
                SELECT @CompanyNameFormField = FormField FROM #SettingData WHERE EntityField = 'CompanyName';
                SELECT @EmailIDFormField = FormField FROM #SettingData WHERE EntityField = 'EmailID';

                -- Assign values from response
                IF ISNULL(@PersonNameFormField, '') <> ''
                    SELECT TOP 1 @PersonName = [value] FROM #ResponseData WHERE [key] = @PersonNameFormField;

                IF ISNULL(@CompanyNameFormField, '') <> ''
                    SELECT TOP 1 @CompanyName = [value] FROM #ResponseData WHERE [key] = @CompanyNameFormField;

                IF ISNULL(@MobileNoFormField, '') <> ''
                    SELECT TOP 1 @MobileNo = [value] FROM #ResponseData WHERE [key] = @MobileNoFormField;
                IF ISNULL(@CountryCodeFormField, '') <> ''
                    SELECT TOP 1 @CountryCode = [value] FROM #ResponseData WHERE [key] = @CountryCodeFormField;

                IF ISNULL(@MobileNo1FormField, '') <> ''
                    SELECT TOP 1 @MobileNo1 = [value] FROM #ResponseData WHERE [key] = @MobileNo1FormField;
                IF ISNULL(@CountryCode1FormField, '') <> ''
                    SELECT TOP 1 @CountryCode1 = [value] FROM #ResponseData WHERE [key] = @CountryCode1FormField;

                IF ISNULL(@MobileNo2FormField, '') <> ''
                    SELECT TOP 1 @MobileNo2 = [value] FROM #ResponseData WHERE [key] = @MobileNo2FormField;
                IF ISNULL(@CountryCode2FormField, '') <> ''
                    SELECT TOP 1 @CountryCode2 = [value] FROM #ResponseData WHERE [key] = @CountryCode2FormField;

                IF ISNULL(@EmailIDFormField, '') <> ''
                    SELECT TOP 1 @EmailID = [value] FROM #ResponseData WHERE [key] = @EmailIDFormField;

                -- Fallback logic for EmailID and MobileNo if not found by mapping
                IF ISNULL(@EmailID, '') = ''
                BEGIN
                    SELECT TOP 1 @EmailID = [value]
                    FROM #ResponseData
                    WHERE [value] LIKE '%@%.__%' OR [value] LIKE '%@%'
                    ORDER BY CASE WHEN [value] LIKE '%@%.__%' THEN 0 ELSE 1 END;
                END

                IF ISNULL(@MobileNo, '') = ''
                BEGIN
                    SELECT TOP 1 @MobileNo = [value]
                    FROM #ResponseData
                    WHERE [value] NOT LIKE '%[^0-9]%' AND LEN([value]) BETWEEN 7 AND 15;
                END

                -- Trim extracted values
                SET @PersonName = LTRIM(RTRIM(ISNULL(@PersonName,'')));
                SET @EmailID = LTRIM(RTRIM(ISNULL(@EmailID,'')));
                SET @MobileNo = LTRIM(RTRIM(ISNULL(@MobileNo,'')));
                SET @MobileNo1 = LTRIM(RTRIM(ISNULL(@MobileNo1,'')));
                SET @MobileNo2 = LTRIM(RTRIM(ISNULL(@MobileNo2,'')));

                -- Fallback for PersonName: try key containing 'name', then longest alpha-containing value
                IF ISNULL(@PersonName,'') = ''
                BEGIN
                    SELECT TOP 1 @PersonName = [value]
                    FROM #ResponseData
                    WHERE LOWER([key]) LIKE '%name%' AND LEN([value]) > 1
                    ORDER BY LEN([value]) DESC;

                    IF ISNULL(@PersonName,'') = ''
                    BEGIN
                        SELECT TOP 1 @PersonName = [value]
                        FROM #ResponseData
                        WHERE [value] NOT LIKE '%@%' -- not an email
                          AND [value] LIKE '%[A-Za-z]%' -- contains letter
                          AND [value] LIKE '%[^0-9]%' -- not purely numeric
                          AND LEN([value]) > 1
                        ORDER BY LEN([value]) DESC;
                    END
                END

                -- Require PersonName and at least one contact (Email or any Mobile)
                IF ISNULL(@PersonName,'') = '' OR (ISNULL(@EmailID,'') = '' AND ISNULL(@MobileNo,'') = '' AND ISNULL(@MobileNo1,'') = '' AND ISNULL(@MobileNo2,'') = '')  
                BEGIN  
                    SET @Result = 'Fail: Missing required fields - PersonName and at least one of EmailID or MobileNo required';  
                    SELECT @Result AS Result;  
                    RETURN;  
                END  

                DECLARE @Enquiry TABLE (Enquiryid BIGINT);  
                SET @SourceName  =  'DynamicWebForm'  
                DECLARE @SourceID bigint = 0

                IF(NOT EXISTS (SELECT 1 FROM dbo.usersourceSettings WITH(NOLOCK) WHERE Name = @SourceName AND userID = @ParentID ))
                BEGIN
                    INSERT INTO dbo.UserSourceSettings
                    (
                        Name
                        ,UserID
                        ,IsEditable
                        ,IsActive
                        ,CreatedDate
                        ,ModifiedDate
                        ,ModifiedBy
                    )
                    SELECT @SourceName , @ParentID ,1,1,GETDATE(),GETDATE(),@ParentID
                    SELECT  @SourceID = SCOPE_IDENTITY()   
                END
                ELSE
                BEGIN
                    SELECT TOP 1 @SourceID = SourceID FROM dbo.usersourceSettings WITH(NOLOCK) WHERE Name = @SourceName AND userID = @ParentID
                END        

                -- Insert Enquiry
                INSERT INTO @Enquiry  
                EXEC @EntityId = usp_mk_InsertUserEnquiryDetails   
                    @PersonName=@PersonName,@PersonImage=@PersonImage,@CompanyName=@CompanyName,
                    @MobileNo=@MobileNo,@MobileNo1=@MobileNo1,@MobileNo2=@MobileNo2,  
                    @EmailID=@EmailID,@EmailID1=@EmailID1,@EmailID2=@EmailID2,@City=@City,@State=@State,@Country=@Country,
                    @CountryCode = @CountryCode,  
                    @CountryCode1=@CountryCode1,@CountryCode2=@CountryCode2,@ResidentialAddress=@ResidentialAddress,@OfficeAddress=@OfficeAddress,  
                    @PinCode=@PinCode,@SourceName=@SourceID,@MediumName=@MediumName,@CampaignName=@CampaignName,@InitialRemarks=@InitialRemarks,  
                    @ParentID=@ParentID,@CreatedBy=@ParentID,@custom=@custom;  

                SELECT @EntityId = Enquiryid FROM @Enquiry;  
            END  
        END  

        -- Save form response  
        INSERT INTO dbo.tbl_sy_FormResponseDetails (Form_Id, Entity_Id, FormResponseJson, FormSharedet_Id, RespondedURL)  
        VALUES (@FormId, @EntityId, @SurveyJson, @FormSharedet_Id, @RespondedURL);  

        SET @Result = 'Inserted';  

        -- Log activity  
        DECLARE @EventName NVARCHAR(255) = 'Form response created';  
        DECLARE @EventTemplate NVARCHAR(MAX) = CONCAT('Form response created by ', @EntityName);                

        EXEC dbo.UspSaveEntityActivity_withid 'user', @FormSharedet_Id, @EntityId, @EntityId, @EventTemplate, @EventName, 'dbo.tbl_sy_FormMaster', @FormSharedet_Id;  

    END TRY  
    BEGIN CATCH  
        EXEC dbo.usp_InsertErrorInfo;  
        SET @Result = 'Fail: ' + ERROR_MESSAGE();  
    END CATCH  

    SELECT @Result AS Result;  
END  


GO

/* ============================================================
   Procedure: [dbo].[usp_sy_InsertSharedDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_sy_InsertSharedDetails]
    @FormTitle NVARCHAR(200),
    @UserId BIGINT,
    @FormId BIGINT,
    @Entity_Id BIGINT,
    @EntityType VARCHAR(20),
    @EntityName VARCHAR(500)
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @Result NVARCHAR(500);
    DECLARE @InsertedId BIGINT;

    BEGIN TRY
        DECLARE @SharedContentJson NVARCHAR(MAX);

        SELECT @SharedContentJson = ContentJson 
        FROM tbl_sy_FormMaster 
        WHERE Form_Id = @FormId;

        -- Insert data and capture inserted id
        INSERT INTO tbl_sy_FormShareDetails
            (Form_Id, SharedContentJson, CreatedBy, [Entity_Id], EntityType, EntityName)
        VALUES
            (@FormId, @SharedContentJson, @UserId, @Entity_Id, @EntityType, @EntityName);

        -- Get the ID of the inserted row
        SET @InsertedId = SCOPE_IDENTITY();

        -- Return success with inserted id
        SELECT 'Success' AS Result, @InsertedId AS InsertedId;

        --Activity Entry
        DECLARE @EventName NVARCHAR(255) = 'Form shared';
        DECLARE @EventTemplate NVARCHAR(MAX) = CONCAT('Form shared to  ', @EntityName, ' by ', @UserId);
              
        exec UspSaveEntityActivity_withid 'user', @InsertedId, @UserId, @UserId, @EventTemplate, @EventName, 'tbl_sy_FormMaster', @InsertedId;
    END TRY
    BEGIN CATCH
        EXEC usp_InsertErrorInfo
        -- Return fail with error message
        SELECT 'Fail: ' + ERROR_MESSAGE() AS Result, NULL AS InsertedId;
    END CATCH
END



