/* ============================================================
   Procedure: [dbo].[usp_sy_UpdateFormMoreSettings]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_sy_UpdateFormMoreSettings]

    @UserId BIGINT,
    @FormId BIGINT = 0,
    @MoreSettings NVARCHAR(MAX)

AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @Result NVARCHAR(200);
    DECLARE @NewMoreSettings NVARCHAR(MAX);

    BEGIN TRY

      
        IF @MoreSettings IS NULL OR LTRIM(RTRIM(@MoreSettings)) = ''
        BEGIN
            UPDATE dbo.tbl_sy_FormMaster
            SET
                MoreSettings = @MoreSettings,
                ModifiedBy = @UserId,
                ModifiedOn = GETDATE()
            WHERE Form_Id = @FormId;

            SET @Result = 'Updated';
        END
        ELSE
        BEGIN
           
            DECLARE @pre TABLE (
                idx INT IDENTITY(1,1),
                label NVARCHAR(400),
                formField NVARCHAR(400),
                locked BIT
            );

            DECLARE @std TABLE (
                idx INT IDENTITY(1,1),
                label NVARCHAR(400),
                formField NVARCHAR(400),
                locked BIT
            );

          
            INSERT INTO @pre (label, formField, locked)
            SELECT
                JSON_VALUE([value], '$.label'),
                JSON_VALUE([value], '$.formField'),
                CASE
                    WHEN COALESCE(LTRIM(RTRIM(JSON_VALUE([value], '$.formField'))), '') <> ''
                         AND (
                              LOWER(COALESCE(JSON_VALUE([value], '$.label'), '')) LIKE '%mobile%'
                              OR LOWER(COALESCE(JSON_VALUE([value], '$.label'), '')) LIKE '%email%'
                             )
                        THEN CAST(1 AS BIT)
                    WHEN JSON_VALUE([value], '$.locked') IN ('1','true','True','TRUE') THEN CAST(1 AS BIT)
                    ELSE CAST(0 AS BIT)
                END
            FROM OPENJSON(@MoreSettings, '$.preMapped');

            -- Populate standard
            INSERT INTO @std (label, formField, locked)
            SELECT
                JSON_VALUE([value], '$.label'),
                JSON_VALUE([value], '$.formField'),
                CASE
                    WHEN COALESCE(LTRIM(RTRIM(JSON_VALUE([value], '$.formField'))), '') <> ''
                         AND LOWER(COALESCE(JSON_VALUE([value], '$.label'), '')) LIKE '%name%'
                        THEN CAST(1 AS BIT)
                    WHEN JSON_VALUE([value], '$.locked') IN ('1','true','True','TRUE') THEN CAST(1 AS BIT)
                    ELSE CAST(0 AS BIT)
                END
            FROM OPENJSON(@MoreSettings, '$.standard');

          
            DECLARE @preJson NVARCHAR(MAX) = (
                SELECT label, formField, locked
                FROM @pre
                ORDER BY idx
                FOR JSON PATH
            );

            DECLARE @stdJson NVARCHAR(MAX) = (
                SELECT label, formField, locked
                FROM @std
                ORDER BY idx
                FOR JSON PATH
            );

         
            DECLARE @customJson NVARCHAR(MAX) =
                COALESCE(JSON_QUERY(@MoreSettings, '$.custom'), '[]');

   
            SET @NewMoreSettings = '{"preMapped":' + COALESCE(@preJson, '[]')
                                  + ',"standard":' + COALESCE(@stdJson, '[]')
                                  + ',"custom":' + @customJson + '}';

        
            UPDATE dbo.tbl_sy_FormMaster
            SET
                MoreSettings = @NewMoreSettings,
                ModifiedBy = @UserId,
                ModifiedOn = GETDATE()
            WHERE Form_Id = @FormId;

            SET @Result = 'Updated';
        END

    END TRY
    BEGIN CATCH
        EXEC usp_InsertErrorInfo;
        SET @Result = 'Fail: ' + ERROR_MESSAGE();
    END CATCH;

    SELECT @Result AS Result;

END;


