   Procedure: [dbo].[usp_sy_UpdateSharedURL]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_sy_UpdateSharedURL]
    @FormUrl NVARCHAR(MAX),
    @UserId bigint,
    --@FormId bigint,
    @FormShareDet_Id bigint
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @Result NVARCHAR(50);

    BEGIN TRY

        -- Insert data into the tbl_sy_FormResponseDetails table
        UPDATE tbl_sy_FormShareDetails
        set SharedURL = @FormUrl
        where  FormSharedet_Id = @FormSharedet_Id and CreatedBy = @UserId;

        -- Set the result to success if the insertion is successful
        SET @Result = 'Updated';

        ----Activity Entry
        --DECLARE @EventName NVARCHAR(255) = 'Form response created';
        --DECLARE @EventTemplate NVARCHAR(MAX) = CONCAT('Form response created by ', @EntityName);              
              
        --exec UspSaveEntityActivity_withid 'user', @FormSharedet_Id, @Entity_Id, @Entity_Id, @EventTemplate, @EventName, 'tbl_sy_FormMaster', @FormSharedet_Id;
    END TRY
    BEGIN CATCH
        EXEC usp_InsertErrorInfo
        -- Set the result to fail and provide error information
        SET @Result = 'Fail: ' + ERROR_MESSAGE();
    END CATCH

    -- Return the result set
    SELECT @Result AS Result;
END;



