/* ============================================================
   Procedure: [dbo].[Usp_SyncCustomFieldLeadValueToNewTable]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_SyncCustomFieldLeadValueToNewTable  --33819 
(
  @UserID bigint   
)
as
Begin
    begin try    
 
      if(@UserID > 0)
	   Begin
	      if(exists (select 1 from User_Detail with(nolock) where User_ID = @UserID))
		   Begin
			  declare @ParentID bigint = isnull((select top 1 isnull(ParentID,0) from User_Detail with(nolock) where User_ID = @UserID),0)
			  if(@ParentID > 0)
			  begin
			     declare @Status int = 0, @TableName nvarchar(500) = ''    
			     exec @Status = [Usp_CreateTable_CustomFieldLeadValueByParentID_WhileSyncing] @ParentID, @TableName output
				 if(@Status = 1)
				     Begin
					     exec [Usp_TransferAndUpdateIntoCustomFieldLeadValueByParentID_Syncing] @ParentID
					 End
			  end
			  else
			   Begin
			     select 'ParentID Does Not Exists'  
			   end

		   End
		 else
		  begin
		    select 'UserID Does Not Exists'  
		 end
	   end     
      else
	    Begin
	      select ''
	    End 

      end try
	  begin catch
	     exec usp_InsertErrorInfo
	  end catch
	    

End


