CREATE   PROCEDURE [dbo].[Usp_SyncMobileOfflineData]  
(  
    @jsonData NVARCHAR(MAX),  
    @CreatedBy BIGINT,  
    @ParentId BIGINT,  
    @Execute BIT = 1  -- 0 = print debug only, 1 = execute  
)  
AS  
BEGIN  
/*declare  
@jsonData NVARCHAR(MAX)='
      "data": [
            {
                "details": {
                    "EnquiryId": 0,
