    SET NOCOUNT on;  
    BEGIN TRY  
        PRINT '--- Start SyncMobileOfflineData ---';  
  
        -- Ensure incoming JSON is a valid JSON object. If caller passed only '"data": [...]' or an array,  
        -- wrap it in braces to become a JSON object: { "data": [...] }  
        IF @jsonData IS NULL SET @jsonData = '{}';  
        IF LTRIM(@jsonData) NOT LIKE '{%' SET @jsonData = '{' + @jsonData + '}';  
  
        -- Temporary raw table: one row per item in $.data  
        IF OBJECT_ID('tempdb..#RawData') IS NOT NULL DROP TABLE #RawData;  
        CREATE TABLE #RawData (  
            [idx] INT IDENTITY(1,1) PRIMARY KEY,  
            [value] NVARCHAR(MAX),  
            EntityId NVARCHAR(100) NULL,  
            EntityType NVARCHAR(100) NULL,  
            PageCode NVARCHAR(100) NULL,  
            CreatedTimeStamp NVARCHAR(100) NULL,  
            UpdatedTimeStamp NVARCHAR(100) NULL,  
            ActionType NVARCHAR(100) NULL  
        );  
  
        INSERT INTO #RawData ([value], EntityId, EntityType, PageCode, CreatedTimeStamp, UpdatedTimeStamp, ActionType)  
        SELECT  
            [value],  
            JSON_VALUE([value], '$.EntityId'),  
            JSON_VALUE([value], '$.EntityType'),  
            JSON_VALUE([value], '$.PageCode'),  
            JSON_VALUE([value], '$.CreatedTimeStamp'),  
            JSON_VALUE([value], '$.UpdatedTimeStamp'),  
            JSON_VALUE([value], '$.ActionType')  
        FROM OPENJSON(@jsonData, '$.data');  
  
        DECLARE @cnt INT;  
        SELECT @cnt = COUNT(1) FROM #RawData;  
        PRINT 'Parsed JSON into #RawData. Total rows = ' + CONVERT(NVARCHAR(20), @cnt);  
  
        -- Note: This procedure expects the following user-defined table types and other procs to exist:  
        -- dbo.PermissionStageType, dbo.OfflineEnquiryType, dbo.OfflineCustFieldsType, dbo.customEnquiry2,  
        -- dbo.OfflineLeadType, dbo.OfflineCustFieldsType (or equivalents), dbo.OfflineLeadFollowupType,  
        -- dbo.OfflineTaskType, and stored procedures used later (Usp_InsertOfflineEnquiryDetails, etc.).  
  
        -- ============================  
        -- ENQUIRY (PAG10002 or EntityType = 'Enquiry')  
        -- ============================  
        IF EXISTS (SELECT 1 FROM #RawData WHERE PageCode = 'PAG10002' OR EntityType = 'Enquiry')  
        BEGIN  
            PRINT '--- Start Enquiry Processing ---';  
            DECLARE @PermissionStage AS dbo.PermissionStageType;  
          
		  if(@ParentId = @CreatedBy)
		  begin
		  INSERT INTO @PermissionStage
		
            EXEC usp_UA_GetAllPermissionByModuleCodeUserId 'S', 'PAG10002', @CreatedBy;  
          end
		  else
		   begin

		   INSERT INTO @PermissionStage(
			 UserId
			,TeamCode
			,TeamName
			,RoleName
			,ParentId,	ModuleCode,	ModuleName,	ScopeCode,	RoleCode,[Add]	,Edit,	[View],	[Delete],	Search,	Import,	Export,	MassUpdate,	MassDelete,	Standard1
			,	Standard2,	Standard3,	Standard4,	Standard5,	Download,	[Print],	AddTask,	AddAppointment,	AddFollowup,
			AddNote,	SendSms	,SendMail,	Special1,	Special2,	Special3,	Special4,	Special5,	SendVoice,	
			MergeLead,	SendWhatsapp,	UploadDocument,	DeleteDocument,	AddDeal,	AddTax,	AddQuotation,
			AddInvoice,	AddWebform,	AddCustomField,	MassAssign,	MassSMS	,MassEmail,	MassBroadcast,	[Type],
			EntityActionMappingCode,	EntitySpActionMappingCode,	EntitySpAction2MappingCode,	[URL]) 
            EXEC usp_UA_GetAllPermissionByModuleCodeUserId 'S', 'PAG10002', @CreatedBy; 


		   end


		  print 'E' 
            DECLARE @EnquiryMain_Insert dbo.OfflineEnquiryType;  
           print 'F'
		   DECLARE @EnquiryCustom_Insert dbo.OfflineCustFieldsType;  
           
		   print 'g'
		   
             INSERT INTO @EnquiryMain_Insert(EntityId,EntityType,EnquiryId,PersonName,PersonImage,CompanyName,  
            WhereLatitude,WhereLongitude,MobileNo,MobileNo1,MobileNo2,EmailId,EmailId1,EmailId2,  
            CountryCode,CountryCode1,CountryCode2,SourceName,Medium,Campaign,InitialRemarks,  
            CountryName,[State],City,Pincode,WhereAddress,ResidentialAddress,OfficeAddress,PageCode,  
            CreatedTimeStamp,UpdatedTimeStamp,ActionType,EnquiryTags,ParentID,Owner,CreatedBy)  
            SELECT TRY_CAST(rd.EntityId AS BIGINT),  
                rd.EntityType,  
                TRY_CAST(JSON_VALUE(rd.[value], '$.details.EnquiryId') AS BIGINT),  
                JSON_VALUE(rd.[value], '$.details.PersonName'),  
                JSON_VALUE(rd.[value], '$.details.PersonImage'),  
                JSON_VALUE(rd.[value], '$.details.CompanyName'),  
                JSON_VALUE(rd.[value], '$.details.WhereLatitude'),  
                JSON_VALUE(rd.[value], '$.details.WhereLongitude'),  
                RIGHT(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(JSON_VALUE(rd.[value], '$.details.MobileNo1'), '+', ''), '-', ''), '(', ''), ')', ''), ' ', ''),10),  
                RIGHT(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(JSON_VALUE(rd.[value], '$.details.MobileNo2'), '+', ''), '-', ''), '(', ''), ')', ''), ' ', ''),10),  
                RIGHT(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(JSON_VALUE(rd.[value], '$.details.MobileNo3'), '+', ''), '-', ''), '(', ''), ')', ''), ' ', ''),10),  
                JSON_VALUE(rd.[value], '$.details.EmailId1'),  
                JSON_VALUE(rd.[value], '$.details.EmailId2'),  
                JSON_VALUE(rd.[value], '$.details.EmailId3'),  
                LEFT(JSON_VALUE(rd.[value], '$.details.MobileNo1'), CHARINDEX(' ', JSON_VALUE(rd.[value], '$.details.MobileNo1') + ' ') - 1),  
                LEFT(JSON_VALUE(rd.[value], '$.details.MobileNo2'), CHARINDEX(' ', JSON_VALUE(rd.[value], '$.details.MobileNo2') + ' ') - 1),  
                LEFT(JSON_VALUE(rd.[value], '$.details.MobileNo3'), CHARINDEX(' ', JSON_VALUE(rd.[value], '$.details.MobileNo3') + ' ') - 1),  
                JSON_VALUE(rd.[value], '$.details.SourceName'),  
                JSON_VALUE(rd.[value], '$.details.Medium'),  
                JSON_VALUE(rd.[value], '$.details.Campaign'),  
                JSON_VALUE(rd.[value], '$.details.InitialRemarks'),  
                JSON_VALUE(rd.[value], '$.details.CountryName'),  
                JSON_VALUE(rd.[value], '$.details.State'),  
                JSON_VALUE(rd.[value], '$.details.City'),  
                JSON_VALUE(rd.[value], '$.details.Pincode'),  
                JSON_VALUE(rd.[value], '$.details.WhereAddress'),  
                JSON_VALUE(rd.[value], '$.details.ResidentialAddress'),  
                JSON_VALUE(rd.[value], '$.details.OfficeAddress'),  
                rd.PageCode,  
                rd.CreatedTimeStamp,  
                rd.UpdatedTimeStamp,  
                rd.ActionType,  
                NULLIF(JSON_VALUE(rd.[value], '$.details.EnquiryTags'), ''),  
                @ParentId,  
                @ParentId,
				@CreatedBy
            FROM #RawData rd  
            WHERE (PageCode = 'PAG10002' OR EntityType = 'Enquiry') AND rd.ActionType LIKE '%Insert';  
  
            INSERT INTO @EnquiryCustom_Insert(FieldId, FieldValue, mobileno, emailid)  
            SELECT  
                TRY_CAST(JSON_VALUE(cf.[value], '$.FieldId') AS INT),  
                JSON_VALUE(cf.[value], '$.FieldValue'),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.MobileNo1'), ''),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.EmailId1'), '')  
            FROM #RawData rd  
            CROSS APPLY OPENJSON(rd.[value], '$.details.lstCustomField') cf  
            WHERE (rd.PageCode = 'PAG10002' OR rd.EntityType = 'Enquiry') AND rd.ActionType LIKE '%Insert';  
  
            DECLARE @EnquiryMain_Update dbo.OfflineEnquiryType;  
            DECLARE @EnquiryCustom_Update dbo.customEnquiry2;  
            
			
            INSERT INTO @EnquiryMain_Update(EntityId,EntityType,EnquiryId,PersonName,PersonImage,  
            CompanyName,WhereLatitude,WhereLongitude,MobileNo,MobileNo1,MobileNo2,EmailId,EmailId1,  
            EmailId2,CountryCode,CountryCode1,CountryCode2,SourceName,Medium,Campaign,InitialRemarks,  
            CountryName,[State],City,Pincode,WhereAddress,ResidentialAddress,OfficeAddress,PageCode,  
            CreatedTimeStamp,UpdatedTimeStamp,ActionType,EnquiryTags,ParentID,Owner)  
            
			
			SELECT TRY_CAST(rd.EntityId AS BIGINT),  
                rd.EntityType,  
                TRY_CAST(JSON_VALUE(rd.[value], '$.details.EnquiryId') AS BIGINT),  
                JSON_VALUE(rd.[value], '$.details.PersonName'),  
                JSON_VALUE(rd.[value], '$.details.PersonImage'),  
                JSON_VALUE(rd.[value], '$.details.CompanyName'),  
                JSON_VALUE(rd.[value], '$.details.WhereLatitude'),  
                JSON_VALUE(rd.[value], '$.details.WhereLongitude'),  
                RIGHT(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(JSON_VALUE(rd.[value], '$.details.MobileNo1'), '+', ''), '-', ''), '(', ''), ')', ''), ' ', ''),10),  
                RIGHT(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(JSON_VALUE(rd.[value], '$.details.MobileNo2'), '+', ''), '-', ''), '(', ''), ')', ''), ' ', ''),10),  
                RIGHT(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(JSON_VALUE(rd.[value], '$.details.MobileNo3'), '+', ''), '-', ''), '(', ''), ')', ''), ' ', ''),10),  
                JSON_VALUE(rd.[value], '$.details.EmailId1'),  
                JSON_VALUE(rd.[value], '$.details.EmailId2'),  
                JSON_VALUE(rd.[value], '$.details.EmailId3'),  
                LEFT(JSON_VALUE(rd.[value], '$.details.MobileNo1'), CHARINDEX(' ', JSON_VALUE(rd.[value], '$.details.MobileNo1') + ' ') - 1),  
                LEFT(JSON_VALUE(rd.[value], '$.details.MobileNo2'), CHARINDEX(' ', JSON_VALUE(rd.[value], '$.details.MobileNo2') + ' ') - 1),  
                LEFT(JSON_VALUE(rd.[value], '$.details.MobileNo3'), CHARINDEX(' ', JSON_VALUE(rd.[value], '$.details.MobileNo3') + ' ') - 1),  
                JSON_VALUE(rd.[value], '$.details.SourceName'),  
                JSON_VALUE(rd.[value], '$.details.Medium'),  
                JSON_VALUE(rd.[value], '$.details.Campaign'),  
                JSON_VALUE(rd.[value], '$.details.InitialRemarks'),  
                JSON_VALUE(rd.[value], '$.details.CountryName'),  
                JSON_VALUE(rd.[value], '$.details.State'),  
                JSON_VALUE(rd.[value], '$.details.City'),  
                JSON_VALUE(rd.[value], '$.details.Pincode'),  
                JSON_VALUE(rd.[value], '$.details.WhereAddress'),  
                JSON_VALUE(rd.[value], '$.details.ResidentialAddress'),  
                JSON_VALUE(rd.[value], '$.details.OfficeAddress'),  
                rd.PageCode,  
                rd.CreatedTimeStamp,  
                rd.UpdatedTimeStamp,  
                rd.ActionType,  
                NULLIF(JSON_VALUE(rd.[value], '$.details.EnquiryTags'), ''),  
                @ParentId,  
                @ParentId  
            FROM #RawData rd  
            WHERE (PageCode = 'PAG10002' OR rd.EntityType = 'Enquiry') AND rd.ActionType LIKE '%Update';  
  
            INSERT INTO @EnquiryCustom_Update(EnquiryID, FieldId, FieldValue)  
            SELECT  
                TRY_CAST(JSON_VALUE(cf.[value], '$.EnquiryId') AS INT),  
                TRY_CAST(JSON_VALUE(cf.[value], '$.FieldId') AS INT),  
                JSON_VALUE(cf.[value], '$.FieldValue')  
            FROM #RawData rd  
            CROSS APPLY OPENJSON(rd.[value], '$.details.lstCustomField') cf  
            WHERE (rd.PageCode = 'PAG10002' OR rd.EntityType = 'Enquiry') AND rd.ActionType LIKE '%Update';  
  
            IF EXISTS (SELECT 1 FROM @EnquiryMain_Insert)  
            BEGIN  
                IF EXISTS (SELECT 1 FROM @PermissionStage WHERE [Add] = 1)  
                BEGIN  
                    PRINT 'Permission Check Passed: Enquiry Add';  
                    IF @Execute = 1  
                    BEGIN  
                        EXEC Usp_InsertOfflineEnquiryDetails @EnquiryMain_Insert, @EnquiryCustom_Insert;  
                    END  
                    ELSE  
                    BEGIN  
                        PRINT 'Skipped actual Enquiry Insert because @Execute = 0';  
                    END  
                END  
                ELSE  
                    PRINT 'Permission Denied: Enquiry Add';  
            END  
  
            IF EXISTS (SELECT 1 FROM @EnquiryMain_Update)  
            BEGIN  
                IF EXISTS (SELECT 1 FROM @PermissionStage WHERE [Edit] = 1)  
                BEGIN  
                    PRINT 'Permission Check Passed: Enquiry Edit';  
                    IF @Execute = 1  
                    BEGIN  
                        EXEC Usp_UpdateOfflineEnquiryDetails @EnquiryMain_Update, @EnquiryCustom_Update;  
                    END  
                    ELSE  
                    BEGIN  
                        PRINT 'Skipped actual Enquiry Update because @Execute = 0';  
                    END  
                END  
                ELSE  
                    PRINT 'Permission Denied: Enquiry Edit';  
            END  
        END  
  
        -- (Lead, Followup, Task, Appointment logic remains unchanged except removed stray DROP TABLE calls)  
  
        -- ============================  
        -- LEAD (PAG10031 or EntityType = 'Lead')  
        -- ============================  
                IF EXISTS (SELECT 1 FROM #RawData WHERE PageCode = 'PAG10031' OR EntityType = 'Lead')  
        BEGIN  
            --INSERT INTO @PermissionStage  
           -- exec usp_UA_GetAllPermissionByModuleCodeUserId 'S', 'PAG10031', @CreatedBy;  
  
             if(@ParentId = @CreatedBy)
		  begin
		  INSERT INTO @PermissionStage
		
            EXEC usp_UA_GetAllPermissionByModuleCodeUserId 'S', 'PAG10031', @CreatedBy;  
          end
		  else
		   begin

		   INSERT INTO @PermissionStage(
			 UserId
			,TeamCode
			,TeamName
			,RoleName
			,ParentId,	ModuleCode,	ModuleName,	ScopeCode,	RoleCode,[Add]	,Edit,	[View],	[Delete],	Search,	Import,	Export,	MassUpdate,	MassDelete,	Standard1
			,	Standard2,	Standard3,	Standard4,	Standard5,	Download,	[Print],	AddTask,	AddAppointment,	AddFollowup,
			AddNote,	SendSms	,SendMail,	Special1,	Special2,	Special3,	Special4,	Special5,	SendVoice,	
			MergeLead,	SendWhatsapp,	UploadDocument,	DeleteDocument,	AddDeal,	AddTax,	AddQuotation,
			AddInvoice,	AddWebform,	AddCustomField,	MassAssign,	MassSMS	,MassEmail,	MassBroadcast,	[Type],
			EntityActionMappingCode,	EntitySpActionMappingCode,	EntitySpAction2MappingCode,	[URL]) 
            EXEC usp_UA_GetAllPermissionByModuleCodeUserId 'S', 'PAG10031', @CreatedBy; 


		   end   


            DECLARE @LeadMain_Insert dbo.OfflineLeadType;  
            DECLARE @LeadCustomFields_Insert dbo.OfflineCustFieldsType;  
  
            INSERT INTO @LeadMain_Insert  
            (  
                LeadId, PersonName, PersonImage, WhereLatitude, WhereLongitude, ParentID,  
                MobileNo, MobileNo1, MobileNo2,   
                EmailID, EmailID1, EmailID2,   
                CountryCode, CountryCode1, CountryCode2,   
                SourceName, MediumName, CampaignName, Remarks, CompanyName,   
                Country, State, City, Pincode,  
                ResidentialAddress, OfficialAddress, AssignedTo,   
                LeadTags, IsReassign, Products, AmountPaid, FollowUpRemarks, FollowUpStatus  
            )      
            SELECT  
                NULLIF(JSON_VALUE(rd.[value], '$.details.LeadId'), ''),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.PersonName'), ''),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.PersonImage'), ''),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.WhereLatitude'), ''),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.WhereLongitude'), ''),  
                @ParentId,  
  
                -- Mobile numbers cleaned to 10 digits each  
                RIGHT(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(JSON_VALUE(rd.[value], '$.details.MobileNo1'), '+', ''), '-', ''), '(', ''), ')', ''), ' ', ''),10),  
                RIGHT(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(JSON_VALUE(rd.[value], '$.details.MobileNo2'), '+', ''), '-', ''), '(', ''), ')', ''), ' ', ''),10),  
                RIGHT(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(JSON_VALUE(rd.[value], '$.details.MobileNo3'), '+', ''), '-', ''), '(', ''), ')', ''), ' ', ''),10),  
  
                -- Emails  
                NULLIF(JSON_VALUE(rd.[value], '$.details.EmailId1'), ''),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.EmailId2'), ''),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.EmailId3'), ''),  
  
                -- Country Codes extracted from mobiles  
                NULLIF(LEFT(JSON_VALUE(rd.[value], '$.details.MobileNo1'),  
                CHARINDEX(' ', JSON_VALUE(rd.[value], '$.details.MobileNo1') + ' ') - 1), ''),  
                NULLIF(LEFT(JSON_VALUE(rd.[value], '$.details.MobileNo2'),  
                CHARINDEX(' ', JSON_VALUE(rd.[value], '$.details.MobileNo2') + ' ') - 1), ''),  
                NULLIF(LEFT(JSON_VALUE(rd.[value], '$.details.MobileNo3'),  
                CHARINDEX(' ', JSON_VALUE(rd.[value], '$.details.MobileNo3') + ' ') - 1), ''),  
  
                -- Source / Campaign  
                NULLIF(JSON_VALUE(rd.[value], '$.details.SourceName'), ''),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.Medium'), ''),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.Campaign'), ''),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.InitialRemarks'), ''),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.CompanyName'), ''),  
  
                -- Location  
                NULLIF(JSON_VALUE(rd.[value], '$.details.CountryName'), ''),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.State'), ''),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.City'), ''),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.Pincode'), ''),  
  
                -- Addresses  
                NULLIF(JSON_VALUE(rd.[value], '$.details.ResidentialAddress'), ''),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.OfficeAddress'), ''),  
  
           CASE   
    WHEN NULLIF(JSON_VALUE(rd.[value], '$.details.AssignedTo'), '') IS NULL   
         OR JSON_VALUE(rd.[value], '$.details.AssignedTo') = '0'  
    THEN @CreatedBy  
    ELSE JSON_VALUE(rd.[value], '$.details.AssignedTo')  
END AS AssignedTo,  
  
                ---- Tags  
                NULLIF(JSON_VALUE(rd.[value], '$.details.LeadTags'), ''),  
  
                ---- FollowUp nested fields  
                TRY_CAST(NULLIF(JSON_VALUE(rd.[value], '$.details.followUp.IsReAssign'), '') AS BIT),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.followUp.Products'), ''),  
                TRY_CAST(NULLIF(JSON_VALUE(rd.[value], '$.details.followUp.AmountPaid'), '') AS NUMERIC(18,2)),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.followUp.Remarks'), ''),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.followUp.FollowUpStatus'), '')  
            FROM #RawData rd  
            WHERE (rd.PageCode = 'PAG10031' OR rd.EntityType = 'Lead') AND rd.ActionType LIKE '%Insert';  
  
            INSERT INTO @LeadCustomFields_Insert (FieldId, FieldValue, MobileNo, EmailId)  
            SELECT  
                TRY_CAST(JSON_VALUE(cf.[value], '$.FieldId') AS INT),  
                JSON_VALUE(cf.[value], '$.FieldValue'),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.MobileNo1'), ''), -- primary mobile  
                NULLIF(JSON_VALUE(rd.[value], '$.details.EmailId1'), '')   -- primary email  
            FROM #RawData rd  
            CROSS APPLY OPENJSON(rd.[value], '$.details.lstCustomField') AS cf  
            WHERE (rd.PageCode = 'PAG10031' OR rd.EntityType = 'Lead') AND rd.ActionType LIKE '%Insert';  
  
            SELECT * FROM @LeadMain_Insert;  
            SELECT * FROM @LeadCustomFields_Insert;  
  
            DECLARE @LeadMain_Update dbo.OfflineLeadType;  
            DECLARE @LeadCustomFields_Update dbo.CustomLeads3;  
  
            INSERT INTO @LeadMain_Update  
            (  
                LeadId, PersonName, PersonImage, WhereLatitude, WhereLongitude, ParentID,  
                MobileNo, MobileNo1, MobileNo2,   
                EmailID, EmailID1, EmailID2,   
                CountryCode, CountryCode1, CountryCode2,   
                SourceName, MediumName, CampaignName, Remarks, CompanyName,   
                Country, State, City, Pincode,  
                ResidentialAddress, OfficialAddress, AssignedTo,   
                LeadTags, IsReassign, Products, AmountPaid, FollowUpRemarks, FollowUpStatus  
            )      
            SELECT  
                NULLIF(JSON_VALUE(rd.[value], '$.details.LeadId'), ''),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.PersonName'), ''),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.PersonImage'), ''),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.WhereLatitude'), ''),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.WhereLongitude'), ''),  
                @ParentId,  
  
                -- Mobile numbers cleaned to 10 digits each  
                RIGHT(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(JSON_VALUE(rd.[value], '$.details.MobileNo1'), '+', ''), '-', ''), '(', ''), ')', ''), ' ', ''),10),  
                RIGHT(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(JSON_VALUE(rd.[value], '$.details.MobileNo2'), '+', ''), '-', ''), '(', ''), ')', ''), ' ', ''),10),  
                RIGHT(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(JSON_VALUE(rd.[value], '$.details.MobileNo3'), '+', ''), '-', ''), '(', ''), ')', ''), ' ', ''),10),  
  
                -- Emails  
                NULLIF(JSON_VALUE(rd.[value], '$.details.EmailId1'), ''),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.EmailId2'), ''),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.EmailId3'), ''),  
  
                -- Country Codes extracted from mobiles  
                NULLIF(LEFT(JSON_VALUE(rd.[value], '$.details.MobileNo1'),  
                CHARINDEX(' ', JSON_VALUE(rd.[value], '$.details.MobileNo1') + ' ') - 1), ''),  
                NULLIF(LEFT(JSON_VALUE(rd.[value], '$.details.MobileNo2'),  
                CHARINDEX(' ', JSON_VALUE(rd.[value], '$.details.MobileNo2') + ' ') - 1), ''),  
                NULLIF(LEFT(JSON_VALUE(rd.[value], '$.details.MobileNo3'),  
                CHARINDEX(' ', JSON_VALUE(rd.[value], '$.details.MobileNo3') + ' ') - 1), ''),  
  
                -- Source / Campaign  
                NULLIF(JSON_VALUE(rd.[value], '$.details.SourceName'), ''),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.Medium'), ''),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.Campaign'), ''),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.InitialRemarks'), ''),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.CompanyName'), ''),  
  
                -- Location  
                NULLIF(JSON_VALUE(rd.[value], '$.details.CountryName'), ''),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.State'), ''),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.City'), ''),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.Pincode'), ''),  
  
                -- Addresses  
                NULLIF(JSON_VALUE(rd.[value], '$.details.ResidentialAddress'), ''),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.OfficeAddress'), ''),  
  
                -- Assignment  
                NULLIF(JSON_VALUE(rd.[value], '$.details.AssignedTo'), ''),  
  
                ---- Tags  
                NULLIF(JSON_VALUE(rd.[value], '$.details.LeadTags'), ''),  
  
                ---- FollowUp nested fields  
                TRY_CAST(NULLIF(JSON_VALUE(rd.[value], '$.details.followUp.IsReAssign'), '') AS BIT),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.followUp.Products'), ''),  
                TRY_CAST(NULLIF(JSON_VALUE(rd.[value], '$.details.followUp.AmountPaid'), '') AS NUMERIC(18,2)),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.followUp.Remarks'), ''),  
                NULLIF(JSON_VALUE(rd.[value], '$.details.followUp.FollowUpStatus'), '')  
            FROM #RawData rd  
            WHERE (rd.PageCode = 'PAG10031' OR rd.EntityType = 'Lead') AND rd.ActionType LIKE '%Update';  
  
            INSERT INTO @LeadCustomFields_Update(LeadId,FieldId, FieldValue)  
            SELECT  
                TRY_CAST(JSON_VALUE(cf.[value], '$.LeadId') AS INT),  
                TRY_CAST(JSON_VALUE(cf.[value], '$.FieldId') AS INT),  
                JSON_VALUE(cf.[value], '$.FieldValue')  
            FROM #RawData rd  
            CROSS APPLY OPENJSON(rd.[value], '$.details.lstCustomField') AS cf  
            WHERE (rd.PageCode = 'PAG10031' OR rd.EntityType = 'Lead') AND rd.ActionType LIKE '%Update';  
  
            -----------------------------------------------------------------  
            -- Permission Check before calling Insert / Update  
            -----------------------------------------------------------------  
            IF EXISTS (SELECT 1 FROM @LeadMain_Insert)  
            BEGIN  
                IF EXISTS (SELECT 1 FROM @PermissionStage WHERE [Add] = 1)  
                BEGIN  
                    PRINT 'Permission Check Passed: Lead Add';  
                    IF @Execute = 1  
                    BEGIN  
                        EXEC Usp_InsertOfflineLeadDetails @LeadMain_Insert, @LeadCustomFields_Insert;  
                    END  
                END  
                ELSE  
                    PRINT 'Permission Denied: Lead Add';  
            END  
  
            IF EXISTS (SELECT 1 FROM @LeadMain_Update)  
            BEGIN  
                IF EXISTS (SELECT 1 FROM @PermissionStage WHERE [Edit] = 1)  
                BEGIN  
                    PRINT 'Permission Check Passed: Lead Edit';  
                    IF @Execute = 1  
                    BEGIN  
                        -- show the rows being updated (debug)  
                        SELECT * FROM @LeadMain_Update;  
                        EXEC Usp_UpdateOfflineLeadDetails @LeadMain_Update, @LeadCustomFields_Update;  
                    END  
                END  
                ELSE  
                    PRINT 'Permission Denied: Lead Edit';  
            END  
        END  
        -- ============================  
        -- FOLLOWUP (PAG10039 or EntityType = 'Followup')  
        -- ============================  
  
          IF EXISTS (SELECT 1 FROM #RawData WHERE PageCode = 'PAG10039' OR EntityType = 'Followup')  
   BEGIN  
  
      -- INSERT INTO @PermissionStage  
      -- exec usp_UA_GetAllPermissionByModuleCodeUserId 'S', 'PAG10039', @CreatedBy;  
  
     
             if(@ParentId = @CreatedBy)
		  begin
		  INSERT INTO @PermissionStage
		
            EXEC usp_UA_GetAllPermissionByModuleCodeUserId 'S', 'PAG10039', @CreatedBy;  
          end
		  else
		   begin

		   INSERT INTO @PermissionStage(
			 UserId
			,TeamCode
			,TeamName
			,RoleName
			,ParentId,	ModuleCode,	ModuleName,	ScopeCode,	RoleCode,[Add]	,Edit,	[View],	[Delete],	Search,	Import,	Export,	MassUpdate,	MassDelete,	Standard1
			,	Standard2,	Standard3,	Standard4,	Standard5,	Download,	[Print],	AddTask,	AddAppointment,	AddFollowup,
			AddNote,	SendSms	,SendMail,	Special1,	Special2,	Special3,	Special4,	Special5,	SendVoice,	
			MergeLead,	SendWhatsapp,	UploadDocument,	DeleteDocument,	AddDeal,	AddTax,	AddQuotation,
			AddInvoice,	AddWebform,	AddCustomField,	MassAssign,	MassSMS	,MassEmail,	MassBroadcast,	[Type],
			EntityActionMappingCode,	EntitySpActionMappingCode,	EntitySpAction2MappingCode,	[URL]) 
            EXEC usp_UA_GetAllPermissionByModuleCodeUserId 'S', 'PAG10039', @CreatedBy; 


		   end 


       DECLARE @FollowupMain_Insert dbo.OfflineLeadFollowupType;  
    
       INSERT INTO @FollowupMain_Insert  
      (LeadId, AssignedTo, FollowUpStatus, NextStatusDate, Products, AmountPaid, Remarks,   
       UserId, IsReassign, ParentId, NotifyBySMS, NotifyByEmail, SmsScheduelDateTime, EmailScheduelDateTime)  
       SELECT  
           TRY_CAST(JSON_VALUE(rd.[value], '$.details.LeadId') AS INT),  
           TRY_CAST(JSON_VALUE(rd.[value], '$.details.AssignedTo') AS INT),  
           -- FupValue can be comma-separated (e.g. '7,1,0'); extract first part and cast to INT  
           TRY_CAST(  
               CASE WHEN CHARINDEX(',', JSON_VALUE(rd.[value], '$.details.FupValue')) > 0  
                    THEN LEFT(JSON_VALUE(rd.[value], '$.details.FupValue'), CHARINDEX(',', JSON_VALUE(rd.[value], '$.details.FupValue')) - 1)  
                    ELSE JSON_VALUE(rd.[value], '$.details.FupValue')  
               END AS INT  
           ),  
           -- keep date/time as string if your TVP expects NVARCHAR; if it expects DATETIME use TRY_CAST(... AS DATETIME)  
           NULLIF(JSON_VALUE(rd.[value], '$.details.NextStatusDate'), '') ,  
           NULLIF(JSON_VALUE(rd.[value], '$.details.Products'), ''),  
           TRY_CAST(NULLIF(JSON_VALUE(rd.[value], '$.details.AmountPaid'), '') AS DECIMAL(18,2)),  
           NULLIF(JSON_VALUE(rd.[value], '$.details.Remarks'), ''),  
           @CreatedBy,  
           TRY_CAST(NULLIF(JSON_VALUE(rd.[value], '$.details.IsReAssign'), '') AS BIT),  
           @ParentId,  
           TRY_CAST(NULLIF(JSON_VALUE(rd.[value], '$.details.NotifyBySMS'), '') AS BIT),  
           TRY_CAST(NULLIF(JSON_VALUE(rd.[value], '$.details.NotifyByEmail'), '') AS BIT),  
           NULLIF(JSON_VALUE(rd.[value], '$.details.SmsScheduelDateTime'), ''),  
           NULLIF(JSON_VALUE(rd.[value], '$.details.EmailScheduelDateTime'), '')  
       FROM #RawData rd  
       WHERE (rd.PageCode = 'PAG10039' OR rd.EntityType = 'Followup') AND rd.ActionType LIKE '%Insert';  
  
       IF EXISTS (SELECT 1 FROM @FollowupMain_Insert)  
       BEGIN  
           IF EXISTS (SELECT 1 FROM @PermissionStage WHERE [Add] = 1)  
           BEGIN  
             PRINT 'Permission Check Passed: Followup Add';  
               EXEC Usp_InsertOfflineLeadFollowupDetails @FollowupMain_Insert;  
           END  
           ELSE  
               PRINT 'Permission Denied: Followup Add';  
       END  
  
       print 'End Followup from main SP';  
   END  
  
        -- ======================================  
        -- TASK (PAG10034 or EntityType = 'Task')  
        -- ======================================  
        IF EXISTS (SELECT 1 FROM #RawData WHERE PageCode = 'PAG10034' OR EntityType = 'Task')  
        BEGIN  
            PRINT 'task'  
         --   INSERT INTO @PermissionStage  
         --   exec usp_UA_GetAllPermissionByModuleCodeUserId 'S', 'PAG10034', @CreatedBy;  
          
             if(@ParentId = @CreatedBy)
		  begin
		  INSERT INTO @PermissionStage
		
            EXEC usp_UA_GetAllPermissionByModuleCodeUserId 'S', 'PAG10034', @CreatedBy;  
          end
		  else
		   begin

		   INSERT INTO @PermissionStage(
			 UserId
			,TeamCode
			,TeamName
			,RoleName
			,ParentId,	ModuleCode,	ModuleName,	ScopeCode,	RoleCode,[Add]	,Edit,	[View],	[Delete],	Search,	Import,	Export,	MassUpdate,	MassDelete,	Standard1
			,	Standard2,	Standard3,	Standard4,	Standard5,	Download,	[Print],	AddTask,	AddAppointment,	AddFollowup,
			AddNote,	SendSms	,SendMail,	Special1,	Special2,	Special3,	Special4,	Special5,	SendVoice,	
			MergeLead,	SendWhatsapp,	UploadDocument,	DeleteDocument,	AddDeal,	AddTax,	AddQuotation,
			AddInvoice,	AddWebform,	AddCustomField,	MassAssign,	MassSMS	,MassEmail,	MassBroadcast,	[Type],
			EntityActionMappingCode,	EntitySpActionMappingCode,	EntitySpAction2MappingCode,	[URL]) 
            EXEC usp_UA_GetAllPermissionByModuleCodeUserId 'S', 'PAG10034', @CreatedBy; 


		   end 


            DECLARE @TaskMain_Insert dbo.OfflineTaskType;  
            DECLARE @TaskMain_Update dbo.OfflineTaskType;  
  
            INSERT INTO @TaskMain_Insert(Id,Title,Description,TaskId,LeadId,StartDate,EndDate,IsTask,IsAppointment,  
            IsCompleted,AssignedTo,CreatedBy,CollabratoerUserIds,NotifyMe,IsEmail,IsSMS,SmsSchedule,EmailSchedule,  
            AppVersion, CreatedTimeStamp, UpdatedTimeStamp,IsActive)  
            SELECT  
                JSON_VALUE(rd.[value], '$.details.Id'),  
                JSON_VALUE(rd.[value], '$.details.Title'),  
                JSON_VALUE(rd.[value], '$.details.Description'),  
                JSON_VALUE(rd.[value], '$.details.TaskId'),  
                JSON_VALUE(rd.[value], '$.details.LeadId'),  
                JSON_VALUE(rd.[value], '$.details.StartDate'),  
                JSON_VALUE(rd.[value], '$.details.EndDate'),  
                JSON_VALUE(rd.[value], '$.details.IsTask'),  
                JSON_VALUE(rd.[value], '$.details.IsAppointment'),  
                JSON_VALUE(rd.[value], '$.details.IsCompleted'),  
                JSON_VALUE(rd.[value], '$.details.AssignedTo'),  
                @CreatedBy,  
                JSON_VALUE(rd.[value], '$.details.CollaboratorUserIds'),  
                JSON_VALUE(rd.[value], '$.details.NotifyMe'),  
                JSON_VALUE(rd.[value], '$.details.IsEmail'),  
                JSON_VALUE(rd.[value], '$.details.IsSMS'),  
                JSON_VALUE(rd.[value], '$.details.SmsSchedule'),  
                JSON_VALUE(rd.[value], '$.details.EmailSchedule'),  
                JSON_VALUE(rd.[value], '$.details.AppVersion'),  
                rd.CreatedTimeStamp,  
                rd.UpdatedTimeStamp,  
    1  
            FROM #RawData rd  
            WHERE (rd.PageCode = 'PAG10034' OR rd.EntityType = 'Task') AND rd.ActionType LIKE '%Insert';  
  
            INSERT INTO @TaskMain_Update(Id,Title,Description,TaskId,LeadId,StartDate,EndDate,IsTask,IsAppointment,  
            IsCompleted,AssignedTo,CreatedBy,CollabratoerUserIds,NotifyMe,IsEmail,IsSMS,SmsSchedule,EmailSchedule,  
            AppVersion, CreatedTimeStamp, UpdatedTimeStamp,IsActive)  
            SELECT  
                JSON_VALUE(rd.[value], '$.details.Id'),  
                JSON_VALUE(rd.[value], '$.details.Title'),  
                JSON_VALUE(rd.[value], '$.details.Description'),  
                JSON_VALUE(rd.[value], '$.details.TaskId'),  
                JSON_VALUE(rd.[value], '$.details.LeadId'),  
                JSON_VALUE(rd.[value], '$.details.StartDate'),  
                JSON_VALUE(rd.[value], '$.details.EndDate'),  
                JSON_VALUE(rd.[value], '$.details.IsTask'),  
                JSON_VALUE(rd.[value], '$.details.IsAppointment'),  
                JSON_VALUE(rd.[value], '$.details.IsCompleted'),  
                JSON_VALUE(rd.[value], '$.details.AssignedTo'),  
                @CreatedBy,  
                JSON_VALUE(rd.[value], '$.details.CollaboratorUserIds'),  
                JSON_VALUE(rd.[value], '$.details.NotifyMe'),  
                JSON_VALUE(rd.[value], '$.details.IsEmail'),  
                JSON_VALUE(rd.[value], '$.details.IsSMS'),  
                JSON_VALUE(rd.[value], '$.details.SmsSchedule'),  
                JSON_VALUE(rd.[value], '$.details.EmailSchedule'),  
              JSON_VALUE(rd.[value], '$.details.AppVersion'),  
                rd.CreatedTimeStamp,  
                rd.UpdatedTimeStamp,  
    1  
            FROM #RawData rd  
            WHERE (rd.PageCode = 'PAG10034' OR rd.EntityType = 'Task') AND rd.ActionType LIKE '%Update';  
  
             IF EXISTS (SELECT 1 FROM @TaskMain_Insert)  
            BEGIN  
                IF EXISTS (SELECT 1 FROM @PermissionStage WHERE [Add] = 1)  
                BEGIN  
                    PRINT 'Permission Check Passed: Task Add';  
           
                    exec Usp_InsertOfflineTaskOrAppointmentDetails @TaskMain_Insert;  
  
  
  
                END  
                ELSE  
                    PRINT 'Permission Denied: Task Add';  
            END  
  
            IF EXISTS (SELECT 1 FROM @TaskMain_Update)  
            BEGIN  
                IF EXISTS (SELECT 1 FROM @PermissionStage WHERE [Edit] = 1)  
                BEGIN  
                    PRINT 'Permission Check Passed: Task Edit';  
                    EXEC Usp_UpdateOfflineTaskOrAppointmentDetails @TaskMain_Update;  
                END  
                ELSE  
                    PRINT 'Permission Denied: Task Edit';  
            END  
        END  
  
        -- ====================================================  
        -- APPOINTMENT (PAG10035 or EntityType = 'Appointment')  
        -- ====================================================  
        IF EXISTS (SELECT 1 FROM #RawData WHERE PageCode = 'PAG10035' OR EntityType = 'Appointment')  
        BEGIN  
            PRINT 'app'  
            --INSERT INTO @PermissionStage  
            --exec usp_UA_GetAllPermissionByModuleCodeUserId 'S', 'PAG10035', @CreatedBy;  
			
             if(@ParentId = @CreatedBy)
		  begin
		  INSERT INTO @PermissionStage
		
            EXEC usp_UA_GetAllPermissionByModuleCodeUserId 'S', 'PAG10035', @CreatedBy;  
          end
		  else
		   begin

		   INSERT INTO @PermissionStage(
			 UserId
			,TeamCode
			,TeamName
			,RoleName
			,ParentId,	ModuleCode,	ModuleName,	ScopeCode,	RoleCode,[Add]	,Edit,	[View],	[Delete],	Search,	Import,	Export,	MassUpdate,	MassDelete,	Standard1
			,	Standard2,	Standard3,	Standard4,	Standard5,	Download,	[Print],	AddTask,	AddAppointment,	AddFollowup,
			AddNote,	SendSms	,SendMail,	Special1,	Special2,	Special3,	Special4,	Special5,	SendVoice,	
			MergeLead,	SendWhatsapp,	UploadDocument,	DeleteDocument,	AddDeal,	AddTax,	AddQuotation,
			AddInvoice,	AddWebform,	AddCustomField,	MassAssign,	MassSMS	,MassEmail,	MassBroadcast,	[Type],
			EntityActionMappingCode,	EntitySpActionMappingCode,	EntitySpAction2MappingCode,	[URL]) 
            EXEC usp_UA_GetAllPermissionByModuleCodeUserId 'S', 'PAG10035', @CreatedBy; 


		   end 

  
            DECLARE @AppointmentMain_Insert dbo.OfflineTaskType;  
            DECLARE @AppointmentMain_Update dbo.OfflineTaskType;  
  
            INSERT INTO @AppointmentMain_Insert(Id,Title,Description,TaskId,LeadId,StartDate,EndDate,IsTask,IsAppointment,  
            IsCompleted,AssignedTo,CreatedBy,CollabratoerUserIds,NotifyMe,IsEmail,IsSMS,SmsSchedule,EmailSchedule,  
            AppVersion, CreatedTimeStamp, UpdatedTimeStamp,IsActive)  
            SELECT  
                JSON_VALUE(rd.[value], '$.details.Id'),  
                JSON_VALUE(rd.[value], '$.details.Title'),  
                JSON_VALUE(rd.[value], '$.details.Description'),  
                JSON_VALUE(rd.[value], '$.details.TaskId'),  
                JSON_VALUE(rd.[value], '$.details.LeadId'),  
                JSON_VALUE(rd.[value], '$.details.StartDate'),  
                JSON_VALUE(rd.[value], '$.details.EndDate'),  
                JSON_VALUE(rd.[value], '$.details.IsTask'),  
                JSON_VALUE(rd.[value], '$.details.IsAppointment'),  
                JSON_VALUE(rd.[value], '$.details.IsCompleted'),  
                JSON_VALUE(rd.[value], '$.details.AssignedTo'),  
                @CreatedBy,  
                JSON_VALUE(rd.[value], '$.details.CollaboratorUserIds'),  
                JSON_VALUE(rd.[value], '$.details.NotifyMe'),  
                JSON_VALUE(rd.[value], '$.details.IsEmail'),  
                JSON_VALUE(rd.[value], '$.details.IsSMS'),  
                JSON_VALUE(rd.[value], '$.details.SmsSchedule'),  
                JSON_VALUE(rd.[value], '$.details.EmailSchedule'),  
                JSON_VALUE(rd.[value], '$.details.AppVersion'),  
                rd.CreatedTimeStamp,  
                rd.UpdatedTimeStamp,  
               1  
            FROM #RawData rd  
            WHERE (rd.PageCode = 'PAG10035' OR rd.EntityType = 'Appointment') AND rd.ActionType LIKE '%Insert';  
  
            INSERT INTO @AppointmentMain_Update(Id,Title,Description,TaskId,LeadId,StartDate,EndDate,IsTask,IsAppointment,  
            IsCompleted,AssignedTo,CreatedBy,CollabratoerUserIds,NotifyMe,IsEmail,IsSMS,SmsSchedule,EmailSchedule,  
            AppVersion, CreatedTimeStamp, UpdatedTimeStamp,IsActive)  
            SELECT  
                JSON_VALUE(rd.[value], '$.details.Id'),  
                JSON_VALUE(rd.[value], '$.details.Title'),  
         JSON_VALUE(rd.[value], '$.details.Description'),  
                JSON_VALUE(rd.[value], '$.details.TaskId'),  
                JSON_VALUE(rd.[value], '$.details.LeadId'),  
                JSON_VALUE(rd.[value], '$.details.StartDate'),  
                JSON_VALUE(rd.[value], '$.details.EndDate'),  
                JSON_VALUE(rd.[value], '$.details.IsTask'),  
                JSON_VALUE(rd.[value], '$.details.IsAppointment'),  
                JSON_VALUE(rd.[value], '$.details.IsCompleted'),  
                JSON_VALUE(rd.[value], '$.details.AssignedTo'),  
                @CreatedBy,  
                JSON_VALUE(rd.[value], '$.details.CollaboratorUserIds'),  
                JSON_VALUE(rd.[value], '$.details.NotifyMe'),  
                JSON_VALUE(rd.[value], '$.details.IsEmail'),  
                JSON_VALUE(rd.[value], '$.details.IsSMS'),  
                JSON_VALUE(rd.[value], '$.details.SmsSchedule'),  
                JSON_VALUE(rd.[value], '$.details.EmailSchedule'),  
                JSON_VALUE(rd.[value], '$.details.AppVersion'),  
                rd.CreatedTimeStamp,  
                rd.UpdatedTimeStamp,  
    1  
            FROM #RawData rd  
            WHERE (rd.PageCode = 'PAG10035' OR rd.EntityType = 'Appointment') AND rd.ActionType LIKE '%Update';  
  
             IF EXISTS (SELECT 1 FROM @AppointmentMain_Insert)  
            BEGIN  
                IF EXISTS (SELECT 1 FROM @PermissionStage WHERE [Add] = 1)  
                BEGIN  
                    PRINT 'Permission Check Passed: Appointment Add';  
                    exec Usp_InsertOfflineTaskOrAppointmentDetails @AppointmentMain_Insert;  
                END  
                ELSE  
                    PRINT 'Permission Denied: Appointment Add';  
            END  
  
            IF EXISTS (SELECT 1 FROM @AppointmentMain_Update)  
            BEGIN  
                IF EXISTS (SELECT 1 FROM @PermissionStage WHERE [Edit] = 1)  
                BEGIN  
                    PRINT 'Permission Check Passed: Appointment Edit';  
                    EXEC Usp_UpdateOfflineTaskOrAppointmentDetails @AppointmentMain_Update;  
                END  
                ELSE  
                    PRINT 'Permission Denied: Appointment Edit';  
            END  
        END  
  
        -- Cleanup raw  
        DROP TABLE #RawData;  
  
    END TRY  
    BEGIN CATCH  
        IF OBJECT_ID('tempdb..#RawData') IS NOT NULL DROP TABLE #RawData;  
        EXEC usp_InsertErrorInfo;  
    END CATCH  
END  



