/* ============================================================
   Procedure: [dbo].[Usp_SyncToUserSearchData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_SyncToUserSearchData --78,335      
(      
 @FilterIDPRM Bigint,      
 @CreatedByPRM bigint      
)      
as      
Begin      
      
 Declare @FilterID bigint = @FilterIDPRM ,@CreatedBy bigint = @CreatedByPRM      
 declare @LastSyncTimeVAR  varchar(50) = ''      
 select top 1 @LastSyncTimeVAR = CAST(LastSyncTime as varchar(50)) from UserMailsFilters where ID = @FilterID        
 set @LastSyncTimeVAR = ISNULL(@LastSyncTimeVAR,'')        
    
if(@LastSyncTimeVAR = '')    
 Begin    
   update UserExtractedData set Valid =  case when (dbo.fnAppMobileCheck(Column1) = 1 or dbo.fnAppEmailCheck(column2) = 1)    
                                           then 1    
                                           else 0    
                                           end        
    where FilterID = @FilterID and (select isnull(LastSyncTime,'') from UserMailsFilters where ID=@FilterID)=''       
 End    
else    
  Begin    
       update UserExtractedData set Valid =  case when (dbo.fnAppMobileCheck(Column1) = 1 or dbo.fnAppEmailCheck(column2) = 1)    
                                           then 1    
                                           else 0    
                                           end        
    where FilterID = @FilterID and CreatedOn > CONVERT(datetime,@LastSyncTimeVAR)    
  End    
      
if(@LastSyncTimeVAR = '')      
 Begin      
insert into UserSearchData (ImportedListID,ParentID,MobileNumber,EmailID,Column1,Column2,Column3,Column4,Column5,Column6,Column7,Column8,CreatedOn,CreatedBy)      
      
select UMF.MappedList,UEXD.ParentID,UEXD.Column1,UEXD.Column2,UEXD.Column3,UEXD.Column4,UEXD.Column5,UEXD.Column6,UEXD.Column7,UEXD.Column8,UEXD.Column9,UEXD.Column10,GETDATE(),@CreatedBy from UserExtractedData UEXD(nolock) inner join UserMailsFilters UMF
  
    
(nolock) on UEXD.FilterID      
 = UMF.ID        
 where UEXD.FilterID = @FilterID and isnull(UMF.LastSyncTime,'') = '' and UEXD.Valid = 1       
       
    Update UserMailsFilters set LastSyncTime = GETDATE() where ID = @FilterID      
       
    select 'Sync Completed'      
       
 End      
       
 else      
  Begin      
 insert into UserSearchData (ImportedListID,ParentID,MobileNumber,EmailID,Column1,Column2,Column3,Column4,Column5,Column6,Column7,Column8,CreatedOn,CreatedBy)      
        
  select UMF.MappedList,UEXD.ParentID,UEXD.Column1,UEXD.Column2,UEXD.Column3,UEXD.Column4,UEXD.Column5,UEXD.Column6,UEXD.Column7,UEXD.Column8,UEXD.Column9,UEXD.Column10,GETDATE(),@CreatedBy from UserExtractedData UEXD(nolock) inner join UserMailsFilters UMF(nolock) on UEXD.FilterID      
         = UMF.ID        
         where UEXD.FilterID = @FilterID and UEXD.CreatedOn > CONVERT(datetime,@LastSyncTimeVAR) and UEXD.Valid = 1       
    Update UserMailsFilters set LastSyncTime = GETDATE() where ID = @FilterID      
        
    select 'Sync Completed'      
  End      
       
 End


GO

/* ============================================================
   Procedure: [dbo].[Usp_SyncToUserSearchDataJob]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_SyncToUserSearchDataJob] --78,335      
as      
Begin      
create table #syncfilters(FiltersToBeSynced bigint,Mappedlist bigint,Lastsynctime datetime)
insert into #syncfilters
select ID,MappedList,LastSyncTime from UserMailsFilters where isnull(MappedList,0)<>0

update u set Valid =  case when (dbo.fnAppMobileCheck(isnull(Column1,'9999999999')) = 1 and dbo.fnAppEmailCheck(isnull(column2,'anyemail@anydomain.com')) = 1) then 1 else 0 end from UserExtractedData u join #syncfilters s on u.FilterID = s.FiltersToBeSynced and CreatedOn > s.Lastsynctime where Column1 is not null and Column2 is not null    

select u.* into #userextracteddata from UserExtractedData u join #syncfilters s on u.FilterID = s.FiltersToBeSynced and CreatedOn > s.Lastsynctime where u.Valid=1 

insert into UserSearchData (ImportedListID,ParentID,MobileNumber,EmailID,Column1,Column2,Column3,Column4,Column5,Column6,Column7,Column8,CreatedOn,CreatedBy)      
select UMF.MappedList,UEXD.ParentID,UEXD.Column1,UEXD.Column2,UEXD.Column3,UEXD.Column4,UEXD.Column5,UEXD.Column6,UEXD.Column7,UEXD.Column8,UEXD.Column9,UEXD.Column10,GETDATE(),ParentID from #UserExtractedData UEXD inner join #syncfilters UMF (nolock) on UEXD.FilterID = UMF.FiltersToBeSynced and UEXD.CreatedOn > umf.Lastsynctime and UEXD.Valid = 1       

Update u set LastSyncTime = GETDATE() from UserMailsFilters u join #syncfilters s on u.ID = s.FiltersToBeSynced
select 'Sync Completed' 

drop table #syncfilters
drop table #userextracteddata     
  
End


GO

/* ============================================================
   Procedure: [dbo].[usp_TableFieldsListByEntityName]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--usp_TableFieldsListByEntityName 'enquiry', 34594
--usp_TableFieldsListByEntityName 'lead', 34594
CREATE   PROCEDURE [dbo].[usp_TableFieldsListByEntityName]
@EntityType varchar(20) = 'enquiry',
@UserId bigint
AS
BEGIN

Declare @ParentId bigint 

select @ParentId = ParentId from User_Detail(nolock) where User_ID = @UserId

--Declare @EntityType varchar(20) = 'enquiry',
--@ParentId bigint = 34594
Declare @TableName varchar(50) = 'UserLeads'
if(@EntityType = 'lead')
Begin
select * from (
select Column_Name FieldName, Column_Name FieldValue, datatype, ColumnType from (
SELECT Column_Name, data_type datatype, 'B' ColumnType
FROM INFORMATION_SCHEMA.COLUMNS
WHERE TABLE_NAME = N''+ @TableName+''
)t where t.COLUMN_NAME not in ('Id','CreatedOn', 'CreatedBy', 'ModifiedOn', 'ModifiedBy', 'latitude', 'longitude', 'WhatsAppNoColName', 'LastFollowupCreatedOn','LastFollowupCreatedBy', 'ParentID','ProfileImgFileName')
Union
select FieldName FieldName, FieldName FieldValue, 
(case when datatype = 'v' then 'varchar' 
when datatype = 'd' then 'datetime' 
when datatype = 'f' then 'float'
else datatype end) datatype, 'C' ColumnType from customfields (nolock)
where ParentID = @ParentId and isActive = 1 and datatype not in ('m','r','s','c', 'l')
)tt
order by ColumnType asc
End
else if(@EntityType = 'enquiry')
Begin

set @TableName = 'UserEnquiry'
select * from (
select Column_Name FieldName, Column_Name FieldValue, datatype, ColumnType from (
SELECT Column_Name, data_type datatype, 'B' ColumnType
FROM INFORMATION_SCHEMA.COLUMNS
WHERE TABLE_NAME = N''+ @TableName+''
)t where t.COLUMN_NAME not in ('Id','CreatedOn', 'CreatedBy', 'ModifiedOn', 'ModifiedBy', 'latitude', 'longitude', 'WhatsAppNoColName', 'LastFollowupCreatedOn','LastFollowupCreatedBy')
Union
select FieldName FieldName, FieldName FieldValue, 
(case when datatype = 'v' then 'varchar' 
when datatype = 'd' then 'datetime' 
when datatype = 'f' then 'float'
else datatype end) datatype, 'C' ColumnType from customfields (nolock)
where ParentID = @ParentId and isActive = 1 and datatype not in ('m','r','s','c', 'l')
)tt
order by ColumnType asc

--(t.COLUMN_NAME != 'Id' or Column_Name != 'CreatedOn' or Column_Name != 'CreatedBy' or Column_Name != 'ModifiedOn' or Column_Name != 'ModifiedBy')
End

END



GO

/* ============================================================
   Procedure: [dbo].[usp_TawToPrechatToEnquiry]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE usp_TawToPrechatToEnquiry
@SourceCode NVARCHAR(200),        
@MediumCode BIGINT,        
@CampaignCode BIGINT,        
@ParentId BIGINT,        
@PrechatAutoId BIGINT,        
@ModifiedLead fbLeadEnquiry READONLY          
--ON tbl_fb_FacebookLeadJson          
--AFTER INSERT          
AS          
BEGIN          
 
 drop table if exists #tempMoEnquiry
 drop table if exists #customEnquiryFieldMo
 drop table if exists #tempEnquiryMainFieldMo
 drop table if exists #tempCustomEnquiryFieldMo
 drop table if exists #fbLeadDataMo
  drop table if exists #tempLeadMo
 
 declare @isleadcreated int=0         
 DECLARE @RowJson NVARCHAR(MAX),  @FbLeadgenId NVARCHAR(200), @FbFormId NVARCHAR(200), @Cnt INT  = 1, @RowCount INT, @EnquiryId BIGINT, @QUERY NVARCHAR(MAX) = '', @ParamDef NVARCHAR(500) = '', @AutoLeadDistribution BIT, @tempEnquiryId BIGINT = 1,   
 @LeadValueRow NVARCHAR(MAX), @fbFeildName NVARCHAR(200), @enquiryFeildName NVARCHAR(200), @enquiryFeildDataType NVARCHAR(200)        
          
      
 BEGIN TRY          
  -- GETTING PARENT ID AND FROM ID          
           
  select @ParentId = cd.ParentId from tbl_ttc_PrechatFormData pfd inner join tbl_ttc_ClientDetails cd on pfd.TtcClientId = cd.Id where pfd.Id = @PrechatAutoId;      
      
    SELECT @RowCount = COUNT(*) FROM @ModifiedLead          
        
   SELECT * INTO #tempEnquiryMainFieldMo FROM UserEnquiry WHERE EnquiryID < 0          
         
      
   SET IDENTITY_INSERT #tempEnquiryMainFieldMo ON          
   INSERT INTO #tempEnquiryMainFieldMo (EnquiryID, SourceName, MediumName, CampaignName, ParentID, IsOpen, IsduplicateEmail, IsduplicateMobile, enquirysource) VALUES ( @tempEnquiryId, @SourceCode, @MediumCode, @CampaignCode, @ParentId, 1, 0, 0, 38 )        
   SET IDENTITY_INSERT #tempEnquiryMainFieldMo OFF          
          
   CREATE TABLE #tempCustomEnquiryFieldMo          
   (          
    fieldID BIGINT,          
    fieldvalue SQL_VARIANT          
   )          
             
   WHILE( @Cnt <= @RowCount)          
   BEGIN          
    DECLARE @ColName NVARCHAR(500) = '',  @ColValue NVARCHAR(500) = ''          
          
    SELECT @ColName = colName, @ColValue = colValue From @ModifiedLead WHERE Id = @Cnt          
    print concat('Moblie No  supplyed',  @ColValue)    
 PRINT @ColName        
          
    SELECT @enquiryFeildDataType = DATA_TYPE FROM INFORMATION_SCHEMA.COLUMNS WHERE  TABLE_NAME = 'UserEnquiry' AND COLUMN_NAME  = @ColName           
              
    IF(COL_LENGTH('dbo.UserEnquiry', @ColName) IS NOT NULL)          
     BEGIN          
      IF(LTRIM(RTRIM(@ColName)) = 'MobileNo' OR LTRIM(RTRIM(@ColName)) = 'MobileNo1' OR LTRIM(RTRIM(@ColName)) = 'MobileNo1')          
       BEGIN          
        DECLARE @Mobile NVARCHAR(50) = @ColValue, @CountryCount INT, @Start INT = 1, @CountryCode NVARCHAR(10) = '', @MobileNo_Checked BIGINT = 0     
       
   SELECT @CountryCount = MAX(Country_ID) FROM m_country1(nolock)          
       
   WHILE(@Start< @CountryCount)          
   BEGIN          
    IF(EXISTS(SELECT * FROM m_country1(nolock) WHERE Country_ID = @Start))          
     BEGIN          
      DECLARE @PatterCountryCode NVARCHAR(10), @CountryCodeLen INT = 0;          
    SELECT @PatterCountryCode = CountryCode, @CountryCodeLen = LEN(CountryCode) FROM m_country1(nolock) WHERE Country_ID = @Start          
      IF(LTRIM(RTRIM(@PatterCountryCode)) = SUBSTRING(LTRIM(RTRIM(@Mobile)), 0, @CountryCodeLen + 1))          
      BEGIN          
     SET @CountryCode = @PatterCountryCode          
     SET @MobileNo_Checked = CAST(SUBSTRING(@Mobile, @CountryCodeLen + 1, LEN(@Mobile) + 1)   AS bigint)       
     --PRINT 'Matched'          
     BREAK          
      END          
    END          
    SET @Start = @Start + 1      
        
   IF(@MobileNo_Checked = 0)    
   BEGIN    
    SET @MobileNo_Checked = CAST(@Mobile AS bigint)    
   END    
    
    END       
         
   --PRINT CONCAT('countrycode', @CountryCode)    
    
    IF (ISNULL(@CountryCode,'') = '')       
  BEGIN       
  SET @CountryCode = (select ISNULL(CountryCode, '+91') from User_Detail(nolock) where User_ID = @ParentId )    
  END      
      
  --print @MobileNo_Checked    
    
   UPDATE #tempEnquiryMainFieldMo           
    SET CountryCode = case when @ColName = 'MobileNo' then @CountryCode else CountryCode end,           
  CountryCode1 = case when @ColName = 'MobileNo1' then @CountryCode else CountryCode1 end,           
  CountryCode2 = case when @ColName = 'MobileNo2' then @CountryCode else CountryCode2 end,           
  MobileNo = case when @ColName = 'MobileNo' then @MobileNo_Checked else MobileNo end,          
  MobileNo1 = case when @ColName = 'MobileNo1' then @MobileNo_Checked else MobileNo1 end,          
  MobileNo2 = case when @ColName = 'MobileNo2' then @MobileNo_Checked else MobileNo2 end          
   WHERE EnquiryID = @tempEnquiryId          
                
       END          
      ELSE          
       BEGIN          
        SET @QUERY = 'UPDATE #tempEnquiryMainFieldMo SET ' + @ColName +' =  '          
        SET @QUERY += CASE WHEN @enquiryFeildDataType = 'int'          
         OR @enquiryFeildDataType = 'bigint'           
         OR @enquiryFeildDataType = 'float'          
         OR @enquiryFeildDataType = 'numeric'          
         OR @enquiryFeildDataType = 'decimal'          
         OR @enquiryFeildDataType = 'money'          
          THEN @ColValue +'  WHERE EnquiryID = '+CAST(@tempEnquiryId AS NVARCHAR)          
         ELSE          
         '''' + @ColValue +'''  WHERE EnquiryID = ' + CAST(@tempEnquiryId AS NVARCHAR)          
         END           
         --print @QUERY          
         execute sp_executesql @QUERY          
       END          
     END          
    ELSE          
     BEGIN          
      DECLARE @CustomFieldId BIGINT = 0          
      SELECT @CustomFieldId = field_ID FROM customfields WHERE ParentID = @ParentId and fieldname = @ColName        
      INSERT INTO #tempCustomEnquiryFieldMo (fieldID, fieldvalue) VALUES (@CustomFieldId, @ColValue)          
     END          
          
    --PRINT @LeadValueRow          
    SET @Cnt = @Cnt + 1          
   END          
          
   DECLARE @leadn1 BIGINT = 0          
   SELECT * INTO  #tempLeadMo FROM (                  
    SELECT leadno, isnull(mobileno,'0') AS [mobile], '1' AS [email] FROM UserLeads(NOLOCK) WHERE ParentID=@ParentID and MobileNo<>''                                  
    union                                  
    select leadno, isnull(mobileno1,'0') as [mobile],'1' as [email] from UserLeads(nolock) where ParentID=@ParentID and MobileNo1<>''                                  
    union                                  
    select leadno, isnull(mobileno2,'0') as [mobile],'1' as [email] from UserLeads(nolock) where ParentID=@ParentID and MobileNo2<>''                                  
    union                                  
    select leadno, '0' as [mobile],isnull(nullif(emailid,''),'1') as [email] from UserLeads(nolock) where ParentID=@ParentID   and emailid<>''                                
    union                                  
    select leadno, '0' as [mobile],isnull(nullif(emailid1,''),'1') as [email] from UserLeads(nolock) where ParentID=@ParentID  and emailid1<>''                                                 
    union                                  
    select leadno, '0' as [mobile],isnull(nullif(emailid2,''),'1') as [email] from UserLeads(nolock) where ParentID=@ParentID  and emailid2<>''                                     
   ) lc          
            
   set @leadn1 = isnull( ( select top 1 t.leadno from #tempLeadMo t INNER JOIN UserEnquiry e on                
    (          
     t.mobile = e.MobileNo or t.mobile = e.MobileNo1 or t.mobile = e.MobileNo2 or t.email = e.EmailID or t.email = e.EmailID1 or t.email = e.EmailID2          
    ) WHERE e.EnquiryID = @tempEnquiryId           
    ), 0 )          
          
  select * from #tempEnquiryMainFieldMo        
  BEGIN TRANSACTION          
     DECLARE @RC bigint=0          
    INSERT INTO UserEnquiry (PersonName,  CompanyName,  MobileNo,  MobileNo1,  MobileNo2, EmailID, EmailID1, EmailID2, City, State, Country, CountryCode, CountryCode1,   
 CountryCode2, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, CreatedDate, CreatedBy, IsOpen, LeadNo, img_ext, ProfileImgFileName, IsduplicateEmail, IsduplicateMobile, enquirysource )           
   SELECT PersonName,  CompanyName,  MobileNo,  MobileNo1, MobileNo2, EmailID, EmailID1, EmailID2, City, State, Country, CountryCode, CountryCode1,   
   CountryCode2, PinCode, ResidentialAddress, OfficeAddress, SourceName, MediumName, CampaignName, InitialRemarks, ParentID, getdate(), CreatedBy, IsOpen, LeadNo, img_ext, ProfileImgFileName, IsduplicateEmail, IsduplicateMobile, enquirysource           
   FROM #tempEnquiryMainFieldMo   Where isnull(PersonName, '') != '' and (isnull(MobileNo, '') != '' OR isnull(EmailID, '') != '') and ISNULL(SourceName, '') != ''          
    Select @RC = @@ROWCOUNT          
          
        
        
   SET @EnquiryId = SCOPE_IDENTITY()          
 IF(@EnquiryId > 0 and @RC > 0)          
  BEGIN         
     PRINT 'Entered'        
        
     INSERT INTO customfieldEnquiryvalue  ( EnquiryID, fieldID, fieldvalue )          
   SELECT @EnquiryId, fieldID, fieldvalue FROM #tempCustomEnquiryFieldMo          
          
     INSERT INTO parsedenquiries(rawenquiryid, enquiryid, parentid, EnquirySource) VALUES (@PrechatAutoId, @EnquiryId, @ParentId, 'TawkTo Prechat')          
     --Auto Lead Distribution section start          
   SET @AutoLeadDistribution = isnull((SELECT isnull(AutoLeadDistribution,0) FROM CRMCampaignSettings(nolock) WHERE UserID = @ParentId),0)          
   IF (@AutoLeadDistribution = 1 and @leadn1=0)                                        
   BEGIN                             
    SET @Leadn1 = isnull((select MAX(LeadNo) FROM UserLeads WHERE  ParentID = @ParentID),0)+1                                                  
          
    INSERT INTO userleads (LeadNo, PersonName, MobileNo, EmailID, MobileNo1, EmailID1, City, State, Country, CountryCode, CountryCode1, ResidentialAddress, OfficeAddress, CompanyName, AssignedTo, SourceName, ParentID, Remarks, CreatedOn, CreatedBy, enquirysource)        
    SELECT @leadn1, substring(PersonName,1,100), MobileNo, EmailID, MobileNo1, EmailID1, City, State, Country, CountryCode, CountryCode1, ResidentialAddress, OfficeAddress, CompanyName,   
 (SELECT TOP 1 VALUE FROM fn_Split((SELECT agents FROM CRMCampaignSettings WHERE userid=@ParentId),'#') ORDER BY NEWID()), SourceName, @ParentId,'',GETDATE(), @ParentId, enquirysource FROM UserEnquiry where EnquiryID = @EnquiryId          
                
      DECLARE @LeadId BIGINT;          
      SET @LeadId = SCOPE_IDENTITY()          
   set @isleadcreated=1  
         
     INSERT INTO customfieldLeadvalue ( EnquiryID, fieldID, fieldvalue, LeadID )          
      SELECT @EnquiryId, fieldID, fieldvalue, @LeadId FROM #tempCustomEnquiryFieldMo          
          
     UPDATE UserEnquiry  SET LeadNo = CASE WHEN @LeadN1<>0 THEN @leadn1 ELSE null END,
	  IsOpen= case when @isleadcreated=1 then 0 else 1 end WHERE EnquiryID=@EnquiryId          
              
    Insert into  tbl_MergeLeadsEnquiry(EnquiryNo ,LeadNo,IsOpen)   
 values (@EnquiryID,@Leadn1,case when @isleadcreated=1 then 0 else 1 end)          
  end          
   --Auto Lead Distribution section end               
   --UPDATING tbl_fb_FacebookLeadJson table after successfully completed all work          
  UPDATE tbl_ttc_PrechatFormData SET IsProcessed = 1, ProcessedOn = GETDATE(), EnquiryId = @EnquiryId WHERE Id = @PrechatAutoId         
  END        
   SELECT 1          
          
  --SAVING ALL WORK          
  COMMIT TRANSACTION          
 END TRY          
 BEGIN CATCH          
  ROLLBACK TRANSACTION          
  SELECT * INTO #errorMSG FROM(            
 SELECT ERROR_NUMBER() AS ErrorNumber, ERROR_SEVERITY() AS ErrorSeverity, ERROR_STATE() AS ErrorState, ERROR_PROCEDURE() AS ErrorProcedure, ERROR_LINE() AS ErrorLine, ERROR_MESSAGE() AS ErrorMessage) ER            
      
      
 DECLARE @FailedReason NVARCHAR(MAX)            
  SELECT @FailedReason = ErrorMessage FROM #errorMSG            
            
  SELECT LEN(@FailedReason)            
       
   UPDATE tbl_ttc_PrechatFormData SET IsProcessed = 1, Reason = @FailedReason, ProcessedOn = GETDATE()  WHERE Id = @PrechatAutoId            
            
          
   SELECT 0          
 END CATCH          
 
 drop table if exists #tempMoEnquiry
 drop table if exists #customEnquiryFieldMo
 drop table if exists #tempEnquiryMainFieldMo
 drop table if exists #tempCustomEnquiryFieldMo
 drop table if exists #fbLeadDataMo
  drop table if exists #tempLeadMo
      
          
           
END



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_AI_AgreedMasterInsert]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_TBL_AI_AgreedMasterInsert]        
 (  
 @Mode varchar(2),         
 @IsAgreed bit,  
 @AgreeContent varchar(300),  
 @UserId bigint,        
 @ParentId bigint,  
 @Status bit,        
 @CreatedBy bigint  
)  
AS  
  SET NOCOUNT ON  
  BEGIN TRY  
 IF (@Mode='I')/*This is for Insert TBL_AI_ContentMaster Details */         
 BEGIN   
  if Exists(select top 1 * from TBL_AI_AgreedMaster where ParentId = @ParentId)
  Begin
  Select 'Already Accessed' [Status]         
  End
  Else
  Begin
  insert into TBL_AI_AgreedMaster(IsAgreed, AgreeContent, User_Id, ParentId, [Status], CreatedBy, CreatedDate)  
  values(@IsAgreed, @AgreeContent, @UserId, @ParentId, @Status, @UserId,  GETDATE())         
  Select 'Record Saved' [Status]         
  End
 END /*End here for insert*/                    
 END TRY                    
BEGIN CATCH  
  
 DECLARE @ErrorMessage NVARCHAR(4000);                    
 SELECT @ErrorMessage = ERROR_MESSAGE();                    
 RAISERROR (@ErrorMessage, 16, 1);                    
END CATCH     
  



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_AI_ContentMaster]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_TBL_AI_ContentMaster]
 (                     
 @Mode varchar(2),           
 @QuestionText nvarchar(300),   
 @FeatureTypeCode nvarchar(50),   
 @UserId bigint = 0,          
 @ParentId bigint =0,    
 @Contain varchar(20),    
 @Language varchar(10), 
 @ParamName varchar(50),
 @ParamVal varchar(500)    
)           
AS           
  SET NOCOUNT ON           
  BEGIN TRY           
  If(@Mode='QS')/*This is for List of  Details */                      
  begin           
Select Distinct QuestionText SearchText    
--, QuestionId, QuestionCode,  ResponseLength, Temprature, TopP, FrequencyPenalty, PresencePenalty, StopSequences, BestOf, InjectStartText, InjectRestartText, ShowProbabilities, BodyTopText, LevelValue, CompanyName, Industry, Sentiments, Keywords, Language, Answer, FeatureTypeCode, PrevQuestionId, QuestionType,[Status]    
--, UserId, ParentId     
from TBL_AI_ContentMaster tacm          
inner join TBL_AI_FeatureTypeMaster taftm on taftm.FeatureTypeCode = tacm.FeatureTypeCode  
  where (tacm.ParentId = @ParentId or tacm.ParentId Is Null) and  
  tacm.FeatureTypeCode = @FeatureTypeCode and tacm.QuestionText like '%'+ @QuestionText + '%'    
 end /*End here for list*/                     
  
  
 Else If(@Mode='NS')/*This is for List of  Details */                      
  begin           
Select distinct U_CompanyName SearchText from TBL_AI_ContentMaster tacm          
  where (tacm.ParentId = @ParentId or tacm.ParentId Is Null) and    
  tacm.U_CompanyName like '%'+ @QuestionText + '%'    
 end /*End here for list*/                     
  
 Else If(@Mode='IS')/*This is for List of  Details */                      
  begin           
Select distinct U_Industry SearchText from TBL_AI_ContentMaster tacm          
  where (tacm.ParentId = @ParentId or tacm.ParentId Is Null) and    
  tacm.U_CompanyName like '%'+ @QuestionText + '%'    
 end /*End here for list*/                     
 Else If(@Mode='SS')/*This is for List of  Details */                      
  begin           
   Select distinct U_Sentiments SearchText from TBL_AI_ContentMaster tacm          
   where (tacm.ParentId = @ParentId or tacm.ParentId Is Null) and    
   tacm.U_Sentiments like '%'+ @QuestionText + '%'    
 end /*End here for list*/                     
 Else If(@Mode='KS')/*This is for List of  Details */                      
  begin           
   Select distinct U_Keywords SearchText from TBL_AI_ContentMaster tacm          
   where (tacm.ParentId = @ParentId or tacm.ParentId Is Null) and    
   tacm.U_Keywords like '%'+ @QuestionText + '%'    
 end /*End here for list*/                     
  Else If(@Mode='AL')/*This is for List of  Details */                    
  begin         
   declare @strSql  varchar(2000)
-- declare @ParamName varchar(50)='U_industry',@ParamVal varchar(500)='soft', @strSql nvarchar(max)='', @ParentId bigint=34594

 set @strSql ='select distinct ' + @ParamName + ' as SearchText from TBL_AI_ContentMaster(nolock) where FeatureTypeCode = '''+ @FeatureTypeCode +''' and ParentId=' + cast(@ParentId as varchar) + ' and ' + @ParamName + ' like ''%' + @ParamVal + '%'''

 exec(@strSql)
 end /*End here for list*/                   
 Else If(@Mode='CS')/*This is for List of  Details */                      
  begin    
 select distinct FeatureName SearchText    
 from TBL_AI_FeatureTypeMaster taft where taft.TypeOfTbl = 'Service' and taft.Status = 1     
 and taft.FeatureName like '%'+ @QuestionText + '%'    
 end /*End here for list*/                     
    
 Else If(@Mode='CC')/*This is for List of Details */                      
  begin    
 select top 1 --FeatureTypeId, FeatureTypeCode, FeatureName, TypeOfTbl, ModelText, UrlParameter,     
 ResponseLength, Temprature, TopP, FrequencyPenalty, PresencePenalty, StopSequences, BestOf, InjectStartText, InjectRestartText, ShowProbabilities,'' as BodyTopText--, BodyBottomText    
 , 4 LevelValue, '' CompanyName, '' Industry, '' Sentiments, '' Keywords, '' Language    
 from TBL_AI_FeatureTypeMaster taft where taft.TypeOfTbl = 'Service' and taft.Status = 1     
 and taft.FeatureName like '%' + @QuestionText + '%'    
 end /*End here for list*/                     
 Else If(@Mode='DD')/*This is for List of Details */                      
  begin  
 select --QuestionId, QuestionCode, QuestionText,     
  
 tacm.P_ResponseLength ResponseLength, taftm.Temprature, taftm.TopP, taftm.FrequencyPenalty, taftm.PresencePenalty, taftm.StopSequences, taftm.BestOf, taftm.InjectStartText, taftm.InjectRestartText, taftm.ShowProbabilities, '' as BodyTopText, P_LevelValue, tacm.U_CompanyName, tacm.U_Industry, tacm.U_Sentiments, tacm.U_Keywords, [Language],
tacm.QuestionCode, tacm.U_PersonName, tacm.U_EmployeeName, tacm.U_Designation, tacm.U_Address, tacm.U_OldAddress, tacm.U_Topic, tacm.U_PageName, tacm.U_Keywords, tacm.U_ParagraphBox, tacm.U_ParagraphBoxLabel, tacm.U_CompanyName,   
 tacm.U_Industry, tacm.U_Tone, tacm.U_ToneList,tacm.U_ChatTone, tacm.U_You, tacm.U_Type, tacm.U_Columns,  
tacm.U_Analyze, tacm.U_Contact, tacm.U_Sentiments, tacm.U_For, tacm.U_Equation, tacm.U_Scenario, tacm.U_CodingLanguage, tacm.U_TranslateTo,  
tacm.U_TextToJSON, tacm.U_JsonStringValidate, tacm.U_CodeBlock, tacm.U_StartWith, tacm.U_NoofQuestions,  
tacm.U_QuestionLevel,

tactm.PromptDetails, tactm.PersonName PersonName, tactm.EmployeeName, tactm.Designation, tactm.Address, tactm.OldAddress, tactm.Topic, tactm.PageName, tactm.KeywordsChk, tactm.ParagraphBox, tactm.ParagraphBoxLabel, tactm.CompanyNameChk,   
 tactm.IndustryChk, tactm.Tone, tactm.ToneList,tactm.ChatTone, tactm.You, tactm.Type, tactm.Columns,  
tactm.Analyze, tactm.Contact, tactm.SentimentsChk, tactm.[For], tactm.Equation, tactm.Scenario, tactm.CodingLanguage, tactm.TranslateTo,  
tactm.TextToJSON, tactm.JsonStringValidate, tactm.CodeBlock, tactm.StartWith, tactm.NoofQuestions,  
tactm.QuestionLevel
 --, FeatureTypeCode, PrevQuestionId QuestionType    
 from TBL_AI_ContentMaster tacm   
 inner join TBL_AI_FeatureTypeMaster taftm on tacm.FeatureTypeCode = taftm.FeatureTypeCode  
 inner join TBL_AI_ContentFieldsMaster tactm on tacm.QuestionCode = tactm.QuestionCode  
 where tacm.ISActive = 1 and tacm.FeatureTypeCode = @FeatureTypeCode and tacm.QuestionText like '%' + @QuestionText + '%'  
 end /*End here for list*/                     
    
 END TRY                      
BEGIN CATCH                      
 DECLARE @ErrorMessage NVARCHAR(4000);                      
 SELECT @ErrorMessage = ERROR_MESSAGE();                      
 RAISERROR (@ErrorMessage, 16, 1);                      
END CATCH 



GO

