	and tacm.QuestionText like '%' + @QuestionText + '%' and tacm.FeatureTypeCode != ''     
	--group by QuestionId, QuestionCode, QuestionText, tacm.FeatureTypeCode, P_ResponseLength, P_LevelValue,  Language,
 --   U_CompanyName, U_Industry, U_Sentiments, U_Keywords, U_PersonName, U_EmployeeName, U_Designation, U_Address, U_OldAddress, U_Topic,  U_PageName, U_PageOther, U_ParagraphBox, U_Tone, U_ToneList, U_ChatTone, U_You, U_Type, U_TypeOther, U_Columns, U_Analyze, U_Contact, U_For, U_Equation, U_Scenario, U_CodingLanguage, U_TranslateTo, U_TextToJSON, U_JsonStringValidate, U_CodeBlock, U_StartWith, U_NoofQuestions, U_QuestionLevel, U_CalanderDateTime
order by tacm.createdDate Desc

