   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_TBL_AI_ContentMasterInsert]          
 (    
 @Mode varchar(2),           
 @QuestionText nvarchar(MAX),    
 @P_ResponseLength int,    
 @P_Temprature decimal(4, 2),    
 @P_TopP decimal(4, 2),    
 @P_FrequencyPenalty decimal(4, 2),    
 @P_PresencePenalty decimal(4, 2),    
 @P_StopSequences nvarchar(20),    
 @P_BestOf int,    
 @P_InjectStartText nvarchar(20),    
 @P_InjectRestartText nvarchar(20),    
 @P_ShowProbabilities varchar(20),    
 @P_BodyTopText varchar(500),    
 @P_LevelValue int,    
 @U_CompanyName nvarchar(500),    
 @U_Industry nvarchar(500),    
 @U_Sentiments nvarchar(500),    
 @U_Keywords nvarchar(500),    
 @Language varchar(50),    
 @Answer nvarchar(MAX),    
 @FeatureTypeCode varchar(50),    
 @PrevQuestionId bigint,    
 @APIText nvarchar(MAX),    
 @U_PersonName nvarchar(500),    
 @U_EmployeeName nvarchar(500),    
 @U_Designation nvarchar(500),    
 @U_Address nvarchar(500),    
 @U_OldAddress nvarchar(500),    
 @U_Topic nvarchar(500),    
 @U_PageName nvarchar(500),    
 @U_PageOther nvarchar(500),  
 @U_ParagraphBox nvarchar(MAX),    
 @U_ParagraphBoxLabel nvarchar(MAX),    
 @U_Tone nvarchar(500),    
 @U_ToneList nvarchar(500),    
 @U_ChatTone nvarchar(500),    
 @U_You nvarchar(500),    
 @U_Type nvarchar(500),    
 @U_TypeOther nvarchar(500),    
 @U_Columns nvarchar(500),    
 @U_Analyze nvarchar(500),    
 @U_Contact nvarchar(500),    
 @U_For nvarchar(500),    
 @U_Equation nvarchar(500),    
 @U_Scenario nvarchar(500),    
 @U_CodingLanguage nvarchar(500),    
 @U_TranslateTo nvarchar(500),    
 @U_TextToJSON nvarchar(2000),    
 @U_JsonStringValidate nvarchar(2000),    
 @U_CodeBlock nvarchar(500),    
 @U_StartWith nvarchar(500),    
 @U_NoofQuestions nvarchar(500),    
 @U_QuestionLevel nvarchar(500),    
 @UserId bigint,          
 @ParentId bigint,    
 @IsActive bit,          
 @CreatedBy bigint    
)    
AS    
  SET NOCOUNT ON    
  BEGIN TRY   
  if(@Mode = 'FA')
  Begin
  set @Mode='I'
  End
 IF (@Mode='I')/*This is for Insert TBL_AI_ContentMaster Details */           
 BEGIN     
 Declare @QuestionCode varchar(150)    
 Declare @Q_ID Bigint     
    
  set @QuestionCode = ('Ques' + Cast(((select Max(QuestionId) from TBL_AI_ContentMaster(nolock))+1) as varchar(30)))    
      
  insert into TBL_AI_ContentMaster(QuestionCode, QuestionText, P_ResponseLength, P_Temprature, P_TopP, P_FrequencyPenalty,   
  P_PresencePenalty, P_StopSequences, P_BestOf, P_InjectStartText, P_InjectRestartText, P_ShowProbabilities, P_BodyTopText,   
  P_LevelValue, U_CompanyName, U_Industry, U_Sentiments, U_Keywords, [Language], Answer, FeatureTypeCode, PrevQuestionId,   
  APIText,  U_PersonName ,U_EmployeeName, U_Designation, U_Address, U_OldAddress, U_Topic, U_PageName, U_PageOther, U_ParagraphBox, U_ParagraphBoxLabel, U_Tone,  U_ToneList, U_ChatTone, U_You, U_Type, U_TypeOther, U_Columns, U_Analyze, U_Contact,   
  U_For, U_Equation, U_Scenario, U_CodingLanguage, U_TranslateTo, U_TextToJSON, U_JsonStringValidate, U_CodeBlock,   
  U_StartWith, U_NoofQuestions, U_QuestionLevel, UserId, ParentId, IsActive, CreatedBy, CreatedDate)    
    
  values(@QuestionCode, @QuestionText, @P_ResponseLength, @P_Temprature, @P_TopP, @P_FrequencyPenalty, @P_PresencePenalty,   
  @P_StopSequences, @P_BestOf, @P_InjectStartText, @P_InjectRestartText, @P_ShowProbabilities, @P_BodyTopText, @P_LevelValue,   
  @U_CompanyName, @U_Industry, @U_Sentiments, @U_Keywords, @Language, @Answer, @FeatureTypeCode, @PrevQuestionId, @APIText,    
  @U_PersonName ,@U_EmployeeName, @U_Designation, @U_Address, @U_OldAddress, @U_Topic, @U_PageName, @U_PageOther, @U_ParagraphBox, @U_ParagraphBoxLabel, @U_Tone, @U_ToneList, @U_ChatTone, @U_You, @U_Type, @U_TypeOther, @U_Columns, @U_Analyze, @U_Contact, 
@U_For, @U_Equation, @U_Scenario, @U_CodingLanguage, @U_TranslateTo, @U_TextToJSON, @U_JsonStringValidate, @U_CodeBlock, @U_StartWith, @U_NoofQuestions, @U_QuestionLevel, @UserId, @ParentId, 1, @UserId,  GETDATE())           
    
  set @Q_ID = SCOPE_IDENTITY()    
      
   --declare @ParentId bigint,     
 declare @Price decimal(18,4), @Cost decimal(18,4),     
 @mCount int, @TotalBalance decimal(18, 4), @MId int    
     
 declare @Pulse decimal(18,4),@TPrice decimal(18,4),@words int,@isunicode int=0    
     
 select @ParentId = ParentID, @MId = M_ID from User_Detail(nolock) where User_ID = @UserId    
 select top 1 @Pulse = (Price * LoadFactor),@Tprice=Price,@words=words from [dbo].[tbl_AI_PriceMaster](nolock) where FeatureTypeId = @P_LevelValue     
 and isnull(parentid, 0) in (0,@parentid)   
 order by parentid desc  
    
 select  top 1 @TotalBalance = isnull(balance, 0) FROM IntCredit_Details c with (nolock) where user_ID= @parentid   
 order by Credit_ID desc  
    
Declare @AnswerWords int = 0   
select @AnswerWords = count(*) from dbo.fn_Split(dbo.[fn_removewhitespaces](@Answer), ' ')  
if  cast(@answer as varchar(max))=@answer  
begin  
set @cost=ceiling(@AnswerWords/cast(@words as float))*@TPrice  
end  
else  
begin  
set @isunicode=1  
set @cost=2*ceiling(@AnswerWords/cast(@words as float))*@TPrice  
end    
    
 -- declare @Pulse decimal(18,4) = 0.48    
    
 --  Declare @Price decimal(18,4), @Cost decimal(18,4),     
 --@mCount int, @TotalBalance decimal(18, 4), @MId int, @Answer nvarchar(max) = 'Looking for alearn more!' "    
 --  Declare  @AnswerWords numeric(18,2) = LEN(@Answer)/4    
      
 --set @Cost = ceiling((isnull(@Pulse, 0) * @AnswerWords))    
   
      
 -- select @Cost , @AnswerWords, LEN(@Answer)/4    
    
 declare @Remarks nvarchar(max) = concat('Amount Deducted for AI Q_ID: ', cast(@Q_ID as nvarchar)+ ' that read like "'  
 +left(@QuestionText,20)+'...",Level: '+   
 cast(@P_LevelValue as nvarchar)+' Unicode: '+case when @isunicode=0 then 'False' else 'True' end +', Words: '+cast(@answerwords as nvarchar)  )    
    
 exec proc_UpdateIntCreditDetail_new     
   @M_ID = @MId,    
   @User_ID = @parentid,    
   @Price = @Cost,    
   @BATCHID = 0,    
   @remark = @Remarks,    
   @typecredit = 12    
    
    select top 1 @TotalBalance = isnull(balance, 0) FROM IntCredit_Details c with (nolock) where user_ID=@parentid   
 order by Credit_ID desc  
    
    Select 'Record Saved' [Status], @QuestionCode Code, @TotalBalance as Balance, 'Balance Available' as remarks    
    
 END /*End here for insert*/                      

 else IF (@Mode='IA')/*This is for Insert TBL_AI_ContentMaster Details */           
 BEGIN     
 Declare @QuestionCodeA varchar(150)    
 Declare @Q_IDA Bigint     
    
  set @QuestionCodeA = ('Ques' + Cast(((select Max(QuestionId) from TBL_AI_ContentMaster(nolock))+1) as varchar(30)))    
      
  insert into TBL_AI_ContentMaster(QuestionCode, QuestionText, P_ResponseLength, P_Temprature, P_TopP, P_FrequencyPenalty,   
  P_PresencePenalty, P_StopSequences, P_BestOf, P_InjectStartText, P_InjectRestartText, P_ShowProbabilities, P_BodyTopText,   
  P_LevelValue, U_CompanyName, U_Industry, U_Sentiments, U_Keywords, [Language], Answer, FeatureTypeCode, PrevQuestionId,   
  APIText,  U_PersonName ,U_EmployeeName, U_Designation, U_Address, U_OldAddress, U_Topic, U_PageName, U_PageOther, U_ParagraphBox, U_ParagraphBoxLabel, U_Tone,  U_ToneList, U_ChatTone, U_You, U_Type, U_TypeOther, U_Columns, U_Analyze, U_Contact,   
  U_For, U_Equation, U_Scenario, U_CodingLanguage, U_TranslateTo, U_TextToJSON, U_JsonStringValidate, U_CodeBlock,   
  U_StartWith, U_NoofQuestions, U_QuestionLevel, UserId, ParentId, IsActive, CreatedBy, CreatedDate)    
    
  values(@QuestionCodeA, @QuestionText, @P_ResponseLength, @P_Temprature, @P_TopP, @P_FrequencyPenalty, @P_PresencePenalty,   
  @P_StopSequences, @P_BestOf, @P_InjectStartText, @P_InjectRestartText, @P_ShowProbabilities, @P_BodyTopText, @P_LevelValue,   
  @U_CompanyName, @U_Industry, @U_Sentiments, @U_Keywords, @Language, @Answer, @FeatureTypeCode, @PrevQuestionId, @APIText,    
  @U_PersonName ,@U_EmployeeName, @U_Designation, @U_Address, @U_OldAddress, @U_Topic, @U_PageName, @U_PageOther, @U_ParagraphBox, @U_ParagraphBoxLabel, @U_Tone, @U_ToneList, @U_ChatTone, @U_You, @U_Type, @U_TypeOther, @U_Columns, @U_Analyze, @U_Contact, 
@U_For, @U_Equation, @U_Scenario, @U_CodingLanguage, @U_TranslateTo, @U_TextToJSON, @U_JsonStringValidate, @U_CodeBlock, @U_StartWith, @U_NoofQuestions, @U_QuestionLevel, @UserId, @ParentId, 1, @UserId,  GETDATE())           
    
  set @Q_IDA = SCOPE_IDENTITY()    
      
   --declare @ParentId bigint,     
 declare @PriceA decimal(18,4), @CostA decimal(18,4),     
 @mCountA int, @TotalBalanceA decimal(18, 4), @MIdA int    
     
 declare @PulseA decimal(18,4),@TPriceA decimal(18,4),@wordsA int,@isunicodeA int=0    
     
 select @ParentId = ParentID, @MIdA = M_ID from User_Detail(nolock) where User_ID = @UserId    
 select top 1 @PulseA = (Price * LoadFactor),@TpriceA=Price,@wordsA=words from [dbo].[tbl_AI_PriceMaster](nolock) where FeatureTypeId = @P_LevelValue     
 and isnull(parentid, 0) in (0,@parentid)   
 order by parentid desc  
    
 select  top 1 @TotalBalanceA = isnull(balance, 0) FROM IntCredit_Details c with (nolock) where user_ID= @parentid   
 order by Credit_ID desc  
    
Declare @AnswerWordsA int = 0   
select @AnswerWordsA = count(*) from dbo.fn_Split(dbo.[fn_removewhitespaces](@Answer), ' ')  
if  cast(@answer as varchar(max))=@answer  
begin  
set @costA=ceiling(@AnswerWordsA/cast(@wordsA as float))*@TPriceA  
end  
else  
begin  
set @isunicodeA=1  
set @costA=2*ceiling(@AnswerWordsA/cast(@words as float))*@TPriceA  
end    
    
 -- declare @PulseA decimal(18,4) = 0.48    
    
 --  Declare @PriceA decimal(18,4), @CostA decimal(18,4),     
 --@mCountA int, @TotalBalanceA decimal(18, 4), @MIdA int, @Answer nvarchar(max) = 'Looking for alearn more!' "    
 --  Declare  @AnswerWordsA numeric(18,2) = LEN(@Answer)/4    
      
 --set @CostA = ceiling((isnull(@PulseA, 0) * @AnswerWordsA))    
   
      
 -- select @CostA , @AnswerWordsA, LEN(@Answer)/4    
  
 declare @RemarksA nvarchar(max) = concat('Amount Deducted for AI Q_ID: ', cast(@Q_IDA as nvarchar)+ ' for User Id: ' + @UserId + ' and Parent Id: ' + @parentid + ' that read like "' 
 +left(@QuestionText,20)+'...",Level: '+ 
 cast(@P_LevelValue as nvarchar)+' Unicode: '+case when @isunicodeA=0 then 'False' else 'True' end +', Words: '+cast(@answerwordsA as nvarchar)  )    

 set @parentid = 335
 
 exec proc_UpdateIntCreditDetail_new     
   @M_ID = @MIdA,    
   @User_ID = @parentid,    
   @Price = @CostA,    
   @BATCHID = 0,    
   @remark = @RemarksA,    
   @typecredit = 12    
    
    select top 1 @TotalBalanceA = isnull(balance, 0) FROM IntCredit_Details c with (nolock) where user_ID=@parentid   
 order by Credit_ID desc  
    
    Select 'Record Saved' [Status], @QuestionCodeA Code, @TotalBalanceA as Balance, 'Balance Available' as remarks    
    
 END /*End here for insert*/                      

 END TRY                      
BEGIN CATCH    
 exec usp_InsertErrorInfo  
 --DECLARE @ErrorMessage NVARCHAR(4000);                      
 --SELECT @ErrorMessage = ERROR_MESSAGE();                      
 --RAISERROR (@ErrorMessage, 16, 1);                      
END CATCH    
  


GO

