CREATE   PROCEDURE [dbo].[usp_TBL_AI_FeatureTypeMaster]      
(
 @Mode varchar(2), 
 @FeatureTypeCode nvarchar(300) = null, 
 @QuestionCode nvarchar(20) = null,
 @UserId bigint = 0, 
 @ParentId bigint =0,
 @Contain varchar(20),
 @Language varchar(10)
)
AS       
  SET NOCOUNT ON       
  BEGIN TRY       
  If(@Mode='QS')/*This is for List of  Details */                  
  begin 
Select Distinct FeatureTypeId, FeatureTypeCode, FeatureName, TypeOfTbl, ModelText, UrlParameter,
ResponseLength, Temprature, TopP, FrequencyPenalty, PresencePenalty, StopSequences, BestOf, InjectStartText, InjectRestartText, ShowProbabilities,  ParentFeatureTypeId, [Status] from TBL_AI_FeatureTypeMaster tafm 
 where tafm.TypeOfTbl = 'Service' and tafm.Status = 1 and tafm.FeatureTypeCode = @FeatureTypeCode or @FeatureTypeCode Is null
 end /*End here for list*/                 
Else If(@Mode='QF')/*This is for List of  Details */                  
  begin 
select ContentFieldsId,
PersonName,
EmployeeName,
Designation,
Address,
OldAddress,
Topic,
PageName,
KeywordsChk,
ParagraphBox,
ParagraphBoxLabel,
CompanyNameChk,
IndustryChk,
Tone,
ToneList,
Type,
Columns,
Analyze,
Contact,
SentimentsChk,
[For],
CodingLanguage,
TranslateTo,
TextToJSON,
JsonStringValidate,
CodeBlock,
StartWith
 from TBL_AI_ContentFieldsMaster tacf where tacf.QuestionCode = @QuestionCode
 end /*End here for list*/                 
 END TRY
