/* ============================================================
   Procedure: [dbo].[usp_tbl_APP_GetBatchNotification_New_navigation]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_tbl_APP_GetBatchNotification_New_navigation] --1                       
	(@BatchSize INT = 1)
AS
BEGIN
	/*  
  
 Added: DBA  
  
 Date: 2025-01-11  
  
 */
	DROP TABLE IF EXISTS #AppBatchNotification
	DROP TABLE IF EXISTS #BatchNotificationDetail

		CREATE TABLE #AppBatchNotification (
			BatchNotification_Id BIGINT
			,CONSTRAINT PK_#AppBatchNotification_ID_nav PRIMARY KEY CLUSTERED (BatchNotification_Id)
			);

	CREATE TABLE #BatchNotificationDetail (
		BatchNotification_Id BIGINT
		,User_ID BIGINT
		,LastAttemptedTime DATETIME
		,Retries INT
		,IsProcessed BIT
		,RawReason NVARCHAR(MAX)
		,DeviceId VARCHAR(1000)
		);

	INSERT INTO #AppBatchNotification (BatchNotification_Id)
	SELECT BatchNotification_Id
	FROM [tbl_APP_BatchNotification] M(NOLOCK)
	WHERE IsProcessed = 0
		AND GETDATE() <= CutOffTime
		AND TotalProcessed < totalrecords
		AND m.createdon >= dateadd(HH, - 6, getdate());

	INSERT INTO #BatchNotificationDetail (
		BatchNotification_Id
		,User_ID
		,LastAttemptedTime
		,Retries
		,IsProcessed
		,RawReason
		,DeviceId
		)
	SELECT t.BatchNotification_Id
		,User_ID
		,LastAttemptedTime
		,Retries
		,IsProcessed
		,RawReason
		,DeviceId
	FROM [tbl_APP_BatchNotificationDetail] BND WITH (NOLOCK)
	INNER JOIN #AppBatchNotification t ON t.BatchNotification_Id = BND.BatchNotification_Id
	WHERE BND.IsProcessed = 0;

	SELECT TOP 10 *
		,0 DataId
		,'' TypeName
		,ClickActionUrl MobPath
	FROM [tbl_APP_BatchNotification] M(NOLOCK)
	INNER JOIN #AppBatchNotification t ON t.BatchNotification_Id = M.BatchNotification_Id
	WHERE --dbo.ufn_getuserparentid(M.CreatedBy) in (34594,32222) and    
		M.createdon >= dateadd(HH, - 6, getdate())
		AND
		--  BatchNotification_Id=  54679        
		--  or                   
		--    IsProcessed=0               
		--   and GETDATE() <= CutOffTime                    
		--   and TotalProcessed<totalrecords              
		--and   
		EXISTS (
			SELECT 1
			FROM #BatchNotificationDetail BND
			LEFT OUTER JOIN User_Detail(NOLOCK) UL ON BND.User_ID = UL.User_ID
			WHERE --BND.User_id not in (32222, 34594) and  
				ISNULL(UL.DeviceID, '') <> ''
				AND UL.Type NOT IN (
					3
					,4
					)
				AND BND.BatchNotification_Id = M.BatchNotification_Id
				AND BND.IsProcessed = 0
				AND (
					isnull(lastattemptedtime, '') = ''
					OR datediff(s, lastattemptedtime, getdate()) >= cast((
							SELECT TOP 1 isnull(MinValue, 0)
							FROM dbo.Minimum_Func(((2 ^ Retries) + rand(1)), 32)
							) AS INTEGER)
					)
				AND (
					isnull(lastattemptedtime, '') = ''
					OR datediff(MI, lastattemptedtime, getdate()) > 10
					)
				AND (
					(isnull(BND.RawReason, '') = '')
					OR (
						Bnd.RawReason NOT LIKE '%UNREGISTERED%'
						AND Bnd.RawReason NOT LIKE '%Not%Registered%'
						AND Bnd.RawReason NOT LIKE '%Missing%Registration%'
						AND Bnd.RawReason NOT LIKE '%SENDER_ID_MISMATCH%'
						)
					)
			)
	ORDER BY --case when t.batchnotification_id=7093156 then 0 else 1 end,  
		BatchSentTime
		,CreatedOn
END



GO

