/* ============================================================
   Procedure: [dbo].[usp_tbl_APP_SetBatchNotificationDetail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_tbl_APP_SetBatchNotificationDetail      
(      
    @BatchNotificationDetail_Id bigint,      
    @LastAttemptedTime Datetime,      
    @LastStatus nvarchar(max),      
    @IsProcessed bit      
)      
AS      
BEGIN      
    Update  [tbl_APP_BatchNotificationDetail]      
    Set   Retries = ISNULL(Retries,0)+1, LastAttemptedTime=isnull(@LastAttemptedTime,getdate()), LastStatus=@LastStatus, IsProcessed=@IsProcessed      
    Where   BatchNotificationDetail_Id=@BatchNotificationDetail_Id      
END   


