/* ============================================================
   Procedure: [dbo].[usp_tbl_APP_SetBatchNotificationEndTime_New]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

        
CREATE   PROC usp_tbl_APP_SetBatchNotificationEndTime_New        
(        
    @BatchNotification_Id bigint,        
    @BatchCompleteTime datetime,        
    @TotalProcessed int,        
    @IsProcessed bit        
)        
AS        
BEGIN        
        
 --   Update  [MK_BatchNotification]       
 --Set BatchCompleteTime=@BatchCompleteTime, LastBatchProcessed=@BatchCompleteTime,       
 -- TotalProcessed+=@TotalProcessed, IsProcessed=@IsProcessed        
 --   Where   BatchNotification_Id=@BatchNotification_Id        
      
    --Update  [MK_BatchNotification]       
    -- Set BatchCompleteTime=@BatchCompleteTime, LastBatchProcessed=@BatchCompleteTime,       
    -- IsProcessed=@IsProcessed        
    --Where   BatchNotification_Id=@BatchNotification_Id        
    
   declare @ProcessedCount int = 0    
   select @ProcessedCount = isnull(Count(1),0) from [tbl_APP_BatchNotificationDetail] where BatchNotification_Id = @BatchNotification_Id    
              and  IsProcessed = 1    
    
    Update  [tbl_APP_BatchNotification]       
     Set TotalProcessed = @ProcessedCount    
    Where   BatchNotification_Id=@BatchNotification_Id        
    
   Declare @TotalRecordCount int = 0  
     
   select @TotalRecordCount = isnull(TotalRecords,0) from [tbl_APP_BatchNotification] where BatchNotification_Id=@BatchNotification_Id      
   if(@TotalRecordCount = @ProcessedCount)  
      Begin  
  
              Update  [tbl_APP_BatchNotification]       
                Set BatchCompleteTime=@BatchCompleteTime, LastBatchProcessed=@BatchCompleteTime,       
                   IsProcessed=@IsProcessed        
                 Where   BatchNotification_Id=@BatchNotification_Id        
  
   End  
      
    
    
END 


GO

