CREATE   PROCEDURE [dbo].[usp_TBL_BM_AgentCheck]                    
(    
 @Mode varchar(2),    
 @ClientToken varchar(500) = '',    
 @SecretKey varchar(500) = ''        
)              
AS              
 SET NOCOUNT ON              
  BEGIN TRY          
 IF (@Mode='U')/*This is for Insert TBL_AI_ContentMaster Details */                     
 BEGIN               
 Declare @Status bit = 0    
 Declare @JSONMessage nvarchar(Max)  
 set @JSONMessage = '' + @ClientToken  
  
insert into TBL_BM_MessageTransaction (JSONMessage, CreatedDate) values('', getDate())  
  
 if Exists(select 1 from TBL_BM_AgentCheck where ClientToken = @ClientToken)        
 Begin    
    
 Update TBL_BM_AgentCheck set SecretKey = @SecretKey, UpdateDate = GETDATE() where ClientToken = @ClientToken     
    
 set @Status = 1    
    
 End    
    
 Select @Status [Status], @SecretKey [Secret]    
       
 END /*End here for insert*/                                

 Else IF (@Mode='I')/*This is for Insert TBL_AI_ContentMaster Details */                     
 BEGIN               
  
insert into TBL_BM_MessageTransaction (JSONMessage, CreatedDate) values('', getDate())  
    
Select 1 [Status], 'blank' [Secret]    
       
 END /*End here for insert*/                                

 END TRY                                
BEGIN CATCH              
 exec usp_InsertErrorInfo            
END CATCH



GO

/* ============================================================
   Procedure: [dbo].[usp_tbl_BM_AgentMaster]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_tbl_BM_AgentMaster]        
(    
 @Mode varchar(2),           
 @ID bigint = 0,        
 @AgentName nvarchar(100) = null,        
 @Description nvarchar(150) = null,        
 @Color nvarchar(20) = null,        
 @BannerImage nvarchar(300) = null,        
 @SmallLogo nvarchar(300) = null,        
 @Privacypolicy nvarchar(200) = null,        
 @Termsofservice nvarchar(200) = null,        
 @defaultcutofflimit bigint =0,      
 @dtAgentContactDataBO nvarchar(max) = null,     
 @defaultcutoffType varchar(10) = null,    
 @Active bit = 0,          
 @ParentId bigint =0          
)    
AS           
  SET NOCOUNT ON           
  BEGIN TRY           
  IF (@Mode='I')/*This is for Insert TBL_UA_TeamMaster Details */                      
 BEGIN           
If  Not Exists(select 1 from tbl_BM_AgentMaster(nolock) where AgentName = @AgentName and ParentId = @ParentId)        
Begin        
    
 insert into tbl_BM_AgentMaster(AgentName, [Description], Color, BannerImage, SmallLogo, Privacypolicy, Termsofservice, defaultcutofflimit, defaultcutoffType,  LaunchStatus, ActivationStatus, ParentId, Active, CreatedBy, CreatedDate)   
 Values(@AgentName, @Description, @Color, @BannerImage, @SmallLogo, @Privacypolicy, @Termsofservice, @defaultcutofflimit, @defaultcutoffType, 1, 0, @ParentId, 1, @ParentId, GetDate())   
          
 set @ID =  @@Identity        
        
 insert into tbl_BM_AgentMasContactInfo (ID, ContactType, ContactData, LabelContactData)          
 select @ID, ContactType, ContactData, LabelContactData from openjson(@dtAgentContactDataBO)          
with          
(          
 ContactType nvarchar(10) '$.ContactType',          
 ContactData nvarchar(50) '$.ContactData',          
 LabelContactData nvarchar(100) '$.LabelContactData'        
) t           
          
 Select 'Record Saved' Status, @ID ID         
          
 END         
 END /*End here for insert*/           
        
 END TRY                      
