/* ============================================================
   Procedure: [dbo].[usp_tbl_BM_AgentMaster_Search]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
CREATE   PROCEDURE [dbo].[usp_tbl_BM_AgentMaster_Search]                  
(    
 @Mode varchar(2),                   
 @AgentName varchar(100) = '',            
 @ParentId bigint =0,            
 @Contain varchar(20) = 'StartWith',            
 @OffsetValue int = 0,                                                                    
 @PagingSize int  = 10        
)    
AS    
  SET NOCOUNT ON                   
  BEGIN TRY                   
--Declare @Mode varchar(2) = 'S',                   
-- @AgentName varchar(100) = '',            
-- @ParentId bigint =32222,        
-- @Contain varchar(20) = 'StartWith',            
-- ,@OffsetValue int = 0        
-- ,@PagingSize int  = 10        
          
If(@Mode='S')/*This is for List of  Details */                              
  begin           
 declare @TimeZoneName nvarchar(255) = ( select TimeZone from User_Detail(nolock) where User_ID = @ParentId)       
      
 select count(t.ID) over() as TotalRow, * from (      
  select tba.ID, AgentName, Description, Color, BannerImage, SmallLogo, Privacypolicy, Termsofservice, defaultcutofflimit, defaultcutoffType,   
  Case when LaunchStatus = 1 then 'Submitted'  
  when LaunchStatus = 2 then 'Approved'  
  when LaunchStatus = 3 then 'Rejected'  
  else ''  
  End  
  LaunchStatusD, LaunchStatus,   
   Reason,Case when ActivationStatus = 1 then 'Active'  
  else 'Inactive'  
  End  
  ActivationStatusD, ActivationStatus,  
  tba.ParentId, (UL.FName +' '+ UL.LName) as CreatedUser, Active, Active stActive,   
  CreatedBy, dbo.fn_ConvertDateTime(cast(CreatedDate as datetime),   
  cast(@TimeZoneName as nvarchar(255)), 0) as CreatedDate from Tbl_BM_AgentMaster(noLock) tba   
  inner join User_Detail (noLock) UL on UL.User_Id = tba.ParentId   
  where tba.ParentId = @ParentId   
  
) t       
order by t.ID Desc      
OFFSET @OffsetValue Rows FETCH NEXT @PagingSize ROWS ONLY            
        
 end /*End here for list*/                             
 END TRY                              
BEGIN CATCH            
DECLARE @ErrorMessage NVARCHAR(4000);                              
SELECT @ErrorMessage = ERROR_MESSAGE();                              
RAISERROR (@ErrorMessage, 16, 1);                              
END CATCH   
  


GO

