CREATE   PROCEDURE [dbo].[usp_tbl_BM_AgentMaster_Update]        
(    
 @Mode varchar(2),           
 @ID bigint = 0,        
 @AgentName nvarchar(100) = null,        
 @Description nvarchar(150) = null,        
 @Color nvarchar(20) = null,        
 @BannerImage nvarchar(300) = null,        
 @SmallLogo nvarchar(300) = null,        
 @Privacypolicy nvarchar(200) = null,        
 @Termsofservice nvarchar(200) = null,        
 @defaultcutofflimit bigint =0,      
 @dtAgentContactDataBO nvarchar(max) = null,     
 @defaultcutoffType varchar(10) = null,    
 @Active bit = 0,          
 @ParentId bigint =0          
)    
AS           
  SET NOCOUNT ON           
  BEGIN TRY           
  IF (@Mode='U')/*This is for Insert TBL_UA_TeamMaster Details */                      
 BEGIN           
If Exists(select 1 from tbl_BM_AgentMaster(nolock) where ID = @ID and ParentId = @ParentId)        
Begin  
Update tbl_BM_AgentMaster set AgentName = @AgentName, [Description] = @Description, Color = @Color, BannerImage = @BannerImage, SmallLogo = @SmallLogo, Privacypolicy = @Privacypolicy, Termsofservice = @Termsofservice, defaultcutofflimit = @defaultcutofflimit, defaultcutoffType = @defaultcutoffType,  LaunchStatus = 1, ActivationStatus = 0, ParentId = @ParentId, Active = 1, ModifiedBy = @ParentId , CreatedDate = GetDate()   
 where Id =@ID  
  
  
delete tbl_BM_AgentMasContactInfo where id = @ID  
  
 insert into tbl_BM_AgentMasContactInfo (ID, ContactType, ContactData, LabelContactData)          
 select @ID, ContactType, ContactData, LabelContactData from openjson(@dtAgentContactDataBO)          
with          
(          
 ContactType nvarchar(10) '$.ContactType',          
 ContactData nvarchar(50) '$.ContactData',          
 LabelContactData nvarchar(100) '$.LabelContactData'        
) t           
          
 Select 'Record Updated' Status, @ID ID         
          
 END         
 END /*End here for insert*/           
        
 END TRY                      
BEGIN CATCH                      
           
 DECLARE @ErrorMessage NVARCHAR(4000);                      
 SELECT @ErrorMessage = ERROR_MESSAGE();                      
 RAISERROR (@ErrorMessage, 16, 1);                      
END CATCH   
  


GO

