/* ============================================================
   Procedure: [dbo].[usp_Tbl_BM_General_Delivery_Custom]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_Tbl_BM_General_Delivery_Custom](        
 @Mode varchar(2),
 @TempTableName varchar(100)
)
as
begin
 if(@Mode = 'U')
Begin  
Declare @IsUnSubscribed bit = 1  

DECLARE @query_a AS nvarchar(4000)  
DECLARE @query_b AS nvarchar(4000)  
DECLARE @query_c AS nvarchar(4000)  

 SET @query_a = 'update '+@TempTableName+' set IsUnSubscribed = 0 where IsUnSubscribed Is null and (CountryCode + MobileNo) = (select (CountryCode + MobileNo) from tbl_BM_OptInOutMessages(nolock) where Opttype = ''In'')'
  
EXECUTE sp_executesql @query_a; 

print @TempTableName+' IsUnSubscribed = 0'  

 SET @query_b = 'update Tbl_BM_General_DeliveryLess set IsUnSubscribed = 1 where IsUnSubscribed Is null and (CountryCode + MobileNo) = (select (CountryCode + MobileNo) from tbl_BM_OptInOutMessages(nolock) where Opttype = ''Out'')' 

EXECUTE sp_executesql @query_b; 
  
 SET @query_c = 'update Tbl_BM_General_DeliveryLess set IsUnSubscribed = 1 where IsUnSubscribed Is null and (CountryCode + MobileNo) != (select (CountryCode + MobileNo) from tbl_BM_OptInOutMessages(nolock) )'

EXECUTE sp_executesql @query_c; 

print @TempTableName+' IsUnSubscribed = 1'  
  
End  
End



GO

/* ============================================================
   Procedure: [dbo].[usp_Tbl_BM_General_Delivery_Dynamic]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_Tbl_BM_General_Delivery_Dynamic]      
(    
 @Mode varchar(2)= null,    
 @BatchID bigint = 0,    
 @TotalRecords int = 201,    
 @TempTableName varchar(100) = null  
)    
as             
  SET NOCOUNT ON             
  BEGIN TRY             
Begin        
If(@Mode = 'I')      
Begin      
Declare @ParentId bigint     
-- Main Table    
if(@TotalRecords > 200)    
Begin    
DECLARE @query_a AS nvarchar(4000)    
    
 SET @query_a = 'insert into '+ @TempTableName +' (GenMainID, ParentId, MsgHistoryID,     
MobileNo, CountryCode, SourceName, MsgContent, BMTemplateId, JSONMsgContent, AgentId, CreatedOn, ScheduleDateTime)    
    
select m1.GenMainID, (select ParentId from User_Detail(nolock) where User_ID = m1.UserID), h1.MsgHistoryID,  
h1.MobileNo, h1.CountryCode, m1.Source, h1.MsgContent, h1.BMTemplateId, h1.JSONMsgContent, m1.AgentId, GETDATE(), m1.ScheduledDateTime  
from Tbl_BM_General_Delivery_Main m1  
inner join Tbl_BM_General_MessageHistory h1 on h1.BatchId = m1.BatchId  
where m1.BatchId =  '+cast(@BatchID  as varchar(100))+'  
and m1.TotalRecords > 200 and h1.MobileNo != '''''  
  
EXECUTE sp_executesql @query_a;   
    
update Tbl_BM_General_Delivery_Main set IsProcessed = 1, ProcessTable = @TempTableName where BatchId = @BatchId    
select 'Updated Successfully' status        
End    
End    
End     
 END TRY                        
BEGIN CATCH                        
             
 DECLARE @ErrorMessage NVARCHAR(4000);                        
 SELECT @ErrorMessage = ERROR_MESSAGE();                        
 RAISERROR (@ErrorMessage, 16, 1);                        
END CATCH



GO

