(            
 @Mode varchar(2)    
)    
as    
begin    
 if(@Mode = 'U')    
Begin    
Declare @IsUnSubscribed bit = 1
Declare @id bigint    
  
--if Exists(select 1 from Tbl_BM_General_DeliveryLess gd1 where gd1.IsUnSubscribed Is null)    
--Begin    
    
--update Tbl_BM_General_DeliveryLess set IsUnSubscribed = 0 where isnull(IsUnSubscribed, 0) = 0 and (CountryCode + MobileNo) in (select (CountryCode + MobileNo) from tbl_BM_OptInOutMessages(nolock) where Opttype = 'In')    
--print 'Tbl_BM_General_DeliveryLess IsUnSubscribed = 0'    
    
--update Tbl_BM_General_DeliveryLess set IsUnSubscribed = 1 where isnull(IsUnSubscribed, 0) = 0 and (CountryCode + MobileNo) in (select (CountryCode + MobileNo) from tbl_BM_OptInOutMessages(nolock) where Opttype = 'Out')    
    
--update Tbl_BM_General_DeliveryLess set IsUnSubscribed = 1 where isnull(IsUnSubscribed, 0) = 0 and (CountryCode + MobileNo) not in (select (CountryCode + MobileNo) from tbl_BM_OptInOutMessages(nolock) )    
--print 'Tbl_BM_General_DeliveryLess IsUnSubscribed = 1'    
    
--End    
  
--if Exists(select 1 from Tbl_BM_General_Delivery gd2 where gd2.IsUnSubscribed Is null)    
--Begin    
    
--update Tbl_BM_General_Delivery set IsUnSubscribed = 0 where isnull(IsUnSubscribed, 0) = 0 and (CountryCode + MobileNo) in (select (CountryCode + MobileNo) from tbl_BM_OptInOutMessages(nolock) where Opttype = 'In')    
--print 'Tbl_BM_General_Delivery IsUnSubscribed = 0'    
    
--update Tbl_BM_General_Delivery set IsUnSubscribed = 1 where isnull(IsUnSubscribed, 0) = 0 and (CountryCode + MobileNo) in (select (CountryCode + MobileNo) from tbl_BM_OptInOutMessages(nolock) where Opttype = 'Out')    
    
--update Tbl_BM_General_Delivery set IsUnSubscribed = 1 where isnull(IsUnSubscribed, 0) = 0 and (CountryCode + MobileNo) not in (select (CountryCode + MobileNo) from tbl_BM_OptInOutMessages(nolock) )    
--print 'Tbl_BM_General_Delivery IsUnSubscribed = 1'    
    
--End    
  
DECLARE @Counter INT , @MaxId INT  
  
SELECT distinct @Counter = min(BatchId) , @MaxId = max(BatchId)   
FROM Tbl_BM_General_Delivery_Main --where ProcessTable not in ('Tbl_BM_General_DeliveryLess' , 'Tbl_BM_General_Delivery')  
   
WHILE(@Counter IS NOT NULL  
      AND @Counter <= @MaxId)  
BEGIN  
DECLARE @ProcessTable NVARCHAR(200)  
   SELECT top 1 @ProcessTable = ProcessTable  
   FROM Tbl_BM_General_Delivery_Main WHERE BatchId = @Counter  
Declare @quiery1 nvarchar(max)  
set @quiery1 = 'update ' + @ProcessTable + ' set IsUnSubscribed = 0 where isnull(IsUnSubscribed, 0) = 0 and MobileNo in (select isnull((CountryCode + MobileNo),0) from tbl_BM_OptInOutMessages(nolock) where Opttype = ''In'') '    
  
exec sp_executesql @quiery1  
  
Declare @quiery2 nvarchar(max)  
set @quiery2 = 'update ' + @ProcessTable + ' set IsUnSubscribed = 1 where isnull(IsUnSubscribed, 0) = 0 and MobileNo in (select isnull((CountryCode + MobileNo),0) from tbl_BM_OptInOutMessages(nolock) where Opttype = ''Out'') '   
exec sp_executesql @quiery2  
  
    
Declare @quiery3 nvarchar(max)  
set @quiery3 = 'update ' + @ProcessTable + ' set IsUnSubscribed = 0 where isnull(IsUnSubscribed, 0) = 0 and MobileNo not in (select isnull((CountryCode + MobileNo),0) from tbl_BM_OptInOutMessages(nolock)) '   
  
exec sp_executesql @quiery3  
  
update Tbl_BM_General_Delivery_Main set ProcessStartTime = getDate() where Batchid = @Counter  
     
 SET @Counter = @Counter  + 1          
End  
End    
End



GO

/* ============================================================
   Procedure: [dbo].[usp_Tbl_BM_General_Delivery_Main]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_Tbl_BM_General_Delivery_Main]          
(        
@Mode varchar(2),        
@BatchID bigint = null,              
@TotalRecords bigint = null,              
@UserID bigint = null        
)        
as                 
Begin            
If(@Mode = 'I')          
Begin          
        
Declare @ParentId bigint         
        
--Declare @MsgHistoryID bigint              
--Declare @Agent_ID bigint              
--select @Agent_ID = AgentId from tbl_BM_AgentMaster(nolock) where ParentId = @ParentId              
--Declare @Revoke_Limit int              
--select @Revoke_Limit = (isnull(defaultcutofflimit, 1) *              
--(Case when isnull(defaultcutoffType, 'Hour') = 'Days' then 24              
--else 1              
--End)) from tbl_BM_AgentMaster(nolock) where ParentId = @ParentId              
            
Declare @CostDeducted numeric(18,4)            
            
set @CostDeducted = (select top 1 Isnull(Price, 1) * @TotalRecords from tbl_BM_PriceMaster(nolock))            
            
--update BatchInfo set TotalRecords = @TotalRecords, CostDeducted = @CostDeducted where BatchID = @BatchID and USERID = @ParentId            
            
 declare @Price decimal(18,4), @Cost decimal(18,4),                   
 @mCount int, @TotalBalance decimal(18, 4), @MId int, @Remarks varchar(100)                  
          
-- declare @Pulse decimal(18,4),@TPrice decimal(18,4),@words int,@isunicode int=0             
            
 select @ParentId = ParentID, @MId = M_ID from User_Detail(nolock) where User_ID = @UserId                  
 select top 1 @Price = Price from [dbo].[tbl_BM_PriceMaster](nolock)               
 where isnull(parentid, 0) in (0,@parentid) order by parentid desc                
 set @Cost = (cast(@TotalRecords as numeric(18, 4)) * @Price)           
 set @Remarks = 'RCS Business Message Batch: '+ Cast(@BatchID as varchar(50))+' Cost '+cast(@Cost as varchar(50));            
            
 exec proc_UpdateIntCreditDetail_new @M_ID = @MId,                  
   @User_ID = @parentid,                  
   @Price = @Cost,                  
   @BATCHID = @BatchID,                  
   @remark = @Remarks,                  
   @typecredit = 14                  
        
-- Main Table 
declare @json nvarchar(max)=(select top 1 JSONMsgContent from Tbl_BM_General_MessageHistory(nolock) where BatchID = @BatchID)
 declare @cdate datetime,@sdate datetime
 select @cdate=min(createddate),@sdate=min(scheduleddatetime) from Tbl_BM_General_MessageHistory(nolock) where BatchID = @BatchID
insert into Tbl_BM_General_Delivery_Main (UserID, BatchID, MsgHistoryID, AgentId, TotalRecords, IsPrority, ScheduledDateTime,     
IsUniCode, IsMultimediaMsg, CreatedBy, CreatedDate, IsActive, Source, Status, RevokeLimit, CostDeducted, BMTemplateId, JSONMsgContent)        
        
select UserID, BatchID, 0, AgentId, count(1), IsPrority, @cdate, IsUniCode, IsMultimediaMsg,     
CreatedBy,@cdate, 1, SourceName, Status, RevokeLimit, @CostDeducted, BMTemplateId, JSONMsgContent     
from Tbl_BM_General_MessageHistory m(nolock) where BatchID = @BatchID 
and not exists (select 1 from Tbl_BM_General_Delivery_Main(nolock) where batchid= m.batchid)
group by 
UserID, BatchID,AgentId, IsPrority, IsUniCode, IsMultimediaMsg,     
CreatedBy,SourceName, Status, RevokeLimit,BMTemplateId, JSONMsgContent 

--or MsgHistoryID > (select  isnull(Max(MsgHistoryID), 0) from Tbl_BM_General_Delivery_Main(nolock))        
        
--delete Tbl_BM_JsonUpload where BatchID = @BatchID          
  
End          
  select 'Updated Successfully' status            
End



