 select top(@PageSize) Id, ParentId, MobileNo, CountryCode, SourceName, TableName, ColumnId, ColumnName, MsgContent, AgentId, IsProcessed,         
 isnull(StatusId,0) StatusId, isnull(StatusDesc, '') , '' [Message] From Tbl_BM_General_Delivery (nolock)       
 Where (id % 2 = 0) and isnull(IsProcessed, 0) = @IsProcessed and (Isnull(ScheduleDateTime, GETDATE()) <= GETDATE())      
END  
End



