   Procedure: [dbo].[usp_Tbl_BM_General_MessageProcessing_Delete]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_Tbl_BM_General_MessageProcessing_Delete]  
as
Begin

Delete Tbl_BM_General_MessageProcessing where (StatusId = 5 or StatusId < 0 or MsgHistoryID = (select distinct MsgHistoryID from Tbl_BM_General_MessageProcessingDump(nolock)))

UPDATE Tbl_BM_General_MessageHistory  
SET MessageId = t2.MessageId,  
IsRCMEnabled = t2.IsRCMEnabled
FROM Tbl_BM_General_MessageHistory t1  
INNER JOIN Tbl_BM_General_MessageProcessingDump t2 ON t1.MsgHistoryID = t2.MsgHistoryID  


select distinct * FROM Tbl_BM_General_MessageHistory t1  
INNER JOIN Tbl_BM_General_MessageProcessingDump t2 ON t1.MsgHistoryID = t2.MsgHistoryID  

 select 'Deleted Successfully' status    
End



GO

/* ============================================================
   Procedure: [dbo].[usp_Tbl_BM_General_MessageProcessing_RCSUpdate]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_Tbl_BM_General_MessageProcessing_RCSUpdate]    
(    
@Mode varchar(2),      
@MobileNo varchar(25) = null,      
@StatusId int,      
@StatusDesc varchar(100),      
@IsRCMEnabled bit,    
@RowData nvarchar(4000) = null    
)      
as             
Begin        
If(@Mode = 'U')      
Begin      
if(@RowData != '')    
Begin    
if(@StatusId < 0)    
Begin    
  -- Update Tbl_BM_General_MessageProcessing Table    
    
update Tbl_BM_General_MessageProcessing set     
IsRCMEnabled = @IsRCMEnabled, StatusId = @StatusId, StatusDesc = @StatusDesc, ProcessEndTime = GETDATE(),    
IsActive = 0    
where isnull(IsRCMEnabled, 0) = 0 and  isnull(StatusId, 0) = 0     
and MobileNo in (SELECT value FROM OPENJSON(@RowData))    
    
  -- Update Tbl_BM_General_MessageHistory Table    
    
 update Tbl_BM_General_MessageHistory set Status = 0, IsRCMEnabled = @IsRCMEnabled    
 where isnull(IsRCMEnabled, 0) = 0 and MobileNo in (SELECT value    
 FROM OPENJSON(@RowData))    
    
 -- Update Tbl_BM_General_MessageProcessingDump Table    
-- insert Tbl_BM_General_MessageProcessingDump (MsgProcessID, UserID, BatchID ,MsgHistoryID, MobileNo, CountryCode, SourceName, MsgContent, BMTemplateId, JSONMsgContent, MessageId, IsPrority, ProcessStartTime, ProcessEndTime, ScheduledDateTime, IsUniCode,IsMultimediaMsg,  CreatedBy, CreatedDate, Source, StatusId, StatusDesc,IsActive,RevokeLimit, IsRCMEnabled,IsUnSubscribed)    
    
--select MsgProcessID, UserID, BatchID ,MsgHistoryID, MobileNo, CountryCode, SourceName, MsgContent, BMTemplateId, JSONMsgContent, MessageId, IsPrority, ProcessStartTime, ProcessEndTime, ScheduledDateTime, IsUniCode, IsMultimediaMsg, CreatedBy, CreatedDate, Source, StatusId, StatusDesc, IsActive, 5, IsRCMEnabled, IsUnSubscribed    
-- from Tbl_BM_General_MessageProcessing(nolock) where StatusId < 0 and IsRCMEnabled = 0  and MobileNo=@MobileNo  
    
  select 'Updated Successfully' status        
End    
if(@StatusId > 0)    
Begin    
update Tbl_BM_General_MessageProcessing set     
IsRCMEnabled = @IsRCMEnabled, StatusId = @StatusId, StatusDesc = @StatusDesc, IsActive = 1    
where isnull(IsRCMEnabled, 0) = 0 and  isnull(StatusId, 0) = 0     
and MobileNo in (SELECT value    
 FROM OPENJSON(@RowData))    
    
 update Tbl_BM_General_MessageHistory set Status = 1, IsRCMEnabled = @IsRCMEnabled    
 where isnull(IsRCMEnabled, 0) = 0 and MobileNo in (SELECT value    
 FROM OPENJSON(@RowData))    
    
  select 'Updated Successfully' status        
End    
 End    
    
if(@MobileNo != '')    
Begin    
  update Tbl_BM_General_MessageProcessing set     
IsRCMEnabled = @IsRCMEnabled, StatusId = @StatusId, StatusDesc = @StatusDesc    
where MobileNo = @MobileNo and isnull(IsRCMEnabled, 0) = 0 and  isnull(StatusId, 0) = 0     
  select 'Updated Successfully' status        
End    
    
End      
End



GO

