CREATE   PROC [dbo].[usp_Tbl_BM_JsonUpload_Search_WS]                  
(      
 @BucketId int = 1,  
 @BucketSize int = 4,  
 @PageSize int=20            
)                    
AS                    
  SET NOCOUNT ON               
  BEGIN TRY               
BEGIN                    
 drop table if exists #temp

 select top(@PageSize) RowID, UserID, BatchID, JsonContent, ParentId, CreatedBy, CreatedDate, IsActive      
 into #temp
 from Tbl_BM_JsonUpload(nolock) 
 where (RowID % @BucketSize) = @BucketId and  
 IsActive = 1 and (Isnull(CreatedDate, GETDATE()) <= GETDATE())                

 update A Set A.Isactive=0
 From Tbl_BM_JsonUpload A inner join #temp B
 on A.RowID=B.RowID

 select * from #temp

End       
 END TRY                          
BEGIN CATCH                          
               
 DECLARE @ErrorMessage NVARCHAR(4000);                          
 SELECT @ErrorMessage = ERROR_MESSAGE();                          
 RAISERROR (@ErrorMessage, 16, 1);                          
END CATCH



