   Procedure: [dbo].[usp_tbl_BM_OptInOutMessages]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_tbl_BM_OptInOutMessages]         
(
   @AgentId bigint,     
   @countryCode [varchar](10) NULL,    
   @MobileNo [varchar](15) NULL,    
   @Opttype [varchar](3) NULL,    
   @OptStatus [bit] NULL,    
   @MessageId varchar(100) NULL,    
   @Remarks varchar(1000) = null         
)    
as         
Begin    
if Exists(select 1 from tbl_BM_OptInOutMessages where MobileNo = @MobileNo and countryCode = @CountryCode and AgentId = @AgentId)
Begin
  Update tbl_BM_OptInOutMessages set AgentId = @AgentId, Opttype = @Opttype, OptStatus = @OptStatus, OptDate = GETDATE(), MessageId = @MessageId, Remarks = @Remarks
  where countryCode = @countryCode and MobileNo = @MobileNo

  select 'Saved Successfully'
End
Else
Begin
  insert into tbl_BM_OptInOutMessages (AgentId, countryCode, MobileNo, Opttype, OptStatus, OptDate, MessageId, Remarks)     
  values(@AgentId, @countryCode, @MobileNo, @Opttype, @OptStatus, GETDATE(), @MessageId, @Remarks)        

  select 'Saved Successfully'
End

  if(@Opttype = 'In')
  Begin
  Update Mysms_Dev..Tbl_BM_General_Delivery set IsSubscribed = 0, LastProcessedOn = GETDATE() where MobileNo = @mobileNo
  End
  else
  Begin
  Update Mysms_Dev..Tbl_BM_General_Delivery set IsSubscribed = 1, LastProcessedOn = GETDATE() where MobileNo = @mobileNo
  End
  select 'Saved Successfully'

End




GO

