CREATE   PROCEDURE [dbo].[usp_Tbl_BM_OptInOutMessages_IsUnSubscribed](        
 @Mode varchar(2),        
 @MobileNo bigint, 
 @CountryCode bigint
)
as        
begin        
 if(@Mode = 'S')
Begin
Declare @IsUnSubscribed bit
Declare @id bigint
if Exists(select id from tbl_BM_OptInOutMessages(nolock) where MobileNo = @MobileNo and countryCode = @CountryCode)
Begin
select @id = id from tbl_BM_OptInOutMessages(nolock) where MobileNo = @MobileNo and countryCode = @CountryCode order by id desc

if Exists(select * from tbl_BM_OptInOutMessages where  id = @id and Opttype = 'In')
Begin
set @IsUnSubscribed = 0
End
else
Begin
set @IsUnSubscribed = 1
End
End
else
Begin
set @IsUnSubscribed = 1
End
end
end



