/* ============================================================
   Procedure: [dbo].[usp_TBL_CL_UserChat_Save]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--usp_TBL_CL_UserChatPermission_Save 'BS', 0, 'Branch Kit19', 34594, '9911001100', 'newemail@gmail.com','27.11222', '77.00999','Addressss', 'New Delhi', 'delhi', 'India', '110085', 34594, 1
CREATE   PROCEDURE [dbo].[usp_TBL_CL_UserChat_Save] (
@Mode VARCHAR(2),
@ChatId bigint = 0,
@LabelNames nvarchar(300) = '',
@IsPin bit = false,
@ChatTransactionList nvarchar(max) = '',
@ChatMsg nvarchar(max) = '',
@AttachFileName nvarchar(300) = '',
@FileType nvarchar(20) = '',
@SendDate datetime = null,
@ParentId bigint = 0,
@CreatedBy bigint = 0,
@IsActive bit = false
)
AS
SET NOCOUNT ON

BEGIN TRY

IF (@Mode = 'CI') /*This is for Insert Details */
	BEGIN
	if(not Exists(Select 1 from TBL_CL_UserChat(nolock) ucpe Where ucpe.ParentId = @ParentId and ucpe.LabelNames = @LabelNames))
	Begin
	insert into TBL_CL_UserChat(LabelNames, IsPin, ChatMsg, ParentId, CreatedBy, CreatedDate, IsActive)
								   Values(@LabelNames, @IsPin, @ChatMsg, @ParentId, @CreatedBy, GetDate(), @IsActive)

	Declare @Id bigint
	Set @Id = SCOPE_IDENTITY()

	insert into TBL_CL_ChatTransaction(ChatId, SenderId, ReceiverId, TypeOfEntity, EntityId, SendDate, ParentId, CreatedBy, CreatedDate, IsActive)
	select @Id, SenderId, ReceiverId, TypeOfEntity, EntityId, @SendDate, @ParentId, @CreatedBy, GETDATE(), @IsActive from openjson(@ChatTransactionList)
	with 
	(
	 SenderId bigint '$.SenderId',                  
	 ReceiverId bigint '$.ReceiverId',                  
	 TypeOfEntity varchar(30) '$.TypeOfEntity',
	 EntityId bigint '$.EntityId'
	) tF

	insert into TBL_CL_UserChatAttachment(ChatId, AttachFileName, FileType, ParentId, CreatedBy, CreatedDate, IsActive)
	values (@Id, @AttachFileName, @FileType, @ParentId, @CreatedBy, GETDATE(), @IsActive)
			
	  Select 'Saved Record' Status, @Id ChatId
	End
	Else
	Begin
		Select 'Record Already Exist' Status
	End
	End
Else IF (@Mode = 'CU') /*This is for Insert Details */
	BEGIN
	if(Exists(Select 1 from TBL_CL_UserChat(nolock) ucpe Where ucpe.ParentId = @ParentId and ucpe.ChatId = @ChatId))
	Begin
	update TBL_CL_UserChat set LabelNames = @LabelNames, IsPin = @IsPin, ChatMsg = @ChatMsg, UpdatedBy = @CreatedBy, UpdatedDate = GetDate(), IsActive = @IsActive where ChatId = @ChatId

	update TBL_CL_ChatTransaction set IsActive = 0 where ChatId = @ChatId and ParentId = @ParentId 
	--and ReceiverId not in (select ReceiverId from openjson(@ChatTransactionList)
	--with 
	--(
	-- ReceiverId bigint '$.ReceiverId'
	--) tF
	--)

	insert into TBL_CL_ChatTransaction(ChatId, SenderId, ReceiverId, TypeOfEntity, EntityId, SendDate, ParentId, CreatedBy, CreatedDate, IsActive)
	select @ChatId, SenderId, ReceiverId, TypeOfEntity, EntityId, @SendDate, @ParentId, @CreatedBy, GETDATE(), @IsActive from openjson(@ChatTransactionList)
	with 
	(
	 SenderId bigint '$.SenderId',                  
	 ReceiverId bigint '$.ReceiverId',                  
	 TypeOfEntity varchar(30) '$.TypeOfEntity',
	 EntityId bigint '$.EntityId'
	) tF

	update TBL_CL_UserChatAttachment set IsActive = 0 where ChatId = @ChatId and ParentId = @ParentId 

	insert into TBL_CL_UserChatAttachment(ChatId, AttachFileName, FileType, ParentId, CreatedBy, CreatedDate, IsActive)
	values (@Id, @AttachFileName, @FileType, @ParentId, @CreatedBy, GETDATE(), @IsActive)


	Select 'Updated Record' Status, @ChatId Id
	
	End
	Else
	Begin
		Select 'Record not Exist' Status, @ChatId Id
	End
	End
Else IF (@Mode = 'CE') /*This is for Insert Details */
	BEGIN
    select @ParentId = ParentId from User_Detail(nolock) where User_Id = @CreatedBy

	select * from TBL_CL_UserChat(nolock) where ChatId = @ChatId

	select * from TBL_CL_ChatTransaction(nolock) where ChatId = @ChatId

	select * from TBL_CL_UserChatAttachment(nolock) where ChatId = @ChatId

	End
Else IF (@Mode = 'CD') /*This is for Insert Details */
	BEGIN
   select @ParentId = ParentId from User_Detail(nolock) where User_Id = @CreatedBy

	update TBL_CL_UserChat set IsDeleted = 1 where ChatId = @ChatId
	update TBL_CL_ChatTransaction set IsDeleted = 1 where ChatId = @ChatId
	update TBL_CL_UserChatAttachment set IsDeleted = 1 where ChatId = @ChatId

 Select 'Deleted Record' Status
 End
END TRY

BEGIN CATCH
	DECLARE @ErrorMessage NVARCHAR(4000);
	SELECT @ErrorMessage = ERROR_MESSAGE();
	RAISERROR (
			@ErrorMessage
			,16
			,1
			);
END CATCH



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_CL_UserChatPermission_Save]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--usp_TBL_CL_UserChatPermission_Save 'BS', 0, 'Branch Kit19', 34594, '9911001100', 'newemail@gmail.com','27.11222', '77.00999','Addressss', 'New Delhi', 'delhi', 'India', '110085', 34594, 1 
CREATE   PROCEDURE [dbo].[usp_TBL_CL_UserChatPermission_Save] (
@Mode VARCHAR(2),
@UserChatPermissionId bigint = 0,
@UserId	bigint = 0,
@View bit = false,
@Create bit	= false,
@Edit bit = false,
@Delete bit	= false,
@CreateGroup bit = false,
@ParentId bigint = 0,
@CreatedBy bigint = 0,
@IsActive bit = false
)
AS
SET NOCOUNT ON

BEGIN TRY
IF (@Mode = 'PI') /*This is for Insert Details */
	BEGIN
	if(not Exists(Select 1 from TBL_CL_UserChatPermission(nolock) ucpe Where ucpe.ParentId = @ParentId and ucpe.UserId = @UserId))
	Begin
	insert into TBL_CL_UserChatPermission(UserId, [View], [Create], Edit, [Delete], CreateGroup, ParentId, CreatedBy, CreatedDate, IsActive)
								   Values(@UserId, @View, @Create, @Edit, @Delete, @CreateGroup, @ParentId, @CreatedBy, GetDate(), @IsActive)
		
		Select 'Saved Record' Status, SCOPE_IDENTITY() Id
	End
	Else
	Begin
		Select 'Record Already Exist' Status
	End
	End
Else IF (@Mode = 'PU') /*This is for Insert Details */
	BEGIN
	if(Exists(Select 1 from TBL_CL_UserChatPermission(nolock) ucpe Where ucpe.ParentId = @ParentId and ucpe.UserId = @UserId))
	Begin
	update TBL_CL_UserChatPermission set UserId = @UserId, [View] = @View, [Create] = @Create, Edit = @Edit, [Delete] = @Delete, CreateGroup = @CreateGroup, UpdatedBy = @CreatedBy, UpdatedDate = GetDate(), IsActive = @IsActive where UserChatPermissionId = @UserChatPermissionId
	  
	  Select 'Updated Record' Status, @UserChatPermissionId Id
	End
	Else
	Begin
		Select 'Record not Exist' Status, @UserChatPermissionId Id
	End
	End
Else IF (@Mode = 'PE') /*This is for Insert Details */
	BEGIN
	Select UserChatPermissionId, UserId, [View], [Create] ,Edit, [Delete], CreateGroup, Check1, Check2, Check3, Check4, Check5, ParentId, CreatedDate, CreatedBy, UpdatedDate, UpdatedBy, IsActive from TBL_CL_UserChatPermission(nolock) 
	where UserChatPermissionId = @UserChatPermissionId
	End
Else IF (@Mode = 'PD') /*This is for Insert Details */
	BEGIN
	update TBL_CL_UserChatPermission  set IsActive = @IsActive where UserChatPermissionId = @UserChatPermissionId
 Select 'Deleted Record' Status
 End
END TRY

BEGIN CATCH
	DECLARE @ErrorMessage NVARCHAR(4000);
	SELECT @ErrorMessage = ERROR_MESSAGE();
	RAISERROR (
			@ErrorMessage
			,16
			,1
			);
END CATCH



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_CL_UserChatPermission_Search]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_TBL_CL_UserChatPermission_Search] (
@Mode VARCHAR(2),
@UserChatPermissionId bigint = 0,
@SearchText varchar(100) = '',
@Contain varchar(100) = '',
@CreatedBy bigint = 0,
@Offset int = 0,
@PageSize int = 10
)
AS
SET NOCOUNT ON

BEGIN TRY
IF (@Mode = 'PL') /*This is for Insert Details */
	BEGIN

Declare @UserIdTeamLst nvarchar(max)
	
select @UserIdTeamLst = UserIdTeamLst from ufn_GetUserRoleScope(@CreatedBy)  
	
Declare @query nvarchar(max) 
set @query = 'Select count(ucp.UserChatPermissionId) over() as TotalRecords, ucp.UserChatPermissionId, ucp.UserId, FName + '' '' + LName + ''('' + ude.User_Login + '')'' UserName, [View], [Create], Edit, [Delete], CreateGroup, 
 ucp.ParentId, ucp.CreatedDate, ucp.CreatedBy, isnull(ucp.UpdatedDate, ucp.CreatedDate) UpdatedDate, isnull(ucp.UpdatedBy, ucp.CreatedBy) UpdatedBy, ucp.IsActive, ucp.UserId, FName + '' '' + LName + ''('' + ude.User_Login + '')'' CreatedByName
 , case when ucp.IsActive = 1 then ''Active'' else ''InActive'' End Status
 from TBL_CL_UserChatPermission(nolock) ucp
 inner join User_Detail (nolock)  ude on ucp.UserId = ude.User_Id 
 where ucp.UserId in (select item from dbo.fu_SplitString(''' + cast(@UserIdTeamLst as varchar(1000)) + ''', '','')) and ude.FName +'' ''+ LName +''('' + ude.User_Login + '')'' like ''%'+ @SearchText +'%''
 Order By ucp.UserChatPermissionId Desc  
 Offset '+ cast(@Offset as varchar(10)) + ' rows fetch next '+ cast(@PageSize as varchar(10)) + ' rows only '  

 print @query 
 execute sp_executesql @query  

 End
END TRY

BEGIN CATCH
	DECLARE @ErrorMessage NVARCHAR(4000);
	SELECT @ErrorMessage = ERROR_MESSAGE();
	RAISERROR (
			@ErrorMessage
			,16
			,1
			);
END CATCH



GO

