  -- Exec usp_tbl_ET_Attendance @Mode='SI', @AttendanceId=0, @UserId=32222, @AttendanceIn='10-Aug-2023 10:25:25',@AttendanceOut=null,@LatitudeIn=21.2128431,@LongitudeIn=72.8232869,@DeviceId='dSrR-yO0SESaA8ebrYvEv8:APA91bGahFPO2U8oXWdVenPqVLYk3Jip-GW59lkfKHzVXHUmPLjAOZ6ztor1phQInKfEn4kH0PNZjjPgNeTpl20h33gTNDIikQE4G8B0qgrH7ns5hCYDyUv4e0gbONGI7wEBwwYP7VN-',@RemarksIn=''
CREATE   PROCEDURE [dbo].[usp_tbl_ET_Attendance]  
 (      
  @Mode VARCHAR(2),
  @AttendanceId BIGINT = 0,
  @UserId BIGINT = 0,
  @AttendanceIn DateTime = NULL,
  @AttendanceOut DateTime = NULL,
  @LatitudeIn float = NULL,
  @LongitudeIn float = NULL,
  @LatitudeOut float = NULL,
  @LongitudeOut float = NULL,
  @Address nvarchar(500) = NULL,
  @DeviceId VARCHAR(500) = NULL,
  @RemarksIn VARCHAR(500) = NULL,
  @RemarksOut VARCHAR(500) = NULL,
  @AttendanceGroupId BIGINT = 0,
  @ShiftId BIGINT = 0,
  @CreatedBy BIGINT = 0,
  @IsActive bit = 1,
  @LocationMetaData NVARCHAR(MAX) = NULL
 )      
AS      
SET NOCOUNT ON      
      
BEGIN TRY      
  
  --DECLARE 
	 -- @Mode VARCHAR(2),
	 -- @AttendanceId BIGINT = 0,
	 -- @UserId BIGINT = 0,
	 -- @AttendanceIn DateTime = NULL,
	 -- @AttendanceOut DateTime = NULL,
	 -- @LatitudeIn float = NULL,
	 -- @LongitudeIn float = NULL,
	 -- @LatitudeOut float = NULL,
	 -- @LongitudeOut float = NULL,
	 -- @Address nvarchar(500) = NULL,
	 -- @DeviceId VARCHAR(500) = NULL,
	 -- @RemarksIn VARCHAR(500) = NULL,
	 -- @RemarksOut VARCHAR(500) = NULL,
	 -- @AttendanceGroupId BIGINT = 0,
	 -- @ShiftId BIGINT = 0,
	 -- @CreatedBy BIGINT = 0,
	 -- @IsActive bit = 1      


 Declare @ShiftName varchar(100), @StartTime time, @EndTime time, @IsSignInEnabled int =0, @EventDesc NVARCHAR(MAX)=''

 IF (@Mode = 'SI') /*This is for Insert usp_tbl_ET_Attendance Details */      
 BEGIN      
 Declare @ParentId bigint, @SignInDateTime datetime
      
 --SELECT top 1 @ParentId = ParentId      
 -- FROM User_detail WITH (NOLOCK)      
 -- WHERE User_Id = @UserId      
 set @AttendanceGroupId = 0      
       
 Select top 1 @AttendanceGroupId = atgp.AttendanceGroupId, @ParentId = atgp.ParentId      
 --, atgp.AttendanceGroupName, GroupType,       
 --   isnull(SignInFormId, 0)  SignInFormId, isnull(SignOutFormId, 0) SignInFormId,       
 --isnull(SignInType, '') SignInType, isnull(SignOutType, '') SignOutType, isnull(SignInPromptType, '') SignInPromptType,       
 --isnull(SignOutPromptType, '') SignOutPromptType,       
 --(case when isnull(agum.UserId, 0) = 0 then isnull(DefaultUserId, 0) else isnull(agum.UserId, 0) end) UserId,       
 --(case when isnull(agum.GeoRestriction, '') = '' then isnull(DefaultGeoRestriction, '') else isnull(agum.GeoRestriction, '') End)      
 --GeoRestrictionChild,       
 --(case when isnull(agum.AuthType, '') = '' then isnull(DefaultAuthType, '') else isnull(agum.AuthType, '') end) AuthTypeChild,       
 --(case when isnull(agum.AttendanceCalcType, '') = '' then isnull(DefaultAttendanceCalcType, '')      
 --    else isnull(agum.AttendanceCalcType, '') end) AttendanceCalcType,       
 --(case when isnull(agum.UserAutoSignIn, '') = '' then isnull(DefaultAutoSignIn, '')      
 --    else isnull(agum.UserAutoSignIn, '') end) UserAutoSignIn,       
 --(case when isnull(agum.UserAutoSignOut, '') = '' then isnull(DefaultAutoSignOut, '')      
 --    else isnull(agum.UserAutoSignOut, '') end) UserAutoSignOut,       
 --isnull(AllowedAttendanceOverride, 0) AllowedAttendanceOverride,       
 --   isnull(AttendaceApprover, 0) AttendeceApprover, isnull(SignInRange, 0) SignInRange, isnull(SignOutRange, 0) SignOutRange      
 from TBL_ET_AttendanceGroup atgp(nolock)       
 left join TBL_ET_AttendanceGroupUserMapping agum (nolock) on atgp.AttendanceGroupId = agum.AttendanceGroupId 
 where agum.UserId = @UserId and atgp.IsActive = 1 and agum.IsActive = 1       
      
      
 set @ShiftId = 0      
 select top 1 @ShiftId = shmr.ShiftId, @StartTime = shmr.StartTime
 from TBL_ET_ShiftMaster shmr(nolock) inner join TBL_ET_ShiftUserMapping suma (nolock) 
 on shmr.ShiftId = suma.ShiftId and shmr.IsActive = 1      
 Where suma.UserId = @UserId      

 if(@ShiftId=0)
 Begin
	select @ShiftId=SMR.ShiftId, @StartTime = SMR.StartTime
	From TBL_ET_AttendanceGroup(nolock) AG inner join TBL_ET_ShiftMaster(nolock) SMR
	on AG.RosterId=SMR.ShiftId and SMR.IsActive=1
	Where AG.AttendanceGroupId=@AttendanceGroupId
 End
       
 DECLARE @ID BIGINT;      
      
 if((@AttendanceGroupId > 0) and (@ShiftId > 0))      
 Begin      
 --IF NOT EXISTS (      
 -- SELECT * FROM TBL_ET_Attendance WITH (NOLOCK) WHERE cast(AttendanceIn as Date) = Cast(@AttendanceIn as Date) AND ParentId = @ParentId and UserId = @UserId      
 --  )      
 -- BEGIN      
   INSERT INTO TBL_ET_Attendance ( UserId, AttendanceIn, LatitudeIn, LongitudeIn, DeviceId, RemarksIn, RemarksOut, 
		AttendanceGroupId, ShiftId, ParentId, IsActive, CreatedBy, CreatedDate )      
   VALUES (@UserId, @AttendanceIn, @LatitudeIn, @LongitudeIn, @DeviceId, @RemarksIn, @RemarksOut, 
		@AttendanceGroupId, @ShiftId, @ParentId, @IsActive, @UserId, GETDATE() )      
      
   SET @ID = scope_identity();      
   
   select @SignInDateTime=DATEADD(day, DATEDIFF(day, 0, cast(@AttendanceIn as date)), left(@StartTime,8))

   exec usp_et_InsertSingleMovementCodeInternal 
		@MovementCode = 'SIGN_IN', @Latitude = @LatitudeIn, @Longitude = @LongitudeIn, @Address = @Address, @LocationDateTime = @AttendanceIn,
		@AttendanceId = @ID, @PhysicalAppointmentId = null, @BreakTransactionId = null, @DeviceId = @DeviceId, @UserId = @UserId
   
   If(@SignInDateTime <  @AttendanceIn) -- Late SignIn
   Begin
		Select @EventDesc=replace(replace(AM.EventTemplate,'#username#',dbo.fn_getentityfullname('user',@UserId)),'#signintime#',format(@AttendanceIn,'dd-MMM-yyyy hh:mm tt'))
		from ActivityMaster(Nolock) AM
		Where AM.EventName='User Signed In late'

		Exec UspSaveEntityActivity_withid @entityname='User',@EntityID=0,@UserID=@UserId,@ParentID=@ParentId,@EventDescription=@EventDesc,@EventName='User Signed In late',@reftables='TBL_ET_Attendance',@refid=@ID
   End
   Else	-- Normal Sign In
   Begin
		Select @EventDesc=replace(replace(AM.EventTemplate,'#username#',dbo.fn_getentityfullname('user',@UserId)),'#signintime#',format(@AttendanceIn,'dd-MMM-yyyy hh:mm tt'))
		from ActivityMaster(Nolock) AM
		Where AM.EventName='User signed in'

		Exec UspSaveEntityActivity_withid @entityname='User',@EntityID=0,@UserID=@UserId,@ParentID=@ParentId,@EventDescription=@EventDesc,@EventName='User Signed In',@reftables='TBL_ET_Attendance',@refid=@ID
   End
   
   End      
   SELECT 'Record Saved' STATUS, @ID AttendeceId      
      
 Select top 1 atgp.AttendanceGroupId, atgp.AttendanceGroupName, GroupType, atgp.ParentId, isnull(SignInFormId, 0) SignInFormId, isnull(SignOutFormId, 0) SignInFormId, isnull(atgp.DefaultGeoRestrictionIn, '') GeoRestrictionIn, isnull(atgp.DefaultAuthTypeIn, '') AuthTypeIn, isnull(atgp.DefaultGeoRestrictionOut, '') GeoRestrictionOut, isnull(atgp.DefaultAuthTypeOut, '') AuthTypeOut, isnull(SignInType, '') SignInType, isnull(SignOutType, '') SignOutType, isnull(SignInPromptType, '') SignInPromptType, isnull(SignOutPromptType, '') SignOutPromptType, DefaultGeoRestrictionIn, DefaultGeoRestrictionOut, isnull(aggr.TrackLocationInterval, 60) TrackLocationInterval, DefaultAuthTypeIn, DefaultAuthTypeOut, isnull(agum.UserId, 0) UserId, isnull(agum.GeoRestriction, '') GeoRestrictionChild, isnull(agum.AuthType, '') AuthTypeChild, isnull(agum.AttendanceCalcType, '') AttendanceCalcType, (case when isnull(agum.AttendanceCalcType, '') = '' then isnull(DefaultAttendanceCalcType, '') else isnull(agum.AttendanceCalcType, '') end) AttendanceCalcType, isnull(AllowedAttendanceOverride, 0) AllowedAttendanceOverride, isnull(AttendaceApprover, 0) AttendeceApprover, isnull(atgp.SignInRange, 0) SignInRange, isnull(atgp.SignOutRange, 0) SignOutRange     
 from TBL_ET_AttendanceGroup atgp(nolock) left join TBL_ET_AttendanceGroupUserMapping agum (nolock)   
 on atgp.AttendanceGroupId = agum.AttendanceGroupId left join TBL_ET_AttendanceGroupGeoRestriction (nolock) aggr  
 on atgp.AttendanceGroupId = aggr.AttGroupId and aggr.IsActive = 1      
 where atgp.ParentId = @ParentId and agum.UserId = @UserId and atgp.IsActive = 1 and agum.IsActive = 1      
      
  --END      
  --ELSE      
  --BEGIN      
  -- SELECT 'Record Already Exist' STATUS      
  --END      
 END /*End here for insert*/      
 Else IF (@Mode = 'SO') /*This is for Update/ Signout  usp_tbl_ET_Attendance Details */      
 BEGIN      
 Declare @ParentId2 bigint, @SignOutDateTime datetime, @ShiftDiff time(0), @AttInOutDiff time(0)
  SELECT top 1 @ParentId2 = ParentId FROM User_detail WITH (NOLOCK) WHERE User_Id = @UserId      
 set @AttendanceGroupId = 0      
 Select top 1 @AttendanceGroupId = atgp.AttendanceGroupId from TBL_ET_AttendanceGroup atgp(nolock)       
   left join TBL_ET_AttendanceGroupUserMapping agum (nolock) on atgp.AttendanceGroupId = agum.AttendanceGroupId  
   where atgp.ParentId = @ParentId2 and (agum.UserId = @UserId) and atgp.IsActive = 1      
       
 set @ShiftId = 0      
 select top 1 @ShiftId = shmr.ShiftId, @StartTime=shmr.StartTime, @EndTime = shmr.EndTime 
 from TBL_ET_ShiftMaster shmr(nolock)inner join TBL_ET_ShiftUserMapping suma (nolock) 
 on shmr.ShiftId = suma.ShiftId and shmr.IsActive = 1       
 Where suma.UserId = @UserId       

 if(@ShiftId=0)
 Begin
	select @ShiftId=SMR.ShiftId, @StartTime=SMR.StartTime, @EndTime = SMR.EndTime 
	From TBL_ET_AttendanceGroup(nolock) AG inner join TBL_ET_ShiftMaster(nolock) SMR
	on AG.RosterId=SMR.ShiftId and SMR.IsActive=1
	Where AG.AttendanceGroupId=@AttendanceGroupId
 End

 select @SignOutDateTime=DATEADD(day, DATEDIFF(day, 0, cast(@AttendanceOut as date)), left(@EndTime,8))
 select @ShiftDiff=cast(DATEADD(SS,DATEDIFF(ss,cast(@StartTime as time(0)),cast(@EndTime as time(0))),0) as time(0))
      
 IF EXISTS (SELECT top 1 * FROM TBL_ET_Attendance WITH (NOLOCK) WHERE cast(AttendanceIn as Date) = Cast(@AttendanceOut as Date) AND ParentId = @ParentId2 and UserId = @UserId)      
 BEGIN      
	Update TBL_ET_Attendance Set  AttendanceOut = @AttendanceOut, LatitudeOut = @LatitudeOut, LongitudeOut = @LongitudeOut, RemarksOut = @DeviceId + ' ' + RemarksOut, UpdatedBy = @UserId, UpdatedDate = GETDATE(), @AttendanceId = AttendanceId, @AttendanceIn=AttendanceIn
    where UserId = @UserId and  isnull(AttendanceOut, '') = ''
		and cast(AttendanceIn as Date) = Cast(@AttendanceOut as Date)      
		
	exec usp_et_InsertSingleMovementCodeInternal 
		@MovementCode = 'SIGN_OUT', @Latitude = @LatitudeOut, @Longitude = @LongitudeOut, @Address = @Address, @LocationDateTime = @AttendanceOut,
		@AttendanceId = @AttendanceId, @PhysicalAppointmentId = null, @BreakTransactionId = null, @DeviceId = @DeviceId, @UserId = @UserId
      
	SELECT 'Record Updated' STATUS      
 
	select @AttInOutDiff=cast(DATEADD(SS, DATEDIFF(ss, @AttendanceIn, @AttendanceOut), 0) as time(0))

	If(@SignOutDateTime >  @AttendanceOut) -- Early SignOut
	Begin
		Select @EventDesc=replace(replace(AM.EventTemplate,'#username#',dbo.fn_getentityfullname('user',@UserId)),'#signouttime#',format(@AttendanceIn,'dd-MMM-yyyy hh:mm tt'))
		from ActivityMaster(Nolock) AM
		Where AM.EventName='User Signed Out early'

		Exec UspSaveEntityActivity_withid @entityname='User',@EntityID=0,@UserID=@UserId,@ParentID=@ParentId,@EventDescription=@EventDesc,@EventName='User Signed Out early',@reftables='TBL_ET_Attendance',@refid=@AttendanceId
	End
	Else	-- Normal Sign Out
	Begin
		Select @EventDesc=replace(replace(AM.EventTemplate,'#username#',dbo.fn_getentityfullname('user',@UserId)),'#signouttime#',format(@AttendanceIn,'dd-MMM-yyyy hh:mm tt'))
		from ActivityMaster(Nolock) AM
		Where AM.EventName='User signed out'

		Exec UspSaveEntityActivity_withid @entityname='User',@EntityID=0,@UserID=@UserId,@ParentID=@ParentId,@EventDescription=@EventDesc,@EventName='User signed out',@reftables='TBL_ET_Attendance',@refid=@AttendanceId
	End

	If(@ShiftDiff > @AttInOutDiff) -- Shifttime > Att. Time
	Begin
		Select @EventDesc=replace(AM.EventTemplate,'#username#',dbo.fn_getentityfullname('user',@UserId))
		from ActivityMaster(Nolock) AM
		Where AM.EventName='User worked less than shift time'

		Exec UspSaveEntityActivity_withid @entityname='User',@EntityID=0,@UserID=@UserId,@ParentID=@ParentId,@EventDescription=@EventDesc,@EventName='User worked less than shift time',@reftables='TBL_ET_Attendance',@refid=@AttendanceId
	End
       
	Select top 1 AttendanceId, UserId, AttendanceIn, isnull(AttendanceOut, '') AttendanceOut, isnull(LatitudeIn, '') LatitudeIn, isnull(LongitudeIn, '') LongitudeIn, isnull(LatitudeOut, '') LatitudeOut, isnull(LongitudeOut, '') LongitudeOut, isnull(DeviceId, '') DeviceId, isnull(RemarksIn, '') RemarksIn, isnull(RemarksOut, '') RemarksOut, isnull(AttendanceGroupId, 0) AttendanceGroupId, isnull(ShiftId, 0) ShiftId, ParentId, CreatedDate, isnull(CreatedBy, 0) CreatedBy, isnull(UpdatedDate, '') UpdatedDate, isnull(UpdatedBy, 0) UpdatedBy, case when IsActive = 1 then 'Active' else 'Deactive' end IsActiveStatus  
	from TBL_ET_Attendance where UserId = @UserId and cast(AttendanceIn as Date) = Cast(@AttendanceOut as Date)  
  END      
  ELSE      
  BEGIN      
      
	INSERT INTO TBL_ET_Attendance(UserId, AttendanceOut, LatitudeOut, LongitudeOut, DeviceId, RemarksOut, AttendanceGroupId, 
		ShiftId, ParentId, IsActive, UpdatedBy, UpdatedDate)
	VALUES( @UserId, @AttendanceOut, @LatitudeOut, @LongitudeOut, @DeviceId, @RemarksOut, @AttendanceGroupId, 
		@ShiftId, @ParentId2, @IsActive, @UserId, GETDATE()) 

      
   DECLARE @ID2 BIGINT;      
      
   SET @ID2 = scope_identity();

    exec usp_et_InsertSingleMovementCodeInternal 
		@MovementCode = 'SIGN_IN', @Latitude = @LatitudeOut, @Longitude = @LongitudeOut, @Address = @Address, @LocationDateTime = @AttendanceOut,
		@AttendanceId = @ID2, @PhysicalAppointmentId = null, @BreakTransactionId = null, @DeviceId = @DeviceId, @UserId = @UserId

   SELECT 'Record Saved, Sign In data not Exist' STATUS, @ID2 AttendeceId      
      	  
	If(@SignOutDateTime >  @AttendanceOut) -- Early SignOut
	Begin
		Select @EventDesc=replace(replace(AM.EventTemplate,'#username#',dbo.fn_getentityfullname('user',@UserId)),'#signouttime#',format(@AttendanceIn,'dd-MMM-yyyy hh:mm tt'))
		from ActivityMaster(Nolock) AM
		Where AM.EventName='User Signed Out early'

		Exec UspSaveEntityActivity_withid @entityname='User',@EntityID=0,@UserID=@UserId,@ParentID=@ParentId,@EventDescription=@EventDesc,@EventName='User Signed Out early',@reftables='TBL_ET_Attendance',@refid=@ID2
	End
	Else	-- Normal Sign Out
	Begin
		Select @EventDesc=replace(replace(AM.EventTemplate,'#username#',dbo.fn_getentityfullname('user',@UserId)),'#signouttime#',format(@AttendanceIn,'dd-MMM-yyyy hh:mm tt'))
		from ActivityMaster(Nolock) AM
		Where AM.EventName='User signed out'

		Exec UspSaveEntityActivity_withid @entityname='User',@EntityID=0,@UserID=@UserId,@ParentID=@ParentId,@EventDescription=@EventDesc,@EventName='User signed out',@reftables='TBL_ET_Attendance',@refid=@ID2
	End

 Select top 1 AttendanceId, UserId, AttendanceIn, isnull(AttendanceOut, '') AttendanceOut, isnull(LatitudeIn, '') LatitudeIn, isnull(LongitudeIn, '') LongitudeIn, isnull(LatitudeOut, '') LatitudeOut, isnull(LongitudeOut, '') LongitudeOut, isnull(DeviceId, '') DeviceId, isnull(RemarksIn, '') RemarksIn, isnull(RemarksOut, '') RemarksOut, isnull(AttendanceGroupId, 0) AttendanceGroupId, isnull(ShiftId, 0) ShiftId, ParentId, CreatedDate, isnull(CreatedBy, 0) CreatedBy, isnull(UpdatedDate, '') UpdatedDate, isnull(UpdatedBy, 0) UpdatedBy, case when IsActive = 1 then 'Active' else 'Deactive' end IsActiveStatus  
 from TBL_ET_Attendance where UserId = @UserId and cast(AttendanceIn as Date) = Cast(@AttendanceOut as Date)      
  END      
 END /*End here for insert*/      
 Else IF (@Mode = 'SE') /*This is for Search Details */      
 BEGIN      
      
 set @AttendanceId=0  
    set @ShiftId = 0      
  
 Select top 1 @AttendanceId=isnull(atgp.AttendanceGroupId,0), @ShiftId=isnull(atgp.RosterId,0)  
 from TBL_ET_AttendanceGroup atgp(nolock) inner join TBL_ET_AttendanceGroupUserMapping agum (nolock)   
 on atgp.AttendanceGroupId = agum.AttendanceGroupId      
 where atgp.GroupType in ('Geo','Kit19') and agum.UserId = @UserId and atgp.IsActive = 1 and agum.IsActive = 1  
      
  
 select top 1 @ShiftId = isnull(shmr.ShiftId,0), @ShiftName = ShiftName, @StartTime = StartTime,   
 @EndTime = EndTime   
 from TBL_ET_ShiftMaster shmr(nolock) inner join TBL_ET_ShiftUserMapping suma (nolock)   
 on shmr.ShiftId = suma.ShiftId and shmr.IsActive = 1      
 Where suma.UserId = @UserId  
  
 if(@ShiftId=0)
 Begin
	select @ShiftId=SMR.ShiftId, @ShiftName = SMR.ShiftName, @StartTime = SMR.StartTime, @EndTime = SMR.EndTime
	From TBL_ET_AttendanceGroup(nolock) AG inner join TBL_ET_ShiftMaster(nolock) SMR
	on AG.RosterId=SMR.ShiftId and SMR.IsActive=1
	Where AG.AttendanceGroupId=@AttendanceGroupId
 End

 If(@AttendanceId > 0 and @ShiftId>0)  
 Begin  
  Set @IsSignInEnabled=1;  
 End  
  
 if Exists(Select top 1 AttendanceId from TBL_ET_Attendance atdn (nolock) where UserId = @UserId and Cast(AttendanceIn as Date) = Cast(GetDate() as Date) and IsActive = 1 order by AttendanceId desc)      
 Begin      
  Select top 1 (case when isnull(AttendanceOut, '') = '' then 1 else 0 end) IsSignInStatus, isnull(aggr.TrackLocationInterval, 15) TrackLocationInterval, AttendanceId, UserId, AttendanceIn, isnull(AttendanceOut, '') AttendanceOut, CONVERT(varchar, AttendanceIn , 103) AttendanceInNew, (case when AttendanceOut = '' then '' else CONVERT(varchar, AttendanceOut , 103) end) AttendanceOutNew, isnull(AttendanceOut, '') AttendanceOut, isnull(LatitudeIn, '') LatitudeIn,  isnull(LongitudeIn, '') LongitudeIn, isnull(LatitudeOut, '') LatitudeOut, isnull(LongitudeOut, '') LongitudeOut,  isnull(DeviceId, '') DeviceId, isnull(RemarksIn, '') RemarksIn, isnull(RemarksOut, '') RemarksOut, isnull(AttendanceGroupId, 0) AttendanceGroupId, isnull(ShiftId, 0) ShiftId, atdn.ParentId, atdn.CreatedDate,   isnull(atdn.CreatedBy, 0) CreatedBy, isnull(atdn.UpdatedDate, '') UpdatedDate, isnull(atdn.UpdatedBy, 0) UpdatedBy, case when atdn.IsActive = 1 then 'Active' else 'Deactive' end IsActiveStatus, @IsSignInEnabled as IsSignInEnabled  
  from TBL_ET_Attendance atdn (nolock) left join TBL_ET_AttendanceGroupGeoRestriction (nolock) aggr   
  on atdn.AttendanceGroupId = aggr.AttGroupId and aggr.IsActive = 1  
  where UserId = @UserId and Cast(AttendanceIn as Date) = Cast(GetDate() as Date) and atdn.IsActive = 1  
  order by AttendanceId desc      
 End      
 else      
 Begin      
  Select 0 AttendanceId, 0 IsSignInStatus, 0 TrackLocationInterval, @IsSignInEnabled as IsSignInEnabled  
 End      
  
 Select top 1 atgp.AttendanceGroupId, atgp.AttendanceGroupName, GroupType, atgp.ParentId, isnull(SignInFormId, 0)  SignInFormId, isnull(SignOutFormId, 0) SignInFormId, isnull(SignInType, '') SignInType, isnull(SignOutType, '') SignOutType, isnull(SignInPromptType, '') SignInPromptType, isnull(SignOutPromptType, '') SignOutPromptType, (case when isnull(agum.UserId, 0) = 0 then isnull(ParentId, 0) else isnull(agum.UserId, 0) end) UserId, (case when isnull(agum.GeoRestriction, '') = '' then isnull(DefaultGeoRestrictionIn, '') else isnull(agum.GeoRestriction, '') End) GeoRestrictionChildIn, (case when isnull(agum.GeoRestriction, '') = '' then isnull(DefaultGeoRestrictionOut, '') else isnull(agum.GeoRestriction, '') End)GeoRestrictionChildOut, (case when isnull(agum.AuthType, '') = '' then isnull(DefaultAuthTypeIn, '') else isnull(agum.AuthType, '') end) AuthTypeChildIn, (case when isnull(agum.AuthType, '') = '' then isnull(DefaultAuthTypeOut, '') else isnull(agum.AuthType, '') end) AuthTypeChildOut, (case when isnull(agum.AttendanceCalcType, '') = '' then isnull(DefaultAttendanceCalcType, '') else isnull(agum.AttendanceCalcType, '') end) AttendanceCalcType, (case when isnull(agum.UserAutoSignIn, '') = '' then isnull(atgp.SignInRange, '') else 0 end) UserAutoSignIn, (case when isnull(agum.UserAutoSignOut, '') = '' then isnull(atgp.SignOutRange, '') else 0 end) UserAutoSignOut, isnull(AllowedAttendanceOverride, 0) AllowedAttendanceOverride, isnull(AttendaceApprover, 0) AttendeceApprover, isnull(atgp.SignInRange, 0) SignInRange, isnull(atgp.SignOutRange, 0) SignOutRange, isnull(@ShiftName, '') ShiftName, isnull(cast(@StartTime as varchar(5)),'') StartTime, isnull(cast(@EndTime as varchar(5)),'') EndTime
 from TBL_ET_AttendanceGroup atgp(nolock) left join TBL_ET_AttendanceGroupUserMapping agum (nolock)   
 on atgp.AttendanceGroupId = agum.AttendanceGroupId      
 where agum.UserId = @UserId and atgp.IsActive = 1 and agum.IsActive = 1       
       
 Declare @ParentId3 bigint--, @UserId bigint=42322
  
 SELECT top 1 @ParentId3 = ParentId FROM User_detail WITH (NOLOCK) WHERE User_Id = @UserId      
  
 -- Branch   
 select distinct GESM.GeoEntitySiteId Id, GEM.EntityId, GeoEntityType, isnull(Mobile, '') Mobile, isnull(EmailId, '') EmailId, isnull(GeoEntitySiteName, '') [name], isnull(Latitude, '') Latitude, isnull(Longitude, '') Longitude, Isnull(MapAddress, '') MapAddress, isnull(GESM.Address, '') Address, isnull(City, '') City, isnull(State, '') State, isnull(Country, '') Country, isnull(PinCode, '') PinCode--, UBSM.UserId  
 -- select *   
 from TBL_ET_GeoEntityMaster GEM (nolock) inner join TBL_ET_GeoEntitySiteMaster GESM (nolock)   
 on GEM.GeoEntityId = GESM.GEOEntityId /*inner join TBL_ET_UserBaseSiteMapping UBSM (nolock)   
 on GESM.GeoEntitySiteID = UBSM.GeoEntitySiteId*/      
 Where GEM.IsActive = 1 and GESM.IsActive = 1 and GEM.ParentId=@ParentId3 and GEM.GeoEntityType='Branch'  
 --and UBSM.UserId = @UserId      
      
 -- Site List(Old)      
 /*
 select distinct PHAP.PhysicalAppointmentId, GEM.EntityId, GEM.GeoEntityName, GeoEntityType, isnull(Mobile, '') Mobile, isnull(EmailId, '') EmailId, GESM.GeoEntitySiteId, isnull(GeoEntitySiteName, '') GeoEntitySiteName, isnull(GESM.Latitude, '') Latitude, isnull(GESM.Longitude, '') Longitude, Isnull(MapAddress, '') MapAddress, isnull(GESM.Address, '') Address, isnull(City, '') City, isnull(State, '') State, isnull(Country, '') Country, isnull(PinCode, '') PinCode, PAUM.UserId,   
 --isnull(UBSM.CheckInVicinityRange, 0) CheckInVicinityRange, isnull(UBSM.CheckOutVicinityRange, 0) CheckOutVicinityRange,   
 isnull(AGUM.SignInRange, 0) CheckInVicinityRange, isnull(AGUM.SignOutRange, 0) CheckOutVicinityRange,   
 isnull(GeoEntitySiteName, '') EntityName, 'https://kit19.com/UserCRMCampaign/img/img_avatar1.png' EntityProfileInage, isnull(GESM.Address, '') EntityAddress, isnull(Mobile, '') EntityMobile, isnull(EmailId, '') EntityEmailId   
 -- select *   
 from TBL_ET_GeoEntityMaster GEM (nolock) inner join TBL_ET_GeoEntitySiteMaster GESM (nolock)   
 on GEM.GeoEntityId = GESM.GEOEntityId inner join TBL_ET_PhysicalAppointment PHAP (nolock)   
 on GEM.GeoEntityId = PHAP.GEOEntityId inner join TBL_ET_PhyAppointUserMapping PAUM (nolock)   
 on PHAP.PhysicalAppointmentId = PAUM.PhysicalAppointmentId inner join TBL_ET_AttendanceGroupUserMapping(nolock) AGUM  
 on PAUM.UserId=AGUM.UserId  
 --TBL_ET_UserBaseSiteMapping UBSM (nolock) on GESM.GeoEntitySiteID = UBSM.GeoEntitySiteId      
 Where GEM.IsActive = 1 and GESM.IsActive = 1 and PHAP.IsActive = 1 and PAUM.IsActive = 1 and PAUM.UserId = @UserId      
 */

 -- Site List(New)
  select distinct GESM.GeoEntitySiteId, GEM.EntityId, GEM.GeoEntityName, GeoEntityType, isnull(Mobile, '') Mobile, isnull(EmailId, '') EmailId, GESM.GeoEntitySiteId, isnull(GeoEntitySiteName, '') GeoEntitySiteName, isnull(GESM.Latitude, '') Latitude, isnull(GESM.Longitude, '') Longitude, Isnull(MapAddress, '') MapAddress, isnull(GESM.Address, '') Address, isnull(City, '') City, isnull(State, '') State, isnull(Country, '') Country, isnull(PinCode, '') PinCode, AGUM.UserId,   
 --isnull(UBSM.CheckInVicinityRange, 0) CheckInVicinityRange, isnull(UBSM.CheckOutVicinityRange, 0) CheckOutVicinityRange,   
 isnull(AGUM.SignInRange, 0) CheckInVicinityRange, isnull(AGUM.SignOutRange, 0) CheckOutVicinityRange,   
 isnull(GeoEntitySiteName, '') EntityName, 'https://kit19.com/UserCRMCampaign/img/img_avatar1.png' EntityProfileInage, isnull(GESM.Address, '') EntityAddress, isnull(Mobile, '') EntityMobile, isnull(EmailId, '') EntityEmailId     
  --select *   
 from TBL_ET_GeoEntityMaster GEM (nolock) inner join TBL_ET_GeoEntitySiteMaster GESM (nolock)   
 on GEM.GeoEntityId = GESM.GEOEntityId inner join TBL_ET_AttendanceGroupUserMapping(nolock) AGUM  
 on GESM.GeoEntitySiteId=AGUM.BaseSiteID
 Where GEM.IsActive = 1 and GESM.IsActive = 1 and AGUM.UserId=@UserId
 and GEM.GeoEntityType in ('Site','Location') 
  
    -- Site Pool   
 select Id, EntityId, GeoEntityType, Mobile, EmailId, [name], Latitude, Longitude, MapAddress, Address, City, State, Country, PinCode, GeoEntitySitePoolId, GeoEntitySitePoolName 
From (
 select  row_number()over(partition by GESM.GeoEntitySiteId order by GESM.GeoEntitySiteId) sno,  GESM.GeoEntitySiteId Id, GEM.EntityId, GeoEntityType, isnull(Mobile, '') Mobile, isnull(EmailId, '') EmailId, isnull(GeoEntitySiteName, '') [name], isnull(Latitude, '') Latitude, isnull(Longitude, '') Longitude, Isnull(MapAddress, '') MapAddress, isnull(GESM.Address, '') Address, isnull(City, '') City, isnull(State, '') State, isnull(Country, '') Country, isnull(PinCode, '') PinCode, SP.GeoEntitySitePoolId, SP.GeoEntitySitePoolName  
 -- select *   
 from TBL_ET_GeoEntityMaster GEM (nolock) inner join TBL_ET_GeoEntitySiteMaster GESM (nolock)   
 on GEM.GeoEntityId = GESM.GEOEntityId inner join TBL_ET_GeoEntitySitePoolList SPL (nolock)   
 on GESM.GeoEntitySiteID = SPL.GeoEntitySiteId inner join TBL_ET_GeoEntitySitePool SP (nolock)     
 on SPL.GeoEntitySitePoolId = SP.GeoEntitySitePoolId  
 Where GEM.IsActive = 1 and GESM.IsActive = 1 and SPL.Isactive=1 and GEM.ParentId=@ParentId3   
 and GEM.GeoEntityType not in ('Branch')  
 ) T
Where T.Sno=1      
  
 -- Territory List  
 SELECT distinct TM.TerritoryId, TM.TerritoryName, TM.ParentId, TUM.UserId, TGF.GeofenceId, GFL.Latitude,  
   GFL.Longitude, GFL.FenceType, GFL.Radius, GFL.sno  
 FROM TBL_ET_TerritoryMaster TM (nolock) INNER JOIN TBL_ET_TerritoryUserMapping TUM (nolock)   
 ON  TM.TerritoryId = TUM.TerritoryId INNER JOIN TBL_ET_TerritoryGeofence TGF (nolock)   
 ON  TM.TerritoryId = TGF.TerritoryId INNER JOIN TBL_ET_GeofenceList GFL (nolock)   
 ON  TGF.GeofenceId = GFL.GeofenceId  
 WHERE   (TM.IsActive = 1) AND (TUM.IsActive = 1) AND (TGF.IsActive = 1) AND (GFL.IsActive = 1) AND (TUM.UserId = @UserId)  
  
 End      
  
END TRY      
      
BEGIN CATCH      
 DECLARE @ErrorMessage NVARCHAR(4000);      
      
 SELECT @ErrorMessage = ERROR_MESSAGE();      
      
 RAISERROR (      
   @ErrorMessage      
   ,16      
   ,1      
   );      
END CATCH      



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_Attendance_rpt]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_TBL_ET_Attendance_rpt]
(
  @Mode varchar(10) = '',
  @SearchText nvarchar(max) = '',
  @FromDate varchar(25) = '',
  @ToDate varchar(25) = '',
  @UserIds varchar(max) = '',
  @ParentId bigint = 0,
  @Contain nvarchar(max) = ''
)
AS
SET NOCOUNT ON
BEGIN
	 /*
	  declare 
	  @Mode varchar(10) = N'SM',
	  @SearchText nvarchar(max) = N'',
	  @FromDate varchar(25) = N'01-Jan-2024',
	  @ToDate varchar(25) = N'31-Jan-2024',
	  @UserIds varchar(max) = N'',
	  @ParentId bigint = 42812,
	  @Contain nvarchar(max) = N''
	 */

	  Declare @UserID bigint =  @ParentId ;
	  Declare @ParentIDSql bigint = 0
	  select @ParentIDSql = isnull(ParentId,0) from User_Detail with(nolock) where User_ID = @UserID
 
	BEGIN TRY
	
	if(rtrim(ltrim(isnull(@UserIds,''))) != '0')
     begin
	   IF (@Mode = 'SM') /*This is for Insert usp_tbl_ET_Attendance Details */
	 BEGIN

	if(@SearchText = '')
	 Begin
	 set @SearchText = ''
	 End
	 else
	 Begin
	 set @SearchText = ' and ' + @SearchText
	 End

	if(@Contain = '')
	 Begin
	 set @Contain = ''
	 End
	 else
	 Begin
	 set @Contain = ' and ' + @Contain
	 End

	--Declare @UserIds varchar(max) ='34594,36931,36932',
	--@FromDate varchar(20) = '',
	--@ToDate varchar(20) = ''
	Declare @query nvarchar(max)
	set @query = 'select * from ( select UserName, User_ID, User_ID UserId, ParentID, User_Login, EmployeeName, PresentDays, HalfDays, 
	(TotalDays - PresentDays - WeeklyOffDays - OnLeaveDays - (HalfDays * .5)) AbsentDays, WeeklyOffDays,
	OnLeaveDays, TotalDays, InLateDays, OutEarlyDays, TotalAttendanceTime from (
	select (ud.FName + '' '' + ud.LName) as UserName, ud.User_ID, ud.ParentID, ud.User_Login, 
	ud.FName + '' '' + ud.LName + ''( '' +ud.User_Login + '' )'' EmployeeName, 
	--atda.AttendanceIn , convert(varchar(12), atda.AttendanceIn, 113) AttendanceIn, 
	dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, '''+ @FromDate +''', '''+ @ToDate +''', ''TotalWorkingDay'') PresentDays, 
	dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, '''+ @FromDate +''', '''+ @ToDate +''', ''HalfDays'') HalfDays, 
	dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, '''+ @FromDate +''', '''+ @ToDate +''', ''WeekOff'') WeeklyOffDays, 
	dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, '''+ @FromDate +''', '''+ @ToDate +''', ''TotalLeave'') OnLeaveDays, 
	dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, '''+ @FromDate +''', '''+ @ToDate +''', ''TotalDays'') TotalDays, 
	dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, '''+ @FromDate +''', '''+ @ToDate +''', ''LateSignin'') InLateDays, 
	dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, '''+ @FromDate +''', '''+ @ToDate +''', ''OutEarlyDays'') OutEarlyDays, 
	dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, '''+ @FromDate +''', '''+ @ToDate +''', ''Totalminutes'') TotalAttendanceTime
	from User_detail(nolock) ud 
	where ud.User_Id in (select item from dbo.fu_SplitString('''+ cast(@UserIds as nvarchar(max))+''', '','')) 
	)q)t where (1=1) ' + @SearchText + '' + @Contain + ''

	print @query

	execute sp_executesql @query

	 End 
	 end
	 else if(rtrim(ltrim(isnull(@UserIds,''))) = '0')
	   begin
	    



	   IF (@Mode = 'SM') /*This is for Insert usp_tbl_ET_Attendance Details */
	 BEGIN

			DECLARE @IsAdmin BIT = 0
			DECLARE @TimeZoneName NVARCHAR(255) = isnull((SELECT TimeZone FROM User_Detail(NOLOCK) WHERE User_ID = @Userid), 'India Standard Time')
			DECLARE @UserIDTeam BIGINT = @Userid;
			DECLARE @tbluser TABLE (
				User_ID BIGINT
				,Name VARCHAR(100)
				,IMAGE NVARCHAR(200)
				)

			SELECT @IsAdmin = IsAdmin
			FROM User_Detail(NOLOCK)
			WHERE User_ID = @Userid

			DECLARE @ScopeCode VARCHAR(10) = ''
			select @ScopeCode = ScopeCode    
			 from ufn_GetUserRoleScope(@UserId) 

			 if(@ScopeCode = 'GLOBAL')
			   begin
				   set @IsAdmin = 1 
			   end


			IF (@IsAdmin = 1)
			BEGIN
				INSERT INTO @tbluser
				EXEC Use_GetUserDetails @ParentIdSql
			END
			ELSE
			BEGIN
				INSERT INTO @tbluser
				EXEC Use_GetUserDetails @UserId
			END

		DECLARE @UserIdTeamLst VARCHAR(4000) = ''
  	     SELECT @UserIdTeamLst = isnull(STRING_AGG(User_ID, ','), '')
	       FROM @tbluser


	if(@SearchText = '')
	 Begin
	 set @SearchText = ''
	 End
	 else
	 Begin
	 set @SearchText = ' and ' + @SearchText
	 End

	if(@Contain = '')
	 Begin
	 set @Contain = ''
	 End
	 else
	 Begin
	 set @Contain = ' and ' + @Contain
	 End

	--Declare @UserIds varchar(max) ='34594,36931,36932',
	--@FromDate varchar(20) = '',
	--@ToDate varchar(20) = ''
	Declare @query_2 nvarchar(max)
	set @query_2 = 'select * from ( select UserName, User_ID, User_ID UserId, ParentID, User_Login, EmployeeName, PresentDays, HalfDays, 
	(TotalDays - PresentDays - WeeklyOffDays - OnLeaveDays - (HalfDays * .5)) AbsentDays, WeeklyOffDays,
	OnLeaveDays, TotalDays, InLateDays, OutEarlyDays, TotalAttendanceTime from (
	select (ud.FName + '' '' + ud.LName) as UserName, ud.User_ID, ud.ParentID, ud.User_Login, 
	ud.FName + '' '' + ud.LName + ''( '' +ud.User_Login + '' )'' EmployeeName, 
	--atda.AttendanceIn , convert(varchar(12), atda.AttendanceIn, 113) AttendanceIn, 
	dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, '''+ @FromDate +''', '''+ @ToDate +''', ''TotalWorkingDay'') PresentDays, 
	dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, '''+ @FromDate +''', '''+ @ToDate +''', ''HalfDays'') HalfDays, 
	dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, '''+ @FromDate +''', '''+ @ToDate +''', ''WeekOff'') WeeklyOffDays, 
	dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, '''+ @FromDate +''', '''+ @ToDate +''', ''TotalLeave'') OnLeaveDays, 
	dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, '''+ @FromDate +''', '''+ @ToDate +''', ''TotalDays'') TotalDays, 
	dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, '''+ @FromDate +''', '''+ @ToDate +''', ''LateSignin'') InLateDays, 
	dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, '''+ @FromDate +''', '''+ @ToDate +''', ''OutEarlyDays'') OutEarlyDays, 
	dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, '''+ @FromDate +''', '''+ @ToDate +''', ''Totalminutes'') TotalAttendanceTime
	from User_detail(nolock) ud 
	where ud.User_Id in (select item from dbo.fu_SplitString('''+ cast(@UserIdTeamLst as nvarchar(max))+''', '','') ) 
	)q)t where (1=1) ' + @SearchText + '' + @Contain + ''

	print @query_2

	execute sp_executesql @query_2

	 End 

	   end
	   		 

	END TRY 

	BEGIN CATCH 
	 DECLARE @ErrorMessage NVARCHAR(4000); 

	 SELECT @ErrorMessage = ERROR_MESSAGE(); 
 
	 RAISERROR ( 
	   @ErrorMessage 
	   ,16 
	   ,1 
	   ); 
	END CATCH  
END



GO

/* ============================================================
   Procedure: [dbo].[usp_tbl_ET_AttendanceAutoUpdate]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE  [dbo].[usp_tbl_ET_AttendanceAutoUpdate] (    
@UserId bigint,
@EntryDate date
)
AS
SET NOCOUNT ON    
    
BEGIN TRY    
 BEGIN 
--Declare @UserId bigint = 34594,
--@EntryDate date = '2023-02-13'

 Declare @IsSignInStatus bit = 0
 Declare @IsSignOutStatus bit = 0
 Declare @Parentid2 bigint 
 Select @Parentid2 = ParentId from User_Detail(nolock) where User_Id = @UserId  

 Declare @latitude1 float = 0, @longitude1 float = 0, @latitude2 float = 0, @longitude2 float = 0, @AutoSignIn nvarchar(150) = '', @AutoSignOut nvarchar(150) = '', @SignInRange int = 0, @SignOutRange int = 0, @Distance float = -1

if Exists(Select top 1 AttendanceId from TBL_ET_Attendance atdn (nolock) where UserId = @UserId and Cast(AttendanceIn as Date) = Cast(@EntryDate as Date)
--Cast(GetDate() as Date) 
and IsActive = 1 order by AttendanceId desc)    
Begin 
 Select top 1 (case when isnull(AttendanceIn, '') = '' then 0 else 1 end) IsSignInStatus, (case when isnull(AttendanceOut, '') = '' then 0 else 1 end) IsSignOutStatus, isnull(aggr.TrackLocationInterval, 5) TrackLocationInterval, AttendanceId, UserId, AttendanceIn, isnull(AttendanceOut, '') AttendanceOut, isnull(LatitudeIn, '') LatitudeIn,     
  isnull(LongitudeIn, '') LongitudeIn, isnull(LatitudeOut, '') LatitudeOut, isnull(LongitudeOut, '') LongitudeOut,    
  isnull(DeviceId, '') DeviceId, isnull(RemarksIn, '') RemarksIn, isnull(RemarksOut, '') RemarksOut,     
  isnull(AttendanceGroupId, 0) AttendanceGroupId, isnull(ShiftId, 0) ShiftId, atdn.ParentId, atdn.CreatedDate,    
  isnull(atdn.CreatedBy, 0) CreatedBy, isnull(atdn.UpdatedDate, '') UpdatedDate, isnull(atdn.UpdatedBy, 0) UpdatedBy,     
  case when atdn.IsActive = 1 then 'Active' else 'Deactive' end IsActiveStatus    
  from TBL_ET_Attendance atdn (nolock) 
  left join TBL_ET_AttendanceGroupGeoRestriction (nolock) aggr on atdn.AttendanceGroupId = aggr.AttGroupId and aggr.IsActive = 1    
  where UserId = @UserId and Cast(AttendanceIn as Date) = Cast(@EntryDate as Date) and atdn.IsActive = 1 order by AttendanceId desc    
End 

select top 1 --agup.AttendanceGroupId, agum.UserId, @IsSignInStatus IsSignInStatus, @IsSignOutStatus IsSignOutStatus,
@AutoSignIn = (case when agum.UserAutoSignIn != '' then agum.UserAutoSignIn
else agup.SignInType end),
@AutoSignOut = (case when agum.UserAutoSignOut != '' then agum.UserAutoSignOut
else agup.SignOutType end),
@SignInRange = (Case when agum.SignInRange > 0 then agum.SignInRange 
else agup.SignInRange end),
@SignOutRange = (Case when agum.SignOutRange > 0 then agum.SignOutRange 
else agup.SignOutRange end),
--ultr.MovementCode, 
--agup.DefaultGeoRestrictionIn, agup.DefaultGeoRestrictionOut, 
--agum.GeoRestriction, agum.AuthType, 
--agum.AttendanceCalcType, agum.UserBranchId, agum.BaseSiteID,
--agum.OnDuty, agup.GroupType, agup.SignInFormId, agup.SignOutFormId,agup.DefaultGeoRestrictionIn,
--agup.DefaultGeoRestrictionOut, agup.DefaultAuthTypeIn, agup.DefaultAuthTypeOut,
@latitude2 = gesm.Latitude, @longitude2 = gesm.Longitude
from TBL_ET_AttendanceGroup(nolock) agup 
left join TBL_ET_AttendanceGroupUserMapping(nolock) agum on agup.AttendanceGroupId = agum.AttendanceGroupId
left join TBL_ET_GeoEntitySiteMaster (nolock) gesm on agum.BaseSiteID = gesm.GeoEntitySiteId
where agum.UserId = @UserId
order by agup.AttendanceGroupId desc

select top 1 @latitude1 = Latitude, @longitude1 = Longitude, 
@Distance = dbo.fnCalcDistanceKM(Latitude, @latitude2, Longitude, @longitude2) from TBL_ET_UserLocationTracking(nolock) ultr where ultr.UserId = @UserId
order by ultr.UserLocationTrackingId desc

Declare @CurrentDate datetime = GetDate();

Declare @StartTime time, @EndTime time, @CurrentTime time(5)
select top 1 @StartTime = StartTime, @EndTime = EndTime from TBL_ET_ShiftUserMapping(nolock) shum
inner join TBL_ET_ShiftMaster(nolock) shma on shum.ShiftId = shma.ShiftId
inner join User_Detail(nolock) ud on shum.UserId = ud.User_ID
where UserId = @UserId
order by shum.ShiftUserMappingId desc

set @CurrentTime = cast(@CurrentDate as time(5));--.ToString('HH:mm')

--Auto SignIn
if ((@AutoSignIn = 'automatic') and (@IsSignInStatus = 0) and ((@Distance * 1000) <= @SignInRange)) 
Begin 
print 'SignIn'

execute usp_tbl_ET_Attendance 'SI', 0, @UserId, @CurrentDate, null, @latitude1,  @longitude1, null, null, 'mobileauto', '', '', 0, 0,  @UserId, 1

End 

--Select @IsSignInStatus IsSignInStatus, @IsSignOutStatus IsSignOutStatus--, @AttendanceIn2 AttendanceIn,--, @AttendanceOut2 AttendanceOut 

--CheckIn
--set @IsSignInStatus = 1
if(@IsSignInStatus = 1)
Begin
 
drop table if Exists #Temptable
Create table #Temptable(UserId bigint, Latitude varchar(100), Longitude varchar(100))

insert into #Temptable (UserId, Latitude, Longitude)
select top 1 UserId, Latitude, Longitude from TBL_ET_UserLocationTracking(nolock) ultr where ultr.UserId = @UserId
order by ultr.UserLocationTrackingId desc

Select @IsSignInStatus IsSignInStatus, --@AttendanceIn2 AttendanceIn, 
@IsSignOutStatus IsSignOutStatus--, @AttendanceOut2 AttendanceOut 

Declare @PhysicalAppointmentId bigint, @DistanceCheckin float = -1, @CheckIn Datetime, @LatitudeChk float, @LongitudeChk float, @IsAutoCheckIn bit = 1, @CheckInRange int, @CheckOutRange int, @LatitudeIn float, @LongitudeIn float

select top 1 @PhysicalAppointmentId = t.Id, @DistanceCheckin = distance, @LatitudeChk = Latitude, @LongitudeChk = Longitude, @CheckInRange = CheckInRange, @CheckOutRange = CheckOutRange, @LatitudeIn = LatitudeIn, @LongitudeIn = LongitudeIn from (
Select Distinct papt.PhysicalAppointmentId Id, gesm.Latitude, gesm.Longitude, dbo.fnCalcDistanceKM(ultr.Latitude, gesm.Latitude, ultr.Longitude, gesm.Longitude) distance, phcs.CheckInRange, phcs.CheckOutRange, gecu.LatitudeIn, gecu.LongitudeIn
 from TBL_ET_PhysicalAppointment(nolock) papt  
 left join TBL_ET_PhysicalAppointmentCheckInOutSetting (nolock) phcs on papt.PhysicalAppointmentId = phcs.PhysicalAppointmentId
 left join TBL_ET_GeoEntitySiteMaster(nolock) gesm on papt.GeoEntitySiteId = gesm.GeoEntitySiteId  
 left join TBL_ET_GeoEntityMaster(nolock) gemr on gesm.GeoEntityId = gemr.GeoEntityId  
 left join TBL_ET_PhyAppointUserMapping(nolock) paum on papt.PhysicalAppointmentId = paum.PhysicalAppointmentId  
 left join User_Detail(nolock) ud on papt.AssignedTo = ud.User_ID  
 left join TBL_ET_GeoEntityCheckInOut (nolock) gecu on papt.PhysicalAppointmentId = gecu.PhysicalAppointmentId  
 left join #Temptable (nolock) ultr on ud.User_ID = ultr.UserId
-- left join tbl_tsk_UserOutcomeMaster (nolock) oc on papt.OutcomesId = oc.Id  
-- left join TBL_ET_BreakTransaction (nolock) bt on paum.UserId = bt.CreatedBy and bt.StartDate between papt.StartDate and papt.EndDate  
 where paum.UserId = @UserId and 
 ((cast(papt.StartDate as Date) between cast(@EntryDate as Date) and cast(@EntryDate as Date)) 
 or (cast(papt.EndDate as Date) between cast(@EntryDate as Date) and cast(@EntryDate as Date))) 
)t
order by distance asc
--CheckIn

if(@CheckInRange < (@DistanceCheckin * 1000))
 Begin
 exec usp_tbl_ET_GeoEntityCheckInOut 'CI', 0, @PhysicalAppointmentId, @UserId, @CheckIn, NULL, @LatitudeChk, @LongitudeChk, NULL, NULL, 'mobileauto', NULL, NULL, 1
 End

--CheckOut
if((@LatitudeIn != '') and (@LongitudeIn != '') and (@CheckOutRange > (@DistanceCheckin * 1000)))
 Begin
exec usp_tbl_ET_GeoEntityCheckInOut 'CO', 0, @PhysicalAppointmentId, @UserId, NULL, @CheckIn, NULL, NULL, @LatitudeChk, @LongitudeChk, 'mobileauto', NULL, NULL, 1
End
End

--set @EndTime = cast('14:00' as time)
--Auto SignOut
if ((@CurrentTime > @EndTime) and (@AutoSignOut = 'automatic') and (@IsSignOutStatus = 0) and ((@Distance* 1000) > @SignOutRange)) 
Begin 
print 'SignOut'

execute usp_tbl_ET_Attendance 'SO', 0, @UserId, null, @CurrentDate, null, null, @latitude1, @longitude1, 'mobileauto', '', '', 0, 0,  @UserId, 1

End

 End 
END TRY 
    
BEGIN CATCH 
 DECLARE @ErrorMessage NVARCHAR(4000); 
    
 SELECT @ErrorMessage = ERROR_MESSAGE(); 
    
 RAISERROR (    
   @ErrorMessage    
   ,16    
   ,1    
   );    
END CATCH    



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_AttendanceGpUserRoleSetting_Name]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec usp_TBL_ET_AttendanceGpUserRoleSetting_Name @OffsetValue=0,@PagingSize=5,@SearchText=N'',@Condition=N'StartWith',@UserId=34594,@ParentId=34594
--exec usp_TBL_ET_AttendanceGpUserRoleSetting_Name @OffsetValue=0,@PagingSize=5,@SearchText=N'',@Condition=N'StartWith',@UserId=27053,@ParentId=27053  
--exec usp_TBL_ET_AttendanceGpUserRoleSetting_Name @OffsetValue=0,@PagingSize=5,@SearchText=N'',@Condition=N'StartWith',@UserId=32222,@ParentId=32222  
CREATE   PROCEDURE  [dbo].[usp_TBL_ET_AttendanceGpUserRoleSetting_Name]   
(        
 @OffsetValue int = 0        
 ,@PagingSize int = 0        
 ,@SearchText nvarchar(max) = ''       
 ,@Condition varchar(20) = 'StartWith'                              
 ,@UserId bigint = 0        
 ,@ParentId bigint = 0        
)      
AS      
SET NOCOUNT ON      
      
BEGIN TRY        
    
-- Declare @OffsetValue int = 0,@PagingSize int = 10,@SearchText nvarchar(max) = '',@Condition varchar(20) = 'StartWith',@UserId bigint = 34594,@ParentId bigint = 34594        
    
--Declare @ParentId bigint        
Select @ParentId = ParentId from User_Detail(nolock) where User_Id = @UserId      
        
if(@SearchText != '')      
Begin        
set @SearchText = ' and ' + @SearchText        
End        
Declare @UserIdTeamLst varchar(4000)        
select @UserIdTeamLst = UserIdTeamLst from ufn_GetUserRoleScope(@UserId)        
print @UserIdTeamLst       
    
      
Declare @query nvarchar(max)       
set @query = 'select count(*) over() as TotalRecords, t.* from (select ud.User_Login + '' ('' + ud.FName + '' '' + ud.LName + '')'' EmployeeName, ud.Image, isnull(ud.ProfilePictureName, '''') ProfilePictureName, ud.ParentId, AttGroupUserMapId, atguma.AttendanceGroupId, isnull(urmm.RoleCode, '''') RoleCode, isnull(rm.RoleName, '''') RoleName, ISNULL((select top 1 RoleDesc from Serv_Role_mast a inner join serv_agent_mast b on a.RoleId = b.RoleId inner join Serv_User_Detail c on c.ser_user_id = b.Userid where a.ParentId= ud.ParentID and c.User_id_old = ud.User_ID ),''-NA-'') SupportRoleName, isnull(atgp.AttendanceGroupName, '''') AttendanceGroupName, isnull(usbranch.name, '''') BranchName, ud.user_id as UserId, GeoRestriction, AuthType, AttendanceCalcType, UserBranchId, isnull(BaseSiteID, 0) BaseSiteID, isnull(BaseSiteType, '''') BaseSiteType, case when ISNULL(BaseSiteType, '''') in (''GeoEntitySite'',''Site'',''Branch'') then ISNULL(gesm.GeoEntitySiteName, '''') when ISNULL(BaseSiteType, '''') = ''Territory'' then isnull(tm.TerritoryName,'''') when ISNULL(BaseSiteType, '''') = ''Sitepool'' then isnull(sp.GeoEntitySitePoolName,'''')  else '''' end as GeoEntitySiteName, cast(isnull(ud.OnDuty, 0) as bit)  OnDuty, isnull(UserAutoSignIn, 0) UserAutoSignIn, isnull(UserAutoSignOut, 0) UserAutoSignOut, isnull(atguma.SignInRange, '''') SignInRange, isnull(atguma.SignOutRange, '''') SignOutRange, atguma.CreatedDate, atguma.CreatedBy, isnull(atguma.UpdatedDate, atguma.CreatedDate) UpdatedDate, atguma.UpdatedBy, (case when atguma.IsActive = 1 then ''Active'' else ''InActive'' End) Status, ud.IsAdmin, cast(0 as bit) UserStatus, cast(0 as bit) SupportStatus from User_Detail(nolock) ud left join TBL_ET_AttendanceGroupUserMapping(nolock) atguma   
 on atguma.UserId = ud.User_ID left join TBL_UA_UserRoleMappingMaster(nolock) urmm  
 on atguma.UserId = urmm.UserId left join VW_SystemRole_RoleMaster(nolock) rm  
 on urmm.RoleCode = rm.RoleCode left join TBL_ET_AttendanceGroup(nolock) atgp  
 on atguma.AttendanceGroupId = atgp.AttendanceGroupId left join tbl_inv_UserTaxNumber(nolock) usbranch  
 on atguma.UserBranchId = usbranch.ID left join TBL_ET_GeoEntitySiteMaster(nolock) gesm  
 on atguma.BaseSiteID = gesm.GeoEntitySiteId LEFT JOIN TBL_ET_TerritoryMaster(NOLOCK) tm 
 ON atguma.BaseSiteID = tm.TerritoryId LEFT JOIN TBL_ET_GeoEntitySitePool(NOLOCK) sp 
 ON atguma.BaseSiteID = sp.GeoEntitySitePoolId  
 where ud.User_Id in (select item from dbo.fu_SplitString(''' + cast(@UserIdTeamLst as varchar(4000)) + ''', '',''))    
 )t where (1=1) ' + @SearchText + '       
 Order By t.CreatedDate Desc       
 Offset '+ cast(@OffsetValue as varchar(10)) + ' rows fetch next '+ cast(@PagingSize as varchar(10)) + ' rows only '       
         
 print @query        
      
 execute sp_executesql @query        
       
END TRY        
        
BEGIN CATCH        
 DECLARE @ErrorMessage NVARCHAR(4000);        
 SELECT @ErrorMessage = ERROR_MESSAGE();        
 RAISERROR (        
   @ErrorMessage        
   ,16        
   ,1        
   );        
END CATCH        



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_AttendanceGpUserRoleSettingSave]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec usp_TBL_ET_AttendanceGpUserRoleSettingSave @Mode=N'UI',@AttGroupUserMapId=0,@RoleCode=N'0',@SupportRoleId=0,@AttendanceGroupId=0,@GeoRestriction=N'0',@AuthType=N'0',@AttendanceCalcType=N'0',@UserBranchId=0,@BaseSiteID=0,@BaseSiteType=N'-1',@OnDuty=0,@UserAutoSignIn=N'-1',@UserAutoSignOut=N'-1',@SignInRange=0,@SignOutRange=0,@UserIds=N'36932',@UserStatus=0,@SupportStatus=0,@CreatedBy=34594,@IsActive=1    
--exec usp_TBL_ET_AttendanceGpUserRoleSettingSave @Mode=N'UI',@AttGroupUserMapId=0,@RoleCode=N'0',@SupportRoleId=0,@AttendanceGroupId=0,@GeoRestriction=N'0',@AuthType=N'0',@AttendanceCalcType=N'0',@UserBranchId=0,@BaseSiteID=0,@BaseSiteType=N'-1',@OnDuty=0,@UserAutoSignIn=N'-1',@UserAutoSignOut=N'-1',@SignInRange=0,@SignOutRange=0,@UserIds=N'34594,36931,36932',@UserStatus=0,@SupportStatus=0,@CreatedBy=34594,@IsActive=1    
--exec usp_TBL_ET_AttendanceGpUserRoleSettingSave @Mode=N'UI',@AttGroupUserMapId=0,@RoleCode=N'SYS_ADMIN',@SupportRoleId=791,@AttendanceGroupId=51,@GeoRestriction=N'Site',@AuthType=N'Physical',@AttendanceCalcType=N'TimeCount',@UserBranchId=29,@BaseSiteID=3,@BaseSiteType=N'Branch',@OnDuty=1,@UserAutoSignIn=N'Auto',@UserAutoSignOut=N'Auto',@SignInRange=10,@SignOutRange=10,@UserIds=N'34594',@UserStatus=1,@SupportStatus=1,@CreatedBy=34594,@IsActive=1    
CREATE   PROCEDURE  [dbo].[usp_TBL_ET_AttendanceGpUserRoleSettingSave]
(      
 @Mode VARCHAR(2),      
 @AttGroupUserMapId bigint=0,      
 @RoleCode varchar(30) = '',      
 @SupportRoleId bigint = 0,      
 @AttendanceGroupId bigint,      
 @GeoRestriction varchar(50),      
 @AuthType varchar(50),      
 @AttendanceCalcType varchar(50),      
 @UserBranchId int,      
 @BaseSiteID bigint,      
 @BaseSiteType varchar(30),      
 @OnDuty bit,      
 @UserAutoSignIn varchar(50),      
 @UserAutoSignOut varchar(50),      
 @SignInRange int,      
 @SignOutRange int,      
 @UserIds nvarchar(max),      
 @UserStatus bit,      
 @SupportStatus bit,      
 @CreatedBy bigint,      
 @IsActive bit      
)      
AS      
SET NOCOUNT ON      
      
BEGIN TRY      
Declare @ParentId bigint      
      
Select @ParentId = ParentId from User_Detail(nolock) where User_Id = @CreatedBy      
      
IF (@Mode = 'UI') /*This is for Insert Details */      
BEGIN      
 If(@SupportRoleId=0)    
 Begin    
  If exists(SELECT TOP 1 RoleDesc FROM Serv_Role_mast a INNER JOIN serv_agent_mast b     
  ON a.RoleId = b.RoleId INNER JOIN Serv_User_Detail c ON c.ser_user_id = b.Userid    
        WHERE a.ParentId = @ParentId AND c.User_id_old in (SELECT item FROM dbo.fu_SplitString(@UserIds, ',')) and b.Active=1)    
  Begin    
   update b set b.Active=0     
   FROM Serv_Role_mast a INNER JOIN serv_agent_mast b     
   ON a.RoleId = b.RoleId INNER JOIN Serv_User_Detail c ON c.ser_user_id = b.Userid    
   WHERE a.ParentId = @ParentId AND c.User_id_old in (SELECT item FROM dbo.fu_SplitString(@UserIds, ',')) and b.Active=1    
  End    
 End    
 Else    
 Begin    
  If exists(SELECT TOP 1 RoleDesc FROM Serv_Role_mast a INNER JOIN serv_agent_mast b     
  ON a.RoleId = b.RoleId INNER JOIN Serv_User_Detail c ON c.ser_user_id = b.Userid    
        WHERE a.ParentId = @ParentId AND c.User_id_old in (SELECT item FROM dbo.fu_SplitString(@UserIds, ',')) and b.Active=1)    
  Begin    
   update b set b.RoleId=@SupportRoleId     
   FROM Serv_Role_mast a INNER JOIN serv_agent_mast b     
   ON a.RoleId = b.RoleId INNER JOIN Serv_User_Detail c ON c.ser_user_id = b.Userid    
   WHERE a.ParentId = @ParentId AND c.User_id_old in (SELECT item FROM dbo.fu_SplitString(@UserIds, ',')) and b.Active=1    
  End    
 End    
    
 UPDATE TBL_ET_AttendanceGroupUserMapping SET     
  AttendanceGroupId = case when isnull(@AttendanceGroupId,0)=0 then AttendanceGroupId else @AttendanceGroupId end,
  GeoRestriction = case when isnull(@GeoRestriction,'0')='0' then GeoRestriction else @GeoRestriction end,     
  AuthType = case when isnull(@AuthType,'0')='0' then AuthType else @AuthType end,     
  AttendanceCalcType = case when isnull(@AttendanceCalcType,'0')='0' then AttendanceCalcType else @AttendanceCalcType end,     
  UserBranchId = case when isnull(@UserBranchId,0)='' then UserBranchId else @UserBranchId end,     
  BaseSiteID = case when isnull(@BaseSiteID,0)=0 then BaseSiteID else @BaseSiteID end,     
  BaseSiteType = case when isnull(@BaseSiteType,'-1')='-1' then BaseSiteType else @BaseSiteType end,     
  OnDuty = isnull(@OnDuty,0),     
  UserAutoSignIn = case when isnull(@UserAutoSignIn,'-1')='-1' then UserAutoSignIn else @UserAutoSignIn end,    
  UserAutoSignOut = case when isnull(@UserAutoSignOut,'-1')='-1' then UserAutoSignOut else @UserAutoSignOut end,  
  SignInRange = case when isnull(@SignInRange,0)=0 then SignInRange else @SignInRange end,     
  SignOutRange = case when isnull(@SignOutRange,0)=0 then SignOutRange else @SignOutRange end,     
  UpdatedDate = GETDATE(),     
  UpdatedBy = @CreatedBy,     
  IsActive = @IsActive    
 WHERE UserId IN (SELECT item FROM dbo.fu_SplitString(@UserIds, ','));      
    
  insert into TBL_ET_AttendanceGroupUserMapping (AttendanceGroupId, UserId, GeoRestriction, AuthType, AttendanceCalcType, UserBranchId, BaseSiteID, BaseSiteType, OnDuty, UserAutoSignIn, UserAutoSignOut, SignInRange, SignOutRange, CreatedDate, CreatedBy, IsActive)      
      
  select @AttendanceGroupId, item, @GeoRestriction, @AuthType, @AttendanceCalcType, @UserBranchId, @BaseSiteID, @BaseSiteType, @OnDuty, @UserAutoSignIn, @UserAutoSignOut, @SignInRange, @SignOutRange, GetDate(), @CreatedBy, @IsActive from dbo.fu_SplitString(@UserIds, ',') where item not in (select UserId from TBL_ET_AttendanceGroupUserMapping(nolock) atgu inner join User_Detail(nolock) ud on atgu.UserId = ud.User_Id where ud.ParentId = @ParentId)      
      
--- Update in Role       
      
  UPDATE urmm SET urmm.UserRoleMappingCode = (@RoleCode + '_' + Cast(@ParentId AS VARCHAR(10)) + '_' + Cast(item AS VARCHAR(10))), urmm.RoleCode = @RoleCode, urmm.ModifiedDate =getdate()     
  FROM TBL_UA_UserRoleMappingMaster urmm inner join (select * from (SELECT distinct item from dbo.fu_SplitString(@UserIds, ','))t) uisi on urmm.UserId = uisi.item      
      
  INSERT INTO TBL_UA_UserRoleMappingMaster (UserRoleMappingCode,RoleCode, ParentId, UserId, Active, CreatedBy, CreatedDate)      
  SELECT (@RoleCode + '_' + Cast(@ParentId AS VARCHAR(10)) + '_' + Cast(item AS VARCHAR(10)))        
   ,@RoleCode, @ParentId, item, 1, @CreatedBy ,GETDATE()        
  FROM dbo.fu_SplitString(@UserIds, ',') aa  where aa.item not in (select UserId from TBL_UA_UserRoleMappingMaster(nolock) where ParentId = @ParentId)      

	insert into TBL_ET_TerritoryUserMapping
	(TerritoryId, UserId, ParentId, CreatedDate, CreatedBy, IsActive)
	select AGUM.BaseSiteID as TerritoryId, AGUM.UserId, @ParentId as ParentId, getdate() as CreatedDate, AGUM.CreatedBy, 1 as IsActive 
	from TBL_ET_AttendanceGroupUserMapping(nolock) AGUM left join TBL_ET_TerritoryUserMapping(nolock) TUM
	On AGUM.BaseSiteID=TUM.TerritoryId and AGUM.IsActive=1 and AGUM.UserId=TUM.UserId and TUM.IsActive=1
	where AGUM.UserId in (select item from dbo.fu_SplitString(@UserIds, ','))
	and AGUM.BaseSiteType='Territory' and TUM.UserId is null

      
  Select 'Record Saved' STATUS      
 End      
      
END TRY      
      
BEGIN CATCH      
 DECLARE @ErrorMessage NVARCHAR(4000);      
 SELECT @ErrorMessage = ERROR_MESSAGE();      
 RAISERROR (      
   @ErrorMessage      
   ,16      
   ,1      
   );      
END CATCH      



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_AttendanceGroup]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec usp_TBL_ET_AttendanceGroup @Mode=N'AGU',@AttendanceGroupId=47,@AttendanceGroupName=N'Geo Type Attendance Grp',@GroupType=N'Geo',@ParentId=34594,@SignInFormId=1,@SignOutFormId=12,@DefaultGeoRestrictionIn=N'Site',@DefaultAuthTypeIn=N'Physical',@DefaultGeoRestrictionOut=N'Site',@DefaultAuthTypeOut=N'Physical',@SignInType=N'Auto',@SignOutType=N'Manual',@SignInPromptType=N'',@SignOutPromptType=N'',@DefaultAttendanceCalcType=N'TimeCount',@AllowedAttendanceOverride=1,@AttendanceApproverType=N'AnyAdmin',@AttendanceApprover=0,@SignInRange=100,@SignOutRange=250,@CalculateTimeSpentIn=N'BaseSite',@CalculateScheduleVisitCount=N'mins',@SignInTimeLater=30,@SignInTimeLaterType=N'mins',@SignIndisallowedMessage=N'Message one',@SignOutdisallowedMessage=N'Message two',@ApplyLeaveBeforeLimit=5,@FormConditionList=N'[]',@SignInConditionList=N'[]',@SignOutConditionList=N'[]',@AttendanceConditionList=N'[{"SequenceNo":1,"TypeOfStatus":"Absent","AttendanceMinPercentage":"0","AttendanceMaxPercentage":"25"},{"SequenceNo":2,"TypeOfStatus":"ShortDay","AttendanceMinPercentage":"26","AttendanceMaxPercentage":"50"},{"SequenceNo":3,"AttendanceMinPercentage":"51","AttendanceMaxPercentage":"70"},{"SequenceNo":4,"AttendanceMinPercentage":"71","AttendanceMaxPercentage":"100"}]',@LeaveRequestIn=N'Time',@RosterId=2,@FixedNoMeeting=0,@LocationRange=20,@CreatedBy=34594,@IsActive=1
CREATE   PROCEDURE  [dbo].[usp_TBL_ET_AttendanceGroup] 
(  
 @Mode VARCHAR(3),  
 @AttendanceGroupId bigint = 0,  
 @AttendanceGroupName varchar(100),  
 @GroupType varchar(50),  
 @ParentId bigint,  
 @SignInFormId bigint,  
 @SignOutFormId bigint,  
 @DefaultGeoRestrictionIn varchar(50),  
 @DefaultAuthTypeIn varchar(50),  
 @DefaultGeoRestrictionOut varchar(50),  
 @DefaultAuthTypeOut varchar(50),  
 @SignInType varchar(20),  
 @SignOutType varchar(20),  
 @SignInPromptType varchar(20),  
 @SignOutPromptType varchar(20),  
 @DefaultAttendanceCalcType varchar(50),  
 @AllowedAttendanceOverride bit,  
 @AttendanceApproverType varchar(20),
 @AttendanceApprover bigint,  
 @SignInRange int,  
 @SignOutRange int,  
 @CalculateTimeSpentIn varchar(50),  
 @CalculateScheduleVisitCount varchar(50),  
 @SignInTimeLater int,  
 @SignInTimeLaterType varchar(50),  
 @SignIndisallowedMessage varchar(50),  
 @SignOutdisallowedMessage varchar(50),  
 @LeaveRequestIn varchar(20),  
 @ApplyLeaveBeforeLimit int,  
 @RosterId bigint,  
 @FixedNoMeeting int,  
 @LocationRange int,  
 @FormConditionList nvarchar(max),  
 @SignInConditionList nvarchar(max),  
 @SignOutConditionList nvarchar(max),  
 @AttendanceConditionList nvarchar(max),                      
 @CreatedBy bigint,  
 @IsActive bit  
  )  
AS  
SET NOCOUNT ON  
  
BEGIN TRY  
IF (@Mode = 'AGI') /*This is for Insert Details */  
 BEGIN  
 if(Not Exists(Select AttendanceGroupName from TBL_ET_AttendanceGroup(nolock) ag Where ag.AttendanceGroupName = @AttendanceGroupName and ag.ParentId = @ParentId))  
 Begin  
 insert into TBL_ET_AttendanceGroup (AttendanceGroupName, GroupType, ParentId, SignInFormId, SignOutFormId, DefaultGeoRestrictionIn, DefaultAuthTypeIn, DefaultGeoRestrictionOut, DefaultAuthTypeOut, SignInType, SignOutType, SignInPromptType, SignOutPromptType, DefaultAttendanceCalcType, AllowedAttendanceOverride, AttendanceApproverType, AttendaceApprover, SignInRange, SignOutRange, CalculateTimeSpentIn, CalculateScheduleVisitCount, SignInTimeLater, SignInTimeLaterType, SignIndisallowedMessage, SignOutdisallowedMessage, LeaveRequestIn, ApplyLeaveBeforeLimit, RosterId, FixedNoMeeting, LocationRange, CreatedBy, CreatedDate, IsActive)  
 Values(@AttendanceGroupName, @GroupType, @ParentId, @SignInFormId, @SignOutFormId, @DefaultGeoRestrictionIn, @DefaultAuthTypeIn, @DefaultGeoRestrictionOut, @DefaultAuthTypeOut, @SignInType, @SignOutType, @SignInPromptType, @SignOutPromptType, @DefaultAttendanceCalcType, @AllowedAttendanceOverride, @AttendanceApproverType, @AttendanceApprover, @SignInRange, @SignOutRange, @CalculateTimeSpentIn, @CalculateScheduleVisitCount, @SignInTimeLater, @SignInTimeLaterType, @SignIndisallowedMessage, @SignOutdisallowedMessage, @LeaveRequestIn, @ApplyLeaveBeforeLimit, @RosterId, @FixedNoMeeting, @LocationRange, @CreatedBy, GetDate(), @IsActive)  
   
 set @AttendanceGroupId = SCOPE_IDENTITY()  
  
 if(@FormConditionList != '')  
 Begin  
 insert into TBL_ET_LocationConditionSetting (AttendanceGroupid, PhysicalAppointmentTypeId, TypeofForm, PromptMessage, CreatedDate, CreatedBy, IsActive)  
 select @AttendanceGroupid, @SignInFormId, 'SignInForm', '', GETDATE(), @CreatedBy, @IsActive  
  
 Declare @LCId1 bigint = SCOPE_IDENTITY()  
  
 Insert into TBL_ET_LocationConditionDetail (LCId, SequenceNo, Operand1, Operator, Operand2, Conjunction, CreatedDate, CreatedBy, IsActive)  
 select @LCId1, SequenceNo, Operand1, Operator, Operand2, Conjunction, GETDATE(), @CreatedBy, @IsActive from openjson(@FormConditionList)  
 with   
 (  
  SequenceNo int '$.SequenceNo',                    
  Operand1 nvarchar(100) '$.Operand1',                    
  Operator nvarchar(50) '$.Operator',  
  Operand2 nvarchar(50) '$.Operand2',  
  Conjunction nvarchar(50) '$.Conjunction'  
 ) tF  
  End  
  
 if(@SignInConditionList != '')  
 Begin  
 insert into TBL_ET_LocationConditionSetting (AttendanceGroupid, PhysicalAppointmentTypeId, TypeofForm, PromptMessage, CreatedDate, CreatedBy, IsActive)  
 select @AttendanceGroupid, @SignInFormId, 'SignIn', '', GETDATE(), @CreatedBy, @IsActive  
  
 Declare @LCId2 bigint = SCOPE_IDENTITY()  
  
  insert into TBL_ET_LocationConditionDetail (LCId, SequenceNo, Operand1, Operator, Operand2, Conjunction, CreatedDate, CreatedBy, IsActive)  
 select @LCId2, SequenceNo, Operand1, Operator, Operand2, Conjunction, GETDATE(), @CreatedBy, @IsActive from openjson(@SignInConditionList)  
 with   
 (  
  SequenceNo int '$.SequenceNo',                    
  Operand1 nvarchar(100) '$.Operand1',                    
  Operator nvarchar(50) '$.Operator',  
  Operand2 nvarchar(50) '$.Operand2',  
  Conjunction nvarchar(50) '$.Conjunction'  
 ) tS  
 End  
  
 if(@SignOutConditionList != '')  
 Begin  
 insert into TBL_ET_LocationConditionSetting (AttendanceGroupid, PhysicalAppointmentTypeId, TypeofForm, PromptMessage, CreatedDate, CreatedBy, IsActive)  
 select @AttendanceGroupid, @SignOutFormId, 'SignOut', '', GETDATE(), @CreatedBy, @IsActive  
  
 Declare @LCId3 bigint = SCOPE_IDENTITY()  
  
 insert into TBL_ET_LocationConditionDetail (LCId, SequenceNo, Operand1, Operator, Operand2, Conjunction, CreatedDate, CreatedBy, IsActive)  
 select @LCId3, SequenceNo, Operand1, Operator, Operand2, Conjunction, GETDATE(), @CreatedBy, @IsActive from openjson(@SignOutConditionList)  
 with   
 (  
  SequenceNo int '$.SequenceNo',                    
  Operand1 nvarchar(100) '$.Operand1',                    
  Operator nvarchar(50) '$.Operator',  
  Operand2 nvarchar(50) '$.Operand2',  
