   Procedure: [dbo].[usp_TBL_ET_AttendanceGroupBranchList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--usp_TBL_ET_AttendanceGroupBranchList 'AGL', 0, 'A Group 1', 34594, 1 
CREATE   PROCEDURE  [dbo].[usp_TBL_ET_AttendanceGroupBranchList] (
	@Mode VARCHAR(3),
	@AttGroupBranchMapId bigint = 0,
	@AttendanceGroupId bigint = 0,
	@BranchId bigint = 0,
	@CreatedBy bigint,
	@SearchText varchar(150) = null,
	@OffsetValue int = 0,
	@PagingSize int = 10
  )
AS
SET NOCOUNT ON

BEGIN TRY
Declare @ParentId bigint
Select @ParentId = ParentId from User_Detail (nolock) Where User_ID = @CreatedBy
IF (@Mode = 'ABL') /*This is for List */
  Begin
	Select count(agbp.AttGroupBranchMapId) over() as TotalRecords, agbp.AttGroupBranchMapId, agbp.AttendanceGroupId, BranchId, tiut.Name, tiut.address,
	tiut.city_id, tiut.state_id, tiut.country_id, mc.City_Name, ms.State_Name , mco.Country_Name
	from TBL_ET_AttendanceGroupBranchMapping(nolock) agbp
	inner join tbl_inv_UserTaxNumber (nolock) tiut on agbp.BranchId = tiut.id
	inner join m_city1 (nolock) mc on tiut.city_id = mc.City_ID
	inner join m_state1 (nolock) ms on tiut.state_id = ms.State_ID
	inner join m_country1 (nolock) mco on tiut.country_id = mco.Country_ID
	inner join User_Detail (nolock) Ud on agbp.CreatedBy = Ud.User_ID
	Where tiut.name like '%' + @SearchText + '%' and agbp.AttendanceGroupId = (case when @AttendanceGroupId = 0 then agbp.AttendanceGroupId else @AttendanceGroupId End) and agbp.BranchId = (case when @BranchId = 0 then agbp.BranchId else @BranchId End) 
	and Ud.ParentId = @ParentId and tiut.isactive = 1
	Order by agbp.AttGroupBranchMapId desc
	offset @OffsetValue rows fetch next @PagingSize rows only 
  End
 Else IF (@Mode = 'ABD') /*This is for Detail */
  Begin
	Select agbp.AttGroupBranchMapId, agbp.AttendanceGroupId, BranchId, tiut.Name, tiut.address,
	tiut.city_id, tiut.state_id, tiut.country_id, mc.City_Name, ms.State_Name , mco.Country_Name
	from TBL_ET_AttendanceGroupBranchMapping(nolock) agbp
	inner join tbl_inv_UserTaxNumber (nolock) tiut on agbp.BranchId = tiut.id
	inner join m_city1 (nolock) mc on tiut.city_id = mc.City_ID
	inner join m_state1 (nolock) ms on tiut.state_id = ms.State_ID
	inner join m_country1 (nolock) mco on tiut.country_id = mco.Country_ID
	inner join User_Detail (nolock) Ud on agbp.CreatedBy = Ud.User_ID
	Where agbp.AttGroupBranchMapId = @AttGroupBranchMapId and Ud.ParentId = @ParentId

  End
END TRY

BEGIN CATCH
	DECLARE @ErrorMessage NVARCHAR(4000);
	SELECT @ErrorMessage = ERROR_MESSAGE();
	RAISERROR (
			@ErrorMessage
			,16
			,1
			);
END CATCH



