  Select ag.AttendanceGroupId, AttendanceGroupName, GroupType, ParentId, SignInFormId, SignOutFormId, DefaultGeoRestrictionIn, DefaultAuthTypeIn, DefaultGeoRestrictionOut, DefaultAuthTypeOut, SignInType, SignOutType, SignInPromptType, SignOutPromptType, DefaultAttendanceCalcType, AllowedAttendanceOverride, AttendanceApproverType, AttendaceApprover, SignInRange, SignOutRange, LeaveRequestIn, CalculateTimeSpentIn, CalculateScheduleVisitCount, SignInTimeLater, SignInTimeLaterType, SignIndisallowedMessage, SignOutdisallowedMessage, ApplyLeaveBeforeLimit, RosterId, FixedNoMeeting, LocationRange, ag.CreatedDate, ag.CreatedBy, ag.UpdatedDate, ag.UpdatedBy, ag.IsActive, dbo.GetNameIdList(ag.AttendanceGroupId, 'Name') BranchNameList, dbo.GetNameIdList(ag.AttendanceGroupId, 'Id') BranchIdList, dbo.GetNameIdList(ag.AttendanceGroupId, 'UserMapName') UserMappedNameList, dbo.GetNameIdList(ag.AttendanceGroupId, 'UserMapId') UserMappedIdList  
 from TBL_ET_AttendanceGroup(nolock) ag   
  Where ag.AttendanceGroupName like '%' + @AttendanceGroupName + '%' and ag.ParentId = @ParentId  
 End  
 Else if(@AttendanceGroupId > 0)  
 Begin  
  
  Select ag.AttendanceGroupId, AttendanceGroupName, GroupType, ParentId, SignInFormId, SignOutFormId, DefaultGeoRestrictionIn, DefaultAuthTypeIn, DefaultGeoRestrictionOut, DefaultAuthTypeOut, SignInType, SignOutType, SignInPromptType, SignOutPromptType, DefaultAttendanceCalcType, AllowedAttendanceOverride, AttendanceApproverType, AttendaceApprover, SignInRange, SignOutRange, LeaveRequestIn, CalculateTimeSpentIn, CalculateScheduleVisitCount, SignInTimeLater, SignInTimeLaterType, SignIndisallowedMessage, SignOutdisallowedMessage, ApplyLeaveBeforeLimit, RosterId, FixedNoMeeting, LocationRange, ag.CreatedDate, ag.CreatedBy, ag.UpdatedDate, ag.UpdatedBy, ag.IsActive, dbo.GetNameIdList(ag.AttendanceGroupId, 'Name') BranchNameList, dbo.GetNameIdList(ag.AttendanceGroupId, 'Id') BranchIdList, dbo.GetNameIdList(ag.AttendanceGroupId, 'UserMapName') UserMappedNameList, dbo.GetNameIdList(ag.AttendanceGroupId, 'UserMapId') UserMappedIdList from TBL_ET_AttendanceGroup(nolock) ag   
  Where ag.ParentId = @ParentId and ag.AttendanceGroupId = @AttendanceGroupId   
  
   --select * from TBL_ET_LocationConditionSetting(nolock) lcs where lcs.AttendanceGroupId = @AttendanceGroupId  
    
  select lcd.LCId, lcd.SequenceNo, lcd.Operand1, lcd.Operator, lcd.Operand2, lcd.Conjunction, lcs.PhysicalAppointmentTypeId, lcs.TypeofForm, lcs.AttendanceGroupid   
  from TBL_ET_LocationConditionDetail(nolock) lcd  
  inner join TBL_ET_LocationConditionSetting (nolock) lcs on lcd.LCId  = lcs.LCId  
  where lcs.AttendanceGroupid = @AttendanceGroupId  
  
 select top 4 * from TBL_ET_AttendanceGroupAttendanceSettings where AttendanceGroupid = @AttendanceGroupId  
  
 End  
 End  
   Else IF (@Mode = 'AGD') /*This is for Insert Details */  
 BEGIN  
  
 Update TBL_ET_AttendanceGroup set IsDelete = 1, IsActive = 0 where AttendanceGroupId = @AttendanceGroupId and ParentId = @ParentId  

 if(@@ROWCount>0)
 Begin
	Select 'Record Deleted' STATUS
 End
 Else
 Begin
	Select 'Record Already Deleted' STATUS
 End
  
 End  
   Else IF (@Mode = 'AGV') /*This is for Insert Details */  
 BEGIN  
  
 Declare @UserIdTeamLst nvarchar(max)   
 select @UserIdTeamLst = UserIdTeamLst from ufn_GetUserRoleScope(@CreatedBy)   
 print @UserIdTeamLst   
  
 Select distinct ag.AttendanceGroupId, AttendanceGroupName, GroupType, ParentId, SignInFormId, SignOutFormId, DefaultGeoRestrictionIn, DefaultAuthTypeIn, DefaultGeoRestrictionOut, DefaultAuthTypeOut, SignInType, SignOutType, SignInPromptType, SignOutPromptType, DefaultAttendanceCalcType, AllowedAttendanceOverride, AttendanceApproverType, AttendaceApprover, ag.SignInRange, ag.SignOutRange, LeaveRequestIn,   CalculateTimeSpentIn, CalculateScheduleVisitCount, SignInTimeLater, SignInTimeLaterType, SignIndisallowedMessage, SignOutdisallowedMessage, ApplyLeaveBeforeLimit, RosterId, FixedNoMeeting, LocationRange, ag.CreatedDate, ag.CreatedBy, ag.UpdatedDate, ag.UpdatedBy, ag.IsActive, dbo.GetNameIdList(ag.AttendanceGroupId, 'Name') BranchNameList, dbo.GetNameIdList(ag.AttendanceGroupId, 'Id') BranchIdList, dbo.GetNameIdList(ag.AttendanceGroupId, 'UserMapName') UserMappedNameList, dbo.GetNameIdList(ag.AttendanceGroupId, 'UserMapId') UserMappedIdList  
     from TBL_ET_AttendanceGroup(nolock) ag inner join TBL_ET_AttendanceGroupUserMapping (nolock) agum 
	 on ag.AttendanceGroupId = agum.AttendanceGroupId  
  Where ag.AttendanceGroupName like '%' + @AttendanceGroupName + '%' and (agum.UserId in (select item from dbo.fu_SplitString(cast(@UserIdTeamLst as nvarchar(max)), ',')))  
  
 End  
END TRY  
  
BEGIN CATCH  
 DECLARE @ErrorMessage NVARCHAR(4000);  
 SELECT @ErrorMessage = ERROR_MESSAGE();  
 RAISERROR (  
   @ErrorMessage  
   ,16  
   ,1  
   );  
END CATCH  



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_AttendanceGroupList_Name]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--exec usp_TBL_ET_AttendanceGroupList_Name @OffsetValue=0,@PagingSize=50,@SearchText=N'',@Condition=N'StartWith',@UserId=34594,@ParentId=34594
CREATE   PROCEDURE  [dbo].[usp_TBL_ET_AttendanceGroupList_Name]  
(  
 @OffsetValue int = 0,                      
 @PagingSize int = 20,                          
 @SearchText [varchar](200) = NULL,                          
 @Condition varchar(20) = 'StartWith',                          
 @UserId [bigint] NULL,                          
 @ParentId [bigint] NULL  
)  
AS                          
  SET NOCOUNT ON   
  BEGIN TRY   
  begin   
  
declare @IsAdmin bit = 0    
declare @TimeZoneName nvarchar(255) =  isnull(( select TimeZone from User_Detail(nolock) where User_ID = @Userid),'India Standard Time')    
Declare @UserIDTeam bigint = @Userid ;    
declare @tbluser table (User_ID bigint,Name varchar(100), Image varchar(100))    
  
select @IsAdmin = IsAdmin, @ParentId = ParentId from User_Detail(nolock) where User_ID = @Userid    
if(@UserId = @ParentId)    
begin    
 set @Userid = 0;    
 insert into @tbluser    
 exec Use_GetUserDetails @ParentId  
end    
else   
Begin    
 insert into @tbluser    
 exec Use_GetUserDetails @UserId  
End  
  
if not exists(select * from TBL_ET_AttendanceGroup(nolock) where ParentId = @ParentId)  
Begin  
  
INSERT INTO [dbo].[TBL_ET_AttendanceGroup] ([AttendanceGroupName],[GroupType]  
           ,[ParentId] ,[SignInFormId] ,[SignOutFormId]  
           ,[DefaultGeoRestrictionIn]           ,[DefaultGeoRestrictionOut]  
           ,[DefaultAuthTypeIn]           ,[DefaultAuthTypeOut]  
           ,[SignInType]           ,[SignOutType]  
           ,[SignInPromptType]           ,[SignOutPromptType]  
           ,[DefaultAttendanceCalcType]           ,[CalculateTimeSpentIn]  
           ,[CalculateScheduleVisitCount]           ,[AllowedAttendanceOverride]  
           ,[LeaveRequestIn]           ,[AttendanceApproverType]  
           ,[AttendaceApprover]           ,[ApplyLeaveBeforeLimit]  
           ,[SignInRange]           ,[SignOutRange]  
           ,[SignInTimeLater]           ,[SignInTimeLaterType]  
           ,[SignIndisallowedMessage]           ,[SignOutdisallowedMessage], [RosterId]  
           ,[CreatedDate]           ,[CreatedBy],[UpdatedDate]           ,[UpdatedBy]  
           ,[IsActive]           ,[IsDelete])  
     select [AttendanceGroupName],[GroupType]  
           ,@ParentId as ParentId,[SignInFormId] ,[SignOutFormId]  
           ,[DefaultGeoRestrictionIn]           ,[DefaultGeoRestrictionOut]  
           ,[DefaultAuthTypeIn]           ,[DefaultAuthTypeOut]  
           ,[SignInType]           ,[SignOutType]  
           ,[SignInPromptType]           ,[SignOutPromptType]  
           ,[DefaultAttendanceCalcType]           ,[CalculateTimeSpentIn]  
           ,[CalculateScheduleVisitCount] ,[AllowedAttendanceOverride]  
           ,[LeaveRequestIn]           ,[AttendanceApproverType]  
           ,(case when GroupType in ('Geo','Kit19') then @ParentId   
     else 0 End) as AttendaceApprover ,[ApplyLeaveBeforeLimit]  
           ,[SignInRange]           ,[SignOutRange]  
           ,[SignInTimeLater]           ,[SignInTimeLaterType]  
           ,[SignIndisallowedMessage]           ,[SignOutdisallowedMessage], [RosterId]  
           ,[CreatedDate]           ,@ParentId as CreatedBy  
           ,[UpdatedDate]           ,[UpdatedBy]  
           ,[IsActive]           ,[IsDelete] from TBL_ET_AttendanceGroup(nolock) where ParentId = -1  
  
End  
  
Select count(t.AttendanceGroupId) over() as TotalRow,  * from (  
Select distinct ag.AttendanceGroupId, AttendanceGroupName, GroupType, ParentId, SignInFormId, SignOutFormId, DefaultGeoRestrictionIn, DefaultAuthTypeIn, DefaultGeoRestrictionOut, DefaultAuthTypeOut, SignInType, SignOutType, SignInPromptType, SignOutPromptType, DefaultAttendanceCalcType, AllowedAttendanceOverride, AttendanceApproverType, AttendaceApprover,   
(case when agum.SignInRange > 0 then agum.SignInRange else ag.SignInRange End) SignInRange,  
(case when agum.SignOutRange > 0 then agum.SignOutRange else ag.SignOutRange End) SignOutRange,   
ApplyLeaveBeforeLimit, RosterId, ag.CreatedDate, ag.CreatedBy, ag.UpdatedDate, ag.UpdatedBy, ag.IsActive, dbo.GetNameIdList(ag.AttendanceGroupId, 'Name') BranchNameList, dbo.GetNameIdList(ag.AttendanceGroupId, 'Id') BranchIdList, dbo.GetNameIdList(ag.AttendanceGroupId, 'UserMapName') UserMappedNameList, dbo.GetNameIdList(ag.AttendanceGroupId, 'UserMapId') UserMappedIdList, (case when Isnull(ag.IsActive, 0) = 1 then 'Active'  
 when Isnull(ag.IsDelete, 0) = 1 then 'Deleted' else 'IsActive' End) Status,   
 (case when Isnull(ag.IsDelete, 0) = 1 then 'Deleted' else '' End) DeleteStatus  
from TBL_ET_AttendanceGroup(nolock) ag left join TBL_ET_AttendanceGroupUserMapping(nolock) agum 
on ag.AttendanceGroupId = agum.AttendanceGroupId   
 Where Isnull(ag.IsDelete, 0) = 0 and Isnull(ag.IsActive, 0) = 1 and ag.AttendanceGroupName like '%' + @SearchText + '%' and (agum.UserId in (select User_ID from @tbluser) or ag.ParentId = @ParentId)   
 )t  
 Order by t.AttendanceGroupName Asc   
 OFFSET @OffsetValue Rows FETCH NEXT @PagingSize ROWS ONLY   
  end   
 END TRY   
BEGIN CATCH  
exec usp_inserterrorinfo  
 DECLARE @ErrorMessage NVARCHAR(4000);                           
 SELECT @ErrorMessage = ERROR_MESSAGE();                           
 RAISERROR (@ErrorMessage, 16, 1);                           
END CATCH  



GO

/* ============================================================
   Procedure: [dbo].[Usp_TBL_ET_AttendanceGroupUserMappingList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--Usp_TBL_ET_AttendanceGroupUserMappingList 'AGL', 0, 'A Group 1', 34594, 1 
CREATE   PROCEDURE  [dbo].[Usp_TBL_ET_AttendanceGroupUserMappingList] (
	@Mode VARCHAR(3),
	@AttGroupUserMapId bigint = 0,
	@AttendanceGroupId bigint = 0,
	@UserId bigint = 0,
	@SearchText varchar(100) = '',
	@OffsetValue int = 0,
	@PagingSize int = 0
  )
AS
SET NOCOUNT ON

BEGIN TRY
Declare @ParentId bigint
Select @ParentId = ParentId from User_Detail (nolock) Where User_ID = @UserId

IF (@Mode = 'AUL') /*This is for Insert Details */
	BEGIN
	Select count(agm.AttGroupUserMapId) over() as TotalRecords, agm.AttGroupUserMapId, agm.AttendanceGroupId, UserId, GeoRestriction, AuthType, AttendanceCalcType, UserBranchId, BaseSiteID, BaseSiteType, UserAutoSignIn, UserAutoSignOut, 
	concat(ud.FName, ' ', ud.LName) FullName, tiut.name UserBranchName, agm.CreatedDate, agm.CreatedBy, agm.IsActive 
	from TBL_ET_AttendanceGroupUserMapping (nolock) agm
	inner join User_Detail (nolock) ud on agm.UserId = ud.User_ID
	inner join tbl_inv_UserTaxNumber (nolock) tiut on agm.UserBranchId = tiut.id
	where tiut.name like '%' + @SearchText + '%' and agm.AttendanceGroupId = IIf(@AttendanceGroupId > 0, @AttendanceGroupId, agm.AttendanceGroupId) and 
	ud.ParentID = @ParentId and UserId = IIf(@UserId > 0, @UserId, agm.UserId)
	order by agm.AttGroupUserMapId Desc
	offset @OffsetValue rows fetch next @PagingSize rows only

  End
 Else IF (@Mode = 'AUD') /*This is for Insert Details */
  Begin
	Select agm.AttGroupUserMapId, agm.AttendanceGroupId, UserId, GeoRestriction, AuthType, AttendanceCalcType, UserBranchId, BaseSiteID, BaseSiteType,
	UserAutoSignIn, UserAutoSignOut, concat(ud.FName, ' ', ud.LName) FullName, tiut.name UserBranchName, agm.CreatedDate, agm.CreatedBy, agm.IsActive 
	from TBL_ET_AttendanceGroupUserMapping (nolock) agm
	inner join User_Detail (nolock) ud on agm.UserId = ud.User_ID
	inner join tbl_inv_UserTaxNumber (nolock) tiut on agm.UserBranchId = tiut.id
	where agm.AttGroupUserMapId = @AttGroupUserMapId and ud.ParentID = @ParentId

  End
END TRY

BEGIN CATCH
	DECLARE @ErrorMessage NVARCHAR(4000);
	SELECT @ErrorMessage = ERROR_MESSAGE();
	RAISERROR (
			@ErrorMessage
			,16
			,1
			);
END CATCH



GO

/* ============================================================
   Procedure: [dbo].[Usp_TBL_ET_AttendanceGroupUserMappingSave]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--Usp_TBL_ET_AttendanceGroupUserMappingSave 'AGL', 0, 'A Group 1', 34594, 1 
CREATE   PROCEDURE  [dbo].[Usp_TBL_ET_AttendanceGroupUserMappingSave] (
	@Mode VARCHAR(3),
	@AttGroupUserMapId bigint = 0,
	@AttendanceGroupId bigint = 0,
	@UserId bigint = 0,
	@GeoRestriction varchar(100) = null,
	@AuthType varchar(100) = null,
	@AttendanceCalcType varchar(100) = null,
	@UserBranchId int = 0,
	@BaseSiteID bigint =0, 
	@BaseSiteType varchar(20) = null,
	@UserAutoSignIn int = 0,
	@UserAutoSignOut int = 0,
	@CreatedBy bigint,
	@IsActive bit = true
  )
AS
SET NOCOUNT ON

BEGIN TRY
Declare @ParentId bigint
Select @ParentId = ParentId from User_Detail (nolock) Where User_ID = @CreatedBy
 IF (@Mode = 'AUI') /*This is for Insert Details */
	BEGIN
	if(Not Exists(Select UserId from TBL_ET_AttendanceGroupUserMapping(nolock) agup
	inner join User_Detail (nolock) Ud on agup.CreatedBy = Ud.User_ID
	Where AttendanceGroupId = @AttendanceGroupId and agup.UserId = @UserId and Ud.ParentId = @ParentId))
	Begin
	insert Into TBL_ET_AttendanceGroupUserMapping (AttendanceGroupId, UserId, GeoRestriction, AuthType, AttendanceCalcType, UserBranchId, 
	BaseSiteID, BaseSiteType, UserAutoSignIn, UserAutoSignOut, CreatedDate, CreatedBy, IsActive)
	values (@AttendanceGroupId, @UserId, @GeoRestriction, @AuthType, @AttendanceCalcType, @UserBranchId,
	@BaseSiteID, @BaseSiteType, @UserAutoSignIn, @UserAutoSignOut, GETDATE(), @CreatedBy, @IsActive)

	Select 'Record Saved' Status, cast(SCOPE_IDENTITY() as bigint) Id 
	End
	Else
	Begin
	Select 'Record Already Exists' Status, 0 Id
	End
  End
 Else IF (@Mode = 'AUU') /*This is for Insert Details */
  Begin
	if(Exists(Select UserId from TBL_ET_AttendanceGroupUserMapping(nolock) agup
	inner join User_Detail (nolock) Ud on agup.CreatedBy = Ud.User_ID
	Where agup.UserId = @UserId and Ud.ParentId = @ParentId))
	Begin

	Update TBL_ET_AttendanceGroupUserMapping set AttendanceGroupId = @AttendanceGroupId, UserId = @UserId, GeoRestriction = @GeoRestriction, AuthType = @AuthType, AttendanceCalcType = @AttendanceCalcType, UserBranchId = @UserBranchId, BaseSiteID = @BaseSiteID, BaseSiteType = @BaseSiteType,
	UserAutoSignIn = @UserAutoSignIn, UserAutoSignOut = @UserAutoSignOut, UpdatedDate = GETDATE(), UpdatedBy = @CreatedBy, IsActive = @IsActive
	where AttGroupUserMapId = @AttGroupUserMapId

	Select 'Record Updated' Status, @AttGroupUserMapId Id
	End
	Else
	Begin
	Select 'Record Not Exists' Status, @AttGroupUserMapId Id
	End
  End
END TRY

BEGIN CATCH
	DECLARE @ErrorMessage NVARCHAR(4000);
	SELECT @ErrorMessage = ERROR_MESSAGE();
	RAISERROR (
			@ErrorMessage
			,16
			,1
			);
END CATCH



GO

/* ============================================================
   Procedure: [dbo].[usp_tbl_ET_AttendanceIssueAprove]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_tbl_ET_AttendanceIssueAprove] (
	@Mode VARCHAR(2)
	,@AttendenceIssueId bigint = 0
	,@AttendanceId BIGINT = 0
	,@UserId BIGINT = 0
	,@ActionType varchar(15) = null
	,@ActionDateTime DateTime = NULL
	,@AttendanceGroupId BIGINT = 0
	,@ShiftId BIGINT = 0
	,@Remarks VARCHAR(500) = NULL
	,@ApproverStatus VARCHAR(15) = NULL
	,@RequestDate DateTime = NULL
	,@CreatedBy BIGINT = 0
	,@IsActive bit = 1
	)
AS
SET NOCOUNT ON

BEGIN TRY
	IF (@Mode = 'II') /*This is for Insert Details */
	BEGIN
	Declare @ParentId bigint
	set @AttendanceGroupId = 0
 
	Select top 1 @AttendanceGroupId = atgp.AttendanceGroupId, @ParentId = atgp.ParentId
	from TBL_ET_AttendanceGroup atgp(nolock) 
	left join TBL_ET_AttendanceGroupUserMapping agum (nolock) on atgp.AttendanceGroupId = agum.AttendanceGroupId
	where agum.UserId = @UserId and atgp.IsActive = 1 and agum.IsActive = 1 


	set @ShiftId = 0
	select top 1 @ShiftId = shmr.ShiftId from TBL_ET_ShiftMaster shmr(nolock) 
	inner join TBL_ET_ShiftUserMapping suma (nolock) on shmr.ShiftId = suma.ShiftId and shmr.IsActive = 1
	Where suma.UserId = @UserId
	
	DECLARE @ID BIGINT;

	if((@AttendanceGroupId > 0) and (@ShiftId > 0))
	Begin
	IF NOT EXISTS (SELECT 1 FROM TBL_ET_Attendance WITH (NOLOCK) WHERE cast(AttendanceIn as Date) = CAST(@ActionDateTime as date) AND ParentId = @ParentId and UserId = @UserId)
		BEGIN
			INSERT INTO TBL_ET_AttendanceIssueRequest (
				 UserId
				,ActionType
				,ActionDateTime
				,AttendanceGroupId
				,ShiftId
				,Remarks
				,ParentId
				,RequestDate
				,IsActive
				,CreatedBy
				,CreatedDate
				)
			VALUES (
				@UserId
				,@ActionType
				,@ActionDateTime
				,@AttendanceGroupId
				,@ShiftId
				,@Remarks
				,@ParentId
				,GETDATE()
				,@IsActive
				,@UserId
				,GETDATE()				
				)

			SET @ID = scope_identity();

		SELECT 'Record Saved' STATUS, @ID AttendeceIssueId

       	Select GETDATE()
		END
		ELSE
		BEGIN
			SELECT 'Record Already Exist' STATUS, 0 AttendeceIssueId
		END
	END /*End here for insert*/
	ELSE
		BEGIN
			SELECT 'Attendance group not assigned' STATUS, 0 AttendeceIssueId
  	    END
	END
	Else IF (@Mode = 'IU') /*This is for Insert Details */
	BEGIN
	Declare @ParentId2 bigint
	set @AttendanceGroupId = 0
 
	Select top 1 @AttendanceGroupId = atgp.AttendanceGroupId, @ParentId2 = atgp.ParentId
	from TBL_ET_AttendanceGroup atgp(nolock) 
	left join TBL_ET_AttendanceGroupUserMapping agum (nolock) on atgp.AttendanceGroupId = agum.AttendanceGroupId
	where agum.UserId = @UserId and atgp.IsActive = 1 and agum.IsActive = 1 


	set @ShiftId = 0
	select top 1 @ShiftId = shmr.ShiftId from TBL_ET_ShiftMaster shmr(nolock) 
	inner join TBL_ET_ShiftUserMapping suma (nolock) on shmr.ShiftId = suma.ShiftId and shmr.IsActive = 1
	Where suma.UserId = @UserId
	
	DECLARE @ID2 BIGINT;

	if((@AttendenceIssueId > 0) and (@AttendanceGroupId > 0) and (@ShiftId > 0))
	Begin
		Update TBL_ET_AttendanceIssueRequest set UserId = @UserId, ActionType =@ActionType, ActionDateTime = @ActionDateTime, AttendanceGroupId = @AttendanceGroupId, ShiftId = @ShiftId, Remarks = @Remarks, ParentId = @ParentId, RequestDate = GETDATE(), IsActive = @IsActive, CreatedBy = @CreatedBy, CreatedDate = GETDATE()
			where AttendanceIssueId = @AttendenceIssueId

		SELECT 'Record Updated' STATUS, @AttendenceIssueId AttendanceIssueId

       	Select GETDATE()
       End
	  ELSE
	   BEGIN
		 SELECT 'Record not exist' STATUS, 0 AttendanceIssueId
	   END
	END /*End here for insert*/
	Else IF (@Mode = 'UI') /*This is for Update Details */
	BEGIN
	if(not Exists (select 1 from TBL_ET_AttendanceIssueReqApproval(nolock) where AttendenceIssueId = @AttendenceIssueId and ApproverStatus = @ApproverStatus))
	Begin
	if((@AttendenceIssueId > 0) and (@ApproverStatus != ''))
	Begin
			INSERT INTO TBL_ET_AttendanceIssueReqApproval (
				AttendenceIssueId
				,ApprovedBy
				,ApproverRemarks
				,ApproverStatus
				,ApprovedDate
				,IsActive
				,CreatedBy
				,CreatedDate
				)
			VALUES (
				 @AttendenceIssueId
				,@UserId
				,@Remarks
				,@ApproverStatus
				,GETDATE()
				,@IsActive
				,@UserId
				,GETDATE()				
				)
		SELECT 'Record Saved!' Status, @AttendenceIssueId AttendenceIssueId
		End
		ELSE
		BEGIN
			SELECT 'Record not Saved.' Status, @AttendenceIssueId AttendenceIssueId 
		END

       End
		ELSE
		BEGIN
			SELECT 'Record Already Exist!' Status, @AttendenceIssueId AttendenceIssueId 
		END

       	Select GETDATE()
	END /*End here for update*/

END TRY

BEGIN CATCH
	DECLARE @ErrorMessage NVARCHAR(4000);
	SELECT @ErrorMessage = ERROR_MESSAGE();
	RAISERROR (
			@ErrorMessage
			,16
			,1
			);
END CATCH



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_AttendanceIssueReqApprList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE  [dbo].[usp_TBL_ET_AttendanceIssueReqApprList] (
	@Mode VARCHAR(2)
	,@AttendanceIssueReqApprovalId bigint = 0
	,@AttendanceIssueId bigint = 0
	,@SearchText nvarchar(max) = ''
	,@CreatedBy	bigint = 0
	,@Offset int = 0
	,@PageSize int = 0
)
AS
SET NOCOUNT ON

BEGIN TRY
Declare @ParentId bigint
Select @ParentId = ParentId from User_Detail(nolock) where User_Id = @CreatedBy

  IF (@Mode = 'AL') /*This is List Details */
   BEGIN

if(@SearchText != '')
Begin
set @SearchText = ' and ' + @SearchText
End
Declare @UserIdTeamLst varchar(4000)
select @UserIdTeamLst = UserIdTeamLst 
		from ufn_GetUserRoleScope(@CreatedBy)
print @UserIdTeamLst
Declare @query nvarchar(max)
set @query = 'Select count(atr.AttendanceIssueId) over() as TotalRecords, atr.AttendanceIssueId, atr.ActionType, (ud.FName + '' '' + ud.LName) + ''('' + ud.User_Login + '')'' EmployeeName, Cast(atr.ScheduledDateTime as varchar(20)) ScheduledDateTime, Cast(atr.ActionDateTime as varchar(20)) ActionDateTime, Cast(atr.RequestDate as varchar(20)) RequestDate, (case when atr.IsActive = 1 then ''Active''
 else ''InActive'' End) Status, isnull(atra.ApprovedBy, 0) ApprovedBy,
 (ud2.FName + '' '' + ud2.LName) + ''('' + ud2.User_Login + '')'' ApprovedName,
isnull(atra.ApproverRemarks, '''') ApproverRemarks, isnull(atra.ApproverStatus, ''Pending'') ApproverStatus, 
isnull(atra.ApprovedDate , '''') ApprovedDate, isnull(atra.AttendanceIssueReqApprovalId, 0) AttendanceIssueReqApprovalId,
 atr.Remarks from TBL_ET_AttendanceIssueRequest(nolock) atr 
 inner join User_Detail(nolock) ud on atr.UserId = ud.User_ID
 left join TBL_ET_AttendanceIssueReqApproval(nolock) atra on atr.AttendanceIssueId = atra.AttendenceIssueId
 left join User_Detail(nolock) ud2 on atra.ApprovedBy = ud2.User_ID
 where (atr.UserId in (select item from dbo.fu_SplitString(''' + cast(@UserIdTeamLst as varchar(1000)) + ''', '',''))) 
 and ActionType != '''' and (atr.AttendanceIssueId not in (select atraa.AttendenceIssueId from TBL_ET_AttendanceIssueReqApproval(nolock) atraa where atraa.ApproverStatus = ''Approved'')) ' + @SearchText + '
 Order By atr.ActionDateTime Desc
 Offset '+ cast(@Offset as varchar(10)) + ' rows fetch next '+ cast(@PageSize as varchar(10)) + ' rows only '
 
 print @query

Declare @query2 nvarchar(max)
set @query2 = 'Select count(atr.AttendanceIssueId) over() as TotalRecords, atr.AttendanceIssueId, atr.ActionType, (ud.FName + '' '' + ud.LName) + ''('' + ud.User_Login + '')'' EmployeeName,Cast(atr.ScheduledDateTime as varchar(20)) ScheduledDateTime, Cast(atr.ActionDateTime as varchar(20)) ActionDateTime, Cast(atr.RequestDate as varchar(20)) RequestDate, (case when atr.IsActive = 1 then ''Active''
 else ''InActive'' End) Status, isnull(atra.ApprovedBy, 0) ApprovedBy,
 (ud.FName + '' '' + ud.LName) + ''('' + ud.User_Login + '')'' ApprovedName,
isnull(atra.ApproverRemarks, '''') ApproverRemarks, isnull(atra.ApproverStatus, ''Pending'') ApproverStatus, 
isnull(atra.ApprovedDate , '''') ApprovedDate, isnull(atra.AttendanceIssueReqApprovalId, 0) AttendanceIssueReqApprovalId,
 atr.Remarks from TBL_ET_AttendanceIssueRequest(nolock) atr 
 inner join User_Detail(nolock) ud on atr.UserId = ud.User_ID
 left join TBL_ET_AttendanceIssueReqApproval(nolock) atra on atr .AttendanceIssueId = atra.AttendenceIssueId
 left join User_Detail(nolock) ud2 on atra.ApprovedBy = ud2.User_ID
 where (atr.UserId in (select item from dbo.fu_SplitString(''' + cast(@UserIdTeamLst as varchar(1000)) + ''', '',''))) 
 and ActionType != '''' and atra.ApproverStatus = ''Approved'' ' + @SearchText + '
 Order By atr.ActionDateTime Desc
 Offset '+ cast(@Offset as varchar(10)) + ' rows fetch next '+ cast(@PageSize as varchar(10)) + ' rows only '
 
 execute sp_executesql @query

 execute sp_executesql @query2

   END /*End here for list */

  Else IF (@Mode = 'DI') /*This is List Details */
   BEGIN

	Select count(atr.AttendanceIssueId) over() as TotalRecords, atr.AttendanceIssueId, atr.ActionType, 
	(ud.FName + ' ' + ud.LName) + '(' + ud.User_Login + ')' EmployeeName, ud.Address, ud.CompnayName,
	convert(varchar, atr.ScheduledDateTime, 100) ScheduledDateTime, 
	convert(varchar, atr.ActionDateTime, 100) ActionDateTime, 
	convert(varchar, atr.RequestDate, 100) RequestDate, 
	(case when atr.IsActive = 1 then 'Active' else 'InActive' End) Status, atr.Remarks 
	from TBL_ET_AttendanceIssueRequest(nolock) atr 
	inner join User_Detail(nolock) ud on atr.UserId = ud.User_ID
	where atr.AttendanceIssueId = @AttendanceIssueId

	Select GetDate() CurrentDate
   END /*End here for list */
  Else IF (@Mode = 'DA') /*This is List Details */
   BEGIN

	Select count(aira.AttendanceIssueReqApprovalId) over() as TotalRecords, 
	aira.AttendanceIssueReqApprovalId, atr.AttendanceIssueId, atr.ActionType, 
	convert(varchar, aira.ApprovedDate, 104) ApprovedDate, 
	aira.ApproverStatus, aira.ApproverRemarks, aira.ApprovedBy,
	(ud2.FName + ' ' + ud2.LName) + '(' + ud2.User_Login + ')' ApproverName,
	(ud.FName + ' ' + ud.LName) + '(' + ud.User_Login + ')' EmployeeName,
	ud.Address, ud.CompnayName,
	convert(varchar, atr.ScheduledDateTime, 100) ScheduledDateTime, 
	convert(varchar, atr.ActionDateTime, 100) ActionDateTime, 
	convert(varchar, atr.RequestDate, 100) RequestDate, 
	(case when atr.IsActive = 1 then 'Active' else 'InActive' End) Status, atr.Remarks 
	from TBL_ET_AttendanceIssueRequest(nolock) atr 
	inner join TBL_ET_AttendanceIssueReqApproval(nolock) aira on atr.AttendanceIssueId = aira.AttendenceIssueId
	inner join User_Detail(nolock) ud on atr.UserId = ud.User_ID
	inner join User_Detail(nolock) ud2 on aira.ApprovedBy = ud2.User_ID
	where aira.AttendanceIssueReqApprovalId = @AttendanceIssueReqApprovalId

	Select GetDate() CurrentDate
   END /*End here for list */

END TRY

BEGIN CATCH
	DECLARE @ErrorMessage NVARCHAR(4000);
	SELECT @ErrorMessage = ERROR_MESSAGE();
	RAISERROR (
			@ErrorMessage
			,16
			,1
			);
END CATCH



