/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_AttendanceIssueReqApprList_Name]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE  [dbo].[usp_TBL_ET_AttendanceIssueReqApprList_Name] ( 
	@OffsetValue int = 0,
	@PagingSize int = 6,
	@SearchText nvarchar(max) = '',
	@Condition varchar(20) = 'StartWith',
	@UserId bigint,
	@ApproverStatus nvarchar(max) = '',
	@ParentId bigint  
)
as
begin

	--declare
	--	@OffsetValue int = 0,
	--	@PagingSize int = 1,
	--	@SearchText nvarchar(max) = '',
	--	@Condition varchar(20) = 'StartWith',
	--	@UserId bigint = 27215,
	--	@ApproverStatus nvarchar(max) = 'Approved,Rejected,Pending',
	--	@ParentId bigint = 27215 


	declare
		@StartPoint int, @EndPoint int
	
	set @StartPoint = (@OffsetValue + 1)
	set	@EndPoint = (@StartPoint + @PagingSize - 1 )

	select @ParentId = ParentId from User_Detail(nolock) where User_Id = @UserId
  
	if(@SearchText != '')  
	begin  
		set @SearchText = ' and ' + @SearchText  
	end 
	
	declare @UserIdTeamLst varchar(4000)  
	select @UserIdTeamLst = UserIdTeamLst from ufn_GetUserRoleScope(@UserId)  
	
	print @UserIdTeamLst  

	declare @query nvarchar(max)  
	set @query = concat(N'select * from ( ',
		N'select  ',
		N'row_number() over (partition by ParentId order by ActionDateTime desc) as sno,  ',
		N'count(t.AttendanceIssueId) over() as TotalRecords, * from  ',
		N'( ',
			N'select atr.AttendanceIssueId, atr.ActionType,  ',
			N'concat(ud.FName, '' '', ud.LName,  '' ('' , ud.User_Login , '')'') EmployeeName, ',
			N'cast(atr.ScheduledDateTime as varchar(20)) ScheduledDateTime,  ',
			N'cast(atr.ActionDateTime as varchar(20)) ActionDateTime,  ',
			N'cast(atr.RequestDate as varchar(20)) RequestDate,  ',
			N'(case when atr.IsActive = 1 then ''Active'' else ''InActive'' End) Status,  ',
			N'isnull(atra.ApprovedBy, 0) ApprovedBy, ',
			N'concat(ud2.FName, '' '', ud2.LName, ''('', ud2.User_Login, '')'') as ApprovedName, ',
			N'isnull(atra.ApproverRemarks, '''') ApproverRemarks,  ',
			N'isnull(atra.ApproverStatus, ''Pending'') ApproverStatus, ',
			N'cast(isnull(atra.ApprovedDate , '''') as varchar(20)) ApprovedDate, isnull(atra.AttendanceIssueReqApprovalId, 0) ',
			N'AttendanceIssueReqApprovalId, ',
			N'atr.Remarks,  ',
			N'concat(isnull(iutn.Address, ''''), '', '', isnull(ct.City_Name, ''''),  '', '', ',
			N'isnull(st.State_Name, ''''), '', '',  isnull(co.Country_Name, '''')) as [BranchAddress],  ',
			N'(select top 1 isnull(CONVERT(VARCHAR, AttendanceIn, 100), '''') LastLoginAttendanceIn from TBL_ET_Attendance(nolock) ',
				N'Where UserId = atr.UserId order by 1 desc) LastLoginAttendanceIn, ',
				N'atr.ParentId ',
		N'from TBL_ET_AttendanceIssueRequest(nolock) atr    ',
				N'inner join User_Detail(nolock) ud on atr.UserId = ud.User_ID   ',
				N'left join TBL_ET_AttendanceIssueReqApproval(nolock) atra on atr.AttendanceIssueId = atra.AttendenceIssueId   ',
				N'left join User_Detail(nolock) ud2 on atra.ApprovedBy = ud2.User_ID   ',
				N'left join TBL_ET_AttendanceGroupUserMapping (nolock) agum on atr.UserId = agum.UserId ',
				N'left join tbl_inv_UserTaxNumber (nolock) iutn on agum.UserBranchId = iutn.Id ',
				N'left join M_City (nolock) ct on iutn.City_Id = ct.City_Id ',
				N'left join M_State (nolock) st on iutn.State_Id = st.State_Id ',
				N'left join M_Country (nolock) co on iutn.Country_Id = co.Country_Id ',
				N'where (atr.UserId in (select item from dbo.fu_SplitString(''', @UserIdTeamLst, ''', '','')))    ',
				N'and isnull(atr.ActionType, '''') <> ''''   ',
				N'and isnull(atra.ApproverStatus, ''Pending'') in (',
				N'select lower(trim([value])) from string_split(''', @ApproverStatus,''', '',''))  ',
			N') t  ',
		N') b where sno between ', @StartPoint, ' and ', @EndPoint, ' and (1=1)  ' )

	print @query
	execute sp_executesql @query

end



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_AttendanceIssueReqList_Name]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_TBL_ET_AttendanceIssueReqList_Name] (  
 @OffsetValue int = 0  
 ,@PagingSize int = 0  
 ,@SearchText nvarchar(max) = ''  
 ,@Condition varchar(20) = 'StartWith'                        
 ,@UserId bigint = 0  
 ,@ParentId bigint = 0  
)
AS
SET NOCOUNT ON

BEGIN TRY  
--Declare @ParentId bigint  
Select @ParentId = ParentId from User_Detail(nolock) where User_Id = @UserId
  
if(@SearchText != '')
Begin  
set @SearchText = ' and ' + @SearchText  
End  
Declare @UserIdTeamLst varchar(4000)  
select @UserIdTeamLst = UserIdTeamLst from ufn_GetUserRoleScope(@UserId)  
print @UserIdTeamLst  
Declare @query nvarchar(max)
set @query = 'Select distinct count(t.AttendanceIssueId) over() as TotalRecords, * from (Select atr.AttendanceIssueId, atr.ActionType, (ud.FName + '' '' + ud.LName) + '' ('' + ud.User_Login + '')'' EmployeeName, convert(varchar, atr.ScheduledDateTime, 22) ScheduledDateTime, Cast
(atr.ActionDateTime as varchar(20)) ActionDateTime, Cast(atr.RequestDate as varchar(20)) RequestDate, (case when atr.IsActive = 1 then ''Active''  
 else ''InActive'' End) Status, isnull(atra.ApprovedBy, 0) ApprovedBy,  
 (ud2.FName + '' '' + ud2.LName) + ''('' + ud2.User_Login + '')'' ApprovedName,  
isnull(atra.ApproverRemarks, '''') ApproverRemarks, isnull(atra.ApproverStatus, ''Pending'') ApproverStatus,   
isnull(atra.ApprovedDate , '''') ApprovedDate, isnull(atra.AttendanceIssueReqApprovalId, 0) AttendanceIssueReqApprovalId,  
 atr.Remarks, isnull(iutn.Address, '''') +'', ''+ isnull(ct.City_Name, '''') + '', '' + isnull(st.State_Name, '''') + '', '' + isnull(co.Country_Name, '''')BranchAddress, (select top 1 isnull(CONVERT(VARCHAR, AttendanceIn, 100), '''') LastLoginAttendanceIn from TBL_ET_Attendance(nolock)
Where UserId = atr.UserId order by 1 desc) LastLoginAttendanceIn from TBL_ET_AttendanceIssueRequest(nolock) atr   
 inner join User_Detail(nolock) ud on atr.UserId = ud.User_ID  
 inner join TBL_ET_AttendanceGroupUserMapping (nolock) agum on atr.UserId = agum.UserId
 inner join tbl_inv_UserTaxNumber (nolock) iutn on agum.UserBranchId = iutn.Id
 left join M_City (nolock) ct on iutn.City_Id = ct.City_Id
 left join M_State (nolock) st on iutn.State_Id = st.State_Id
 left join M_Country (nolock) co on iutn.Country_Id = co.Country_Id
 left join TBL_ET_AttendanceIssueReqApproval(nolock) atra on atr.AttendanceIssueId = atra.AttendenceIssueId  
 left join User_Detail(nolock) ud2 on atra.ApprovedBy = ud2.User_ID  
 where (atr.UserId in (select item from dbo.fu_SplitString(''' + cast(@UserIdTeamLst as varchar(1000)) + ''', '','')))   
 and ActionType != '''' and (atr.AttendanceIssueId not in (select atraa.AttendenceIssueId from TBL_ET_AttendanceIssueReqApproval(nolock) atraa where (atraa.ApproverStatus = ''Approved'' or atraa.ApproverStatus = ''Rejected''))) 
)t 
 where (1=1) ' + @SearchText + ' 
  Order By t.ActionDateTime Desc 
 Offset '+ cast(@OffsetValue as varchar(10)) + ' rows fetch next '+ cast(@PagingSize as varchar(10)) + ' rows only ' 
   
 print @query  

 execute sp_executesql @query  
 
END TRY  
  
BEGIN CATCH  
 DECLARE @ErrorMessage NVARCHAR(4000);  
 SELECT @ErrorMessage = ERROR_MESSAGE();  
 RAISERROR (  
   @ErrorMessage  
   ,16  
   ,1  
   );  
END CATCH  



