/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_AttendanceLeaveDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--usp_TBL_ET_AttendanceLeaveDetails 'DD', 34594, '2023-03-13 00:00:00.000','2023-03-13 00:00:00.000'
CREATE   PROCEDURE [dbo].[usp_TBL_ET_AttendanceLeaveDetails] (
	@Mode VARCHAR(2),
	@UserId bigint,
	@StartDate Datetime,
	@EndDate Datetime
	)
AS
SET NOCOUNT ON

BEGIN TRY

IF (@Mode = 'AD') /*This is for Insert Details */
	BEGIN

--Declare @Mode VARCHAR(2) = '',
--	@UserId bigint = --34594, --
--	34594,-- 36932, 38991, 39832, 39304, 34126, 34081, 32392, 32226, 34136
--	@StartDate Datetime = '2022-12-09 00:00:00.000',
--	@EndDate Datetime = '2022-12-09 00:00:00.000'


select * from (
Select atra.LeaveApprovalId, atra.LeaveRequestId, telr.LeaveId, Cast(telr.FromDate as varchar(100)) FromDate, Cast(telr.ToDate as varchar(100)) ToDate, Cast(CONVERT(varchar, telr.FromDate,13) as varchar(12)) FromDateNew, cast(CONVERT(varchar,telr.ToDate,13) as varchar(12)) ToDateNew, StartQuarterDate, EndQuarterDate, cast(FromTime as varchar(5)) FromTime, cast(ToTime as varchar(5)) ToTime, telr.UserId, Remarks, Cast(telr.CreatedDate as varchar(100)) RequestDate, TypeOfLeave,
	case When ((telr.EndQuarterDate - telr.StartQuarterDate) + 1) = 4 then 'Full Leave'
	When ((telr.EndQuarterDate - telr.StartQuarterDate) + 1) = 3 then 'Half and Short Leave'
	When ((telr.EndQuarterDate - telr.StartQuarterDate) + 1) = 2 then 'Half Leave'
	When ((telr.EndQuarterDate - telr.StartQuarterDate) + 1) = 1 then 'Short Leave'
	else '' end LeaveRequestStatus,
	ud.CompnayName, (isnull(ud.Address, '') + ',' + isnull(ct.City_Name, '') + ',' + isnull(st.State_Name, '') + ',' + isnull(co.Country_Name, '')) Address, (ud.FName + ' ' + ud.LName) + ' (' + ud.User_Login + ')' EmployeeName, (ud2.FName + ' ' + ud2.LName) + '(' + ud2.User_Login + ')' ApprovedName,  
 isnull(atra.RemarksApprover, '') RemarksApprover, isnull(atra.ApproverStatus, 'Pending') ApproverStatus,   
 --isnull(atra.ApprovedDate , '') ApprovedDate, 
 --isnull(atra.LeaveApprovalId, 0) LeaveApprovalId, 
 isnull(iutn.Address, '') +', '+ isnull(ct.City_Name, '') + ', ' + isnull(st.State_Name, '') + ', ' + isnull(co.Country_Name, '') BranchAddress, 
(select top 1 isnull(CONVERT(VARCHAR, AttendanceIn, 100), '''') LastLoginAttendanceIn from TBL_ET_Attendance(nolock) Where UserId = telr.UserId order by 1 desc) LastLoginAttendanceIn  from TBL_ET_LeaveApproval (nolock) atra
 inner join TBL_ET_LeaveRequest (nolock) telr on atra.LeaveRequestId = telr.LeaveRequestId
 inner join User_Detail(nolock) ud on telr.UserId = ud.User_ID  
 left join User_Detail(nolock) ud2 on atra.ApproverUserId = ud2.User_ID  
 left join TBL_ET_AttendanceGroupUserMapping (nolock) agum on telr.UserId = agum.UserId
 left join tbl_inv_UserTaxNumber (nolock) iutn on agum.UserBranchId = iutn.Id
 left join M_City (nolock) ct on iutn.City_Id = ct.City_Id
 left join M_State (nolock) st on iutn.State_Id = st.State_Id
 left join M_Country (nolock) co on iutn.Country_Id = co.Country_Id
	where telr.UserId = @UserId
	and (((telr.FromDate between @StartDate and @EndDate) or (telr.ToDate between @StartDate and @EndDate)))

Union all
select 0 LeaveApprovalId, * from (Select distinct telr.LeaveRequestId, telr.LeaveId, Cast(telr.FromDate as varchar(100)) FromDate, Cast(telr.ToDate as varchar(100)) ToDate, Cast(CONVERT(varchar, telr.FromDate,13) as varchar(12)) FromDateNew, cast(CONVERT(varchar,telr.ToDate,13) as varchar(12)) ToDateNew, 
	StartQuarterDate, EndQuarterDate, cast(FromTime as varchar(5)) FromTime, cast(ToTime as varchar(5)) ToTime, telr.UserId, Remarks, Cast(telr.CreatedDate as varchar(100)) RequestDate, 
	--(case when (telr.EndQuarterDate - telr.StartQuarterDate + 1) = 1 then 'shortLeave'
	--when (telr.EndQuarterDate - telr.StartQuarterDate + 1) = 2 then 'halfLeave'
	--when (telr.EndQuarterDate - telr.StartQuarterDate + 1) = 3 then 'fullLeavee'
	--when (telr.EndQuarterDate - telr.StartQuarterDate + 1) = 4 then 'fullDay' else '' end) 
	TypeOfLeave, '' LeaveRequestStatus, ud.CompnayName, (isnull(ud.Address, '') + ',' + isnull(ct.City_Name, '') + ',' + isnull(st.State_Name, '') + ',' + isnull(co.Country_Name, '')) Address, '' EmployeeName, '' ApporverName, '' RemarksApprover,  isnull(atra.ApproverStatus, 'Pending') ApproverStatus, 
 isnull(iutn.Address, '') +', '+ isnull(ct.City_Name, '') + ', ' + isnull(st.State_Name, '') + ', ' + isnull(co.Country_Name, '') BranchAddress, 
(select top 1 isnull(CONVERT(VARCHAR, AttendanceIn, 100), '''') LastLoginAttendanceIn from TBL_ET_Attendance(nolock) Where UserId = telr.UserId order by 1 desc) LastLoginAttendanceIn from TBL_ET_LeaveRequest(nolock) telr
 inner join User_Detail(nolock) ud on telr.UserId = ud.User_ID  
 inner join TBL_ET_LeaveApproval(nolock) atra on telr.LeaveRequestId != atra.LeaveRequestId
 left join User_Detail(nolock) ud2 on atra.ApproverUserId = ud2.User_ID  
 left join TBL_ET_AttendanceGroupUserMapping (nolock) agum on telr.UserId = agum.UserId
 left join tbl_inv_UserTaxNumber (nolock) iutn on agum.UserBranchId = iutn.Id
 left join M_City (nolock) ct on iutn.City_Id = ct.City_Id
 left join M_State (nolock) st on iutn.State_Id = st.State_Id
 left join M_Country (nolock) co on iutn.Country_Id = co.Country_Id
	where telr.UserId = @UserId
	and (((telr.FromDate between @StartDate and @EndDate) or (telr.ToDate between @StartDate and @EndDate)))
)t where ApproverStatus = 'Pending'
)q

 END /*End here for search*/

END TRY

BEGIN CATCH
	DECLARE @ErrorMessage NVARCHAR(4000);
	SELECT @ErrorMessage = ERROR_MESSAGE();
	RAISERROR (
			@ErrorMessage
			,16
			,1
			);
END CATCH



