/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_AttendanceLeaveStatusCALA]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec usp_tbl_ET_AttendanceLeaveStatusCALA 'ATS', '2023-01-01', '2023-01-31', 34594, 'Attendance'
--exec usp_tbl_ET_AttendanceLeaveStatusCALA 'ATS', '2023-01-01', '2023-01-31', 34594, 'Leave'
--exec usp_tbl_ET_AttendanceLeaveStatusCALA 'ATS', '2022-12-01', '2022-12-31', 34594, 'Attendance'
CREATE   PROCEDURE  [dbo].[usp_TBL_ET_AttendanceLeaveStatusCALA] (
	@Mode VARCHAR(3)
	,@FromDate DateTime = NULL
	,@ToDate DateTime = NULL
	,@UserId BIGINT = 0
	,@TypeOfStatus VARCHAR(20) = NULL
	)
AS
SET NOCOUNT ON

BEGIN TRY
	--Declare
	--	@Mode VARCHAR(3) = N'ATS',
	--	@FromDate DateTime = N'2023-5-01',
	--	@ToDate DateTime = N'2023-5-31',
	--	@UserId BIGINT = 32222,
	--	@TypeOfStatus VARCHAR(20) = N'Attendance'


	IF (@Mode = 'ATS') /*This is for Search Details */
	BEGIN
	drop table if exists #TampTbl

	Create table #TampTbl(date date)

	;with dates_CTE (date) as (
		select cast(@FromDate as Date) 
		Union ALL
		select DATEADD(day, 1, date)
		from dates_CTE
		where date < cast(@ToDate as Date)
		)
	insert into #TampTbl (date)
	select c.* from dates_CTE c;
	
	select *, (case when ((WorkingDuration = '0.00') and (AttendanceDate <= getdate())) then 'Absent'
	when ((WorkingDuration = '0.00') and (AttendanceDate > getdate())) then '' else 'Persent' end) AttendanceStatus from (
	select date AttendanceDate, ROW_NUMBER() OVER(PARTITION BY date ORDER BY date ASC) AS row_number, isnull(cast(TotalHoursTime as varchar(10)) +':'+ cast((TotalMinutesTime % 60) as varchar(10)), '0.00') WorkingDuration, isnull(UserId, @UserId) UserId, isnull(ParentId, 0) ParentId, AttendanceIn, AttendanceOut
	from (
	select tt.date, isnull(teat.AttendanceIn, '') AttendanceIn, isnull(teat.AttendanceOut, '') AttendanceOut, DATEDIFF(hour, AttendanceIn, AttendanceOut) As TotalHoursTime, (DATEDIFF(MINUTE, AttendanceIn, AttendanceOut) % 60) As TotalMinutesTime, UserId, ParentId,
	case when AttendanceIn != '' then cast(AttendanceIn as Date) when AttendanceIn != '' then cast(AttendanceOut as Date) else '' End AttendanceDate from #TampTbl tt 
	 Left join TBL_ET_Attendance (nolock) teat on cast(teat.AttendanceIn as date) = tt.date and teat.UserId = @UserId 
	 ) t1
	 )t11 where row_number = 1

	select (DATEDIFF(Day, @FromDate, @ToDate) +1) TotalAttendance,
	Sum((case 
	when (isnull(tlr.AttendanceIn, '') = '' and isnull(tlr.AttendanceOut, '') != '')  then 1 
	when isnull(tlr.AttendanceIn, '') != '' then 1
	else 0 end)) TotalPresent from ( Select 
		row_number() over (partition by cast(tlr.AttendanceIn as date)
			order by AttendanceId desc) as rno,	
	cast(tlr.AttendanceIn as date) AttendanceIn, 
	cast(tlr.AttendanceOut as date) AttendanceOut

	from TBL_ET_Attendance (nolock) tlr where
	 (
		 (cast(tlr.AttendanceIn as date) between Cast(@FromDate as date) and Cast(@ToDate as date)) or
		 (cast(tlr.AttendanceOut as date) between Cast(@FromDate as date) and Cast(@ToDate as date))
		 ) and tlr.UserId = @UserId
	) tlr where rno = 1

	 select GetDate() TodayDate

	 select GetDate() TodayDate

	End
	ELse IF (@Mode = 'AIO') /*This is for Search Details */
	BEGIN
	Declare @UserBranchId bigint  =0
	select top 1 @UserBranchId = UserBranchId from TBL_ET_AttendanceGroupUserMapping(nolock) um
	 where um.Userid =@UserId

	drop table if exists #TampTbl2

	Create table #TampTbl2(date date)

	;with dates_CTE2 (date) as (
		select cast(@FromDate as Date) 
		Union ALL
		select DATEADD(day, 1, date)
		from dates_CTE2
		where date < cast(@ToDate as Date)
		)
	insert into #TampTbl2 (date)
	select c.* from dates_CTE2 c;
	
	select AttendanceDate,
	WorkingDuration, AttendanceIn , AttendanceOut, HolidayName,
	 (case when FORMAT(AttendanceIn,'hh:mm tt') = '12:00 AM' then '' else FORMAT(AttendanceIn,'hh:mm tt') end) InTime, 
	 (case when FORMAT(AttendanceOut,'hh:mm tt') = '12:00 AM' then '' else FORMAT(AttendanceOut,'hh:mm tt') end) OutTime,
	(case when TotalQuarter = 4 then 'FL' when TotalQuarter = 3 then 'FL-1Q' when TotalQuarter = 2 then 'HL' when TotalQuarter = 1 then 'SL' else '' end)
	LeaveType,
	(case 
	when HolidayName != '' then 'Holiday'
	when ((DATENAME(dw, AttendanceDate) = 'Sunday') and (AttendanceDate <= getdate())) then 'Week Off'
	when ((WorkingDuration = '0.00') and (AttendanceDate <= getdate())) then 'Absent'
	when ((WorkingDuration = '0.00') and (AttendanceDate > getdate())) then '' else 'Persent' end) AttendanceStatus from (
	select date AttendanceDate, ROW_NUMBER() OVER(PARTITION BY date ORDER BY date ASC) AS row_number, isnull(cast(TotalHoursTime as varchar(10)) +':'+ cast((TotalMinutesTime % 60) as varchar(10)), '0.00') WorkingDuration, isnull(t1.UserId, @UserId) UserId, isnull(t1.ParentId, 0) ParentId, AttendanceIn, AttendanceOut, isnull(StartQuarterDate, 0) StartQuarterDate, isnull(EndQuarterDate, 0) EndQuarterDate, (case when (isnull(EndQuarterDate, 0) - isnull(StartQuarterDate, 0)) > 0 then (isnull(EndQuarterDate, 0) - isnull(StartQuarterDate, 0) + 1) else 0 end) TotalQuarter, isnull(hm.HolidayName, '') HolidayName, @UserBranchId UserBranchId
	from (
	select tt.date, isnull(teat.AttendanceIn, '') AttendanceIn, isnull(teat.AttendanceOut, '') AttendanceOut, DATEDIFF(hour, AttendanceIn, AttendanceOut) As TotalHoursTime, (DATEDIFF(MINUTE, AttendanceIn, AttendanceOut) % 60) As TotalMinutesTime, teat.UserId, teat.ParentId,
	case when AttendanceIn != '' then cast(AttendanceIn as Date) when AttendanceIn != '' then cast(AttendanceOut as Date) else '' End AttendanceDate, telr.StartQuarterDate, telr.EndQuarterDate from #TampTbl2 tt 
	 Left join TBL_ET_Attendance (nolock) teat on cast(teat.AttendanceIn as date) = tt.date and teat.UserId = @UserId 
	 left join TBL_ET_LeaveRequest (nolock) telr on cast(tt.date as date) between telr.FromDate and telr.ToDate and telr.UserId = @UserId 
	 ) t1
	 left join TBL_ET_HolidayMaster (nolock) hm on (cast(hm.HolidayDate as date) = cast(t1.date as date))
	 left join TBL_ET_HolidayBranch (nolock) hmb on (@UserBranchId = hmb.BranchId)
	 ) t11
	 where row_number = 1

	 select GetDate() TodayDate

	 select GetDate() TodayDate

	 select GetDate() TodayDate
	End
	Else IF (@Mode = 'CIO') /*This is for Search Details */
	BEGIN
	drop table if exists #TampTbl3

	Create table #TampTbl3(date date)

	;with dates_CTE3 (date) as (
		select cast(@FromDate as Date) 
		Union ALL
		select DATEADD(day, 1, date)
		from dates_CTE3
		where date < cast(@ToDate as Date)
		)
	insert into #TampTbl3 (date)
	select c.* from dates_CTE3 c;

	select *, (TotalCheckInRequest - (TotalInApproved + TotalInReject)) TotalInPending,
	(TotalCheckOutRequest - (TotalOutApproved + TotalOutReject)) TotalOutPending
	--,(case when isnull(TotalInApproved, 0) > 0 then
	--((isnull(TotalInApproved, 0) / isnull(((TotalInApproved + TotalInReject) + (TotalCheckInRequest - (TotalInApproved + TotalInReject))),0)) * 100)
	--Else 0 End) InApprovedPer,
	--(case when isnull(TotalOutApproved, 0) > 0 then
	--((isnull(TotalOutApproved, 0) / isnull(((TotalOutApproved + TotalOutReject) + (TotalCheckOutRequest - (TotalOutApproved + TotalOutReject))),0)) * 100)
	--Else 0 End) OutApprovedPer,
	--(case when isnull(TotalInReject, 0) > 0 then
	--((isnull(TotalInReject, 0) / isnull(((TotalInApproved + TotalInReject) + (TotalCheckInRequest - (TotalInApproved + TotalInReject))),0)) * 100)
	--Else 0 End) InRejectPer,
	--(case when isnull(TotalOutReject, 0) > 0 then
	--((isnull(TotalOutReject, 0) / isnull(((TotalOutApproved + TotalOutReject) + (TotalCheckOutRequest - (TotalOutApproved + TotalOutReject))),0)) * 100)
	--Else 0 End) OutRejectPer,
	--	(case when isnull((TotalCheckInRequest - (TotalInApproved + TotalInReject)), 0) > 0 then
	--((isnull((TotalCheckInRequest - (TotalInApproved + TotalInReject)), 0) / isnull(((TotalInApproved + TotalInReject) + (TotalCheckInRequest - (TotalInApproved + TotalInReject))),0)) * 100)
	--Else 0 End) InPendingPer,
	--(case when isnull((TotalCheckOutRequest - (TotalOutApproved + TotalOutReject)), 0) > 0 then
	--((isnull((TotalCheckOutRequest - (TotalOutApproved + TotalOutReject)), 0) / isnull(((TotalOutApproved + TotalOutReject) + (TotalCheckOutRequest - (TotalOutApproved + TotalOutReject))),0)) * 100)
	--Else 0 End) OutPendingPer
	from (
	select AttendanceDate, WorkingDuration, AttendanceIn, AttendanceOut, 
	(case when ((TotalCountCheckIn = 0) and (TotalCountCheckOut  = 0)) then 0
	else TotalDefaultCount End) TotalDefaultCount, TotalCountCheckIn, TotalCountCheckOut,
	sum(CheckInRequestCount) TotalCheckInRequest, sum(CheckOutRequestCount) TotalCheckOutRequest,
	sum(ApprovedInCount) TotalInApproved, sum(RejectInCount) TotalInReject,
	sum(ApprovedOutCount) TotalOutApproved, sum(RejectOutCount) TotalOutReject
	from (
	select date AttendanceDate, ROW_NUMBER() OVER(PARTITION BY date ORDER BY date ASC) AS row_number, isnull(cast(TotalHoursTime as varchar(10)) +':'+ cast((TotalMinutesTime % 60) as varchar(10)), '0.00') WorkingDuration, isnull(tt1.UserId, @UserId) UserId, isnull(tt1.ParentId, 0) ParentId, AttendanceIn, AttendanceOut, sum(DefaultCount) TotalDefaultCount, sum(CountCheckIn) TotalCountCheckIn, sum(CountCheckOut) TotalCountCheckOut, sum((case when chinrIn.ActionDateTime != '' then 1 else 0 end)) CheckInRequestCount, 
	sum((case when chinrOut.ActionDateTime != '' then 1 else 0 end)) CheckOutRequestCount,
	sum((case when chinraIn.ApproverStatus = 'Approved' then 1 else 0 end)) ApprovedInCount,
	sum((case when chinraOut.ApproverStatus = 'Approved' then 1 else 0 end)) ApprovedOutCount,
	sum((case when chinraIn.ApproverStatus = 'Reject' then 1 else 0 end)) RejectInCount,
	sum((case when chinraOut.ApproverStatus = 'Reject' then 1 else 0 end)) RejectOutCount
	from (
	select t1.date, t1.TotalHoursTime, t1.TotalMinutesTime, t1.UserId, t1.ParentId, t1.AttendanceIn, t1.AttendanceOut, 1 DefaultCount, (case when chin.CheckIn != '' then 1 else 0 End) CountCheckIn, (case when chin.CheckOut != '' then 1 else 0 End) CountCheckOut from(
	select tt.date, isnull(teat.AttendanceIn, '') AttendanceIn, isnull(teat.AttendanceOut, '') AttendanceOut, DATEDIFF(hour, AttendanceIn, AttendanceOut) As TotalHoursTime, (DATEDIFF(MINUTE, AttendanceIn, AttendanceOut) % 60) As TotalMinutesTime, teat.UserId, teat.ParentId,
	case when AttendanceIn != '' then cast(AttendanceIn as Date) when AttendanceIn != '' then cast(AttendanceOut as Date) else '' End AttendanceDate from #TampTbl3 tt 
	Left join TBL_ET_Attendance (nolock) teat on ((cast(teat.AttendanceIn as date) = tt.date) or (cast(teat.AttendanceOut as date) = tt.date)) and teat.UserId = @UserId 
	) t1 
	left join TBL_ET_GeoEntityCheckInOut (nolock) chin on ((cast(chin.CheckIn as date) between cast(t1.AttendanceIn as date) and cast(t1.AttendanceOut as Date)) or (cast(chin.CheckOut as date) between cast(t1.AttendanceIn as date) and cast(t1.AttendanceOut as Date)))
	) tt1 
	left join TBL_ET_GeoEntityCheckInOutRequest (nolock) chinrIn on chinrIn.ActionType = 'CheckIn' and (cast(chinrIn.ActionDateTime as date) between cast(tt1.AttendanceIn as date) and cast(tt1.AttendanceOut as Date))
	left join TBL_ET_GeoEntityCheckInOutRequest (nolock) chinrOut on chinrOut.ActionType = 'CheckOut' and (cast(chinrOut.ActionDateTime as date) between cast(tt1.AttendanceIn as date) and cast(tt1.AttendanceOut as Date))
	left join TBL_ET_GeoEntityCheckInOutRequestApproval (nolock) chinraIn on chinrIn.GeoEntityChkInOutRequestId = chinraIn.GeoEntityChkInOutRequestId
	left join TBL_ET_GeoEntityCheckInOutRequestApproval (nolock) chinraOut on chinrOut.GeoEntityChkInOutRequestId = chinraOut.GeoEntityChkInOutRequestId
	group by DefaultCount, CountCheckIn, CountCheckOut, date, AttendanceIn, AttendanceOut, tt1.UserId, tt1.ParentId, TotalHoursTime, TotalMinutesTime, chinrIn.ActionDateTime, chinrOut.ActionDateTime, chinraIn.ApproverStatus, chinraOut.ApproverStatus
	) t11 
	where row_number = 1 
	group by CheckInRequestCount, CheckOutRequestCount, AttendanceDate, WorkingDuration, AttendanceIn, AttendanceOut, TotalDefaultCount,
	TotalCountCheckIn, TotalCountCheckOut 
	) t12
	order by AttendanceDate asc 

	 select GetDate() TodayDate

	 select GetDate() TodayDate

	 select GetDate() TodayDate
	End
	Else IF (@Mode = 'LS') /*This is for Search Details */
	BEGIN
	Declare @UserBranchId4 bigint  =0
	select top 1 @UserBranchId4 = UserBranchId from TBL_ET_AttendanceGroupUserMapping(nolock) um
	 where um.Userid =@UserId

	drop table if exists #TampTbl4

	Create table #TampTbl4(date date)

	;with dates_CTE4 (date) as (
		select cast(@FromDate as Date) 
		Union ALL
		select DATEADD(day, 1, date)
		from dates_CTE4
		where date < cast(@ToDate as Date)
		)
	insert into #TampTbl4 (date)
	select c.* from dates_CTE4 c;
	
	select AttendanceDate, HolidayName, 
	(case when TotalQuarter = 4 then 'FL' when TotalQuarter = 3 then 'FL-1Q' when TotalQuarter = 2 then 'HL' when TotalQuarter = 1 then 'SL' else '' end) LeaveRequest, 
	(case when TotalQuarter = 4 then 1 when TotalQuarter = 3 then 1 when TotalQuarter = 2 then 1 when TotalQuarter = 1 then 1 else 0 end) 
	TotalLeaveRequest, TotalApproved, TotalPending, TotalReject from (
	select date AttendanceDate, ROW_NUMBER() OVER(PARTITION BY date ORDER BY date ASC) AS row_number, isnull(StartQuarterDate, 0) StartQuarterDate, isnull(EndQuarterDate, 0) EndQuarterDate, (case when (isnull(EndQuarterDate, 0) - isnull(StartQuarterDate, 0)) > 0 then (isnull(EndQuarterDate, 0) - isnull(StartQuarterDate, 0) + 1) else 0 end) TotalQuarter, isnull(hm.HolidayName, '') HolidayName, @UserBranchId4 UserBranchId, 
	sum(ApprovedCount) TotalApproved, sum(PendingCount) TotalPending, sum(RejectCount) TotalReject
	from (
	select tt.date, isnull(teat.AttendanceIn, '') AttendanceIn, isnull(teat.AttendanceOut, '') AttendanceOut, 
	case when AttendanceIn != '' then cast(AttendanceIn as Date) when AttendanceIn != '' then cast(AttendanceOut as Date) else '' End AttendanceDate,
	telr.StartQuarterDate, telr.EndQuarterDate, 
	(case when telra.ApproverStatus = 'Approved' Then 1 else 0 End) ApprovedCount,
	(case when ((tt.date between telr.FromDate and telr.ToDate) and telr.LeaveRequestId not in (select LeaveRequestId from TBL_ET_LeaveApproval(nolock) telaa where telaa.LeaveRequestId = telr.LeaveRequestId)) Then 1 else 0 End) PendingCount,
	(case when telra.ApproverStatus = 'Reject' then 1 else 0 end) RejectCount
	from #TampTbl4 tt 
	 Left join TBL_ET_Attendance (nolock) teat on cast(teat.AttendanceIn as date) = tt.date and teat.UserId = @UserId 
	 left join TBL_ET_LeaveRequest (nolock) telr on cast(tt.date as date) between telr.FromDate and telr.ToDate and telr.UserId = @UserId 
	 left join TBL_ET_LeaveApproval (nolock) telra on telr.LeaveRequestId = telra.LeaveRequestId and telra.IsActive = 1
	 ) t1
	 left join TBL_ET_HolidayBranch (nolock) hmbr on (@UserBranchId4 = hmbr.BranchId)
	 left join TBL_ET_HolidayMaster (nolock) hm on (hmbr.HolidayId = hm.HolidayId) and (cast(hm.HolidayDate as date) = cast(t1.date as date))
	 Group by t1.date, StartQuarterDate, EndQuarterDate, hm.HolidayName
	 ) t11
	where row_number = 1

	 --Total Count
	select TotalRequest, TotalApprover, TotalReject, (TotalRequest - (TotalApprover + TotalReject)) TotalPending from (
	 select (Select Sum((DATEDIFF(day, FromDate, ToDate) + 1)) from TBL_ET_LeaveRequest(nolock) tlr where 
	 ((cast(tlr.FromDate as date) between Cast(@FromDate as date) and Cast(@ToDate as date)) or
	 (cast(tlr.ToDate as date) between Cast(@FromDate as date) and Cast(@ToDate as date)))
	 and tlr.UserId = @UserId) TotalRequest, Sum(CountApproverDay) TotalApprover, Sum(CountRejectDay) TotalReject from (
	 Select (DATEDIFF(day, FromDate, ToDate) + 1) CountRequestDay,
	 (case when la.ApproverStatus = 'Approved' then 1 else 0 end) CountApproverDay, 
	 (case when la.ApproverStatus = 'Reject' then 1 else 0 end) CountRejectDay 
	 from TBL_ET_LeaveRequest(nolock) tlr 
	 left join TBL_ET_LeaveApproval (nolock) la on tlr.LeaveRequestId = la.LeaveRequestId
	 where (
	 (cast(tlr.FromDate as date) between Cast(@FromDate as date) and Cast(@ToDate as date)) or
	 (cast(tlr.ToDate as date) between Cast(@FromDate as date) and Cast(@ToDate as date))
	 ) and tlr.UserId = @UserId
	 )t
	 )tt


	Select GETDATE()

	Select GETDATE()
	End
	Else IF (@Mode = 'CIS') /*This is for Search Details */
	BEGIN
	Select GETDATE()
	End
END TRY

BEGIN CATCH
	DECLARE @ErrorMessage NVARCHAR(4000);

	SELECT @ErrorMessage = ERROR_MESSAGE();

	RAISERROR (
			@ErrorMessage
			,16
			,1
			);
END CATCH



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_AttendanceList_Name]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--usp_TBL_ET_AttendanceList_Name 'AL', 0, 10, '', ' (month(cast(AttendanceIn as date)) = Month(cast(''2023-02-01'' as date)) and year(cast(AttendanceIn as date)) = year(cast(''2023-02-01'' as date))) ', '', '', 34594,34594
--usp_TBL_ET_AttendanceList_Name 'AL', 0, 100, '', 'CheckInCount=2', '2023-03-01', '', 34594,34594
CREATE   PROCEDURE [dbo].[usp_TBL_ET_AttendanceList_Name] (
 @Mode varchar(10) = ''
 ,@OffsetValue int = 0
 ,@PagingSize int = 10
 ,@SearchText nvarchar(max) = ''
 ,@Condition varchar(max) = ''
 ,@FromDate varchar(20) = ''
 ,@ToDate varchar(20) = ''
 ,@UserId bigint = 0
 ,@ParentId bigint = 0
)
AS
SET NOCOUNT ON
BEGIN TRY

	--declare 
	--	@Mode varchar(10) = N'AL',
	--	@OffsetValue int = 0,
	--	@PagingSize int = 10,
	--	@SearchText nvarchar(max) = N'',
	--	@Condition varchar(max) = '',
	--	@FromDate varchar(25) = N'01-Sep-2025',
	--	@ToDate varchar(25) = N'01-Sep-2025',
	--	@UserId bigint = 48929,
	--	@ParentId bigint = 48529



Select @ParentId = ParentId from User_Detail(nolock) where User_Id = @UserId 
Declare @UserIdTeamLst nvarchar(max) 

if(@SearchText != '') 
Begin 
set @SearchText = ' and ' + @SearchText 
End 

if(@Condition != '')
Begin
set @Condition = ' and ' + @Condition
end
else
Begin
set @Condition = ''
End

select @UserIdTeamLst = UserIdTeamLst from ufn_GetUserRoleScope(@UserId) 
print @UserIdTeamLst 

DECLARE @ReportDate VARCHAR(20)=@FromDate

DECLARE @LastDay INT =DAY(EOMONTH(@ReportDate))

DECLARE @DayStart INT=01

drop table if exists #TEMPMonth

CREATE TABLE #TEMPMonth ([MDay] VARCHAR(20))

WHILE @LastDay>=@DayStart

BEGIN
    
INSERT INTO #TEMPMonth 
    
SELECT CAST(CAST(YEAR(@ReportDate)AS VARCHAR)+'-'+CAST(MONTH(@ReportDate)AS VARCHAR)+'-'+CAST(@DayStart AS VARCHAR) AS DATE)
    SET @DayStart+=1
END

INSERT INTO TBL_ET_TEMPMonthDate(MDate)

SELECT * FROM #TEMPMonth where cast(MDay as Date) not in (select MDate from TBL_ET_TEMPMonthDate)


Declare @query1 nvarchar(max)
Declare @query2 nvarchar(max)

set @query1 = ' Select distinct count(t.AttendanceId) over() as TotalRecords, t.*, ''Day Schedule'' DayType,
	SUM(t.WorkingMinutes) over() as [TotalMonthHours]
from (Select dbo.fn_TBL_ET_GetAttendanceStatus(atra.AttendanceGroupId, (case when ((DATEDIFF(minute,CAST(atra.AttendanceIn AS DATETIME), CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME)) * 100)/DATEDIFF(MINUTE, smat.StartTime, smat.EndTime)) > 100 then 100 else ((DATEDIFF(minute,CAST(atra.AttendanceIn AS DATETIME), CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME)) * 100)/DATEDIFF(MINUTE, smat.StartTime, smat.EndTime)) end)) AttendanceStatus, dbo.fn_TBL_ET_AttendanceTotalSummary(atra.UserId, format(CAST(atra.AttendanceIn AS DATE), ''dd-MMM-yyyy''), ''TotalCount'') TotalhoursMonth, dbo.fn_TBL_ET_AttendanceTotalSummary(atra.UserId, format(CAST(atra.AttendanceIn AS DATE), ''dd-MMM-yyyy''), ''TotalWorkingDay'') TotalWorkingDay, dbo.fn_TBL_ET_AttendanceTotalSummary(atra.UserId, format(CAST(atra.AttendanceIn AS DATE), ''dd-MMM-yyyy''), ''TotalLeave'') TotalLeave, dbo.fn_TBL_ET_AttendanceTotalSummary(atra.UserId, format(CAST(atra.AttendanceIn AS DATE), ''dd-MMM-yyyy''), ''WeekOff'') WeekOff, dbo.fn_TBL_ET_AttendanceTotalSummary(atra.UserId, format(CAST(atra.AttendanceIn AS DATE), ''dd-MMM-yyyy''), ''LateSignin'') LateSignin, atra.AttendanceId, FORMAT(CAST(tmde.MDate AS DATETIME),''dd-MMM-yyyy'') MDate, atra.AttendanceIn, 
atra.AttendanceOut, FORMAT(CAST(atra.AttendanceIn AS DATETIME),''hh:mm tt'') IATime, FORMAT(CAST(atra.AttendanceOut AS DATETIME),''hh:mm tt'') OATime, 
(cast(DATEDIFF(hour,CAST(atra.AttendanceIn AS DATETIME), CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME)) as varchar(10)) +'':''+ cast((DATEDIFF(minute,CAST(atra.AttendanceIn AS DATETIME), CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME))%60) as varchar(10))) +'' Hrs'' TotalHours,
cast(atra.AttendanceIn as date) IADate, cast(atra.AttendanceOut as date) OADate, atra.CreatedDate, atra.LatitudeIn, atra.LongitudeIn, atra.LatitudeOut,
atra.LongitudeOut, atra.DeviceId, atra.RemarksIn, atra.RemarksOut, atra.AttendanceGroupId, atra.ShiftId, smat.ShiftName, agum.UserId, atra.ParentId, (ud2.FName +'' ''+ ud2.LName) UserName,ud2.User_Login, atra.CreatedBy, isnull(atra.UpdatedBy, atra.CreatedBy) UpdatedBy, atra.IsActive,
smat.StartTime, smat.EndTime, cast((cast((DATEDIFF(MINUTE, smat.StartTime, smat.EndTime)/60) as varchar(10)) +'':''+ (cast(isnull(DATEDIFF(MINUTE, smat.StartTime, smat.EndTime),''00'')%60 as varchar(10)))) as varchar(15)) ShiftTime,
cast(cast(DATEDIFF(hour,CAST(atra.AttendanceIn AS DATETIME), CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME)) as varchar(10)) +'':''+ cast((DATEDIFF(minute,CAST(atra.AttendanceIn AS DATETIME), CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME))%60) as varchar(10)) as time) WorkingTime, DATEDIFF(MINUTE, smat.StartTime, smat.EndTime) ShiftMinutes,
DATEDIFF(minute,CAST(atra.AttendanceIn AS DATETIME), CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME)) WorkingMinutes,
(case when ((DATEDIFF(minute,CAST(atra.AttendanceIn AS DATETIME), CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME)) * 100)/DATEDIFF(MINUTE, smat.StartTime, smat.EndTime)) > 100 then 100 else ((DATEDIFF(minute,CAST(atra.AttendanceIn AS DATETIME), CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME)) * 100)/DATEDIFF(MINUTE, smat.StartTime, smat.EndTime)) end) AttendancePerc, 
  dbo.fn_TBL_ET_GeoEntityCheckInOutCount(atra.UserId, cast(atra.AttendanceIn as varchar(20)), ''CheckIn'') CheckInCount, 
  dbo.fn_TBL_ET_GeoEntityCheckInOutCount(atra.UserId, cast(atra.AttendanceIn as varchar(20)), ''CheckOut'') CheckOutCount,
  dbo.fn_TBL_ET_BreakTransactionListByUserIdDate(atra.UserId, cast(atra.AttendanceIn as varchar(20))) BreakTrans
 from TBL_ET_TEMPMonthDate(nolock) tmde '

set @query2 = ' left join TBL_ET_Attendance(nolock) atra on cast(tmde.MDate as date) = cast(atra.AttendanceIn as date) 
 inner join TBL_ET_AttendanceGroup(nolock) atgp on atra.AttendanceGroupId = atgp.AttendanceGroupId 
 left join TBL_ET_AttendanceGroupUserMapping (nolock) agum on atra.UserId = agum.UserId 
 left join User_Detail(nolock) ud2 on agum.UserId = ud2.User_ID 
 left join tbl_inv_UserTaxNumber (nolock) iutn on agum.UserBranchId = iutn.Id
 left join M_City (nolock) ct on iutn.City_Id = ct.City_Id
 left join M_State (nolock) st on iutn.State_Id = st.State_Id
 left join M_Country (nolock) co on iutn.Country_Id = co.Country_Id
 left join TBL_ET_ShiftMaster (nolock) smat on atra.ShiftId = smat.ShiftId
 where (Month(cast(tmde.MDate as date)) = Month(cast('''+ cast(@FromDate as varchar(25)) + ''' as date)) and Year(cast(tmde.MDate as date)) = Year(cast('''+ cast(@FromDate as varchar(25)) + ''' as date))) and
 (agum.UserId = ' + cast(@UserId as nvarchar(max)) + ') 
)t where (1=1) ' + @SearchText + ' '+ @Condition + ' 
 Order By t.AttendanceIn Asc 
 Offset ' + cast(@OffsetValue as varchar(10)) + ' rows fetch next '+ cast(@PagingSize as varchar(10)) + ' rows only ' 

 --(select item from dbo.fu_SplitString(''' + cast(@UserIdTeamLst as nvarchar(max)) + ''', '','')) 
 print @Condition 

 print @query1 
 print @query2 
  
declare @query3 nvarchar(max) = @query1 + @query2
 execute sp_executesql @query3

END TRY  
  
BEGIN CATCH  
 DECLARE @ErrorMessage NVARCHAR(max);  
 SELECT @ErrorMessage = ERROR_MESSAGE();  
 RAISERROR (  
   @ErrorMessage  
   ,16 
   ,1  
   );  
END CATCH 




GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_AttendanceList_Name_Cache]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_TBL_ET_AttendanceList_Name_Cache] (
 @Mode varchar(10) = ''
 ,@OffsetValue int = 0
 ,@PagingSize int = 10
 ,@SearchText nvarchar(max) = ''
 ,@Condition varchar(max) = ''
 ,@FromDate varchar(20) = ''
 ,@ToDate varchar(20) = ''
 ,@UserId bigint = 0
 ,@ParentId bigint = 0
)
AS
SET NOCOUNT ON
BEGIN 

				DECLARE @MonthStart DATETIME;
				DECLARE @MonthEnd DATETIME;

			select @ParentID = ParentID from Mysms.[dbo].User_Detail(nolock) where User_ID = @UserId;

				-- Get the first and last date of the current month
				--SET @MonthStart = FORMAT(DATEADD(DAY, 1 - DAY(GETDATE()), CAST(GETDATE() AS DATE)), 'dd-MMM-yyyy'); -- First day of current month
				--SET @MonthEnd = FORMAT(EOMONTH(GETDATE()), 'dd-MMM-yyyy'); -- Last day of current month

				Declare @Currentdate  DATE  = GETDATE();  -- Today's date
				SET @MonthStart      = FORMAT(DATEADD(DAY, -30, @Currentdate), 'dd-MMM-yyyy'); -- 30 days before today
				SET @MonthEnd  =  FORMAT(DATEADD(DAY, -1, @Currentdate), 'dd-MMM-yyyy');

				--if(ISNULL(@UserIds, '') =  '') begin set @UserIds = '' end

				-- Check conditions and select data
			IF (@FromDate Between @MonthStart AND @MonthEnd AND @ToDate Between @MonthStart AND @MonthEnd)    
				BEGIN
					  SELECT [EmployeeCalenderReportId]
					  ,[TotalRecords]
					  ,[AttendanceId]
					  ,[MDate]
					  ,[AttendanceIn]
					  ,[AttendanceOut]
					  ,[IADate]
					  ,[IATime]
					  ,[OADate]
					  ,[OATime]
					  ,[TotalHours]
					  ,[LatitudeIn]
					  ,[LongitudeIn]
					  ,[LatitudeOut]
					  ,[LongitudeOut]
					  ,[AttendanceGroupId]
					  ,[UserId]
					  ,[ParentId]
					  ,[ShiftId]
					  ,[ShiftName]
					  ,[RemarksIn]
					  ,[RemarksOut]
					  ,[DeviceId]
					  ,[CreatedBy]
					  ,[UpdatedBy]
					  ,[CreatedDate]
					  ,[IsActive]
					  ,[DayType]
					  ,[AttendanceStatus]
					  ,[AttendancePerc]
					  ,[CheckInCount]
					  ,[CheckOutCount]
					  ,[WorkingMinutes]
					  ,[StartTime]
					  ,[BreakTrans]
					  ,[TotalhoursMonth]
					  ,[TotalWorkingDay]
					  ,[TotalLeave]
					  ,[WeekOff]
					  ,[LateSignin]
					  ,[UserName]
					  ,[User_Login]
					  ,[ShiftMinutes]
					  ,[WorkingTime]
					  ,[ShiftTime]
					  ,[EndTime]
						FROM [dbo].[tbl_EmployeeCalenderReport_Cache](nolock)
						WHERE [UserId]= @UserId  and [MDate] between @FromDate and @ToDate
				END
			ELSE IF (@FromDate < @MonthStart OR @ToDate < @MonthStart)
				BEGIN
					SELECT [EmployeeCalenderReportId]
					  ,[TotalRecords]
					  ,[AttendanceId]
					  ,[MDate]
					  ,[AttendanceIn]
					  ,[AttendanceOut]
					  ,[IADate]
					  ,[IATime]
					  ,[OADate]
					  ,[OATime]
					  ,[TotalHours]
					  ,[LatitudeIn]
					  ,[LongitudeIn]
					  ,[LatitudeOut]
					  ,[LongitudeOut]
					  ,[AttendanceGroupId]
					  ,[UserId]
					  ,[ParentId]
					  ,[ShiftId]
					  ,[ShiftName]
					  ,[RemarksIn]
					  ,[RemarksOut]
					  ,[DeviceId]
					  ,[CreatedBy]
					  ,[UpdatedBy]
					  ,[CreatedDate]
					  ,[IsActive]
					  ,[DayType]
					  ,[AttendanceStatus]
					  ,[AttendancePerc]
					  ,[CheckInCount]
					  ,[CheckOutCount]
					  ,[WorkingMinutes]
					  ,[StartTime]
					  ,[BreakTrans]
					  ,[TotalhoursMonth]
					  ,[TotalWorkingDay]
					  ,[TotalLeave]
					  ,[WeekOff]
					  ,[LateSignin]
					  ,[UserName]
					  ,[User_Login]
					  ,[ShiftMinutes]
					  ,[WorkingTime]
					  ,[ShiftTime]
					  ,[EndTime]
						FROM [dbo].[tbl_EmployeeCalenderReport_Archive](nolock)
						WHERE [UserId]= @UserId and [MDate] between @FromDate and @ToDate
				END
			ELSE
				BEGIN
					EXEC [Mysms].[dbo].usp_TBL_ET_AttendanceList_Name @Mode, @OffsetValue, @PagingSize, @SearchText, @Condition, @FromDate, @ToDate, @UserId, @ParentId;
				END

END



