/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_AttendanceListCalC]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--usp_TBL_ET_AttendanceListCalC 0, 1000, '', '', '2023-03-01', '', 34594,34594
CREATE   PROCEDURE [dbo].[usp_TBL_ET_AttendanceListCalC] (
  @OffsetValue int = 0
 ,@PagingSize int = 0
 ,@SearchText nvarchar(max) = ''
 ,@Condition varchar(20) = 'StartWith'
 ,@FromDate varchar(20) = ''
 ,@ToDate varchar(20) = ''
 ,@UserId bigint = 0
 ,@ParentId bigint = 0
)
AS
SET NOCOUNT ON
BEGIN TRY

Select @ParentId = ParentId from User_Detail(nolock) where User_Id = @UserId 
Declare @UserIdTeamLst nvarchar(max) 

if(@SearchText != '')
Begin  
set @SearchText = ' and ' + @SearchText  
End
select @UserIdTeamLst = UserIdTeamLst from ufn_GetUserRoleScope(@UserId) 
--print @UserIdTeamLst 
select distinct * from (
select distinct 'SignIn' ListType, FORMAT(CAST(atra.AttendanceIn AS DATETIME),'hh:mm tt') Duration, 
FORMAT(CAST(atra.AttendanceIn AS DATETIME),'hh:mm tt') IATime, FORMAT(CAST(atra.AttendanceOut AS DATETIME),'hh:mm tt') OATime, 
(cast(DATEDIFF(hour,CAST(atra.AttendanceIn AS DATETIME), CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME)) as varchar(10)) +':'+ cast((DATEDIFF(minute,CAST(atra.AttendanceIn AS DATETIME), CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME))%60) as varchar(10))) +' Hrs' TotalHours,
cast(atra.AttendanceIn as date) IADate, cast(atra.AttendanceOut as date) OADate, 'Green' Color,
cast(cast(atra.AttendanceIn as date) as varchar(10)) IADate2, cast(cast(atra.AttendanceOut as date) as varchar(10)) OADate2
from TBL_ET_Attendance(nolock) atra 
 inner join TBL_ET_AttendanceGroup(nolock) atgp on atra.AttendanceGroupId = atgp.AttendanceGroupId 
 left join TBL_ET_AttendanceGroupUserMapping (nolock) agum on atra.UserId = agum.UserId 
 left join User_Detail(nolock) ud2 on agum.UserId = ud2.User_ID 
 left join tbl_inv_UserTaxNumber (nolock) iutn on agum.UserBranchId = iutn.Id
 left join M_City (nolock) ct on iutn.City_Id = ct.City_Id
 left join M_State (nolock) st on iutn.State_Id = st.State_Id
 left join M_Country (nolock) co on iutn.Country_Id = co.Country_Id
 left join TBL_ET_ShiftMaster (nolock) smat on atra.ShiftId = smat.ShiftId
 where ((Month(cast(atra.AttendanceIn  as date)) = Month(cast(@FromDate as Date))) and 
 (Year(cast(atra.AttendanceIn  as date)) = Year(cast(@FromDate as Date))))
 and agum.UserId = @UserId
 --and (agum.UserId in (select item from dbo.fu_SplitString(cast(@UserIdTeamLst as nvarchar(max)), ','))) 

Union all

select distinct 'SignOut' ListType, FORMAT(CAST(atra.AttendanceOut AS DATETIME),'hh:mm tt') Duration,
FORMAT(CAST(atra.AttendanceIn AS DATETIME),'hh:mm tt') IATime, FORMAT(CAST(atra.AttendanceOut AS DATETIME),'hh:mm tt') OATime, 
(cast(DATEDIFF(hour,CAST(atra.AttendanceIn AS DATETIME), CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME)) as varchar(10)) +':'+ cast((DATEDIFF(minute,CAST(atra.AttendanceIn AS DATETIME), CAST(isnull(atra.AttendanceOut, atra.AttendanceIn) AS DATETIME))%60) as varchar(10))) +' Hrs' TotalHours,
cast(atra.AttendanceIn as date) IADate, cast(atra.AttendanceOut as date) OADate, 'Green' Color, cast(cast(atra.AttendanceIn as date) as varchar(10)) IADate2, cast(cast(atra.AttendanceOut as date) as varchar(10)) OADate2
from TBL_ET_Attendance(nolock) atra 
 inner join TBL_ET_AttendanceGroup(nolock) atgp on atra.AttendanceGroupId = atgp.AttendanceGroupId 
 left join TBL_ET_AttendanceGroupUserMapping (nolock) agum on atra.UserId = agum.UserId 
 left join User_Detail(nolock) ud2 on agum.UserId = ud2.User_ID 
 left join tbl_inv_UserTaxNumber (nolock) iutn on agum.UserBranchId = iutn.Id
 left join M_City (nolock) ct on iutn.City_Id = ct.City_Id
 left join M_State (nolock) st on iutn.State_Id = st.State_Id
 left join M_Country (nolock) co on iutn.Country_Id = co.Country_Id
 left join TBL_ET_ShiftMaster (nolock) smat on atra.ShiftId = smat.ShiftId
 where ((Month(cast(atra.AttendanceOut  as date)) = Month(cast(@FromDate as Date))) and 
 (Year(cast(atra.AttendanceOut  as date)) = Year(cast(@FromDate as Date))))
 and agum.UserId = @UserId

-- and (agum.UserId in (select item from dbo.fu_SplitString(cast(@UserIdTeamLst as nvarchar(max)), ',')))

Union all

Select distinct brtm.BreakTypeName ListType, 
 (FORMAT(CAST(brtr.StartDate AS DATETIME),'hh:mm tt') + ' ' + FORMAT(CAST(brtr.EndDate AS DATETIME),'hh:mm tt')) Duration,
 FORMAT(CAST(brtr.StartDate AS DATETIME),'hh:mm tt') IATime, FORMAT(CAST(brtr.EndDate AS DATETIME),'hh:mm tt') OATime,
 (cast(DATEDIFF(hour,CAST(brtr.StartDate AS DATETIME), CAST(isnull(brtr.EndDate, brtr.StartDate) AS DATETIME)) as varchar(10)) +':'+ cast((DATEDIFF(minute,CAST(brtr.StartDate AS DATETIME), CAST(isnull(brtr.EndDate, brtr.StartDate) AS DATETIME))%60) as varchar(10))) +' Hrs' TotalHours,
 cast(brtr.StartDate as date) IADate, cast(brtr.EndDate as date) OADate, 'Orange' Color, cast(cast(brtr.StartDate as date) as varchar(10)) IADate2, cast(cast(brtr.EndDate as date) as varchar(10)) OADate2
 
 from TBL_ET_BreakTransaction(nolock) brtr
 inner join TBL_ET_BreakTypeMaster(nolock) brtm on brtr.BreakTypeId = brtm.BreakTypeId
 where  brtr.UserId = @UserId and ((Month(cast(brtr.StartDate as date)) = Month(cast(@FromDate as Date))) and 
 (Year(cast(brtr.EndDate  as date)) = Year(cast(@FromDate as Date))))

Union all

select distinct 'CheckIn' ListType, FORMAT(CAST(gecq.CheckIn AS DATETIME),'hh:mm tt') Duration, FORMAT(CAST(gecq.CheckIn AS DATETIME),'hh:mm tt') IATime, FORMAT(CAST(gecq.CheckOut AS DATETIME),'hh:mm tt') OATime,
 (cast(DATEDIFF(hour,CAST(gecq.CheckIn AS DATETIME), CAST(isnull(gecq.CheckOut, gecq.CheckIn) AS DATETIME)) as varchar(10)) +':'+ cast((DATEDIFF(minute,CAST(gecq.CheckIn AS DATETIME), CAST(isnull(gecq.CheckOut, gecq.CheckIn) AS DATETIME))%60) as varchar(10))) +' Hrs' TotalHours,
 cast(gecq.CheckIn as date) IADate, cast(gecq.CheckOut as date) OADate, 'Pink' Color, cast(cast(gecq.CheckIn as date) as varchar(10)) IADate2, cast(cast(gecq.CheckOut as date) as varchar(10)) OADate2
 from TBL_ET_GeoEntityCheckInOut(nolock) gecq 
 where gecq.UserId = @UserId and ((Month(cast(gecq.CheckIn as date)) = Month(cast(@FromDate as Date))) and 
 (Year(cast(gecq.CheckIn  as date)) = Year(cast(@FromDate as Date))))

Union all

select distinct 'CheckOut' ListType, FORMAT(CAST(gecq.CheckOut AS DATETIME),'hh:mm tt') Duration, FORMAT(CAST(gecq.CheckIn AS DATETIME),'hh:mm tt') IATime, FORMAT(CAST(gecq.CheckOut AS DATETIME),'hh:mm tt') OATime,
 (cast(DATEDIFF(hour,CAST(gecq.CheckIn AS DATETIME), CAST(isnull(gecq.CheckOut, gecq.CheckIn) AS DATETIME)) as varchar(10)) +':'+ cast((DATEDIFF(minute,CAST(gecq.CheckIn AS DATETIME), CAST(isnull(gecq.CheckOut, gecq.CheckIn) AS DATETIME))%60) as varchar(10))) +' Hrs' TotalHours,
 cast(gecq.CheckIn as date) IADate, cast(gecq.CheckOut as date) OADate, 'Pink' Color, cast(cast(gecq.CheckIn as date) as varchar(10)) IADate2, cast(cast(gecq.CheckOut as date) as varchar(10)) OADate2
 from TBL_ET_GeoEntityCheckInOut(nolock) gecq 
 where gecq.UserId = @UserId and ((Month(cast(gecq.CheckOut as date)) = Month(cast(@FromDate as Date))) and 
 (Year(cast(gecq.CheckOut  as date)) = Year(cast(@FromDate as Date))))
)t
order by IADate Desc 

END TRY 
  
BEGIN CATCH 
 DECLARE @ErrorMessage NVARCHAR(4000); 
 SELECT @ErrorMessage = ERROR_MESSAGE(); 
 RAISERROR ( 
   @ErrorMessage 
   ,16 
   ,1 
   ); 
END CATCH 



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_AttendanceSettingList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_TBL_ET_AttendanceSettingList] (  
	 @Mode VARCHAR(3)
	,@UserId bigint = 0
	,@StartDate datetime = null
	,@EndDate datetime =  null
)
AS
SET NOCOUNT ON
begin
	BEGIN TRY 

	--declare 
	--	@Mode VARCHAR(3) = 'ST',
	--	@UserId bigint = '44000',
	--	@StartDate datetime = '11-Dec-2023 12:50:45',
	--	@EndDate datetime = '11-Dec-2023 12:50:45'
	
		declare @ParentId bigint
		IF (@Mode = 'ST') /*This is for List */ 
		Begin
			declare 
				@SignInDateTime datetime, @AttendanceGroupId bigint,
				@ShiftId bigint, @StartTime datetime
      
				--SELECT top 1 @ParentId = ParentId FROM User_detail WITH (NOLOCK) WHERE User_Id = @UserId      
				set @AttendanceGroupId = 0      
       
			select top 1 @AttendanceGroupId = atgp.AttendanceGroupId, @ParentId = atgp.ParentId
				from TBL_ET_AttendanceGroup atgp(nolock)       
			left join TBL_ET_AttendanceGroupUserMapping agum (nolock) on atgp.AttendanceGroupId = agum.AttendanceGroupId 
			where agum.UserId = @UserId and atgp.IsActive = 1 and agum.IsActive = 1       
      
      
			set @ShiftId = 0      
			select top 1 @ShiftId = shmr.ShiftId, @StartTime = shmr.StartTime,  @EndDate = shmr.EndTime
			from TBL_ET_ShiftMaster shmr(nolock) inner join TBL_ET_ShiftUserMapping suma (nolock) 
			on shmr.ShiftId = suma.ShiftId and shmr.IsActive = 1      
			Where suma.UserId = @UserId      

			if(@ShiftId=0)
			Begin
				select @ShiftId=SMR.ShiftId, @StartTime = SMR.StartTime, @EndDate = SMR.EndTime
				From TBL_ET_AttendanceGroup(nolock) AG inner join TBL_ET_ShiftMaster(nolock) SMR
				on AG.RosterId=SMR.ShiftId and SMR.IsActive=1
				Where AG.AttendanceGroupId=@AttendanceGroupId
			End

		--select @ShiftId

		select atgr.*, 
			isnull(@ShiftId, 0) ShiftId, @StartTime as [StartTime], @EndDate as [EndTime],
			(select concat(Ud.FName, ' ', isnull(Ud.LName, ''))  from User_Detail(nolock) Ud where Ud.User_Id = @UserId) FullName
		from TBL_ET_AttendanceGroup(nolock) atgr 
		where  atgr.AttendanceGroupId = @AttendanceGroupId


		--select  
		--	atgr.*, isnull(shum.ShiftId, 0) ShiftId, sm.StartTime, sm.EndTime, concat(Ud.FName, ' ', isnull(Ud.LName, '')) FullName
		--from TBL_ET_AttendanceGroup(nolock) atgr 
		--	inner join TBL_ET_AttendanceGroupUserMapping(nolock) atum on atgr.AttendanceGroupId = atum.AttendanceGroupId
		--	inner join TBL_ET_ShiftUserMapping (nolock) shum on atum.UserId = shum.UserId
		--	inner join TBL_ET_ShiftMaster (nolock) sm on sm.ShiftId = shum.ShiftId
		--	inner join User_Detail (nolock) Ud on shum.UserId = Ud.User_ID 
		--where atum.UserId = @UserId
		End
	END TRY 
	BEGIN CATCH 
	 DECLARE @ErrorMessage NVARCHAR(4000); 
	 SELECT @ErrorMessage = ERROR_MESSAGE(); 
	 RAISERROR (@ErrorMessage, 16, 1);  
	END CATCH  
end



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_AttendanceSignInOutDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec usp_TBL_ET_AttendanceSignInOutDetails @Mode=N'AD',@UserId=32222,@StartDate=N'17-Jun-2023 00:00:00.000',@EndDate=N'17-Jun-2023 00:00:00.000'
--go


--usp_TBL_ET_AttendanceSignInOutDetails 'DD', 34594, '2022-12-09 00:00:00.000','2022-12-09 00:00:00.000'
CREATE   PROCEDURE  [dbo].[usp_TBL_ET_AttendanceSignInOutDetails] (
	@Mode VARCHAR(2),
	@UserId bigint,
	@StartDate Datetime,
	@EndDate Datetime
	)
AS
SET NOCOUNT ON

BEGIN TRY

--declare @Mode VARCHAR(2) = 'AD',
--	@UserId bigint = 32222,
--	@StartDate Datetime = N'17-Jun-2023 00:00:00.000',
--	@EndDate Datetime = N'17-Jun-2023 00:00:00.000'


IF (@Mode = 'AD') /*This is for Insert Details */
	BEGIN



select top 1 
	(case when DATEDIFF(minute, cast(atte.AttendanceIn as time(5)), cast(atte.AttendanceOut as time(5))) > 0 
		then 'Present'
	else 'Absent' End ) AttendanceStatus,
	cast(cast(atte.AttendanceIn as time(5)) as varchar(5)) AttendanceIn, 
	tiun.Address,
	(case when lower(atteb.GeoRestriction) in ('dynamic','none') then dbo.udf_ef_GetUserLocattionAddress(@UserId, atte.LatitudeIn, atte.LongitudeIn) 
		else concat( tiun.Address, ', ', isnull(mci.City_Name, ''), ', ', isnull(msi.State_Name, ''), ', ', isnull(mco.Country_Name, '')) end ) SignInAddress,
	(case when lower(atteb.GeoRestriction) in ('dynamic','none') then dbo.udf_ef_GetUserLocattionAddress(@UserId, atte.LatitudeOut, atte.LongitudeOut)
		else concat( tiun.Address, ', ', isnull(mci.City_Name, ''), ', ', isnull(msi.State_Name, ''), ', ', isnull(mco.Country_Name, '')) end ) SignOutAddress,
	concat( tiun.Address, ', ', isnull(mci.City_Name, ''), ', ', isnull(msi.State_Name, ''), ', ', isnull(mco.Country_Name, '')) FullAddress,
	cast(cast(atte.AttendanceOut as time(5)) as varchar(5)) AttendanceOut, 
	isnull(atte.RemarksIn, '') RemarksIn, 
	isnull(atte.RemarksOut, '') RemarksOut,
	brtm.BreakTypeName, 
	isnull(cast(cast(brti.StartDate as time(5)) as varchar(5)), '') BreakStartTime, 
	isnull(cast(cast(brti.EndDate as time(5)) as varchar(5)), '') BreakEndTime, 
	isnull((case when atirIn.ActualDateTime = '1900-01-01 00:00:00.000' then '' end), '') AttendanceInRequestIn, 
	isnull((case when atirOut.ActualDateTime = '1900-01-01 00:00:00.000' then '' end), '') AttendanceInRequestOut,
	isnull(atirAIn.ApproverStatus, '') ApproverStatusIn, 
	isnull(atirAOut.ApproverStatus, '') ApproverStatusOut,
	isnull(lr.TypeOfLeave, '') TypeOfLeave, 
	isnull(cast(cast(lr.FromTime as time(5)) as varchar(5)), '') LeaveFromTime, 
	isnull(cast(cast(lr.ToTime as time(5)) as varchar(5)), '') LeaveToTime 
from TBL_ET_Attendance (nolock) atte 
	left join TBL_ET_AttendanceGroupUserMapping (nolock) atteb on atte.AttendanceGroupId = atteb.AttendanceGroupId
	left join tbl_inv_UserTaxNumber (nolock) tiun on atteb.UserBranchId = tiun.id
	left join TBL_ET_BreakTransaction (nolock) brti on atte.UserId = brti.UserId and ((cast(brti.StartDate as date) between cast(@StartDate as date) and cast(@EndDate as date)) or (cast(brti.EndDate as date) between cast(@StartDate as date) and cast(@EndDate as date))) 
	left join TBL_ET_BreakTypeMaster (nolock) brtm on brti.BreakTypeId = brtm.BreakTypeId 
	left join TBL_ET_AttendanceIssueRequest (nolock) atirIn on cast(atte.AttendanceIn as date) = cast(atirIn.ActualDateTime as date) and atirIn.ActionType = 'SignIn' 
	left join TBL_ET_AttendanceIssueRequest (nolock) atirOut on cast(atte.AttendanceOut as date) = cast(atirOut.ActualDateTime as date) and atirOut.ActionType = 'SignOut' 
	left join TBL_ET_AttendanceIssueReqApproval (nolock) atirAIn on atirIn.AttendanceIssueId = atirAIn.AttendenceIssueId 
	left join TBL_ET_AttendanceIssueReqApproval (nolock) atirAOut on atirIn.AttendanceIssueId = atirAOut.AttendenceIssueId 
	left join TBL_ET_LeaveRequest (nolock) lr on atte.UserId = lr.UserId and ((cast(atte.AttendanceIn as date) between cast(lr.FromDate as date) and cast(lr.ToDate as date)) or (cast(atte.AttendanceOut as date) between cast(lr.FromDate as date) and cast(lr.ToDate as date))) 
	left join M_City (nolock) mci on tiun.city_id = mci.City_ID
	left join M_State (nolock) msi on tiun.state_id = msi.State_ID
	left join M_Country (nolock) mco on tiun.country_id = mco.Country_ID
	where atte.UserId = @UserId and (
		(cast(atte.AttendanceIn as date) between cast(@StartDate as date) and cast(@EndDate as date)) 
		or (cast(atte.AttendanceOut as date) between cast(@StartDate as date) and cast(@EndDate as date))
	) 
order by 1 desc 

--select * from (
--Select atra.LeaveApprovalId, atra.LeaveRequestId, telr.LeaveId, Cast(telr.FromDate as varchar(100)) FromDate, Cast(telr.ToDate as varchar(100)) ToDate, Cast(CONVERT(varchar, telr.FromDate,13) as varchar(12)) FromDateNew, cast(CONVERT(varchar,telr.ToDate,13) as varchar(12)) ToDateNew, StartQuarterDate, EndQuarterDate, cast(FromTime as varchar(5)) FromTime, cast(ToTime as varchar(5)) ToTime, telr.UserId, Remarks, Cast(telr.CreatedDate as varchar(100)) RequestDate, TypeOfLeave,
--	case When ((telr.EndQuarterDate - telr.StartQuarterDate) + 1) = 4 then 'Full Leave'
--	When ((telr.EndQuarterDate - telr.StartQuarterDate) + 1) = 3 then 'Half and Short Leave'
--	When ((telr.EndQuarterDate - telr.StartQuarterDate) + 1) = 2 then 'Half Leave'
--	When ((telr.EndQuarterDate - telr.StartQuarterDate) + 1) = 1 then 'Short Leave'
--	else '' end LeaveRequestStatus,
--	ud.CompnayName, (isnull(ud.Address, '') + ',' + isnull(ct.City_Name, '') + ',' + isnull(st.State_Name, '') + ',' + isnull(co.Country_Name, '')) Address, (ud.FName + ' ' + ud.LName) + ' (' + ud.User_Login + ')' EmployeeName, (ud2.FName + ' ' + ud2.LName) + '(' + ud2.User_Login + ')' ApprovedName,  
-- isnull(atra.RemarksApprover, '') RemarksApprover, isnull(atra.ApproverStatus, 'Pending') ApproverStatus,   
-- --isnull(atra.ApprovedDate , '') ApprovedDate, 
-- --isnull(atra.LeaveApprovalId, 0) LeaveApprovalId, 
-- isnull(iutn.Address, '') +', '+ isnull(ct.City_Name, '') + ', ' + isnull(st.State_Name, '') + ', ' + isnull(co.Country_Name, '') BranchAddress, 
--(select top 1 isnull(CONVERT(VARCHAR, AttendanceIn, 100), '''') LastLoginAttendanceIn from TBL_ET_Attendance(nolock) Where UserId = telr.UserId order by 1 desc) LastLoginAttendanceIn  from TBL_ET_LeaveApproval (nolock) atra
-- inner join TBL_ET_LeaveRequest (nolock) telr on atra.LeaveRequestId = telr.LeaveRequestId
-- inner join User_Detail(nolock) ud on telr.UserId = ud.User_ID  
-- left join User_Detail(nolock) ud2 on atra.ApproverUserId = ud2.User_ID  
-- left join TBL_ET_AttendanceGroupUserMapping (nolock) agum on telr.UserId = agum.UserId
-- left join tbl_inv_UserTaxNumber (nolock) iutn on agum.UserBranchId = iutn.Id
-- left join M_City (nolock) ct on iutn.City_Id = ct.City_Id
-- left join M_State (nolock) st on iutn.State_Id = st.State_Id
-- left join M_Country (nolock) co on iutn.Country_Id = co.Country_Id
--	where telr.UserId = @UserId
--	and (((telr.FromDate between @StartDate and @EndDate) or (telr.ToDate between @StartDate and @EndDate)))

--Union all
--select 0 LeaveApprovalId, * from (Select distinct telr.LeaveRequestId, telr.LeaveId, Cast(telr.FromDate as varchar(100)) FromDate, Cast(telr.ToDate as varchar(100)) ToDate, Cast(CONVERT(varchar, telr.FromDate,13) as varchar(12)) FromDateNew, cast(CONVERT(varchar,telr.ToDate,13) as varchar(12)) ToDateNew, 
--	StartQuarterDate, EndQuarterDate, cast(FromTime as varchar(5)) FromTime, cast(ToTime as varchar(5)) ToTime, telr.UserId, Remarks, Cast(telr.CreatedDate as varchar(100)) RequestDate, 
--	--(case when (telr.EndQuarterDate - telr.StartQuarterDate + 1) = 1 then 'shortLeave'
--	--when (telr.EndQuarterDate - telr.StartQuarterDate + 1) = 2 then 'halfLeave'
