/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_BranchSave]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--usp_TBL_ET_BranchSave 'BS', 0, 'Branch Kit19', 34594, '9911001100', 'newemail@gmail.com','27.11222', '77.00999','Addressss', 'New Delhi', 'delhi', 'India', '110085', 34594, 1 
CREATE   PROCEDURE  [dbo].[usp_TBL_ET_BranchSave] (
	@Mode VARCHAR(2),
	@BranchId bigint = 0,
	@BranchName varchar(100),
	@ParentId bigint,
	@Mobile varchar(100), 
	@EmailId varchar(100), 
	@Latitude float,
	@Longitude float, 
	@Address varchar(200),
	@CityId bigint,
	@StateId bigint, 
	@CountryId bigint, 
	@PinCode varchar(20), 
	@CreatedBy bigint, 
	@IsActive bit
  )
AS
SET NOCOUNT ON

BEGIN TRY
IF (@Mode = 'BI') /*This is for Insert Details */
	BEGIN
	if(Exists(Select name from tbl_inv_UserTaxNumber(nolock) tiun Where tiun.parentid = @ParentId and tiun.Name = @BranchName and tiun.city_id = @CityId))
	Begin
	insert into tbl_inv_UserTaxNumber(name, parentid, mobile, emailid, latitude, longitude, address, city_id, state_id, country_id, pincode, created_by, created_at, isactive)
	Values(@BranchName, @ParentId, @Mobile, @EmailId, @Latitude, @Longitude, @Address, @CityId, @StateId, @CountryId, @PinCode, @CreatedBy, GetDate(), @IsActive)
		
		Select 'Saved Record' Status, SCOPE_IDENTITY() Id
	End
	Else
	Begin
		Select 'Record Already Exist' Status, tiun.* from tbl_inv_UserTaxNumber(nolock) tiun Where tiun.parentid = @ParentId and tiun.Name = @BranchName and tiun.city_id = @CityId
	End
	End
Else IF (@Mode = 'BU') /*This is for Insert Details */
	BEGIN
	if(Exists(Select name from tbl_inv_UserTaxNumber(nolock) tiun Where tiun.parentid = @ParentId and tiun.Id = @BranchId))
	Begin

	update tbl_inv_UserTaxNumber set name = @BranchName, parentid = @parentid, mobile = @mobile, emailid = @emailid, latitude = @latitude, longitude = @longitude, address = @address, city_id = @CityId, state_id = @StateId, country_id = @CountryId, pincode = @PinCode, created_by = @CreatedBy, 
	updated_at = GetDate(), isactive = @IsActive where id = @BranchId
		
		Select 'Updated Record' Status, @BranchId Id
	End
	Else
	Begin
		Select 'Record not Exist' Status, @BranchId Id
	End
	End

END TRY

BEGIN CATCH
	DECLARE @ErrorMessage NVARCHAR(4000);
	SELECT @ErrorMessage = ERROR_MESSAGE();
	RAISERROR (
			@ErrorMessage
			,16
			,1
			);
END CATCH



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_BreakStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--usp_TBL_ET_BreakTransaction 'TL', 0, 0, 0, '', '', '',0, 1, 34594 
CREATE   PROCEDURE  [dbo].[usp_TBL_ET_BreakStatus] (
	@Mode VARCHAR(2)
	,@UserId bigint = 0
)
AS
SET NOCOUNT ON

BEGIN TRY
	Declare @ParentId bigint

	Select @ParentId = ParentId From User_Detail(nolock) where User_Id = @UserId

 IF (@Mode = 'BL') /*This is for Insert Details */
 BEGIN

  Select BreakTypeId, BreakTypeName, ParentId from TBL_ET_BreakTypeMaster (nolock) bm 
   where ParentId = @ParentId and isnull(BreakTypeName, '') != ''

  if Exists(Select top 1 BreakTransactionId from TBL_ET_BreakTransaction atdn (nolock) where UserId = @UserId and Cast(StartDate as Date) = Cast(GetDate() as Date) and EndDate is null and IsActive = 1 order by BreakTransactionId desc)  
	 Begin 
	   Select top 1 (case when isnull(EndDate, '') = '' then 1 else 0 end) IsBreakInStatus, BreakTransactionId, UserId, cast(StartDate as time) StartTime, CAST((GETDATE()-StartDate) as time(0)) BreakTime
	   from TBL_ET_BreakTransaction atdn (nolock)
	  where UserId = @UserId and Cast(StartDate as Date) = Cast(GetDate() as Date) and EndDate is null and atdn.IsActive = 1 order by BreakTransactionId desc 
	End
	else
	Begin
	select 0 IsBreakInStatus, 0 BreakTransactionId, @UserId UserId
	End

   END /*End here for list */

END TRY

BEGIN CATCH
	DECLARE @ErrorMessage NVARCHAR(4000);
	SELECT @ErrorMessage = ERROR_MESSAGE();
	RAISERROR (
			@ErrorMessage
			,16
			,1
			);
END CATCH



GO

