-- exec usp_TBL_ET_BreakTransaction @Mode=N'TO',@BreakTransactionId=105,@BreakTypeId=0,@UserId=34594,@StartDate=default,@EndDate=N'2023-05-30T15:09:07.537Z',@Remarks=default,@CreatedBy=34594,@IsActive=1,@ParentId=34594
--usp_TBL_ET_BreakTransaction 'TL', 0, 0, 0, '', '', '',0, 1, 34594   
CREATE   PROCEDURE  [dbo].[usp_TBL_ET_BreakTransaction] (  
	@Mode VARCHAR(2),
	@BreakTransactionId bigint=0,
	@BreakTypeId int=0,
	@UserId bigint=0,
	@StartDate datetime=null,
	@EndDate datetime=null,
	@Remarks varchar(200)=null,
	@CreatedBy bigint=0,
	@IsActive bit=1,
	@ParentId bigint=0,
	@Latitude float=0,
	@Longitude float=0,
	@Address nvarchar(500)=null,
	@DeviceId nvarchar(50)='',
	@LocationMetaData nvarchar(max) = null
)  
AS  
SET NOCOUNT ON 
  
BEGIN TRY  

	--declare
	--	@Mode VARCHAR(2)   = N'TO',
	--	@BreakTransactionId bigint = 328,
	--	@BreakTypeId int = 0,
	--	@UserId bigint = 34594,
	--	@StartDate datetime = N'06-Dec-2023 13:15:54',
	--	@EndDate datetime = N'06-Dec-2023 13:21:22',
	--	@Remarks varchar(200) = N'',
	--	@CreatedBy bigint = 34594,
	--	@IsActive bit = 1,
	--	@ParentId bigint = 34594,
	--	@Latitude float = 0,
	--	@Longitude float = 0,
	--	@Address nvarchar(500) = null,
	--	@DeviceId nvarchar(50) = ''

	declare @LocationDateTime datetime= getdate()

 IF (@Mode = 'TI') /*This is for Insert Details */  
 BEGIN  
 DECLARE @ID BIGINT;  
  
 if(Not Exists(select BreakTypeId from TBL_ET_BreakTransaction(nolock) where BreakTypeId = @BreakTypeId and UserId = @UserId and ((StartDate between  
 @StartDate and @EndDate) or (StartDate between @StartDate and @EndDate))))  
 Begin  
  INSERT INTO TBL_ET_BreakTransaction (BreakTypeId, UserId, StartDate, Remarks, CreatedDate, CreatedBy, IsActive)  
  VALUES (@BreakTypeId, @UserId, GETDATE()/*@StartDate*/, @Remarks, GETDATE(), @CreatedBy, @IsActive)  
  
  SET @ID = scope_identity();  
  
	exec usp_et_InsertSingleMovementCodeInternal  
		@MovementCode = 'BREAK_IN', @Latitude = @Latitude, @Longitude = @Longitude, @Address = @Address, @LocationDateTime = @LocationDateTime,
		@AttendanceId = null, @PhysicalAppointmentId = null, @BreakTransactionId = @ID, @DeviceId = @DeviceId, @UserId = @UserId


  SELECT 'Record Saved' STATUS, @ID BreakTransactionId  
 END  
 ELSE  
 BEGIN  
  SELECT 'Record Already Exist' STATUS  
  END  
 END /*End here for insert*/  
  
 Else IF (@Mode = 'TO') /*This is for Update Details */  
 BEGIN  
 if(Exists(select BreakTransactionId from TBL_ET_BreakTransaction(nolock) where BreakTransactionId = @BreakTransactionId and UserId = @UserId))  
 Begin  
  
	Update TBL_ET_BreakTransaction set UserId = @UserId, EndDate = GETDATE() --@EndDate --, Remarks = @Remarks  
	,IsActive = @IsActive, UpdatedBy = @CreatedBy, UpdatedDate = GETDATE()      
	where BreakTransactionId = @BreakTransactionId  
  
	exec usp_et_InsertSingleMovementCodeInternal  
		@MovementCode = 'BREAK_OUT', @Latitude = @Latitude, @Longitude = @Longitude, @Address = @Address, @LocationDateTime = @LocationDateTime,
		@AttendanceId = null, @PhysicalAppointmentId = null, @BreakTransactionId = @BreakTransactionId, @DeviceId = @DeviceId, @UserId = @UserId

 SELECT 'Record Updated' STATUS, @BreakTransactionId BreakTransactionId  
  
    Select GETDATE()  
  
    End  
 ELSE  
  BEGIN  
  SELECT 'Update Issue.' STATUS  
     Select GETDATE()  
 END  
  
 END /*End here for update*/  
  
 Else IF (@Mode = 'TL') /*This is List Details */  
 BEGIN  
 if(@StartDate != '' and @EndDate !=  '')  
 Begin  
 Select BreakTransactionId, BreakTypeId, UserId, Concat(ud.FName, ' ', isnull(ud.LName, '')) AgentName,  
 StartDate, isnull(EndDate, '') EndDate, Remarks, CreatedDate, CreatedBy, UpdatedDate, UpdatedBy, IsActive from TBL_ET_BreakTransaction (nolock) bm   
 inner join User_Detail (nolock) ud on bm.UserId  = ud.User_ID  
 where bm.BreakTypeId = (Case When @BreakTypeId != '' then @BreakTypeId else bm.BreakTypeId End)   
 and bm.BreakTransactionId = (Case When @BreakTransactionId != 0 then @BreakTransactionId else bm.BreakTransactionId End)  
 and ((StartDate  between @StartDate and @EndDate) or (EndDate between @StartDate and @EndDate))  
 and ParentId = @ParentId  
 End  
 else  
 Begin  
 Select BreakTransactionId, BreakTypeId, UserId, Concat(ud.FName, ' ', isnull(ud.LName, '')) AgentName,  
 StartDate, isnull(EndDate, '') EndDate, Remarks, CreatedDate, CreatedBy, UpdatedDate, UpdatedBy, IsActive from TBL_ET_BreakTransaction (nolock) bm   
 inner join User_Detail (nolock) ud on bm.UserId  = ud.User_ID  
 where bm.BreakTypeId = (Case When @BreakTypeId != '' then @BreakTypeId else bm.BreakTypeId End)   
 and bm.BreakTransactionId = (Case When @BreakTransactionId != 0 then @BreakTransactionId else bm.BreakTransactionId End)  
 and ParentId = @ParentId  
 End  
 END /*End here for list */  
  
END TRY  
  
BEGIN CATCH  
 DECLARE @ErrorMessage NVARCHAR(4000);  
 SELECT @ErrorMessage = ERROR_MESSAGE();  
 RAISERROR (  
   @ErrorMessage  
   ,16  
   ,1  
   );  
END CATCH  



GO

