   Procedure: [dbo].[usp_TBL_ET_BreakTransaction_Name]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec usp_TBL_ET_BreakTransaction_Name @SearchText=default,@Contain=default,@UserId=34594,@OffsetValue=0,@PagingSize=6
CREATE   PROCEDURE [dbo].[usp_TBL_ET_BreakTransaction_Name] (    
  @OffsetValue int = 0    
 ,@PagingSize int = 0    
 ,@SearchText nvarchar(500) = ''    
 ,@Contain nvarchar(1000) = ''                          
 ,@UserId bigint = 0    
 ,@ParentId bigint = 0  
)  
AS  
SET NOCOUNT ON  
  
BEGIN TRY    
--Declare @ParentId bigint    
Select @ParentId = ParentId from User_Detail(nolock) where User_Id = @UserId  
if(@SearchText = '')    
Begin    
set @SearchText = ''  
End   
if(@Contain = '')    
Begin    
set @Contain = ''  
End   
    
if(@Contain != '')    
Begin    
set @Contain = ' and ' + @Contain  
End   
Declare @UserIdTeamLst varchar(4000)    
select @UserIdTeamLst = UserIdTeamLst from ufn_GetUserRoleScope(@UserId)    
print @UserIdTeamLst    
  
Declare @query nvarchar(max)    
set @query = 'Select count(t.BreakTransactionId) over() as TotalRecords, * from (Select BreakTransactionId, atdn.BreakTypeId, BreakTypeName, (ud.FName + '' '' + ud.LName) + '' ('' + ud.User_Login + '')'' EmployeeName, format(atdn.StartDate, ''dd-MMM-yyyy'') StartDate, atdn.StartDate StartDateNew, format(atdn.EndDate, ''dd-MMM-yyyy'') EndDate, atdn.EndDate EndDateNew, CONVERT(VARCHAR(8),StartDate,108) as FromTime, CONVERT(VARCHAR(8),EndDate,108) ToTime, CONVERT(VARCHAR(8),(EndDate - StartDate),108) BreakTime, Remarks, (case when atdn.IsActive = 1 then ''Active'' else ''InActive'' End) Status  
from TBL_ET_BreakTransaction (nolock) atdn inner join User_Detail(nolock) ud on atdn.UserId = ud.User_ID   
 left join TBL_ET_BreakTypeMaster(nolock) btma on atdn.BreakTypeId = btma.BreakTypeId   
 where (atdn.UserId in (select item from dbo.fu_SplitString(''' + cast(@UserIdTeamLst as varchar(4000)) + ''', '','')))  
 )t   
where (t.EmployeeName like ''%'+ @SearchText +'%'' or t.BreakTypeName like ''%'+ @SearchText +'%'') ' + @Contain + '   
Order By t.StartDate Desc   
Offset '+ cast(@OffsetValue as varchar(10)) + ' rows fetch next '+ cast(@PagingSize as varchar(10)) + ' rows only '   
  
print @query   
 execute sp_executesql @query   
  
END TRY   
  
BEGIN CATCH   
 DECLARE @ErrorMessage NVARCHAR(4000);   
 SELECT @ErrorMessage = ERROR_MESSAGE();   
 RAISERROR (   
   @ErrorMessage   
   ,16    
   ,1    
   );    
END CATCH    



GO

