   Procedure: [dbo].[usp_TBL_ET_BreakTypeMaster]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--usp_TBL_ET_BreakTypeMaster 'BL', 0, '', 34594, 34594, 1   
--usp_TBL_ET_BreakTypeMaster 'BI', 0, 'Tea Break', 34594, 34594, 1   
--usp_TBL_ET_BreakTypeMaster 'BU', 1, 'Tea Break', 34594, 34594, 1   
CREATE   PROCEDURE  [dbo].[usp_TBL_ET_BreakTypeMaster] (  
 @Mode VARCHAR(2)  
 ,@BreakTypeId int = 0  
 ,@BreakTypeName varchar(200) =''  
 ,@ParentId bigint = 0  
 ,@CreatedBy bigint = 0  
 ,@IsActive bit = 1  
)  
AS  
SET NOCOUNT ON  
  
BEGIN TRY  
 IF (@Mode = 'BI') /*This is for Insert Details */  
 BEGIN  
 DECLARE @ID BIGINT;  
  
 if(Not Exists(select BreakTypeId from TBL_ET_BreakTypeMaster(nolock) where BreakTypeName = @BreakTypeName and ParentId = @ParentId and IsActive=1))  
 Begin  
   INSERT INTO TBL_ET_BreakTypeMaster (  
    BreakTypeName  
    ,ParentId  
    ,CreatedDate  
    ,CreatedBy  
    ,IsActive  
    )  
   VALUES (  
    @BreakTypeName  
    ,@ParentId  
    ,GETDATE()      
    ,@CreatedBy  
    ,@IsActive  
    )  
  
   SET @ID = scope_identity();  
  
  SELECT 'Record Saved' STATUS, @ID BreakTypeId  
  
  END  
  ELSE  
  BEGIN  
   SELECT 'Record Already Exist' STATUS  
   
   Select GETDATE()  
  END  
 END /*End here for insert*/  
  
 Else IF (@Mode = 'BU') /*This is for Update Details */  
 BEGIN  
 if(Exists(select BreakTypeId from TBL_ET_BreakTypeMaster(nolock) where BreakTypeId = @BreakTypeId))  
 Begin  
  
 Update TBL_ET_BreakTypeMaster  set BreakTypeName = @BreakTypeName  
    ,IsActive = @IsActive  
    ,UpdatedBy = @CreatedBy  
    ,UpdatedDate = GETDATE()      
    where BreakTypeId = @BreakTypeId  
  
  SELECT 'Record Updated' STATUS, @BreakTypeId BreakTypeId  
  
        Select GETDATE()  
  
       End  
  ELSE  
  BEGIN  
   SELECT 'Update Issue.' STATUS  
        Select GETDATE()  
  END  
  
 END /*End here for update*/  
  
 Else IF (@Mode = 'BL') /*This is List Details */  
 BEGIN  
  
 Select BreakTypeId, BreakTypeName, ParentId from TBL_ET_BreakTypeMaster (nolock) bm   
 where bm.BreakTypeName =   
 (Case When @BreakTypeName != '' then @BreakTypeName else bm.BreakTypeName End) and   
 bm.BreakTypeId =   
 (Case When @BreakTypeId != 0 then @BreakTypeId else bm.BreakTypeId End)  
 and ParentId = @ParentId and bm.BreakTypeName != ''  
  
 END /*End here for list */  
 Else IF (@Mode = 'BD') /*This is List Details */  
 BEGIN  
  
 Select * from TBL_ET_BreakTypeMaster (nolock) bm where bm.BreakTypeId = @BreakTypeId   
  
 END /*End here for list */  
 Else IF (@Mode = 'DD') /*This is List Details */  
 BEGIN  
  
 update TBL_ET_BreakTypeMaster set IsActive = 0 where BreakTypeId = @BreakTypeId   
 SELECT 'Record deleted' STATUS  
      
 END /*End here for list */  
  
END TRY  
  
BEGIN CATCH  
 DECLARE @ErrorMessage NVARCHAR(4000);  
 SELECT @ErrorMessage = ERROR_MESSAGE();  
 RAISERROR (  
   @ErrorMessage  
   ,16  
   ,1  
   );  
END CATCH  



