/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_CheckAutoSignIn]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--usp_TBL_ET_CheckAutoSignIn 'SignIn', 34594, '28.5600262167001', '28.7563178490813', '77.2751907029688', '77.287757451475'
--usp_TBL_ET_CheckAutoSignIn 'SignOut', 34594, '28.5600262167001', '28.7663178490813', '77.2751907029688', '78.887757451475'
CREATE   PROCEDURE  [dbo].[usp_TBL_ET_CheckAutoSignIn]
(
@TypeOfAction varchar(10),
@UserId bigint,
@Latitude1 float = null,
@Longitude1 float = null,
@Latitude2 float = null,
@Longitude2 float = null,
@CheckStartDate varchar(20) = null,
@CheckEndDate varchar(20) = null
) 
as 
Begin 
--Declare @TypeOfAction varchar(10) = 'SignIn',
--@UserId bigint = 34594,
--@Latitude1 float = '28.5600262167001',
--@Longitude1 float = '77.2751907029688',
--@Latitude2 float = '28.7563178490813',
--@Longitude2 float = '77.287757451475',
--@CheckStartDate varchar(20) = null,
--@CheckEndDate varchar(20) = null

if(@TypeOfAction = 'SignIn')
Begin 
Declare @SignInRangeInMeter int 
Declare @Distance float 
Declare @Code nvarchar(200) = 'Userloggedintotimetracking' 
Declare @NotficationName nvarchar(500) 
select @NotficationName = [Name] from TBL_ET_ActionCondition(nolock) where Code = @Code 
Select @SignInRangeInMeter = (case when atgp.SignInType = 'Manual' then 0 when atgp.SignInType = 'Auto' then atgp.SignInRange else 0 end) 
from TBL_ET_AttendanceGroup(nolock) atgp 
inner join TBL_ET_AttendanceGroupUserMapping(nolock) atgu on atgp.AttendanceGroupId = Atgu.AttendanceGroupId 
Where atgu.UserId = @UserId and atgp.IsActive = 1 
if not Exists(Select 1 from TBL_ET_Attendance (nolock) teat where cast(teat.AttendanceIn as date) = cast(GETDATE() as date) and teat.UserId = @UserId) 
Begin 
if(@SignInRangeInMeter > 0) 
Begin 
set @Distance = ((select dbo.fnCalcDistanceKM(@Latitude1, @Latitude2, @Longitude1, @Longitude2)) * 1000) 
if(@Distance < @SignInRangeInMeter) 
Begin 
Insert into TBL_ET_ActionNotification (Code, NotficationName, UserId, ParentId, CreatedDate, CreatedBy, IsActive) 
Select @Code, @Code + ' Notification', @UserId, @UserId, GETDATE(), @UserId, 1 
Select 'Updated' Status 
End 
else 
Begin 
Select 'Not update' Status 
End 
End 
End 
Begin 
Select 'Already Attendance Updated' Status 
End 
End 
else if(@TypeOfAction = 'SignOut') 
Begin 
Select case when atgp.SignOutType = 'Manual' then 0 when atgp.SignOutType = 'Auto' then atgp.SignOutRange else 0 end SignOutRange 
from TBL_ET_AttendanceGroup(nolock) atgp 
inner join TBL_ET_AttendanceGroupUserMapping(nolock) atgu on atgp.AttendanceGroupId = Atgu.AttendanceGroupId 
Where atgu.UserId = @UserId and atgp.IsActive = 1 
End 
else if(@TypeOfAction = 'fieldexecutiverange') 
Begin 
Select top 1 * from TBL_ET_AttendanceGroup(nolock) atgp 
inner join TBL_ET_AttendanceGroupUserMapping(nolock) atgu on atgp.AttendanceGroupId = Atgu.AttendanceGroupId 
Where atgu.UserId = @UserId and atgp.IsActive = 1 
End 
else if(@TypeOfAction = 'Compliancewarnings') 
Begin 
Select top 1 * from TBL_ET_UserLocationTracking(nolock) ult where ult.UserId = @UserId and ult.IsActive = 1 
End 
End 
 



