/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_CheckInOutIssueReqApprList_Name]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE  [dbo].[usp_TBL_ET_CheckInOutIssueReqApprList_Name] (  
 @OffsetValue int = 0 
 ,@PagingSize int = 0  
 ,@SearchText nvarchar(max) = ''  
 ,@Condition varchar(20) = 'StartWith'                        
 ,@UserId bigint = 0  
 ,@ParentId bigint = 0  
)
AS
SET NOCOUNT ON
begin
	BEGIN TRY  

	--declare
	--	@OffsetValue int = 0,
	--	@PagingSize int = 20,
	--	@SearchText nvarchar(max) = '',
	--	@Condition varchar(20) = '',
	--	@UserId bigint = 42980,
	--	@ParentId bigint = 42980    


	Select @ParentId = ParentId from User_Detail(nolock) where User_Id = @UserId
  
	if(@SearchText != '')  
	Begin  
	set @SearchText = ' and ' + @SearchText  
	End 
	Declare @UserIdTeamLst nvarchar(max)  
	select @UserIdTeamLst = UserIdTeamLst from ufn_GetUserRoleScope(@UserId)  
	print @UserIdTeamLst

	Declare @query nvarchar(max) 
	set @query = concat(N'Select count(t.GeoEntityChkInOutReqApprovalId) over() as TotalRecords, * from ( ',
			N'Select chiur.GeoEntityChkInOutRequestId, (ud.FName + '' '' + ud.LName) + '' ('' + ud.User_Login + '')'' EmployeeName, gemr.Mobile, ',
			N'gemr.EmailId, gemr.EntityId, gemr.GeoEntityType,	gesm.GeoEntitySiteId, gesm.GeoEntitySiteName SiteName, ',
			N'isnull(papt.OutcomesId, 0) OutcomesId, (Case ',
			N'When gemr.GeoEntityType =''lead'' Then (Select ud.LeadNo from userLeads ud ',
			N'where ud.Id= gemr.EntityId) ',
			N'When gemr.GeoEntityType =''enquiry'' Then (Select ue.LeadNo from UserEnquiry ue ',
			N'where ue.EnquiryId= gemr.EntityId) ',
			N'else 0 End) LeadNo, ',
			N'(Case ',
			N'When gemr.GeoEntityType =''lead'' Then (Select ud.PersonName from userLeads ud ',
			N'where ud.Id= gemr.EntityId) ',
			N'When gemr.GeoEntityType =''enquiry'' Then (Select ue.PersonName from UserEnquiry ue ',
			N'where ue.EnquiryId= gemr.EntityId) ',
			N'End) PersonName, ',
			N'(Case ',
			N'When gemr.GeoEntityType =''lead'' Then (Select ud.ProfileImgFileName from userLeads ud ',
			N'where ud.Id= gemr.EntityId) ',
			N'When gemr.GeoEntityType =''enquiry'' Then (Select ue.ProfileImgFileName from UserEnquiry ue ',
			N'where ue.EnquiryId= gemr.EntityId) ',
			N'else ',
			N''''' ',
			N'End) ImageName, ',
			N'ud.ProfilePictureName, isnull(gera.GeoEntityChkInOutReqApprovalId, 0) GeoEntityChkInOutReqApprovalId, chiur.PhysicalAppointmentId, ',
			N'chiur.UserId, chiur.ActionType, Cast(chiur.ScheduledDateTime as varchar(100)) ScheduledDateTime, ',
			N'Cast(chiur.ActionDateTime as varchar(20)) ActionDateTime, Cast(chiur.CreatedDate as varchar(20)) RequestDate,  ',
			N'Cast(chiur.CreatedDate as varchar(20)) CreatedDate, chiur.CreatedBy, chiur.IsActive, isnull(chiur.Remarks, '''') Remarks, ',
			N'chiur.ParentId, (case when chiur.IsActive = 1 then ''Active'' else ''InActive'' End) Status, isnull(gera.ApprovedBy, 0) ApprovedBy, ',
			N'(ud2.FName + '' '' + ud2.LName) + ''('' + ud2.User_Login + '')'' ApprovedName,  ',
			N'isnull(gera.ApproverRemarks, '''') ApproverRemarks, isnull(gera.ApproverStatus, ''Pending'') ApproverStatus,  ',
			N'cast(isnull(gera.ApprovedDate , '''') as varchar(20)) ApprovedDate,  ',
			N'isnull(iutn.Address, '''') +'', ''+ isnull(ct.City_Name, '''') + '', '' + isnull(st.State_Name, '''') + '', '' + ',
			N'isnull(co.Country_Name, '''') ',
			N'BranchAddress, ',
			N'(select top 1 isnull(CONVERT(VARCHAR, AttendanceIn, 100), '''') LastLoginAttendanceIn  ',
			N'from TBL_ET_Attendance(nolock)  ',
			N'Where UserId = chiur.UserId order by 1 desc) LastLoginAttendanceIn from  ',
			N'TBL_ET_GeoEntityCheckInOutRequest(nolock) chiur ',
			N'inner join User_Detail(nolock) ud on chiur.UserId = ud.User_ID   ',
			N'inner join TBL_ET_GeoEntityCheckInOutRequestApproval(nolock) gera on chiur.GeoEntityChkInOutRequestId = gera.GeoEntityChkInOutRequestId ',
			N'inner join User_Detail(nolock) ud2 on gera.ApprovedBy = ud2.User_ID   ',
			N'left join TBL_ET_AttendanceGroupUserMapping (nolock) agum on chiur.UserId = agum.UserId ',
			N'inner join TBL_ET_PhysicalAppointment (nolock) papt on  chiur.PhysicalAppointmentId = papt.PhysicalAppointmentId ',
			N'left join TBL_ET_GeoEntitySiteMaster(nolock) gesm on papt.GeoEntitySiteId = gesm.GeoEntitySiteId ',
			N'left join TBL_ET_GeoEntityMaster(nolock) gemr on gesm.GeoEntityId = gemr.GeoEntityId ',
			N'left join tbl_inv_UserTaxNumber (nolock) iutn on agum.UserBranchId = iutn.Id ',
			N'left join M_City (nolock) ct on iutn.City_Id = ct.City_Id ',
			N'left join M_State (nolock) st on iutn.State_Id = st.State_Id ',
			N'left join M_Country (nolock) co on iutn.Country_Id = co.Country_Id ',
			N'Where  (chiur.UserId in (select item from dbo.fu_SplitString(''' + cast(@UserIdTeamLst as varchar(1000)) + ''', '','')))    ',
			N'and chiur.ActionType != '''' and (gera.ApproverStatus = ''Approved'' or gera.ApproverStatus = ''Rejected'')   ',
			N')t ',
			N'where (1=1) ',  @SearchText, ' ',
			N'Order By t.ActionDateTime Desc  ',
			N'Offset ', @OffsetValue, ' rows fetch next ', @PagingSize, ' rows only ')
  
	print @query 
	 execute sp_executesql @query  
 
	END TRY  
  
	BEGIN CATCH  
	 DECLARE @ErrorMessage NVARCHAR(4000);  
	 SELECT @ErrorMessage = ERROR_MESSAGE();  
	 RAISERROR (  
	   @ErrorMessage  
	   ,16  
	   ,1  
	   );  
	END CATCH  
END



