 ,@SearchText nvarchar(max) = ''  
 ,@Condition varchar(20) = 'StartWith'                        
 ,@UserId bigint = 0  
 ,@ParentId bigint = 0  
)
AS
SET NOCOUNT ON

BEGIN TRY  
Select @ParentId = ParentId from User_Detail(nolock) where User_Id = @UserId

if(@SearchText != '')  
Begin  
set @SearchText = ' and ' + @SearchText  
End 
Declare @UserIdTeamLst varchar(4000)  
select @UserIdTeamLst = UserIdTeamLst from ufn_GetUserRoleScope(@UserId)  
print @UserIdTeamLst  

Declare @query nvarchar(max) 
set @query = 'Select count(t.GeoEntityChkInOutRequestId) over() as TotalRecords, * from (Select chiur.GeoEntityChkInOutRequestId, (ud.FName + '' '' + ud.LName) + '' ('' + ud.User_Login + '')'' EmployeeName, gemr.Mobile, gemr.EmailId, gemr.EntityId, gemr.GeoEntityType, 
	gesm.GeoEntitySiteId, gesm.GeoEntitySiteName SiteName, isnull(papt.OutcomesId, 0) OutcomesId,
	(Case
       When gemr.GeoEntityType =''lead'' Then (Select ud.LeadNo from userLeads ud
       where ud.Id= gemr.EntityId)
       When gemr.GeoEntityType =''enquiry'' Then (Select ue.LeadNo from UserEnquiry ue
       where ue.EnquiryId= gemr.EntityId)
	   else
	   0
     End) LeadNo,
	(Case
       When gemr.GeoEntityType =''lead'' Then (Select ud.PersonName from userLeads ud
       where ud.Id= gemr.EntityId)
       When gemr.GeoEntityType =''enquiry'' Then (Select ue.PersonName from UserEnquiry ue
     where ue.EnquiryId= gemr.EntityId)
     End) PersonName,
	 (Case
       When gemr.GeoEntityType =''lead'' Then (Select ud.ProfileImgFileName from userLeads ud
       where ud.Id= gemr.EntityId)
       When gemr.GeoEntityType =''enquiry'' Then (Select ue.ProfileImgFileName from UserEnquiry ue
       where ue.EnquiryId= gemr.EntityId)
	   else
	   ''''
    End) ImageName,
ud.ProfilePictureName, 0 GeoEntityChkInOutReqApprovalId, chiur.PhysicalAppointmentId, chiur.UserId, chiur.ActionType, Cast(chiur.ScheduledDateTime as varchar(100)) ScheduledDateTime, Cast(chiur.ActionDateTime as varchar(20)) ActionDateTime, Cast(chiur.CreatedDate as varchar(20)) RequestDate, Cast(chiur.CreatedDate as varchar(20)) CreatedDate, chiur.CreatedBy, chiur.IsActive, isnull(chiur.Remarks, '''') Remarks, chiur.ParentId, (case when chiur.IsActive = 1 then ''Active'' else ''InActive'' End) Status, 0 ApprovedBy, '''' ApproverRemarks, ''Pending'' ApproverStatus, '''' ApprovedDate, isnull(iutn.Address, '''') +'', ''+ isnull(ct.City_Name, '''') + '', '' + isnull(st.State_Name, '''') + '', '' + isnull(co.Country_Name, '''')  BranchAddress, (select top 1 isnull(CONVERT(VARCHAR, AttendanceIn, 100), '''') LastLoginAttendanceIn from TBL_ET_Attendance(nolock) Where UserId = chiur.UserId order by 1 desc) LastLoginAttendanceIn from 
 TBL_ET_GeoEntityCheckInOutRequest(nolock) chiur
 inner join User_Detail(nolock) ud on chiur.UserId = ud.User_ID  
 inner join TBL_ET_AttendanceGroupUserMapping (nolock) agum on chiur.UserId = agum.UserId
 inner join TBL_ET_PhysicalAppointment (nolock) papt on  chiur.PhysicalAppointmentId = papt.PhysicalAppointmentId
 left join TBL_ET_GeoEntitySiteMaster(nolock) gesm on papt.GeoEntitySiteId = gesm.GeoEntitySiteId
 left join TBL_ET_GeoEntityMaster(nolock) gemr on gesm.GeoEntityId = gemr.GeoEntityId
 left join tbl_inv_UserTaxNumber (nolock) iutn on agum.UserBranchId = iutn.Id
 left join M_City (nolock) ct on iutn.City_Id = ct.City_Id
 left join M_State (nolock) st on iutn.State_Id = st.State_Id
 left join M_Country (nolock) co on iutn.Country_Id = co.Country_Id
Where GeoEntityChkInOutRequestId not in (select GeoEntityChkInOutRequestId from TBL_ET_GeoEntityCheckInOutRequestApproval(nolock) aa where (aa.CreatedBy in (select item from dbo.fu_SplitString(''' + cast(@UserIdTeamLst as nvarchar(max)) + ''', '','')))) and (chiur.UserId in (select item from dbo.fu_SplitString(''' + cast(@UserIdTeamLst as nvarchar(max)) + ''', '','')))   
 and chiur.ActionType != '''' 
 )t 
 where (1=1) ' + @SearchText + ' 
 Order By t.ActionDateTime Desc 
 Offset '+ cast(@OffsetValue as varchar(10)) + ' rows fetch next '+ cast(@PagingSize as varchar(10)) + ' rows only '  
  
print @query 
 execute sp_executesql @query  
 
END TRY  
  
BEGIN CATCH  
 DECLARE @ErrorMessage NVARCHAR(4000);  
 SELECT @ErrorMessage = ERROR_MESSAGE();  
 RAISERROR (  
   @ErrorMessage  
   ,16  
   ,1  
   );  
END CATCH  



