       where ue.EnquiryId= gemr.EntityId)
	   else
	   ''
   End) ImageName,
   atr.PhysicalAppointmentId,
   ud.ParentID as [ParentId],
   concat(papt.Title, ' ( ', papt.StartDate, '-', papt.EndDate, ' )') AS [PhysicalAppointmentDisplayName],
  ud.ProfilePictureName, ud.Address, ud.CompnayName,
	convert(varchar, atr.ScheduledDateTime, 100) ScheduledDateTime, 
	convert(varchar, atr.ActionDateTime, 100) ActionDateTime, 
	convert(varchar, atr.RequestDate, 100) RequestDate, 
	(case when atr.IsActive = 1 then 'Active' else 'InActive' End) Status, atr.Remarks 
	from TBL_ET_GeoEntityCheckInOutRequest(nolock) atr 
	inner join User_Detail(nolock) ud on atr.UserId = ud.User_ID
	inner join TBL_ET_PhysicalAppointment (nolock) papt on atr.PhysicalAppointmentId = papt.PhysicalAppointmentId
	left join TBL_ET_GeoEntitySiteMaster(nolock) gesm on papt.GeoEntitySiteId = gesm.GeoEntitySiteId
	left join TBL_ET_GeoEntityMaster(nolock) gemr on gesm.GeoEntityId = gemr.GeoEntityId
	where atr.GeoEntityChkInOutRequestId = @GeoEntityChkInOutRequestId

	Select GetDate() CurrentDate
   END /*End here for list */
  Else IF (@Mode = 'CS') /*This is List Details */
   BEGIN

 Select count(atr.GeoEntityChkInOutRequestId) over() as TotalRecords, atr.GeoEntityChkInOutRequestId, atr.ActionType, 
	(ud.FName + ' ' + ud.LName) + ' (' + ud.User_Login + ')' EmployeeName, gemr.Mobile, gemr.EmailId, gemr.EntityId, gemr.GeoEntityType, 
	gesm.GeoEntitySiteId, gesm.GeoEntitySiteName SiteName, isnull(papt.OutcomesId, 0) OutcomesId, '' ImageName,
	(Case
       When gemr.GeoEntityType ='lead' Then (Select ud.LeadNo from userLeads ud
       where ud.Id= gemr.EntityId)
       When gemr.GeoEntityType ='enquiry' Then (Select ue.LeadNo from UserEnquiry ue
       where ue.EnquiryId= gemr.EntityId)
	   else
	   0
     End) LeadNo,
	(Case
       When gemr.GeoEntityType ='lead' Then (Select ud.PersonName from userLeads ud
       where ud.Id= gemr.EntityId)
