/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_ComplianceRules]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- usp_TBL_ET_ComplianceRules 'CE', 4, '', '', '', 34594, 0, 1
CREATE   PROCEDURE [dbo].[usp_TBL_ET_ComplianceRules] (  
 @Mode VARCHAR(3),  
 @ComplianceRulesId bigint = 0,  
 @ComplianceRulesName varchar(100) = '',  
 @FieldConditionList nvarchar(max) = '',  
 @ActionConditionList nvarchar(max) = '',  
 @ParentId bigint = 0, 
 @CreatedBy bigint = 0, 
 @IsActive bit = 1
  )  
AS 
SET NOCOUNT ON  
  
BEGIN TRY  
set  @ParentId = (select ParentId from User_detail (nolock) where User_Id = @CreatedBy) 

IF (@Mode = 'CI') /*This is for Insert Details */  
 BEGIN 

 if(Not Exists(Select 1 from TBL_ET_ComplianceRules(nolock) ag Where ag.ComplianceRulesName = @ComplianceRulesName and ag.ParentId = @ParentId))  
 Begin
 insert into TBL_ET_ComplianceRules (ComplianceRulesName, ParentId, CreatedBy, CreatedDate, IsActive)  
 Values(@ComplianceRulesName, @ParentId, @CreatedBy, GetDate(), @IsActive)  
   
 set @ComplianceRulesId = SCOPE_IDENTITY()  
  
    if(@FieldConditionList != '')  
 Begin  

 Insert into TBL_ET_ComplianceRulesCondition (ComplianceRulesId, SequenceNo, Operand1, Operator, Operand2, Conjunction, ParentId, CreatedDate, CreatedBy, IsActive)  
 select @ComplianceRulesId, SequenceNo, Operand1, Operator, Operand2, Conjunction, @ParentId, GETDATE(), @CreatedBy, @IsActive from openjson(@FieldConditionList)  
 with 
 (  
  SequenceNo int '$.SequenceNo',                    
  Operand1 nvarchar(100) '$.Operand1',                    
  Operator nvarchar(50) '$.Operator',  
  Operand2 nvarchar(50) '$.Operand2',  
  Conjunction nvarchar(50) '$.Conjunction'  
 ) tF  
  End  
  
    if(@ActionConditionList != '')  
 Begin  
 insert into TBL_ET_ComplianceBreachDetail (ComplianceRulesId, BreachNo , BreachNoName, IsNotification, IsTakeAction, Message, ParentId, CreatedDate, CreatedBy, IsActive)  
 select @ComplianceRulesId, BreachNo, BreachNoName, IsNotification, IsTakeAction, [Message], @ParentId, GETDATE(), @CreatedBy, @IsActive from openjson(@ActionConditionList)  
 with   
 (
  BreachNo int '$.BreachNo',                    
  BreachNoName nvarchar(100) '$.BreachNoName',                    
  IsNotification bit '$.IsNotification',                    
  IsTakeAction bit '$.IsTakeAction',  
  Message nvarchar(500) '$.Message'  
 ) tS  
 End  
  
 Select 'Record Saved' Status, @ComplianceRulesId ComplianceRulesId
  
 End  
 Else  
 Begin  
  Select 'Record Already Exist!' Status  
 End  
 End  
Else IF (@Mode = 'CU') /*This is for Insert Details */  
 BEGIN
 
 if(Exists(Select top 1 ComplianceRulesId from TBL_ET_ComplianceRules(nolock) ag Where ag.ComplianceRulesId = @ComplianceRulesId and ag.ParentId = @ParentId))  
 Begin  
  
 update TBL_ET_ComplianceRules set ComplianceRulesName = @ComplianceRulesName, ParentId = @ParentId, UpdatedDate = GetDate(), UpdatedBy = @CreatedBy, IsActive = @IsActive where ComplianceRulesId = @ComplianceRulesId
  
delete TBL_ET_ComplianceRulesCondition where ComplianceRulesId = @ComplianceRulesId
delete TBL_ET_ComplianceBreachDetail where ComplianceRulesId = @ComplianceRulesId 
  
    if(@FieldConditionList != '')  
 Begin  
  
 Insert into TBL_ET_ComplianceRulesCondition (ComplianceRulesId, SequenceNo, Operand1, Operator, Operand2, Conjunction, ParentId, CreatedDate, CreatedBy, IsActive)  
 select @ComplianceRulesId, SequenceNo, Operand1, Operator, Operand2, Conjunction, @ParentId, GETDATE(), @CreatedBy, @IsActive from openjson(@FieldConditionList)  
 with 
 (  
  SequenceNo int '$.SequenceNo',                    
  Operand1 nvarchar(100) '$.Operand1',                    
  Operator nvarchar(50) '$.Operator',  
  Operand2 nvarchar(50) '$.Operand2',  
  Conjunction nvarchar(50) '$.Conjunction'  
 ) tF  
  End  
  
    if(@ActionConditionList != '')  
 Begin  
 insert into TBL_ET_ComplianceBreachDetail (ComplianceRulesId, BreachNo, BreachNoName, IsNotification, IsTakeAction, Message, ParentId, CreatedDate, CreatedBy, IsActive)  
 select @ComplianceRulesId, BreachNo, BreachNoName, IsNotification, IsTakeAction, [Message], @ParentId, GETDATE(), @CreatedBy, @IsActive from openjson(@ActionConditionList)  
 with   
 (  
  BreachNo int '$.BreachNo',                    
  BreachNoName nvarchar(100) '$.BreachNoName',  
  IsNotification bit '$.IsNotification',                    
  IsTakeAction bit '$.IsTakeAction',  
  Message nvarchar(500) '$.Message'  
 ) tS  
 End  
  
  Select 'Record Updated' Status, @ComplianceRulesId ComplianceRulesId  
 End 
 Else  
 Begin 
  Select 'Record not Exist!' Status, @ComplianceRulesId ComplianceRulesId
 End 
 End 
Else IF (@Mode = 'CL') /*This is for Insert Details */  
 BEGIN 
 select ComplianceRulesId, ComplianceRulesName, ParentId, CreatedDate, CreatedBy, UpdatedDate, UpdatedBy, IsActive from TBL_ET_ComplianceRules 
 where ParentId =@ParentId and ComplianceRulesName like '%'+ @ComplianceRulesName +'%'

End 
Else IF (@Mode = 'CE') /*This is for Insert Details */  
 BEGIN 
 Select ComplianceRulesId, ComplianceRulesName, crs.ParentId, crs.CreatedDate, crs.CreatedBy, crs.UpdatedDate, crs.UpdatedBy, crs.IsActive,
  (ud.FName + ' ' + ud.LName + '( '+ User_Login +')') CreatedUserName, cast(crs.CreatedDate as varchar(11)) CreatedDateS, isnull(crs.UpdatedDate,
  crs.CreatedDate) UpdatedDate
 from TBL_ET_ComplianceRules(nolock) crs
 inner join User_detail(nolock) ud on  crs.CreatedBy = ud.User_ID
 where crs.ParentId =@ParentId and ComplianceRulesId = @ComplianceRulesId

 Select ComplianceRulesCondId, ComplianceRulesId, SequenceNo, Operand1, Operator, Operand2, Conjunction,
 (ud.FName + ' ' + ud.LName + '( '+ User_Login +')') CreatedUserName, crc.ParentId, 
 cast(crc.CreatedDate as varchar(11)) CreatedDateS, isnull(crc.UpdatedDate, crc.CreatedDate) UpdatedDate, 
 CreatedDate, CreatedBy, UpdatedDate, UpdatedBy, crc.IsActive, 
 case when crc.IsActive = 1 then 'Active' else 'InActive' End Status
 from TBL_ET_ComplianceRulesCondition (nolock) crc 
 inner join User_detail(nolock) ud on  crc.CreatedBy = ud.User_ID 
 where crc.ParentId = @ParentId and crc.ComplianceRulesId = @ComplianceRulesId 

 Select * from TBL_ET_ComplianceBreachDetail (nolock) cr
 where ParentId =@ParentId and ComplianceRulesId = @ComplianceRulesId

End  

Else IF (@Mode = 'DL') /*This is for Insert Details */  
 BEGIN  
 Update TBL_ET_ComplianceRules set IsActive = 0 where ComplianceRulesId = @ComplianceRulesId
 Update TBL_ET_ComplianceRulesCondition set IsActive = 0 where ComplianceRulesId = @ComplianceRulesId
 Update TBL_ET_ComplianceBreachDetail set IsActive = 0 where ComplianceRulesId = @ComplianceRulesId
Select 'Record Deleted' Status
End  
END TRY  
  
BEGIN CATCH  
 DECLARE @ErrorMessage NVARCHAR(4000);  
 SELECT @ErrorMessage = ERROR_MESSAGE();  
 RAISERROR (  
   @ErrorMessage  
   ,16  
   ,1  
   );  
END CATCH  



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_ComplianceRulesList_Name]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_TBL_ET_ComplianceRulesList_Name]  
(  
 @OffsetValue int = 0,                      
 @PagingSize int = 20,                          
 @SearchText [varchar](200) = NULL,                          
 @Condition varchar(20) = '',                          
 @UserId [bigint] NULL,                          
 @ParentId [bigint] NULL  
)  
AS                          
  SET NOCOUNT ON      
  BEGIN TRY                          
  begin 

declare @IsAdmin bit = 0    
declare @TimeZoneName nvarchar(255) =  isnull(( select TimeZone from MySMS.dbo.User_Detail(nolock) where User_ID = @Userid),'India Standard Time')    
Declare @UserIDTeam bigint = @Userid ;    
declare @tbluser table (User_ID bigint,Name varchar(100), Image varchar(100))    
  
select @IsAdmin = IsAdmin, @ParentId = ParentId from MySMS.dbo.User_Detail(nolock) where User_ID = @Userid    
if(@UserId = @ParentId)    
begin    
 set @Userid = 0;    
 insert into @tbluser    
 exec MySMS.dbo.Use_GetUserDetails @ParentId  
end    
else   
Begin    
 insert into @tbluser    
 exec MySMS.dbo.Use_GetUserDetails @UserId  
End 
Select count(t.ComplianceRulesId) over() as TotalRow,  * from (  
Select distinct ag.ComplianceRulesId, ComplianceRulesName, ag.ParentId, '' FieldConditionList, '' ActionConditionList,
(ud.FName + ' ' + ud.LName + '( '+ User_Login +')') CreatedUserName,
ag.CreatedDate, ag.CreatedBy, cast(ag.CreatedDate as varchar(11)) CreatedDateS, isnull(ag.UpdatedDate, ag.CreatedDate) UpdatedDate, 
isnull(ag.UpdatedBy, ag.CreatedBy) UpdatedBy, ag.IsActive, 
case when ag.IsActive = 1 then 'Active' else 'InActive' End Status
from TBL_ET_ComplianceRules(nolock) ag 
inner join User_detail(nolock) ud on  ag .CreatedBy = ud.User_ID
 Where ag.ComplianceRulesName like '%' + @SearchText + '%' and (ag.CreatedBy in (select User_ID from @tbluser) or ag.ParentId = @ParentId)   
 )t  
 Order by t.ComplianceRulesName Asc   
 OFFSET @OffsetValue Rows FETCH NEXT @PagingSize ROWS ONLY   
  end   
 END TRY   
BEGIN CATCH  
exec MySMS.dbo.usp_inserterrorinfo  
 DECLARE @ErrorMessage NVARCHAR(4000);                           
 SELECT @ErrorMessage = ERROR_MESSAGE();                           
 RAISERROR (@ErrorMessage, 16, 1);                           
END CATCH



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_DailyPlan]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_TBL_ET_DailyPlan] (  
 @Mode VARCHAR(2),  
 @UserId bigint,  
 @StartDate Datetime,  
 @EndDate Datetime  
 )  
AS  
SET NOCOUNT ON  

BEGIN TRY 


--Declare 
--	@Mode VARCHAR(2) = N'DD',  
--	@UserId bigint = 32222,-- 36932, 38991, 39832, 39304, 34126, 34081, 32392, 32226, 34136  
--	@StartDate Datetime = N'09-Jun-2023 00:00:00.000',  
--	@EndDate Datetime = N'09-Jun-2023 00:00:00.000'


 IF (@Mode = 'DP') /*This is for Insert Details */  
 BEGIN  
  
--Declare @Mode VARCHAR(2) = '',  
-- @UserId bigint = --34594, --  
-- 34594,-- 36932, 38991, 39832, 39304, 34126, 34081, 32392, 32226, 34136  
-- @StartDate Datetime = '2022-12-09 00:00:00.000',  
-- @EndDate Datetime = '2022-12-09 00:00:00.000'  
  
 Declare @Parentid bigint  
 Declare @IsSignInStatus bit = 0  
 Declare @AttendanceIn DateTime = null  
  
 Select @Parentid = ParentId from User_Detail(nolock) where User_Id = @UserId  
  
 --Select dbo.fn_GetSignInStatus(@UserId) IsSignInStatus  
  Select top 1 @IsSignInStatus = (case when isnull(AttendanceIn, '') != '' then 1 else 0 end), @AttendanceIn = AttendanceIn   
 from TBL_ET_Attendance atdn (nolock) where UserId = @UserId and Cast(AttendanceIn as Date) = Cast(@StartDate as Date) and IsActive = 1    
 order by AttendanceId desc  
  
 Select @IsSignInStatus IsSignInStatus, @AttendanceIn AttendanceIn  
  
 Drop table if Exists #Appointmentlist  
  
 CREATE TABLE #Appointmentlist (Id bigint, APTType varchar(30), Title varchar(200), Description nvarchar(max), StartDate datetime, EndDate datetime, Address nvarchar(max), Status varchar(15), CheckIn datetime, CheckOut datetime, LatitudeIn varchar(50), LongitudeIn varchar(50), LatitudeOut varchar(50), LongitudeOut varchar(50), Latitude varchar(50), Longitude varchar(50), Mobile varchar(50), EmailId  varchar(50), EntityId bigint, GeoEntityType varchar(20), OwnerName varchar(20), GeoEntitySiteId bigint, SiteName nvarchar(max), OutcomesId bigint, Outcome varchar(20), LeadNo bigint, PersonName varchar(100), ImageName varchar(150), ParentId bigint, BreakTransactionId bigint, BreakStartDate datetime, BreakEndDate datetime, CheckInStatus varchar(30), CheckOutStatus
 varchar(30))  
   
 insert into #Appointmentlist (Id, APTType, Title, Description, StartDate, EndDate, Address, Status, CheckIn, CheckOut, LatitudeIn, LongitudeIn, LatitudeOut, LongitudeOut, Latitude, Longitude, Mobile, EmailId, EntityId, GeoEntityType, OwnerName, GeoEntitySiteId, SiteName, OutcomesId, Outcome, LeadNo, PersonName, ImageName, ParentId, BreakTransactionId, BreakStartDate, BreakEndDate, CheckInStatus, CheckOutStatus)  
  
 select * from (  
 Select Distinct papt.PhysicalAppointmentId Id, 'PhysicalApt' APTType, papt.Title, papt.Description, papt.StartDate, papt.EndDate, papt.Address, papt.Status, gecu.CheckIn, gecu.CheckOut, gecu.LatitudeIn, gecu.LongitudeIn,  gecu.LatitudeOut, gecu.LongitudeOut,  
 gesm.Latitude, gesm.Longitude, gemr.Mobile, gemr.EmailId, gemr.EntityId, gemr.GeoEntityType,  
 Concat(ud.FName, ' ', isnull(ud.LName, '')) OwnerName,   
 gesm.GeoEntitySiteId, gesm.GeoEntitySiteName SiteName, isnull(papt.OutcomesId, 0) OutcomesId, isnull(oc.OutcomeName, '') Outcome,  
 (Case  
       When gemr.GeoEntityType ='lead' Then (Select ud.LeadNo from userLeads ud  
       where ud.Id= gemr.EntityId)  
       When gemr.GeoEntityType ='enquiry' Then (Select ue.LeadNo from UserEnquiry ue  
       where ue.EnquiryId= gemr.EntityId)  
    else  
    0  
     End) LeadNo,  
 (Case  
       When gemr.GeoEntityType ='lead' Then (Select ud.PersonName from userLeads ud  
       where ud.Id= gemr.EntityId)  
       When gemr.GeoEntityType ='enquiry' Then (Select ue.PersonName from UserEnquiry ue  
     where ue.EnquiryId= gemr.EntityId)  
     End) PersonName,  
  (Case  
       When gemr.GeoEntityType ='lead' Then (Select ud.ProfileImgFileName from userLeads ud  
       where ud.Id= gemr.EntityId)  
       When gemr.GeoEntityType ='enquiry' Then (Select ue.ProfileImgFileName from UserEnquiry ue  
       where ue.EnquiryId= gemr.EntityId)  
    else  
    ''  
    End) ImageName, @Parentid ParentId, isnull(bt.BreakTransactionId, 0) BreakTransactionId, isnull(bt.StartDate, null) BreakStartDate, isnull(bt.EndDate, null) BreakEndDate, (case when ((isnull(gecu.CheckIn, '') = '') and (isnull(gecrIn.ActionDateTime, '') = '')) then 'CheckInPending'   
 when isnull(gecu.CheckIn, '') != '' then 'CheckInNormal'  
 when ((gecrIn.ActionDateTime != '') and (isnull(gecrIn.ActionDateTime, '') = '')) then 'CheckInPending'  
 when ((gecrIn.ActionDateTime != '') and (geca.ApproverStatus = 'Rejected')) then 'CheckInRejected'  
 when ((gecrIn.ActionDateTime != '') and (geca.ApproverStatus = 'Approved')) then 'CheckInApproved'  
 else '' end) CheckInStatus,   
 (case when ((isnull(gecu.CheckOut, '') = '') and (isnull(gecrOut.ActionDateTime, '') = '')) then 'CheckOutPending'   
 when isnull(gecu.CheckIn, '') != '' then 'CheckOutNormal'  
 when ((gecrOut.ActionDateTime != '') and (isnull(gecrOut.ActionDateTime, '') = '')) then 'CheckOutPending'  
 when ((gecrOut.ActionDateTime != '') and (geca.ApproverStatus = 'Rejected')) then 'CheckOutRejected'  
 when ((gecrOut.ActionDateTime != '') and (geca.ApproverStatus = 'Approved')) then 'CheckOutApproved'  
 else '' end)  
   
 --(case when gecu.CheckOut = null then 'CheckLOutPending' else 'CheckOutNormal' end)   
 CheckOutStatus  
 from TBL_ET_PhysicalAppointment(nolock) papt  
 inner join TBL_ET_GeoEntitySiteMaster(nolock) gesm on papt.GeoEntitySiteId = gesm.GeoEntitySiteId  
 inner join TBL_ET_GeoEntityMaster(nolock) gemr on gesm.GeoEntityId = gemr.GeoEntityId  
 inner join TBL_ET_PhyAppointUserMapping(nolock) paum on papt.PhysicalAppointmentId = paum.PhysicalAppointmentId  
 left join User_Detail(nolock) ud on papt.AssignedTo = ud.User_ID  
 left join TBL_ET_GeoEntityCheckInOut (nolock) gecu on papt.PhysicalAppointmentId = gecu.PhysicalAppointmentId  
 left join TBL_ET_GeoEntityCheckInOutRequest (nolock) gecrIn on papt.PhysicalAppointmentId = gecrIn.PhysicalAppointmentId and gecrIn.ActionType = 'CheckIn'  
 left join TBL_ET_GeoEntityCheckInOutRequest (nolock) gecrOut on papt.PhysicalAppointmentId = gecrOut.PhysicalAppointmentId and gecrOut.ActionType = 'CheckOut'  
 left join TBL_ET_GeoEntityCheckInOutRequestApproval (nolock) geca on gecrOut.GeoEntityChkInOutRequestId = geca.GeoEntityChkInOutRequestId  
 left join tbl_tsk_UserOutcomeMaster (nolock) oc on papt.OutcomesId = oc.Id  
 left join TBL_ET_BreakTransaction (nolock) bt on paum.UserId = bt.CreatedBy and bt.StartDate between papt.StartDate and papt.EndDate  
 where paum.UserId = @UserId   
 and ((cast(papt.StartDate as Date) between cast(@StartDate as Date) and cast(@EndDate as Date))  
 or (cast(papt.EndDate as Date) between cast(@StartDate as Date) and cast(@EndDate as Date)))  
 )tt  
  
 DECLARE @Query NVARCHAR(MAX) =   
  N'Select * from ( SELECT TaskHistoryId Id, ''VirtualApt'' APTType, Title, Description, StartDate, EndDate, Address, STATUS, '''' CheckIn, '''' CheckOut,  '''' LatitudeIn, '''' LongitudeIn, '''' LatitudeOut, '''' LongitudeOut,  '''' Latitude, '''' Longitude, '''' Mobile, '''' EmailId, LeadId EntityId, ''lead'' GeoEntityType, RelatedTo OwnerName, 0 GeoEntitySiteId, RelatedToProfile SiteName, OutcomesId, OutcomeName Outcome, 0 LeadNo, Collaboraters PersonName, ImageName, ParentId, BreakTransactionId, isnull(BreakStartDate, null) BreakStartDate, isnull(BreakEndDate, null) BreakEndDate, CheckInStatus, CheckOutStatus FROM ( SELECT A.LeadId, A.Id as [TaskHistoryId], A.Title, A.Description, A.Address, A.StartDate, A.EndDate, A.STATUS, UL.PersonName as [RelatedTo], UL.ProfileImgFileName AS [RelatedToProfile], dbo.udf_mk_GetTaskCreatorName(A.CreatedBy) AS [CreatorName], A.ParentID, A.AssignedTo, A.CreatedBy, 0 AS [UserId], A.IsTask, A.IsAppointment, A.OutcomesId, A.IsActive, A.CompletedOn, A.TaskId, dbo.udf_mk_GetTotalAttachment(A.Id) AS [TotalAttachments],  A.Remarks, A.CreatedOn, A.UpdatedOn, dbo.udf_tsk_GetCollaboratersNames(A.Id) AS [Collaboraters], dbo.udf_mk_GetTaskCreatorName(A.AssignedTo) AS [OwnerName], UOM.OutcomeName, UL.ProfileImgFileName ImageName, 0
 BreakTransactionId, null BreakStartDate, null BreakEndDate, '''' CheckInStatus, '''' CheckOutStatus  
      FROM ( SELECT TH.LeadId, TH.Id, TH.Title, TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.STATUS, UD.ParentID, TH.AssignedTo, TH.CreatedBy, 0 AS [UserId], TH.IsTask, TH.IsAppointment, TH.OutcomesId, TH.IsActive, TH.CompletedOn, TH.TaskId, TH.Remarks, TH.CreatedOn, TH.UpdatedOn FROM tbl_tsk_TaskHistory(NOLOCK) TH INNER JOIN UserLeads(NOLOCK) UL ON TH.LeadId = UL.ID AND th.taskid <> 4 LEFT JOIN User_Detail(NOLOCK) UD ON TH.CreatedBy = UD.User_ID OR UL.ParentID = UD.User_ID WHERE UD.User_Id ='
 + cast(@UserId AS VARCHAR) + ' AND IsActive = 1 AND TH.IsAppointment = ''1''   
    UNION'  
  
 DECLARE @Query1 NVARCHAR(max) = N' SELECT TH.LeadId, TH.Id, TH.Title, TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.STATUS, UD.ParentID, TH.AssignedTo, TH.CreatedBy,0 AS [UserId], TH.IsTask, TH.IsAppointment, TH.OutcomesId, TH.IsActive, TH.CompletedOn, TH.TaskId, TH.Remarks, TH.CreatedOn, TH.UpdatedOn FROM tbl_tsk_TaskHistory(NOLOCK) TH INNER JOIN UserLeads(NOLOCK) UL ON TH.LeadId = UL.ID AND th.taskid <> 4 LEFT JOIN User_Detail(NOLOCK) UD ON TH.AssignedTo = UD.User_ID OR UL.ParentID = UD.User_ID LEFT JOIN tbl_tsk_UserTaskMaster(NOLOCK) UTM ON TH.TaskId = UTM.Id WHERE UD.User_Id =' + cast(@UserId AS VARCHAR) + ' AND IsActive = 1 AND TH.IsAppointment = ''1''     
  
    UNION SELECT TH.LeadId, TH.Id, TH.Title,  TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.STATUS, UD.ParentID, TH.AssignedTo, TH.CreatedBy, 0 AS [UserId], TH.IsTask,  TH.IsAppointment,  TH.OutcomesId, TH.IsActive, TH.CompletedOn, TH.TaskId, TH.Remarks, TH.CreatedOn, TH.UpdatedOn FROM tbl_tsk_TaskHistory(NOLOCK) TH JOIN User_Detail(NOLOCK) UD ON TH.CreatedBy = UD.User_ID AND th.taskid <> 4  LEFT JOIN tbl_tsk_CollaborationUserMapping(NOLOCK) TCM ON TH.Id = TCM.TaskHistoryId WHERE TCM.User_Id =' + cast(@UserId AS VARCHAR) + ' AND IsActive = 1 AND TH.IsAppointment = ''1''   
 ) A INNER JOIN UserLeads(NOLOCK) UL ON A.LeadId = UL.ID LEFT JOIN lead_score_history_latest(NOLOCK) LS ON LS.leadid = UL.ID LEFT JOIN tbl_tsk_UserOutcomeMaster(NOLOCK) UOM ON UOM.Id = A.OutcomesId LEFT JOIN tbl_tsk_UserTaskMaster(NOLOCK) UTM ON A.TaskId 
= UTM.Id left join tbl_tsk_TaskActionPermission(NOLOCK) tap on tap.task_type_id = A.TaskId and tap.parent_id = ' + cast(@ParentId AS VARCHAR) + ' ) T where 1 = 1 and ((cast(StartDate as Date) between cast(''' + cast(@StartDate AS VARCHAR) + '''  as Date) 
and cast(''' + cast(@EndDate AS VARCHAR) + ''' as Date))  
 )  
 )ttt  
 order by StartDate asc ';  
 --or (cast(EndDate as Date) between cast(''' + cast(@StartDate AS VARCHAR) + ''' as Date) and cast(''' + cast(@EndDate AS VARCHAR) + ''' as Date))  
   
 DECLARE @Query2 NVARCHAR(max) = @Query + @Query1  
  
 PRINT @Query  
 PRINT @Query1  
  
 --print @Query2  
  
insert into #Appointmentlist (Id, APTType, Title, Description, StartDate, EndDate, Address, Status, CheckIn, CheckOut, LatitudeIn, LongitudeIn, LatitudeOut, LongitudeOut, Latitude, Longitude, Mobile, EmailId, EntityId, GeoEntityType, OwnerName, GeoEntitySiteId, SiteName, OutcomesId, Outcome, LeadNo, PersonName, ImageName, ParentId, BreakTransactionId, BreakStartDate, BreakEndDate, CheckInStatus, CheckOutStatus)  
  
EXECUTE sp_executesql @Query2  
  
select * from #Appointmentlist order by StartDate Asc  
  
 --Select dbo.fn_GetSignOutStatus(@UserId) IsSignOutStatus  
 Declare @IsSignOutStatus bit = 0  
 Declare @AttendanceOut DateTime = null  
  
 Select top 1 @IsSignOutStatus = (case when isnull(AttendanceOut, '') = '' then 0 else 1 end), @AttendanceOut = AttendanceOut    
  from TBL_ET_Attendance atdn (nolock) where UserId = @UserId and Cast(AttendanceIn as Date) = Cast(@StartDate as Date) and IsActive = 1    
  order by AttendanceId desc  
  
 Select @IsSignOutStatus IsSignOutStatus, @AttendanceOut AttendanceOut  
  
 END /*End here for search*/  
 Else IF (@Mode = 'DD') /*This is for Insert Details */  
 BEGIN  
  
--Declare @Mode VARCHAR(2) = '',  
-- @UserId bigint = --34594, --  
-- 34594,-- 36932, 38991, 39832, 39304, 34126, 34081, 32392, 32226, 34136  
-- @StartDate Datetime = '2022-12-09 00:00:00.000',  
-- @EndDate Datetime = '2022-12-09 00:00:00.000'  
  
 Declare @Parentid2 bigint  
 Declare @IsSignInStatus2 bit = 0  
 Declare @AttendanceIn2 DateTime = null  
  
 Select @Parentid2 = ParentId from User_Detail(nolock) where User_Id = @UserId  
  
 --Select dbo.fn_GetSignInStatus(@UserId) IsSignInStatus  
  Select top 1 @IsSignInStatus2 = (case when isnull(AttendanceIn, '') != '' then 1 else 0 end), @AttendanceIn2 = AttendanceIn   
 from TBL_ET_Attendance atdn (nolock) where UserId = @UserId and Cast(AttendanceIn as Date) = Cast(@StartDate as Date) and IsActive = 1    
 order by AttendanceId desc  
  
 Select @IsSignInStatus2 IsSignInStatus, @AttendanceIn2 AttendanceIn  
  
 Drop table if Exists #Appointmentlist2  
  
 CREATE TABLE #Appointmentlist2 (Id bigint, APTType varchar(30), Title nvarchar(255), Description nvarchar(255), StartDate datetime, EndDate datetime, Address nvarchar(max), Status varchar(15), CheckIn datetime, CheckOut datetime, CheckInTime time(5), CheckOutTime time(5), LatitudeIn varchar(50), LongitudeIn varchar(50), LatitudeOut varchar(50), LongitudeOut varchar(50), Latitude varchar(50), Longitude varchar(50), Mobile varchar(50), EmailId  varchar(50), EntityId bigint, GeoEntityType varchar(20), OwnerName varchar(20), GeoEntitySiteId bigint, SiteName varchar(150), OutcomesId bigint, Outcome varchar(20), LeadNo bigint, PersonName varchar(100), ImageName varchar(150), ParentId bigint, BreakTransactionId bigint, BreakStartDate datetime, BreakEndDate datetime, CheckInStatus varchar(30), CheckOutStatus varchar(30), RemarksIn nvarchar(max), RemarksOut nvarchar(max))  
   
 insert into #Appointmentlist2 (Id, APTType, Title, Description, StartDate, EndDate, Address, Status, CheckIn, CheckOut, CheckInTime, CheckOutTime, LatitudeIn, LongitudeIn, LatitudeOut, LongitudeOut, Latitude, Longitude, Mobile, EmailId, EntityId, GeoEntityType, OwnerName, GeoEntitySiteId, SiteName, OutcomesId, Outcome, LeadNo, PersonName, ImageName, ParentId, BreakTransactionId, BreakStartDate, BreakEndDate, CheckInStatus, CheckOutStatus, RemarksIn, RemarksOut)  
  
 select Distinct * from (  
 Select Distinct papt.PhysicalAppointmentId Id, 'PhysicalApt' APTType, papt.Title, papt.Description, papt.StartDate, papt.EndDate, papt.Address, papt.Status, gecu.CheckIn, gecu.CheckOut, convert(time,gecu.CheckIn, 0) CheckInTime, convert(time,gecu.CheckOut, 0) CheckOutTime, gecu.LatitudeIn, gecu.LongitudeIn,  gecu.LatitudeOut, gecu.LongitudeOut,  
 gesm.Latitude, gesm.Longitude, gemr.Mobile, gemr.EmailId, gemr.EntityId, gemr.GeoEntityType,  
 Concat(ud.FName, ' ', isnull(ud.LName, '')) OwnerName,   
 gesm.GeoEntitySiteId, gesm.GeoEntitySiteName SiteName, isnull(papt.OutcomesId, 0) OutcomesId, isnull(oc.OutcomeName, '') Outcome,  
 (Case  
       When gemr.GeoEntityType ='lead' Then (Select ud.LeadNo from userLeads ud  
       where ud.Id= gemr.EntityId)  
       When gemr.GeoEntityType ='enquiry' Then (Select ue.LeadNo from UserEnquiry ue  
       where ue.EnquiryId= gemr.EntityId)  
    else  
    0  
     End) LeadNo,  
 (Case  
       When gemr.GeoEntityType ='lead' Then (Select ud.PersonName from userLeads ud  
       where ud.Id= gemr.EntityId)  
       When gemr.GeoEntityType ='enquiry' Then (Select ue.PersonName from UserEnquiry ue  
     where ue.EnquiryId= gemr.EntityId)  
     End) PersonName,  
  (Case  
       When gemr.GeoEntityType ='lead' Then (Select ud.ProfileImgFileName from userLeads ud  
       where ud.Id= gemr.EntityId)  
       When gemr.GeoEntityType ='enquiry' Then (Select ue.ProfileImgFileName from UserEnquiry ue  
       where ue.EnquiryId= gemr.EntityId)  
    else  
    ''  
    End) ImageName, @Parentid2 ParentId, isnull(bt.BreakTransactionId, 0) BreakTransactionId, isnull(bt.StartDate, null) BreakStartDate, isnull(bt.EndDate, null) BreakEndDate, (case when ((isnull(gecu.CheckIn, '') = '') and (isnull(gecrIn.ActionDateTime, 
'') = '')) then 'CheckInPending'   
 when isnull(gecu.CheckIn, '') != '' then 'CheckInNormal'  
 when ((gecrIn.ActionDateTime != '') and (isnull(gecrIn.ActionDateTime, '') = '')) then 'CheckInPending'  
 when ((gecrIn.ActionDateTime != '') and (geca.ApproverStatus = 'Rejected')) then 'CheckInRejected'  
 when ((gecrIn.ActionDateTime != '') and (geca.ApproverStatus = 'Approved')) then 'CheckInApproved'  
 else '' end) CheckInStatus,   
 (case when ((isnull(gecu.CheckOut, '') = '') and (isnull(gecrOut.ActionDateTime, '') = '')) then 'CheckOutPending'   
 when isnull(gecu.CheckIn, '') != '' then 'CheckOutNormal'  
 when ((gecrOut.ActionDateTime != '') and (isnull(gecrOut.ActionDateTime, '') = '')) then 'CheckOutPending'  
 when ((gecrOut.ActionDateTime != '') and (geca.ApproverStatus = 'Rejected')) then 'CheckOutRejected'  
 when ((gecrOut.ActionDateTime != '') and (geca.ApproverStatus = 'Approved')) then 'CheckOutApproved'  
 else '' end) CheckOutStatus, isnull(gecu.RemarksIn , '') RemarksIn, isnull(gecu.RemarksOut, '') RemarksOut  
 from TBL_ET_PhysicalAppointment(nolock) papt  
 inner join TBL_ET_GeoEntitySiteMaster(nolock) gesm on papt.GeoEntitySiteId = gesm.GeoEntitySiteId  
 inner join TBL_ET_GeoEntityMaster(nolock) gemr on gesm.GeoEntityId = gemr.GeoEntityId  
 inner join TBL_ET_PhyAppointUserMapping(nolock) paum on papt.PhysicalAppointmentId = paum.PhysicalAppointmentId  
 left join User_Detail(nolock) ud on papt.AssignedTo = ud.User_ID  
 left join TBL_ET_GeoEntityCheckInOut (nolock) gecu on papt.PhysicalAppointmentId = gecu.PhysicalAppointmentId  
 left join TBL_ET_GeoEntityCheckInOutRequest (nolock) gecrIn on papt.PhysicalAppointmentId = gecrIn.PhysicalAppointmentId and gecrIn.ActionType = 'CheckIn'  
 left join TBL_ET_GeoEntityCheckInOutRequest (nolock) gecrOut on papt.PhysicalAppointmentId = gecrOut.PhysicalAppointmentId and gecrOut.ActionType = 'CheckOut'  
 left join TBL_ET_GeoEntityCheckInOutRequestApproval (nolock) geca on gecrIn.GeoEntityChkInOutRequestId = gecrIn.GeoEntityChkInOutRequestId  
 left join TBL_ET_GeoEntityCheckInOutRequestApproval (nolock) geca2 on gecrOut.GeoEntityChkInOutRequestId = geca2.GeoEntityChkInOutRequestId  
 left join tbl_tsk_UserOutcomeMaster (nolock) oc on papt.OutcomesId = oc.Id  
 left join TBL_ET_BreakTransaction (nolock) bt on paum.UserId = bt.CreatedBy and bt.StartDate between papt.StartDate and papt.EndDate  
 where paum.UserId = @UserId   
 and ((cast(papt.StartDate as Date) between cast(@StartDate as Date) and cast(@EndDate as Date))  
 or (cast(papt.EndDate as Date) between cast(@StartDate as Date) and cast(@EndDate as Date)))  
 )tt  
  
 DECLARE @Query4 NVARCHAR(MAX) =   
 N'Select * from ( SELECT TaskHistoryId Id, ''VirtualApt'' APTType, Title, Description, StartDate, EndDate, Address, STATUS, '''' CheckIn, '''' CheckOut, '''' CheckInTime, '''' CheckOutTime,  '''' LatitudeIn, '''' LongitudeIn, '''' LatitudeOut, '''' LongitudeOut,  '''' Latitude, '''' Longitude, '''' Mobile, '''' EmailId, LeadId EntityId, ''lead'' GeoEntityType, RelatedTo OwnerName, 0 GeoEntitySiteId, RelatedToProfile SiteName, OutcomesId, OutcomeName Outcome, 0 LeadNo, Collaboraters PersonName, ImageName, ParentId, BreakTransactionId, isnull(BreakStartDate, null) BreakStartDate, isnull(BreakEndDate, null) BreakEndDate, CheckInStatus, CheckOutStatus, '''' RemarksIn, '''' RemarksOut FROM ( SELECT A.LeadId, A.Id as [TaskHistoryId], A.Title, A.Description, A.Address, A.StartDate, A.EndDate, A.STATUS, UL.PersonName as [RelatedTo], UL.ProfileImgFileName AS [RelatedToProfile], dbo.udf_mk_GetTaskCreatorName(A.CreatedBy) AS [CreatorName], A.ParentID, A.AssignedTo, A.CreatedBy, 0 AS [UserId], A.IsTask, A.IsAppointment, A.OutcomesId, A.IsActive, A.CompletedOn, A.TaskId, dbo.udf_mk_GetTotalAttachment(A.Id) AS [TotalAttachments],  A.Remarks, A.CreatedOn, A.UpdatedOn, dbo.udf_tsk_GetCollaboratersNames(A.Id) AS [Collaboraters], dbo.udf_mk_GetTaskCreatorName(A.AssignedTo) AS [OwnerName], UOM.OutcomeName, UL.ProfileImgFileName ImageName, 0 BreakTransactionId, null BreakStartDate, null BreakEndDate, '''' CheckInStatus, '''' CheckOutStatus, '''' RemarksIn, '''' RemarksOut  
  FROM ( SELECT TH.LeadId, TH.Id, TH.Title, TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.STATUS, UD.ParentID, TH.AssignedTo, TH.CreatedBy, 0 AS [UserId], TH.IsTask, TH.IsAppointment, TH.OutcomesId, TH.IsActive, TH.CompletedOn, TH.TaskId, TH.Remarks, TH.CreatedOn, TH.UpdatedOn FROM tbl_tsk_TaskHistory(NOLOCK) TH INNER JOIN UserLeads(NOLOCK) UL ON TH.LeadId = UL.ID AND th.taskid <> 4 LEFT JOIN User_Detail(NOLOCK) UD ON TH.CreatedBy = UD.User_ID OR UL.ParentID = UD.User_ID WHERE UD.User_Id =' + cast(@UserId AS VARCHAR) + ' AND IsActive = 1 AND TH.IsAppointment = ''1''   
    UNION'  
  
 DECLARE @Query5 NVARCHAR(max) = N' SELECT TH.LeadId, TH.Id, TH.Title, TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.STATUS, UD.ParentID, TH.AssignedTo, TH.CreatedBy,0 AS [UserId], TH.IsTask, TH.IsAppointment, TH.OutcomesId, TH.IsActive, TH.CompletedOn, TH.TaskId, TH.Remarks, TH.CreatedOn, TH.UpdatedOn FROM tbl_tsk_TaskHistory(NOLOCK) TH INNER JOIN UserLeads(NOLOCK) UL ON TH.LeadId = UL.ID AND th.taskid <> 4 LEFT JOIN User_Detail(NOLOCK) UD ON TH.AssignedTo = UD.User_ID OR UL.ParentID = UD.User_ID LEFT JOIN tbl_tsk_UserTaskMaster(NOLOCK) UTM ON TH.TaskId = UTM.Id WHERE UD.User_Id =' + cast(@UserId AS VARCHAR) + ' AND IsActive = 1 AND TH.IsAppointment = ''1''     
  
    UNION SELECT TH.LeadId, TH.Id, TH.Title,  TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.STATUS, UD.ParentID, TH.AssignedTo, TH.CreatedBy, 0 AS [UserId], TH.IsTask,  TH.IsAppointment,  TH.OutcomesId, TH.IsActive, TH.CompletedOn, TH.TaskId, TH.Remarks, TH.CreatedOn, TH.UpdatedOn FROM tbl_tsk_TaskHistory(NOLOCK) TH JOIN User_Detail(NOLOCK) UD ON TH.CreatedBy = UD.User_ID AND th.taskid <> 4  LEFT JOIN tbl_tsk_CollaborationUserMapping(NOLOCK) TCM ON TH.Id = TCM.TaskHistoryId WHERE TCM.User_Id ='
 + cast(@UserId AS VARCHAR) + ' AND IsActive = 1 AND TH.IsAppointment = ''1''   
 ) A INNER JOIN UserLeads(NOLOCK) UL ON A.LeadId = UL.ID LEFT JOIN lead_score_history_latest(NOLOCK) LS ON LS.leadid = UL.ID LEFT JOIN tbl_tsk_UserOutcomeMaster(NOLOCK) UOM ON UOM.Id = A.OutcomesId LEFT JOIN tbl_tsk_UserTaskMaster(NOLOCK) UTM ON A.TaskId = UTM.Id left join tbl_tsk_TaskActionPermission(NOLOCK) tap on tap.task_type_id = A.TaskId and tap.parent_id = ' + cast(@ParentId2 AS VARCHAR) + ' ) T where 1 = 1 and ((cast(StartDate as Date) between cast(''' + cast(@StartDate AS VARCHAR) + '''  as Date)
 and cast(''' + cast(@EndDate AS VARCHAR) + ''' as Date))  
 )  
 )ttt  
 order by StartDate asc ';  
 --or (cast(EndDate as Date) between cast(''' + cast(@StartDate AS VARCHAR) + ''' as Date) and cast(''' + cast(@EndDate AS VARCHAR) + ''' as Date))  
   
 DECLARE @Query3 NVARCHAR(max) = @Query4 + @Query5  
  
 PRINT @Query4  
 PRINT @Query5  
  
 --print @Query2  
  
insert into #Appointmentlist2 (Id, APTType, Title, Description, StartDate, EndDate, Address, Status, CheckIn, CheckOut, CheckInTime, CheckOutTime, LatitudeIn, LongitudeIn, LatitudeOut, LongitudeOut, Latitude, Longitude, Mobile, EmailId, EntityId, GeoEntityType, OwnerName, GeoEntitySiteId, SiteName, OutcomesId, Outcome, LeadNo, PersonName, ImageName, ParentId, BreakTransactionId, BreakStartDate, BreakEndDate, CheckInStatus, CheckOutStatus, RemarksIn, RemarksOut)  
  
EXECUTE sp_executesql @Query3  
  
select Id, APTType, Title, Description, StartDate, EndDate, Address, Status, CheckIn, CheckOut, cast(CheckInTime as varchar(5)) CheckInTime, cast(CheckOutTime as varchar(5)) CheckOutTime, LatitudeIn, LongitudeIn, LatitudeOut, LongitudeOut, Latitude, Longitude, Mobile, EmailId, EntityId, GeoEntityType, OwnerName, GeoEntitySiteId, SiteName, OutcomesId, Outcome, LeadNo, PersonName, ImageName, ParentId, BreakTransactionId, BreakStartDate, BreakEndDate, CheckInStatus, CheckOutStatus, RemarksIn, RemarksOut from
 #Appointmentlist2 order by StartDate Asc  
  
 --Select dbo.fn_GetSignOutStatus(@UserId) IsSignOutStatus  
 Declare @IsSignOutStatus2 bit = 0  
 Declare @AttendanceOut2 DateTime = null  
  
 Select top 1 @IsSignOutStatus2 = (case when isnull(AttendanceOut, '') = '' then 0 else 1 end), @AttendanceOut2 = AttendanceOut    
  from TBL_ET_Attendance atdn (nolock) where UserId = @UserId and Cast(AttendanceIn as Date) = Cast(@StartDate as Date) and IsActive = 1    
  order by AttendanceId desc  
  
 Select @IsSignOutStatus2 IsSignOutStatus, @AttendanceOut2 AttendanceOut  
  
 END /*End here for search*/  
  
END TRY  
  
BEGIN CATCH  
 DECLARE @ErrorMessage NVARCHAR(4000);  
 SELECT @ErrorMessage = ERROR_MESSAGE();  
 RAISERROR (  
   @ErrorMessage  
   ,16  
   ,1  
   );  
END CATCH  



