/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_DailySchedueDetailByUserId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec usp_TBL_ET_DailySchedueDetailByUserId @UserId=34594,@FromDate=N'2023-03-01',@ToDate=N'2023-03-31',@Contain=N''
-- exec usp_TBL_ET_DailySchedueDetailByUserId @UserId=34594,@FromDate=N'2023-03-10',@ToDate=N'2023-03-10',@Contain=N''
-- exec usp_TBL_ET_DailySchedueDetailByUserId @UserId=32222,@FromDate=N'2023-06-09',@ToDate=N'2023-06-09',@Contain=N''
---- exec usp_TBL_ET_DailySchedueDetailByUserId @UserId=36932,@FromDate=N'2023-03-10',@ToDate=N'2023-03-10',@Contain=N''
CREATE   PROCEDURE  [dbo].[usp_TBL_ET_DailySchedueDetailByUserId] (      
	@UserId bigint,      
	@FromDate Date,      
	@ToDate Date,      
	@Contain nvarchar(500) = ''      
)      
AS      
SET NOCOUNT ON            
BEGIN TRY      
 Begin      

	--declare 
	--	@UserId bigint=43398,
	--	@FromDate Date =N'28-Jul-2025',
	--	@ToDate Date = N'28-Jul-2025',
	--	@Contain nvarchar(500) = ''      
      
	-- select count(t.UserLocationTrackingId) TotalRecords, * from ( 

	declare 
		@TotalPhyAppointment int  = 0,
		@CompletedPhyAppointment int  = 0


	select 
		@TotalPhyAppointment = count(fu.Userid),
		@CompletedPhyAppointment = sum(case when isnull(ch.CheckOut, '') <> '' then 1 else 0 end )
	from TBL_ET_PhysicalAppointment(nolock) pa
	inner join TBL_ET_PhyAppointUserMapping(nolock) fu on pa.PhysicalAppointmentId = fu.PhysicalAppointmentId
	inner join TBL_ET_GeoEntityCheckInOut(nolock) ch on pa.PhysicalAppointmentId = ch.PhysicalAppointmentId
		where fu.UserId = @UserId 
		and ( cast(pa.StartDate as date) between @FromDate and @ToDate
			or cast(pa.EndDate as date) between @FromDate and @ToDate )
	group by fu.UserId
		
 
	select 
		count(*) over() TotalRecords,
		coalesce(ud.User_ID,ud1.User_Id,0) as User_ID, 
		coalesce(ud.ParentID,atte.ParentId,0) as ParentID, 
		coalesce(ud.FName,ud1.FName,'') +' '+ coalesce(ud.LName,ud1.LName,'') +  ' ('+ coalesce(ud.User_Login,ud1.User_Login,'') +')' as UserName,
		ud.FName as [AgentFirstName],
		ud.LName as [AgentLastName],
		coalesce(ud.Mobile, ud1.Mobile,'') as Mobile, 
		coalesce(ud.Email, ud1.Email,'') as Email, 
		coalesce(ud.ProfilePictureName,ud1.ProfilePictureName,'') as ProfilePictureName,
		coalesce(ud.ProfilePictureName,ud1.ProfilePictureName,'')  [ProfileImage],
		isnull(atte.AttendanceIn, ultr.LocationDateTime) as AttendanceIn, 
		format(isnull(atte.AttendanceIn, ultr.LocationDateTime), 'dd-MMM-yyyy HH:mm') as LastPunchedAt, 
		concat(format( DATEADD(minute, 
			DATEDIFF(minute, isnull(atte.AttendanceIn, ultr.LocationDateTime),
			coalesce(atte.AttendanceOut, ultrd.LocationDateTime, getdate())), 0), 'HH:mm:ss'), ' Hrs')
		as TimeElapsed,
		@TotalPhyAppointment as [TotalPhyAppointment],
		@CompletedPhyAppointment as [CompletedPhyAppointment],
		isnull(atte.AttendanceOut,ultrd.LocationDateTime) as AttendanceOut, 
		dbo.fn_GetAppointmentStatusCount(ud.User_ID, cast(@FromDate as Date), cast(@ToDate as Date), '') AllAppointment,
		dbo.fn_GetAppointmentStatusCount(ud.User_ID, cast(@FromDate as Date), cast(@ToDate as Date), 'Pending') Pending,
		dbo.fn_GetAppointmentStatusCount(ud.User_ID, cast(@FromDate as Date), cast(@ToDate as Date), 'Approved') Completed,
		'No Current Task' CurrentTask, 
		(case 
			when ((atte.AttendanceIn != '') and (atte.AttendanceOut is null)) then 'On Duty'
			when ((atte.AttendanceIn != '') and (atte.AttendanceOut != '')) then 'Off Duty'
		else 'Unreachable' End ) OnDuty,
		--convert(varchar(5),DateDiff(s, atte.AttendanceIn, isnull(atte.AttendanceOut,getDate()))/3600)+':'+convert(varchar(5),DateDiff(s, atte.AttendanceIn, isnull(atte.AttendanceOut,getDate()))%3600/60) 

	  CONVERT(varchar(8), DATEADD(ss, DATEDIFF(ss, isnull(atte.AttendanceIn, ultr.LocationDateTime), isnull(atte.AttendanceOut,ultrd.LocationDateTime)), 0), 114) as WorkingTime,  
	  --CAST(dbo.fnCalcDistanceKM(ultr.Latitude, atte.LatitudeIn, ultr.Longitude, atte.LongitudeIn) AS DECIMAL(15, 2))
		try_convert(decimal, coalesce(ultrd.Distance,
		cast(dbo.fnCalcDistanceKM(ultrd.Latitude, 
			atte.LatitudeIn, ultrd.Longitude, atte.LongitudeIn) AS DECIMAL(15, 2)), 
		0)) / 1000 as Travel,
		--isnull(ultr.Sno, 0) AS Sno,
		isnull(ultr.UserLocationTrackingId,0) as UserLocationTrackingId,
		isnull(ultr.MovementCode, 'SIGN_IN') AS MovementCode,
		ultr.Remarks,
		ultr.UserId,
		ultr.LocationDateTime,
		isnull(ultr.Latitude,atte.LatitudeIn) as Latitude, isnull(ultr.Longitude,atte.LongitudeIn) as Longitude,
		ultr.Address,
		ultr.BatteryPerc,
		ultr.NetworkPerc,
		ultr.CreatedDate,
		ultr.CreatedBy,
		ultr.IsActive,
		ultr.IsMock,
		ultr.IsBulk     
	--select *
	  from (
		select UserLocationTrackingId, MovementCode, Remarks, UserId, LocationDateTime, Latitude, Longitude, Address, BatteryPerc,  
			NetworkPerc, CreatedDate, CreatedBy, IsActive, IsMock, IsBulk, Speed, Distance, LocationMetaData, IsDistanceCalc From (  
				select ROW_NUMBER()over(partition by userId,cast(LocationDateTime as date) order by UserLocationTrackingId) as Sno,  
				UserLocationTrackingId, MovementCode, Remarks, UserId, LocationDateTime, Latitude, Longitude, Address, BatteryPerc,  
				NetworkPerc, CreatedDate, CreatedBy, IsActive, IsMock, IsBulk, Speed, Distance, LocationMetaData, IsDistanceCalc  
				from TBL_ET_UserLocationTracking(nolock) where cast(LocationDateTime AS DATE) between CAST(@FromDate AS DATE) and CAST(@ToDate AS DATE)
				union  
				select ROW_NUMBER()over(partition by userId,cast(LocationDateTime as date) order by UserLocationTrackingId) as Sno,  
				UserLocationTrackingId, MovementCode, Remarks, UserId, LocationDateTime, Latitude, Longitude, Address, BatteryPerc,  
				NetworkPerc, CreatedDate, CreatedBy, IsActive, IsMock, IsBulk, Speed, Distance, LocationMetaData, IsDistanceCalc  
				FROM TBL_ET_UserLocationTracking_Archived WITH (NOLOCK) where cast(LocationDateTime AS DATE) between CAST(@FromDate AS DATE) and CAST(@ToDate AS DATE)
			) T  
			where T.Sno=1
		) ultr 
	  INNER JOIN User_Detail(NOLOCK) ud ON ultr.UserId = ud.User_ID and ud.Status = 1 
	  inner join (select UserLocationTrackingId, MovementCode, Remarks, UserId, LocationDateTime, Latitude, Longitude, Address, BatteryPerc,  
		  NetworkPerc, CreatedDate, CreatedBy, IsActive, IsMock, IsBulk, Speed, Distance, LocationMetaData, IsDistanceCalc From (  
			select ROW_NUMBER()over(partition by userId,cast(LocationDateTime as date) order by LocationDateTime desc) as Sno,  
			UserLocationTrackingId, MovementCode, Remarks, UserId, LocationDateTime, Latitude, Longitude, Address, BatteryPerc,  
			NetworkPerc, CreatedDate, CreatedBy, IsActive, IsMock, IsBulk, Speed, Distance, LocationMetaData, IsDistanceCalc  
			from TBL_ET_UserLocationTracking(nolock) where cast(LocationDateTime AS DATE) between CAST(@FromDate AS DATE) and CAST(@ToDate AS DATE) 
		 union  
		 select ROW_NUMBER()over(partition by userId,cast(LocationDateTime as date) order by LocationDateTime desc) as Sno,  
		  UserLocationTrackingId, MovementCode, Remarks, UserId, LocationDateTime, Latitude, Longitude, Address, BatteryPerc,  
		  NetworkPerc, CreatedDate, CreatedBy, IsActive, IsMock, IsBulk, Speed, Distance, LocationMetaData, IsDistanceCalc  
		 FROM TBL_ET_UserLocationTracking_Archived WITH (NOLOCK) where cast(LocationDateTime AS DATE) between CAST(@FromDate AS DATE) and CAST(@ToDate AS DATE) 
		) T where T.Sno=1  ) ultrd on ultr.UserId=ultrd.UserId 
	 and cast(ultr.LocationDateTime as date) = cast(ultrd.LocationDateTime as date) 
	  full outer JOIN V_TBL_ET_Attendance(NOLOCK) atte ON ud.User_ID = atte.UserId and ud.Status = 1 
			and CAST(ultr.LocationDateTime as Date) = isnull(CAST(atte.AttendanceIn as Date),CAST(atte.AttendanceOut as Date)) 
			left join User_Detail(nolock) ud1 on atte.UserId=ud1.User_ID
	  where 
		(
			ultr.UserId = @UserId or atte.UserId = @UserId
		)
		AND (cast(ultr.LocationDateTime AS DATE) between CAST(@FromDate AS DATE) and CAST(@ToDate AS DATE)
			or cast(atte.AttendanceIn AS DATE) between CAST(@FromDate AS DATE) and CAST(@ToDate AS DATE) 
			or cast(atte.AttendanceOut as date) between CAST(@FromDate AS DATE) and CAST(@ToDate AS DATE) 
	)

	

  --)t    
  --where sno = 1     
  --Group by User_ID, sno, ParentID, UserName, Mobile, Email, ProfilePictureName, AttendanceIn, AttendanceOut, AllAppointment, Pending, Completed, CurrentTask, OnDuty, UserLocationTrackingId, MovementCode, Remarks, UserId, LocationDateTime, Latitude, Longitude, Address, BatteryPerc, NetworkPerc, CreatedDate, CreatedBy, IsActive, IsMock, IsBulk, WorkingTime, Travel    
  --Order By t.LocationDateTime Desc     
    
--DD    
    
 Declare @Parentid2 bigint      
 Declare @IsSignInStatus2 bit = 0      
 Declare @AttendanceIn2 DateTime = null      
      
 Select @Parentid2 = ParentId from User_Detail(nolock) where User_Id = @UserId      
      
 -- Select top 1 @IsSignInStatus2 = (case when isnull(AttendanceIn, '') != '' then 1 else 0 end), @AttendanceIn2 = AttendanceIn       
 --from TBL_ET_Attendance atdn (nolock) where UserId = @UserId and Cast(AttendanceIn as Date) = Cast(@FromDate as Date) and IsActive = 1        
 --order by AttendanceId desc      
      
-- Select @IsSignInStatus2 IsSignInStatus, @AttendanceIn2 AttendanceIn      
      
 Drop table if Exists #Appointmentlist2      
      
 CREATE TABLE #Appointmentlist2 (Id bigint, APTType varchar(30), Title varchar(200), Description varchar(200), StartDate datetime, EndDate datetime, Address varchar(500), Status varchar(15), CheckIn datetime, CheckOut datetime, CheckInTime time(5), CheckOutTime time(5), LatitudeIn varchar(50), LongitudeIn varchar(50), LatitudeOut varchar(50), LongitudeOut varchar(50), Latitude varchar(50), Longitude varchar(50), Mobile varchar(50), EmailId  varchar(50), EntityId bigint, GeoEntityType varchar(20), OwnerName varchar(50), GeoEntitySiteId bigint, SiteName varchar(150), OutcomesId bigint, Outcome varchar(20), LeadNo bigint, PersonName varchar(100), ImageName varchar(150), ParentId bigint, BreakTransactionId bigint, BreakStartDate datetime, BreakEndDate datetime, CheckInStatus varchar(30), CheckOutStatus varchar(30), RemarksIn varchar(500), RemarksOut varchar(500), Remarks varchar(500), TaskId bigint)      
       
 insert into #Appointmentlist2 (Id, APTType, Title, Description, StartDate, EndDate, Address, Status, CheckIn, CheckOut, CheckInTime, CheckOutTime, LatitudeIn, LongitudeIn, LatitudeOut, LongitudeOut, Latitude, Longitude, Mobile, EmailId, EntityId, GeoEntityType, OwnerName, GeoEntitySiteId, SiteName, OutcomesId, Outcome, LeadNo, PersonName, ImageName, ParentId, BreakTransactionId, BreakStartDate, BreakEndDate, CheckInStatus, CheckOutStatus, RemarksIn, RemarksOut, Remarks, TaskId)      
      
 select Distinct * from (      
 Select Distinct papt.PhysicalAppointmentId Id, 'PhysicalApt' APTType, papt.Title, papt.Description, papt.StartDate, papt.EndDate, papt.Address, papt.Status, gecu.CheckIn, gecu.CheckOut, convert(time,gecu.CheckIn, 0) CheckInTime, convert(time,gecu.CheckOut, 0) CheckOutTime, gecu.LatitudeIn, gecu.LongitudeIn, gecu.LatitudeOut, gecu.LongitudeOut, gesm.Latitude, gesm.Longitude, gemr.Mobile, gemr.EmailId, gemr.EntityId, gemr.GeoEntityType,     
 Concat(ud.FName, ' ', isnull(ud.LName, '')) OwnerName, gesm.GeoEntitySiteId, gesm.GeoEntitySiteName SiteName, isnull(papt.OutcomesId, 0) OutcomesId, isnull(oc.OutcomeName, '') Outcome,   
 (Case      
       When gemr.GeoEntityType ='lead' Then (Select ud.LeadNo from userLeads(nolock) ud      
       where ud.Id= gemr.EntityId)      
       When gemr.GeoEntityType ='enquiry' Then (Select ue.LeadNo from UserEnquiry(nolock) ue      
       where ue.EnquiryId= gemr.EntityId)      
    else      
    0   
     End) LeadNo,      
 (Case      
       When gemr.GeoEntityType ='lead' Then (Select ud.PersonName from userLeads(nolock) ud      
       where ud.Id= gemr.EntityId)      
       When gemr.GeoEntityType ='enquiry' Then (Select ue.PersonName from UserEnquiry(nolock) ue      
     where ue.EnquiryId= gemr.EntityId) else ''      
     End) PersonName,      
 (Case      
       When gemr.GeoEntityType ='lead' Then (Select ud.ProfileImgFileName from userLeads(nolock) ud      
       where ud.Id= gemr.EntityId)      
       When gemr.GeoEntityType ='enquiry' Then (Select ue.ProfileImgFileName from UserEnquiry(nolock) ue      
       where ue.EnquiryId= gemr.EntityId)      
    else      
    ''      
    End) ImageName, @Parentid2 ParentId, isnull(bt.BreakTransactionId, 0) BreakTransactionId, isnull(bt.StartDate, null) BreakStartDate, isnull(bt.EndDate, null) BreakEndDate, (case when ((isnull(gecu.CheckIn, '') = '') and (isnull(gecrIn.ActionDateTime, '') = '')) then 'CheckInPending'       
 when isnull(gecu.CheckIn, '') != '' then 'CheckInNormal'      
 when ((gecrIn.ActionDateTime != '') and (isnull(gecrIn.ActionDateTime, '') = '')) then 'CheckInPending'      
 when ((gecrIn.ActionDateTime != '') and (geca.ApproverStatus = 'Rejected')) then 'CheckInRejected'      
 when ((gecrIn.ActionDateTime != '') and (geca.ApproverStatus = 'Approved')) then 'CheckInApproved'      
 else '' end) CheckInStatus,       
 (case when ((isnull(gecu.CheckOut, '') = '') and (isnull(gecrOut.ActionDateTime, '') = '')) then 'CheckOutPending'       
 when isnull(gecu.CheckIn, '') != '' then 'CheckOutNormal'      
 when ((gecrOut.ActionDateTime != '') and (isnull(gecrOut.ActionDateTime, '') = '')) then 'CheckOutPending'      
 when ((gecrOut.ActionDateTime != '') and (geca.ApproverStatus = 'Rejected')) then 'CheckOutRejected'      
 when ((gecrOut.ActionDateTime != '') and (geca.ApproverStatus = 'Approved')) then 'CheckOutApproved'      
 else '' end) CheckOutStatus, isnull(gecu.RemarksIn , '') RemarksIn, isnull(gecu.RemarksOut, '') RemarksOut, isnull(papt.Remarks, '') Remarks, papt.TaskTypeId TaskId    
 from TBL_ET_PhysicalAppointment(nolock) papt left join TBL_ET_GeoEntitySiteMaster(nolock) gesm 
 on papt.GeoEntitySiteId = gesm.GeoEntitySiteId left join TBL_ET_GeoEntityMaster(nolock) gemr 
 on gesm.GeoEntityId = gemr.GeoEntityId inner join TBL_ET_PhyAppointUserMapping(nolock) paum 
 on papt.PhysicalAppointmentId = paum.PhysicalAppointmentId left join User_Detail(nolock) ud 
 on papt.AssignedTo = ud.User_ID left join TBL_ET_GeoEntityCheckInOut (nolock) gecu 
 on papt.PhysicalAppointmentId = gecu.PhysicalAppointmentId left join TBL_ET_GeoEntityCheckInOutRequest(nolock) gecrIn 
 on papt.PhysicalAppointmentId = gecrIn.PhysicalAppointmentId and gecrIn.ActionType = 'CheckIn'      
	left join TBL_ET_GeoEntityCheckInOutRequest (nolock) gecrOut 
 on papt.PhysicalAppointmentId = gecrOut.PhysicalAppointmentId and gecrOut.ActionType = 'CheckOut'     
	left join TBL_ET_GeoEntityCheckInOutRequestApproval (nolock) geca 
 on gecrIn.GeoEntityChkInOutRequestId = gecrIn.GeoEntityChkInOutRequestId left join TBL_ET_GeoEntityCheckInOutRequestApproval (nolock) geca2 
 on gecrOut.GeoEntityChkInOutRequestId = geca2.GeoEntityChkInOutRequestId left join tbl_tsk_UserOutcomeMaster (nolock) oc 
 on papt.OutcomesId = oc.Id left join TBL_ET_BreakTransaction (nolock) bt 
 on paum.UserId = bt.CreatedBy and bt.StartDate between papt.StartDate and papt.EndDate      
 where paum.UserId = @UserId and ((cast(papt.StartDate as Date) between cast(@FromDate as Date) and cast(@ToDate as Date)) or (cast(papt.EndDate as Date) between cast(@FromDate as Date) and cast(@ToDate as Date)))      
 )tt      
      /*
 DECLARE @Query4 NVARCHAR(MAX) =       
 N'Select * from ( SELECT TaskHistoryId Id, ''VirtualApt'' APTType, Title, Description, StartDate, EndDate, Address, STATUS, '''' CheckIn, '''' CheckOut, '''' CheckInTime, '''' CheckOutTime,  '''' LatitudeIn, '''' LongitudeIn, '''' LatitudeOut, '''' LongitudeOut,  '''' Latitude, '''' Longitude, '''' Mobile, '''' EmailId, LeadId EntityId, ''lead'' GeoEntityType, RelatedTo OwnerName, 0 GeoEntitySiteId, RelatedToProfile SiteName, OutcomesId, OutcomeName Outcome, 0 LeadNo, Collaboraters PersonName, ImageName, ParentId, BreakTransactionId, isnull(BreakStartDate, null) BreakStartDate, isnull(BreakEndDate, null) BreakEndDate, CheckInStatus, CheckOutStatus, '''' RemarksIn, '''' RemarksOut, Remarks, TaskId FROM ( SELECT A.LeadId, A.Id as [TaskHistoryId], A.Title, A.Description, A.Address, A.StartDate, A.EndDate, A.STATUS, UL.PersonName as [RelatedTo], UL.ProfileImgFileName AS [RelatedToProfile], dbo.udf_mk_GetTaskCreatorName(A.CreatedBy) AS [CreatorName], A.ParentID, A.AssignedTo, A.CreatedBy, 0 AS [UserId], A.IsTask, A.IsAppointment, A.OutcomesId, A.IsActive, A.CompletedOn, A.TaskId, dbo.udf_mk_GetTotalAttachment(A.Id) AS [TotalAttachments],  A.Remarks, A.CreatedOn, A.UpdatedOn, dbo.udf_tsk_GetCollaboratersNames(A.Id) AS [Collaboraters], dbo.udf_mk_GetTaskCreatorName(A.AssignedTo) AS [OwnerName], UOM.OutcomeName, UL.ProfileImgFileName ImageName, 0 BreakTransactionId, null BreakStartDate, null BreakEndDate, '''' CheckInStatus, '''' CheckOutStatus, '''' RemarksIn, '''' RemarksOut     
  FROM ( SELECT TH.LeadId, TH.Id, TH.Title, TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.STATUS, UD.ParentID, TH.AssignedTo, TH.CreatedBy, 0 AS [UserId], TH.IsTask, TH.IsAppointment, TH.OutcomesId, TH.IsActive, TH.CompletedOn, TH.TaskId, TH.Remarks, TH.CreatedOn, TH.UpdatedOn 
  FROM tbl_tsk_TaskHistory(NOLOCK) TH INNER JOIN UserLeads(NOLOCK) UL 
  ON TH.LeadId = UL.ID AND th.taskid <> 4 LEFT JOIN User_Detail(NOLOCK) UD 
