  WHERE UD.User_Id =' + cast(@UserId AS VARCHAR) + ' AND IsActive = 1 AND TH.IsAppointment = ''1''       
    UNION '      
      
 DECLARE @Query5 NVARCHAR(max) = N' SELECT TH.LeadId, TH.Id, TH.Title, TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.STATUS, UD.ParentID, TH.AssignedTo, TH.CreatedBy,0 AS [UserId], TH.IsTask, TH.IsAppointment, TH.OutcomesId, TH.IsActive, TH.CompletedOn, TH.TaskId, TH.Remarks, TH.CreatedOn, TH.UpdatedOn 
 FROM tbl_tsk_TaskHistory(NOLOCK) TH INNER JOIN UserLeads(NOLOCK) UL 
 ON TH.LeadId = UL.ID AND th.taskid <> 4 LEFT JOIN User_Detail(NOLOCK) UD 
 ON TH.AssignedTo = UD.User_ID OR UL.ParentID = UD.User_ID LEFT JOIN tbl_tsk_UserTaskMaster(NOLOCK) UTM 
 ON TH.TaskId = UTM.Id WHERE UD.User_Id =' + cast(@UserId AS VARCHAR) + ' AND IsActive = 1 AND TH.IsAppointment = ''1''
   UNION 
   SELECT TH.LeadId, TH.Id, TH.Title,  TH.Description, TH.Address, TH.StartDate, TH.EndDate, TH.STATUS, UD.ParentID, TH.AssignedTo, TH.CreatedBy, 0 AS [UserId], TH.IsTask,  TH.IsAppointment,  TH.OutcomesId, TH.IsActive, TH.CompletedOn, TH.TaskId, TH.Remarks, TH.CreatedOn, TH.UpdatedOn 
	FROM tbl_tsk_TaskHistory(NOLOCK) TH JOIN User_Detail(NOLOCK) UD 
