select Id, APTType, Title, Description, StartDate, EndDate, Address, Status, CheckIn, CheckOut, cast(CheckInTime as varchar(5)) CheckInTime, cast(CheckOutTime as varchar(5)) CheckOutTime, LatitudeIn, LongitudeIn, LatitudeOut, LongitudeOut, Latitude, Longitude, Mobile, EmailId, EntityId, GeoEntityType, OwnerName, GeoEntitySiteId, SiteName, OutcomesId, Outcome, LeadNo, PersonName, ImageName, ParentId, BreakTransactionId, BreakStartDate, BreakEndDate, CheckInStatus, CheckOutStatus, RemarksIn, RemarksOut, Remarks, TaskId 
from #Appointmentlist2 
order by StartDate Asc      
      
 --Declare @IsSignOutStatus2 bit = 0      
 --Declare @AttendanceOut2 DateTime = null      
      
 --Select top 1 @IsSignOutStatus2 = (case when isnull(AttendanceOut, '') = '' then 0 else 1 end), @AttendanceOut2 = AttendanceOut        
 -- from TBL_ET_Attendance atdn (nolock) where UserId = @UserId and Cast(AttendanceIn as Date) = Cast(@FromDate as Date) and IsActive = 1        
 -- order by AttendanceId desc      
      
-- Select @IsSignOutStatus2 IsSignOutStatus, @AttendanceOut2 AttendanceOut      
    
      
 End      
END TRY      
      
BEGIN CATCH      
 DECLARE @ErrorMessage NVARCHAR(4000);      
 SELECT @ErrorMessage = ERROR_MESSAGE();      
 RAISERROR (      
   @ErrorMessage      
   ,16      
   ,1      
   );      
END CATCH     



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_DailySchedueViewByUserId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec usp_TBL_ET_DailySchedueViewByUserId @SearchText=N'',@UserId=34594,@FromDate=N'2023-03-01',@ToDate=N'2023-03-31',@OffsetValue=0,@PagingSize=100,@Contain=N''
--exec usp_TBL_ET_DailySchedueViewByUserId @SearchText=N'',@UserId=32222,@FromDate=N'2023-06-09',@ToDate=N'2023-06-09',@OffsetValue=0,@PagingSize=100,@Contain=N''
--exec usp_TBL_ET_DailySchedueViewByUserId @SearchText=N'',@UserId=27053,@FromDate=N'2023-05-12',@ToDate=N'2023-05-12',@OffsetValue=0,@PagingSize=100,@Contain=N''
-- exec usp_TBL_ET_DailySchedueViewByUserId @SearchText=N'',@UserId=34594,@FromDate=N'2023-03-10',@ToDate=N'2023-03-10',@OffsetValue=0,@PagingSize=100,@Contain=N''

CREATE   PROCEDURE [dbo].[usp_TBL_ET_DailySchedueViewByUserId] 
(  
 @SearchText nvarchar(200) = '',  
 @UserId bigint,  
 @UserIds nvarchar(max),  
 @FromDate varchar(10),  
 @ToDate varchar(10),  
 @OffsetValue int = 0,  
 @PagingSize int = 100,  
 @Contain nvarchar(500) = ''  
)  
AS  
SET NOCOUNT ON  
  
BEGIN TRY  
 Begin  
 if(@Contain is null)  
 Begin  
	set @Contain = '';  
 End  
 else if(@Contain != '')  
 Begin  
	set @Contain = ' and OnDuty =''' + @Contain + '''';  
 End  
  -- declare @SearchText nvarchar(200) = '',@UserId bigint=36305,@FromDate varchar(10)='2023-06-15',@ToDate varchar(10)='2023-06-15',@OffsetValue int=0,@PagingSize int=100,@Contain nvarchar(500) = ''  

  Declare @UserIdTeamLst nvarchar(Max) = ''         
  Declare @UserLoginTeamLst nvarchar(Max) = ''         
  
--select @UserIdTeamLst = UserIdTeamLst, @UserLoginTeamLst = UserLoginTeamLst from dbo.ufn_GetUserRoleScope(@UserId)   
  
	drop table if exists #tempUsers  
	create table #tempUsers(User_ID bigint, Name nvarchar(255), Image nvarchar(255))  
	insert into #tempUsers(User_ID, Name, Image)  
	exec Use_GetUserDetails @UserID = @UserId  

	if(ISNULL(@UserIds, '') =  '') begin set @UserIds = '' end

	drop table if exists #tempSelectedUser
	create table #tempSelectedUser ( UserId bigint )
	insert into #tempSelectedUser(UserId) select [value] from string_split(@UserIds, ',') where [value] > 0

 Declare @Query nvarchar(max) =   
 concat( N' select * from (  
  select coalesce(ud.User_ID,ud1.User_Id,0) as User_ID, coalesce(ud.ParentID,atte.ParentId,0) as ParentID, coalesce(ud.FName,ud1.FName,'''') +'' ''+ coalesce(ud.LName,ud1.LName,'''') +  '' (''+ coalesce(ud.User_Login,ud1.User_Login,'''') +'')'' as UserName, coalesce(ud.Mobile,ud1.Mobile,'''') as Mobile, coalesce(ud.Email,ud1.Email,'''') as Email, coalesce(ud.ProfilePictureName,ud1.ProfilePictureName,'''') as ProfilePictureName, FORMAT(isnull(atte.AttendanceIn, ultr.LocationDateTime),''dd-MMM-yyyy HH:mm:ss'') AttendanceIn, FORMAT(isnull(atte.AttendanceOut,ultrd.LocationDateTime),''dd-MMM-yyyy HH:mm:ss'') AttendanceOut, 0 Pending, 0 Completed, ''No Current Task'' CurrentTask, (case when ((atte.AttendanceIn != '''') and (atte.AttendanceOut is null)) then ''On Duty'' when ((atte.AttendanceIn != '''') and (atte.AttendanceOut != '''')) then ''Off Duty'' else ''Unreachable'' End) OnDuty, CONVERT(varchar(8), DATEADD(ss, DATEDIFF(ss, isnull(atte.AttendanceIn, ultr.LocationDateTime), isnull(atte.AttendanceOut,ultrd.LocationDateTime)), 0), 114) as WorkingTime, coalesce(ultrd.Distance,CAST(dbo.fnCalcDistanceKM(ultr.Latitude, atte.LatitudeIn, ultr.Longitude, atte.LongitudeIn) AS DECIMAL(15, 2)),0) as Travel, isnull(ultr.Sno,0) as Sno, isnull(ultr.UserLocationTrackingId,0) as UserLocationTrackingId, isnull(ultr.MovementCode,''SIGN_IN'') as MovementCode, ultr.Remarks, ultr.UserId, ultr.LocationDateTime, isnull(ultr.Latitude,atte.LatitudeIn) as Latitude, isnull(ultr.Longitude,atte.LongitudeIn) as Longitude, ultr.Address, ultr.BatteryPerc, ultr.NetworkPerc, ultr.CreatedDate, ultr.CreatedBy, ultr.IsActive, ultr.IsMock, ultr.IsBulk, (select count(*) from User_Detail(nolock) where ParentId = coalesce(ud.ParentID,atte.ParentId,0) and Status=1) TotalUsers, COUNT(*)over() TotalRecords 
  from V_TBL_ET_UserLocationTracking(nolock) ultr ' ,
  N' inner join #tempUsers tu on ultr.UserId = tu.User_ID ',
	iif(LEN(@UserIds) > 0, 'inner join #tempSelectedUser su on ultr.UserId = su.UserId ', '') ,
  N'inner join User_Detail (nolock) ud 
  on ultr.UserId = ud.User_ID and ud.Status = 1 inner join V_TBL_ET_UserLocationTrackingDesc(nolock) ultrd
  on ultr.UserId=ultrd.UserId and cast(ultr.LocationDateTime as date) = cast(ultrd.LocationDateTime as date) full outer join V_TBL_ET_Attendance(nolock) atte 
  on ud.User_ID = atte.UserId and ud.Status = 1 and CAST(ultr.LocationDateTime as Date)=isnull(CAST(atte.AttendanceIn as Date),CAST(atte.AttendanceOut as Date)) left join User_Detail(nolock) ud1 
  on atte.UserId=ud1.User_ID
  where (ultr.UserId in (select item from dbo.fu_SplitString(''' + cast(@UserIdTeamLst as varchar(4000)) + ''', '','')) or atte.UserId in (select item from dbo.fu_SplitString(''' + cast(@UserIdTeamLst as varchar(4000)) + ''', '','')) )
  and (coalesce(ud.FName,ud1.FName,'''') like''%'+ @SearchText + '%'' or coalesce(ud.LName,ud1.LName,'''') like''%'+ @SearchText + '%'' and coalesce(ud.User_Login,ud1.User_Login,'''') like''%'+ @SearchText + '%''   
  and coalesce(ud.Mobile,ud1.Mobile,'''') like''%'+ @SearchText + '%'')   
  and (cast(ultr.LocationDateTime as date) between Cast('''+ cast(@FromDate as varchar(10)) +''' as date) and Cast('''+ cast(@ToDate as varchar(10)) +''' as date)  
  or (cast(atte.AttendanceIn as date) between Cast('''+ cast(@FromDate as varchar(10)) +''' as date) and Cast('''+ cast(@ToDate as varchar(10)) +''' as date)) or (cast(atte.AttendanceOut as date) between Cast('''+ cast(@FromDate as varchar(10)) +''' as date) and Cast('''+ cast(@ToDate as varchar(10)) +''' as date)))  
  )t  
  where (1=1) ' + @Contain + '  
  Order By t.LocationDateTime Desc   
  Offset ' + cast(@OffsetValue as varchar(10)) + ' rows fetch next  ' + cast(@PagingSize as varchar(10)) + ' rows only '  )
  
 print @query      
    
 execute sp_executesql @query      
  
 End  
END TRY  
  
BEGIN CATCH  
 DECLARE @ErrorMessage NVARCHAR(4000);  
 SELECT @ErrorMessage = ERROR_MESSAGE();  
 RAISERROR (  
   @ErrorMessage  
   ,16  
   ,1  
   );  
END CATCH  



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_DailySchedueViewByUserIdNew]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_TBL_ET_DailySchedueViewByUserIdNew](  
 @SearchText nvarchar(200),   
 @Contain nvarchar(500),  
 @UserId bigint,  
 @UserIds nvarchar(max) = '',  
 @FromDate date,    
 @ToDate date,    
 @OffsetValue int = 0,    
 @PagingSize int = 100  
)  
as   
begin  
  
 --declare  
 -- @SearchText nvarchar(200) = N'',   
 -- @Contain nvarchar(500) = N'',  
 -- @UserId bigint = 52616,  
 -- @UserIds nvarchar(max) = N'52616',  
 -- @FromDate date = N'18-May-2026',    
 -- @ToDate date = N'18-May-2026',    
 -- @OffsetValue int = 0,    
 -- @PagingSize int = 100  

  --select  @SearchText=N'',@UserId=47082,@UserIds='',@FromDate=N'27-May-2025',@ToDate=N'27-May-2025',@OffsetValue=0,@PagingSize=0,@Contain=N''
  
 DECLARE @ParentId BIGINT, @isAdmin BIT = 0;  
  
 -- Get parent ID and admin status  
 SELECT @ParentId = ParentId, @isAdmin = IsAdmin   
 FROM User_Detail (NOLOCK)   
 WHERE User_Id = @UserId;  
  
 -- Set UserIds to empty string if NULL  
 IF (ISNULL(@UserIds, '') = '')   
  SET @UserIds = '';  
  
 -- Temporary tables  
 DROP TABLE IF EXISTS #tempUsers;  
 CREATE TABLE #tempUsers (User_ID BIGINT, Name NVARCHAR(255), Image NVARCHAR(255));  
 INSERT INTO #tempUsers (User_ID, Name, Image)  
 EXEC Use_GetUserDetails @UserID = @UserId;  
  
 DROP TABLE IF EXISTS #tempSelectedUser;  
 CREATE TABLE #tempSelectedUser (UserId BIGINT);  
 INSERT INTO #tempSelectedUser (UserId)  
 SELECT [value] FROM STRING_SPLIT(@UserIds, ',') where [value] > 0;  
  
 -- Precompute values for LocationInfos  
 DROP TABLE IF EXISTS #tempUserLocations;  
 CREATE TABLE #tempUserLocations (  
  UserId BIGINT,  
  LastPunchedAt DATETIME,  
  LocationInfos NVARCHAR(MAX)  
 );  
  
 declare @selectUserCount int = 0  
 select @selectUserCount = count(1) from #tempSelectedUser  
  
  print concat('@selectUserCount => ', @selectUserCount)
  
 -- Logic from the UDF integrated  
 INSERT INTO #tempUserLocations (UserId, LastPunchedAt, LocationInfos)  
 SELECT   
  ud.User_ID,  
  COALESCE(lk.LocationDateTime, att.AttendanceIn) AS LastPunchedAt,  
  CASE   
   WHEN ISNULL(COALESCE(lk.LocationDateTime, att.AttendanceIn), '1900-01-01 00:00:00.000') = '1900-01-01 00:00:00.000'   
   THEN '{}'   
   ELSE   
    (SELECT   
     CASE WHEN CAST(lk.LocationDateTime AS DATE) <= CAST(DATEADD(DAY, -30, GETDATE()) AS DATE)  
     THEN   
      (SELECT TOP 1   
       isnull(LocationDateTime, '') as [LocationDateTime],      
       isnull(MovementCode, '') as [MovementCode],       
       CAST(CAST(isnull(BatteryPerc, '0') AS DECIMAL(18,2)) AS INT) as [BatteryPerc],       
       CAST(CAST(isnull(NetworkPerc, '0') AS DECIMAL(18,2)) AS INT) as[NetworkPerc],    
       CAST(CAST(isnull(Speed, '0') AS DECIMAL(18,2)) AS INT) as [Speed],  
       ROUND(TRY_CONVERT(decimal(18,3), isnull(  
        (SELECT MAX(cast(Distance as float))   
         FROM TBL_ET_UserLocationTracking(NOLOCK) iu   
         WHERE iu.UserId = ud.User_ID AND cast(iu.LocationDateTime as date) = cast( lk.LocationDateTime as date)  
        ), 0)) / 1000, 3) as [Distance],    
       isnull(Address, '') as [Address]    
      FROM TBL_ET_UserLocationTracking_Archived(NOLOCK)   
       WHERE UserId = ud.User_ID AND cast(LocationDateTime as date) = cast(lk.LocationDateTime as date)  
      ORDER BY LocationDateTime DESC   
      FOR JSON AUTO, INCLUDE_NULL_VALUES, WITHOUT_ARRAY_WRAPPER)  
     ELSE   
      (SELECT TOP 1   
       isnull(LocationDateTime, '') as [LocationDateTime],      
       isnull(MovementCode, '') as [MovementCode],       
       CAST(CAST(isnull(BatteryPerc, '0') AS DECIMAL(18,2)) AS INT) as [BatteryPerc],       
       CAST(CAST(isnull(NetworkPerc, '0') AS DECIMAL(18,2)) AS INT) as[NetworkPerc],    
       CAST(CAST(isnull(Speed, '0') AS DECIMAL(18,2)) AS INT) as [Speed],  
       ROUND(TRY_CONVERT(decimal(18,3), isnull(  
        (SELECT MAX(cast(Distance as float))   
         FROM TBL_ET_UserLocationTracking(NOLOCK) iu   
         WHERE iu.UserId = ud.User_ID AND cast(iu.LocationDateTime as date) = cast(lk.LocationDateTime as date)  
        ), 0)) / 1000, 3) as [Distance],    
       isnull(Address, '') as [Address]    
      FROM TBL_ET_UserLocationTracking(NOLOCK)   
       WHERE UserId = ud.User_ID AND cast(LocationDateTime as date) = cast(lk.LocationDateTime as date)  
      ORDER BY LocationDateTime DESC   
      FOR JSON AUTO, INCLUDE_NULL_VALUES, WITHOUT_ARRAY_WRAPPER)  
     END  
    )  
  END AS LocationInfos  
 FROM User_Detail (NOLOCK) ud  
 INNER JOIN #tempUsers tu ON ud.User_ID = tu.User_ID  
 LEFT JOIN #tempSelectedUser su ON ud.User_Id = su.UserId  
 LEFT JOIN (  
  SELECT * FROM (  
   SELECT   
    a.UserId,   
    AttendanceIn,   
    ROW_NUMBER() OVER (PARTITION BY a.UserId ORDER BY AttendanceId DESC) AS sno  
   FROM TBL_ET_Attendance (NOLOCK) a  
   INNER JOIN #tempUsers ti ON a.UserId = ti.User_ID  
   LEFT JOIN #tempSelectedUser su ON ti.User_ID = su.UserId  
   WHERE CAST(AttendanceIn AS DATE) <= @FromDate  
  ) l WHERE l.sno = 1  
 ) att ON ud.User_Id = att.UserId  
 LEFT JOIN (  
  SELECT * FROM (  
   SELECT   
    ult.UserId,   
    LocationDateTime,  
    ROW_NUMBER() OVER (PARTITION BY ult.UserId ORDER BY CAST(LocationDateTime AS DATETIME) DESC) AS sno  
   FROM TBL_ET_UserLocationTracking (NOLOCK) ult  
   INNER JOIN #tempUsers ti ON ult.UserId = ti.User_ID  
   LEFT JOIN #tempSelectedUser su ON ti.User_ID = su.UserId  
   WHERE CAST(LocationDateTime AS DATE) <= @FromDate  
  ) l WHERE l.sno = 1  
 ) lk ON att.UserId = lk.UserId AND CAST(lk.LocationDateTime AS DATE) = CAST(att.AttendanceIn AS DATE)  
 WHERE ud.ParentID = @ParentId AND att.UserId IS NOT NULL;  
  
 -- Precompute values for udf_et_GetAgentWorkHours  
 DROP TABLE IF EXISTS #tempWorkHours;  
 CREATE TABLE #tempWorkHours (  
  UserId BIGINT,  
  WorkHours NVARCHAR(MAX)  
 );  
  
 INSERT INTO #tempWorkHours (UserId, WorkHours)  
 SELECT   
  ud.User_ID,  
  dbo.udf_et_GetAgentWorkHours(ud.User_ID, CAST(COALESCE(lk.LocationDateTime, att.AttendanceIn) AS DATE))  
 FROM User_Detail (NOLOCK) ud  
 INNER JOIN #tempUsers tu ON ud.User_ID = tu.User_ID  
 LEFT JOIN #tempSelectedUser su ON ud.User_Id = su.UserId  
 LEFT JOIN (  
  SELECT * FROM (  
   SELECT   
    a.UserId,   
    AttendanceIn,   
    ROW_NUMBER() OVER (PARTITION BY a.UserId ORDER BY AttendanceId DESC) AS sno  
   FROM TBL_ET_Attendance (NOLOCK) a  
   INNER JOIN #tempUsers ti ON a.UserId = ti.User_ID  
   LEFT JOIN #tempSelectedUser su ON ti.User_ID = su.UserId  
   WHERE CAST(AttendanceIn AS DATE) <= @FromDate  
  ) l WHERE l.sno = 1  
 ) att ON ud.User_Id = att.UserId  
 LEFT JOIN (  
  SELECT * FROM (  
   SELECT   
    ult.UserId,   
    LocationDateTime,  
    ROW_NUMBER() OVER (PARTITION BY ult.UserId ORDER BY CAST(LocationDateTime AS DATETIME) DESC) AS sno  
   FROM TBL_ET_UserLocationTracking (NOLOCK) ult  
   INNER JOIN #tempUsers ti ON ult.UserId = ti.User_ID  
   LEFT JOIN #tempSelectedUser su ON ti.User_ID = su.UserId  
   WHERE CAST(LocationDateTime AS DATE) <= @FromDate  
  ) l WHERE l.sno = 1  
 ) lk ON att.UserId = lk.UserId AND CAST(lk.LocationDateTime AS DATE) = CAST(att.AttendanceIn AS DATE)  
 WHERE ud.ParentID = @ParentId AND att.UserId IS NOT NULL;  
  
  
 -- Main query  
 SELECT   
  COUNT(1) OVER (ORDER BY ud.ParentID) AS [TotalAgent],   
  SUM(CASE WHEN ud.AgentStatus = 'InActive' THEN 1 ELSE 0 END) OVER (ORDER BY ud.ParentID) AS [InActiveCount],   
  SUM(CASE WHEN ud.AgentStatus = 'Active' THEN 1 ELSE 0 END) OVER (ORDER BY ud.ParentID) AS [ActiveCount],   
  ud.AgentId,   
  ud.AgentLogin,   
  ud.AgentFirstName,   
  ud.AgentLastName,   
  ud.AgentMobileNo,   
  ud.AgentEmail,   
  ud.AgentImage,   
  ud.AgentDisplayName,   
  FORMAT(ud.LastPunchedAt, 'dd-MMM-yyyy HH:mm') AS [LastPunchedAt],   
  ud.AgentStatus,   
  ud.Latitude,   
  ud.Longitude,   
  isnull(ul.LocationInfos, ( select * from (select     
    CAST(@FromDate AS DATE) as [LocationDateTime],        
    '' as [MovementCode],         
    0 as [BatteryPerc],         
    0 as[NetworkPerc],      
    0 as [Speed],      
    0 as [Distance],      
    '' as [Address] ) p for json auto, include_null_values, without_array_wrapper   
   )) as [LocationInfos],   
  ISNULL(Phy.TotalPhy, 0) AS [TotalPhy],   
  ISNULL(Phy.PhyCompleted, 0) AS [PhyCompleted],   
  wh.WorkHours,   
  IIF(CAST(@FromDate AS DATE) = CAST(ud.LastPunchedAt AS DATE), '1', '0') AS [IsActive]  
 FROM (  
  SELECT   
   ud.ParentID AS [ParentId],  
   ud.User_Id AS AgentId,  
   ud.FName AS [AgentFirstName],  
   ud.LName AS [AgentLastName],  
   ud.Mobile AS [AgentMobileNo],  
   ud.Email AS [AgentEmail],  
   ud.ProfilePictureName AS [AgentImage],  
   CONCAT(ud.User_Login, '(', ud.FName, ' ', ud.LName, ')') AS [AgentDisplayName],  
   ud.User_Login AS AgentLogin,  
   COALESCE(lk.LocationDateTime, att.AttendanceIn) AS [LastPunchedAt],  
   CASE   
    WHEN ISNULL(COALESCE(lk.LocationDateTime, att.AttendanceIn), '') = '' THEN 'InActive'  
    WHEN CAST(COALESCE(lk.LocationDateTime, att.AttendanceIn) AS DATE) <> @FromDate THEN 'InActive'  
    ELSE 'Active'  
   END AS [AgentStatus],  
   COALESCE(lk.Latitude, att.LatitudeIn) AS [Latitude],  
   COALESCE(lk.Longitude, att.LongitudeIn) AS [Longitude]  
  FROM User_Detail (NOLOCK) ud  
  INNER JOIN #tempUsers tu ON ud.User_ID = tu.User_ID  
  LEFT JOIN #tempSelectedUser su ON ud.User_Id = su.UserId  
  LEFT JOIN (  
   SELECT * FROM (  
    SELECT   
     a.UserId,   
     AttendanceIn,   
     LatitudeIn,   
     LongitudeIn,   
     ROW_NUMBER() OVER (PARTITION BY a.UserId ORDER BY AttendanceId DESC) AS sno  
    FROM TBL_ET_Attendance (NOLOCK) a  
    INNER JOIN #tempUsers ti ON a.UserId = ti.User_ID  
    LEFT JOIN #tempSelectedUser su ON ti.User_ID = su.UserId  
    WHERE CAST(AttendanceIn AS DATE) <= @FromDate  
   ) l WHERE l.sno = 1  
  ) att ON ud.User_Id = att.UserId  
  LEFT JOIN (  
   SELECT * FROM (  
    SELECT   
     ult.UserId,   
     LocationDateTime,  
     Latitude,  
     Longitude,  
     ROW_NUMBER() OVER (PARTITION BY ult.UserId ORDER BY CAST(LocationDateTime AS DATETIME) DESC) AS sno  
    FROM TBL_ET_UserLocationTracking (NOLOCK) ult  
    INNER JOIN #tempUsers ti ON ult.UserId = ti.User_ID  
    LEFT JOIN #tempSelectedUser su ON ti.User_ID = su.UserId  
    WHERE CAST(LocationDateTime AS DATE) <= @FromDate  
   ) l WHERE l.sno = 1  
  ) lk ON att.UserId = lk.UserId AND CAST(lk.LocationDateTime AS DATE) = CAST(att.AttendanceIn AS DATE)  
  WHERE ud.ParentID = @ParentId AND att.UserId IS NOT NULL  
 ) ud  
 LEFT JOIN #tempUserLocations ul ON ud.AgentId = ul.UserId AND CAST(ud.LastPunchedAt AS DATE) = CAST(ul.LastPunchedAt AS DATE)  
 LEFT JOIN #tempWorkHours wh ON ud.AgentId = wh.UserId  
 LEFT JOIN V_PhysicalAppointmentCount phy ON ud.AgentId = phy.UserId AND CAST(ud.LastPunchedAt AS DATE) = phy.PhyDate  
  
 WHERE 1 = (case   
  when isnull(@selectUserCount, 0) = 0 then 1  
  when isnull(@selectUserCount, 0) > 0 and   
   exists(select 1 from #tempSelectedUser where UserId = ud.AgentId) then 1   
  else 0 end)   
 ORDER BY   
  CASE   
   WHEN ud.AgentStatus = 'Active' THEN 1  
   WHEN ud.AgentStatus = 'InActive' THEN 2  
   ELSE 3  
  END ASC,   
  CAST(ud.LastPunchedAt AS DATETIME) DESC;  
end  


GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_DashboardLocationList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_TBL_ET_DashboardLocationList]
(
	@Mode VARCHAR(2),
	@SearchText varchar(200) = '',
	@Contain varchar(200) = '',
	@FromDate nvarchar(100) = '',
	@ToDate nvarchar(100) = '',
	@UserId bigint = 0,
	@UserIds nvarchar(max) = '',
	@Offset int = 0,
	@PageSize int = 10 
)
AS
BEGIN TRY 

	--declare 
	--	@Mode VARCHAR(2) = N'LS',
	--	@SearchText varchar(200) = '',
	--	@Contain varchar(200) = '',
	--	@FromDate nvarchar(100) = N'05-Nov-2024',
	--	@ToDate nvarchar(100) = N'11-Nov-2024',
	--	@UserId bigint = 43966,
	--	@UserIds nvarchar(max) = '',
	--	@Offset int = 0,
	--	@PageSize int = 10

	declare @ParentId bigint , @IsAdmin bit, @StartPoint int  = 1, @Endpoint int = 100
	
	select @IsAdmin = IsAdmin, @ParentId = ParentId from User_Detail(NOLOCK) where User_ID = @UserId  
	select @StartPoint = (@Offset + 1), @Endpoint = (@PageSize + @Offset)



	drop table if exists #userTable
	create table #userTable( User_ID bigint,Name nvarchar(100), Image nvarchar(100) )

	if(@Mode = 'LS')
	begin
		
		declare @sqlQuery nvarchar(max)
		
		declare @UserIdTeamLst varchar(500) = ''     
		declare @tbluser table (User_ID bigint,Name varchar(100), Image varchar(100))
		if(@IsAdmin = 1)
		begin
			set @UserId = 0;
			insert into #userTable
			exec Use_GetUserDetails @ParentId
		end
		else
		begin
			insert into #userTable
			exec Use_GetUserDetails @UserId
		end

		if(@SearchText = '') begin set @SearchText = '' end
		if(@Contain = '') begin set @Contain = '' end else begin set @Contain =  ' and ' + @Contain end


		if(ISNULL(@UserIds, '') =  '') begin set @UserIds = '' end

		drop table if exists #tempSelectedUser
		create table #tempSelectedUser ( UserId bigint )
		insert into #tempSelectedUser(UserId) select [value] from string_split(@UserIds, ',')

		set @sqlQuery = concat( N'select TOP 10 p.SNo, p.TotalRecords, ',
			  N'concat( p.FName, '' '', p.LName, '' ('', p.User_Login, '')'' ) AssignedToName, ',
			  N'p.User_Login,  isnull(p.FName,'''') + '' '' + isnull(p.LName,'''')  as [UserFullName] ,',
			  N'( dbo.udf_GetTerritoryDefination(p.AssignedTo) ) AS [TerritoryDefination], ',
			  N'p.User_Id, p.PhysicalAppointmentId, p.Title, p.Description, p.Address, p.CompleteAddress, ',
			  N'format( p.StartDate, ''dd-MMM-yyyy HH:mm'' ) as [StartDate], ',
			  N'format( p.EndDate, ''dd-MMM-yyyy HH:mm'' ) as [EndDate], ',
			  N'isnull(p.OutcomesId, 0) OutcomesId, isnull(uom.OutcomeName, '''') as [OutcomeName], ',
			  N'isnull(uom.Indent, '''') as [OutcomeIntent], isnull(p.Status, '''') PhyStatus, ',
			  N'p.Image, p.ProfilePictureName, p.Remarks as [PhyRemarks], ',
			  N'coalesce( tege.GeoEntityName, tegs.GeoEntitySiteName ) as [GeoEntitySiteName], ',
			  N'tegs.GeoEntitySiteId as [GeoEntitySiteId], tegs.Latitude as [SiteLatitude], ',
			  N'tegs.Longitude as [SiteLongitude],  tegs.MapAddress as [SiteMapAddress], ',
			  N'tegs.Address as [SiteAddress],  tegs.City as [SiteCity], ',
			  N'tegs.State as [SiteState],  tegs.Country as [SiteCountry], ',
			  N'tege.Mobile as [MobileNo], ',
			  N'tege.EmailId as [EmailId], ',
			  N'tegs.PinCode as [SitePinCode],  tege.GeoEntityType as [SiteGeoEntityType], ',
			  N'dbo.fn_TBL_ET_PhysicalCollebratorUM_PhyId( p.PhysicalAppointmentId, ''Collaborator'' ) Collaboratorlist, ',
			  N'dbo.fn_TBL_ET_PhysicalCollebratorUM_PhyId( p.PhysicalAppointmentId, ''FieldExecutive'' ) FieldExecutivelist, ',
			  N'FORMAT( cast( ( case when p.CheckIn != '''' then p.CheckIn else p.CheckOut end ) as datetime ),  ''dd-MM-yyyy'' ) TravelDate, ',
			  N'format( p.CheckIn, ''dd-MMM-yyyy HH:mm'' ) as [CheckIn], ',
			  N'format( p.CheckOut, ''dd-MMM-yyyy HH:mm'' ) as [CheckOut], ',
			  N'tege.EntityId as [SiteGeoEntityId], ',
			  N'case when '+cast(@pagesize as nvarchar)+' > 10 then ''{}'' else isnull( dbo.udf_et_GetPhyAppointmentTravelData( p.AssignedTo, ',
			  N'( case when p.CheckIn != '''' then p.CheckIn else p.CheckOut end ), p.PhysicalAppointmentId ), ''{}'' ) end as [TravelData], ',
			  N'( case when isnull(p.CheckIn, '''') = '''' or '+cast(@pagesize as nvarchar)+' > 10 then ''{}'' ',
			  N'else dbo.udf_GetClosestUserLocation( p.AssignedTo, cast(p.CheckIn as datetime) ) end ) as [LocationInfo], ',
			  N'isnull(tege.GeoEntityType, '''') EntityType ',
			N'from ( select t.SNo, t.TotalRecords, ',
				N't.GeoEntitySiteId, t.CheckIn, t.CheckOut, t.Address, t.AssignedTo, t.CompleteAddress, ',
				N't.Description, t.EndDate, t.OutcomesId, t.PhysicalAppointmentId, t.Remarks, t.StartDate, ',
				N't.Status, t.Title, t.FName, t.Image, t.LName, t.ProfilePictureName, t.User_Id, t.User_Login ',
			N'from ( select ',
					N'row_number() over(partition by ud.ParentId order by tepa.PhysicalAppointmentId desc) as SNo, ',
					N'count(tepa.AssignedTo) over() as TotalRecords, ',
					N'geci.CheckIn, geci.CheckOut, tepa.GeoEntitySiteId, tepa.Address, tepa.AssignedTo, tepa.CompleteAddress, tepa.Description, ',
					N'tepa.EndDate, tepa.OutcomesId, tepa.PhysicalAppointmentId, tepa.Remarks, tepa.StartDate, tepa.Status, tepa.Title, ud.FName, ud.Image, ',
					N'ud.LName, ud.ProfilePictureName, ud.User_Id, ud.User_Login ',
			N'from TBL_ET_PhysicalAppointment(nolock) tepa ',
				N'inner join #userTable tu on tepa.AssignedTo = tu.User_Id ',
				iif(LEN(@UserIds) > 0, 'inner join #tempSelectedUser  su on tepa.AssignedTo = su.UserId ', ''),
				N'inner join TBL_ET_GeoEntityCheckInOut(nolock) geci on tepa.PhysicalAppointmentId = geci.PhysicalAppointmentId ',
				N'inner join User_Detail(nolock) ud on tepa.AssignedTo = ud.User_ID ',
			N'where ( ( cast(geci.CheckIn as date) between cast(''',@FromDate, ''' as date) and cast(''', @ToDate,''' as date)) ',
				N'or ( cast(geci.CheckOut as date) between cast(''',@FromDate, ''' as date) and cast(''', @ToDate,''' as date)) ',
				N')  and (  ud.User_Login like ''%', @SearchText, '%'' ',
				N'or ud.FName like ''%', @SearchText, '%'' or ud.LName like ''%', @SearchText, '%'' or tepa.Title like ''%', @SearchText, '%'' ',
			N')) t where t.SNo between ', @StartPoint, ' and ', @Endpoint, ' ) p ',
			N'left join TBL_ET_GeoEntitySiteMaster(nolock) tegs on p.GeoEntitySiteId = tegs.GeoEntitySiteId ',
			N'left join TBL_ET_GeoEntityMaster(nolock) tege on tegs.GeoEntityId = tege.GeoEntityId ',
			N'left join tbl_tsk_UserOutcomeMaster(nolock) uom on p.OutcomesId = uom.Id ',
			N'order by p.SNo asc ')

		print @sqlQuery

		execute sp_executesql @sqlQuery



	end
END TRY  
BEGIN CATCH  
	exec usp_InsertErrorInfo
END CATCH 





GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_ExpenseApprovalList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE  [dbo].[usp_TBL_ET_ExpenseApprovalList] (
	@Mode VARCHAR(2)
	,@ExpenseApprovalId bigint = 0
	,@SearchText varchar(100) = ''
	,@FromDate datetime = null
	,@ToDate datetime = null
	,@CreatedBy	bigint = 0
	,@Offset int = 0
	,@PageSize int = 0
)
AS
SET NOCOUNT ON

BEGIN TRY
Declare @ParentId bigint
Select @ParentId = ParentId from User_Detail(nolock) where User_Id = @CreatedBy

  IF (@Mode = 'AL') /*This is List Details */
   BEGIN

	 Select count(bm.ExpenseApprovalId) over() as TotalRecords, bm.ExpenseApprovalId, bm.ExpenseClaimId, bm.ApproverStatus,
	 bm.ApproverRemarks, bm.ApproverUserId, bm.ApprovedAmount, es.SuccessfullVisit, es.ClaimAmount, es.TotalAmount,
	 bm.ParentId, bm.CreatedDate, bm.CreatedBy, bm.UpdatedDate, bm.UpdatedBy, bm.IsActive,
	  Cast(es.FromDate as varchar(11)) FromDate, Cast(es.ToDate as varchar(11)) ToDate, concat(ud.FName, '', isnull(ud.LName, '') + ' (' + isnull(ud.User_Login, '') +')') UserFullName,  concat(ud2.FName, '', isnull(ud2.LName, '') + ' (' + isnull(ud2.User_Login, '') +')') CreatedFullName, AttachDocuments, '' FileName, '' FileType, '' AttachDocumentsUrl
	 from TBL_ET_ExpenseApproval (nolock) bm 
	 left join TBL_ET_ExpenseClaim(nolock) es on bm.ExpenseClaimId = es.ExpenseClaimId 
	 left join TBL_ET_ExpenseHead(nolock) eh on es.ExpenseHeadId = eh.ExpenseHeadId 
	 inner join User_detail(nolock) ud on bm.CreatedBy = ud.User_Id
	 inner join User_detail(nolock) ud2 on bm.CreatedBy = ud2.User_Id
	 where bm.ExpenseApprovalId = (Case When @ExpenseApprovalId != 0 then @ExpenseApprovalId else bm.ExpenseApprovalId End) 
	 and ((es.CreatedDate between @FromDate and @ToDate)) -- or (es.ToDate between @FromDate and @ToDate)) 
	 and eh.ExpenseHeadName like '%' + @SearchText + '%' 
	 and bm.ParentId = @ParentId 
	 Order By FromDate Desc
	 Offset @Offset rows fetch next @PageSize rows only 

   END /*End here for list */

  Else IF (@Mode = 'AD') /*This is List Details */
   BEGIN

	 Select bm.ExpenseApprovalId, bm.ExpenseClaimId, bm.ApproverStatus, concat(ud.FName, '', isnull(ud.LName, '') + ' (' + isnull(ud.User_Login, '') +')') UserFullName,  concat(ud2.FName, '', isnull(ud2.LName, '') + ' (' + isnull(ud2.User_Login, '') +')') CreatedFullName,  concat(ud3.FName, '', isnull(ud3.LName, '') + ' (' + isnull(ud3.User_Login, '') +')') ApprovedName, 
	 es.Remarks,es.Reimbursement, bm.ApproverRemarks, bm.ApproverUserId, bm.ApprovedAmount, es.SuccessfullVisit, es.ClaimAmount, es.TotalAmount, bm.ParentId, Cast((case when es.UpdatedDate != null then es.UpdatedDate else  es.CreatedDate end) as varchar(100)) RequestDate, Cast((case when es.UpdatedDate != null then es.UpdatedDate else  es.CreatedDate end) as varchar(100)) ApprovedDate, bm.CreatedDate, bm.CreatedBy, bm.UpdatedDate, bm.UpdatedBy, bm.IsActive,
	  Cast(es.FromDate as varchar(11)) FromDate, Cast(es.ToDate as varchar(11)) ToDate, eh.ExpenseHeadName, AttachDocuments, '' FileName,
	  '' FileType, '' AttachDocumentsUrl, es.NoOfVisits, es.ClaimAmount, es.TotalAmount, es.TotalKMs, isnull(es.SiteId1, 0) SiteId1, isnull(es.SiteId2, 0) SiteId2, isnull(esm1.GeoEntitySiteName, '') SiteName1, isnull(esm2.GeoEntitySiteName, '') SiteName2,
	  isnull(esm1.Address, '') SiteName1Address, isnull(esm1.MapAddress, '') SiteName1MapAddress, isnull(esm2.Address, '') SiteName2Address, isnull(esm2.MapAddress, '') SiteName2MapAddress
	 from TBL_ET_ExpenseApproval (nolock) bm 
	 left join TBL_ET_ExpenseClaim(nolock) es on bm.ExpenseClaimId = es.ExpenseClaimId 
	 left join TBL_ET_ExpenseHead(nolock) eh on es.ExpenseHeadId = eh.ExpenseHeadId 
	 inner join User_detail(nolock) ud on bm.CreatedBy = ud.User_Id
	 inner join User_detail(nolock) ud2 on bm.CreatedBy = ud2.User_Id
	inner join User_detail(nolock) ud3 on bm.ApproverUserId = ud3.User_Id
	left join TBL_ET_GeoEntitySiteMaster (nolock) esm1 on es.SiteId1 = esm1.GeoEntitySiteId
	left join TBL_ET_GeoEntitySiteMaster (nolock) esm2 on es.SiteId2 = esm2.GeoEntitySiteId
	
	 where bm.ExpenseApprovalId = @ExpenseApprovalId and bm.ParentId = @ParentId 

   END /*End here for list */

END TRY

BEGIN CATCH
	DECLARE @ErrorMessage NVARCHAR(4000);
	SELECT @ErrorMessage = ERROR_MESSAGE();
	RAISERROR (
			@ErrorMessage
			,16
			,1
			);
END CATCH



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_ExpenseApprovalSave]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE  [dbo].[usp_TBL_ET_ExpenseApprovalSave] (
	@Mode VARCHAR(2)
	,@ExpenseApprovalId	bigint = 0
	,@ExpenseClaimId bigint = 0
	,@ApproverStatus varchar(50) = null
	,@ApproverRemarks varchar(1000)
	,@ApproverUserId bigint = 0
	,@ApprovedAmount numeric(18, 2) = null
	,@ParentId bigint = 0
	,@CreatedBy	bigint = 0
	,@IsActive	bit = 1
)
AS
SET NOCOUNT ON

BEGIN TRY
	select @ParentId = ParentId from User_Detail(nolock) where User_ID = @CreatedBy;
	IF (@Mode = 'AI') /*This is for Insert Details */
	BEGIN
	DECLARE @ID BIGINT;
 if(Not Exists(select ExpenseApprovalId from TBL_ET_ExpenseApproval(nolock) ec where ec.ExpenseClaimId = @ExpenseClaimId and ec.ApproverStatus = @ApproverStatus))
	Begin
			INSERT INTO TBL_ET_ExpenseApproval (ExpenseClaimId
				,ApproverStatus
				,ApproverRemarks
				,ApproverUserId
				,ApprovedAmount
				,ParentId
				,CreatedDate
				,CreatedBy
				,IsActive
				)
			VALUES (
				@ExpenseClaimId
				,@ApproverStatus
				,@ApproverRemarks
				,@ApproverUserId
				,@ApprovedAmount
				,@ParentId
				,GETDATE()				
				,@CreatedBy
				,@IsActive
				)

			SET @ID = scope_identity();

		SELECT 'Record Saved' STATUS, @ID ExpenseApprovalId

		END
		ELSE
		BEGIN
			SELECT 'Record Already Exist' STATUS
 
		 Select GETDATE()
		END
	END /*End here for insert*/

	Else IF (@Mode = 'AU') /*This is for Update Details */
	BEGIN
 if(Exists(select ExpenseApprovalId from TBL_ET_ExpenseApproval(nolock) ec where ec.ExpenseClaimId = @ExpenseClaimId and ec.ParentId = @ParentId
 and ec.ApproverStatus = @ApproverStatus))
	Begin

	Update TBL_ET_ExpenseApproval  set ExpenseClaimId = @ExpenseClaimId
				,ApproverStatus = @ApproverStatus
				,ApproverRemarks = @ApproverRemarks
				,ApproverUserId = @ApproverUserId
				,ApprovedAmount = @ApprovedAmount
				,ParentId = @ParentId
				,IsActive = @IsActive
				,UpdatedBy = @CreatedBy
				,UpdatedDate = GETDATE()				
				where ExpenseApprovalId = @ExpenseApprovalId

		SELECT 'Record Updated' STATUS, @ExpenseApprovalId ExpenseApprovalId

       	Select GETDATE()

       End
		ELSE
		BEGIN
			SELECT 'Update Issue.' STATUS
       	Select GETDATE()
		END

	END /*End here for update*/

END TRY

BEGIN CATCH
	DECLARE @ErrorMessage NVARCHAR(4000);
	SELECT @ErrorMessage = ERROR_MESSAGE();
	RAISERROR (
			@ErrorMessage
			,16
			,1
			);
END CATCH



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_ExpenseClaimAppList_Name]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--usp_TBL_ET_ExpenseClaimAppList_Name 0, '', '2023-01-01', '2023-01-05', 34594, 0, 10
CREATE   PROCEDURE  [dbo].[usp_TBL_ET_ExpenseClaimAppList_Name] (
 @OffsetValue int = 0  
 ,@PagingSize int = 0  
 ,@SearchText nvarchar(max) = '' 
 ,@Condition varchar(20) = 'StartWith'                        
 ,@UserId bigint = 0  
 ,@ParentId bigint = 0 
)
AS
SET NOCOUNT ON

BEGIN TRY  
--Declare @ParentId bigint  
	Select @ParentId = ParentId from User_Detail(nolock) where User_Id = @UserId
	
if(@SearchText != '')
Begin  
set @SearchText = ' and ' + @SearchText  
End  
Declare @UserIdTeamLst varchar(4000)  
select @UserIdTeamLst = UserIdTeamLst from ufn_GetUserRoleScope(@UserId)  
print @UserIdTeamLst 

Declare @query nvarchar(max) 

set @Query = 'Select count(ExpenseApprovalId) over() as TotalRecords, IconClass, ExpenseApprovalId, ExpenseClaimId, ExpenseHeadId, ExpenseHeadName, UserId, UserFullName, CreatedFullName, Cast(FromDate as varchar(11)) FromDate, Cast(ToDate as varchar(11)) ToDate, NoOfVisits, TotalKMs, ClaimAmount, SuccessfullVisit, FailedVisit, Reimbursement, TotalAmount, AttachDocuments, AttachDocuments AttachDocumentsUrl, Remarks, ApproverStatus, ApproverRemarks, ApproverFullName, ApprovedAmount, ApproverDate, Cast(RequestDate as varchar(20)) RequestDate, t.ParentId, t.CreatedDate, t.CreatedBy, t.UpdatedDate, t.UpdatedBy, t.IsActive, SiteName1, SiteName2, BranchAddress, LastLoginAttendanceIn from (Select exap.ExpenseApprovalId, IconClass, bm.ExpenseClaimId, bm.ExpenseHeadId, eh.ExpenseHeadName, bm.UserId, concat(ud.FName, '''', isnull(ud.LName, '''')) UserFullName,  concat(ud2.FName, '''', isnull(ud2.LName, '''')) CreatedFullName, FromDate, ToDate, NoOfVisits, TotalKMs, ClaimAmount, SuccessfullVisit, FailedVisit, Reimbursement, TotalAmount, AttachDocuments, Remarks, isnull(exap.ApproverStatus, ''Pending'') ApproverStatus, isnull(exap.ApproverRemarks, '''') ApproverRemarks, ApprovedAmount, concat(isnull(uda.FName, ''''), '''', isnull(uda.LName, '''')) ApproverFullName, 
	(case when exap.UpdatedDate is null then exap.CreatedDate else exap.UpdatedDate end) ApproverDate,
	(case when bm.UpdatedDate is null then bm.CreatedDate else bm.UpdatedDate end) RequestDate, bm.ParentId, bm.CreatedDate, bm.CreatedBy, bm.UpdatedDate, bm.UpdatedBy, bm.IsActive, isnull(bm.SiteId1, 0) SiteId1, isnull(bm.SiteId2, 0) SiteId2, 
	isnull(esm2.GeoEntitySiteName, '''') SiteName1, isnull(esm2.GeoEntitySiteName, '''') SiteName2, isnull(iutn.Address, '''') +'', ''+ isnull(ct.City_Name, '''') + '', '' + isnull(st.State_Name, '''') + '', '' + isnull(co.Country_Name, '''') BranchAddress, (select top 1 isnull(CONVERT(VARCHAR, AttendanceIn, 100), '''') LastLoginAttendanceIn from TBL_ET_Attendance(nolock) chiur Where UserId = bm.UserId order by 1 desc) LastLoginAttendanceIn from TBL_ET_ExpenseClaim (nolock) bm 
	inner join TBL_ET_ExpenseApproval(nolock) exap on bm.ExpenseClaimId = exap.ExpenseClaimId
	inner join User_detail(nolock) ud on bm.UserId = ud.User_Id
	inner join User_detail(nolock) ud2 on bm.CreatedBy = ud2.User_Id
	left join User_detail(nolock) uda on exap.ApproverUserId = uda.User_Id
	inner join TBL_ET_ExpenseHead(nolock) eh on bm.ExpenseHeadId = eh.ExpenseHeadId
	left join TBL_ET_GeoEntitySiteMaster (nolock) esm1 on bm.SiteId1 = esm1.GeoEntitySiteId
	left join TBL_ET_GeoEntitySiteMaster (nolock) esm2 on bm.SiteId2 = esm2.GeoEntitySiteId
	left join TBL_ET_AttendanceGroupUserMapping (nolock) agum on bm.UserId = agum.UserId
 	left join tbl_inv_UserTaxNumber (nolock) iutn on agum.UserBranchId = iutn.Id 
 left join M_City (nolock) ct on iutn.City_Id = ct.City_Id 
 left join M_State (nolock) st on iutn.State_Id = st.State_Id 
 left join M_Country (nolock) co on iutn.Country_Id = co.Country_Id 
 
	where bm.ParentId = ' + cast(@ParentId as varchar(20)) + ' and (bm.UserId in (select item from dbo.fu_SplitString(''' + cast(@UserIdTeamLst as varchar(1000)) + ''', '','')))) t
	where (1=1) ' + @SearchText + ' Order By FromDate desc
	Offset ' + cast(@OffsetValue as varchar(20)) + ' rows fetch next ' + cast(@PagingSize as varchar(20)) + ' rows only '

	print @Query
	execute sp_executesql @Query

END TRY

BEGIN CATCH
	DECLARE @ErrorMessage NVARCHAR(4000);
	SELECT @ErrorMessage = ERROR_MESSAGE();
	RAISERROR (
			@ErrorMessage
			,16
			,1
			);
END CATCH



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_ExpenseClaimList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--EXEC usp_TBL_ET_ExpenseClaimList 'CD', 70, '', '2023-12-21', '2023-12-21', 43888, 0, 10
CREATE   PROCEDURE  [dbo].[usp_TBL_ET_ExpenseClaimList] (
	@Mode VARCHAR(2)
	,@ExpenseClaimId bigint = 0
	,@SearchText nvarchar(2000) = ''
	,@FromDate DateTime = null
	,@ToDate DateTime = null
	,@CreatedBy	bigint = 0
	,@Offset int = 0
	,@PageSize int = 0
)
AS
BEGIN

	--declare 
	--	@Mode VARCHAR(2)
	--	,@ExpenseClaimId bigint = 0
	--	,@SearchText nvarchar(2000) = ''
	--	,@FromDate DateTime = null
	--	,@ToDate DateTime = null
	--	,@CreatedBy	bigint = 0
	--	,@Offset int = 0
	--	,@PageSize int = 0


	--select @Mode=N'CL',@ExpenseClaimId=0,@SearchText=N'',@FromDate=N'24-May-2025 11:38:38',@ToDate=N'31-May-2025 11:38:38',@CreatedBy=47172,@Offset=0,@PageSize=100

	SET NOCOUNT ON

	BEGIN TRY
		Declare @ParentId bigint
		Select @ParentId = ParentId from User_Detail(nolock) where User_Id = @CreatedBy

		IF (@Mode = 'CL') /*This is List Details */
		BEGIN
		if(@SearchText != '')
		Begin
		set @SearchText = ' and ' + @SearchText;
		End
		Declare @Query nvarchar(max)

		drop table if exists #tblRoleuser
		create table #tblRoleuser(User_ID bigint,Name varchar(100), Image varchar(100))
		insert into #tblRoleuser
		exec Use_GetUserDetails @CreatedBy

		
		print concat('@CreatedBy => ', @CreatedBy)

		set @Query = 'select count(t.ExpenseClaimId) over() as TotalRecords, ExpenseClaimId, ExpenseHeadId, ExpenseHeadName, UserId, UserFullName, CreatedFullName, FromDate, ToDate, NoOfVisits, TotalKMs, ClaimAmount, SuccessfullVisit, FailedVisit, Reimbursement, TotalAmount, AttachDocuments, '''' AttachDocumentsUrl, Remarks, ApproverStatus, ApproverRemarks, ApproverFullName, ApprovedAmount, ApproverDate, t.ParentId, t.CreatedDate, t.CreatedBy, t.UpdatedDate, t.UpdatedBy, t.IsActive from (Select bm.ExpenseClaimId, bm.ExpenseHeadId, eh.ExpenseHeadName, bm.UserId, concat(ud.FName, '''', isnull(ud.LName, '''')) UserFullName,  concat(ud2.FName, '''', isnull(ud2.LName, '''')) CreatedFullName, FromDate, ToDate, NoOfVisits, TotalKMs, ClaimAmount, SuccessfullVisit, FailedVisit, Reimbursement, TotalAmount, AttachDocuments, Remarks, isnull(ApproverStatus, ''Pending'') ApproverStatus, isnull(ApproverRemarks, '''') ApproverRemarks, concat(isnull(uda.FName, ''''), '''', isnull(uda.LName, '''')) ApproverFullName, ApprovedAmount, 
		(case when ea.UpdatedDate is null then ea.CreatedDate else ea.UpdatedDate end) ApproverDate, bm.ParentId, bm.CreatedDate, bm.CreatedBy, bm.UpdatedDate, bm.UpdatedBy, bm.IsActive from TBL_ET_ExpenseClaim (nolock) bm 
		inner join User_detail(nolock) ud on bm.UserId = ud.User_Id
		inner join User_detail(nolock) ud2 on bm.CreatedBy = ud2.User_Id
		left join TBL_ET_ExpenseApproval ea on bm.ExpenseClaimId = ea.ExpenseClaimId
		left join User_detail(nolock) uda on ea.ApproverUserId = uda.User_Id
		inner join TBL_ET_ExpenseHead(nolock) eh on bm.ExpenseHeadId = eh.ExpenseHeadId
		where bm.ParentId = ' + cast(@ParentId as varchar(20)) + 
		+ ' and (bm.UserId in (select User_ID from #tblRoleuser))'
		+' and ((cast(bm.FromDate as date) between cast(''' + cast(@FromDate as varchar(30)) + ''' as date) and cast(''' + cast(@ToDate as varchar(30)) + ''' as date)) or (cast(bm.ToDate as date) between cast(''' + cast(@FromDate as varchar(30)) + ''' as date) and cast(''' + cast(@ToDate as varchar(30)) + ''' as date) ))) t
		where (1=1) ' + @SearchText + ' Order By FromDate desc
		Offset ' + cast(@Offset as varchar(20)) + ' rows fetch next ' + cast(@PageSize as varchar(20)) + ' rows only '

		print @Query
		execute sp_executesql @Query

		END /*End here for list */
		Else IF (@Mode = 'CD') /*This is List Details */
		BEGIN
	
	 Select count(bm.ExpenseClaimId) over() as TotalRecords, bm.ExpenseClaimId, bm.ExpenseHeadId, eh.ExpenseHeadName, bm.UserId, concat(ud.FName, '', isnull(ud.LName, '') + ' (' + isnull(ud.User_Login, '') +')') UserFullName,  concat(ud2.FName, '', isnull(ud2.LName, '') + ' (' + isnull(ud2.User_Login, '') +')') CreatedFullName, ea.ApprovedAmount, ea.ApproverStatus,
	   Cast(bm.FromDate as varchar(11)) FromDate, Cast(bm.ToDate as varchar(11)) ToDate, NoOfVisits, TotalKMs, ClaimAmount, SuccessfullVisit, FailedVisit, Reimbursement, TotalAmount, AttachDocuments, '' AttachDocumentsUrl, '' FileName, '' FileType, Remarks, bm.ParentId, 
	   Cast((case when bm.UpdatedDate != null then bm.UpdatedDate else  bm.CreatedDate end) as varchar(100)) RequestDate, bm.CreatedDate, bm.CreatedBy, bm.UpdatedDate, bm.UpdatedBy, bm.IsActive, isnull(bm.SiteId1, 0) SiteId1, isnull(bm.SiteId2, 0) SiteId2, isnull(esm1.GeoEntitySiteName, '') SiteName1, isnull(esm2.GeoEntitySiteName, '') SiteName2, isnull(esm1.Address, '') SiteName1Address, isnull(esm1.MapAddress, '') SiteName1MapAddress, isnull(esm2.Address, '') SiteName2Address, isnull(esm2.MapAddress, '') SiteName2MapAddress
	from TBL_ET_ExpenseClaim (nolock) bm 
		inner join User_detail(nolock) ud on bm.UserId = ud.User_Id
		inner join User_detail(nolock) ud2 on bm.CreatedBy = ud2.User_Id
		inner join TBL_ET_ExpenseHead(nolock) eh on bm.ExpenseHeadId = eh.ExpenseHeadId
		left join TBL_ET_ExpenseApproval(nolock) ea on bm.ExpenseClaimId = ea.ExpenseClaimId
		left join TBL_ET_GeoEntitySiteMaster (nolock) esm1 on bm.SiteId1 = esm1.GeoEntitySiteId
		left join TBL_ET_GeoEntitySiteMaster (nolock) esm2 on bm.SiteId2 = esm2.GeoEntitySiteId

		where bm.ParentId = @ParentId and bm.ExpenseClaimId = @ExpenseClaimId

		--Site Mapping
		Select ec.ExpenseClaimMappId,  ec.ExpenseClaimId, isnull(ec.SiteId1, 0) SiteId1, isnull(ec.SiteId2, 0) SiteId2, isnull(esm1.GeoEntitySiteName, '') SiteName1, isnull(esm2.GeoEntitySiteName, '') SiteName2, isnull(esm1.Address, '') SiteName1Address, isnull(esm1.MapAddress, '')  SiteName1MapAddress, isnull(esm2.Address, '') SiteName2Address, isnull(esm2.MapAddress, '') SiteName2MapAddress, 0 TotalKMs 
			from TBL_ET_ExpenseClaimMapping
			(nolock) ec
			left join TBL_ET_GeoEntitySiteMaster (nolock) esm1 on ec.SiteId1 = esm1.GeoEntitySiteId
			left join TBL_ET_GeoEntitySiteMaster (nolock) esm2 on ec.SiteId2 = esm2.GeoEntitySiteId
			where ExpenseClaimId = @ExpenseClaimId

	
		-- Attachments
		select id as Id, file_name as FileName, file_type as FileType, file_url as FileUrl
				from TBL_ET_ExpenseClaimAttachments(nolock) 
				where expense_claim_id = @ExpenseClaimId
			
		END /*End here for list */


	END TRY

	BEGIN CATCH
		EXECUTE usp_InsertErrorInfo
	END CATCH
END


GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_ExpenseClaimList_Name]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--usp_TBL_ET_ExpenseClaimList 'CL', 0, '', '2023-01-01', '2023-01-05', 34594, 0, 10
CREATE   PROCEDURE  [dbo].[usp_TBL_ET_ExpenseClaimList_Name] (
 @OffsetValue int = 0  
 ,@PagingSize int = 0  
 ,@SearchText nvarchar(max) = '' 
 ,@Condition varchar(20) = 'StartWith'                        
 ,@UserId bigint = 0  
 ,@ParentId bigint = 0 
)
AS
SET NOCOUNT ON

BEGIN TRY  
--Declare @ParentId bigint  
Select @ParentId = ParentId from User_Detail(nolock) where User_Id = @UserId
	
if(@SearchText != '')
Begin  
set @SearchText = ' and ' + @SearchText  
End  
Declare @UserIdTeamLst varchar(4000)  
select @UserIdTeamLst = UserIdTeamLst from ufn_GetUserRoleScope(@UserId)  
print @UserIdTeamLst 

Declare @query nvarchar(max) 

set @Query = 'Select count(ExpenseClaimId) over() as TotalRecords, IconClass, ExpenseClaimId, ExpenseHeadId, ExpenseHeadName, UserId, UserFullName, CreatedFullName, Cast(FromDate as varchar(11)) FromDate, Cast(ToDate as varchar(11)) ToDate, NoOfVisits, TotalKMs, ClaimAmount, SuccessfullVisit, FailedVisit, Reimbursement, TotalAmount, AttachDocuments, '''' AttachDocumentsUrl, Remarks, ApproverStatus, ApproverRemarks, ApproverFullName, ApproverDate, Cast(RequestDate as varchar(20)) RequestDate, t.ParentId, t.CreatedDate, t.CreatedBy, t.UpdatedDate, t.UpdatedBy, t.IsActive, SiteName1, SiteName2, BranchAddress, LastLoginAttendanceIn from (Select bm.ExpenseClaimId, IconClass, bm.ExpenseHeadId, eh.ExpenseHeadName, bm.UserId, concat(ud.FName, '''', isnull(ud.LName, '''')) UserFullName, concat(ud2.FName, '''', isnull(ud2.LName, '''')) CreatedFullName, FromDate, ToDate, NoOfVisits, TotalKMs, ClaimAmount, SuccessfullVisit, FailedVisit, Reimbursement, TotalAmount, AttachDocuments, Remarks, isnull(ApproverStatus, ''Pending'') ApproverStatus, isnull(ApproverRemarks, '''') ApproverRemarks, concat(isnull(uda.FName, ''''), '''', isnull(uda.LName, '''')) ApproverFullName, 
	(case when ea.UpdatedDate is null then ea.CreatedDate else ea.UpdatedDate end) ApproverDate, 
	(case when bm.UpdatedDate is null then bm.CreatedDate else bm.UpdatedDate end) RequestDate, bm.ParentId, bm.CreatedDate, bm.CreatedBy, bm.UpdatedDate, bm.UpdatedBy, bm.IsActive, isnull(bm.SiteId1, 0) SiteId1, isnull(bm.SiteId2, 0) SiteId2, 
	isnull(esm1.GeoEntitySiteName, '''') SiteName1, isnull(esm2.GeoEntitySiteName, '''') SiteName2, isnull(iutn.Address, '''') +'', ''+ isnull(ct.City_Name, '''') + '', '' + isnull(st.State_Name, '''') + '', '' + isnull(co.Country_Name, '''') BranchAddress, (select top 1 isnull(CONVERT(VARCHAR, AttendanceIn, 100), '''') LastLoginAttendanceIn from TBL_ET_Attendance(nolock) Where UserId = bm.UserId order by 1 desc) LastLoginAttendanceIn from TBL_ET_ExpenseClaim (nolock) bm 
	inner join User_detail(nolock) ud on bm.UserId = ud.User_Id 
	inner join User_detail(nolock) ud2 on bm.CreatedBy = ud2.User_Id 
	left join TBL_ET_ExpenseApproval ea on bm.ExpenseClaimId = ea.ExpenseClaimId 
	left join User_detail(nolock) uda on ea.ApproverUserId = uda.User_Id 
	inner join TBL_ET_ExpenseHead(nolock) eh on bm.ExpenseHeadId = eh.ExpenseHeadId 
	left join TBL_ET_GeoEntitySiteMaster (nolock) esm1 on bm.SiteId1 = esm1.GeoEntitySiteId
	left join TBL_ET_GeoEntitySiteMaster (nolock) esm2 on bm.SiteId2 = esm2.GeoEntitySiteId
	left join TBL_ET_AttendanceGroupUserMapping (nolock) agum on bm.UserId = agum.UserId
	left join tbl_inv_UserTaxNumber (nolock) iutn on agum.UserBranchId = iutn.Id 
	 left join M_City (nolock) ct on iutn.City_Id = ct.City_Id 
	 left join M_State (nolock) st on iutn.State_Id = st.State_Id 
	 left join M_Country (nolock) co on iutn.Country_Id = co.Country_Id 
	where bm.ExpenseClaimId not in (select ExpenseClaimId from TBL_ET_ExpenseApproval(nolock) exap where exap.ParentId =' + cast(@ParentId as varchar(20)) + ') and bm.ParentId = ' + cast(@ParentId as varchar(20)) + ' and (bm.UserId in (select item from dbo.fu_SplitString(''' + cast(@UserIdTeamLst as varchar(1000)) + ''', '','')))) t
	where (1=1) ' + @SearchText + ' Order By FromDate desc
	Offset ' + cast(@OffsetValue as varchar(20)) + ' rows fetch next ' + cast(@PagingSize as varchar(20)) + ' rows only '

	print @Query
	execute sp_executesql @Query

END TRY

BEGIN CATCH
	DECLARE @ErrorMessage NVARCHAR(4000);
	SELECT @ErrorMessage = ERROR_MESSAGE();
	RAISERROR (
			@ErrorMessage
			,16
			,1
			);
END CATCH



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_ExpenseClaimList_new1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--------------------------------------------------------------------------------
CREATE   PROCEDURE  [dbo].[usp_TBL_ET_ExpenseClaimList_new1] (
    @Mode VARCHAR(2)
    ,@ExpenseClaimId bigint = 0
    ,@SearchText nvarchar(2000) = ''
    ,@FromDate DateTime = null
    ,@ToDate DateTime = null
    ,@CreatedBy    bigint = 0
    ,@Offset int = 0
    ,@PageSize int = 0
)
AS
BEGIN
    SET NOCOUNT ON
	--declare 
	--	@Mode VARCHAR(2)='CL'
	--	,@ExpenseClaimId bigint = 0
	--	,@SearchText nvarchar(2000) = ''
	--	,@FromDate DateTime = '04-Apr-2026'
	--	,@ToDate DateTime = '04-Apr-2026'
	--	,@CreatedBy	bigint = 32222
	--	,@Offset int = 0
	--	,@PageSize int = 100
    BEGIN TRY
        Declare @ParentId bigint
        Select @ParentId = ParentId from User_Detail(nolock) where User_Id = @CreatedBy

        IF (@Mode = 'CL') /*This is List Details - return all records (ignore pagination) */
        BEGIN
            if(@SearchText != '')
            Begin
                set @SearchText = ' and ' + @SearchText;
            End

            drop table if exists #tblRoleuser
            create table #tblRoleuser(User_ID bigint,Name varchar(100), Image varchar(100))
            insert into #tblRoleuser
            exec Use_GetUserDetails @CreatedBy

            Declare @Query nvarchar(max)
            Declare @SumQuery nvarchar(max)

            -- Main result: return all matching rows (no OFFSET/FETCH)
            set @Query = 'select count(t.ExpenseClaimId) over() as TotalRecords, ExpenseClaimId, ExpenseHeadId, ExpenseHeadName, UserId, UserFullName, CreatedFullName, FromDate, ToDate, NoOfVisits, TotalKMs, ClaimAmount, SuccessfullVisit, FailedVisit, Reimbursement, TotalAmount, AttachDocuments, '''' AttachDocumentsUrl, Remarks, ApproverStatus, ApproverRemarks, ApproverFullName, ApprovedAmount, ApproverDate, t.ParentId, t.CreatedDate, t.CreatedBy, t.UpdatedDate, t.UpdatedBy, t.IsActive from (Select bm.ExpenseClaimId, bm.ExpenseHeadId, eh.ExpenseHeadName, bm.UserId, concat(ud.FName, '''', isnull(ud.LName, '''')) UserFullName,  concat(ud2.FName, '''', isnull(ud2.LName, '''')) CreatedFullName, FromDate, ToDate, NoOfVisits, TotalKMs, ClaimAmount, SuccessfullVisit, FailedVisit, Reimbursement, TotalAmount, AttachDocuments, Remarks, isnull(ApproverStatus, ''Pending'') ApproverStatus, isnull(ApproverRemarks, '''') ApproverRemarks, concat(isnull(uda.FName, ''''), '''', isnull(uda.LName, '''')) ApproverFullName, ApprovedAmount, '
                + '(case when ea.UpdatedDate is null then ea.CreatedDate else ea.UpdatedDate end) ApproverDate, bm.ParentId, bm.CreatedDate, bm.CreatedBy, bm.UpdatedDate, bm.UpdatedBy, bm.IsActive from TBL_ET_ExpenseClaim (nolock) bm '
                + 'inner join User_detail(nolock) ud on bm.UserId = ud.User_Id '
                + 'inner join User_detail(nolock) ud2 on bm.CreatedBy = ud2.User_Id '
                + 'left join TBL_ET_ExpenseApproval ea on bm.ExpenseClaimId = ea.ExpenseClaimId '
                + 'left join User_detail(nolock) uda on ea.ApproverUserId = uda.User_Id '
                + 'inner join TBL_ET_ExpenseHead(nolock) eh on bm.ExpenseHeadId = eh.ExpenseHeadId '
                + 'where bm.ParentId = ' + cast(@ParentId as varchar(20))
                + ' and (bm.UserId in (select User_ID from #tblRoleuser))'
                + ' and ((cast(bm.FromDate as date) between cast(''' + cast(@FromDate as varchar(30)) + ''' as date) and cast(''' + cast(@ToDate as varchar(30)) + ''' as date)) or (cast(bm.ToDate as date) between cast(''' + cast(@FromDate as varchar(30)) + ''' as date) and cast(''' + cast(@ToDate as varchar(30)) + ''' as date) ))) t '
                + 'where (1=1) ' + @SearchText + ' Order By FromDate desc'

            -- Summary: total ClaimAmount for pending approvals (no pagination)
            set @SumQuery = 'select ISNULL(SUM(t.ClaimAmount),0) PendingApprovalSum from (Select bm.ClaimAmount, isnull(ea.ApproverStatus, ''Pending'') ApproverStatus from TBL_ET_ExpenseClaim (nolock) bm '
                + 'left join TBL_ET_ExpenseApproval ea on bm.ExpenseClaimId = ea.ExpenseClaimId '
                + 'where bm.ParentId = ' + cast(@ParentId as varchar(20))
                + ' and (bm.UserId in (select User_ID from #tblRoleuser))'
                + ' and ((cast(bm.FromDate as date) between cast(''' + cast(@FromDate as varchar(30)) + ''' as date) and cast(''' + cast(@ToDate as varchar(30)) + ''' as date)) or (cast(bm.ToDate as date) between cast(''' + cast(@FromDate as varchar(30)) + ''' as date) and cast(''' + cast(@ToDate as varchar(30)) + ''' as date) ))) t '
                + 'where t.ApproverStatus = ''Pending'' ' + @SearchText

            --print @Query
            --execute sp_executesql @Query

            -- return pending approval sum as a second resultset
            execute sp_executesql @SumQuery

        END /*End here for list */
        ELSE IF (@Mode = 'CD') /*This is Detail */
        BEGIN
            -- Keep existing CD behavior (unchanged) - copy from user-provided logic
            Select count(bm.ExpenseClaimId) over() as TotalRecords, bm.ExpenseClaimId, bm.ExpenseHeadId, eh.ExpenseHeadName, bm.UserId, concat(ud.FName, '', isnull(ud.LName, '') + ' (' + isnull(ud.User_Login, '') +')') UserFullName,  concat(ud2.FName, '', isnull(ud2.LName, '') + ' (' + isnull(ud2.User_Login, '') +')') CreatedFullName, ea.ApprovedAmount, ea.ApproverStatus,
           Cast(bm.FromDate as varchar(11)) FromDate, Cast(bm.ToDate as varchar(11)) ToDate, NoOfVisits, TotalKMs, ClaimAmount, SuccessfullVisit, FailedVisit, Reimbursement, TotalAmount, AttachDocuments, '' AttachDocumentsUrl, '' FileName, '' FileType, Remarks, bm.ParentId, 
           Cast((case when bm.UpdatedDate != null then bm.UpdatedDate else  bm.CreatedDate end) as varchar(100)) RequestDate, bm.CreatedDate, bm.CreatedBy, bm.UpdatedDate, bm.UpdatedBy, bm.IsActive, isnull(bm.SiteId1, 0) SiteId1, isnull(bm.SiteId2, 0) SiteId2, isnull(esm1.GeoEntitySiteName, '') SiteName1, isnull(esm2.GeoEntitySiteName, '') SiteName2, isnull(esm1.Address, '') SiteName1Address, isnull(esm1.MapAddress, '') SiteName1MapAddress, isnull(esm2.Address, '') SiteName2Address, isnull(esm2.MapAddress, '') SiteName2MapAddress
            from TBL_ET_ExpenseClaim (nolock) bm 
                inner join User_detail(nolock) ud on bm.UserId = ud.User_Id
                inner join User_detail(nolock) ud2 on bm.CreatedBy = ud2.User_Id
                inner join TBL_ET_ExpenseHead(nolock) eh on bm.ExpenseHeadId = eh.ExpenseHeadId
                left join TBL_ET_ExpenseApproval(nolock) ea on bm.ExpenseClaimId = ea.ExpenseClaimId
                left join TBL_ET_GeoEntitySiteMaster (nolock) esm1 on bm.SiteId1 = esm1.GeoEntitySiteId
                left join TBL_ET_GeoEntitySiteMaster (nolock) esm2 on bm.SiteId2 = esm2.GeoEntitySiteId

            where bm.ParentId = @ParentId and bm.ExpenseClaimId = @ExpenseClaimId

            --Site Mapping
            Select ec.ExpenseClaimMappId,  ec.ExpenseClaimId, isnull(ec.SiteId1, 0) SiteId1, isnull(ec.SiteId2, 0) SiteId2, isnull(esm1.GeoEntitySiteName, '') SiteName1, isnull(esm2.GeoEntitySiteName, '') SiteName2, isnull(esm1.Address, '') SiteName1Address, isnull(esm1.MapAddress, '')  SiteName1MapAddress, isnull(esm2.Address, '') SiteName2Address, isnull(esm2.MapAddress, '') SiteName2MapAddress, 0 TotalKMs 
                from TBL_ET_ExpenseClaimMapping
                (nolock) ec
                left join TBL_ET_GeoEntitySiteMaster (nolock) esm1 on ec.SiteId1 = esm1.GeoEntitySiteId
                left join TBL_ET_GeoEntitySiteMaster (nolock) esm2 on ec.SiteId2 = esm2.GeoEntitySiteId
                where ExpenseClaimId = @ExpenseClaimId

            -- Attachments
            select id as Id, file_name as FileName, file_type as FileType, file_url as FileUrl
                    from TBL_ET_ExpenseClaimAttachments(nolock) 
                    where expense_claim_id = @ExpenseClaimId
        END

    END TRY

    BEGIN CATCH
        EXECUTE usp_InsertErrorInfo
    END CATCH
END



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_ExpenseClaimSave]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE  [dbo].[usp_TBL_ET_ExpenseClaimSave] (
	@Mode VARCHAR(2)
	,@ExpenseClaimId	bigint = 0
	,@ExpenseHeadId	bigint = 0
	,@SiteId1	bigint = 0
	,@SiteId2	bigint = 0
	,@UserId	bigint = 0
	,@FromDate	datetime = null
	,@ToDate	datetime = null
	,@NoOfVisits	int = 0
	,@TotalKMs	int = 0
	,@ClaimAmount	numeric(18, 2) = 0
	,@SuccessfullVisit	int = 0
	,@FailedVisit	int = 0
	,@Reimbursement	numeric(18, 2) = 0
	,@TotalAmount	numeric(18, 2) = 0
	,@AttachDocuments	varchar(1000) = ''
	,@Remarks	varchar(1000) = ''
	,@SiteList	nvarchar(max) = ''
	,@ParentId bigint = 0
	,@CreatedBy	bigint = 0
	,@IsActive	bit = 1
)
AS
SET NOCOUNT ON

BEGIN TRY
   select @ParentId = ParentId from User_Detail(nolock) where User_id = @UserId

  IF (@Mode = 'CI') /*This is for Insert Details */
	BEGIN
	DECLARE @ID BIGINT;

 if(Not Exists(select ExpenseClaimId from TBL_ET_ExpenseClaim(nolock) ec where ((ec.FromDate between @FromDate and @ToDate) or (ec.ToDate between @FromDate and @ToDate)) and ec.ExpenseHeadId = @ExpenseHeadId and ec.ParentId = @ParentId))
	Begin
			INSERT INTO TBL_ET_ExpenseClaim (ExpenseHeadId
				,SiteId1
				,SiteId2
				,UserId
				,FromDate
				,ToDate
				,NoOfVisits
				,TotalKMs
				,ClaimAmount
				,SuccessfullVisit
				,FailedVisit
				,Reimbursement
				,TotalAmount
				,AttachDocuments
				,Remarks
				,ParentId
				,CreatedDate
				,CreatedBy
				,IsActive
				)
			VALUES (
				@ExpenseHeadId
				,@SiteId1
				,@SiteId2
				,@UserId
				,@FromDate
				,@ToDate
				,@NoOfVisits
				,@TotalKMs
				,@ClaimAmount
				,@SuccessfullVisit
				,@FailedVisit
				,@Reimbursement
				,@TotalAmount
				,@AttachDocuments
				,@Remarks
				,@ParentId
				,GETDATE()				
				,@CreatedBy
				,@IsActive
				)

			SET @ID = scope_identity();

			insert into TBL_ET_ExpenseClaimMapping (ExpenseClaimId, SiteId1, SiteId2)
			select @ID, SiteId1,SiteId2 from openjson(@SiteList)
			with
			(SiteId1 bigint '$.SiteId1',                  
			 SiteId2 bigint '$.SiteId2') t

		SELECT 'Record Saved' STATUS, @ID ExpenseClaimId

		END
		ELSE
		BEGIN
			SELECT 'Record Already Exist' STATUS
 
		 Select GETDATE()
		END
	END /*End here for insert*/

	Else IF (@Mode = 'CU') /*This is for Update Details */
	BEGIN
 if(Exists(select ExpenseClaimId from TBL_ET_ExpenseClaim(nolock) ec where ((ec.FromDate between @FromDate and @ToDate) or (ec.ToDate between @FromDate and @ToDate)) and ExpenseHeadId = @ExpenseHeadId and ParentId = @ParentId))
	Begin

	Update TBL_ET_ExpenseClaim  set ExpenseHeadId = @ExpenseHeadId
				,SiteId1 = @SiteId1
				,SiteId2 = @SiteId2
				,UserId = @UserId
				,FromDate = @FromDate
				,ToDate = @ToDate
				,NoOfVisits = @NoOfVisits
				,TotalKMs = @TotalKMs
				,ClaimAmount = ClaimAmount
				,SuccessfullVisit = @SuccessfullVisit
				,FailedVisit = @FailedVisit
				,Reimbursement = @Reimbursement
				,TotalAmount = @TotalAmount
				,AttachDocuments = @AttachDocuments
				,Remarks = @Remarks
				,ParentId = @ParentId
				,IsActive = @IsActive
				,UpdatedBy = @CreatedBy
				,UpdatedDate = GETDATE()				
				where ExpenseClaimId = @ExpenseClaimId

		SELECT 'Record Updated' STATUS, @ExpenseClaimId ExpenseClaimId
		
		delete TBL_ET_ExpenseClaimMapping where ExpenseClaimId = @ExpenseClaimId
		
		insert into TBL_ET_ExpenseClaimMapping (ExpenseClaimId, SiteId1, SiteId2)
		select @ExpenseClaimId, SiteId1,SiteId2 from openjson(@SiteList)
			with
			(SiteId1 bigint '$.SiteId1',                  
			 SiteId2 bigint '$.SiteId2') t

       	Select GETDATE()

       End
		ELSE
		BEGIN
			SELECT 'Update Issue.' STATUS
       	Select GETDATE()
		END

	END /*End here for update*/

END TRY

BEGIN CATCH
	DECLARE @ErrorMessage NVARCHAR(4000);
	SELECT @ErrorMessage = ERROR_MESSAGE();
	RAISERROR (
			@ErrorMessage
			,16
			,1
			);
END CATCH



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_ExpenseDetail_UserIdFromTo]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_TBL_ET_ExpenseDetail_UserIdFromTo]
(
 --@Mode VARCHAR(2)
 @SearchText varchar(200) = ''
 ,@Contain varchar(200) = ''
 ,@FromDate nvarchar(100) = ''  
 ,@ToDate nvarchar(100) = ''  
 ,@UserId bigint = 0
 ,@Offset int = 0  
 ,@PageSize int = 10 
)
AS  
SET NOCOUNT ON  
BEGIN TRY 

Declare @ParentId bigint , @IsAdmin bit 
Select @IsAdmin = IsAdmin, @ParentId = ParentId from User_Detail(NOLOCK) where User_ID = @UserId  

--Declare @columns NVARCHAR(MAX) = ''
--select @columns += QUOTENAME(ExpenseHeadName) + ',' from TBL_ET_ExpenseHead(nolock) teeh where teeh.ParentId = @ParentId order by ExpenseHeadName Asc

--select @columns

Declare @query nvarchar(max)

set @query = 'select teec.UserId, ud.FName +'' '' + ud.LName +''(''+ud.User_Login+'')'' as UserName,
teec.ExpenseClaimId,
isnull(teeh.ExpenseHeadName, '''') ExpenseHeadName, isnull(teec.TotalAmount,0) TotalAmount, 
FORMAT(cast(teec.FromDate as date), ''dd-MM-yyyy'') FromDate,
FORMAT(cast(teec.ToDate as date), ''dd-MM-yyyy'') ToDate,
Cast(CONVERT(varchar, teec.FromDate,13) as varchar(12)) PeriodFromDate, 
Cast(CONVERT(varchar, teec.ToDate,13) as varchar(12)) PeriodToDate,
teec.CreatedDate CreatedOn,
''Claim'' Status, 0 ApprovedAmount, '''' ApprovedDate,
NoOfVisits, TotalKMs, SiteId1, SiteId2, 
isnull(tees.GeoEntitySiteName, '''') SiteName1, isnull(tees2.GeoEntitySiteName, '''') SiteName2,
0 ApproverUserId, '''' ApproverUserName
from TBL_ET_ExpenseClaim(nolock) teec
inner join User_detail(nolock) ud on teec.UserId = ud.User_ID
left join TBL_ET_ExpenseHead(nolock) teeh on teec.ExpenseHeadId = teeh.ExpenseHeadId
left join TBL_ET_GeoEntitySiteMaster(nolock) tees on teec.SiteId1 = tees.GeoEntitySiteId
left join TBL_ET_GeoEntitySiteMaster(nolock) tees2 on teec.SiteId2 = tees2.GeoEntitySiteId
where teec.UserId = ' + cast(@UserId as varchar(10)) + '  and 
(cast(teec.FromDate as date) between cast('''+ cast(@FromDate as varchar(10))+''' as date) and cast('''+ cast(@ToDate as varchar(10))+''' as date) 
or cast(teec.ToDate as date) between cast('''+ cast(@FromDate as varchar(10))+''' as date) and cast('''+ cast(@ToDate as varchar(10))+''' as date) 
) and teeh.ExpenseHeadName like ''%'+ @SearchText + '%''
 '
print @query 

execute sp_executesql @query 

END TRY 
BEGIN CATCH 
 DECLARE @ErrorMessage NVARCHAR(4000); 
 SELECT @ErrorMessage = ERROR_MESSAGE(); 
 RAISERROR ( 
   @ErrorMessage 
   ,16 
   ,1 
   ); 
END CATCH 
 


GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_ExpenseHeadList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_TBL_ET_ExpenseHeadList] (
	@Mode VARCHAR(2)
	,@ExpenseHeadId bigint = 0
	,@ExpenseHeadName varchar(100) = ''
	,@CreatedBy	bigint = 0
	,@Contain nvarchar(max) = ''
	,@Offset int = 0
	,@PageSize int = 0
	,@ParentId bigint = 0
)
AS
SET NOCOUNT ON

BEGIN TRY
--    Declare @ParentId bigint
	Select @ParentId = ParentId from User_Detail(nolock) where User_Id = @CreatedBy

	IF (@Mode = 'EL') /*This is List Details */
	BEGIN
	Select count(bm.ExpenseHeadId) over() as TotalRecords, bm.ExpenseHeadId, ExpenseHeadName, bm.Description 
	,ExpenseBasis, MaxCap, isnull(IsFixedRate, 0) IsFixedRate,isnull(IsSuccessMeeting, 0) IsSuccessMeeting, isnull(IsFailureMeeting, 0) IsFailureMeeting ,MeetingSuccessReimbursement, MeetingFailureDeduction,isnull(IsOnActual, 0) IsOnActual, 
	isnull(IsAsPerClaim, 0) IsAsPerClaim, IconClass, isnull(IsRate, 0) IsRate,  isnull(Rate, 0) Rate
				,isnull(bm.ClaimedTime, 0) ClaimedTime, isnull(bm.ClaimedPerDay, 0) ClaimedPerDay,
				case when isnull(IsSiteToHome, 0) = 1 then 'Site To Home'
				when isnull(IsHomeToSite, 0) = 1 then 'Home To Site'
				when (isnull(IsSiteToHome, 0) = 1) and (isnull(IsHomeToSite, 0) = 1) then 'Site To Home'
				else ''
				end ClaimAccceptableFor
	,bm.ParentId,  isnull(ClaimUnder, '') ClaimUnder, isnull(IsHomeToSite, 0) IsHomeToSite, isnull(IsSiteToHome, 0) IsSiteToHome, 
	'' UserFullName, bm.CreatedBy UserId,
	bm.CreatedDate, bm.CreatedBy, bm.UpdatedDate, bm.UpdatedBy, bm.IsActive
	from TBL_ET_ExpenseHead (nolock) bm 
	where ((bm.ExpenseHeadName like '%' + @ExpenseHeadName + '%') or (ExpenseBasis like '%' + @ExpenseHeadName + '%')) and 
	bm.ExpenseHeadId = (Case When @ExpenseHeadId != 0 then @ExpenseHeadId else bm.ExpenseHeadId End) and bm.ParentId = @ParentId 
	Order By ExpenseHeadName Asc
	Offset @Offset rows fetch next @PageSize rows only 

	END /*End here for list */
	else IF (@Mode = 'EE') /*This is List Details */
	BEGIN
	Select bm.ExpenseHeadId, ExpenseHeadName, bm.Description 
				,ExpenseBasis, MaxCap, IsFixedRate
				,IsSuccessMeeting, IsFailureMeeting
				,MeetingSuccessReimbursement, MeetingFailureDeduction
				,IsOnActual, IsAsPerClaim
				,IsRate, Rate
				,ClaimedTime, ClaimedPerDay
				,ParentId, ClaimUnder
				,IconClass, IsHomeToSite
				,IsSiteToHome
	,bm.ParentId, ClaimUnder, IconClass, IsHomeToSite, IsSiteToHome, 
	bm.CreatedDate, bm.CreatedBy, bm.UpdatedDate, bm.UpdatedBy, bm.IsActive
	from TBL_ET_ExpenseHead (nolock) bm 
	where bm.ExpenseHeadId =  @ExpenseHeadId 
	END /*End here for list */
END TRY

BEGIN CATCH
	DECLARE @ErrorMessage NVARCHAR(4000);
	SELECT @ErrorMessage = ERROR_MESSAGE();
	RAISERROR (
			@ErrorMessage
			,16
			,1
			);
END CATCH



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_ExpenseHeadSave]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_TBL_ET_ExpenseHeadSave] (
	@Mode VARCHAR(2)
	,@ExpenseHeadId bigint = 0
	,@ExpenseHeadName varchar(100) = ''
	,@Description varchar(250) = ''
	,@ExpenseBasis varchar(20)= ''
	,@MaxCap	int = 0
	,@IsFixedRate bit = 0
	,@IsSuccessMeeting bit = 0
	,@IsFailureMeeting bit = 0
	,@MeetingSuccessReimbursement numeric(18, 2) = 0
	,@MeetingFailureDeduction numeric(18, 2) = 0

	,@IsOnActual bit = 0
	,@IsAsPerClaim bit = 0
	,@IsRate bit = 0
	,@Rate numeric(18, 2) = 0

	,@ClaimedTime int = 0
	,@ClaimedPerDay int = 0

	,@ParentId bigint = 0
	,@ClaimUnder	varchar(30) = ''

	,@IconClass	varchar(30) = ''
	,@IsHomeToSite	bit = false
	,@IsSiteToHome	bit = false
	,@CreatedBy	bigint = 0
	,@IsActive	bit = 1
	
)
AS
SET NOCOUNT ON

BEGIN TRY
	IF (@Mode = 'EI') /*This is for Insert Details */
	BEGIN
	DECLARE @ID BIGINT;

 if(Not Exists(select ExpenseHeadId from TBL_ET_ExpenseHead(nolock) where ExpenseHeadName = @ExpenseHeadName and ParentId = @ParentId))
	Begin
			INSERT INTO TBL_ET_ExpenseHead (ExpenseHeadName
				,Description
				,ExpenseBasis
				,MaxCap
				,IsFixedRate
				,IsSuccessMeeting
				,IsFailureMeeting
				,MeetingSuccessReimbursement
				,MeetingFailureDeduction
				,IsOnActual
				,IsAsPerClaim
				,IsRate
				,Rate
				,ClaimedTime
				,ClaimedPerDay
				,ParentId
				,ClaimUnder
				,IconClass
				,IsHomeToSite
				,IsSiteToHome
				,CreatedDate
				,CreatedBy
				,IsActive
				)
			VALUES (
				@ExpenseHeadName
				,@Description
				,@ExpenseBasis
				,@MaxCap
				,@IsFixedRate
				,@IsSuccessMeeting
				,@IsFailureMeeting
				,@MeetingSuccessReimbursement
				,@MeetingFailureDeduction
				,@IsOnActual
				,@IsAsPerClaim
				,@IsRate
				,@Rate
				,@ClaimedTime
				,@ClaimedPerDay
				,@ParentId
				,@ClaimUnder
				,@IconClass
				,@IsHomeToSite
				,@IsSiteToHome
				,GETDATE()				
				,@CreatedBy
				,@IsActive
				)

			SET @ID = scope_identity();

		SELECT 'Record Saved' STATUS, @ID ExpenseHeadId

		END
		ELSE
		BEGIN
			SELECT 'Record Already Exist' STATUS
		END
	END /*End here for insert*/

	Else IF (@Mode = 'EU') /*This is for Update Details */
	BEGIN
 if(Exists(select top 1 ExpenseHeadId from TBL_ET_ExpenseHead(nolock) where ExpenseHeadId = @ExpenseHeadId))
	Begin

	Update TBL_ET_ExpenseHead  set ExpenseHeadName = @ExpenseHeadName
				,Description = @Description
				,ExpenseBasis =@ExpenseBasis
				,MaxCap = @MaxCap
				,IsFixedRate = @IsFixedRate
				,IsSuccessMeeting = @IsSuccessMeeting
				,IsFailureMeeting = @IsFailureMeeting
				,MeetingSuccessReimbursement = @MeetingSuccessReimbursement
				,MeetingFailureDeduction = @MeetingFailureDeduction
				,IsOnActual = @IsOnActual
				,IsAsPerClaim = @IsAsPerClaim
				,IsRate = @IsRate
				,Rate = @Rate
				,ClaimedTime = @ClaimedTime
				,ClaimedPerDay = @ClaimedPerDay
				,ParentId = @ParentId
				,ClaimUnder = @ClaimUnder
				,IconClass = @IconClass
				,IsHomeToSite = @IsHomeToSite
				,IsSiteToHome = @IsSiteToHome
				,IsActive = @IsActive
				,UpdatedBy = @CreatedBy
				,UpdatedDate = GETDATE()				
				where ExpenseHeadId = @ExpenseHeadId

		SELECT 'Record Updated' STATUS, @ExpenseHeadId ExpenseHeadId

       End
		ELSE
		BEGIN
			SELECT 'Update Issue.' STATUS
		END

	END /*End here for update*/

END TRY

BEGIN CATCH
	DECLARE @ErrorMessage NVARCHAR(4000);
	SELECT @ErrorMessage = ERROR_MESSAGE();
	RAISERROR (
			@ErrorMessage
			,16
			,1
			);
END CATCH



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_ExpenseList_UserIdFromTo]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--usp_TBL_ET_ExpenseLocPhyList_Name 'LS', '','', '2023-03-01', '2023-03-31', 34594, 0, 10   
CREATE   PROCEDURE [dbo].[usp_TBL_ET_ExpenseList_UserIdFromTo]
(
 @Mode VARCHAR(2)
 ,@SearchText varchar(200) = ''
 ,@Contain varchar(200) = ''
 ,@FromDate nvarchar(100) = ''  
 ,@ToDate nvarchar(100) = ''  
 ,@UserId bigint = 0
 ,@Offset int = 0  
 ,@PageSize int = 10 
)
AS  
SET NOCOUNT ON  
BEGIN TRY 

Declare @ParentId bigint , @IsAdmin bit 
Select @IsAdmin = IsAdmin, @ParentId = ParentId from User_Detail(NOLOCK) where User_ID = @UserId  

Declare @columns NVARCHAR(MAX) = ''
select @columns += QUOTENAME(ExpenseHeadName) + ',' from TBL_ET_ExpenseHead(nolock) teeh where teeh.ParentId = @ParentId order by ExpenseHeadName Asc

--select @columns

Declare @query nvarchar(max)

set @query = ' Select * from (
select teec.UserId, --isnull(teec.ExpenseHeadId, '''') ExpenseHeadId, --isnull(teeh.ExpenseHeadName, '''') ExpenseHead,
isnull(teeh.ExpenseHeadName, '''') ExpenseHeadName, sum(isnull(teec.TotalAmount,0)) TotalAmounts
from TBL_ET_ExpenseClaim(nolock) teec
left join TBL_ET_ExpenseHead(nolock) teeh on teec.ExpenseHeadId = teeh.ExpenseHeadId
--left join TBL_ET_ExpenseApproval(nolock) teea on teec.ExpenseClaimId = teea.ExpenseClaimId
where teec.UserId = ' + cast(@UserId as varchar(10)) + '  and
(cast(teec.FromDate as date) between cast('''+ cast(@FromDate as varchar(10))+''' as date) and cast('''+ cast(@ToDate as varchar(10))+''' as date)
or cast(teec.ToDate as date) between cast('''+ cast(@FromDate as varchar(10))+''' as date) and cast('''+ cast(@ToDate as varchar(10))+''' as date)
)
group by teeh.ExpenseHeadName, teec.ExpenseHeadId, teec.UserId
) t 
PIVOT( 
    SUM(t.TotalAmounts) 
    FOR t.ExpenseHeadName IN ( 
        '+ @columns +'[t.TotalAmounts]) 
) AS pivot_table 
 '
print @query

execute sp_executesql @query

END TRY  
BEGIN CATCH  
 DECLARE @ErrorMessage NVARCHAR(4000); 
 SELECT @ErrorMessage = ERROR_MESSAGE(); 
 RAISERROR ( 
   @ErrorMessage 
   ,16 
   ,1 
   ); 
END CATCH 



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_ExpenseListDetail_UserIdFromTo]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--usp_TBL_ET_ExpenseListDetail_UserIdFromTo 'SS', '','', 'Pending', '2023-03-01', '2023-03-31', 34594, 0, 10   
CREATE   PROCEDURE [dbo].[usp_TBL_ET_ExpenseListDetail_UserIdFromTo]
(
 @Mode VARCHAR(2)
 ,@SearchText varchar(200) = ''
 ,@Contain varchar(200) = ''
 ,@cType varchar(20) = ''
 ,@FromDate nvarchar(20) = ''
 ,@ToDate nvarchar(20) = ''
 ,@UserId bigint = 0
 ,@Offset int = 0
 ,@PageSize int = 10
)
AS
SET NOCOUNT ON
BEGIN TRY

Declare @ParentId bigint , @IsAdmin bit
Select @IsAdmin = IsAdmin, @ParentId = ParentId from User_Detail(NOLOCK) where User_ID = @UserId 

if(@Mode = 'SS')
Begin
if(@SearchText != '')
Begin
set @SearchText = ' and ' + @SearchText;
End
--select @columns
Declare @FDate nvarchar(20), @TDate nvarchar(20)
if(@cType = 'Claim')
Begin
select distinct teec.UserId, ud.FName +' ' + ud.LName +'('+ud.User_Login+')' as UserName,
teec.ExpenseClaimId,	
isnull(teeh.ExpenseHeadName, '''') ExpenseHeadName, teec.TotalAmount,
teec.FromDate, teec.ToDate,
Cast(CONVERT(varchar, teec.FromDate,13) as varchar(12)) PeriodFromDate,
Cast(CONVERT(varchar, teec.ToDate,13) as varchar(12)) PeriodToDate,
teec.CreatedDate CreatedOn,
'Claim' Status, 0 ApprovedAmount, '' ApprovedDate,
NoOfVisits, TotalKMs, SiteId1, SiteId2, 
isnull(tees.GeoEntitySiteName, '') SiteName1, isnull(tees2.GeoEntitySiteName, '') SiteName2,
0 ApproverUserId, '' ApproverUserName
from TBL_ET_ExpenseClaim(nolock) teec
inner join User_detail(nolock) ud on teec.UserId = ud.User_ID
inner join TBL_ET_ExpenseHead(nolock) teeh on teec.ExpenseHeadId = teeh.ExpenseHeadId
left join TBL_ET_GeoEntitySiteMaster(nolock) tees on teec.SiteId1 = tees.GeoEntitySiteId
left join TBL_ET_GeoEntitySiteMaster(nolock) tees2 on teec.SiteId2 = tees2.GeoEntitySiteId
where teec.UserId =  @UserId and 
(cast(teec.FromDate as date) between cast(@FromDate as date) and cast(@ToDate as date)
or cast(teec.ToDate as date) between cast(@FromDate as date) and cast(@ToDate as date))
End
else if(@cType = 'Pending')
Begin
select distinct teec.UserId, ud.FName +' ' + ud.LName +'('+ud.User_Login+')' as UserName,
teec.ExpenseClaimId,	
isnull(teeh.ExpenseHeadName, '''') ExpenseHeadName, teec.TotalAmount,
teec.FromDate, teec.ToDate,
Cast(CONVERT(varchar, teec.FromDate,13) as varchar(12)) PeriodFromDate,
Cast(CONVERT(varchar, teec.ToDate,13) as varchar(12)) PeriodToDate,
teec.CreatedDate CreatedOn,
'Pending' Status, 0 ApprovedAmount, '' ApprovedDate,
NoOfVisits, TotalKMs, SiteId1, SiteId2, 
isnull(tees.GeoEntitySiteName, '') SiteName1, isnull(tees2.GeoEntitySiteName, '') SiteName2,
isnull(tbea.ApproverUserId, 0) ApproverUserId, isnull(ud2.FName +' ' + ud2.LName +'('+ud2.User_Login+')', '') as ApproverUserName
from TBL_ET_ExpenseClaim(nolock) teec
inner join User_detail(nolock) ud on teec.UserId = ud.User_ID
inner join TBL_ET_ExpenseApproval(nolock) tbea on teec.ExpenseClaimId != tbea.ExpenseClaimId
left join User_detail(nolock) ud2 on tbea.ApproverUserId = ud2.User_ID
inner join TBL_ET_ExpenseHead(nolock) teeh on teec.ExpenseHeadId = teeh.ExpenseHeadId
left join TBL_ET_GeoEntitySiteMaster(nolock) tees on teec.SiteId1 = tees.GeoEntitySiteId
left join TBL_ET_GeoEntitySiteMaster(nolock) tees2 on teec.SiteId2 = tees2.GeoEntitySiteId
where teec.UserId =  @UserId and 

(cast(teec.FromDate as date) between cast(@FromDate as date) and cast(@ToDate as date)
or cast(teec.ToDate as date) between cast(@FromDate as date) and cast(@ToDate as date))
and ExpenseHeadName like '%' +@SearchText + '%'
End
else if(@cType = 'Approve')
Begin
select distinct teec.UserId, ud.FName +' ' + ud.LName +'('+ud.User_Login+')' as UserName,
teec.ExpenseClaimId,	
isnull(teeh.ExpenseHeadName, '''') ExpenseHeadName, teec.TotalAmount,
teec.FromDate, teec.ToDate,
Cast(CONVERT(varchar, teec.FromDate,13) as varchar(12)) PeriodFromDate,
Cast(CONVERT(varchar, teec.ToDate,13) as varchar(12)) PeriodToDate,
CONVERT(varchar,teec.CreatedDate,100) CreatedOn,
ApproverStatus Status, ApprovedAmount, isnull(CONVERT(varchar,tbea.CreatedDate,100), '') ApprovedDate,
NoOfVisits, TotalKMs, SiteId1, SiteId2, 
isnull(tees.GeoEntitySiteName, '') SiteName1, isnull(tees2.GeoEntitySiteName, '') SiteName2,
isnull(tbea.ApproverUserId, 0) ApproverUserId, isnull(ud2.FName +' ' + ud2.LName +'('+ud2.User_Login+')', '') as ApproverUserName
from TBL_ET_ExpenseClaim(nolock) teec
inner join User_detail(nolock) ud on teec.UserId = ud.User_ID
inner join TBL_ET_ExpenseApproval(nolock) tbea on teec.ExpenseClaimId = tbea.ExpenseClaimId
inner join User_detail(nolock) ud2 on tbea.ApproverUserId = ud2.User_ID
inner join TBL_ET_ExpenseHead(nolock) teeh on teec.ExpenseHeadId = teeh.ExpenseHeadId
left join TBL_ET_GeoEntitySiteMaster(nolock) tees on teec.SiteId1 = tees.GeoEntitySiteId
left join TBL_ET_GeoEntitySiteMaster(nolock) tees2 on teec.SiteId2 = tees2.GeoEntitySiteId
where teec.UserId =  @UserId and ApproverStatus = 'Approved' and
(cast(teec.FromDate as date) between cast(@FromDate as date) and cast(@ToDate as date)
or cast(teec.ToDate as date) between cast(@FromDate as date) and cast(@ToDate as date))
and ExpenseHeadName like '%' +@SearchText + '%'
End
else if(@cType = 'Reject')
Begin
select distinct teec.UserId, ud.FName +' ' + ud.LName +'('+ud.User_Login+')' as UserName,
teec.ExpenseClaimId,	
isnull(teeh.ExpenseHeadName, '''') ExpenseHeadName, teec.TotalAmount,
teec.FromDate, teec.ToDate,
Cast(CONVERT(varchar, teec.FromDate,13) as varchar(12)) PeriodFromDate,
Cast(CONVERT(varchar, teec.ToDate,13) as varchar(12)) PeriodToDate,
CONVERT(varchar,teec.CreatedDate,100) CreatedOn,
ApproverStatus Status, ApprovedAmount, isnull(CONVERT(varchar,tbea.CreatedDate,100), '') ApprovedDate,
NoOfVisits, TotalKMs, SiteId1, SiteId2, 
isnull(tees.GeoEntitySiteName, '') SiteName1, isnull(tees2.GeoEntitySiteName, '') SiteName2,
isnull(tbea.ApproverUserId, 0) ApproverUserId, isnull(ud2.FName +' ' + ud2.LName +'('+ud2.User_Login+')', '') as ApproverUserName
from TBL_ET_ExpenseClaim(nolock) teec
inner join User_detail(nolock) ud on teec.UserId = ud.User_ID
inner join TBL_ET_ExpenseApproval(nolock) tbea on teec.ExpenseClaimId = tbea.ExpenseClaimId
inner join User_detail(nolock) ud2 on tbea.ApproverUserId = ud2.User_ID
inner join TBL_ET_ExpenseHead(nolock) teeh on teec.ExpenseHeadId = teeh.ExpenseHeadId
left join TBL_ET_GeoEntitySiteMaster(nolock) tees on teec.SiteId1 = tees.GeoEntitySiteId
left join TBL_ET_GeoEntitySiteMaster(nolock) tees2 on teec.SiteId2 = tees2.GeoEntitySiteId
where teec.UserId =  @UserId  and ApproverStatus = 'Rejected' and 
(cast(teec.FromDate as date) between cast(@FromDate as date) and cast(@ToDate as date)
or cast(teec.ToDate as date) between cast(@FromDate as date) and cast(@ToDate as date))
and ExpenseHeadName like '%' +@SearchText + '%'
End
else
Begin
select distinct teec.UserId, ud.FName +' ' + ud.LName +'('+ud.User_Login+')' as UserName,
teec.ExpenseClaimId,	
isnull(teeh.ExpenseHeadName, '''') ExpenseHeadName, teec.TotalAmount,
teec.FromDate, teec.ToDate,
Cast(CONVERT(varchar, teec.FromDate,13) as varchar(12)) PeriodFromDate,
Cast(CONVERT(varchar, teec.ToDate,13) as varchar(12)) PeriodToDate,
teec.CreatedDate CreatedOn,
'Claim' Status, 0 ApprovedAmount, '' ApprovedDate,
NoOfVisits, TotalKMs, SiteId1, SiteId2, 
isnull(tees.GeoEntitySiteName, '') SiteName1, isnull(tees2.GeoEntitySiteName, '') SiteName2,
0 ApproverUserId, '' ApproverUserName
from TBL_ET_ExpenseClaim(nolock) teec
inner join User_detail(nolock) ud on teec.UserId = ud.User_ID
inner join TBL_ET_ExpenseHead(nolock) teeh on teec.ExpenseHeadId = teeh.ExpenseHeadId
left join TBL_ET_GeoEntitySiteMaster(nolock) tees on teec.SiteId1 = tees.GeoEntitySiteId
left join TBL_ET_GeoEntitySiteMaster(nolock) tees2 on teec.SiteId2 = tees2.GeoEntitySiteId
where teec.UserId =  @UserId and 
(cast(teec.FromDate as date) between cast(@FromDate as date) and cast(@ToDate as date)
or cast(teec.ToDate as date) between cast(@FromDate as date) and cast(@ToDate as date))
and teeh.ExpenseHeadName like '%' +@SearchText + '%'
End
End
END TRY  
BEGIN CATCH  
 DECLARE @ErrorMessage NVARCHAR(4000); 
 SELECT @ErrorMessage = ERROR_MESSAGE(); 
 RAISERROR ( 
   @ErrorMessage 
   ,16 
   ,1 
   ); 
END CATCH 



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_ExpenseSettingsSave]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE  [dbo].[usp_TBL_ET_ExpenseSettingsSave] (
	@Mode VARCHAR(2)
	,@ExpenseSettingsId	bigint = 0
	,@ExpenseHeadId	bigint = 0
	,@Description	varchar(250) = ''
	,@TypeofActivity varchar(20) = ''
	,@Rate numeric(18, 2) = 0
	,@ParentId bigint = 0
	,@CreatedBy	bigint = 0
	,@IsActive	bit = 1
)
AS
SET NOCOUNT ON

BEGIN TRY
	IF (@Mode = 'SI') /*This is for Insert Details */
	BEGIN
	DECLARE @ID BIGINT;

 if(Not Exists(select ExpenseSettingsId from TBL_ET_ExpenseSettings(nolock) where ExpenseHeadId = @ExpenseHeadId and TypeofActivity = @TypeofActivity and ParentId = @ParentId))
	Begin
			INSERT INTO TBL_ET_ExpenseSettings (ExpenseHeadId
				,Description
				,TypeofActivity
				,Rate
				,ParentId
				,CreatedDate
				,CreatedBy
				,IsActive
				)
			VALUES (
				 @ExpenseHeadId
				,@Description
				,@TypeofActivity
				,@Rate
				,@ParentId
				,GETDATE()				
				,@CreatedBy
				,@IsActive
				)

			SET @ID = scope_identity();

		SELECT 'Record Saved' STATUS, @ID ExpenseSettingsId

		END
		ELSE
		BEGIN
			SELECT 'Record Already Exist' STATUS
 
		 Select GETDATE()
		END
	END /*End here for insert*/

	Else IF (@Mode = 'SU') /*This is for Update Details */
	BEGIN
 if(Exists(select ExpenseSettingsId from TBL_ET_ExpenseSettings(nolock) where ExpenseHeadId = @ExpenseHeadId and TypeofActivity = @TypeofActivity and ParentId = @ParentId))
	Begin

	Update TBL_ET_ExpenseSettings  set ExpenseHeadId = @ExpenseHeadId
				,Description = @Description
				,TypeofActivity = @TypeofActivity
				,Rate = @Rate
				,IsActive = @IsActive
				,UpdatedBy = @CreatedBy
				,UpdatedDate = GETDATE()				
				where ExpenseSettingsId = @ExpenseSettingsId

		SELECT 'Record Updated' STATUS, @ExpenseSettingsId ExpenseSettingsId

       	Select GETDATE()

       End
		ELSE
		BEGIN
			SELECT 'Update Issue.' STATUS
       	Select GETDATE()
		END

	END /*End here for update*/

END TRY

BEGIN CATCH
	DECLARE @ErrorMessage NVARCHAR(4000);
	SELECT @ErrorMessage = ERROR_MESSAGE();
	RAISERROR (
			@ErrorMessage
			,16
			,1
			);
END CATCH



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_FieldConditionList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--usp_TBL_ET_FieldConditionList 'AGL', 0, 'A Group 1', 34594, 1     
CREATE   PROCEDURE  [dbo].[usp_TBL_ET_FieldConditionList] (    
 @Mode VARCHAR(3),    
 @Id bigint = 0,    
 @CreatedBy bigint,    
 @SearchText varchar(150) = null,    
 @OffsetValue int = 0,    
 @PagingSize int = 10    
  )    
AS    
SET NOCOUNT ON    
    
BEGIN TRY    
Declare @ParentId bigint 
Select @ParentId = ParentId from User_Detail (nolock) Where User_ID = @CreatedBy 
IF (@Mode = 'FL') /*This is for List */ 
  Begin 

 Select count(fi.FieldConditionId) over() as TotalRecords, fi.FieldConditionId Id, fi.Name, Code    
 from TBL_ET_FieldCondition(nolock) fi    
 Where fi.Name like '%' + @SearchText + '%' and fi.FieldConditionId = (case when @Id = 0 then fi.FieldConditionId else @Id End)     
  and fi.IsActive = 1 
 Order by fi.FieldConditionId desc 
 offset @OffsetValue rows fetch next @PagingSize rows only     
  End 
else if (@Mode = 'AL') /*This is for List */    
  Begin    

 Select count(ai.ActionConditionId) over() as TotalRecords, ai.ActionConditionId Id, ai.Name, Code    
 from TBL_ET_ActionCondition(nolock) ai    
 Where ai.Name like '%' + @SearchText + '%' and ai.ActionConditionId = (case when @Id = 0 then ai.ActionConditionId else @Id End)     
  and ai.IsActive = 1 
 Order by ai.ActionConditionId desc 
 offset @OffsetValue rows fetch next @PagingSize rows only     
  End 
END TRY 
    
BEGIN CATCH    
 DECLARE @ErrorMessage NVARCHAR(4000);    
 SELECT @ErrorMessage = ERROR_MESSAGE();    
 RAISERROR (    
   @ErrorMessage    
   ,16    
   ,1    
   );    
END CATCH



GO

