CREATE   PROCEDURE [dbo].[usp_TBL_ET_GeoEntityCheckInOut] 
(  
  @Mode VARCHAR(2)  
 ,@GeoEntityCheckId BIGINT = 0  
 ,@PhysicalAppointmentId BIGINT = 0  
 ,@UserId BIGINT = 0  
 ,@CheckIn DateTime = NULL  
 ,@CheckOut DateTime = NULL  
 ,@LatitudeIn float = NULL  
 ,@LongitudeIn float = NULL  
 ,@LatitudeOut float = NULL  
