 ,@Address nvarchar(500) = null
 ,@DeviceId VARCHAR(100) = NULL  
 ,@RemarksIn VARCHAR(500) = NULL  
 ,@RemarksOut VARCHAR(500) = NULL  
 ,@IsActive bit = 1
 ,@LocationMetaData NVARCHAR(MAX) = NULL
 )  
AS  
SET NOCOUNT ON    
BEGIN TRY  

	--declare
	--	@Mode VARCHAR(2),
	--	@GeoEntityCheckId BIGINT = 0,
	--	@PhysicalAppointmentId BIGINT = 0,
	--	@UserId BIGINT = 0,
	--	@CheckIn DateTime = NULL,
	--	@CheckOut DateTime = NULL,
	--	@LatitudeIn float = NULL,
	--	@LongitudeIn float = NULL,
	--	@LatitudeOut float = NULL,
	--	@LongitudeOut float = NULL,
	--	@Address nvarchar(500) = null,
	--	@DeviceId VARCHAR(100) = NULL,
	--	@RemarksIn VARCHAR(500) = NULL,
	--	@RemarksOut VARCHAR(500) = NULL,
	--	@IsActive bit = 1,
	--	@LocationMetaData NVARCHAR(MAX) = NULL



 declare @EventDesc NVARCHAR(MAX)='', @meetingdetails nvarchar(max)='', @SchCheckInDateTime datetime, 
	@SchCheckOutDateTime datetime, @LocationDateTime datetime = getdate()
   
 select @SchCheckInDateTime=StartDate, @SchCheckOutDateTime=EndDate, @meetingdetails=concat(Title,' - ',Address)
   from TBL_ET_PhysicalAppointment(nolock) where PhysicalAppointmentId=@PhysicalAppointmentId

 if(isnull(@LocationMetaData, '') <> '' and isnull(@Address, '') = '')
 begin
 	select @Address = mAddress, @LatitudeIn = mLatitude, @LongitudeIn = mLongitude, 
 		@LatitudeOut = mLatitude, @LongitudeOut = mLongitude
 	from openjson(@LocationMetaData) with (
 		mAddress nvarchar(255) '$.Address',
 		mLatitude nvarchar(255) '$.Latitude',
 		mLongitude nvarchar(255) '$.Longitude' )
 end



 IF (@Mode = 'CI') /*This is for Insert usp_tbl_ET_Attendance Details */  
 BEGIN  
 Declare @ParentId bigint, @AttendanceGroupId bigint = 0, @ShiftId bigint= 0  
  
 Select top 1 @AttendanceGroupId = atgp.AttendanceGroupId, @ParentId = atgp.ParentId  
 from TBL_ET_AttendanceGroup atgp(nolock) left join TBL_ET_AttendanceGroupUserMapping agum (nolock) 
 on atgp.AttendanceGroupId = agum.AttendanceGroupId  
 where agum.UserId = @UserId and atgp.IsActive = 1 and agum.IsActive = 1   
  
 select top 1 @ShiftId = shmr.ShiftId from TBL_ET_ShiftMaster shmr(nolock)   
 inner join TBL_ET_ShiftUserMapping suma (nolock) on shmr.ShiftId = suma.ShiftId and shmr.IsActive = 1  
 Where suma.UserId = @UserId  
   
 DECLARE @ID BIGINT;  
  
 if(@AttendanceGroupId > 0)  
 Begin  
 --IF NOT EXISTS (  
 -- SELECT * FROM TBL_ET_GeoEntityCheckInOut WITH (NOLOCK) WHERE cast(CheckIn as Date) = Cast(@CheckIn as Date) AND ParentId = @ParentId and UserId = @UserId  
 --  )  
 -- BEGIN  

	if(not exists(select 1 from TBL_ET_GeoEntityCheckInOut(nolock) 
		where PhysicalAppointmentId = @PhysicalAppointmentId and ParentId = @ParentId and CheckOut is null))
	begin
		INSERT INTO TBL_ET_GeoEntityCheckInOut(PhysicalAppointmentId, UserId, CheckIn, LatitudeIn, LongitudeIn, 
				DeviceId, RemarksIn, ParentId, IsActive, CreatedBy, CreatedDate )  
		VALUES ( @PhysicalAppointmentId, @UserId, @CheckIn, @LatitudeIn, @LongitudeIn,
				@DeviceId, @RemarksIn, @ParentId, @IsActive, @UserId, @LocationDateTime)  
  
		SET @ID = scope_identity();  

		exec usp_et_InsertSingleMovementCodeInternal  
			@MovementCode = 'CHECK_IN', @Latitude = @LatitudeIn, @Longitude = @LongitudeIn, @Address = @Address, @LocationDateTime = @LocationDateTime,
			@AttendanceId = null, @PhysicalAppointmentId = @PhysicalAppointmentId, @BreakTransactionId = null, @DeviceId = @DeviceId, @UserId = @UserId

	end
	else 
	begin
		select top 1 @ID = GeoEntityCheckId from TBL_ET_GeoEntityCheckInOut(nolock) 
		where PhysicalAppointmentId = @PhysicalAppointmentId and ParentId = @ParentId and CheckOut is null
			order by GeoEntityCheckId desc
	end
   

   If(@SchCheckInDateTime <  @CheckIn) -- Late CheckIn
   Begin
		Select @EventDesc=replace(replace(replace(AM.EventTemplate,'#username#',dbo.fn_getentityfullname('user',@UserId)),'#checkintime#',format(@CheckIn,'dd-MMM-yyyy hh:mm tt')),'#meetingdetails#',@meetingdetails)
		from ActivityMaster(Nolock) AM
		Where AM.EventName='User Checked In late'

		Exec UspSaveEntityActivity_withid @entityname='User',@EntityID=0,@UserID=@UserId,@ParentID=@ParentId,@EventDescription=@EventDesc,@EventName='User Checked In late',@reftables='TBL_ET_GeoEntityCheckInOut',@refid=@ID
   End
   Else	-- Normal CheckIn
   Begin
		Select @EventDesc=replace(replace(replace(AM.EventTemplate,'#username#',dbo.fn_getentityfullname('user',@UserId)),'#checkintime#',format(@CheckIn,'dd-MMM-yyyy hh:mm tt')),'#meetingdetails#',@meetingdetails)
		from ActivityMaster(Nolock) AM
		Where AM.EventName='User checked in'

		Exec UspSaveEntityActivity_withid @entityname='User',@EntityID=0,@UserID=@UserId,@ParentID=@ParentId,@EventDescription=@EventDesc,@EventName='User checked in',@reftables='TBL_ET_GeoEntityCheckInOut',@refid=@ID
   End
   
 End  
   SELECT 'Record Saved' STATUS, @ID GeoEntityCheckId  
  
   Select GetDate()  
  
  --END  
  --ELSE  
  --BEGIN  
  -- SELECT 'Record Already Exist' STATUS  
  --END  
 END /*End here for insert*/  
  
 Else IF (@Mode = 'CO') /*This is for Update/ Signout Details */  
 BEGIN  
 Declare @ParentId2 bigint
  SELECT top 1 @ParentId2 = ParentId FROM User_detail WITH (NOLOCK) WHERE User_Id = @UserId  
  
 IF EXISTS (SELECT top 1 * FROM TBL_ET_GeoEntityCheckInOut WITH (NOLOCK) WHERE cast(CheckIn as Date) = Cast(@CheckOut as Date) AND ParentId = @ParentId2 and UserId = @UserId)  
  BEGIN  
  Update TBL_ET_GeoEntityCheckInOut Set  CheckOut = @CheckOut, LatitudeOut = @LatitudeOut, LongitudeOut = @LongitudeOut, RemarksOut = @DeviceId + ' ' + RemarksOut, UpdatedBy = @UserId, UpdatedDate = GETDATE(), @CheckIn=CheckIn, @GeoEntityCheckId=GeoEntityCheckId
    where UserId = @UserId --and cast(CheckIn as Date) = Cast(@CheckOut as Date) 
				and PhysicalAppointmentId = @PhysicalAppointmentId
   SELECT 'Record Updated' STATUS  

   exec usp_et_InsertSingleMovementCodeInternal  
		@MovementCode = 'CHECK_OUT', @Latitude = @LatitudeOut, @Longitude = @LongitudeOut, @Address = @Address, @LocationDateTime = @LocationDateTime,
		@AttendanceId = null, @PhysicalAppointmentId = @PhysicalAppointmentId, @BreakTransactionId = null, @DeviceId = @DeviceId, @UserId = @UserId
   
   Select GetDate()  

	If(@SchCheckOutDateTime > @CheckOut) -- Early CheckOut
	Begin
		Select @EventDesc=replace(replace(replace(AM.EventTemplate,'#username#',dbo.fn_getentityfullname('user',@UserId)),'#checkouttime#',format(@CheckOut,'dd-MMM-yyyy hh:mm tt')),'#meetingdetails#',@meetingdetails)
		from ActivityMaster(Nolock) AM
		Where AM.EventName='User Checked Out early'

		Exec UspSaveEntityActivity_withid @entityname='User',@EntityID=0,@UserID=@UserId,@ParentID=@ParentId,@EventDescription=@EventDesc,@EventName='User Checked Out early',@reftables='TBL_ET_GeoEntityCheckInOut',@refid=@GeoEntityCheckId
	End
	Else	-- Normal CheckOut
	Begin
		Select @EventDesc=replace(replace(replace(AM.EventTemplate,'#username#',dbo.fn_getentityfullname('user',@UserId)),'#checkouttime#',format(@CheckOut,'dd-MMM-yyyy hh:mm tt')),'#meetingdetails#',@meetingdetails)
		from ActivityMaster(Nolock) AM
		Where AM.EventName='User checked out'

		Exec UspSaveEntityActivity_withid @entityname='User',@EntityID=0,@UserID=@UserId,@ParentID=@ParentId,@EventDescription=@EventDesc,@EventName='User checked out',@reftables='TBL_ET_GeoEntityCheckInOut',@refid=@GeoEntityCheckId
	End
  
  END  
  ELSE  
  BEGIN  
  
   INSERT INTO TBL_ET_GeoEntityCheckInOut(PhysicalAppointmentId, UserId, CheckOut, LatitudeOut, LongitudeOut, 
		DeviceId, RemarksOut, ParentId, IsActive, UpdatedBy, UpdatedDate)  
   VALUES (@PhysicalAppointmentId, @UserId, @CheckOut, @LatitudeOut, @LongitudeOut, 
		@DeviceId, @RemarksOut, @ParentId, @IsActive, @UserId, @LocationDateTime)  
  
   DECLARE @ID2 BIGINT;  
  
   SET @ID2 = scope_identity();  
   SELECT 'Record Saved, Check In data not Exist' STATUS, @ID2 GeoEntityCheckId  
  
	exec usp_et_InsertSingleMovementCodeInternal  
		@MovementCode = 'CHECK_IN', @Latitude = @LatitudeOut, @Longitude = @LongitudeOut, @Address = @Address, @LocationDateTime = @LocationDateTime,
		@AttendanceId = null, @PhysicalAppointmentId = @PhysicalAppointmentId, @BreakTransactionId = null, @DeviceId = @DeviceId, @UserId = @UserId

   Select GetDate()  
  
   END  
 END /*End here for update*/  
  
 Else IF (@Mode = 'CS') /**/  
 BEGIN  
if Exists(Select top 1 GeoEntityCheckId from TBL_ET_GeoEntityCheckInOut geci (nolock) where UserId = @UserId and Cast(CheckIn as Date) = Cast(GetDate() as Date) and IsActive = 1 and ((isnull(CheckOut, '') = '') or (isnull(CheckIn, '') = '')) order by GeoEntityCheckId desc)  
 Begin  
  Select distinct (case when isnull(CheckOut, '') = '' then 1 else 0 end) IsCheckInStatus, UserId, CheckIn, 
  isnull(CheckOut, '') CheckOut,isnull(LatitudeIn, '') LatitudeIn, isnull(LongitudeIn, '') LongitudeIn, 
  isnull(LatitudeOut, '') LatitudeOut, isnull(LongitudeOut, '') LongitudeOut, isnull(DeviceId, '') DeviceId,
  isnull(RemarksIn, '') RemarksIn, isnull(RemarksOut, '') RemarksOut, 
  isnull(PhysicalAppointmentId, 0) PhysicalAppointmentId, ParentId,  
  isnull(CreatedBy, 0) CreatedBy, isnull(UpdatedBy, 0) UpdatedBy,   
  case when IsActive = 1 then 'Active' else 'Deactive' end IsActiveStatus  
  from TBL_ET_GeoEntityCheckInOut geci (nolock) where UserId = @UserId and (Cast(CheckIn as Date) = Cast(GetDate() as Date) or Cast(CheckOut as Date) is null) and IsActive = 1 and ((isnull(CheckOut, '') = '') or (isnull(CheckIn, '') = '')) order by CheckIn desc  
 End  
 else  
 Begin  
  Select 0 GeoEntityCheckId, 0 IsCheckInStatus  
 End  
  
 --Site List  
  
 Select distinct PHAP.PhysicalAppointmentId, PHAP.Title, PHAP.StartDate, PHAP.EndDate, GEM.EntityId, PHAP.CreatedDate, GEM.GeoEntityName, GeoEntityType, isnull(Mobile, '') Mobile, isnull(EmailId, '') EmailId,  
  GESM.GeoEntitySiteId, isnull(GeoEntitySiteName, '') GeoEntitySiteName, isnull(GESM.Latitude, '') Latitude, isnull(GESM.Longitude, '') Longitude, Isnull(MapAddress, '') MapAddress, isnull(GESM.Address, '') Address,   
  isnull(City, '') City, isnull(State, '') State, isnull(Country, '') Country, isnull(PinCode, '') PinCode,  
  PAUM.UserId,isnull(ap.CheckInRange, 0) as [CheckInRange], isnull(ap.CheckOutRange, 0) [CheckOutRange],  
  isnull(GeoEntitySiteName, '') EntityName, 'https://kit19.com/UserCRMCampaign/img/img_avatar1.png' EntityProfileInage, isnull(GESM.Address, '') EntityAddress,  
  isnull(Mobile, '') EntityMobile, isnull(EmailId, '') EntityEmailId  
  from TBL_ET_GeoEntityMaster GEM (nolock) inner join TBL_ET_GeoEntitySiteMaster GESM (nolock) 
  on GEM.GeoEntityId = GESM.GEOEntityId inner join TBL_ET_PhysicalAppointment PHAP (nolock) 
  on GESM.GeoEntitySiteId = PHAP.GeoEntitySiteId inner join TBL_ET_PhyAppointUserMapping PAUM (nolock) 
  on PHAP.PhysicalAppointmentId = PAUM.PhysicalAppointmentId --left join TBL_ET_PhysicalAppointmentCheckInOutSetting PACS (nolock) on PAUM.PhysicalAppointmentId = PACS.PhysicalAppointmentId  
		left join tbl_tsk_TaskActionPermission(nolock) ap on PHAP.TaskTypeId = ap.task_type_id  
  Where --GEM.IsActive = 1 and GESM.IsActive = 1 and PHAP.IsActive = 1 and PAUM.IsActive = 1 and   
  PAUM.UserId = @UserId and cast(GETDATE() as date) between cast(PHAP.StartDate as date) and cast(PHAP.EndDate as date)   
  
 --select distinct PHAP.PhysicalAppointmentId, GEM.EntityId, GEM.GeoEntityName, GeoEntityType, isnull(Mobile, '') Mobile, isnull(EmailId, '') EmailId,  
 --GESM.GeoEntitySiteId, isnull(GeoEntitySiteName, '') GeoEntitySiteName, isnull(GESM.Latitude, '') Latitude, isnull(GESM.Longitude, '') Longitude,  
 --Isnull(MapAddress, '') MapAddress, isnull(GESM.Address, '') Address,   
 --isnull(City, '') City, isnull(State, '') State, isnull(Country, '') Country, isnull(PinCode, '') PinCode,  
 --PAUM.UserId, isnull(PACS.CheckInRange, 0) CheckInRange, isnull(PACS.CheckOutRange, 0) CheckOutRange,  
 --isnull(GeoEntitySiteName, '') EntityName, 'https://kit19.com/UserCRMCampaign/img/img_avatar1.png' EntityProfileInage, isnull(GESM.Address, '') EntityAddress, isnull(Mobile, '') EntityMobile, isnull(EmailId, '') EntityEmailId   
 --from TBL_ET_GeoEntityMaster GEM (nolock)   
 --inner join TBL_ET_GeoEntitySiteMaster GESM (nolock) on GEM.GeoEntityId = GESM.GEOEntityId  
 --inner join TBL_ET_PhysicalAppointment PHAP (nolock) on GESM.GeoEntitySiteId = PHAP.GeoEntitySiteId  
 --inner join TBL_ET_PhyAppointUserMapping PAUM (nolock) on PHAP.PhysicalAppointmentId = PAUM.PhysicalAppointmentId  
 --inner join TBL_ET_PhysicalAppointmentCheckInOutSetting PACS (nolock) on PAUM.PhysicalAppointmentId = PACS.PhysicalAppointmentId  
 --Where GEM.IsActive = 1 and GESM.IsActive = 1 and PHAP.IsActive = 1 and PAUM.IsActive = 1  
 --and PAUM.UserId = @UserId  
  
 End  
END TRY  
  
BEGIN CATCH  
 DECLARE @ErrorMessage NVARCHAR(4000);  
  
 SELECT @ErrorMessage = ERROR_MESSAGE();  
  
 RAISERROR (  
   @ErrorMessage  
   ,16  
   ,1  
   );  
END CATCH  



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_GeoEntityCheckInOut_new1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_TBL_ET_GeoEntityCheckInOut_new1]
(
    @Mode VARCHAR(2)  = 'CS',
    @GeoEntityCheckId BIGINT = 0,
    @PhysicalAppointmentId BIGINT = 0,
    @UserId BIGINT = 32222,
    @CheckIn DateTime = NULL,
    @CheckOut DateTime = NULL,
    @LatitudeIn float = NULL,
    @LongitudeIn float = NULL,
    @LatitudeOut float = NULL,
    @LongitudeOut float = NULL,
    @Address nvarchar(500) = null,
    @DeviceId VARCHAR(100) = NULL,
    @RemarksIn VARCHAR(500) = NULL,
    @RemarksOut VARCHAR(500) = NULL,
    @IsActive bit = 1,
    @LocationMetaData NVARCHAR(MAX) = NULL
)
AS
BEGIN
    SET NOCOUNT ON;

	 --declare
  --    @Mode VARCHAR(2)='CS',
  --    @GeoEntityCheckId BIGINT = 0,
  --    @PhysicalAppointmentId BIGINT = 0,
  --    @UserId BIGINT = 32222,
  --    @CheckIn DateTime = NULL,
  --    @CheckOut DateTime = NULL,
  --    @LatitudeIn float = NULL,
  --    @LongitudeIn float = NULL,
  --    @LatitudeOut float = NULL,
  --    @LongitudeOut float = NULL,
  --    @Address nvarchar(500) = null,
  --    @DeviceId VARCHAR(100) = NULL,
  --    @RemarksIn VARCHAR(500) = NULL,
  --    @RemarksOut VARCHAR(500) = NULL,
  --    @IsActive bit = 1,
  --    @LocationMetaData NVARCHAR(MAX) = NULL

    BEGIN TRY

    declare @EventDesc NVARCHAR(MAX)='', @meetingdetails nvarchar(max)='', @SchCheckInDateTime datetime, 
        @SchCheckOutDateTime datetime, @LocationDateTime datetime = getdate();
   
    select @SchCheckInDateTime=StartDate, @SchCheckOutDateTime=EndDate, @meetingdetails=concat(Title,' - ',Address)
       from TBL_ET_PhysicalAppointment(nolock) where PhysicalAppointmentId=@PhysicalAppointmentId;

    if(isnull(@LocationMetaData, '') <> '' and isnull(@Address, '') = '')
    begin
        select @Address = mAddress, @LatitudeIn = mLatitude, @LongitudeIn = mLongitude, 
            @LatitudeOut = mLatitude, @LongitudeOut = mLongitude
        from openjson(@LocationMetaData) with (
            mAddress nvarchar(255) '$.Address',
            mLatitude nvarchar(255) '$.Latitude',
            mLongitude nvarchar(255) '$.Longitude' );
    end

    IF (@Mode = 'CI')
    BEGIN
        -- (kept original CI behaviour)
        Declare @ParentId bigint, @AttendanceGroupId bigint = 0, @ShiftId bigint= 0;
        Select top 1 @AttendanceGroupId = atgp.AttendanceGroupId, @ParentId = atgp.ParentId  
        from TBL_ET_AttendanceGroup atgp(nolock) left join TBL_ET_AttendanceGroupUserMapping agum (nolock) 
        on atgp.AttendanceGroupId = agum.AttendanceGroupId  
        where agum.UserId = @UserId and atgp.IsActive = 1 and agum.IsActive = 1;

        select top 1 @ShiftId = shmr.ShiftId from TBL_ET_ShiftMaster shmr(nolock)   
        inner join TBL_ET_ShiftUserMapping suma (nolock) on shmr.ShiftId = suma.ShiftId and shmr.IsActive = 1  
        Where suma.UserId = @UserId;
       
        DECLARE @ID BIGINT;
       
        if(@AttendanceGroupId > 0)
        Begin
            if(not exists(select 1 from TBL_ET_GeoEntityCheckInOut(nolock) 
                where PhysicalAppointmentId = @PhysicalAppointmentId and ParentId = @ParentId and CheckOut is null))
            begin
                INSERT INTO TBL_ET_GeoEntityCheckInOut(PhysicalAppointmentId, UserId, CheckIn, LatitudeIn, LongitudeIn, 
                        DeviceId, RemarksIn, ParentId, IsActive, CreatedBy, CreatedDate )  
                VALUES ( @PhysicalAppointmentId, @UserId, @CheckIn, @LatitudeIn, @LongitudeIn,
                        @DeviceId, @RemarksIn, @ParentId, @IsActive, @UserId, @LocationDateTime);
      
                SET @ID = scope_identity();

                exec usp_et_InsertSingleMovementCodeInternal  
                    @MovementCode = 'CHECK_IN', @Latitude = @LatitudeIn, @Longitude = @LongitudeIn, @Address = @Address, @LocationDateTime = @LocationDateTime,
                    @AttendanceId = null, @PhysicalAppointmentId = @PhysicalAppointmentId, @BreakTransactionId = null, @DeviceId = @DeviceId, @UserId = @UserId;

            end
            else 
            begin
                select top 1 @ID = GeoEntityCheckId from TBL_ET_GeoEntityCheckInOut(nolock) 
                where PhysicalAppointmentId = @PhysicalAppointmentId and ParentId = @ParentId and CheckOut is null
                    order by GeoEntityCheckId desc;
            end
           
           If(@SchCheckInDateTime <  @CheckIn)
           Begin
                Select @EventDesc=replace(replace(replace(AM.EventTemplate,'#username#',dbo.fn_getentityfullname('user',@UserId)),'#checkintime#',format(@CheckIn,'dd-MMM-yyyy hh:mm tt')),'#meetingdetails#',@meetingdetails)
                from ActivityMaster(Nolock) AM
                Where AM.EventName='User Checked In late'

                Exec UspSaveEntityActivity_withid @entityname='User',@EntityID=0,@UserID=@UserId,@ParentID=@ParentId,@EventDescription=@EventDesc,@EventName='User Checked In late',@reftables='TBL_ET_GeoEntityCheckInOut',@refid=@ID;
           End
           Else
           Begin
                Select @EventDesc=replace(replace(replace(AM.EventTemplate,'#username#',dbo.fn_getentityfullname('user',@UserId)),'#checkintime#',format(@CheckIn,'dd-MMM-yyyy hh:mm tt')),'#meetingdetails#',@meetingdetails)
                from ActivityMaster(Nolock) AM
                Where AM.EventName='User checked in'

                Exec UspSaveEntityActivity_withid @entityname='User',@EntityID=0,@UserID=@UserId,@ParentID=@ParentId,@EventDescription=@EventDesc,@EventName='User checked in',@reftables='TBL_ET_GeoEntityCheckInOut',@refid=@ID;
           End
       End
       SELECT 'Record Saved' STATUS, @ID GeoEntityCheckId;
       Select GetDate();
    END
    ELSE IF (@Mode = 'CO')
    BEGIN
        -- (kept original CO behaviour)
        Declare @ParentId2 bigint;
        SELECT top 1 @ParentId2 = ParentId FROM User_detail WITH (NOLOCK) WHERE User_Id = @UserId;
        
        IF EXISTS (SELECT top 1 * FROM TBL_ET_GeoEntityCheckInOut WITH (NOLOCK) WHERE cast(CheckIn as Date) = Cast(@CheckOut as Date) AND ParentId = @ParentId2 and UserId = @UserId)
        BEGIN
            Update TBL_ET_GeoEntityCheckInOut Set  CheckOut = @CheckOut, LatitudeOut = @LatitudeOut, LongitudeOut = @LongitudeOut, RemarksOut = @DeviceId + ' ' + RemarksOut, UpdatedBy = @UserId, UpdatedDate = GETDATE(), @CheckIn=CheckIn, @GeoEntityCheckId=GeoEntityCheckId
            where UserId = @UserId and PhysicalAppointmentId = @PhysicalAppointmentId;
           SELECT 'Record Updated' STATUS;

           exec usp_et_InsertSingleMovementCodeInternal  
                @MovementCode = 'CHECK_OUT', @Latitude = @LatitudeOut, @Longitude = @LongitudeOut, @Address = @Address, @LocationDateTime = @LocationDateTime,
                @AttendanceId = null, @PhysicalAppointmentId = @PhysicalAppointmentId, @BreakTransactionId = null, @DeviceId = @DeviceId, @UserId = @UserId;
           
           Select GetDate();

            If(@SchCheckOutDateTime > @CheckOut)
            Begin
                Select @EventDesc=replace(replace(replace(AM.EventTemplate,'#username#',dbo.fn_getentityfullname('user',@UserId)),'#checkouttime#',format(@CheckOut,'dd-MMM-yyyy hh:mm tt')),'#meetingdetails#',@meetingdetails)
                from ActivityMaster(Nolock) AM
                Where AM.EventName='User Checked Out early'

                Exec UspSaveEntityActivity_withid @entityname='User',@EntityID=0,@UserID=@UserId,@ParentID=@ParentId,@EventDescription=@EventDesc,@EventName='User Checked Out early',@reftables='TBL_ET_GeoEntityCheckInOut',@refid=@GeoEntityCheckId;
            End
            Else
            Begin
                Select @EventDesc=replace(replace(replace(AM.EventTemplate,'#username#',dbo.fn_getentityfullname('user',@UserId)),'#checkouttime#',format(@CheckOut,'dd-MMM-yyyy hh:mm tt')),'#meetingdetails#',@meetingdetails)
                from ActivityMaster(Nolock) AM
                Where AM.EventName='User checked out'

                Exec UspSaveEntityActivity_withid @entityname='User',@EntityID=0,@UserID=@UserId,@ParentID=@ParentId,@EventDescription=@EventDesc,@EventName='User checked out',@reftables='TBL_ET_GeoEntityCheckInOut',@refid=@GeoEntityCheckId;
            End
        END
        ELSE
        BEGIN
           INSERT INTO TBL_ET_GeoEntityCheckInOut(PhysicalAppointmentId, UserId, CheckOut, LatitudeOut, LongitudeOut, 
                DeviceId, RemarksOut, ParentId, IsActive, UpdatedBy, UpdatedDate)  
           VALUES (@PhysicalAppointmentId, @UserId, @CheckOut, @LatitudeOut, @LongitudeOut, 
                @DeviceId, @RemarksOut, @ParentId, @IsActive, @UserId, @LocationDateTime);
  
           DECLARE @ID2 BIGINT;
           SET @ID2 = scope_identity();
           SELECT 'Record Saved, Check In data not Exist' STATUS, @ID2 GeoEntityCheckId;
  
            exec usp_et_InsertSingleMovementCodeInternal  
                @MovementCode = 'CHECK_IN', @Latitude = @LatitudeOut, @Longitude = @LongitudeOut, @Address = @Address, @LocationDateTime = @LocationDateTime,
                @AttendanceId = null, @PhysicalAppointmentId = @PhysicalAppointmentId, @BreakTransactionId = null, @DeviceId = @DeviceId, @UserId = @UserId;

           Select GetDate();
        END
    END
    ELSE IF (@Mode = 'CS')
    BEGIN
        if Exists(Select top 1 GeoEntityCheckId from TBL_ET_GeoEntityCheckInOut geci (nolock) where UserId = @UserId and Cast(CheckIn as Date) = Cast(GetDate() as Date) and IsActive = 1 and ((isnull(CheckOut, '') = '') or (isnull(CheckIn, '') = '')) order by GeoEntityCheckId desc)
        Begin
            Select distinct (case when isnull(CheckOut, '') = '' then 1 else 0 end) IsCheckInStatus, UserId, CheckIn, 
            isnull(CheckOut, '') CheckOut,isnull(LatitudeIn, '') LatitudeIn, isnull(LongitudeIn, '') LongitudeIn, 
            isnull(LatitudeOut, '') LatitudeOut, isnull(LongitudeOut, '') LongitudeOut, isnull(DeviceId, '') DeviceId,
            isnull(RemarksIn, '') RemarksIn, isnull(RemarksOut, '') RemarksOut, 
            isnull(PhysicalAppointmentId, 0) PhysicalAppointmentId, ParentId,  
            isnull(CreatedBy, 0) CreatedBy, isnull(UpdatedBy, 0) UpdatedBy,   
            case when IsActive = 1 then 'Active' else 'Deactive' end IsActiveStatus  
            from TBL_ET_GeoEntityCheckInOut geci (nolock) where UserId = @UserId and (Cast(CheckIn as Date) = Cast(GetDate() as Date) or Cast(CheckOut as Date) is null) and IsActive = 1 and ((isnull(CheckOut, '') = '') or (isnull(CheckIn, '') = '')) order by CheckIn desc;
        End
        else
        Begin
            Select 0 GeoEntityCheckId, 0 IsCheckInStatus;
        End

        --Site List: exclude appointments that are 'Completed' (i.e., have both check-in and check-out for today)
        Select distinct PHAP.PhysicalAppointmentId, PHAP.Title, PHAP.StartDate, PHAP.EndDate, GEM.EntityId, PHAP.CreatedDate,
         GEM.GeoEntityName, GeoEntityType, isnull(Mobile, '') Mobile, isnull(EmailId, '') EmailId,  
          GESM.GeoEntitySiteId, isnull(GeoEntitySiteName, '') GeoEntitySiteName, isnull(GESM.Latitude, '') Latitude, isnull(GESM.Longitude, '') Longitude, Isnull(MapAddress, '') MapAddress, isnull(GESM.Address, '') Address,   
          isnull(City, '') City, isnull(State, '') State, isnull(Country, '') Country, isnull(PinCode, '') PinCode,  
          PAUM.UserId,isnull(ap.CheckInRange, 0) as [CheckInRange], isnull(ap.CheckOutRange, 0) [CheckOutRange],  
          isnull(GeoEntitySiteName, '') EntityName, 'https://kit19.com/UserCRMCampaign/img/img_avatar1.png' EntityProfileInage, isnull(GESM.Address, '') EntityAddress,  
          isnull(Mobile, '') EntityMobile, isnull(EmailId, '') EntityEmailId,
          CASE 
            WHEN CAST(PHAP.StartDate as date) > CAST(GETDATE() as date) THEN 'Scheduled'
            WHEN EXISTS (
                SELECT 1 FROM TBL_ET_GeoEntityCheckInOut g
                WHERE g.PhysicalAppointmentId = PHAP.PhysicalAppointmentId
                  AND g.UserId = PAUM.UserId
                  AND g.CheckIn IS NOT NULL
                  AND g.CheckOut IS NOT NULL
                  AND CAST(g.CheckIn as date) = CAST(g.CheckOut as date)
                  AND CAST(g.CheckIn as date) = CAST(GETDATE() as date)
            ) THEN 'Completed'
            WHEN EXISTS (
                SELECT 1 FROM TBL_ET_GeoEntityCheckInOut g
                WHERE g.PhysicalAppointmentId = PHAP.PhysicalAppointmentId
                  AND g.UserId = PAUM.UserId
                  AND g.CheckIn IS NOT NULL
                  AND g.CheckOut IS NULL
                  AND CAST(g.CheckIn as date) = CAST(GETDATE() as date)
            ) THEN 'Ongoing'
            WHEN EXISTS (
                SELECT 1 FROM TBL_ET_GeoEntityCheckInOut g
                WHERE g.PhysicalAppointmentId = PHAP.PhysicalAppointmentId
                  AND g.UserId = PAUM.UserId
                  AND g.CheckIn IS NOT NULL
                  AND (g.CheckOut IS NULL OR CAST(g.CheckOut as date) <> CAST(g.CheckIn as date))
                  AND CAST(g.CheckIn as date) = CAST(PHAP.StartDate as date)
                  AND CAST(PHAP.StartDate as date) < CAST(GETDATE() as date)
            ) THEN 'Over Due'
            WHEN CAST(PHAP.StartDate as date) < CAST(GETDATE() as date)
              AND NOT EXISTS (
                SELECT 1 FROM TBL_ET_GeoEntityCheckInOut g2
                WHERE g2.PhysicalAppointmentId = PHAP.PhysicalAppointmentId
                  AND g2.UserId = PAUM.UserId
              ) THEN 'Over Due'
            WHEN CAST(PHAP.StartDate as date) = CAST(GETDATE() as date) THEN 'Due Today'
            ELSE 'Scheduled'
          END AS TaskStatus
          from TBL_ET_GeoEntityMaster GEM (nolock) inner join TBL_ET_GeoEntitySiteMaster GESM (nolock) 
          on GEM.GeoEntityId = GESM.GEOEntityId inner join TBL_ET_PhysicalAppointment PHAP (nolock) 
          on GESM.GeoEntitySiteId = PHAP.GeoEntitySiteId inner join TBL_ET_PhyAppointUserMapping PAUM (nolock) 
          on PHAP.PhysicalAppointmentId = PAUM.PhysicalAppointmentId 
                left join tbl_tsk_TaskActionPermission(nolock) ap on PHAP.TaskTypeId = ap.task_type_id  
          Where PAUM.UserId = @UserId 
            and cast(GETDATE() as date) between cast(PHAP.StartDate as date) and cast(PHAP.EndDate as date)
            -- Exclude appointments that are 'Completed' for today (both CheckIn and CheckOut exist today)
            and NOT EXISTS (
                SELECT 1 FROM TBL_ET_GeoEntityCheckInOut g
                WHERE g.PhysicalAppointmentId = PHAP.PhysicalAppointmentId
                  AND g.UserId = PAUM.UserId
                  AND g.CheckIn IS NOT NULL
                  AND g.CheckOut IS NOT NULL
                  AND CAST(g.CheckIn as date) = CAST(g.CheckOut as date)
                  AND CAST(g.CheckIn as date) = CAST(GETDATE() as date)
            );
    END

    END TRY
    BEGIN CATCH
     DECLARE @ErrorMessage NVARCHAR(4000);
     SELECT @ErrorMessage = ERROR_MESSAGE();
     RAISERROR (@ErrorMessage,16,1);
    END CATCH
END



GO

