   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_TBL_ET_GeoEntityCheckInOutReqApproval] (
	@Mode VARCHAR(2),
	@GeoEntityChkInOutReqApprovalId bigint = 0,
	@GeoEntityChkInOutRequestId bigint = 0,
	@PhysicalAppointmentId bigint = 0,
	@UserId bigint = 0,
	@ActionType  VARCHAR(15) = NULL,
	@ScheduledDateTime DateTime = NULL,
	@ActionDateTime DateTime = NULL,
	@Remarks VARCHAR(500) = NULL,
	@ApprovedBy bigint = 0,
	@ApproverStatus  VARCHAR(15) = NULL,
	@ApprovedDate DateTime = NULL,
	@ParentId bigint = 0,
	@RequestDate DateTime = NULL,
	@CreatedBy bigint = 0,
	@IsActive bit = 1
	)
AS
SET NOCOUNT ON

BEGIN TRY
Select @ParentId = ParentId from User_detail(nolock) where User_Id = @CreatedBy
	IF (@Mode = 'CI') /*This is for Insert Details */
	BEGIN
	DECLARE @ID BIGINT;
	if (Not Exists (Select * from TBL_ET_GeoEntityCheckInOutRequest(nolock) where RequestDate = @RequestDate and Cast(ActionDateTime as Date) = Cast(@ActionDateTime as Date)))
		Begin
			INSERT INTO TBL_ET_GeoEntityCheckInOutRequest (
				PhysicalAppointmentId,
				UserId,
				ActionType,
				ScheduledDateTime,
				ActionDateTime,
				Remarks,
				ParentId,
				RequestDate,
				CreatedDate,
				CreatedBy,
				IsActive
				)
			VALUES (
				@PhysicalAppointmentId
				,@UserId
				,@ActionType
				,@ScheduledDateTime
				,@ActionDateTime
				,@Remarks
				,@ParentId
				,@RequestDate
				,GETDATE()				
				,@UserId
				,@IsActive
				)

			SET @ID = scope_identity();

		SELECT 'Record Saved' STATUS, @ID GeoEntityChkInOutRequestId

       	Select GETDATE()

		END
		ELSE
		BEGIN
			SELECT 'Record Already Exist' STATUS

	       	Select GETDATE()
		END
	END /*End here for insert*/
	Else IF (@Mode = 'CU') /*This is for Insert Details */
	BEGIN
	if (Exists(Select GeoEntityChkInOutRequestId from TBL_ET_GeoEntityCheckInOutRequest(nolock) where GeoEntityChkInOutRequestId = @GeoEntityChkInOutRequestId))
		Begin
			Update TBL_ET_GeoEntityCheckInOutRequest 
			set
				PhysicalAppointmentId = @PhysicalAppointmentId, UserId = @UserId, ActionType = @ActionType, ScheduledDateTime = @ScheduledDateTime,
				ActionDateTime = @ActionDateTime, Remarks = @Remarks, ParentId = @ParentId, RequestDate = @RequestDate, 
				CreatedDate = GETDATE(), CreatedBy = @CreatedBy, IsActive = @IsActive
				where GeoEntityChkInOutRequestId = @GeoEntityChkInOutRequestId
		SELECT 'Record Updated' STATUS, @GeoEntityChkInOutRequestId GeoEntityChkInOutRequestId

       	Select GETDATE()

		END
		ELSE
		BEGIN
			SELECT 'Record Not Exist' STATUS

	       	Select GETDATE()
		END
	END /*End here for insert*/
	Else IF (@Mode = 'AP') /*This is for Insert Details */
	BEGIN
	DECLARE @ID5 BIGINT;
	if (Not Exists (Select * from TBL_ET_GeoEntityCheckInOutRequest(nolock) where RequestDate = @RequestDate and Cast(ActionDateTime as Date) = Cast(@ActionDateTime as Date)))
		Begin
			INSERT INTO TBL_ET_GeoEntityCheckInOutRequestApproval (GeoEntityChkInOutRequestId, ApproverRemarks, ApprovedBy, ApproverStatus, ApprovedDate, CreatedDate, CreatedBy, IsActive)
			VALUES (@GeoEntityChkInOutRequestId, @Remarks, @ApprovedBy, @ApproverStatus, GETDATE(), GETDATE(), @UserId, @IsActive)

			SET @ID = scope_identity();

		SELECT 'Record Saved' STATUS, @ID5 GeoEntityChkInOutReqApprovalId

       	Select GETDATE()

		END
		ELSE
		BEGIN
			SELECT 'Record Already Exist' STATUS

	       	Select GETDATE()
		END
	END /*End here for insert*/
	Else IF (@Mode = 'AI') /*This is for Update Details */
	BEGIN
	if(Not Exists (select GeoEntityChkInOutReqApprovalId from TBL_ET_GeoEntityCheckInOutRequestApproval(nolock) where GeoEntityChkInOutRequestId = @GeoEntityChkInOutRequestId  and ApproverStatus = @ApproverStatus))
	Begin
	Declare @Id2 bigint

			INSERT INTO TBL_ET_GeoEntityCheckInOutRequestApproval (
				GeoEntityChkInOutRequestId
				,ApproverRemarks
				,ApprovedBy
				,ApproverStatus
				,ApprovedDate
				,CreatedDate
				,CreatedBy
				,IsActive
				)
			VALUES (
				 @GeoEntityChkInOutRequestId
				,@Remarks
				,@ApprovedBy
				,@ApproverStatus
				,GETDATE()
				,GETDATE()
				,@CreatedBy
				,@IsActive
				)
		SELECT 'Record Saved' STATUS, @Id GeoEntityChkInOutReqApprovalId
       End
		ELSE
		BEGIN
			SELECT 'Record Already Exists.' STATUS
		END

       	Select GETDATE()
	END /*End here for update*/
	Else IF (@Mode = 'AU') /*This is for Update Details */
	BEGIN
	if(Exists(Select GeoEntityChkInOutRequestId from TBL_ET_GeoEntityCheckInOutRequestApproval(nolock) where GeoEntityChkInOutRequestId= @GeoEntityChkInOutRequestId and ApproverStatus = @ApproverStatus and Cast(ApprovedDate as Date) = cast(@ApprovedDate as Date)))
	Begin
			Update TBL_ET_GeoEntityCheckInOutRequestApproval set  GeoEntityChkInOutRequestId = @GeoEntityChkInOutRequestId, 
				ApproverRemarks = @Remarks, ApprovedBy = @ApprovedBy, ApproverStatus = @ApproverStatus, 
				ApprovedDate = GETDATE(), CreatedDate = GetDate(), CreatedBy = @CreatedBy, IsActive = @IsActive
				where GeoEntityChkInOutReqApprovalId = @GeoEntityChkInOutReqApprovalId
		SELECT 'Record Updated' STATUS, @GeoEntityChkInOutReqApprovalId GeoEntityChkInOutReqApprovalId
       End
		ELSE
		BEGIN
			SELECT 'Record Not Exists.' STATUS
		END

       	Select GETDATE()
	END /*End here for update*/

END TRY

BEGIN CATCH
	DECLARE @ErrorMessage NVARCHAR(4000);
	SELECT @ErrorMessage = ERROR_MESSAGE();
	RAISERROR (
			@ErrorMessage
			,16
			,1
			);
END CATCH



