/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_GeoEntitySiteMasterSave]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- usp_TBL_ET_GeoEntitySiteMasterSave @Mode='SS',@CreatedBy=32222,@PageSize=50
CREATE   PROCEDURE  [dbo].[usp_TBL_ET_GeoEntitySiteMasterSave] 
(  
 @Mode VARCHAR(2)  
 ,@GeoEntitySiteId bigint = 0  
 ,@GeoEntitySiteName varchar(200) = ''  
 ,@GeoEntityType varchar(200) = null  
 ,@EntityId bigint = 0  
 ,@Mobile varchar(100) = null  
 ,@EmailId varchar(100) = null  
 ,@Latitude varchar(100) = null  
 ,@Longitude varchar(100) = null  
 ,@MapAddress varchar(100) = null  
 ,@Address varchar(100) = null  
 ,@City varchar(100) = null  
 ,@State varchar(100) = null  
 ,@Country varchar(100) = null  
 ,@PinCode varchar(100) = null  
 ,@CreatedBy bigint = 0  
 ,@Contain nvarchar(100) = ''  
 ,@Offset int = 0  
 ,@PageSize int = 10  
 ,@IsActive bit = 1  
)  
AS  
SET NOCOUNT ON  
  
BEGIN TRY  


--declare
--	@Mode VARCHAR(2)  = N'SI'
--	,@GeoEntitySiteId bigint = 0  
--	,@GeoEntitySiteName varchar(200) = N'test branch change2'  
--	,@GeoEntityType varchar(200) = N'Branch'  
--	,@EntityId bigint = 58  
--	,@Mobile varchar(100) = null  
--	,@EmailId varchar(100) = null  
--	,@Latitude varchar(100) = null  
--	,@Longitude varchar(100) = null  
--	,@MapAddress varchar(100) = null  
--	,@Address varchar(100) = null  
--	,@City varchar(100) = null  
--	,@State varchar(100) = null  
--	,@Country varchar(100) = null  
--	,@PinCode varchar(100) = null  
--	,@CreatedBy bigint = 0  
--	,@Contain nvarchar(100) = ''  
--	,@Offset int = 0  
--	,@PageSize int = 10  
--	,@IsActive bit = 1  


 Declare @ParentId bigint  
 Select @ParentId = ParentId from User_Detail(NOLOCK) where User_ID = @CreatedBy  
  
 IF (@Mode = 'SI') /*This is for Insert Details */  
 BEGIN  
 DECLARE @ID BIGINT;  
  
 if(Not Exists(select top 1 GeoEntitySiteId from TBL_ET_GeoEntitySiteMaster(nolock) gesm  
 inner join TBL_ET_GeoEntityMaster (nolock) goem on gesm.GeoEntityId = goem.GeoEntityId   
 where gesm.GeoEntitySiteName = @GeoEntitySiteName and goem.ParentId = @ParentId and gesm.IsActive = 1))  
 Begin  
  
 Declare @GeoEntityId bigint  

 if(isnull(@GeoEntityType, '') = 'branch')
 begin
	print 'branch pickup'

	 Select @Mobile = mobile, @EmailId = emailid, @Latitude = latitude, @Longitude = longitude, @MapAddress = [address],
		@Address = [address],
		@City = (select top 1 City_Name from m_city1(nolock) where City_ID = city_id),
		@State = (select top 1 State_Name from m_state1(nolock) where State_ID = state_id),
		@Country = (select top 1 Country_Name from m_country1(nolock) where Country_ID = country_id),
		@PinCode = pincode
		from tbl_inv_UserTaxNumber (nolock) tiut Where id = @EntityId 

 end
 
 INSERT INTO TBL_ET_GeoEntityMaster( GeoEntityName, GeoEntityType, EntityId, Mobile, EmailId, ParentId,
	CreatedDate, CreatedBy, IsActive)  
 select '', @GeoEntityType, @EntityId, @Mobile, @EmailId, @ParentId, GetDate(), @CreatedBy, 1
   
 set @GeoEntityId = SCOPE_IDENTITY()  
  
  INSERT INTO TBL_ET_GeoEntitySiteMaster (GeoEntitySiteName, GeoEntityId, Latitude, Longitude, MapAddress, Address, City, State, Country, PinCode, CreatedDate, CreatedBy, IsActive)  
  select @GeoEntitySiteName, @GeoEntityId, @Latitude, @Longitude, @MapAddress, @Address, @City, @State, @Country, @PinCode, GETDATE(), @CreatedBy, @IsActive
  
  SET @ID = scope_identity();  
  
  SELECT 'Record Saved' STATUS, @ID GeoEntitySiteId  
 End  
 ELSE  
 BEGIN  
  SELECT 'Record Already Exist' STATUS  
 END  
 END /*End here for insert*/  
  
 Else IF (@Mode = 'SU') /*This is for Update Details */  
 BEGIN  
  if(Exists(select GeoEntitySiteId from TBL_ET_GeoEntitySiteMaster(nolock) where GeoEntitySiteId = @GeoEntitySiteId))  
 Begin  
   
 set @GeoEntityId = (select top 1 GeoEntityId from TBL_ET_GeoEntitySiteMaster(nolock) where GeoEntitySiteId = @GeoEntitySiteId)  
  
 Update TBL_ET_GeoEntityMaster set GeoEntityName = '', GeoEntityType = @GeoEntityType, EntityId = @EntityId, Mobile = @Mobile, EmailId = @EmailId, UpdatedDate = GETDATE(), UpdatedBy = @CreatedBy, IsActive = 1 Where GeoEntityId = @GeoEntityId  
  
 Update TBL_ET_GeoEntitySiteMaster set GeoEntitySiteName = @GeoEntitySiteName  
    ,GeoEntityId = @GeoEntityId  
    ,Latitude = @Latitude  
    ,Longitude = @Longitude  
    ,MapAddress = @MapAddress  
    ,Address = @Address  
    ,City = @City  
    ,State = @State  
    ,Country = @Country  
    ,PinCode = @PinCode  
    ,IsActive = @IsActive  
    ,UpdatedBy = @CreatedBy  
    ,UpdatedDate = GETDATE()      
    where GeoEntitySiteId = @GeoEntitySiteId  
  
  SELECT 'Record Updated' STATUS, @GeoEntitySiteId GeoEntitySiteId  
  
        Select GETDATE()  
  
       End  
  ELSE  
  BEGIN  
   SELECT 'Update Issue.' STATUS  
        Select GETDATE()  
  END  
 END /*End here for update*/  
  
 Else IF (@Mode = 'SL') /*This is List Details */  
 BEGIN  
 Select GeoEntitySiteId  
 ,GeoEntitySiteName  
 ,sm.GeoEntityId  
 ,Latitude  
 ,Longitude  
 ,MapAddress  
 ,sm.Address  
 ,sm.City  
 ,sm.State  
 ,sm.Country  
 ,sm.PinCode  
 , Concat(ud.FName, '' , isnull(ud.LName, '')) CreatedByName   
 , Concat(ud2.FName, '' , isnull(ud2.LName, '')) UpdatedByName   
 ,sm.CreatedDate  
 ,sm.CreatedBy  
 ,sm.UpdatedDate  
 ,sm.UpdatedBy  
 ,sm.IsActive from TBL_ET_GeoEntitySiteMaster (nolock) sm   
 left join TBL_ET_GeoEntityMaster (nolock) em on sm.GeoEntityId  = em.GeoEntityId   
 left join User_Detail (nolock) ud on sm.CreatedBy = ud.User_ID  
 left join User_Detail (nolock) ud2 on sm.UpdatedBy = ud2.User_ID  
 where sm.GeoEntitySiteId = (case when @GeoEntitySiteId > 0 then @GeoEntitySiteId else  
 sm.GeoEntitySiteId end)  
 and sm.GeoEntitySiteName like '%' + @GeoEntitySiteName + '%'  
 and em.ParentId = @ParentId  
 END /*End here for list */  
 Else IF (@Mode = 'SS') /*This is List Details */  
 BEGIN  
  
 if(@Contain != '')  
 Begin  
 set @Contain = ' and IsActive = ''' + @Contain + ''  
 End  
  
Declare @query nvarchar(max)  
set @query = ' Select count(GeoEntitySiteId) over() as TotalRecords, GeoEntitySiteId, GeoEntityType, GeoEntitySiteName, (case when em.GeoEntityType = ''Branch'' then isnull(utnbranch.name, '''') else '''' End) GeoEntityName,  
 sm.GeoEntityId, sm.Latitude, sm.Longitude, sm.MapAddress, sm.Address  
 ,sm.City, sm.State, sm.Country, sm.PinCode  
 , Concat(ud.FName, '''' , isnull(ud.LName, '''')) CreatedByName   
 , Concat(ud2.FName, '''' , isnull(ud2.LName, '''')) UpdatedByName   
 ,sm.CreatedDate, sm.CreatedBy, sm.UpdatedDate, isnull(sm.UpdatedBy, 0) UpdatedBy,sm.IsActive 
 from TBL_ET_GeoEntitySiteMaster (nolock) sm   
 left join TBL_ET_GeoEntityMaster (nolock) em on sm.GeoEntityId  = em.GeoEntityId   
 left join tbl_inv_UserTaxNumber (nolock) utnbranch 
 on em.EntityId = utnbranch.id and  em.GeoEntityType = ''Branch''  
 left join User_Detail (nolock) ud on sm.CreatedBy = ud.User_ID  
 left join User_Detail (nolock) ud2 on sm.UpdatedBy = ud2.User_ID  
 where sm.IsActive=1 and sm.GeoEntitySiteId = (case when '+ cast(@GeoEntitySiteId as varchar(10))+ ' > 0 then '+ cast(@GeoEntitySiteId as varchar(10))+ ' else  
 sm.GeoEntitySiteId end)  
 and sm.GeoEntitySiteName like ''%'+ cast(@GeoEntitySiteName as varchar(200))+ '%'' and em.ParentId = '+ cast(@ParentId as varchar(10))+ ' ' + @Contain + '  
 Order By sm.GeoEntitySiteId Desc  
 Offset '+ cast(@Offset as varchar(10)) + ' rows fetch next '+ cast(@PageSize as varchar(10)) + ' rows only '  
   
 print @query  
  
  execute sp_executesql @query  
  
 END /*End here for list */  
 Else IF (@Mode = 'SD') /*This is List Details */  
 BEGIN  
  
--Select count(GeoEntitySiteId) over() as TotalRecords, GeoEntitySiteId, GeoEntitySiteName, '' GeoEntityName, isnull(em.Mobile, '') Mobile, isnull(em.EmailId, '')EmailId, sm.GeoEntityId, Latitude, Longitude, MapAddress, sm.Address, sm.City, sm.State, sm.Country, isnull(sm.PinCode, '') PinCode  
-- , Concat(ud.FName, ' ' , isnull(ud.LName, ' ')) CreatedByName   
-- , Concat(ud2.FName, ' ' , isnull(ud2.LName, ' ')) UpdatedByName   
-- ,sm.CreatedDate, sm.CreatedBy, sm.UpdatedDate, isnull(sm.UpdatedBy, 0) UpdatedBy  
-- ,sm.IsActive from TBL_ET_GeoEntitySiteMaster (nolock) sm   
-- left join TBL_ET_GeoEntityMaster (nolock) em on sm.GeoEntityId  = em.GeoEntityId   
-- left join User_Detail (nolock) ud on sm.CreatedBy = ud.User_ID  
-- left join User_Detail (nolock) ud2 on sm.UpdatedBy = ud2.User_ID  
-- where sm.GeoEntitySiteId = @GeoEntitySiteId   
  
Select count(GeoEntitySiteId) over() as TotalRecords, GeoEntitySiteId, GeoEntitySiteName,   
(case when em.GeoEntityType = 'Branch' then isnull(utnbranch.name, '')  
else '' End) GeoEntityName, GeoEntityType, isnull(em.Mobile, '') Mobile, isnull(em.EmailId, '')EmailId, sm.GeoEntityId, sm.Latitude, sm.Longitude, sm.MapAddress, sm.Address, sm.City, sm.State, sm.Country, isnull(sm.PinCode, '') PinCode  
 , Concat(ud.FName, ' ' , isnull(ud.LName, ' ')) CreatedByName   
 , Concat(ud2.FName, ' ' , isnull(ud2.LName, ' ')) UpdatedByName   
 ,sm.CreatedDate, sm.CreatedBy, sm.UpdatedDate, isnull(sm.UpdatedBy, 0) UpdatedBy  
 ,sm.IsActive from TBL_ET_GeoEntitySiteMaster (nolock) sm   
 left join TBL_ET_GeoEntityMaster (nolock) em on sm.GeoEntityId  = em.GeoEntityId   
 left join tbl_inv_UserTaxNumber (nolock) utnbranch on em.EntityId  = utnbranch.id and  em.GeoEntityType = 'Branch'  
 left join User_Detail (nolock) ud on sm.CreatedBy = ud.User_ID  
 left join User_Detail (nolock) ud2 on sm.UpdatedBy = ud2.User_ID  
 where sm.GeoEntitySiteId = @GeoEntitySiteId   
  
 END /*End here for list */  
 Else If(@Mode = 'DS') /* Disable Site */
 Begin
	Update TBL_ET_GeoEntitySiteMaster Set IsActive=0 Where GeoEntitySiteId=@GeoEntitySiteId
	
	SELECT 'Record Deleted' STATUS, @ID GeoEntitySiteId  
 End
  
END TRY  
BEGIN CATCH  
 DECLARE @ErrorMessage NVARCHAR(4000);  
 SELECT @ErrorMessage = ERROR_MESSAGE();  
 RAISERROR (  
   @ErrorMessage  
   ,16  
   ,1  
   );  
END CATCH  




GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_GeoEntitySitePoolSave]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--usp_TBL_ET_GeoEntitySitePoolSave 'SI', 0, 1, 1, '66', '27', 'addresss', 'Add', 'cit', 'stat', Indi, '11', GetDate(), 34594     
--usp_TBL_ET_GeoEntitySitePoolSave @Mode='SS', @CreatedBy=32222  
--exec usp_TBL_ET_GeoEntitySitePoolSave @Mode=N'SU',@GeoEntitySitePoolId=11,@GeoEntitySitePoolName=N'pool1',@GeoEntitySiteId=0,@GeoEntitySiteIds=N'44#147#16',@CreatedBy=32222,@IsActive=1  
--exec usp_TBL_ET_GeoEntitySitePoolSave @Mode=N'SU',@GeoEntitySitePoolId=25,@GeoEntitySitePoolName=N'ANANDAM Sitepool',@GeoEntitySiteId=0,@GeoEntitySiteIds=N'165#167',@CreatedBy=41923,@IsActive=1
--exec usp_TBL_ET_GeoEntitySitePoolSave @Mode=N'SU',@GeoEntitySitePoolId=18,@GeoEntitySitePoolName=N'SOLITAIRE SITEPOOL',@GeoEntitySiteId=0,@GeoEntitySiteIds=N'171#264',@CreatedBy=41923,@IsActive=1
CREATE   PROCEDURE [dbo].[usp_TBL_ET_GeoEntitySitePoolSave]
(    
  @Mode VARCHAR(2)    
 ,@GeoEntitySitePoolId bigint = 0    
 ,@GeoEntitySitePoolName varchar(200) = ''    
 ,@GeoEntitySiteId bigint = 0    
 ,@GeoEntitySiteIds nvarchar(4000) = ''    
 ,@CreatedBy bigint = 0    
 ,@Contain nvarchar(100) = ''    
 ,@Offset int = 0    
 ,@PageSize int = 10    
 ,@IsActive bit = 1    
)    
AS    
SET NOCOUNT ON    
    
BEGIN TRY    
 Declare @ParentId bigint    
 Select @ParentId = ParentId from User_Detail(NOLOCK) where User_ID = @CreatedBy    
    
 IF (@Mode = 'SI') /*This is for Insert Details */    
 BEGIN    
 if(Not Exists(select top 1 GeoEntitySitePoolId from TBL_ET_GeoEntitySitePool(nolock) gesm     
 where gesm.GeoEntitySitePoolName = @GeoEntitySitePoolName and gesm.ParentId = @ParentId))    
 Begin    
    
 DECLARE @ID BIGINT;    
    
 INSERT INTO TBL_ET_GeoEntitySitePool (GeoEntitySitePoolName, ParentId, CreatedDate, CreatedBy, IsActive)    
 values( @GeoEntitySitePoolName, @ParentId, GETDATE(), @CreatedBy, @IsActive)    
    
 SET @ID = scope_identity();    
    
 INSERT INTO TBL_ET_GeoEntitySitePoolList (GeoEntitySitePoolId, GeoEntitySiteId, ParentId, CreatedDate, CreatedBy, IsActive)    
 SELECT @ID, item, @ParentId, GETDATE(), @CreatedBy, @IsActive FROM dbo.fu_SplitString(@GeoEntitySiteIds, '#')    
 print @GeoEntitySiteIds    
 SELECT 'Record Saved' STATUS, @ID GeoEntitySitePoolId  
  
 END    
 Else    
 Begin    
 SELECT 'Record Already Exists' STATUS, @ID GeoEntitySitePoolId    
 End    
 END /*End here for insert*/    
 Else IF (@Mode = 'SU') /*This is for Insert Details */    
 BEGIN    
 if(Not Exists(select top 1 GeoEntitySitePoolId from TBL_ET_GeoEntitySitePool(nolock) gesm     
  where gesm.GeoEntitySitePoolName = @GeoEntitySitePoolName and gesm.ParentId = @ParentId and gesm.IsActive=1 and gesm.GeoEntitySitePoolId != @GeoEntitySitePoolId))    
 Begin    
    
  DECLARE @ID2 BIGINT;    
    
  Update TBL_ET_GeoEntitySitePool set GeoEntitySitePoolName = @GeoEntitySitePoolName,     
  UpdatedDate = GETDATE(), UpdatedBy = @CreatedBy, IsActive =  @IsActive    
  where GeoEntitySitePoolId = @GeoEntitySitePoolId    
    
  SET @ID2 = @GeoEntitySitePoolId;    
  
  DELETE TBL_ET_GeoEntitySitePoolList WHERE ParentId = @ParentId and GeoEntitySitePoolId = @GeoEntitySitePoolId    
    
  INSERT INTO TBL_ET_GeoEntitySitePoolList (GeoEntitySitePoolId, GeoEntitySiteId, ParentId, CreatedDate, CreatedBy, IsActive)    
  SELECT @ID2, item, @ParentId, GETDATE(), @CreatedBy, @IsActive FROM dbo.fu_SplitString(@GeoEntitySiteIds, '#') where item not in (select GeoEntitySiteId from TBL_ET_GeoEntitySitePoolList where ParentId = @ParentId and GeoEntitySitePoolId = @GeoEntitySitePoolId)    
    
  SELECT 'Record Updated' STATUS, @ID2 GeoEntitySitePoolId    
  
 End  
 Else    
 Begin    
  SELECT 'Sitepool Name Already Exists' STATUS, @GeoEntitySitePoolId GeoEntitySitePoolId  
 End    
   
 END /*End here for insert*/    
 Else IF (@Mode = 'SL') /*This is List Details */    
 BEGIN     
 Select GeoEntitySitePoolId, GeoEntitySitePoolName, '' GeoEntitySiteNames    
 , Concat(ud.FName, '' , isnull(ud.LName, '')) CreatedByName     
 , Concat(ud2.FName, '' , isnull(ud2.LName, '')) UpdatedByName     
 ,sp.CreatedDate, sp.CreatedBy, sp.UpdatedDate, sp.UpdatedBy     
 ,sp.IsActive from TBL_ET_GeoEntitySitePool sp     
 left join User_Detail (nolock) ud on sp.CreatedBy = ud.User_ID    
 left join User_Detail (nolock) ud2 on sp.UpdatedBy = ud2.User_ID    
 where sp.IsActive=1 and sp.GeoEntitySitePoolId = (case when @GeoEntitySitePoolId > 0 then @GeoEntitySitePoolId else sp.GeoEntitySitePoolId end)     
 and sp.GeoEntitySitePoolName like '%' + @GeoEntitySitePoolName + '%'     
 and sp.ParentId = @ParentId     
 END /*End here for list */     
 Else IF (@Mode = 'SS') /*This is List Details */    
 BEGIN    
 if(@Contain != '')    
 Begin    
 set @Contain = ' and IsActive = ''' + @Contain + ''    
 End    
    
Declare @query nvarchar(max)    
set @query = ' Select count(sp.GeoEntitySitePoolId) over() as TotalRecords, sp.GeoEntitySitePoolId, sp.GeoEntitySitePoolName,  isnull(dbo.fnGetGeoEntitySiteNamesBySitePool(sp.GeoEntitySitePoolId), ''No site'') GeoEntitySiteNames    
 , Concat(ud.FName, '''' , isnull(ud.LName, '''')) CreatedByName     
 , Concat(ud2.FName, '''' , isnull(ud2.LName, '''')) UpdatedByName     
 ,sp.CreatedDate, sp.CreatedBy, isnull(sp.UpdatedDate, sp.CreatedDate) UpdatedDate, isnull(sp.UpdatedBy, sp.CreatedBy) UpdatedBy,sp.IsActive   
 from TBL_ET_GeoEntitySitePool sp left join User_Detail (nolock) ud   
 on sp.CreatedBy = ud.User_ID left join User_Detail (nolock) ud2   
 on sp.UpdatedBy = ud2.User_ID     
 where sp.IsActive=1 and sp.GeoEntitySitePoolId = (case when '+ cast(@GeoEntitySitePoolId as varchar(10))+ ' > 0 then '+ cast(@GeoEntitySitePoolId as varchar(10))+ ' else sp.GeoEntitySitePoolId end)     
 and sp.GeoEntitySitePoolName like ''%' + @GeoEntitySitePoolName + '%''     
 and sp.ParentId = '+ cast(@ParentId as varchar(10)) + ' ' + @Contain + '    
 Order By sp.GeoEntitySitePoolId Desc    
 Offset '+ cast(@Offset as varchar(10)) + ' rows fetch next '+ cast(@PageSize as varchar(10)) + ' rows only '    
     
 print @query    
    
 execute sp_executesql @query    
    
 END /*End here for list */    
 Else IF (@Mode = 'SD') /*This is List Details */    
 BEGIN    
 Select GeoEntitySitePoolId, GeoEntitySitePoolName, dbo.fnGetGeoEntitySiteNamesBySitePool(sp.GeoEntitySitePoolId) GeoEntitySiteNames    
 , dbo.fnGetGeoEntitySiteIdsBySitePool(sp.GeoEntitySitePoolId) GeoEntitySiteIds    
 , Concat(ud.FName, '' , isnull(ud.LName, '')) CreatedByName     
 , Concat(ud2.FName, '' , isnull(ud2.LName, '')) UpdatedByName     
 ,sp.CreatedDate, sp.CreatedBy, sp.UpdatedDate, sp.UpdatedBy     
 ,sp.IsActive from TBL_ET_GeoEntitySitePool sp     
 left join User_Detail (nolock) ud on sp.CreatedBy = ud.User_ID    
 left join User_Detail (nolock) ud2 on sp.UpdatedBy = ud2.User_ID    
 where sp.IsActive=1 and sp.GeoEntitySitePoolId = @GeoEntitySitePoolId    
    
 Select sp.GeoEntitySitePoolListId, sp.GeoEntitySitePoolId, sp.ParentId, sp.GeoEntitySiteId,     
 isnull(gesm.GeoEntitySiteName, '') GeoEntitySiteName,    
 Concat(ud.FName, '' , isnull(ud.LName, '')) CreatedByName     
 , Concat(ud2.FName, '' , isnull(ud2.LName, '')) UpdatedByName     
 ,sp.CreatedDate, sp.CreatedBy, sp.UpdatedDate, sp.UpdatedBy     
 ,sp.IsActive from TBL_ET_GeoEntitySitePoolList sp     
 left join TBL_ET_GeoEntitySiteMaster (nolock) gesm on sp.GeoEntitySiteId = gesm.GeoEntitySiteId  
 left join User_Detail (nolock) ud on sp.CreatedBy = ud.User_ID    
 left join User_Detail (nolock) ud2 on sp.UpdatedBy = ud2.User_ID    
 where sp.IsActive=1 and sp.GeoEntitySitePoolId = @GeoEntitySitePoolId    
    
 END /*End here for list */    
 Else IF (@Mode = 'DL') /*This is List Details */    
 BEGIN    
     
 --Delete TBL_ET_GeoEntitySitePoolList where GeoEntitySitePoolId = @GeoEntitySitePoolId    
 --Delete TBL_ET_GeoEntitySitePool where GeoEntitySitePoolId = @GeoEntitySitePoolId    
 Update TBL_ET_GeoEntitySitePoolList Set IsActive=0 where GeoEntitySitePoolId = @GeoEntitySitePoolId    
 Update TBL_ET_GeoEntitySitePool Set IsActive=0 where GeoEntitySitePoolId = @GeoEntitySitePoolId    
    
 SELECT 'Record Deleted' STATUS, @GeoEntitySitePoolId GeoEntitySitePoolId  
     
 End    
END TRY    
BEGIN CATCH    
 DECLARE @ErrorMessage NVARCHAR(4000);    
 SELECT @ErrorMessage = ERROR_MESSAGE();    
 RAISERROR (    
   @ErrorMessage    
   ,16    
   ,1    
   );    
END CATCH    



GO

/* ============================================================
