--usp_TBL_ET_GeofenceDetailsByUserId 'SI', 0, 1, 1, '66', '27', 'addresss', 'Add', 'cit', 'stat', Indi, '11', GetDate(), 34594 
CREATE   PROCEDURE  [dbo].[usp_TBL_ET_GeofenceDetailsByUserId] (
	 @Mode VARCHAR(2)
	,@UserId bigint = 0
)
AS
SET NOCOUNT ON

BEGIN TRY
IF (@Mode = 'GL') /*This is for Insert Details */
BEGIN

select distinct teum.TerritoryId,teum.UserId, teum.ParentId,
gefl.GeofenceId, gefe.GeofenceName, Latitude, Longitude 
from TBL_ET_TerritoryUserMapping (nolock) teum
inner join TBL_ET_TerritoryMaster (nolock) tema on teum.TerritoryId = tema.TerritoryId
inner join TBL_ET_TerritoryGeofence (nolock) tegf on tema.TerritoryId = tegf.TerritoryId
inner join TBL_ET_GeofenceList (nolock) gefl on tegf.GeofenceId = gefl.GeofenceId
inner join TBL_ET_Geofence (nolock) gefe on gefl.GeofenceId = gefe.GeofenceId

where teum.UserId = @UserId
END

END TRY
BEGIN CATCH
	DECLARE @ErrorMessage NVARCHAR(4000);
	SELECT @ErrorMessage = ERROR_MESSAGE();
	RAISERROR (
			@ErrorMessage
			,16
			,1
			);
END CATCH



