/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_GeofenceSave]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec usp_TBL_ET_GeofenceSave @Mode=N'GI',@GeofenceId=0,@GeofenceName=N'TestGeoFence',@ParentId=32222,@CreatedBy=32222,@IsActive=1,@GeoFenceList=N'[{"Sno":1,"FenceType":"marker","Radius":0.0,"Longitude":77.02283,"Latitude":28.8045082},{"Sno":2,"FenceType":"marker","Radius":0.0,"Longitude":72.80408,"Latitude":19.2678719},{"Sno":3,"FenceType":"polygon","Radius":0.0,"Longitude":72.4525146,"Latitude":23.03755},{"Sno":3,"FenceType":"polygon","Radius":0.0,"Longitude":75.70447,"Latitude":26.9791355},{"Sno":3,"FenceType":"polygon","Radius":0.0,"Longitude":80.802124,"Latitude":26.9791355},{"Sno":3,"FenceType":"polygon","Radius":0.0,"Longitude":85.1966553,"Latitude":25.56055},{"Sno":3,"FenceType":"polygon","Radius":0.0,"Longitude":79.08826,"Latitude":20.8365021},{"Sno":3,"FenceType":"polygon","Radius":0.0,"Longitude":78.47302,"Latitude":17.3488255},{"Sno":4,"FenceType":"circle","Radius":218853.969,"Longitude":85.46033,"Latitude":34.3418655},{"Sno":5,"FenceType":"marker","Radius":0.0,"Longitude":88.27283,"Latitude":22.5513935},{"Sno":6,"FenceType":"marker","Radius":0.0,"Longitude":80.1429443,"Latitude":13.0241146},{"Sno":7,"FenceType":"circle","Radius":111673.984,"Longitude":66.21228,"Latitude":32.2111931},{"Sno":8,"FenceType":"polygon","Radius":0.0,"Longitude":68.58533,"Latitude":38.54668},{"Sno":8,"FenceType":"polygon","Radius":0.0,"Longitude":69.02478,"Latitude":41.3094},{"Sno":8,"FenceType":"polygon","Radius":0.0,"Longitude":71.39783,"Latitude":42.90677},{"Sno":8,"FenceType":"polygon","Radius":0.0,"Longitude":74.605835,"Latitude":42.90677},{"Sno":8,"FenceType":"polygon","Radius":0.0,"Longitude":74.38611,"Latitude":31.4645329},{"Sno":8,"FenceType":"polygon","Radius":0.0,"Longitude":72.80408,"Latitude":33.759304},{"Sno":8,"FenceType":"polygon","Radius":0.0,"Longitude":69.20056,"Latitude":34.5592957}]'   
-- exec usp_TBL_ET_GeofenceSave @Mode=N'SD',@GeofenceId=38
CREATE   PROCEDURE  [dbo].[usp_TBL_ET_GeofenceSave] 
(  
  @Mode VARCHAR(2)  
 ,@GeofenceId bigint = 0  
 ,@GeofenceName varchar(300) = ''  
 --,@FenceType varchar(50) = ''  
 --,@Latitude float=''  
 --,@Longitude float=''  
 --,@Radius float=''  
 ,@Contain nvarchar(100) = ''  
 ,@ParentId bigint = 0  
 ,@CreatedBy bigint = 0  
 ,@Offset int = 0  
 ,@PageSize int = 10  
 ,@IsActive bit = 1
 ,@GeoFenceList nvarchar(max)=null
 ,@MapPropJson nvarchar(max)=null
)  
AS  
SET NOCOUNT ON  
  
BEGIN TRY  
 Select @ParentId = ParentId from User_Detail(NOLOCK) where User_ID = @CreatedBy  
  
 IF (@Mode = 'GI') /*This is for Insert Details */  
 BEGIN  
 if(Not Exists(select top 1 GeofenceId from TBL_ET_Geofence(nolock) gesm   
 where gesm.GeofenceName = @GeofenceName and gesm.ParentId = @ParentId))  
 Begin  
  
 DECLARE @ID BIGINT;
 
 INSERT INTO TBL_ET_Geofence (GeofenceName, ParentId, CreatedDate, CreatedBy, IsActive, MapPropJson)  
 values( @GeofenceName, @ParentId, GETDATE(), @CreatedBy, @IsActive, @MapPropJson)  
  
 SET @ID = scope_identity();  
  
 INSERT INTO TBL_ET_GeofenceList (GeofenceId, sno, FenceType, Latitude, Longitude, Radius, ParentId, CreatedDate, CreatedBy, IsActive)  
   SELECT @ID, Sno, FenceType, Latitude, Longitude, Radius, @ParentId, GetDate(), @CreatedBy, @IsActive  
  FROM openjson(@GeoFenceList) WITH (  
     Sno int '$.Sno'  
    ,FenceType VARCHAR(50) '$.FenceType'  
    ,Radius float '$.Radius'  
    ,Longitude float '$.Longitude'  
    ,Latitude float '$.Latitude'  
    ) t  
 SET @ID = scope_identity();  
  
 SELECT 'Record Saved' STATUS, @ID GeofenceId  
  
 END  
 Else  
 Begin  
 SELECT 'Record Already Exist' STATUS, @ID GeofenceId  
 End  
 END /*End here for insert*/  
 Else IF (@Mode = 'GU') /*This is for Update Details */  
 BEGIN  
 if(Exists(select top 1 GeofenceId from TBL_ET_Geofence(nolock) gesm where gesm.GeofenceId = @GeofenceId))  
 Begin  
  
 DECLARE @ID2 BIGINT;  
  
 update TBL_ET_Geofence 
 set GeofenceName = @GeofenceName, UpdatedBy = @CreatedBy, UpdatedDate = GETDATE(), MapPropJson=@MapPropJson 
 where GeofenceId = @GeofenceId  
  
 SET @ID = @GeofenceId;  
  
 delete TBL_ET_GeofenceList where ParentId = @ParentId and GeofenceId = @GeofenceId  
  
 INSERT INTO TBL_ET_GeofenceList (GeofenceId, sno, FenceType, Latitude, Longitude, Radius, ParentId, CreatedDate, CreatedBy, IsActive)  
   SELECT @ID, Sno, FenceType, Latitude, Longitude, Radius, @ParentId, GetDate(), @CreatedBy, @IsActive  
  FROM openjson(@GeoFenceList) WITH (  
     Sno int '$.Sno'  
    ,FenceType VARCHAR(50) '$.FenceType'  
    ,Radius float '$.Radius'  
    ,Longitude float '$.Longitude'  
    ,Latitude float '$.Latitude'  
    ) t  
  
 SET @ID = scope_identity();  
  
 SELECT 'Record Updated' STATUS, @ID GeofenceId  
  
 END  
 Else  
 Begin  
 SELECT 'No updated' STATUS, @ID GeofenceId  
 End  
 END /*End here for insert*/  
  
 Else IF (@Mode = 'GL') /*This is List Details */  
 BEGIN   
 Select @ParentId = ParentId from User_Detail(NOLOCK) where User_ID = @CreatedBy  
  
 Select sp.GeofenceId, GeofenceName, '' Latitude, '' Longitude, '' MapAddress, sp.ParentId  
 , Concat(ud.FName, '' , isnull(ud.LName, '')) CreatedByName   
 , Concat(ud2.FName, '' , isnull(ud2.LName, '')) UpdatedByName   
 ,sp.CreatedDate, sp.CreatedBy, sp.UpdatedDate, sp.UpdatedBy, sp.MapPropJson   
 ,sp.IsActive from TBL_ET_Geofence sp   
 left join User_Detail (nolock) ud on sp.CreatedBy = ud.User_ID  
 left join User_Detail (nolock) ud2 on sp.UpdatedBy = ud2.User_ID  
 where sp.GeofenceId = (case when @GeofenceId > 0 then @GeofenceId else sp.GeofenceId end)   
 and sp.GeofenceName like '%' + @GeofenceName + '%'   
 and sp.ParentId = @ParentId   
 END /*End here for list */   
  
 Else IF (@Mode = 'SD') /*This is List Details */  
 BEGIN  
  
 Select sp.GeofenceId, GeofenceName, sp.ParentId  
 , Concat(ud.FName, '' , isnull(ud.LName, '')) CreatedByName   
 , Concat(ud2.FName, '' , isnull(ud2.LName, '')) UpdatedByName   
 ,sp.CreatedDate, sp.CreatedBy, sp.UpdatedDate, sp.UpdatedBy, sp.MapPropJson  
 ,sp.IsActive from TBL_ET_Geofence sp   
 left join User_Detail (nolock) ud on sp.CreatedBy = ud.User_ID  
 left join User_Detail (nolock) ud2 on sp.UpdatedBy = ud2.User_ID  
 where sp.GeofenceId = @GeofenceId and sp.IsActive=1
  
 Select * from TBL_ET_GeofenceList(nolock) sp where sp.GeofenceId = @GeofenceId and sp.IsActive=1
  
  
 END /*End here for list */  
 Else IF (@Mode = 'SS') /*This is List Details */  
 BEGIN  
  
   set @Contain = ''  
  
   Declare @query nvarchar(max)  
   set @query = ' Select count(sp.GeofenceId) over() as TotalRecords, sp.GeofenceId, sp.GeofenceName, Concat(ud.FName, '''' , isnull(ud.LName, '''')) CreatedByName, Concat(ud2.FName, '''' , isnull(ud2.LName, '''')) UpdatedByName, sp.CreatedDate, sp.CreatedBy, isnull(sp.UpdatedDate, sp.CreatedDate) UpdatedDate, isnull(sp.UpdatedBy, sp.CreatedBy) UpdatedBy, sp.MapPropJson, sp.IsActive 
   from TBL_ET_Geofence sp left join User_Detail (nolock) ud on sp.CreatedBy = ud.User_ID   
   left join User_Detail (nolock) ud2 on sp.UpdatedBy = ud2.User_ID   
   where sp.IsActive=1 and sp.GeofenceId = (case when '+ cast(@GeofenceId as varchar(10))+ ' > 0 then '+ cast(@GeofenceId as varchar(10))+ ' else sp.GeofenceId end)   
   and sp.GeofenceName like ''%' + @GeofenceName + '%''   
   and sp.ParentId = '+ cast(@ParentId as varchar(10)) + '  
      Order By sp.GeofenceId Desc  
      Offset '+ cast(@Offset as varchar(10)) + ' rows fetch next '+ cast(@PageSize as varchar(10)) + ' rows only '  
  
 print @query  
  
  execute sp_executesql @query  
  
 END /*End here for list */  
 Else If (@Mode = 'DG') /* Disable GeoFence */
 Begin
	Update TBL_ET_Geofence set IsActive=0 Where GeofenceId=@GeofenceId
	Update TBL_ET_GeofenceList set IsActive=0 Where GeofenceId=@GeofenceId

	 SELECT 'Record Deleted' STATUS, @GeofenceId GeofenceId  
 End
  
END TRY  
BEGIN CATCH  
 DECLARE @ErrorMessage NVARCHAR(4000);  
 SELECT @ErrorMessage = ERROR_MESSAGE();  
 RAISERROR (  
   @ErrorMessage  
   ,16  
   ,1  
   );  
END CATCH  



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_GetAttendance_Name]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_TBL_ET_GetAttendance_Name]
(
 @Mode VARCHAR(2)
 ,@SearchText varchar(200) = null  
 ,@FromDate nvarchar(100) = ''  
 ,@ToDate nvarchar(100) = ''  
 ,@AttendanceGroupId bigint = 0
 ,@Contain nvarchar(max) = ''
 ,@Condition nvarchar(max) = ''
 ,@UserId bigint = 0
 ,@Offset int = 0  
 ,@PageSize int = 10 
)
AS  
SET NOCOUNT ON  
  
BEGIN TRY 
 DECLARE @json NVARCHAR(MAX)

 Declare @ParentId bigint, @IsAdmin bit
 Select @IsAdmin = IsAdmin, @ParentId = ParentId from User_Detail(NOLOCK) where User_ID = @UserId

 set @json = isnull((Select top 1 HierarchyJSON from tbl_UA_UserHierarchy(nolock) where ParentId = @ParentId),'')

--SET @json='[{"user_id":39733,"team_name":"","user_login":"Avneesh905301","username":"Avneesh905301","parentid":0},{"user_id":39734,"team_name":"Manager","user_login":"39733-Head-Ops","username":"Headpresales ","parentid":39733},{"user_id":39759,"team_name":"","user_login":"39734-Tele-Sales","username":"Seema Bhat","parentid":39734},{"user_id":39767,"team_name":"","user_login":"39734-Telesales","username":"Seema Bhat","parentid":39734},{"user_id":39798,"team_name":"","user_login":"39733-Telesales1","username":"Aksa Bhat","parentid":39734}]'

--drop table if exists #TblHirarchy

--CREATE TABLE #TblHirarchy (
--	user_id bigint,
--	team_name varchar(200),
--	user_login varchar(200),
--	username varchar(200),
--	parentid bigint
--)

--insert into #TblHirarchy (user_id, team_name, user_login, username, parentid)
--SELECT user_id, team_name, user_login, username, parentid
--		FROM openjson(@json) WITH (
--				user_id bigint '$.user_id'
--				,team_name VARCHAR(200) '$.team_name'
--				,user_login varchar(200) '$.user_login'
--				,username varchar(200) '$.username'
--				,parentid bigint '$.parentid'
--				) t

 declare @UserIdTeamLst nvarchar(max) = '', @MonthYearName varchar(20) = ''
 declare @tbluser table (User_ID bigint,Name varchar(100), Image varchar(100))
 if(@IsAdmin = 1)
	begin
		set @UserId = 0;
		insert into @tbluser
		exec Use_GetUserDetails @ParentId
	end
	else
	Begin
		insert into @tbluser
		exec Use_GetUserDetails @UserId
	End

 select @UserIdTeamLst=isnull(STRING_AGG(User_ID,','),'') From @tbluser
set @MonthYearName = cast(DATENAME(mm, CONVERT(DATETIME,LEFT(@FromDate,10),105)) as varchar(10)) +' '+ cast(Year(CONVERT(DATETIME,LEFT(@FromDate,10),105)) as varchar(4))
if(@Contain != '')
Begin
set @Contain = ' and ' + @Contain
end
else
Begin
set @Contain = ''
End

IF (@Mode = 'AL') /*This is List Details */  
 BEGIN 

Declare @query nvarchar(max)
set @query = 'select count(t.AttendanceGroupId) over() as TotalRecords, * from (
select teum.AttendanceGroupId, teag.AttendanceGroupName,
(ud.FName + '' '' + ud.LName)  UserName, ud.Mobile,
ud.User_ID, ud.ParentID, ud.User_Login, 
ud.FName + '' '' + ud.LName + '' ('' +ud.User_Login + '')'' EmployeeName,
udpa.FName + '' '' + udpa.LName+ '' ('' +udpa.User_Login + '')'' ManagerParent, '''' Designetion, 
ud.Image, ud.ProfilePictureName,
''' + @MonthYearName + ''' MonthYearName,
dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, '''+ @FromDate + ''', ''TotalWorkingDay'') PresentDays, 
isnull(dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, '''+ @FromDate + ''', ''FullDays''),0) FullDays, 
dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, '''+ @FromDate + ''', ''HalfDays'') HalfDays, 
isnull(dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, '''+ @FromDate + ''', ''ShortDays''),0) ShortDays, 
dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, '''+ @FromDate + ''', ''WeekOff'') WeeklyOffDays, 
dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID,'''+ @FromDate + ''', ''TotalLeave'') OnLeaveDays, 
dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID,'''+ @FromDate + ''', ''TotalDays'') TotalDays, 
dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID,'''+ @FromDate + ''', ''LateSignin'') InLateDays, 
dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID,'''+ @FromDate + ''', ''OutEarlyDays'') OutEarlyDays,
dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID,'''+ @FromDate + ''', ''Totalminutes'') TotalAttendanceTime,
dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID,'''+ @FromDate + ''', ''NumberOfBreaks'') NumberOfBreaks,
dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID,'''+ @FromDate + ''', ''TimeInBreaks'') TimeInBreaks,
dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID,'''+ @FromDate + ''', ''MaxBreakTimes'') MaxBreakTimes,
dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID,'''+ @FromDate + ''', ''TotalTask'') TotalTask,
dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID,'''+ @FromDate + ''', ''TimeSpentInTasks'') TimeSpentInTasks,
isnull(dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID,'''+ @FromDate + ''', ''HolidayDays''),0) HolidayDays,
dbo.fn_TBL_ET_GeoEntityCheckInOutCount(ud.User_ID, cast('''+ @FromDate + ''' as varchar(20)), ''CheckInCount'') CheckInCount,   
dbo.fn_TBL_ET_GeoEntityCheckInOutCount(ud.User_ID, cast('''+ @FromDate + ''' as varchar(20)), ''CheckInRequest'') CheckInRequestCount,   
dbo.fn_TBL_ET_GeoEntityCheckInOutCount(ud.User_ID, cast('''+ @FromDate + ''' as varchar(20)), ''CheckOutCount'') CheckOutCount,   
dbo.fn_TBL_ET_GeoEntityCheckInOutCount(ud.User_ID, cast('''+ @FromDate + ''' as varchar(20)), ''CheckOutRequest'') CheckOutRequestCount,   
isnull(dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID,'''+ @FromDate + ''', ''SignIn''),0) SignInCount,
isnull(dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID,'''+ @FromDate + ''', ''SignInRequest''),0) SignInRequestCount,
isnull(dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID,'''+ @FromDate + ''', ''SignOut''),0) SignOutCount,
isnull(dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID,'''+ @FromDate + ''', ''SignOutRequest''),0) SignOutRequestCount,
dbo.fn_TBL_ET_ExpenseTotalSummary(ud.User_ID, '''+ @FromDate + ''', ''TotalTimeSpentTravelled'') TotalTimeSpentTravelled,
dbo.fn_TBL_ET_ExpenseTotalSummary(ud.User_ID, '''+ @FromDate + ''', ''TotalClaim'') TotalClaim,
dbo.fn_TBL_ET_ExpenseTotalSummary(ud.User_ID, '''+ @FromDate + ''', ''TotalApproved'') TotalApproved,
dbo.fn_TBL_ET_ExpenseTotalSummary(ud.User_ID, '''+ @FromDate + ''', ''TotalDistance'') TotalDistance,
isnull(dbo.fn_TBL_ET_ExpenseTotalSummary(ud.User_ID,'''+ @FromDate + ''', ''TotalTravelTime''), 0) TotalTravelTime,
'''' TeamName,  0 HirarchyParentid
from User_Detail(nolock) ud 
inner join TBL_ET_AttendanceGroupUserMapping(nolock) teum on ud.User_Id = teum.UserId
inner join TBL_ET_AttendanceGroup(nolock) teag on teum.AttendanceGroupId = teag.AttendanceGroupId
inner join User_Detail(nolock) udpa on ud.ParentId = udpa.User_Id
--inner join #TblHirarchy thia on ud.User_Id = thia.User_Id 
where (ud.User_ID in (select [value] from dbo.fn_Split(''' + @UserIdTeamLst + ''', '',''))
and teag.AttendanceGroupId = (case when '''+ cast(@AttendanceGroupId as varchar(10)) +''' > 0 then ''' + cast(@AttendanceGroupId as varchar(10)) + ''' else teag.AttendanceGroupId end))
)t where (1=1) '+ @Contain + ''

 print @query

 execute sp_executesql @query

 End
END TRY  
BEGIN CATCH  
 DECLARE @ErrorMessage NVARCHAR(4000); 
 SELECT @ErrorMessage = ERROR_MESSAGE(); 
 RAISERROR ( 
   @ErrorMessage 
   ,16 
   ,1 
   ); 
END CATCH 



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_GetAttendance_NameOld]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_TBL_ET_GetAttendance_NameOld]
(
 @Mode VARCHAR(2)
 ,@SearchText varchar(200) = null  
 ,@FromDate nvarchar(100) = ''  
 ,@ToDate nvarchar(100) = ''  
 ,@AttendanceGroupId bigint = 0
 ,@Contain nvarchar(max) = ''
 ,@UserId bigint = 0
 ,@Offset int = 0  
 ,@PageSize int = 10 
)
AS  
SET NOCOUNT ON  
  
BEGIN TRY 
 DECLARE @json NVARCHAR(MAX)

  Declare @ParentId bigint, @IsAdmin bit
 Select @IsAdmin = IsAdmin, @ParentId = ParentId from User_Detail(NOLOCK) where User_ID = @UserId

 Select top 1 @json = HierarchyJSON from tbl_UA_UserHierarchy(nolock) where ParentId = @ParentId

--SET @json='[{"user_id":39733,"team_name":"","user_login":"Avneesh905301","username":"Avneesh905301","parentid":0},{"user_id":39734,"team_name":"Manager","user_login":"39733-Head-Ops","username":"Headpresales ","parentid":39733},{"user_id":39759,"team_name":"","user_login":"39734-Tele-Sales","username":"Seema Bhat","parentid":39734},{"user_id":39767,"team_name":"","user_login":"39734-Telesales","username":"Seema Bhat","parentid":39734},{"user_id":39798,"team_name":"","user_login":"39733-Telesales1","username":"Aksa Bhat","parentid":39734}]'

drop table if exists #TblHirarchy

CREATE TABLE #TblHirarchy (
	user_id bigint,
	team_name varchar(200),
	user_login varchar(200),
	username varchar(200),
	parentid bigint
)

insert into #TblHirarchy (user_id, team_name, user_login, username, parentid)
SELECT user_id, team_name, user_login, username, parentid
		FROM openjson(@json) WITH (
				user_id bigint '$.user_id'
				,team_name VARCHAR(200) '$.team_name'
				,user_login varchar(200) '$.user_login'
				,username varchar(200) '$.username'
				,parentid bigint '$.parentid'
				) t

 declare @UserIdTeamLst varchar(500) = '', @MonthYearName varchar(20) = ''
 declare @tbluser table (User_ID bigint,Name varchar(100), Image varchar(100))
 if(@IsAdmin = 1)
	begin
		set @UserId = 0;
		insert into @tbluser
		exec Use_GetUserDetails @ParentId
	end
	else
	Begin
		insert into @tbluser
		exec Use_GetUserDetails @UserId
	End

 select @UserIdTeamLst=isnull(STRING_AGG(User_ID,','),'') From @tbluser
set @MonthYearName = cast(DATENAME(mm, Month(CONVERT(DATETIME,LEFT('01-03-2023',10),105))) as varchar(10)) +' '+ cast(Year(CONVERT(DATETIME,LEFT('01-03-2023',10),105)) as varchar(4))
IF (@Mode = 'AL') /*This is List Details */  
 BEGIN 
select count(t.AttendanceGroupId) over() as TotalRecords, * from (

select teum.AttendanceGroupId, teag.AttendanceGroupName,
(ud.FName + ' ' + ud.LName)  UserName, ud.Mobile,
ud.User_ID, ud.ParentID, ud.User_Login, 
ud.FName + ' ' + ud.LName + ' (' +ud.User_Login + ')' EmployeeName,
udpa.FName + ' ' + udpa.LName+ ' (' +udpa.User_Login + ')' ManagerParent, '' Designetion, isnull(thia.team_name, '') TeamName, '' InternalId
, isnull(thia.Parentid, 0) HirarchyParentid, ud.Image, ud.ProfilePictureName,
@MonthYearName MonthYearName,
dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, @FromDate, 'TotalWorkingDay') PresentDays, 
isnull(dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, @FromDate, 'FullDays'),0) FullDays, 
dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, @FromDate, 'HalfDays') HalfDays, 
isnull(dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, @FromDate, 'ShortDays'),0) ShortDays, 
dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, @FromDate, 'WeekOff') WeeklyOffDays, 
dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, @FromDate, 'TotalLeave') OnLeaveDays, 
dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, @FromDate, 'TotalDays') TotalDays, 
dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, @FromDate, 'LateSignin') InLateDays, 
dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, @FromDate, 'OutEarlyDays') OutEarlyDays,
dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, @FromDate, 'Totalminutes') TotalAttendanceTime,
dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, @FromDate, 'NumberOfBreaks') NumberOfBreaks,
dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, @FromDate, 'TimeInBreaks') TimeInBreaks,
dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, @FromDate, 'MaxBreakTimes') MaxBreakTimes,
dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, @FromDate, 'TotalTask') TotalTask,
dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, @FromDate, 'TimeSpentInTasks') TimeSpentInTasks,

isnull(dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, @FromDate, 'HolidayDays'),0) HolidayDays,

dbo.fn_TBL_ET_GeoEntityCheckInOutCount(ud.User_ID, cast(@FromDate as varchar(20)), 'CheckInCount') CheckInCount,   
dbo.fn_TBL_ET_GeoEntityCheckInOutCount(ud.User_ID, cast(@FromDate as varchar(20)), 'CheckInRequest') CheckInRequestCount,   
dbo.fn_TBL_ET_GeoEntityCheckInOutCount(ud.User_ID, cast(@FromDate as varchar(20)), 'CheckOutCount') CheckOutCount,   
dbo.fn_TBL_ET_GeoEntityCheckInOutCount(ud.User_ID, cast(@FromDate as varchar(20)), 'CheckOutRequest') CheckOutRequestCount,   

isnull(dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, @FromDate, 'SignIn'),0) SignInCount,
isnull(dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, @FromDate, 'SignInRequest'),0) SignInRequestCount,
isnull(dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, @FromDate, 'SignOut'),0) SignOutCount,
isnull(dbo.fn_TBL_ET_AttendanceTotalSummary(ud.User_ID, @FromDate, 'SignOutRequest'),0) SignOutRequestCount,


dbo.fn_TBL_ET_ExpenseTotalSummary(ud.User_ID, @FromDate, 'TotalTimeSpentTravelled') TotalTimeSpentTravelled,
dbo.fn_TBL_ET_ExpenseTotalSummary(ud.User_ID, @FromDate, 'TotalClaim') TotalClaim,
dbo.fn_TBL_ET_ExpenseTotalSummary(ud.User_ID, @FromDate, 'TotalApproved') TotalApproved,
dbo.fn_TBL_ET_ExpenseTotalSummary(ud.User_ID, @FromDate, 'TotalDistance') TotalDistance,
isnull(dbo.fn_TBL_ET_ExpenseTotalSummary(ud.User_ID, @FromDate, 'TotalTravelTime'), 0) TotalTravelTime
from User_Detail(nolock) ud 
inner join TBL_ET_AttendanceGroupUserMapping(nolock) teum on ud.User_Id = teum.UserId
inner join TBL_ET_AttendanceGroup(nolock) teag on teum.AttendanceGroupId = teag.AttendanceGroupId
inner join User_Detail(nolock) udpa on ud.ParentId = udpa.User_Id
inner join #TblHirarchy thia on ud.User_Id = thia.User_Id 
where (ud.User_ID in (select [value] from dbo.fn_Split(@UserIdTeamLst, ','))
and teag.AttendanceGroupId = (case when @AttendanceGroupId > 0 then @AttendanceGroupId else teag.AttendanceGroupId end))
--and ((geco.CheckIn between cast(@FromDate as date) and cast(@ToDate as date)) or 
--(geco.CheckOut between cast(@FromDate as date) and cast(@ToDate as date)))
)t


 End
END TRY  
BEGIN CATCH  
 DECLARE @ErrorMessage NVARCHAR(4000); 
 SELECT @ErrorMessage = ERROR_MESSAGE(); 
 RAISERROR ( 
   @ErrorMessage 
   ,16 
   ,1 
   ); 
END CATCH 



GO

