/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_GetLoactionNotification]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE  [dbo].[usp_TBL_ET_GetLoactionNotification] --'SignIn'                    
(
   @TypeOfAction nvarchar(100) = 'SignIn' 
)
AS
BEGIN
Declare @SignInRangeInMeter int 
Declare @Distance float 
Declare @Code nvarchar(200) = 'SignIn' 
Declare @Latitude1 float, @Latitude2 float, @Longitude1 float, @Longitude2 float
Declare @NotficationName nvarchar(500) 

Select @NotficationName = [Name] from TBL_ET_FieldCondition(nolock) where Code = @Code 
Drop table if exists #ListofUser 

CREATE TABLE #ListofUser (AttendanceGroupId bigint, UserId bigint, SignInRange int, BranchLatitude float, BranchLongitude float, ParentId bigint)
insert into #ListofUser (AttendanceGroupId, UserId, SignInRange, BranchLatitude, BranchLongitude, ParentId)
Select distinct atgp.AttendanceGroupId, atgu.UserId, atgp.SignInRange, aiut.latitude BranchLatitude, aiut.longitude BranchLongitude, 
atgp.ParentId
from TBL_ET_AttendanceGroup(nolock) atgp 
inner join TBL_ET_AttendanceGroupUserMapping(nolock) atgu on atgp.AttendanceGroupId = Atgu.AttendanceGroupId 
inner join TBL_ET_AttendanceGroupBranchMapping(nolock) atbm on atgp.AttendanceGroupId = atbm.AttendanceGroupId 
inner join tbl_inv_UserTaxNumber(nolock) aiut on atbm.BranchId = aiut.id
inner join TBL_ET_Attendance (nolock) teat on atgu.UserId = teat.UserId and Cast(teat.AttendanceIn as Date) != cast(GetDate() as Date)
Where atgp.IsActive = 1 and atgp.SignInType = 'Auto' 
 
INSERT INTO TBL_ET_Attendance (UserId, AttendanceIn, LatitudeIn, LongitudeIn, DeviceId, RemarksIn, RemarksOut, AttendanceGroupId, 
ShiftId, ParentId, IsActive, CreatedBy, CreatedDate) 
select t.UserId, GETDATE(), t.Latitude, t.Longitude, 'WebsiteAuto', '', '', t.AttendanceGroupId, t.ShiftId, t.ParentId, 1, t.UserId, GETDATE() 
from (Select lou.UserId, lou.SignInRange, lou.Latitude, lou.Longitude, 
dbo.fnCalcDistanceKM(lou.BranchLatitude, ult.Latitude, lou.BranchLongitude, ult.Longitude) distance, 
ult.Latitude, ult.Longitude, lou.AttendanceGroupId, suma.ShiftId from #ListofUser lou 
inner join TBL_ET_UserLocationTracking(nolock) ult on lou.UserId = ult.UserId and 
ult.UserLocationTrackingId in (select max(ab.UserLocationTrackingId) from TBL_ET_UserLocationTracking(nolock) ab 
 inner join TBL_ET_ShiftUserMapping suma (nolock) on lou.UserId = suma.UserId --and suma.IsActive = 1 
 where Cast(ult.LocationDateTime as Date) = cast(GetDate() as Date)  group by UserId) 
)t 
where t.distance < t.SignInRange
-- Notification For SignIn

--Insert into TBL_ET_ActionNotification (Code, NotficationName, UserId, ParentId, CreatedDate, CreatedBy, IsActive) 
select @Code Code, @Code + ' Notification' Notification, t.UserId, t.ParentId, GETDATE(), t.UserId, 1 
from (Select lou.UserId, lou.SignInRange, lou.Latitude, lou.Longitude, 
dbo.fnCalcDistanceKM(lou.BranchLatitude, ult.Latitude, lou.BranchLongitude, ult.Longitude) distance, 
ult.Latitude, ult.Longitude, lou.AttendanceGroupId, suma.ShiftId from #ListofUser lou 
inner join TBL_ET_UserLocationTracking(nolock) ult on lou.UserId = ult.UserId and 
ult.UserLocationTrackingId in (select max(ab.UserLocationTrackingId) from TBL_ET_UserLocationTracking(nolock) ab 
 inner join TBL_ET_ShiftUserMapping suma (nolock) on lou.UserId = suma.UserId --and suma.IsActive = 1 
 where Cast(ult.LocationDateTime as Date) = cast(GetDate() as Date)  group by UserId) 
)t 
where t.distance < t.SignInRange 

--Select 'Updated' Status 

END 



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_GetLoactionNotificationOthers]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--usp_tbl_ET_GetLoactionNotificationOthers 'UserLoggedinLate'
CREATE   PROCEDURE  [dbo].[usp_TBL_ET_GetLoactionNotificationOthers]
(
  @TypeOfAction nvarchar(100) = 'UserLoggedinLate'
)
AS
BEGIN
Declare @Code nvarchar(200) = @TypeOfAction
Declare @NotficationName nvarchar(500), @TimeInterval int, @TypeofInterval varchar(10), @countlimit int

if(@TypeOfAction = 'UserLoggedinLate')
Begin
--Declare @Code nvarchar(200) = 'UserLoggedinLate' 
--Declare @NotficationName nvarchar(500), @TimeInterval int
Select @NotficationName = [Name], @TimeInterval = TimeInterval from TBL_ET_FieldCondition(nolock) where Code = @Code 
--Select @NotficationName, @TimeInterval

insert into TBL_ET_ActionNotification (Code, NotficationName, UserId, ParentId, CreatedDate, CreatedBy, IsActive)
Select @Code, (tt.FName + ' ' + tt.LName + ' ' + tt.User_Login + ' ' + @NotficationName + ' ' + cast(Dtime as varchar(20)) + ' min(s) delay.'), UserId, ParentId, getdate(), UserId, 1 from ( 
Select distinct teat.AttendanceIn, tesm.ShiftName, tesm.StartTime, tesm.EndTime, 
convert(varchar(32), tesm.StartTime,108) Stime, convert(varchar(32),GETDATE(),108) Ctime,
convert(varchar(32), teat.AttendanceIn, 108) Atime,
DATEDIFF(minute, CONVERT(TIME, convert(varchar(32), tesm.StartTime,108)), CONVERT(TIME, convert(varchar(32), teat.AttendanceIn, 108))) Dtime, 
ud.FName, ud.LName, ud.User_Login, ud.ParentID,
tesu.UserId from TBL_ET_AttendanceGroupUserMapping(nolock) atgu 
inner join TBL_ET_Attendance (nolock) teat on atgu.UserId = teat.UserId and 
Cast(teat.AttendanceIn as Date) != cast(GetDate() as Date)
inner join TBL_ET_ShiftUserMapping (nolock) tesu on atgu.UserId = tesu.UserId and
cast(GetDate() as Date) between Cast(tesu.FromDate as Date) and Cast(tesu.ToDate as Date)
inner join TBL_ET_ShiftMaster (nolock) tesm on tesu.ShiftId = tesm.ShiftId
inner join User_Detail (nolock) ud on atgu.UserId = ud.User_ID
Where teat.IsActive = 1 and 
teat.AttendanceId in (select min(ab.AttendanceId) from TBL_ET_Attendance(nolock) ab where teat.UserId = ab.UserId)
and cast(teat.AttendanceIn as date) not in (select cast(teat.AttendanceIn as date) from TBL_ET_Attendance acn 
where cast(acn.AttendanceIn as date) = cast(getdate() as date)) 
) tt
where Dtime > @TimeInterval 

END
Else if(@TypeOfAction = 'LatecheckIn')
Begin 
--Declare @Code nvarchar(200) = 'LatecheckIn' 
--Declare @NotficationName nvarchar(500), @TimeInterval int
Select @NotficationName = [Name], @TimeInterval = TimeInterval from TBL_ET_FieldCondition(nolock) where Code = @Code 
--Select @NotficationName, @TimeInterval

insert into TBL_ET_ActionNotification (Code, NotficationName, UserId, ParentId, CreatedDate, CreatedBy, IsActive)
Select @Code, 
(tt.FName + ' ' + tt.LName + ' ' + tt.User_Login + ' ' + @NotficationName + ' ' + cast(Dtime as varchar(20)) + ' min(s) delay.'), 
UserId, ParentId, getdate(), UserId, 1 from ( 
Select distinct teecio.CheckIn, tesu.StartDate, tesu.EndDate, 
convert(varchar(32), tesu.StartDate,108) Stime, convert(varchar(32),GETDATE(),108) Ctime,
convert(varchar(32), teecio.CheckIn, 108) Atime,
DATEDIFF(minute, CONVERT(TIME, convert(varchar(32), tesu.StartDate,108)), CONVERT(TIME, convert(varchar(32), teecio.CheckIn, 108))) Dtime, 
ud.FName, ud.LName, ud.User_Login, ud.ParentID, ud.User_Id UserId from TBL_ET_AttendanceGroupUserMapping(nolock) atgu 
inner join TBL_ET_GeoEntityCheckInOut (nolock) teecio on atgu.UserId = teecio.UserId and 
Cast(teecio.CheckIn as Date) != cast(GetDate() as Date) 
inner join TBL_ET_PhysicalAppointment (nolock) tesu on teecio.PhysicalAppointmentId = tesu.PhysicalAppointmentId
inner join User_Detail (nolock) ud on atgu.UserId = ud.User_ID 
Where teecio.IsActive = 1 and 
teecio.GeoEntityCheckId in (select min(ab.GeoEntityCheckId) from TBL_ET_GeoEntityCheckInOut(nolock) ab where teecio.UserId = ab.UserId) 
and cast(teecio.CheckIn as date) not in (select cast(teecio.CheckIn as date) from TBL_ET_GeoEntityCheckInOut acn 
where cast(acn.CheckIn as date) = cast(getdate() as date)) 
) tt 
where Dtime > @TimeInterval 

END
if(@TypeOfAction = 'LocationnotCaptured')
Begin 
Select @NotficationName = [Name], @TimeInterval = TimeInterval from TBL_ET_FieldCondition(nolock) where Code = @Code 
--Select @NotficationName, @TimeInterval 

insert into TBL_ET_ActionNotification (Code, NotficationName, UserId, ParentId, CreatedDate, CreatedBy, IsActive)
Select @Code, 
(tt.FName + ' ' + tt.LName + ' ( ' + tt.User_Login + ' ) ' + @NotficationName + ' on ' + FORMAT (getdate(), 'dd-MM-yyyy') + '.'), 
UserId, ParentId, getdate(), UserId, 1 from ( 
select distinct  
ud.FName, ud.LName, ud.User_Login, ud.ParentID, ud.User_Id UserId, 
CONVERT(TIME, convert(varchar(32), tesm.StartTime,108)) aa, CONVERT(TIME, convert(varchar(32), cast(getdate() as time),108)) abc,
DATEDIFF(minute, CONVERT(TIME, convert(varchar(32), tesm.StartTime,108)), 
CONVERT(TIME, convert(varchar(32), cast(getdate() as time),108))) Dtime
from TBL_ET_AttendanceGroupUserMapping (nolock) agum
inner join TBL_ET_ShiftUserMapping (nolock) tesu on agum.UserId = tesu.UserId and
cast(GetDate() as Date) between Cast(tesu.FromDate as Date) and Cast(tesu.ToDate as Date)
inner join TBL_ET_ShiftMaster (nolock) tesm on tesu.ShiftId = tesm.ShiftId
inner join User_Detail (nolock) ud on agum.UserId = ud.User_ID 
Where agum.IsActive = 1 
and agum.UserId not in 
(select UserId from TBL_ET_UserLocationTracking(nolock) ulti where cast(ulti.LocationDateTime as date) = cast(getdate() as date)) 
) tt 

where Dtime > @TimeInterval 
End
if(@TypeOfAction = 'EarlyCheckOut')
Begin 
Select @NotficationName = [Name], @TimeInterval = TimeInterval from TBL_ET_FieldCondition(nolock) where Code = @Code 
--Select @NotficationName, @TimeInterval

insert into TBL_ET_ActionNotification (Code, NotficationName, UserId, ParentId, CreatedDate, CreatedBy, IsActive)
Select @Code, 
(tt.FName + ' ' + tt.LName + ' ' + tt.User_Login + ' ' + @NotficationName + ' ' + cast(Dtime as varchar(20)) + ' min(s) delay.'), 
UserId, ParentId, getdate(), UserId, 1 from ( 
Select distinct teecio.CheckIn, tesu.StartDate, tesu.EndDate, 
convert(varchar(32), tesu.EndDate,108) Stime, convert(varchar(32),GETDATE(),108) Ctime,
convert(varchar(32), teecio.CheckOut, 108) Atime,
DATEDIFF(minute, CONVERT(TIME, convert(varchar(32), teecio.CheckOut, 108)), CONVERT(TIME, convert(varchar(32), tesu.EndDate,108))) Dtime, 
ud.FName, ud.LName, ud.User_Login, ud.ParentID, ud.User_Id UserId from TBL_ET_AttendanceGroupUserMapping(nolock) atgu 
inner join TBL_ET_GeoEntityCheckInOut (nolock) teecio on atgu.UserId = teecio.UserId and 
Cast(teecio.CheckIn as Date) != cast(GetDate() as Date) 
inner join TBL_ET_PhysicalAppointment (nolock) tesu on teecio.PhysicalAppointmentId = tesu.PhysicalAppointmentId
inner join User_Detail (nolock) ud on atgu.UserId = ud.User_ID 
Where teecio.IsActive = 1 and 
teecio.GeoEntityCheckId in (select min(ab.GeoEntityCheckId) from TBL_ET_GeoEntityCheckInOut(nolock) ab where teecio.UserId = ab.UserId) 
and cast(teecio.CheckIn as date) not in (select cast(teecio.CheckIn as date) from TBL_ET_GeoEntityCheckInOut acn 
where cast(acn.CheckIn as date) = cast(getdate() as date)) 
) tt 
where Dtime > @TimeInterval 

END
if(@TypeOfAction = 'BreakTimetooLong')
Begin 
Select @NotficationName = [Name], @TimeInterval = TimeInterval from TBL_ET_FieldCondition(nolock) where Code = @Code 
--Select @NotficationName, @TimeInterval 
insert into TBL_ET_ActionNotification (Code, NotficationName, UserId, ParentId, CreatedDate, CreatedBy, IsActive)
Select @Code, 
(tt.FName + ' ' + tt.LName + ' ( ' + tt.User_Login + ' ) ' + @NotficationName + ' ' + cast(Dtime as varchar(10)) + ' min(s) from ' + FORMAT (tt.StartDate, 'hh:mm:ss') + ' to ' + FORMAT (tt.EndDate, 'hh:mm:ss')), 
UserId, ParentId, getdate(), UserId, 1 from ( 
Select tebt.StartDate, tebt.EndDate,
ud.FName, ud.LName, ud.User_Login, ud.ParentID, ud.User_Id UserId, 
DATEDIFF(minute, CONVERT(datetime, convert(varchar(32), tebt.StartDate,108)), CONVERT(datetime, convert(varchar(32), tebt.EndDate, 108))) Dtime
from TBL_ET_BreakTransaction(nolock) tebt 
inner join User_Detail (nolock) ud on tebt.UserId = ud.User_ID 
Where tebt.IsActive = 1 
and (cast(tebt.StartDate as date) < cast(getdate() as date)) 
) tt 
where Dtime > @TimeInterval 
END
if(@TypeOfAction = 'StaticLocationCaptured')
Begin 

Select @NotficationName = [Name], @TimeInterval = TimeInterval from TBL_ET_FieldCondition(nolock) where Code = @Code 
set @countlimit = (@TimeInterval/5)
--Select @NotficationName, @TimeInterval, @countlimit
insert into TBL_ET_ActionNotification (Code, NotficationName, UserId, ParentId, CreatedDate, CreatedBy, IsActive)

Select distinct @Code, 
(ud.FName + ' ' + ud.LName + ' ( ' + ud.User_Login + ' ) ' + @NotficationName + ' ' + cast(staticlatlongtotal as varchar(10)) + ' location(s)'), 
tt.UserId, ParentId, getdate(), tt.UserId, 1 from (
Select count(*) staticlatlongtotal, cast(tebt.LocationDateTime as date) LocationDate, tebt.Latitude, tebt.Longitude, tebt.UserId
from TBL_ET_UserLocationTracking(nolock) tebt 
Where tebt.IsActive = 1 
and (cast(tebt.LocationDateTime as date) = cast(getdate() as date))
group by cast(tebt.LocationDateTime as date), tebt.Latitude, tebt.Longitude, tebt.UserId
) tt 
inner join User_Detail (nolock) ud on tt.UserId = ud.User_ID 
where staticlatlongtotal > @countlimit 

END
if(@TypeOfAction = 'Userabsentwithoutleave')
Begin 

Select @NotficationName = [Name], @TimeInterval = TimeInterval from TBL_ET_FieldCondition(nolock) where Code = @Code 

--Select @NotficationName, @TimeInterval, @countlimit
insert into TBL_ET_ActionNotification (Code, NotficationName, UserId, ParentId, CreatedDate, CreatedBy, IsActive)

Select distinct @Code, 
(ud.FName + ' ' + ud.LName + ' ( ' + ud.User_Login + ' ) ' + @NotficationName + ' ' + cast(Dtime as varchar(10)) + ' after mins(s) checked'), 
tt.UserId, ud.ParentId, getdate(), tt.UserId, 1 from (
Select teum.UserId, tesm.*,
CONVERT(TIME, convert(varchar(32), tesm.StartTime,108)) Stime, CONVERT(TIME, convert(varchar(32), cast(getdate() as time),108)) Ctime,
DATEDIFF(minute, CONVERT(TIME, convert(varchar(32), tesm.StartTime,108)), 
CONVERT(TIME, convert(varchar(32), cast(getdate() as time),108))) Dtime
from TBL_ET_AttendanceGroupUserMapping(nolock) teum
inner join TBL_ET_ShiftUserMapping (nolock) tesu on teum.UserId = tesu.UserId and
cast(GetDate() as Date) between Cast(tesu.FromDate as Date) and Cast(tesu.ToDate as Date)
inner join TBL_ET_ShiftMaster (nolock) tesm on tesu.ShiftId = tesm.ShiftId
Where teum.IsActive = 1 
and teum.UserId not in 
(select UserId from TBL_ET_UserLocationTracking(nolock) ulti where cast(ulti.LocationDateTime as date) = cast(getdate() as date)) 
) tt 
inner join User_Detail (nolock) ud on tt.UserId = ud.User_ID 
where Dtime > @TimeInterval

END
if(@TypeOfAction = 'UserWorkedLessShiftTime')
Begin 

Select @NotficationName = [Name], @TimeInterval = TimeInterval from TBL_ET_FieldCondition(nolock) where Code = @Code 

--Select @NotficationName, @TimeInterval, @countlimit
insert into TBL_ET_ActionNotification (Code, NotficationName, UserId, ParentId, CreatedDate, CreatedBy, IsActive)

Select distinct @Code, 
(ud.FName + ' ' + ud.LName + ' ( ' + ud.User_Login + ' ) ' + @NotficationName + ' ' + cast(Dtime as varchar(10)) + ' after mins(s) checked'), 
tt.UserId, ud.ParentId, getdate(), tt.UserId, 1 from (
