inner join TBL_ET_ShiftMaster(nolock) tesm on tesu.ShiftId = tesm.ShiftId
Where teum.IsActive = 1 
and teum.UserId not in (select teul.UserId from TBL_ET_UserLocationTracking(nolock) teul where cast(teul.LocationDateTime as date) = cast(getdate() as date))
) tt
