/* ============================================================
   Procedure: [dbo].[usp_tbl_ET_GetLocationData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_tbl_ET_GetLocationData]  
(  
    @UserId bigint,  
    @FromDate datetime,  
    @ToDate datetime  
)  
AS  
BEGIN
    DECLARE @CurrentDate datetime = GETDATE();
    DECLARE @DateDiff int = DATEDIFF(DAY, @FromDate, @CurrentDate);

    IF @DateDiff > 30
    BEGIN
        -- Data from both tables
        SELECT *   
        FROM   
        (  
            SELECT row_number() OVER (PARTITION BY ROUND(Latitude, 4), ROUND(Longitude, 4) ORDER BY LocationDateTime) AS sno, *  
            FROM TBL_ET_UserLocationTracking (NOLOCK)  
            WHERE IsActive = 1 
            AND UserId = @UserId 
            AND CAST(LocationDateTime AS DATE) BETWEEN CAST(@FromDate AS DATE) AND CAST(@ToDate AS DATE)
            AND (ISNULL(Latitude, 0) > 0 OR ISNULL(Longitude, 0) > 0)

            UNION ALL

            SELECT row_number() OVER (PARTITION BY ROUND(Latitude, 4), ROUND(Longitude, 4) ORDER BY LocationDateTime) AS sno, *  
            FROM TBL_ET_UserLocationTracking_Archived (NOLOCK)  
            WHERE IsActive = 1 
            AND UserId = @UserId 
            AND CAST(LocationDateTime AS DATE) BETWEEN CAST(@FromDate AS DATE) AND CAST(@ToDate AS DATE)
            AND (ISNULL(Latitude, 0) > 0 OR ISNULL(Longitude, 0) > 0)
        ) T  
        WHERE T.sno = 1  
        ORDER BY LocationDateTime;
    END
    ELSE
    BEGIN
        -- Data from the active table only
        SELECT *   
        FROM   
        (  
            SELECT row_number() OVER (PARTITION BY ROUND(Latitude, 4), ROUND(Longitude, 4) ORDER BY LocationDateTime) AS sno, *  
            FROM TBL_ET_UserLocationTracking (NOLOCK)  
            WHERE IsActive = 1 
            AND UserId = @UserId 
            AND CAST(LocationDateTime AS DATE) BETWEEN CAST(@FromDate AS DATE) AND CAST(@ToDate AS DATE)
            AND (ISNULL(Latitude, 0) > 0 OR ISNULL(Longitude, 0) > 0)
        ) T  
        WHERE T.sno = 1  
        ORDER BY LocationDateTime;
    END
END



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_GetSiteVisitDetails_Name]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_TBL_ET_GetSiteVisitDetails_Name]
(
 @Mode VARCHAR(2),
 @SearchText varchar(200) = null,
 @FromDate nvarchar(100) = '',
 @ToDate nvarchar(100) = '',
 @UserId bigint = 0,
 @UserIds nvarchar(max) = '',
 @Offset int = 0,
 @PageSize int = 10,
 @Contain nvarchar(max) = ''
)
AS
SET NOCOUNT ON  
BEGIN
	BEGIN TRY 
		 
		 --declare
			--@Mode VARCHAR(2) = N'SL',
			--@SearchText varchar(200) = N'',
			--@FromDate nvarchar(100) = N'11-Sep-2024',
			--@ToDate nvarchar(100) = N'11-Sep-2024',
			--@UserId bigint = 46409,
			--@UserIds nvarchar(max) = N'46417,46415',
			--@Offset int = 0,
			--@PageSize int = 20,
			--@Contain nvarchar(max) = ''

		declare @ParentId bigint = 0;
		select @ParentId  = ParentID from User_Detail(nolock) where User_Id = @UserId


		drop table if exists #tempUsers   
		create table #tempUsers(User_ID bigint, Name nvarchar(255), Image nvarchar(255))  
		insert into #tempUsers(User_ID, Name, Image)  
		exec Use_GetUserDetails @UserID = @UserId  

		if(ISNULL(@UserIds, '') =  '') begin set @UserIds = '' end

		drop table if exists #tempSelectedUser
		create table #tempSelectedUser ( UserId bigint )
		insert into #tempSelectedUser(UserId) select [value] from string_split(@UserIds, ',')

		if(@Contain = '') begin set @Contain = '' end else begin set @Contain = ' and ' + @Contain end
		if(@SearchText = '') begin set @SearchText = '' end else begin set @SearchText = ' and Title like '+'''%' + @SearchText + '%''' end 

		declare @StartPoint int = ( @Offset + 1 ), @EndPoint int = ( @Offset + @PageSize )
		print concat('@StartPoint => ', @StartPoint, ' @EndPoint => ', @EndPoint)

		declare @sqlQuery nvarchar(max) =  concat(N'select * from  ( select ',
				N'geco.SNo, geco.TotalRecords, geco.PhysicalAppointmentId, phap.Title, phap.StartDate, phap.EndDate, ',
				N'case when FORMAT( CAST(phap.StartDate AS DATETIME), ''dd-MMM-yyyy'' ) = FORMAT( ',
					N'CAST(phap.EndDate AS DATETIME), ''dd-MMM-yyyy'' ) then FORMAT( CAST(phap.StartDate AS DATETIME),  ''dd-MMM-yyyy'' ) ',
					N'else FORMAT( CAST(phap.StartDate AS DATETIME),  ''dd-MMM-yyyy'' ) + '' '' + FORMAT( CAST(phap.EndDate AS DATETIME),  ''DD-MMM-YYYY'' ',
				  N') end ScheduleDate, ',
				N'FORMAT(CAST(phap.StartDate AS DATETIME), ''hh:mm tt'') StartDateIn, ',
				N'FORMAT(CAST(phap.EndDate AS DATETIME), ''hh:mm tt'') EndDateOut, ',
				N'FORMAT(CAST(geco.CheckIn AS DATETIME), ''hh:mm tt'') CheckIn, ',
				N'FORMAT(CAST(geco.CheckOut AS DATETIME), ''hh:mm tt'') CheckOut, ',
				N'geco.LatitudeIn, geco.LongitudeIn, geco.LatitudeOut, geco.LongitudeOut, geco.RemarksIn, geco.RemarksOut, ',
				N'isnull(phcm.Remarks, '''') AppointmentRemarks, isnull(phap.OutcomesId, 0) OutcomesId, ',
				N'isnull(uocm.OutcomeName, '''') OutcomeName, isnull(phap.CompleteAddress, '''') CompleteAddress, ',
				N'isnull(phap.Status, '''') PhysicalAptStatus, isnull(phap.CompletedOn, '''') CompletedOn, ',
				N'goem.GeoEntityId, goem.GeoEntityName, goem.GeoEntityType, goem.Mobile, goem.EmailId, ',
				N'phap.GeoEntitySiteId, ',
				N'(case when goem.GeoEntityType = ''lead'' then isnull( ( select top 1 ul.LeadNo from ',
						N'UserLeads(nolock) ul where ul.Id = goem.EntityId ), 0 ) else 0 end ) LeadNo, ',
				N'(case when goem.GeoEntityType = ''enquiry'' then isnull(( select top 1 ue.EnquiryId from ',
						  N'UserEnquiry(nolock) ue where ue.EnquiryId = goem.EntityId), 0) else 0 end) EnquiryId, ',
				  N'concat( udpa.FName, '' '', isnull(udpa.LName, '''')) UserName, ',
				  N'udpa.Image, udpa.ProfilePictureName, phap.AssignedTo, ',
				  N'concat( udpaassignto.FName, '' '', isnull(udpaassignto.LName, '''')) AssignedUserName, ',
				  N'udpaassignto.Image AssignedImage, udpa.User_Login,',
				  N'udpaassignto.ProfilePictureName AssignToProfilePictureName, ',
				  N'dbo.fn_TBL_ET_PhysicalCollebratorUM_PhyId(geco.PhysicalAppointmentId, ''Collaborator'') UserCollebratorList, ',
				  N'dbo.fn_TBL_ET_PhysicalCollebratorUM_PhyId(geco.PhysicalAppointmentId, ''FieldExecutive'') FieldExecutivelist ',
				N'from ( select * from ( select ',
						N'row_number() over( partition by (select null) order by g.GeoEntityCheckId desc ) as SNo, ',
						N'count(1) over() as TotalRecords, g.PhysicalAppointmentId, g.UserId, g.CheckIn, ',
						N'g.CheckOut, g.LatitudeIn, g.LongitudeIn, g.LatitudeOut, g.LongitudeOut, g.RemarksIn, g.RemarksOut ',
					N'from TBL_ET_GeoEntityCheckInOut (nolock) g ',
					N'inner join #tempUsers tu on g.UserId = tu.User_Id ',
					( case when isnull(@UserIds, '') <> '' then 
						N'inner join #tempSelectedUser su on g.UserId = su.UserId ' else '' end ),
						N'where g.ParentId = ', @ParentId,
						N'and ( cast(g.CheckIn as date) between cast(''', @FromDate, ''' as date) and cast(''', @ToDate, ''' as date) ',
							N'or  cast(g.CheckOut as date) between cast(''', @FromDate, ''' as date) and cast(''', @ToDate, ''' as date) ', 
						N') ) p where p.SNo between ', @StartPoint, ' and ', @EndPoint,
				  N') geco ',
				N'inner join User_detail(nolock) udpa on geco.UserId = udpa.User_Id ',
				N'inner join TBL_ET_PhysicalAppointment(nolock) phap on geco.PhysicalAppointmentId = phap.PhysicalAppointmentId ',
				N'inner join TBL_ET_GeoEntityMaster(nolock) goem on goem.GeoEntityId = phap.GeoEntityId ',
				N'left join TBL_ET_PhyAppointComment (nolock) phcm on phap.PhysicalAppointmentId = phcm.PhysicalAppointmentId ',
				N'left join tbl_tsk_UserOutcomeMaster (nolock) uocm on phap.OutcomesId = uocm.Id ',
				N'left join User_detail(nolock) udpaassignto on phap.AssignedTo = udpaassignto.User_Id',
			N') t order by t.StartDate,t.CheckIn ')

		print @sqlQuery
		execute sp_executesql @sqlQuery 

	END TRY  
	BEGIN CATCH  
		exec usp_InsertErrorInfo
	END CATCH 

	begin try
		exec MySMSAudit.dbo.Usp_AuditTableDataByParentId 
			@User_id = @UserId, @Activity_type = 'Site Visit Details Report viewed by user', @ActionType = 'S',
			@RowJson = '', @Table_name = 'TBL_ET_GeoEntityCheckInOut'
		        
	end try
	begin catch
		exec usp_InsertErrorInfo
	end catch

END



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_GetSiteVisitDetails_Name_Cache]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_TBL_ET_GetSiteVisitDetails_Name_Cache]
(
 @Mode VARCHAR(2),
 @SearchText varchar(200) = null,
 @FromDate nvarchar(100) = '',
 @ToDate nvarchar(100) = '',
 @UserId bigint = 0,
 @UserIds nvarchar(max) = '',
 @Offset int = 0,
 @PageSize int = 10,
 @Contain nvarchar(max) = ''
)
AS
SET NOCOUNT ON  
BEGIN
	BEGIN TRY 

		DECLARE @MonthStart DATETIME;
				DECLARE @MonthEnd DATETIME;
				declare @ParentID bigint = 0;	

			select @ParentID = ParentID from Mysms.[dbo].User_Detail(nolock) where User_ID = @UserId;

				-- Get the first and last date of the current month
				--SET @MonthStart = FORMAT(DATEADD(DAY, 1 - DAY(GETDATE()), CAST(GETDATE() AS DATE)), 'dd-MMM-yyyy'); -- First day of current month
				--SET @MonthEnd = FORMAT(EOMONTH(GETDATE()), 'dd-MMM-yyyy'); -- Last day of current month

				Declare @Currentdate  DATE  = GETDATE();  -- Today's date
				SET @MonthStart      = FORMAT(DATEADD(DAY, -30, @Currentdate), 'dd-MMM-yyyy'); -- 30 days before today
				SET @MonthEnd  =  FORMAT(DATEADD(DAY, -1, @Currentdate), 'dd-MMM-yyyy');

				-- Check conditions and select data
			IF (@FromDate Between @MonthStart AND @MonthEnd AND @ToDate Between @MonthStart AND @MonthEnd) 
				BEGIN
					  SELECT
							  [TotalRecords]
							  ,[PhysicalAppointmentId]
							  ,[Title]
							  ,[StartDate]
							  ,[EndDate]
							  ,[StartDateIn]
							  ,[EndDateOut]
							  ,[ScheduleDate]
							  ,[CheckIn]
							  ,[CheckOut]
							  ,[LatitudeIn]
							  ,[LongitudeIn]
							  ,[LatitudeOut]
							  ,[LongitudeOut]
							  ,[RemarksIn]
							  ,[RemarksOut]
							  ,[AppointmentRemarks]
							  ,[OutcomesId]
							  ,[OutcomeName]
							  ,[CompleteAddress]
							  ,[PhysicalAptStatus]
							  ,[CompletedOn]
							  ,[GeoEntityId]
							  ,[GeoEntityName]
							  ,[GeoEntityType]
							  ,[LeadNo]
							  ,[EnquiryId]
							  ,[Mobile]
							  ,[EmailId]
							  ,[GeoEntitySiteId]
							  ,[UserName]
							  ,[User_Login]
							  ,[ProfilePictureName]
							  ,[UserCollebratorList]
							  ,[FieldExecutivelist]
							  ,[AssignedTo]
							  ,[AssignedUserName]
							  ,[AssignToProfilePictureName]
							  ,[UserId]
							  ,[ParentId]
							 FROM [dbo].[tbl_SiteVisitDetails_Cache](nolock)
								WHERE [UserId]= @UserId  and [ParentId] = @ParentId and StartDate between @FromDate and @ToDate
					END
			ELSE IF (@FromDate < @MonthStart OR @ToDate < @MonthStart)
					BEGIN
						SELECT
							  [TotalRecords]
							  ,[PhysicalAppointmentId]
							  ,[Title]
							  ,[StartDate]
							  ,[EndDate]
							  ,[StartDateIn]
							  ,[EndDateOut]
							  ,[ScheduleDate]
							  ,[CheckIn]
							  ,[CheckOut]
							  ,[LatitudeIn]
							  ,[LongitudeIn]
							  ,[LatitudeOut]
							  ,[LongitudeOut]
							  ,[RemarksIn]
							  ,[RemarksOut]
							  ,[AppointmentRemarks]
							  ,[OutcomesId]
							  ,[OutcomeName]
							  ,[CompleteAddress]
							  ,[PhysicalAptStatus]
							  ,[CompletedOn]
							  ,[GeoEntityId]
							  ,[GeoEntityName]
							  ,[GeoEntityType]
							  ,[LeadNo]
							  ,[EnquiryId]
							  ,[Mobile]
							  ,[EmailId]
							  ,[GeoEntitySiteId]
							  ,[UserName]
							  ,[User_Login]
							  ,[ProfilePictureName]
							  ,[UserCollebratorList]
							  ,[FieldExecutivelist]
							  ,[AssignedTo]
							  ,[AssignedUserName]
							  ,[AssignToProfilePictureName]
							  ,[UserId]
							  ,[ParentId]
							 FROM [dbo].[tbl_SiteVisitDetails_Archive](nolock)
								WHERE [UserId]= @UserId  and [ParentId] = @ParentId and StartDate between @FromDate and @ToDate
					END
			ELSE
				BEGIN
					EXEC [Mysms].[dbo].usp_TBL_ET_GetSiteVisitDetails_Name @Mode, @SearchText, @FromDate, @ToDate, @UserId, @UserIds, @Offset, @PageSize, @Contain;
				END

	END TRY  
	BEGIN CATCH  
		exec MySMS.dbo.usp_InsertErrorInfo
	END CATCH 

	begin try
		exec MySMSAudit.dbo.Usp_AuditTableDataByParentId 
			@User_id = @UserId, @Activity_type = 'Site Visit Details Report viewed by user', @ActionType = 'S',
			@RowJson = '', @Table_name = 'TBL_ET_GeoEntityCheckInOut'
		        
	end try
	begin catch
