   Procedure: [dbo].[usp_TBL_ET_GetSiteVisitList_Name_cache]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_TBL_ET_GetSiteVisitList_Name_cache]
(
 @Mode VARCHAR(2)
 ,@SearchText varchar(200) = null  
 ,@FromDate nvarchar(100) = ''  
 ,@ToDate nvarchar(100) = ''  
 ,@UserId bigint = 0
 ,@Offset int = 0  
 ,@PageSize int = 10 
)
AS  
SET NOCOUNT ON  
  
BEGIN 

				DECLARE @MonthStart DATETIME;
				DECLARE @MonthEnd DATETIME;
				declare @ParentID bigint = 0;	

			select @ParentID = ParentID from Mysms.[dbo].User_Detail(nolock) where User_ID = @UserId;

				-- Get the first and last date of the current month
				--SET @MonthStart = FORMAT(DATEADD(DAY, 1 - DAY(GETDATE()), CAST(GETDATE() AS DATE)), 'dd-MMM-yyyy'); -- First day of current month
				--SET @MonthEnd = FORMAT(EOMONTH(GETDATE()), 'dd-MMM-yyyy'); -- Last day of current month

				Declare @Currentdate  DATE  = GETDATE();  -- Today's date
				SET @MonthStart      = FORMAT(DATEADD(DAY, -30, @Currentdate), 'dd-MMM-yyyy'); -- 30 days before today
				SET @MonthEnd  =  FORMAT(DATEADD(DAY, -1, @Currentdate), 'dd-MMM-yyyy');

				-- Check conditions and select data
			IF (@FromDate Between @MonthStart AND @MonthEnd AND @ToDate Between @MonthStart AND @MonthEnd)  
			BEGIN
					  SELECT 
						   [TotalRecords]
						  ,[User_Id]
						  ,[UserName]
						  ,[ManagerName]
						  ,[ProfilePictureName]
						  ,[ManagerProfilePictureName]
						  ,[Designation]
						  ,[City]
						  ,[User_Login]
						  ,[UserFullName]
						  ,[NoOfSiteVisited]
						  ,[ParentId]
					 FROM [dbo].[tbl_SiteVisitList_Cache](nolock)
					WHERE [User_Id]= @UserId  and [ParentId] = @ParentId  --and CheckIn between @FromDate and @ToDate   
			END
			ELSE IF (@FromDate < @MonthStart OR @ToDate < @MonthStart)
			BEGIN
					  SELECT 
						   [TotalRecords]
						  ,[User_Id]
						  ,[UserName]
						  ,[ManagerName]
						  ,[ProfilePictureName]
						  ,[ManagerProfilePictureName]
						  ,[Designation]
						  ,[City]
						  ,[User_Login]
						  ,[UserFullName]
						  ,[NoOfSiteVisited]
						  ,[ParentId]
					 FROM [dbo].[tbl_SiteVisitList_Archive](nolock)
					WHERE [User_Id]= @UserId  and [ParentId] = @ParentId  --and CheckIn between @FromDate and @ToDate 
			END
			ELSE
				BEGIN
					EXEC [Mysms].[dbo].usp_TBL_ET_GetSiteVisitList_Name @Mode, @SearchText, @FromDate, @ToDate, @UserId, @Offset, @PageSize;
				END
END  



