/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_HolidayMasterList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


--Usp_TBL_ET_HolidayMasterList 'HS', 0, 'holi', '2023-01-01', '2023-12-31', 0, 34594, '', 34594, 0, 10   
CREATE   PROCEDURE  [dbo].[usp_TBL_ET_HolidayMasterList] (
 @Mode VARCHAR(3)
,@HolidayId bigint = 0
,@HolidayName varchar(200) = ''
,@FromDate varchar(20) = ''
,@ToDate varchar(20) = ''
,@BranchId bigint = 0
,@ParentId bigint = 0
,@Contain varchar(500) = ''
,@CreatedBy bigint = 0
,@OffsetValue int = 0
,@PagingSize int = 0
)
AS 
SET NOCOUNT ON 
 
BEGIN TRY 
Select @ParentId = ParentId from User_Detail (nolock) Where User_ID = @CreatedBy 
IF (@Mode = 'HL') /*This is for List */ 
  Begin
	Select count(agas.HolidayId) over() as TotalRecords, agas.HolidayId, HolidayName, HolidayDate, bh.BranchId, agas.ParentId, 
	concat(Ud.FName, ' ', isnull(Ud.LName, '')) FullName, isnull(Color, '#FFA07A') Color, agas.CreatedDate, agas.CreatedBy, agas.IsActive 
	from TBL_ET_HolidayMaster(nolock) agas 
	inner join User_Detail (nolock) Ud on agas.CreatedBy = Ud.User_ID 
	inner join TBL_ET_HolidayBranch (nolock) bh on agas.HolidayId = bh.HolidayId
	Where agas.HolidayName like '%' + @HolidayName + '%' and Ud.ParentId = @ParentId and (HolidayDate between @FromDate and @ToDate)
	and bh.BranchId = (case when @BranchId = 0 then bh.BranchId else @BranchId end)
	order by HolidayName Asc 
	Offset @OffsetValue rows fetch next @PagingSize rows only 
  End
Else IF (@Mode = 'HS') /*This is for List */ 
  Begin
  if(@Contain != '')
  Begin
  set @Contain = ' and '+ @Contain;
  End
 Declare @query nvarchar(max)
 set @query = ' Select count(agas.HolidayId) over() as TotalRecords, agas.HolidayId, HolidayName, Convert(varchar,HolidayDate,105) HolidayDate, bh.BranchId, isnull(tiut.Name, '''') BranchName, '''' BranchNames, agas.ParentId, 
	concat(Ud.FName, '' '', isnull(Ud.LName, '''')) FullName, isnull(Color, ''#FFA07A'') Color, agas.CreatedDate, agas.CreatedBy, agas.IsActive 
	from TBL_ET_HolidayMaster(nolock) agas 
	inner join User_Detail (nolock) Ud on agas.CreatedBy = Ud.User_ID 
	inner join TBL_ET_HolidayBranch (nolock) bh on agas.HolidayId = bh.HolidayId
	inner join tbl_inv_UserTaxNumber (nolock) tiut on bh.BranchId = tiut.Id 
	Where agas.HolidayName like ''%' + @HolidayName + '%'' 
	 and cast(HolidayDate as Date) between cast('''+cast(@FromDate as varchar(12))+''' as Date) and cast('''+cast(@ToDate as varchar(12))+''' as Date) 
  and Ud.ParentId = '+ cast(@ParentId as varchar(10)) + ' ' + @Contain + '
  Order By cast(HolidayDate as date) Asc 
  Offset '+ cast(@OffsetValue as varchar(10)) + ' rows fetch next '+ cast(@PagingSize as varchar(10)) + ' rows only '

 print @query

 execute sp_executesql @query

 End
 Else IF (@Mode = 'HD') /*This is for Details */
  Begin
	Select HolidayId, HolidayName, HolidayDate, 0 BranchId, agas.ParentId, concat(Ud.FName, ' ', isnull(Ud.LName, '')) FullName, 
	isnull(Color, '') Color, agas.CreatedDate, agas.CreatedBy, agas.IsActive from TBL_ET_HolidayMaster(nolock) agas 
	 inner join User_Detail (nolock) Ud on agas.CreatedBy = Ud.User_ID 
	 Where agas.HolidayId = @HolidayId

	Select * from TBL_ET_HolidayBranch(nolock) agas Where agas.HolidayId = @HolidayId

  End
END TRY

BEGIN CATCH
 DECLARE @ErrorMessage NVARCHAR(4000);
 SELECT @ErrorMessage = ERROR_MESSAGE();
 RAISERROR (
   @ErrorMessage  
   ,16  
   ,1  
   );  
END CATCH



GO

/* ============================================================
   Procedure: [dbo].[Usp_TBL_ET_HolidayMasterSave]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--Usp_TBL_ET_HolidayMasterSave 'AGL', 0, 'A Group 1', 34594, 1   
CREATE   PROCEDURE  [dbo].[Usp_TBL_ET_HolidayMasterSave] (  
 @Mode VARCHAR(3)
,@HolidayId bigint = 0
,@HolidayName varchar(200) = ''
,@HolidayDate date = null
,@BranchId bigint = 0
,@Color varchar(10) = ''
,@BranchIds nvarchar(max) = ''
,@HolidayList nvarchar(max) = ''
,@ParentId bigint = 0
,@CreatedBy bigint
,@IsActive bit = true
)
AS
SET NOCOUNT ON
  
BEGIN TRY 
--Declare @ParentId bigint  
Select @ParentId = ParentId from User_Detail (nolock) Where User_ID = @CreatedBy  
 IF (@Mode = 'HS') /*This is for Insert Details */  
 BEGIN
 if(Not Exists(Select agas.CreatedBy from TBL_ET_HolidayMaster(nolock) agas  
 inner join TBL_ET_HolidayBranch (nolock) hbrc on agas.HolidayId = hbrc.HolidayId
 inner join User_Detail (nolock) Ud on agas.CreatedBy = Ud.User_ID 
 Where agas.HolidayName = @HolidayName and hbrc.BranchId = @BranchId and Ud.ParentId = @ParentId)) 
 Begin

 insert Into TBL_ET_HolidayMaster (HolidayName, HolidayDate, Color, ParentId, CreatedDate, CreatedBy, IsActive) 
 values (@HolidayName, @HolidayDate, @Color, @ParentId, GETDATE(), @CreatedBy, @IsActive)
 Declare @ID bigint = SCOPE_IDENTITY()

 insert Into TBL_ET_HolidayBranch (HolidayId, BranchId, ParentId, CreatedDate, CreatedBy, IsActive) 
 SELECT @ID, item, @ParentId, GETDATE(), @CreatedBy, @IsActive FROM dbo.fu_SplitString(@BranchIds, ',')

 Select 'Record Saved' Status, @ID Id   
 End  
 Else  
 Begin 
 Select 'Record Already Exists' Status, 0 Id 
 End
  End 
 Else IF (@Mode = 'HU') /*This is for Update Details */ 
  Begin 
 if(Exists(Select CreatedBy from TBL_ET_HolidayMaster(nolock) agas 
 inner join User_Detail (nolock) Ud on agas.CreatedBy = Ud.User_ID 
 Where agas.HolidayId = @HolidayId and Ud.ParentId = @ParentId))  
 Begin

 Update TBL_ET_HolidayMaster set HolidayName = @HolidayName, HolidayDate = @HolidayDate, Color = @Color, ParentId = @ParentId, 
 UpdatedDate = GETDATE(), UpdatedBy = @CreatedBy, IsActive = @IsActive 
 where HolidayId = @HolidayId 

 DELETE TBL_ET_HolidayBranch WHERE BranchId NOT IN (SELECT DISTINCT item FROM dbo.fu_SplitString(@BranchIds, ',')  
    ) and ParentId = @ParentId and HolidayId = @HolidayId
 
 insert Into TBL_ET_HolidayBranch (HolidayId, BranchId, ParentId, CreatedDate, CreatedBy, IsActive) 
 SELECT @HolidayId, item, @ParentId, GETDATE(), @CreatedBy, @IsActive FROM dbo.fu_SplitString(@BranchIds, ',') where item 
 not in (select BranchId from TBL_ET_HolidayBranch(nolock) where HolidayId = @HolidayId )

 
 Select 'Record Updated' Status, @HolidayId Id 
 End
 Else
 Begin
 Select 'Record Not Exists' Status, @HolidayId Id
 End
  End 
 Else IF (@Mode = 'HP') /*This is for Update Details */ 
  Begin 
 if(Exists(Select CreatedBy from TBL_ET_HolidayMaster(nolock) agas 
 inner join User_Detail (nolock) Ud on agas.CreatedBy = Ud.User_ID 
 Where agas.HolidayId = @HolidayId and Ud.ParentId = @ParentId))  
 Begin

 Update TBL_ET_HolidayMaster set HolidayName = @HolidayName, HolidayDate = @HolidayDate, Color = @Color, ParentId = @ParentId, 
 UpdatedDate = GETDATE(), UpdatedBy = @CreatedBy, IsActive = @IsActive 
 where HolidayId = @HolidayId 

 DELETE TBL_ET_HolidayBranch WHERE BranchId NOT IN (SELECT DISTINCT item FROM dbo.fu_SplitString(@BranchIds, ',')  
    ) and ParentId = @ParentId and HolidayId = @HolidayId
 
 insert Into TBL_ET_HolidayBranch (HolidayId, BranchId, ParentId, CreatedDate, CreatedBy, IsActive) 
 SELECT @ID, item, @ParentId, GETDATE(), @CreatedBy, @IsActive FROM dbo.fu_SplitString(@BranchIds, ',')
 
 
 Select 'Record Updated' Status, @HolidayId Id 
 End
 Else 
 Begin 
 Select 'Record Not Exists' Status, @HolidayId Id 
 End 
  End 
 Else IF (@Mode = 'HH') /*This is for Update Details */ 
  Begin 
--@HolidayList
drop table if exists #holidayTemp 
Create table #holidayTemp ( HolidayName varchar(50), HolidayDate varchar(12), Color varchar(10))
insert into #holidayTemp (HolidayName, HolidayDate, Color)
SELECT HolidayName, HolidayDate, Color FROM openjson(@HolidayList) WITH (
				HolidayName VARCHAR(50) '$.HolidayName'
				,HolidayDate VARCHAR(12) '$.HolidayDate'
				,Color VARCHAR(10) '$.Color'
				) t

drop table if exists #BranchTemp 
Create table #BranchTemp (BranchId bigint)
insert into #BranchTemp(BranchId)
SELECT item FROM dbo.fu_SplitString(@BranchIds, ',')

drop table if exists #holidayTempF 
Create table #holidayTempF ( HolidayName varchar(50), HolidayDate varchar(12), Color varchar(10), BranchId bigint)
insert into #holidayTempF (HolidayName, HolidayDate, Color, BranchId)
select HolidayName, HolidayDate, Color, BranchId from #holidayTemp htem, #BranchTemp btem
delete TBL_ET_HolidayBranch where HolidayId in (
Select agas.HolidayId from TBL_ET_HolidayMaster(nolock) agas 
 inner join TBL_ET_HolidayBranch (nolock) hb on agas.HolidayId = hb.HolidayId
 inner join User_Detail (nolock) Ud on agas.CreatedBy = Ud.User_ID 
 Where agas.HolidayDate in (select HolidayDate from #holidayTemp) and hb.BranchId in (SELECT item FROM dbo.fu_SplitString(@BranchIds, ',')) and Ud.ParentId = @ParentId)

delete TBL_ET_HolidayMaster where HolidayId in (
Select agas.HolidayId from TBL_ET_HolidayMaster(nolock) agas 
 inner join TBL_ET_HolidayBranch (nolock) hb on agas.HolidayId = hb.HolidayId
 inner join User_Detail (nolock) Ud on agas.CreatedBy = Ud.User_ID 
 Where agas.HolidayDate in (select HolidayDate from #holidayTemp) and hb.BranchId in (SELECT item FROM dbo.fu_SplitString(@BranchIds, ',')) and Ud.ParentId = @ParentId)

DECLARE @generated_keys table([HolidayId] bigint)

insert Into TBL_ET_HolidayMaster (HolidayName, HolidayDate, Color, ParentId, CreatedDate, CreatedBy, IsActive) 
OUTPUT inserted.HolidayId INTO @generated_keys
select HolidayName, cast(HolidayDate as date), Color, @ParentId, GETDATE(), @CreatedBy, @IsActive from #holidayTemp

insert Into TBL_ET_HolidayBranch (HolidayId, BranchId, ParentId, CreatedDate, CreatedBy, IsActive) 
 SELECT bb.HolidayId, item, @ParentId, GETDATE(), @CreatedBy, @IsActive FROM dbo.fu_SplitString(@BranchIds, ',') aa, @generated_keys bb
 

 Select 'Record Saved' Status--, @ID Id   
 --End  
 --Else  
 --Begin 
 --Select 'Record Already Exists' Status, 0 Id 
 --End 
 End 

END TRY 
 
BEGIN CATCH 
 DECLARE @ErrorMessage NVARCHAR(4000); 
 SELECT @ErrorMessage = ERROR_MESSAGE(); 
 RAISERROR (  
   @ErrorMessage  
   ,16  
   ,1  
   );  
END CATCH  



GO

/* ============================================================
   Procedure: [dbo].[usp_tbl_ET_Job_UpdateMissingAttInOut]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_tbl_ET_Job_UpdateMissingAttInOut]
As
Begin

	declare @CurDate Date = dateadd(d,-1,getdate())

	drop table if exists #tblUpdateOut
	create table #tblUpdateOut (
		AttendanceId bigint, AttendanceIn datetime, AttendanceOut datetime, UserId bigint, Remarks nvarchar(max) )

--select
--InAttendance=coalesce(ATT.AttendanceIn,iif(ATT.AttendanceOut < ULTA.LocationDateTime,ATT.AttendanceOut,ULTA.LocationDateTime), DATEADD(day, DATEDIFF(day, 0, @CurDate), left(SM.StartTime,8)),DATEADD(day, DATEDIFF(day, 0, @CurDate), left(SMR.StartTime,8))), OutAttendance=coalesce(ATT.AttendanceOut,iif(ATT.AttendanceIn > ULTD.LocationDateTime,ATT.AttendanceIn,ULTD.LocationDateTime), DATEADD(day, DATEDIFF(day, 0, @CurDate), left(SM.EndTime,8)),DATEADD(day, DATEDIFF(day, 0, @CurDate), left(SMR.EndTime,8))), * 

update ATT Set /*ATT.AttendanceIn=coalesce(ATT.AttendanceIn,iif(ATT.AttendanceOut < ULTA.LocationDateTime,ATT.AttendanceOut,ULTA.LocationDateTime), DATEADD(day, DATEDIFF(day, 0, @CurDate), left(SM.StartTime,8)),DATEADD(day, DATEDIFF(day, 0, @CurDate), left(SMR.StartTime,8))),*/ ATT.AttendanceOut=coalesce(ATT.AttendanceOut,iif(ATT.AttendanceIn > ULTD.LocationDateTime,ATT.AttendanceIn,ULTD.LocationDateTime), DATEADD(day, DATEDIFF(day, 0, @CurDate), left(SM.EndTime,8)),DATEADD(day, DATEDIFF(day, 0, @CurDate), left(SMR.EndTime,8))), /*ATT.RemarksIn=iif(isnull(ATT.AttendanceIn,'')='','Forced SignIn',ATT.RemarksIn),*/ ATT.RemarksOut=iif(isnull(ATT.AttendanceOut,'')='','Forced SignOut',ATT.RemarksOut)
OUTPUT inserted.AttendanceId, inserted.AttendanceIn, inserted.AttendanceOut, inserted.UserId, inserted.RemarksOut into #tblUpdateOut
from TBL_ET_Attendance ATT left join V_TBL_ET_UserLocationTracking(nolock) ULTA
on ATT.UserId=ULTA.UserId and cast(isnull(ATT.AttendanceIn,ATT.AttendanceOut) as Date)=Cast(ULTA.LocationDateTime as Date) left Join V_TBL_ET_UserLocationTrackingDesc(nolock) ULTD
on ATT.UserId=ULTD.UserId and cast(isnull(ATT.AttendanceOut,ATT.AttendanceIn) as Date)=Cast(ULTD.LocationDateTime as Date) left join TBL_ET_ShiftUserMapping(nolock) SHUM
on ATT.UserId=SHUM.UserId and SHUM.IsActive=1 left join TBL_ET_ShiftMaster(nolock) SM
on SHUM.ShiftId=SM.ShiftId and SM.IsActive=1 left join TBL_ET_AttendanceGroup(nolock) AG
on ATT.AttendanceGroupId=AG.AttendanceGroupId left join TBL_ET_ShiftMaster(nolock) SMR
on AG.RosterId=SMR.ShiftId and SMR.IsActive=1
where cast(isnull(ATT.CreatedDate,ATT.UpdatedDate) as date) = @CurDate and 
	ATT.IsActive=1 and (ATT.AttendanceIn is null or ATT.AttendanceOut is null)
	--ATT.AttendanceId in (601, 639)                                                                                                                                                                                         
	 and 1 = ( 
		case when SMR.StartTime > SMR.EndTime and DATEDIFF(day, 
			cast(isnull(ATT.CreatedDate, ATT.UpdatedDate) as date), @CurDate) > 0
				then 1
		when SMR.StartTime <= SMR.EndTime and DATEDIFF(day, 
			cast(isnull(ATT.CreatedDate, ATT.UpdatedDate) as date), @CurDate) = 0 then 1 
		else 0 end
	)

	insert into tbl_et_UserLocationTrackingBulkRequest( MovementCode, Remarks, UserId, LocationDateTime, Latitude, Longitude, Address, BatteryPerc, 
		NetworkPerc, CreatedDate, CreatedBy, IsActive, IsMock, IsBulk, Speed, Distance, LocationMetaData, IsDistanceCalc)
	select 'SIGN_OUT', 'Forced SignOut', ATT.UserId, ATT.AttendanceOut, ULTD.Latitude, ULTD.Longitude, ULTD.Address, ULTD.BatteryPerc, 
		ULTD.NetworkPerc, getdate(), ULTD.CreatedBy, 1, ULTD.IsMock, ULTD.IsBulk, ULTD.Speed, ULTD.Distance, 
		concat('{"EntityName":"","EntityId":"","AttendanceId":"', ATT.AttendanceId, '","PhysicalAppointmentId":"","BreakTransactionId":""}'), 1 
	from #tblUpdateOut ATT inner join V_TBL_ET_UserLocationTrackingDesc(nolock) ULTD
		on ATT.UserId=ULTD.UserId and cast(ATT.AttendanceOut as date)=Cast(ULTD.LocationDateTime as date)

	drop table if exists #tblUpdateOut

End



