/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_LeaveApprovalList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE  [dbo].[usp_TBL_ET_LeaveApprovalList] (
@Mode VARCHAR(2)
,@LeaveApprovalId bigint = 0
,@LeaveId bigint  = 0
,@LeaveRequestId bigint = 0
,@ApproverStatus varchar(20) = ''
,@RemarksApprover varchar(250) = ''
,@ApproverUserId bigint = 0
,@FromDate varchar(30) = ''
,@ToDate varchar(30) = ''
,@Offset int = 0
,@PageSize int = 0
)
AS
SET NOCOUNT ON
BEGIN TRY
	Declare @ParentId bigint
	Declare @UserIdTeamLst varchar(4000) = ''       
	select top 1 @ParentId = ParentId from User_Detail(nolock) where User_ID = @ApproverUserId
	select @UserIdTeamLst = UserIdTeamLst from ufn_GetUserRoleScope(@ApproverUserId)     
	IF (@Mode = 'AL')
	BEGIN 
	select count(telr.LeaveApprovalId) over() as TotalRecords,  LeaveApprovalId, telr.LeaveRequestId, Cast(lr.FromDate as varchar(100)) FromDate,  Cast(lr.ToDate as varchar(100)) ToDate, lr.StartQuarterDate, lr.EndQuarterDate, TypeOfLeave,
	case When ((lr.EndQuarterDate - lr.StartQuarterDate) + 1) = 4 then 'Full Leave'
	When ((lr.EndQuarterDate - lr.StartQuarterDate) + 1) = 3 then 'Half and Short Leave'
	When ((lr.EndQuarterDate - lr.StartQuarterDate) + 1) = 2 then 'Half Leave'
	When ((lr.EndQuarterDate - lr.StartQuarterDate) + 1) = 1 then 'Short Leave'
	else '' end LeaveRequestStatus,
	ApproverStatus, RemarksApprover, ApproverUserId, lr.UserId, 
	(ud1.FName + ' ' + ud1.LName) RequesterName, 
	(ud2.FName + ' ' + ud2.LName) ApproverName from TBL_ET_LeaveApproval (nolock) telr 
	inner join TBL_ET_LeaveRequest (nolock) lr on telr.LeaveRequestId = lr.LeaveRequestId 
	inner join TBL_ET_LeaveMaster (nolock) lm on lr.LeaveId = lm.LeaveId and lm.ParentId = @ParentId 
	inner join User_Detail (nolock) ud1 on lr.UserId = ud1.User_ID
	left join User_Detail (nolock) ud2 on telr.ApproverUserId = ud2.User_ID
	where (lm.LeaveId = (case when @LeaveId = 0 then lr.LeaveId else @LeaveId End)) 
	and (lr.UserId in (select item from dbo.fu_SplitString(@UserIdTeamLst, ',')))
	and (((lr.FromDate between @FromDate and @ToDate) or (lr.ToDate between @FromDate and @ToDate)))
	Order By lr.FromDate desc
	Offset @Offset rows fetch next @PageSize rows only

	End
	Else IF (@Mode = 'AD') /*This is for Insert Details */
	BEGIN
	Select atra.LeaveApprovalId, atra.LeaveRequestId, telr.LeaveId, Cast(telr.FromDate as varchar(100)) FromDate, Cast(telr.ToDate as varchar(100)) ToDate, Cast(CONVERT(varchar, telr.FromDate,13) as varchar(12)) FromDateNew, cast(CONVERT(varchar,telr.ToDate,13) as varchar(12)) ToDateNew, StartQuarterDate, EndQuarterDate, cast(FromTime as varchar(5)) FromTime, cast(ToTime as varchar(5)) ToTime, telr.UserId, Remarks, Cast(telr.CreatedDate as varchar(100)) RequestDate, TypeOfLeave,
	case When ((telr.EndQuarterDate - telr.StartQuarterDate) + 1) = 4 then 'Full Leave'
	When ((telr.EndQuarterDate - telr.StartQuarterDate) + 1) = 3 then 'Half and Short Leave'
	When ((telr.EndQuarterDate - telr.StartQuarterDate) + 1) = 2 then 'Half Leave'
	When ((telr.EndQuarterDate - telr.StartQuarterDate) + 1) = 1 then 'Short Leave'
	else '' end LeaveRequestStatus,
	ud.CompnayName, (isnull(ud.Address, '') + ',' + isnull(ct.City_Name, '') + ',' + isnull(st.State_Name, '') + ',' + isnull(co.Country_Name, '')) Address, (ud.FName + ' ' + ud.LName) + ' (' + ud.User_Login + ')' EmployeeName, (ud2.FName + ' ' + ud2.LName) + '(' + ud2.User_Login + ')' ApprovedName,  
 isnull(atra.RemarksApprover, '') RemarksApprover, isnull(atra.ApproverStatus, 'Pending') ApproverStatus,   
 isnull(atra.ApprovedDate , '') ApprovedDate, isnull(atra.LeaveApprovalId, 0) LeaveApprovalId, 
 isnull(iutn.Address, '') +', '+ isnull(ct.City_Name, '') + ', ' + isnull(st.State_Name, '') + ', ' + isnull(co.Country_Name, '') BranchAddress, 
(select top 1 isnull(CONVERT(VARCHAR, AttendanceIn, 100), '''') LastLoginAttendanceIn from TBL_ET_Attendance(nolock) Where UserId = telr.UserId order by 1 desc) LastLoginAttendanceIn  from TBL_ET_LeaveApproval (nolock) atra
 inner join TBL_ET_LeaveRequest (nolock) telr on atra.LeaveRequestId = telr.LeaveRequestId
 inner join User_Detail(nolock) ud on telr.UserId = ud.User_ID  
 left join User_Detail(nolock) ud2 on atra.ApproverUserId = ud2.User_ID  
 left join TBL_ET_AttendanceGroupUserMapping (nolock) agum on telr.UserId = agum.UserId
 left join tbl_inv_UserTaxNumber (nolock) iutn on agum.UserBranchId = iutn.Id
 left join M_City (nolock) ct on iutn.City_Id = ct.City_Id
 left join M_State (nolock) st on iutn.State_Id = st.State_Id
 left join M_Country (nolock) co on iutn.Country_Id = co.Country_Id
	where atra.LeaveApprovalId = @LeaveApprovalId
	End
END TRY

BEGIN CATCH
	DECLARE @ErrorMessage NVARCHAR(4000);
	SELECT @ErrorMessage = ERROR_MESSAGE();
	RAISERROR (
			@ErrorMessage
			,16
			,1
			);
END CATCH



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_LeaveApprovalSave]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE  [dbo].[usp_TBL_ET_LeaveApprovalSave] (
 @Mode VARCHAR(2)
,@LeaveApprovalId bigint
,@LeaveRequestId bigint
,@ApproverStatus varchar(20)
,@RemarksApprover varchar(250)
,@ApproverUserId bigint
,@CreatedBy bigint
,@IsActive bit
)
AS
SET NOCOUNT ON

BEGIN TRY
	Declare @ParentId bigint
	select top 1 @ParentId = ParentId from User_Detail(nolock) where User_ID = @ApproverUserId

	IF (@Mode = 'AS') /*This is for Insert Details */
	BEGIN
	if(not Exists(Select 1 from TBL_ET_LeaveApproval (nolock) telr where LeaveRequestId = @LeaveRequestId and ApproverStatus = @ApproverStatus and ApproverUserId = @ApproverUserId))
	Begin
	insert into TBL_ET_LeaveApproval (LeaveRequestId, ApproverStatus, RemarksApprover, ApproverUserId, ApprovedDate, CreatedDate, CreatedBy, IsActive)
	values (@LeaveRequestId, @ApproverStatus, @RemarksApprover, @ApproverUserId, GETDATE(), GETDATE(), @CreatedBy, @IsActive)

	Select cast(scope_identity() as bigint) Id, 'Record Saved' Status
	 END 
	 else
	 Begin
  	Select 0 Id, 'Already Exists' Status
	 End
	 End
	Else IF (@Mode = 'AU') /*This is for Insert Details */
	BEGIN
	if(Exists(Select 1 from TBL_ET_LeaveApproval (nolock) telr where telr.LeaveRequestId = @LeaveRequestId))
	Begin
		Update TBL_ET_LeaveApproval set LeaveRequestId = @LeaveRequestId, ApproverStatus = @ApproverStatus, RemarksApprover = @RemarksApprover, ApproverUserId = @ApproverUserId, ApprovedDate = GETDATE(),
		UpdatedDate = GETDATE(), UpdatedBy = @CreatedBy, IsActive = @IsActive
		where @LeaveApprovalId = @LeaveApprovalId
		Select @LeaveApprovalId Id, 'Record Updated' Status
	 END
	 else
	 Begin
	Select @LeaveApprovalId Id, 'Record not Exists' Status
	 End
	End
END TRY

BEGIN CATCH
	DECLARE @ErrorMessage NVARCHAR(4000);
	SELECT @ErrorMessage = ERROR_MESSAGE();
	RAISERROR (
			@ErrorMessage
			,16
			,1
			);
END CATCH



GO

/* ============================================================
   Procedure: [dbo].[Usp_TBL_ET_LeaveMasterList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--Usp_TBL_ET_LeaveMasterList 'AGL', 0, 'A Group 1', 34594, 1   
CREATE   PROCEDURE [dbo].[Usp_TBL_ET_LeaveMasterList] (  
 @Mode VARCHAR(3)
,@LeaveId bigint = 0
,@LeaveName varchar(200) = ''
,@CreatedBy bigint = 0
,@OffsetValue int = 0
,@PagingSize int = 0
)
AS
SET NOCOUNT ON
  
BEGIN TRY 
Declare @ParentId bigint
Select @ParentId = ParentId from User_Detail(nolock) Where User_ID = @CreatedBy  
IF (@Mode = 'LL') /*This is for List */ 
  Begin
	Select count(agas.LeaveId) over() as TotalRecords, LeaveId, LeaveName, 
	concat(Ud.FName, ' ', isnull(Ud.LName, '')) FullName, agas.CreatedDate, agas.CreatedBy, agas.IsActive 
	from TBL_ET_LeaveMaster(nolock) agas 
	inner join User_Detail (nolock) Ud on agas.CreatedBy = Ud.User_ID 
	Where agas.LeaveName like '%' + @LeaveName + '%' and Ud.ParentId = @ParentId
	order by LeaveName Asc 
	Offset @OffsetValue rows fetch next @PagingSize rows only 

	select isnull(shum.ShiftId, 0) ShiftId, sm.StartTime, sm.EndTime, concat(Ud.FName, ' ', isnull(Ud.LName, '')) FullName 
	from TBL_ET_ShiftUserMapping (nolock) shum
	inner join TBL_ET_ShiftMaster (nolock) sm on sm.ShiftId = shum.ShiftId
	inner join User_Detail (nolock) Ud on shum.UserId = Ud.User_ID 
	where shum.UserId = @CreatedBy
  End
 Else IF (@Mode = 'LD') /*This is for Details */ 
  Begin
	Select LeaveId, LeaveName, concat(Ud.FName, ' ', isnull(Ud.LName, '')) FullName, agas.CreatedDate, agas.CreatedBy, agas.IsActive 
	from TBL_ET_LeaveMaster(nolock) agas 
	inner join User_Detail (nolock) Ud on agas.CreatedBy = Ud.User_ID 
	 Where agas.LeaveId = @LeaveId

  End
END TRY 
 
BEGIN CATCH 
 DECLARE @ErrorMessage NVARCHAR(4000); 
 SELECT @ErrorMessage = ERROR_MESSAGE(); 
 RAISERROR (  
   @ErrorMessage  
   ,16  
   ,1  
   );  
END CATCH  



GO

