 lere.UserId, lere.CreatedDate, lere.CreatedBy, lere.UpdatedDate, lere.UpdatedBy, (case when lere.IsActive = 1 then ''Active''  
 else ''InActive'' End) Status, isnull(atra.ApproverUserId, 0) ApproverUserId,  
 (ud2.FName + '' '' + ud2.LName) + ''('' + ud2.User_Login + '')'' ApprovedName,  
 isnull(atra.RemarksApprover, '''') RemarksApprover, isnull(atra.ApproverStatus, ''Pending'') ApproverStatus,   
 isnull(atra.ApprovedDate , '''') ApprovedDate, isnull(atra.LeaveApprovalId, 0) LeaveApprovalId,  
 lere.Remarks, isnull(iutn.Address, '''') +'', ''+ isnull(ct.City_Name, '''') + '', '' + isnull(st.State_Name, '''') + '', '' + isnull(co.Country_Name, '''') BranchAddress, (select top 1 isnull(CONVERT(VARCHAR, AttendanceIn, 100), '''') LastLoginAttendanceIn from TBL_ET_Attendance(nolock) Where UserId = lere.UserId order by 1 desc) LastLoginAttendanceIn from TBL_ET_LeaveRequest(nolock) lere
 inner join User_Detail(nolock) ud on lere.UserId = ud.User_ID  
 inner join TBL_ET_LeaveApproval(nolock) atra on lere.LeaveRequestId = atra.LeaveRequestId
 left join User_Detail(nolock) ud2 on atra.ApproverUserId = ud2.User_ID  
 left join TBL_ET_AttendanceGroupUserMapping (nolock) agum on lere.UserId = agum.UserId
 left join tbl_inv_UserTaxNumber (nolock) iutn on agum.UserBranchId = iutn.Id
