 	where (((telr.FromDate between @FromDate and @ToDate) or (telr.ToDate between @FromDate and @ToDate)) and 
	((telr.StartQuarterDate between @StartQuarterDate and @EndQuarterDate) or 
	(telr.EndQuarterDate between @StartQuarterDate and @EndQuarterDate)))

	End
	Else IF (@Mode = 'LD') /*This is for Insert Details */
	BEGIN
