(select top 1 isnull(CONVERT(VARCHAR, AttendanceIn, 100), '''') LastLoginAttendanceIn from TBL_ET_Attendance(nolock) Where UserId = telr.UserId order by 1 desc) LastLoginAttendanceIn from TBL_ET_LeaveRequest(nolock) telr
 inner join User_Detail(nolock) ud on telr.UserId = ud.User_ID  
 inner join TBL_ET_LeaveApproval(nolock) atra on telr.LeaveRequestId != atra.LeaveRequestId
 left join User_Detail(nolock) ud2 on atra.ApproverUserId = ud2.User_ID  
