SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_TBL_ET_LeaveRequestSave] (
	 @Mode VARCHAR(2),
	 @LeaveRequestId bigint= 0,
	 @LeaveId bigint = 0,
	 @FromDate Datetime,
	 @ToDate Datetime,
	 @StartQuarterDate int = 0,
	 @EndQuarterDate int = 0,
	 @FromTime varchar(10) = '',
	 @ToTime varchar(10) = '',
	 @TypeOfLeave varchar(20) = '',
	 @Remarks varchar(500) = '',
	 @UserId bigint,
	 @CreatedBy bigint,
	 @IsActive bit  
)  
AS
BEGIN
SET NOCOUNT ON
  
BEGIN TRY  

--declare  
--	@Mode VARCHAR(2) = N'LU',
--	@LeaveRequestId bigint= 60,
--	@LeaveId bigint = 1,
--	@FromDate Datetime = N'10-May-2023',
--	@ToDate Datetime = N'14-May-2023',
--	@StartQuarterDate int = 0 ,
--	@EndQuarterDate int = 0,
--	@FromTime varchar(10) = N'21:00',
--	@ToTime varchar(10) = N'20:00',
--	@TypeOfLeave varchar(20) = N'fullDay',
--	@Remarks varchar(500) = N'JJIIISJSJIISJID SJOSOS  updated',
--	@UserId bigint = 27215,
--	@CreatedBy bigint = 27215,
--	@IsActive bit = 1


 Declare @ApplyBeforeDays int  
 Declare @ParentId bigint  
 select top 1 @ParentId = ParentId from User_Detail(nolock) where User_ID = @UserId  
 Select top 1 @ApplyBeforeDays = ApplyBeforeDays from TBL_ET_LeaveMaster where ParentId = @ParentId and LeaveId = @LeaveId

 if(@StartQuarterDate = 0 or @EndQuarterDate = 0)
 Begin
Declare @TotalWorkingMint int, @OneQuarterMint int, @ShiftStartTime1 varchar(5), @ShiftStartTime2 varchar(5), @ShiftStartTime3 varchar(5), @ShiftStartTime4 varchar(5), @ShiftEndTime varchar(5), @TotalLeaveMint int, @TotalQuarter int 

 Select @ShiftStartTime1 = cast(shmt.StartTime as varchar(5)), @ShiftEndTime = cast(shmt.EndTime as varchar(5)) 
from TBL_ET_ShiftUserMapping(nolock) suma 
inner join TBL_ET_ShiftMaster(nolock) shmt on suma.ShiftId = shmt.ShiftId 
where suma.IsActive = 1 and suma.UserId = @UserId 

set @TotalWorkingMint = DATEDIFF(minute, @ShiftStartTime1, @ShiftEndTime)
set @OneQuarterMint = (@TotalWorkingMint / 4)
--select convert(time,@ShiftStartTime1, 0)
set @ShiftStartTime2 = DATEADD(minute, @OneQuarterMint, convert(time,@ShiftStartTime1, 0)) 
set @ShiftStartTime3 = DATEADD(minute, @OneQuarterMint, convert(time,@ShiftStartTime2, 0)) 
set @ShiftStartTime4 = DATEADD(minute, @OneQuarterMint, convert(time,@ShiftStartTime3, 0)) 
--select @ShiftStartTime1, @ShiftStartTime2, @ShiftStartTime3, @ShiftStartTime4

set @TotalLeaveMint = DATEDIFF(minute, @FromTime, @ToTime)

--set @TotalLeaveMint = 135

set @TotalQuarter = @TotalLeaveMint / @OneQuarterMint
if((@TotalQuarter = 0) and (@TotalLeaveMint < @OneQuarterMint))
Begin
set @TotalQuarter = 1
End
else if((@TotalQuarter > 0) and (@TotalLeaveMint > (@TotalQuarter * @OneQuarterMint)))
Begin
set @TotalQuarter += 1
End
--select @ShiftStartTime1, @ShiftStartTime2, @ShiftStartTime3, @ShiftStartTime4

if((convert(time,@FromTime, 0) >= convert(time,@ShiftStartTime1, 0)) or (convert(time,@FromTime, 0) < convert(time,@ShiftStartTime2, 0)))
Begin
set @StartQuarterDate = 1
End
else if((convert(time,@FromTime, 0) >= convert(time,@ShiftStartTime2, 0)) or (convert(time,@FromTime, 0) < convert(time,@ShiftStartTime3, 0)))
Begin
set @StartQuarterDate = 2
End
else if((convert(time,@FromTime, 0) >= convert(time,@ShiftStartTime3, 0)) or (convert(time,@FromTime, 0) < convert(time,@ShiftStartTime4, 0)))
Begin
set @StartQuarterDate = 3
End
else
Begin
set @StartQuarterDate = 4
End

if((convert(time,@ToTime, 0) >= convert(time,@ShiftStartTime1, 0)) or (convert(time,@ToTime, 0) < convert(time,@ShiftStartTime2, 0)))
Begin
set @EndQuarterDate = 1
End
else if((convert(time,@ToTime, 0) >= convert(time,@ShiftStartTime2, 0)) or (convert(time,@ToTime, 0) < convert(time,@ShiftStartTime3, 0)))
Begin
set @EndQuarterDate = 2
End
else if((convert(time,@ToTime, 0) >= convert(time,@ShiftStartTime3, 0)) or (convert(time,@ToTime, 0) < convert(time,@ShiftStartTime4, 0)))
Begin
set @EndQuarterDate = 3
End
else
Begin
set @EndQuarterDate = 4
End

End

  
 IF (@Mode = 'LS') /*This is for Insert Details */  
 BEGIN  
 if(not Exists(Select 1 from TBL_ET_LeaveRequest (nolock) telr where LeaveId = @LeaveId and ((FromDate between @FromDate and @ToDate)  
 or (FromDate between @FromDate and @ToDate)) and ((StartQuarterDate between @StartQuarterDate and @EndQuarterDate) or (EndQuarterDate between @StartQuarterDate and @EndQuarterDate))))  
 Begin 
 if((Select DATEDIFF(DAY, Cast(GetDate() as Date), Cast(@FromDate as Date)) - isnull(@ApplyBeforeDays, 0)) >=0)  
 Begin  
 
 

 insert into TBL_ET_LeaveRequest (LeaveId, FromDate, ToDate, StartQuarterDate, EndQuarterDate, FromTime, ToTime, TypeOfLeave, Remarks, UserId, CreatedDate, CreatedBy, IsActive)
 values (@LeaveId, @FromDate, @ToDate, @StartQuarterDate, @EndQuarterDate, @FromTime, @ToTime, @TypeOfLeave, @Remarks, @UserId, GETDATE(), @CreatedBy, @IsActive)

 Select cast(scope_identity() as bigint) Id, 'Record Saved' Status
  End
  else
  Begin
	
   Select 0 Id, concat( 'Apply leave before ', cast(@ApplyBeforeDays as varchar(10)), ' Day(s).') Status 
  END /*End here for search*/ 
  END 
  else  
  Begin  
 Select 0 Id, 'Already Exists' Status  
  END /*End here for search*/  
 End  
 Else IF (@Mode = 'LU') /*This is for Insert Details */  
 BEGIN  
 if(Exists(Select 1 from TBL_ET_LeaveRequest (nolock) telr where telr.LeaveRequestId = @LeaveRequestId))  
 Begin  
 if((Select DATEDIFF(DAY, Cast(GetDate() as Date), Cast(@FromDate as Date)) - isnull(@ApplyBeforeDays, 0)) >=0)  
 Begin 
  Update TBL_ET_LeaveRequest set LeaveId = @LeaveId, FromDate = @FromDate, ToDate = @ToDate, StartQuarterDate = @StartQuarterDate, EndQuarterDate = @EndQuarterDate, FromTime = @FromTime, ToTime = @ToTime, TypeOfLeave = @TypeOfLeave, Remarks = @Remarks, UpdatedDate = GETDATE(), UpdatedBy = @CreatedBy, IsActive = @IsActive where LeaveRequestId = @LeaveRequestId  
  Select @LeaveRequestId Id, 'Record Updated' Status  
  End  
  else  
  Begin  
   Select 0 Id, 'Apply leave before ' + cast(@ApplyBeforeDays as varchar(10)) + ' Day(s).' Status  
  END /*End here for search*/  
  END
  else
  Begin
 Select @LeaveRequestId Id, 'Record not Exists' Status
  End
 End

END TRY

BEGIN CATCH  
 DECLARE @ErrorMessage NVARCHAR(4000);  
 SELECT @ErrorMessage = ERROR_MESSAGE();  
 RAISERROR (  
   @ErrorMessage  
   ,16  
   ,1  
   );  
END CATCH 

END



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_LocationPhyList_Name]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--usp_TBL_ET_LocationPhyList_Name 'LS', '', '2023-03-01', '2023-03-31', 34594, 0, 10   
CREATE   PROCEDURE [dbo].[usp_TBL_ET_LocationPhyList_Name]
(
 @Mode VARCHAR(2)
 ,@SearchText varchar(200) = ''
 ,@Contain varchar(200) = ''
 ,@FromDate nvarchar(100) = ''  
 ,@ToDate nvarchar(100) = ''  
 ,@UserId bigint = 0
 ,@Offset int = 0  
 ,@PageSize int = 10 
)
AS  
SET NOCOUNT ON  
BEGIN TRY 

Declare @ParentId bigint , @IsAdmin bit 
 Select @IsAdmin = IsAdmin, @ParentId = ParentId from User_Detail(NOLOCK) where User_ID = @UserId  
 declare @UserIdTeamLst varchar(500) = ''     
declare @tbluser table (User_ID bigint,Name varchar(100), Image varchar(100))
if(@IsAdmin = 1)
	begin
		set @UserId = 0;
		insert into @tbluser
		exec Use_GetUserDetails @ParentId
	end
	else
	Begin
		insert into @tbluser
		exec Use_GetUserDetails @UserId
	End

 select @UserIdTeamLst=isnull(STRING_AGG(User_ID,','),'') From @tbluser
 if(@UserIdTeamLst = '')
 Begin
 set @UserIdTeamLst = Cast(@UserId as varchar(10))
 
 End

 if(@SearchText = '')
 Begin
 set @SearchText = ''
 End

if(@Contain = '')
Begin
 set @Contain = ''
 End
else
Begin
 set @Contain =  ' and ' + @Contain;
End

if(@Mode = 'LS')

Begin
Declare @query nvarchar(max)
set @query = ' Select count(t.User_ID) over() as TotalRecords, * from ( 
select ud.FName + '' '' + ud.LName + '' (''+ud.User_Login+'')'' AssignedToName,ud.User_Id,
tepa.Title, tepa.Description, tepa.Address, tepa.CompleteAddress, tepa.StartDate, tepa.EndDate,
isnull(tepa.OutcomesId, 0) OutcomesId, isnull(fuss.FollowupStatus, '''') FollowupStatus,
isnull(tepa.Status, '''') PhyStatus, ud.Image, ud.ProfilePictureName, isnull((select top 1 Remarks from TBL_ET_PhyAppointComment (nolock) tepc where tepc.PhysicalAppointmentId = tepa.PhysicalAppointmentId order by 1 desc),'''') PhyRemarks, 
 --(udpa.FName + '' '' + udpa.LName) ManagerName, udpa.Image ManagerImage, udpa.ProfilePictureName ManagerProfilePictureName, 
dbo.fn_TBL_ET_PhysicalCollebratorUM_PhyId(tepa.PhysicalAppointmentId,''Collaborator'') Collaboratorlist,
dbo.fn_TBL_ET_PhysicalCollebratorUM_PhyId(tepa.PhysicalAppointmentId,''FieldExecutive'') FieldExecutivelist,
FORMAT(cast((case when geci.CheckIn != '''' then geci.CheckIn else geci.CheckOut end) as datetime), ''dd-MM-yyyy hh:mm tt'') TravelDate,
geci.CheckIn, geci.CheckOut, FORMAT(geci.CheckIn,''hh:mm tt'') CheckInTime, FORMAT(geci.CheckOut,''hh:mm tt'') CheckOutTime,
DateDiff(minute, geci.CheckIn, geci.CheckOut) DurationofWork, '''' Distance, '''' CheckInAddress, '''' CheckOutAddress,
dbo.fun_getEntityDetail_entityId(tepa.GeoEntityId) EntityName, isnull(tege.GeoEntityType, '''') EntityType
from TBL_ET_PhysicalAppointment(nolock) tepa 
left join User_Detail(nolock) ud on tepa.AssignedTo = ud.User_ID
left join FollowUp_Status(nolock) fuss on tepa.OutcomesId = fuss.ID
left join TBL_ET_GeoEntityCheckInOut(nolock) geci on tepa.PhysicalAppointmentId = geci.PhysicalAppointmentId
left join TBL_ET_GeoEntityMaster(nolock) tege on tepa.GeoEntityId = tege.GeoEntityId
left join TBL_ET_GeoEntitySiteMaster(nolock) tegs on tepa.GeoEntitySiteId = tegs.GeoEntitySiteId
where tepa.AssignedTo in (select [value] from dbo.fn_Split('''+ cast(@UserIdTeamLst as nvarchar(max))+ ''', '','')) and
((cast(geci.CheckIn as date) between cast(''' + cast(@FromDate as varchar(10)) +''' as date) and cast(''' + cast(@ToDate as varchar(10)) +''' as date))
or (cast(geci.CheckOut as date) between cast(''' + cast(@FromDate as varchar(10)) +''' as date) and cast(''' + cast(@ToDate as varchar(10)) +''' as date)))
and Title like ''%'+ @SearchText +'%'' ' + @Contain + '
) t
 Order by t.CheckIn desc 
 OFFSET '+ cast(@Offset as varchar(10)) +' Rows FETCH NEXT '+ cast(@PageSize as varchar(10)) +' ROWS ONLY  '

print @query

execute sp_executesql @query
End
END TRY  
BEGIN CATCH  
 DECLARE @ErrorMessage NVARCHAR(4000); 
 SELECT @ErrorMessage = ERROR_MESSAGE(); 
 RAISERROR ( 
   @ErrorMessage 
   ,16 
   ,1 
   ); 
END CATCH 



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_LocationPhyList_NameNew]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_TBL_ET_LocationPhyList_NameNew]
(
	@Mode VARCHAR(2),
	@SearchText varchar(200) = '',
	@Contain varchar(200) = '',
	@FromDate nvarchar(100) = '',
	@ToDate nvarchar(100) = '',
	@UserId bigint = 0,
	@UserIds nvarchar(max) = '',
	@Offset int = 0,
	@PageSize int = 10 
)
AS
BEGIN TRY 

	--declare 
	--	@Mode VARCHAR(2) = N'LS',
	--	@SearchText varchar(200) = '',
	--	@Contain varchar(200) = '',
	--	@FromDate nvarchar(100) = N'05-Nov-2024',
	--	@ToDate nvarchar(100) = N'11-Nov-2024',
	--	@UserId bigint = 43966,
	--	@UserIds nvarchar(max) = '',
	--	@Offset int = 0,
	--	@PageSize int = 10



	declare @ParentId bigint , @IsAdmin bit, @StartPoint int  = 1, @Endpoint int = 100
	
	select @IsAdmin = IsAdmin, @ParentId = ParentId from User_Detail(NOLOCK) where User_ID = @UserId  
	select @StartPoint = (@Offset + 1), @Endpoint = (@PageSize + @Offset)



	drop table if exists #userTable
	create table #userTable( User_ID bigint,Name nvarchar(100), Image nvarchar(100) )

	if(@Mode = 'LS')
	begin
		
		declare @sqlQuery nvarchar(max)
		
		declare @UserIdTeamLst varchar(500) = ''     
		declare @tbluser table (User_ID bigint,Name varchar(100), Image varchar(100))
		if(@IsAdmin = 1)
		begin
			set @UserId = 0;
			insert into #userTable
			exec Use_GetUserDetails @ParentId
		end
		else
		begin
			insert into #userTable
			exec Use_GetUserDetails @UserId
		end

		if(@SearchText = '') begin set @SearchText = '' end
		if(@Contain = '') begin set @Contain = '' end else begin set @Contain =  ' and ' + @Contain end


		if(ISNULL(@UserIds, '') =  '') begin set @UserIds = '' end

		drop table if exists #tempSelectedUser
		create table #tempSelectedUser ( UserId bigint )
		insert into #tempSelectedUser(UserId) select [value] from string_split(@UserIds, ',')

		set @sqlQuery = concat( N'select p.SNo, p.TotalRecords, ',
			  N'concat( p.FName, '' '', p.LName, '' ('', p.User_Login, '')'' ) AssignedToName, ',
			  N'p.User_Login,  isnull(p.FName,'''') + '' '' + isnull(p.LName,'''')  as [UserFullName] ,',
			  N'( dbo.udf_GetTerritoryDefination(p.AssignedTo) ) AS [TerritoryDefination], ',
			  N'p.User_Id, p.PhysicalAppointmentId, p.Title, p.Description, p.Address, p.CompleteAddress, ',
			  N'format( p.StartDate, ''dd-MMM-yyyy HH:mm'' ) as [StartDate], ',
			  N'format( p.EndDate, ''dd-MMM-yyyy HH:mm'' ) as [EndDate], ',
			  N'isnull(p.OutcomesId, 0) OutcomesId, isnull(uom.OutcomeName, '''') as [OutcomeName], ',
			  N'isnull(uom.Indent, '''') as [OutcomeIntent], isnull(p.Status, '''') PhyStatus, ',
			  N'p.Image, p.ProfilePictureName, p.Remarks as [PhyRemarks], ',
			  N'coalesce( tege.GeoEntityName, tegs.GeoEntitySiteName ) as [GeoEntitySiteName], ',
			  N'tegs.GeoEntitySiteId as [GeoEntitySiteId], tegs.Latitude as [SiteLatitude], ',
			  N'tegs.Longitude as [SiteLongitude],  tegs.MapAddress as [SiteMapAddress], ',
			  N'tegs.Address as [SiteAddress],  tegs.City as [SiteCity], ',
			  N'tegs.State as [SiteState],  tegs.Country as [SiteCountry], ',
			  N'tege.Mobile as [MobileNo], ',
			  N'tege.EmailId as [EmailId], ',
			  N'tegs.PinCode as [SitePinCode],  tege.GeoEntityType as [SiteGeoEntityType], ',
			  N'dbo.fn_TBL_ET_PhysicalCollebratorUM_PhyId( p.PhysicalAppointmentId, ''Collaborator'' ) Collaboratorlist, ',
			  N'dbo.fn_TBL_ET_PhysicalCollebratorUM_PhyId( p.PhysicalAppointmentId, ''FieldExecutive'' ) FieldExecutivelist, ',
			  N'FORMAT( cast( ( case when p.CheckIn != '''' then p.CheckIn else p.CheckOut end ) as datetime ),  ''dd-MM-yyyy'' ) TravelDate, ',
			  N'format( p.CheckIn, ''dd-MMM-yyyy HH:mm'' ) as [CheckIn], ',
			  N'format( p.CheckOut, ''dd-MMM-yyyy HH:mm'' ) as [CheckOut], ',
			  N'tege.EntityId as [SiteGeoEntityId], ',
			  N'case when '+cast(@pagesize as nvarchar)+' > 10 then ''{}'' else isnull( dbo.udf_et_GetPhyAppointmentTravelData( p.AssignedTo, ',
			  N'( case when p.CheckIn != '''' then p.CheckIn else p.CheckOut end ), p.PhysicalAppointmentId ), ''{}'' ) end as [TravelData], ',
			  N'( case when isnull(p.CheckIn, '''') = '''' or '+cast(@pagesize as nvarchar)+' > 10 then ''{}'' ',
			  N'else dbo.udf_GetClosestUserLocation( p.AssignedTo, cast(p.CheckIn as datetime) ) end ) as [LocationInfo], ',
			  N'isnull(tege.GeoEntityType, '''') EntityType ',
			N'from ( select t.SNo, t.TotalRecords, ',
				N't.GeoEntitySiteId, t.CheckIn, t.CheckOut, t.Address, t.AssignedTo, t.CompleteAddress, ',
				N't.Description, t.EndDate, t.OutcomesId, t.PhysicalAppointmentId, t.Remarks, t.StartDate, ',
				N't.Status, t.Title, t.FName, t.Image, t.LName, t.ProfilePictureName, t.User_Id, t.User_Login ',
			N'from ( select ',
					N'row_number() over(partition by ud.ParentId order by tepa.PhysicalAppointmentId desc) as SNo, ',
					N'count(tepa.AssignedTo) over() as TotalRecords, ',
					N'geci.CheckIn, geci.CheckOut, tepa.GeoEntitySiteId, tepa.Address, tepa.AssignedTo, tepa.CompleteAddress, tepa.Description, ',
					N'tepa.EndDate, tepa.OutcomesId, tepa.PhysicalAppointmentId, tepa.Remarks, tepa.StartDate, tepa.Status, tepa.Title, ud.FName, ud.Image, ',
					N'ud.LName, ud.ProfilePictureName, ud.User_Id, ud.User_Login ',
			N'from TBL_ET_PhysicalAppointment(nolock) tepa ',
				N'inner join #userTable tu on tepa.AssignedTo = tu.User_Id ',
				iif(LEN(@UserIds) > 0, 'inner join #tempSelectedUser  su on tepa.AssignedTo = su.UserId ', ''),
				N'inner join TBL_ET_GeoEntityCheckInOut(nolock) geci on tepa.PhysicalAppointmentId = geci.PhysicalAppointmentId ',
				N'inner join User_Detail(nolock) ud on tepa.AssignedTo = ud.User_ID ',
			N'where ( ( cast(geci.CheckIn as date) between cast(''',@FromDate, ''' as date) and cast(''', @ToDate,''' as date)) ',
				N'or ( cast(geci.CheckOut as date) between cast(''',@FromDate, ''' as date) and cast(''', @ToDate,''' as date)) ',
				N')  and (  ud.User_Login like ''%', @SearchText, '%'' ',
				N'or ud.FName like ''%', @SearchText, '%'' or ud.LName like ''%', @SearchText, '%'' or tepa.Title like ''%', @SearchText, '%'' ',
			N')) t where t.SNo between ', @StartPoint, ' and ', @Endpoint, ' ) p ',
			N'left join TBL_ET_GeoEntitySiteMaster(nolock) tegs on p.GeoEntitySiteId = tegs.GeoEntitySiteId ',
			N'left join TBL_ET_GeoEntityMaster(nolock) tege on tegs.GeoEntityId = tege.GeoEntityId ',
			N'left join tbl_tsk_UserOutcomeMaster(nolock) uom on p.OutcomesId = uom.Id ',
			N'order by p.SNo asc ')

		print @sqlQuery

		execute sp_executesql @sqlQuery



	end
END TRY  
BEGIN CATCH  
	exec usp_InsertErrorInfo
END CATCH 





GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_LocationPhyList_NameNew_Cache]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_TBL_ET_LocationPhyList_NameNew_Cache]
(
	@Mode VARCHAR(2),
	@SearchText varchar(200) = '',
	@Contain varchar(200) = '',
	@FromDate nvarchar(100) = '',
	@ToDate nvarchar(100) = '',
	@UserId bigint = 0,
	@UserIds nvarchar(max) = '',
	@Offset int = 0,
	@PageSize int = 10 
)
AS 
BEGIN 
			--exec usp_TBL_ET_LocationPhyList_NameNew_Cache @Mode=N'LS',@SearchText=default,@Contain=default,@FromDate=N'01-Jan-2023',@ToDate=N'27-Nov-2024',@UserId=32222,@UserIds=default,@Offset=0,@PageSize=10

			DECLARE @MonthStart DATETIME;
			DECLARE @MonthEnd DATETIME;
			declare @ParentID bigint = 0;		

			select @ParentID = ParentID from Mysms.[dbo].User_Detail(nolock) where User_ID = @UserId;

				-- Get the first and last date of the current month
				--SET @MonthStart = FORMAT(DATEADD(DAY, 1 - DAY(GETDATE()), CAST(GETDATE() AS DATE)), 'dd-MMM-yyyy'); -- First day of current month
				--SET @MonthEnd = FORMAT(EOMONTH(GETDATE()), 'dd-MMM-yyyy'); -- Last day of current month

				Declare @Currentdate  DATE  = GETDATE();  -- Today's date
				SET @MonthStart      = FORMAT(DATEADD(DAY, -30, @Currentdate), 'dd-MMM-yyyy'); -- 30 days before today
				SET @MonthEnd  =  FORMAT(DATEADD(DAY, -1, @Currentdate), 'dd-MMM-yyyy');

				if(ISNULL(@UserIds, '') =  '') begin set @UserIds = '' end

				-- Check conditions and select data
				IF (@FromDate Between @MonthStart AND @MonthEnd AND @ToDate Between @MonthStart AND @MonthEnd)  
					BEGIN
					   SELECT [LocationReportId]
							  ,[TravelDate]
							  ,[SNo]
							  ,[TotalRecords]
							  ,[AssignedToName]
							  ,[UserFullName]
							  ,[User_Login]
							  ,[PhysicalAppointmentId]
							  ,[Title]
							  ,[Description]
							  ,[Address]
							  ,[CompleteAddress]
							  ,[StartDate]
							  ,[EndDate]
							  ,[OutcomeName]
							  ,[OutcomeIntent]
							  ,[PhyRemarks]
							  ,[GeoEntitySiteId]
							  ,[GeoEntitySiteName]
							  ,[SiteLatitude]
							  ,[SiteLongitude]
							  ,[SiteMapAddress]
							  ,[SiteAddress]
							  ,[SiteCity]
							  ,[SiteState]
							  ,[SiteCountry]
							  ,[MobileNo]
							  ,[EmailId]
							  ,[SitePinCode]
							  ,[SiteGeoEntityType]
							  ,[SiteGeoEntityId]
							  ,[TerritoryDefination]
							  ,[TravelData]
							  ,[LocationInfo]
							  ,[CheckIn]
							  ,[CheckOut]
						 FROM [dbo].[tbl_LocationReport_Cache](nolock)
						WHERE UserId= @UserId and ParentId = @ParentID and (@UserIds = '' OR UserId = @UserIds) and cast([TravelDate] as date) between @FromDate and @ToDate 
					END
			ELSE IF (@FromDate < @MonthStart OR @ToDate < @MonthStart)
				BEGIN
					   SELECT [LocationReportId]
							  ,[TravelDate]
							  ,[SNo]
							  ,[TotalRecords]
							  ,[AssignedToName]
							  ,[UserFullName]
							  ,[User_Login]
							  ,[PhysicalAppointmentId]
							  ,[Title]
							  ,[Description]
							  ,[Address]
							  ,[CompleteAddress]
							  ,[StartDate]
							  ,[EndDate]
							  ,[OutcomeName]
							  ,[OutcomeIntent]
							  ,[PhyRemarks]
							  ,[GeoEntitySiteId]
							  ,[GeoEntitySiteName]
							  ,[SiteLatitude]
							  ,[SiteLongitude]
							  ,[SiteMapAddress]
							  ,[SiteAddress]
							  ,[SiteCity]
							  ,[SiteState]
							  ,[SiteCountry]
							  ,[MobileNo]
							  ,[EmailId]
							  ,[SitePinCode]
							  ,[SiteGeoEntityType]
							  ,[SiteGeoEntityId]
							  ,[TerritoryDefination]
							  ,[TravelData]
							  ,[LocationInfo]
							  ,[CheckIn]
							  ,[CheckOut]
						  FROM [dbo].[tbl_LocationReport_Archive](nolock)
						WHERE UserId= @UserId and ParentId = @ParentID and (@UserIds = '' OR UserId = @UserIds) and cast([TravelDate] as date) between @FromDate and @ToDate  
				END
				ELSE
					BEGIN
						EXEC [Mysms].[dbo].usp_TBL_ET_LocationPhyList_NameNew @Mode, @SearchText, @Contain, @FromDate, @ToDate, @UserId, @UserIds, @Offset, @PageSize;
					END

END 



