NumberOfBreaks, (cast(cast(TimeInBreaks/60 as int)as varchar(10)) +'':''+ cast(cast((TimeInBreaks%60)as int) as varchar(5))+ '' hrs.'') TotalTimeInBreaks, (cast(cast(MaxBreakTimes/60 as int)as varchar(10)) +'':''+ cast(cast((MaxBreakTimes%60)as int) as varchar(5))+ '' hrs.'') MaxBreakTime, TotalTask, 
(cast(cast(TimeSpentInTasks/60 as int)as varchar(10)) +'':''+ cast(cast((TimeSpentInTasks%60)as int) as varchar(5))+ '' hrs.'') TotalTimeSpentInTasks,
(cast(cast(TotalTimeSpentTravelled/60 as int)as varchar(10)) +'':''+ cast(cast((TotalTimeSpentTravelled%60)as int) as varchar(5)) + '' hrs.'') TotalTimeSpentTravel,
TotalClaim, TotalApproved, TotalDistance, TotalTravelTime
from (
