'''' TeamName, '''' InternalId
,-- isnull(thia.Parentid, 0)
0 HirarchyParentid,
dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, '''+ @FromDate+''', '''+ @ToDate+''', ''TotalWorkingDay'') PresentDays, 
