dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, '''+ @FromDate +''', '''+ @ToDate+''', ''TotalDays'') TotalDays, 
dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, '''+ @FromDate +''', '''+ @ToDate+''', ''LateSignin'') InLateDays, 
dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, '''+ @FromDate +''', '''+ @ToDate+''', ''OutEarlyDays'') OutEarlyDays,
dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, '''+ @FromDate +''', '''+ @ToDate+''', ''Totalminutes'') TotalAttendanceTime,
dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, '''+ @FromDate +''', '''+ @ToDate+''', ''NumberOfBreaks'') NumberOfBreaks,
dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, '''+ @FromDate +''', '''+ @ToDate+''', ''TimeInBreaks'') TimeInBreaks,
dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, '''+ @FromDate +''', '''+ @ToDate+''', ''MaxBreakTimes'') MaxBreakTimes,
dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, '''+ @FromDate +''', '''+ @ToDate+''', ''TotalTask'') TotalTask,
dbo.fn_TBL_ET_AttendanceTotalSummaryFT(ud.User_ID, '''+ @FromDate +''', '''+ @ToDate+''', ''TimeSpentInTasks'') TimeSpentInTasks,
dbo.fn_TBL_ET_ExpenseTotalSummaryFT(ud.User_ID, '''+ @FromDate +''', '''+ @ToDate+''', ''TotalTimeSpentTravelled'') TotalTimeSpentTravelled,
dbo.fn_TBL_ET_ExpenseTotalSummaryFT(ud.User_ID, '''+ @FromDate +''', '''+ @ToDate+''', ''TotalClaim'') TotalClaim,
dbo.fn_TBL_ET_ExpenseTotalSummaryFT(ud.User_ID, '''+ @FromDate +''', '''+ @ToDate+''', ''TotalApproved'') TotalApproved,
dbo.fn_TBL_ET_ExpenseTotalSummaryFT(ud.User_ID, '''+ @FromDate +''', '''+ @ToDate+''', ''TotalDistance'') TotalDistance,
dbo.fn_TBL_ET_ExpenseTotalSummaryFT(ud.User_ID, '''+ @FromDate +''', '''+ @ToDate+''', ''TotalTravelTime'') TotalTravelTime
from User_detail(nolock) ud 
inner join User_detail(nolock) udpa on ud.ParentId = udpa.User_Id 
--left join #TblHirarchy thia on ud.User_Id = thia.User_Id 
where ud.User_Id in (select item from dbo.fu_SplitString(''' + cast(@UserIds as nvarchar(max)) + ''', '','')) 
)q )t where (1=1) ' + @SearchText + ' ' + @Contain + '' 

print @query

execute sp_executesql @query

 End 
END TRY 

