/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_PhysicalApp_CommentAtt]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE  [dbo].[usp_TBL_ET_PhysicalApp_CommentAtt](
	@Remarks nvarchar(max),
	@PhysicalAppointmentId bigint,
	@CreatedBy bigint,
	@tblStringList tblStringList readonly
)
as
begin
	declare @PhyAppointCommentId bigint =- 0;
	begin transaction
	begin try
		declare @ParentId bigint, @Username nvarchar(255), @TaskTitle nvarchar(255), @LeadId bigint, @TaskTypeId bigint

		select @ParentId = ParentId, @Username = User_Login from User_Detail(nolock) where User_Id = @CreatedBy 

		select  @TaskTitle = Title, @LeadId = GeoEntityId, @TaskTypeId = PhysicalAppointmentId from TBL_ET_PhysicalAppointment(nolock) where PhysicalAppointmentId  = @PhysicalAppointmentId
		
		insert into TBL_ET_PhyAppointComment(Remarks, PhysicalAppointmentId, ParentId, CreatedDate, CreatedBy, IsActive)
		select @Remarks, @PhysicalAppointmentId, @ParentId, GetDate(), @CreatedBy, 1
	
		set @PhyAppointCommentId = scope_identity()

		if(exists(select 1 from @tblStringList))
		begin
			insert into TBL_ET_PhyAppointCommentAttachment(FileName, CreatedBy, CreatedDate, ParentId, PhyAppointCommentId )
				select strValue, @CreatedBy, getdate(), @ParentId, @PhyAppointCommentId from @tblStringList
		end

		declare @event_title nvarchar(255) = '', @event_description nvarchar(max) = ''

		set @event_title =concat('Comment added to ', iif(@TaskTypeId = 8, 'appointment', 'task' ))

		set @event_description =concat('A comment was added by ', @Username, ' to ', 
			iif(@TaskTypeId = 8, 'appointment', 'task' ), ' titled ', @TaskTitle ,' at ', cast(getdate() as nvarchar))

		exec UspSaveLeadActivity_withid @LeadId, @CreatedBy, @ParentId, @event_description, @event_title, 'TBL_ET_PhyAppointComment',  @PhyAppointCommentId


		commit transaction
	end try
	begin catch
		rollback transaction
		set @PhyAppointCommentId  = 0
		exec usp_InsertErrorInfo
	end catch
	select @PhyAppointCommentId as CommentId
end



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_PhysicalApp_CommentAttWithFileRemarks]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_TBL_ET_PhysicalApp_CommentAttWithFileRemarks]
(
    @Remarks nvarchar(max),
    @PhysicalAppointmentId bigint,
    @CreatedBy bigint,
    @tblFileRemarks dbo.tblFileRemarks readonly
)
AS
BEGIN
    DECLARE @PhyAppointCommentId bigint = -0;
    BEGIN TRANSACTION;
    BEGIN TRY
        DECLARE @ParentId bigint,
                @Username nvarchar(255),
                @TaskTitle nvarchar(255),
                @LeadId bigint,
                @TaskTypeId bigint;

        SELECT @ParentId = ParentId, @Username = User_Login
        FROM User_Detail (NOLOCK)
        WHERE User_Id = @CreatedBy;

        SELECT @TaskTitle = Title, @LeadId = GeoEntityId, @TaskTypeId = PhysicalAppointmentId
        FROM TBL_ET_PhysicalAppointment (NOLOCK)
        WHERE PhysicalAppointmentId = @PhysicalAppointmentId;

        INSERT INTO TBL_ET_PhyAppointComment (Remarks, PhysicalAppointmentId, ParentId, CreatedDate, CreatedBy, IsActive)
        VALUES (@Remarks, @PhysicalAppointmentId, @ParentId, GETDATE(), @CreatedBy, 1);

        SET @PhyAppointCommentId = SCOPE_IDENTITY();

        -- Insert file attachments with per-file remarks (if any rows supplied)
        IF EXISTS (SELECT 1 FROM @tblFileRemarks)
        BEGIN
            INSERT INTO TBL_ET_PhyAppointCommentAttachment (FileName, Remarks, CreatedBy, CreatedDate, ParentId, PhyAppointCommentId)
            SELECT FileName, Remarks, @CreatedBy, GETDATE(), @ParentId, @PhyAppointCommentId
            FROM @tblFileRemarks;
        END

        DECLARE @event_title nvarchar(255) = '', @event_description nvarchar(max) = '';

        SET @event_title = CONCAT('Comment added to ', IIF(@TaskTypeId = 8, 'appointment', 'task'));

        SET @event_description = CONCAT('A comment was added by ', @Username, ' to ',
            IIF(@TaskTypeId = 8, 'appointment', 'task'), ' titled ', @TaskTitle, ' at ', CAST(GETDATE() AS NVARCHAR));

        EXEC UspSaveLeadActivity_withid @LeadId, @CreatedBy, @ParentId, @event_description, @event_title, 'TBL_ET_PhyAppointComment', @PhyAppointCommentId;

        COMMIT TRANSACTION;
    END TRY
    BEGIN CATCH
        ROLLBACK TRANSACTION;
        SET @PhyAppointCommentId = 0;
        EXEC usp_InsertErrorInfo;
    END CATCH

    SELECT @PhyAppointCommentId AS CommentId;

    -- Audit row JSON
    DECLARE @rowJson NVARCHAR(MAX) = (
        SELECT * FROM TBL_ET_PhyAppointComment WITH (NOLOCK) WHERE PhyAppointCommentId = @PhyAppointCommentId FOR JSON AUTO, INCLUDE_NULL_VALUES
    );

    EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @CreatedBy,
        @Activity_type = 'Inst_PhysApp_cmmnt',
        @ActionType = 'I',
        @RowJson = @rowJson,
        @Table_name = 'TBL_ET_PhyAppointComment';
END



GO

