	--	,@gCalendarId nvarchar(MAX) = N''
	--	,@CancelMeeting bit = 0  
	--	,@Status varchar(20) = null  
	--	,@task_deletedOn datetime = null  
	--	,@Remarks nvarchar(1000) = null  
	--	,@CollaboratorList varchar(4000) = N''  
	--	,@FieldExecutiveList varchar(4000) = N'32222'  
	--	,@EntityId bigint = 10843583
	--	,@EntityType varchar(20) = 'lead' -- lead/enquiry/location(3)  
	--	,@EntityName varchar(200) = N'Test Aug Lead'
	--	,@Mobile varchar(200) = N'1234567892,,'  
	--	,@EmailId varchar(200) = N'test98@gmail.com,,'
	--	,@Latitude float = N'21.2128703'
	--	,@Longitude float = N'72.8233487'  
	--	,@CreatedBy bigint = 32222  
	--	,@FileName varchar(300) = null  
	--	,@IsActive bit = 1  
  
 --IF (@Mode = 'PP') /*This is for Insert Details */  
 --BEGIN  
 --Declare @ParentId bigint  
 --Select @ParentId = ParentId from User_Detail(nolock) where User_ID = @CreatedBy  
  
 --Declare @GeoEntityId bigint, @ID BIGINT  
  
 --select @GeoEntityId = GeoEntityId from TBL_ET_PhysicalAppointment (nolock) where GeoEntitySiteId = @GeoEntitySiteId  
  
 --if((@Title != '') and (@Description != '') and (@GeoEntitySiteId > 0) and (@StartDate != '') and (@EndDate != ''))  
 --   Begin  
 --    INSERT INTO TBL_ET_PhysicalAppointment (  
 --   Title  
 --   ,Description  
 --   ,Address  
 --   ,StartDate  
 --   ,EndDate  
 --   ,GeoEntityId  
