 --   ,GETDATE()      
 --   )  
 -- SET @ID = scope_identity();  
 --    SELECT 'Record Saved' STATUS, @ID PhysicalAppointmentId  
 --      End  
 --   ELSE  
 --   BEGIN  
 -- SELECT 'Record Already Exist' STATUS  
 --   END  
  
 --END /*End here for insert*/  
 declare @ParentId bigint  
 Select @ParentId = ParentId from User_Detail(nolock) where User_ID = @CreatedBy  
   
   Declare @GeoEntityId bigint, @ID BIGINT  
     
   if not Exists(select top 1 EntityId from TBL_ET_GeoEntityMaster(nolock) where EntityId = @EntityId and GeoEntityType = @EntityType)  
   Begin  
     
	if(@EntityType = 'lead')  
 Begin  
 --347631  
  
	insert into TBL_ET_GeoEntityMaster (EntityId, GeoEntityType, GeoEntityName, Mobile, EmailId, ParentId, CreatedDate, CreatedBy, IsActive)  
	select top 1 ID, @EntityType, PersonName, CONCAT(MobileNo, ',', MobileNo1, ',', MobileNo2), CONCAT(EmailID, ',', EmailID1, ',', EmailID2), @ParentId, GetDate(), @CreatedBy, 1 from UserLeads (nolock) where Id = @EntityId  
   
	set @GeoEntityId = scope_identity();  
 End  
 else if(@EntityType = 'enquiry')  
 Begin  
	insert into TBL_ET_GeoEntityMaster (EntityId, GeoEntityType, GeoEntityName, Mobile, EmailId, ParentId, CreatedDate, CreatedBy, IsActive)  
	select top 1 EnquiryId, @EntityType, PersonName, CONCAT(MobileNo, ',', MobileNo1, ',', MobileNo2), CONCAT(EmailID, ',', EmailID1, ',', EmailID2), @ParentId, GetDate(), @CreatedBy, 1 from UserEnquiry(nolock) where EnquiryId = @EntityId  
	set @GeoEntityId = scope_identity();  
 end  
 end  
 else if(@EntityType = 'location')  
 begin  
	insert into TBL_ET_GeoEntityMaster (EntityId, GeoEntityType, GeoEntityName, Mobile, EmailId, ParentId, CreatedDate, CreatedBy, IsActive)  
	select @EntityId, @EntityType, @EntityName, @Mobile, @EmailId, @ParentId, GetDate(), @CreatedBy, 1   
	set @GeoEntityId = scope_identity();  
 end
 else  
 Begin  
	select @GeoEntityId = GeoEntityId from TBL_ET_GeoEntityMaster(nolock) where EntityId = @EntityId and GeoEntityType = @EntityType   
 end  
  
 insert TBL_ET_GeoEntitySiteMaster (GeoEntitySiteName, GeoEntityId, Latitude, Longitude, MapAddress, Address, CreatedDate, CreatedBy, IsActive)  
 select @EntityName, @GeoEntityId, @Latitude, @Longitude, @CompleteAddress, @Address, GetDate(), @CreatedBy, 1  
   
 set @GeoEntitySiteId = scope_identity();  


 --select @GeoEntityId1 = GeoEntityId from TBL_ET_PhysicalAppointment (nolock) where GeoEntitySiteId = @GeoEntitySiteId  
   
 IF (@Mode = 'PI') /*This is for Insert Details */  
 BEGIN  
   
	if((@Title != '') and (@GeoEntitySiteId > 0) and (@StartDate != '') and (@EndDate != ''))  
	Begin  
	
		INSERT INTO TBL_ET_PhysicalAppointment (Title, Description, Address, StartDate, EndDate, GeoEntityId, 
			GeoEntitySiteId, AssignedTo, TaskTypeId, CompleteAddress, gCalendarId, ParentId, IsActive, CreatedBy, CreatedDate)  
		VALUES ( @Title, @Description, @Address, @StartDate, @EndDate, @GeoEntityId, 
			@GeoEntitySiteId, @AssignedTo, @TaskTypeId, @CompleteAddress, @gCalendarId, @ParentId, @IsActive, @CreatedBy, GETDATE()      
			)  
	
	
	SET @ID = scope_identity();  
	--Save In Collaborator  
	if(@CollaboratorList != '')  
	Begin  
	Insert into TBL_ET_PhyAppointCollaboratorUserMapping(UserId, PhysicalAppointmentId, CreatedBy, CreatedDate, IsActive)  
	select value, @ID, @CreatedBy, GETDATE(), 1 from STRING_SPLIT(@CollaboratorList, ',')  
	End  
    
	--Save In Field Executive  
	if(@FieldExecutiveList != '')  
	Begin  
	Insert into TBL_ET_PhyAppointUserMapping(UserId, PhysicalAppointmentId, CreatedBy, CreatedDate, IsActive)  
	select value, @ID, @CreatedBy, GETDATE(), 1 from STRING_SPLIT(@FieldExecutiveList, ',')  
	End    
		SELECT 'Record Saved' STATUS, @ID PhysicalAppointmentId  

		exec usp_GenerateActivityByRefTable @RefTable = 'TBL_ET_PhysicalAppointment', @RefTableId = @ID 
	End  
	ELSE  
	BEGIN  
	SELECT 'Record Already Exist' STATUS  
	END  
  
 END /*End here for insert*/  
  
 Else IF (@Mode = 'PU') /*This is for Update Details */  
 BEGIN  
	 if( isnull(@Title, '') <> '' --and isnull(@Description, '') <> ''   
	  and isnull(@GeoEntitySiteId, 0) > 0  and isnull(@StartDate, '') <> '' and isnull(@EndDate, '') <> ''  
	  --and (isnull(@OutcomesId, 0) = 0)  
	 )  
	 begin  
		declare @GeoEntitySiteName varchar(200)  
  
		select @GeoEntityId = GeoEntityId, @GeoEntitySiteName = GeoEntityName from TBL_ET_GeoEntityMaster(nolock)   
		where EntityId = @EntityId and GeoEntityType = @EntityType  
  
		update TBL_ET_GeoEntitySiteMaster set GeoEntitySiteName = @GeoEntitySiteName, GeoEntityId = @GeoEntityId, Latitude = @Latitude, Longitude = @Longitude, MapAddress = @CompleteAddress, Address = @Address, UpdatedDate = GetDate(), UpdatedBy = @CreatedBy, IsActive = 1   
		where GeoEntitySiteId = @GeoEntitySiteId  
   
		Update TBL_ET_PhysicalAppointment set Title = @Title, Description = @Description, Address = @Address, StartDate = @StartDate,  
		EndDate = @EndDate, GeoEntityId = @GeoEntityId, GeoEntitySiteId = @GeoEntitySiteId, AssignedTo = @AssignedTo,   
		TaskTypeId = @TaskTypeId, CompleteAddress = @CompleteAddress, gCalendarId = @gCalendarId, UpdatedBy = @CreatedBy, UpdatedDate = GETDATE()  
		where PhysicalAppointmentId = @PhysicalAppointmentId  
  
		print @CollaboratorList
	  --Update In Collaborator  
		if(@CollaboratorList != '')  
		Begin  
			Insert into TBL_ET_PhyAppointCollaboratorUserMapping(UserId, PhysicalAppointmentId, CreatedBy, CreatedDate, IsActive)  
			select value, @PhysicalAppointmentId, @CreatedBy, GETDATE(), 1 from STRING_SPLIT(@CollaboratorList, ',')   
			where value not in (select UserId from TBL_ET_PhyAppointCollaboratorUserMapping(nolock) where PhysicalAppointmentId = @PhysicalAppointmentId)  
		End  
    
			--Update In Field Executive  
		if(@FieldExecutiveList != '')  
		begin  
			Insert into TBL_ET_PhyAppointUserMapping(UserId, PhysicalAppointmentId, CreatedBy, CreatedDate, IsActive)  
			select value, @PhysicalAppointmentId, @CreatedBy, GETDATE(), 1 from STRING_SPLIT(@FieldExecutiveList, ',') where value not in (select UserId from TBL_ET_PhyAppointUserMapping(nolock) where PhysicalAppointmentId = @PhysicalAppointmentId)  
		end 
		select 'Record Updated' [STATUS], @PhysicalAppointmentId PhysicalAppointmentId  
	end  
	else if (isnull(@OutcomesId, 0) > 0)  
	Begin  
		SELECT 'Record can not update, Outcomes already Saved.' STATUS  
	End  
	ELSE  
	BEGIN  
		SELECT 'Update Issue.' STATUS  
	End
	
	
  
 END /*End here for update*/  
 Else IF (@Mode = 'PA') /*This is for Select Details */  
 BEGIN  
  
 select PhysicalAppointmentId, Title, Description, phap.Address AppointmentAddress, StartDate, EndDate,   
 phap.GeoEntityId, phap.GeoEntitySiteId, AssignedTo, TaskTypeId, OutcomesId,   
 CompletedOn, CompleteAddress, gCalendarId, CancelMeeting, Status, phap.ParentId, task_deletedOn, phap.Remarks,   
 GeoEntityName, GeoEntityType, EntityId, Mobile, EmailId,  
 GeoEntitySiteName, Latitude, Longitude, MapAddress, gesm.Address SiteAddress, City, State, Country, PinCode  
 --CreatedDate, CreatedBy, UpdatedDate, UpdatedBy, IsActive   
 from TBL_ET_PhysicalAppointment phap (nolock)  
 left join TBL_ET_GeoEntitySiteMaster gesm (nolock) on phap.GeoEntitySiteId = gesm.GeoEntitySiteId  
 left join TBL_ET_GeoEntityMaster gemr (nolock) on gesm.GeoEntityId = gemr.GeoEntityId   
 where phap.CreatedBy = @CreatedBy and phap.Title like '%'+ @Title +'%'   
 --and ((phap.StartDate between isnull(@StartDate, phap.StartDate) and isnull(@EndDate, phap.EndDate)) or (phap.EndDate between isnull(@StartDate, phap.StartDate) and isnull(@EndDate, phap.EndDate)))  
  
 END  
 Else IF (@Mode = 'PL')  
 BEGIN  
 set @StartDate = DATEADD(DAY, -50, GETDATE())  
 set @EndDate = GETDATE()  
 Select * from (  
    select phap.PhysicalAppointmentId, Title, Title + '-CheckIn-' + cast(StartDate as varchar(100)) +'-'+ cast(EndDate as varchar(100)) TitleData,  
  Description, phap.Address AppointmentAddress, StartDate, EndDate,   
  phap.GeoEntityId, phap.GeoEntitySiteId, AssignedTo, TaskTypeId, OutcomesId,   
  CompletedOn, CompleteAddress, gCalendarId, CancelMeeting, Status, phap.ParentId, task_deletedOn, phap.Remarks,   
  GeoEntityName, GeoEntityType, EntityId, Mobile, EmailId,  
  GeoEntitySiteName, Latitude, Longitude, MapAddress, gesm.Address SiteAddress, City, State, Country, PinCode  
  from TBL_ET_PhysicalAppointment phap (nolock)  
  inner join TBL_ET_GeoEntityCheckInOut(nolock) gecu on ((phap.PhysicalAppointmentId != gecu.PhysicalAppointmentId)   
  or (gecu.CheckIn between @StartDate and @EndDate)  
  )  
  inner join TBL_ET_GeoEntityCheckInOutRequest(nolock) gecur on phap.PhysicalAppointmentId != gecur.PhysicalAppointmentId and gecur.ActionType = 'CheckIn'  
  left join TBL_ET_GeoEntitySiteMaster gesm (nolock) on phap.GeoEntitySiteId = gesm.GeoEntitySiteId  
  left join TBL_ET_GeoEntityMaster gemr (nolock) on gesm.GeoEntityId = gemr.GeoEntityId   
  where ((phap.StartDate between @StartDate and @EndDate) or (phap.EndDate between @StartDate and @EndDate)) and   
  phap.CreatedBy = @CreatedBy   
  and CancelMeeting Is null  
  and phap.Title like '%'+ @Title +'%'  
  union  
  select phap.PhysicalAppointmentId, Title, Title + '-CheckOut-' + cast(StartDate as varchar(100)) +'-'+ cast(EndDate as varchar(100)) TitleData,  
  Description, phap.Address AppointmentAddress, StartDate, EndDate,   
  phap.GeoEntityId, phap.GeoEntitySiteId, AssignedTo, TaskTypeId, OutcomesId,   
  CompletedOn, CompleteAddress, gCalendarId, CancelMeeting, Status, phap.ParentId, task_deletedOn, phap.Remarks,   
  GeoEntityName, GeoEntityType, EntityId, Mobile, EmailId,  
  GeoEntitySiteName, Latitude, Longitude, MapAddress, gesm.Address SiteAddress, City, State, Country, PinCode  
  from TBL_ET_PhysicalAppointment phap (nolock)  
  inner join TBL_ET_GeoEntityCheckInOut(nolock) gecu on phap.PhysicalAppointmentId != gecu.PhysicalAppointmentId   
  and ((phap.PhysicalAppointmentId = gecu.PhysicalAppointmentId) or (gecu.CheckOut between @StartDate and @EndDate))  
  inner join TBL_ET_GeoEntityCheckInOutRequest(nolock) gecur on phap.PhysicalAppointmentId != gecur.PhysicalAppointmentId and gecur.ActionType = 'CheckOut'  
  left join TBL_ET_GeoEntitySiteMaster gesm (nolock) on phap.GeoEntitySiteId = gesm.GeoEntitySiteId  
  left join TBL_ET_GeoEntityMaster gemr (nolock) on gesm.GeoEntityId = gemr.GeoEntityId   
  where ((phap.StartDate between @StartDate and @EndDate) or (phap.EndDate between @StartDate and @EndDate)) and   
  phap.CreatedBy = @CreatedBy   
  and CancelMeeting Is null  
  and phap.Title like '%'+ @Title +'%'  
 )t  
  
 END /*End here for update*/  
  
 Else IF (@Mode = 'PS') /*This is for Select Details */  
 BEGIN  
  
 select PhysicalAppointmentId, Title, Description, Address, StartDate, EndDate, GeoEntityId, GeoEntitySiteId, AssignedTo, TaskTypeId, OutcomesId,   
 CompletedOn, CompleteAddress, gCalendarId, CancelMeeting, Status, ParentId, task_deletedOn, Remarks,   
 CreatedDate, CreatedBy, UpdatedDate, UpdatedBy, IsActive from TBL_ET_PhysicalAppointment(nolock)  
  where PhysicalAppointmentId = @PhysicalAppointmentId  
  
 END /*End here for update*/  
 Else IF (@Mode = 'PE') /*This is for Cancel Meeting Details */  
 BEGIN  
   
 update TBL_ET_PhysicalAppointment set CancelMeeting = @CancelMeeting, UpdatedDate = GetDate(), UpdatedBy = @CreatedBy   
 where PhysicalAppointmentId = @PhysicalAppointmentId  
  
 SELECT 'Appointment Cancelled' STATUS, @PhysicalAppointmentId PhysicalAppointmentId  
 END /*End here for update*/  
  
 Else IF (@Mode = 'PO') /*This is for Update Outcome Details */  
 BEGIN  
	if((@PhysicalAppointmentId > 0) and ((select top 1 EndDate from TBL_ET_PhysicalAppointment(nolock) 
		where PhysicalAppointmentId = @PhysicalAppointmentId) != '') and (isnull(@OutcomesId, 0) > 0))  
	begin 
		if(exists(select 1 from TBL_ET_PhysicalAppointment(nolock) where PhysicalAppointmentId = @PhysicalAppointmentId and isnull(OutcomesId, 0 ) = 0))
		begin
			Update TBL_ET_PhysicalAppointment set 
				OutcomesId = @OutcomesId, 
				Status ='Completed', 
				CompletedOn = @CompletedOn, 
				Remarks = @Remarks, UpdatedBy = @CreatedBy   
			where PhysicalAppointmentId = @PhysicalAppointmentId

			/*
				PhysicalAppointmentId 
			*/

			begin try
				declare 
					@acUserName nvarchar(255),
					@acTaskType nvarchar(255),
					@acTaskTitle nvarchar(255),
					@acOutcomeId bigint,
					@acOutcome nvarchar(255),
					@acGeoEntityId nvarchar(25),
					@acEntityId bigint,
					@acGeoEntityName nvarchar(25),
					@acStartTime datetime,
					@acEntityNo bigint = 0,
					@acEntityPersonName nvarchar(255)

				select @acTaskTitle = Title, @TaskTypeId = TaskTypeId, @acGeoEntityId = GeoEntityId, @acStartTime = StartDate, @acOutcomeId = OutcomesId
					from TBL_ET_PhysicalAppointment(nolock)  where PhysicalAppointmentId = @PhysicalAppointmentId


				select @acGeoEntityName = GeoEntityType, @acEntityId = EntityId from TBL_ET_GeoEntityMaster(nolock) where GeoEntityId = @acGeoEntityId

				print concat('@acGeoEntityName => ', @acGeoEntityName)

				if(@acGeoEntityName in ('lead', 'enquiry'))
				begin

					select @acOutcome = OutcomeName from tbl_tsk_UserOutcomeMaster(nolock) where id = @acOutcomeId
					select @acUserName = User_Login from User_Detail(nolock) where User_ID = @CreatedBy
					select @acTaskType = TasKName  from tbl_tsk_UserTaskMaster(nolock) where id = @TaskTypeId


					declare 
						@eventName nvarchar(255) = case when @acGeoEntityName = 'lead' then 'Lead physical Appointment Completed' else 'Enquiry physical Appointment Completed'end ,
						@eventDescription nvarchar(512) = ''
					
					if(@acGeoEntityName = 'lead')
					begin
						select @acEntityNo = LeadNo, @acEntityPersonName = PersonName  from UserLeads(nolock) where id = @acEntityId
						set @eventDescription = concat(@acUserName, ' completed a physical appointment for lead no. ', @acGeoEntityId, 
							', Name: ', @acEntityPersonName, ' on ', format(@acStartTime, 'dd-MMM-yyyy HH:mm:ss' ), '. Outcome: ', @acOutcome) 
					end

					if(@acGeoEntityName = 'enquiry')
					begin
						select @acEntityPersonName = PersonName  from UserEnquiry(nolock) where EnquiryID = @acEntityId
						set @eventDescription = concat(@acUserName, ' completed a physical appointment for enquiry no. ', @acGeoEntityId, 
							', Name: ', @acEntityPersonName, ' on ', format(@acStartTime, 'dd-MMM-yyyy HH:mm:ss' ), '. Outcome: ', @acOutcome) 
					end
					
				
					exec UspSaveEntityActivity_withid
						@entityname = @acGeoEntityName,
						@EntityID = @acEntityId,
						@UserID = @CreatedBy,
						@ParentID = @ParentId,
						@EventDescription = @eventDescription,
						@EventName = @eventName,
						@reftables = 'TBL_ET_PhysicalAppointment',
						@refid = @PhysicalAppointmentId


				end
			end try
			begin catch
				exec usp_InsertErrorInfo
			end catch

			SELECT 'Outcome Saved' STATUS, @PhysicalAppointmentId PhysicalAppointmentId  , 1 as [StatusCode]
		end
		else
		begin
			SELECT 'Outcome already saved' STATUS, 2 as [StatusCode]
		end
	end  
	else if (isnull(@OutcomesId, 0) = 0)  
	begin  
		SELECT 'Select Outcomes' STATUS,  0 as [StatusCode]
	end  
	else
	begin
		select 'Outcomes not saved.' STATUS, 0 as [StatusCode]
	end 
 END /*End here for update*/  
 Else IF (@Mode = 'OC') /*This is for Cancel Meeting Details */  
 BEGIN  
   
 update TBL_ET_PhysicalAppointment set OutcomesId = 0, UpdatedDate = GetDate(), UpdatedBy = @CreatedBy   
 where PhysicalAppointmentId = @PhysicalAppointmentId  
  
 SELECT 'Outcomes Removed' STATUS, @PhysicalAppointmentId PhysicalAppointmentId  
 END /*End here for update*/  
  
 else if (@Mode = 'PD')  
 begin  
  UPDATE TBL_ET_PhysicalAppointment SET IsActive = 0 WHERE PhysicalAppointmentId = @PhysicalAppointmentId  
  SELECT 'Appointment Removed' STATUS, @PhysicalAppointmentId PhysicalAppointmentId  
 end  
  
 Else IF (@Mode = 'CM') /*This is for Physical Comment Details */  
 BEGIN  
 set @ParentId = (Select ParentId from User_Detail(nolock) where User_Id = @CreatedBy)  
 insert into TBL_ET_PhyAppointComment(Remarks, PhysicalAppointmentId, ParentId, CreatedDate, CreatedBy, IsActive)  
 select @Remarks, @PhysicalAppointmentId, @ParentId, GetDate(), @CreatedBy, 1  
   
 Declare @CommentId bigint, @Msg varchar(200)  
 set @CommentId = scope_identity()  
 set @Msg = 'Comment Saved'  
  
 if(@FileName != '')  
 Begin  
  
 insert into TBL_ET_PhyAppointCommentAttachment(FileName, PhyAppointCommentId, ParentId, CreatedDate, CreatedBy, IsActive)  
 select @FileName, @CommentId, @ParentId, GetDate(), @CreatedBy, 1  
 set @Msg = @Msg + ' with Attachment.'  
 End  
 SELECT @Msg STATUS, @CommentId CommentId  
 END /*End here for update*/  
 Else IF (@Mode = 'MR') /*This is for Physical Comment Details */  
 BEGIN  
 update TBL_ET_PhyAppointComment set IsActive = 0, UpdatedDate = GetDate(), UpdatedBy = CreatedBy   
 where PhyAppointCommentId = @CommentId  
   
 update TBL_ET_PhyAppointCommentAttachment  set IsActive = 0 , UpdatedDate = GetDate(), UpdatedBy = @CreatedBy  
 where PhyAppointCommentId = @CommentId  
  
 SELECT 'Comment Deleted' STATUS, @CommentId CommentId  
 END /*End here for update*/  
  
END TRY  
  
BEGIN CATCH  
 DECLARE @ErrorMessage NVARCHAR(4000);  
 SELECT @ErrorMessage = ERROR_MESSAGE();  
 RAISERROR (  
   @ErrorMessage  
   ,16  
   ,1  
   );  
END CATCH  



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_PhysicalAppointmentEntityId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE  [dbo].[usp_TBL_ET_PhysicalAppointmentEntityId] (
	@Mode VARCHAR(2)
	,@GeoEntityType varchar(20) = 'lead' --lead
    ,@EntityId bigint = 0--3436251
	,@CreatedBy BIGINT = 0--37540--34594
	)
AS
SET NOCOUNT ON

BEGIN TRY
	IF (@Mode = 'PL') /*This is for Insert Details */
	BEGIN
	Declare @ParentId bigint
	DECLARE @ID BIGINT;

	select @ParentId = ParentId from User_detail(nolock) where User_Id = @CreatedBy

	select distinct ul.PersonName, 
			ul.ProfileImgFileName as PersonImage, 
			isnull(o.OutcomeName, '') as Outcome,
			isnull(o.Indent, '') as Intent,
			(case 
				when LOWER(t.Status) = 'completed' then 'Completed' else ( case 
					when CAST(iif(t.IsTask = 1, t.EndDate, t.StartDate) as date) > CAST(GETDATE() as date) then 'Scheduled' 
					when CAST(iif(t.IsTask = 1, t.EndDate, t.StartDate) as date) < CAST(GETDATE() as date) then 'Over Due' 
					else 'Due Today' end
				) end
			) as TaskStatus,t.* from (
Select 'physicalapt' rectype, phap.PhysicalAppointmentId Id, phap.Title, phap.Description, phap.Address, 
phap.StartDate, phap.EndDate, goem.EntityId LeadId, 
ud.Image as AgentImage,trim(concat(trim(cast(ud.FName as nvarchar)), ' ', trim(cast(ud.LName as nvarchar)))) as AgentName, 
ud.ParentID as ParentId,
isnull(phap.Status, '') Status, phap.CreatedBy as AgentId, isnull(phap.OutcomesId , 0) OutcomesId, 0 IsTask, 
iif(@CreatedBy in (phap.CreatedBy, phap.AssignedTo), 1, 0) as IsEditable, 0 as IsRemoval
from TBL_ET_PhysicalAppointment phap (nolock)
	inner join TBL_ET_GeoEntitySiteMaster gesm on phap.GeoEntitySiteId = gesm.GeoEntitySiteId
	inner join TBL_ET_GeoEntityMaster goem on gesm.GeoEntityId = goem.GeoEntityId
	inner join User_Detail ud (nolock) on phap.AssignedTo = ud.User_ID 
where goem.GeoEntityType = 'lead' and goem.EntityId = @EntityId and phap.CreatedBy = @CreatedBy

Union

Select 'physicalapt' rectype, phap.PhysicalAppointmentId Id, phap.Title, phap.Description, phap.Address, 
phap.StartDate, phap.EndDate, goem.EntityId LeadId,
ud.Image as AgentImage,trim(concat(trim(cast(ud.FName as nvarchar)), ' ', trim(cast(ud.LName as nvarchar)))) as AgentName, 
ud.ParentID as ParentId,
isnull(phap.Status, '') Status, phap.CreatedBy as AgentId, isnull(phap.OutcomesId , 0) OutcomesId, 0 IsTask, 
iif(@CreatedBy in (phap.CreatedBy, phap.AssignedTo), 1, 0) as IsEditable, 0 as IsRemoval
from TBL_ET_PhysicalAppointment phap (nolock)
	inner join TBL_ET_GeoEntitySiteMaster gesm on phap.GeoEntitySiteId = gesm.GeoEntitySiteId
	inner join TBL_ET_GeoEntityMaster goem on gesm.GeoEntityId = goem.GeoEntityId
	inner join User_Detail ud (nolock) on phap.CreatedBy = ud.User_ID 
where goem.GeoEntityType = 'lead' and goem.EntityId = @EntityId and phap.CreatedBy = @CreatedBy

Union

select 'virtualapt' rectype, th.Id, th.Title, th.Description, th.Address, 
th.StartDate, th.EndDate, th.LeadId, 
ud.Image as AgentImage,trim(concat(trim(cast(ud.FName as nvarchar)), ' ', trim(cast(ud.LName as nvarchar)))) as AgentName, 
ud.ParentID as ParentId,
isnull(th.Status, '') Status, th.CreatedBy as AgentId, isnull(th.OutcomesId, 0) OutcomesId, th.IsTask, 
iif(@CreatedBy in (th.CreatedBy, th.AssignedTo), 1, 0) as IsEditable, 0 as IsRemoval 
from tbl_tsk_TaskHistory th 
inner join User_Detail ud (nolock) on th.AssignedTo = ud.User_ID 
where th.IsAppointment = 1 and th.CreatedBy = @CreatedBy and th.LeadId = @EntityId 

Union

select 'virtualapt' rectype, th.Id, th.Title, th.Description, th.Address, 
th.StartDate, th.EndDate, th.LeadId,ud.Image as AgentImage,trim(concat(trim(cast(ud.FName as nvarchar)), ' ', trim(cast(ud.LName as nvarchar)))) as AgentName, 
ud.ParentID as ParentId,
isnull(th.Status, '') Status, th.AssignedTo as AgentId, isnull(th.OutcomesId, 0) OutcomesId, th.IsTask, 
iif(@CreatedBy in (th.CreatedBy, th.AssignedTo), 1, 0) as IsEditable, 0 as IsRemoval 
from tbl_tsk_TaskHistory th 
inner join User_Detail ud (nolock) on th.AssignedTo = ud.User_ID 
where th.IsAppointment = 1 and th.AssignedTo = @CreatedBy and th.LeadId = @EntityId 
)
t
inner join UserLeads(nolock) ul on t.LeadId = ul.ID 
--inner join User_Detail(nolock) ud on t.AgentId = ud.User_ID
left join tbl_tsk_UserOutcomeMaster(nolock) o on t.OutcomesId  = o.Id
order by t.Id, t.StartDate, t.EndDate  desc

	--Select phap.*, goem.EntityId from 
	--TBL_ET_PhysicalAppointment phap (nolock)
	--inner join TBL_ET_GeoEntitySiteMaster gesm on phap.GeoEntitySiteId = gesm.GeoEntitySiteId
	--inner join TBL_ET_GeoEntityMaster goem on gesm.GeoEntityId = goem.GeoEntityId
	--where goem.GeoEntityType = 'lead' and goem.EntityId = @EntityId--3436251
	--and  phap.CreatedBy = @CreatedBy --37540--34594

	END /*End here for update*/

END TRY

BEGIN CATCH
	DECLARE @ErrorMessage NVARCHAR(4000);
	SELECT @ErrorMessage = ERROR_MESSAGE();
	RAISERROR (
			@ErrorMessage
			,16
			,1
			);
END CATCH



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_PhysicalAppointmentTypeSetting]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE  [dbo].[usp_TBL_ET_PhysicalAppointmentTypeSetting] (
	@Mode VARCHAR(2)
   ,@PhyApptTypeSettingId bigint = 0
   ,@task_type_id bigint = 0
   ,@MarkOutcomeOnCheckOut bit = false
   ,@GeoRestriction varchar(20) = null
   ,@AuthType varchar(50) = null
   ,@AllowedCheckInOutOverride bit = false
   ,@CheckInOutApprover bigint = 0
    ,@CheckInRange int = 0
	,@CheckOutRange int = 0
	,@CheckInFormId int = 0
	,@CheckOutFormId int = 0
	,@CreatedBy BIGINT = 0
	,@IsActive bit = 1
	)
AS
SET NOCOUNT ON

BEGIN TRY
	IF (@Mode = 'TI') /*This is for Insert Details */
	BEGIN
	Declare @ParentId bigint
	DECLARE @ID BIGINT;

	select @ParentId = ParentId from User_detail(nolock) where User_Id = @CreatedBy

 if(@PhyApptTypeSettingId = 0)
	Begin
			INSERT INTO TBL_ET_PhysicalAppointmentTypeSetting (
				task_type_id
				,MarkOutcomeOnCheckOut
				,GeoRestriction
				,AuthType
				,AllowedCheckInOutOverride
				,CheckInOutApprover
				,CheckInRange
				,CheckOutRange
				,CheckInFormId
				,CheckOutFormId
				,ParentId
				,IsActive
				,CreatedBy
				,CreatedDate
				)
			VALUES (
				@task_type_id
				,@MarkOutcomeOnCheckOut
				,@GeoRestriction
				,@AuthType
				,@AllowedCheckInOutOverride
				,@CheckInOutApprover
				,@CheckInRange
				,@CheckOutRange
				,@CheckInFormId
				,@CheckOutFormId
				,@ParentId
				,@IsActive
				,@CreatedBy
				,GETDATE()				
				)

			SET @ID = scope_identity();

		SELECT 'Record Saved' STATUS, @ID PhyApptTypeSettingId

       	Select GETDATE()

		END
		ELSE
		BEGIN
			SELECT 'Record Already Exist' STATUS
 
		 Select GETDATE()
		END
	END /*End here for insert*/

	Else IF (@Mode = 'TU') /*This is for Update Details */
	BEGIN
	if(@PhyApptTypeSettingId > 0)
	Begin

	Update TBL_ET_PhysicalAppointmentTypeSetting  set task_type_id = @task_type_id
				 ,MarkOutcomeOnCheckOut = @MarkOutcomeOnCheckOut
				,GeoRestriction = @GeoRestriction
				,AuthType = @AuthType
				,AllowedCheckInOutOverride = @AllowedCheckInOutOverride
				,CheckInOutApprover = @CheckInOutApprover
				,CheckInRange = @CheckInRange
				,CheckOutRange = @CheckOutRange
				,CheckInFormId = @CheckInFormId
				,CheckOutFormId = @CheckOutFormId
				,IsActive = @IsActive
				,CreatedBy = @CreatedBy
				,CreatedDate = GETDATE()				
				where PhyApptTypeSettingId  = @PhyApptTypeSettingId

		SELECT 'Record Updated' STATUS, @PhyApptTypeSettingId AttendenceIssueId

       	Select GETDATE()

       End
		ELSE
		BEGIN
			SELECT 'Update Issue.' STATUS
       	Select GETDATE()
		END

	END /*End here for update*/

		Else IF (@Mode = 'TL') /*This is for Update Details */
	BEGIN

	Select * from TBL_ET_PhysicalAppointmentTypeSetting (nolock) phAT 
	where phat.PhyApptTypeSettingId  = (case when @PhyApptTypeSettingId > 0 then @PhyApptTypeSettingId else phat.PhyApptTypeSettingId  end) 
				 and phat.CreatedBy = @CreatedBy and 
				 phat.task_type_id = (case when @task_type_id > 0 then @task_type_id else phat.task_type_id end)

	END /*End here for update*/

END TRY

BEGIN CATCH
	DECLARE @ErrorMessage NVARCHAR(4000);
	SELECT @ErrorMessage = ERROR_MESSAGE();
	RAISERROR (
			@ErrorMessage
			,16
			,1
			);
END CATCH



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_RoleSupportRoleBranchAttdGroup]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--usp_TBL_ET_RoleSupportRoleBranchAttdGroup 'AL', 34594   
CREATE   PROCEDURE  [dbo].[usp_TBL_ET_RoleSupportRoleBranchAttdGroup] (  
 @Mode VARCHAR(2)  
 ,@UserId bigint = 0  
) 
AS  
SET NOCOUNT ON  

BEGIN TRY

--DECLARE 
--@Mode VARCHAR(2) = N'AL',
--@UserId bigint = 41923 

IF (@Mode = 'AL') /*This is List Details */
BEGIN

--Declare @Mode VARCHAR(2) = 'AL',
--@UserId bigint = 34594
Declare @ParentId bigint
SELECT @ParentId = ParentId FROM User_detail (nolock) WHERE [User_Id] = @UserId

Declare @UserIdTeamLst varchar(4000)  
select @UserIdTeamLst = UserIdTeamLst from ufn_GetUserRoleScope(@UserId)  
print @UserIdTeamLst 

--User Role List
Select * from (Select RoleId, RoleName, RoleCode, IsInternal, ParentId FROM TBL_UA_RoleMaster (nolock) rmua  
  WHERE rmua.ParentId = @ParentId  
  Union  
Select RoleId, RoleName, RoleCode, IsInternal, ParentId FROM VW_SystemRole_RoleMaster (nolock) rm --tbl_UA_RoleMaster rm               
  WHERE rm.RoleId IN (4,9)
)tr order by RoleName Asc  
  
--Support Role List 
select [RoleId], [RoleDesc], [ParentId], [dummy_rec] from Serv_Role_mast (nolock)
where ParentId=@ParentId  and Active= 1       
  
--Branch List  
select Id, Name from tbl_inv_UserTaxNumber(nolock) branc   
where branc.IsActive = 1 and branc.is_deleted = 0 and ParentId = @ParentId  
  
--Attendance Group List  
select atgp.AttendanceGroupId, atgp.AttendanceGroupName from TBL_ET_AttendanceGroup(nolock) atgp   
where atgp.IsActive = 1 and atgp.ParentId = @ParentId  

--select distinct gesm.GeoEntitySiteId, 
--isnull(gesm.GeoEntitySiteName, ('Site ' + ' - ' +  cast(gesm.GeoEntitySiteId as varchar(20)))) GeoEntitySiteName, 
--gesm.Latitude, gesm.Longitude from TBL_ET_PhysicalAppointment(nolock) pa 
-- inner join TBL_ET_PhyAppointUserMapping(nolock) paum on pa.PhysicalAppointmentId = paum.PhysicalAppointmentId 
-- inner join TBL_ET_GeoEntitySiteMaster(nolock) gesm on pa.GeoEntitySiteId = gesm.GeoEntitySiteId --and gesm.IsActive = 1 
-- inner join TBL_ET_GeoEntityMaster(nolock) gem on pa.GeoEntityId = gesm.GeoEntityId 
--where gesm.GeoEntitySiteName != '' and 
--paum.UserId in (select item from dbo.fu_SplitString(@UserIdTeamLst, ','))

select distinct gesm.GeoEntitySiteId, 
isnull(gesm.GeoEntitySiteName, ('Site ' + ' - ' +  cast(gesm.GeoEntitySiteId as varchar(20)))) GeoEntitySiteName, 
gesm.Latitude, gesm.Longitude from TBL_ET_GeoEntitySiteMaster(nolock) gesm 
where gesm.IsActive = 1 and isnull(gesm.GeoEntitySiteName, '') <> '' and 
gesm.CreatedBy in (select item from dbo.fu_SplitString(@UserIdTeamLst, ','))

 END /*End here for list */  
  
END TRY  
  
BEGIN CATCH  
 DECLARE @ErrorMessage NVARCHAR(4000);  
 SELECT @ErrorMessage = ERROR_MESSAGE();  
 RAISERROR (  
   @ErrorMessage  
   ,16  
   ,1  
   );  
END CATCH  



