/* ============================================================
   Procedure: [dbo].[Usp_TBL_ET_ShiftMasterList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--Usp_TBL_ET_AttendanceGroupAttendanceSettingsSave 'AGL', 0, 'A Group 1', 34594, 1   
CREATE   PROCEDURE  [dbo].[Usp_TBL_ET_ShiftMasterList] (  
 @Mode VARCHAR(3),
 @ShiftId bigint = 0,
 @ShiftName nvarchar(100) = '',
 @CreatedBy bigint,
 @OffsetValue int = 0,
 @PagingSize int = 0,
 @Condition nvarchar(100) = ''
)
AS
SET NOCOUNT ON
  
BEGIN TRY 
Declare @ParentId bigint  
Select @ParentId = ParentId from User_Detail (nolock) Where User_ID = @CreatedBy  
IF (@Mode = 'SL') /*This is for List */ 
  Begin
	Select count(agas.ShiftId) over() as TotalRecords, ShiftId, ShiftName, StartTime, EndTime, agas.ParentId, 
	concat(Ud.FName, ' ', isnull(Ud.LName, '')) FullName, agas.CreatedDate, agas.CreatedBy, agas.IsActive from TBL_ET_ShiftMaster(nolock) agas 
	inner join User_Detail (nolock) Ud on agas.CreatedBy = Ud.User_ID 
	Where agas.ShiftName like '%' + @ShiftName + '%' and Ud.ParentId = @ParentId
	order by ShiftName Asc
	Offset @OffsetValue rows fetch next @PagingSize rows only
  End
 Else IF (@Mode = 'SD') /*This is for Details */ 
  Begin
	Select ShiftId, ShiftName, StartTime, EndTime, agas.ParentId, concat(Ud.FName, ' ', isnull(Ud.LName, '')) FullName,  
	agas.CreatedDate, agas.CreatedBy, agas.IsActive from TBL_ET_ShiftMaster(nolock) agas 
	 inner join User_Detail (nolock) Ud on agas.CreatedBy = Ud.User_ID 
	 Where agas.ShiftId = @ShiftId
  End
END TRY 
 
BEGIN CATCH 
 DECLARE @ErrorMessage NVARCHAR(4000); 
 SELECT @ErrorMessage = ERROR_MESSAGE(); 
 RAISERROR (  
   @ErrorMessage  
   ,16  
   ,1  
   );  
END CATCH  



GO

/* ============================================================
   Procedure: [dbo].[Usp_TBL_ET_ShiftMasterSave]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--Usp_TBL_ET_AttendanceGroupAttendanceSettingsSave 'AGL', 0, 'A Group 1', 34594, 1     
CREATE   PROCEDURE  [dbo].[Usp_TBL_ET_ShiftMasterSave] (    
 @Mode VARCHAR(3),  
 @ShiftId bigint = 0,  
 @ShiftName nvarchar(100) = '',  
 @StartTime time = null,  
 @EndTime time = null,  
 @CreatedBy bigint,  
 @IsActive bit = true  
)  
AS  
SET NOCOUNT ON  
    
BEGIN TRY   
Declare @ParentId bigint    
Select @ParentId = ParentId from User_Detail (nolock) Where User_ID = @CreatedBy    
 IF (@Mode = 'SI') /*This is for Insert Details */    
 BEGIN  
 if(Not Exists(Select CreatedBy from TBL_ET_ShiftMaster(nolock) agas Where agas.ShiftName = @ShiftName and agas.ParentId = @ParentId))   
 Begin  
 insert Into TBL_ET_ShiftMaster (ShiftName, StartTime, EndTime, ParentId, CreatedDate, CreatedBy, IsActive)   
 values (@ShiftName, @StartTime, @EndTime, @ParentId, GETDATE(), @CreatedBy, @IsActive)  
  
 Select 'Record Saved' Status, cast(SCOPE_IDENTITY() as bigint) Id     
 End    
 Else    
 Begin   
 Select 'Record Already Exists' Status, 0 Id   
 End   
  End   
 Else IF (@Mode = 'SU') /*This is for Update Details */   
  Begin   
 if(not Exists(Select CreatedBy from TBL_ET_ShiftMaster(nolock) agas   
 Where agas.ShiftId != @ShiftId and agas.ShiftName = @ShiftName and agas.ParentId = @ParentId))    
 Begin  
  
 Update TBL_ET_ShiftMaster set ShiftName = @ShiftName, StartTime = @StartTime, EndTime = @EndTime, 
 ParentId = @ParentId, UpdatedDate = GETDATE(), UpdatedBy = @CreatedBy, IsActive = @IsActive  
 where ShiftId = @ShiftId   
   
 Select 'Record Updated' Status, @ShiftId Id   
 End  
 Else   
 Begin   
 Select 'Shift already Exists' Status, @ShiftId Id   
 End   
 End   
  
 Else IF (@Mode = 'UU') /*This is for Update Details */   
  Begin   
 Begin  
  
 Update TBL_ET_ShiftMaster set IsActive = @IsActive,  UpdatedDate = GETDATE(), UpdatedBy = @CreatedBy  
 where ShiftId = @ShiftId   
   
 Select 'Record Updated' Status, @ShiftId Id   
 End  
  
  End   
END TRY   
   
BEGIN CATCH   
 DECLARE @ErrorMessage NVARCHAR(4000);   
 SELECT @ErrorMessage = ERROR_MESSAGE();   
 RAISERROR (    
   @ErrorMessage    
   ,16    
   ,1    
   );    
END CATCH    



GO

/* ============================================================
   Procedure: [dbo].[Usp_TBL_ET_ShiftUserMappingDetail_UserId_Date]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--Usp_TBL_ET_ShiftUserMappingDetail_UserId_Date 37540, '2023-03-11'   
CREATE   PROCEDURE [dbo].[Usp_TBL_ET_ShiftUserMappingDetail_UserId_Date] (    
 @UserId bigint = 0,  
 @ShiftDate date  
)    
AS  
SET NOCOUNT ON    
  
BEGIN TRY   
	--Declare @UserId bigint = 34594,  
	-- @ShiftDate date = '04-May-2023'  -- '2023-05-04'
  
	Declare @ParentId bigint   
  
	Select @ParentId = ParentId from User_Detail (nolock) ud Where ud.User_ID = @UserId   
	
	drop table if exists #tempShift

	Select top 1 tesu.*, format(FromDate,'MM/dd/yyyy') FromDateSt, format(ToDate,'MM/dd/yyyy') ToDateSt 
		into #tempShift
	from TBL_ET_ShiftUserMapping (nolock) tesu   
	where tesu.IsActive = 1 and 
	tesu.UserId = @UserId  and
	(cast(@ShiftDate as date) between cast(tesu.FromDate as date) and cast(coalesce(tesu.ClosureDate, tesu.ToDate) as date))   
	ORDER BY tesu.ShiftUserMappingId desc

	declare @tShiftWeekOff bigint
	select @tShiftWeekOff = ShiftUserMappingId from #tempShift

	select * from #tempShift
  
	select tesumo.* from TBL_ET_ShiftUserMapping (nolock) tesu   
	inner join TBL_ET_ShiftUserMappWeekOff(nolock) tesumo on tesumo.ShiftUserMappingId = tesu.ShiftUserMappingId   
	where tesu.IsActive = 1 and tesumo.IsActive = 1 and tesu.UserId = @UserId and (cast(@ShiftDate as date) between cast(tesu.FromDate as date) and cast(coalesce(tesu.ClosureDate, tesu.ToDate) as date)) and tesu.ShiftUserMappingId = @tShiftWeekOff  ORDER BY tesu.ShiftUserMappingId desc
  
END TRY    
BEGIN CATCH   
	 DECLARE @ErrorMessage NVARCHAR(4000);   
	 SELECT @ErrorMessage = ERROR_MESSAGE();   
	 RAISERROR (@ErrorMessage, 16, 1);   
END CATCH 



GO

/* ============================================================
   Procedure: [dbo].[Usp_TBL_ET_ShiftUserMappingList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_TBL_ET_ShiftUserMappingList] (  
 @Mode VARCHAR(3),
 @Id bigint = 0,
 @SearchText nvarchar(100) = '',
 @CreatedBy bigint,
 @OffsetValue int = 0,
 @PagingSize int = 0,
 @Condition nvarchar(100) = '',
 @FromDate date = null,
 @ToDate date= null
)
AS
SET NOCOUNT ON
  
BEGIN TRY 


--declare
--	@Mode VARCHAR(3) = 'SS',
--	@Id bigint = 0,
--	@SearchText nvarchar(100) = N'Mukesh',
--	@CreatedBy bigint = 34594,
--	@OffsetValue int = 0,
--	@PagingSize int = 800,
--	@Condition nvarchar(100) = '',
--	@FromDate date = N'2023-05-01',
--	@ToDate date= N'2023-05-31'


declare @ParentId bigint  
Select @ParentId = ParentId from User_Detail (nolock) Where User_ID = @CreatedBy  
IF (@Mode = 'SL') /*This is for List */ 
  Begin
Select count(agas.ShiftUserMappingId) over() as TotalRecords, sfma.ShiftName, agas.ShiftUserMappingId, agas.ShiftId, agas.UserId, 
 agas.FromDate, agas.ToDate, agas.ClosureDate, agas.IsWorkDay,agas.IsMonday, agas.IsTuesday,
 agas.IsWednesday, agas.IsThursday, agas.IsFriday, agas.IsSaturday, agas.IsSunday, agas.IsWeekOff, Ud.ParentId, 
	concat(Ud.FName, ' ', isnull(Ud.LName, '')) FullName, agas.CreatedDate, agas.CreatedBy, agas.IsActive from 
	TBL_ET_ShiftUserMapping(nolock) agas 
	inner join TBL_ET_ShiftMaster (nolock) sfma on agas.ShiftId = sfma.ShiftId
	inner join User_Detail (nolock) Ud on agas.CreatedBy = Ud.User_ID 
	Where sfma.ShiftName like '%' + @SearchText + '%' and Ud.ParentId = @ParentId
	order by ShiftName Asc
	Offset @OffsetValue rows fetch next @PagingSize rows only
  End
Else If (@Mode = 'SS') /*This is for List */ 
  Begin
drop table If Exists #TblDatelist 

Create table #TblDatelist(AllDates DATE)

;WITH ListDates(AllDates) AS
(    SELECT @FromDate AS DATE
    UNION ALL
    SELECT DATEADD(DAY,1,AllDates)
    FROM ListDates 
    WHERE AllDates < @ToDate)
insert into #TblDatelist (AllDates)
SELECT AllDates FROM ListDates

Declare @VDate nvarchar(max) 
select @VDate = String_Agg('['+format(AllDates,'dd-MMM-yyyy')+']', ',') from #TblDatelist
--select @VDate

--Declare @VDateMain nvarchar(max) 
--select @VDateMain = String_Agg('['+(cast(DAY(AllDates) as varchar(10)) +' '+ DATENAME(month, AllDates)) +' '+ cast(YEAR(AllDates) as varchar(10))+']', ',') from #TblDatelist
--select @VDateMain

Declare @query nvarchar(max), @query2 nvarchar(max)

set @query = concat (N' select * from ( 
	SELECT format(AllDates,''dd-MMM-yyyy'') DisplayDate,
	ud.User_id UserId, Ud.FName + '' '' + Ud.LName + ''(''+ Ud.User_Login +'')'' UserName,
	dbo.getShiftNameByDate(lsdt.AllDates, Ud.User_Id) ShiftName FROM #TblDatelist as lsdt,
	User_Detail (nolock) Ud Where Ud.ParentId = ', cast(@ParentId as varchar(10)), ' and 1 = ( case 
		when isnull(''%', @SearchText, '%'', '''') = '''' then 1	
		when isnull(''%', @SearchText, '%'', '''') <> '''' and ud.User_Login like ''%', @SearchText, '%'' then 1
		when isnull(''%', @SearchText, '%'', '''') <> '''' and ud.FName like ''%', @SearchText, '%'' then 1
		else 0 end )  )t PIVOT( max(ShiftName) FOR DisplayDate IN (' , @VDate, ' )) AS pivot_table ');

print @query
execute sp_sqlexec @query

Select cast(DAY(AllDates) as varchar(10)) +' '+ DATENAME(month, AllDates) Column1, cast(DAY(AllDates) as varchar(10)) Days, DATENAME(month, AllDates) Months, DATENAME(WEEKDAY, AllDates) WeekDayName, format(AllDates,'dd-MMM-yyyy') AllDates, format(AllDates,'yyyy-MM-dd') AllDates2 from #TblDatelist

End
 Else IF (@Mode = 'SD') /*This is for Details */ 
  Begin
	Select agas.ShiftId, ShiftName, StartTime, EndTime, sm.ParentId, concat(Ud.FName, ' ', isnull(Ud.LName, '')) FullName,  
	agas.ShiftUserMappingId, agas.ShiftId, agas.UserId, agas.FromDate, agas.ToDate, agas.ClosureDate, agas.IsWorkDay, 
	agas.IsMonday, agas.IsTuesday, agas.IsWednesday, agas.IsThursday, agas.IsFriday, agas.IsSaturday, agas.IsSunday, 
	agas.IsWeekOff, agas.CreatedDate, agas.CreatedBy, agas.IsActive from 
	TBL_ET_ShiftUserMapping (nolock) agas 
	 inner join TBL_ET_ShiftMaster (nolock) sm on agas.ShiftId = sm.ShiftId 
	 inner join User_Detail (nolock) Ud on agas.CreatedBy = Ud.User_ID 
	 Where agas.ShiftId = @Id
  End


END TRY 
 
BEGIN CATCH 
 DECLARE @ErrorMessage NVARCHAR(4000); 
 SELECT @ErrorMessage = ERROR_MESSAGE(); 
 RAISERROR (  
   @ErrorMessage  
   ,16  
   ,1  
   );  
END CATCH  



GO

/* ============================================================
   Procedure: [dbo].[Usp_TBL_ET_ShiftUserMappingSave]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--Usp_TBL_ET_ShiftUserMappingSave 'RI', 0, 1, '34594,36931,36932,38990,38991,38992,38993,38994,38995,38996', 34594, 1   
CREATE   PROCEDURE [dbo].[Usp_TBL_ET_ShiftUserMappingSave] (  
	@Mode VARCHAR(3),
	@ShiftUserMappingId bigint = 0,
	@ShiftId bigint = 0,
	@UserIds nvarchar(max) = '',
	@FromDate date = null,
	@ToDate date = null,
	@IsWorkDay bit = false,
	@IsMonday bit = false,
	@IsTuesday bit = false,
	@IsWednesday bit = false,
	@IsThursday bit = false,
	@IsFriday bit = false,
	@IsSaturday bit = false,
	@IsSunday bit = false,
	@IsWeekOff bit = false,
	@WeekOffList nvarchar(max) = '',
	@CreatedBy bigint,
	@IsActive bit = true
)
AS
SET NOCOUNT ON
  
BEGIN TRY
	Declare @ParentId bigint 
	Select @ParentId = ParentId from User_Detail (nolock) Where User_ID = @CreatedBy 
	
	if (@Mode = 'RI') /*This is for Insert Details */  
	begin
		if(exists(select value from string_split(@UserIds, ',')))
		begin
			if( exists(select 1 from ( select value UserId from string_split(@UserIds, ','))t 
				where t.UserId in (select UserId from TBL_ET_ShiftUserMapping(nolock) esum 
				inner join User_Detail(nolock) ud on esum.UserId = ud.User_ID where ud.ParentId = @ParentId 
					and (cast(esum.FromDate as date) > cast(@FromDate as date) or cast(esum.ToDate as date) > cast(@FromDate as date)))
			))
			begin
				print 1
				declare @ClosureDate Date 
				set @ClosureDate  = getDate()
				update TBL_ET_ShiftUserMapping set ClosureDate = CASE 
					WHEN cast(@FromDate as date) < cast(FromDate as date) or cast(@FromDate as date) < cast(getDate() as date) THEN getDate()
					ELSE @FromDate END WHERE ShiftUserMappingId IN ( select ShiftUserMappingId from ( select value UserId from string_split(@UserIds, ',')) t where t.UserId in (select UserId from TBL_ET_ShiftUserMapping(nolock) esum
					inner join User_Detail(nolock) ud on esum.UserId = ud.User_ID 
					where ud.ParentId = @ParentId and (cast(esum.FromDate as date) > cast(@FromDate as date) or cast(esum.ToDate as date) > cast(@FromDate as date))));
			end


			declare @TableWithIdentity table (ID bigint);
			insert Into TBL_ET_ShiftUserMapping ( ShiftId, UserId, FromDate, ToDate, IsWorkDay, IsMonday, IsTuesday, 
				IsWednesday, IsThursday, IsFriday, IsSaturday, IsSunday, IsWeekOff, CreatedDate, CreatedBy, IsActive) 
			 output inserted.ShiftUserMappingId into @TableWithIdentity
			 select @ShiftId, UserId, @FromDate, @ToDate, @IsWorkDay, @IsMonday, @IsTuesday, @IsWednesday, @IsThursday, 
				@IsFriday, @IsSaturday, @IsSunday, @IsWeekOff, GETDATE(), @CreatedBy, @IsActive 
			from ( select [value] UserId from string_split(@UserIds, ',')) t 
				where t.UserId not in (select UserId from TBL_ET_ShiftUserMapping(nolock) esum
				inner join User_Detail(nolock) ud on esum.UserId = ud.User_ID
			where ud.ParentId = @ParentId and esum.FromDate > @FromDate)

			if(@WeekOffList != '')
			begin
				declare @TableWeekOffList table (WeekOffDay varchar(10), WeekName varchar(10));
				insert into @TableWeekOffList (WeekOffDay, WeekName) 
				select WeekOffDay, WeekName from openjson(@WeekOffList) 
					with ( WeekOffDay nvarchar(100) '$.WeekOffDay',                    
						WeekName nvarchar(100) '$.WeekName' ) tF 

				insert into TBL_ET_ShiftUserMappWeekOff (ShiftUserMappingId, WeekOffDay, WeekName, ParentId, CreatedDate, CreatedBy, IsActive)
				select ID, WeekOffDay, WeekName, @ParentId, GETDATE(), @CreatedBy, @IsActive from @TableWeekOffList, @TableWithIdentity

			end

			select 'Record Saved' Status--, cast(SCOPE_IDENTITY() as bigint) Id 
		end
		else 
		begin 
			select 'Record Already Exists' Status, 0 Id 
		end
	end
else IF (@Mode = 'RU') /*This is for Update Details */  
 BEGIN

	update TBL_ET_ShiftUserMapping set IsActive = 0 where UserId in ( 
		select value UserId from string_split(@UserIds, ',')) and ((cast(FromDate as date) between cast(@FromDate as date) and cast(@ToDate as date)) or (cast(ToDate as date) between cast(@FromDate as date) and cast(@ToDate as date)))

	update TBL_ET_ShiftUserMappWeekOff set IsActive = 0 where ShiftUserMappingId in (
		select ShiftUserMappingId from TBL_ET_ShiftUserMapping where UserId in (select value UserId from string_split(@UserIds, ',')) and ((cast(FromDate as date) between cast(@FromDate as date) and cast(@ToDate as date)) 
		or (cast(ToDate as date) between cast(@FromDate as date) and cast(@ToDate as date))))

	 --if(Not Exists(Select CreatedBy from TBL_ET_ShiftUserMapping(nolock) agas  
	 --inner join User_Detail (nolock) Ud on agas.CreatedBy = Ud.User_ID 
	 --Where agas.ShiftId = @ShiftId and Ud.ParentId = @ParentId)) 
	-- Begin
if(Exists(select value from string_split(@UserIds, ',')))
 Begin

--update TBL_ET_ShiftUserMapping set
if(Exists(select 1 from (
select value UserId from string_split(@UserIds, ',')
)t where t.UserId in (select UserId from TBL_ET_ShiftUserMapping(nolock) esum
 inner join User_Detail(nolock) ud on esum.UserId = ud.User_ID
where esum.IsActive = 1 and ud.ParentId = @ParentId and 
(cast(esum.FromDate as date) > cast(@FromDate as date) or cast(esum.ToDate as date) > cast(@FromDate as date)))))
Begin
Print 1

Declare @ClosureDate2 Date 
set @ClosureDate2  = getDate()

update TBL_ET_ShiftUserMapping set ClosureDate  
= CASE 
WHEN cast(@FromDate as date) < cast(FromDate as date) or cast(@FromDate as date) < cast(getDate() as date) THEN getDate()
ELSE @FromDate
END
WHERE ShiftUserMappingId IN (select ShiftUserMappingId from (
select value UserId from string_split(@UserIds, ',')
)t where t.UserId in (select UserId from TBL_ET_ShiftUserMapping(nolock) esum
 inner join User_Detail(nolock) ud on esum.UserId = ud.User_ID
where ud.ParentId = @ParentId and (cast(esum.FromDate as date) > cast(@FromDate as date) or cast(esum.ToDate as date) > cast(@FromDate as date))));

End


DECLARE @TableWithIdentity2 TABLE (ID bigint);

insert Into TBL_ET_ShiftUserMapping (ShiftId, UserId, FromDate, ToDate, IsWorkDay, 
 IsMonday, IsTuesday, IsWednesday, IsThursday, IsFriday, IsSaturday, IsSunday, 
 IsWeekOff, CreatedDate, CreatedBy, IsActive) 

output inserted.ShiftUserMappingId into @TableWithIdentity2

select @ShiftId, UserId, @FromDate, @ToDate, @IsWorkDay, 
 @IsMonday, @IsTuesday, @IsWednesday, @IsThursday, @IsFriday, @IsSaturday, @IsSunday, 
 @IsWeekOff, GETDATE(), @CreatedBy, @IsActive from (
select value UserId from string_split(@UserIds, ',')
)t

if(@WeekOffList != '')
 Begin
DECLARE @TableWeekOffList2 TABLE (WeekOffDay varchar(10), WeekName varchar(10));
insert into @TableWeekOffList2 (WeekOffDay, WeekName)
select WeekOffDay, WeekName from openjson(@WeekOffList) 
 with
 (
  WeekOffDay nvarchar(100) '$.WeekOffDay',                    
  WeekName nvarchar(100) '$.WeekName' 
 ) tF

insert into TBL_ET_ShiftUserMappWeekOff (ShiftUserMappingId, WeekOffDay, WeekName, ParentId, CreatedDate, CreatedBy, IsActive)
select ID, WeekOffDay, WeekName, @ParentId, GETDATE(), @CreatedBy, @IsActive from @TableWeekOffList2, @TableWithIdentity2

 End

Select 'Record Saved' Status--, cast(SCOPE_IDENTITY() as bigint) Id 
 End
 Else 
 Begin 
 Select 'Record Already Exists' Status, 0 Id 
 End 
  End

END TRY 
 
BEGIN CATCH 
 DECLARE @ErrorMessage NVARCHAR(4000); 
 SELECT @ErrorMessage = ERROR_MESSAGE(); 
 RAISERROR (  
   @ErrorMessage  
   ,16  
   ,1  
   );  
END CATCH  



