/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_SiteListForExpense]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--usp_TBL_ET_SiteListForExpense 'SL', 34594, '2022-12-09'  
CREATE   PROCEDURE  [dbo].[usp_TBL_ET_SiteListForExpense] (  
 @Mode VARCHAR(2)  
 ,@UserId bigint = 0  
 ,@ActivityDate datetime = null  
)  
AS  
SET NOCOUNT ON  
  
BEGIN TRY  
Declare @ParentId bigint  
Select @ParentId = ParentId from User_Detail(nolock) where User_Id = @UserId  
  
  IF (@Mode = 'SL') /*This is List Details */  
   BEGIN  
  
drop table if Exists #temp_Site  
  
CREATE TABLE #temp_Site (PhysicalAppointmentId bigint, Title varchar(300), StartDate datetime, EndDate datetime, GeoEntitySiteId bigint,  
 GeoEntitySiteName varchar(300), CheckIn datetime, CheckOut datetime, UserId bigint,  
 Address varchar(300), LatitudeS1 float, LongitudeS1 float, next_PhysicalAppointmentId bigint)  
  
insert into #temp_Site (PhysicalAppointmentId, Title, StartDate, EndDate, GeoEntitySiteId, GeoEntitySiteName, CheckIn, CheckOut, UserId, Address, LatitudeS1, LongitudeS1, next_PhysicalAppointmentId)  
--WITH cte_list AS(  
select distinct pa.PhysicalAppointmentId, Title, pa.StartDate, pa.EndDate, pa.GeoEntitySiteId,  
  isnull(gesm.GeoEntitySiteName, (gem.GeoEntityName + ' - ' +  gem.GeoEntityType)) GeoEntitySiteName, CheckIn, CheckOut, paum.UserId,   
  pa.Address, gesm.Latitude LatitudeS1, gesm.Longitude LongitudeS1, 0 next_PhysicalAppointmentId  
 from TBL_ET_PhysicalAppointment(nolock) pa   
 inner join TBL_ET_PhyAppointUserMapping(nolock) paum on pa.PhysicalAppointmentId = paum.PhysicalAppointmentId  
 inner join TBL_ET_GeoEntitySiteMaster(nolock) gesm on pa.GeoEntitySiteId = gesm.GeoEntitySiteId  
 inner join TBL_ET_GeoEntityMaster(nolock) gem on pa.GeoEntityId = gesm.GeoEntityId  
 inner join TBL_ET_GeoEntityCheckInOut(nolock) gecu on pa.PhysicalAppointmentId = gecu.PhysicalAppointmentId  
 where  Cast(pa.StartDate as Date) = CAST(@ActivityDate as Date) and paum.UserId = @UserId  
 order by CheckIn asc
--)  
 
drop table if Exists #temp_Site2  
  
CREATE TABLE #temp_Site2 (PhysicalAppointmentId bigint, Title varchar(300), StartDate datetime, EndDate datetime, GeoEntitySiteId bigint,  
 GeoEntitySiteName varchar(300), CheckIn datetime, CheckOut datetime, UserId bigint, Address varchar(300), LatitudeS1 float, LongitudeS1 float, next_PhysicalAppointmentId bigint)  
  
insert into #temp_Site2 (PhysicalAppointmentId, Title, StartDate, EndDate, GeoEntitySiteId, GeoEntitySiteName, CheckIn, CheckOut, UserId,   
  Address, LatitudeS1, LongitudeS1, next_PhysicalAppointmentId)  
  
SELECT Distinct ctpa.PhysicalAppointmentId, ctpa.Title, ctpa.StartDate, ctpa.EndDate, ctpa.GeoEntitySiteId, ctpa.GeoEntitySiteName,   
  CheckIn, CheckOut, UserId, Address, LatitudeS1, LongitudeS1, LEAD(ctpa.PhysicalAppointmentId,1) OVER (  
  ORDER BY ctpa.StartDate  
  ) next_PhysicalAppointmentId  
  FROM   
  #temp_Site ctpa  
  
drop table if Exists #temp_Site3  
  
CREATE TABLE #temp_Site3 (PhysicalAppointmentId bigint, Title varchar(300), StartDate datetime, EndDate datetime, GeoEntitySiteId bigint,  
 GeoEntitySiteName varchar(300), CheckIn datetime, CheckOut datetime, UserId bigint, Address varchar(300), LatitudeS1 float, LongitudeS1 float,   
 Address2 varchar(300), LatitudeS2 float, LongitudeS2 float, next_PhysicalAppointmentId bigint, GeoEntitySiteId2 bigint, GeoEntitySiteName2  varchar(300))  
  
insert into #temp_Site3 (PhysicalAppointmentId, Title, StartDate, EndDate, GeoEntitySiteId, GeoEntitySiteName, CheckIn, CheckOut, UserId,   
 Address, LatitudeS1, LongitudeS1, Address2, LatitudeS2, LongitudeS2, next_PhysicalAppointmentId, GeoEntitySiteId2, GeoEntitySiteName2)  
  
select ctpa2.PhysicalAppointmentId, ctpa2.Title, ctpa2.StartDate, ctpa2.EndDate, ctpa2.GeoEntitySiteId, ctpa2.GeoEntitySiteName,   
CheckIn, CheckOut, UserId, ctpa2.Address, ctpa2.LatitudeS1, ctpa2.LongitudeS1,   
pa2.Address Address2, gesm2.Latitude LatitudeS2, gesm2.Longitude LongitudeS2,   
next_PhysicalAppointmentId, gesm2.GeoEntitySiteId GeoEntitySiteId2, isnull(gesm2.GeoEntitySiteName, (gem2.GeoEntityName + ' - ' +  gem2.GeoEntityType)) GeoEntitySiteName2   
 from #temp_Site2 ctpa2   
 inner join TBL_ET_PhysicalAppointment(nolock) pa2 on  ctpa2.next_PhysicalAppointmentId = pa2.PhysicalAppointmentId  
 inner join TBL_ET_GeoEntitySiteMaster(nolock) gesm2 on pa2.GeoEntitySiteId = gesm2.GeoEntitySiteId  
 inner join TBL_ET_GeoEntityMaster(nolock) gem2 on gesm2.GeoEntityId = gem2.GeoEntityId  
  
select * from (  
select tsite.*, (tsite.GeoEntitySiteName + ' to ' + GeoEntitySiteName2) SiteFromTo, 0 distance from #temp_Site3 tsite  
)ttt where ttt.GeoEntitySiteName != ttt.GeoEntitySiteName2  
  
end  
  
END TRY  
  
BEGIN CATCH  
 DECLARE @ErrorMessage NVARCHAR(4000);  
 SELECT @ErrorMessage = ERROR_MESSAGE();  
 RAISERROR (  
   @ErrorMessage  
   ,16  
   ,1  
   );  
END CATCH  



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_TaskConditionByTaskId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_TBL_ET_TaskConditionByTaskId]        
@TaskId BIGINT,        
@UserId BIGINT    
AS        
BEGIN       
    
  declare @ParentId bigint = 0  
  select @ParentId = ParentID from User_Detail(nolock) where User_Id = @UserId  
  
	SELECT TCDetailId, TOM.TCId, TOM.TypeofForm, SequenceNo, Operand1, Operator, Operand2, Conjunction FROM TBL_ET_TaskConditionSetting TOM 
		INNER JOIN TBL_ET_TaskConditionDetail UOM  ON  TOM.TCId = UOM.TCId  
		where TOM.AttendanceGroupid = @TaskId
			ORDER BY UOM.SequenceNo ASC       
   

END



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_TerritoryMasterSave]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--usp_TBL_ET_TerritoryMasterSave 'SI', 0, 1, 1, '66', '27', 'addresss', 'Add', 'cit', 'stat', Indi, '11', GetDate(), 34594
CREATE   PROCEDURE  [dbo].[usp_TBL_ET_TerritoryMasterSave] (
	 @Mode VARCHAR(2)
	,@TerritoryId bigint = 0
	,@TerritoryName varchar(200) = ''
	,@Description varchar(200) = ''
	,@GeofenceIds nvarchar(max) = ''
	,@UserIds nvarchar(max) = ''
	,@ManagerIds nvarchar(max) = ''
	,@CreatedBy bigint = 0
	,@Contain nvarchar(100) = ''
	,@Offset int = 0
	,@PageSize int = 10
	,@IsActive bit = 1
)
AS
SET NOCOUNT ON

BEGIN TRY


	--declare
	--	 @Mode VARCHAR(2) = N'SU'
	--	,@TerritoryId bigint = 2
	--	,@TerritoryName varchar(200) = N'north zone ahmdnagr'
	--	,@Description varchar(200) = N'bnvnbn'
	--	,@GeofenceIds nvarchar(max) = N'0,1'
	--	,@UserIds nvarchar(max) = N'36932,38990,38991,38992,38993'
	--	,@ManagerIds nvarchar(max) = N'39303,39304,39834'
	--	,@CreatedBy bigint = 34594
	--	,@Contain nvarchar(100) = N''
	--	,@Offset int = 0
	--	,@PageSize int = 10
	--	,@IsActive bit = 1

	Declare @ParentId bigint
	Select @ParentId = ParentId from User_Detail(NOLOCK) where User_ID = @CreatedBy

	declare @tUM as table (
		Id bigint identity (1,1),
		UserId bigint,
		IsManager bit default 0
	)

	if(isnull(@ManagerIds, '') <> '')
	begin
		insert into @tUM (UserId, IsManager) 
		select [value], 1 from string_split(@ManagerIds, ',');
	end

	if(isnull(@UserIds, '') <> '')
	begin
		insert into @tUM (UserId, IsManager) 		
		select u.UserId, u.IsManager 
			from @tUM m right join ( 
				select [value] as [UserId], 0 as IsManager from string_split(@UserIds, ',')
			) u on m.UserId  = u.UserId where m.UserId is null
	end

	IF (@Mode = 'SI') /*This is for Insert Details */
	BEGIN
	if(Not Exists(select top 1 TerritoryId from TBL_ET_TerritoryMaster(nolock) gesm 
	where gesm.TerritoryName = @TerritoryName and gesm.ParentId = @ParentId))
	Begin

	DECLARE @ID BIGINT;

	INSERT INTO TBL_ET_TerritoryMaster (TerritoryName, Description, ParentId, CreatedDate, CreatedBy, IsActive)
	values( @TerritoryName, @Description, @ParentId, GETDATE(), @CreatedBy, @IsActive)

	SET @ID = scope_identity();

	INSERT INTO TBL_ET_TerritoryGeofence (TerritoryId, GeofenceId, ParentId, CreatedDate, CreatedBy, IsActive)
	SELECT @ID, item, @ParentId, GETDATE(), @CreatedBy, @IsActive FROM dbo.fu_SplitString(@GeofenceIds, ',')

	INSERT INTO TBL_ET_TerritoryUserMapping (TerritoryId, UserId, IsManager, ParentId, CreatedDate, CreatedBy, IsActive)
	SELECT @ID, t.UserId, t.IsManager, @ParentId, GETDATE(), @CreatedBy, @IsActive FROM @tUM t
	--SELECT @ID, item, @ParentId, GETDATE(), @CreatedBy, @IsActive FROM dbo.fu_SplitString(@UserIds, ',')

	SELECT 'Record Saved' STATUS, @ID TerritoryId
	END
	Else
	Begin
	SELECT 'Record Already Exists' STATUS, 0 TerritoryId
	End
	END /*End here for insert*/
	
	Else IF (@Mode = 'SU') /*This is for Insert Details */
	BEGIN
	if(Exists(select top 1 TerritoryId from TBL_ET_TerritoryMaster(nolock) gesm 
	where gesm.TerritoryId = @TerritoryId))
	Begin

	DELETE TBL_ET_TerritoryGeofence WHERE GeofenceId NOT IN (SELECT DISTINCT item FROM dbo.fu_SplitString(@GeofenceIds, ',')  
    ) and ParentId = @ParentId and TerritoryId = @TerritoryId

	
	DELETE TBL_ET_TerritoryUserMapping WHERE UserId NOT IN (SELECT DISTINCT UserId FROM @tUM  
    ) and ParentId = @ParentId and TerritoryId = @TerritoryId

	DECLARE @ID2 BIGINT;

	Update TBL_ET_TerritoryMaster set TerritoryName = @TerritoryName, Description = @Description, UpdatedDate = GETDATE(), UpdatedBy = @CreatedBy, IsActive = @IsActive
	where TerritoryId = @TerritoryId

	SET @ID2 = @TerritoryId;

	INSERT INTO TBL_ET_TerritoryGeofence (TerritoryId, GeofenceId, ParentId, CreatedDate, CreatedBy, IsActive)
	SELECT DISTINCT @ID2, item, @ParentId, GETDATE(), @CreatedBy, @IsActive FROM dbo.fu_SplitString(@GeofenceIds, ',') where Item not in (select DISTINCT GeofenceId from TBL_ET_TerritoryGeofence(nolock) where TerritoryId = @TerritoryId)

	INSERT INTO TBL_ET_TerritoryUserMapping (TerritoryId, UserId, IsManager, ParentId, CreatedDate, CreatedBy, IsActive)
	SELECT @TerritoryId, t.UserId, t.IsManager, @ParentId, GETDATE(), @CreatedBy, @IsActive 
	FROM @tUM t where t.UserId not in (	
		select DISTINCT UserId from TBL_ET_TerritoryUserMapping(nolock) where TerritoryId = @TerritoryId
	)

	update tm set tm.IsManager = case when t.IsManager = 1 then 1 else 0 end
	from TBL_ET_TerritoryUserMapping(nolock) tm
		left join @tUM t on tm.UserId = t.UserId 
	where TerritoryId = @TerritoryId --and tm.isManager = 0


	SELECT 'Record Updated' STATUS, @TerritoryId TerritoryId

	END /*End here for insert*/
	Else
	Begin
	SELECT 'No record found' STATUS, @TerritoryId TerritoryId
	End

	END /*End here for insert*/

	Else IF (@Mode = 'SL') /*This is List Details */
	BEGIN 
	Select TerritoryId, TerritoryName, Description, '' GeofenceNames, '' UserNames
	, Concat(ud.FName, '' , isnull(ud.LName, '')) CreatedByName 
	, Concat(ud2.FName, '' , isnull(ud2.LName, '')) UpdatedByName 
	,sp.CreatedDate, sp.CreatedBy, sp.UpdatedDate, sp.UpdatedBy 
	,sp.IsActive from TBL_ET_TerritoryMaster sp 
	left join User_Detail (nolock) ud on sp.CreatedBy = ud.User_ID
	left join User_Detail (nolock) ud2 on sp.UpdatedBy = ud2.User_ID
	where sp.TerritoryId = (case when @TerritoryId > 0 then @TerritoryId else sp.TerritoryId end) 
	and sp.TerritoryName like '%' + @TerritoryName + '%' 
	and sp.ParentId = @ParentId 
	END /*End here for list */ 

	Else IF (@Mode = 'SS') /*This is List Details */
	BEGIN

	if(@Contain != '')
	Begin
	set @Contain = ' and IsActive = ''' + @Contain + ''
	End

Declare @query nvarchar(max)
set @query = ' Select count(sp.TerritoryId) over() as TotalRecords, sp.TerritoryId, sp.TerritoryName, Description, isnull(dbo.ufn_GetGeofenceNamesTerritoryId(sp.TerritoryId), ''No geofence'') GeofenceNames, isnull(dbo.ufn_GetUserNamesTerritoryId(sp.TerritoryId), ''No user'') UserNames
	, Concat(ud.FName, '''' , isnull(ud.LName, '''')) CreatedByName 
	, Concat(ud2.FName, '''' , isnull(ud2.LName, '''')) UpdatedByName 
	,sp.CreatedDate, sp.CreatedBy, isnull(sp.UpdatedDate, sp.CreatedDate) UpdatedDate, isnull(sp.UpdatedBy, sp.CreatedBy) UpdatedBy 
	,sp.IsActive, dbo.udf_GetTerritoryManagerName(sp.TerritoryId) as [ManagerName] from TBL_ET_TerritoryMaster sp 
	left join User_Detail (nolock) ud on sp.CreatedBy = ud.User_ID 
	left join User_Detail (nolock) ud2 on sp.UpdatedBy = ud2.User_ID 
	where sp.TerritoryId = (case when '+ cast(@TerritoryId as varchar(10))+ ' > 0 then '+ cast(@TerritoryId as varchar(10))+ ' else sp.TerritoryId end) 
	and sp.TerritoryName like ''%' + @TerritoryName + '%'' 
	and sp.ParentId = '+ cast(@ParentId as varchar(10)) + ' ' + @Contain + '
 Order By sp.TerritoryId Desc
 Offset '+ cast(@Offset as varchar(10)) + ' rows fetch next '+ cast(@PageSize as varchar(10)) + ' rows only '
 
 print @query

  execute sp_executesql @query

	END /*End here for list */
	Else IF (@Mode = 'SD') /*This is List Details */
	BEGIN
	Select sp.TerritoryId, sp.TerritoryName, Description, isnull(dbo.ufn_GetGeofenceNamesTerritoryId(sp.TerritoryId), 'No geofence') GeofenceNames, 
	isnull(dbo.ufn_GetUserNamesTerritoryId(sp.TerritoryId), 'No Users') UserNames
	, Concat(ud.FName, '' , isnull(ud.LName, '')) CreatedByName, Concat(ud2.FName, '' , isnull(ud2.LName, '')) UpdatedByName 
	,sp.CreatedDate, sp.CreatedBy, isnull(sp.UpdatedDate, sp.CreatedDate) UpdatedDate, isnull(sp.UpdatedBy, sp.CreatedBy) UpdatedBy 
	,sp.IsActive from TBL_ET_TerritoryMaster sp 
	left join User_Detail (nolock) ud on sp.CreatedBy = ud.User_ID 
	left join User_Detail (nolock) ud2 on sp.UpdatedBy = ud2.User_ID 
	where sp.TerritoryId = @TerritoryId 

	Select * from TBL_ET_TerritoryGeofence(nolock) spgf 
	where spgf.TerritoryId = @TerritoryId 

	Select TerritoryIUserMappingd, TerritoryId, UserId, ParentId, CreatedDate, CreatedBy, UpdatedDate, UpdatedBy, IsActive, isnull(isManager, 0) as [IsManager]
from TBL_ET_TerritoryUserMapping(nolock) spud 
	where spud.TerritoryId = @TerritoryId 

	END /*End here for list */
	Else IF (@Mode = 'DL') /*This is List Details */
	BEGIN

	delete TBL_ET_TerritoryGeofence where TerritoryId = @TerritoryId 

	delete TBL_ET_TerritoryUserMapping where TerritoryId = @TerritoryId 

	delete TBL_ET_TerritoryMaster 	where TerritoryId = @TerritoryId 

	SELECT 'Record Deleted' STATUS

	End
END TRY
BEGIN CATCH
	DECLARE @ErrorMessage NVARCHAR(4000);
	SELECT @ErrorMessage = ERROR_MESSAGE();
	RAISERROR (
			@ErrorMessage
			,16
			,1
			);
END CATCH



GO

