   Procedure: [dbo].[usp_TBL_ET_UserLocationTracking]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--alter table TBL_ET_UserLocationTracking add Speed varchar(50), Distance varchar(50)
--usp_TBL_ET_UserLocationTracking 'LT', 0 ,'SignIn','SignIn',34594,'2022-12-28 20:00','27.1','77.1',34594,1
-- exec usp_TBL_ET_UserLocationTracking @Mode=N'LT',@MovementCode=N'SIGN_IN',@Remarks=N'32222 is SignIn.',@UserId=32222,@LocationDateTime=N'29-May-2023 20:04:59',@Latitude=N'21.2128848',@Longitude=N'72.8234148',@CreatedBy=32222,@IsActive=1,@IsMock=0,@Address=N'100, Katargam, Surat, Gujarat,395004, India',@BatteryPerc=N'68',@NetworkPerc=N'0',@Speed=N'0.0',@Distance=N'11.0'
CREATE   PROCEDURE [dbo].[usp_TBL_ET_UserLocationTracking] 
(  
	 @Mode VARCHAR(2),  
	 @UserLocationTrackingId bigint = 0,  
	 @MovementCode varchar(20),  
	 @Remarks varchar(1000),  
	 @UserId bigint,  
	 @LocationDateTime Datetime,  
	 @Latitude float,  
	 @Longitude float,  
	 @CreatedBy bigint,  
	 @IsActive bit,  
	 @IsMock bit = 0,
	 @Address nvarchar(1000)= '',
	 @BatteryPerc varchar(20)= '',  
	 @NetworkPerc varchar(20)= '',  
	 @Speed varchar(50)= '',
	 @Distance varchar(50)= '',
	 @LocationMetaData nvarchar(max) = ''
)  
AS  
SET NOCOUNT ON  
  
BEGIN TRY  
 IF (@Mode = 'LT') /*This is for Insert Details */  
 BEGIN  
  
--Declare @MovementCode varchar(20) = 'SignIn',  
--      @Remarks varchar(1000) = 'SignIn',  
--     @UserId bigint = 34594,  
--     @LocationDateTime Datetime = '2022-12-28 20:00',  
--     @Latitude float = '27.1',  
--     @Longitude float = '77.1',  
--     @CreatedBy bigint = 34594,  
--     @IsActive bit = 1  

insert into tbl_et_UserLocationTrackingBulkRequest (MovementCode, Remarks, UserId, LocationDateTime, Latitude, Longitude, CreatedDate, CreatedBy, IsActive, IsMock, [Address], BatteryPerc,NetworkPerc, Speed, Distance, LocationMetaData)  
 values(@MovementCode, @Remarks, @UserId, @LocationDateTime, @Latitude, @Longitude, GETDATE(), @CreatedBy, @IsActive, @IsMock, @Address, @BatteryPerc, @NetworkPerc, @Speed, @Distance, @LocationMetaData) 

  /*
 insert into TBL_ET_UserLocationTracking (MovementCode, Remarks, UserId, LocationDateTime, Latitude, Longitude, CreatedDate, CreatedBy, IsActive, IsMock, [Address], BatteryPerc,NetworkPerc, Speed, Distance, LocationMetaData)  
 values(@MovementCode, @Remarks, @UserId, @LocationDateTime, @Latitude, @Longitude, GETDATE(), @CreatedBy, @IsActive, @IsMock, @Address, @BatteryPerc, @NetworkPerc, @Speed, @Distance, @LocationMetaData)  
  

 
 Declare @Identity bigint = cast(scope_identity() as bigint)  
 Declare @ParentId bigint, @EventDesc nvarchar(max)=''
 
 Select @ParentId=ParentId from User_Detail(nolock) where User_id=@UserId
  
  If(@MovementCode='GPS_OFF')
  Begin
	if not exists(select * from TBL_ET_UserLocationTracking(Nolock) where MovementCode!='GPS_OFF' and userId=@UserId and datediff(SECOND,LocationDateTime,@LocationDateTime) between 0 and 900)
	Begin
		Select @EventDesc=replace(AM.EventTemplate,'#username#',dbo.fn_getentityfullname('user',@UserId))
		from ActivityMaster(Nolock) AM
		Where AM.EventName='GPS_OFF'

		Exec UspSaveEntityActivity_withid @entityname='User',@EntityID=0,@UserID=@UserId,@ParentID=@ParentId,@EventDescription=@EventDesc,@EventName='GPS_OFF',@reftables='TBL_ET_UserLocationTracking',@refid=@Identity
	End
  End

  If(cast(@BatteryPerc as int) < 30)
  Begin
	Select @EventDesc=replace(replace(AM.EventTemplate,'#username#',dbo.fn_getentityfullname('user',@UserId)),'#batteryperc#',@BatteryPerc)
	from ActivityMaster(Nolock) AM
	Where AM.EventName='Low battery'

	Exec UspSaveEntityActivity_withid @entityname='User',@EntityID=0,@UserID=@UserId,@ParentID=@ParentId,@EventDescription=@EventDesc,@EventName='Low battery',@reftables='TBL_ET_UserLocationTracking',@refid=@Identity
  End

  If(@NetworkPerc=0)
  Begin
	if not exists(select * from TBL_ET_UserLocationTracking(Nolock) where NetworkPerc!=0 and userId=@UserId and datediff(SECOND,LocationDateTime,@LocationDateTime) between 0 and 900)
	Begin
		Select @EventDesc=replace(AM.EventTemplate,'#username#',dbo.fn_getentityfullname('user',@UserId))
		from ActivityMaster(Nolock) AM
		Where AM.EventName='Network off'

		Exec UspSaveEntityActivity_withid @entityname='User',@EntityID=0,@UserID=@UserId,@ParentID=@ParentId,@EventDescription=@EventDesc,@EventName='Network off',@reftables='TBL_ET_UserLocationTracking',@refid=@Identity
	End
  End

  If(@MovementCode='STATIONARY')
  Begin
	if not exists(select * from TBL_ET_UserLocationTracking(Nolock) where MovementCode!='STATIONARY' and userId=@UserId and datediff(SECOND,LocationDateTime,@LocationDateTime) between 0 and 900)
	Begin
		Select @EventDesc=replace(AM.EventTemplate,'#username#',dbo.fn_getentityfullname('user',@UserId))
		from ActivityMaster(Nolock) AM
		Where AM.EventName='User stationary or little movement'

		Exec UspSaveEntityActivity_withid @entityname='User',@EntityID=0,@UserID=@UserId,@ParentID=@ParentId,@EventDescription=@EventDesc,@EventName='User stationary or little movement',@reftables='TBL_ET_UserLocationTracking',@refid=@Identity
	End
  End


 Declare @CDateTime DateTime = GETDATE()  
  
 exec usp_tbl_ET_AttendanceAutoUpdate @UserId, @CDateTime  

 */
   
 --Select  'Saved Record' Status, @Identity UserLocationTrackingId  
  
 End  
END TRY  
  
BEGIN CATCH  
 DECLARE @ErrorMessage NVARCHAR(4000);  
 SELECT @ErrorMessage = ERROR_MESSAGE();  
 RAISERROR (  
   @ErrorMessage  
   ,16  
   ,1  
   );  
END CATCH  



GO

