   Procedure: [dbo].[usp_TBL_ET_UserLocationTrackingBulk]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_TBL_ET_UserLocationTrackingBulk] (  
	@Mode VARCHAR(2),  
	@UserLocationTrackingId bigint = 0,  
	@LocationList nvarchar(max),  
	@UserId bigint,  
	@CreatedBy bigint,  
	@IsActive bit  
)  
AS  
begin
	
	SET NOCOUNT ON  

	--declare
	--	@Mode VARCHAR(2) = N'BT',  
	--	@UserLocationTrackingId bigint = 0,  
	--	@LocationList nvarchar(max) = N'[{"MovementCode":"SIGN_OUT","Remarks":"Abhi01 is SignOut.","LocationDateTime":"29-Feb-2024 12:49:18","Latitude":"21.2128466","Longitude":"72.8233152","IsMock":0,"Address":"B-120, Katargam, Surat, Gujarat,395004, India","BatteryPerc":"12","NetworkPerc":"1","Speed":"0.0","TotalCoverDistance":"104.0","LocationMetaData":"{\"EntityName\":\"Dynamic\",\"EntityId\":\"0\",\"DeviceId\":\"dNhRdMX9QgqC_zPC-Q9Kl-:APA91bHdqY90KJciuJ_684LoI39L9isTha6siZ3yfmRTRK1UsHfmUquYuPzoUTJmkzQZSy_qu7Yo1tZdapLZ6sFB4l4LPWWZleOcLgNLtE-_IUTJx0DNJ1YS67TrEfSR6VYdX2Iw9N_5\",\"AttendanceId\":\"20097\",\"PhysicalAppointmentId\":\"\",\"BreakTransactionId\":\"\"}"},{"MovementCode":"STATIONARY","Remarks":"Abhi01 is not moving.","LocationDateTime":"29-Feb-2024 12:49:21","Latitude":"21.212805","Longitude":"72.8232391","IsMock":0,"Address":"41, Katargam, Surat, Gujarat,395004, India","BatteryPerc":"12","NetworkPerc":"1","Speed":"0.06666666666666667","TotalCoverDistance":"104.0","LocationMetaData":"{\"EntityName\":\"\",\"EntityId\":\"\",\"DeviceId\":\"dNhRdMX9QgqC_zPC-Q9Kl-:APA91bHdqY90KJciuJ_684LoI39L9isTha6siZ3yfmRTRK1UsHfmUquYuPzoUTJmkzQZSy_qu7Yo1tZdapLZ6sFB4l4LPWWZleOcLgNLtE-_IUTJx0DNJ1YS67TrEfSR6VYdX2Iw9N_5\",\"AttendanceId\":\"\",\"PhysicalAppointmentId\":\"\",\"BreakTransactionId\":\"\"}"}]',
	--	@UserId bigint = 32222,  
	--	@CreatedBy bigint = 32222,  
	--	@IsActive bit  = 1



	BEGIN TRY  
	 IF (@Mode = 'BT') /*This is for Insert Details */  
	 BEGIN  

		insert into tbl_et_UserLocationTrackingBulkRequest(MovementCode, Remarks, LocationDateTime, Latitude, Longitude, IsMock, UserId, 
			CreatedDate, CreatedBy, IsActive, IsBulk, Address, BatteryPerc, NetworkPerc, Speed, Distance, LocationMetaData, IsProcess
			, ErrorDescription ) 
		select distinct MovementCode, Remarks, LocationDateTime, Latitude, Longitude, IsMock, @UserId, 
			GETDATE(), @CreatedBy, @IsActive, 1, Address, BatteryPerc, NetworkPerc, Speed, Distance, LocationMetaData,
			case when isnull([Address], '') = '' then 5 else 0 end ,
			case when isnull([Address], '') = '' then 'Invalid coordinates due to no network' else null end
		from openjson(@LocationList) with ( 
			MovementCode nvarchar(20) '$.MovementCode',                    
			Remarks nvarchar(1000) '$.Remarks',                    
			LocationDateTime datetime '$.LocationDateTime',  
			Latitude float '$.Latitude',  
			Longitude float '$.Longitude',  
			IsMock bit '$.IsMock',  
			[Address] nvarchar(500) '$.Address',  
			BatteryPerc nvarchar(20) '$.BatteryPerc',  
			[NetworkPerc] nvarchar(20) '$.NetworkPerc',  
			[Speed] nvarchar(20) '$.Speed',  
			[Distance] nvarchar(20) '$.TotalCoverDistance',  
			[LocationMetaData] nvarchar(max) '$.LocationMetaData'  
		) t 

	 End  
	END TRY  
  
	BEGIN CATCH  
	  EXEC usp_insertErrorInfo
	END CATCH  
end



GO

