CREATE   PROCEDURE [dbo].[usp_TBL_ET_UserLocationTrakerRoute] (
	@Mode VARCHAR(2),
	@UserId bigint,
	@LocationDateTime Datetime
  )
AS
SET NOCOUNT ON

BEGIN TRY
IF (@Mode = 'TR') /*This is for Insert Details */
BEGIN

--Declare @UserId bigint = 34594,
--	    @LocationDateTime Datetime = '2022-12-28 20:00'
	
	if(@LocationDateTime <= DATEADD(day, -30, getdate()))
	begin
		Select * from TBL_ET_UserLocationTracking_Archived(nolock) 
		Where UserId = @UserId and Cast(LocationDateTime as Date) = Cast(@LocationDateTime as Date)
			Order By LocationDateTime Asc
	end
	else
	begin
		Select * from TBL_ET_UserLocationTracking(nolock) 
		Where UserId = @UserId and Cast(LocationDateTime as Date) = Cast(@LocationDateTime as Date)
			Order By LocationDateTime Asc
	end
End
END TRY

