/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_UserVisitPhyDetails_Name]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--usp_TBL_ET_UserVisitPhyDetails_Name 'LS', 34595, '2023-03-01', '2023-03-31', 34594, 0, 10   
CREATE   PROCEDURE [dbo].[usp_TBL_ET_UserVisitPhyDetails_Name]
(
 @Mode VARCHAR(2)
 ,@PhysicalAppointmentId bigint = 0
 ,@UserId bigint
 ,@FromDate nvarchar(100) = ''  
 ,@ToDate nvarchar(100) = ''  
)
AS  
SET NOCOUNT ON  
BEGIN TRY 

if(@Mode = 'LD')

Begin
Declare @querydetails nvarchar(max)
set @querydetails = '  
select ud.FName + '' '' + ud.LName + '' (''+ud.User_Login+'')'' AssignedToName,ud.User_Id,
tepa.Title, tepa.Description, tepa.Address, tepa.CompleteAddress, tepa.StartDate, tepa.EndDate,
 FORMAT(tepa.StartDate,''hh:mm tt'') StartDateTime, FORMAT(tepa.EndDate,''hh:mm tt'') EndDateTime,
isnull(tepa.OutcomesId, 0) OutcomesId, isnull(fuss.FollowupStatus, '''') FollowupStatus,
isnull(tepa.Status, '''') PhyStatus, ud.Image, ud.ProfilePictureName, isnull((select top 1 Remarks from TBL_ET_PhyAppointComment (nolock) tepc where tepc.PhysicalAppointmentId = tepa.PhysicalAppointmentId order by 1 desc),'''') PhyRemarks, 
FORMAT(cast((case when tepa.StartDate != '''' then tepa.StartDate else tepa.EndDate end) as datetime), ''dd-MM-yyyy hh:mm tt'') ScheduleDate,
FORMAT(cast((case when geci.CheckIn != '''' then geci.CheckIn else geci.CheckOut end) as datetime), ''dd-MM-yyyy hh:mm tt'') TravelDate,
geci.CheckIn, geci.CheckOut, FORMAT(geci.CheckIn,''hh:mm tt'') CheckInTime, FORMAT(geci.CheckOut,''hh:mm tt'') CheckOutTime,
DateDiff(minute, geci.CheckIn, geci.CheckOut) DurationofWork, '''' Distance, '''' CheckInAddress, '''' CheckOutAddress,
dbo.fun_getEntityDetail_entityId(tepa.GeoEntityId) EntityName, isnull(tege.GeoEntityType, '''') EntityType
from TBL_ET_PhysicalAppointment(nolock) tepa 
left join User_Detail(nolock) ud on tepa.AssignedTo = ud.User_ID
left join FollowUp_Status(nolock) fuss on tepa.OutcomesId = fuss.ID
left join TBL_ET_GeoEntityCheckInOut(nolock) geci on tepa.PhysicalAppointmentId = geci.PhysicalAppointmentId
left join TBL_ET_GeoEntityMaster(nolock) tege on tepa.GeoEntityId = tege.GeoEntityId
left join TBL_ET_GeoEntitySiteMaster(nolock) tegs on tepa.GeoEntitySiteId = tegs.GeoEntitySiteId 
where tepa.AssignedTo = '+ cast(@UserId as nvarchar(20))+ ' and 
((cast(geci.CheckIn as date) between cast(''' + cast(@FromDate as varchar(10)) +''' as date) and cast(''' + cast(@ToDate as varchar(10)) +''' as date))
or (cast(geci.CheckOut as date) between cast(''' + cast(@FromDate as varchar(10)) +''' as date) and cast(''' + cast(@ToDate as varchar(10)) +''' as date))) and
geci.PhysicalAppointmentId = '+ cast(@PhysicalAppointmentId as nvarchar(20)) +''

print @querydetails

execute sp_executesql @querydetails
End

END TRY  
BEGIN CATCH  
 DECLARE @ErrorMessage NVARCHAR(4000); 
 SELECT @ErrorMessage = ERROR_MESSAGE(); 
 RAISERROR ( 
   @ErrorMessage 
   ,16 
   ,1 
   );
END CATCH 



GO

/* ============================================================
   Procedure: [dbo].[usp_TBL_ET_UserVisitPhyList_Name]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--usp_TBL_ET_UserVisitPhyList_Name 'LS', '', '', '2023-03-01', '2023-03-31', 34594, 0, 10   
CREATE   PROCEDURE [dbo].[usp_TBL_ET_UserVisitPhyList_Name]
(
 @Mode VARCHAR(2)
 ,@SearchText varchar(200) = ''
 ,@Contain varchar(200) = ''
 ,@FromDate nvarchar(100) = ''  
 ,@ToDate nvarchar(100) = ''  
 ,@UserId bigint = 0
 ,@Offset int = 0  
 ,@PageSize int = 10 
)
AS
SET NOCOUNT ON  
BEGIN TRY 

Declare @ParentId bigint, @IsAdmin bit 
 Select @IsAdmin = IsAdmin, @ParentId = ParentId from User_Detail(NOLOCK) where User_ID = @UserId  
 declare @UserIdTeamLst varchar(500) = ''     
declare @tbluser table (User_ID bigint,Name varchar(100), Image varchar(100))
if(@IsAdmin = 1)
	begin
		set @UserId = 0;
		insert into @tbluser
		exec Use_GetUserDetails @ParentId
	end
	else
	Begin
		insert into @tbluser
		exec Use_GetUserDetails @UserId
	End

 select @UserIdTeamLst=isnull(STRING_AGG(User_ID,','),'') From @tbluser
 if(@UserIdTeamLst = '')
 Begin
 set @UserIdTeamLst = Cast(@UserId as varchar(10))
 
 End

 if(@SearchText = '')
 Begin
 set @SearchText = ''
 End

if(@Contain = '')
Begin
 set @Contain = ''
 End
else
Begin
 set @Contain =  ' and ' + @Contain;
End

if(@Mode = 'LS')

Begin
Declare @query nvarchar(max)
set @query = ' Select count(t.User_Id) over() as TotalRecords, AssignedToName, User_Id, 
count(t.PhysicalAppointmentId) TotalAssigned, count(isnull(t.GeoEntityCheckId, 0)) TotalVisit, dbo.fn_TBL_ET_PhysicalAppointmentTypeCount(User_Id,''' + cast(@FromDate as varchar(10)) + ''',''' + cast(@ToDate as varchar(10))+''',''Missed'') TotalMissed, dbo.fn_TBL_ET_PhysicalAppointmentTypeCount(User_Id,''' + cast(@FromDate as varchar(10)) + ''',''' + cast(@ToDate as varchar(10))+''',''Pending'')  TotalPending
from (select distinct tepa.PhysicalAppointmentId, ud.FName + '' '' + ud.LName + '' (''+ud.User_Login+'')'' AssignedToName, ud.User_Id, tepa.Title, tepa.Description, tepa.Address, tepa.CompleteAddress, isnull(geci.GeoEntityCheckId, 0) GeoEntityCheckId
from TBL_ET_PhysicalAppointment(nolock) tepa 
left join User_Detail(nolock) ud on tepa.AssignedTo = ud.User_ID
left join FollowUp_Status(nolock) fuss on tepa.OutcomesId = fuss.ID
left join TBL_ET_GeoEntityCheckInOut(nolock) geci on tepa.PhysicalAppointmentId = geci.PhysicalAppointmentId
inner join TBL_ET_PhyAppointUserMapping(nolock) trpu on tepa.PhysicalAppointmentId = geci.PhysicalAppointmentId
where tepa.AssignedTo in (select [value] from dbo.fn_Split('''+ cast(@UserIdTeamLst as nvarchar(max))+ ''', '','')) and 
((cast(geci.CheckIn as date) between cast(''' + cast(@FromDate as varchar(10)) +''' as date) and cast(''' + cast(@ToDate as varchar(10)) +''' as date))
or (cast(geci.CheckOut as date) between cast(''' + cast(@FromDate as varchar(10)) +''' as date) and cast(''' + cast(@ToDate as varchar(10)) +''' as date)))
and (ud.FName + '' '' + ud.LName + '' (''+ud.User_Login+'')'' like ''%'+ @SearchText +'%'') and Title like ''%'+ @SearchText +'%'' ' + @Contain + '
)t
group by AssignedToName, User_Id
order by t.User_Id asc
OFFSET '+ cast(@Offset as varchar(10)) +' Rows FETCH NEXT '+ cast(@PageSize as varchar(10)) +' ROWS ONLY  


select ud.FName + '' '' + ud.LName + '' (''+ud.User_Login+'')'' AssignedToName,ud.User_Id,
tepa.Title, tepa.Description, tepa.Address, tepa.CompleteAddress, tepa.StartDate, tepa.EndDate,
 FORMAT(tepa.StartDate,''hh:mm tt'') StartDateTime, FORMAT(tepa.EndDate,''hh:mm tt'') EndDateTime,
isnull(tepa.OutcomesId, 0) OutcomesId, isnull(fuss.FollowupStatus, '''') FollowupStatus,
isnull(tepa.Status, '''') PhyStatus, ud.Image, ud.ProfilePictureName, isnull((select top 1 Remarks from TBL_ET_PhyAppointComment (nolock) tepc where tepc.PhysicalAppointmentId = tepa.PhysicalAppointmentId order by 1 desc),'''') PhyRemarks, 
FORMAT(cast((case when tepa.StartDate != '''' then tepa.StartDate else tepa.EndDate end) as datetime), ''dd-MM-yyyy hh:mm tt'') ScheduleDate,
FORMAT(cast((case when geci.CheckIn != '''' then geci.CheckIn else geci.CheckOut end) as datetime), ''dd-MM-yyyy hh:mm tt'') TravelDate,
geci.CheckIn, geci.CheckOut, FORMAT(geci.CheckIn,''hh:mm tt'') CheckInTime, FORMAT(geci.CheckOut,''hh:mm tt'') CheckOutTime,
DateDiff(minute, geci.CheckIn, geci.CheckOut) DurationofWork, '''' Distance, '''' CheckInAddress, '''' CheckOutAddress,
dbo.fun_getEntityDetail_entityId(tepa.GeoEntityId) EntityName, isnull(tege.GeoEntityType, '''') EntityType, geci.PhysicalAppointmentId
from TBL_ET_PhysicalAppointment(nolock) tepa 
left join User_Detail(nolock) ud on tepa.AssignedTo = ud.User_ID
left join FollowUp_Status(nolock) fuss on tepa.OutcomesId = fuss.ID
left join TBL_ET_GeoEntityCheckInOut(nolock) geci on tepa.PhysicalAppointmentId = geci.PhysicalAppointmentId
left join TBL_ET_GeoEntityMaster(nolock) tege on tepa.GeoEntityId = tege.GeoEntityId
left join TBL_ET_GeoEntitySiteMaster(nolock) tegs on tepa.GeoEntitySiteId = tegs.GeoEntitySiteId 
where tepa.AssignedTo in (select [value] from dbo.fn_Split('''+ cast(@UserIdTeamLst as nvarchar(max))+ ''', '','')) and 
((cast(geci.CheckIn as date) between cast(''' + cast(@FromDate as varchar(10)) +''' as date) and cast(''' + cast(@ToDate as varchar(10)) +''' as date))
or (cast(geci.CheckOut as date) between cast(''' + cast(@FromDate as varchar(10)) +''' as date) and cast(''' + cast(@ToDate as varchar(10)) +''' as date)))

'

print @query

execute sp_executesql @query
End

END TRY  
BEGIN CATCH  
 DECLARE @ErrorMessage NVARCHAR(4000); 
 SELECT @ErrorMessage = ERROR_MESSAGE(); 
 RAISERROR ( 
   @ErrorMessage 
   ,16 
   ,1 
   );
END CATCH




