/* ============================================================
   Procedure: [dbo].[usp_Tbl_MassEnquiryRemoveTag]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE usp_Tbl_MassEnquiryRemoveTag  
    @IDS VARCHAR(MAX) = '',    
 @RemoveTags nvarchar (max)=null,  
    @MassOperationName NVARCHAR(100),   
    @EntityType NVARCHAR(10),  
    @UserId BIGINT  
AS  
BEGIN  
    SET NOCOUNT ON;  
  
    BEGIN TRY  
        -- Temporary table to hold the split IDs  
        DECLARE @IDsTable TABLE (ID BIGINT)  
          
        -- Temporary table to capture inserted rows  
        DECLARE @InsertedTable TABLE (EntityID BIGINT)  
  
  DECLARE @ParentID BIGINT;         SELECT @ParentID = ParentID         FROM User_Detail (NOLOCK)         WHERE User_ID = @UserId;  
  
        -- Split the IDs and insert into the temporary table  
        DECLARE @Pos INT, @Str VARCHAR(MAX)  
        SET @Pos = 1  
        WHILE CHARINDEX(',', @IDS, @Pos) > 0  
        BEGIN  
            SET @Str = SUBSTRING(@IDS, @Pos, CHARINDEX(',', @IDS, @Pos) - @Pos)  
            INSERT INTO @IDsTable (ID) VALUES (CAST(@Str AS BIGINT))  
            SET @Pos = CHARINDEX(',', @IDS, @Pos) + 1  
        END  
        INSERT INTO @IDsTable (ID) VALUES (CAST(SUBSTRING(@IDS, @Pos, LEN(@IDS) - @Pos + 1) AS BIGINT))  
  
        -- Insert into Tbl_MassInternationalSMS and capture the inserted rows  
        INSERT INTO Tbl_MassEnquiryRemoveTag (  
            EntityID,  
   Tags,  
            MassOperationName,  
            UserID,  
            Parentid,  
            CreatedDate,  
            IsProcessed,  
            Remarks,  
            BatchStartTime,  
            BatchEndTime,  
            EntityType,  
            isvalid,  
            metadata,  
            ErrorDetails  
        )  
        OUTPUT   
            INSERTED.EntityID INTO @InsertedTable -- Capture the inserted rows  
        SELECT  
            ID,  
   @RemoveTags,  
            @MassOperationName,  
            @UserId,  
            @ParentID,   
            GETDATE(),  
            0,   
            NULL,   
            GETDATE(),  
            NULL,   
            @EntityType,  
            1,   
            NULL,   
            NULL   
     
        FROM @IDsTable  
  
        -- Return a status message and count of rows inserted for the given IDs  
        SELECT   
            'Success' AS StatusMessage,   
            COUNT(*) AS TotalRecords   
        FROM @InsertedTable  
    END TRY  
    BEGIN CATCH  
        DECLARE @ErrorMessage NVARCHAR(4000)  
        DECLARE @ErrorSeverity INT  
        DECLARE @ErrorState INT  
  
        SELECT   
            @ErrorMessage = ERROR_MESSAGE(),  
            @ErrorSeverity = ERROR_SEVERITY(),  
            @ErrorState = ERROR_STATE()  
  
        -- Rethrow the error to be handled by the calling procedure or application  
        RAISERROR (@ErrorMessage, @ErrorSeverity, @ErrorState)  
    END CATCH  
END




GO

/* ============================================================
   Procedure: [dbo].[usp_tbl_Partner_GetBatchNotification_New]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

---------------------------------------------------------------------------
CREATE   PROC [dbo].[usp_tbl_Partner_GetBatchNotification_New] -- 1                     
(                        
   @BatchSize int=1                        
)                        
AS                        
BEGIN

	/*
	Added:	DBA
	Date:	2025-01-11
	*/
	--declare @BatchSize int=1 
	drop table if exists #AppBatchNotification
	drop table if exists #BatchNotificationDetail

	CREATE TABLE #AppBatchNotification
	(
		BatchNotification_Id BIGINT
		,CONSTRAINT PK_#AppBatchNotification_ID PRIMARY KEY CLUSTERED
		(
			BatchNotification_Id
		)
	);

	CREATE TABLE #BatchNotificationDetail
	(
		 BatchNotification_Id BIGINT
		,User_ID BIGINT
		,LastAttemptedTime DATETIME
		,Retries INT
		,IsProcessed BIT
		,RawReason NVARCHAR(MAX)
		,DeviceId VARCHAR (1000)
	);

	INSERT INTO #AppBatchNotification (BatchNotification_Id)
	Select BatchNotification_Id 
	From   [tbl_APP_BatchNotification] M(nolock)                       
    Where                    
     IsProcessed=0             
    and GETDATE() <= CutOffTime                  
    and TotalProcessed<totalrecords;

	INSERT INTO #BatchNotificationDetail (BatchNotification_Id, User_ID, LastAttemptedTime,
		Retries, IsProcessed, RawReason, DeviceId)
	SELECT t.BatchNotification_Id, User_ID, LastAttemptedTime,
		Retries, IsProcessed, RawReason, DeviceId
	FROM [tbl_APP_BatchNotificationDetail] BND WITH (NOLOCK)
	INNER JOIN #AppBatchNotification t
		ON t.BatchNotification_Id = BND.BatchNotification_Id
	WHERE BND.IsProcessed = 0;
	
	Select top 1 *, 0 DataId, '' TypeName, ClickActionUrl MobPath
    From   [tbl_APP_BatchNotification] M(nolock)
	INNER JOIN #AppBatchNotification t ON t.BatchNotification_Id = M.BatchNotification_Id

	--INNER JOIN User_Detail UD WITH (NOLOCK)
 --   ON M.CreatedBy = UD.User_ID
 --   AND UD.Type IN (3, 4)

       Where  dbo.ufn_getuserparentid(M.CreatedBy) in (32222) and     
  --  BatchNotification_Id=  54679      
 --  or                 
 --    IsProcessed=0             
 --   and GETDATE() <= CutOffTime                  
 --   and TotalProcessed<totalrecords            
 --and 
 exists(Select  1                  
    From   #BatchNotificationDetail BND 
	left outer join User_Detail(nolock) UL                
      On   BND.User_ID = UL.User_ID                
          
    Where       
      
    ISNULL(UL.DeviceID,'') <> ''  and UL.Type IN (3,4) and      
        
   BND.BatchNotification_Id=M.BatchNotification_Id and BND.IsProcessed=0                 
    and      
       
  (isnull(lastattemptedtime,'')='' or datediff(s,lastattemptedtime,getdate())>=cast( (select top 1 isnull(MinValue,0) from dbo.Minimum_Func(((2^Retries)+rand(1)), 32))  as integer))               
      
       
       
 and        
 (isnull(lastattemptedtime,'')='' or datediff(MI,lastattemptedtime,getdate())>10)    
 and (          
    (isnull(BND.RawReason,'') = '')          
    or          
    (          
       Bnd.RawReason not like '%UNREGISTERED%'          
    and          
       Bnd.RawReason not like '%Not%Registered%'           
    and           
    Bnd.RawReason not like '%Missing%Registration%'           
       and           
    Bnd.RawReason not like '%SENDER_ID_MISMATCH%'           
            
    )))  order by BatchSentTime,CreatedOn    
       
        
END   





GO

/* ============================================================
   Procedure: [dbo].[usp_tbl_Partner_SetBatchNotificationEndTime_New]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-----------------------------------------------------------


CREATE   PROC [dbo].[usp_tbl_Partner_SetBatchNotificationEndTime_New]        
(        
    @BatchNotification_Id bigint,        
    @BatchCompleteTime datetime,        
    @TotalProcessed int,        
    @IsProcessed bit        
)        
AS        
BEGIN        
        
 --   Update  [MK_BatchNotification]       
 --Set BatchCompleteTime=@BatchCompleteTime, LastBatchProcessed=@BatchCompleteTime,       
 -- TotalProcessed+=@TotalProcessed, IsProcessed=@IsProcessed        
 --   Where   BatchNotification_Id=@BatchNotification_Id        
      
    --Update  [MK_BatchNotification]       
    -- Set BatchCompleteTime=@BatchCompleteTime, LastBatchProcessed=@BatchCompleteTime,       
    -- IsProcessed=@IsProcessed        
    --Where   BatchNotification_Id=@BatchNotification_Id        
    
   declare @ProcessedCount int = 0    
   select @ProcessedCount = isnull(Count(1),0) from [tbl_APP_BatchNotificationDetail] WITH (NOLOCK) where BatchNotification_Id = @BatchNotification_Id    
              and  IsProcessed = 1    
    
    Update  [tbl_APP_BatchNotification]       
     Set TotalProcessed = @ProcessedCount    
    Where   BatchNotification_Id=@BatchNotification_Id        
    
   Declare @TotalRecordCount int = 0  
     
   select @TotalRecordCount = isnull(TotalRecords,0) from [tbl_APP_BatchNotification] WITH (NOLOCK) where BatchNotification_Id=@BatchNotification_Id      
   if(@TotalRecordCount = @ProcessedCount)  
      Begin  
  
              Update  [tbl_APP_BatchNotification]       
                Set BatchCompleteTime=@BatchCompleteTime, LastBatchProcessed=@BatchCompleteTime,       
                   IsProcessed=@IsProcessed        
                 Where   BatchNotification_Id=@BatchNotification_Id        
  
   End  
      
    
    
END 




