 @ActionName varchar(50),
 @ActionCode varchar(50),
 @Active bit	=0,
 @UserId bigint = 0
)          
AS          
  SET NOCOUNT ON           
  BEGIN TRY            
  IF (@Mode='I')/*This is for Insert TBL_UA_ActionMaster Details */            
 BEGIN            
   IF NOT EXISTS(select 1 from TBL_UA_ActionMaster where ActionName = @ActionName)             
     BEGIN 
     insert into TBL_UA_ActionMaster(ActionName, ActionCode, Active, CreatedBy, CreatedDate) 
	 values(@ActionName, @ActionCode, @Active, @UserId, GETDATE())          
	 Select @@IDENTITY ID, @ActionCode Code
     END 
   ELSE          
    BEGIN          
     SELECT -10      /* Use for TBL_UA_ActionMaster Exist or not  */          
    END  
 END /*End here for insert*/            
          
  else if(@Mode='S')/*This is for List of TBL_UA_ActionMaster Details */            
 begin 
  select ActionId, ActionName, ActionCode, Active, CreatedBy, CreatedDate, ModifiedBy, ModifiedDate from TBL_UA_ActionMaster         
 end /*End here for list*/           
 
 else if(@Mode='E')/*This is for TBL_UA_ActionMaster Details */            
   begin            
  select ActionId, ActionName, ActionCode, Active, CreatedBy, CreatedDate, ModifiedBy, ModifiedDate from TBL_UA_ActionMaster 
  where ActionId = @ActionId
   end /*End here for details*/            
          
 else if(@Mode='U')/*This is for TBL_UA_ActionMaster Update Row */            
   begin            
  update TBL_UA_ActionMaster set ActionName = @ActionName, ActionCode = @ActionCode, Active = @Active, ModifiedBy = @UserId, 
  ModifiedDate = GETDATE() where ActionId = @ActionId
   end /*End here for details*/            
          
  else if(@Mode='D')/*This is for TBL_UA_ActionMaster delete Row */            
   begin 
  delete from TBL_UA_ActionMaster where ActionId = @ActionId 
   end /*End here for details*/            
           
 END TRY            
BEGIN CATCH            
            
 DECLARE @ErrorMessage NVARCHAR(4000);            
 SELECT @ErrorMessage = ERROR_MESSAGE();            
 RAISERROR (@ErrorMessage, 16, 1);            
END CATCH 



