CREATE   PROCEDURE [dbo].[usp_tbl_UA_MobilePageFields] --'ss',0,0,34594,34594,null,null,0,20,'Task',null,null                          
(                                   
 @Mode varchar(2),                         
 @PageFieldMaskId bigint = 0,                    
 @PageFieldId bigint = 0,                    
 @ParentId bigint = 0,                    
 @UserId varchar(2000) = null,                    
 @PageCode varchar(50) = null,                    
 @RoleCode varchar(50) = null,                    
 @OffsetValue int = 0,                                                                            
 @PagingSize int  = 10,                    
 @FilterText varchar(1000) = null,   
 @MaskJSON nvarchar (max)=null,
 @MobMaskRowID bigint = 0  
)                    
AS                         
  SET NOCOUNT ON                         
  BEGIN TRY      
 -- Declare @Mode varchar(2)='I', @PageFieldMaskId bigint = 0,                    
 --@PageFieldId bigint = 0,                    
 --@ParentId bigint = 0,                    
 --@UserId varchar(2000) = '32222',                    
 --@PageCode varchar(50) = 'PAG10031',                    
 --@RoleCode varchar(50) = 'MANA',                    
 --@OffsetValue int = 0,                                                                            
 --@PagingSize int  = 10,                    
 --@FilterText varchar(1000) = null,   
 --@MaskJSON nvarchar (max)='[{\"MaskType\":\"hidden\",\"IsExportAllow\":true,\"FieldName\":\"\",\"TableName\":\"\",\"FieldType\":\"\",\"ParentId\":\"32222\"},{\"MaskType\":\"masked\",\"IsExportAllow\":false,\"FieldName\":\"\",\"TableName\":\"\",\"FieldType\":\"\",\"ParentId\":\"32222\"}]'  
  IF (@Mode='I')/*This is for Insert usp_tbl_UA_PageFields Details */                                                  
 BEGIN   
      declare @RoleID int = 0  

	  if(CHARINDEX('SYS_',@RoleCode) = 1)
	     begin
		   select top 1 @RoleID = id from systemroles with(nolock) where SysRoleCode = @RoleCode     
		 end
      else
	     begin
		   select top 1 @RoleID = RoleId from [TBL_UA_RoleMaster] with(nolock) where RoleCode = @RoleCode 
		   --and ParentId = @ParentId     
		 end
      

  insert into tbl_UA_Mob_PageFieldMaskDetails(RoleId, PageCode, UserId, MaskJSON, CreatedDate, CreatedBy)                    
    values
	   (
	    --(select top 1 roleId from [dbo].[TBL_UA_RoleMaster] (nolock) where RoleCode=@RoleCode and Active=1)
		   @RoleID
		  ,@PageCode
		  ,@UserId
		  ,@MaskJSON
		  ,GETDATE(),         
		   @UserId
	    --@ParentId
	   )      
       
  Select 'Record Saved' Status   
 END /*End here for insert*/    
 else if(@Mode='S')/*This is for List of  Details */                                    
 begin   
 --declare @ParentId bigint=32222, @PageCode varchar(50)='PAG10002'  
DROP TABLE IF EXISTS #CombinedTable   
create table #CombinedTable  
(  
 [PageFieldId] int,   
 FieldName varchar(50),  
 PageCode varchar(50),   
 DisplayName varchar(50),  
 TableName varchar(50),  
 FieldType varchar(50)  
)  
  
insert into #CombinedTable (PageFieldId, PageCode, FieldName, DisplayName, TableName, FieldType) (Select PageFieldId, PageCode, FieldName, FieldName DisplayName, TableName, FieldType From tbl_UA_Mob_PageFields pg Where pg.PageCode = @PageCode)  
  
insert into #CombinedTable (PageFieldId, FieldName,PageCode, DisplayName, TableName, FieldType) SELECT [field_ID] as [PageFieldId], [fieldname] as FieldName, '' as PageCode,[fieldname] as DisplayName,'' as TableName,'' as FieldType from (SELECT [field_ID]
, [fieldname], (case datatype when 'd' then 'Date' when 'f' then 'Numeric' when 'v' then 'Text' when 'r' then 'Radio' when 'm' then 'Multiline'  when 's' then 'Select' when 'c' then 'Checkbox' when 'e' then 'Expression' end) as [datatype], [sequence] FROM
 [customfields](nolock) c   
      left join tbl_Formulas(nolock) f on c.formulaId = f.id where [c].[ParentID]= @ParentId and c.isActive <> 0 ) t  
      where t.datatype in ('Numeric', 'Text', 'Multiline') order by [sequence] asc   
select * from #CombinedTable  
               
                
 end /*End here for list*/     
 if(@Mode='T')/*This is for List to bind page dropdown Details */           
  begin                         
  select distinct PageCode, TableName From tbl_UA_Mob_PageFields where TableName != ''                     
 end /*End here for list*/  
 if(@Mode = 'SS')
   begin
        select count(id) over() as TotalRow, *   
         from (Select distinct  pfmd.ID,
	     '' as UserLogins
		,'' as UserIds
	    ,pfmd.ID as  PageHiddenFieldsId,
		--(select top 1 tupf.TableName from tbl_UA_PageFields(nolock) tupf where tupf.PageCode = PFMD.PageCode) TableName
		(select top 1 TUM.ModuleName from TBL_UA_ModuleMaster as TUM with(nolock) where TUM.ModuleCode = PFMD.PageCode ) TableName
	   /*
	   ,(
	     case when  isnull(tur.RoleCode, '') <> ''
	      then tur.RoleCode
		 else sysRole.SysRoleCode 
		  end
	   ) as RoleCode   
	   , 
       (
	    case when  isnull(tur.RoleName, '') <> ''
	       then tur.RoleName
		  else sysRole.rolename 
		 end
	   ) as RoleName,
	   */
	  ,tbl.RoleCode
	  ,tbl.RoleName 

	  -- MaskJSON,
	 ,(select STRING_AGG(FieldName, ', ')
	   from openJson(MaskJSON) with(FieldName nvarchar(200))
	  ) as FieldNames
	 ,PageCode,UserId from tbl_UA_Mob_PageFieldMaskDetails as PFMD with(nolock)
	   /*
	   left JOIN TBL_UA_RoleMaster tur on PFMD.RoleId = tur.RoleId                
       left join systemroles sysRole on PFMD.RoleId = sysRole.id 
	   */
	 left join 
	  (
        select tur.Rolecode as RoleCode ,tur.RoleId,tur.RoleName  from TBL_UA_RoleMaster as tur with(nolock) where tur.ParentId = @ParentId -- PFMD.RoleId = tur.RoleId
		 union 
		select sysRole.SysRoleCode as RoleCode ,sysRole.ID as RoleId , sysRole.rolename from systemroles as sysRole with(nolock) --where PFMD.RoleId = sysRole.id 
	  ) as tbl 
	  on PFMD.RoleId = tbl.RoleId
	   
	   Where PFMD.UserId = @ParentId --and tup.TableName != '' 
		     --and (isnull(tur.RoleId,0) <> 0 or isnull(sysRole.id,0) <> 0)  
			and (isnull(tbl.RoleId,0) <> 0)   

		) as t where isnull(t.RoleCode,'') != ''
		  and
		  (
			  PageCode like '%'+ isnull(@FilterText,'')+'%'                    
				or 
			  TableName like '%'+isnull(@FilterText,'')+'%'                    
				  --or UserIds like '%'+@FilterText+'%'                    
			  --or UserLogins like '%'+@FilterText+'%'                    
		  )
		 
       order by PageHiddenFieldsId desc                    
        OFFSET @OffsetValue Rows FETCH NEXT @PagingSize ROWS ONLY  
   end

 if(@Mode = 'U')
   begin
   DECLARE @json NVARCHAR(MAX) = ''   --'[{"HiddenType":"masked","IsExportAllow":true,"FieldName":"PersonName","TableName":"Lead","FieldType":"Main","ParentId":"34594"},{"HiddenType":"masked","IsExportAllow":false,"FieldName":"EmailID","TableName":"Lead","FieldType":"Main","ParentId":"34594"}]';
   Declare @PageHiddenFieldsId_U nvarchar(50) = '0'
   Declare @PageCode_U nvarchar(50) = ''
   Declare @PageFieldId_U nvarchar(50) = '0'
   Declare @RoleCode_U nvarchar(50) = '' 
   Declare @UserIds_U nvarchar(50) = '0' 
   declare @RoleID_U int = 0  

   select top 1 @PageCode_U = PageCode,  @json = MaskJSON, @RoleID_U = RoleId from tbl_UA_Mob_PageFieldMaskDetails with(nolock) where id = @MobMaskRowID 

     /*
	  if(CHARINDEX('SYS_',@RoleCode) = 1)
	     begin
		   select top 1 @RoleID = id from systemroles with(nolock) where SysRoleCode = @RoleCode     
		 end
      else
	     begin
		   select top 1 @RoleID = RoleId from [TBL_UA_RoleMaster] with(nolock) where RoleCode = @RoleCode 
		   --and ParentId = @ParentId     
		 end
     */

	 select top 1 @RoleCode_U = SysRoleCode from systemroles with(nolock) where id =  @RoleID_U  
     if(isnull(@RoleCode_U,'') = '' )
	   begin
	      select top 1 @RoleCode_U = RoleCode from TBL_UA_RoleMaster with(nolock) where RoleId =  @RoleID_U  
	   end


-- Create a table to store the parsed JSON values
  
   drop table if exists #ParsedData

   CREATE TABLE #ParsedData (
    HiddenType NVARCHAR(MAX),
    IsExportAllow BIT,
    DisplayName NVARCHAR(MAX),
    TableName NVARCHAR(MAX),
    FieldType NVARCHAR(MAX),
    ParentId BigINT,
    PageHiddenFieldsId nvarchar(50),
	PageCode nvarchar(50),
	PageFieldId nvarchar(50),
	RoleCode nvarchar(50),
	UserIds nvarchar(max)

   );

-- Parse the JSON and insert into the table
INSERT INTO #ParsedData (HiddenType, IsExportAllow, DisplayName, TableName, FieldType, ParentId
     ,PageHiddenFieldsId,PageCode,PageFieldId, RoleCode,UserIds)
SELECT HiddenType, IsExportAllow, FieldName, TableName, FieldType, ParentId,@PageHiddenFieldsId_U,@PageCode_U,@PageFieldId_U, @RoleCode_U,@UserIds_U
FROM OPENJSON(@json)
WITH (
    HiddenType NVARCHAR(MAX) '$.HiddenType',
    IsExportAllow BIT '$.IsExportAllow',
    FieldName NVARCHAR(MAX) '$.FieldName',
    TableName NVARCHAR(MAX) '$.TableName',
    FieldType NVARCHAR(MAX) '$.FieldType',
    ParentId INT '$.ParentId'
);

-- Select data from the table
   SELECT * FROM #ParsedData;
   drop table if exists #ParsedData

  end


  IF (@Mode='P')/*This is for update usp_tbl_UA_PageFields Details */                                                  
 BEGIN   
      declare @RoleID_P int = 0  

	  if(CHARINDEX('SYS_',@RoleCode) = 1)
	     begin
		   select top 1 @RoleID_P = id from systemroles with(nolock) where SysRoleCode = @RoleCode     
		 end
      else
	     begin
		   select top 1 @RoleID_P = RoleId from [TBL_UA_RoleMaster] with(nolock) where RoleCode = @RoleCode 
		   --and ParentId = @ParentId     
		 end
      
	 delete from  tbl_UA_Mob_PageFieldMaskDetails where id = @MobMaskRowID;

    insert into tbl_UA_Mob_PageFieldMaskDetails(RoleId, PageCode, UserId, MaskJSON, CreatedDate, CreatedBy)                    
        values
	     (
	    --(select top 1 roleId from [dbo].[TBL_UA_RoleMaster] (nolock) where RoleCode=@RoleCode and Active=1)
		   @RoleID_P
		  ,@PageCode
		  ,@ParentId
		  ,@MaskJSON
		  ,GETDATE(),         
		   @ParentId
	    --@ParentId
	    )      
       
  Select 'Record Saved' Status   
 END /*End here for update*/ 
  IF (@Mode='D')/*This is for Insert usp_tbl_UA_PageFields Details */                                                  
 BEGIN 
     delete from  tbl_UA_Mob_PageFieldMaskDetails where id = @MobMaskRowID;
	 Select 'Record Deleted' Status   
 End



 END TRY                                    
BEGIN CATCH                                    
                    
 DECLARE @ErrorMessage NVARCHAR(4000);                                 
 SELECT @ErrorMessage = ERROR_MESSAGE(); RAISERROR (@ErrorMessage, 16, 1);                                    
END CATCH 


GO

