   Procedure: [dbo].[usp_tbl_UA_ModuleMaster]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_tbl_UA_ModuleMaster]  -- 'sp'       
(      
 @Mode varchar(2),              
 @ModuleId bigint = 0,          
 @ModuleName varchar(100) = null,          
 @ModuleCode varchar(50) = null,          
 @ModuleDescription varchar(1000) = null,          
 @URL varchar(400) = null,          
 @ParentModuleId bigint = 0,          
 @Type varchar(10) = null,          
 @Sequence decimal(18,4) = 0,        
 @StaticPath varchar(400) = null,          
 @IsInternal bit =0,       
 @Active bit =1,          
 @UserId bigint = 0,          
 @ParentId bigint = 0 ,
 @Title varchar(950) = null, 
 @Tag varchar(950) = null          
)        
AS        
  SET NOCOUNT ON        
  DECLARE @activity VARCHAR(MAX) = ''    
 ,@action VARCHAR(1) = ''    
 ,@rowJson NVARCHAR(MAX) = ''    
  BEGIN TRY         
  IF (@Mode='I')/*This is for Insert TBL_UA_ModuleMaster Details */                      
 BEGIN                      
   IF NOT EXISTS(select 1 from TBL_UA_ModuleMaster(nolock) where ModuleName = @ModuleName and  ModuleDescription = @ModuleDescription)                       
     BEGIN           
  select @ParentId = ParentId from User_Detail(nolock) where ParentId = @UserId           
          
  select  top 1 @ModuleCode = ((Case When (@URL = '#' or @URL = '' or @URL Is null) Then 'MOD'          
  Else 'PAG'          
  End) + Cast((10000 + ModuleId + 1) as Varchar)) from TBL_UA_ModuleMaster(nolock) order by moduleId desc          
          
     insert into TBL_UA_ModuleMaster(ModuleName, ModuleCode, ModuleDescription, URL, Type, StaticPath, ParentModuleId, Active, CreatedBy, CreatedDate,           
  ModifiedBy, ModifiedDate, ParentId, [Sequence], IsInternal,Title,Tag)           
  values(@ModuleName, @ModuleCode, @ModuleDescription,           
  (Case When (@URL = '#' or @URL = '' or @URL Is null) Then '#'          
  Else @URL          
  End),          
  (Case When (@URL = '#' or @URL = '' or @URL Is null) Then 'Module'          
  When (@URL != '') then 'Page'          
  Else 'Page'          
  End),        
  @StaticPath, @ParentModuleId, 1, @UserId, GETDATE(), @UserId, GETDATE(), @ParentId, @Sequence, @IsInternal,@Title,@Tag)           
   --(Cast(@ParentModuleId as varchar(5))+'.001')        
  Select 'Record Saved' Status, scope_identity() ID, @ModuleCode Code      
  DECLARE @ID BIGINT;    
    
   SET @ID = scope_identity();   
     SET @rowJson = (    
     SELECT *    
     FROM TBL_UA_ModuleMaster    
     WHERE ModuleId = @ID    
     FOR JSON AUTO    
      ,INCLUDE_NULL_VALUES    
     )    
   SET @activity = 'Inst_modulemaster'    
   SET @action = 'I'    
     END           
   ELSE           
    BEGIN           
     SELECT -10      /* Use for TBL_UA_ModuleMaster Exist or not  */           
    END           
 END /*End here for insert*/           
          
 else if(@Mode='SP')/*This is for List of TBL_UA_ModuleMaster Details */           
 begin        
 select ModuleId, ModuleName, isnull((Case when tumm.ParentModuleId > 0 then (select tumm2.ModuleName from TBL_UA_ModuleMaster tumm2 where tumm2.ModuleId = tumm.ParentModuleId) + ' > ' + tumm.ModuleName     
   else ModuleName        
   End),'') ModuleNameTree, ModuleCode, ModuleDescription, URL, StaticPath, ParentModuleId, [Sequence], IsInternal,       
  Case when tumm.Active = 1 then 'Active'     
  else 'Inactive'         
  End         
 stActive, Active, isnull(CreatedBy,0) as CreatedBy, CreatedDate, isnull(ModifiedBy,0) as ModifiedBy, isnull(ModifiedDate,GETDATE()) as ModifiedDate          
  from TBL_UA_ModuleMaster(nolock) tumm          
              
 SET @rowJson = ''    
  SET @activity = 'View_ModuleMaster'    
  SET @action = 'S'    
 end /*End here for list*/                     
          
-- else if(@Mode='SA')/*This is for List of TBL_UA_ModuleMaster Details */           
-- begin           
          
--  select Case when tumm.Type = 'Module' Then CAST((CAST(tumm.ModuleId as varchar(10)) +'.'+ cast(tumm.ParentModuleId as varchar(10))) as numeric(18,3))          
--     else CAST((CAST(tumm.ParentModuleId as varchar(10)) +'.'+ cast(tumm.ModuleId as varchar(10))) as numeric(18,4))          
-- End DisplaySNO, [Sequence], ModuleName ModuleNameTree,          
--tumm.ModuleId, tumm.ModuleName, tupm.ModuleCode, tumm.ModuleDescription, [Add], Edit, [View],          
--                            [Delete], Search, Import, Export, MassUpdate, MassDelete, Download,          
--                            [Print], AddTask, AddAppointment, AddFollowup, AddNote, SendSms,          
--                            SendMail, tumm.Type, ParentModuleId, tupm.Active,           
--  Case when tupm.Active = 1 then 'Active'           
--  else 'Inactive'          
--  End         
--  stActive, User_Login, tupm.CreatedBy, tupm.CreatedDate, tupm.ModifiedBy, tupm.ModifiedDate           
--  from tbl_UA_PermissionMaster tupm       
--  inner join TBL_UA_ModuleMaster tumm on tumm.ModuleCode = tupm.ModuleCode          
--  inner join tbl_UA_EntityActionMappingMaster tuea on tuea.EntityActionMappingCode = tupm.EntityActionMappingCode          
--  inner join tbl_UA_EntitySpActionMappingMaster tueas on tueas.EntitySpActionMappingCode = tupm.EntitySpActionMappingCode          
--  inner join User_Detail ud on ud.User_Id = tupm.CreatedBy          
--  where tupm.ModuleCode =           
--  Case when @ModuleCode = 'All' Then tupm.ModuleCode          
--  else @ModuleCode          
--  End          
          
-- end /*End here for list*/                     
          
 else if(@Mode='SM')/*This is for List of TBL_UA_ModuleMaster Details */           
begin           
 select * from (          
  select ModuleId, ModuleName, ModuleCode, ModuleDescription, URL,          
  Case when ParentModuleId > 0 then (select ModuleName from TBL_UA_ModuleMaster tumm2 where tumm2.ModuleId = tumm.ParentModuleId) + ' > ' + ModuleName          
   else ModuleName          
   End ModuleNameTree,          
   isnull(StaticPath,'') StaticPath, ParentModuleId, [Sequence], IsInternal, tumm.Active,           
  Case when tumm.Active = 1 then 'Active'           
  else 'Inactive'          
  End          
  stActive, User_Login, tumm.CreatedBy, tumm.CreatedDate,           
  Case when tumm.ModifiedBy is null then tumm.CreatedBy          
  else tumm.CreatedBy          
  End ModifiedBy,          
  Case when tumm.ModifiedDate  is null then tumm.CreatedDate          
  else tumm.ModifiedDate          
  End ModifiedDate           
  from TBL_UA_ModuleMaster (nolock) tumm          
  inner join User_Detail ud on ud.User_Id = tumm.CreatedBy           
  Where tumm.type = 'Module'          
  ) t          
  Where t.ModuleNameTree !=''           
 order by t.ModuleName Asc     
 SET @rowJson = ''    
  SET @activity = 'View_ModuleMaster'    
  SET @action = 'S'    
 end /*End here for list*/                     
           
 else if(@Mode='S')/*This is for List of TBL_UA_ModuleMaster Details */           
 begin           
 Select tumm.ModuleId, tumm.ModuleName, tumm.ModuleCode, tumm.ModuleDescription, tumm.URL, tumm.StaticPath, tumm.ParentModuleId,           
  isnull(tumm2.ModuleName, '') ModuleParentName, tumm.IsInternal, tumm.Active,           
  Case when tumm.Active = 1 then 'Active'           
  else 'Inactive'          
  End          
  stActive, User_Login, tumm.Sequence, tumm.Type,         
  tumm.CreatedBy, tumm.CreatedDate, Case when tumm.ModifiedBy is null then tumm.CreatedBy          
  else tumm.ModifiedBy          
  End  ModifiedBy,          
  Case when tumm.ModifiedDate  is null then tumm.CreatedDate          
  else tumm.ModifiedDate          
  End ModifiedDate           
, tumm.ModifiedDate           
  from TBL_UA_ModuleMaster(nolock) tumm          
  inner join User_Detail(nolock) ud on ud.User_Id = tumm.CreatedBy          
 LEFT JOIN TBL_UA_ModuleMaster(nolock) tumm2 ON tumm2.ModuleId = tumm.ParentModuleId          
         SET @rowJson = ''    
  SET @activity = 'View_ModuleMaster'    
  SET @action = 'S'    
 end /*End here for list*/                     
 else if(@Mode='E')/*This is for TBL_UA_ModuleMaster Details */                      
   begin                      
  select ModuleId, ModuleName, ModuleCode, ModuleDescription, URL, Type, StaticPath, ParentModuleId, [Sequence], IsInternal,     
    Case when Active = 1 then 'Active'           
    else 'Inactive'           
    End           
   stActive,           
   Active, CreatedBy, CreatedDate, ModifiedBy, ModifiedDate, ParentId ,Title,Tag         
   from TBL_UA_ModuleMaster(nolock) where ModuleId = @ModuleId      
   SET @rowJson = ''    
  SET @activity = 'View_ModuleMaster'    
  SET @action = 'S'    
   end /*End here for details*/                      
          
 else if(@Mode='U')/*This is for TBL_UA_ModuleMaster Update Row */                      
   begin                      
  update TBL_UA_ModuleMaster set ModuleName = @ModuleName, ModuleDescription = @ModuleDescription,           
   URL = @URL, ParentModuleId = @ParentModuleId, Active = @Active, ModifiedBy = @UserId, [Sequence] = @Sequence, StaticPath = @StaticPath,      
   IsInternal = @IsInternal, ModifiedDate = GETDATE(),Title=@Title,Tag=@Tag where ModuleId = @ModuleId          
   Select 'Record Saved' Status, @ModuleId ID, @ModuleCode Code      
    SET @rowJson = (    
    SELECT *    
    FROM TBL_UA_ModuleMaster    
    WHERE ModuleId = @ModuleId    
    FOR JSON AUTO    
     ,INCLUDE_NULL_VALUES    
    )    
  SET @activity = 'Updt_ModuleMaster'    
  SET @action = 'U'    
   end /*End here for details*/                      
          
 else if(@Mode='D')/*This is for TBL_UA_ModuleMaster delete Row */                      
   begin           
 Update TBL_UA_ModuleMaster set Active = 0 where ModuleId = @ModuleId          
 Select 'Record Deleted' Status, @ModuleId ID      
   SET @rowJson = (    
    SELECT *    
    FROM TBL_UA_ModuleMaster    
    WHERE ModuleId = @ModuleId    
    FOR JSON AUTO    
     ,INCLUDE_NULL_VALUES    
    )    
  SET @activity = 'Delt_ModuleMaster'    
  SET @action = 'U'    
  
   end /*End here for details*/                      
           
 END TRY                      
BEGIN CATCH                      
                      
 DECLARE @ErrorMessage NVARCHAR(4000);                      
 SELECT @ErrorMessage = ERROR_MESSAGE();                      
 RAISERROR (@ErrorMessage, 16, 1);                      
END CATCH         
IF @rowJson IS NOT NULL    
BEGIN    
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId    
  ,@Activity_type = @activity    
  ,@ActionType = @action    
  ,@RowJson = @rowJson    
  ,@Table_name = 'TBL_UA_ModuleMaster'    
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_tbl_UA_ModuleMasterGetModuleCodeByURL]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_tbl_UA_ModuleMasterGetModuleCodeByURL]      
(
 @URL varchar(400)
)    
AS    
 SET NOCOUNT ON     
 BEGIN TRY     
  IF (@URL !='')
  BEGIN                  
DROP table if exists #Temp1
Create table #Temp1(Id int IDENTITY(1, 1), FieldName varchar(400))

insert into #Temp1 (FieldName)
SELECT value FROM STRING_SPLIT(@URL, '?')

DROP table if exists #TempResult
Create table #TempResult(Idss int IDENTITY(1, 1), ResultFieldName varchar(400))

if((select count(*) from #Temp1) = 2)
Begin
	DROP table if exists #TempQuerystring
	Create table #TempQuerystring(Ids int IDENTITY(1, 1), QFieldName varchar(400))

	Declare @sField varchar(100) = (select top 1 FieldName from #Temp1 order by Id Desc)

	insert into #TempQuerystring (QFieldName)
	SELECT value FROM STRING_SPLIT(@sField, '&')

	--select * from #TempQuerystring
	DECLARE @count INT;
	SET @count = (select count(*) from #TempQuerystring);

	--select @count
	Declare @lcount int = @count
	SET @count = 1;
	Declare @VPath varchar(400) = (select top 1 FieldName from #Temp1)
	WHILE @count <= @lcount
	BEGIN
	set @VPath = @VPath + (Case when @count = 1 then ('?'+ (select QFieldName from  #TempQuerystring where Ids = @count))
		else ('&'+ (select QFieldName from  #TempQuerystring where Ids = @count))
		end)
	insert into #TempResult(ResultFieldName)
	select @VPath
	
	SET @count = @count + 1;
	END
End
	insert into #TempResult(ResultFieldName)
	select top 1 FieldName from #Temp1 

--Select * from #TempResult

Declare @ModuleCode Varchar(30)

Declare @UrlCount int  = (select count (*) from #TempResult)
Declare @UrlCountother int = @UrlCount
set @UrlCount = 0
while @UrlCount <= @UrlCountother
Begin
 Select @ModuleCode = ModuleCode from TBL_UA_ModuleMaster(nolock) where Active = 1 and URL like '%' + (select ResultFieldName from #TempResult where Idss = @UrlCount) + ''

 SET @UrlCount = @UrlCount + 1;
End
select @ModuleCode
  END
 END TRY                  
BEGIN CATCH                  
                  
 DECLARE @ErrorMessage NVARCHAR(4000);                  
 SELECT @ErrorMessage = ERROR_MESSAGE();                  
 RAISERROR (@ErrorMessage, 16, 1);                  
END CATCH     



GO

/* ============================================================
   Procedure: [dbo].[usp_tbl_UA_PageFieldList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_tbl_UA_PageFieldList] --'M',46633,'PAG10031',0,10,null   --'M',34594,'PAG10002',0,10,null                          
(                                     
 -- declare
 @Mode varchar(2), --= 'M',                      
 @UserId varchar(2000) = null, --= '34594',  --= null,                      
 @PageCode varchar(50) = null, --= 'PAG10002',   --= null,                
 @OffsetValue int = 0,                                                                              
 @PagingSize int  = 10,                      
 @FilterText varchar(1000) = null    
)                      
AS                           
  SET NOCOUNT ON
  
       declare @ParentId bigint = 0
	   select @ParentId = ParentId from User_Detail with(nolock) where User_ID =  @UserId

  BEGIN TRY       
if(@Mode='M')/*This is for List of  Details */                                      
 begin     
   select distinct
      MPM.UserId
	, MPM.RoleId
	,(
	   case when isnull(MPM.RoleId,0) <> 0 and isnull(MPM.RoleId,0) <= 10
	      then sysRole.rolename
		  else tur.RoleName
	  	 end
	 ) as RoleName
	,(
	   case when isnull(MPM.RoleId,0) <> 0 and isnull(MPM.RoleId,0) <= 10
	      then sysRole.SysRoleCode
		  else tur.RoleCode
	  	 end
	 ) as RoleCode

	,MPM.MaskJSON
	,MPM.PageCode
	,MPM.CreatedDate
	,MPM.CreatedBy
	,MPM.ModifiedBy
	,MPM.ModifiedDate
   from [dbo].tbl_UA_Mob_PageFieldMaskDetails as MPM with(nolock)  
      left JOIN TBL_UA_RoleMaster as tur with(nolock) on MPM.RoleId = tur.RoleId                
      left join systemroles as sysRole with(nolock) on MPM.RoleId = sysRole.id 

	where dbo.ufn_getuserparentid( MPM.UserId) = @ParentId
	       -- (MPM.userId=@UserId or MPM.UserId = @ParentId) 
	
	and MPM.PageCode=@PageCode  and  isnull(MPM.RoleId,0) <> 0    
 
 end /*End here for list*/       
            
 END TRY                                      
BEGIN CATCH                                      
                      
 DECLARE @ErrorMessage NVARCHAR(4000);                                   
 SELECT @ErrorMessage = ERROR_MESSAGE();                                      
 RAISERROR (@ErrorMessage, 16, 1);                                      
END CATCH 


GO

/* ============================================================
   Procedure: [dbo].[usp_tbl_UA_PageFields]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_tbl_UA_PageFields]                      
(                                 
 
 @Mode varchar(2),                       
 @PageHiddenFieldsId bigint = 0,                  
 @PageFieldId bigint = 0,                  
 @ParentId bigint = 0,                  
 @UserIds varchar(2000) = null,                  
 @PageCode varchar(50) = null,                  
 @RoleCode varchar(50) = null,                  
 @OffsetValue int = 0,                                                                          
 @PagingSize int  = 10,                  
 @FilterText varchar(1000) = null,                  
 @dtpageHiddenFields nvarchar(max) = null                  
)                  
AS                       
  SET NOCOUNT ON  
  /*
 declare  @Mode varchar(2) = 'SS' ,                       
 @PageHiddenFieldsId bigint = 0,                  
 @PageFieldId bigint = 0,                  
 @ParentId bigint = 34594,                  
 @UserIds varchar(2000) = 34594, --null,                  
 @PageCode varchar(50) = null,                  
 @RoleCode varchar(50) = null,                  
 @OffsetValue int = 0,                                                                          
 @PagingSize int  = 10,                  
 @FilterText varchar(1000) = 'Task', --null,                  
 @dtpageHiddenFields nvarchar(max) = null 
 */

  BEGIN TRY                       
  IF (@Mode='I')/*This is for Insert usp_tbl_UA_PageFields Details */                                                
 BEGIN                  
--Declare @PageHiddenFieldsId bigint                   
 if Exists(select 1 from tbl_UA_PageHiddenFields where ParentId = @ParentId and PageCode = @PageCode and RoleCode = @RoleCode)                  
 Begin                  
 select @PageHiddenFieldsId = PageHiddenFieldsId from tbl_UA_PageHiddenFields where ParentId = @ParentId and PageCode = @PageCode and RoleCode = @RoleCode                  
                  
 --Declare @PageHiddenFieldsSettingsId bigint                  
                  
 --select top 1 @PageHiddenFieldsSettingsId = PageHiddenFieldsSettingsId from tbl_UA_PageHiddenFieldsSettings                   
 --where PageHiddenFieldsId = @PageHiddenFieldsId                   
                  
-- Delete tbl_UA_PageHiddenFieldsUserMapping where PageHiddenFieldsSettingsId = @PageHiddenFieldsSettingsId                   
                  
 Delete tbl_UA_PageHiddenFieldsSettings where PageHiddenFieldsId = @PageHiddenFieldsId                   
                  
 End                  
 else                  
 Begin                  
 insert into tbl_UA_PageHiddenFields(ParentId, PageCode, RoleCode, Active, CreatedBy, CreatedDate)                  
 values(@ParentId, @PageCode, @RoleCode, 1, @ParentId, GETDATE())                  
 set @PageHiddenFieldsId = @@IDENTITY                  
                  
 End                  
                  
DECLARE @myNewPKTable TABLE (PageHiddenFieldsSettingsId BIGINT)                  
                  
 insert into tbl_UA_PageHiddenFieldsSettings (PageHiddenFieldsId, PageFieldId, HiddenType, IsExportAllow, Active, CreatedBy, CreatedDate)                  
OUTPUT INSERTED.PageHiddenFieldsSettingsId INTO @myNewPKTable(PageHiddenFieldsSettingsId)                  
select @PageHiddenFieldsId, [PageFieldId], [HiddenType], [IsExportAllow], 1, @ParentId, GetDate() from openjson(@dtpageHiddenFields)                   
 with                  
 (                  
  [PageFieldId] bigint '$.PageFieldId',                  
  [HiddenType] varchar(50) '$.HiddenType',                  
  [IsExportAllow] bit '$.IsExportAllow'                  
 ) t                  
                  
 --CREATE TABLE #TableUser (UserId BIGINT)                  
 --INSERT INTO #TableUser (UserId)                  
 --Select Item from fu_SplitString(@UserIds, ',')                  
                  
 --insert into tbl_UA_PageHiddenFieldsUserMapping (PageHiddenFieldsSettingsId, UserId, Active, CreatedBy, CreatedDate)                  
 --select tb1.PageHiddenFieldsSettingsId, tb2.UserId, 1, @ParentId, GetDate() from #TableUser tb2                  
 --, @myNewPKTable tb1                  
                   
 --drop TABLE #TableUser                   
                  
 Select 'Record Saved' Status, @PageHiddenFieldsId ID                                    
                                    
 END /*End here for insert*/                                     
  IF (@Mode='P')/*This is for Insert usp_tbl_UA_PageFields Details */                                                
 BEGIN                  
          
  update tbl_UA_PageHiddenFields set PageCode = @PageCode , RoleCode = @RoleCode where PageHiddenFieldsId = @PageHiddenFieldsId                  
          
 select @PageHiddenFieldsId = PageHiddenFieldsId from tbl_UA_PageHiddenFields where ParentId = @ParentId and PageCode = @PageCode and RoleCode = @RoleCode                  
                 
                  
 Delete tbl_UA_PageHiddenFieldsSettings where PageHiddenFieldsId = @PageHiddenFieldsId                   
                  
 DECLARE @myNewPKTable2 TABLE (PageHiddenFieldsSettingsId BIGINT)                  
                  
 insert into tbl_UA_PageHiddenFieldsSettings (PageHiddenFieldsId, PageFieldId, HiddenType, IsExportAllow, Active, CreatedBy, CreatedDate)                  
OUTPUT INSERTED.PageHiddenFieldsSettingsId INTO @myNewPKTable2(PageHiddenFieldsSettingsId)                  
select @PageHiddenFieldsId, [PageFieldId], [HiddenType], [IsExportAllow], 1, @ParentId, GetDate() from openjson(@dtpageHiddenFields)                   
 with                  
 (                  
  [PageFieldId] bigint '$.PageFieldId',                  
  [HiddenType] varchar(50) '$.HiddenType',                  
  [IsExportAllow] bit '$.IsExportAllow'                  
 ) t                  
                  
 Select 'Record Saved' Status, @PageHiddenFieldsId ID                                    
                                    
 END /*End here for insert*/                                     
                  
 else if(@Mode='S')/*This is for List of  Details */                                  
 begin                
 if Not Exists(select 1 from tbl_UA_PageFields where ParentId = @parentID)                
 Begin                
 --Declare @parentID bigint = 33819                
                
insert tbl_UA_PageFields (PageCode, FieldName, DisplayName, TableName, CustomFieldId, FieldType, ParentId, IsActive)                
SELECT '' PageCode, [FieldName], [FieldName] DisplayName, '' TableName, field_ID, 'Custom', @parentID, 1                
 FROM [customfields](nolock) c                  
 left join tbl_Formulas(nolock) f on c.formulaId = f.id                  
 where [c].[ParentID]= @parentID and c.isActive <> 0 and datatype in ('f', 'v', 'm')                
End                
                
                
 select * from (                  
 Select PageFieldId, PageCode, FieldName, FieldName DisplayName, TableName, FieldType                  
  From tbl_UA_PageFields pg Where pg.PageCode = @PageCode                  
 UNION ALL                  
                  
 Select PageFieldId, PageCode, FieldName, FieldName DisplayName, TableName, FieldType                  
  From tbl_UA_PageFields pg Where pg.ParentId = @ParentId                  
 )t                  
              
 end /*End here for list*/                  
 else if(@Mode='E')/*This is for List of  Details */                                  
  begin                       
                  
   CREATE TABLE #TableUser1 (UserId BIGINT)                  
 INSERT INTO #TableUser1 (UserId)                  
 Select Item from fu_SplitString(@UserIds, ',')                  
 select * from (                 
 Select tupMain.PageFieldId, tupMain.PageCode, tupMain.FieldName, tupMain.FieldName DisplayName, tupMain.TableName,                   
  isnull(( select distinct tus.HiddenType From tbl_UA_PageHiddenFields tph                  
  INNER JOIN tbl_UA_PageHiddenFieldsSettings tus on tph.PageHiddenFieldsId = tus.PageHiddenFieldsId                  
  INNER JOIN tbl_UA_PageFields tup on tus.PageFieldId = tup.PageFieldId                  
  INNER JOIN tbl_UA_PageHiddenFieldsUserMapping tpm on tus.PageHiddenFieldsSettingsId = tpm.PageHiddenFieldsSettingsId                  
  Where tup.PageCode = @PageCode                  
  and tup.PageFieldId = tupMain.PageFieldId                  
  and tph.ParentId = @ParentId and tpm.UserId in (select UserId from #TableUser1)                  
  ), '' ) HiddenType,   isnull(( select distinct tus.IsExportAllow                  
  From tbl_UA_PageHiddenFields tph                
  INNER JOIN tbl_UA_PageHiddenFieldsSettings tus on tph.PageHiddenFieldsId = tus.PageHiddenFieldsId                  
  INNER JOIN tbl_UA_PageFields tup on tus.PageFieldId = tup.PageFieldId                  
  INNER JOIN tbl_UA_PageHiddenFieldsUserMapping tpm on tus.PageHiddenFieldsSettingsId = tpm.PageHiddenFieldsSettingsId                  
  Where tup.PageCode = @PageCode                  
  and tup.PageFieldId = tupMain.PageFieldId                  
  and tph.ParentId = @ParentId and tpm.UserId in (select UserId from #TableUser1)                  
  ), 0) IsExportAllow                   
  From tbl_UA_PageFields tupMain                  
  Where tupMain.PageCode = @PageCode                  
  Union    
   Select tupMain.PageFieldId, tupMain.PageCode, tupMain.FieldName, tupMain.DisplayName, tupMain.TableName,                   
   '' HiddenType, '' IsExportAllow                   
  From tbl_UA_PageFields tupMain                  
  Where tupMain.ParentId = @ParentId and tupMain.PageFieldId not in (Select tupMain1.PageFieldId     
  From tbl_UA_PageFields tupMain1                
  Where tupMain1.PageCode = @PageCode)    
  ) t    
  drop table #TableUser1                  
                  
 end /*End here for list*/                  
else if(@Mode='T')/*This is for List of TBL_UA_TeamMaster Details */         
  begin                       
  select distinct PageCode, TableName From tbl_UA_PageFields where TableName != ''                   
 end /*End here for list*/                  
 else if(@Mode='SO')/*This is for List of tbl_UA_PageHiddenFields Details */                                  
  begin                       
 select tup.TableName, tph.PageHiddenFieldsId, tph.PageCode, tup.FieldName, tup.DisplayName, tus.PageFieldId , isnull(STUFF((SELECT DISTINCT ', '+ udl1.User_Login from Tbl_UA_PageHiddenFieldsUserMapping urmm1                         
       inner join User_Detail udl1 on udl1.User_Id = urmm1.UserId                   
       where urmm1.PageHiddenFieldsSettingsId = tus.PageHiddenFieldsSettingsId FOR XML PATH('') ), 1, 1, ''),'')  UserIds,                   
  tus.HiddenType, tus.IsExportAllow                  
  From tbl_UA_PageHiddenFields tph                  
  INNER JOIN tbl_UA_PageHiddenFieldsSettings tus on tph.PageHiddenFieldsId = tus.PageHiddenFieldsId                  
  INNER JOIN tbl_UA_PageFields tup on tus.PageFieldId = tup.PageFieldId                  
  Where tph.ParentId = @ParentId                  
 end /*End here for list*/                  
 else if(@Mode='SS')/*This is for List of tbl_UA_PageHiddenFields Details */                                  
  begin                       
  select count(PageHiddenFieldsId) over() as TotalRow, * from (                  
  select distinct (select top 1 tupf.TableName from tbl_UA_PageFields(nolock) tupf where tupf.PageCode = tph.PageCode) TableName, tph.PageHiddenFieldsId, tph.PageCode,  
       (  
      case when  isnull(tph.RoleCode, '') <> ''  
       then tph.RoleCode  
   else sysRole.SysRoleCode   
    end  
    ) as RoleCode     
    ,   
       (  
       case when  isnull(tur.RoleName, '') <> ''  
         then tur.RoleName  
     else sysRole.rolename   
     end  
    ) as RoleName  
   ,                  
  isnull(STUFF((SELECT DISTINCT ', '+ udl1.User_Login                        
                      from Tbl_UA_PageHiddenFieldsUserMapping urmm1                         
       inner join User_Detail udl1 on udl1.User_Id = urmm1.UserId                   
       where urmm1.PageHiddenFieldsSettingsId = tus.PageHiddenFieldsSettingsId                   
    FOR XML PATH('') ), 1, 1, ''),'') UserLogins,                   
   isnull(STUFF((SELECT DISTINCT ', '+ Cast(udl1.User_Id as varchar(10))                   
                 from Tbl_UA_PageHiddenFieldsUserMapping urmm1                         
   inner join User_Detail udl1 on udl1.User_Id = urmm1.UserId                   
   where urmm1.PageHiddenFieldsSettingsId = tus.PageHiddenFieldsSettingsId                   
    FOR XML PATH('') ), 1, 1, ''),'') UserIds,                   
   isnull(STUFF((SELECT DISTINCT ', '+ pf.FieldName from tbl_UA_PageHiddenFieldsSettings phfs                  
   inner join tbl_UA_PageHiddenFields phs on phfs.PageHiddenFieldsId = phs.PageHiddenFieldsId                  
   inner join tbl_UA_PageFields pf on phfs.PageFieldId = pf.PageFieldId                   
    where phfs.PageHiddenFieldsId = tus.PageHiddenFieldsId                   
    FOR XML PATH('') ), 1, 1, ''),'') FieldNames                  
    From tbl_UA_PageHiddenFields tph                  
  INNER JOIN tbl_UA_PageHiddenFieldsSettings tus on tph.PageHiddenFieldsId = tus.PageHiddenFieldsId                  
  INNER JOIN tbl_UA_PageFields tup on tus.PageFieldId = tup.PageFieldId                  
  left JOIN TBL_UA_RoleMaster tur on tph.RoleCode = tur.RoleCode                  
  left join systemroles sysRole on tph.RoleCode = sysRole.SysRoleCode                    
  Where tph.ParentId = @ParentId and tup.TableName != '' ) t                  
   where
    (                     
      PageCode like '%'+isnull(@FilterText,'')+'%'                    
        or 
      TableName like '%'+isnull(@FilterText,'')+'%'                    
      --or UserIds like '%'+@FilterText+'%'                    
      --or UserLogins like '%'+isnull(@FilterText,'')+'%'                    
	)                     
  order by PageHiddenFieldsId desc                      
   OFFSET @OffsetValue Rows FETCH NEXT @PagingSize ROWS ONLY                  
  end /*End here for list*/                  
 else if(@Mode='U')/*This is for List of tbl_UA_PageHiddenFields Details */                                  
  begin                       
 Declare @TableName varchar(50)              
 set @TableName = isNull((select top 1  tup.TableName              
  From tbl_UA_PageHiddenFields tph                   
   INNER JOIN tbl_UA_PageHiddenFieldsSettings tus on tph.PageHiddenFieldsId = tus.PageHiddenFieldsId                  
   INNER JOIN tbl_UA_PageFields tup on tus.PageFieldId = tup.PageFieldId                  
   Where tph.ParentId = @ParentId and tph.PageHiddenFieldsId = @PageHiddenFieldsId  and tup.TableName != ''),'')              
              
select * from (              
 select tup.TableName, tph.PageHiddenFieldsId, tph.PageCode, tus.PageFieldId, tup.FieldName DisplayName, tph.RoleCode,                  
 tus.HiddenType, tus.IsExportAllow,                   
    isnull(STUFF((SELECT DISTINCT ', '+ Cast(udl1.User_Id as varchar(10))                   
      from Tbl_UA_PageHiddenFieldsUserMapping urmm1                         
     inner join User_Detail udl1 on udl1.User_Id = urmm1.UserId                   
     where urmm1.PageHiddenFieldsSettingsId = tus.PageHiddenFieldsSettingsId                   
     FOR XML PATH('') ), 1, 1, ''),'') UserIds                  
  From tbl_UA_PageHiddenFields tph                   
   INNER JOIN tbl_UA_PageHiddenFieldsSettings tus on tph.PageHiddenFieldsId = tus.PageHiddenFieldsId                  
   INNER JOIN tbl_UA_PageFields tup on tus.PageFieldId = tup.PageFieldId                  
   Where tph.ParentId = @ParentId and tph.PageHiddenFieldsId = @PageHiddenFieldsId and tph.Active = 1                   
              
Union              
              
select ss.TableName, 0 PageHiddenFieldsId, ss.PageCode, ss.PageFieldId, ss.FieldName DisplayName, '' RoleCode,                  
 'normal' HiddenType, 0 IsExportAllow, '' UserIds from [dbo].[tbl_UA_PageFields] ss where ss.TableName = @TableName              
 and ss.PageFieldId not in (select  tup.PageFieldId              
  From tbl_UA_PageHiddenFields tph                   
   INNER JOIN tbl_UA_PageHiddenFieldsSettings tus on tph.PageHiddenFieldsId = tus.PageHiddenFieldsId                  
   INNER JOIN tbl_UA_PageFields tup on tus.PageFieldId = tup.PageFieldId                  
   Where tph.ParentId = @ParentId and tph.PageHiddenFieldsId = @PageHiddenFieldsId                   
)              
Union        
  Select  '' TableName, 0 PageHiddenFieldsId, PageCode, PageFieldId, FieldName DisplayName, '' RoleCode, 'normal' HiddenType, 0 IsExportAllow, '' UeserIds        
  From tbl_UA_PageFields pg        
  Where pg.ParentId = @ParentId and pg.PageFieldId not in (select  tup.PageFieldId              
  From tbl_UA_PageHiddenFields tph                   
   INNER JOIN tbl_UA_PageHiddenFieldsSettings tus on tph.PageHiddenFieldsId = tus.PageHiddenFieldsId                  
   INNER JOIN tbl_UA_PageFields tup on tus.PageFieldId = tup.PageFieldId                  
   Where tph.ParentId = @ParentId and tph.PageHiddenFieldsId = @PageHiddenFieldsId                   
)        
        
)t              
   order by RoleCode desc, PageFieldId Asc              
              
 --select tup.TableName, tph.PageHiddenFieldsId, tph.PageCode, tus.PageFieldId, tup.DisplayName, tph.RoleCode,                  
 --tus.HiddenType, tus.IsExportAllow,                   
 --   isnull(STUFF((SELECT DISTINCT ', '+ Cast(udl1.User_Id as varchar(10))       
 --     from Tbl_UA_PageHiddenFieldsUserMapping urmm1                         
 --    inner join User_Detail udl1 on udl1.User_Id = urmm1.UserId                   
 --    where urmm1.PageHiddenFieldsSettingsId = tus.PageHiddenFieldsSettingsId                   
 --    FOR XML PATH('') ), 1, 1, ''),'') UserIds                  
 -- From tbl_UA_PageHiddenFields tph                   
 --  INNER JOIN tbl_UA_PageHiddenFieldsSettings tus on tph.PageHiddenFieldsId = tus.PageHiddenFieldsId                  
 --  INNER JOIN tbl_UA_PageFields tup on tus.PageFieldId = tup.PageFieldId                  
 --  Where tph.ParentId = @ParentId and tph.PageHiddenFieldsId = @PageHiddenFieldsId                   
 --  order by PageFieldId desc                      
                  
   end /*End here for list*/  
 Else IF (@Mode='D')/*This is for Insert usp_tbl_UA_PageFields Details */                                                
 BEGIN                  
 delete tbl_UA_PageHiddenFieldsSettings where PageHiddenFieldsId = @PageHiddenFieldsId  
  
 delete tbl_UA_PageHiddenFields where PageHiddenFieldsId = @PageHiddenFieldsId  
 select 'Deleted Successfully!'                 
 End                  
 END TRY                                  
BEGIN CATCH                                  
                  
 DECLARE @ErrorMessage NVARCHAR(4000);                               
 SELECT @ErrorMessage = ERROR_MESSAGE();                                  
 RAISERROR (@ErrorMessage, 16, 1);                                  
END CATCH 


GO

/* ============================================================
   Procedure: [dbo].[usp_tbl_UA_PageFields_Temp]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_tbl_UA_PageFields_Temp] --'SS', 0,0,34594,null,null,null,0,50,null,null
(
	@Mode VARCHAR(2)
	,@PageHiddenFieldsId BIGINT = 0
	,@PageFieldId BIGINT = 0
	,@ParentId BIGINT = 0
	,@UserIds VARCHAR(2000) = NULL
	,@PageCode VARCHAR(50) = NULL
	,@RoleCode VARCHAR(50) = NULL
	,@OffsetValue INT = 0
	,@PagingSize INT = 10
	,@FilterText VARCHAR(1000) = NULL
	,@dtpageHiddenFields NVARCHAR(max) = NULL
	)
AS
SET NOCOUNT ON

DECLARE @activity VARCHAR(MAX) = ''
	,@action VARCHAR(1) = ''
	,@rowJson NVARCHAR(MAX) = ''

BEGIN TRY
	IF (@Mode = 'I') /*This is for Insert usp_tbl_UA_PageFields Details */
	BEGIN
		--Declare @PageHiddenFieldsId bigint                 
		IF EXISTS (
				SELECT 1
				FROM tbl_UA_PageHiddenFields
				WHERE ParentId = @ParentId
					AND PageCode = @PageCode
					AND RoleCode = @RoleCode
				)
		BEGIN
			SELECT @PageHiddenFieldsId = PageHiddenFieldsId
			FROM tbl_UA_PageHiddenFields
			WHERE ParentId = @ParentId
				AND PageCode = @PageCode
				AND RoleCode = @RoleCode

			--Declare @PageHiddenFieldsSettingsId bigint                
			--select top 1 @PageHiddenFieldsSettingsId = PageHiddenFieldsSettingsId from tbl_UA_PageHiddenFieldsSettings                 
			--where PageHiddenFieldsId = @PageHiddenFieldsId                 
			-- Delete tbl_UA_PageHiddenFieldsUserMapping where PageHiddenFieldsSettingsId = @PageHiddenFieldsSettingsId                 
			DELETE tbl_UA_PageHiddenFieldsSettings
			WHERE PageHiddenFieldsId = @PageHiddenFieldsId
		END
		ELSE
		BEGIN
			INSERT INTO tbl_UA_PageHiddenFields (
				ParentId
				,PageCode
				,RoleCode
				,Active
				,CreatedBy
				,CreatedDate
				)
			VALUES (
				@ParentId
				,@PageCode
				,@RoleCode
				,1
				,@ParentId
				,GETDATE()
				)

			SET @PageHiddenFieldsId = @@IDENTITY
		END

		DECLARE @myNewPKTable TABLE (PageHiddenFieldsSettingsId BIGINT)

		INSERT INTO tbl_UA_PageHiddenFieldsSettings (
			PageHiddenFieldsId
			,PageFieldId
			,HiddenType
			,IsExportAllow
			,Active
			,CreatedBy
			,CreatedDate
			)
		OUTPUT INSERTED.PageHiddenFieldsSettingsId
		INTO @myNewPKTable(PageHiddenFieldsSettingsId)
		SELECT @PageHiddenFieldsId
			,[PageFieldId]
			,[HiddenType]
			,[IsExportAllow]
			,1
			,@ParentId
			,GetDate()
		FROM openjson(@dtpageHiddenFields) WITH (
				[PageFieldId] BIGINT '$.PageFieldId'
				,[HiddenType] VARCHAR(50) '$.HiddenType'
				,[IsExportAllow] BIT '$.IsExportAllow'
				) t

		--CREATE TABLE #TableUser (UserId BIGINT)                
		--INSERT INTO #TableUser (UserId)                
		--Select Item from fu_SplitString(@UserIds, ',')                
		--insert into tbl_UA_PageHiddenFieldsUserMapping (PageHiddenFieldsSettingsId, UserId, Active, CreatedBy, CreatedDate)                
		--select tb1.PageHiddenFieldsSettingsId, tb2.UserId, 1, @ParentId, GetDate() from #TableUser tb2                
		--, @myNewPKTable tb1                
		--drop TABLE #TableUser                 
		SELECT 'Record Saved' STATUS
			,@PageHiddenFieldsId ID

		SET @rowJson = (
				SELECT *
				FROM tbl_UA_PageHiddenFields WITH (NOLOCK)
				WHERE PageHiddenFieldsId = @PageHiddenFieldsId
				FOR JSON AUTO
					,INCLUDE_NULL_VALUES
				)
		SET @activity = 'Inst_usr_pgfldmsk'
		SET @action = 'I'
	END /*End here for insert*/

	IF (@Mode = 'P') /*This is for Insert usp_tbl_UA_PageFields Details */
	BEGIN
		UPDATE tbl_UA_PageHiddenFields
		SET PageCode = @PageCode
			,RoleCode = @RoleCode
		WHERE PageHiddenFieldsId = @PageHiddenFieldsId

		SELECT @PageHiddenFieldsId = PageHiddenFieldsId
		FROM tbl_UA_PageHiddenFields
		WHERE ParentId = @ParentId
			AND PageCode = @PageCode
			AND RoleCode = @RoleCode

		DELETE tbl_UA_PageHiddenFieldsSettings
		WHERE PageHiddenFieldsId = @PageHiddenFieldsId

		DECLARE @myNewPKTable2 TABLE (PageHiddenFieldsSettingsId BIGINT)

		INSERT INTO tbl_UA_PageHiddenFieldsSettings (
			PageHiddenFieldsId
			,PageFieldId
			,HiddenType
			,IsExportAllow
			,Active
			,CreatedBy
			,CreatedDate
			)
		OUTPUT INSERTED.PageHiddenFieldsSettingsId
		INTO @myNewPKTable2(PageHiddenFieldsSettingsId)
		SELECT @PageHiddenFieldsId
			,[PageFieldId]
			,[HiddenType]
			,[IsExportAllow]
			,1
			,@ParentId
			,GetDate()
		FROM openjson(@dtpageHiddenFields) WITH (
				[PageFieldId] BIGINT '$.PageFieldId'
				,[HiddenType] VARCHAR(50) '$.HiddenType'
				,[IsExportAllow] BIT '$.IsExportAllow'
				) t

		SELECT 'Record Saved' STATUS
			,@PageHiddenFieldsId ID

		SET @rowJson = (
				SELECT *
				FROM tbl_UA_PageHiddenFields WITH (NOLOCK)
				WHERE PageHiddenFieldsId = @PageHiddenFieldsId
				FOR JSON AUTO
					,INCLUDE_NULL_VALUES
				)
		SET @activity = 'Updt_usr_pgfldmsk'
		SET @action = 'U'
	END /*End here for insert*/
	ELSE IF (@Mode = 'S') /*This is for List of  Details */
	BEGIN
		IF NOT EXISTS (
				SELECT 1
				FROM tbl_UA_PageFields
				WHERE ParentId = @parentID
				)
		BEGIN
			--Declare @parentID bigint = 33819              
			INSERT tbl_UA_PageFields (
				PageCode
				,FieldName
				,DisplayName
				,TableName
				,CustomFieldId
				,FieldType
				,ParentId
				,IsActive
				)
			SELECT '' PageCode
				,[FieldName]
				,[FieldName] DisplayName
				,'' TableName
				,field_ID
				,'Custom'
				,@parentID
				,1
			FROM [customfields](NOLOCK) c
			LEFT JOIN tbl_Formulas(NOLOCK) f ON c.formulaId = f.id
			WHERE [c].[ParentID] = @parentID
				AND c.isActive <> 0
				AND datatype IN (
					'f'
					,'v'
					,'m'
					)
		END

		SELECT *
		FROM (
			SELECT PageFieldId
				,PageCode
				,FieldName
				,FieldName DisplayName
				,TableName
				,FieldType
			FROM tbl_UA_PageFields pg
			WHERE pg.PageCode = @PageCode
			
			UNION ALL
			
			SELECT PageFieldId
				,PageCode
				,FieldName
				,FieldName DisplayName
				,TableName
				,FieldType
			FROM tbl_UA_PageFields pg
			WHERE pg.ParentId = @ParentId
			) t

		SET @activity = 'Get Page Field Masking'
		SET @action = 'S'
	END /*End here for list*/
	ELSE IF (@Mode = 'E') /*This is for List of  Details */
	BEGIN
		CREATE TABLE #TableUser1 (UserId BIGINT)

		INSERT INTO #TableUser1 (UserId)
		SELECT Item
		FROM fu_SplitString(@UserIds, ',')

		SELECT *
		FROM (
			SELECT tupMain.PageFieldId
				,tupMain.PageCode
				,tupMain.FieldName
				,tupMain.FieldName DisplayName
				,tupMain.TableName
				,isnull((
						SELECT DISTINCT tus.HiddenType
						FROM tbl_UA_PageHiddenFields tph
						INNER JOIN tbl_UA_PageHiddenFieldsSettings tus ON tph.PageHiddenFieldsId = tus.PageHiddenFieldsId
						INNER JOIN tbl_UA_PageFields tup ON tus.PageFieldId = tup.PageFieldId
						INNER JOIN tbl_UA_PageHiddenFieldsUserMapping tpm ON tus.PageHiddenFieldsSettingsId = tpm.PageHiddenFieldsSettingsId
						WHERE tup.PageCode = @PageCode
							AND tup.PageFieldId = tupMain.PageFieldId
							AND tph.ParentId = @ParentId
							AND tpm.UserId IN (
								SELECT UserId
								FROM #TableUser1
								)
						), '') HiddenType
				,isnull((
						SELECT DISTINCT tus.IsExportAllow
						FROM tbl_UA_PageHiddenFields tph
						INNER JOIN tbl_UA_PageHiddenFieldsSettings tus ON tph.PageHiddenFieldsId = tus.PageHiddenFieldsId
						INNER JOIN tbl_UA_PageFields tup ON tus.PageFieldId = tup.PageFieldId
						INNER JOIN tbl_UA_PageHiddenFieldsUserMapping tpm ON tus.PageHiddenFieldsSettingsId = tpm.PageHiddenFieldsSettingsId
						WHERE tup.PageCode = @PageCode
							AND tup.PageFieldId = tupMain.PageFieldId
							AND tph.ParentId = @ParentId
							AND tpm.UserId IN (
								SELECT UserId
								FROM #TableUser1
								)
						), 0) IsExportAllow
			FROM tbl_UA_PageFields tupMain
			WHERE tupMain.PageCode = @PageCode
			
			UNION
			
			SELECT tupMain.PageFieldId
				,tupMain.PageCode
				,tupMain.FieldName
				,tupMain.DisplayName
				,tupMain.TableName
				,'' HiddenType
				,'' IsExportAllow
			FROM tbl_UA_PageFields tupMain
			WHERE tupMain.ParentId = @ParentId
				AND tupMain.PageFieldId NOT IN (
					SELECT tupMain1.PageFieldId
					FROM tbl_UA_PageFields tupMain1
					WHERE tupMain1.PageCode = @PageCode
					)
			) t

		DROP TABLE #TableUser1

		SET @activity = 'Get Page Field Masking'
		SET @action = 'S'
	END /*End here for list*/
	ELSE IF (@Mode = 'T') /*This is for List of TBL_UA_TeamMaster Details */
	BEGIN
		SELECT DISTINCT PageCode
			,TableName
		FROM tbl_UA_PageFields
		WHERE TableName != ''
	END /*End here for list*/
	ELSE IF (@Mode = 'SO') /*This is for List of tbl_UA_PageHiddenFields Details */
	BEGIN
		SELECT tup.TableName
			,tph.PageHiddenFieldsId
			,tph.PageCode
			,tup.FieldName
			,tup.DisplayName
			,tus.PageFieldId
			,isnull(STUFF((
						SELECT DISTINCT ', ' + udl1.User_Login
						FROM Tbl_UA_PageHiddenFieldsUserMapping urmm1
						INNER JOIN User_Detail udl1 ON udl1.User_Id = urmm1.UserId
						WHERE urmm1.PageHiddenFieldsSettingsId = tus.PageHiddenFieldsSettingsId
						FOR XML PATH('')
						), 1, 1, ''), '') UserIds
			,tus.HiddenType
			,tus.IsExportAllow
		FROM tbl_UA_PageHiddenFields tph
		INNER JOIN tbl_UA_PageHiddenFieldsSettings tus ON tph.PageHiddenFieldsId = tus.PageHiddenFieldsId
		INNER JOIN tbl_UA_PageFields tup ON tus.PageFieldId = tup.PageFieldId
		WHERE tph.ParentId = @ParentId
	END /*End here for list*/
	ELSE IF (@Mode = 'SS') /*This is for List of tbl_UA_PageHiddenFields Details */
	BEGIN
		SELECT count(PageHiddenFieldsId) OVER () AS TotalRow
			,*
		FROM (
			SELECT DISTINCT (
					SELECT TOP 1 tupf.TableName
					FROM tbl_UA_PageFields(NOLOCK) tupf
					WHERE tupf.PageCode = tph.PageCode
					) TableName
				,tph.PageHiddenFieldsId
				,tph.PageCode
				,tph.RoleCode
				,tur.RoleName
				,isnull(STUFF((
							SELECT DISTINCT ', ' + udl1.User_Login
							FROM Tbl_UA_PageHiddenFieldsUserMapping urmm1
							INNER JOIN User_Detail udl1 ON udl1.User_Id = urmm1.UserId
							WHERE urmm1.PageHiddenFieldsSettingsId = tus.PageHiddenFieldsSettingsId
							FOR XML PATH('')
							), 1, 1, ''), '') UserLogins
				,isnull(STUFF((
							SELECT DISTINCT ', ' + Cast(udl1.User_Id AS VARCHAR(10))
							FROM Tbl_UA_PageHiddenFieldsUserMapping urmm1
							INNER JOIN User_Detail udl1 ON udl1.User_Id = urmm1.UserId
							WHERE urmm1.PageHiddenFieldsSettingsId = tus.PageHiddenFieldsSettingsId
							FOR XML PATH('')
							), 1, 1, ''), '') UserIds
				,isnull(STUFF((
							SELECT DISTINCT ', ' + pf.FieldName
							FROM tbl_UA_PageHiddenFieldsSettings phfs
							INNER JOIN tbl_UA_PageHiddenFields phs ON phfs.PageHiddenFieldsId = phs.PageHiddenFieldsId
							INNER JOIN tbl_UA_PageFields pf ON phfs.PageFieldId = pf.PageFieldId
							WHERE phfs.PageHiddenFieldsId = tus.PageHiddenFieldsId
							FOR XML PATH('')
							), 1, 1, ''), '') FieldNames
			FROM tbl_UA_PageHiddenFields tph
			INNER JOIN tbl_UA_PageHiddenFieldsSettings tus ON tph.PageHiddenFieldsId = tus.PageHiddenFieldsId
			INNER JOIN tbl_UA_PageFields tup ON tus.PageFieldId = tup.PageFieldId
			inner join VW_SystemRole_RoleMaster tur on tph.RoleCode = tur.RoleCode    
 			--inner JOIN TBL_UA_RoleMaster tur ON tph.RoleCode = tur.RoleCode
			WHERE tph.ParentId = @ParentId
				AND tup.TableName != ''
			) t
		-- where (                   
		-- PageCode like '%'+@FilterText+'%'                  
		--or TableName like '%'+@FilterText+'%'                  
		--or UserIds like '%'+@FilterText+'%'                  
		--)                   
		ORDER BY PageHiddenFieldsId DESC OFFSET @OffsetValue Rows

		FETCH NEXT @PagingSize ROWS ONLY

		SET @activity = 'View_usr_pgfldmsk'
		SET @action = 'S'
	END /*End here for list*/
	ELSE IF (@Mode = 'U') /*This is for List of tbl_UA_PageHiddenFields Details */
	BEGIN
		DECLARE @TableName VARCHAR(50)

		SET @TableName = isNull((
					SELECT TOP 1 tup.TableName
					FROM tbl_UA_PageHiddenFields tph
					INNER JOIN tbl_UA_PageHiddenFieldsSettings tus ON tph.PageHiddenFieldsId = tus.PageHiddenFieldsId
					INNER JOIN tbl_UA_PageFields tup ON tus.PageFieldId = tup.PageFieldId
					WHERE tph.ParentId = @ParentId
						AND tph.PageHiddenFieldsId = @PageHiddenFieldsId
						AND tup.TableName != ''
					), '')

		SELECT *
		FROM (
			SELECT tup.TableName
				,tph.PageHiddenFieldsId
				,tph.PageCode
				,tus.PageFieldId
				,tup.FieldName DisplayName
				,tph.RoleCode
				,tus.HiddenType
				,tus.IsExportAllow
				,isnull(STUFF((
							SELECT DISTINCT ', ' + Cast(udl1.User_Id AS VARCHAR(10))
							FROM Tbl_UA_PageHiddenFieldsUserMapping urmm1
							INNER JOIN User_Detail udl1 ON udl1.User_Id = urmm1.UserId
							WHERE urmm1.PageHiddenFieldsSettingsId = tus.PageHiddenFieldsSettingsId
							FOR XML PATH('')
							), 1, 1, ''), '') UserIds
			FROM tbl_UA_PageHiddenFields tph
			INNER JOIN tbl_UA_PageHiddenFieldsSettings tus ON tph.PageHiddenFieldsId = tus.PageHiddenFieldsId
			INNER JOIN tbl_UA_PageFields tup ON tus.PageFieldId = tup.PageFieldId
			WHERE tph.ParentId = @ParentId
				AND tph.PageHiddenFieldsId = @PageHiddenFieldsId
			
			UNION
			
			SELECT ss.TableName
				,0 PageHiddenFieldsId
				,ss.PageCode
				,ss.PageFieldId
				,ss.FieldName DisplayName
				,'' RoleCode
				,'normal' HiddenType
				,0 IsExportAllow
				,'' UserIds
			FROM [dbo].[tbl_UA_PageFields] ss
			WHERE ss.TableName = @TableName
				AND ss.PageFieldId NOT IN (
					SELECT tup.PageFieldId
					FROM tbl_UA_PageHiddenFields tph
					INNER JOIN tbl_UA_PageHiddenFieldsSettings tus ON tph.PageHiddenFieldsId = tus.PageHiddenFieldsId
					INNER JOIN tbl_UA_PageFields tup ON tus.PageFieldId = tup.PageFieldId
					WHERE tph.ParentId = @ParentId
						AND tph.PageHiddenFieldsId = @PageHiddenFieldsId
					)
			
			UNION
			
			SELECT '' TableName
				,0 PageHiddenFieldsId
				,PageCode
				,PageFieldId
				,FieldName DisplayName
				,'' RoleCode
				,'normal' HiddenType
				,0 IsExportAllow
				,'' UeserIds
			FROM tbl_UA_PageFields pg
			WHERE pg.ParentId = @ParentId
				AND pg.PageFieldId NOT IN (
					SELECT tup.PageFieldId
					FROM tbl_UA_PageHiddenFields tph
					INNER JOIN tbl_UA_PageHiddenFieldsSettings tus ON tph.PageHiddenFieldsId = tus.PageHiddenFieldsId
					INNER JOIN tbl_UA_PageFields tup ON tus.PageFieldId = tup.PageFieldId
					WHERE tph.ParentId = @ParentId
						AND tph.PageHiddenFieldsId = @PageHiddenFieldsId
					)
			) t
		ORDER BY RoleCode DESC
			,PageFieldId ASC
			--select tup.TableName, tph.PageHiddenFieldsId, tph.PageCode, tus.PageFieldId, tup.DisplayName, tph.RoleCode,                
			--tus.HiddenType, tus.IsExportAllow,                 
			--   isnull(STUFF((SELECT DISTINCT ', '+ Cast(udl1.User_Id as varchar(10))     
			--     from Tbl_UA_PageHiddenFieldsUserMapping urmm1                       
			--    inner join User_Detail udl1 on udl1.User_Id = urmm1.UserId                 
			--    where urmm1.PageHiddenFieldsSettingsId = tus.PageHiddenFieldsSettingsId                 
			--    FOR XML PATH('') ), 1, 1, ''),'') UserIds                
			-- From tbl_UA_PageHiddenFields tph                 
			--  INNER JOIN tbl_UA_PageHiddenFieldsSettings tus on tph.PageHiddenFieldsId = tus.PageHiddenFieldsId                
			--  INNER JOIN tbl_UA_PageFields tup on tus.PageFieldId = tup.PageFieldId                
			--  Where tph.ParentId = @ParentId and tph.PageHiddenFieldsId = @PageHiddenFieldsId                 
			--  order by PageFieldId desc                    
	END /*End here for list*/
	ELSE IF (@Mode = 'D') /*This is for Insert usp_tbl_UA_PageFields Details */
	BEGIN
		SET @rowJson = (
				SELECT *
				FROM tbl_UA_PageHiddenFields WITH (NOLOCK)
				WHERE PageHiddenFieldsId = @PageHiddenFieldsId
				FOR JSON AUTO
					,INCLUDE_NULL_VALUES
				)

		DELETE tbl_UA_PageHiddenFieldsSettings
		WHERE PageHiddenFieldsId = @PageHiddenFieldsId

		DELETE tbl_UA_PageHiddenFields
		WHERE PageHiddenFieldsId = @PageHiddenFieldsId

		SELECT 'Deleted Successfully!'

		SET @activity = 'Delt_usr_pgfldmsk'
		SET @action = 'D'
	END
END TRY

BEGIN CATCH
	DECLARE @ErrorMessage NVARCHAR(4000);

	SELECT @ErrorMessage = ERROR_MESSAGE();

	RAISERROR (
			@ErrorMessage
			,16
			,1
			);
END CATCH

IF @rowJson IS NOT NULL
BEGIN
	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserIds
		,@Activity_type = @activity
		,@ActionType = @action
		,@RowJson = @rowJson
		,@Table_name = 'tbl_UA_PageHiddenFields'
END



GO

