-- inner join tbl_UA_PageFields pagfi on phs.PageFieldId = pagfi.PageFieldId          
-- where phf.UserId = @UserId and paghf.ParentId = @ParentId and paghf.PageCode = @PageCode          
   end /*End here for list*/          
 END TRY                          
