/* ============================================================
   Procedure: [dbo].[usp_tbl_UA_PermissionMaster]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_tbl_UA_PermissionMaster]
(           
 @Mode varchar(2), 
 @PermissionId bigint = 0,
 @PermissionCode varchar(50) = null,
 @ModuleCode varchar(50) = null,
 @EntityActionMappingCode varchar(50) = null,
 @EntitySpActionMappingCode varchar(50) = null,
 @dtEntityActionAllMappingMaster nvarchar(max) = null,
 @UserId bigint =0,
 @Active bit = 0,
 @ParentId bigint =0
) 
AS 
  SET NOCOUNT ON 
  BEGIN TRY 
  IF (@Mode='I')/*This is for Insert TBL_UA_TeamMaster Details */            
 BEGIN 
 --select @EntityActionMappingCode = dbo.GetEntityActionMappingCode(@dtEntityActionAllMappingMaster)
 --select @EntitySpActionMappingCode = dbo.GetEntitySpActionMappingCode(@dtEntityActionAllMappingMaster)

 SELECT @ParentId = ParentID FROM User_Detail where User_ID = @UserId;  

 delete TBL_UA_PermissionMaster where ModuleCode in (select ModuleCode from openjson(@dtEntityActionAllMappingMaster)
	with
	(ModuleCode varchar(50) '$.ModuleCode'
	) ttt
	)

 insert into TBL_UA_PermissionMaster (PermissionCode, ModuleCode, EntityActionMappingCode, EntitySpActionMappingCode, 
 ParentId, Active, CreatedBy, CreatedDate, ModifiedBy, ModifiedDate)

select isnull((ModuleCode +'_'+ isnull(dbo.GetEntityActionMappingCode(@dtEntityActionAllMappingMaster),'') 
+'_'+ isnull(dbo.GetEntitySpActionMappingCode(@dtEntityActionAllMappingMaster),'')),'Per001'), ModuleCode, 
dbo.GetEntityActionMappingCode(@dtEntityActionAllMappingMaster), 
 dbo.GetEntitySpActionMappingCode(@dtEntityActionAllMappingMaster), @ParentId, 1, @UserId, GetDate(), @UserId, GetDate() from openjson(@dtEntityActionAllMappingMaster)
with
(
	ModuleCode varchar(50) '$.ModuleCode',
	[Add] bit '$.Add',
	Edit bit '$.Edit',
	[View] bit '$.View',
	[Delete] bit '$.Delete',
	Search bit '$.Search',
	Import bit '$.Import',
	Export bit '$.Export',
	MassUpdate bit '$.MassUpdate',
	MassDelete bit '$.MassDelete',
	Download bit '$.Download',
	[Print] bit '$.Print',
	AddTask bit '$.AddTask',
	AddAppointment bit '$.AddAppointment',
	AddFollowup bit '$.AddFollowup',
	AddNote bit '$.AddNote',
	SendSms bit '$.SendSms',
	SendMail bit '$.SendMail' 
) t 

 Select 'Record Saved' Status, @@Identity ID, @PermissionCode Code 

 END /*End here for insert*/ 
 
else if(@Mode='S')/*This is for List of TBL_UA_TeamMaster Details */ 
 begin 

 select @ParentId = ParentId from User_Detail where User_Id =  @UserId

 select PermissionId, PermissionCode, 
 tumm.ModuleName,
 tupm.ModuleCode, tupm.EntityActionMappingCode, tupm.EntitySpActionMappingCode, case when tupm.Active = 1 then 'Active' 
  when tupm.Active = 2 then 'Deleted' 
   else 'InActive' 
  End stActive, 
  tupm.Active, tuud.User_Login Created_User,
  tupm.CreatedBy, tupm.CreatedDate, isnull(tupm.ModifiedBy, 0) ModifiedBy, 
  case when tupm.ModifiedDate is Null then tupm.CreatedDate 
  else tupm.ModifiedDate 
  End ModifiedDate from TBL_UA_PermissionMaster tupm
  inner join tbl_UA_ModuleMaster tumm on tumm.ModuleCode = tupm.ModuleCode
  inner join TBL_UA_EntityActionMappingMaster tuem on tuem.EntityActionMappingCode = tupm.EntityActionMappingCode
  inner join TBL_UA_EntitySpActionMappingMaster tumms on tumms.EntitySpActionMappingCode = tupm.EntitySpActionMappingCode
  inner join User_Detail tuud on tuud.User_Id = tupm.CreatedBy
   where tupm.ParentId = @ParentId 
 end /*End here for list*/ 

 else if(@Mode='E')/*This is for TBL_UA_TeamMaster Details */            
   begin 
 
 --Declare @ModuleCode varchar(50) 
 --Select @ModuleCode = ModuleCode from TBL_UA_PermissionMaster tutm where PermissionId = @PermissionId 

 Declare @MType varchar(10) = 'Module' 
 select @MType = Case when URL = '#' Then 'Module' 
 else 'Page' 
 End from TBL_UA_ModuleMaster where ModuleCode = @ModuleCode 

 Select @MType

 Select DisplaySNO = Case when ParentModuleId = 0 Then Cast((Cast(ModuleId as varchar(10)) + '.' + Cast(ParentModuleId as varchar(10))) 
	as numeric(18,3))
    Else Cast((Cast(ParentModuleId as varchar(10)) +'.'+ Cast(ModuleId as varchar(10))) as numeric(18,2))  
     End, ModuleId, ModuleName, pm.ModuleCode, ModuleDescription, PermissionId, PermissionCode, pm.EntityActionMappingCode, 
 pm.EntitySpActionMappingCode, mm.Type,
  eam.[Add], eam.Edit, eam.[View], eam.[Delete], eam.Search, eam.Import, eam.Export, eam.MassUpdate, eam.MassDelete, 
  eams.Download, eams.[Print], eams.AddTask, eams.AddAppointment, eams.AddFollowup, eams.AddNote, eams.SendSms, eams.SendMail 
   from TBL_UA_ModuleMaster mm 
	 inner join TBL_UA_PermissionMaster pm on pm.ModuleCode = mm.ModuleCode 
	 inner join TBL_UA_EntityActionMappingMaster eam on eam.EntityActionMappingCode = pm.EntityActionMappingCode 
	 inner join TBL_UA_EntitySpActionMappingMaster eams on eams.EntitySpActionMappingCode = pm.EntitySpActionMappingCode 
	 where pm.ModuleCode = @ModuleCode
 
  end /*End here for details*/ 

  else if(@Mode='D')/*This is for TBL_UA_TeamMaster delete Row */           
   begin 
  --Update TBL_UA_PermissionMaster set Active = 2 where PermissionId = @PermissionId 
  delete TBL_UA_PermissionMaster where PermissionId = @PermissionId 
  Select 'Record Delete' Status, @PermissionId ID 
   end /*End here for details*/            

  else if(@Mode='SD')/*This is for Select ModulePermission List by UserId Row */          
   begin 
	SELECT @ParentId = ParentID FROM User_Detail where User_ID = @UserId;  

	Select DisplaySNO = Case when ParentModuleId = 0 Then Cast((Cast(ModuleId as varchar(10)) + '.' + Cast(ParentModuleId as varchar(10))) 
	as numeric(18,3))
    Else Cast((Cast(ParentModuleId as varchar(10)) +'.'+ Cast(ModuleId as varchar(10))) as numeric(18,2))  
     End, PermissionId, PermissionCode, tumm.ModuleId, tupm.ModuleCode, ModuleName, 
	ModuleDescription, 
	tupm.EntityActionMappingCode, tupm.EntitySpActionMappingCode, ParentId 
	 from TBL_UA_PermissionMaster tupm
	 inner join TBL_UA_ModuleMaster tumm on tumm.ModuleCode = tupm.ModuleCode 
	 inner join TBL_UA_EntityActionMappingMaster tuem on tuem.EntityActionMappingCode = tupm.EntityActionMappingCode
	 inner join TBL_UA_EntitySpActionMappingMaster tumms on tumms.EntitySpActionMappingCode = tupm.EntitySpActionMappingCode
	 
	 where ParentId = @ParentId --and ModuleCode = @ModuleCode
   end /*End here for details*/            

  else if(@Mode='PD')/*This is for Select Permission Code by ModuleCode Row */          
   begin 
	SELECT @ParentId = ParentID FROM User_Detail where User_ID = @UserId;  

	Select PermissionId, PermissionCode, tumm.ModuleId, tupm.ModuleCode, ModuleName, 
	ModuleDescription, EntityActionMappingCode, EntitySpActionMappingCode, ParentId, [Type] 
	 from TBL_UA_PermissionMaster tupm
	 inner join  TBL_UA_ModuleMaster tumm on tumm.ModuleCode = tupm.ModuleCode 
	 where tupm.ParentId = @ParentId and 
	  tupm.ModuleCode = 
	  Case When @ModuleCode = 'All' Then tupm.ModuleCode 
	  Else @ModuleCode
	  End 
   end /*End here for details*/            

 END TRY            
BEGIN CATCH            
 
 DECLARE @ErrorMessage NVARCHAR(4000);            
 SELECT @ErrorMessage = ERROR_MESSAGE();            
 RAISERROR (@ErrorMessage, 16, 1);            
END CATCH 



GO

/* ============================================================
   Procedure: [dbo].[usp_tbl_UA_PermissionScopeMappingMaster]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_tbl_UA_PermissionScopeMappingMaster]
(
 @Mode varchar(2),
 @PermissionScopeMappingId bigint = 0,
 @PermissionScopeMappingCode varchar (50) = null,
 @PermissionCode varchar (50) = null,
 @ModuleCode varchar (50) = null,
 @dtPermissionScopeMappingList nvarchar(max) = null,
 @Active bit = 0,
 @UserId bigint = 0,
 @LogUserId bigint = 0,
 @ParentId bigint = 0
)          
AS 
  SET NOCOUNT ON 
  BEGIN TRY 
  IF (@Mode='I')/*This is for Insert TBL_UA_TeamScopeMappingMaster Details */            
 BEGIN         

select @ParentId = ParentId from User_Detail where User_Id =  @UserId

delete TBL_UA_PermissionScopeMappingMaster where ParentId = @ParentId and PermissionCode in 
(Select PermissionCode from openjson(@dtPermissionScopeMappingList)
with
(
	PermissionCode varchar(50) '$.PermissionCode'
) t2)

insert into TBL_UA_PermissionScopeMappingMaster(PermissionScopeMappingCode, PermissionCode, ScopeCode, TeamCode, UserId, ParentId, Active,
CreatedBy, CreatedDate, ModifiedBy, ModifiedDate) 

Select case when ScopeCode = 'GLO' Then PermissionCode + '_' + ScopeCode
when ScopeCode = 'TEA' Then PermissionCode + '_' + ScopeCode + '_' + TeamCode
--when ScopeCode = 'USE' Then PermissionCode + '_' + ScopeCode + '_' + UserId
else PermissionCode + '_' + ScopeCode
End, PermissionCode, ScopeCode, TeamCode, UserId, @ParentId, @Active, @UserId, GetDate(), 
 @UserId, GetDate() 
 from openjson(@dtPermissionScopeMappingList)
with
(
	PermissionCode varchar(50) '$.PermissionCode',
	[ScopeCode] varchar(50) '$.ScopeCode',
	TeamCode varchar(50) '$.TeamCode',
	[UserId] bigint '$.UserId'
) t 
Select 'Record Saved' Status
 
 END /*End here for insert*/            
          
  else if(@Mode='S')/*This is for List of tbl_UA_PermissonScopeMappingMaster Details */            
 begin 
  select @ParentId = ParentId from User_Detail where User_Id =  @UserId

  select PermissionScopeMappingId, PermissionScopeMappingCode, 
  tumm.ModuleName, tups.PermissionCode, tusm.ScopeName, tutm.TeamName, tuum.User_Login UserName, tuud.User_Login, 
  tups.TeamCode, tups.ScopeCode, isnull(UserId, 0) UserId, case when tups.Active = 1 then 'Active' 
  else 'InActive'
  End stActive,
  tups.Active, tups.CreatedBy, tups.CreatedDate, isnull(tups.ModifiedBy, 0) ModifiedBy, 
  case when tups.ModifiedDate is Null then tups.CreatedDate
  else tups.ModifiedDate 
  End ModifiedDate
  from tbl_UA_PermissionScopeMappingMaster tups
  inner join tbl_UA_PermissionMaster tupm on tupm.PermissionCode = tups.PermissionCode
  inner join tbl_UA_ModuleMaster tumm on tumm.ModuleCode = tupm.ModuleCode
  inner join TBL_UA_ScopeMaster tusm on tusm.ScopeCode = tups.ScopeCode
  left join TBL_UA_TeamMaster tutm on tutm.TeamCode = tups.TeamCode
  left join User_Detail tuum on tuum.User_Id = tups.UserId
  inner join User_Detail tuud on tuud.User_Id = tups.CreatedBy
  
  where tups.ParentId = @ParentId end /*End here for list*/           
 
 else if(@Mode='E')/*This is for tbl_UA_PermissonScopeMappingMaster Details */            
   begin            
  select tuom.ModuleCode, tumm.ModuleName, PermissionScopeMappingId, PermissionScopeMappingCode, tuos.PermissionCode, 
  TeamCode, ScopeCode, UserId, 
  case when tuos.Active = 1 then 'Active'
  else 'InActive'
  End stActive,
  tuos.Active, tuos.CreatedBy, tuos.CreatedDate, isnull(tuos.ModifiedBy, 0) ModifiedBy, 
  case when tuos.ModifiedDate is Null then tuos.CreatedDate
  else tuos.ModifiedDate 
  End ModifiedDate
  from tbl_UA_PermissionScopeMappingMaster tuos
  inner join tbl_UA_PermissionMaster tuom on tuom.PermissionCode = tuos.PermissionCode 
  inner join tbl_UA_ModuleMaster tumm on tumm.ModuleCode = tuom.ModuleCode
  Where PermissionScopeMappingId = @PermissionScopeMappingId
   end /*End here for details*/            
          
 else if(@Mode='U')/*This is for tbl_UA_PermissonScopeMappingMaster Update Row */            
   begin            
	 --set @PermissionScopeMappingCode = @TeamCode + '_' + @ScopeCode
  --update tbl_UA_PermissonScopeMappingMaster set PermissionScopeMappingCode = @PermissionScopeMappingCode, TeamCode=@TeamCode, ScopeCode = @ScopeCode, 
  --UserId = @UserId, Active = @Active, ModifiedBy = @LogUserId, ModifiedDate = GETDATE() where PermissionScopeMappingId = @PermissionScopeMappingId
	 Select 'Record Updated' Status, @@IDENTITY ID, @PermissionScopeMappingCode Code
   end /*End here for details*/            
          
  else if(@Mode='D')/*This is for tbl_UA_PermissonScopeMappingMaster delete Row */            
   begin 

  delete tbl_UA_PermissionScopeMappingMaster where PermissionScopeMappingId = @PermissionScopeMappingId
	 Select 'Record Deleted' Status, @PermissionScopeMappingId ID
   end /*End here for details*/            
 END TRY            
BEGIN CATCH            
            
 DECLARE @ErrorMessage NVARCHAR(4000);            
 SELECT @ErrorMessage = ERROR_MESSAGE();            
 RAISERROR (@ErrorMessage, 16, 1);            
END CATCH 



GO

/* ============================================================
   Procedure: [dbo].[usp_tbl_UA_PermissionUserRoleModuleMappingMaster]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_tbl_UA_PermissionUserRoleModuleMappingMaster]
(
 @Mode varchar(2),
 @RolePermissionMappingId bigint = 0,
 @RolePermissionMappingCode	varchar(50),
 @PermissionCode varchar(50),
 @UserRoleMappingCode varchar(50),
 @Active bit = 0,
 @UserId bigint = 0
)          
AS          
  SET NOCOUNT ON           
  BEGIN TRY            
