/* ============================================================
   Procedure: [dbo].[usp_tbl_UA_RoleMaster]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


---------------------------------------------------------------------------------------------------
 CREATE   PROCEDURE [dbo].[usp_tbl_UA_RoleMaster] (        
 @Mode VARCHAR(2)        
 ,@RoleId BIGINT = 0        
 ,@RoleName VARCHAR(50) = NULL        
 ,@RoleCode VARCHAR(50) = NULL        
 ,@Active BIT = 0        
 ,@UserId BIGINT = 0        
 ,@ParentId BIGINT = 0        
 ,@fromdate DATETIME = NULL        
 ,@todate DATETIME = NULL        
 ,@status CHAR(1) = NULL        
 )        
AS        
SET NOCOUNT ON        
        
DECLARE @activity VARCHAR(MAX) = ''        
 ,@action VARCHAR(1) = ''        
 ,@rowJson NVARCHAR(MAX) = ''        
        
BEGIN TRY        
 IF (@Mode = 'I') /*This is for Insert TBL_UA_TeamMaster Details */        
 BEGIN        
  SELECT @ParentId = ParentId        
  FROM User_detail WITH (NOLOCK)        
  WHERE User_Id = @UserId        
        
  IF (@RoleCode = '')        
  BEGIN        
   SET @RoleCode = 'ROLE' + Cast((        
      1000 + isnull((        
        SELECT Max(RoleId)        
        FROM TBL_UA_RoleMaster WITH (NOLOCK)        
        ), 1)        
      ) AS VARCHAR(10))        
  END        
        
  IF (        
    ('Admin' = @RoleName)        
    OR ('User' = @RoleName)        
    OR ('Guest' = @RoleName)        
    )        
  BEGIN        
   SELECT 'Record Already Exist' STATUS        
  END        
  ELSE IF NOT EXISTS (        
    SELECT 1        
    FROM TBL_UA_RoleMaster WITH (NOLOCK)        
    WHERE (        
      RoleName = @RoleName        
      AND IsInternal = 1        
      )        
     OR (        
      RoleName = @RoleName        
      AND ParentId = @ParentId        
      )        
    )        
  BEGIN        
   INSERT INTO TBL_UA_RoleMaster (        
    RoleName        
    ,RoleCode        
    ,ParentId        
    ,Active        
    ,CreatedBy        
    ,CreatedDate        
    )        
   VALUES (        
    @RoleName        
    ,@RoleCode        
    ,@ParentId        
    ,@Active        
    ,@UserId        
    ,GETDATE()        
    )        
        
   DECLARE @ID BIGINT;        
        
   SET @ID = @@IDENTITY;        
        
   SELECT 'Record Saved' STATUS        
    ,@ID        
    ,@RoleCode Code        
        
   SET @rowJson = (        
     SELECT *        
     FROM TBL_UA_RoleMaster        
     WHERE RoleId = @ID        
     FOR JSON AUTO        
      ,INCLUDE_NULL_VALUES        
     )        
   SET @activity = 'Inst_usrrole'        
   SET @action = 'I'        
  END        
  ELSE        
  BEGIN        
   SELECT 'Record Already Exist' STATUS        
  END        
 END /*End here for insert*/        
 ELSE IF (@Mode = 'S') /*This is for List of TBL_UA_TeamMaster Details */        
 BEGIN        
  SELECT @ParentId = ParentId        
  FROM User_detail WITH (NOLOCK)        
  WHERE User_Id = @UserId        
        
  DECLARE @TimeZoneName NVARCHAR(255) = (        
    SELECT TimeZone        
    FROM User_Detail(NOLOCK)        
    WHERE User_ID = @Userid        
    )        
        
  SELECT *        
  FROM (        
   SELECT Id RoleId        
    ,RoleName        
    ,SysRoleCode RoleCode        
    ,CASE         
     WHEN IsActive = 1        
      THEN 'Active'        
     ELSE 'InActive'        
     END stActive        
    ,IsActive Active        
    ,'' CreatedUser        
    ,335 CreatedBy        
    ,dbo.fn_ConvertDateTime(getDate(), @TimeZoneName, 0) CreatedDate        
    ,335 ModifiedBy        
    ,getDate() ModifiedDate        
    ,0 IsInternal        
    ,0 PeerView        
   FROM systemRoles tm WITH (NOLOCK)        
   WHERE  
       isnull(tm.isactive,0) = 1 and       
   Id IN (        
     4        
     ,9        
     ,10        
     )        
           
   UNION ALL        
           
   SELECT RoleId        
    ,RoleName        
    ,RoleCode        
    ,CASE         
     WHEN tm.Active = 1        
      THEN 'Active'        
     ELSE 'InActive'        
     END stActive        
    ,Active        
    ,ud.User_Login CreatedUser        
    ,tm.CreatedBy        
    ,dbo.fn_ConvertDateTime(tm.CreatedDate, @TimeZoneName, 0) AS CreatedDate        
    ,isnull(tm.ModifiedBy, 0) ModifiedBy        
    ,CASE         
     WHEN tm.ModifiedDate IS NULL        
      THEN dbo.fn_ConvertDateTime(tm.CreatedDate, @TimeZoneName, 0)        
     ELSE dbo.fn_ConvertDateTime(tm.ModifiedDate, @TimeZoneName, 0)        
     END ModifiedDate        
    ,IsInternal    
	,0 PeerView
   FROM TBL_UA_RoleMaster tm WITH (NOLOCK)        
   INNER JOIN User_detail ud ON ud.User_Id = tm.CreatedBy        
   WHERE  
      isnull(tm.Active,0) = 1  
      and   
   (        
     tm.RoleId IN (        
      4        
      ,9        
      )        
     AND tm.IsInternal = 1        
     )        
    OR (        
     tm.IsInternal = 0        
     AND tm.ParentId = @ParentId        
     and isnull(tm.Active,0) = 1  
  )        
   ) t        
  WHERE  
    isnull(t.Active,0) = 1   
  and   
    (        
    @RoleName IS NULL        
    OR t.RoleName LIKE '%' + @RoleName + '%'        
    )        
   AND (        
    @status IS NULL        
    OR t.Active = @status        
    )        
   AND (        
    @fromdate IS NULL        
    OR t.CreatedDate > @fromdate        
    )        
   AND (        
    @todate IS NULL        
    OR t.CreatedDate < @todate        
    )        
  SET @rowJson = ''          
  SET @activity = 'View_usrrole'        
  SET @action = 'S'        
 END /*End here for list ,10*/        
 ELSE IF (@Mode = 'E') /*This is for TBL_UA_TeamMaster Details */        
 BEGIN        
  SELECT RoleId        
   ,RoleName        
   ,RoleCode        
   ,CASE         
    WHEN Active = 1        
     THEN 'Active'        
    ELSE 'InActive'        
    END stActive        
   ,Active        
   ,CreatedBy        
   ,CreatedDate        
   ,isnull(ModifiedBy, 0) ModifiedBy        
   ,CASE         
    WHEN ModifiedDate IS NULL        
     THEN CreatedDate        
    ELSE ModifiedDate        
    END ModifiedDate        
  FROM TBL_UA_RoleMaster tutm WITH (NOLOCK)        
  WHERE IsInternal = 0        
   AND RoleId = @RoleId        
 END /*End here for details*/        
 ELSE IF (@Mode = 'U') /*This is for TBL_UA_TeamMaster Update Row */        
 BEGIN        
  IF NOT EXISTS (        
    SELECT 1        
    FROM TBL_UA_RoleMaster WITH (NOLOCK)        
    WHERE (        
      RoleName = @RoleName        
      AND IsInternal = 1        
      )        
     OR (        
      RoleName = @RoleName        
      AND ParentId = @ParentId        
      )        
    )        
  BEGIN        
   UPDATE TBL_UA_RoleMaster        
   SET RoleName = @RoleName        
    ,--RoleCode = @RoleCode,               
    Active = @Active        
    ,ModifiedBy = @UserId        
    ,ModifiedDate = GETDATE()        
   WHERE IsInternal = 0        
    AND RoleId = @RoleId        
        
   SELECT 'Record Updated' STATUS        
    ,@RoleId ID        
    ,@RoleCode Code        
        
   SET @rowJson = (        
     SELECT *        
     FROM TBL_UA_RoleMaster        
     WHERE RoleId = @RoleId        
     FOR JSON AUTO        
      ,INCLUDE_NULL_VALUES        
     )        
   SET @activity = 'Updt_usrrole'        
   SET @action = 'U'        
  END        
 END /*End here for details*/        
 ELSE IF (@Mode = 'D') /*This is for TBL_UA_TeamMaster delete Row */        
 BEGIN        
  DELETE        
  FROM TBL_UA_RoleMaster        
  WHERE IsInternal = 0        
   AND RoleId = @RoleId        
        
  SELECT 'Record Delete' STATUS        
   ,@RoleId ID        
    SET @rowJson = (        
    SELECT *        
    FROM TBL_UA_RoleMaster         
    WHERE RoleId = @RoleId        
    FOR JSON AUTO        
     ,INCLUDE_NULL_VALUES        
    )        
  SET @activity = 'Delt_usrrole'        
  SET @action = 'U'        
 END /*End here for details*/        
 ELSE IF (@Mode = 'SU')        
 BEGIN        
  UPDATE TBL_UA_RoleMaster        
  SET Active = @Active        
   ,ModifiedBy = @UserId        
   ,ModifiedDate = GETDATE()        
  WHERE IsInternal = 0        
   AND RoleId = @RoleId        
        
  SELECT 'Record Updated' STATUS        
   ,@RoleId ID        
   ,@RoleCode Code        
        
  SET @rowJson = (        
    SELECT *        
    FROM TBL_UA_RoleMaster       
    WHERE RoleId = @RoleId        
    FOR JSON AUTO        
     ,INCLUDE_NULL_VALUES        
    )        
  SET @activity = 'Updt_usrrole_sts'        
  SET @action = 'U'        
 END /*End here for details*/        
END TRY        
        
BEGIN CATCH        
 DECLARE @ErrorMessage NVARCHAR(4000);        
        
 SELECT @ErrorMessage = ERROR_MESSAGE();        
        
 RAISERROR (        
   @ErrorMessage        
   ,16        
   ,1        
   );        
END CATCH        
        
IF @rowJson IS NOT NULL        
BEGIN        
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId        
  ,@Activity_type = @activity        
  ,@ActionType = @action        
  ,@RowJson = @rowJson        
  ,@Table_name = 'TBL_UA_RoleMaster'        
END 




GO

