-- ,@Status TINYINT = NULL  

--select @Mode=N'I',@RoleCode=N'ROLE3572',@ScopeCode=N'USER',@ModuleCode=N'MOD10041',@EntityActionMappingCode=null,@EntitySpActionMappingCode=null,@EntitySpAction2MappingCode=null,@dtEntityActionAllMappingMaster=N'[{"ModuleCode":"PAG10031","Add":true,"Edit":true,"View":true,"Delete":true,"Search":true,"Import":true,"Export":true,"MassUpdate":true,"MassDelete":true,"Download":true,"Print":true,"AddTask":true,"AddAppointment":true,"AddFollowup":true,"AddNote":true,"SendSms":true,"SendMail":true,"SendVoice":true,"MergeLead":true,"SendWhatsapp":true,"UploadDocument":true,"DeleteDocument":true,"AddDeal":true,"AddTax":true,"AddQuotation":true,"AddInvoice":true,"AddWebform":true,"AddCustomField":true,"MassAssign":true,"MassSMS":true,"MassEmail":true,"MassBroadcast":true,"Standard1":true}]',@Active=0,@UserId=51532

SET NOCOUNT ON  
  DECLARE @activity VARCHAR(MAX) = ''    
 ,@action VARCHAR(1) = ''    
 ,@rowJson NVARCHAR(MAX) = ''  
BEGIN TRY  
 IF (@Mode = 'I') /*This is for Insert TBL_UA_RolePermissionMappingMaster Details */  
 BEGIN  
