   ,dbo.GetEntityActionMappingCodeNew01([Add], Edit, [View], [Delete], Search, Import, Export, MassUpdate, MassDelete, isnull(Standard1, 0), isnull(Standard2, 0), isnull(Standard3, 0), isnull(Standard4, 0), isnull(Standard5, 0))  
   ,dbo.GetEntitySpActionMappingCodeNew(Download, [Print], AddTask, AddAppointment, AddFollowup, AddNote, SendSms, SendMail)  
   ,dbo.GetEntitySpAction2MappingCodeNew(SendVoice, MergeLead, SendWhatsapp, UploadDocument, DeleteDocument, AddDeal, AddTax, AddQuotation, AddInvoice, AddWebform, AddCustomField, MassAssign, MassSMS, MassEmail, MassBroadcast)  
   ,@ParentId  
   ,1  
   ,@UserId  
   ,GetDate()  
   ,@UserId  
