   ,tupm.EntityActionMappingCode  
   ,tupm.EntitySpActionMappingCode  
   ,tupm.EntitySpAction2MappingCode  
   ,turm.RoleName  
   ,tusm.ScopeName  
   ,tumm.ModuleName  
   ,CASE   
    WHEN tupm.Active = 1  
     THEN 'Active'  
    WHEN tupm.Active = 2  
     THEN 'Deleted'  
    ELSE 'InActive'  
    END stActive  
   ,tupm.Active  
   ,tuud.User_Login Created_User  
   ,tupm.CreatedBy  
   ,tupm.CreatedDate  
   ,isnull(tupm.ModifiedBy, 0) ModifiedBy  
   ,CASE   
    WHEN tupm.ModifiedDate IS NULL  
     THEN tupm.CreatedDate  
    ELSE tupm.ModifiedDate  
    END ModifiedDate  
  FROM TBL_UA_RolePermissionMappingMaster(nolock) tupm  
  INNER JOIN VW_SystemRole_RoleMaster turm ON turm.RoleCode = tupm.RoleCode --tbl_UA_RoleMaster                      
  INNER JOIN tbl_UA_ScopeMaster(nolock) tusm ON tusm.ScopeCode = tupm.ScopeCode  
  INNER JOIN tbl_UA_ModuleMaster(nolock) tumm ON tumm.ModuleCode = tupm.ModuleCode  
  INNER JOIN TBL_UA_EntityActionMappingMaster(nolock) tuem ON tuem.EntityActionMappingCode = tupm.EntityActionMappingCode  
  INNER JOIN TBL_UA_EntitySpActionMappingMaster(nolock) tumms ON tumms.EntitySpActionMappingCode = tupm.EntitySpActionMappingCode  
  LEFT JOIN TBL_UA_EntitySpAction2MappingMaster(nolock) tumms2 ON tumms2.EntitySpAction2MappingCode = tupm.EntitySpAction2MappingCode  
  INNER JOIN User_Detail(nolock) tuud ON tuud.User_Id = tupm.CreatedBy  
  WHERE tupm.ParentId = @ParentId  
   AND (  
    @FilterText IS NULL  
    OR turm.RoleName LIKE '%' + @FilterText + '%'  
    OR tumm.ModuleName LIKE '%' + @FilterText + '%'  
    )  
   AND (  
    @Status IS NULL  
    OR tupm.Active = @Status  
    )  
  ORDER BY tupm.ScopeCode  
   ,tupm.RoleCode  
   ,[sequence]  
   --OFFSET @OffsetValue Rows FETCH NEXT @PagingSize ROWS ONLY     
  SET @rowJson = ''      
  SET @activity = 'View_usrrolePermission'    
