     ,isnull(Standard2, 0) Standard2
     ,isnull(Standard3, 0) Standard3
     ,isnull(Standard4, 0) Standard4
     ,isnull(Standard5, 0) Standard5
     ,isnull(tumm.Type, 0) [Type]  
    FROM TBL_UA_ModuleMaster(nolock) tumm  
    LEFT JOIN TBL_UA_RolePermissionMappingMaster(nolock) tupm ON tumm.ModuleCode = tupm.ModuleCode  
    LEFT JOIN tbl_UA_EntityActionMappingMaster(nolock) tuea ON tuea.EntityActionMappingCode = tupm.EntityActionMappingCode  
    LEFT JOIN tbl_UA_EntitySpActionMappingMaster(nolock) tueas ON tueas.EntitySpActionMappingCode = tupm.EntitySpActionMappingCode  
    LEFT JOIN tbl_UA_EntitySpAction2MappingMaster(nolock) tueas2 ON tueas2.EntitySpAction2MappingCode = tupm.EntitySpAction2MappingCode  
    WHERE tupm.ParentId = @ParentId  
     AND tupm.RoleCode = @RoleCode  
     AND tupm.ScopeCode = @ScopeCode  
     AND (  
      tumm.ModuleCode = @ModuleCode  
      OR tumm.ParentModuleId = @ModuleId  
      OR tumm.ParentModuleId IN (  
       SELECT ModuleId  
       FROM TBL_UA_ModuleMaster(nolock)  
       WHERE ParentModuleId = @ModuleId  
       )  
      OR tumm.ParentModuleId IN (  
       SELECT ModuleId  
       FROM TBL_UA_ModuleMaster(nolock)  
       WHERE ParentModuleId IN (  
         SELECT ModuleId  
         FROM TBL_UA_ModuleMaster(nolock)  
         WHERE ParentModuleId = @ModuleId  
         )  
       )  
      OR tumm.ParentModuleId IN (  
       SELECT ModuleId  
       FROM TBL_UA_ModuleMaster(nolock)  
       WHERE ParentModuleId IN (  
         SELECT ModuleId  
         FROM TBL_UA_ModuleMaster(nolock)  
         WHERE ParentModuleId IN (  
           SELECT ModuleId  
           FROM TBL_UA_ModuleMaster(nolock)  
           WHERE ParentModuleId = @ModuleId  
           )  
         )  
       )  
      )  
      
    UNION ALL  
      
    SELECT *  
    FROM (  
     SELECT [Sequence] DisplaySNO  
      ,tumm.ModuleId  
      ,tumm.ModuleDescription  
      ,tumm.ModuleName  
      ,tumm.ModuleCode  
      ,0 RolePermissionMappingId  
      ,'' RolePermissionMappingCode  
      ,0 [Add]  
      ,0 Edit  
      ,0 [View]  
      ,0 [Delete]  
      ,0 Search  
      ,0 Import  
      ,0 Export  
      ,0 MassUpdate  
      ,0 MassDelete  
      ,0 Download  
      ,0 [Print]  
      ,0 AddTask  
      ,0 AddAppointment  
      ,0 AddFollowup  
      ,0 AddNote  
      ,0 SendSms  
      ,0 SendMail  
      ,0 SendVoice  
      ,0 MergeLead  
      ,0 SendWhatsapp  
      ,0 UploadDocument  
      ,0 DeleteDocument  
      ,0 AddDeal  
      ,0 AddTax  
      ,0 AddQuotation  
      ,0 AddInvoice  
      ,0 AddWebform  
      ,0 AddCustomField  
      ,0 MassAssign  
      ,0 MassSMS  
      ,0 MassEmail  
      ,0 MassBroadcast  
      ,0 Standard1  
      ,0 Standard2  
      ,0 Standard3  
      ,0 Standard4  
      ,0 Standard5  
      ,tupm.[Type]  
     FROM TBL_UA_ModuleMaster(nolock) tumm  
     LEFT JOIN TBL_UA_ActionStructure(nolock) tupm ON tumm.Type = tupm.Type  
     WHERE (  
       tumm.ModuleCode = @ModuleCode  
       OR tumm.ParentModuleId = @ModuleId  
       OR tumm.ParentModuleId IN (  
        SELECT ModuleId  
        FROM TBL_UA_ModuleMaster(nolock)  
        WHERE ParentModuleId = @ModuleId  
        )  
       OR tumm.ParentModuleId IN (  
        SELECT ModuleId  
        FROM TBL_UA_ModuleMaster(nolock)  
        WHERE ParentModuleId IN (  
          SELECT ModuleId  
          FROM TBL_UA_ModuleMaster(nolock)  
          WHERE ParentModuleId = @ModuleId  
          )  
        )  
       OR tumm.ParentModuleId IN (  
        SELECT ModuleId  
        FROM TBL_UA_ModuleMaster(nolock)  
        WHERE ParentModuleId IN (  
          SELECT ModuleId  
          FROM TBL_UA_ModuleMaster(nolock)  
          WHERE ParentModuleId IN (  
            SELECT ModuleId  
            FROM TBL_UA_ModuleMaster(nolock)  
            WHERE ParentModuleId = @ModuleId  
            )  
          )  
        )  
       )  
     ) q  
    WHERE q.ModuleCode NOT IN (  
      SELECT tumm.ModuleCode  
      FROM TBL_UA_ModuleMaster(nolock) tumm  
      LEFT JOIN TBL_UA_RolePermissionMappingMaster(nolock) tupm ON tumm.ModuleCode = tupm.ModuleCode  
      LEFT JOIN tbl_UA_EntityActionMappingMaster(nolock) tuea ON tuea.EntityActionMappingCode = tupm.EntityActionMappingCode  
      LEFT JOIN tbl_UA_EntitySpActionMappingMaster(nolock) tueas ON tueas.EntitySpActionMappingCode = tupm.EntitySpActionMappingCode  
      LEFT JOIN tbl_UA_EntitySpAction2MappingMaster(nolock) tueas2 ON tueas2.EntitySpAction2MappingCode = tupm.EntitySpAction2MappingCode  
      WHERE tupm.ParentId = @ParentId  
       AND tupm.RoleCode = @RoleCode  
       AND tupm.ScopeCode = @ScopeCode  
       AND (  
        tumm.ModuleCode = @ModuleCode  
        OR tumm.ParentModuleId = @ModuleId  
        OR tumm.ParentModuleId IN (  
         SELECT ModuleId  
         FROM TBL_UA_ModuleMaster(nolock)  
         WHERE ParentModuleId = @ModuleId  
         )  
        OR tumm.ParentModuleId IN (  
         SELECT ModuleId  
         FROM TBL_UA_ModuleMaster(nolock)  
         WHERE ParentModuleId IN (  
           SELECT ModuleId  
           FROM TBL_UA_ModuleMaster(nolock)  
           WHERE ParentModuleId = @ModuleId  
           )  
         )  
        OR tumm.ParentModuleId IN (  
         SELECT ModuleId  
         FROM TBL_UA_ModuleMaster(nolock)  
         WHERE ParentModuleId IN (  
           SELECT ModuleId  
           FROM TBL_UA_ModuleMaster(nolock)  
           WHERE ParentModuleId IN (  
             SELECT ModuleId  
             FROM TBL_UA_ModuleMaster(nolock)  
             WHERE ParentModuleId = @ModuleId  
             )  
           )  
         )  
        )  
      )  
    ) t  
   ORDER BY t.DisplaySNO ASC  
  END  
 END  
 ELSE IF (@Mode = 'D') /*This is for TBL_UA_RolePermissionMappingMaster delete Row */  
 BEGIN  
  --Update TBL_UA_RolePermissionMappingMaster set Active = 2 where PermissionId = @PermissionId                       
  DELETE  
  FROM TBL_UA_RolePermissionMappingMaster  
  WHERE RolePermissionMappingId = @RolePermissionMappingId  
        SET @rowJson = (    
    SELECT *    
    FROM TBL_UA_RolePermissionMappingMaster     
    WHERE RolePermissionMappingId = @RolePermissionMappingId    
    FOR JSON AUTO    
     ,INCLUDE_NULL_VALUES    
    )    
  SET @activity = 'Delt_usrrolepermission'    
  SET @action = 'D'    
  
  SELECT 'Record Delete' STATUS  
   ,@RolePermissionMappingId ID  
 END /*End here for details*/  
  
 ELSE IF (@Mode = 'SU') /*This is for TBL_UA_RolePermissionMappingMaster delete Row */  
 BEGIN  
  --Update TBL_UA_RolePermissionMappingMaster set Active = 2 where PermissionId = @PermissionId                       
  UPDATE  TBL_UA_RolePermissionMappingMaster SET Active=@Active  
  WHERE RolePermissionMappingId = @RolePermissionMappingId  
  
  SELECT 'Record Status Updated' STATUS  
   ,@RolePermissionMappingId ID  
       SET @rowJson = (    
    SELECT *    
    FROM TBL_UA_RolePermissionMappingMaster     
    WHERE RolePermissionMappingId = @RolePermissionMappingId    
    FOR JSON AUTO    
     ,INCLUDE_NULL_VALUES    
    )    
  SET @activity = 'Updt_usrrolepermission'    
  SET @action = 'U'    
 END /*End here for details*/  
END TRY  
  
BEGIN CATCH  
 DECLARE @ErrorMessage NVARCHAR(4000);  
  
 SELECT @ErrorMessage = ERROR_MESSAGE();  
  
 RAISERROR (  
   @ErrorMessage  
   ,16  
   ,1  
   );  
END CATCH  
IF @rowJson IS NOT NULL    
BEGIN    
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId    
  ,@Activity_type = @activity    
  ,@ActionType = @action    
  ,@RowJson = @rowJson    
  ,@Table_name = 'TBL_UA_RolePermissionMappingMaster'    
END 
  


