/* ============================================================
   Procedure: [dbo].[usp_tbl_UA_ScopeMaster]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_tbl_UA_ScopeMaster (
	@Mode VARCHAR(2)
	,@ScopeId INT = 0
	,@ScopeName VARCHAR(50) = NULL
	,@ScopeCode VARCHAR(50) = NULL
	,@Active BIT = 0
	,@UserId BIGINT = 0
	)
AS
SET NOCOUNT ON

DECLARE @activity VARCHAR(MAX) = ''
	,@action VARCHAR(1) = ''
	,@rowJson NVARCHAR(MAX) = ''

BEGIN TRY
	IF (@Mode = 'I') /*This is for Insert TBL_UA_ScopeMaster Details */
	BEGIN
		IF NOT EXISTS (
				SELECT 1
				FROM TBL_UA_ScopeMaster
				WHERE ScopeName = @ScopeName
				)
		BEGIN
			INSERT INTO TBL_UA_ScopeMaster (
				ScopeName
				,ScopeCode
				,Active
				,CreatedBy
				,CreatedDate
				)
			VALUES (
				@ScopeName
				,@ScopeCode
				,@Active
				,@UserId
				,GETDATE()
				)

			SELECT @@IDENTITY ID
				,@ScopeCode Code

			SET @rowJson = (
					SELECT *
					FROM TBL_UA_ScopeMaster WITH(NOLOCK)
					WHERE ScopeName = @ScopeName
					FOR JSON AUTO
						,INCLUDE_NULL_VALUES
					)
			SET @activity = 'Inst_usrrole_perm_mapp'
			SET @action = 'I'
		END
		ELSE
		BEGIN
			SELECT - 10 /* Use for TBL_UA_ScopeMaster Exist or not  */
		END
	END /*End here for insert*/
	ELSE IF (@Mode = 'S') /*This is for List of TBL_UA_ScopeMaster Details */
	BEGIN
		SELECT ScopeId
			,ScopeName
			,ScopeCode
			,CASE 
				WHEN Active = 1
					THEN 'Active'
				ELSE 'InActive'
				END stActive
			,Active
			,CreatedBy
			,CreatedDate
			,isnull(ModifiedBy, 0) ModifiedBy
			,CASE 
				WHEN ModifiedDate IS NULL
					THEN CreatedDate
				ELSE ModifiedDate
				END ModifiedDate
		FROM TBL_UA_ScopeMaster

		SET @activity = 'View_usrrole_perm_mapp'
		SET @action = 'S'
	END /*End here for list*/
	ELSE IF (@Mode = 'E') /*This is for TBL_UA_ScopeMaster Details */
	BEGIN
		SELECT ScopeId
			,ScopeName
			,ScopeCode
			,CASE 
				WHEN Active = 1
					THEN 'Active'
				ELSE 'InActive'
				END stActive
			,Active
			,CreatedBy
			,CreatedDate
			,isnull(ModifiedBy, 0) ModifiedBy
			,CASE 
				WHEN ModifiedDate IS NULL
					THEN CreatedDate
				ELSE ModifiedDate
				END ModifiedDate
		FROM TBL_UA_ScopeMaster
		WHERE ScopeId = @ScopeId
	END /*End here for details*/
	ELSE IF (@Mode = 'U') /*This is for TBL_UA_ScopeMaster Update Row */
	BEGIN
		UPDATE TBL_UA_ScopeMaster
		SET ScopeName = @ScopeName
			,ScopeCode = @ScopeCode
			,Active = @Active
			,ModifiedBy = @UserId
			,ModifiedDate = GETDATE()
		WHERE ScopeId = @ScopeId

		SET @rowJson = (
				SELECT *
				FROM TBL_UA_ScopeMaster WITH(NOLOCK)
				WHERE ScopeId = @ScopeId
				FOR JSON AUTO
					,INCLUDE_NULL_VALUES
				)
		SET @activity = 'Updt_usrrole_perm_mapp'
		SET @action = 'U'
	END /*End here for details*/
	ELSE IF (@Mode = 'D') /*This is for TBL_UA_ScopeMaster delete Row */
	BEGIN
		SET @rowJson = (
				SELECT *
				FROM TBL_UA_ScopeMaster WITH(NOLOCK)
				WHERE ScopeId = @ScopeId
				FOR JSON AUTO
					,INCLUDE_NULL_VALUES
				)
		SET @activity = 'Delt_usrrole_perm_mapp'
		SET @action = 'D'

		DELETE
		FROM TBL_UA_ScopeMaster
		WHERE ScopeId = @ScopeId
	END /*End here for details*/
END TRY

BEGIN CATCH
	DECLARE @ErrorMessage NVARCHAR(4000);

	SELECT @ErrorMessage = ERROR_MESSAGE();

	RAISERROR (
			@ErrorMessage
			,16
			,1
			);
END CATCH

IF @rowJson IS NOT NULL
BEGIN
	EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @Userid
		,@Activity_type = @activity
		,@ActionType = @action
		,@RowJson = @rowJson
		,@Table_name = 'TBL_UA_ScopeMaster'
END



GO

/* ============================================================
   Procedure: [dbo].[usp_tbl_UA_TeamMaster]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_tbl_UA_TeamMaster (  
 @Mode VARCHAR(2)  
 ,@TeamId BIGINT = 0  
 ,@TeamName VARCHAR(50) = NULL  
 ,@TeamCode VARCHAR(50) = ''  
 ,@UserCodeList VARCHAR(500) = NULL  
 ,@Active BIT = 1  
 ,@UserId BIGINT = 0  
 ,@ParentId BIGINT = 0  
 ,@fromdate DATETIME = NULL  
 ,@todate DATETIME = NULL  
 ,@status CHAR(1) = NULL  
 )  
AS  
SET NOCOUNT ON  
  
DECLARE @activity VARCHAR(MAX) = ''  
 ,@action VARCHAR(1) = ''  
 ,@rowJson NVARCHAR(MAX) = ''  
  
BEGIN TRY  
 IF (@Mode = 'I') /*This is for Insert TBL_UA_TeamMaster Details */  
 BEGIN  
  IF (@TeamCode = '')  
  BEGIN  
   SET @TeamCode = 'TEAM' + Cast((  
      1000 + isnull((  
        SELECT Max(TeamId)  
        FROM TBL_UA_TeamMaster  
        ), 1)  
      ) AS VARCHAR(10))  
  END  
  
  SELECT @ParentId = ParentId  
  FROM User_detail WITH (NOLOCK)  
  WHERE User_Id = @UserId  
  
  IF NOT EXISTS (  
    SELECT 1  
    FROM TBL_UA_TeamMaster WITH (NOLOCK)  
    WHERE TeamName = @TeamName  
     AND ParentId = @ParentId  
    )  
  BEGIN  
   INSERT INTO TBL_UA_TeamMaster (  
    TeamName  
    ,TeamCode  
    ,ParentId  
    ,Active  
    ,CreatedBy  
    ,CreatedDate  
    )  
   VALUES (  
    @TeamName  
    ,@TeamCode  
    ,@ParentId  
    ,@Active  
    ,@UserId  
    ,GETDATE()  
    )  
  
   DECLARE @ID BIGINT;  
  
   SET @ID = scope_identity();  
  
   INSERT INTO TBL_UA_TeamUserMappingMaster (  
    TeamCode  
    ,ParentId  
    ,UserId  
    ,Active  
    ,CreatedBy  
    ,CreatedDate  
    )  
   SELECT @TeamCode  
    ,@ParentId  
    ,item  
    ,@Active  
    ,@UserId  
    ,GETDATE()  
   FROM dbo.fu_SplitString(@UserCodeList, ',') aa  
  
   SELECT 'Record Saved' STATUS  
    ,@ID  
    ,@TeamCode Code  
  
   SET @rowJson = (  
     SELECT *  
     FROM TBL_UA_TeamMaster  
     WHERE TeamId = @ID  
     FOR JSON AUTO  
      ,INCLUDE_NULL_VALUES  
     )  
   SET @activity = 'Inst_usrteam'  
   SET @action = 'I'  
  END  
  ELSE  
  BEGIN  
   SELECT 'Record Already Exist' STATUS  
  END  
 END /*End here for insert*/  
 ELSE IF (@Mode = 'S') /*This is for List of TBL_UA_TeamMaster Details */  
 BEGIN  
  SELECT @ParentId = ParentId  
  FROM User_detail WITH (NOLOCK)  
  WHERE User_Id = @UserId  
  
  DECLARE @TimeZoneName NVARCHAR(255) = (  
    SELECT TimeZone  
    FROM User_Detail(NOLOCK)  
    WHERE User_ID = @Userid  
    )  
  
  SELECT tm.TeamId  
   ,tm.TeamName  
   ,tm.TeamCode  
   ,CASE   
    WHEN Active = 1  
     THEN 'Active'  
    ELSE 'InActive'  
    END stActive  
   ,Active  
   ,ud.User_Login CreatedUser  
   ,tm.CreatedBy  
   ,dbo.fn_ConvertDateTime(tm.CreatedDate, @TimeZoneName, 0) AS CreatedDate  
   ,isnull(tm.ModifiedBy, 0) ModifiedBy  
   ,CASE   
    WHEN tm.ModifiedDate IS NULL  
     THEN dbo.fn_ConvertDateTime(CreatedDate, @TimeZoneName, 0)  
    ELSE dbo.fn_ConvertDateTime(tm.ModifiedDate, @TimeZoneName, 0)  
    END ModifiedDate  
  FROM TBL_UA_TeamMaster tm WITH (NOLOCK)  
  INNER JOIN User_detail ud WITH (NOLOCK) ON ud.User_Id = tm.CreatedBy  
  WHERE tm.ParentId = @ParentId  
   AND (  
    tm.TeamName LIKE '%' + @TeamName + '%'  
    OR @TeamName IS NULL  
    )  
   AND (  
    @status IS NULL  
    OR tm.Active = @status  
    )  
   AND (  
    @fromdate IS NULL  
    OR tm.CreatedDate > @fromdate  
    )  
   AND (  
    @todate IS NULL  
    OR tm.CreatedDate < @todate  
    )  
  
  SET @rowJson = ''  
  SET @activity = 'View_usrteam'  
  SET @action = 'S'  
 END /*End here for list*/  
 ELSE IF (@Mode = 'E') /*This is for TBL_UA_TeamMaster Details */  
 BEGIN  
  SELECT TeamId  
   ,TeamName  
   ,TeamCode  
   ,isnull((  
     SELECT List_Output  
     FROM (  
      SELECT TeamCode  
       ,STRING_AGG([UserId], ', ') AS List_Output  
      FROM TBL_UA_TeamUserMappingMaster WITH (NOLOCK)  
      WHERE TeamCode = tutm.TeamCode  
      GROUP BY TeamCode  
      ) t  
     ), '') UserCodeList  
   ,CASE   
    WHEN Active = 1  
     THEN 'Active'  
    ELSE 'InActive'  
    END stActive  
   ,Active  
   ,CreatedBy  
   ,CreatedDate  
   ,isnull(ModifiedBy, 0) ModifiedBy  
   ,CASE   
    WHEN ModifiedDate IS NULL  
     THEN CreatedDate  
    ELSE ModifiedDate  
    END ModifiedDate  
  FROM TBL_UA_TeamMaster tutm WITH (NOLOCK)  
  WHERE TeamId = @TeamId  
 END /*End here for details*/  
 ELSE IF (@Mode = 'EU') /*This is for TBL_UA_TeamMaster Details */  
 BEGIN  
  SELECT TeamId  
   ,TeamName  
   ,TeamCode  
   ,isnull((  
     SELECT List_Output  
     FROM (  
      SELECT TeamCode  
       ,STRING_AGG([UserId], ', ') AS List_Output  
      FROM TBL_UA_TeamUserMappingMaster WITH (NOLOCK)  
      WHERE TeamCode = tutm.TeamCode  
      GROUP BY TeamCode  
      ) t  
     ), '') UserCodeList  
   ,CASE   
    WHEN Active = 1  
     THEN 'Active'  
    ELSE 'InActive'  
    END stActive  
   ,Active  
   ,CreatedBy  
   ,CreatedDate  
   ,isnull(ModifiedBy, 0) ModifiedBy  
   ,CASE   
    WHEN ModifiedDate = NULL  
     THEN CreatedDate  
    ELSE ModifiedDate  
    END ModifiedDate  
  FROM TBL_UA_TeamMaster tutm WITH (NOLOCK)  
  WHERE TeamId = @TeamId  
  
  SELECT @ParentId = ParentID  
  FROM User_Detail WITH (NOLOCK)  
  WHERE User_ID = @UserId;  
  
  SELECT USER_ID  
   ,User_Login + ' (' + UD.FName + ' ' + UD.LName + ')' AS User_Login  
   ,dbo.GetUserId_Checked(@TeamId, UD.USER_ID) Check_ed  
  FROM User_Detail(NOLOCK) UD  
  WHERE ParentID = @ParentId  
   AND STATUS = 1  
 END /*End here for details*/  
 ELSE IF (@Mode = 'U') /*This is for TBL_UA_TeamMaster Update Row */  
 BEGIN  
  UPDATE TBL_UA_TeamMaster  
  SET TeamName = @TeamName  
   ,TeamCode = @TeamCode  
   ,Active = @Active  
   ,ModifiedBy = @UserId  
   ,ModifiedDate = GETDATE()  
  WHERE TeamId = @TeamId  
  
  DELETE TBL_UA_TeamUserMappingMaster  
  WHERE TeamCode = @TeamCode  
  
  INSERT INTO TBL_UA_TeamUserMappingMaster (  
   TeamCode  
   ,ParentId  
   ,UserId  
   ,Active  
   ,CreatedBy  
   ,CreatedDate  
   )  
  SELECT @TeamCode  
   ,@ParentId  
   ,item  
   ,@Active  
   ,@UserId  
   ,GETDATE()  
  FROM dbo.fu_SplitString(@UserCodeList, ',') aa  
  
  SELECT 'Record Updated' STATUS  
   ,@TeamId ID  
   ,@TeamCode Code  
  
  SET @rowJson = (  
    SELECT *  
    FROM TBL_UA_TeamMaster  
    WHERE TeamId = @TeamId  
    FOR JSON AUTO  
     ,INCLUDE_NULL_VALUES  
    )  
  SET @activity = 'Updt_usrteam'  
  SET @action = 'U'  
 END /*End here for details*/  
 ELSE IF (@Mode = 'D') /*This is for TBL_UA_TeamMaster delete Row */  
 BEGIN  
  UPDATE TBL_UA_TeamMaster  
  SET Active = 0  
  WHERE TeamId = @TeamId  
  
  SELECT 'Record Deleted' STATUS  
   ,@TeamId ID  
  
  SET @rowJson = (  
    SELECT *  
    FROM TBL_UA_TeamMaster  
    WHERE TeamId = @TeamId  
    FOR JSON AUTO  
     ,INCLUDE_NULL_VALUES  
    )  
  SET @activity = 'Delt_usrteam'  
  SET @action = 'U'  
 END /*End here for details*/  
END TRY  
  
BEGIN CATCH  
 DECLARE @ErrorMessage NVARCHAR(4000);  
  
 SELECT @ErrorMessage = ERROR_MESSAGE();  
  
 RAISERROR (  
   @ErrorMessage  
   ,16  
   ,1  
   );  
END CATCH  
  
IF @rowJson IS NOT NULL  
BEGIN  
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId  
  ,@Activity_type = @activity  
  ,@ActionType = @action  
  ,@RowJson = @rowJson  
  ,@Table_name = 'TBL_UA_TeamMaster'  
END  


GO

/* ============================================================
   Procedure: [dbo].[usp_tbl_UA_TeamParentMappingMaster]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_tbl_UA_TeamParentMappingMaster]
 (
 @Mode varchar(2),          
 @TeamParentMappingId	bigint = 0,
 @TeamCode	varchar(50) = null,
 @ParentId	bigint = 0,
 @Active	bit	= 0,
 @UserId	bigint = 0
)          
AS          
  SET NOCOUNT ON           
  BEGIN TRY            
  IF (@Mode='I')/*This is for Insert TBL_UA_TeamParentMappingMaster Details */            
 BEGIN            
   IF NOT EXISTS(select 1 from TBL_UA_TeamParentMappingMaster where TeamCode = @TeamCode and ParentId = @ParentId)             
     BEGIN 
     insert into TBL_UA_TeamParentMappingMaster(TeamCode, ParentId, Active, CreatedBy, CreatedDate) 
	 values(@TeamCode, @ParentId, @Active, @UserId, GETDATE())          
	 Select @@IDENTITY ID, @TeamCode Code
     END           
   ELSE          
    BEGIN          
     SELECT -10      /* Use for TBL_UA_TeamParentMappingMaster Exist or not  */          
    END  
 END /*End here for insert*/            
          
  else if(@Mode='S')/*This is for List of TBL_UA_TeamParentMappingMaster Details */            
 begin 
  select TeamParentMappingId, TeamCode, ParentId, case when Active = 1 then 'Active'
  else 'InActive'
  End stActive,
  Active, CreatedBy, CreatedDate, isnull(ModifiedBy, 0) ModifiedBy, 
  case when ModifiedDate is Null then CreatedDate
  else ModifiedDate 
  End ModifiedDate from TBL_UA_TeamParentMappingMaster         
 end /*End here for list*/           
 
 else if(@Mode='E')/*This is for TBL_UA_TeamParentMappingMaster Details */            
   begin 
  select TeamParentMappingId, TeamCode, ParentId, case when Active = 1 then 'Active'
  else 'InActive'
  End stActive, Active, CreatedBy, CreatedDate, isnull(ModifiedBy, 0) ModifiedBy, 
  case when ModifiedDate is Null then CreatedDate
  else ModifiedDate
  End ModifiedDate from TBL_UA_TeamParentMappingMaster 
  where TeamParentMappingId = @TeamParentMappingId
   end /*End here for details*/            
          
 else if(@Mode='U')/*This is for TBL_UA_TeamParentMappingMaster Update Row */            
   begin 
  update TBL_UA_TeamParentMappingMaster set TeamCode = @TeamCode, ParentId = @ParentId, Active = @Active, ModifiedBy = @UserId, 
  ModifiedDate = GETDATE() where TeamParentMappingId = @TeamParentMappingId
   end /*End here for details*/            
          
  else if(@Mode='D')/*This is for TBL_UA_TeamParentMappingMaster delete Row */            
   begin 
  
  update TBL_UA_TeamParentMappingMaster set Active = 0 where TeamParentMappingId = @TeamParentMappingId
   end /*End here for details*/            
           
 END TRY            
BEGIN CATCH            
            
 DECLARE @ErrorMessage NVARCHAR(4000);            
 SELECT @ErrorMessage = ERROR_MESSAGE();            
 RAISERROR (@ErrorMessage, 16, 1);            
END CATCH 



GO

/* ============================================================
   Procedure: [dbo].[usp_tbl_UA_TeamUserMappingMaster]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_tbl_UA_TeamUserMappingMaster]
 (
 @Mode varchar(2),          
 @TeamUserMappingId	bigint = 0,
 @TeamCode	varchar(50) = null,
 @ParentId	bigint = 0,
 @UserId	bigint = 0,
 @Active	bit	= 0,
 @LogUserId	bigint = 0
)          
AS          
  SET NOCOUNT ON           
  BEGIN TRY            
  IF (@Mode='I')/*This is for Insert TBL_UA_TeamUserMappingMaster Details */            
 BEGIN            
   IF NOT EXISTS(select 1 from TBL_UA_TeamUserMappingMaster where TeamCode = @TeamCode and ParentId = @ParentId and UserId = @UserId)             
     BEGIN 
     insert into TBL_UA_TeamUserMappingMaster(TeamCode, ParentId, UserId, Active, CreatedBy, CreatedDate) 
	 values(@TeamCode, @ParentId, @UserId, @Active, @LogUserId, GETDATE())          
	 Select @@IDENTITY ID, @TeamCode Code
     END           
   ELSE          
    BEGIN          
     SELECT -10      /* Use for TBL_UA_TeamUserMappingMaster Exist or not  */          
    END  
 END /*End here for insert*/            
          
  else if(@Mode='S')/*This is for List of TBL_UA_TeamUserMappingMaster Details */            
 begin 
  select TeamUserMappingId, TeamCode, ParentId, UserId, case when Active = 1 then 'Active'
  else 'InActive'
  End stActive,
  Active, CreatedBy, CreatedDate, isnull(ModifiedBy, 0) ModifiedBy, 
  case when ModifiedDate is Null then CreatedDate
  else ModifiedDate 
  End ModifiedDate from TBL_UA_TeamUserMappingMaster         
 end /*End here for list*/           
 
 else if(@Mode='E')/*This is for TBL_UA_TeamUserMappingMaster Details */            
   begin 
  select TeamUserMappingId, TeamCode, ParentId, UserId, case when Active = 1 then 'Active'
  else 'InActive'
  End stActive, Active, CreatedBy, CreatedDate, isnull(ModifiedBy, 0) ModifiedBy, 
  case when ModifiedDate is Null then CreatedDate
  else ModifiedDate
  End ModifiedDate from TBL_UA_TeamUserMappingMaster 
  where TeamUserMappingId = @TeamUserMappingId
   end /*End here for details*/            
          
 else if(@Mode='U')/*This is for TBL_UA_TeamUserMappingMaster Update Row */            
   begin 
  update TBL_UA_TeamUserMappingMaster set TeamCode = @TeamCode, ParentId = @ParentId, UserId = @UserId, Active = @Active, ModifiedBy = @LogUserId, 
  ModifiedDate = GETDATE() where TeamUserMappingId = @TeamUserMappingId
   end /*End here for details*/            
          
  else if(@Mode='D')/*This is for TBL_UA_TeamUserMappingMaster delete Row */            
   begin 
  
  update TBL_UA_TeamUserMappingMaster set Active = 0 where TeamUserMappingId = @TeamUserMappingId
   end /*End here for details*/            
           
 END TRY            
BEGIN CATCH            
            
 DECLARE @ErrorMessage NVARCHAR(4000);            
 SELECT @ErrorMessage = ERROR_MESSAGE();            
 RAISERROR (@ErrorMessage, 16, 1);            
END CATCH 



GO

/* ============================================================
   Procedure: [dbo].[usp_tbl_UA_UserHierarchy]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_tbl_UA_UserHierarchy   
(    
  @Mode VARCHAR(2)    
 ,@ParentId BIGINT = 0    
 ,@HierarchyJSON VARCHAR(Max) = NULL    
 ,@CreatedBy BIGINT = 0    
 ,@UserId BIGINT = 0    
 ,@ReportTo BIGINT = 0    
 )    
AS    
SET NOCOUNT ON    
    
DECLARE @activity VARCHAR(MAX) = ''    
 ,@action VARCHAR(1) = ''    
 ,@rowJson NVARCHAR(MAX) = ''    
    
BEGIN TRY    
 IF (@Mode = 'I') /*This is for Insert tbl_UA_UserHierarchy Details */    
 BEGIN    
  
 declare @roleid bigint  
 -- declare @HierarchyJSON nvarchar(max)=N'[{"roleid":4,"rolename":"Admin","parentid":0,"rolecode":"SYS_ADMIN"},{"roleid":9,"rolename":"User","parentid":4,"rolecode":"SYS_USER"},{"roleid":10,"rolename":"Guest","parentid":4,"rolecode":"SYS_GUEST"},{"roleid":92,"rolename":"Test1","parentid":9,"rolecode":"ROLE1058"},{"roleid":98,"rolename":"Test2","parentid":9,"rolecode":"ROLE1097"},{"roleid":58,"rolename":"HR","parentid":10,"rolecode":"ROLE1007"}]'  
  
 select @roleid=roleid   
 from openjson(@HierarchyJSON)  
 with  
 (  
 roleid bigint '$.roleid'  
 )  
  
 If(@roleid>0)  
 Begin  
 IF EXISTS (    
    SELECT 1    
    FROM tbl_UA_RoleHierarchy(nolock)    
    WHERE ParentId = @ParentId  and IsActive=1  
    )    
 BEGIN    
    UPDATE tbl_UA_RoleHierarchy    
    SET HierarchyJSON = @HierarchyJSON    
  ,ModifiedBy = @CreatedBy    
  ,ModifiedDate = GETDATE()    
    WHERE ParentId = @ParentId and IsActive=1  
    
  SELECT 'Record Updated' STATUS, @ParentId ParentId    
    
    SET @rowJson = (    
   SELECT *    
   FROM tbl_UA_RoleHierarchy(nolock)    
   WHERE ParentId = @ParentId and IsActive=1  
   FOR JSON AUTO, INCLUDE_NULL_VALUES    
   )    
    SET @activity = 'Updt_rolehrrc'    
    SET @action = 'U'    
 END    
 ELSE    
 BEGIN    
    INSERT INTO tbl_UA_RoleHierarchy (    
  ParentId    
  ,HierarchyJSON    
  ,CreatedBy    
  ,CreatedDate    
  ,ModifiedBy    
  ,ModifiedDate,  
  IsActive  
  )    
    VALUES (    
  @ParentId    
  ,@HierarchyJSON    
  ,@CreatedBy    
  ,GETDATE()    
  ,@CreatedBy    
  ,GETDATE()  
  ,1  
  )    
    
    SELECT 'Record Saved' STATUS, @ParentId ParentId    
    
    SET @rowJson = (    
   SELECT *    
   FROM tbl_UA_RoleHierarchy(nolock)  
   WHERE ParentId = @ParentId  and IsActive=1  
   FOR JSON AUTO, INCLUDE_NULL_VALUES    
   )    
    SET @activity = 'Inst_rolehrrc'    
    SET @action = 'I'    
 END    
  
 End  
 Else --User  
 Begin  
  
  IF EXISTS (    
    SELECT 1    
    FROM tbl_UA_UserHierarchy(nolock)    
    WHERE ParentId = @ParentId  and IsActive=1  
    )    
  BEGIN    
   UPDATE tbl_UA_UserHierarchy    
   SET HierarchyJSON = @HierarchyJSON    
    ,ModifiedBy = @CreatedBy    
    ,ModifiedDate = GETDATE()    
   WHERE ParentId = @ParentId and IsActive=1  
    
   SELECT 'Record Updated' STATUS    
    ,@ParentId ParentId    
    
   SET @rowJson = (    
     SELECT *    
     FROM tbl_UA_UserHierarchy(nolock)    
     WHERE ParentId = @ParentId and IsActive=1  
     FOR JSON AUTO    
      ,INCLUDE_NULL_VALUES    
     )    
   SET @activity = 'Updt_usrhrrc'    
   SET @action = 'U'    
  END    
  ELSE    
  BEGIN    
   INSERT INTO tbl_UA_UserHierarchy (    
    ParentId    
    ,HierarchyJSON    
    ,CreatedBy    
    ,CreatedDate    
    ,ModifiedBy    
    ,ModifiedDate,  
 IsActive  
    )    
   VALUES (    
    @ParentId    
    ,@HierarchyJSON    
    ,@CreatedBy    
    ,GETDATE()    
    ,@CreatedBy    
    ,GETDATE()  
 ,1  
    )    
    
   SELECT 'Record Saved' STATUS, @ParentId ParentId    
    
   SET @rowJson = (    
     SELECT *    
     FROM tbl_UA_UserHierarchy(nolock)  
     WHERE ParentId = @ParentId  and IsActive=1  
     FOR JSON AUTO, INCLUDE_NULL_VALUES    
     )    
   SET @activity = 'Inst_usrhrrc'    
   SET @action = 'I'    
  END    
    
 End  
  
 END /*End here for insert*/    
 ELSE IF (@Mode = 'S') /*This is for List of tbl_UA_UserHierarchy Details */    
 BEGIN    
  SELECT ParentId    
  FROM User_Detail(nolock)    
 END /*End here for details*/    
 ELSE IF (@Mode = 'G') /*This is for Insert tbl_UA_UserHierarchy Details */    
 BEGIN    
  DECLARE @Parentuser_login VARCHAR(100)    
  DECLARE @Parentuser_name VARCHAR(100)    
  DECLARE @user_login VARCHAR(100)    
  DECLARE @user_name VARCHAR(100)    
    
  SELECT @Parentuser_login = user_login    
   ,@Parentuser_name = (FName + ' ' + LName)    
  FROM User_Detail(nolock)
  WHERE User_Id = @ParentId and Status=1   
    
  SELECT @user_login = user_login    
   ,@user_name = (FName + ' ' + LName)    
  FROM User_Detail(nolock)
  WHERE User_Id = @UserId  and Status=1   
    
  CREATE TABLE #TableData2 (    
   [user_id] BIGINT    
   ,team_name VARCHAR(100)    
   ,user_login VARCHAR(100)    
   ,username VARCHAR(100)    
   ,[parentid] BIGINT    
   )    
    
  IF EXISTS (    
    SELECT 1    
    FROM tbl_UA_UserHierarchy(nolock)
    WHERE ParentId = @ParentId and IsActive=1    
    )    
  BEGIN    
   SELECT @HierarchyJSON = HierarchyJSON    
   FROM tbl_UA_UserHierarchy(nolock)   
   WHERE ParentId = @ParentId and IsActive=1
    
   INSERT INTO #TableData2 (    
    [user_id]    
    ,team_name    
    ,user_login    
    ,username    
    ,[parentid]    
    )    
   SELECT [user_id]    
    ,''    
    ,user_login    
    ,username    
    ,[parentid]    
   FROM OPENJSON(@HierarchyJSON) WITH (    
     [user_id] BIGINT    
     ,user_login VARCHAR(100)    
     ,username VARCHAR(100)    
     ,[parentid] BIGINT    
     )    
    
   INSERT INTO #TableData2 (    
    [user_id]    
    ,team_name    
    ,user_login    
    ,username    
    ,[parentid]    
    )    
   SELECT @UserId    
    ,''    
    ,@user_login    
    ,@user_name    
    ,@ReportTo    
    
   SET @HierarchyJSON = (    
     SELECT *    
     FROM #TableData2    
     FOR JSON AUTO    
     )    
    
   UPDATE tbl_UA_UserHierarchy    
   SET HierarchyJSON = @HierarchyJSON    
    ,ModifiedBy = @CreatedBy    
    ,ModifiedDate = GETDATE()    
   WHERE ParentId = @ParentId and IsActive=1 
    
   DROP TABLE #TableData2    
    
   SELECT 'Record Updated' STATUS    
    ,@ParentId ParentId    
    
   SET @rowJson = (    
     SELECT *    
     FROM tbl_UA_UserHierarchy(nolock)
     WHERE ParentId = @ParentId and IsActive=1
     FOR JSON AUTO    
      ,INCLUDE_NULL_VALUES    
     )    
   SET @activity = 'Updt_usrhrrc'    
   SET @action = 'U'    
  END    
  ELSE    
  BEGIN    
   INSERT INTO #TableData2 (    
    [user_id]    
    ,team_name    
    ,user_login    
    ,username    
    ,[parentid]    
    )    
   SELECT @ParentId    
    ,''    
    ,@Parentuser_login    
    ,@Parentuser_name    
    ,0    
    
   INSERT INTO #TableData2 (    
    [user_id]    
    ,team_name    
    ,user_login    
    ,username    
    ,[parentid]    
    )    
   SELECT @UserId    
    ,''    
    ,@user_login    
    ,@user_name    
    ,@ReportTo    
    
   SET @HierarchyJSON = (    
     SELECT *    
     FROM #TableData2    
     FOR JSON AUTO    
     )    
    
   INSERT INTO tbl_UA_UserHierarchy (    
    ParentId    
    ,HierarchyJSON    
    ,CreatedBy    
    ,CreatedDate    
    ,ModifiedBy    
    ,ModifiedDate    
    )    
   VALUES (    
    @ParentId    
    ,@HierarchyJSON    
    ,@CreatedBy    
    ,GETDATE()    
    ,@CreatedBy    
    ,GETDATE()    
    )    
    
   DROP TABLE #TableData2    
    
   SELECT 'Record Saved' STATUS    
    ,@ParentId ParentId    
    
   SET @rowJson = (    
     SELECT *    
     FROM tbl_UA_UserHierarchy    
     WHERE ParentId = @ParentId    
     FOR JSON AUTO    
      ,INCLUDE_NULL_VALUES    
     )    
   SET @activity = 'Inst_usrhrrc'    
   SET @action = 'I'    
  END    
 END    
END TRY    
    
BEGIN CATCH    
 DECLARE @ErrorMessage NVARCHAR(4000);    
    
 SELECT @ErrorMessage = ERROR_MESSAGE();    
    
 RAISERROR (    
   @ErrorMessage    
   ,16    
   ,1    
   );    
END CATCH    
    
IF @rowJson IS NOT NULL    
BEGIN    
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId    
  ,@Activity_type = @activity    
  ,@ActionType = @action    
  ,@RowJson = @rowJson    
  ,@Table_name = 'tbl_UA_UserHierarchy'    
END    



GO

/* ============================================================
   Procedure: [dbo].[usp_tbl_UA_UserRoleMappingMaster]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


  --Exec usp_tbl_UA_UserRoleMappingMaster @Mode='SR',@UserId=32222  
  --Exec usp_tbl_UA_UserRoleMappingMaster @Mode='S',@UserId=32222  
  --Exec usp_tbl_UA_UserRoleMappingMaster @Mode='D',@RoleCode='SYS_GUEST',@UserId=32222  
CREATE   PROCEDURE [dbo].[usp_tbl_UA_UserRoleMappingMaster]  
(      
 @Mode VARCHAR(2)      
 ,@UserRoleMappingId BIGINT = 0      
 ,@UserRoleMappingCode VARCHAR(50) = NULL      
 ,@RoleName VARCHAR(50) = NULL      
 ,@RoleCode VARCHAR(50) = NULL      
 ,@UserCodeList VARCHAR(4000) = NULL      
 ,@ParentId BIGINT = 0      
 ,@Active BIT = 0      
 ,@UserId BIGINT = 0      
 ,@FilterText NVARCHAR(MAX)=NULL      
 )      
AS      
SET NOCOUNT ON      

--declare
--	@Mode VARCHAR(2) = N'EN',
--	@UserRoleMappingId BIGINT = 0,
--	@UserRoleMappingCode VARCHAR(50) = NULL,
--	@RoleName VARCHAR(50) = NULL,
--	@RoleCode VARCHAR(50) = N'SYS_ADMIN',
--	@UserCodeList VARCHAR(4000) = '',
--	@ParentId BIGINT = 0,
--	@Active BIT = 0,
--	@UserId BIGINT = 46622,
--	@FilterText NVARCHAR(MAX)=NULL      
      
DECLARE @activity VARCHAR(MAX) = ''      
 ,@action VARCHAR(1) = ''      
 ,@rowJson NVARCHAR(MAX) = ''      
      
BEGIN TRY      
 IF (@Mode = 'I') /*This is for Insert TBL_UA_UserRoleMappingMaster Details */      
 BEGIN      
  SELECT @ParentId = ParentId      
  FROM User_detail      
  WHERE [User_Id] = @UserId      
      
  DELETE TBL_UA_UserRoleMappingMaster      
  WHERE [UserId] IN (      
    SELECT item      
    FROM dbo.fu_SplitString(@UserCodeList, ',')      
    )      
      
  DELETE TBL_UA_UserRoleMappingMaster      
  WHERE ParentId = @ParentId      
   AND userId IN (      
    SELECT item      
    FROM dbo.fu_SplitString(@UserCodeList, ',')      
    )      
      
  INSERT INTO TBL_UA_UserRoleMappingMaster (      
   UserRoleMappingCode      
   ,RoleCode      
   ,ParentId      
   ,UserId      
   ,Active      
   ,CreatedBy      
   ,CreatedDate      
   )      
  SELECT (@RoleCode + '_' + Cast(@ParentId AS VARCHAR(10)) + '_' + Cast(item AS VARCHAR(10)))      
   ,@RoleCode      
   ,@ParentId      
   ,item      
   ,@Active      
   ,@UserId      
   ,GETDATE()      
  FROM dbo.fu_SplitString(@UserCodeList, ',') aa      
  WHERE item != 1      
      
  DECLARE @ID BIGINT = SCOPE_IDENTITY()      
      
  SELECT 'Record Saved' STATUS      
   ,@UserRoleMappingCode AS Code      
      
  SET @rowJson = (      
    SELECT *      
    FROM TBL_UA_UserRoleMappingMaster WITH (NOLOCK)      
    WHERE UserRoleMappingId = @ID      
    FOR JSON AUTO      
     ,INCLUDE_NULL_VALUES      
    )      
  SET @activity = 'Inst_usrrole_mapp'      
  SET @action = 'I'      
 END      
 ELSE IF (@Mode = 'S') /*This is for List of TBL_UA_UserRoleMappingMaster Details */      
 BEGIN      
  SELECT @ParentId = ParentId      
  FROM User_detail      
  WHERE [User_Id] = @UserId      
      
  SELECT DISTINCT rm.RoleCode      
   ,RoleName      
   ,(      
    SELECT count(UserId)      
    FROM TBL_UA_UserRoleMappingMaster urmm1      
    WHERE (      
      urmm1.RoleCode = rm.RoleCode      
      AND urmm1.ParentId = @ParentId     
   and isnull(urmm1.Active,1) = 1    
      )      
     OR (      
      urmm1.RoleCode = rm.RoleCode      
      AND urmm1.ParentId = rm.ParentId      
      and isnull(urmm1.Active,1) = 1    
   )      
    ) UsersCount      
   ,isnull(STUFF((      
      SELECT DISTINCT ',' + udl1.User_Login      
      FROM TBL_UA_UserRoleMappingMaster urmm1      
      INNER JOIN User_Detail udl1 ON udl1.User_Id = urmm1.UserId      
      WHERE (      
        urmm1.RoleCode = rm.RoleCode      
        AND urmm1.ParentId = @ParentId      
        and isnull(urmm1.Active,1) = 1    
  )      
       OR (      
        urmm1.RoleCode = rm.RoleCode      
        AND urmm1.ParentId = rm.ParentId      
        and isnull(urmm1.Active,1) = 1    
  )      
      FOR XML PATH('')      
      ), 1, 1, ''), '') UserNames      
   ,CASE       
    WHEN urmm.CreatedBy IS NULL      
     THEN 0      
    ELSE urmm.CreatedBy      
    END CreatedBy      
   ,CASE       
    WHEN udl.User_Login IS NULL      
     THEN ''      
    ELSE udl.User_Login      
    END CreatedUser      
  FROM VW_SystemRole_RoleMaster rm --tbl_UA_RoleMaster rm                   
  LEFT JOIN TBL_UA_UserRoleMappingMaster urmm ON urmm.RoleCode = rm.RoleCode      
   AND urmm.ParentId = @ParentId and isnull(urmm.Active,1) = 1      
  LEFT JOIN User_Detail udl ON udl.User_Id = urmm.CreatedBy      
  WHERE rm.RoleId IN (      
    4      
    ,9,10      
    )      
   OR rm.ParentId = @ParentId      
   AND(@FilterText IS NULL OR RoleName LIKE '%'+@FilterText+'%')      
  SET @activity = 'View_usrrole_mapp'      
  SET @action = 'S'      
 END /*End here for list ,10 */      
 ELSE IF (@Mode = 'E') /*This is for TBL_UA_UserRoleMappingMaster Details */      
 BEGIN      
  SELECT RoleId      
   ,RoleName      
   ,rm.RoleCode      
   ,UserId      
  FROM TBL_UA_UserRoleMappingMaster urmm      
  INNER JOIN VW_SystemRole_RoleMaster rm ON rm.RoleCode = urmm.RoleCode      
  WHERE urmm.RoleCode = @RoleCode      
 END /*End here for list*/      
 ELSE IF (@Mode = 'EN') /*This is for TBL_UA_UserRoleMappingMaster Details */      
 BEGIN      
  SELECT @ParentId = ParentID      
  FROM User_Detail      
  WHERE User_ID = @UserId      
      
	SELECT *      
		FROM (      
		SELECT User_Id UserId      
		,ud.User_Login      
		,ud.ParentId      
		,rm.RoleCode      
		,rm.RoleName      
		,ud.User_Login + ' (' + ud.FName + ' ' + ud.LName + ')' AS User_Login_And_Name      
	FROM User_Detail ud      
	LEFT JOIN TBL_UA_UserRoleMappingMaster urmml ON ud.User_Id = urmml.UserId      
	LEFT JOIN VW_SystemRole_RoleMaster rm ON urmml.RoleCode = rm.RoleCode      
	WHERE ud.ParentId = @ParentId AND  rm.RoleCode = @RoleCode
   UNION       
   SELECT User_Id UserId      
    ,udd.User_Login      
    ,udd.ParentId      
    ,'' RoleCode      
    ,'' RoleName      
    ,udd.User_Login + ' (' + udd.FName + ' ' + udd.LName + ')' AS User_Login_And_Name      
   FROM User_Detail udd      
   WHERE udd.ParentId = @ParentId      
    AND udd.User_Id NOT IN (      
     SELECT UserId      
     FROM TBL_UA_UserRoleMappingMaster urmml      
     WHERE urmml.ParentId = @ParentId
     )      
	 union 
	 SELECT User_Id UserId      
		,ud.User_Login      
		,ud.ParentId      
		, '' as RoleCode      
		,'' as RoleName      
		,ud.User_Login + ' (' + ud.FName + ' ' + ud.LName + ')' AS User_Login_And_Name      
	FROM User_Detail ud      
	LEFT JOIN TBL_UA_UserRoleMappingMaster urmml ON ud.User_Id = urmml.UserId      
	LEFT JOIN VW_SystemRole_RoleMaster rm ON urmml.RoleCode = rm.RoleCode      
	WHERE ud.User_ID = @ParentId and @RoleCode = 'SYS_ADMIN' and rm.RoleCode is null

   ) t      
  ORDER BY RoleCode DESC      

  

 END /*End here for details*/      
 ELSE IF (@Mode = 'U') /*This is for Update TBL_UA_UserRoleMappingMaster Details */      
 BEGIN      
  SELECT @ParentId = ParentId      
  FROM User_detail      
  WHERE [User_Id] = @UserId      
      
  DELETE TBL_UA_UserRoleMappingMaster      
  WHERE [UserId] IN (      
    SELECT item      
    FROM dbo.fu_SplitString(@UserCodeList, ',')      
    )      
      
  DELETE TBL_UA_UserRoleMappingMaster      
  WHERE RoleCode = @RoleCode      
   AND ParentId = @ParentId      
      
  INSERT INTO TBL_UA_UserRoleMappingMaster (      
   UserRoleMappingCode      
   ,RoleCode      
   ,ParentId      
   ,UserId      
   ,Active      
   ,CreatedBy      
   ,CreatedDate      
   )      
  SELECT (@RoleCode + '_' + Cast(@ParentId AS VARCHAR(20)) + '_' + Cast(item AS VARCHAR(20)))      
   ,@RoleCode      
   ,@ParentId      
   ,cast(item AS BIGINT)      
   ,@Active      
   ,@UserId      
   ,GETDATE()      
  FROM dbo.fu_SplitString(@UserCodeList, ',') aa      
  WHERE item != 1      
      
  SELECT 'Record Updated'      
   ,Cast(@UserId AS VARCHAR) UserId      
      
  --  delete tbl_UA_RoleMaster where ParentId = @ParentId and RoleCode not in (Select RoleCode from TBL_UA_UserRoleMappingMaster)                   
  SET @rowJson = (      
    SELECT *      
    FROM TBL_UA_UserRoleMappingMaster WITH (NOLOCK)      
    WHERE RoleCode = @RoleCode      
     AND ParentId = @ParentId      
    FOR JSON AUTO      
     ,INCLUDE_NULL_VALUES      
    )      
  SET @activity = 'Updt_usrrole_mapp'      
  SET @action = 'U'      
   --  delete tbl_UA_RoleMaster where ParentId = @ParentId and RoleCode not in (Select RoleCode from TBL_UA_UserRoleMappingMaster)                     
 END /*End here for details*/      
 ELSE IF (@Mode = 'D') /*This is for TBL_UA_UserRoleMappingMaster delete Row */      
 BEGIN      
   SELECT @ParentId = ParentId      
  FROM User_detail(nolock)
  WHERE [User_Id] = @UserId      

 SET @rowJson = (      
    SELECT *      
    FROM TBL_UA_UserRoleMappingMaster WITH (NOLOCK)      
    WHERE RoleCode = @RoleCode      
     AND ParentId = @ParentId      
    FOR JSON AUTO      
     ,INCLUDE_NULL_VALUES      
    )      
      
  DELETE TBL_UA_UserRoleMappingMaster      
  WHERE RoleCode = @RoleCode AND ParentId = @ParentId  
      
  --update TBL_UA_RoleMaster set Active = 0 where RoleCode in (select RoleCode from TBL_UA_UserRoleMappingMaster where  UserRoleMappingId = @UserRoleMappingId)                   
  SELECT 'Record Delete' STATUS, @@ROWCOUNT AS ID      
      
  SET @activity = 'Delt_usrrole_mapp'      
  SET @action = 'D'      
 END /*End here for details*/      
 ELSE IF (@Mode = 'SR') /*This is for List of TBL_UA_UserRoleMappingMaster Details */      
 BEGIN      
  SELECT @ParentId = ParentID      
  FROM User_Detail      
  WHERE User_ID = @UserId      
      
  SELECT DISTINCT User_Id UserId      
   ,ud.User_Login      
   ,ud.ParentId      
   ,isnull(urmml.RoleCode, '') RoleCode      
   ,isnull(rm.RoleName, '') RoleName      
   ,ud.IsAdmin      
  FROM User_Detail ud      
  LEFT JOIN TBL_UA_UserRoleMappingMaster urmml ON urmml.UserId = ud.User_Id      
  LEFT JOIN VW_SystemRole_RoleMaster rm ON rm.RoleCode = urmml.RoleCode      
  WHERE ud.ParentId = @ParentId      
 END      
END TRY      
      
BEGIN CATCH      
 DECLARE @ErrorMessage NVARCHAR(4000);      
      
 SELECT @ErrorMessage = ERROR_MESSAGE();      
      
 RAISERROR (      
   @ErrorMessage      
   ,16      
   ,1      
   );      
END CATCH      
      
IF @rowJson IS NOT NULL      
BEGIN      
 EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @Userid      
  ,@Activity_type = @activity      
  ,@ActionType = @action      
  ,@RowJson = @rowJson      
  ,@Table_name = 'TBL_UA_RoleMaster'      
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_tbl_UA_UserRoleMappingMaster_Login]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_tbl_UA_UserRoleMappingMaster_Login]  
(   
 @UserId bigint = 0,  
 @RoleId int = 0  
 )   
AS   
  SET NOCOUNT ON   
  BEGIN TRY   
  Declare @RoleCode varchar(50)  
  Declare @ParentId bigint = 0   
  
   select @RoleCode = RoleCode from Tbl_UA_RoleMaster (nolock) where RoleId = @RoleId  
   select @ParentId = ParentId from User_detail (nolock) where [User_Id] = @UserId   
  
   insert into TBL_UA_UserRoleMappingMaster(UserRoleMappingCode, RoleCode, ParentId, UserId, Active, CreatedBy, CreatedDate)   
   values((@RoleCode + '_'+ Cast(@ParentId as varchar(10)) + '_' + Cast(@UserId as varchar(10))), @RoleCode, @ParentId, @UserId, 1,   
   @UserId, GETDATE())   
  
  Select 'Record Saved' Status  
 END TRY   
BEGIN CATCH   
   
 DECLARE @ErrorMessage NVARCHAR(4000);   
 SELECT @ErrorMessage = ERROR_MESSAGE();   
 RAISERROR (@ErrorMessage, 16, 1);   
END CATCH   


