    )    
   
   DECLARE @UserCodeTable TABLE (UserCode VARCHAR(MAX));
DECLARE @PeerViewTable TABLE (PeerViewId VARCHAR(MAX));

-- Insert split values into the respective table variables
INSERT INTO @UserCodeTable
SELECT item
