    WHERE RoleCode = @RoleCode      
     AND ParentId = @ParentId      
    FOR JSON AUTO      
     ,INCLUDE_NULL_VALUES      
    )    

   DELETE TBL_UA_UserRoleMappingMaster WHERE cast(RoleCode as varchar(20)) = cast(@RoleCode as varchar(20)) and ParentId = @ParentId  

  --update TBL_UA_RoleMaster set Active = 0 where RoleCode in (select RoleCode from TBL_UA_UserRoleMappingMaster where  UserRoleMapp2ingId = @UserRoleMappingId)                 
