/* ============================================================
   Procedure: [dbo].[usp_tbl_WA_InsertRuleSeqWise]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_tbl_WA_InsertRuleSeqWise] 
(
@RuleIdSeqWise nvarchar(max)=''
)
as
begin


SELECT ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) AS SerialNumber,
       value AS Value
into #temp FROM STRING_SPLIT(@RuleIdSeqWise, ',');

UPDATE a
SET a.SeqNumber = b.SerialNumber
FROM tbl_WA_RuleMaster a
JOIN #temp b ON a.RuleId = b.Value;
SELECT 'Saved Successfully.' [Status]

end




GO

/* ============================================================
   Procedure: [dbo].[usp_tblcustomButton]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_tblcustomButton]  
    @UserID BIGINT,  
    @ButtonText NVARCHAR(100) = NULL  
AS  
BEGIN  
    SET NOCOUNT ON;  
   DECLARE @ParentId BIGINT;  
    BEGIN TRY  
	 SELECT @ParentId = ParentID
        FROM User_Detail (NOLOCK)  
        WHERE User_ID = @UserId;
        SELECT  
            cb.ButtonId,  
            cb.ButtonName,  
   cb.ButtonDescription,  
  
            cb.PlaceOnPage,  
    mm.ModuleName,  
            cb.ActionBePerform,  
   cb.ActionDetails,  
   cb.ButtonDisposition,  
   cb.UserType  
             
        FROM  
            tbl_CB_CustomButtons cb  
        INNER JOIN  
            TBL_UA_ModuleMaster mm ON cb.ModuleCode = mm.ModuleCode  
        WHERE  
            cb.IsActive = 1  and cb.ParentId=@ParentId
              
            AND (  
                @ButtonText IS NULL OR  
                cb.ButtonName LIKE '%' + @ButtonText + '%' OR  
                mm.ModuleName LIKE '%' + @ButtonText + '%'  
            ) order by ButtonId desc  
    END TRY  
    BEGIN CATCH  
         exec usp_InsertErrorInfo  
    END CATCH  
END



GO

/* ============================================================
   Procedure: [dbo].[usp_tblcustomButtonDetailsById]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


------------------------

CREATE   PROCEDURE usp_tblcustomButtonDetailsById  
    @UserID BIGINT,  
    @ButtonId BIGINT = NULL  
AS  
BEGIN  
    SET NOCOUNT ON;  
  
    BEGIN TRY  
        SELECT  
            cb.ButtonId,  
            cb.ButtonName,  
            cb.ButtonDescription,  
            cb.PlaceOnPage,  
            mm.ModuleName,  
            cb.ActionBePerform,  
            cb.ActionDetails,  
            cb.ButtonDisposition  
        FROM  
            tbl_CB_CustomButtons cb  
        INNER JOIN  
            TBL_UA_ModuleMaster mm ON cb.ModuleCode = mm.ModuleCode  
        WHERE  
            cb.IsActive = 1  
            AND (  
                @ButtonId IS NULL OR  
                cb.ButtonId = @ButtonId  
            )  
        ORDER BY  
            ButtonId DESC;  
    END TRY  
    BEGIN CATCH  
        DECLARE @ErrorMessage NVARCHAR(MAX);  
        DECLARE @ErrorNumber INT, @ErrorSeverity INT, @ErrorState INT, @ErrorLine INT, @ErrorProcedure NVARCHAR(128);  
  
        SELECT   
            @ErrorNumber = ERROR_NUMBER(),  
            @ErrorSeverity = ERROR_SEVERITY(),  
            @ErrorState = ERROR_STATE(),  
            @ErrorLine = ERROR_LINE(),  
            @ErrorProcedure = ISNULL(ERROR_PROCEDURE(), '-');  
  
        SET @ErrorMessage = FORMATMESSAGE(  
            'Error %d, Severity %d, State %d, Procedure %s, Line %d: %s.',  
            @ErrorNumber, @ErrorSeverity, @ErrorState, @ErrorProcedure, @ErrorLine, ERROR_MESSAGE()  
        );  
  
        -- Optionally, print the error message (useful for debugging)  
        PRINT @ErrorMessage;  
  
        -- Rethrow the error to the calling application  
        THROW;  
    END CATCH  
END




GO

/* ============================================================
   Procedure: [dbo].[usp_tblcustomButtonUpdate]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


---------------------------------------------

CREATE   PROCEDURE usp_tblcustomButtonUpdate  
    @UserID BIGINT,  
    @ButtonId BIGINT,  
    @ButtonName NVARCHAR(100) = NULL,  
    @PlaceOnPage NVARCHAR(100) = NULL,  
    @ActionBePerform NVARCHAR(100) = NULL,  
    @ModuleName NVARCHAR(100) = NULL  
AS  
BEGIN  
    SET NOCOUNT ON;  
  
    BEGIN TRY  
        -- Update the record in the tbl_CB_CustomButtons table  
        UPDATE tbl_CB_CustomButtons  
        SET   
            ButtonName = ISNULL(@ButtonName, ButtonName),  
            PlaceOnPage = ISNULL(@PlaceOnPage, PlaceOnPage),  
            ActionBePerform = ISNULL(@ActionBePerform, ActionBePerform),  
            ModuleCode = (SELECT ModuleCode FROM TBL_UA_ModuleMaster WHERE ModuleName = @ModuleName)  
        WHERE   
            ButtonId = @ButtonId  
            AND UserId = @UserID;  
  
        -- Check if any row was updated  
        IF @@ROWCOUNT = 0  
        BEGIN  
            RAISERROR('No matching record found or no changes made.', 16, 1);  
        END  
    END TRY  
    BEGIN CATCH  
        DECLARE @ErrorMessage NVARCHAR(MAX);  
        DECLARE @ErrorNumber INT, @ErrorSeverity INT, @ErrorState INT, @ErrorLine INT, @ErrorProcedure NVARCHAR(128);  
  
        SELECT   
            @ErrorNumber = ERROR_NUMBER(),  
            @ErrorSeverity = ERROR_SEVERITY(),  
            @ErrorState = ERROR_STATE(),  
            @ErrorLine = ERROR_LINE(),  
            @ErrorProcedure = ISNULL(ERROR_PROCEDURE(), '-');  
  
        SET @ErrorMessage = FORMATMESSAGE(  
            'Error %d, Severity %d, State %d, Procedure %s, Line %d: %s.',  
            @ErrorNumber, @ErrorSeverity, @ErrorState, @ErrorProcedure, @ErrorLine, ERROR_MESSAGE()  
        );  
  
        -- Optionally, print the error message (useful for debugging)  
        PRINT @ErrorMessage;  
  
        -- Rethrow the error to the calling application  
        THROW;  
    END CATCH  
END




GO

/* ============================================================
   Procedure: [dbo].[usp_tblEnquiryStage]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_tblEnquiryStage]    
    @ParentID BIGINT    
AS    
BEGIN    
    SET NOCOUNT ON;    
    
    BEGIN TRY    
        -- Create a temporary table to hold the results    
        DECLARE @ResultTable TABLE (    
            StageID BIGINT,    
            StageName NVARCHAR(100),    
            SequenceNo INT,    
            [Conditions] NVARCHAR(255), -- Increase the size to accommodate multiple conditions    
            ParentID BIGINT    
        );    
    
        -- Insert the query results into the temporary table    
        INSERT INTO @ResultTable (StageID, StageName, SequenceNo, [Conditions], ParentID)    
        SELECT    
            cb.StageID,    
            cb.StageName,    
            cb.SequenceNo,    
            -- Construct the Conditions field by concatenating active conditions    
            COALESCE(    
                CASE WHEN cb.EnquiryAttributes = 1 THEN 'Enquiry Attribute' ELSE NULL END, '') +    
            COALESCE(    
                CASE WHEN cb.BasedOnScore = 1 THEN     
                    CASE WHEN cb.EnquiryAttributes = 1 THEN ', ' ELSE '' END + 'Based On Score' ELSE NULL END, '') +    
            COALESCE(    
                CASE WHEN cb.CompletingChecklist = 1 THEN     
                    CASE WHEN cb.EnquiryAttributes = 1 OR cb.BasedOnScore = 1 THEN ', ' ELSE '' END + 'Completing Checklist' ELSE NULL END,     
            'No Active Conditions') AS [Conditions],    
            cb.ParentID    
        FROM    
            tbl_enquiry_stage cb    
        WHERE    
            cb.IsActive = 1 AND cb.ParentID = @ParentID;    
    
        -- Check if the temporary table is empty    
        IF NOT EXISTS (SELECT 1 FROM @ResultTable)    
        BEGIN    
            -- If no records are found, insert a default record    
            INSERT INTO @ResultTable (StageID, StageName, SequenceNo, [Conditions], ParentID)    
            VALUES (0, 'Default Stage', 0, 'No Active Conditions', 0);    
        END    
    
        -- Select the results from the temporary table    
        SELECT * FROM @ResultTable;    
    
    END TRY    
    BEGIN CATCH    
        -- Log the error using the error logging procedure    
        EXEC usp_InsertErrorInfo;    
    
    END CATCH    
END;    


GO

/* ============================================================
   Procedure: [dbo].[usp_tc_compaignerror]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_tc_compaignerror]  
    @tid BIGINT,  
 @UserId BIGINT,  
    @OffsetValue INT = 0,  
    @PagingSize INT = 100  
AS  
BEGIN  
  
 --declare  
 -- @tid BIGINT = 12,  
 -- @UserId BIGINT =   34594,  
 -- @OffsetValue INT = 0,  
 -- @PagingSize INT = 100  
  
    DECLARE @eventid INT;  
    SELECT @eventid = eventid FROM triggeredcampaigns WITH (NOLOCK) WHERE id = @tid;  
 DECLARE @ParentID BIGINT = 0  
  
 SELECT TOP 1 @ParentID = isnull(ParentID, User_ID)  
 FROM User_Detail(NOLOCK)  
 WHERE User_ID = @UserID  
  
 declare @StartPoint int = @OffsetValue + 1, @EndPoint int  = (@OffsetValue + @PagingSize )  
  
    IF @eventid NOT IN (680, 681)    
    BEGIN    
          
  SELECT * FROM (  
   SELECT   
    ROW_NUMBER() OVER( PARTITION BY (select null) order by s.id desc)as [SNo],  
    COUNT(1) over() as [TotalRow],  
    Format(s.scheduledfor, 'dd-MMM-yyyy HH:mm') AS [ActivityDate], -- dd-MMM-yyyy HH:mm   
    t.cname AS [TriggeredName],  
    s.scheduledaction AS [Medium],  
    Format(COALESCE(s.processedat, s.createdon), 'dd-MMM-yyyy HH:mm') AS [ProcessedDate],  
    s.s_errormessage AS [ErrorDescription],  
    dbo.udf_ims_GetAssoisatedEntityProfile(  
     am.context,   
     CASE WHEN am.context = 'enquiry' THEN eh.EnquiryID ELSE lh.LeadID END  
    ) AS [EntityDetails]  
   FROM scheduledtodos s WITH (NOLOCK)    
   INNER JOIN triggeredcampaigns t WITH (NOLOCK) ON    
    s.parentid = t.parentid  
    and ((s.tcampaignid IN (t.smscampaignid, t.mailcampaignid, t.voicecampaignid, t.whatsappcampaignid) AND s.scheduledaction = 'campaign')    
    OR (s.scheduledaction = 'AutomationRules' AND s.eventid = t.eventid))    
   INNER JOIN ActivityMaster (NOLOCK) am ON s.eventid = am.ID  
   LEFT JOIN tbl_EnquiryEventHistory (NOLOCK) eh ON am.context = 'enquiry' AND s.activityid = eh.HistoryID  
   LEFT JOIN tbl_LeadEventHistory (NOLOCK) lh ON am.context = 'lead' AND s.activityid = lh.HistoryID  
   WHERE t.id = @tid   
  ) t where t.SNo between @StartPoint and @EndPoint  
    
    END    
    ELSE    
    BEGIN    
  SELECT * FROM (  
    SELECT   
     ROW_NUMBER() OVER( PARTITION BY (select null) order by s.id desc)as [SNo],  
     COUNT(1) over() as [TotalRow],  
    Format(s.scheduledfor, 'dd-MMM-yyyy HH:mm') AS [ActivityDate],  
    t.cname AS [TriggeredName],  
    s.scheduledaction AS [Medium],  
    Format(COALESCE(s.processedat, s.createdon), 'dd-MMM-yyyy HH:mm') AS [ProcessedDate],  
    s.s_errormessage AS [ErrorDescription],  
    dbo.udf_ims_GetAssoisatedEntityProfile(  
     am.context,   
     CASE WHEN am.context = 'enquiry' THEN eh.EnquiryID ELSE lh.LeadID END  
    ) AS [EntityProfile]  
   FROM scheduledtodos s WITH (NOLOCK)    
   INNER JOIN triggeredcampaigns t WITH (NOLOCK) ON    
    s.parentid = t.parentid  
    and  ((s.tcampaignid IN (t.smscampaignid, t.mailcampaignid, t.voicecampaignid, t.whatsappcampaignid)) AND s.scheduledaction = 'tcampaign')   
   INNER JOIN ActivityMaster (NOLOCK) am ON s.eventid = am.ID  
   LEFT JOIN tbl_EnquiryEventHistory (NOLOCK) eh ON am.context = 'enquiry' AND s.activityid = eh.HistoryID  
   LEFT JOIN tbl_LeadEventHistory (NOLOCK) lh ON am.context = 'lead' AND s.activityid = lh.HistoryID  
   WHERE t.id = @tid   
  ) t where t.SNo between @StartPoint and @EndPoint  
    END;  
END  


GO

/* ============================================================
   Procedure: [dbo].[usp_tc_compaignerror_new]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_tc_compaignerror_new]  
    @tid BIGINT,  
 @UserId BIGINT,  
    @OffsetValue INT = 0,  
    @PagingSize INT = 100  
AS  
BEGIN  
  
 --declare  
 -- @tid BIGINT = 12,  
 -- @UserId BIGINT =   34594,  
 -- @OffsetValue INT = 0,  
 -- @PagingSize INT = 100  
  
    DECLARE @eventid INT;  
    SELECT @eventid = eventid FROM triggeredcampaigns WITH (NOLOCK) WHERE id = @tid;  
 DECLARE @ParentID BIGINT = 0  
  
 SELECT TOP 1 @ParentID = isnull(ParentID, User_ID)  
 FROM User_Detail(NOLOCK)  
 WHERE User_ID = @UserID  
  
 declare @StartPoint int = @OffsetValue + 1, @EndPoint int  = (@OffsetValue + @PagingSize )  
  
    IF @eventid NOT IN (680, 681)    
    BEGIN    
          
  SELECT * FROM (  
   SELECT   
    ROW_NUMBER() OVER( PARTITION BY (select null) order by s.id desc)as [SNo],  
    COUNT(1) over() as [TotalRow],  
    Format(s.scheduledfor, 'dd-MMM-yyyy HH:mm') AS [ActivityDate], -- dd-MMM-yyyy HH:mm   
    t.cname AS [TriggeredName],  
    case when s.scheduledaction='Campaign' then ucm.Medium else 'Sequence' end AS [Medium],  
    Format(COALESCE(s.processedat, s.createdon), 'dd-MMM-yyyy HH:mm') AS [ProcessedDate],  
    s.s_errormessage AS [ErrorDescription],  
    dbo.udf_ims_GetAssoisatedEntityProfile(  
     am.context,   
     CASE WHEN am.context = 'enquiry' THEN eh.EnquiryID ELSE lh.LeadID END  
    ) AS [EntityDetails]  
   FROM scheduledtodos s WITH (NOLOCK)    
   INNER JOIN triggeredcampaigns t WITH (NOLOCK) ON    
    s.parentid = t.parentid  
    and ((s.tcampaignid IN (t.smscampaignid, t.mailcampaignid, t.voicecampaignid, t.whatsappcampaignid) AND s.scheduledaction = 'campaign')    
    OR (s.scheduledaction = 'AutomationRules' AND s.eventid = t.eventid))    
   INNER JOIN ActivityMaster (NOLOCK) am ON s.eventid = am.ID  
   left join UserCampaignMaster (nolock) ucm on ucm.id in (t.smscampaignid,t.mailcampaignid,t.whatsappcampaignid,t.voicecampaignid)
   LEFT JOIN tbl_EnquiryEventHistory (NOLOCK) eh ON am.context = 'enquiry' AND s.activityid = eh.HistoryID  
   LEFT JOIN tbl_LeadEventHistory (NOLOCK) lh ON am.context = 'lead' AND s.activityid = lh.HistoryID  

   WHERE t.id = @tid and ltrim(s.s_errormessage) not like 'No active sequence%' and ltrim(s.s_errormessage) not like 'Parent %'       
  ) t where t.SNo between @StartPoint and @EndPoint  
    
    END    
    ELSE    
    BEGIN    
  SELECT * FROM (  
    SELECT   
     ROW_NUMBER() OVER( PARTITION BY (select null) order by s.id desc)as [SNo],  
     COUNT(1) over() as [TotalRow],  
    Format(s.scheduledfor, 'dd-MMM-yyyy HH:mm') AS [ActivityDate],  
    t.cname AS [TriggeredName],  
    case when s.std_sequenceid=0 then 'Campaign' when s.std_trgid=0 then 'Sequence'  else 'Campaigns and Sequence' end AS [Medium],  
    Format(COALESCE(s.processedat, s.createdon), 'dd-MMM-yyyy HH:mm') AS [ProcessedDate],  
    s.s_errormessage AS [ErrorDescription],  
    dbo.udf_ims_GetAssoisatedEntityProfile(  
     am.context,   
     CASE WHEN am.context = 'enquiry' THEN eh.EnquiryID ELSE lh.LeadID END  
    ) AS [EntityProfile]  
   FROM scheduledtodos s WITH (NOLOCK)    
   INNER JOIN triggeredcampaigns t WITH (NOLOCK) ON    
    s.parentid = t.parentid  
    and  (s.std_trgid=t.id
	--(s.tcampaignid IN (t.smscampaignid, t.mailcampaignid, t.voicecampaignid, t.whatsappcampaignid)) 
	AND s.scheduledaction = 'tcampaign')   
   INNER JOIN ActivityMaster (NOLOCK) am ON s.eventid = am.ID  
     -- left join UserCampaignMaster (nolock) ucm on ucm.id in (t.smscampaignid,t.mailcampaignid,t.whatsappcampaignid,t.voicecampaignid)
   LEFT JOIN tbl_EnquiryEventHistory (NOLOCK) eh ON am.context = 'enquiry' AND s.activityid = eh.HistoryID  
   LEFT JOIN tbl_LeadEventHistory (NOLOCK) lh ON am.context = 'lead' AND s.activityid = lh.HistoryID  
   WHERE t.id = @tid   
  ) t where t.SNo between @StartPoint and @EndPoint  
    END;  
END  


GO

/* ============================================================
   Procedure: [dbo].[usp_tc_KycOperationsByMod]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_tc_KycOperationsByMod](
     @KYCId int = 0,
     @UserId bigint,    
     @Payload nvarchar(max), 
     @Mode nvarchar(50)
 )
AS
BEGIN
    
    --DECLARE 
    --    @KYCId int = 1,
    --    @UserId bigint = 335,
    --    @Payload nvarchar(max) = N'[{"Id":1,"ParentId":32222,"Status":"approved","Remarks":"asfasdf sadfasdfasfasf aasf asfasfas"},{"Id":2,"ParentId":32222,"Remarks":"saf asfsfasfsdf"},{"Id":3,"ParentId":32222,"Remarks":""},{"Id":4,"ParentId":32222,"Remarks":""},{"Id":5,"ParentId":32222,"Remarks":""},{"Id":6,"ParentId":32222,"Remarks":""}]',
    --    @Mode nvarchar(50) = 'VERIFY-KYC' -- SAVE-KYC

    --SELECT @KYCId=43,@UserId=32222, @Payload=N'[{"Id":10175,"ParentId":34594,"Status":"approved","Remarks":"ASFD ASDFASDFAS FASFASFAS"},{"Id":10176,"ParentId":34594,"Status":"rejected","Remarks":"as asdfsaf afa fasfas fas fasfa sa"}]',@Mode=N'VERIFY-KYC'
    
    DECLARE 
        @Status int = 0,
        @Message nvarchar(500) = 'Invalid operation',
        @Details nvarchar(max) = NULL

        IF( ISNUMERIC(CAST(@KYCId AS nvarchar)) = 0 AND NOT @KYCId > 0)
        BEGIN
            select @Message = 'Invalid KYCId, it must be a numeric value.', @Status = 404, @Details = '[]';
            GOTO RESULT;
        END

        IF @UserId IS NULL
        BEGIN
            select @Message = 'Invalid UserId, it must have a valid value.', @Status = 404, @Details = NULL;
            GOTO RESULT;
        END

        DECLARE @ParentId bigint, @M_ID bigint
        SELECT @ParentId = ParentId, @M_ID = M_ID FROM User_Detail WHERE USER_ID = @UserId
        
        IF(@Mode = 'SAVE-KYC')
        BEGIN
            PRINT CONCAT('Mode => ', @Mode)

            DROP TABLE IF EXISTS #KycDocuments

            BEGIN TRANSACTION TranKycOperation
            BEGIN TRY
                DECLARE @CurrentDate datetime = GETDATE()
                DECLARE @FromDataTime datetime = @CurrentDate, @NextDueDate datetime = DATEADD(month, 6, @CurrentDate)

                SELECT DocumentTypeId, DocumentSubTypeId, DocumentFileName, ContentType, ContentSize 
                    INTO #KycDocuments
                FROM OPENJSON(@Payload) WITH (
                    DocumentTypeId bigint '$.DocumentTypeId',
                    DocumentSubTypeId bigint '$.DocumentSubTypeId',
                    DocumentFileName NVARCHAR(255) '$.DocumentFileName',
                    ContentType nvarchar(50) '$.ContentType',
                    ContentSize int '$.ContentSize'
                )
                
                IF(@KYCId = 0)
                BEGIN
                    INSERT INTO tbl_KycMaster (UserType, ParentId, CreatedBy, CreatedOn, FromDateTime, NextDueDate, Status, IsActive, ModifiedBy, ModifiedOn, M_ID) 
                        SELECT 'Business', @ParentId, @UserId, @CurrentDate, @FromDataTime, @NextDueDate, 'Submitted', 1, @UserId, @CurrentDate, @M_ID        
                    SET @KYCId = SCOPE_IDENTITY()
                END
                ELSE
                BEGIN
                    UPDATE tbl_KycMaster SET  ModifiedBy = @UserId,  ModifiedOn = GETDATE(), Status = 'Re-Submitted' WHERE Id = @KYCId
                END

                IF(@KYCId > 0 AND EXISTS(SELECT 1 FROM #KycDocuments))
                BEGIN
                    UPDATE d  SET d.isActive = 0 FROM tbl_uploadDocumentation(nolock) d 
                        INNER JOIN #KycDocuments k ON d.DocumentTypeId = k.DocumentTypeId AND d.DocumentSubTypeId = k.DocumentSubTypeId
                    WHERE d.KYCId = @KYCId

                    INSERT INTO tbl_uploadDocumentation(KycId, ParentId, FileName, DocumentTypeId, DocumentSubTypeId, ContentType, ContentSize, 
                        CreatedOn, CreatedBy, ModifiedBy, ModifiedOn, IsActive, Remarks, Approver, DocStatus) 
                    select @KYCId, @ParentId, DocumentFileName, DocumentTypeId, DocumentSubTypeId, ContentType, ContentSize,
                        @CurrentDate, @UserId, @UserId, @CurrentDate, 1, '', '', 'Submitted' FROM #KycDocuments

                END

                SELECT @Status = 200, @Message = 'Success', @Details = CONCAT('Kyc document saved successfully with KYCId ', @KYCId, ' on ', FORMAT(@CurrentDate, 'dd-MMM-yyyy HH:mm:ss')) 

                COMMIT TRANSACTION TranKycOperation
            END TRY
            BEGIN CATCH
                ROLLBACK TRANSACTION TranKycOperation
                EXEC usp_InsertErrorInfo 
                SELECT @Status = 500, @Message = ERROR_MESSAGE(), @Details = NULL
            END CATCH
        END


		IF(@Mode = 'KYC-STATUS')
        BEGIN
            PRINT CONCAT('Mode => ', @Mode)

             SELECT @Details = (
                SELECT m.id, m.UserType, m.ParentId, m.CreatedBy, format(m.CreatedOn, 'dd-MMM-yyyy HH:mm:ss') as [CreatedOn], format(m.FromDateTime, 'dd-MMM-yyyy HH:mm:ss' ) as [FromDateTime],
                    format(m.NextDueDate, 'dd-MMM-yyyy HH:mm:ss') as [NextDueDate], m.Status, m.M_ID,
                    d.[FileName], d.DocumentTypeId, d.DocumentSubTypeId, d.ContentType, d.ContentSize, d.Remarks, d.Approver, d.DocStatus
                FROM tbl_KycMaster(NOLOCK) m
                    INNER JOIN tbl_uploadDocumentation(NOLOCK) d ON m.Id = d.KycId
                WHERE m.ParentId = @ParentId and m.IsActive = 1 and d.IsActive = 1 FOR JSON PATH
            ) 

            SELECT @Status = 200, @Message = 'Success', @Details = ISNULL(@Details, '[]')
        END
		
        IF(@Mode = 'VERIFY-KYC')
        BEGIN
            PRINT CONCAT('Mode => ', @Mode)
			
			DECLARE @kycStatus NVARCHAR(50)
            DROP TABLE IF EXISTS #KYCDocumentVerify

			SELECT Id, ParentId, Status, Remarks INTO #KYCDocumentVerify FROM OPENJSON(@Payload) WITH ( 
				Id bigint '$.Id', 
				ParentId bigint '$.ParentId', 
				Status nvarchar(50) '$.Status', 
				Remarks nvarchar(200) '$.Remarks'
			)

			update k set
				k.Status = isnull(k.Status, d.DocStatus),
				k.Remarks = isnull(k.Remarks, d.Remarks)
			FROM #KYCDocumentVerify k
                    inner join tbl_uploadDocumentation d on k.Id = d.ID
				where d.KycId = @KYCId

		
            BEGIN TRANSACTION TranVerifyKyc
            BEGIN TRY
                
				update d set d.DocStatus = isnull(k.[Status], 'submitted'), d.Remarks = k.Remarks FROM #KYCDocumentVerify k 
                    inner join tbl_uploadDocumentation d on k.Id = d.ID where d.KycId = @KYCId

                declare @tdC int = 0, @tdA int = 0, @tdR int = 0

                select 
                    @tdC = count(1), 
                    @tdA = SUM(case when [Status] = 'approved' then 1 else 0 end), 
                    @tdR = SUM(case when [Status] = 'rejected' then 1 else 0 end) 
                from #KYCDocumentVerify

                set @kycStatus = (case 
                    when @tdC = @tdA and @tdA > 0 then 'approved'
                    when @tdC = @tdR and @tdR > 0 then 'rejected'
                    when @tdA > 0 and @tdA < @tdC then 'partial'
                    else 'submitted' end)

                UPDATE tbl_KycMaster SET ModifiedBy = @UserId, ModifiedOn = GETDATE(), Status = @kycStatus WHERE Id = @KYCId


                SELECT @Status = 200, @Message = 'Document Status Updated Successfully', @Details = @Payload
                COMMIT TRANSACTION TranVerifyKyc
            END TRY
            BEGIN CATCH
                ROLLBACK TRANSACTION TranVerifyKyc
                EXEC usp_InsertErrorInfo
                SELECT @Status = 500, @Message = ERROR_MESSAGE(), @Details = NULL
            END CATCH

        END

    RESULT:
    SELECT @Status AS [Status], @Message AS [Message], @Details AS [Details]

END



GO

/* ============================================================
   Procedure: [dbo].[usp_TeamMaster_TeamCode]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_TeamMaster_TeamCode] 
 (
 @TeamCode varchar(50) = null, 
 @ParentId bigint = null 
) 
AS 
  SET NOCOUNT ON           
  BEGIN TRY           
  begin
  select * from (
  select TeamId, TeamName, tutm.TeamCode, tm.UserId, (ud.FName + ' ' + LName) [Name], (Case when UD.User_ID = UD.ParentID then 'Manager'
  else 'User' End) Roles from TBL_UA_TeamMaster tutm(nolock)         
  inner join TBL_UA_TeamUserMappingMaster tm on tutm.TeamCode = tm.TeamCode 
  inner join User_Detail ud on tm.UserId = ud.User_ID 
  where ud.Status= 1 --and tutm.Active = 1 
  and tutm.TeamCode = --'Team1' 
  @TeamCode and tutm.ParentId = @ParentId 
  )t order by Roles Asc
  end /*End here for details*/ 
 END TRY 
BEGIN CATCH 
 DECLARE @ErrorMessage NVARCHAR(4000); 
 SELECT @ErrorMessage = ERROR_MESSAGE(); 
 RAISERROR (@ErrorMessage, 16, 1); 
END CATCH 




GO

