/* ============================================================
   Procedure: [dbo].[usp_TodayCallDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_TodayCallDetails]   
as  
begin  
CREATE TABLE #TempLinked          
 (          
  Result VARCHAR(50)          
 )    
 INSERT INTO #TempLinked          
 EXEC GetStatusofLinkedServer 'CRM'    
 IF NOT EXISTS(          
        SELECT 'x'          
        FROM   #TempLinked          
    )          
 BEGIN  
 select name,status,dateupdated,enqno,company_name,mobile_no,mobile_no2,mobile_no3,executive into #p1 
 from CRM.CRMDB.dbo.pre_enquiry pr (nolock) where pr.mobile_no in (select substring([From],2,10) 
 from passthru p  where p.createddate>CAST(getdate() as DATE))  
 select name,status,dateupdated,enqno,company_name,mobile_no,mobile_no2,mobile_no3,executive into #p2 
 from CRM.CRMDB.dbo.pre_enquiry pr (nolock) where pr.mobile_no2 in (select substring([From],2,10) from 
 passthru p  where p.createddate>CAST(getdate() as DATE))  
 select name,status,dateupdated,enqno,company_name,mobile_no,mobile_no2,mobile_no3,executive into #p3 from CRM.CRMDB.dbo.pre_enquiry pr (nolock) where pr.mobile_no3 in (select substring([From],2,10) from passthru p  where p.createddate>CAST(getdate() as DATE))  
 select name,status,dateupdated,enqno,company_name,mobile_no,mobile_no2,mobile_no3,executive into #pre_enquiry from   
 (select name,status,dateupdated,enqno,company_name,mobile_no,mobile_no2,mobile_no3,executive from #p1  
  union  
  select name,status,dateupdated,enqno,company_name,mobile_no,mobile_no2,mobile_no3,executive from #p2  
  union  
  select name,status,dateupdated,enqno,company_name,mobile_no,mobile_no2,mobile_no3,executive from #p3  
  ) A  
   
 select [From],isnull(name,'Enq not added') as Name,isnull(status,'Enq not added') as Status,
 isnull(cast(dateupdated as nvarchar(20)),'Enq not added') as Statusdate,isnull(Executive,'') as Executive, 
 p.DialWhomNumber,case when pr.enqno IS null then 'Enq not added' else cast(pr.enqno as nvarchar(10)) end as RefrenceNo,
 isnull([company_name],'') as company_name,p.StartTime into #temp from passthru p 
 left join #pre_enquiry pr (nolock) 
 on substring([From],2,10)=pr.mobile_no 
 or substring([From],2,10)=pr.mobile_no2 or substring([From],2,10)=pr.mobile_no3 
 where p.createddate>CAST(getdate() as DATE)   
   
 DECLARE @xml NVARCHAR(MAX)DECLARE @body NVARCHAR(MAX),@count int=(select count(1) from #temp)  
 SET @xml =CAST(( SELECT [From] AS 'td','',[Name] AS 'td','',[Status] AS 'td','', Statusdate AS 'td','',
 Executive  AS 'td','',DialWhomNumber  AS 'td','', RefrenceNo AS 'td','',[company_name]  AS 'td','',
 StartTime from #temp FOR XML PATH('tr'), ELEMENTS )AS NVARCHAR(MAX))      
SET @body ='<html><H1>Today''s Call report as on ' +cast (getdate() as nvarchar)+ '. Total Calls: '
+ cast(@count as nvarchar(10)) + ' </H1><body><table border = 2><tr><th>From</th><th>Name</th><th>Status</th>
<th>Statusdate</th><th>Executive</th><th>DialWhomNumber</th><th>RefrenceNo</th><th>company_name</th>
<th>StartTime</th></tr>'       
SET @body = @body + @xml +'</table></body></html>'      
declare @subject nvarchar(100)='Call Status today as on ' + cast(getdate() as nvarchar(20))  
  
EXEC usp_enqueueemail      
@profile_name='Alerts',       
@recipients='csshukla@pelsoftlabs.in',      
@blind_copy_recipients='karuna@pelsoftlabs.in',      
@subject=@subject ,      
@body = @body,      
@body_format ='HTML'      
drop table #temp      
   
 end  
   
    
end



GO

