/* ============================================================
   Procedure: [dbo].[usp_ToggleAcres99_Status]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_ToggleAcres99_Status
	--335,'trtertrtr',0             
	@userid BIGINT
	,@Acres99_UserName NVARCHAR(500)
	,@cstatus BIT
AS
BEGIN
	DECLARE @parentid BIGINT = (
			SELECT parentid
			FROM user_detail(NOLOCK)
			WHERE user_id = @userid
			)
		,@activity VARCHAR(MAX) = ''

	IF (@userid <> 335)
	BEGIN
		-- start particular user             
		IF EXISTS (
				SELECT 1
				FROM Acres99_Mapping(NOLOCK)
				WHERE Acres_UserName = @Acres99_UserName
				)
		BEGIN
			DECLARE @status BIT = (
					SELECT STATUS
					FROM Acres99_Mapping(NOLOCK)
					WHERE Acres_UserName = @Acres99_UserName
						AND Kit19ParentID = @parentid
					)

			IF @status = @cstatus
			BEGIN
				SELECT CASE 
						WHEN @status = 0
							THEN 'ID is in inactive state already'
						ELSE 'ID is in active state already'
						END
			END

			IF @status <> @cstatus
			BEGIN
				IF @status = 1
				BEGIN
					UPDATE Acres99_Mapping
					SET STATUS = 0
					FROM Acres99_Mapping(NOLOCK)
					WHERE Acres_UserName = @Acres99_UserName
						AND Kit19ParentID = @parentid

					SELECT 'ID deactivated successfully'

					SET @activity = 'Updt_99acrMppng_DActvt'
				END
				ELSE IF @status = 0
				BEGIN
					UPDATE Acres99_Mapping
					SET STATUS = 1
					FROM Acres99_Mapping(NOLOCK)
					WHERE Acres_UserName = @Acres99_UserName
						AND Kit19ParentId = @parentid

					SELECT 'ID activated successfully'

					SET @activity = 'Updt_99acrMppng_Actvt'
				END
				ELSE
				BEGIN
					SELECT 'Sorry ! This ID is not mapped with your account. If this TradeIndia ID belongs to you, Please contact us'
				END
			END
		END
				--End Particular user  
	END
	ELSE
	BEGIN
		-- Start 335 user  
		IF EXISTS (
				SELECT 1
				FROM Acres99_Mapping(NOLOCK)
				WHERE Acres_UserName = @Acres99_UserName
				)
		BEGIN
			DECLARE @status_new BIT = (
					SELECT TOP 1 STATUS
					FROM Acres99_Mapping(NOLOCK)
					WHERE Acres_UserName = @Acres99_UserName
					)

			IF @status_new = @cstatus
			BEGIN
				SELECT CASE 
						WHEN @status_new = 0
							THEN 'ID is in inactive state already'
						ELSE 'ID is in active state already'
						END
			END

			IF @status_new <> @cstatus
			BEGIN
				IF @status_new = 1
				BEGIN
					UPDATE Acres99_Mapping
					SET STATUS = 0
					FROM Acres99_Mapping(NOLOCK)
					WHERE Acres_UserName = @Acres99_UserName

					SELECT 'ID deactivated successfully'

					SET @activity = 'Updt_99acrMppng_DActvt'
				END
				ELSE IF @status_new = 0
				BEGIN
					UPDATE Acres99_Mapping
					SET STATUS = 1
					FROM Acres99_Mapping(NOLOCK)
					WHERE Acres_UserName = @Acres99_UserName

					SELECT 'ID activated successfully'

					SET @activity = 'Updt_99acrMppng_Actvt'
				END
						--else            
						--begin            
						--Select 'Sorry ! This ID is not mapped with your account. If this TradeIndia ID belongs to you, Please contact us'            
						--end            
			END
		END
				-- end 335 user  
	END

	DECLARE @rowJson VARCHAR(MAX) = (
			SELECT *
			FROM Acres99_Mapping(NOLOCK)
			WHERE Acres_UserName = @Acres99_UserName
			FOR JSON AUTO
				,INCLUDE_NULL_VALUES
			)

	IF @rowJson IS NOT NULL
	BEGIN
		EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @userid
			,@Activity_type = @activity
			,@ActionType = 'U'
			,@RowJson = @rowJson
			,@Table_name = 'Acres99_Mapping'
	END
END



GO

/* ============================================================
   Procedure: [dbo].[usp_ToggleExporterKeyStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_ToggleExporterKeyStatus    
  @userid BIGINT      
 ,@ExporterKey NVARCHAR(500)      
 ,@cstatus INT      
AS      
BEGIN      
 DECLARE @parentid BIGINT = (      
   SELECT parentid      
   FROM user_detail(NOLOCK)      
   WHERE user_id = @userid      
   )      
   ,@activity VARCHAR(MAX)=''      
 IF (@userid <> 335)      
 BEGIN      
  --start particular user           
  IF EXISTS (      
    SELECT 1      
    FROM tbl_ExporterMapping(NOLOCK)      
    WHERE ExporterKey = @ExporterKey      
    )      
  BEGIN      
   DECLARE @status INT = (      
     SELECT STATUS      
     FROM tbl_ExporterMapping(NOLOCK)      
     WHERE ExporterKey = @ExporterKey      
      AND ParentId = @parentid      
     )      
      
   IF @status = @cstatus      
   BEGIN      
    SELECT CASE       
      WHEN @status = 0      
       THEN 'Id is in inactive state already'      
      ELSE 'Id is in active state already'      
      END      
   END      
      
   IF @status <> @cstatus      
   BEGIN      
    IF @status = 1      
    BEGIN      
     UPDATE tbl_ExporterMapping      
     SET STATUS = 0      
     FROM tbl_ExporterMapping(NOLOCK)      
     WHERE ExporterKey = @ExporterKey      
      AND ParentId = @parentid      
      
     SELECT 'Id deactivated Successfully'      
     SET @activity='Update Exporter Key Mapping - Deactivated'      
       
    END      
    ELSE IF @status = 0      
    BEGIN      
     UPDATE tbl_ExporterMapping      
     SET STATUS = 1      
     FROM tbl_ExporterMapping(NOLOCK)      
     WHERE ExporterKey = @ExporterKey      
      AND ParentId = @parentid      
      
     SELECT 'Id Activated Successfully'      
     SET @activity='Update Exporter Key Mapping - Activated'      
    END      
    ELSE      
    BEGIN      
     SELECT 'Sorry ! This Id is not mapped with your account. If this Exporter key belongs to you, Please contact us'      
    END      
   END      
  END      
    --End particular user      
 END      
 ELSE      
 BEGIN      
  -- start 335 user      
  IF EXISTS (      
    SELECT 1      
    FROM tbl_ExporterMapping(NOLOCK)      
    WHERE ExporterKey = @ExporterKey      
    )      
  BEGIN      
   DECLARE @status_new INT = (      
     SELECT TOP 1 STATUS      
     FROM tbl_ExporterMapping(NOLOCK)      
     WHERE ExporterKey = @ExporterKey      
     )      
      
   IF @status_new = @cstatus      
   BEGIN      
    SELECT CASE       
      WHEN @status_new = 0      
       THEN 'Id is in inactive state already'      
      ELSE 'Id is in active state already'      
      END      
   END      
      
   IF @status_new <> @cstatus      
   BEGIN      
    IF @status_new = 1      
    BEGIN      
     UPDATE tbl_ExporterMapping      
     SET STATUS = 0      
     FROM tbl_ExporterMapping(NOLOCK)      
     WHERE ExporterKey = @ExporterKey      
      
     SELECT 'Id deactivated Successfully'      
     SET @activity='Update Exporter Key Mapping - Deactivated'      
    END      
    ELSE IF @status_new = 0      
    BEGIN      
     UPDATE tbl_ExporterMapping      
     SET STATUS = 1      
     FROM tbl_ExporterMapping(NOLOCK)      
     WHERE ExporterKey = @ExporterKey      
      
     SELECT 'Id Activated Successfully'      
     SET @activity='Update Exporter Key Mapping - Activated'      
    END      
      --else            
      --begin            
      --Select 'Sorry ! This Id is not mapped with your account. If this IndiaMart id belongs to you, Please contact us'            
      --end            
   END      
  END      
 END      
   -- end 335 user       
       
  DECLARE @rowJson VARCHAR(MAX) = (      
    SELECT *      
    FROM tbl_ExporterMapping(NOLOCK)      
    WHERE ExporterKey = @ExporterKey      
    FOR JSON AUTO      
     ,INCLUDE_NULL_VALUES      
    )      
      
  IF @rowJson IS NOT NULL      
  BEGIN      
   EXEC MySmsAudit.dbo.Usp_AuditTableDataByParentId @User_id = @userid      
    ,@Activity_type = @activity      
    ,@ActionType = 'U'      
    ,@RowJson = @rowJson      
    ,@Table_name = 'tbl_ExporterMapping'      
  END      
       
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_ToggleIndiaMartIDStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.usp_ToggleIndiaMartIDStatus @userid BIGINT
	,@IndiaMartId NVARCHAR(200)
	,@cstatus INT
AS
BEGIN
	DECLARE @parentid BIGINT = (
			SELECT parentid
			FROM user_detail(NOLOCK)
			WHERE user_id = @userid
			)
		,@activity VARCHAR(MAX) = ''

	IF (@userid <> 335)
	BEGIN
		--start particular user     
		IF EXISTS (
				SELECT 1
				FROM IndiamartMapping(NOLOCK)
				WHERE IndiamartId = @IndiaMartId
				)
		BEGIN
			DECLARE @status INT = (
					SELECT STATUS
					FROM IndiamartMapping(NOLOCK)
					WHERE IndiamartId = @IndiaMartId
						AND Kit19ParentId = @parentid
					)

			IF @status = @cstatus
			BEGIN
				SELECT CASE 
						WHEN @status = 0
							THEN 'Id is in inactive state already'
						ELSE 'Id is in active state already'
						END
			END

			IF @status <> @cstatus
			BEGIN
				IF @status = 1
				BEGIN
					UPDATE IndiamartMapping
					SET STATUS = 0
					FROM IndiamartMapping(NOLOCK)
					WHERE IndiamartId = @IndiaMartId
