/* ============================================================
   Procedure: [dbo].[usp_total_count_for_dnd]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_total_count_for_dnd]
@U_ID INT,                 
@SENDER_ID NVARCHAR(100),                 
@FDATE NVARCHAR(20),                  
@TDATE NVARCHAR(20)                  
AS 
IF(@U_ID!='')                
BEGIN                
SELECT COUNT(*) FROM [MYSMSREPORT].[DBO].[SixDaysHistory7] (NOLOCK) where U_ID=@U_ID AND (CONVERT(NVARCHAR,CONVERT(DATETIME,MESSAGEINSERTDATE,104),112) 
BETWEEN CONVERT(NVARCHAR,CONVERT(DATETIME,@FDATE,104),112) AND CONVERT(NVARCHAR,CONVERT(DATETIME,@TDATE,104),112))          
END                
ELSE IF(@SENDER_ID!='')                
BEGIN               
SELECT COUNT(*) FROM [MYSMSREPORT].[DBO].[SixDaysHistory7] (NOLOCK) WHERE SENDERID=@SENDER_ID 
AND (CONVERT(NVARCHAR,CONVERT(DATETIME,MESSAGEINSERTDATE,104),112) BETWEEN               
CONVERT(NVARCHAR,CONVERT(DATETIME,@FDATE,104),112) AND CONVERT(NVARCHAR,CONVERT(DATETIME,@TDATE,104),112))                
END 



GO

