/* ============================================================
   Procedure: [dbo].[Usp_ToViewPlanMasterDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

  
      
/*          
   Created By:    Santosh Kumar          
   Created Date:  10-05-2017 4:00 PM          
   SP For : To view records of Planmaster          
   Alter by :              
   Alter Date :           
              
*/          
          
CREATE   PROC [dbo].[Usp_ToViewPlanMasterDetails] --''         
@Search VARCHAR(250)        
AS          
BEGIN  
 SELECT PM.ID,  
        PM.PlanName,  
        PM.Price,  
        PM.IsActive,  
        PM.PlanDescription,  
        UF.Name  AS UserFilter,  
        PM.Quantity,  
        PM.IsSMS,  
        PM.IsMail  
 FROM   PlanMaster PM(NOLOCK)  
        INNER JOIN User_Filter UF(NOLOCK)  
             ON  PM.UserFilter = UF.Code  
 WHERE  ISNULL(@Search, '') = ''  
        OR  PlanName LIKE '%' + @Search + '%'  
        OR  Price LIKE '%' + @Search + '%'  
 ORDER BY  
        pm.ID          DESC  
END  


GO

