/* ============================================================
   Procedure: [dbo].[usp_ToViewSearchDetailsForInternalUser]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].usp_ToViewSearchDetailsForInternalUser          
@IsActive BIT            
AS              
BEGIN
	SELECT A.SearchName,
	       A.ID,
	       A.IsActive,
	       A.JobStatus,
	       A.CRMRoles,
	       A.RoleName,
	       A.UserName,
	       A.CRMUSERS,
	       (
	           CASE 
	                WHEN A.RoleName <> '' THEN '<p><b>CRM Roles:</b>' + A.RoleName 
	                     + '</p>'
	                ELSE ''
	           END +
	           CASE 
	                WHEN A.UserName <> '' THEN '<p><b>UserName:</b>' + A.UserName 
	                     + '</p>'
	                ELSE ''
	           END +
	           '<p><b>Job Status:</b>' + CASE 
	                                          WHEN A.JobStatus = 1 THEN 'On'
	                                          ELSE 'Off'
	                                     END 
	           + '</p>'
	       )  AS SearchCriteria
	FROM   (
	           SELECT SD.SearchName,
	                  SD.ID,
	                  SD.IsActive,
	                  SD.JobStatus,
	                  SD.CRMRoles,
	                  (
	                      SELECT STUFF(
	                                 (
	                                     SELECT N', ' + MR.RoleName
	                                     FROM   [M_Role] AS MR
	                                            INNER JOIN dbo.fn_Split(SD.CRMRoles, '#') AS 
	                                                 fs
	                                                 ON  mr.RoleID = fs.[value] 
	                                                     FOR XML 
	                                                     PATH(''),
	                                            TYPE
	                                 ) 
	                                 .value('text()[1]', 'nvarchar(max)'),
	                                 1,
	                                 2,
	                                 N''
	                             )
	                  )              AS RoleName,
	                  SD.CRMUSERS,
	                  (
	                      SELECT STUFF(
	                                 (
	                                     SELECT N', ' + UL.UserName
	                                     FROM   CRM_UserLogin AS UL
	                                            INNER JOIN dbo.fn_Split(SD.CRMUSERS, '#') AS 
	                                                 fs
	                                                 ON  ul.UserID = fs.[value]
	                                                     FOR XML 
	                                                     PATH(''),
	                                            TYPE
	                                 ) 
	                                 .value('text()[1]', 'nvarchar(max)'),
	                                 1,
	                                 2,
	                                 N''
	                             )
	                  )              AS UserName
	           FROM   SearchDetails  AS SD
	           WHERE  SD.IsInternalUsers = 1
	                  AND SD.IsCRMDB = 1
	                  AND SD.IsActive = @IsActive
	       )     A
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_ToViewSearchDetailsForInternalUser_Temp]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


/*      
  Created By : Santosh Kumar      
  Created Date:03/06/2017      
  SP For View Internal User Details      
  Alter Date :      
  Alter by   :         
*/      
CREATE   PROC [dbo].[usp_ToViewSearchDetailsForInternalUser_Temp]  
@IsActive BIT    
AS      
BEGIN
	SELECT SD.SearchName,
	       SD.ID,
	       SD.IsActive,
	       SD.JobStatus,
	       SD.CRMRoles,
	       (
	           CASE 
	                WHEN SD.CRMRoles <> '' THEN '<p><b>CRMRoles:</b>' + SD.CRMRoles 
	                     + '</p>'
	                ELSE ''
	           END +
	           CASE 
	                WHEN SD.UserName <> '' THEN '<p><b>UserName:</b>' + SD.UserName 
	                     + '</p>'
	                ELSE ''
	           END
	       )                             AS SearchCriteria,
	       (
	           SELECT STUFF(
	                      (
	                          SELECT N', ' + MR.Role
	                          FROM   CRMDB.[dbo].[M_Role] AS MR
	                                 INNER JOIN dbo.fn_Split(SD.CRMRoles, '#') AS 
	                                      fs
	                                      ON  MR.RoleID = fs.[value] FOR XML 
	                                          PATH(''),
	                                 TYPE
	                      ) 
	                      .value('text()[1]', 'nvarchar(max)'),
	                      1,
	                      2,
	                      N''
	                  )
	       )                             AS RoleName,
	       SD.CRMUSERS,
	       (
	           SELECT STUFF(
	                      (
	                          SELECT N', ' + UL.User_Name
	                          FROM   CRMDB.[dbo].[User_Login] AS UL
	                                 INNER JOIN dbo.fn_Split(SD.CRMUSERS, '#') AS 
	                                      fs
	                                      ON  UL.User_ID = fs.[value] FOR XML 
	                                          PATH(''),
	                                 TYPE
	                      ) 
	                      .value('text()[1]', 'nvarchar(max)'),
	                      1,
	                      2,
	                      N''
	                  )
	       )                             AS UserName
	FROM   MYSMSRND.[dbo].SearchDetails  AS SD
	WHERE  SD.IsInternalUsers = 1
	       AND SD.IsCRMDB = 1
	       AND SD.IsActive = @IsActive
END           



