/* ============================================================
   Procedure: [dbo].[Usp_ToViewSMSMailTemplate]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

        
            
CREATE   PROC [dbo].[Usp_ToViewSMSMailTemplate] --'',0,1           
@Search VARCHAR(250),    
@IsSMS BIT,    
@IsMail BIT          
AS            
BEGIN
	IF (@IsSms = 1 AND @IsMail = 0)
	BEGIN
	    SELECT TemplateID,
	           TEMPLATE,IsSMS,IsMAIL
	    FROM   SMSMailTemplate
	    WHERE  (
	               ISNULL(@Search, '') = ''
	               OR TEMPLATE LIKE '%' + @Search + '%'
	           )
	           AND IsSMS = @IsSMS
	           AND IsMAIL = @IsMail
	    ORDER BY
	           TemplateID DESC
	END
	ELSE 
	IF (@IsSms = 0 AND @IsMail = 1)
	BEGIN
	    (
	        SELECT TemplateID,
	               TEMPLATE,IsSMS,IsMAIL
	        FROM   SMSMailTemplate
	        WHERE  (
	                   ISNULL(@Search, '') = ''
	                   OR TEMPLATE LIKE '%' + @Search + '%'
	               )
	               AND IsSMS = @IsSMS
	               AND IsMAIL = @IsMail
	    ) 
	    UNION 
	    
	    (
	        SELECT pltmp.Id             AS TemplateID,
	               pltmp.Template_Body  AS TEMPLATE,0,1
	        FROM   PelConnectDB.dbo.Templates AS pltmp
	        WHERE  (
	                   (
	                       ISNULL(@Search, '') = ''
	                       OR pltmp.Template_Name LIKE '%' + @Search + '%'
	                   )
	                   AND pltmp.Template_Type = 'EMAIL'
	               )
	    )
	END
END    
    
    
    


