SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_tp_AddActivity]
(
	@TicketId				bigint,
	@ParentId				bigint,
	@FieldName				nvarchar(100),
	@OldValue				nvarchar(max),
	@NewValue				nvarchar(max),
	@ActivityDescription	nvarchar(max),
	@ActivityBy				bigint,
	@ActivityDatetime		datetime,
	@ActivityId				bigint out,
	@EventId				bigint=null,
	@EventName				NVARCHAR(500)=null,
	@EntityType				varchar(50)=null,
	@EntityId				bigint=null
)
AS
BEGIN
	-- declare @TicketId bigint=146,@ParentId bigint=32222,@FieldName nvarchar(100)='Subject', @OldValue nvarchar(max)='subject10', @NewValue nvarchar(max)='subject11', @ActivityDescription nvarchar(max)='Ticket Edited', @ActivityBy bigint=1, @ActivityDatetime datetime='23-Feb-2024', @ActivityId bigint, @EventId bigint=null, @EventName NVARCHAR(500)='Leads ticket updated'

	declare @TicketActivityTable nvarchar(max)='', @strQuery nvarchar(max)=''

	Exec [Usp_tp_CreateTicketActivityTableByParentID] @ParentId, @TicketActivityTable out
	
	If(isnull(@EventId,0) = 0)
	Begin
		SELECT @EventId = ISNULL([ID], 0) FROM ActivityMaster(NOLOCK) WHERE  [EventName] = @EventName;
	End
	If(isnull(@OldValue,'') != isnull(@NewValue,''))
	Begin
		Set @strQuery = Concat(N'insert into ',@TicketActivityTable,'(TicketId,ParentId,FieldName,OldValue,NewValue,ActivityDescription,ActivityBy,ActivityDatetime,EventId,EntityType,EntityId)
		values(@TicketId,@ParentId,@FieldName,@OldValue,@NewValue,@ActivityDescription,@ActivityBy,@ActivityDatetime,@EventId,@EntityType,@EntityId); Set @ActivityId1=Scope_Identity();')

		Exec sp_executesql @strQuery,N'@TicketId bigint,@ParentId bigint,@FieldName nvarchar(100),@OldValue nvarchar(max),@NewValue nvarchar(max),@ActivityDescription nvarchar(max),@ActivityBy bigint,@ActivityDatetime datetime,@EventId bigint,@EntityType varchar(50),@EntityId bigint,@ActivityId1 bigint out',@TicketId,@ParentId,@FieldName,@OldValue,@NewValue,@ActivityDescription,@ActivityBy,@ActivityDatetime,@EventId,@EntityType,@EntityId,@ActivityId1=@ActivityId out
	--	print @strQuery
		print concat('@ActivityId: ',@ActivityId)
	End

END



