/* ============================================================
   Procedure: [dbo].[Usp_tp_AddCountryCodeColumnsToExistingTables]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_tp_AddCountryCodeColumnsToExistingTables]
AS
BEGIN
    DECLARE @TableName NVARCHAR(MAX)
    DECLARE @AddColumnsQuery NVARCHAR(MAX)

    DECLARE TableCursor CURSOR FOR
    SELECT TABLE_NAME
    FROM INFORMATION_SCHEMA.TABLES
    WHERE TABLE_NAME LIKE 'tbl_tp_TicketMaster_%'

    OPEN TableCursor
    FETCH NEXT FROM TableCursor INTO @TableName

    WHILE @@FETCH_STATUS = 0
    BEGIN
        SET @AddColumnsQuery = N'ALTER TABLE [dbo].[' + @TableName + '] ' +
                               'ADD ' +
                               'CountryCode NVARCHAR(50) NULL, ' +
                               'CountryCode1 NVARCHAR(50) NULL, ' +
                               'CountryCode2 NVARCHAR(50) NULL'

        -- Check if columns already exist before adding
        IF NOT EXISTS (
            SELECT 1 
            FROM INFORMATION_SCHEMA.COLUMNS 
            WHERE TABLE_NAME = @TableName AND COLUMN_NAME = 'CountryCode'
        )
        BEGIN
            EXEC sp_executesql @AddColumnsQuery
        END

        FETCH NEXT FROM TableCursor INTO @TableName
    END

    CLOSE TableCursor
    DEALLOCATE TableCursor
END



