  --EXEC sp_executesql @DynamicQuery, N'@InsertedId BIGINT OUTPUT', @InsertedId OUTPUT;  
  
  --Select @InsertedId=SCOPE_IDENTITY()   
  PRINT @DynamicQuery; 


  declare @str varchar(50)=cast(@InsertedId as varchar)  
  print ('update ' + @TicketMasterTable + ' set TicketNo=''T-''+cast(TicketId as varchar) Where TicketId='+@str)

  Exec ('update ' + @TicketMasterTable + ' set TicketNo=''T-''+cast(TicketId as varchar) Where TicketId='+@str)  
  

    
	--exec usp_tp_ApplyDispatcherRule @InsertedId, @ParentID
  
  DECLARE @DynamicInsertedId BIGINT;  
  DECLARE @MaxIdQuery NVARCHAR(MAX);  
  SET @MaxIdQuery=N'SELECT @DynamicInsertedId = MAX(TicketID) FROM ' + QUOTENAME(@TicketMasterTable);  
  
  EXEC sp_executesql @MaxIdQuery, N'@DynamicInsertedId BIGINT OUTPUT', @DynamicInsertedId OUTPUT;  
  
  --DECLARE @UpdateQuery NVARCHAR(MAX);  
  --SET @UpdateQuery=N'  
  -- UPDATE ' + QUOTENAME(@TicketMasterTable) +  
  --'              
  -- SET TicketNo = ''000'' + CAST(@DynamicInsertedId AS NVARCHAR(20)) + '' - TICKET''              
  -- WHERE TicketID = @DynamicInsertedId              
  --';  
  --EXEC sp_executesql @UpdateQuery, N'@DynamicInsertedId INT', @DynamicInsertedId;  

  --new ticket number logic--

 -- start---
  SET @DynamicInsertedId = @InsertedId;
DECLARE @UpdateQuery NVARCHAR(MAX);
DECLARE @UpdateNumberQuery NVARCHAR(MAX);
DECLARE @NextTicketNo NVARCHAR(100);
DECLARE @LastTicketNo NVARCHAR(50);
DECLARE @CurrentNumber INT;
DECLARE @Prefix NVARCHAR(50) = '';
DECLARE @Suffix NVARCHAR(50) = '';
DECLARE @ParamDefinition NVARCHAR(MAX);
DECLARE @fetchnumberSQL NVARCHAR(MAX);
DECLARE @ExtractedNumber NVARCHAR(20) = '';
DECLARE @LeadingZeros NVARCHAR(20) = '';
DECLARE @IncrementedNumber NVARCHAR(20);
DECLARE @Pattern NVARCHAR(50);
DECLARE @LastDigitPos INT;
DECLARE @FormatJson NVARCHAR(MAX);
DECLARE @Number NVARCHAR(50) = '';

-- Fetch the FormatJson from tbl_tp_TicketNoFormat
SELECT @FormatJson = FormatJson
FROM tbl_tp_TicketNoFormat
WHERE ParentId = @ParentID AND IsActive = 1;

-- Declare a table to store format values
DECLARE @FormatValues TABLE (
    [Value] NVARCHAR(50),
    [DataType] NVARCHAR(50)
);


INSERT INTO @FormatValues ([Value], [DataType])
SELECT 
    JSON_VALUE(value, '$.value') AS [Value],
    JSON_VALUE(value, '$.datatype') AS [DataType]
FROM OPENJSON(@FormatJson, '$.FormatValues');

-- Extract the prefix, number, and suffix into variables
SELECT TOP 1 @Prefix = COALESCE([Value], '') 
FROM @FormatValues WHERE [DataType] = 'prefix';

SELECT TOP 1 @Number = COALESCE([Value], '0') 
FROM @FormatValues WHERE [DataType] = 'number';

SELECT TOP 1 @Suffix = COALESCE([Value], '') 
FROM @FormatValues WHERE [DataType] = 'suffix';

-- Construct SQL to fetch the last ticket number
SET @fetchnumberSQL = N'
SELECT TOP 1 @LastTicketNo = TicketNo
FROM ' + QUOTENAME(@TicketMasterTable) + '
WHERE TicketNo LIKE @Prefix + ''%'' + @Suffix
ORDER BY TicketID DESC;';

SET @ParamDefinition = N'@LastTicketNo NVARCHAR(50) OUTPUT, @Prefix NVARCHAR(50), @Suffix NVARCHAR(50)';

-- Execute the SQL to fetch the last ticket number
EXEC sp_executesql 
    @fetchnumberSQL, 
    @ParamDefinition, 
    @LastTicketNo = @LastTicketNo OUTPUT, 
    @Prefix = @Prefix, 
    @Suffix = @Suffix;

PRINT @LastTicketNo;

-- Case 1: If @LastTicketNo is NULL and @FormatJson is NOT NULL
IF @LastTicketNo IS NULL AND @FormatJson IS NOT NULL
BEGIN
    -- If number is NULL, default to '1'
    IF @Number IS NULL
        SET @Number = '1';

    -- Generate the next ticket number
    SET @NextTicketNo = @Prefix + @Number + @Suffix;

    -- Prepare the update query to insert the ticket number
    SET @UpdateNumberQuery = N'
    UPDATE ' + QUOTENAME(@TicketMasterTable) + '    
    SET TicketNo = @NextTicketNo    
    WHERE TicketID = @Ticket_ID';
    
    -- Execute the update query
    EXEC sp_executesql @UpdateNumberQuery, N'@Ticket_ID BIGINT, @NextTicketNo NVARCHAR(50)', @Ticket_ID = @DynamicInsertedId, @NextTicketNo = @NextTicketNo;
END


ELSE IF @LastTicketNo IS NOT NULL AND @FormatJson IS NOT NULL
BEGIN
    -- Find the last digit's position in @LastTicketNo
    SET @LastDigitPos = LEN(@LastTicketNo) - LEN(@Suffix);

    -- Extract the number portion from @LastTicketNo
    SET @ExtractedNumber = SUBSTRING(@LastTicketNo, LEN(@Prefix) + 1, @LastDigitPos - LEN(@Prefix));

    -- Handle leading zeros and increment the number
    IF LEFT(@ExtractedNumber, 1) = '0'
    BEGIN
        SET @IncrementedNumber = CAST(CAST(@ExtractedNumber AS INT) + 1 AS NVARCHAR(20));
        SET @LeadingZeros = REPLICATE('0', LEN(@ExtractedNumber) - LEN(@IncrementedNumber));
        SET @Number = @LeadingZeros + @IncrementedNumber;
    END
    ELSE
    BEGIN
        SET @IncrementedNumber = CAST(CAST(@ExtractedNumber AS INT) + 1 AS NVARCHAR(20));
        SET @Number = @IncrementedNumber;
    END

    SET @NextTicketNo = @Prefix + @Number + @Suffix;

    SET @UpdateNumberQuery = N'
    UPDATE ' + QUOTENAME(@TicketMasterTable) + '    
    SET TicketNo = @NextTicketNo    
    WHERE TicketID = @Ticket_ID';

    EXEC sp_executesql @UpdateNumberQuery, N'@Ticket_ID BIGINT, @NextTicketNo NVARCHAR(50)', @Ticket_ID = @DynamicInsertedId, @NextTicketNo = @NextTicketNo;
END

ELSE IF  @FormatJson IS NULL 
BEGIN
 SET @NextTicketNo = '000' + CAST(@DynamicInsertedId AS NVARCHAR(20)) + ' - TICKET';
    SET @UpdateQuery = N'    
    UPDATE ' + QUOTENAME(@TicketMasterTable) + '    
    SET TicketNo = ''000'' + CAST(@Ticket_ID AS NVARCHAR(20)) + '' - TICKET''    
    WHERE TicketID = @Ticket_ID';    
	    PRINT 'updatedqueries: ' + @UpdateQuery;
    EXEC sp_executesql @UpdateQuery, N'@Ticket_ID BIGINT', @Ticket_ID = @DynamicInsertedId;
END
set @ResultOut = '{"TicketId":"'+cast(@NextTicketNo as varchar)+'"} '  
  
--end------

  DECLARE @UpdateQuery1 NVARCHAR(MAX);  
  
  IF( @SelectedTicket = 'Child')  
  BEGIN  
   SET @UpdateQuery1=N'UPDATE ' + QUOTENAME(@TicketMasterTable) +   
   ' SET IsParentTicket =  1 WHERE ParentTicketID > 0 AND TicketID = @TicketID';  
  
   EXEC sp_executesql @UpdateQuery1, N'@TicketID INT', @TicketID;  
  
   SET @UpdateQuery1=N'UPDATE ' + QUOTENAME(@TicketMasterTable) +  
   ' SET IsChildTicket =  1 WHERE  TicketID = @DynamicInsertedId';  
  
   EXEC sp_executesql @UpdateQuery1, N'@DynamicInsertedId INT', @DynamicInsertedId;  
  END;  
  
  IF( @SelectedTicket = 'Merge' )  
  BEGIN  
  
   SET @UpdateQuery1=N'UPDATE ' + QUOTENAME(@TicketMasterTable) +  
   ' SET IsMerged = CASE WHEN ParentTicketID > 0 THEN 1 ELSE 0 END WHERE TicketID = @DynamicInsertedId';  
  
   EXEC sp_executesql @UpdateQuery1, N'@TicketID INT', @TicketID;  
  
   SET @UpdateQuery1=N'UPDATE ' + QUOTENAME(@TicketMasterTable) +  
   ' SET ParentTicketID = @ParentTicketID WHERE  TicketID = @DynamicInsertedId';  
  
   EXEC sp_executesql @UpdateQuery1, N'@TicketID INT', @TicketID;  
  END;  
  
  IF( @SelectedTicket = 'Split' )  
  BEGIN  
  
   SET @UpdateQuery1=N'UPDATE ' + QUOTENAME(@TicketMasterTable) +  
   ' SET IsSplitted = 1 WHERE  TicketID = @TicketID';  
  
   EXEC sp_executesql @UpdateQuery1, N'@TicketID INT', @TicketID;  
  
   SET @UpdateQuery1=N' UPDATE ' + QUOTENAME(@TicketMasterTable) +  
   ' SET ParentTicketID = @ParentTicketID WHERE  TicketID = @DynamicInsertedId';  
  
   EXEC sp_executesql @UpdateQuery1, N'@ParentTicketID', @ParentTicketID;  
  END;  
  

  CREATE TABLE #TagsData  
  (  
   [TagData] NVARCHAR(MAX)  
  );  
  
  INSERT INTO #TagsData([TagData])  
  SELECT value FROM STRING_SPLIT(@TcktTag, ',');  
  
  CREATE TABLE #SplitValues  
  (  
   [OriginalData] NVARCHAR(MAX),  
   [TagIDs]       NVARCHAR(MAX),  
   [Tags]         NVARCHAR(MAX)  
  );  
  
  INSERT INTO #SplitValues([OriginalData], [TagIDs], [Tags])  
  SELECT [TagData] AS [OriginalData],  
       CASE  
       WHEN ISNUMERIC([extracted_integers]) = 1  
        THEN [extracted_integers]  
       END AS [TagIDs], [extracted_strings] AS [Tags]  
  FROM(SELECT [TagData], STRING_AGG(CASE WHEN ISNUMERIC([val]) = 1 THEN [val] ELSE NULL END, ',') AS [extracted_integers], STRING_AGG(CASE WHEN ISNUMERIC([val]) = 0 THEN [val] ELSE NULL END, ',') AS [extracted_strings]  
    FROM(SELECT [TagData], value AS [val] FROM #TagsData CROSS APPLY STRING_SPLIT(TagData, ',')) AS  
    split_values  
    GROUP BY [TagData]) AS aggregated_data;  
  
  DECLARE @InsertedTagMapping TABLE  
  (  
   [TagID]    INT,  
   [EntityID] INT  
  );  
  
  DECLARE @TagMasterID INT;  
  IF EXISTS(SELECT [Tags] FROM #SplitValues WHERE [Tags] IS NOT NULL)  
  BEGIN  
  
   DECLARE @Tag NVARCHAR(MAX);  
  
   DECLARE cur CURSOR  
   FOR SELECT TRIM(value) AS [Tag] FROM #SplitValues CROSS APPLY STRING_SPLIT(Tags, ',') WHERE [Tags] IS  
   NOT NULL;  
  
   OPEN cur;  
   FETCH NEXT FROM cur INTO @Tag;  
  
   WHILE @@FETCH_STATUS = 0  
   BEGIN  
  
    INSERT INTO TagMaster([Tag], [ParentID], [CreatedDate], [CreatedBy], [IsActive])  
    VALUES(@Tag, @ParentID, GETDATE(), @UserId, 1);  
  
    DECLARE @GeneratedTagID INT;  
    SET @GeneratedTagID=SCOPE_IDENTITY();  
  
    INSERT INTO EntityTagMapping([TagID], [EntityID], [Entity], [CreatedDate])  
    VALUES(@GeneratedTagID, @InsertedId, 'Ticket', GETDATE());  
  
    FETCH NEXT FROM cur INTO @Tag;  
  END;  
  
   CLOSE cur;  
   DEALLOCATE cur;  
  
  END;  
  
  IF EXISTS(SELECT [TagIDs] FROM #SplitValues WHERE [TagIDs] IS NOT NULL)  
  BEGIN  
   INSERT INTO EntityTagMapping([EntityID], [Entity], [TagID], [CreatedDate])  
   SELECT @InsertedId, 'Ticket', [TagIDs], GETDATE() FROM #SplitValues;  
  
  END;  
  
  DROP TABLE #TagsData;  
  DROP TABLE #SplitValues;  
  
  DECLARE @DynamicTicketTagUpdate NVARCHAR(MAX);  
  SET @DynamicTicketTagUpdate=N'                    
  UPDATE ' + QUOTENAME(@TicketMasterTable) +  
  N'                          
  SET TicketTag = STUFF(                    
   (SELECT '', '' + CONVERT(NVARCHAR(MAX), TagID)                    
  FROM EntityTagMapping                           
    WHERE EntityID = @DynamicInsertedId AND Entity = ''Ticket''                    
    FOR XML PATH ('''')), 1, 2, '''')         
  WHERE TicketID = @DynamicInsertedId;';  
  
  EXEC sp_executesql @DynamicTicketTagUpdate, N'@DynamicInsertedId INT', @DynamicInsertedId=@InsertedId;  
  
  --Update  tbl_tp_TicketMaster SET TicketTag = (SELECT               
  --           STRING_AGG(CONVERT(NVARCHAR(MAX), TagID), ', ') AS CommaSeparatedEntityIDs FROM EntityTagMapping Where EntityID = @InsertedId AND Entity = 'Ticket')                              
  DECLARE @TicketHistoryId BIGINT;  
  
  INSERT INTO tbl_tp_TicketHistory([TicketID], [TicketStatusID], [ParentID], [ActionDateTime], [Remarks],  
  [Note], [UserResponse], [AssignedUser], [AssignedGroup], [TicketPriority], [AssignedSource], [AssignedBy])  
  VALUES(@DynamicInsertedId, @TcktStatus, @ParentID, NULL, NULL, NULL, NULL, @AssignedUser, @AssignedGroup,  
  @TcktPriority, @ParentID, @ParentID);  
  
  SET @TicketHistoryId=SCOPE_IDENTITY();  
  
  IF( @FileName IS NOT NULL )  
  BEGIN  
   INSERT INTO tbl_tp_TicketAttachment([TicketID], [TicketHistoryID], [DisplayName], [FileUrl],  
   [IsActive], [CreatedBy], [CreatedOn])  
   VALUES(@DynamicInsertedId, @TicketHistoryId, @FileName, @FilePath, 1, @UserId, GETDATE());  
  END;  
  
  IF( @Product IS NOT NULL )  
  BEGIN  
   INSERT INTO tbl_tp_TicketProducts([TicketID], [ProductID], [IsActive], [CreatedBy], [CreatedOn])  
   SELECT @DynamicInsertedId, CONVERT(BIGINT, value), 1, @UserId, GETDATE()  
   FROM STRING_SPLIT(@Product, ',')  
   WHERE ISNUMERIC(value) = 1;  
  END;  
  
  DECLARE @DynamicRowJsonQuery NVARCHAR(MAX);  
  
  SET @DynamicRowJsonQuery=N'            
  SELECT @jsonResult = (            
   SELECT *             
   FROM ' + QUOTENAME(@TicketMasterTable) +  
  '             
   WHERE TicketID = @DynamicInsertedId             
   FOR JSON AUTO, INCLUDE_NULL_VALUES            
  )';  
  
  DECLARE @jsonResult NVARCHAR(MAX);  
  
  EXEC sp_executesql @DynamicRowJsonQuery, N'@DynamicInsertedId BIGINT, @jsonResult NVARCHAR(MAX) OUTPUT',  
  @DynamicInsertedId, @jsonResult OUTPUT;  
  
  SET @rowJson=@jsonResult;  
  
  IF @rowJson IS NOT NULL  
  BEGIN  
   EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData @User_id=@UserId, @Activity_type=  
   'Inst_manageticketmaster', @ActionType='I', @RowJson=@rowJson, @Table_name=@TicketMasterTable,  
   @ip_adress=@IPAdress, @device_id=@DeviceId, @IsImpersonation=@IsImpersonation, @ImpersonatorId=  
   @ImpersonatorId;  
  END;  
  ---------------------------------Start  part for activity ------------------------------------------------

    SET @DynamicSQL = 'SELECT ' + QUOTENAME(@ColumnName) + ', ' + QUOTENAME(@ColumnName1) +     
  ' FROM ' + QUOTENAME(@TicketMasterTable) +    
  ' WHERE TicketID = ' + CAST(@DynamicInsertedId AS NVARCHAR(MAX));    
  DECLARE @Result TABLE (TicketNo NVARCHAR(50), CreatedOn DATE);    
    
  INSERT INTO @Result    
  EXEC sp_executesql @DynamicSQL;    
    
  SELECT @TicketNo = TicketNo, @CreatedOn = CreatedOn FROM @Result;    
    
  exec usp_tp_RaiseEmailNotification @DynamicInsertedId,@ParentID,@AssignedGroup,@TpUserId,@AssignedUser,'New Ticket Created','Agent'    
  exec usp_tp_RaiseEmailNotification @DynamicInsertedId,@ParentID,0,@TpUserId,@TpUserId,'New Ticket Created','Requester'    
    
  SELECT @EventDesc = @UserCreated + ' has created ticket ' + @TicketNo + ' with subject ' + @TcktSubject + ' raised on ' + CONVERT(NVARCHAR(255), @CreatedOn) + ' for ' + @EntityName + ': No = ' + CONVERT(NVARCHAR(255), @EntityID)     
    
  -- EXEC Usp_tp_SaveEntityActivity_withid @entityname = @EntityName, @EntityID = @EntitytID,@UserID = @UserId, @ParentID = @ParentId, @EventDescription = @EventDesc, @EventName = 'Agent Raises Ticket', @reftables = @TicketMasterTable, @refid = @DynamicInsertedId, @refColName = 'TicketID',@Groupid = @AssignedGroup,@AgentId = @AssignedUser ,@Type = 'Agent'    
    SELECT @EventName =@EntityName+' raises new ticket'
  exec UspSaveEntityActivity_withid @entityname = @EntityName, @EntityID = @EntityID, @UserID= @UserId, @ParentID = @ParentId,@EventDescription = @EventDesc, @EventName = @EventName, @reftables = 'tbl_tp_TicketHistory', @refid= @TicketHistoryId    


  --------------------------------------------End-----------------------------------------------------------------------------
  IF( @SelectedTicket = 'New' )  
  BEGIN  
   SELECT 'Ticket Raised Successfully';  
  END;  
  IF( @SelectedTicket = 'Child' )  
  BEGIN  
   SELECT 'Child Ticket Created Successfully';  
  END;  
  IF( @SelectedTicket = 'Merge' )  
  BEGIN  
   SELECT 'Ticket Merged Successfully';  
  END;  
  IF( @SelectedTicket = 'Split' )  
  BEGIN  
   SELECT 'Ticket Splitted Successfully';  
  END;  

    insert into tbl_tp_DispatcherApplyHistory(TicketId,ParentID,DispatcherID,Mode,IsApplied,ApplyDate,IsActive,CreatedBy,CreatedDate)  
  values(@InsertedId,@ParentId,null,'Manual',0,null,1,@TpUserId,GETDATE())  
    
  insert into tbl_tp_SlaReapplyHistory(TicketId,ParentID,SlaID,Mode,IsApplied,ApplyDate,IsActive,CreatedBy,CreatedDate)  
  values(@InsertedId,@ParentId,null,'Manual',0,null,1,@TpUserId,GETDATE())  
  
 END  
 ELSE  
 BEGIN  
  IF (@TicketID > 0) -- 'Update' 
  BEGIN  
   UPDATE tbl_tp_TicketMaster SET [TicketTypeId]=@TcktType, [TicketCategoryId]=@TcktCategory,  
   [ModifiedBy]=@CreatedBy, AssignedSource=@AssignedSource, [ModifiedOn]=GETDATE(),   
   [Subject]=@TcktSubject, [Description]=@TcktDescription  
   WHERE [TicketID] = @TicketID;  
  
   CREATE TABLE #TagsData1  
   (  
    [TagData] NVARCHAR(MAX)  
   );  
  
   INSERT INTO #TagsData1([TagData])  
   SELECT value FROM STRING_SPLIT(@TcktTag, ',');  
  
   CREATE TABLE #SplitValues1  
   (  
    [OriginalData] NVARCHAR(MAX),  
    [TagIDs]       NVARCHAR(MAX),  
    [Tags]         NVARCHAR(MAX)  
   );  
  
   INSERT INTO #SplitValues1([OriginalData], [TagIDs], [Tags])  
   SELECT [TagData] AS [OriginalData],  
        CASE  
        WHEN ISNUMERIC([extracted_integers]) = 1  
         THEN [extracted_integers]  
        END AS [TagIDs], [extracted_strings] AS [Tags]  
   FROM(SELECT [TagData], STRING_AGG(CASE  
             WHEN ISNUMERIC([val]) = 1  
              THEN [val]  
             ELSE NULL  
             END, ',') AS [extracted_integers], STRING_AGG(CASE  
                       WHEN ISNUMERIC([val])  
                       = 0  
                        THEN [val]  
                       ELSE NULL  
                       END, ',') AS  
                       [extracted_strings]  
     FROM(SELECT [TagData], value AS [val] FROM #TagsData1 CROSS APPLY STRING_SPLIT(TagData, ',')) AS  
     split_values  
     GROUP BY [TagData]) AS aggregated_data;  
  
   DECLARE @InsertedTagMapping1 TABLE  
   (  
    [TagID]    INT,  
    [EntityID] INT  
   );  
  
   DECLARE @TagMasterID1 INT;  
  
   IF EXISTS(SELECT [Tags] FROM #SplitValues1 WHERE [Tags] IS NOT NULL)  
   BEGIN  
  
    DECLARE @Tag1 NVARCHAR(MAX);  
  
    DECLARE cur CURSOR  
    FOR SELECT TRIM(value) AS [Tag] FROM #SplitValues1 CROSS APPLY STRING_SPLIT(Tags, ',') WHERE  
    [Tags] IS NOT NULL;  
  
    OPEN cur;  
    FETCH NEXT FROM cur INTO @Tag1;  
  
    WHILE @@FETCH_STATUS = 0  
    BEGIN  
  
     INSERT INTO TagMaster([Tag], [ParentID], [CreatedDate], [CreatedBy], [IsActive])  
     VALUES(@Tag1, @ParentID, GETDATE(), @UserId, 1);  
  
     DECLARE @GeneratedTagID1 INT;  
     SET @GeneratedTagID1=SCOPE_IDENTITY();  
  
     DELETE FROM EntityTagMapping WHERE [EntityID] = @TicketID  
                AND [Entity] = 'TICKET';  
  
     INSERT INTO EntityTagMapping([TagID], [EntityID], [Entity], [CreatedDate])  
     VALUES(@GeneratedTagID1, @TicketID, 'Ticket', GETDATE());  
  
     FETCH NEXT FROM cur INTO @Tag1;  
   END;  
  
    CLOSE cur;  
    DEALLOCATE cur;  
  
   END;  
  
   IF EXISTS(SELECT [TagIDs] FROM #SplitValues1 WHERE [TagIDs] IS NOT NULL)  
   BEGIN  
  
    DELETE FROM EntityTagMapping  
    WHERE [EntityID] = @TicketID  
       AND [Entity] = 'TICKET'  
       AND [TagID] IN(SELECT [TagIDs] FROM [#SplitValues1]);  
  
    INSERT INTO EntityTagMapping([EntityID], [Entity], [TagID], [CreatedDate])  
    SELECT @TicketID, 'Ticket', [TagIDs], GETDATE() FROM #SplitValues1;  
   END;  
  
   DROP TABLE #TagsData1;  
   DROP TABLE #SplitValues1;  
  
   UPDATE tbl_tp_TicketMaster SET [TicketTag]=(SELECT STRING_AGG(CONVERT(NVARCHAR(MAX), [TagID]), ', ')  
   AS [CommaSeparatedEntityIDs]  
              FROM [EntityTagMapping]  
              WHERE [EntityID] = @TicketID  
                 AND [Entity] = 'Ticket');  
  
   DECLARE @TicketHistoryId1 BIGINT;  
  
   INSERT INTO tbl_tp_TicketHistory([TicketID], [TicketStatusID], [ParentID], [ActionDateTime],  
   [Remarks], [Note], [UserResponse], [AssignedUser], [TicketPriority], [AssignedSource], [AssignedBy])  
   VALUES(@InsertedId, @TcktStatus, @ParentID, NULL, NULL, NULL, NULL, @ParentID, @TcktPriority, 10,  
   @ParentID);  
  
   SET @TicketHistoryId1=SCOPE_IDENTITY();  
  
   IF( @FileName IS NOT NULL )  
  
   BEGIN  
  
    INSERT INTO tbl_tp_TicketAttachment([TicketID], [TicketHistoryID], [DisplayName], [FileUrl],  
    [IsActive], [CreatedBy], [CreatedOn])  
    VALUES(@TicketID, @TicketHistoryId, @FileName, @FilePath, 1, @UserId, GETDATE());  
  
   END;  
  
   IF @@ROWCOUNT > 0  
   BEGIN  
    SELECT 'Ticket Updated Successfully';  
   END;  
  
   DECLARE @DynamicRowJsonQuery1 NVARCHAR(MAX);  
  
   SET @DynamicRowJsonQuery=  
   N'SELECT @jsonResult = (            
   SELECT *             
   FROM ' + QUOTENAME(@TicketMasterTable) +  
   '             
   WHERE TicketID = @DynamicInsertedId             
   FOR JSON AUTO, INCLUDE_NULL_VALUES)';  
  
   DECLARE @jsonResult1 NVARCHAR(MAX);  
  
   EXEC sp_executesql @DynamicRowJsonQuery1, N'@DynamicInsertedId BIGINT, @jsonResult NVARCHAR(MAX) OUTPUT', @DynamicInsertedId, @jsonResult OUTPUT;  
  
   SET @rowJson=@jsonResult;  
  
   IF @rowJson IS NOT NULL  
   BEGIN  
    EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData @User_id=@UserId, @Activity_type=  
    'Updt_manageticketmaster', @ActionType='U', @RowJson=@rowJson, @Table_name=@TicketMasterTable,  
    @ip_adress=@IPAdress, @device_id=@DeviceId, @IsImpersonation=@IsImpersonation, @ImpersonatorId=  
    @ImpersonatorId;  
   END;  
  END;  
 END;  
END  





GO

/* ============================================================
   Procedure: [dbo].[usp_tp_AddEditTicketWithLogin_001]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_tp_AddEditTicketWithLogin_001]  
(  
 @ParentID bigint,      
 @TicketID bigint, -- 0 Add, !=0 Edit  
 @UserId BIGINT, -- kit19 UserId  
 @TcktSubject nvarchar(MAX),  
 @TcktDescription nvarchar(MAX),  
 @ParentTicketID bigint = NULL,  
 @EntityID bigint = NULL,  
 @EntityName nvarchar(50) = NULL,  
 @MobileNumber bigint = NULL,  
 @EmailID nvarchar(MAX) = NULL,  
 @MobileNumber1 bigint = NULL,  
 @EmailID1 nvarchar(MAX) = NULL,  
 @MobileNumber2 bigint = NULL,  
 @EmailID2 nvarchar(MAX) = NULL,  
 @TcktPriority bigint = NULL,  
 @TcktStatus bigint = NULL,  
 @TcktSource bigint = NULL,  
 @TcktCategory bigint = NULL,  
 @TcktType bigint = NULL,  
 @TcktTag nvarchar(MAX) = NULL,  
 @CreatedBy BIGINT = NULL,  
 @FileName nvarchar(MAX) = NULL,  
 @FilePath nvarchar(MAX) = NULL,  
 @Product nvarchar(max) = NULL,  
 @Company nvarchar(500) = NULL,  
 @AssignedGroup bigint = NULL,  
 @AssignedUser bigint = NULL,  
 @AssignedSource nvarchar(200) = Null,   
 @SelectedTicket nvarchar(10) = NULL ,  
 @CustomFieldValueJson NVARCHAR(max) ,  
 @MetaData nvarchar(MAX) = NULL,  
 @CreateEntityLogin bit=0, -- 0(Do not create login for Entity), 1(create login for Entity)  
 @ResultOut nvarchar(max) output  
)  
AS      
--    DECLARE 
--        @ParentID bigint = 32222,    
--        @UserId BIGINT = 32222,    
--        @TicketID bigint = 30346,    
--        @ParentTicketID bigint = 0,    
--        @EntityID bigint = 34128,    
--        @EntityName nvarchar(50) = N'User',    
--        @MobileNumber bigint = 0,    
--        @EmailID nvarchar(MAX) = N'',    
--        @MobileNumber1 bigint = 0,    
--        @EmailID1 nvarchar(MAX) = N'',    
--        @MobileNumber2 bigint = 0,    
--        @EmailID2 nvarchar(MAX) = N'',    
--        @TcktPriority bigint = 4,    
--        @TcktStatus bigint = 1,    
--        @TcktSource bigint = 3,    
--        @TcktCategory bigint = 103,    
--        @TcktType bigint = 12,    
--        @TcktTag nvarchar(MAX) = N'0,',    
--        @TcktSubject nvarchar(MAX) = N'sdsdnsd nsd alert test without  number test new 131025',    
--        @TcktDescription nvarchar(MAX) = N'sdsdssdsdasasnn',    
--        @CreatedBy BIGINT = 1,    
--        @FileName nvarchar(MAX) = NULL,    
--        @FilePath nvarchar(MAX) = NULL,  
--        -- @Attachement  nvarchar(MAX)='{}',
--        @CountryCode bigint = NULL,
--        @CountryCode1 bigint = NULL,
--        @CountryCode2 bigint = NULL,
--        @Option nvarchar(50) = N'Update',    
--        @Product nvarchar(max) = N'',    
--        @Company nvarchar(500) = N'',    
--        @AssignedGroup bigint = 0,    
--        @AssignedUser bigint = 88,    
--        @AssignedSource nvarchar(200) = Null,   
--        @SelectedTicket nvarchar(10) = N'',    
--        @CustomFieldValueJson NVARCHAR(max) = N'{}',    
--        @MetaData nvarchar(MAX) = N'{"IPAddress":"::1","MacAddress":"00FFB0003F75","IsImpersonation":false,"ImpersonatorId":0}',  
--        @CreateEntityLogin bit = 0, -- 0 = do not create login, 1 = create login
--        @ResultOut nvarchar(max);  -- ✅ removed "output" keyword

--SELECT @ParentID = 51532, @TicketID = 0, @UserId = 51532, @TcktSubject = 'sdfsf', @TcktDescription = 'sdfsf sdf', @EntityID = 51532, @EntityName = 'lead', @MobileNumber = '', @EmailID = '', @MobileNumber1 = '', @EmailID1 = '', @MobileNumber2 = '', @EmailID2 = '', @TcktPriority = 1, @TcktSource = 268, @TcktCategory = 1383, @TcktType = 1486, @CreatedBy = 51532, @AssignedGroup = 0, @AssignedUser = 7833, @AssignedSource = 20, @CustomFieldValueJson = NULL, @CreateEntityLogin = 0;

Begin  
   SET NOCOUNT ON;                           
                                          
  DECLARE @InsertedId BIGINT= 0, @TpUserId BIGINT, @rowJson NVARCHAR(MAX), @IPAdress NVARCHAR(50),   
  @DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT, @sqls NVARCHAR(MAX)= '',   
  @status INT, @TicketMasterTable NVARCHAR(MAX), @customfieldlist NVARCHAR(MAX),   
  @customfieldvalue NVARCHAR(MAX)= '', @DynamicQuery NVARCHAR(MAX), @Type VARCHAR(50);    
 DECLARE @ActivityId BIGINT, @EventDesc NVARCHAR(MAX),@Actitivitydesc NVARCHAR(MAX),   
  @UserCreated NVARCHAR(100), @TicketNo NVARCHAR(50), @CreatedOn DATE,@CustomFieldInsertSQL NVARCHAR(MAX) ,@CustomFieldName NVARCHAR(MAX),@EventName NVARCHAR(MAX),
  @CustomFieldsValue NVARCHAR(MAX),  @ActivityDatetime datetime=GetDate(), @TicketActivityTable nvarchar(max)    
    
    Select @TpUserId = TpUser_Id  From tbl_tp_UserLogin (noLock) Where ParentId = @ParentID and User_ID=@UserId  
                                         
    SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)                                      
    SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)                                      
    SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)  
    SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)                      
                         
	DECLARE @Keys NVARCHAR(MAX) = '';    
	DECLARE @Values NVARCHAR(MAX) = '';    
    
	 DECLARE @ColumnName NVARCHAR(100) = 'TicketNo';    
 DECLARE @ColumnName1 NVARCHAR(100) = 'CreatedOn';    
 DECLARE @DynamicSQL NVARCHAR(MAX);    

	SELECT @Keys = @Keys + CASE WHEN @Keys = '' THEN '' ELSE ',' END + QUOTENAME([key]),   
   @Values = @Values + CASE WHEN @Values = '' THEN '' ELSE ',' END +     
   CASE    
       WHEN ISJSON([value]) = 1 THEN QUOTENAME([value], '"')    
       WHEN ISNUMERIC([value]) = 1 THEN [value]    
       WHEN LOWER([value]) = 'true' THEN '1'    
       WHEN LOWER([value]) = 'false' THEN '0'    
       ELSE '''' + [value] + ''''    
   END    
   FROM OPENJSON(@CustomFieldValueJson);    
    
	SET @Values = REPLACE(@Values, '"NULL"', 'NULL');    
    
 --SELECT @Keys AS customfieldlist, @Values AS @customfieldvalue;           
                          
 EXEC @status = Usp_tp_CreateTicketMasterTableByParentID @ParentID,@TicketMasterTable OUTPUT  
  
    
	IF (@TicketID = 0) -- 'Insert'  
	BEGIN  
  If(@CreateEntityLogin = 1)  
  Begin  
   If not Exists(Select * from tbl_tp_UserLogin(nolock) Where EntityId=@EntityID and EntityName=@EntityName)  
   Begin  
    If(@EntityName='Lead')  
    Begin  
     INSERT INTO [dbo].[tbl_tp_UserLogin]  
     ([ParentId], [User_Id], [LoginName], [Pwd], [Name], [ProfileImgUrl], [Country_Code],   
     [Mobile], [Email], [Company], [Country], [City], [State],   
     [Address], [Zip], [IsInternal], [IsActive], [CreatedBy], [CreatedOn], [Timezone])  
     SELECT [ParentId], @UserId, PersonName+cast(ID as varchar), cast(ID as varchar), PersonName, [ProfileImgFileName], [CountryCode], STR([mobileno], 20, 0) AS [Mobile], [EMailid], [CompanyName], [Country], [City], [State], [ResidentialAddress], [Pincode], 1, 1, @UserId, GETDATE(), (select [Timezone] from User_Detail(nolock) where User_ID=@UserId)  
     FROM UserLeads(NOLOCK)  
     WHERE [ID] = @EntityID;  
    End  
  
    If(@EntityName='Enquiry')  
    Begin  
