  DECLARE @DynamicInsertQuery NVARCHAR(MAX);  
  DECLARE @OutputInsertedParam NVARCHAR(MAX)= N'@innerInsertedId bigint = 0 OUTPUT'
  
  -- Build dynamic SQL    
  SET @DynamicQuery=N'INSERT INTO ' + QUOTENAME(@TicketMasterTable) +  
  N' (    
   tpUser_Id, ParentId, TicketNo, RequesterMobileNo, RequesterEmailID,     
   RequesterMobileNo1, RequesterEmailID1, RequesterMobileNo2, RequesterEmailID2,                    
   Subject, Description, TicketStatusID, Remarks, Note, UserResponse,                    
   TicketPriority, AssignedUser, AssignedGroup, AssignedSource, TicketCategoryId,                    
   TicketTypeId, TicketSourceId, ProductId, IsMerged, IsSplitted,                    
   IsParentTicket, IsChildTicket, ParentTicketID, LastActionDatetime, AssignedBy,                    
   AssignedDateTime, TicketTag, EntityID, EntityName, Company, IsActive, CreatedBy,     
   CreatedOn, ModifiedBy, ModifiedOn, SplittedBy, SplittedOn, MergedBy, MergedOn,     
   ClosedBy, ClosedOn, CreatedChildBy, CreatedChildOn ' +   
   CASE WHEN @customfieldlist <> '' THEN ', ' + @customfieldlist ELSE '' END +   
   N') VALUES (' + CAST(@TpUserId AS NVARCHAR(MAX)) + ', ' + CAST(@ParentID AS NVARCHAR(MAX)) + ', ' +  
   '''000 - TICKET'', ' + '''' + REPLACE(ISNULL(@MobileNumber,''), '''', '''''') + ''', ' +   
   '''' + REPLACE(ISNULL(@EmailID, ''), '''', '''''') + ''', ' +   
   '''' + REPLACE(ISNULL(@MobileNumber1, ''),'''', '''''') + ''', ' +   
   '''' + REPLACE(ISNULL(@EmailID1, ''), '''', '''''') + ''', ' +   
   '''' + REPLACE(ISNULL(@MobileNumber2, ''), '''','''''') + ''', ' +   
   '''' + REPLACE(ISNULL(@EmailID2, ''), '''', '''''') + ''', ' +   
   '''' + REPLACE(ISNULL(@TcktSubject, ''), '''','''''') + ''', ' +   
   '''' + REPLACE(ISNULL(@TcktDescription, ''), '''', '''''') + ''', ' +   
   CAST(ISNULL(@TcktStatus, 1) AS NVARCHAR(MAX)) + ', ' + 'NULL, NULL, NULL, ' +   
   -- Remarks, Note, UserResponse    
   CAST(ISNULL(@TcktPriority, 0) AS NVARCHAR(MAX)) + ', ' +   
   -- TicketPriority  
   CAST(ISNULL(@ParentID,0) AS NVARCHAR(MAX)) + ', ' + CAST(ISNULL(@AssignedGroup,0) AS NVARCHAR(MAX)) +   
   ', ''' + @AssignedSource + ''', ' + CAST(ISNULL(@TcktCategory, 0) AS NVARCHAR(MAX)) + ', ' + CAST(ISNULL(@TcktType, 0) AS NVARCHAR(MAX)) + ', ' + CAST(ISNULL(@TcktSource, 0) AS NVARCHAR(MAX)) + ', ' + 'NULL, 0, 0, 0, 0, ' + -- IsMerged, IsSplitted, IsParentTicket, IsChildTicket  
   CAST(ISNULL(@ParentTicketID, 0) AS NVARCHAR(MAX)) + ', GETDATE(), ' + 'NULL, GETDATE(), ' +   
   -- ParentTicketID, LastActionDatetime, AssignedBy, AssignedDateTime    
   'NULL' + ', ' + -- TicketTag (replace 'NULL' with an appropriate value)    
   CAST(ISNULL(@EntityID, 0) AS NVARCHAR(MAX)) + ', ' + -- EntityID    
   '''' + ISNULL(@EntityName, '') + ''', ''' + REPLACE(ISNULL(@Company, ''), '''', '''''')  
   + ''', 1, ' + -- EntityName, Company, IsActive    
   CAST(ISNULL(@CreatedBy, 0) AS NVARCHAR(MAX)) +  
   ', GETDATE(), NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL';  
  
  -- Append custom field values if they are provided    
	IF @customfieldvalue <> ''  
	BEGIN  
	SET @DynamicQuery= @DynamicQuery + N', ' + @customfieldvalue;  
  END  
  
  -- Complete the query    
  SET @DynamicQuery=@DynamicQuery + N'); Select @innerInsertedId = scope_identity(); ';  
  

  -- Execute the dynamic query    
  EXEC sp_executesql @DynamicQuery, @OutputInsertedParam, @innerInsertedId = @InsertedId output;  
 
