   EXEC sp_executesql @UpdateQuery1, N'@TicketID INT', @TicketID;  
  
   SET @UpdateQuery1=N'UPDATE ' + QUOTENAME(@TicketMasterTable) +  
   ' SET ParentTicketID = @ParentTicketID WHERE  TicketID = @DynamicInsertedId';  
  
   EXEC sp_executesql @UpdateQuery1, N'@TicketID INT', @TicketID;  
