  CREATE TABLE #TagsData  
  (  
   [TagData] NVARCHAR(MAX)  
  );  
  
  INSERT INTO #TagsData([TagData])  
  SELECT value FROM STRING_SPLIT(@TcktTag, ',');  
  
  CREATE TABLE #SplitValues  
  (  
   [OriginalData] NVARCHAR(MAX),  
   [TagIDs]       NVARCHAR(MAX),  
   [Tags]         NVARCHAR(MAX)  
  );  
  
  INSERT INTO #SplitValues([OriginalData], [TagIDs], [Tags])  
  SELECT [TagData] AS [OriginalData],  
       CASE  
       WHEN ISNUMERIC([extracted_integers]) = 1  
        THEN [extracted_integers]  
       END AS [TagIDs], [extracted_strings] AS [Tags]  
  FROM(SELECT [TagData], STRING_AGG(CASE WHEN ISNUMERIC([val]) = 1 THEN [val] ELSE NULL END, ',') AS [extracted_integers], STRING_AGG(CASE WHEN ISNUMERIC([val]) = 0 THEN [val] ELSE NULL END, ',') AS [extracted_strings]  
    FROM(SELECT [TagData], value AS [val] FROM #TagsData CROSS APPLY STRING_SPLIT(TagData, ',')) AS  
    split_values  
    GROUP BY [TagData]) AS aggregated_data;  
  
  DECLARE @InsertedTagMapping TABLE  
  (  
   [TagID]    INT,  
   [EntityID] INT  
  );  
  
  DECLARE @TagMasterID INT;  
  IF EXISTS(SELECT [Tags] FROM #SplitValues WHERE [Tags] IS NOT NULL)  
  BEGIN  
  
   DECLARE @Tag NVARCHAR(MAX);  
  
   -- Create a table variable to hold tags with row numbers
    DECLARE @TagsToProcess TABLE (
        RowNum INT IDENTITY(1,1),
        Tag NVARCHAR(MAX)
    );

    -- Populate the table with tags to process
    INSERT INTO @TagsToProcess (Tag)
    SELECT TRIM(value) AS [Tag] 
    FROM #SplitValues 
    CROSS APPLY STRING_SPLIT(Tags, ',') 
    WHERE [Tags] IS NOT NULL;

    -- Initialize variables
    DECLARE @CurrentRow INT = 1;
    DECLARE @TotalRows INT = (SELECT COUNT(*) FROM @TagsToProcess);
    DECLARE @GeneratedTagID INT;

    -- Loop through each tag
    WHILE @CurrentRow <= @TotalRows
    BEGIN
        -- Get the current tag
        SELECT @Tag = Tag 
        FROM @TagsToProcess 
        WHERE RowNum = @CurrentRow;
    
        -- Insert into TagMaster
        INSERT INTO TagMaster([Tag], [ParentID], [CreatedDate], [CreatedBy], [IsActive])
        VALUES(@Tag, @ParentID, GETDATE(), @UserId, 1);
    
        -- Capture the generated ID
        SET @GeneratedTagID = SCOPE_IDENTITY();
    
        -- Insert into EntityTagMapping
        INSERT INTO EntityTagMapping([TagID], [EntityID], [Entity], [CreatedDate])
        VALUES(@GeneratedTagID, @InsertedId, 'Ticket', GETDATE());
    
        -- Move to next row
        SET @CurrentRow = @CurrentRow + 1;
    END;
  
  END;  
  
  IF EXISTS(SELECT [TagIDs] FROM #SplitValues WHERE [TagIDs] IS NOT NULL)  
  BEGIN  
   INSERT INTO EntityTagMapping([EntityID], [Entity], [TagID], [CreatedDate])  
   SELECT @InsertedId, 'Ticket', [TagIDs], GETDATE() FROM #SplitValues;  
  
  END;  
  
