     SET @GeneratedTagID1=SCOPE_IDENTITY();  
  
     DELETE FROM EntityTagMapping WHERE [EntityID] = @TicketID  
                AND [Entity] = 'TICKET';  
  
     INSERT INTO EntityTagMapping([TagID], [EntityID], [Entity], [CreatedDate])  
     VALUES(@GeneratedTagID1, @TicketID, 'Ticket', GETDATE());  
  
     FETCH NEXT FROM cur INTO @Tag1;  
   END;  
  
    CLOSE cur;  
    DEALLOCATE cur;  
  
   END;  
  
   IF EXISTS(SELECT [TagIDs] FROM #SplitValues1 WHERE [TagIDs] IS NOT NULL)  
   BEGIN  
  
    DELETE FROM EntityTagMapping  
    WHERE [EntityID] = @TicketID  
       AND [Entity] = 'TICKET'  
       AND [TagID] IN(SELECT [TagIDs] FROM [#SplitValues1]);  
  
    INSERT INTO EntityTagMapping([EntityID], [Entity], [TagID], [CreatedDate])  
    SELECT @TicketID, 'Ticket', [TagIDs], GETDATE() FROM #SplitValues1;  
   END;  
  
   DROP TABLE #TagsData1;  
   DROP TABLE #SplitValues1;  
  
   UPDATE tbl_tp_TicketMaster SET [TicketTag]=(SELECT STRING_AGG(CONVERT(NVARCHAR(MAX), [TagID]), ', ')  
   AS [CommaSeparatedEntityIDs]  
              FROM [EntityTagMapping]  
              WHERE [EntityID] = @TicketID  
                 AND [Entity] = 'Ticket');  
  
   DECLARE @TicketHistoryId1 BIGINT;  
  
   INSERT INTO tbl_tp_TicketHistory([TicketID], [TicketStatusID], [ParentID], [ActionDateTime],  
   [Remarks], [Note], [UserResponse], [AssignedUser], [TicketPriority], [AssignedSource], [AssignedBy])  
   VALUES(@InsertedId, @TcktStatus, @ParentID, NULL, NULL, NULL, NULL, @ParentID, @TcktPriority, 10,  
   @ParentID);  
  
   SET @TicketHistoryId1=SCOPE_IDENTITY();  
  
   IF( @FileName IS NOT NULL )  
  
   BEGIN  
  
    INSERT INTO tbl_tp_TicketAttachment([TicketID], [TicketHistoryID], [DisplayName], [FileUrl],  
    [IsActive], [CreatedBy], [CreatedOn])  
    VALUES(@TicketID, @TicketHistoryId, @FileName, @FilePath, 1, @UserId, GETDATE());  
  
   END;  
  
   IF @@ROWCOUNT > 0  
   BEGIN  
    SELECT 'Ticket Updated Successfully';  
   END;  
  
   DECLARE @DynamicRowJsonQuery1 NVARCHAR(MAX);  
  
   SET @DynamicRowJsonQuery=  
   N'SELECT @jsonResult = (            
   SELECT *             
   FROM ' + QUOTENAME(@TicketMasterTable) +  
   '             
   WHERE TicketID = @DynamicInsertedId             
   FOR JSON AUTO, INCLUDE_NULL_VALUES)';  
  
   DECLARE @jsonResult1 NVARCHAR(MAX);  
  
   EXEC sp_executesql @DynamicRowJsonQuery1, N'@DynamicInsertedId BIGINT, @jsonResult NVARCHAR(MAX) OUTPUT', @DynamicInsertedId, @jsonResult OUTPUT;  
  
   SET @rowJson=@jsonResult;  
  
   IF @rowJson IS NOT NULL  
   BEGIN  
    EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData @User_id=@UserId, @Activity_type=  
    'Updt_manageticketmaster', @ActionType='U', @RowJson=@rowJson, @Table_name=@TicketMasterTable,  
    @ip_adress=@IPAdress, @device_id=@DeviceId, @IsImpersonation=@IsImpersonation, @ImpersonatorId=  
    @ImpersonatorId;  
   END;  
  END;  
 END;  
END  





