/* ============================================================
   Procedure: [dbo].[Usp_tp_Advance_EmailSettings]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_tp_Advance_EmailSettings]
    @TpUserID VARCHAR(50),
    @ConfigureDKIM BIT = 0,
    @SetAutomaticBccEmail BIT = 0,
    @ConfigurePrefixForTicketID BIT = 0,
    @AllowAgentsToInitiateConversation BIT = 0,
    @UseAgentNamesInTicketReplies BIT = 0,
    @UseReplyToEmailAddress BIT = 0,
    @ForForwardedEmailsUseOriginalSender BIT = 0,
    @AllowEmailsToBeSentToWildcardAddress BIT = 0,
    @CreateNewTicketForCustomerResponse BIT = 0,
    @IgnoreSenderEmailForThread BIT = 0,
    @DetectAutomatedReplies BIT = 0,
    @EnableAllMessagesInQuotedText BIT = 0,
    @CreateNewTicketWhenSubjectChanges BIT = 0
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @ExistingEmailSettingID INT

    -- Check if the settings already exist for the provided TpUserID
    SELECT @ExistingEmailSettingID = AdvanceEmailSettingID
    FROM tpl_tp_AdvanceEmailSettings(nolock)
    WHERE TpUserID = @TpUserID

    IF @ExistingEmailSettingID IS NOT NULL
    BEGIN
        -- Update settings if the user already exists
        UPDATE tpl_tp_AdvanceEmailSettings
        SET
            ConfigureDKIM = @ConfigureDKIM,
            SetAutomaticBccEmail = @SetAutomaticBccEmail,
            ConfigurePrefixForTicketID = @ConfigurePrefixForTicketID,
            AllowAgentsToInitiateConversation = @AllowAgentsToInitiateConversation,
            UseAgentNamesInTicketReplies = @UseAgentNamesInTicketReplies,
            UseReplyToEmailAddress = @UseReplyToEmailAddress,
            ForForwardedEmailsUseOriginalSender = @ForForwardedEmailsUseOriginalSender,
            AllowEmailsToBeSentToWildcardAddress = @AllowEmailsToBeSentToWildcardAddress,
            CreateNewTicketForCustomerResponse = @CreateNewTicketForCustomerResponse,
            IgnoreSenderEmailForThread = @IgnoreSenderEmailForThread,
            DetectAutomatedReplies = @DetectAutomatedReplies,
            EnableAllMessagesInQuotedText = @EnableAllMessagesInQuotedText,
            CreateNewTicketWhenSubjectChanges = @CreateNewTicketWhenSubjectChanges
        WHERE TpUserID = @TpUserID
    END
    ELSE
    BEGIN
        -- Insert settings if the user doesn't exist
        INSERT INTO tpl_tp_AdvanceEmailSettings (
            TpUserID,
            ConfigureDKIM,
            SetAutomaticBccEmail,
            ConfigurePrefixForTicketID,
            AllowAgentsToInitiateConversation,
            UseAgentNamesInTicketReplies,
            UseReplyToEmailAddress,
            ForForwardedEmailsUseOriginalSender,
            AllowEmailsToBeSentToWildcardAddress,
            CreateNewTicketForCustomerResponse,
            IgnoreSenderEmailForThread,
            DetectAutomatedReplies,
            EnableAllMessagesInQuotedText,
            CreateNewTicketWhenSubjectChanges
        )
        VALUES (
            @TpUserID,
            @ConfigureDKIM,
            @SetAutomaticBccEmail,
            @ConfigurePrefixForTicketID,
            @AllowAgentsToInitiateConversation,
            @UseAgentNamesInTicketReplies,
            @UseReplyToEmailAddress,
            @ForForwardedEmailsUseOriginalSender,
            @AllowEmailsToBeSentToWildcardAddress,
            @CreateNewTicketForCustomerResponse,
            @IgnoreSenderEmailForThread,
            @DetectAutomatedReplies,
            @EnableAllMessagesInQuotedText,
            @CreateNewTicketWhenSubjectChanges
        )
    END
END



