			@MobileNumber NVARCHAR(20),@EmailID NVARCHAR(200),@EntitytID BIGINT,@EntityName NVARCHAR(20)    
  
	Exec usp_tp_CreateEntityForLogin @TpUserId  
  
    Select	@UserId = User_ID, @ParentID = ParentId, @MobileNumber = Mobile, @EmailID = Email, 
			@EntitytID = EntityId, @EntityName = EntityName 
