    SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)           
                                                 
	DECLARE @Keys NVARCHAR(MAX) = '';        
	DECLARE @Values NVARCHAR(MAX) = '';        
           
	DECLARE @ActivityId BIGINT, @EventDesc NVARCHAR(MAX), @UserCreated NVARCHAR(100), @TicketNo NVARCHAR(50), @CreatedOn DATE, @TicketHistoryId BIGINT = 0         
          
	SELECT @UserCreated = isnull(Name,LoginName) FROM tbl_tp_UserLogin(noLock) WHERE TpUser_Id = @TpUserId AND IsActive = 1
	DECLARE @ColumnName NVARCHAR(100) = 'TicketNo';          
	DECLARE @ColumnName1 NVARCHAR(100) = 'CreatedOn';          
	DECLARE @DynamicSQL NVARCHAR(MAX);          
                            
	SELECT	@Keys = @Keys + CASE WHEN @Keys = '' THEN '' ELSE ',' END + QUOTENAME([key]),
			@Values = @Values + CASE WHEN @Values = '' THEN '' ELSE ',' END +                             
			CASE WHEN ISJSON([value]) = 1 THEN QUOTENAME([value], '"')
			WHEN ISNUMERIC([value]) = 1 THEN [value]                       
			WHEN LOWER([value]) = 'true' THEN '1'                            
			WHEN LOWER([value]) = 'false' THEN '0'                            
			ELSE '''' + [value] + ''''                            
		   END                            
	FROM OPENJSON(@CustomFieldValueJson);                   
                            
	SET @Values = REPLACE(@Values, '"NULL"', 'NULL');                            
                                                                                       
  EXEC @status = Usp_tp_CreateTicketMasterTableByParentID @ParentID,@TicketMasterTable OUTPUT          
                            
  IF @Option = 'Insert'
  BEGIN
                                             
	DECLARE @DynamicInsertQuery NVARCHAR(MAX);                                            
     
	 
print concat('line 108:',' EntityName: ',@entityname,', Entityid: ',@entitytid, ', Requester email: ',@emailid)
	SET @DynamicQuery =
	N'INSERT INTO ' + QUOTENAME(@TicketMasterTable) + N' (
	tpUser_Id, ParentId, TicketNo, RequesterMobileNo, RequesterEmailID,
	RequesterMobileNo1, RequesterEmailID1, RequesterMobileNo2, RequesterEmailID2,
	Subject, Description, TicketStatusID, Remarks, Note, UserResponse,
	TicketPriority, AssignedUser, AssignedGroup, AssignedSource, TicketCategoryId,
	TicketTypeId, TicketSourceId, ProductId, IsMerged, IsSplitted,
	IsParentTicket, IsChildTicket, ParentTicketID, LastActionDatetime, AssignedBy,
	AssignedDateTime, TicketTag, EntityID, EntityName, Company, IsActive, CreatedBy,
	CreatedOn, ModifiedBy, ModifiedOn, SplittedBy, SplittedOn, MergedBy, MergedOn,
	ClosedBy, ClosedOn, CreatedChildBy, CreatedChildOn ' +
	CASE WHEN @Keys <> '' THEN ', ' + @Keys ELSE '' END +
	N') 
	VALUES (
	' + CAST(@TpUserId AS NVARCHAR(MAX)) + ', ' +
	CAST(ISNULL(@ParentID, 0) AS NVARCHAR(MAX)) + ', ' +
	'''000 - TICKET'', ' +
	'''' + REPLACE(ISNULL(@MobileNumber, ''), '''', '''''') + ''', ' +
	'''' + REPLACE(ISNULL(@EmailID, ''), '''', '''''') + ''', ' +
	'''' + REPLACE(ISNULL(NULL, 'NA'), '''', '''''') + ''', ' +
	'''' + REPLACE(ISNULL(NULL, 'NA'), '''', '''''') + ''', ' +
	'''' + REPLACE(ISNULL(NULL, 'NA'), '''', '''''') + ''', ' +
	'''' + REPLACE(ISNULL(NULL, 'NA'), '''', '''''') + ''', ' +
	'''' + REPLACE(ISNULL(@TcktSubject, ''), '''', '''''') + ''', ' +
	'''' + REPLACE(ISNULL(@TcktDescription, ''), '''', '''''') + ''', ' +
	CAST(ISNULL(@TcktStatus, 0) AS NVARCHAR(MAX)) + ', ' +
	'NULL, ''Ticket Created'', NULL, ' + -- Remarks, Note, UserResponse
	CAST(ISNULL(@TcktPriority, 0) AS NVARCHAR(MAX)) + ', ' + -- TicketPriority
	CAST(ISNULL(NULL, 0) AS NVARCHAR(MAX)) + ', ' +
	CAST(ISNULL(NULL, 0) AS NVARCHAR(MAX)) + ', ' +
	'''Customer'', ' +
	CAST(ISNULL(@TcktCategory, 0) AS NVARCHAR(MAX)) + ', ' +
	CAST(ISNULL(@TcktType, 0) AS NVARCHAR(MAX)) + ', ' +
	CAST(ISNULL(49, 0) AS NVARCHAR(MAX)) + ', ' +
	CAST(ISNULL( @TcktProduct, 0) AS NVARCHAR(MAX)) + ', ' +
	'0, 0, 0, 0, ' + -- IsMerged, IsSplitted, IsParentTicket, IsChildTicket
	CAST(ISNULL(0, 0) AS NVARCHAR(MAX)) + ', GETDATE(), ' +
	'NULL, GETDATE(), ' + -- ParentTicketID, LastActionDatetime, AssignedBy, AssignedDateTime
	'NULL' + ', ' + -- TicketTag (replace 'NULL' with an appropriate value)
	CAST(ISNULL(@EntitytID, 0) AS NVARCHAR(MAX)) + ', ' + -- EntityID
	'''' + ISNULL(@EntityName, '') + ''', ''' + REPLACE(ISNULL(@Company, ''), '''', '''''') + ''', 1, ' + -- EntityName, Company, IsActive
	CAST(ISNULL(@TpUserId, 0) AS NVARCHAR(MAX)) + ', GETDATE(), NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL '; -- Other field values
           
	IF @Values <> ''
	BEGIN
		SET @DynamicQuery = @DynamicQuery + N', ' + @Values + N'); Set @Ticket_Id=Scope_Identity()';
	END
	ELSE
	BEGIN
		SET @DynamicQuery = @DynamicQuery + N'); Set @Ticket_Id=Scope_Identity()';
	END
                                                             
    Print @DynamicQuery                            
 
	EXEC sp_executesql @DynamicQuery, N'@Ticket_Id BIGINT OUTPUT', @Ticket_Id=@InsertedId OUTPUT;        
       
	print '@InsertedId: ' + cast(@InsertedId as varchar)      
      
                                      
	DECLARE @DynamicInsertedId BIGINT;
	DECLARE @MaxIdQuery NVARCHAR(MAX);

	Set @DynamicInsertedId=@InsertedId

	DECLARE @UpdateQuery NVARCHAR(MAX);

	--SET @UpdateQuery = N'
	--UPDATE ' + QUOTENAME(@TicketMasterTable) + '                                      
	--SET TicketNo = ''000'' + CAST(@Ticket_ID AS NVARCHAR(20)) + '' - AGENT''  
	--WHERE TicketID = @Ticket_ID';                                      
	--EXEC sp_executesql @UpdateQuery, N'@Ticket_ID BIGINT', @Ticket_ID=@DynamicInsertedId; 
SET @DynamicInsertedId = @InsertedId;
DECLARE @UpdateNumberQuery NVARCHAR(MAX);
DECLARE @NextTicketNo NVARCHAR(100);
DECLARE @LastTicketNo NVARCHAR(50);
DECLARE @CurrentNumber INT;
DECLARE @Prefix NVARCHAR(50) = '';
DECLARE @Suffix NVARCHAR(50) = '';
DECLARE @ParamDefinition NVARCHAR(MAX);
DECLARE @fetchnumberSQL NVARCHAR(MAX);
DECLARE @ExtractedNumber NVARCHAR(20) = '';
DECLARE @LeadingZeros NVARCHAR(20) = '';
DECLARE @IncrementedNumber NVARCHAR(20);
DECLARE @Pattern NVARCHAR(50);
DECLARE @LastDigitPos INT;
DECLARE @FormatJson NVARCHAR(MAX);
DECLARE @Number NVARCHAR(50) = '';

-- Fetch the FormatJson from tbl_tp_TicketNoFormat
SELECT @FormatJson = FormatJson
FROM tbl_tp_TicketNoFormat(nolock)
WHERE ParentId = @ParentID AND IsActive = 1;

-- Declare a table to store format values
DECLARE @FormatValues TABLE (
    [Value] NVARCHAR(50),
    [DataType] NVARCHAR(50)
);


INSERT INTO @FormatValues ([Value], [DataType])
SELECT 
    JSON_VALUE(value, '$.value') AS [Value],
    JSON_VALUE(value, '$.datatype') AS [DataType]
FROM OPENJSON(@FormatJson, '$.FormatValues');
SELECT TOP 1 @Prefix = COALESCE([Value], '') 
FROM @FormatValues WHERE [DataType] = 'prefix';
SELECT TOP 1 @Number = COALESCE([Value], '0') 
FROM @FormatValues WHERE [DataType] = 'number';
SELECT TOP 1 @Suffix = COALESCE([Value], '') 
FROM @FormatValues WHERE [DataType] = 'suffix';

SET @fetchnumberSQL = N'
SELECT TOP 1 @LastTicketNo = TicketNo
FROM ' + QUOTENAME(@TicketMasterTable) + '
WHERE TicketNo LIKE @Prefix + ''%'' + @Suffix
ORDER BY TicketID DESC;';

SET @ParamDefinition = N'@LastTicketNo NVARCHAR(50) OUTPUT, @Prefix NVARCHAR(50), @Suffix NVARCHAR(50)';


EXEC sp_executesql 
    @fetchnumberSQL, 
    @ParamDefinition, 
    @LastTicketNo = @LastTicketNo OUTPUT, 
    @Prefix = @Prefix, 
    @Suffix = @Suffix;

IF @LastTicketNo IS NULL AND @FormatJson IS NOT NULL
BEGIN
    IF @Number IS NULL
        SET @Number = '1';
    SET @NextTicketNo = @Prefix + @Number + @Suffix;
    SET @UpdateNumberQuery = N'
    UPDATE ' + QUOTENAME(@TicketMasterTable) + '    
    SET TicketNo = @NextTicketNo    
    WHERE TicketID = @Ticket_ID';
    EXEC sp_executesql @UpdateNumberQuery, N'@Ticket_ID BIGINT, @NextTicketNo NVARCHAR(50)', @Ticket_ID = @DynamicInsertedId, @NextTicketNo = @NextTicketNo;
END


ELSE IF @LastTicketNo IS NOT NULL AND @FormatJson IS NOT NULL
BEGIN

    SET @LastDigitPos = LEN(@LastTicketNo) - LEN(@Suffix);


    SET @ExtractedNumber = SUBSTRING(@LastTicketNo, LEN(@Prefix) + 1, @LastDigitPos - LEN(@Prefix));


    IF LEFT(@ExtractedNumber, 1) = '0'
    BEGIN
        SET @IncrementedNumber = CAST(CAST(@ExtractedNumber AS INT) + 1 AS NVARCHAR(20));
        SET @LeadingZeros = REPLICATE('0', LEN(@ExtractedNumber) - LEN(@IncrementedNumber));
        SET @Number = @LeadingZeros + @IncrementedNumber;
    END
    ELSE
    BEGIN
        SET @IncrementedNumber = CAST(CAST(@ExtractedNumber AS INT) + 1 AS NVARCHAR(20));
        SET @Number = @IncrementedNumber;
    END

    SET @NextTicketNo = @Prefix + @Number + @Suffix;

    SET @UpdateNumberQuery = N'
    UPDATE ' + QUOTENAME(@TicketMasterTable) + '    
    SET TicketNo = @NextTicketNo    
    WHERE TicketID = @Ticket_ID';

    EXEC sp_executesql @UpdateNumberQuery, N'@Ticket_ID BIGINT, @NextTicketNo NVARCHAR(50)', @Ticket_ID = @DynamicInsertedId, @NextTicketNo = @NextTicketNo;
END

ELSE IF  @FormatJson IS NULL 
BEGIN

	SET @UpdateQuery = N'
	UPDATE ' + QUOTENAME(@TicketMasterTable) + '                                      
	SET TicketNo = ''000'' + CAST(@Ticket_ID AS NVARCHAR(20)) + '' - AGENT''  
	WHERE TicketID = @Ticket_ID';                                      
	EXEC sp_executesql @UpdateQuery, N'@Ticket_ID BIGINT', @Ticket_ID=@DynamicInsertedId; 
END

	DECLARE @UpdateQuery1 NVARCHAR(MAX);         
                               
	CREATE TABLE #TagsData 
	(
		TagData NVARCHAR(MAX)
	);
                                                      
	INSERT INTO #TagsData (TagData)
	SELECT value FROM STRING_SPLIT(@TcktTag, ',');
                                                      
	CREATE TABLE #SplitValues 
	(
		OriginalData NVARCHAR(MAX),
		TagIDs NVARCHAR(MAX),
		Tags NVARCHAR(MAX)
	);
                                                      
	INSERT INTO #SplitValues (OriginalData, TagIDs, Tags)
	SELECT	TagData AS OriginalData,
			CASE WHEN ISNUMERIC(extracted_integers) = 1 THEN extracted_integers END AS TagIDs,
			extracted_strings AS Tags
	FROM (
		SELECT TagData,
		STRING_AGG(CASE WHEN ISNUMERIC(val) = 1 THEN val ELSE NULL END, ',') AS extracted_integers,
		STRING_AGG(CASE WHEN ISNUMERIC(val) = 0 THEN val ELSE NULL END, ',') AS extracted_strings
		FROM (
			SELECT TagData, value AS val
			FROM #TagsData
			CROSS APPLY STRING_SPLIT(TagData, ',')
		) AS split_values
		GROUP BY TagData
	) AS aggregated_data;
                                                      
	DECLARE @InsertedTagMapping TABLE (TagID INT, EntityID INT);
                            
	DECLARE @TagMasterID INT;
       
	IF EXISTS (SELECT Tags FROM #SplitValues WHERE Tags IS NOT NULL)
	BEGIN
		DECLARE @Tag NVARCHAR(MAX);

		DECLARE cur CURSOR FOR
		SELECT TRIM(value) AS Tag
		FROM #SplitValues
		CROSS APPLY STRING_SPLIT(Tags, ',')
		WHERE Tags IS NOT NULL;

		OPEN cur;
		FETCH NEXT FROM cur INTO @Tag;

		WHILE @@FETCH_STATUS = 0
		BEGIN
			INSERT INTO TagMaster (Tag, ParentID, CreatedDate, CreatedBy, IsActive)
			VALUES (@Tag, @ParentID, GETDATE(), @UserId, 1);

			DECLARE @GeneratedTagID INT;
			SET @GeneratedTagID = SCOPE_IDENTITY();

			INSERT INTO EntityTagMapping (TagID, EntityID, Entity, CreatedDate,ParentId)
			VALUES (@GeneratedTagID, @InsertedId, 'Ticket', GETDATE(),@ParentID);

			FETCH NEXT FROM cur INTO @Tag;
		END;

		CLOSE cur;
		DEALLOCATE cur;
	END;        
                                                      
	IF EXISTS (SELECT TagIDs FROM #SplitValues WHERE TagIDs IS NOT NULL)
	BEGIN
		INSERT INTO EntityTagMapping (EntityID, Entity, TagID, CreatedDate,ParentId)
		SELECT @InsertedId, 'Ticket', TagIDs, GETDATE() , @ParentID
		FROM #SplitValues
	END;
                                                                         
	DROP TABLE #TagsData;
	DROP TABLE #SplitValues;
                                                      
	DECLARE @DynamicTicketTagUpdate NVARCHAR(MAX);
	SET @DynamicTicketTagUpdate = N'
	UPDATE ' + QUOTENAME(@TicketMasterTable) + N'
	SET TicketTag = STUFF(
	(SELECT '', '' + CONVERT(NVARCHAR(MAX), TagID)
	FROM EntityTagMapping
	WHERE EntityID = @Ticket_ID AND Entity = ''Ticket''
	FOR XML PATH ('''')), 1, 2, '''')
	WHERE TicketID = @Ticket_ID;';
                                            
	EXEC sp_executesql @DynamicTicketTagUpdate, N'@Ticket_ID BIGINT', @Ticket_ID=@DynamicInsertedId;                     
	INSERT INTO tbl_tp_TicketHistory (TicketID,TicketStatusID,ParentID,ActionDateTime,Remarks,Note,UserResponse,AssignedUser,AssignedGroup,TicketPriority,AssignedSource,AssignedBy)
	VALUES (@DynamicInsertedId ,@TcktStatus,@ParentID,getdate(),NULL,'Ticket Created',NULL,0,0,@TcktPriority,'Customer',@TpUserId)

    SET @TicketHistoryId = SCOPE_IDENTITY();                                                      
                                                      
	--IF (@FileName IS NOT NULL)
	--BEGIN
