        SELECT @DynamicInsertedId, @TicketHistoryId, FileName, FilePath, 1, @TpUserId, GETDATE(),@ParentID
        FROM @jsonTable;
    END
                          
	DECLARE @DynamicRowJsonQuery NVARCHAR(MAX);                                    
                                    
	SET @DynamicRowJsonQuery = N'
	SELECT @json_Result = (
	SELECT *
	FROM ' + QUOTENAME(@TicketMasterTable) + '
	WHERE TicketID = @Ticket_ID
	FOR JSON AUTO, INCLUDE_NULL_VALUES
	)';
                                    
	DECLARE @jsonResult NVARCHAR(MAX);                                    
                                    
	EXEC sp_executesql @DynamicRowJsonQuery, N'@Ticket_ID BIGINT, @json_Result NVARCHAR(MAX) OUTPUT', @Ticket_ID=@DynamicInsertedId, @json_Result=@jsonResult OUTPUT;                                                              
	SET @rowJson = @jsonResult;
	
	IF @rowJson IS NOT NULL
	BEGIN
		EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData
		@User_id = @ParentID, -- @UserId, -- external user
		@Activity_type = 'Inst_agentraiseticketmaster',
		@ActionType = 'I',
		@RowJson = @rowJson,
		@Table_name = @TicketMasterTable,
		@ip_adress = @IPAdress,
		@device_id = @DeviceId,
		@IsImpersonation = @IsImpersonation,
		@ImpersonatorId = @ImpersonatorId;

		SELECT 'Ticket Raised Successfully';
	END
  
	 exec usp_tp_RaiseEmailNotification @DynamicInsertedId,@ParentID,0,@TpUserId,@TpUserId,'New Ticket Created','Agent'  
	 exec usp_tp_RaiseEmailNotification @DynamicInsertedId,@ParentID,0,@TpUserId,@TpUserId,'New Ticket Created','Requester'  
     
	SET @DynamicSQL = 'SELECT ' + QUOTENAME(@ColumnName) + ', ' + QUOTENAME(@ColumnName1) + ' FROM ' + QUOTENAME(@TicketMasterTable) + ' WHERE TicketID = ' + CAST(@DynamicInsertedId AS NVARCHAR(MAX));          
	DECLARE @Result TABLE (TicketNo NVARCHAR(50), CreatedOn DATE);          
          
	INSERT INTO @Result          
	EXEC sp_executesql @DynamicSQL;          
          
	SELECT @TicketNo = TicketNo, @CreatedOn = CreatedOn FROM @Result;          
          print concat('@UserCreated: ',@UserCreated)
          print concat('@TicketNo: ',@TicketNo)
          print concat('@TcktSubject: ',@TcktSubject)
          print concat('@CreatedOn: ',@CreatedOn)
          print concat('@EntityName: ',@EntityName)
          print concat('@EntitytID: ',@EntitytID)
	SELECT @EventDesc = @UserCreated + ' has created ticket ' + @TicketNo + ' with subject ' + @TcktSubject + ' raised on ' + CONVERT(NVARCHAR(255), @CreatedOn) + ' for ' + @EntityName + ': No = ' + CONVERT(NVARCHAR(255), @EntitytID) 

	print concat('@EventDesc: ',@EventDesc)
          
	exec UspSaveEntityActivity_withid @entityname = @EntityName, @EntityID = @EntitytID, @UserID= @ParentID, @ParentID = @ParentID, @EventDescription = @EventDesc, @EventName = 'Lead raises new ticket', @reftables = 'tbl_tp_ticketHistory', @refid= @TicketHistoryId

	-- EXEC Usp_tp_SaveEntityActivity_withid @entityname = @EntityName, @EntityID = @EntitytID,  @UserID = @ParentID, @ParentID = @ParentId, @EventDescription = @EventDesc, @EventName = 'Lead raises ticket', @reftables = @TicketMasterTable, @refid = @DynamicInsertedId, @refColName = 'TicketID', @Groupid = 0, @AgentId =  @ParentID, @Type = 'Requester'

	 
	  insert into tbl_tp_DispatcherApplyHistory(TicketId,ParentID,DispatcherID,Mode,IsApplied,ApplyDate,IsActive,CreatedBy,CreatedDate)  
	  values(@DynamicInsertedId,@ParentID,null,'Manual',0,null,1,@TpUserId,GETDATE())  
    
	  insert into tbl_tp_SlaReapplyHistory(TicketId,ParentID,SlaID,Mode,IsApplied,ApplyDate,IsActive,CreatedBy,CreatedDate)  
	  values(@DynamicInsertedId,@ParentID,null,'Manual',0,null,1,@TpUserId,GETDATE())  
		
  END                                                 
  ELSE IF @Option = 'Update'
  BEGIN
    DECLARE @DynamicUpdateQuery NVARCHAR(MAX);          

	drop table if exists #tblTicketBeforeEdit
	drop table if exists #tblTicketAfterEdit
	drop table if exists #tblFields

	create table #tblTicketBeforeEdit
	(
		TicketID			bigint,
		tpUser_Id			bigint,
		ParentID			bigint,
		TicketNo			nvarchar(100),	     	     
		RequesterMobileNo	nvarchar(100),	     	     
		RequesterEmailID	nvarchar(400),	     	     
		RequesterMobileNo1	nvarchar(100),	     	     
		RequesterEmailID1	nvarchar(400),	     	     
		RequesterMobileNo2	nvarchar(100),	     	     
		RequesterEmailID2	nvarchar(400),	     	     
		Subject				nvarchar(2000),
		Description			nvarchar(max),
		TicketStatusID		bigint,
		Remarks				nvarchar(max),
		Note				nvarchar(max),
		UserResponse		nvarchar(max),
		TicketPriority		bigint,
		AssignedUser		bigint,
		AssignedGroup		bigint,
		AssignedSource		nvarchar(100),
		TicketCategoryId	bigint,
		TicketTypeId		int,
		TicketSourceId		bigint,
		ProductId			bigint,
		IsMerged			bit,
		IsSplitted			bit,
		IsParentTicket		bit,
		IsChildTicket		bit,
		ParentTicketID		bigint,
		LastActionDatetime	datetime,
		AssignedBy			bigint,
		AssignedDateTime	datetime,
		TicketTag			nvarchar(2000),
