    -- Delete existing records that match the criteria
    DELETE FROM tbl_tp_TicketAttachment
    WHERE TicketID = @TicketID
      AND ParentID = @ParentID


    -- Insert new records
    INSERT INTO tbl_tp_TicketAttachment (TicketID, TicketHistoryID, DisplayName, FileUrl, IsActive, CreatedBy, CreatedOn, ParentID)
    SELECT @TicketID, @TicketHistoryId, FileName, FilePath, 1, @TpUserId, GETDATE(), @ParentID
    FROM @jsonTableUpdate;
END;                

	IF @TicketHistoryId > 0
		SELECT 'Ticket Updated Successfully';                                                         
                          
	DECLARE @DynamicRowJsonQuery1 NVARCHAR(MAX);                                    
                                    
	SET @DynamicRowJsonQuery = N'
	SELECT @json_Result = (
	SELECT *
	FROM ' + QUOTENAME(@TicketMasterTable) + '
	WHERE TicketID = @DynamicInsertedId
	FOR JSON AUTO, INCLUDE_NULL_VALUES
	)';

	DECLARE @jsonResult1 NVARCHAR(MAX),@rowcnt int, @i int=1, @FieldName varchar(100), @OldValue nvarchar(max), @NewValue nvarchar(max), @ActivityDatetime datetime=getdate(), @TicketActivityTable NVARCHAR(500)='tbl_tp_TicketActivity_'+cast(@ParentId as nvarchar);
                                  
	EXEC sp_executesql @DynamicRowJsonQuery1, N'@DynamicInsertedId BIGINT, @json_Result NVARCHAR(MAX) OUTPUT', @DynamicInsertedId=@TicketID, @json_Result=@jsonResult1 OUTPUT;                                                        
	SET @rowJson = @jsonResult1;   
	
  	SELECT @DynamicUpdateQuery = concat(N'insert into #tblTicketAfterEdit(TicketID, tpUser_Id, ParentID, TicketNo, RequesterMobileNo, RequesterEmailID, RequesterMobileNo1, RequesterEmailID1, RequesterMobileNo2, RequesterEmailID2, Subject, Description, TicketStatusID, Remarks, Note, UserResponse, TicketPriority, AssignedUser, AssignedGroup, AssignedSource, TicketCategoryId, TicketTypeId, TicketSourceId, ProductId, IsMerged, IsSplitted, IsParentTicket, IsChildTicket, ParentTicketID, LastActionDatetime, AssignedBy, AssignedDateTime, TicketTag, EntityID, EntityName, Company, CreatedBy, CreatedOn)
	Select	TicketID, tpUser_Id, ParentID, TicketNo, RequesterMobileNo, RequesterEmailID, RequesterMobileNo1, RequesterEmailID1, RequesterMobileNo2, RequesterEmailID2, Subject, Description, TicketStatusID, Remarks, Note, UserResponse, TicketPriority, AssignedUser, AssignedGroup, AssignedSource, TicketCategoryId, TicketTypeId, TicketSourceId, ProductId, IsMerged, IsSplitted, IsParentTicket, IsChildTicket, ParentTicketID, LastActionDatetime, AssignedBy, AssignedDateTime, TicketTag, EntityID, EntityName, Company, CreatedBy, CreatedOn
		From ',@TicketMasterTable, N'
		Where TicketID = ', @TicketID)

	EXEC sp_executesql @DynamicUpdateQuery;

	IF @rowJson IS NOT NULL
	BEGIN
		EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData
		@User_id = @ParentID, -- @UserId, -- External User
		@Activity_type = 'Updt_agentraiseticketmaster',
		@ActionType = 'U',
		@RowJson = @rowJson,
		@Table_name = @TicketMasterTable,
		@ip_adress = @IPAdress,
		@device_id = @DeviceId,
		@IsImpersonation = @IsImpersonation,
		@ImpersonatorId = @ImpersonatorId;
	END

	select * 
	into #tblFields
	from dbo.fn_split('TicketNo,RequesterMobileNo,RequesterEmailID,RequesterMobileNo1,RequesterEmailID1,RequesterMobileNo2,RequesterEmailID2,Subject,Description,TicketStatusID,Remarks,Note,UserResponse,TicketPriority,AssignedUser,AssignedGroup,TicketCategoryId,TicketTypeId,TicketSourceId,TicketTag,EntityID,EntityName,Company',',')

	Select @rowcnt=count(*) From #tblFields

	While(@i <= @rowcnt)
	Begin
		Select @FieldName=value From #tblFields Where position=@i

		set @DynamicSQL=concat(N'select @OldValue1=isnull(A.',@FieldName,N',''0''),@NewValue1=isnull(B.',@FieldName,N',''0'')
		From #tblTicketBeforeEdit A inner join #tblTicketAfterEdit B
		On	A.TicketID=B.TicketID')

		EXEC sp_executesql @DynamicSQL,N'@OldValue1 nvarchar(max) output,@NewValue1 nvarchar(max) output',@OldValue1=@OldValue output,@NewValue1=@NewValue output
		
		print concat('@OldValue: ',@OldValue)
		print concat('@NewValue: ',@NewValue)

		If(@OldValue != @NewValue)
		Begin
			print concat('diff @FieldName: ',@FieldName)
			print concat('diff @UserCreated: ',@UserCreated)
			print concat('diff @TicketNo: ',@TicketNo)

			SELECT @EventDesc = @UserCreated + ' updated ticket ' + @TicketNo + ' for field ' + @FieldName + ' From ' + @OldValue + ' to ' + @NewValue

			print concat('@EventDesc: ',@EventDesc)
			print concat('@EntityName: ',@EntityName)
			print concat('@EntitytID: ',@EntitytID)
			print concat('@UserId: ',@UserId)
			print concat('@refid: ',@TicketHistoryId)

			Exec usp_tp_AddActivity  @TicketId=@TicketID, @ParentId=@ParentId, @FieldName=@FieldName, @OldValue=@OldValue, @NewValue=@NewValue, @ActivityDescription='Raised Ticket Edited', @ActivityBy=@TpUserId, @ActivityDatetime=@ActivityDatetime, @ActivityId=@ActivityId out, @EventId=null, @EventName='Leads ticket updated'

			exec UspSaveEntityActivity_withid @entityname = @EntityName, @EntityID = @EntitytID, @UserID= @ParentId, @ParentID = @ParentId, @EventDescription = @EventDesc, @EventName = 'Leads ticket updated', @reftables = @TicketActivityTable, @refid= @ActivityId

			--exec UspSaveEntityActivity_withid @entityname = @EntityName, @EntityID = @EntitytID, @UserID= @ParentId, @ParentID = @ParentId, @EventDescription = @EventDesc, @EventName = 'Leads ticket updated', @reftables = 'tbl_tp_ticketHistory', @refid= @TicketHistoryId
			
