/* ============================================================
   Procedure: [dbo].[usp_Tp_AI_SaveChatHistory]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_Tp_AI_SaveChatHistory]
(
	@P_RefId bigint,
	@P_reftable_name varchar(200),
	@P_entityName varchar(200),
	@P_prompt_text nvarchar(max),
	@P_Response_text nvarchar(max),
	@P_userId bigint
)
as
Begin
	
	Declare @ParentId bigint = (select ParentId from tbl_tp_UserLogin(nolock) where TpUser_Id = @P_userId) ;
	Declare @row_id bigint , @metadata varchar(max), @ActivityType varchar(10)= '' , @ActType VARCHAR(1) = '' ; 

	BEGIN TRY
	
		IF NOT EXISTS(SELECT 1 FROM  tbl_Tp_AI_GPTChatActivityHistory(nolock)  WHERE   REFID = @P_RefId  AND PARENTID = @PARENTID)  
		BEGIN  
			SET @ActivityType = 'Insert'; set @ActType ='I';

			INSERT INTO tbl_Tp_AI_GPTChatActivityHistory( prompt_text	,response_text,	RefId	,ReftableName	,EntityName,	Parentid	,CreatedBy,	CreatedDate )
			VALUES (@P_prompt_text, @P_Response_text , @P_RefId ,  @P_reftable_name ,@P_entityName, @ParentId , @P_userId , GETDATE() )

			SELECT  @row_id = SCOPE_IDENTITY() ;

		END
		ELSE BEGIN

			SET @ActivityType = 'Update'; set @ActType ='U';
			update tbl_Tp_AI_GPTChatActivityHistory set response_text= coalesce( @P_Response_text,'') + char(13)+ coalesce( response_text,''), ModifiedBy =@P_USERID , ModifiedDate = GETDATE()  
			where RefId = @P_RefId  and Parentid = @ParentId;  	
			
			select @row_id = History_id from tbl_Tp_AI_GPTChatActivityHistory(nolock)  WHERE   REFID = @P_RefId  AND PARENTID = @PARENTID

		END


	END TRY
	BEGIN CATCH
		PRINT CONCAT('Error occurred: ', ERROR_MESSAGE(), ' | Error Number: ', ERROR_NUMBER(), ' | Line: ', ERROR_LINE());
		
	END CATCH


	 SET @metadata = (  SELECT *  FROM tbl_Tp_AI_GPTChatActivityHistory(nolock)  WHERE history_id = @row_id  FOR JSON AUTO );

	 print @metadata;

		EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @P_userId  
		,@Activity_type = @ActivityType
		,@ActionType = @ActType
		,@RowJson =''
		,@Table_name = 'tbl_Tp_AI_GPTChatActivityHistory'  ;


end




