/* ============================================================
   Procedure: [dbo].[usp_tp_ApplyDispatcherRule]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec usp_tp_ApplyDispatcherRule @TicketId=10215,@ParentId=32222
CREATE   PROC usp_tp_ApplyDispatcherRule
(
	@TicketId	BIGINT,
	@ParentId	BIGINT
)
AS     
BEGIN    
  print '----------------------usp_tp_ApplyDispatcherRule-------------------------'
  print '@TicketId: ' + cast(@TicketId as varchar)
  print '@ParentId: ' + cast(@ParentId as varchar)

DECLARE @LoopCounter INT , @MaxId INT, @sqlstr as nvarchar(max), @DispatcherID bigint
  
create table #Rulesbyorder(id int identity(1,1),DispatcherRuleId bigint)  
  
insert into #Rulesbyorder(DispatcherRuleId)  
select Disptchr_Id 
FROM tbl_tp_DispatcherMaster(NOLOCK) --Serv_Ticket_Dispatch  (nolock)    
where ParentID = @ParentId and Active=1 and IsEnabled=1
order by SequenceNo --ord_no  
  
declare @min int,@max int  
select @min=min(id),@max=max(id) from #Rulesbyorder  
        
SELECT @LoopCounter =DispatcherRuleId FROM #Rulesbyorder    where id=@min  
--select @MaxId = DispatcherRuleId FROM #Rulesbyorder where id=@max                    
                    
WHILE(@LoopCounter IS NOT NULL AND @min <= @Max)                    
BEGIN
 SELECT @LoopCounter =DispatcherRuleId FROM #Rulesbyorder  where id=@min  
 
 print '@min: ' + cast(@min as varchar)
 print '@LoopCounter(DispatcherRuleId): ' + cast(@LoopCounter as varchar)
 
 declare @Ruleid bigint                    
 --declare @Rule_Match_type int                    
                     
 SELECT @Ruleid = Disptchr_Id--,  @Rule_Match_type =  Rule_Match_type                     
 FROM tbl_tp_DispatcherMaster(nolock) --Serv_Ticket_Dispatch   (nolock)                  
 where ParentID = @ParentId and Disptchr_Id = @LoopCounter

 print '@Ruleid: ' + cast(@Ruleid as varchar)
                     
 declare @rsult int =0                    
 if exists(select 1 from tbl_tp_DispatcherCondition(nolock) --Serv_Ticket_Dispatch_Filter 
 where Disptchr_Id = @Ruleid and Active=1)
  begin             
  print 'calling usp_tp_ApplyDispatcherRuleCondition:- '
    --select @Ruleid , @Rule_Match_type, @ticketid               
   --exec Serv_Aoto_Dispatcher_Support @Ruleid , @Rule_Match_type, @ticketid,@rsult output             
   exec usp_tp_ApplyDispatcherRuleCondition @Ruleid , @ParentId, @ticketid,@rsult output
                  
   if @rsult = 1
   begin
		If exists(Select * From tbl_tp_DispatcherApplyHistory(nolock) Where TicketId=@ticketid and ParentID=@ParentId and IsActive=1)
		Begin
			Select @DispatcherID=DispatcherID From tbl_tp_DispatcherApplyHistory(nolock) Where TicketId=@ticketid and ParentID=@ParentId and IsActive=1

			If(@DispatcherID > 0)
			Begin
				Update tbl_tp_DispatcherApplyHistory Set IsActive=0 Where TicketId=@ticketid and ParentID=@ParentId and IsActive=1

				insert into tbl_tp_DispatcherApplyHistory(TicketId,ParentID,DispatcherID,Mode,IsApplied,ApplyDate,IsActive,CreatedBy,CreatedDate)
				values(@ticketid,@ParentId,@Ruleid,'Auto',1,GETDATE(),1,-1,GETDATE())
			End
			Else
			Begin
				Update tbl_tp_DispatcherApplyHistory Set DispatcherID=@Ruleid, IsApplied=1,ApplyDate=GETDATE()
				Where TicketId=@ticketid and ParentID=@ParentId and IsActive=1
			End
		End
		Else
		Begin
			insert into tbl_tp_DispatcherApplyHistory(TicketId,ParentID,DispatcherID,Mode,IsApplied,ApplyDate,IsActive,CreatedBy,CreatedDate)
			values(@ticketid,@ParentId,@Ruleid,'Auto',1,GETDATE(),1,-1,GETDATE())
		End

		print 'break;'
		break;
   end
  end                    
           
 set @min=@min+1             
  -- SET @LoopCounter  = @LoopCounter  + 1                            
END               

   If(@rsult=0)
   Begin
   		If exists(Select * From tbl_tp_DispatcherApplyHistory(nolock) Where TicketId=@ticketid and ParentID=@ParentId and IsActive=1)
		Begin
			Update tbl_tp_DispatcherApplyHistory Set IsApplied=1,ApplyDate=GETDATE(),Remarks='No Matching Dispatcher Rule Found'
			Where TicketId=@ticketid and ParentID=@ParentId and IsActive=1

		End
		Else
		Begin
			insert into tbl_tp_DispatcherApplyHistory(TicketId,ParentID,DispatcherID,Mode,IsApplied,ApplyDate,IsActive,CreatedBy,CreatedDate,Remarks)
			values(@ticketid,@ParentId,@Ruleid,'Auto',1,GETDATE(),1,-1,GETDATE(),'No Matching Dispatcher Rule Found')
		End
   End


END 



GO

/* ============================================================
   Procedure: [dbo].[usp_tp_ApplyDispatcherRuleCondition]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_tp_ApplyDispatcherRuleCondition]
(                        
@DispatcherRuleId bigint,
@ParentId bigint,
@ticketid bigint ,
@result int output
)                        
AS                        
BEGIN                        
print '--------------------------usp_tp_ApplyDispatcherRuleCondition------------------------------'
DECLARE @LoopCounter INT , @MaxId INT, @fld_Name NVARCHAR(200), @FieldName nvarchar(100)='', 
		@Filter_Value NVARCHAR(100),  @Filter_Cond NVARCHAR(100)='', @Conjunction varchar(10), 
		@sqlstr as nvarchar(max)='' --, @result as int

print '@DispatcherRuleId: ' + cast(@DispatcherRuleId as varchar)
print '@ParentId: ' + cast(@ParentId as varchar)
print '@ticketid: ' + cast(@ticketid as varchar)

cReate table #tmp (rno int,ticketid bigint)                        
declare @rcno as int

-- select * FROM Serv_Ticket_Dispatch_Filter where ParentID = 37540    
if exists(select 1 FROM tbl_tp_DispatcherCondition(nolock) --Serv_Ticket_Dispatch_Filter 
where Disptchr_Id = @DispatcherRuleId and Active=1 )    
 begin                    
  SELECT @LoopCounter = min(Condtion_Id) , @MaxId = max(Condtion_Id)
  --SELECT @LoopCounter = min(tkt_filter_ID) , @MaxId = max(tkt_filter_ID)                         
  FROM tbl_tp_DispatcherCondition(nolock) --Serv_Ticket_Dispatch_Filter
  where Disptchr_Id = @DispatcherRuleId and Active=1
	print '@LoopCounter(Condtion_Id): ' + cast(@LoopCounter as varchar)
  declare @cond varchar(max)=''                        
                          
  WHILE(@LoopCounter IS NOT NULL AND @LoopCounter <= @MaxId)                        
  BEGIN                        
 SELECT @FieldName = td.FieldName,@Filter_Cond = ct.ConditionalOperator, @Filter_Value = ltrim(rtrim(td.Value)), @Conjunction=td.Conjunction  
 --SELECT @fld_Name = ct.fldnm,@Filter_Cond = Filter_Cond, @Filter_Value = ltrim(rtrim(Filter_Value))  
 FROM tbl_tp_DispatcherCondition(nolock) td inner join tbl_tp_ConditionalOperator(nolock) ct
 --FROM Serv_Ticket_Dispatch_Filter td inner join Serv_Cond_TypeMaster ct  
 --on ct.Description = td.Filter_Field and td.Filter_FldType = ct.opt  
 on td.Operator = ct.ConditionId
 --WHERE tkt_filter_ID = @LoopCounter and DispatcherRuleId = @DispatcherRuleId  
 WHERE td.Condtion_Id = @LoopCounter and td.Disptchr_Id = @DispatcherRuleId and td.Active=1 and ct.IsActive=1

	print '@FieldName: ' + @FieldName
	print '@Filter_Cond: ' + @Filter_Cond
	print '@Filter_Value: ' + @Filter_Value
	print '@Conjunction: ' + @Conjunction

   set @cond = ''+@Filter_Cond +'''' +@Filter_Value+''''                        
	
	if @Filter_Cond = 'like'
	set @cond = ' like '''+'%' +@Filter_Value+'%'''

	if @Filter_Cond = 'not like'
	set @cond = ' not like '''+'%' +@Filter_Value+'%'''

	if @Filter_Cond = 'End with'
	set @cond = ' like '''+'%' +@Filter_Value+''''

	if @Filter_Cond = 'Not End with'
	set @cond = ' not like '''+'%' +@Filter_Value+''''

	if @Filter_Cond = 'Start with'
	set @cond = ' like ''' +@Filter_Value+'%'''

	if @Filter_Cond = 'Not Start with'
	set @cond = ' not like ''' +@Filter_Value+'%'''

	print '@cond: ' + @cond
                          
   declare @orcnd as varchar(Max) = ''
   select @fld_Name=[text] from openjson(@FieldName) with ( [text] nvarchar(100))
   set @orcnd = @fld_Name +@cond                        

   if @fld_Name = 'Company'                        
   begin                        
		set @orcnd = ' tm.'+@fld_Name +@cond                        
   end                        
                          
   if @fld_Name = 'Subject'
   begin                        
		set @orcnd = ' ( Subject ' +@cond  +' )'                        
   end                        
 
	if @fld_Name = 'Description'
	begin                        
		set @orcnd = ' ( Description ' +@cond  +' )'                        
	end                        
                           
	if @fld_Name = 'TicketPriority'
	begin
		set @orcnd = ' ( TicketPriority ' +@cond +' )'
	end

	print '@fld_Name: ' + @fld_Name
	print '@orcnd: ' + @orcnd
      
  --if (@Rule_Match_type = 2)                        
  if (@Conjunction = 'AND')                        
  begin                        
  if (@sqlstr ='')                        
    set @sqlstr = ' and ('+ @orcnd                        
   else                        
    set @sqlstr = @sqlstr+' and '+ @orcnd                         
  end                        
  else -- OR
  begin                        
  if (@sqlstr ='')                        
   set @sqlstr =  ' and ('+ @orcnd                        
  else                        
    set @sqlstr = @sqlstr+' or '+ @orcnd                        
  end                        
                          
    SET @LoopCounter  = @LoopCounter  + 1                                
 END -- end while                       
                         
 --if (@Rule_Match_type = 1)                        
  set @sqlstr = @sqlstr +')'
                          
-- set @sqlstr = 'Select top 1 ROW_NUMBER() OVER(ORDER BY ticketid ASC) rno, tm.ticketid  from '                          +'Serv_TicketMaster tm inner join Serv_User_Detail ud '+    
		--' on ud.ser_user_id = tm.User_id '+
		--' where tm.ticketid = '+ cast(@ticketid as varchar(20)) + @sqlstr                        

 set @sqlstr = 'Select top 1 ROW_NUMBER() OVER(ORDER BY ticketid ASC) rno, tm.ticketid  from '+
	'tbl_tp_TicketMaster_'+Cast(@ParentId as varchar)+' tm '+                        
    ' where tm.ticketid = '+ cast(@ticketid as varchar(20)) + @sqlstr                        
        
 print '@sqlstr: ' + @sqlstr        
  --set @sqlstr = 'Select ROW_NUMBER() OVER(ORDER BY ticketid ASC) rno, tm.ticketid  from '                        
  --+'Serv_TicketMaster tm '+                        
  --  ' where tm.ticketid = '+ cast(@ticketid as varchar(20)) + @sqlstr                        
        
                         
 insert into #tmp EXECUTE (@sqlstr)                        
                     
end                    
else                    
begin                    
	--insert into #tmp (rno ,ticketid )                    
	--Select ROW_NUMBER() OVER(ORDER BY ticketid ASC) rno, tm.ticketid  
	--from	Serv_TicketMaster tm inner join Serv_User_Detail ud                     
	--on ud.ser_user_id = tm.User_id where ticketid = @ticketid                    

	set @sqlstr = 'Select top 1 ROW_NUMBER() OVER(ORDER BY ticketid ASC) rno, tm.ticketid  from '+
	'tbl_tp_TicketMaster_'+Cast(@ParentId as varchar)+' tm '+
    ' where tm.ticketid = '+ cast(@ticketid as varchar(20)) 
        
	print '@sqlstr: ' + @sqlstr        
    insert into #tmp EXECUTE (@sqlstr)
                    
end                    
    
select @rcno= COUNT(*) from #tmp                        
 set @result = 0

 print '@rcno: ' + cast(@rcno as varchar)

if @rcno > 0                        
Begin                        
	set @result = 1
	DECLARE @Maxrow INT = 0 , @EmployeeName NVARCHAR(100);
                                 
                        
 --select *, ROW_NUMBER() OVER(ORDER BY ord_no ASC) rno 
 --into #tmpaction                         
 --from Serv_Ticket_Dispatch_Action    
 --where DispatcherRuleId = @DispatcherRuleId                        

	select *, ROW_NUMBER() OVER(ORDER BY SequenceNo ASC) rno
	into #tmpaction
	from tbl_tp_DispatcherAction(nolock) DA inner join tbl_tp_ActionTypeMaster(nolock) AM
	on	 DA.Action_Id=AM.ActionType_Id AND am.Mode='Dispatchr'
	where DA.Disptchr_Id = @DispatcherRuleId
    
-- select * from Serv_Ticket_Dispatch_Action where parentid=37540    
	select  @LoopCounter = MIN(rno), @Maxrow= max(rno) from #tmpaction

	print '@LoopCounter: ' + cast(@LoopCounter as varchar)
	print '@Maxrow: ' + cast(@Maxrow as varchar)
                          
  WHILE(@LoopCounter <= @Maxrow)                        
  BEGIN                       
   declare @actn as varchar(20), @act_val as varchar(20)

   select @actn = Description,@act_val = Action_Value 
   from #tmpaction
   where rno = @LoopCounter

	print '@LoopCounter: ' + cast(@LoopCounter as varchar)
	print '@actn: ' + isnull(@actn,'')
	print '@act_val: ' + isnull(@act_val,'')

   declare	@Agent_id as bigint =0, @AssignTo bigint=0, @AssignGroup bigint=0, @MaxSno int, 
			@RowLastAssigned int, @ActivityDatetime datetime=getdate(), @ActivityId bigint=0
   declare	@grpid as bigint =0, @user_id as bigint, @ParentStatusId bigint, @AssignmentMode nvarchar(100),
			@AgentGroupMap_Id bigint, @TicketStatusId bigint=0
  
   --select @user_id = user_id, @AssignTo=isnull(AssignTo,0), @AssignGroup=isnull(Assign_Group,0)  
   --from Serv_TicketMaster with(nolock)   
   --where TicketID = @ticketid  

   	set @sqlstr = 'Select @tpUserid=tm.tpUser_Id, @AsgUserId=isnull(tm.AssignedUser,0), @AsgGrpId=isnull(tm.AssignedGroup,0), @TicketStatusId1=isnull(tm.TicketStatusId,0)  from '+
	'tbl_tp_TicketMaster_'+Cast(@ParentId as varchar)+' tm '+
    ' where tm.ticketid = '+ cast(@ticketid as varchar(20)) 

	print '@sqlstr: ' + @sqlstr

	EXECUTE sp_executesql @sqlstr, N'@tpUserid bigint output, @AsgUserId bigint output, @AsgGrpId bigint output, @TicketStatusId1 bigint output', @tpUserid = @user_id output, @AsgUserId = @AssignTo output, @AsgGrpId = @AssignGroup output, @TicketStatusId1 = @TicketStatusId output


   --select @user_id = user_id, @AssignTo=isnull(AssignTo,0), @AssignGroup=isnull(Assign_Group,0)  
   --from Serv_TicketMaster with(nolock)   
   --where TicketID = @ticketid  
   --------------------------------------------------------------------------------------  
   --if @actn= 'Add Tag'
   --begin                        
   -- update dbo.Serv_TicketMaster set Status=1, tkt_tag = @act_val                        
   -- where TicketID = @ticketid                        
   --end
   --if @actn= 'Set Type as'
   --begin                        
   -- update dbo.Serv_TicketMaster set Status=1, Ticket_type =                         
   -- (select Type_ID  FROM Serv_TicketType_Mast where Type_Desc = @act_val)                        
   -- where TicketID = @ticketid                        
   --end
  
	print '@AssignTo: ' + cast(@AssignTo as varchar)
	print '@AssignGroup: ' + cast(@AssignGroup as varchar)

   If(@AssignTo=0 and @AssignGroup=0)  
   Begin

    if @actn= 'Assign to Agent'
    begin
		--select @Agent_id=ser_user_id, @ParentID= ParentID FROM Serv_User_Detail where Login_id = @act_val  
  
		--update Serv_TicketHistory set TransferredTo = @Agent_id  
	 -- --(select ser_user_id FROM Serv_User_Detail where Login_id = @act_val)  
	 -- where TicketID = @ticketid  
  
	 -- update dbo.Serv_TicketMaster set Status=1, AssignTo = @Agent_id  
	 -- --(select ser_user_id FROM Serv_User_Detail where Login_id = @act_val)  
	 -- where TicketID = @ticketid  

	  set @sqlstr = 'update tm set tm.AssignedUser=@AsgUserId  from '+
	'tbl_tp_TicketMaster_'+Cast(@ParentId as varchar)+' tm '+
    ' where tm.ticketid = '+ cast(@ticketid as varchar(20)) 
	print '@sqlstr: ' + @sqlstr

	EXECUTE sp_executesql @sqlstr, N'@AsgUserId bigint', @AsgUserId = @act_val

	  set @sqlstr = 'update tm set tm.AssignedUser=@AsgUserId  from '+
	'tbl_tp_TicketHistory tm '+
    ' where tm.ticketid = '+ cast(@ticketid as varchar(20)) 
	print '@sqlstr: ' + @sqlstr

	EXECUTE sp_executesql @sqlstr, N'@AsgUserId bigint', @AsgUserId = @act_val

	Exec usp_tp_AddActivity @TicketId=@ticketid, @ParentId=@ParentId, @FieldName='AssignedUser', @OldValue='0', @NewValue=@act_val, @ActivityDescription='Assigned User By Dispatcher Rule', @ActivityBy=@user_id, @ActivityDatetime=@ActivityDatetime, @ActivityId=@ActivityId out, @EventId=null, @EventName=null
  
	  --exec serv_Raise_emailNotification_support1 @ticketid,@ParentID,0 , @user_id,@Agent_id,'Ticket Assigned to Agent','Agent'  
	  ----exec serv_Raise_emailNotification @ticketid,@ParentID,@grpid , @user_id,@user_id,'Ticket Assigned to Group','Requester'  
	  ----exec serv_Raise_emailNotification_support1 @ticketid,@ParentID,0 , @user_id,@Agent_id,'New Ticket Created','Requester'  
    end                        
      
    if @actn= 'Assign to Group'
    begin
   --select @grpid =Groupid FROM Serv_Group_Mast with(nolock) where Group_Name = @act_val and Parentid=@ParentID  
                          
   --update Serv_TicketHistory set Assign_Group = @grpid where TicketID = @ticketid                        
                     
   --update dbo.Serv_TicketMaster set Status=1, Assign_Group = @grpid    
   ----(select Groupid FROM dbo.Serv_Group_Mast where Group_Name = @act_val)                        
   --where TicketID = @ticketid                       

   --select top 1 @Agent_id=UserId from Serv_Agent_Mast where parentid=@ParentID and Group_id=@grpid and Access_Level='All Group'    

    drop table if exists #tmpRRAssigment

	select @AssignmentMode=Assigned from tbl_tp_GroupMaster(nolock) Where GroupId=@act_val
	print '@AssignmentMode: '+ isnull(@AssignmentMode,'')

	If(@AssignmentMode='roundrobin')
	Begin
	
		select ROW_NUMBER()over(order by AgentGroupMap_Id) Sno,* 
		into #tmpRRAssigment
		from tbl_tp_AgentGroupMapping(nolock) 
		Where IsActive=1 and GroupId=@act_val

		Select @MaxSno=max(Sno) from #tmpRRAssigment

		select @RowLastAssigned=Sno+1 from #tmpRRAssigment(nolock) Where IsEdit=1

		If(@RowLastAssigned > @MaxSno)
		Begin
			Set @RowLastAssigned=1
		End

		Select @RowLastAssigned=isnull(@RowLastAssigned,1)

		print '@MaxSno: ' + cast(@MaxSno as varchar)
		print '@RowLastAssigned: ' + cast(@RowLastAssigned as varchar)

		select @AgentGroupMap_Id=AgentGroupMap_Id from #tmpRRAssigment(nolock) Where Sno=@RowLastAssigned

		Update tbl_tp_AgentGroupMapping 
		Set IsEdit=IIF(@AgentGroupMap_Id=AgentGroupMap_Id,1,0),@Agent_id=IIF(@AgentGroupMap_Id=AgentGroupMap_Id,TpUserId,@Agent_id) 
		Where IsActive=1 and GroupId=@act_val

		set @sqlstr = 'update tm set tm.AssignedGroup=@AsgGroupId,tm.AssignedUser=@AsgUserId from '+
		'tbl_tp_TicketMaster_'+Cast(@ParentId as varchar)+' tm '+
		' where tm.ticketid = '+ cast(@ticketid as varchar(20)) 
		print '@sqlstr: ' + @sqlstr

		EXECUTE sp_executesql @sqlstr, N'@AsgGroupId bigint, @AsgUserId bigint', @AsgGroupId = @act_val, @AsgUserId = @Agent_id

		set @sqlstr = 'update tm set tm.AssignedGroup=@AsgGroupId,tm.AssignedUser=@AsgUserId from '+
		'tbl_tp_TicketHistory tm '+
		' where tm.ticketid = '+ cast(@ticketid as varchar(20)) 
		print '@sqlstr: ' + @sqlstr

		EXECUTE sp_executesql @sqlstr, N'@AsgGroupId bigint, @AsgUserId bigint', @AsgGroupId = @act_val, @AsgUserId = @Agent_id
	End
	--If(@AssignmentMode='skillbased')
	--Begin
	
		--select top 100 * from tbl_tp_AgentSkillMapping
		--select top 100 * from tbl_tp_SkillMaster

		/* To done after correction in skill agent maping */
	--End
	Else
	Begin

	  set @sqlstr = 'update tm set tm.AssignedGroup=@AsgGroupId  from '+
	'tbl_tp_TicketMaster_'+Cast(@ParentId as varchar)+' tm '+
    ' where tm.ticketid = '+ cast(@ticketid as varchar(20)) 
	print '@sqlstr: ' + @sqlstr

	EXECUTE sp_executesql @sqlstr, N'@AsgGroupId bigint', @AsgGroupId = @act_val

	  set @sqlstr = 'update tm set tm.AssignedGroup=@AsgGroupId  from '+
	'tbl_tp_TicketHistory tm '+
    ' where tm.ticketid = '+ cast(@ticketid as varchar(20)) 
	print '@sqlstr: ' + @sqlstr

	EXECUTE sp_executesql @sqlstr, N'@AsgGroupId bigint', @AsgGroupId = @act_val
	End

	Exec usp_tp_AddActivity @TicketId=@ticketid, @ParentId=@ParentId, @FieldName='AssignedGroup', @OldValue='0', @NewValue=@act_val, @ActivityDescription='Assigned Group By Dispatcher Rule', @ActivityBy=@user_id, @ActivityDatetime=@ActivityDatetime, @ActivityId=@ActivityId out, @EventId=null, @EventName=null

	--exec serv_Raise_emailNotification_support1 @ticketid,@ParentID,@grpid , @user_id,@Agent_id,'Ticket Assigned to Group','Agent'    
                        
   ----exec serv_Raise_emailNotification_support1 @ticketid,@ParentID,@grpid , @user_id,@Agent_id,'New Ticket Created','Requester'    
    end
  
    --if @actn= 'Assign Product'
   --begin                        
   --  update dbo.Serv_TicketMaster set Status=1, Product = @act_val                        
   --  where TicketID = @ticketid                        
   --end                        
   --if @actn= 'Skip New Ticket email Notification'                        
   --begin                        
   --  update dbo.Serv_TicketMaster set Status=1, skip_nticketmail = 1                        
   --  where TicketID = @ticketid                        
   --end                        
   --if @actn = 'Set Priority As'                        
   --begin                        
   -- update dbo.Serv_TicketMaster set Status=1, Priority =                        
   --  (select Priority_ID FROM Serv_Priority_Mast where Priority_Desc = @act_val)                        
   --  where TicketID = @ticketid                        
                           
   -- update Serv_TicketHistory set Status = 1, Priority =                        
   --  (select Priority_ID FROM Serv_Priority_Mast where Priority_Desc = @act_val)                         
   -- where TicketID = @ticketid                        
   --end                        
    if @actn = 'Delete the Ticket'
    begin
    --update dbo.Serv_TicketMaster set deleted = 1, Remarks = @act_val                        
    --where TicketID = @ticketid                        

	set @sqlstr = 'update tm set tm.IsActive=0,Note=''Deleted via Dispatcher Rule''  from '+
	'tbl_tp_TicketMaster_'+Cast(@ParentId as varchar)+' tm '+
    ' where tm.ticketid = '+ cast(@ticketid as varchar(20)) 
	print '@sqlstr: ' + @sqlstr

	EXEC (@sqlstr)

	Exec usp_tp_AddActivity @TicketId=@ticketid, @ParentId=@ParentId, @FieldName='IsActive', @OldValue='1', @NewValue='0', @ActivityDescription='Deleted By Dispatcher Rule', @ActivityBy=@user_id, @ActivityDatetime=@ActivityDatetime, @ActivityId=@ActivityId out, @EventId=null, @EventName=null

   end

    if @actn = 'Set Ticket Status as'
	begin
	Select @ParentStatusId=ParentStatus_Id  From tbl_tp_TicketStatusMaster(nolock) Where TicketStatus_ID=@act_val
    --update Serv_TicketHistory set Status = (select Stat_ID FROM Serv_Ticket_Stat_Mast where Stat_Desc = @act_val)    
    -- where TicketID in (select TicketID From #tmp)                        
                        
    --update dbo.Serv_TicketMaster set Status =                         
    -- (select Stat_ID FROM Serv_Ticket_Stat_Mast where Stat_Desc = @act_val)                        
    -- where TicketID = @ticketid        
	 
	set @sqlstr = 'update tm set tm.TicketStatusId=@StatusId  from '+
	'tbl_tp_TicketMaster_'+Cast(@ParentId as varchar)+' tm '+
    ' where tm.ticketid = '+ cast(@ticketid as varchar(20)) 
	print '@sqlstr: ' + @sqlstr

	EXECUTE sp_executesql @sqlstr, N'@StatusId bigint', @StatusId = @act_val

	set @sqlstr = 'update tm set tm.TicketStatusId=@StatusId  from '+
	'tbl_tp_TicketHistory tm '+
    ' where tm.ticketid = '+ cast(@ticketid as varchar(20)) 
	print '@sqlstr: ' + @sqlstr

	EXECUTE sp_executesql @sqlstr, N'@StatusId bigint', @StatusId = @act_val

	Exec usp_tp_AddActivity @TicketId=@ticketid, @ParentId=@ParentId, @FieldName='TicketStatusId', @OldValue=@TicketStatusId, @NewValue=@act_val, @ActivityDescription='Ticket Status Set By Dispatcher Rule', @ActivityBy=@user_id, @ActivityDatetime=@ActivityDatetime, @ActivityId=@ActivityId out, @EventId=null, @EventName=null

 --if @act_val=4 or @ParentStatusId = 4
 -- exec serv_Raise_emailNotification_support1 @TicketID,@ParentID,0 , @User_ID,@User_ID,'Agent Solves the Ticket','Requester'                      
                      
 --if @act_val=2 or @ParentStatusId = 2
 -- exec serv_Raise_emailNotification_support1 @TicketID,@ParentID,0 , @User_ID,@User_ID,'Agent Closes the Ticket','Requester'                      
   end

    if @actn = 'Mark as Spam'
    begin
	 Select @ParentStatusId=ParentStatus_Id  From tbl_tp_TicketStatusMaster(nolock) Where TicketStatus_ID=@act_val

    --update dbo.Serv_TicketMaster set spam = 1, Remarks = @act_val                        
    -- where TicketID = @ticketid                        
	If(@act_val=9 or @ParentStatusId=9)
	Begin
		set @sqlstr = 'update tm set tm.TicketStatusId=@StatusId  from '+
		'tbl_tp_TicketMaster_'+Cast(@ParentId as varchar)+' tm '+
		' where tm.ticketid = '+ cast(@ticketid as varchar(20)) 
		print '@sqlstr: ' + @sqlstr

		EXECUTE sp_executesql @sqlstr, N'@StatusId bigint', @StatusId = @act_val

		set @sqlstr = 'update tm set tm.TicketStatusId=@StatusId  from '+
		'tbl_tp_TicketHistory tm '+
		' where tm.ticketid = '+ cast(@ticketid as varchar(20)) 
		print '@sqlstr: ' + @sqlstr

		EXECUTE sp_executesql @sqlstr, N'@StatusId bigint', @StatusId = @act_val
		
		Exec usp_tp_AddActivity @TicketId=@ticketid, @ParentId=@ParentId, @FieldName='TicketStatusId', @OldValue=@TicketStatusId, @NewValue=@act_val, @ActivityDescription='Ticket Marked as Spam by Dispatcher Rule', @ActivityBy=@user_id, @ActivityDatetime=@ActivityDatetime, @ActivityId=@ActivityId out, @EventId=null, @EventName=null
	End
   end

   End
   Else
   Begin
		print 'Dispatcher Rule not Applicable'
   End
   
   set @LoopCounter = @LoopCounter+1                        
                          
  end
                          
  --select * from #tmpaction    
  --drop table #tmpaction                        
if object_id('tempdb..#tmpaction') is not null begin drop table #tmpaction end        
 end                        
                     
--drop table #tmp                        
if object_id('tempdb..#tmp') is not null begin drop table #tmp end        
--select @result as rsult                        
return @result                        
end           



GO

/* ============================================================
   Procedure: [dbo].[usp_tp_ApplyScenarioUpdate]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Exec usp_tp_ApplyScenarioUpdate 154,32222
CREATE   PROC usp_tp_ApplyScenarioUpdate
(
	@TicketID	bigint,
	@ParentId	BIGINT,
	@ActivityId bigint
)
AS
Begin
	-- declare @TicketID bigint=154,@ParentId BIGINT=32222

	drop table if exists #tmp_tbl_tp_ScenarioMaster
	drop table if exists #tmp_tbl_tp_ScenarioCondition
	drop table if exists #tmp_tbl_tp_ScenarioAction
	drop table if exists #tmp_tbl_tp_ScenarioTriggeredField
	drop table if exists #tmp_tbl_ActivityFields

	Declare @TpUserId bigint, @TktCnt int=0, @ActivityDatetime datetime
	Declare @StrQuery nvarchar(max)='', @StrSql nvarchar(max)='', @StrParamDefination nvarchar(max)='' 

	Create table #tmp_tbl_ActivityFields
	(
		RowNo	int identity(1,1),
		FieldName varchar(100)
	)

	Set @StrQuery =Concat(N'Select @ActivityDatetime1=ActivityDatetime From tbl_tp_TicketActivity_',@ParentId,N'(nolock) Where TicketID=',@TicketID,N' and ParentID=',@ParentId)
	Set @StrParamDefination = N'@ActivityDatetime1 datetime output'
	Exec sp_executesql @StrQuery, @StrParamDefination, @ActivityDatetime1=@ActivityDatetime output

	print concat('@ActivityDatetime: ',@ActivityDatetime)

	Set @StrQuery =Concat(N'insert into #tmp_tbl_ActivityFields Select FieldName From tbl_tp_TicketActivity_',@ParentId,N'(nolock) Where TicketID=',@TicketID,N' and ParentID=',@ParentId,N' and ActivityDatetime=@ActivityDatetime')
	Set @StrParamDefination = N'@ActivityDatetime datetime'
	Exec sp_executesql @StrQuery, @StrParamDefination, @ActivityDatetime

	Set @StrQuery=N'Select @TCnt=count(*) from tbl_tp_TicketMaster_' + Cast(@ParentId as nvarchar) + N'(nolock) Where TicketId=@TktId '
	Set @StrParamDefination = N'@TCnt int output, @TktId bigint'

	Create table #tmp_tbl_tp_ScenarioMaster
	(
		RowNo int identity(1,1),
		Scenario_Id bigint,
		Scenario_Name nvarchar(400),
		SequenceNo int
	)

	Create table #tmp_tbl_tp_ScenarioCondition
	(
		RowNo			int identity(1,1),
		Condition_Id	bigint,
		FieldName		nvarchar(200),
		Operator		nvarchar(100),
		OperatorText	nvarchar(100),
		ConditionValue	nvarchar(max),
		Conjunction		nvarchar(20),
		ConditionSequenceNo		int
	)

	Create table #tmp_tbl_tp_ScenarioAction
	(
		RowNo				int identity(1,1),
		ScenarioAction_Id	bigint,
		Action_Id			bigint,
		ActionName			nvarchar(1000),
		ActionValue			nvarchar(max),
		ActionSequenceNo	int
	)

	Create table #tmp_tbl_tp_ScenarioTriggeredField
	(
		RowNo				int identity(1,1),
		ScenarioId			bigint,
		tfield_Id			bigint,
		ParentId			bigint,
		FieldName			varchar(100),
		conjunction			varchar(50)
	)

	insert into #tmp_tbl_tp_ScenarioMaster
	Select Scenario_Id,Scenario_Name,SequenceNo
	From tbl_tp_ScenarioMaster(nolock)
	Where ParentId=@ParentId and Active=1 and IsEnabled=1
	order by SequenceNo

	Declare @iRowno int=1, @iRowCnt int, @jRowno int=1, @jRowCnt int, @kRowno int=1, @kRowCnt int
	Declare @Scenario_Id bigint, @SequenceNo int, @OldVal nvarchar(max), @ScenarioID bigint
	Declare @Condition_Id bigint, @FieldName nvarchar(200), @Operator nvarchar(100), @OperatorText nvarchar(100), @ConditionValue nvarchar(max), @Conjunction nvarchar(20), @ConditionSequenceNo int
	Declare @ScenarioAction_Id bigint, @Action_Id bigint, @ActionName nvarchar(1000), @ActionValue nvarchar(max), @ActionSequenceNo int, @FieldConjunction nvarchar(20), @FieldCnt int=0

	Select @TpUserId=TpUser_Id from tbl_tp_UserLogin(nolock) Where User_Id=@ParentId

	Select @iRowCnt=count(*) From #tmp_tbl_tp_ScenarioMaster

	print concat('@iRowCnt: ',@iRowCnt)

	While(@iRowno <= @iRowCnt)
	Begin
		Set @StrSql = @StrQuery + 'and ('

		Select @SequenceNo=SequenceNo, @Scenario_Id=Scenario_Id
		From	#tmp_tbl_tp_ScenarioMaster
		Where	RowNo=@iRowno

		print '--------------------------------------BEGIN----------------------------------------------'
		print concat('@iRowno: ',@iRowno)
		print concat('@SequenceNo: ',@SequenceNo)
		print concat('@Scenario_Id: ',@Scenario_Id)

		truncate table #tmp_tbl_tp_ScenarioTriggeredField

		insert into #tmp_tbl_tp_ScenarioTriggeredField(ScenarioId,tfield_Id,ParentId,FieldName,conjunction)
		Select	ScenarioId,tfield_Id,ParentId,FieldName,conjunction
		From	tbl_tp_ScenarioTriggeredField(nolock)
		Where	IsActive=1 and Scenarioid=@Scenario_Id

		Select top 1 @FieldConjunction=Conjunction from #tmp_tbl_tp_ScenarioTriggeredField
		Select @FieldCnt=count(*) From #tmp_tbl_tp_ScenarioTriggeredField

		print concat(char(13),'@FieldConjunction: ',@FieldConjunction)
		print concat('@FieldCnt: ',@FieldCnt)

		If(@FieldConjunction='AND')
		Begin
			If(@FieldCnt != (Select Count(*)
			From #tmp_tbl_tp_ScenarioTriggeredField A inner join #tmp_tbl_ActivityFields B
			On A.FieldName=B.FieldName))
			Begin
				print 'Activity Fields do not match with Scenario Trigger Fields;continue'
				Set @iRowno=@iRowno+1
				continue;
			End
		End
		Else--OR
		Begin
			If((Select Count(*)
			From #tmp_tbl_tp_ScenarioTriggeredField A inner join #tmp_tbl_ActivityFields B
			On A.FieldName=B.FieldName)=0)
			Begin
				print 'Activity Fields do not match with Scenario Trigger Fields;continue'
				Set @iRowno=@iRowno+1
				continue;
			End
		End

		truncate table #tmp_tbl_tp_ScenarioCondition

		insert into #tmp_tbl_tp_ScenarioCondition
		(Condition_Id, FieldName, Operator, OperatorText, ConditionValue, Conjunction, ConditionSequenceNo)
		Select  SC.Condtion_Id, SC.FieldName, SC.Operator, CO.OperatorText, SC.Value, SC.Conjunction, SC.SequenceNo
		From	tbl_tp_ScenarioCondition(nolock) SC inner join tbl_tp_ConditionalOperator(nolock) CO
		On		SC.Operator=CO.ConditionId
		Where	Active=1 and Scenario_Id=@Scenario_Id
		Order by	SC.SequenceNo

		Select @jRowno=1, @jRowCnt=0

		Select @jRowCnt=count(*) from #tmp_tbl_tp_ScenarioCondition
		print concat('@jRowCnt: ',@jRowCnt)

		While(@jRowno<=@jRowCnt)
		Begin
			Select @Condition_Id=Condition_Id, @FieldName=FieldName, @Operator=Operator, @OperatorText=OperatorText, @ConditionValue=ConditionValue, @Conjunction=Conjunction, @ConditionSequenceNo=ConditionSequenceNo
			From	#tmp_tbl_tp_ScenarioCondition
			Where	RowNo=@jRowno

			If(@jRowno>1)
			Begin
				Set @StrSql += ' ' + @Conjunction 
			End

			Set @StrSql += concat(' (',@FieldName,' ',iif(@Operator<7,replace(@OperatorText,'[A]',@ConditionValue),@OperatorText),' ',iif(@Operator>6,''''+@ConditionValue+'''',' '),') ')

			print concat('@jRowno: ',@jRowno)
			print concat('@Condition_Id: ',@Condition_Id)
			print concat('@FieldName: ',@FieldName)
			print concat('@Operator: ',@Operator)
			print concat('@OperatorText: ',@OperatorText)
			print concat('@ConditionValue: ',@ConditionValue)
			print concat('@Conjunction: ',@Conjunction)
			print concat('@ConditionSequenceNo: ',@ConditionSequenceNo)
			print concat('@StrSql',@jRowno,' : ',@StrSql)
			print ''

			Set @jRowno=@jRowno+1
		End
			print concat('@StrSql(A): ',@StrSql)

		If(@jRowno=@jRowCnt+1)
		Begin
			Set @StrSql += ') '
			print '@StrSql(Final): ' + cast(@StrSql as varchar(max))
			Exec sp_executesql @StrSql, @StrParamDefination, @TCnt=@TktCnt output, @TktId=@TicketID

			print concat('@TktCnt: ',@TktCnt)

			If(@TktCnt > 0)
			Begin
				If exists(Select * From tbl_tp_ScenarioApplyHistory(nolock) Where TicketId=@TicketID and ParentID=@ParentId and IsActive=1)
				Begin
					Select @ScenarioID=ScenarioID From tbl_tp_ScenarioApplyHistory(nolock) Where TicketId=@TicketID and ParentID=@ParentId and IsActive=1

					If(@ScenarioID > 0)
					Begin
						Update tbl_tp_ScenarioApplyHistory Set IsActive=0 Where TicketId=@TicketID and ParentID=@ParentId and IsActive=1

						insert into tbl_tp_ScenarioApplyHistory(TicketId,ParentID,ActivityID,ScenarioID,Mode,IsApplied,ApplyDate,IsActive,CreatedBy,CreatedDate)
						values(@TicketID,@ParentId,@ActivityId,@Scenario_Id,'Auto',1,GETDATE(),1,-1,GETDATE())
					End
					Else
					Begin
						Update tbl_tp_ScenarioApplyHistory Set ScenarioID=@Scenario_Id, IsApplied=1,ApplyDate=GETDATE()
						Where TicketId=@TicketID and ParentID=@ParentId and IsActive=1
					End
				End
				Else
				Begin
					insert into tbl_tp_ScenarioApplyHistory(TicketId,ParentID,ScenarioID,Mode,IsApplied,ApplyDate,IsActive,CreatedBy,CreatedDate)
					values(@TicketID,@ParentId,@Scenario_Id,'Auto',1,GETDATE(),1,-1,GETDATE())
				End

				insert into #tmp_tbl_tp_ScenarioAction(ScenarioAction_Id, Action_Id, ActionValue, ActionSequenceNo, ActionName)
				select	SA.ScenarioAction_Id, AM.ActionType_Id, SA.Action_Value, SA.SequenceNo, AM.Description
				from	tbl_tp_ScenarioAction(nolock) SA inner join tbl_tp_ActionTypeMaster(nolock) AM
				On		SA.Action_Id=AM.ActionType_Id and AM.Mode='Scenario'
				Where	SA.Scenario_Id=@Scenario_Id and SA.Active=1
				order by SA.SequenceNo

				Select @kRowCnt=0, @kRowno=1

				Select @kRowCnt=count(*) From #tmp_tbl_tp_ScenarioAction
				
				print concat('@kRowCnt: ',@kRowCnt)

				While(@kRowno <= @kRowCnt)
				Begin
					Select  @ScenarioAction_Id=ScenarioAction_Id, @Action_Id=Action_Id, @ActionValue=ActionValue, @ActionSequenceNo=ActionSequenceNo, @ActionName=ActionName
					From	#tmp_tbl_tp_ScenarioAction
					Where	RowNo=@kRowno

					print concat('@kRowno: ',@kRowno)
					print concat('@ScenarioAction_Id: ',@ScenarioAction_Id)
					print concat('@Action_Id: ',@Action_Id)
					print concat('@ActionValue: ',@ActionValue)
					print concat('@ActionSequenceNo: ',@ActionSequenceNo)
					print concat('@ActionName: ',@ActionName)

					Set @ActivityDatetime=GETDATE()

					If(@ActionName='Assign to Agent')
					Begin
						Set @StrSql=N'Update tbl_tp_TicketMaster_' + Cast(@ParentId as nvarchar) + N' Set @OldVal1=AssignedUser,AssignedUser=@AsgUser Where TicketId=@TktId '
						Set @StrParamDefination = N'@AsgUser bigint, @TktId bigint,@OldVal1 bigint output'
						
						print '@StrSql: ' + cast(@StrSql as varchar(max))
						Exec sp_executesql @StrSql, @StrParamDefination, @AsgUser=@ActionValue, @TktId=@TicketID, @OldVal1=@OldVal output

						Set @StrSql=N'With cte As ( SELECT ROW_NUMBER()over(ORDER BY TicketHistoryID DESC) Sno,AssignedUser From tbl_tp_TicketHistory Where TicketId=@TktId and ParentId=@PId) Update cte Set AssignedUser=@AsgUser where SNo=1 '
						Set @StrParamDefination = N'@TktId bigint, @PId bigint, @AsgUser bigint'
						
						print '@StrSql: ' + cast(@StrSql as varchar(max))
						Exec sp_executesql @StrSql, @StrParamDefination, @TktId=@TicketID, @PId=@ParentId, @AsgUser=@ActionValue

						Exec usp_tp_AddActivity @TicketId=@TicketID, @ParentId=@ParentId, @FieldName='AssignedUser', @OldValue=@OldVal, @NewValue=@ActionValue, @ActivityDescription='Agent Assigned by Scenario Rule', @ActivityBy=@TpUserId, @ActivityDatetime=@ActivityDatetime, @ActivityId=@ActivityId out, @EventId=null, @EventName=null, @EntityType='Scenario', @EntityId=@Scenario_Id
					End

					If(@ActionName='Assign to Group')
					Begin
						Set @StrSql=N'Update tbl_tp_TicketMaster_' + Cast(@ParentId as nvarchar) + N' Set @OldVal1=AssignedGroup,AssignedGroup=@AsgGroup Where TicketId=@TktId '
						Set @StrParamDefination = N'@AsgGroup bigint, @TktId bigint, @OldVal1 bigint output'
						
						print '@StrSql: ' + cast(@StrSql as varchar(max))
						Exec sp_executesql @StrSql, @StrParamDefination, @AsgGroup=@ActionValue, @TktId=@TicketID,@OldVal1=@OldVal output

						Set @StrSql=N'With cte As ( SELECT ROW_NUMBER()over(ORDER BY TicketHistoryID DESC) Sno,AssignedGroup From tbl_tp_TicketHistory Where TicketId=@TktId and ParentId=@PId) Update cte Set AssignedGroup=@AsgGroup where SNo=1 '
						Set @StrParamDefination = N'@TktId bigint, @PId bigint, @AsgGroup bigint'
						
						print '@StrSql: ' + cast(@StrSql as varchar(max))
						Exec sp_executesql @StrSql, @StrParamDefination, @TktId=@TicketID, @PId=@ParentId, @AsgGroup=@ActionValue

						Exec usp_tp_AddActivity @TicketId=@TicketID, @ParentId=@ParentId, @FieldName='AssignedGroup', @OldValue=@OldVal, @NewValue=@ActionValue, @ActivityDescription='Group Assigned by Scenario Rule', @ActivityBy=@TpUserId, @ActivityDatetime=@ActivityDatetime, @ActivityId=@ActivityId out, @EventId=null, @EventName=null, @EntityType='Scenario', @EntityId=@Scenario_Id
					End

					If(@ActionName='Mark as Spam')
					Begin
						Set @StrSql=N'Update tbl_tp_TicketMaster_' + Cast(@ParentId as nvarchar) + N' Set @OldVal1=TicketStatusID,TicketStatusID=9 Where TicketId=@TktId '
						Set @StrParamDefination = N'@TktId bigint,@OldVal1 output'
						
						print '@StrSql: ' + cast(@StrSql as varchar(max))
						Exec sp_executesql @StrSql, @StrParamDefination, @TktId=@TicketID, @OldVal1=@OldVal output

						Set @StrSql=N'With cte As ( SELECT ROW_NUMBER()over(ORDER BY TicketHistoryID DESC) Sno,TicketStatusID From tbl_tp_TicketHistory Where TicketId=@TktId and ParentId=@PId) Update cte Set TicketStatusID=9 where SNo=1 '
						Set @StrParamDefination = N'@TktId bigint, @PId bigint'
						
						print '@StrSql: ' + cast(@StrSql as varchar(max))
						Exec sp_executesql @StrSql, @StrParamDefination, @TktId=@TicketID, @PId=@ParentId

						Exec usp_tp_AddActivity @TicketId=@TicketID, @ParentId=@ParentId, @FieldName='TicketStatusID', @OldValue=@OldVal, @NewValue=9, @ActivityDescription='Ticket marked as Spam by Scenario Rule', @ActivityBy=@TpUserId, @ActivityDatetime=@ActivityDatetime, @ActivityId=@ActivityId out, @EventId=null, @EventName=null, @EntityType='Scenario', @EntityId=@Scenario_Id
					End

					If(@ActionName='Set Ticket Status as')
					Begin
						Set @StrSql=N'Update tbl_tp_TicketMaster_' + Cast(@ParentId as nvarchar) + N' Set TicketStatusID=@TktStatId Where TicketId=@TktId '
						Set @StrParamDefination = N'@TktId bigint, @TktStatId bigint'
						
						print '@StrSql: ' + cast(@StrSql as varchar(max))
						Exec sp_executesql @StrSql, @StrParamDefination, @TktStatId=@ActionValue, @TktId=@TicketID

						Set @StrSql=N'With cte As ( SELECT ROW_NUMBER()over(ORDER BY TicketHistoryID DESC) Sno,TicketStatusID From tbl_tp_TicketHistory Where TicketId=@TktId and ParentId=@PId) Update cte Set TicketStatusID=@TktStatId where SNo=1 '
						Set @StrParamDefination = N'@TktId bigint, @PId bigint, @TktStatId bigint'
						
						print '@StrSql: ' + cast(@StrSql as varchar(max))
						Exec sp_executesql @StrSql, @StrParamDefination, @TktId=@TicketID, @PId=@ParentId, @TktStatId=@ActionValue

						Exec usp_tp_AddActivity @TicketId=@TicketID, @ParentId=@ParentId, @FieldName='TicketStatusID', @OldValue=@OldVal, @NewValue=9, @ActivityDescription='Ticket Status set by Scenario Rule', @ActivityBy=@TpUserId, @ActivityDatetime=@ActivityDatetime, @ActivityId=@ActivityId out, @EventId=null, @EventName=null, @EntityType='Scenario', @EntityId=@Scenario_Id
					End

					If(@ActionName='Delete')
					Begin
						Set @StrSql=N'Update tbl_tp_TicketMaster_' + Cast(@ParentId as nvarchar) + N' Set IsActive=0 Where TicketId=@TktId '
						Set @StrParamDefination = N'@TktId bigint'
						
						print '@StrSql: ' + cast(@StrSql as varchar(max))
						Exec sp_executesql @StrSql, @StrParamDefination, @TktId=@TicketID

						Exec usp_tp_AddActivity @TicketId=@TicketID, @ParentId=@ParentId, @FieldName='IsActive', @OldValue=1, @NewValue=0, @ActivityDescription='Ticket Deleted by Scenario Rule', @ActivityBy=@TpUserId, @ActivityDatetime=@ActivityDatetime, @ActivityId=@ActivityId out, @EventId=null, @EventName=null, @EntityType='Scenario', @EntityId=@Scenario_Id
					End

					Set @kRowno=@kRowno+1
				End

				print ' return '
				return
			End
		End

		Set @iRowno=@iRowno+1
		
		print '--------------------------------------END----------------------------------------------'

	End

	If(@TktCnt = 0)
	Begin
		If exists(Select * From tbl_tp_ScenarioApplyHistory(nolock) Where TicketId=@TicketID and ParentID=@ParentId and IsActive=1)
		Begin
			Update tbl_tp_ScenarioApplyHistory Set IsApplied=1,ApplyDate=GETDATE(),Remarks='No Matching Scenario Rule Found'
			Where TicketId=@TicketID and ParentID=@ParentId and IsActive=1
		End
		Else
		Begin
			insert into tbl_tp_ScenarioApplyHistory(TicketId,ParentID,ScenarioID,Mode,IsApplied,ApplyDate,IsActive,CreatedBy,CreatedDate,Remarks)
			values(@TicketID,@ParentId,@Scenario_Id,'Auto',1,GETDATE(),1,-1,GETDATE(),'No Matching Scenario Rule Found')
		End
	End

End



GO

/* ============================================================
   Procedure: [dbo].[usp_tp_ApplySLA]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Exec usp_tp_ApplySLA 32222  
CREATE   PROCEDURE [dbo].[usp_tp_ApplySLA]  
(  
 @PID bigint=0,  
 @CutOffDate datetime='17-Nov-2023'  
)  
AS  
BEGIN  
  
-- declare @PID bigint=32222,@CutOffDate datetime='01-Mar-2024'  
  
if object_id('tempdb..#tbl_ParentId') is not null begin drop table #tbl_ParentId end  
if object_id('tempdb..#tbl_TicketSLA') is not null begin drop table #tbl_TicketSLA end  
if object_id('tempdb..#tbl_TicketList') is not null begin drop table #tbl_TicketList end  
  
create table #tbl_ParentId  
(  
 Id int identity(1,1),  
 ParentId bigint  
)  
    
create table #tbl_TicketList  
(  
 RowId	int identity(1,1)
)

create table #tbl_TicketSLA
(  
 RowId				int identity(1,1),  
 SLA_ID				bigint,  
 SequenceNo			int, 
 ParentId			bigint,  
 SLA_Detail_Id		bigint, 
 Priority_ID		int, 
 Respond_Val		int, 
 Respond_Unit		nvarchar(400), 
 Respond_Sec		bigint, 
 Resolve_Val		int,
 Resolve_Unit		nvarchar(400),
 Resolve_Sec		bigint,
 Operational_Unit	nvarchar(400), 
 TicketID			bigint,
 tpUserId			bigint,
 AssignedUser		bigint,
 AssignedGroup		bigint,
 CreatedOn			datetime
)  
  
	DECLARE @tbluser TABLE 
	(
		TpUser_ID BIGINT,
		User_ID BIGINT,
		Name VARCHAR(100),
		IMAGE NVARCHAR(200),
		MgrId bigint
	)

declare @iPId bigint=1, @iSLASettingId int=1, @iTL int=1, @PIdCnt bigint=0, @ser_user_id bigint=0, @ParentId bigint=0, @SLASettingCnt int=0, @TLCnt int=0, @StrParentid nvarchar(20) ='', @StrCutoffDate nvarchar(50)=''
declare @SLAResp_ID bigint, @SLA_ID bigint, @TicketId bigint, @Priority_ID int, @Respond_Sec bigint, @Resolve_Sec bigint, @Respond_Esc_Freq nvarchar(100), @Respond_Esc_AgentId bigint, @Respond_Esc_Sec bigint, @Respond_Rem_Freq nvarchar(100), @Respond_Rem_AgentId bigint, @Respond_Rem_Sec bigint, @Resolve_Rem_Freq nvarchar(100), @Resolve_Rem_AgentId bigint, @Resolve_Rem_Sec bigint, @ResolutionTo varchar(50)='' 
declare @ResolutionEsc1Sec bigint=0, @ResolutionEsc1AgentId bigint=0, @ResolutionEsc2Sec bigint=0,   
  @ResolutionEsc2AgentId bigint=0, @ResolutionEsc3Sec bigint=0, @ResolutionEsc3AgentId bigint=0,   
  @ResolutionEsc4Sec bigint=0, @ResolutionEsc4AgentId bigint=0  
declare @Apply_GroupId bigint, @Apply_TicketTypeId bigint, @Apply_Source nvarchar(400), @Apply_TicketCategory nvarchar(400), @Apply_Company nvarchar(400)  
declare @IsResponseRem bit, @ResponseRemAgentId bigint, @IsResponseEsc bit, @ResponseEscAgentId bigint, @IsResolutionRem bit, @ResolutionRemAgentId bigint, @IsResolutionEsc1 bit, @IsResolutionEsc2 bit, @IsResolutionEsc3 bit, @IsResolutionEsc4 bit, @AdminTpUserId bigint=0

  declare @minTicketID bigint=0, @maxTicketID bigint=0, @minSLA_Id bigint=0, @maxSLA_Id bigint=0,
		  @RecCnt int=0, @i int=1, @SequenceNo int, @SLA_Detail_Id bigint, @Operational_Unit nvarchar(200),
		  @ESCREMSequenceNo int, @IsResolutionEsc bit, @ResponseRemType nvarchar(200), 
		  @ResponseRemActionId bigint, @ResponseRemDate datetime, @Frequency_Sec bigint, 
		  @ResponseTo nvarchar(100), @ResponseVal bigint, @tpUserId bigint, @AssignedUser bigint,
		  @AssignedGroup bigint, @CreatedOn datetime
  declare @csvFieldListwithDataType nvarchar(max)='', @csvFieldList nvarchar(max)='', 
		  @StrWhere nvarchar(max)='', @strQuery nvarchar(max)=''

insert into #tbl_ParentId  
select distinct parentid from tbl_tp_SLAMaster(nolock) Where Active=1 and ParentID=case when @PID=0 then ParentID else @PID end  
--select distinct parentid from Serv_SLA_Setting(nolock) Where Active=1 and ParentID=case when @PID=0 then ParentID else @PID end  
  
select @PIdCnt=Count(*) from #tbl_ParentId  
print '@PIdCnt: ' + cast(@PIdCnt as varchar)  

drop table if exists #tblFieldList

 create table #tblFieldList
 (
	Column_Name varchar(100),
	FieldName varchar(100),
	Data_type varchar(20),
	Field_type varchar(20),
	Choices nvarchar(max)
 )


While @iPId <= @PIdCnt  
Begin  
 Select @ParentId=ParentId From #tbl_ParentId Where Id=@iPId  
 print '@ParentId: ' + cast(@ParentId as varchar)  
 select @StrParentid=cast(@ParentId as varchar), @StrCutoffDate=format(@CutOffDate,'dd-MMM-yyyy')
 
 truncate table #tblFieldList

 insert into #tblFieldList
 exec usp_tp_GetTicketFields @ParentId

 insert into #tblFieldList(Column_Name,FieldName,Data_type,Field_type,Choices)
 values('TicketID','TicketID','bigint','',''),('ParentId','ParentId','bigint','',''),('tpUser_Id','tpUser_Id','bigint','','')

 select @csvFieldListwithDataType=string_agg(FieldName+ ' ' +case when Data_type in ('varchar','nvarchar') then Data_type+'(max)' else Data_type end,','), @csvFieldList=string_agg(FieldName,',')
 from #tblFieldList
 
 -- select * from #tblFieldList
 print concat('@csvFieldList: ',@csvFieldList)

 exec ('alter table #tbl_TicketList add ' + @csvFieldListwithDataType)

 exec ('insert into #tbl_TicketList(' + @csvFieldList + ')
   select ' + @csvFieldList + '
 From tbl_tp_TicketMaster_'+ @StrParentid + '(nolock) 
 Where IsActive=1 and ParentID='+ @StrParentid + ' and dbo.ufn_tp_GetParentTicketStatus(TicketStatusID) not in (3,5,8,9,10) and CreatedOn >= ''' + @StrCutoffDate + ''' ' )
 --Serv_TicketMaster(nolock) 
   --and TicketID in (66652)  
 --Select * From Serv_TicketMaster(nolock) Where ParentID=36950 and Status not in (2,4)  
 select @TLCnt=Count(*) from #tbl_TicketList  
 print '@TLCnt: ' + cast(@TLCnt as varchar)  
  
  drop table if exists #tbl_TicketSLAList

	select ROW_NUMBER()over(ORDER BY TM.TicketID, SLA.SequenceNo) as RowSno, SLA.SLA_Id, SLA.SLA_Name, SLA.SLA_Description, SLA.SequenceNo, SLD.SLA_Detail_Id, SLD.Priority_ID, SLD.Respond_Val, SLD.Respond_Unit, SLD.Respond_Sec, SLD.Resolve_Val, SLD.Resolve_Unit, SLD.Resolve_Sec, SLD.Operational_Unit, TM.*
	into #tbl_TicketSLAList
	From	tbl_tp_SLAMaster(nolock) SLA INNER JOIN tbl_tp_SLADetail(nolock) SLD
	ON SLA.SLA_Id = SLD.SLA_Id AND SLA.Active = 1 AND SLA.IsEnabled = 1 INNER JOIN #tbl_TicketList(nolock) TM
	ON SLD.Priority_ID = TM.TicketPriority and SLA.ParentId=@ParentId
		
	Select @minTicketID=min(TicketID),@maxTicketID=max(TicketID) From #tbl_TicketSLAList

	print concat('@minTicketID: ',@minTicketID)
	print concat('@maxTicketID: ',@maxTicketID)

	While(@minTicketID <= @maxTicketID)
	Begin

		Select @minSLA_Id=min(SLA_Id),@maxSLA_Id=max(SLA_Id) From #tbl_TicketSLAList Where TicketID=@minTicketID

		print concat('@minSLA_Id: ',@minSLA_Id)
		print concat('@maxSLA_Id: ',@maxSLA_Id)

		While(@minSLA_Id <= @maxSLA_Id)
		Begin
			if exists(Select * from tbl_tp_SLACondition(nolock) where SLA_ID=@minSLA_Id and Active=1)
			Begin
				Select @StrWhere=STRING_AGG(concat(SLC.FieldName,' ',iif(SLC.Operator<7,replace(CO.OperatorText,'[A]',SLC.Value),CO.OperatorText),' ',iif(SLC.Operator>6,''''+SLC.Value+''' ',' '),SLC.Conjunction),' ')
				from tbl_tp_SLACondition(nolock) SLC inner join tbl_tp_ConditionalOperator(nolock) CO
				On	SLC.Operator=CO.ConditionId and SLC.Active=1 and CO.IsActive=1
				where SLC.SLA_ID=@minSLA_Id

				If(len(@StrWhere)>0)
				Begin
					Set @StrWhere=left(@StrWhere,len(@StrWhere)-3)
				End

				truncate table #tbl_TicketSLA

				set @strQuery=concat('insert into #tbl_TicketSLA 
				Select SLA_ID, SequenceNo, ParentId, SLA_Detail_Id, Priority_ID, Respond_Val, Respond_Unit, Respond_Sec, Resolve_Val, Resolve_Unit, Resolve_Sec, Operational_Unit, TicketID, tpUser_Id, AssignedUser, AssignedGroup, CreatedOn
				 From #tbl_TicketSLAList Where TicketID=',@minTicketID,' and SLA_ID=',@minSLA_Id,' and ',@StrWhere,' order by SequenceNo')

				 print concat('@strQuery: ',@strQuery)
				Exec sp_executesql @strQuery

				Select @RecCnt=count(*) From #tbl_TicketSLA
				print concat('@RecCnt: ',@RecCnt)

				If(@RecCnt>0)
				Begin
					set @i=1

					While(@i<=@RecCnt)
					Begin
						Delete From @tbluser

						select @SLA_ID=SLA_ID, @SequenceNo=SequenceNo, @SLA_Detail_Id=SLA_Detail_Id, @Respond_Sec=Respond_Sec, @Resolve_Sec=Resolve_Sec, @Operational_Unit=Operational_Unit, @tpUserId=tpUserId, @AssignedUser=AssignedUser, @AssignedGroup=AssignedGroup, @CreatedOn=CreatedOn
						From #tbl_TicketSLA 
						Where RowId=@i
						
						print concat(char(13),'------- @i: ', @i,'-------')
						print concat('@SLA_ID: ',@SLA_ID)
						print concat('@SequenceNo: ',@SequenceNo)
						print concat('@SLA_Detail_Id: ',@SLA_Detail_Id)
						print concat('@Respond_Sec: ',@Respond_Sec)
						print concat('@Resolve_Sec: ',@Resolve_Sec)
						print concat('@Operational_Unit: ',@Operational_Unit)
						print concat('@tpUserId: ',@tpUserId)
						print concat('@AssignedUser: ',@AssignedUser)
						print concat('@AssignedGroup: ',@AssignedGroup)
						print concat('@CreatedOn: ',@CreatedOn)

						Select top 1 @ESCREMSequenceNo=SequenceNo, @IsResponseRem=IsResponseRem, @IsResolutionRem=IsResolutionRem, @IsResponseEsc=IsResponseEsc, @IsResolutionEsc=IsResolutionEsc, @ResponseRemType=ResponseRemType, @ResponseRemActionId=ResponseRemActionId, @ResponseRemDate=ResponseRemDate 
						From tbl_tp_SLA_ESC_REM_ApplyHistory(nolock)
						Where IsActive=1 and TicketId=@minTicketID and ParentID=@ParentId and SLAID=@SLA_ID
						order by ESC_REM_Id desc

						print concat(char(13),'@ESCREMSequenceNo: ',@ESCREMSequenceNo)
						print concat('@IsResponseRem: ',@IsResponseRem)
						print concat('@IsResolutionRem: ',@IsResolutionRem)
						print concat('@IsResponseEsc: ',@IsResponseEsc)
						print concat('@IsResolutionEsc: ',@IsResolutionEsc)
						print concat('@ResponseRemType: ',@ResponseRemType)
						print concat('@ResponseRemActionId: ',@ResponseRemActionId)
						print concat('@ResponseRemDate: ',@ResponseRemDate)

						If(@ESCREMSequenceNo is null)
						Begin
							-- No SLA Steps found
							If exists(select * from tbl_tp_TicketHistory(nolock) where TicketID=@minTicketID and ParentID=@ParentId and Remarks is not null)
							Begin
								print 'Response Already Sent, Move to Resolution Reminder'
								Set @IsResolutionRem=1
								Set @ESCREMSequenceNo=0
							End
							Else
							Begin
								print 'Start with Response Reminder if Applicable'
								Set @IsResponseRem=1
								Set @ESCREMSequenceNo=0
							End
						End
						Else
						Begin
							If(@IsResponseRem=1)
							Begin
								If exists(select * from tbl_tp_TicketHistory(nolock) where TicketID=@minTicketID and ParentID=@ParentId and Remarks is not null)
								Begin
									print 'Response Already Sent, Move to Resolution Reminder'
									Set @IsResponseRem=0
									Set @IsResponseEsc=0
									Set @IsResolutionRem=1
									Set @IsResolutionEsc=0
									Set @ESCREMSequenceNo=0
								End
								Else
								Begin
									If(@ESCREMSequenceNo=(Select max(SequenceNo) From tbl_tp_SLAResponseDetail(nolock) Where Active=1 and IsEscalation=0 and SLA_Id=@SLA_ID))
									Begin
										print 'All Response Reminder Steps Completed, Move to Response Escalation'
										Set @IsResponseRem=0
										Set @IsResponseEsc=1
										Set @IsResolutionRem=0
										Set @IsResolutionEsc=0
										Set @ESCREMSequenceNo=0
									End
								End
							End

							If(@IsResponseEsc=1)
							Begin
								If exists(select * from tbl_tp_TicketHistory(nolock) where TicketID=@minTicketID and ParentID=@ParentId and Remarks is not null)
								Begin
									print 'Response Already Sent, Move to Resolution Reminder'
										Set @IsResponseRem=0
										Set @IsResponseEsc=0
										Set @IsResolutionRem=1
										Set @IsResolutionEsc=0
										Set @ESCREMSequenceNo=0
								End
								Else
								Begin
									If(@ESCREMSequenceNo=(Select max(SequenceNo) From tbl_tp_SLAResponseDetail(nolock) Where Active=1 and IsEscalation=1 and SLA_Id=@SLA_ID))
									Begin
										print 'All Response Escalation Steps Completed, Move to Resolution Reminder'
										Set @IsResponseRem=0
										Set @IsResponseEsc=0
										Set @IsResolutionRem=1
										Set @IsResolutionEsc=0
										Set @ESCREMSequenceNo=0
									End
								End
							End

							If(@IsResolutionRem=1)
							Begin
								If exists(select * from tbl_tp_TicketHistory(nolock) where TicketID=@minTicketID and ParentID=@ParentId and dbo.ufn_tp_GetParentTicketStatus(TicketStatusID) in (3,5))
								Begin
									print 'Ticket Already Resolved;break'
									break;
								End
								Else
								Begin
									If(@ESCREMSequenceNo=(Select max(SequenceNo) From tbl_tp_SLAResolutionDetail(nolock) Where Active=1 and IsEscalation=0 and SLA_Id=@SLA_ID))
									Begin
										print 'All Resolution Reminder Steps Completed, Move to Resolution Escalation'
										Set @IsResponseRem=0
										Set @IsResponseEsc=0
										Set @IsResolutionRem=0
										Set @IsResolutionEsc=1
										Set @ESCREMSequenceNo=0
									End
								End
							End

							If(@IsResolutionEsc=1)
							Begin
								If exists(select * from tbl_tp_TicketHistory(nolock) where TicketID=@minTicketID and ParentID=@ParentId and dbo.ufn_tp_GetParentTicketStatus(TicketStatusID) in (3,5))
								Begin
									print 'Ticket Already Resolved;break'
									break;
								End
								Else
								Begin
									If(@ESCREMSequenceNo=(Select max(SequenceNo) From tbl_tp_SLAResolutionDetail(nolock) Where Active=1 and IsEscalation=1 and SLA_Id=@SLA_ID))
									Begin
										print 'All Resolution Escalation Steps Completed;End'
										break;
									End
								End
							End
						End
						
						print concat(char(13),'after @ESCREMSequenceNo: ',@ESCREMSequenceNo)
						print concat('@IsResponseRem: ',@IsResponseRem)
						print concat('@IsResolutionRem: ',@IsResolutionRem)
						print concat('@IsResponseEsc: ',@IsResponseEsc)
						print concat('@IsResolutionEsc: ',@IsResolutionEsc)

						If(@IsResponseRem=1)
						Begin
							If exists(Select * From tbl_tp_SLAResponseDetail(nolock) Where IsEscalation=0 and SLA_Id=@SLA_ID and SequenceNo=@ESCREMSequenceNo+1)
							Begin
								Select @Frequency_Sec=Frequency_Sec, @ResponseTo=ResponseTo, @ResponseVal=ResponseVal
								From tbl_tp_SLAResponseDetail(nolock) 
								Where IsEscalation=0 and SLA_Id=@SLA_ID and SequenceNo=@ESCREMSequenceNo+1
								
								print concat('ResponseReminderDate: ',DATEADD(SECOND,@Respond_Sec+@Frequency_Sec,@CreatedOn))
								print concat('@ResponseTo: ',@ResponseTo)
								print concat('@ResponseVal: ',@ResponseVal)

								If(DATEADD(SECOND,@Respond_Sec+@Frequency_Sec,@CreatedOn) < GETDATE() )
								Begin

									If(@ResponseTo='TicketManager')
									Begin
										INSERT INTO @tbluser
										EXEC usp_tp_GetUserHierarchyList @tpUserId

										Select @AdminTpUserId=MgrId From @tbluser Where tpUser_Id=@tpUserId
										
										exec usp_tp_RaiseEmailNotification @minTicketID, @ParentId, 0, @tpUserId, @AdminTpUserId, 'First Response SLA Reminder','Agent' 

										insert into tbl_tp_SLA_ESC_REM_ApplyHistory
										values(@minTicketID,@SLA_ID,@ParentId,@ESCREMSequenceNo+1,1,0,0,0,@ResponseTo,@AdminTpUserId,GETDATE(),1,335,GETDATE())
									End

									If(@ResponseTo='admin')
									Begin
										Select @AdminTpUserId=TpUser_Id 
										From tbl_tp_UserLogin(nolock)
										Where ParentId=User_Id and ParentId=@ParentId

										exec usp_tp_RaiseEmailNotification @minTicketID, @ParentId, 0, @tpUserId, @AdminTpUserId, 'First Response SLA Reminder','Agent' 

										insert into tbl_tp_SLA_ESC_REM_ApplyHistory
										values(@minTicketID,@SLA_ID,@ParentId,@ESCREMSequenceNo+1,1,0,0,0,@ResponseTo,@AdminTpUserId,GETDATE(),1,335,GETDATE())
									End

									If(@ResponseTo='group')
									Begin
										exec usp_tp_RaiseEmailNotification @minTicketID, @ParentId, @AssignedGroup, @tpUserId, 0, 'First Response SLA Reminder','Agent' 

										insert into tbl_tp_SLA_ESC_REM_ApplyHistory
										values(@minTicketID,@SLA_ID,@ParentId,@ESCREMSequenceNo+1,1,0,0,0,@ResponseTo,@AssignedGroup,GETDATE(),1,335,GETDATE())						End

									If(@ResponseTo='agent')
									Begin
										exec usp_tp_RaiseEmailNotification @minTicketID, @ParentId, 0, @tpUserId, @AssignedUser, 'First Response SLA Reminder','Agent' 

										insert into tbl_tp_SLA_ESC_REM_ApplyHistory
										values(@minTicketID,@SLA_ID,@ParentId,@ESCREMSequenceNo+1,1,0,0,0,@ResponseTo,@AssignedUser,GETDATE(),1,335,GETDATE())
									End

								End

							End
						End

						If(@IsResponseEsc=1)
						Begin
							If exists(Select * From tbl_tp_SLAResponseDetail(nolock) Where IsEscalation=1 and SLA_Id=@SLA_ID and SequenceNo=@ESCREMSequenceNo+1)
							Begin
								Select @Frequency_Sec=Frequency_Sec, @ResponseTo=ResponseTo, @ResponseVal=ResponseVal
								From tbl_tp_SLAResponseDetail(nolock) 
								Where IsEscalation=1 and SLA_Id=@SLA_ID and SequenceNo=@ESCREMSequenceNo+1
								
								print concat('ResponseEscalationDate: ',DATEADD(SECOND,@Respond_Sec+@Frequency_Sec,@CreatedOn))
								print concat('@ResponseTo: ',@ResponseTo)
								print concat('@ResponseVal: ',@ResponseVal)

								If(DATEADD(SECOND,@Respond_Sec+@Frequency_Sec,@CreatedOn) < GETDATE() )
								Begin

									If(@ResponseTo='TicketManager')
									Begin
										INSERT INTO @tbluser
										EXEC usp_tp_GetUserHierarchyList @tpUserId

										Select @AdminTpUserId=MgrId From @tbluser Where tpUser_Id=@tpUserId
										
										exec usp_tp_RaiseEmailNotification @minTicketID, @ParentId, 0, @tpUserId, @AdminTpUserId, 'First Response SLA Violation','Agent' 

										insert into tbl_tp_SLA_ESC_REM_ApplyHistory
										values(@minTicketID,@SLA_ID,@ParentId,@ESCREMSequenceNo+1,0,0,1,0,@ResponseTo,@AdminTpUserId,GETDATE(),1,335,GETDATE())
									End

									If(@ResponseTo='admin')
									Begin
										Select @AdminTpUserId=TpUser_Id 
										From tbl_tp_UserLogin(nolock)
										Where ParentId=User_Id and ParentId=@ParentId

										exec usp_tp_RaiseEmailNotification @minTicketID, @ParentId, 0, @tpUserId, @AdminTpUserId, 'First Response SLA Violation','Agent' 

										insert into tbl_tp_SLA_ESC_REM_ApplyHistory
										values(@minTicketID,@SLA_ID,@ParentId,@ESCREMSequenceNo+1,0,0,1,0,@ResponseTo,@AdminTpUserId,GETDATE(),1,335,GETDATE())
									End

									If(@ResponseTo='group')
									Begin
										exec usp_tp_RaiseEmailNotification @minTicketID, @ParentId, @AssignedGroup, @tpUserId, 0, 'First Response SLA Violation','Agent' 

										insert into tbl_tp_SLA_ESC_REM_ApplyHistory
										values(@minTicketID,@SLA_ID,@ParentId,@ESCREMSequenceNo+1,0,0,1,0,@ResponseTo,@AssignedGroup,GETDATE(),1,335,GETDATE())						End

									If(@ResponseTo='agent')
									Begin
										exec usp_tp_RaiseEmailNotification @minTicketID, @ParentId, 0, @tpUserId, @AssignedUser, 'First Response SLA Violation','Agent' 

										insert into tbl_tp_SLA_ESC_REM_ApplyHistory
										values(@minTicketID,@SLA_ID,@ParentId,@ESCREMSequenceNo+1,0,0,1,0,@ResponseTo,@AssignedUser,GETDATE(),1,335,GETDATE())
									End

								End

							End
						End

						If(@IsResolutionRem=1)
						Begin
							If exists(Select * From tbl_tp_SLAResolutionDetail(nolock) Where IsEscalation=0 and SLA_Id=@SLA_ID and SequenceNo=@ESCREMSequenceNo+1)
							Begin
								Select @Frequency_Sec=Frequency_Sec, @ResponseTo=ResolutionTo, @ResponseVal=ResolutionVal
								From tbl_tp_SLAResolutionDetail(nolock) 
								Where IsEscalation=0 and SLA_Id=@SLA_ID and SequenceNo=@ESCREMSequenceNo+1
								
								print concat('ResolutionReminderDate: ',DATEADD(SECOND,@Resolve_Sec+@Frequency_Sec,@CreatedOn))
								print concat('@ResponseTo: ',@ResponseTo)
								print concat('@ResponseVal: ',@ResponseVal)

								If(DATEADD(SECOND,@Resolve_Sec+@Frequency_Sec,@CreatedOn) < GETDATE() )
								Begin

									If(@ResponseTo='TicketManager')
									Begin
										INSERT INTO @tbluser
										EXEC usp_tp_GetUserHierarchyList @tpUserId

										Select @AdminTpUserId=MgrId From @tbluser Where tpUser_Id=@tpUserId
										
										exec usp_tp_RaiseEmailNotification @minTicketID, @ParentId, 0, @tpUserId, @AdminTpUserId, 'Resolution Time SLA Reminder','Agent' 

										insert into tbl_tp_SLA_ESC_REM_ApplyHistory
										values(@minTicketID,@SLA_ID,@ParentId,@ESCREMSequenceNo+1,0,1,0,0,@ResponseTo,@AdminTpUserId,GETDATE(),1,335,GETDATE())
									End

									If(@ResponseTo='admin')
									Begin
										Select @AdminTpUserId=TpUser_Id 
										From tbl_tp_UserLogin(nolock)
										Where ParentId=User_Id and ParentId=@ParentId

										exec usp_tp_RaiseEmailNotification @minTicketID, @ParentId, 0, @tpUserId, @AdminTpUserId, 'Resolution Time SLA Reminder','Agent' 

										insert into tbl_tp_SLA_ESC_REM_ApplyHistory
										values(@minTicketID,@SLA_ID,@ParentId,@ESCREMSequenceNo+1,0,1,0,0,@ResponseTo,@AdminTpUserId,GETDATE(),1,335,GETDATE())
									End

									If(@ResponseTo='group')
									Begin
										exec usp_tp_RaiseEmailNotification @minTicketID, @ParentId, @AssignedGroup, @tpUserId, 0, 'Resolution Time SLA Reminder','Agent' 

										insert into tbl_tp_SLA_ESC_REM_ApplyHistory
										values(@minTicketID,@SLA_ID,@ParentId,@ESCREMSequenceNo+1,0,1,0,0,@ResponseTo,@AssignedGroup,GETDATE(),1,335,GETDATE())						End

									If(@ResponseTo='agent')
									Begin
										exec usp_tp_RaiseEmailNotification @minTicketID, @ParentId, 0, @tpUserId, @AssignedUser, 'Resolution Time SLA Reminder','Agent' 

										insert into tbl_tp_SLA_ESC_REM_ApplyHistory
										values(@minTicketID,@SLA_ID,@ParentId,@ESCREMSequenceNo+1,0,1,0,0,@ResponseTo,@AssignedUser,GETDATE(),1,335,GETDATE())
									End

								End

							End
						End

						If(@IsResolutionEsc=1)
						Begin
							If exists(Select * From tbl_tp_SLAResolutionDetail(nolock) Where IsEscalation=1 and SLA_Id=@SLA_ID and SequenceNo=@ESCREMSequenceNo+1)
							Begin
								Select @Frequency_Sec=Frequency_Sec, @ResponseTo=ResolutionTo, @ResponseVal=ResolutionVal
								From tbl_tp_SLAResolutionDetail(nolock) 
								Where IsEscalation=1 and SLA_Id=@SLA_ID and SequenceNo=@ESCREMSequenceNo+1
								
								print concat('ResolutionEscalationDate: ',DATEADD(SECOND,@Resolve_Sec+@Frequency_Sec,@CreatedOn))
								print concat('@ResponseTo: ',@ResponseTo)
								print concat('@ResponseVal: ',@ResponseVal)

								If(DATEADD(SECOND,@Resolve_Sec+@Frequency_Sec,@CreatedOn) < GETDATE() )
								Begin

									If(@ResponseTo='TicketManager')
									Begin
										INSERT INTO @tbluser
										EXEC usp_tp_GetUserHierarchyList @tpUserId

										Select @AdminTpUserId=MgrId From @tbluser Where tpUser_Id=@tpUserId
										
										exec usp_tp_RaiseEmailNotification @minTicketID, @ParentId, 0, @tpUserId, @AdminTpUserId, 'Resolution Time SLA Violation','Agent' 

										insert into tbl_tp_SLA_ESC_REM_ApplyHistory
										values(@minTicketID,@SLA_ID,@ParentId,@ESCREMSequenceNo+1,0,0,0,1,@ResponseTo,@AdminTpUserId,GETDATE(),1,335,GETDATE())
									End

									If(@ResponseTo='admin')
									Begin
										Select @AdminTpUserId=TpUser_Id 
										From tbl_tp_UserLogin(nolock)
										Where ParentId=User_Id and ParentId=@ParentId

										exec usp_tp_RaiseEmailNotification @minTicketID, @ParentId, 0, @tpUserId, @AdminTpUserId, 'Resolution Time SLA Violation','Agent' 

										insert into tbl_tp_SLA_ESC_REM_ApplyHistory
										values(@minTicketID,@SLA_ID,@ParentId,@ESCREMSequenceNo+1,0,0,0,1,@ResponseTo,@AdminTpUserId,GETDATE(),1,335,GETDATE())
									End

									If(@ResponseTo='group')
									Begin
										exec usp_tp_RaiseEmailNotification @minTicketID, @ParentId, @AssignedGroup, @tpUserId, 0, 'Resolution Time SLA Violation','Agent' 

										insert into tbl_tp_SLA_ESC_REM_ApplyHistory
										values(@minTicketID,@SLA_ID,@ParentId,@ESCREMSequenceNo+1,0,0,0,1,@ResponseTo,@AssignedGroup,GETDATE(),1,335,GETDATE())						End

									If(@ResponseTo='agent')
									Begin
										exec usp_tp_RaiseEmailNotification @minTicketID, @ParentId, 0, @tpUserId, @AssignedUser, 'Resolution Time SLA Violation','Agent' 

										insert into tbl_tp_SLA_ESC_REM_ApplyHistory
										values(@minTicketID,@SLA_ID,@ParentId,@ESCREMSequenceNo+1,0,0,0,1,@ResponseTo,@AssignedUser,GETDATE(),1,335,GETDATE())
									End

								End

							End
						End

						Set @i+=1
					End

				End

			End

			Set @minSLA_Id+=1
		End
		
		if(@minTicketID = @maxTicketID)
		Begin
			print 'Loop Iteration Completed;Break'
			break
		End
		Else
		Begin
			Select @minTicketID=min(TicketID) From #tbl_TicketSLAList Where TicketID>@minTicketID
		End
	End

  
 Set @iPId=@iPId+1  
 Set @iSLASettingId=1  
 Set @iTL=1  
  
 truncate table #tbl_TicketList  
 truncate table #tbl_TicketSLA  
End  
  
  
END  



GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_ChangeAgentMaster]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_tp_ChangeAgentMaster] --2
(
 @CreatedBy BIGINT,
 @tpUserid BIGINT
)
AS
BEGIN
    DECLARE @NewIsActive BIT;

    SELECT @NewIsActive = IsActive
    FROM tbl_tp_UserLogin
    WHERE TpUser_Id = @tpUserid AND User_Id IS NOT NULL;

    UPDATE tbl_tp_UserLogin
    SET
        IsActive = CASE WHEN @NewIsActive = 0 THEN 1 ELSE 0 END,
        ModifiedBy = @CreatedBy,
        ModifiedOn = GETDATE()
    WHERE TpUser_Id = @tpUserid AND User_Id IS NOT NULL;

    SELECT CASE WHEN @NewIsActive = 0 THEN 'Activated' ELSE 'Deactivated' END AS [Status];
END



GO

