  --@MetaData nvarchar(200)  
)            
as            
Begin     
  --declare 
  --@Permissionid bigint=5,  
  --@RoleId bigint=55,
  --@tpuserid bigint=60  ,          
  --@MetaData nvarchar(200)  ='{"IPAddress":"::1","MacAddress":"00FF08A6B99C","IsImpersonation":false,"ImpersonatorId":0}'
DECLARE @Status int=1 ,@ParentID Bigint,@UserID Bigint, @TimeZone nvarchar (400)  ,@rowJson NVARCHAR(MAX)  , @IPAdress NVARCHAR(50),@DeviceId NVARCHAR(50),@IsImpersonation BIT ,@ImpersonatorId INT    
