   Begin        

       UPDATE tbl_tp_RolesMaster SET IsDefault = 0 WHERE ParentId = @ParentID 
       Update  tbl_tp_RolesMaster set IsDefault = 1  where Role_Id = @RoleId and  ParentId=@ParentID   
  	  	   
       select 'Role Changed' 
