/* ============================================================
   Procedure: [dbo].[Usp_tp_ChangeDispatchrRuleStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_ChangeDispatchrRuleStatus]                
(                      
  @DispatchrId BIGINT,                      
  @Type NVARCHAR(200) ,  
  @IsEnable BIT,
  @TpUserID BIGINT,                    
  @MetaData NVARCHAR(200)            
)                      
AS  
BEGIN              
            
DECLARE @ParentID BIGINT,@UserId BIGINT, @TimeZone NVARCHAR(400), @rowJson NVARCHAR(MAX), @IPAddress NVARCHAR(50), @DeviceId NVARCHAR(50), @IsImpersonation BIT,     @ImpersonatorId INT  

  Select @ParentID = ParentId,@TimeZone = TimeZone,@UserId = User_Id  From tbl_tp_UserLogin (noLock) Where TpUser_Id = @TpUserID 
  AND IsActive = 1                      
  
SET @IPAddress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)              
SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)              
SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)              
SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)              
               
BEGIN                   
IF (@Type = 'Toggle')                 
BEGIN                    
   UPDATE tbl_tp_DispatcherMaster 
   SET IsEnabled = @IsEnable,  
   ModifiedBy = @UserId,  
   ModifiedDate = GETDATE()     
   WHERE Disptchr_Id = @DispatchrId 
   IF (@IsEnable = 0)

   BEGIN
        
		 SELECT 'disabled' AS msg, 1 AS row   
     
   END

      IF (@IsEnable = 1)

   BEGIN
        
		 SELECT 'enabled' AS msg, 1 AS row   
     
   END
     
                   
END                    
ELSE                    
BEGIN                    
   UPDATE tbl_tp_DispatcherMaster 
   SET Active = 0,  
   ModifiedBy = @UserId,  
   ModifiedDate = GETDATE()  
   WHERE Disptchr_Id = @DispatchrId                      
   SELECT 'deleted' AS msg, 1 AS row            
            
   SET @rowJson = (SELECT * FROM tbl_tp_SLAMaster FOR JSON AUTO, INCLUDE_NULL_VALUES)                      
                      
   IF @rowJson IS NOT NULL                      
   BEGIN                      
      EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData @User_id = @UserID                      
            , @Activity_type = 'Delt_dispatchermaster'                      
            , @ActionType = 'D'                      
            , @RowJson = @rowJson                      
            , @Table_name = 'tbl_tp_DispatcherMaster', @ip_adress = @IPAddress, @device_id = @DeviceId, @IsImpersonation = @IsImpersonation,@ImpersonatorId =  @ImpersonatorId               
   END             
END           
END     
END  



