CREATE   PROCEDURE [dbo].[Usp_tp_ChangeSLAPoliciesStatus]                
(                      
  @SLA_Id BIGINT, 
  @IsEnable BIT,
  @Type NVARCHAR(10),            
  @TpUserID BIGINT,                    
  @MetaData NVARCHAR(200)            
)                      
AS  
BEGIN              
            
DECLARE @ParentID BIGINT,@UserId BIGINT,  @rowJson NVARCHAR(MAX), @IPAddress NVARCHAR(50), @DeviceId NVARCHAR(50), @IsImpersonation BIT,     @ImpersonatorId INT              
Select @ParentID = ParentId,@UserId = User_Id  From tbl_tp_UserLogin (noLock) Where TpUser_Id = @TpUserID AND IsActive = 1                      
  
SET @IPAddress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)              
SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)              
SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)              
SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)              
               
BEGIN                   
IF (@Type = 'Delete')                 
BEGIN                    
   UPDATE tbl_tp_SLAMaster SET Active = 0,  
   ModifiedBy = @UserId,  
   ModifiedDate = GETDATE()     
   WHERE SLA_Id = @SLA_Id    
     
   SELECT 'Deleted' AS msg                     
END                    

IF (@Type = 'Toggle')  
BEGIN                    
   UPDATE tbl_tp_SLAMaster SET IsEnabled = @IsEnable,  
    ModifiedBy = @UserId,  
   ModifiedDate = GETDATE()   
   WHERE SLA_Id = @SLA_Id                      
   SELECT 'StatusChanged' AS msg
   
   END
            
   SET @rowJson = (SELECT * FROM tbl_tp_SLAMaster FOR JSON AUTO, INCLUDE_NULL_VALUES)                      
                      
   IF @rowJson IS NOT NULL                      
   BEGIN                      
      EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData @User_id = @UserID   
	  
            , @Activity_type = 'Delete_SLAPoliciy'                      
            , @ActionType = 'D'                      
            , @RowJson = @rowJson                      
            , @Table_name = 'tbl_tp_SLAMaster', @ip_adress = @IPAddress, @device_id = @DeviceId, @IsImpersonation = @IsImpersonation, @ImpersonatorId =  @ImpersonatorId               
   END             
END           
END     
 



