/* ============================================================
   Procedure: [dbo].[USP_tp_ChangeTicketPassword_App]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[USP_tp_ChangeTicketPassword_App]
    @tpUserID int,
    @oldpassword nvarchar(50),
    @NewPwd nvarchar(50)
AS
BEGIN
    DECLARE @count int

    -- Check if the old password matches for the provided UserID
    SELECT @count = COUNT(*) FROM tbl_tp_UserLogin (NOLOCK) WHERE TpUser_Id = @tpUserID AND pwd = @oldpassword

    IF @count > 0
    BEGIN
        -- Update the password for the specific user
        UPDATE tbl_tp_UserLogin SET pwd = @NewPwd WHERE TpUser_Id = @tpUserID
        SELECT 'Password changed Successfully' AS msg
    END
    ELSE
    BEGIN
        -- The old password provided is incorrect for the given user
        SELECT 'Old Password is Wrong' AS msg
    END
END



GO

