   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_CheckCustomFieldExists]    
@ParentId BIGINT,    
@FieldName VARCHAR (100)    
AS
BEGIN

    DECLARE @Status INT,@TicketMasterTable NVARCHAR(max)

    EXEC @Status = Usp_tp_CreateTicketMasterTableByParentID @ParentID,@TicketMasterTable OUTPUT 
	
    SET NOCOUNT ON;
    DECLARE @P CHAR(1);
    SET @P = '0';

    IF EXISTS (SELECT COLUMN_NAME FROM INFORMATION_SCHEMA.COLUMNS WHERE TABLE_NAME = @TicketMasterTable AND COLUMN_NAME = @FieldName)
    BEGIN
        SET @P = '1';
    END

    SELECT @P AS DUPLICATE;

END



