/* ============================================================
   Procedure: [dbo].[Usp_tp_CompleteAgentdetailsSave]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_CompleteAgentdetailsSave]
    @UserId INT, 
    @SelectedSkills NVARCHAR(MAX) = NULL,  
    @SelectedRoles NVARCHAR(MAX) = NULL,  
    @SelectedGroups NVARCHAR(MAX) = NULL,
	@selectedviewGroups NVARCHAR(MAX) = NULL, 
    @AllAccess BIT,
    @EditAccess BIT,
    @ViewAccess BIT,
    @RestrictedAccess BIT,
	@Option nvarchar
AS
BEGIN
    PRINT 'Received Data:'
    PRINT 'UserId: ' + CAST(@UserId AS NVARCHAR(10));
    PRINT 'SelectedSkills: ' + COALESCE(@SelectedSkills, 'NULL');
    PRINT 'SelectedRoles: ' + COALESCE(@SelectedRoles, 'NULL');
    PRINT 'SelectedGroups: ' + COALESCE(@SelectedGroups, 'NULL');
    PRINT 'AllAccess: ' + CAST(@AllAccess AS NVARCHAR(10));
    PRINT 'EditAccess: ' + CAST(@EditAccess AS NVARCHAR(10));
    PRINT 'ViewAccess: ' + CAST(@ViewAccess AS NVARCHAR(10));
    PRINT 'RestrictedAccess: ' + CAST(@RestrictedAccess AS NVARCHAR(10));
    
    -- Insert Skills into tbl_tp_AgentSkillMapping
    IF (@SelectedSkills IS NOT NULL)
    BEGIN
        INSERT INTO tbl_tp_AgentSkillMapping (tpUserId, Skill_Id, IsActive, CreatedBy, CreatedDate)
        SELECT @UserId, value, 1, @UserId, GETDATE()
        FROM STRING_SPLIT(@SelectedSkills, ',');
    END


    IF (@SelectedRoles IS NOT NULL)
       UPDATE tbl_tp_agentrolemapping
       SET Active = 0
       WHERE tpuserid = @UserId AND role_id IN (SELECT value FROM STRING_SPLIT(@SelectedRoles, ','));

    BEGIN
        INSERT INTO tbl_tp_agentrolemapping (tpuserid, role_id, Active, CreatedBy, CreatedDate)
        SELECT @UserId, value, 1, @UserId, GETDATE()
        FROM STRING_SPLIT(@SelectedRoles, ',');
    END

    -- Insert Groups into tbl_tp_AgentGroupMapping based on the access type flags
    IF (@AllAccess = 1 AND @SelectedGroups IS NOT NULL)
    BEGIN
        INSERT INTO tbl_tp_AgentGroupMapping (tpUserId, GroupId, IsActive, CreatedBy, CreatedDate, [AccessType])
        SELECT @UserId, value, 1, @UserId, GETDATE(), 'GlobalAccess'
        FROM STRING_SPLIT(@SelectedGroups, ',');
    END

    IF (@EditAccess = 1 AND @SelectedGroups IS NOT NULL)
    BEGIN
        INSERT INTO tbl_tp_AgentGroupMapping (tpUserId, GroupId, IsActive, CreatedBy, CreatedDate, [AccessType],IsEdit)
        SELECT @UserId, value, 1, @UserId, GETDATE(), 'assignedToGroup',1
        FROM STRING_SPLIT(@SelectedGroups, ',');
    END

    IF (@ViewAccess = 1 AND @selectedviewGroups IS NOT NULL)
    BEGIN
        INSERT INTO tbl_tp_AgentGroupMapping (tpUserId, GroupId, IsActive, CreatedBy, CreatedDate, [AccessType])
        SELECT @UserId, value, 1, @UserId, GETDATE(), 'assignedToGroup'
        FROM STRING_SPLIT(@selectedviewGroups, ',');
    END

    IF (@RestrictedAccess = 1 AND @SelectedGroups IS NOT NULL)
    BEGIN
        INSERT INTO tbl_tp_AgentGroupMapping (tpUserId, GroupId, IsActive, CreatedBy, CreatedDate, [AccessType])
        SELECT @UserId, value, 1, @UserId, GETDATE(), 'RestrictedAccess'
        FROM STRING_SPLIT(@SelectedGroups, ',');
    END
END




GO

