/* ============================================================
   Procedure: [dbo].[usp_tp_CreateEntityForLogin]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_tp_CreateEntityForLogin
(
	@TpUserId bigint
)
As
Begin
	declare @EntityId bigint=0, @EntityName varchar(20)='', @Mobile nvarchar(40), @Email	nvarchar(200), 
			@ParentId bigint

	Select	@EntityId=isnull(EntityId,0), @EntityName=isnull(EntityName,''), @Mobile=nullif(Mobile,''),
			@Email=nullif(Email,''), @ParentId=ParentId
	from tbl_tp_UserLogin(nolock) 
	Where TpUser_Id=@TpUserId

	If(@EntityName='' or @EntityId=0)
	Begin
		Select @EntityId=Id,@EntityName='Lead' from UserLeads(nolock) Where ParentID=@ParentId and (@Email in (EmailID,EmailID1,EmailID2) or @Mobile in (MobileNo,MobileNo1,MobileNo2))

		If(@EntityId=0)
		Begin
			Select @EntityId=EnquiryId,@EntityName='Enquiry' from UserEnquiry(nolock) Where ParentID=@ParentId and (@Email in (EmailID,EmailID1,EmailID2) or @Mobile in (MobileNo,MobileNo1,MobileNo2))
		End
	
		DECLARE @SourceID BIGINT,@LeadNo bigint;

		SELECT TOP 1 @SourceID=[SourceID]
		FROM UserSourceSettings(NOLOCK)
		WHERE [NAME] = 'ServiceTicketSignup' AND [UserID] = @ParentID
		ORDER BY [SourceID] DESC;

		If(@EntityName='Lead' or @EntityName='')
		Begin
			SELECT @LeadNo=MAX([Leadno]) + 1 FROM userleads(nolock) WHERE [parentid] = @ParentId;

			INSERT INTO userleads([LeadNo], [PersonName], [EmailID], MobileNo, [AssignedTo], [SourceName],
			[ParentID], [Remarks], [CreatedOn], [CreatedBy], [FollowUpStatus], [NextStatusDate],
			[FollowupDate])
			SELECT @leadno, Name, email, Mobile, ParentId, @SourceID, ParentId,
			'Lead Added from New Support Ticket', GETDATE(), ParentId, 1, GETDATE(), GETDATE()
			from tbl_tp_UserLogin(nolock) 
			Where TpUser_Id=@TpUserId

			Select @EntityId=SCOPE_IDENTITY();

			UPDATE [tbl_tp_UserLogin] SET [EntityId]=@EntityId,EntityName='Lead' WHERE [TpUser_Id]=@TpUserId;
		End
		Else
		Begin--Enquiry
			INSERT INTO UserEnquiry([PersonName], [EmailID], MobileNo, [SourceName],
			[ParentID], [InitialRemarks], [CreatedDate], [CreatedBy])
			SELECT  Name, email, Mobile, @SourceID, ParentId,
			'Lead Added from New Support Ticket', GETDATE(), ParentId
			from tbl_tp_UserLogin(nolock) 
			Where TpUser_Id=@TpUserId

			Select @EntityId=SCOPE_IDENTITY();

			UPDATE [tbl_tp_UserLogin] SET [EntityId]=@EntityId,EntityName='Enquiry' WHERE [TpUser_Id]=@TpUserId;
		End
	End


End



GO

/* ============================================================
   Procedure: [dbo].[usp_tp_CreateInternalUser]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Exec usp_tp_CreateInternalUser @Parentid=32198, @Kit19UserId=32198  
CREATE   PROC usp_tp_CreateInternalUser  
(  
 @Parentid bigint,   
 @Kit19UserId bigint  
)  
AS  
Begin  
   
 Declare @TpUserid bigint=0, @GroupID bigint = 0   
  
 If not exists(select * from tbl_tp_UserLogin(nolock) where User_id = @Parentid and IsActive=1)  
 Begin  
  insert into tbl_tp_UserLogin(ParentId, User_id,Name, LoginName, Pwd,  Mobile,    
  Email, Company, Country, City, State, Address, Zip, IsActive)                                 
  select ParentId,user_id, FName+','+LName, User_Login,                                 
  Pwd, CONVERT(varchar(20), Cast(Mobile as BigInt)) Mobile,      
  EMail, CompnayName,Country,  City, State,  Address ,  Pincode, 1  
  from user_detail(nolock)   
  where  User_id = @Parentid  
  
  Select @TpUserid=SCOPE_IDENTITY()  
 End  
  
 If(@Kit19UserId != @Parentid)  
 Begin  
  If not exists(select * from tbl_tp_UserLogin(nolock) where User_id = @Kit19UserId and ParentID = @Parentid and IsActive=1)  
  Begin  
   insert into tbl_tp_UserLogin(ParentId, User_id,Name, LoginName, Pwd,  Mobile,  
   Email, Company, Country, City, State, Address, Zip, IsActive)  
   select ParentId,user_id, FName+','+LName, User_Login,  
   Pwd, CONVERT(varchar(20), Cast(Mobile as BigInt)) Mobile,  
   EMail, CompnayName,Country,  City, State,  Address ,  Pincode, 1  
   from user_detail(nolock)  
   where  User_id = @Kit19UserId and ParentID = @Parentid  
  
   Select @TpUserid=SCOPE_IDENTITY()  
  End  
  Else  
  Begin  
   Select 'Login already exists' as Msg  
   return  
  End  
 End  
  
 IF NOT EXISTS(SELECT * FROM tbl_tp_GroupMaster WHERE ParentId = @ParentID)      
 BEGIN      
  insert into tbl_tp_GroupMaster(ParentId,GroupName,GroupDesc,Active,Assigned)  
  values(@ParentID,'Admin','Admin',1,'roundrobin')  
  
  select @GroupID = SCOPE_IDENTITY()  
  
  insert into tbl_tp_AgentGroupMapping  
  (tpUserId,GroupId,IsActive,CreatedBy,CreatedDate,AccessType)--,IsAssigned)  
  Values(@TpUserid,@GroupID,1,@TpUserid,GETDATE(),'GlobalAccess')--,0)  
 END          
  
 If(@TpUserid>0)  
 Begin  
  Select 'Login Created in Ticket Portal' as Msg  
 End  
 Else  
 Begin  
  Select 'Login could not be Created in Ticket Portal' as Msg  
 End  
  
End  


GO

