   Procedure: [dbo].[Usp_tp_CreateTicketActivityTableByParentID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_CreateTicketActivityTableByParentID]
(            
  @ParentID bigint,          
  @TicketActivityTable nvarchar(max) output           
)            
AS         
Begin

   SET @TicketActivityTable = 'tbl_tp_TicketActivity_'+cast(@ParentId as varchar)           
   
   if((@ParentID is not null) and (@ParentID <> 0))
   Begin
	   Declare @Qtbl Nvarchar(max) = N' CREATE TABLE [dbo].'+@TicketActivityTable+'(            
			[ActivityID] [bigint] IDENTITY(1,1) Primary Key NOT NULL,
			[TicketID] [bigint] NOT NULL,
			[ParentID] [bigint] NOT NULL,
			[FieldName] [nvarchar](100) NOT NULL,
			[OldValue] [nvarchar](max) NULL,
			[NewValue] [nvarchar](max) NULL,
			[ActivityDescription] [nvarchar](max) NULL,
			[ActivityDatetime] [datetime] NOT NULL default(getdate()),
			[ActivityBy] [bigint] NOT NULL,
			[EventId] [bigint] NULL,
			[IsActive] [bit] NOT NULL default(1),
			[EntityType] [varchar](50) NULL,
			[EntityId] [bigint] NULL
		)
	   '            
            
		IF Not EXISTS (SELECT * FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME = N'tbl_tp_TicketActivity_' + cast(@ParentID as nvarchar(max)))
		BEGIN
			print  N'creating tbl_tp_TicketActivity_' + cast(@ParentID as nvarchar(max))             
			--print @Qtbl            
			exec sp_executesql @Qtbl            
			return 1          
		End	
   End

End   



GO

