   set @PosEnd=CHARINDEX('AGENT',@MailSubject)  
  
   If(@PosEnd=0)  
   Begin  
  set @PosEnd=CHARINDEX('TICKET',@MailSubject)  
   End  
  
  print concat('@MailSubject: ',@MailSubject)
  print concat('@Pos: ',@Pos)
  print concat('@PosEnd: ',@PosEnd)

   If(@Pos > 11)    
   Begin    
    Set @TicketNo = trim(SUBSTRING(@MailSubject,@Pos,@PosEnd-@Pos+1))    
    Set @Mode='Edit'    
   End    
   Else    
   Begin    
    Set @Mode='Add'    
   End    
  End    
    
  print '@Mode=' + @Mode    
  print '@TicketNo=' + @TicketNo    
    
  If(@Mode='Add')    
  Begin    
   set @TicketResponse = 0    
    
   --If not exists(select * from Serv_ticket_AutoNo where ParentId = @ParentId and prefix not like 'T%')    
   --Begin    
