CREATE   PROCEDURE [dbo].[Usp_tp_CreateTicketMasterTableByParentID]            
(            
  @ParentID bigint,          
  @TicketMasterTable nvarchar(max) output           
)            
  AS         
Begin            
               
          
   SET @TicketMasterTable = 'tbl_tp_TicketMaster_'+cast(@ParentId as varchar)           
     if((@ParentID is not null) and (@ParentID <> 0))            
   Begin            
   Declare @Qtbl Nvarchar(max) = N' CREATE TABLE [dbo].'+@TicketMasterTable+'(            
   [TicketID] [bigint] IDENTITY(1,1) Primary Key NOT NULL,            
   [tpUser_Id] [bigint] NULL,          
   [ParentID] [bigint] NULL,                      
   [TicketNo] [nvarchar](50) NOT NULL,                     
   [RequesterMobileNo] [nvarchar](50) NULL,                      
   [RequesterEmailID] [nvarchar](200) NULL,     
   [RequesterMobileNo1] [nvarchar](50) NULL,                      
   [RequesterEmailID1] [nvarchar](200) NULL,    
   [RequesterMobileNo2] [nvarchar](50) NULL,                      
   [RequesterEmailID2] [nvarchar](200) NULL,    
   [Subject] [nvarchar](max) NOT NULL,                      
   [Description] [nvarchar](max) NOT NULL,                     
   [TicketStatusID] [bigint]NOT NULL,                      
   [Remarks] [nvarchar] (max) NULL,                      
   [Note] [nvarchar] (max) NULL,                      
   [UserResponse] [nvarchar](max) NULL,                      
   [TicketPriority] [bigint] NOT NULL,                      
   [AssignedUser] [bigint] NULL,                      
   [AssignedGroup] [bigint] NULL,                      
   [AssignedSource][nvarchar](100)NOT NULL,                      
   [TicketCategoryId] [bigint] NOT NULL,                      
   [TicketTypeId] [int] NOT NULL,                      
   [TicketSourceId] [bigint] NOT NULL,                      
   [ProductId] [bigint] NULL,                      
   [IsMerged] [bit] NOT NULL,                      
   [IsSplitted][bit] NOT NULL,                     
   [IsParentTicket] [bit] NOT NULL,                      
   [IsChildTicket] [bit] NOT NULL,                      
   [ParentTicketID] [bigint] NULL,                      
   [LastActionDatetime] [datetime] NOT NULL,                    
   [AssignedBy] [bigint] NULL,                      
   [AssignedDateTime] [datetime] NULL,                      
   [TicketTag] [nvarchar](1000) NULL,                      
   [EntityID] [bigint] NULL,                      
   [EntityName] [nvarchar](20)NULL,      
   [Company] [nvarchar](400)NULL,      
   [IsActive] [bit] NOT NULL,                      
   [CreatedBy] [bigint] NOT NULL,                      
   [CreatedOn] [datetime] NOT NULL,             
   [ModifiedBy] [bigint]  NULL,           
   [ModifiedOn] [datetime] NULL,  
   [SplittedBy] [bigint]  NULL,           
   [SplittedOn] [datetime] NULL,  
   [MergedBy] [bigint]  NULL,           
   [MergedOn] [datetime] NULL,  
   [ClosedBy] [bigint]  NULL,           
   [ClosedOn] [datetime] NULL,  
   [CreatedChildBy] [bigint]  NULL,           
   [CreatedChildOn] [datetime] NULL,
   [CountryCode] [nvarchar](50) NULL, 
   [CountryCode1] [nvarchar](50) NULL,  
   [CountryCode2] [nvarchar](50) NULL   
   )  
     
   '            
            
         IF Not EXISTS (SELECT * FROM INFORMATION_SCHEMA.TABLES WHERE TABLE_NAME = N'tbl_tp_TicketMaster_' + cast(@ParentID as nvarchar(max)))            
          BEGIN            
         --print  N'creating tbl_tp_TicketMaster_' + cast(@ParentID as nvarchar(max))             
      --print @Qtbl            
      exec sp_executesql @Qtbl            
   return 1          
    End            
   End            
End   



GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_CreateTicketMasterTableByParentID_jk]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*
================================================================================
FIX3 (JK) - Create TicketMaster test table + indexes
Name: dbo.Usp_tp_CreateTicketMasterTableByParentID_jk

Changes vs Fix2:
  - ROOT CAUSE FIX: Replaced single giant DECLARE @sql NVARCHAR(MAX) = N'...'
    with multiple SET @sql += N'...' segments.
    WHY: SQL Server evaluates string literals as NVARCHAR(4000) at parse time.
    A single DECLARE = N'huge literal' silently truncates anything beyond ~4000
    chars — causing the dynamic SQL to be cut off mid-statement (e.g. ending at
    "AND name" without the "= N'IX_...'" part), which triggered the parse error:
    "An expression of non-boolean type specified in a context where a condition 
    is expected, near 'name'."
    Using SET @sql += keeps the LEFT side as NVARCHAR(MAX) so concatenation 
    is safe regardless of total length.
  - [name] column stays bracketed in all sys.indexes checks (from Fix2).
  - CATCH block uses SELECT @sql (not PRINT) so full SQL visible if it fails.
  - Short @ObjName used for OBJECT_ID() calls (no schema brackets needed there).

This proc CREATES the JK test table only. It does NOT populate data.
Use JK_TestTable_Populate_and_Notes.sql to copy rows while preserving TicketID.
================================================================================
*/
CREATE   PROCEDURE dbo.Usp_tp_CreateTicketMasterTableByParentID_jk
(
    @ParentID       BIGINT,
    @TicketMasterTable NVARCHAR(MAX) OUTPUT
)
AS
BEGIN
    SET NOCOUNT ON;

    IF (ISNULL(@ParentID, 0) = 0)
    BEGIN
        SET @TicketMasterTable = NULL;
        RETURN 0;
    END

    DECLARE @BaseName  SYSNAME        = N'tbl_tp_TicketMaster_jk_' + CONVERT(VARCHAR(20), @ParentID);
    DECLARE @ObjName   NVARCHAR(300)  = N'dbo.' + @BaseName;                              -- for OBJECT_ID()
    DECLARE @FullName  NVARCHAR(300)  = QUOTENAME(N'dbo') + N'.' + QUOTENAME(@BaseName);  -- for DDL
    DECLARE @PKName    NVARCHAR(200)  = QUOTENAME(N'PK_' + @BaseName);

    SET @TicketMasterTable = @BaseName;

    ---------------------------------------------------------------------------
    -- Build dynamic SQL in SEGMENTS using SET @sql += 
    -- This avoids the NVARCHAR(4000) silent-truncation bug that occurs when
    -- a large string literal is assigned in a single DECLARE = N'...' statement.
    ---------------------------------------------------------------------------
    DECLARE @sql NVARCHAR(MAX) = N'';   -- Start as empty NVARCHAR(MAX)

    ---------------------------------------------------------------------------
    -- SEGMENT 1: Create table (if not exists)
    ---------------------------------------------------------------------------
    SET @sql += N'
IF OBJECT_ID(N''' + @ObjName + N''', ''U'') IS NULL
BEGIN
    CREATE TABLE ' + @FullName + N'
    (
        [TicketID]             [bigint]         IDENTITY(1,1) NOT NULL,
        [tpUser_Id]            [bigint]         NULL,
        [ParentID]             [bigint]         NULL,
        [TicketNo]             [nvarchar](50)   NOT NULL,
        [RequesterMobileNo]    [nvarchar](50)   NULL,
        [RequesterEmailID]     [nvarchar](200)  NULL,
        [RequesterMobileNo1]   [nvarchar](50)   NULL,
        [RequesterEmailID1]    [nvarchar](200)  NULL,
        [RequesterMobileNo2]   [nvarchar](50)   NULL,
        [RequesterEmailID2]    [nvarchar](200)  NULL,
        [Subject]              [nvarchar](max)  NOT NULL,
        [Description]          [nvarchar](max)  NOT NULL,
        [TicketStatusID]       [bigint]         NOT NULL,
        [Remarks]              [nvarchar](max)  NULL,
        [Note]                 [nvarchar](max)  NULL,
        [UserResponse]         [nvarchar](max)  NULL,
        [TicketPriority]       [bigint]         NOT NULL,
        [AssignedUser]         [bigint]         NULL,
        [AssignedGroup]        [bigint]         NULL,
        [AssignedSource]       [nvarchar](100)  NOT NULL,
        [TicketCategoryId]     [bigint]         NOT NULL,
        [TicketTypeId]         [int]            NOT NULL,
        [TicketSourceId]       [bigint]         NOT NULL,
        [ProductId]            [bigint]         NULL,
        [IsMerged]             [bit]            NOT NULL,
        [IsSplitted]           [bit]            NOT NULL,
        [IsParentTicket]       [bit]            NOT NULL,
        [IsChildTicket]        [bit]            NOT NULL,
        [ParentTicketID]       [bigint]         NULL,
        [LastActionDatetime]   [datetime]       NOT NULL,
        [AssignedBy]           [bigint]         NULL,
        [AssignedDateTime]     [datetime]       NULL,
        [TicketTag]            [nvarchar](1000) NULL,
        [EntityID]             [bigint]         NULL,
        [EntityName]           [nvarchar](20)   NULL,
        [Company]              [nvarchar](400)  NULL,
        [IsActive]             [bit]            NOT NULL,
        [CreatedBy]            [bigint]         NOT NULL,
        [CreatedOn]            [datetime]       NOT NULL,
        [ModifiedBy]           [bigint]         NULL,
        [ModifiedOn]           [datetime]       NULL,
        [SplittedBy]           [bigint]         NULL,
        [SplittedOn]           [datetime]       NULL,
        [MergedBy]             [bigint]         NULL,
        [MergedOn]             [datetime]       NULL,
        [ClosedBy]             [bigint]         NULL,
        [ClosedOn]             [datetime]       NULL,
        [CreatedChildBy]       [bigint]         NULL,
        [CreatedChildOn]       [datetime]       NULL,
        [CountryCode]          [nvarchar](50)   NULL,
        [CountryCode1]         [nvarchar](50)   NULL,
        [CountryCode2]         [nvarchar](50)   NULL,
        CONSTRAINT ' + @PKName + N' PRIMARY KEY CLUSTERED ([TicketID])
    );
END;
';

    ---------------------------------------------------------------------------
    -- SEGMENT 2: Add SortDate computed column (if not exists)
    ---------------------------------------------------------------------------
    SET @sql += N'
-- Add persisted computed column for fast ORDER BY paging
IF COL_LENGTH(N''' + @ObjName + N''', ''SortDate'') IS NULL
BEGIN
    ALTER TABLE ' + @FullName + N'
    ADD SortDate AS (ISNULL([ModifiedOn], [CreatedOn])) PERSISTED;
END;
';

    ---------------------------------------------------------------------------
    -- SEGMENT 3: Index IX_TM_IsActive_SortDate (default paging index)
    ---------------------------------------------------------------------------
    SET @sql += N'
IF NOT EXISTS (
    SELECT 1
    FROM   sys.indexes
    WHERE  object_id = OBJECT_ID(N''' + @ObjName + N''')
      AND  [name]    = N''IX_TM_IsActive_SortDate''
)
BEGIN
    CREATE NONCLUSTERED INDEX IX_TM_IsActive_SortDate
    ON ' + @FullName + N' (IsActive, SortDate DESC, TicketID DESC)
    INCLUDE (
        ParentID, TicketStatusID, TicketPriority, TicketCategoryId, TicketTypeId,
        AssignedUser, AssignedGroup, Company, CreatedOn, ModifiedOn,
        AssignedDateTime, ClosedOn, EntityID, EntityName, tpUser_Id, TicketNo
    );
END;
';

    ---------------------------------------------------------------------------
    -- SEGMENT 4: Index IX_TM_AssignedUser_SortDate
    ---------------------------------------------------------------------------
    SET @sql += N'
IF NOT EXISTS (
    SELECT 1
    FROM   sys.indexes
    WHERE  object_id = OBJECT_ID(N''' + @ObjName + N''')
      AND  [name]    = N''IX_TM_AssignedUser_SortDate''
)
BEGIN
    CREATE NONCLUSTERED INDEX IX_TM_AssignedUser_SortDate
    ON ' + @FullName + N' (AssignedUser, IsActive, SortDate DESC, TicketID DESC)
    INCLUDE (
        ParentID, TicketStatusID, TicketPriority, TicketCategoryId, TicketTypeId,
        AssignedGroup, Company, CreatedOn, ModifiedOn,
        AssignedDateTime, ClosedOn, EntityID, EntityName, tpUser_Id, TicketNo
    );
END;
';

    ---------------------------------------------------------------------------
    -- SEGMENT 5: Index IX_TM_AssignedGroup_SortDate
    ---------------------------------------------------------------------------
    SET @sql += N'
IF NOT EXISTS (
    SELECT 1
    FROM   sys.indexes
    WHERE  object_id = OBJECT_ID(N''' + @ObjName + N''')
      AND  [name]    = N''IX_TM_AssignedGroup_SortDate''
)
BEGIN
    CREATE NONCLUSTERED INDEX IX_TM_AssignedGroup_SortDate
    ON ' + @FullName + N' (AssignedGroup, IsActive, SortDate DESC, TicketID DESC)
    INCLUDE (
        ParentID, TicketStatusID, TicketPriority, TicketCategoryId, TicketTypeId,
        AssignedUser, Company, CreatedOn, ModifiedOn,
        AssignedDateTime, ClosedOn, EntityID, EntityName, tpUser_Id, TicketNo
    );
END;
';

    ---------------------------------------------------------------------------
    -- Execute with full error visibility
    ---------------------------------------------------------------------------
    BEGIN TRY
        EXEC sys.sp_executesql @sql;
        RETURN 1;
    END TRY
    BEGIN CATCH
        -- SELECT instead of PRINT so the full SQL is visible (PRINT caps at 4000 chars)
        SELECT @sql AS DebugDynamicSQL;
        THROW;
    END CATCH

END



GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_CreateTicketMasterTableByParentID_JK_optmz]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE [dbo].[Usp_tp_CreateTicketMasterTableByParentID_JK_optmz]            
(            
  @ParentID bigint,          
  @TicketMasterTable nvarchar(max) output           
)            
  AS         
Begin 
    SET NOCOUNT ON;

    IF (ISNULL(@ParentID, 0) = 0)
    BEGIN
        SET @TicketMasterTable = NULL;
        RETURN 0;
    END

    DECLARE @BaseName  SYSNAME        = N'tbl_tp_TicketMaster_' + CONVERT(VARCHAR(20), @ParentID);
    DECLARE @ObjName   NVARCHAR(300)  = N'dbo.' + @BaseName;                              -- for OBJECT_ID()
    DECLARE @FullName  NVARCHAR(300)  = QUOTENAME(N'dbo') + N'.' + QUOTENAME(@BaseName);  -- for DDL
    DECLARE @PKName    NVARCHAR(200)  = QUOTENAME(N'PK_' + @BaseName);

    SET @TicketMasterTable = @BaseName;

       DECLARE @sql NVARCHAR(MAX) = N'';   

    
    --   Create table (if not exists)
    
    SET @sql += N'
IF OBJECT_ID(N''' + @ObjName + N''', ''U'') IS NULL
BEGIN
    CREATE TABLE ' + @FullName + N'
    (
        [TicketID]             [bigint]         IDENTITY(1,1) NOT NULL,
        [tpUser_Id]            [bigint]         NULL,
        [ParentID]             [bigint]         NULL,
        [TicketNo]             [nvarchar](50)   NOT NULL,
        [RequesterMobileNo]    [nvarchar](50)   NULL,
        [RequesterEmailID]     [nvarchar](200)  NULL,
        [RequesterMobileNo1]   [nvarchar](50)   NULL,
        [RequesterEmailID1]    [nvarchar](200)  NULL,
        [RequesterMobileNo2]   [nvarchar](50)   NULL,
        [RequesterEmailID2]    [nvarchar](200)  NULL,
        [Subject]              [nvarchar](max)  NOT NULL,
        [Description]          [nvarchar](max)  NOT NULL,
        [TicketStatusID]       [bigint]         NOT NULL,
        [Remarks]              [nvarchar](max)  NULL,
        [Note]                 [nvarchar](max)  NULL,
        [UserResponse]         [nvarchar](max)  NULL,
        [TicketPriority]       [bigint]         NOT NULL,
        [AssignedUser]         [bigint]         NULL,
        [AssignedGroup]        [bigint]         NULL,
        [AssignedSource]       [nvarchar](100)  NOT NULL,
        [TicketCategoryId]     [bigint]         NOT NULL,
        [TicketTypeId]         [int]            NOT NULL,
        [TicketSourceId]       [bigint]         NOT NULL,
        [ProductId]            [bigint]         NULL,
        [IsMerged]             [bit]            NOT NULL,
        [IsSplitted]           [bit]            NOT NULL,
        [IsParentTicket]       [bit]            NOT NULL,
        [IsChildTicket]        [bit]            NOT NULL,
        [ParentTicketID]       [bigint]         NULL,
        [LastActionDatetime]   [datetime]       NOT NULL,
        [AssignedBy]           [bigint]         NULL,
        [AssignedDateTime]     [datetime]       NULL,
        [TicketTag]            [nvarchar](1000) NULL,
        [EntityID]             [bigint]         NULL,
        [EntityName]           [nvarchar](20)   NULL,
        [Company]              [nvarchar](400)  NULL,
        [IsActive]             [bit]            NOT NULL,
        [CreatedBy]            [bigint]         NOT NULL,
        [CreatedOn]            [datetime]       NOT NULL,
        [ModifiedBy]           [bigint]         NULL,
        [ModifiedOn]           [datetime]       NULL,
        [SplittedBy]           [bigint]         NULL,
        [SplittedOn]           [datetime]       NULL,
        [MergedBy]             [bigint]         NULL,
        [MergedOn]             [datetime]       NULL,
        [ClosedBy]             [bigint]         NULL,
        [ClosedOn]             [datetime]       NULL,
        [CreatedChildBy]       [bigint]         NULL,
        [CreatedChildOn]       [datetime]       NULL,
        [CountryCode]          [nvarchar](50)   NULL,
        [CountryCode1]         [nvarchar](50)   NULL,
        [CountryCode2]         [nvarchar](50)   NULL,
        CONSTRAINT ' + @PKName + N' PRIMARY KEY CLUSTERED ([TicketID])
    );
END;
';


    SET @sql += N'
-- Add computed persisted computed column for fast ORDER BY paging
IF COL_LENGTH(N''' + @ObjName + N''', ''SortDate'') IS NULL
BEGIN
    ALTER TABLE ' + @FullName + N'
    ADD SortDate AS (ISNULL([ModifiedOn], [CreatedOn])) PERSISTED;
END;
';


    -- Index IX_TM_IsActive_SortDate (default paging index)
 
    SET @sql += N'
IF NOT EXISTS (
    SELECT 1
    FROM   sys.indexes
    WHERE  object_id = OBJECT_ID(N''' + @ObjName + N''')
      AND  [name]    = N''IX_TM_IsActive_SortDate''
)
BEGIN
    CREATE NONCLUSTERED INDEX IX_TM_IsActive_SortDate
    ON ' + @FullName + N' (IsActive, SortDate DESC, TicketID DESC)
    INCLUDE (
        ParentID, TicketStatusID, TicketPriority, TicketCategoryId, TicketTypeId,
        AssignedUser, AssignedGroup, Company, CreatedOn, ModifiedOn,
        AssignedDateTime, ClosedOn, EntityID, EntityName, tpUser_Id, TicketNo
    );
END;
';

    --  Index IX_TM_AssignedUser_SortDate

    SET @sql += N'
IF NOT EXISTS (
    SELECT 1
    FROM   sys.indexes
    WHERE  object_id = OBJECT_ID(N''' + @ObjName + N''')
      AND  [name]    = N''IX_TM_AssignedUser_SortDate''
)
BEGIN
    CREATE NONCLUSTERED INDEX IX_TM_AssignedUser_SortDate
    ON ' + @FullName + N' (AssignedUser, IsActive, SortDate DESC, TicketID DESC)
    INCLUDE (
        ParentID, TicketStatusID, TicketPriority, TicketCategoryId, TicketTypeId,
        AssignedGroup, Company, CreatedOn, ModifiedOn,
        AssignedDateTime, ClosedOn, EntityID, EntityName, tpUser_Id, TicketNo
    );
END;
';

    
    --  Index IX_TM_AssignedGroup_SortDate
    
    SET @sql += N'
IF NOT EXISTS (
    SELECT 1
    FROM   sys.indexes
    WHERE  object_id = OBJECT_ID(N''' + @ObjName + N''')
      AND  [name]    = N''IX_TM_AssignedGroup_SortDate''
)
BEGIN
    CREATE NONCLUSTERED INDEX IX_TM_AssignedGroup_SortDate
    ON ' + @FullName + N' (AssignedGroup, IsActive, SortDate DESC, TicketID DESC)
    INCLUDE (
        ParentID, TicketStatusID, TicketPriority, TicketCategoryId, TicketTypeId,
        AssignedUser, Company, CreatedOn, ModifiedOn,
        AssignedDateTime, ClosedOn, EntityID, EntityName, tpUser_Id, TicketNo
    );
END;
';

    
  
    
    BEGIN TRY
        EXEC sys.sp_executesql @sql;
        RETURN 1;
    END TRY
    BEGIN CATCH
        -- just for error catch to mayank/jk  if errors
        SELECT @sql AS DebugDynamicSQL;
        THROW;
    END CATCH

END




