/* ============================================================
   Procedure: [dbo].[Usp_tp_DeleteManageTicketById]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_DeleteManageTicketById]                              
(                              
@TicketIds NVARCHAR(MAX),                                                   
@ParentId BIGINT ,
@UserId BIGINT
)

AS  
BEGIN

  DECLARE @status INT 
  DECLARE @DynamicQuery NVARCHAR(MAX);
  DECLARE @TableName NVARCHAR(MAX) ;
  EXEC @status = Usp_tp_CreateTicketMasterTableByParentID @ParentID, @TableName OUTPUT  
  
SET @DynamicQuery = '
    UPDATE ' + @TableName + '
    SET IsActive = 0,
        ModifiedOn = GETDATE(),
        ModifiedBy = ' + CAST(@UserId AS NVARCHAR(MAX)) + '
    WHERE TicketID IN (' + @TicketIds + ');
    
    SELECT ''Tickets deleted successfully'' AS Result;
'; 




EXEC sp_executesql @DynamicQuery;
End  



