/* ============================================================
   Procedure: [dbo].[usp_tp_FilterAuthorforAutocomplete]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_tp_FilterAuthorforAutocomplete]  
(  
    @P_ID BIGINT,  
    @SearchText VARCHAR(100),  
    @FilterPattern VARCHAR(50), -- 'Name', 'CategoryName', 'AnotherFilter1', 'AnotherFilter2'  
    @SearchPattern VARCHAR(10) = 'Begin' -- 'End', 'Contain'  
)  
AS  
BEGIN 
--declare 
--     @P_ID BIGINT=32222,  
--    @SearchText VARCHAR(100)='c',  
--    @FilterPattern VARCHAR(50)='CategoryName', -- 'Name', 'CategoryName', 'AnotherFilter1', 'AnotherFilter2'  
--    @SearchPattern VARCHAR(10) = 'Begin' -- 'End', 'Contain'  

	   IF @SearchText = ''
    BEGIN
        -- Return an empty result set if @SearchText is blank
        SELECT NULL WHERE 1 = 0
        RETURN
    END

    IF (@FilterPattern = 'Name')  
    BEGIN  
        -- Your existing logic for 'Name' filter
        SELECT Author_Id AS Author_Id, ParentId, AuthorName AS Author_Name  
        FROM tbl_tp_Author  
        WHERE ParentID = @P_ID  AND IsActive=1
            AND (  
                ISNULL(AuthorName, '') LIKE + CASE @SearchPattern  
                    WHEN 'Begin' THEN @SearchText + '%'  
                    WHEN 'Contain' THEN '%' + @SearchText + '%'  
                    WHEN 'End' THEN '%' + @SearchText  
                    ELSE ''  
                END  
            )  
    END  
    ELSE IF (@FilterPattern = 'CategoryName')  
    BEGIN  
        WITH CategoryHierarchyCTE AS (
            SELECT
                ArticleCate_Id,
                ParentCategoryId,
                CategoryName,
                CAST(CategoryName AS NVARCHAR(MAX)) AS Sequencehierarchy,
                1 AS CategoryLevel
            FROM
                tbl_tp_ArticleCategory
            WHERE
                ParentCategoryId IS NULL 

            UNION ALL

            SELECT 
                c.ArticleCate_Id,
                c.ParentCategoryId,
                c.CategoryName,
                CAST(ch.Sequencehierarchy + '>' + c.CategoryName AS NVARCHAR(MAX)) AS Sequencehierarchy,
                ch.CategoryLevel + 1 AS CategoryLevel
            FROM
                tbl_tp_ArticleCategory c
            INNER JOIN
                CategoryHierarchyCTE ch ON c.ParentCategoryId = ch.ArticleCate_Id
        )

        SELECT  c.ArticleCate_Id AS CategoryId, c.ParentCategoryId,
		  CASE
            WHEN c.ParentCategoryId IS NULL THEN c.CategoryName
            ELSE ''
        END AS Category_Name,
               CASE
            WHEN c.ParentCategoryId IS NULL THEN ''
            ELSE ch.Sequencehierarchy
        END AS Sequencehierarchy,ch.CategoryLevel
        FROM CategoryHierarchyCTE ch
        JOIN tbl_tp_ArticleCategory c ON ch.ArticleCate_Id = c.ArticleCate_Id
        WHERE c.ParentID = @P_ID
            AND (
                ISNULL(c.CategoryName, '') LIKE + CASE @SearchPattern  
                    WHEN 'Begin' THEN @SearchText + '%'  
                    WHEN 'Contain' THEN '%' + @SearchText + '%'  
                    WHEN 'End' THEN '%' + @SearchText  
                    ELSE ''  
                END  
            )  
    END  
	  ELSE IF (@FilterPattern = 'ArticleCMS')  
 BEGIN  
        SELECT AM.ArticleTitle AS Articletitle,  AM.ParentId, AM.Article_ID AS ArticleId ,ATH.AuthorName, 
		'/Screen/WebsitePortal/ArticleDetail.aspx#' + CAST(AM.Article_ID AS NVARCHAR(50)) AS URL
        FROM tbl_tp_ArticleMaster(nolock) AM  inner join tbl_tp_Author(nolock) ATH 
		on AM.Author_id= ATH.Author_Id 
		
        WHERE AM.ParentID = @P_ID  and edit_status='Publish'
            AND ((  
                ISNULL(AM.ArticleTitle, '') LIKE + CASE @SearchPattern  
                    WHEN 'Begin' THEN @SearchText + '%'  
                    WHEN 'Contain' THEN '%' + @SearchText + '%'  
                    WHEN 'End' THEN '%' + @SearchText  
                    ELSE ''  
                END  
            ) 
			or(
			 ISNULL(ATH.AuthorName, '') LIKE + CASE @SearchPattern  
                    WHEN 'Begin' THEN @SearchText + '%'  
                    WHEN 'Contain' THEN '%' + @SearchText + '%'  
                    WHEN 'End' THEN '%' + @SearchText  
                    ELSE ''  
                END  
			))
    END  
		  ELSE IF (@FilterPattern = 'FaqCMS')  
 BEGIN  
         SELECT FM.FaqCategoryName AS FaqCategoryName,  FM.ParentId, FM.FaqCategoryId AS CategoryId ,FM.jsonqa
		
        FROM tbl_tp_TicketFaqCategory_Master(nolock) FM  
		       
			   WHERE FM.ParentID = @P_ID  and FM.IsActive=1
            AND ((  
                ISNULL(FM.FaqCategoryName, '') LIKE + CASE @SearchPattern  
                    WHEN 'Begin' THEN @SearchText + '%'  
                    WHEN 'Contain' THEN '%' + @SearchText + '%'  
                    WHEN 'End' THEN '%' + @SearchText  
                    ELSE ''  
                END  
            ) 
			or(
			 ISNULL(FM.jsonqa, '') LIKE + CASE @SearchPattern  
                    WHEN 'Begin' THEN @SearchText + '%'  
                    WHEN 'Contain' THEN '%' + @SearchText + '%'  
                    WHEN 'End' THEN '%' + @SearchText  
                    ELSE ''  
                END 
			))
    END  
    PRINT 'FilterPattern: ' + @FilterPattern

END





GO

/* ============================================================
   Procedure: [dbo].[usp_tp_FilterLeadAndEnquiryByNameEmailMobile]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_tp_FilterLeadAndEnquiryByNameEmailMobile]  
(  
    @UserType NVARCHAR(20),  
    @P_ID BIGINT,  
    @SearchText VARCHAR(100),  
    @FilterPattern VARCHAR(10) = 'Email', -- 'Name', 'Mobile'  
    @SearchPattern VARCHAR(10) = 'Begin', -- 'End', 'Contain'  
    @TpUserId BIGINT  -- New parameter for the current user's TpUserId
)  
AS  
BEGIN  
declare
--        @UserType NVARCHAR(20) = 'User',  
--        @P_ID BIGINT = 32222,  
--        @SearchText VARCHAR(100) = 'tes',  
--        @FilterPattern VARCHAR(10) = 'Email', -- 'Name','Mobile'  
--        @SearchPattern VARCHAR(10) = 'Begin', -- 'End','Contain'  
--		@TpUserId bigint=60,

     @User_ID BIGINT, @ParentID BIGINT, @MobileNumber NVARCHAR(50), @EmailID NVARCHAR(MAX), @EntityID BIGINT, @EntityName NVARCHAR(100),@CountryCode NVARCHAR(50), @Company NVARCHAR(100);

    -- Get current user information based on TpUser_Id
    SELECT @User_ID = User_ID, @ParentID = ParentId, @MobileNumber = Mobile, @EmailID = Email, 
           @EntityID = TpUser_Id, @EntityName = EntityName,@CountryCode=Country_Code,@Company=Company
    FROM tbl_tp_UserLogin (NOLOCK) 
    WHERE TpUser_Id = @TpUserId AND IsActive = 1;

    IF (@UserType = 'Lead')  
    BEGIN  
     
	 if(@P_ID=34594)
	 begin
        SELECT @EntityID AS ID, @Company AS CompanyName, @MobileNumber AS MobileNo, NULL AS MobileNo1, NULL AS MobileNo2, 
               @EmailID AS EmailID, NULL AS EmailID1, NULL AS EmailID2, @EntityName AS Entity, 
               strLead = ISNULL('ME', '') + ' | ' + ISNULL(@EmailID, '') + ', ' + ISNULL(@MobileNumber, ''), 
               @CountryCode AS CountryCode, NULL AS CountryCode1, NULL AS CountryCode2
			
        UNION ALL

 
        SELECT ID, CompanyName, MobileNo, MobileNo1, MobileNo2, EmailID, EmailID1, EmailID2, 'Lead' AS Entity,  
               strLead = ISNULL(PersonName, '') + ' | ' + ISNULL(EmailID, '') + ', ' + ISNULL(MobileNo, ''), 
               CountryCode, CountryCode1, CountryCode2
        FROM UserLeads(nolock)  
        WHERE ParentID = @P_ID  
            AND (  
                ISNULL(EmailID, '') LIKE CASE @SearchPattern  
                    WHEN 'Begin' THEN @SearchText + '%'  
                    WHEN 'Contain' THEN '%' + @SearchText + '%'  
                    WHEN 'End' THEN '%' + @SearchText  
                    ELSE ''  
                END  
                OR  
                ISNULL(EmailID1, '') LIKE CASE @SearchPattern  
                    WHEN 'Begin' THEN @SearchText + '%'  
                    WHEN 'Contain' THEN '%' + @SearchText + '%'  
                    WHEN 'End' THEN '%' + @SearchText  
                    ELSE ''  
                END  
                OR  
                ISNULL(EmailID2, '') LIKE CASE @SearchPattern  
                    WHEN 'Begin' THEN @SearchText + '%'  
                    WHEN 'Contain' THEN '%' + @SearchText + '%'  
                    WHEN 'End' THEN '%' + @SearchText  
                    ELSE ''  
                END  
                OR  
                ISNULL(PersonName, '') LIKE CASE @SearchPattern  
                    WHEN 'Begin' THEN @SearchText + '%'  
                    WHEN 'Contain' THEN '%' + @SearchText + '%'  
                    WHEN 'End' THEN '%' + @SearchText  
                    ELSE ''  
                END  
                OR  
                ISNULL(MobileNo, '') LIKE CASE @SearchPattern  
                    WHEN 'Begin' THEN @SearchText + '%'  
                    WHEN 'Contain' THEN '%' + @SearchText + '%'  
                    WHEN 'End' THEN '%' + @SearchText  
                    ELSE ''  
                END  
                OR  
                ISNULL(MobileNo1, '') LIKE CASE @SearchPattern  
                    WHEN 'Begin' THEN @SearchText + '%'  
                    WHEN 'Contain' THEN '%' + @SearchText + '%'  
                    WHEN 'End' THEN '%' + @SearchText  
                    ELSE ''  
                END  
                OR  
                ISNULL(MobileNo2, '') LIKE CASE @SearchPattern  
                    WHEN 'Begin' THEN @SearchText + '%'  
                    WHEN 'Contain' THEN '%' + @SearchText + '%'  
                    WHEN 'End' THEN '%' + @SearchText  
                    ELSE ''  
                END  
            ); 
	end
	else
	begin 
           SELECT ID, CompanyName, MobileNo, MobileNo1, MobileNo2, EmailID, EmailID1, EmailID2, 'Lead' AS Entity,  
               strLead = ISNULL(PersonName, '') + ' | ' + ISNULL(EmailID, '') + ', ' + ISNULL(MobileNo, ''), 
               CountryCode, CountryCode1, CountryCode2
        FROM UserLeads(nolock)  
        WHERE ParentID = @P_ID  
            AND (  
                ISNULL(EmailID, '') LIKE CASE @SearchPattern  
                    WHEN 'Begin' THEN @SearchText + '%'  
                    WHEN 'Contain' THEN '%' + @SearchText + '%'  
                    WHEN 'End' THEN '%' + @SearchText  
                    ELSE ''  
                END  
                OR  
                ISNULL(EmailID1, '') LIKE CASE @SearchPattern  
                    WHEN 'Begin' THEN @SearchText + '%'  
                    WHEN 'Contain' THEN '%' + @SearchText + '%'  
                    WHEN 'End' THEN '%' + @SearchText  
                    ELSE ''  
                END  
                OR  
                ISNULL(EmailID2, '') LIKE CASE @SearchPattern  
                    WHEN 'Begin' THEN @SearchText + '%'  
                    WHEN 'Contain' THEN '%' + @SearchText + '%'  
                    WHEN 'End' THEN '%' + @SearchText  
                    ELSE ''  
                END  
                OR  
                ISNULL(PersonName, '') LIKE CASE @SearchPattern  
                    WHEN 'Begin' THEN @SearchText + '%'  
                    WHEN 'Contain' THEN '%' + @SearchText + '%'  
                    WHEN 'End' THEN '%' + @SearchText  
                    ELSE ''  
                END  
                OR  
                ISNULL(MobileNo, '') LIKE CASE @SearchPattern  
                    WHEN 'Begin' THEN @SearchText + '%'  
                    WHEN 'Contain' THEN '%' + @SearchText + '%'  
                    WHEN 'End' THEN '%' + @SearchText  
                    ELSE ''  
                END  
                OR  
                ISNULL(MobileNo1, '') LIKE CASE @SearchPattern  
                    WHEN 'Begin' THEN @SearchText + '%'  
                    WHEN 'Contain' THEN '%' + @SearchText + '%'  
                    WHEN 'End' THEN '%' + @SearchText  
                    ELSE ''  
                END  
                OR  
                ISNULL(MobileNo2, '') LIKE CASE @SearchPattern  
                    WHEN 'Begin' THEN @SearchText + '%'  
                    WHEN 'Contain' THEN '%' + @SearchText + '%'  
                    WHEN 'End' THEN '%' + @SearchText  
                    ELSE ''  
                END  
            ); 
	end
    END  
    ELSE IF (@UserType = 'Enquiry')  
    BEGIN  
	   if(@P_ID=34594)
	   begin
        SELECT @EntityID AS ID, @Company AS CompanyName, @MobileNumber AS MobileNo, NULL AS MobileNo1, NULL AS MobileNo2, 
               @EmailID AS EmailID, NULL AS EmailID1, NULL AS EmailID2, @EntityName AS Entity, 
               strLead = ISNULL('ME', '') + ' | ' + ISNULL(@EmailID, '') + ', ' + ISNULL(@MobileNumber, ''), 
               NULL AS CountryCode, NULL AS CountryCode1, NULL AS CountryCode2
        UNION ALL
        SELECT EnquiryID AS ID, CompanyName, MobileNo, MobileNo1, MobileNo2, EmailID, EmailID1, EmailID2, 'Enquiry' AS Entity,  
               strLead = ISNULL(PersonName, '') + ' | ' + ISNULL(EmailID, '') + ', ' + ISNULL(MobileNo, ''), 
               CountryCode, CountryCode1, CountryCode2
        FROM UserEnquiry(nolock)  
        WHERE ParentID = @P_ID  
            AND (  
                ISNULL(EmailID, '') LIKE CASE @SearchPattern  
                    WHEN 'Begin' THEN @SearchText + '%'  
                    WHEN 'Contain' THEN '%' + @SearchText + '%'  
                    WHEN 'End' THEN '%' + @SearchText  
                    ELSE ''  
                END  
                OR  
                ISNULL(EmailID1, '') LIKE CASE @SearchPattern  
                    WHEN 'Begin' THEN @SearchText + '%'  
                    WHEN 'Contain' THEN '%' + @SearchText + '%'  
                    WHEN 'End' THEN '%' + @SearchText  
                    ELSE ''  
                END  
                OR  
                ISNULL(EmailID2, '') LIKE CASE @SearchPattern  
                    WHEN 'Begin' THEN @SearchText + '%'  
                    WHEN 'Contain' THEN '%' + @SearchText + '%'  
                    WHEN 'End' THEN '%' + @SearchText  
                    ELSE ''  
                END  
                OR  
                ISNULL(PersonName, '') LIKE CASE @SearchPattern  
                    WHEN 'Begin' THEN @SearchText + '%'  
                    WHEN 'Contain' THEN '%' + @SearchText + '%'  
                    WHEN 'End' THEN '%' + @SearchText  
                    ELSE ''  
                END  
                OR  
                ISNULL(MobileNo, '') LIKE CASE @SearchPattern  
                    WHEN 'Begin' THEN @SearchText + '%'  
                    WHEN 'Contain' THEN '%' + @SearchText + '%'  
                    WHEN 'End' THEN '%' + @SearchText  
                    ELSE ''  
                END  
                OR  
                ISNULL(MobileNo1, '') LIKE CASE @SearchPattern  
                    WHEN 'Begin' THEN @SearchText + '%'  
                    WHEN 'Contain' THEN '%' + @SearchText + '%'  
                    WHEN 'End' THEN '%' + @SearchText  
                    ELSE ''  
                END  
                OR  
