                    WHEN 'Begin' THEN @SearchText + '%'  
                    WHEN 'Contain' THEN '%' + @SearchText + '%'  
                    WHEN 'End' THEN '%' + @SearchText  
                    ELSE ''  
                END  
            ); 
	   end
	   else
	   begin
        SELECT EnquiryID AS ID, CompanyName, MobileNo, MobileNo1, MobileNo2, EmailID, EmailID1, EmailID2, 'Enquiry' AS Entity,  
               strLead = ISNULL(PersonName, '') + ' | ' + ISNULL(EmailID, '') + ', ' + ISNULL(MobileNo, ''), 
