                    WHEN 'Begin' THEN @SearchText + '%'  
                    WHEN 'Contain' THEN '%' + @SearchText + '%'  
                    WHEN 'End' THEN '%' + @SearchText  
                    ELSE ''  
                END  
                OR  
                ISNULL(MobileNo, '') LIKE CASE @SearchPattern  
                    WHEN 'Begin' THEN @SearchText + '%'  
                    WHEN 'Contain' THEN '%' + @SearchText + '%'  
                    WHEN 'End' THEN '%' + @SearchText  
                    ELSE ''  
                END  
                OR  
