        UNION ALL
        SELECT User_Id AS ID, Company as CompanyName, Mobile as MobileNo,'' as MobileNo1, '' as MobileNo2, Email as EmailID,'' as EmailID1, '' as EmailID2, 'User' AS Entity,  
               strLead = ISNULL( LoginName, '') + ' | ' + ISNULL(Email, '') + ', ' + ISNULL(Mobile, ''), 
              Country_Code as CountryCode, '' as CountryCode1, '' as CountryCode2
        FROM tbl_tp_UserLogin(nolock)  
        WHERE ParentID = @P_ID  
            AND (  
                ISNULL(Email, '') LIKE CASE @SearchPattern  
                    WHEN 'Begin' THEN @SearchText + '%'  
                    WHEN 'Contain' THEN '%' + @SearchText + '%'  
                    WHEN 'End' THEN '%' + @SearchText  
