/* ============================================================
   Procedure: [dbo].[usp_tp_FilterTicketNumber]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_tp_FilterTicketNumber]      
(       
    @ParentID BIGINT,      
    @SearchText NVARCHAR(max),
    @Mode NVARCHAR(500)  
)      
AS      
BEGIN
    DECLARE @DynamicSQL NVARCHAR(MAX), 
            @status INT, 
            @tableName NVARCHAR(MAX),
			@UserIds NVARCHAR(MAX),
            @GroupIds NVARCHAR(MAX),
            @SearchTextList NVARCHAR(MAX)
			 --  @ParentID BIGINT = 34594,      
    --@SearchText NVARCHAR(100) = 'kmuke',
    --@Mode NVARCHAR(50) = 'Assignto' 

    -- Create ticket master table for the parent ID
    EXEC @status = Usp_tp_CreateTicketMasterTableByParentID @ParentID, @tableName OUTPUT;  

    IF @SearchText = ''
    BEGIN
        RETURN;
    END

    IF @Mode IN ('Subject', 'Lead/Enquiry', 'ID', 'GetTickets')
    BEGIN
        SET @DynamicSQL = N'  
            SELECT  
               TicketID, TicketNo, Subject,EntityName, EntityID, Description, TicketStatusID, TicketPriority, AssignedGroup, AssignedUser, RequesterEmailID, CreatedOn, ModifiedOn
            FROM ' + @tableName + ' (NOLOCK)  
            WHERE 1 = 1'; 

        IF @Mode = 'Subject'
        BEGIN
            SET @DynamicSQL += ' AND Subject LIKE @SearchText + ''%'' ';
        END
        ELSE IF @Mode = 'Lead/Enquiry'
        BEGIN
            SET @DynamicSQL += ' AND (RequesterMobileNo1 LIKE @SearchText + ''%'' 
                                   OR RequesterMobileNo LIKE @SearchText + ''%'' 
                                   OR RequesterMobileNo2 LIKE @SearchText + ''%'' 
                                   OR RequesterEmailID LIKE @SearchText + ''%'' 
                                   OR RequesterEmailID1 LIKE @SearchText + ''%'' 
                                   OR RequesterEmailID2 LIKE @SearchText + ''%'' 
                                   OR Description LIKE @SearchText + ''%'' 
                                   OR TicketNo LIKE @SearchText + ''%'') ';
        END
        ELSE IF @Mode = 'ID'
        BEGIN
            SET @DynamicSQL += ' AND TicketID LIKE @SearchText + ''%'' ';
        END
        ELSE IF @Mode = 'GetTickets'
        BEGIN
            SET @SearchTextList = '(' + @SearchText + ')';
            SET @DynamicSQL += ' AND TicketID IN ' + @SearchTextList;
        END

        EXEC sp_executesql @DynamicSQL, N'@SearchText NVARCHAR(200)', @SearchText;
    END

    -- Separate section for User Logo
    IF @Mode = 'GetLogo'
    BEGIN
	DECLARE @SubDomain NVARCHAR(200);
	print @SubDomain
            SET @SubDomain = SUBSTRING(@SearchText, LEN(@SearchText) - CHARINDEX('/', REVERSE(@SearchText)) + 2, LEN(@SearchText));
            DECLARE @FullPortalName NVARCHAR(MAX) = @SearchText + @SubDomain;

                SELECT TOP 1 @ParentId = ParentId
                FROM tbl_tp_Portalsetting WITH (NOLOCK)
                WHERE @SubDomain = PortalName and IsActive=1;
				print @ParentId


        SELECT LogoPath1, LogoPath2 
        FROM tbl_tp_PortalSetting 
        WHERE ParentId = @ParentID 
        AND IsActive = 1 
        AND IsEnabled = 1;
    END

	IF @Mode IN ('All', 'GlobalSubject', 'GlobalContact', 'GlobalTicketNo', 'Assignto','RecentViews')
BEGIN
    SET @DynamicSQL = N'  
        SELECT  
           TicketID, TicketNo,EntityName, Subject, EntityID, Description, TicketStatusID, TicketPriority, AssignedGroup, AssignedUser, RequesterEmailID, CreatedOn, ModifiedOn
        FROM ' + @tableName + ' (NOLOCK)  
        WHERE 1 = 1'; 

    -- Search across all fields for 'All' mode
    IF @Mode = 'All'
    BEGIN
        SET @DynamicSQL += ' AND (Subject LIKE @SearchText + ''%'' 
                                OR Description LIKE @SearchText + ''%'' 
                                OR TicketNo LIKE @SearchText + ''%'' 
                                OR RequesterMobileNo1 LIKE @SearchText + ''%'' 
                                OR RequesterMobileNo LIKE @SearchText + ''%'' 
                                OR RequesterMobileNo2 LIKE @SearchText + ''%'' 
                                OR RequesterEmailID LIKE @SearchText + ''%'' 
							    OR RequesterEmailID1 LIKE @SearchText + ''%'' 
							    OR RequesterEmailID2 LIKE @SearchText + ''%'' 
                                OR AssignedGroup LIKE @SearchText + ''%'' 
                                OR AssignedUser LIKE @SearchText + ''%'' ) ';
    END

    -- Global search based on subject
    ELSE IF @Mode = 'GlobalSubject'
    BEGIN
        SET @DynamicSQL += ' AND Subject LIKE @SearchText + ''%'' ';
    END

    -- Global search based on contact details (phone/email)
    ELSE IF @Mode = 'GlobalContact'
    BEGIN
        SET @DynamicSQL += ' AND (RequesterMobileNo1 LIKE @SearchText + ''%'' 
                               OR RequesterMobileNo LIKE @SearchText + ''%'' 
                               OR RequesterMobileNo2 LIKE @SearchText + ''%'' 
                               OR RequesterEmailID LIKE @SearchText + ''%'' 
							   OR RequesterEmailID1 LIKE @SearchText + ''%'' 
							   OR RequesterEmailID2 LIKE @SearchText + ''%'' 
                              ) ';
    END

    -- Global search based on Ticket No
    ELSE IF @Mode = 'GlobalTicketNo'
    BEGIN
        SET @DynamicSQL += ' AND TicketNo LIKE @SearchText + ''%'' ';
    END

    -- Search based on Assigned Group or Assigned User
   IF @Mode = 'Assignto'
    BEGIN
        -- Get matching UserIds from tbl_tp_UserLogin based on Name or LoginName
        SELECT @UserIds = STRING_AGG(CAST(TpUser_Id AS NVARCHAR), ',') 
        FROM tbl_tp_UserLogin 
        WHERE Name LIKE '%' + @SearchText + '%' OR LoginName LIKE '%' + @SearchText + '%';

        -- Get matching GroupIds from tbl_tp_GroupMaster based on GroupName
        SELECT @GroupIds = STRING_AGG(CAST(GroupId AS NVARCHAR), ',') 
        FROM tbl_tp_GroupMaster 
        WHERE GroupName LIKE '%' + @SearchText + '%';

        -- Add conditions for AssignedUser and AssignedGroup if there are matching results
        IF @UserIds IS NOT NULL AND LEN(@UserIds) > 0
        BEGIN
            SET @DynamicSQL += ' AND AssignedUser IN (' + @UserIds + ') ';
        END

        IF @GroupIds IS NOT NULL AND LEN(@GroupIds) > 0
        BEGIN
            SET @DynamicSQL += ' AND AssignedGroup IN (' + @GroupIds + ') ';
        END
    END


    -- Execute the dynamic SQL with parameterized input
    EXEC sp_executesql @DynamicSQL, N'@SearchText NVARCHAR(200)', @SearchText;
END


END









GO

/* ============================================================
   Procedure: [dbo].[usp_tp_GetActiveTicketCustomFields]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_tp_GetActiveTicketCustomFields]
 @TicketID BIGINT,
 @TpUserId BIGINT
AS
DECLARE 
    --@TicketID BIGINT = 148,
    --@TpUserId BIGINT = 90,
    @TimeZone NVARCHAR(400),
    @rowJson NVARCHAR(MAX),
    @IPAdress NVARCHAR(50),
    @ParentId BIGINT,
    @UserID BIGINT,   
    @DeviceId NVARCHAR(50),
    @IsImpersonation BIT,
    @ImpersonatorId INT,   
    @ProductTableName NVARCHAR(100),
    @DynamicColumns NVARCHAR(MAX) = '', 
    @IsAdmin BIT = 0,   
    @DynamicSQL NVARCHAR(MAX);  

-- Retrieve user details
SELECT 
    @UserID = User_Id,
    @ParentId = ParentId,
    @TimeZone = ISNULL(TimeZone, 'India Standard Time'),   
    @IsAdmin = CASE WHEN User_Id = ParentId THEN 1 ELSE 0 END
FROM 
    tbl_tp_UserLogin (NOLOCK)   
WHERE 
    TpUser_Id = @TpUserId 
    AND IsActive = 1;

BEGIN
    SET NOCOUNT ON;

    DECLARE @ActiveFields NVARCHAR(MAX) = '';

    -- Step 1: Get the list of active custom fields
    SELECT @ActiveFields = STRING_AGG(FieldName, ', ')
    FROM (
        SELECT 
            JSON_VALUE(value, '$.FieldName') AS FieldName
        FROM 
            OPENJSON((SELECT top 1 DisplayJson FROM tbL_tp_TicketCustomFieldDisplayJson WHERE ParentId = @ParentId))
        WHERE 
            JSON_VALUE(value, '$.Active') = 'true'
    ) AS ActiveFields;

    -- Check if there are active fields
    IF @ActiveFields IS NULL OR @ActiveFields = ''
 BEGIN
        SELECT 
            '' AS CustomField

    END

    -- Step 2: Construct the dynamic SQL query to select these fields and convert to JSON
    SET @DynamicSQL = '
    SELECT 
        (
            SELECT ' + @ActiveFields + '
            FOR JSON PATH, WITHOUT_ARRAY_WRAPPER
        ) AS CustomField
    FROM 
        tbl_tp_TicketMaster_' + CAST(@ParentId AS NVARCHAR(50)) + '
    WHERE 
        TicketID = @TicketID';

    -- Step 3: Execute the dynamic SQL
    EXEC sp_executesql @DynamicSQL, N'@TicketID BIGINT', @TicketID;
END



