-- exec Usp_tp_GetAgentRaisedTicketDetails @TpUserId=90,@CategoryId=0,@ProductId=0,@CreatedInterval=0,@ClosedInterval=0,@Type=0,@MetaData=N'{"IPAddress":"::1","MacAddress":"00FF61AD0C56","IsImpersonation":false,"ImpersonatorId":0}'  
-- exec Usp_tp_GetAgentRaisedTicketDetails @TpUserId=90,@CategoryId=0,@ProductId=0,@CreatedInterval=0,@ClosedInterval=0,@Type=0,@SqlWhere=N'dbo.ufn_tp_GetParentTicketStatus(TicketStatusID)=1',@MetaData=N'{"IPAddress":"::1","MacAddress":"00FF61AD0C56","IsImpersonation":false,"ImpersonatorId":0}' 
-- exec Usp_tp_GetAgentRaisedTicketDetails @TpUserId=1,@CategoryId=0,@ProductId=0,@CreatedInterval=0,@ClosedInterval=0,@Type=0,@MetaData=N'{"IPAddress":"::1","MacAddress":"00FF61AD0C56","IsImpersonation":false,"ImpersonatorId":0}'  
-- exec Usp_tp_GetAgentRaisedTicketDetails @TpUserId=1,@CategoryId=0,@Pageno=1,@Pagesize=20,@ProductId=0,@CreatedInterval=0,@ClosedInterval=0,@Type=0,@SqlWhere=N'', @MetaData=N'{"IPAddress":"::1","MacAddress":"00FF61AD0C56","IsImpersonation":false,"ImpersonatorId":0}'  
CREATE   PROCEDURE [dbo].[Usp_tp_GetAgentRaisedTicketDetails]
(
 @TpUserId BIGINT,  
 @CategoryId BIGINT,  
 @ProductId BIGINT,  
 @Type BIGINT,  
 @CreatedInterval BIGINT,  
 @ClosedInterval BIGINT,
 @Pageno NVARCHAR(100) = NULL,
 @Pagesize NVARCHAR(100) = NULL,
 @SqlWhere nvarchar(max) = NULL,  
 @MetaData NVARCHAR(200)  
)
AS                
BEGIN  

BEGIN TRY
	DECLARE @ParentID BIGINT, @TimeZone NVARCHAR(400), @UserID BIGINT, @rowJson NVARCHAR(MAX),   
    @IPAdress NVARCHAR(50), @DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT,  
    @EntityId BIGINT=0, @EntityName nvarchar(20)='' , @offset INT = ISNULL(NULLIF(@Pagesize, ''), 20);
                        
    IF (@CategoryId = 0)  
        SET @CategoryId = NULL                
                            
    IF (@ProductId = 0)  
        SET @ProductId = NULL                
                            
    IF (@Type = 0)  
        SET @Type = NULL                
                        
    IF (@CreatedInterval = 0)  
        SET @CreatedInterval = NULL                
                        
    IF (@ClosedInterval = 0)  
        SET @ClosedInterval = NULL                
                        
	If (concat(@SqlWhere,'')='')
	Begin
		SET @SqlWhere=N' and 1=1 '
	End
	Else
	Begin
		SET @SqlWhere=' and ' + @SqlWhere
	End
  
	Exec usp_tp_CreateEntityForLogin @TpUserId  
  
    Select @TimeZone = isnull(TimeZone,'India Standard Time'), @ParentID = ParentId, @UserID = User_Id,  
    @EntityId=EntityId, @EntityName=EntityName  
	From tbl_tp_UserLogin (noLock)   
	Where TpUser_Id = @TpUserId  AND IsActive = 1  
                        
	DECLARE @TimeAgoCreated DATETIME = DATEADD(MINUTE, -@CreatedInterval, GETDATE());
	DECLARE @TimeAgoClosed DATETIME = DATEADD(MINUTE, -@ClosedInterval, GETDATE());

	DECLARE @DynamicSQL NVARCHAR(MAX)
	DECLARE @sqls NVARCHAR(MAX) = ''
	DECLARE @status INT
	DECLARE @tableName NVARCHAR(MAX) = ''

	EXEC @status = Usp_tp_CreateTicketMasterTableByParentID @ParentID, @tableName OUTPUT
                        
	SET @DynamicSQL = N'
	WITH AggregatedAttachments AS (
	SELECT
	TicketID,
	(COUNT(TicketAttachmentID) - 1) AS TotalAttachments,
	STRING_AGG(ISNULL(TAM.TicketAttachmentID, ''No Attachment Available''), '', '') AS TicketAttachmentID,
	STRING_AGG(ISNULL(TAM.DisplayName, ''No Attachment Available''), '', '') AS AggregatedDisplayNames,
	STRING_AGG(ISNULL(TAM.FileUrl, ''''), '', '') AS AggregatedFileUrls,
	MIN(ISNULL(TAM.DisplayName, ''No Attachment Available'')) AS SingleDisplayName,
	MIN(ISNULL(TAM.FileUrl, '''')) AS SingleFileUrl
	FROM tbl_tp_TicketAttachment TAM (NOLOCK)
	WHERE TAM.IsActive = 1 and TAM.ParentId=@ParentID
	GROUP BY TicketID
	)

select * from ( 
		SELECT ROW_NUMBER()over(order by isnull(TM.ModifiedOn,TM.CreatedOn) desc) RecNo,count(*)over(order by TM.ParentID) TotalCount,TM.TicketID,
	TM.tpUser_Id,
	TUL.Name,
	TUL.Company as UserCompany,
	TM.ParentId,
	TicketNo,
	TM.EntityID,
	TM.EntityName,
	RequesterMobileNo,
	RequesterEmailID,
	TM.Company,
	Subject,
	TM.Description,
	TM.TicketStatusID,
	TSM.TicketStatus,
	TM.TicketPriority,
	TPM.PriorityName,
	TPMS.Name As ProductName,
	TUL.Name AS AssignedUser,
	TM.TicketSourceId,
	TSOM.TicketSourceName,
	TicketTypeId as TypeId,
	dbo.fn_ConvertDateTime(TM.CreatedOn, @TimeZone, ''0'') as CreatedOn,
	TM.IsActive,
	TM.ProductId,
	TM.TicketCategoryId,
	TM.TicketTypeId as TicketType,
	IsParentTicket,
	ISNULL(th.UserResponse, th.Remarks) AS LastRemark,
	(th.RemarkType) AS RemarkType,
    ISNULL(th.AssignedBy, 0) AS RemarkBy,
	ISNULL(AA.AggregatedDisplayNames, ''No Attachment Available'') DisplayName,
	ISNULL(AA.AggregatedFileUrls, '''') FileUrl,
	ISNULL(AA.SingleDisplayName, ''No Attachment Available'') SingleAttachmentDisplayName,
	AA.SingleFileUrl AS SingleAttachmentFileUrl,
	AA.AggregatedDisplayNames,
	AA.AggregatedFileUrls,
	AA.TicketAttachmentID,
	AA.TotalAttachments,
	(SELECT COUNT(TicketID) FROM ' + @tableName + ') as TicketTotalCount,
	(SELECT STRING_AGG(Tag, '', '') FROM TagMaster WHERE ID IN (SELECT value FROM STRING_SPLIT(TM.TicketTag, '',''))) AS Tags
	FROM ' + @tableName + ' TM (NOLOCK)
	INNER JOIN tbl_tp_UserLogin TUL (NOLOCK) ON TUL.TpUser_Id = TM.CreatedBy AND TUL.IsActive = 1
	LEFT JOIN tbl_tp_TicketStatusMaster TSM (NOLOCK) ON TM.TicketStatusID = TSM.TicketStatus_ID AND TSM.IsActive = 1
	LEFT JOIN tbl_tp_TicketPriorityMaster TPM (NOLOCK) ON TM.TicketPriority = TPM.Priority_ID AND TPM.Active = 1
	LEFT JOIN ' + QUOTENAME('tbl_productmaster_' + CAST(@ParentId AS NVARCHAR(MAX))) + ' TPMS ON TM.ProductId = TPMS.ProductID AND TPMS.IsActive = 1
	LEFT JOIN tbl_tp_TicketSourceMaster TSOM (NOLOCK) ON TM.TicketSourceId = TSOM.TicketSourceId AND TSOM.IsActive = 1
	LEFT JOIN (Select  TicketID, ParentID, UserResponse, Remarks, AssignedBy, RemarkType
	From
	(    
		select Row_number()over(partition by ParentID,TicketID order by TicketHistoryID desc) as Sno,RemarkType=iif(Remarks is not null,''A'',''C''),*     
		from tbl_tp_TicketHistory(nolock)  where Remarks is not null  or UserResponse is not null
	)T 
	Where T.Sno=1 ) th on TM.TicketID = th.TicketID and th.ParentID=TM.ParentID
	LEFT JOIN (
	SELECT Distinct TTP.TicketID
	FROM tbl_tp_TicketProducts (NOLOCK) TTP WHERE TTP.IsActive = 1 AND (@ProductId IS NULL OR TTP.ProductID = @ProductId)
	) TP ON TP.TicketID = TM.TicketID
	LEFT JOIN AggregatedAttachments AA ON TM.TicketID = AA.TicketID
	WHERE TM.IsActive = 1 AND
	(TM.CreatedBy = @TpUserId or (TM.EntityId=@EntityId and TM.EntityName=@EntityName))
	AND (@CategoryId IS NULL OR TM.TicketCategoryId = @CategoryId)
	AND (@ProductId IS NULL OR TM.ProductId = @ProductId)
	AND (@Type IS NULL OR TM.TicketTypeId = @Type) ' + @SqlWhere + '
	AND (@CreatedInterval IS NULL OR TM.CreatedOn >= DATEADD(MINUTE, -@CreatedInterval, GETDATE()))
	AND (
	@ClosedInterval IS NULL OR
	(TM.CreatedOn >= DATEADD(MINUTE, -@ClosedInterval, GETDATE()) AND TM.TicketStatusID = 3)
	)) as tbl  where  RecNo between '  + CONVERT(NVARCHAR(max),(@Pageno - 1)*@offset + 1 ) + N' AND ' + CONVERT(NVARCHAR(max), @offset * @Pageno)  
		 + ' ORDER BY Tbl.TicketID DESC '

	PRINT CAST(@DynamicSQL AS VARCHAR(MAX) )
   
    EXEC sp_executesql @DynamicSQL,                
    N'@ParentID BIGINT, @CategoryId BIGINT, @ProductId BIGINT, @Type BIGINT, @CreatedInterval BIGINT, @ClosedInterval BIGINT , @TimeZone NVARCHAR(400), @TpUserId  BIGINT, @EntityId bigint, @EntityName nvarchar(20)',  
    @ParentID, @CategoryId, @ProductId, @Type, @CreatedInterval, @ClosedInterval, @TimeZone, @TpUserId, @EntityId, @EntityName  
                
                
	EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData @User_id = @ParentID     
            ,@Activity_type = 'View_agentraisedmaster'                                          
            ,@ActionType = 'S'                                          
            ,@RowJson = 'NULL'                                          
            ,@Table_name = @tableName  ,@ip_adress = @IPAdress ,@device_id = @DeviceId,@IsImpersonation = @IsImpersonation,@ImpersonatorId = @ImpersonatorId                 
END TRY
BEGIN CATCH
	PRINT 'Error occurred: ' + ERROR_MESSAGE()
END CATCH

END   



GO

