CREATE   PROCEDURE [dbo].[Usp_tp_GetAgentRaisedTicketDetails_temp] --32222,0,0,0,0,0,'{}'
(
    @UserID INT,
    @CategoryId INT,
    @ProductId INT,
    @Type INT,
    @CreatedInterval INT,
    @ClosedInterval INT,
    @MetaData NVARCHAR(200)
)
AS
BEGIN
    BEGIN TRY
           DECLARE @ParentID Bigint, @TimeZone nvarchar(400), @rowJson NVARCHAR(MAX), @IPAdress NVARCHAR(50),        
                @DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT        
        
                IF (@CategoryId = 0)        
                    SET @CategoryId = NULL        
                  
                IF (@ProductId = 0)        
                    SET @ProductId = NULL        
                  
                IF (@Type = 0)        
                   SET @Type = NULL        
        
               IF (@CreatedInterval = 0)        
                   SET  @CreatedInterval = NULL          
        
               IF (@ClosedInterval = 0)        
                   SET  @ClosedInterval = NULL      
         
       Select @TimeZone = TimeZone  From tbl_tp_UserLogin (noLock) Where User_Id = @UserID  

        -- Calculate time intervals
        DECLARE @TimeAgoCreated DATETIME = DATEADD(MINUTE, -@CreatedInterval, GETDATE());
        DECLARE @TimeAgoClosed DATETIME = DATEADD(MINUTE, -@ClosedInterval, GETDATE());

        -- Dynamic table name
        DECLARE @DynamicTableName NVARCHAR(100) = 'tbl_tp_TicketMaster_' + CAST(@ParentID AS NVARCHAR(20));
		DECLARE @SQL NVARCHAR(MAX);
        -- Dynamic SQL query
        SET @SQL = N'
            WITH AggregatedAttachments AS (
                SELECT
                    TicketID, (COUNT(TicketAttachmentID) - 1) AS TotalAttachments,
                    STRING_AGG(ISNULL(TAM.TicketAttachmentID, ''No Attachment Available''), '', '') AS TicketAttachmentID,
                    STRING_AGG(ISNULL(TAM.DisplayName, ''No Attachment Available''), '', '') AS AggregatedDisplayNames,
                    STRING_AGG(ISNULL(TAM.FileUrl, ''''), '', '') AS AggregatedFileUrls,
                    MIN(ISNULL(TAM.DisplayName, ''No Attachment Available'')) AS SingleDisplayName,
                    MIN(ISNULL(TAM.FileUrl, '''')) AS SingleFileUrl
                FROM tbl_tp_TicketAttachment TAM (NOLOCK)
                WHERE TAM.IsActive = 1
                GROUP BY TicketID
            )

			Select * from AggregatedAttachments

            SELECT
                TM.TicketID, TM.tpUser_Id, TM.ParentId, TicketNo, TM.EntityID, TM.EntityName,
                RequesterMobileNo, RequesterEmailID, Subject, Description, TM.TicketStatusID, TSM.TicketStatus,
                TM.TicketPriority, TPM.PriorityName, TUL.Name AS AssignedUser, TM.TicketSourceId,
                TSOM.TicketSourceName, TicketTypeId, dbo.fn_ConvertDateTime(TM.CreatedOn, @TimeZone, 0) as CreatedOn,
                TM.IsActive, TM.ProductId, TM.TicketCategoryId, TM.TicketTypeId,
                ISNULL(AA.AggregatedDisplayNames, ''No Attachment Available'') AS DisplayName,
                ISNULL(AA.AggregatedFileUrls, '''') AS FileUrl, AA.SingleDisplayName AS SingleAttachmentDisplayName,
                AA.SingleFileUrl AS SingleAttachmentFileUrl, AA.AggregatedDisplayNames, AA.AggregatedFileUrls,
                AA.TicketAttachmentID, AA.TotalAttachments,
                (
                    SELECT COUNT(TicketID) FROM ' + QUOTENAME(@DynamicTableName) + '
                ) AS TotalCount,
                (
                    SELECT STRING_AGG(Tag, '', '') FROM TagMaster
                    WHERE ID IN (SELECT value FROM STRING_SPLIT(TM.TicketTag, ''''))
                ) AS Tags
            FROM ' + QUOTENAME(@DynamicTableName) + ' TM (NOLOCK)
            INNER JOIN tbl_tp_UserLogin TUL (NOLOCK) ON TUL.ParentId = TM.AssignedUser AND TUL.IsActive = 1
            LEFT JOIN tbl_tp_TicketStatusMaster TSM (NOLOCK) ON TM.TicketStatusID = TSM.TicketStatus_ID AND TSM.IsActive = 1
            LEFT JOIN tbl_tp_TicketPriorityMaster TPM (NOLOCK) ON TM.TicketPriority = TPM.Priority_ID AND TPM.Active = 1
            LEFT JOIN tbl_tp_TicketSourceMaster TSOM (NOLOCK) ON TM.TicketSourceId = TSOM.TicketSourceId AND TSOM.IsActive = 1
            LEFT JOIN AggregatedAttachments AA ON TM.TicketID = AA.TicketID
            WHERE
                (TM.ParentId = @ParentID OR @ParentID IS NULL)
                AND (TM.TicketCategoryId = @CategoryId OR @CategoryId IS NULL)
                AND (TM.ProductId = @ProductId OR @ProductId IS NULL)
                AND (TM.TicketTypeId = @Type OR @Type IS NULL)
                AND (@TimeAgoCreated IS NULL OR TM.CreatedOn >= @TimeAgoCreated)
                AND (@TimeAgoClosed IS NULL OR (TM.CreatedOn >= @TimeAgoClosed AND TicketStatusID = 3))
        ';

        -- Print the dynamic SQL for debugging
        PRINT @SQL;
		EXEC sp_executesql @SQL
        -- Execute the dynamic SQL query
        EXEC sp_executesql @SQL,
            N'@ParentID INT, @CategoryId INT, @ProductId INT, @Type INT, @TimeAgoCreated DATETIME, @TimeAgoClosed DATETIME, @TimeZone NVARCHAR(400)',
            @ParentID, @CategoryId, @ProductId, @Type, @TimeAgoCreated, @TimeAgoClosed, @TimeZone;

        -- Execute audit
        --EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData
        --    @User_id = @UserID,
        --    @Activity_type = 'View_agentraisedmaster',
        --    @ActionType = 'S',
        --    @RowJson = 'NULL',
        --    @Table_name = @DynamicTableName,
        --    @ip_adress = @IPAdress,
        --    @device_id = @DeviceId,
        --    @IsImpersonation = @IsImpersonation,
        --    @ImpersonatorId = @ImpersonatorId;

    END TRY
    BEGIN CATCH
        PRINT 'Error occurred: ' + ERROR_MESSAGE();
    END CATCH
END



