CREATE   PROCEDURE [dbo].[Usp_tp_GetAgentRaisedTicketDetails111]  --32222,0,0,0,0,0,'{}'     
(  
    @UserID BIGINT,  
    @CategoryId BIGINT,  
    @ProductId BIGINT,  
    @Type BIGINT,  
    @CreatedInterval BIGINT,  
    @ClosedInterval BIGINT,  
    @MetaData NVARCHAR(200)  
)  
AS  
BEGIN  
    BEGIN TRY  
        DECLARE @ParentID BIGINT, @TimeZone NVARCHAR(400), @rowJson NVARCHAR(MAX), @IPAdress NVARCHAR(50),  
                @DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT  
  
        Select @TimeZone = TimeZone  From tbl_tp_UserLogin (noLock) Where User_Id = @UserID    
        Select @ParentID = ParentId  From tbl_tp_UserLogin (noLock) Where User_Id = @UserID      
        DECLARE @TimeAgoCreated DATETIME = DATEADD(MINUTE, -@CreatedInterval, GETDATE());          
        DECLARE @TimeAgoClosed DATETIME = DATEADD(MINUTE, -@ClosedInterval, GETDATE());     
  
        DECLARE @sqls NVARCHAR(MAX) = ''  
        DECLARE @status INT  
        DECLARE @tableName NVARCHAR(MAX) = ''  
  
        -- Generate the dynamic table name using Usp_CreateProductTableByParentID  
         EXEC @status = Usp_tp_CreateTicketMasterTableByParentID @ParentID            
  ,@tableName OUTPUT    
  Select @status  
  Select @tableName  
        BEGIN  
            DECLARE @DynamicSQL NVARCHAR(MAX)  
  
            SET @DynamicSQL = N'  
  WITH AggregatedAttachments AS (  
            SELECT  
                TicketID,  
                (COUNT(TicketAttachmentID) - 1) AS TotalAttachments,  
                STRING_AGG(ISNULL(TAM.TicketAttachmentID, ''No Attachment Available''), '', '') AS TicketAttachmentID,  
                STRING_AGG(ISNULL(TAM.DisplayName, ''No Attachment Available''), '', '') AS AggregatedDisplayNames,  
                STRING_AGG(ISNULL(TAM.FileUrl, ''''), '', '') AS AggregatedFileUrls,  
                MIN(ISNULL(TAM.DisplayName, ''No Attachment Available'')) AS SingleDisplayName,  
                MIN(ISNULL(TAM.FileUrl, '''')) AS SingleFileUrl  
            FROM tbl_tp_TicketAttachment TAM (NOLOCK)  
            WHERE TAM.IsActive = 1  
            GROUP BY TicketID  
        )  
  
  
    SELECT TM.TicketID, TM.tpUser_Id, TM.ParentId, TicketNo, TM.EntityID, TM.EntityName,         
               RequesterMobileNo, RequesterEmailID, Subject, Description, TM.TicketStatusID, TSM.TicketStatus,        
               TM.TicketPriority, TPM.PriorityName, TUL.Name AS AssignedUser, TM.TicketSourceId,         
               TSOM.TicketSourceName, TicketTypeId, TM.CreatedOn,        
               TM.IsActive, TM.ProductId, TM.TicketCategoryId, TM.TicketTypeId,ISNULL(AA.AggregatedDisplayNames,''No Attachment Available'')DisplayName,ISNULL(AA.AggregatedFileUrls,'')FileUrl ,AA.SingleDisplayName AS SingleAttachmentDisplayName,  
    AA.SingleFileUrl AS SingleAttachmentFileUrl,AA.AggregatedDisplayNames,AA.AggregatedFileUrls ,(AA.TicketAttachmentID)TicketAttachmentID , AA.TotalAttachments,     
               (SELECT COUNT(TicketID) FROM '+ @tableName +') TotalCount ,(SELECT STRING_AGG(Tag, '', '')  FROM TagMaster  
        
               WHERE ID IN (SELECT value FROM STRING_SPLIT(TM.TicketTag, '',''))) AS Tags                                       
               FROM '+ @tableName + ' TM (NOLOCK)    
      INNER JOIN tbl_tp_UserLogin TUL (NOLOCK) ON TUL.ParentId = TM.AssignedUser AND TUL.IsActive = 1        
               LEFT JOIN tbl_tp_TicketStatusMaster TSM (NOLOCK) ON TM.TicketStatusID = TSM.TicketStatus_ID AND TSM.IsActive = 1     
               LEFT JOIN tbl_tp_TicketPriorityMaster TPM (NOLOCK) ON TM.TicketPriority = TPM.Priority_ID   AND TPM.Active = 1     
               LEFT JOIN tbl_tp_TicketSourceMaster TSOM (NOLOCK) ON TM.TicketSourceId = TSOM.TicketSourceId AND TSOM.IsActive = 1      
               LEFT JOIN AggregatedAttachments AA ON TM.TicketID = AA.TicketID  
  
            WHERE  
                (TM.ParentId = @ParentID OR @ParentID IS NULL)  
            AND ((TM.TicketCategoryId = @CategoryId OR @CategoryId IS NULL))          
            AND (TM.ProductId = @ProductId OR @ProductId IS NULL)          
            AND (TM.TicketTypeId = @Type OR @Type IS NULL)              
                 
            '  
  
            -- Printing the dynamic query for debugging purposes  
            PRINT @DynamicSQL  
  
            EXEC sp_executesql @DynamicSQL 
                --N'@ParentID BIGINT, @CategoryId BIGINT, @ProductId BIGINT, @Type BIGINT, @CreatedInterval BIGINT, @ClosedInterval BIGINT',  
                --@ParentID, @CategoryId, @ProductId, @Type, @CreatedInterval, @ClosedInterval , @TimeZone 
  
            --EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData @User_id = @UserId  
                -- Other parameters ...  
  
        END  
  
    END TRY  
    BEGIN CATCH  
        PRINT 'Error occurred: ' + ERROR_MESSAGE()  
    END CATCH  
END  



