CREATE   PROCEDURE [dbo].[Usp_tp_GetAgentRaisedTicketDetails12345]
(
    @ParentID INT,
    @CategoryId INT,
    @ProductId INT,
    @Type INT,
    @CreatedInterval INT,
    @ClosedInterval INT,
    @MetaData NVARCHAR(200)
)
AS
BEGIN
    BEGIN TRY
        DECLARE @TimeZone NVARCHAR(400);
        DECLARE @SQL NVARCHAR(MAX);
        
        -- ... Parameter defaults and TimeZone retrieval ...

        -- Calculate time intervals
        DECLARE @TimeAgoCreated DATETIME = DATEADD(MINUTE, -@CreatedInterval, GETDATE());
        DECLARE @TimeAgoClosed DATETIME = DATEADD(MINUTE, -@ClosedInterval, GETDATE());

        -- Dynamic table name
        DECLARE @DynamicTableName NVARCHAR(100) = 'tbl_tp_TicketMaster_' + CAST(@ParentID AS NVARCHAR(20));

        -- Construct the dynamic SQL query
        SET @SQL = N'
            WITH AggregatedAttachments AS (
                -- ... AggregatedAttachments CTE ...
            )
            SELECT
                TM.TicketID, TM.tpUser_Id, TM.ParentId, TicketNo, TM.EntityID, TM.EntityName,
                -- ... Other selected columns ...
            FROM ' + QUOTENAME(@DynamicTableName) + N' TM (NOLOCK)
            INNER JOIN tbl_tp_UserLogin TUL (NOLOCK) ON TUL.ParentId = TM.AssignedUser AND TUL.IsActive = 1
            -- ... Other joins ...
            LEFT JOIN AggregatedAttachments AA ON TM.TicketID = AA.TicketID
            WHERE
                (TM.ParentId = @ParentID OR @ParentID IS NULL)
                AND (TM.TicketCategoryId = @CategoryId OR @CategoryId IS NULL)
                AND (TM.ProductId = @ProductId OR @ProductId IS NULL)
                AND (TM.TicketTypeId = @Type OR @Type IS NULL)
                AND (@TimeAgoCreated IS NULL OR TM.CreatedOn >= @TimeAgoCreated)
                AND (@TimeAgoClosed IS NULL OR (TM.CreatedOn >= @TimeAgoClosed AND TicketStatusID = 3))
        ';

        -- Execute the dynamic SQL query
        EXEC sp_executesql @SQL,
            N'@ParentID INT, @CategoryId INT, @ProductId INT, @Type INT, @TimeAgoCreated DATETIME, @TimeAgoClosed DATETIME, @TimeZone NVARCHAR(400)',
            @ParentID, @CategoryId, @ProductId, @Type, @TimeAgoCreated, @TimeAgoClosed, @TimeZone;

        -- Execute audit
        EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData
            --@User_id = @UserID,
            @Activity_type = 'View_agentraisedmaster',
            @ActionType = 'S',
            @RowJson = 'NULL',
            @Table_name = @DynamicTableName
            --@ip_adress = @IPAdress,
            --@device_id = @DeviceId,
            --@IsImpersonation = @IsImpersonation,
            --@ImpersonatorId = @ImpersonatorId;

    END TRY
    BEGIN CATCH
        PRINT 'Error occurred: ' + ERROR_MESSAGE();
    END CATCH
END



GO

/* ============================================================
   Procedure: [dbo].[usp_tp_GetAllArticleSamCategory]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_tp_GetAllArticleSamCategory]
    @DomainName NVARCHAR(255),
	@catearticleId BIGINT    
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @ParentId BIGINT;
    DECLARE @tpuserid BIGINT;

 SELECT @ParentId = c.ParentId
      FROM tbl_tp_client_domain c WITH (NOLOCK)
      WHERE @DomainName = c.ClientDomain;

	   IF @ParentId IS NULL
	   BEGIN
	   DECLARE @SubDomain NVARCHAR(200);
    SET @SubDomain = SUBSTRING(@DomainName, LEN(@DomainName) - CHARINDEX('/', REVERSE(@DomainName)) + 2, LEN(@DomainName));
        BEGIN
            SET @SubDomain = @SubDomain
            SELECT @ParentId = ParentId
            FROM tbl_tp_Portalsetting WITH (NOLOCK)
            WHERE @SubDomain = PortalName;
			END;
			END;
 IF @ParentId IS NULL
 BEGIN
    SELECT @ParentId = c.ParentId
    FROM tbl_tp_client_domain c WITH (NOLOCK)
    WHERE REPLACE(@DomainName, 'www.', '') LIKE '%' + REPLACE(c.ClientDomain, 'www.', '') + '%';
END;

IF @ParentId IS NULL
BEGIN
    SELECT @ParentId = c.ParentId
    FROM tbl_tp_client_domain c WITH (NOLOCK)
    WHERE REPLACE(@DomainName, 'https://', '') LIKE '%' + REPLACE(c.ClientDomain, 'https://', '') + '%'
        OR REPLACE(@DomainName, 'http://', '') LIKE '%' + REPLACE(c.ClientDomain, 'http://', '') + '%';
END;

IF @ParentId IS NULL
BEGIN
    SELECT @ParentId = c.ParentId
    FROM tbl_tp_client_domain c WITH (NOLOCK)
    WHERE REPLACE(REPLACE(@DomainName, 'https://', ''), 'http://', '') LIKE '%' + REPLACE(REPLACE(c.ClientDomain, 'https://', ''), 'http://', '') + '%';
END;


    IF @ParentId IS NOT NULL
    BEGIN
     select * from tbl_tp_ArticleMaster(nolock) where Category_Id=@catearticleId and ParentId=@ParentId

    END
    ELSE
    BEGIN
        PRINT 'No related Article found.';
    END
END;




