/* ============================================================
   Procedure: [dbo].[Usp_tp_GetArticleMaseterList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_tp_GetArticleMaseterList]
(                                  
    @tpuserid BIGINT,
    @SqlWhere NVARCHAR(MAX) = NULL

)
AS
BEGIN
--declare
--    @tpuserid BIGINT=1,
--    @SqlWhere NVARCHAR(MAX) = ''

    DECLARE @ParentID BIGINT, @UserId BIGINT, @TimeZone NVARCHAR(400),
            @IPAdress NVARCHAR(50), @DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT,
			   @MetaData NVARCHAR(200)='{}';
    SELECT @TimeZone = TimeZone, @UserId = User_ID, @ParentID = ParentId 
    FROM tbl_tp_UserLogin (NOLOCK) 
    WHERE TpUser_Id = @tpuserid;

	If (concat(@SqlWhere,'')='')  
 Begin  
  SET @SqlWhere=N' and 1=1 '  
 End  
 Else  
 Begin  
  SET @SqlWhere=N' and ' + @SqlWhere  
 End  

    SET @IPAdress = JSON_VALUE(@MetaData, '$.IPAddress');
    SET @DeviceId = JSON_VALUE(@MetaData, '$.MacAddress');
    SET @IsImpersonation = JSON_VALUE(@MetaData, '$.IsImpersonation');
    SET @ImpersonatorId = JSON_VALUE(@MetaData, '$.ImpersonatorId');


DECLARE @Sql NVARCHAR(MAX);
SET @Sql = N'
WITH CategoryHierarchyCTE AS (
    SELECT
        ArticleCate_Id,
        ParentCategoryId,
        CategoryName,
        CAST(CategoryName AS NVARCHAR(MAX)) AS Sequencehierarchy,
        1 AS CategoryLevel
    FROM
        tbl_tp_ArticleCategory
    WHERE
        ParentCategoryId IS NULL

    UNION ALL

    SELECT
        c.ArticleCate_Id,
        c.ParentCategoryId,
        c.CategoryName,
        CAST(ch.Sequencehierarchy + ''>'' + c.CategoryName AS NVARCHAR(MAX)) AS Sequencehierarchy,
        ch.CategoryLevel + 1 AS CategoryLevel
    FROM
        tbl_tp_ArticleCategory c
    INNER JOIN
        CategoryHierarchyCTE ch ON c.ParentCategoryId = ch.ArticleCate_Id
)

SELECT
    am.*,
    ta.AuthorName,
    cat.CategoryName,
    cat.Sequencehierarchy
FROM
    tbl_tp_ArticleMaster am (NOLOCK)
LEFT JOIN
    tbl_tp_Author ta (NOLOCK) ON am.Author_id = ta.Author_Id
LEFT JOIN
    CategoryHierarchyCTE cat ON am.Category_Id = cat.ArticleCate_Id
WHERE
    (am.ParentId = @ParentID OR am.ParentId IS NULL) AND am.IsActive = 1 ' + @SqlWhere + '
ORDER BY
    am.CreatedDate DESC;
';

EXEC sp_executesql @Sql, N'@ParentID BIGINT, @UserId BIGINT, @IPAdress NVARCHAR(50), @DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT',
                   @ParentID, @UserId, @IPAdress, @DeviceId, @IsImpersonation, @ImpersonatorId;

EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData
    @User_id = @UserId,
    @Activity_type = 'View_articlemaster',
    @ActionType = 'S',
    @RowJson = 'NULL',
    @Table_name = 'tbl_tp_ArticleMaster',
    @ip_adress = @IPAdress,
    @device_id = @DeviceId,
    @IsImpersonation = @IsImpersonation,
    @ImpersonatorId = @ImpersonatorId;

END;




GO

/* ============================================================
   Procedure: [dbo].[usp_tp_GetArticlePageDetailWebsitePortal]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_tp_GetArticlePageDetailWebsitePortal]
    @DomainName NVARCHAR(255),
	@ArticleId bigint
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @ParentId BIGINT;
    DECLARE @tpuserid BIGINT;

 SELECT @ParentId = c.ParentId
      FROM tbl_tp_client_domain c WITH (NOLOCK)
      WHERE @DomainName = c.ClientDomain;

	   IF @ParentId IS NULL
	   BEGIN
	   DECLARE @SubDomain NVARCHAR(200);
    SET @SubDomain = SUBSTRING(@DomainName, LEN(@DomainName) - CHARINDEX('/', REVERSE(@DomainName)) + 2, LEN(@DomainName));
        BEGIN
            SET @SubDomain = @SubDomain
            SELECT @ParentId = ParentId
            FROM tbl_tp_Portalsetting WITH (NOLOCK)
            WHERE @SubDomain = PortalName;
			END;
			END;
 IF @ParentId IS NULL
 BEGIN
    SELECT @ParentId = c.ParentId
    FROM tbl_tp_client_domain c WITH (NOLOCK)
    WHERE REPLACE(@DomainName, 'www.', '') LIKE '%' + REPLACE(c.ClientDomain, 'www.', '') + '%';
END;

IF @ParentId IS NULL
BEGIN
    SELECT @ParentId = c.ParentId
    FROM tbl_tp_client_domain c WITH (NOLOCK)
    WHERE REPLACE(@DomainName, 'https://', '') LIKE '%' + REPLACE(c.ClientDomain, 'https://', '') + '%'
        OR REPLACE(@DomainName, 'http://', '') LIKE '%' + REPLACE(c.ClientDomain, 'http://', '') + '%';
END;

IF @ParentId IS NULL
BEGIN
    SELECT @ParentId = c.ParentId
    FROM tbl_tp_client_domain c WITH (NOLOCK)
    WHERE REPLACE(REPLACE(@DomainName, 'https://', ''), 'http://', '') LIKE '%' + REPLACE(REPLACE(c.ClientDomain, 'https://', ''), 'http://', '') + '%';
END;

    SELECT @tpuserid = tpuserid
    FROM tbl_tp_pagesection (NOLOCK)
    WHERE ParentId = @ParentId;

    IF @tpuserid IS NOT NULL
    BEGIN
	 UPDATE tbl_tp_ArticleMaster
        SET ViewCount = CASE WHEN ViewCount IS NULL THEN 1 ELSE ViewCount + 1 END
        WHERE Article_Id = @ArticleId; 

        WITH CategoryHierarchyCTE AS (
            SELECT
                ArticleCate_Id,
                ParentCategoryId,
                CategoryName,
                CAST(CategoryName AS NVARCHAR(MAX)) AS Sequencehierarchy,
                1 AS CategoryLevel
            FROM
                tbl_tp_ArticleCategory
            WHERE
                ParentCategoryId IS NULL

            UNION ALL

            SELECT
                c.ArticleCate_Id,
                c.ParentCategoryId,
                c.CategoryName,
                CAST(ch.Sequencehierarchy + '>' + c.CategoryName AS NVARCHAR(MAX)) AS Sequencehierarchy,
                ch.CategoryLevel + 1 AS CategoryLevel
            FROM
                tbl_tp_ArticleCategory c
            INNER JOIN
                CategoryHierarchyCTE ch ON c.ParentCategoryId = ch.ArticleCate_Id
        )

        SELECT
            am.*,
            ta.AuthorName,
            cat.CategoryName,
            cat.Sequencehierarchy
        FROM
            tbl_tp_ArticleMaster am (NOLOCK)
        LEFT JOIN
            tbl_tp_Author ta (NOLOCK) ON am.Author_id = ta.Author_Id
        LEFT JOIN
            CategoryHierarchyCTE cat ON am.Category_Id = cat.ArticleCate_Id
        WHERE
            (am.ParentId = @ParentID OR am.ParentId IS NULL) AND am.IsActive = 1
            OR am.Category_Id IN (SELECT ArticleCate_Id FROM CategoryHierarchyCTE WHERE ArticleCate_Id = @tpuserid)
        ORDER BY
            am.CreatedDate DESC;

    END
    ELSE
    BEGIN
        PRINT 'No active page found.';
    END
END;




GO

/* ============================================================
   Procedure: [dbo].[usp_tp_GetAssignmentGroupPermission]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_tp_GetAssignmentGroupPermission]  
 @tpUserId BIGINT
AS
BEGIN
--declare     @tpUserId BIGINT=1

    SET NOCOUNT ON;

    DECLARE @AssignedUser BIGINT,
            @IsAdmin BIT = 0,
            @UserID BIGINT,
            @TimeZone NVARCHAR(400),
            @DefaultCustomRoleId BIGINT,
            @DefaultPredefinedRoleId BIGINT,
            @AssignedRoleId BIGINT,
            @ParentId BIGINT = 0,
            @tpUserIds NVARCHAR(MAX),
            @PermissionCodes NVARCHAR(MAX), 
            @PermissionValues NVARCHAR(MAX),
            @CurrentCode NVARCHAR(50),
            @Start INT,
            @CommaIndex INT;

    -- Step 1: Fetch user details
    SELECT 
        @UserID = User_Id, 
        @ParentId = ParentId,
        @TimeZone = ISNULL(TimeZone, 'India Standard Time'),   
        @IsAdmin = (CASE WHEN User_Id = ParentId THEN 1 ELSE 0 END)  
    FROM tbl_tp_UserLogin (NOLOCK)   
    WHERE TpUser_Id = @tpUserId AND IsActive = 1;

    -- Step 2: Get the assigned role ID from agent role mapping
    SELECT 
        @AssignedRoleId = arm.role_id
    FROM tbl_tp_agentrolemapping arm WITH (NOLOCK)
    WHERE arm.tpuserid = @tpUserId 
      AND arm.Active = 1;


    IF @AssignedRoleId IS NULL
    BEGIN
        SET @DefaultCustomRoleId = (
            SELECT TOP 1 Role_Id 
            FROM tbl_tp_RolesMaster (NOLOCK) 
            WHERE IsPredefined = 0 AND IsDefault = 1
        );

        IF @DefaultCustomRoleId IS NULL
        BEGIN
            SET @DefaultPredefinedRoleId = (
                SELECT TOP 1 Role_Id 
                FROM tbl_tp_RolesMaster (NOLOCK) 
                WHERE IsPredefined = 1 AND IsDefault = 1
            );
            SET @AssignedRoleId = @DefaultPredefinedRoleId;
        END
        ELSE
        BEGIN
            SET @AssignedRoleId = @DefaultCustomRoleId;
        END
    END


    SELECT 
     @PermissionCodes = 
            STUFF((
                SELECT DISTINCT ',' + CAST(PermissionCode AS NVARCHAR(MAX))
                FROM tbl_tp_Assignment_PermissionField (NOLOCK)
                WHERE Role_Id = @AssignedRoleId
                  AND IsActive = 1
                  --AND PermissionCode = 'SPECIFIC_USER'
                FOR XML PATH(''), TYPE
            ).value('.', 'NVARCHAR(MAX)'), 1, 1, ''),
        @PermissionValues = 
            STUFF((
                SELECT DISTINCT ',' + CAST(PermissionValues AS NVARCHAR(MAX))
                FROM tbl_tp_Assignment_PermissionField (NOLOCK)
                WHERE Role_Id = @AssignedRoleId
                  AND IsActive = 1
                  AND PermissionCode = 'SPECIFIC_Group'
                FOR XML PATH(''), TYPE
            ).value('.', 'NVARCHAR(MAX)'), 1, 1, '')
    FROM tbl_tp_Assignment_PermissionField (NOLOCK)
    WHERE Role_Id = @AssignedRoleId AND IsActive = 1;

    DECLARE @Results TABLE (Group_Id BIGINT, Group_Name NVARCHAR(255));

    IF @PermissionCodes IS NOT NULL
    BEGIN

        DECLARE @UniquePermissionCodes TABLE (PermissionCode NVARCHAR(50));


        SET @Start = 1;

        WHILE @Start <= LEN(@PermissionCodes)
        BEGIN
            SET @CommaIndex = CHARINDEX(',', @PermissionCodes, @Start);

            IF @CommaIndex = 0
            BEGIN
                SET @CommaIndex = LEN(@PermissionCodes) + 1; -- Last element
            END


            SET @CurrentCode = TRIM(SUBSTRING(@PermissionCodes, @Start, @CommaIndex - @Start));

            IF NOT EXISTS (SELECT 1 FROM @UniquePermissionCodes WHERE PermissionCode = @CurrentCode)
            BEGIN
                INSERT INTO @UniquePermissionCodes (PermissionCode) VALUES (@CurrentCode);
            END


            SET @Start = @CommaIndex + 1;
        END

        DECLARE @LoopCode NVARCHAR(50);
        DECLARE permission_cursor CURSOR FOR
        SELECT PermissionCode FROM @UniquePermissionCodes;

        OPEN permission_cursor;
        FETCH NEXT FROM permission_cursor INTO @LoopCode;

        WHILE @@FETCH_STATUS = 0
        BEGIN

         

            IF @LoopCode = 'ALL_Groups'
            BEGIN
                INSERT INTO @Results (Group_Id, Group_Name)
                SELECT 
                    GroupId AS Group_Id, 
                    GroupName AS Group_Name
                FROM tbl_tp_GroupMaster (NOLOCK)
                WHERE ParentID = @ParentId AND Active = 1
                ORDER BY GroupId ASC;


                BREAK;
            END
            ELSE IF @LoopCode = 'GROUP_BELONG'
            BEGIN
                INSERT INTO @Results (Group_Id, Group_Name)
                SELECT 
                    gm.GroupId AS Group_Id, 
                    gm.GroupName AS Group_Name
                FROM tbl_tp_GroupMaster gm (NOLOCK)
                INNER JOIN tbl_tp_AgentGroupMapping agm (NOLOCK)
                    ON gm.GroupId = agm.GroupId
                WHERE gm.ParentID = @ParentId 
                  AND agm.tpuserid = @tpUserId
                  AND gm.Active = 1
                ORDER BY gm.GroupId ASC;
            END
            ELSE IF @LoopCode = 'SPECIFIC_Group'
            BEGIN
                IF @PermissionValues IS NOT NULL AND LEN(@PermissionValues) > 0
                BEGIN
                    INSERT INTO @Results (Group_Id, Group_Name)
                    SELECT 
                        gm.GroupId AS Group_Id, 
                        gm.GroupName AS Group_Name
                    FROM tbl_tp_GroupMaster gm (NOLOCK)
                    WHERE gm.ParentID = @ParentId 
                      AND gm.GroupId IN (SELECT value FROM STRING_SPLIT(@PermissionValues, ','))
                      AND gm.Active = 1
                    ORDER BY gm.GroupId ASC;
                END
            END


            FETCH NEXT FROM permission_cursor INTO @LoopCode;
        END

        CLOSE permission_cursor;
        DEALLOCATE permission_cursor;
    END
    IF NOT EXISTS (SELECT 1 FROM @Results)
    BEGIN
        INSERT INTO @Results (Group_Id, Group_Name)
        SELECT 
            GroupId AS Group_Id, 
            GroupName AS Group_Name
        FROM tbl_tp_GroupMaster (NOLOCK)
        WHERE ParentID = @ParentId AND Active = 1
        ORDER BY GroupId ASC;
    END
    SELECT * FROM @Results;
END;




GO

