/* ============================================================
   Procedure: [dbo].[Usp_tp_GetCategoryHierarchyAndCount]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_GetCategoryHierarchyAndCount]
AS
BEGIN
    WITH CategoryHierarchyCTE AS (
        SELECT
            ArticleCate_Id,
            ParentCategoryId,
            CategoryName,
            CAST(CategoryName AS NVARCHAR(MAX)) AS Sequencehierarchy,
            1 AS CategoryLevel
        FROM
            tbl_tp_ArticleCategory
        WHERE
            ParentCategoryId IS NULL 

        UNION ALL

        SELECT
            c.ArticleCate_Id,
            c.ParentCategoryId,
            c.CategoryName,
            CAST(ch.Sequencehierarchy + '>' + c.CategoryName AS NVARCHAR(MAX)) AS Sequencehierarchy,
            ch.CategoryLevel + 1 AS CategoryLevel
        FROM
            tbl_tp_ArticleCategory c
        INNER JOIN
            CategoryHierarchyCTE ch ON c.ParentCategoryId = ch.ArticleCate_Id
    )

    SELECT
        ArticleCate_Id,
        ParentCategoryId,
        CategoryName,
        Sequencehierarchy,
        CategoryLevel,
        (
            SELECT COUNT(*)
            FROM tbl_tp_ArticleCategory sub
            WHERE CategoryHierarchyCTE.Sequencehierarchy LIKE sub.CategoryName + '%'
        ) AS RecordCount
    FROM
        CategoryHierarchyCTE
    ORDER BY
        Sequencehierarchy;
END;




GO

