CREATE   PROCEDURE [dbo].[Usp_tp_GetContactFormDetails]  
(                                
    @SortField NVARCHAR(20) = NULL,  
    @ParentID BIGINT = NULL,  
    @TpUserId BIGINT = NULL,  
    @Pageno NVARCHAR(100) = NULL,    
    @Pagesize NVARCHAR(100) = NULL,    
    @SqlWhere NVARCHAR(MAX) = NULL, 
    --@StrSql NVARCHAR(MAX) = NULL, 
    @MetaData NVARCHAR(200) = NULL  
)                                
AS                                
BEGIN  
--declare @SortField NVARCHAR(20) = N'',     
--  @ParentID BIGINT = 32222,  
--  @TpUserId BIGINT = 1,       
--  @Pageno NVARCHAR(100) = N'1',    
--  @Pagesize NVARCHAR(100) = null,    
--  @SqlWhere nvarchar(max) = N'', 
--  --@StrSql NVARCHAR(MAX) = N'TM.CreatedDate BETWEEN CAST(''2024-08-01'' AS DATE) AND CAST(''2024-08-06'' AS DATE)',
--  @MetaData NVARCHAR(200)=N'{"IPAddress":"::1","MacAddress":"00FF61AD0C56","IsImpersonation":false,"ImpersonatorId":0}'  
BEGIN TRY  

    DECLARE @TimeZone NVARCHAR(400), @rowJson NVARCHAR(MAX), @IPAdress NVARCHAR(50), @UserID BIGINT,   
        @DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT,   
        @ProductTableName NVARCHAR(100), @DynamicColumns NVARCHAR(MAX) = '', @IsAdmin BIT = 0,  
        @DynamicSQL NVARCHAR(MAX), @sqls NVARCHAR(MAX) = '', @status INT, @tableName NVARCHAR(MAX) = '',  
        @AccessType NVARCHAR(100) = '', @StrGroupIds NVARCHAR(MAX) = '', @StrWhere NVARCHAR(MAX) = ' AND 1=1 ',  
        @offset INT = ISNULL(NULLIF(@Pagesize, ''), 20);    

    SELECT @UserID = User_Id, @TimeZone = ISNULL(TimeZone, 'India Standard Time'),   
           @IsAdmin = CASE WHEN User_Id = ParentId THEN 1 ELSE 0 END  
    FROM tbl_tp_UserLogin (NOLOCK)   
    WHERE TpUser_Id = @TpUserId AND IsActive = 1;

    DROP TABLE IF EXISTS #tbl_tp_AgentGroupMapping;

    SELECT *  
    INTO #tbl_tp_AgentGroupMapping  
    FROM tbl_tp_AgentGroupMapping (NOLOCK)   
    WHERE TpUserId = @TpUserId AND IsActive = 1;

    SELECT @AccessType = AccessType FROM #tbl_tp_AgentGroupMapping;

    IF(@AccessType = 'GlobalAccess')  
    BEGIN  
        SET @IsAdmin = 1;  
    END  
    ELSE IF(@AccessType = 'AssignedToGroup')  
    BEGIN  
        SELECT @StrGroupIds = STRING_AGG(ISNULL(NULLIF(GroupId, ''), 0), ',') 
        FROM #tbl_tp_AgentGroupMapping;    
    END;

    IF (@SortField = '') SET @SortField = NULL;

    IF (CONCAT(@SqlWhere, '') = '')  
    BEGIN  
        SET @SqlWhere = N' AND 1=1 ';  
    END  
    ELSE  
    BEGIN  
        SET @SqlWhere = N' AND ' + @SqlWhere;  
    END;
	   -- IF (CONCAT(@StrSql, '') = '')  
    --BEGIN  
    --    SET @StrSql = N' AND 1=1 ';  
    --END  
    --ELSE  
    --BEGIN  
    --    SET @StrSql = N' AND ' + @StrSql;  
    --END;

    IF @SortField IS NOT NULL  
    BEGIN  
        SET @DynamicSQL = N'
        SELECT * FROM (  
            SELECT   
                ROW_NUMBER() OVER (ORDER BY ISNULL(TM.CreatedDate,'''') DESC) AS RecNo,  
                COUNT(*) OVER () AS TotalCount,  
                TM.Id,  
                TM.ParentId,  
				ISNULL(TM.EntityID,'''') AS EntityID, 
                ISNULL(TM.EntityName,'''') AS EntityName,  
                JSON_VALUE(TM.FormData, ''$.name'') AS Name,
                JSON_VALUE(TM.FormData, ''$.email'') AS Email,
                JSON_VALUE(TM.FormData, ''$.phone'') AS Phone,
                JSON_VALUE(TM.FormData, ''$.subject'') AS Subject,
                JSON_VALUE(TM.FormData, ''$.description'') AS Description,
                JSON_VALUE(TM.FormData, ''$.domain'') AS Domain,
                TM.Status,
                dbo.fn_ConvertDateTime(TM.CreatedDate, @TimeZone, 0) AS CreatedOn,    
                TM.IsActive  
            FROM tbl_tp_ContactUsWebsitePortal TM (NOLOCK)  
            WHERE TM.ParentId = @ParentID ' + @SqlWhere + N' AND TM.IsActive = 1  
        ) T  
        WHERE T.RecNo BETWEEN ' + CONVERT(NVARCHAR(MAX), (@Pageno - 1) * @offset + 1) + N' AND ' + CONVERT(NVARCHAR(MAX), @offset * @Pageno) + N'  
        ORDER BY ' +
        CASE  
            WHEN @SortField = 'Name' THEN 'Name'  
            WHEN @SortField = 'Email' THEN 'Email'  
            WHEN @SortField = 'Phone' THEN 'Phone'  
            WHEN @SortField = 'Subject' THEN 'Subject'  
            WHEN @SortField = 'Description' THEN 'Description'  
            WHEN @SortField = 'CreatedOn' THEN 'CreatedOn'  
            WHEN @SortField = 'Status' THEN 'Status'  
            ELSE 'Id DESC'  
        END;

        PRINT @DynamicSQL;  
    END  
    ELSE  
    BEGIN  
        SET @DynamicSQL = N'
        SELECT * FROM (  
            SELECT   
                ROW_NUMBER() OVER (ORDER BY ISNULL(TM.CreatedDate,'''') DESC) AS RecNo,  
                COUNT(*) OVER () AS TotalCount,  
                TM.Id,  
                TM.ParentId,  
              	ISNULL(TM.EntityID,'''') AS EntityID, 
                ISNULL(TM.EntityName,'''') AS EntityName,
                JSON_VALUE(TM.FormData, ''$.name'') AS Name,
                JSON_VALUE(TM.FormData, ''$.email'') AS Email,
                JSON_VALUE(TM.FormData, ''$.phone'') AS Phone,
                JSON_VALUE(TM.FormData, ''$.subject'') AS Subject,
                JSON_VALUE(TM.FormData, ''$.description'') AS Description,
                JSON_VALUE(TM.FormData, ''$.domain'') AS Domain,
                TM.Status,
                dbo.fn_ConvertDateTime(TM.CreatedDate, @TimeZone, 0) AS CreatedOn,    
                TM.IsActive  
            FROM tbl_tp_ContactUsWebsitePortal TM (NOLOCK)  
            WHERE TM.ParentId = @ParentID ' + @SqlWhere + N'  AND TM.IsActive = 1  
        ) T  
        WHERE T.RecNo BETWEEN ' + CONVERT(NVARCHAR(MAX), (@Pageno - 1) * @offset + 1) + N' AND ' + CONVERT(NVARCHAR(MAX), @offset * @Pageno) + N'  
        ORDER BY Id DESC;';

        PRINT @DynamicSQL;  
    END;  

    EXEC sp_executesql @DynamicSQL,  
    N'@ParentID BIGINT, @TimeZone NVARCHAR(400)',  
    @ParentID, @TimeZone;  

    EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData   
    @User_id = @UserID,  
    @Activity_type = 'View_ContactForm',  
    @ActionType = 'S',  
    @RowJson = 'NULL',  
    @Table_name = @tableName,  
    @ip_adress = @IPAdress,  
    @device_id = @DeviceId,  
    @IsImpersonation = @IsImpersonation,  
    @ImpersonatorId = @ImpersonatorId;  

END TRY  
BEGIN CATCH  
    PRINT 'Error occurred: ' + ERROR_MESSAGE();  
END CATCH  
END;




GO

