            @Activity_type = 'View_businesshours',
            @ActionType = 'S',
            @RowJson = @rowJson,
            @Table_name = 'tbl_tp_BusinessHours',
            @ip_adress = @IPAdress,
            @device_id = @DeviceId,
            @IsImpersonation = @IsImpersonation,
            @ImpersonatorId = @ImpersonatorId;
    END
END



