/* ============================================================
   Procedure: [dbo].[usp_tp_GetDataForEmailSettings]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_tp_GetDataForEmailSettings]
    @tpUserId BIGINT,
    @MetaData NVARCHAR(MAX)
AS
BEGIN
--declare
    --@tpUserId BIGINT=1,
    --@MetaData NVARCHAR(MAX)='{}'
    DECLARE @UserId BIGINT, @ParentId BIGINT, @TimeZone NVARCHAR(400), @rowJson NVARCHAR(MAX), @IPAdress NVARCHAR(50), @DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT;

    -- Retrieve User_Id and TimeZone for the given ParentId
    SELECT @UserId = User_Id, @ParentId = ParentId, @TimeZone = TimeZone FROM tbl_tp_UserLogin (NOLOCK) WHERE TpUser_Id = @tpUserId;

    -- Extract values from the JSON metadata
    SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress);
    SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress);
    SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation);
    SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId);



	    DECLARE @SQL NVARCHAR(MAX);
    SET @SQL = N'
     SELECT
    ES.name as Name,
    STRING_AGG( MG.usermail, '','') AS UserEmails
FROM 
    tbl_tp_EmailSetting AS ES
LEFT JOIN 
    supportmailforwarding AS MG ON ES.ParentId = MG.ParentId
 WHERE ES.ParentId = ' + CAST(@ParentId AS NVARCHAR(20))  + N' 
		GROUP BY 
    ES.name
    ';
	print @SQL
    EXEC sp_executesql @SQL;

    -- Construct a JSON representation of the retrieved data
    SET @rowJson = (SELECT * FROM tbl_tp_EmailSetting WHERE ParentID = @ParentId FOR JSON AUTO, INCLUDE_NULL_VALUES);

    -- If rowJson is not null, insert an audit record
    IF @rowJson IS NOT NULL
    BEGIN
        EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData
            @User_id = @UserId,
            @Activity_type = 'View_emailsettings',
            @ActionType = 'S',
            @RowJson = @rowJson,
            @Table_name = 'tbl_tp_EmailSetting',
            @ip_adress = @IPAdress,
            @device_id = @DeviceId,
            @IsImpersonation = @IsImpersonation,
            @ImpersonatorId = @ImpersonatorId;
    END;
END





