/* ============================================================
   Procedure: [dbo].[usp_tp_GetDataForRolePermission]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_tp_GetDataForRolePermission]      
    @RoleId BIGINT,    
    @TpUserId BIGINT,    
    @MetaData NVARCHAR(MAX)    
AS        
BEGIN    
--declare 
--   @RoleId BIGINT=0,    
--    @TpUserId BIGINT=1,    
--    @MetaData NVARCHAR(MAX)  ='{}' 
    DECLARE @ParentId BIGINT,@UserId BIGINT, @TimeZone NVARCHAR(400), @rowJson NVARCHAR(MAX), @IPAdress NVARCHAR(50), @DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT;    
    SELECT @ParentId = ParentId,@UserId = User_Id, @TimeZone = TimeZone FROM tbl_tp_UserLogin (NOLOCK) WHERE TpUser_Id = @TpUserId    
    
    SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress);    
    SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress);    
    SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation);    
    SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId);    
        
    WITH AllPermissions AS (    
        SELECT    
            P.PermissionId,    
            P.Section_Id,    
            P.Permission_Type,
	        P.FieldDropdown,
            P.ParentPermissionType,    
            P.IsActive,    
            P.CreatedBy,
            P.Created_Date,
			P.Permission_Code,    
            CASE WHEN M.Role_Id IS NOT NULL THEN 1 ELSE 0 END AS IsChecked    
        FROM tbl_tp_Permission_Master AS P    
        LEFT JOIN tbl_tp_Permission_Mapping AS M ON P.PermissionId = M.Permission_Id AND M.Role_Id = @RoleId  
		  WHERE P.IsActive = 1
    )    
        
  SELECT    
    AP.PermissionId,
    COUNT(ARM.tpuserid) AS tpuserid_count,
    STRING_AGG(ARM.tpuserid, ',') AS tpuserid_list,
    AP.Section_Id,    
    S.Section,   
    AP.Permission_Type, 
	AP.FieldDropdown,
    AP.ParentPermissionType,    
    AP.IsActive,    
    AP.CreatedBy,    
    AP.Created_Date,    
    AP.IsChecked,    
    M.Role_Id,    
    M.CreatedBy AS Mapping_CreatedBy,    
    M.CreatedOn AS Mapping_CreatedOn,
	 AP.Permission_Code
FROM AllPermissions AS AP    
LEFT JOIN tbl_tp_Permission_Mapping AS M ON AP.PermissionId = M.Permission_Id AND M.Role_Id = @RoleId    
LEFT JOIN tbl_tp_SectionMaster AS S ON AP.Section_Id = S.Section_Id  
LEFT JOIN tbl_tp_agentrolemapping AS ARM ON M.Role_Id = ARM.role_id 
GROUP BY AP.PermissionId, AP.Section_Id, S.Section, AP.Permission_Type,AP.FieldDropdown, AP.ParentPermissionType, AP.IsActive, AP.CreatedBy, AP.Created_Date, AP.IsChecked, M.Role_Id, M.CreatedBy, M.CreatedOn, AP.Permission_Code
ORDER BY AP.Section_Id, AP.PermissionId;
    
    
    SET @rowJson = (SELECT * FROM tbl_tp_RolesMaster tm WHERE (Role_Id = @RoleId) AND (@RoleId > 0 )  FOR JSON AUTO, INCLUDE_NULL_VALUES);              
    IF @rowJson IS NOT NULL                        
    BEGIN                        
        EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData               
            @User_id = @UserId,                        
            @Activity_type = 'View_rolemaster',                        
            @ActionType = 'U',                        
            @RowJson = @rowJson,                        
            @Table_name = 'tbl_tp_RolesMaster',                
            @ip_adress = @IPAdress,              
            @device_id = @DeviceId,              
            @IsImpersonation = @IsImpersonation,              
            @ImpersonatorId = @ImpersonatorId;                  
    END     
END 








GO

