CREATE   PROC usp_tp_GetDispatcherScenarioSLAQueue
(
	@BatchSize int=10
)
AS
Begin
	-- declare @BatchSize int=10

	Select top(@BatchSize) * 
	From [tbl_tp_DispatcherApplyHistory](nolock)
	Where IsActive=1 and IsApplied=0

	Select top(@BatchSize) * 
	From [tbl_tp_ScenarioApplyHistory](nolock)
	Where IsActive=1 and IsApplied=0

	Select top(@BatchSize) * 
	From [tbl_tp_SlaReapplyHistory](nolock)
	Where IsActive=1 and IsApplied=0

End



