/* ============================================================
   Procedure: [dbo].[Usp_tp_GetDispatchrRulesList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_GetDispatchrRulesList]  --1,'{}'      
(        
    @TpUserId BIGINT = NULL,        
    @MetaData NVARCHAR(200) = NULL        
)        
AS        
BEGIN  
--DECLARE	
-- @TpUserId BIGINT = 60,        
--@MetaData NVARCHAR(200) = '{}'   
    DECLARE @UserId BIGINT,   
         @ParentId BIGINT,  
            @TimeZone NVARCHAR(400),        
            @rowJson NVARCHAR(MAX),        
            @IPAdress NVARCHAR(50),        
            @DeviceId NVARCHAR(50),        
            @IsImpersonation BIT,        
            @ImpersonatorId INT        
        
    SELECT @UserId = User_Id, @ParentId=ParentId, @TimeZone = isnull(TimeZone,'India Standard Time') FROM tbl_tp_UserLogin (NOLOCK) WHERE TpUser_Id = @TpUserId AND IsActive = 1        
        
    SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)        
    SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)        
    SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)        
    SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)        
        
    SELECT M.Disptchr_Id,M.Rule_Name,M.Rule_Description,M.SequenceNo,M.Active,M.ParentId,M.CreatedBy,TUL1.Name,    
    TUL1.LoginName,dbo.fn_ConvertDateTime(M.CreatedDate, @TimeZone, 0) CreatedDate,M.IsEnabled,C.Condtion_Id,C.FieldName,C.Operator,C.Value,C.Conjunction,C.SequenceNo,        
    C.Active,A.DispatchrAction_Id,A.Action_Id,A.Action_Value,A.SequenceNo,A.Active,A.ParentId,A.createdBy,A.CreatedDate,        
    CASE  WHEN A.Action_Id = 2 THEN SGM.GroupName   WHEN A.Action_Id = 1 THEN TUL.Name        
          WHEN A.Action_Id = 4 THEN TSM.TicketStatus ELSE NULL END AS ValueName,ATM.Description AS ActionTypeDescription        
    FROM tbl_tp_DispatcherMaster AS M    
    JOIN tbl_tp_DispatcherCondition AS C ON M.Disptchr_Id = C.Disptchr_Id    
    JOIN tbl_tp_DispatcherAction AS A ON M.Disptchr_Id = A.Disptchr_Id    
    LEFT JOIN tbl_tp_GroupMaster SGM ON A.Action_Id = 2 AND SGM.Groupid = A.Action_Value    
    LEFT JOIN tbl_tp_UserLogin TUL ON A.Action_Id = 1 AND TUL.User_Id = A.Action_Value    
    LEFT JOIN tbl_tp_ticketstatusmaster TSM ON A.Action_Id = 4 AND TSM.TicketStatus_ID = A.Action_Value    
    LEFT JOIN tbl_tp_ActionTypeMaster ATM ON ATM.ActionType_Id = A.Action_Id    
    LEFT JOIN tbl_tp_UserLogin TUL1 ON TUL1.TpUser_Id = M.CreatedBy    
    WHERE (M.ParentId = @ParentId) AND M.Active = 1  
	ORDER BY M.SequenceNo
    
        
    SET @rowJson = (SELECT * FROM tbl_tp_DispatcherMaster FOR JSON AUTO, INCLUDE_NULL_VALUES)        
        
    IF @rowJson IS NOT NULL        
    BEGIN        
        EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData        
            @User_id = @UserId,        
            @Activity_type = 'View_dispatchermaster',        
            @ActionType = 'S',        
            @RowJson = '',        
            @Table_name = 'tbl_tp_DispatcherMaster',        
            @ip_adress = @IPAdress,        
            @device_id = @DeviceId,        
            @IsImpersonation = @IsImpersonation,        
            @ImpersonatorId = @ImpersonatorId        
    END        
END 





GO

