   Procedure: [dbo].[Usp_tp_GetEmailNotificationAndType]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- Exec Usp_tp_GetEmailNotificationAndType @ParentId=32222
CREATE   PROCEDURE [dbo].[Usp_tp_GetEmailNotificationAndType]
(
	@ParentId bigint
)
AS
BEGIN
	 --declare @ParentId bigint=32222

	If not exists(Select * from tbl_tp_TicketNotificationDetail(nolock) Where ParentId=@ParentId and IsActive=1)
	Begin
		print 'Default Insertion'
		insert into tbl_tp_TicketNotificationDetail(Subject, Description, NotificationId, IsEnabled, ParentId, IsActive, CreatedBy, CreatedOn)
		Select DefaultSubject, DefaultBody, Notification_Id, 1, @ParentId, IsActive, CreatedBy, GETDATE()
		from tbl_tp_NotificationMaster(nolock) 
		Where IsActive=1 and CreatedBy=335
	End

    Select ND.NotificationDetail_Id, NM.NotificationName, NM.NotificationType, ND.Subject, ND.Description, ND.NotificationId, ND.IsEnabled, ND.ParentId, ND.IsActive, ND.CreatedBy, ND.CreatedOn 
	from tbl_tp_NotificationMaster(nolock) NM  INNER JOIN tbl_tp_TicketNotificationDetail(nolock) ND  
    ON NM.Notification_Id = ND.NotificationId
	Where ND.ParentId=@ParentId and NM.IsActive=1

END






