-- exec Usp_tp_GetManageTicketDetails@SortField=N'Sort',@ParentID=32222,@TpUserId=1,@Agent=0,@Group=0,@Priority=0,@Company=N'0',@PageNo=1,@Pagesize=null,@TagId=0,@CategoryId=0,@ProductId=0,@Type=0,@CreatedInterval=259200,@ClosedInterval=0,@MetaData=N'{"IPAddress":"::1","MacAddress":"00FF61AD0C56","IsImpersonation":false,"ImpersonatorId":0}'  

CREATE   PROCEDURE [dbo].[Usp_tp_GetManageTicketDetails_JK_OptmzV1]  
(                                
 @SortField NVARCHAR(20) = NULL,  
 @Predinedview NVARCHAR(MAX) = NULL,  
 @ParentID BIGINT = NULL,  
 @TpUserId BIGINT = NULL,  
 @Agent BIGINT = NULL,  
 @Group BIGINT = NULL,  
 @Priority BIGINT = NULL,  
 @Company NVARCHAR(300) = NULL,  
 @TagId BIGINT = NULL,  
 @CategoryId BIGINT = NULL,  
 @Pageno NVARCHAR(100) = NULL,    
 @Pagesize NVARCHAR(100) = NULL,    
 @ProductId BIGINT = NULL,  
 @Type BIGINT = NULL,  
 @CreatedInterval BIGINT = NULL,  
 @ClosedInterval BIGINT = NULL,  
 @SqlWhere nvarchar(max) = NULL,  
 @MetaData NVARCHAR(200) = NULL  
)                                
AS                                
BEGIN  
BEGIN TRY  

--declare @SortField NVARCHAR(20) = N'',    
--  @Predinedview NVARCHAR(100) = N'',    
--  @ParentID BIGINT = 46831,  
--  @TpUserId BIGINT = 2338,    
--  @Agent BIGINT = 0,    
--  @Group BIGINT = 0,--15,    
--  @Priority BIGINT = 0,    
--  @Company NVARCHAR(300) = '',--N'test',    
--  @TagId BIGINT = 0,--54,    
--  @CategoryId BIGINT = 0,    
--  @Pageno NVARCHAR(100) = N'1',    
--  @Pagesize NVARCHAR(100) = null,    
--  @ProductId BIGINT = null,--0,    
--  @Type BIGINT = 0,--13,    
--  @CreatedInterval BIGINT = 0,    
--  @ClosedInterval BIGINT = 0,--0,    
--  @SqlWhere nvarchar(max) = N'ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) = 1', @MetaData NVARCHAR(200)=N'{"IPAddress":"::1","MacAddress":"00FF61AD0C56","IsImpersonation":false,"ImpersonatorId":0}'    
  
--declare @SortField NVARCHAR(20) = N'',@ParentID BIGINT = 34594,@TpUserId BIGINT = 91,@Agent BIGINT = 0,@Group BIGINT = 0,@Priority BIGINT = 0,@Company NVARCHAR(300) = N'',@TagId BIGINT = 0,@CategoryId BIGINT = 0,@ProductId BIGINT = 0,@Type BIGINT = 0,@CreatedInterval BIGINT = 0,@ClosedInterval BIGINT = 0,@SqlWhere nvarchar(max) = NULL,@MetaData NVARCHAR(200)=N'{"IPAddress":"::1","MacAddress":"00FF61AD0C56","IsImpersonation":false,"ImpersonatorId":0}'  
  
 DECLARE @TimeZone NVARCHAR(400), @rowJson NVARCHAR(MAX), @IPAdress NVARCHAR(50), @UserID BIGINT,   
   @DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT,   
   @ProductTableName NVARCHAR(100), @DynamicColumns NVARCHAR(MAX) = '' , @IsAdmin BIT = 0,  
   @TimeAgoCreated DATETIME = DATEADD(MINUTE, @CreatedInterval, GETDATE()),  
   @TimeAgoClosed DATETIME = DATEADD(MINUTE, -@ClosedInterval, GETDATE()),  
   @DynamicSQL NVARCHAR(MAX), @sqls NVARCHAR(MAX) = '', @status INT, @tableName NVARCHAR(MAX) = '',  
   @AccessType nvarchar(100)='', @StrGroupIds nvarchar(max)='', @StrWhere nvarchar(max)=' and 1=1 ',  
   @offset INT = 50,
   @PageNoInt INT = 1,
   @FetchRows INT = 50,
   @OffsetRows INT = 0,
   @TicketMasterFull NVARCHAR(300) = N'',
   @ProductMasterFull NVARCHAR(300) = N'',
   @DynColsSelect NVARCHAR(MAX) = N'';    
  
 SELECT @UserID = User_Id, @TimeZone = isnull(TimeZone,'India Standard Time'),   
   @IsAdmin = (CASE WHEN User_Id = ParentId THEN 1 ELSE 0 END)  
 FROM tbl_tp_UserLogin(nolock)   
 WHERE TpUser_Id = @TpUserId AND IsActive = 1  
  
 drop table if exists #tbl_tp_AgentGroupMapping  
  
 Select *  
 into #tbl_tp_AgentGroupMapping  
 from tbl_tp_AgentGroupMapping(nolock)   
 Where tpUserId=@TpUserId AND IsActive = 1  
  
 Select @AccessType=AccessType from #tbl_tp_AgentGroupMapping  
  
 If(@AccessType='GlobalAccess')  
 Begin  
  Set @IsAdmin=1  
 End  
 Else If(@AccessType='AssignedToGroup')  
 Begin  
  Select @StrGroupIds=STRING_AGG(isnull (nullif (GroupId,''),0),',') From #tbl_tp_AgentGroupMapping    
 End  
  
 print concat('@AccessType: ',@AccessType)  
 print concat('@IsAdmin: ',@IsAdmin)  
  
 IF (@CategoryId = 0)  
 SET @CategoryId = NULL                         
  
 IF (isnull(@Agent,0) = 0)  
 Begin  
  SET @Agent = NULL  
 End  
 Else  
 Begin  
  Set @StrWhere += concat(N' and TM.AssignedUser = ', @Agent)  
 End  
  
 IF (isnull(@Group,0) = 0)  
 Begin  
  SET @Group = NULL  
 End  
 Else  
 Begin  
  set @StrWhere += concat(N' and TM.AssignedGroup = ', @Group)  
 End  
  
 IF (isnull(@Priority,0) = 0)  
 Begin  
  SET @Priority = NULL  
 End  
  
 IF (@TagId = 0)  
 Begin  
  SET @TagId = NULL  
 End  
  
 IF (@ProductId = 0)  
 SET @ProductId = NULL  
  
 IF (isnull(@Type,0) = 0)  
 Begin  
  SET @Type = NULL  
 End  
  
 IF (@CreatedInterval = 0)  
 Begin  
  SET @CreatedInterval = NULL  
 End  
  
 IF (@ClosedInterval = 0)  
 Begin  
  SET @ClosedInterval = NULL  
 End  
  
 IF (@SortField = '')  
 SET @SortField = NULL  
  
 If (concat(@SqlWhere,'')='')  
 Begin  
  SET @SqlWhere=N' and 1=1 '  
 End  
 Else  
 Begin  
  SET @SqlWhere=N' and ' + @SqlWhere

-- JK-OPT: Safe paging defaults + conversions (Pagesize default 20 (client confirmed))
SET @FetchRows  = ISNULL(NULLIF(TRY_CONVERT(INT, @Pagesize), 0), 20);
SET @PageNoInt  = ISNULL(NULLIF(TRY_CONVERT(INT, @Pageno), 0), 1);
SET @OffsetRows = (@PageNoInt - 1) * @FetchRows;
SET @offset     = @FetchRows; -- keep old variable used in SortField branch

-- JK-OPT: Replace scalar UDF in @SqlWhere to join-based expression
SET @SqlWhere = REPLACE(@SqlWhere,
    'ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID)',
    'ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID)'
);
SET @SqlWhere = REPLACE(@SqlWhere,
    'ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID)',
    'ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID)'
);  
 End  
  
 EXEC @status = Usp_tp_CreateTicketMasterTableByParentID_jk @ParentID, @tableName OUTPUT

-- JK-OPT: Schema-qualified table names for dynamic SQL
SET @TicketMasterFull = QUOTENAME(N'dbo') + N'.' + QUOTENAME(@tableName);
SET @ProductMasterFull = QUOTENAME(N'dbo') + N'.' + QUOTENAME(N'tbl_productmaster_' + CAST(@ParentID AS NVARCHAR(20)));
  
  
 SELECT @DynamicColumns = STRING_AGG(column_name, ',')  
 FROM INFORMATION_SCHEMA.COLUMNS  
 WHERE table_name = @tableName  
 AND column_name NOT IN (  
 'TicketID', 'tpUser_Id', 'ParentID', 'RequesterMobileNo','CountryCode', 'RequesterEmailID',  
 'RequesterMobileNo1','CountryCode1', 'RequesterEmailID1', 'RequesterMobileNo2','CountryCode2', 'RequesterEmailID2',  
 'Subject', 'Description', 'TicketStatusID', 'Remarks', 'Note', 'UserResponse',  
 'TicketPriority', 'AssignedUser', 'AssignedGroup', 'AssignedSource', 'TicketCategoryId',  
 'TicketTypeId', 'TicketSourceId', 'ProductId', 'IsMerged', 'IsSplitted', 'IsParentTicket',  
 'IsChildTicket', 'ParentTicketID', 'LastActionDatetime', 'AssignedBy', 'AssignedDateTime',  
 'TicketTag', 'EntityID', 'EntityName', 'Company', 'IsActive', 'CreatedBy', 'CreatedOn',  
 'ModifiedBy', 'ModifiedOn', 'SplittedBy', 'SplittedOn', 'MergedBy', 'MergedOn',  
 'ClosedBy', 'ClosedOn', 'CreatedChildBy', 'CreatedChildOn'  
 )  
  AND column_name NOT IN (  
  SELECT JSON_VALUE([value], '$.FieldName') AS inActiveFieldNames
  FROM tbL_tp_TicketCustomFieldDisplayJson dj
  CROSS APPLY OPENJSON(dj.[DisplayJson])
  WHERE JSON_VALUE([value], '$.Active') = 'false'
);

 -- JK-OPT: Dynamic columns safe handling (avoid empty/NULL causing double commas)
 SET @DynamicColumns = ISNULL(@DynamicColumns, N'');
 SET @DynColsSelect = CASE WHEN NULLIF(LTRIM(RTRIM(@DynamicColumns)), N'') IS NULL THEN N'' ELSE N', ' + @DynamicColumns END;

 print concat('@Priority: ',@Priority)  
 print concat('@TagId: ',@TagId)  
 print concat('@Type: ',@Type)  
 print concat('@CreatedInterval: ',@CreatedInterval)  
 print concat('@ClosedInterval: ',@ClosedInterval)  
 print concat('@StrWhere: ',@StrWhere)  
   
 drop table if exists #tmpTBLSort    
    
 IF @SortField IS NOT NULL  
 BEGIN  
  print 'a'  
  
  SET @DynamicSQL = N'  
  WITH AggregatedAttachments AS  
  (  
  SELECT  
  TicketID,  
  (COUNT(TicketAttachmentID) - 1) AS TotalAttachments,  
  STRING_AGG(ISNULL(TAM.TicketAttachmentID, ''No Attachment Available''), '', '') AS TicketAttachmentID,  
  STRING_AGG(ISNULL(TAM.DisplayName, ''No Attachment Available''), '', '') AS AggregatedDisplayNames,  
  STRING_AGG(ISNULL(TAM.FileUrl, ''''), '', '') AS AggregatedFileUrls,  
  MIN(ISNULL(TAM.DisplayName, ''No Attachment Available'')) AS SingleDisplayName,  
  MIN(ISNULL(TAM.FileUrl, '''')) AS SingleFileUrl  
  FROM tbl_tp_TicketAttachment TAM (NOLOCK)  
  WHERE TAM.IsActive = 1  and TAM.ParentId=@Parent_ID
  GROUP BY TicketID  
  )  
  
  SELECT  
  ROW_NUMBER() OVER (ORDER BY ISNULL(TM.ModifiedOn, TM.CreatedOn) DESC) RecNo,  
  COUNT(*) OVER (ORDER BY TM.ParentID) TotalCount,  
  TM.TicketID,  
  TM.tpUser_Id,  
  ISNULL(TUL.Name, ''UnKnown'') AS Name,  
  TM.ParentId,  
  --tm.TicketNo ,    
  TM.EntityID,  
  TM.EntityName,  
  TM.ParentTicketID,  
  SGM.GroupName,  
  TM.AssignedGroup,  
  TM.ClosedOn,  
  CASE  
  WHEN TM.EntityName = ''Lead'' THEN UL.PersonName  
  WHEN TM.EntityName = ''Enquiry'' THEN UE.PersonName  
  ELSE ''Unknown''  
  END AS RequesterName,  
  RequesterMobileNo,
  RequesterMobileNo1,
  RequesterMobileNo2,
  TM.CountryCode,
  TM.CountryCode1,
  TM.CountryCode2,
  RequesterEmailID,
  RequesterEmailID1,
  RequesterEmailID2,
  --SGM.GroupName,    
  TM.Company,  
  TM.Subject,  
  TM.Description,  
  TM.TicketStatusID,  
  TSM.TicketStatus,  
  TM.TicketPriority,  
  TPM.PriorityName,  
  TUL.Name AS AssignedUser,  
  TM.TicketSourceId,  
  TSOM.TicketSourceName,  
  TicketTypeId,  
  TTM.Type_Name,  
  dbo.fn_ConvertDateTime(TM.CreatedOn, @Time_Zone, 0) AS CreatedOn,  
  dbo.fn_ConvertDateTime(TM.ModifiedOn, @Time_Zone, 0) AS ModifiedOn,  
  TM.IsActive,  
    		(
    SELECT
        ISNULL(
            NULLIF(
                JSON_QUERY(
                    (
                        SELECT
                            DisplayName AS ''FileName'',
                            FileUrl AS ''FilePath''
                        FROM tbl_tp_TicketAttachment
                        WHERE TicketID = TM.TicketID and ParentId= TM.ParentId
                            AND IsActive = 1
                            AND DisplayName IS NOT NULL AND DisplayName <> ''''
                            AND FileUrl IS NOT NULL AND FileUrl <> ''''
                        FOR JSON PATH
                    )
                ),
                ''[]''
            ),
            ''''
        )
) AS Attachement,
  TM.ProductId,  
  TM.TicketCategoryId,  
  IsParentTicket,  
  ISNULL(AA.AggregatedDisplayNames, ''No Attachment Available'') DisplayName,  
  ISNULL(AA.AggregatedFileUrls, '''') FileUrl,  
  ISNULL(AA.SingleDisplayName, ''No Attachment Available'') SingleAttachmentDisplayName,  
  AA.SingleFileUrl AS SingleAttachmentFileUrl,  
  AA.AggregatedDisplayNames,  
  AA.AggregatedFileUrls,  
  AA.TicketAttachmentID,  
  AA.TotalAttachments,  
  ' + @DynamicColumns + ',  
  ISNULL((SELECT STRING_AGG(Name, '','') AS Products
         FROM tbl_productmaster_' + CAST(@ParentId AS NVARCHAR(10)) + '(nolock)
         WHERE ProductID IN (
             SELECT value
             FROM STRING_SPLIT(
                 (SELECT STRING_AGG(ProductID, '','') 
                 FROM tbl_tp_TicketProducts (NOLOCK) 
                 WHERE TicketID = TM.TicketID AND IsActive = 1), '',''
             )
         )),'''') AS Products, 
  (  
  SELECT STRING_AGG(Tag, '', '')  
  FROM TagMaster  
  WHERE ID IN (SELECT value FROM STRING_SPLIT(TM.TicketTag, '',''))  
  ) AS Tags into #tmpTBLSort    
  FROM ' + @tableName + ' TM (NOLOCK)  
  LEFT JOIN tbl_tp_UserLogin TUL (NOLOCK) ON TUL.TpUser_Id = isnull(nullif(TM.AssignedUser,0),TM.CreatedBy) AND TUL.IsActive = 1  
  LEFT JOIN tbl_tp_TicketStatusMaster TSM (NOLOCK) ON TM.TicketStatusID = TSM.TicketStatus_ID  
  LEFT JOIN tbl_tp_TicketType_Master TTM (NOLOCK) ON TM.TicketTypeId = TTM.Type_ID  
  LEFT JOIN tbl_tp_TicketPriorityMaster TPM (NOLOCK) ON TM.TicketPriority = TPM.Priority_ID  
  LEFT JOIN tbl_tp_TicketSourceMaster TSOM (NOLOCK) ON TM.TicketSourceId = TSOM.TicketSourceId  
  LEFT JOIN AggregatedAttachments AA (NOLOCK) ON TM.TicketID = AA.TicketID  
  LEFT JOIN tbl_tp_GroupMaster SGM (NOLOCK) ON SGM.GroupId = TM.AssignedGroup  
  LEFT JOIN UserLeads UL (NOLOCK) ON TM.EntityID = UL.ID AND TM.EntityName = ''Lead''  
  LEFT JOIN UserEnquiry UE (NOLOCK) ON TM.EntityID = UE.EnquiryID AND TM.EntityName = ''Enquiry''  
  Left join tbl_tp_SlaReapplyHistory SRH (nolock) ON TM.TicketID = SRH.TicketID and TM.ParentId = SRH.ParentId and SRH.IsActive=1
  Left join tbl_tp_SLADetail SLD (nolock) ON SRH.slaID=SLD.SLA_ID and TM.TicketPriority=SLD.Priority_ID and SLD.IsActive=1
  WHERE  
  (@Parent_ID IS NULL OR TM.ParentId = @Parent_ID)  
  AND (@Category_Id IS NULL OR TM.TicketCategoryId = @Category_Id)  
  AND (@Type_Id IS NULL OR TM.TicketTypeId = @Type_Id)  
  AND (@Group_Id IS NULL OR TM.AssignedGroup = @Group_Id)  
  AND (@Priority_Id IS NULL OR TM.TicketPriority = @Priority_Id)  
  AND (@Company_Name IS NULL OR ISNULL(TM.Company, '''') LIKE ''%' + @Company + '%'')  
  AND (@Created_Interval IS NULL OR TM.CreatedOn >= DATEADD(MINUTE, -@Created_Interval, GETDATE()))  
  AND (@Closed_Interval IS NULL OR (TM.ClosedOn >= DATEADD(MINUTE, -@Closed_Interval, GETDATE()) AND ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) in (3,5)))  
  --AND (TM.EntityName = ''Lead'' OR TM.EntityName = ''Enquiry'')  
  AND TM.IsActive = 1  
  ' +   
  --CASE WHEN @IsAdmin = 0 THEN ' AND TM.AssignedUser = ' + CAST(@TpuserId AS NVARCHAR(MAX)) ELSE '' END + Case when @AccessType='AssignedToGroup' then ' and TM.AssignedGroup in (' + @StrGroupIds + ')' else '' end   
  @StrWhere  
  + N'  
  AND (@Tag_Id IS NULL OR TM.TicketID IN ( SELECT EntityID FROM EntityTagMapping  
  WHERE ParentID = ' + CAST(@ParentID AS NVARCHAR(MAX)) + '  
  AND TagID = ' + COALESCE(CAST(@TagId AS NVARCHAR(MAX)), 'NULL') + '  
  AND Entity = ''Ticket'')) ' + @SqlWhere + '  
  AND (@Product_Id IS NULL OR TM.TicketID IN (SELECT TicketID FROM tbl_tp_TicketProducts  
  WHERE ParentId = ' + CAST(@ParentID AS NVARCHAR(MAX)) + '  
  AND IsActive = 1))' + 
      CASE                                                      
        WHEN @Predinedview = 'Tickets raised today' THEN N' AND cast(TM.CreatedOn as DATE)=CAST(GETDATE() AS DATE)'  
        WHEN @Predinedview = 'Tickets assigned to me' THEN N' AND TM.Assigneduser=' + CAST(@TpUserId AS NVARCHAR(MAX))  
        WHEN @Predinedview = 'Tickets assigned to me today' THEN N' AND TM.AssignedUser = ' + CAST(@TpUserId AS NVARCHAR(MAX)) + N' AND CAST(TM.AssignedDateTime AS DATE) = CAST(GETDATE() AS DATE)'  
		WHEN @Predinedview = 'Tickets assigned to my group today' THEN iif(@IsAdmin =1,N'', N' AND TM.AssignedGroup in ('+@StrGroupIds+N') = AND CAST(TM.AssignedDateTime AS DATE) = CAST(GETDATE() AS DATE)')  
		WHEN @Predinedview = 'Unassigned tickets' THEN N' AND isnull(TM.AssignedUser,0)=0 and IsNull(TM.AssignedGroup,0)=0 '  
		WHEN @Predinedview = 'Tickets with response sla today' THEN N' AND isnull(TM.Remarks,'''') = '''' and  Cast(DateAdd(second,SLD.Respond_Sec,TM.CreatedOn) as Date) = Cast(getdate() as Date) '   
		WHEN @Predinedview = 'Tickets with resolution sla today' THEN N' AND ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) not in (3,5) and Cast(DateAdd(second,SLD.Resolve_Sec,TM.CreatedOn) as Date) = Cast(getdate() as Date) '                 
		WHEN @Predinedview = 'Unreplied tickets' THEN N' AND isnull(TM.Remarks,'''')='''' '                 
		WHEN @Predinedview = 'Tickets with overdue response' THEN N' AND isnull(TM.Remarks,'''') = '''' and  Cast(DateAdd(second,SLD.Respond_Sec,TM.CreatedOn) as Date) < Cast(getdate() as Date) '
		WHEN @Predinedview = 'Tickets with overdue resolution' THEN N' AND ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) not in (3,5) and Cast(DateAdd(second,SLD.Resolve_Sec,TM.CreatedOn) as Date) < Cast(getdate() as Date) '  
		WHEN @Predinedview = 'Open Tickets' THEN N' AND ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) = 2'  
        WHEN @Predinedview = 'Tickets raised by me' THEN N' AND TM.tpUser_Id='  + CAST(@TpUserId AS NVARCHAR(MAX))  
		WHEN @Predinedview = 'High Priority Tickets assigned to me' THEN N' AND TPM.PriorityName LIKE ''%High%'' AND TM.AssignedUser = ' + CAST(@TpUserId AS NVARCHAR(MAX))  
		WHEN @Predinedview = 'Tickets Awaiting Customer Response' THEN N' AND isnull(TM.Remarks,'''')!='''' and isnull(TM.UserResponse,'''')='''' '  
		WHEN @Predinedview = 'Recently Updated Tickets' THEN N' AND  cast(TM.ModifiedOn as DATE) =  CAST(GETDATE() AS DATE)'  
		WHEN @Predinedview = 'Closed Tickets' THEN N' AND ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) = 3'
		WHEN @Predinedview = 'Tickets with Feedback Requested' THEN N' AND ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) = 3 and Tf.RatingId is null '
		WHEN @Predinedview = 'Escalated Tickets' THEN N' AND ( (isnull(TM.Remarks,'''') = '''' and  Cast(DateAdd(second,SLD.Respond_Sec,TM.CreatedOn) as Date) < Cast(getdate() as Date)) OR (ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) not in (3,5) and Cast(DateAdd(second,SLD.Resolve_Sec,TM.CreatedOn) as Date) < Cast(getdate() as Date)) ) '  
		WHEN @Predinedview = 'Tickets Open for over 24 hrs' THEN N' AND ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) = 2 AND DATEDIFF(HOUR, TM.CreatedOn, GETDATE()) > 24'                 
            ELSE N''
  
     END + ' 
  ORDER BY '+  
  CASE  
  WHEN @SortField = 'DateCreated' THEN 'TM.CreatedOn'  
  WHEN @SortField = 'Status' THEN 'CAST(TM.TicketStatusID AS VARCHAR(255))'  
  WHEN @SortField = 'TicketNo' THEN 'TicketNo'  
  WHEN @SortField = 'Subject' THEN 'Subject'  
  WHEN @SortField = 'Description' THEN 'Description'  
  WHEN @SortField = 'AssignGroup' THEN 'SGM.GroupName'  
  WHEN @SortField = 'Requester' THEN 'ISNULL(UL.PersonName, UE.PersonName)'  
  WHEN @SortField = 'TicketType' THEN 'TTM.Type_Name'  
  WHEN @SortField = 'Priority' THEN 'TPM.PriorityName'  
  WHEN @SortField = 'Desc' THEN 'ISNULL(TM.ModifiedOn, TM.CreatedOn) desc'  
  WHEN @SortField = 'Asc' THEN 'ISNULL(TM.ModifiedOn, TM.CreatedOn) '  
  WHEN @SortField = 'Resolveddt' THEN 'TM.ClosedOn'  
  WHEN @SortField = 'AssignedDateTime' THEN 'TM.AssignedDateTime'  
  ELSE 'TM.TicketID DESC'  
  END + ' ; select * from #tmpTBLSort where RecNo between '  + CONVERT(NVARCHAR(max),(@Pageno - 1)*@offset + 1 ) + N' AND ' + CONVERT(NVARCHAR(max), @offset * @Pageno)        
  PRINT CAST(@DynamicSQL AS VARCHAR(MAX));  
 END  
 
ELSE  
BEGIN  
    -----------------------------------------------------------------------
    -- JK-OPT: SortField IS NULL => Page-first then enrich
    -- Goal: avoid processing/sorting all rows; do heavy work only for the page.
    -----------------------------------------------------------------------
    PRINT 'b (JK-OPT - Page first then enrich)';

    -----------------------------------------------------------------------
    -- JK-OPT: Access filter builder (keeps old behaviour)
    -----------------------------------------------------------------------
    DECLARE @AccessFilter NVARCHAR(MAX) = N'';
    IF (@IsAdmin = 0)
    BEGIN
        IF (@AccessType = 'AssignedToGroup')
        BEGIN
            IF NULLIF(@StrGroupIds,'') IS NULL
                SET @AccessFilter = N' AND 1=0 '; -- no groups => no rows
            ELSE
                SET @AccessFilter = N' AND TM.AssignedGroup IN (' + @StrGroupIds + N') ';
        END
        ELSE
            SET @AccessFilter = N' AND TM.AssignedUser = @TpUserId ';
    END

    -----------------------------------------------------------------------
    -- JK-OPT: PredinedView filter builder (fixed bug + removed UDF)
    -----------------------------------------------------------------------
    DECLARE @PredWhere NVARCHAR(MAX) = N'';
    SET @PredWhere =
    CASE
        WHEN @Predinedview = 'Tickets raised today' THEN N' AND CAST(TM.CreatedOn AS DATE)=CAST(GETDATE() AS DATE)'
        WHEN @Predinedview = 'Tickets assigned to me' THEN N' AND TM.AssignedUser = @TpUserId'
        WHEN @Predinedview = 'Tickets assigned to me today' THEN N' AND TM.AssignedUser = @TpUserId AND CAST(TM.AssignedDateTime AS DATE) = CAST(GETDATE() AS DATE)'
        WHEN @Predinedview = 'Tickets assigned to my group today'
             THEN CASE WHEN @IsAdmin = 1 OR NULLIF(@StrGroupIds,'') IS NULL
                       THEN N''
                       ELSE N' AND TM.AssignedGroup IN (' + @StrGroupIds + N') AND CAST(TM.AssignedDateTime AS DATE) = CAST(GETDATE() AS DATE)'
                  END
        WHEN @Predinedview = 'Unassigned tickets' THEN N' AND ISNULL(TM.AssignedUser,0)=0 AND ISNULL(TM.AssignedGroup,0)=0'
        WHEN @Predinedview = 'Tickets with response sla today' THEN N' AND ISNULL(TM.Remarks,'''') = '''' AND CAST(DATEADD(SECOND,SLD.Respond_Sec,TM.CreatedOn) AS DATE)=CAST(GETDATE() AS DATE)'
        WHEN @Predinedview = 'Tickets with resolution sla today' THEN N' AND ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) NOT IN (3,5) AND CAST(DATEADD(SECOND,SLD.Resolve_Sec,TM.CreatedOn) AS DATE)=CAST(GETDATE() AS DATE)'
        WHEN @Predinedview = 'Unreplied tickets' THEN N' AND ISNULL(TM.Remarks,'''')='''' '
        WHEN @Predinedview = 'Tickets with overdue response' THEN N' AND ISNULL(TM.Remarks,'''') = '''' AND CAST(DATEADD(SECOND,SLD.Respond_Sec,TM.CreatedOn) AS DATE) < CAST(GETDATE() AS DATE)'
        WHEN @Predinedview = 'Tickets with overdue resolution' THEN N' AND ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) NOT IN (3,5) AND CAST(DATEADD(SECOND,SLD.Resolve_Sec,TM.CreatedOn) AS DATE) < CAST(GETDATE() AS DATE)'
        WHEN @Predinedview = 'Open Tickets' THEN N' AND ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) = 2'
        WHEN @Predinedview = 'Tickets raised by me' THEN N' AND TM.tpUser_Id = @TpUserId'
        WHEN @Predinedview = 'High Priority Tickets assigned to me' THEN N' AND TPM.PriorityName LIKE ''%High%'' AND TM.AssignedUser = @TpUserId'
        WHEN @Predinedview = 'Tickets Awaiting Customer Response' THEN N' AND ISNULL(TM.Remarks,'''')<>'''' AND ISNULL(TM.UserResponse,'''')='''' '
        WHEN @Predinedview = 'Recently Updated Tickets' THEN N' AND CAST(TM.ModifiedOn AS DATE) = CAST(GETDATE() AS DATE)'
        WHEN @Predinedview = 'Closed Tickets' THEN N' AND ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) = 3'
        WHEN @Predinedview = 'Tickets with Feedback Requested' THEN N' AND ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) = 3 AND Tf.RatingId IS NULL'
        WHEN @Predinedview = 'Escalated Tickets'
             THEN N' AND ( (ISNULL(TM.Remarks,'''') = '''' AND CAST(DATEADD(SECOND,SLD.Respond_Sec,TM.CreatedOn) AS DATE) < CAST(GETDATE() AS DATE)) OR
                           (ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) NOT IN (3,5) AND CAST(DATEADD(SECOND,SLD.Resolve_Sec,TM.CreatedOn) AS DATE) < CAST(GETDATE() AS DATE)) )'
        WHEN @Predinedview = 'Tickets Open for over 24 hrs' THEN N' AND ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) = 2 AND DATEDIFF(HOUR, TM.CreatedOn, GETDATE()) > 24'
        ELSE N''
    END;

    -----------------------------------------------------------------------
    -- JK-OPT: Dynamic SQL - page-first then enrich
    -----------------------------------------------------------------------
    SET @DynamicSQL = N'
DROP TABLE IF EXISTS #Filtered;

-- 1) Narrow filter set first (TicketID + SortDate)
SELECT
    TM.TicketID,
    SortDate = ISNULL(TM.ModifiedOn, TM.CreatedOn)
INTO #Filtered
FROM ' + @TicketMasterFull + N' TM WITH (NOLOCK)
LEFT JOIN dbo.tbl_tp_TicketStatusMaster TSM WITH (NOLOCK) ON TM.TicketStatusID = TSM.TicketStatus_ID
LEFT JOIN dbo.tbl_tp_TicketPriorityMaster TPM (NOLOCK) ON TM.TicketPriority = TPM.Priority_ID
LEFT JOIN dbo.tbl_tp_TicketRatingFeedback Tf (NOLOCK) ON TM.TicketID = Tf.TicketID AND TM.ParentId = Tf.ParentId
LEFT JOIN dbo.tbl_tp_SlaReapplyHistory SRH (NOLOCK) ON TM.TicketID = SRH.TicketID AND TM.ParentId = SRH.ParentId AND SRH.IsActive=1
LEFT JOIN dbo.tbl_tp_SLADetail SLD (NOLOCK) ON SRH.slaID = SLD.SLA_ID AND TM.TicketPriority = SLD.Priority_ID AND SLD.IsActive=1
WHERE
    (@Parent_ID IS NULL OR TM.ParentId = @Parent_ID)
    AND (@Category_Id IS NULL OR TM.TicketCategoryId = @Category_Id)
    AND (@Type_Id IS NULL OR TM.TicketTypeId = @Type_Id)
    AND (@Group_Id IS NULL OR TM.AssignedGroup = @Group_Id)
    AND (@Priority_Id IS NULL OR TM.TicketPriority = @Priority_Id)
    AND (@Company_Name IS NULL OR ISNULL(TM.Company, N'''') LIKE N''%'' + @Company_Name + N''%'')
    AND (@Created_Interval IS NULL OR TM.CreatedOn >= DATEADD(MINUTE, -@Created_Interval, GETDATE()))
    AND (@Closed_Interval IS NULL OR (TM.ClosedOn >= DATEADD(MINUTE, -@Closed_Interval, GETDATE()) AND ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) IN (3,5)))
    AND TM.IsActive = 1
' + @StrWhere + N'
' + @AccessFilter + N'
    AND (@Tag_Id IS NULL OR EXISTS (
        SELECT 1
        FROM dbo.EntityTagMapping etm WITH (NOLOCK)
        WHERE etm.ParentId = @Parent_ID AND etm.Entity = ''Ticket''
          AND etm.EntityID = TM.TicketID AND etm.TagID = @Tag_Id
    ))
    AND (@Product_Id IS NULL OR EXISTS (
        SELECT 1
        FROM dbo.tbl_tp_TicketProducts ttp WITH (NOLOCK)
        WHERE ttp.ParentId = @Parent_ID AND ttp.TicketID = TM.TicketID
          AND ttp.IsActive = 1 AND ttp.ProductID = @Product_Id
    ))
' + @SqlWhere + N'
' + @PredWhere + N'
;

DECLARE @TotalCount BIGINT = (SELECT COUNT_BIG(*) FROM #Filtered);

;WITH PageTickets AS
(
    SELECT TicketID, SortDate
    FROM #Filtered
    ORDER BY SortDate DESC, TicketID DESC
    OFFSET @OffsetRows ROWS FETCH NEXT @FetchRows ROWS ONLY
),
AggAttach AS
(
    SELECT
        A.TicketID,
        TotalAttachments = (COUNT(*) - 1),
        TicketAttachmentID     = STRING_AGG(CAST(A.TicketAttachmentID AS NVARCHAR(MAX)), '',''),
        AggregatedDisplayNames = STRING_AGG(ISNULL(A.DisplayName, ''No Attachment Available''), '',''),
        AggregatedFileUrls     = STRING_AGG(ISNULL(A.FileUrl, ''''), '',''),
        SingleDisplayName      = MIN(ISNULL(A.DisplayName, ''No Attachment Available'')),
        SingleFileUrl          = MIN(ISNULL(A.FileUrl, ''''))
    FROM dbo.tbl_tp_TicketAttachment A WITH (NOLOCK)
    JOIN PageTickets P ON P.TicketID = A.TicketID
    WHERE A.ParentId = @Parent_ID AND A.IsActive = 1
    GROUP BY A.TicketID
),
LastHistory AS
(
    SELECT TicketID, ParentID, UserResponse, Remarks, AssignedBy,
           RemarkType = CASE WHEN Remarks IS NOT NULL THEN ''A'' ELSE ''C'' END
    FROM
    (
        SELECT TH.*,
               rn = ROW_NUMBER() OVER (PARTITION BY TH.ParentID, TH.TicketID ORDER BY TH.TicketHistoryID DESC)
        FROM dbo.tbl_tp_TicketHistory TH WITH (NOLOCK)
        JOIN PageTickets P ON P.TicketID = TH.TicketID
        WHERE TH.ParentID = @Parent_ID
          AND (TH.Remarks IS NOT NULL OR TH.UserResponse IS NOT NULL)
    ) X
    WHERE rn = 1
),
TagsAgg AS
(
    SELECT etm.EntityID AS TicketID,
           Tags = STRING_AGG(CAST(tgm.Tag AS NVARCHAR(MAX)), '','')
    FROM dbo.EntityTagMapping etm WITH (NOLOCK)
    JOIN PageTickets P ON P.TicketID = etm.EntityID
    LEFT JOIN dbo.TagMaster tgm WITH (NOLOCK) ON tgm.ID = etm.TagID
    WHERE etm.ParentId = @Parent_ID AND etm.Entity = ''Ticket''
    GROUP BY etm.EntityID
)

SELECT
    RecNo      = @OffsetRows + ROW_NUMBER() OVER (ORDER BY P.SortDate DESC, TM.TicketID DESC),
    TotalCount = @TotalCount,

    TM.TicketID,
    TM.tpUser_Id,
    ISNULL(TUL.Name, ''UnKnown'') AS Name,
    TM.ParentId,
    TM.EntityID,
    TM.EntityName,
    TM.ParentTicketID,
    SGM.GroupName,
    TM.AssignedGroup,
    TM.AssignedUser AS AssignedUserId,
    CASE
        WHEN TM.EntityName = ''Lead'' THEN UL.PersonName
        WHEN TM.EntityName = ''Enquiry'' THEN UE.PersonName
        ELSE ''Unknown''
    END AS RequesterName,
    TM.RequesterMobileNo,
    TM.RequesterMobileNo1,
    TM.RequesterMobileNo2,
    TM.CountryCode,
    TM.CountryCode1,
    TM.CountryCode2,
    TM.RequesterEmailID,
    TM.RequesterEmailID1,
    TM.RequesterEmailID2,
    TM.Company,
    TM.Subject,
    TM.Description,
    TSM.ParentStatus_Id,
    TM.TicketStatusID,
    TSM.TicketStatus,
    TM.TicketPriority,
    TPM.PriorityName,
    TUL.Name AS AssignedUser,
    TM.TicketSourceId,
    TSOM.TicketSourceName,
    TM.TicketTypeId,
    TTM.Type_Name,
    dbo.fn_ConvertDateTime(TM.CreatedOn, @Time_Zone, 0) AS CreatedOn,
    dbo.fn_ConvertDateTime(TM.ModifiedOn, @Time_Zone, 0) AS ModifiedOn,
    TM.IsActive,
    TM.ProductId,
    TM.TicketCategoryId,
    TM.IsParentTicket,
    ISNULL(LH.UserResponse, LH.Remarks) AS LastRemark,
    LH.RemarkType,
    ISNULL(LH.AssignedBy, 0) AS RemarkBy,
    ISNULL(AA.AggregatedDisplayNames, ''No Attachment Available'') AS DisplayName,
    ISNULL(AA.AggregatedFileUrls, '''') AS FileUrl,
    ISNULL(AA.SingleDisplayName, ''No Attachment Available'') AS SingleAttachmentDisplayName,
    AA.SingleFileUrl AS SingleAttachmentFileUrl,
    AA.AggregatedDisplayNames,
    AA.AggregatedFileUrls,
    AA.TicketAttachmentID,
    AA.TotalAttachments' + @DynColsSelect + N',
    TM.TicketNo,
    ISNULL(TG.Tags, '''') AS Tags,
    ISNULL(PR.Products, '''') AS Products,

    CASE
        WHEN TSM.TicketStatus = ''New'' AND DATEDIFF(HOUR, TM.CreatedOn, GETDATE()) < 24 THEN ''New Ticket''
        WHEN TSM.TicketStatus = ''Spam'' THEN ''Spam''
        WHEN TSM.TicketStatus = ''Close'' THEN ''Ticket Closed''
        WHEN TSM.TicketStatus = ''Invalid'' THEN ''Invalid''
        WHEN TSM.TicketStatus = ''Waiting on Customer'' THEN ''Waiting on Customer Response''
        WHEN TSM.TicketStatus = ''Waiting On Third Party'' THEN ''ON HOLD''
        WHEN ISNULL(TM.Remarks,'''') = '''' AND CAST(DATEADD(SECOND,SLD.Respond_Sec,TM.CreatedOn) AS DATE) = CAST(GETDATE() AS DATE) THEN ''First Response Due Soon''
        WHEN ISNULL(TM.Remarks,'''') = '''' AND CAST(DATEADD(SECOND,SLD.Respond_Sec,TM.CreatedOn) AS DATE) < CAST(GETDATE() AS DATE) THEN ''First Response Overdue''
        WHEN TM.TicketId = Tf.TicketId THEN ''Feedback Requested''
        WHEN LH.RemarkType <> ''A'' AND TPM.PriorityName LIKE ''%High%'' THEN ''High Priority''
        WHEN LH.RemarkType <> ''A'' AND TPM.PriorityName LIKE ''%Low%''  THEN ''Low Priority''
        WHEN LH.UserResponse IS NOT NULL THEN ''Customer Responded''
        WHEN ( (ISNULL(TM.Remarks,'''') = '''' AND CAST(DATEADD(SECOND,SLD.Respond_Sec,TM.CreatedOn) AS DATE) < CAST(GETDATE() AS DATE))
            OR (ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) NOT IN (3,5) AND CAST(DATEADD(SECOND,SLD.Resolve_Sec,TM.CreatedOn) AS DATE) < CAST(GETDATE() AS DATE)) ) THEN ''Escalated Ticket''
        WHEN TSM.TicketStatus = ''Reopened'' THEN ''Reopened Ticket''
        WHEN TM.AssignedUser IS NOT NULL AND LH.RemarkType <> ''A'' THEN ''Assigned to Agent''
        WHEN TSM.TicketStatus NOT IN (''Close'',''Resolved'') AND LH.RemarkType = ''A'' THEN ''Agent Responded''
        WHEN TSM.TicketStatus = ''Resolution in Progress'' THEN ''Resolution in Progress''
        WHEN TSM.TicketStatus = ''Resolution Submitted'' THEN ''Resolution Submitted''
        WHEN TSM.TicketStatus = ''SLA Breached'' THEN ''SLA Breached''
        WHEN TSM.TicketStatus <> ''Ticket Closed'' AND TM.AssignedUser IS NOT NULL AND LH.Remarks IS NULL
             AND DATEDIFF(HOUR, TM.CreatedOn, GETDATE()) > 24 THEN ''Pending Agent Action''
        ELSE ''''
    END AS TicketCustomTag,

    (
        SELECT ISNULL(
            NULLIF(JSON_QUERY((
                SELECT A2.DisplayName AS FileName, A2.FileUrl AS FilePath
                FROM dbo.tbl_tp_TicketAttachment A2 WITH (NOLOCK)
                WHERE A2.TicketID = TM.TicketID AND A2.ParentId = TM.ParentId
                  AND A2.IsActive = 1
                  AND A2.DisplayName IS NOT NULL AND A2.DisplayName <> ''''
                  AND A2.FileUrl IS NOT NULL AND A2.FileUrl <> ''''
                FOR JSON PATH
            )), ''[]''),
        '''')
    ) AS Attachement

FROM PageTickets P
JOIN ' + @TicketMasterFull + N' TM WITH (NOLOCK) ON TM.TicketID = P.TicketID
LEFT JOIN dbo.tbl_tp_UserLogin TUL WITH (NOLOCK) ON TUL.TpUser_Id = ISNULL(NULLIF(TM.AssignedUser, 0), TM.CreatedBy) AND TUL.IsActive = 1
LEFT JOIN dbo.tbl_tp_TicketStatusMaster TSM WITH (NOLOCK) ON TM.TicketStatusID = TSM.TicketStatus_ID
LEFT JOIN dbo.tbl_tp_TicketRatingFeedback Tf (NOLOCK) ON TM.TicketID = Tf.TicketID AND TM.ParentId = Tf.ParentId
LEFT JOIN dbo.tbl_tp_TicketType_Master TTM (NOLOCK) ON TM.TicketTypeId = TTM.Type_ID
LEFT JOIN dbo.tbl_tp_TicketPriorityMaster TPM (NOLOCK) ON TM.TicketPriority = TPM.Priority_ID
LEFT JOIN dbo.tbl_tp_TicketSourceMaster TSOM (NOLOCK) ON TM.TicketSourceId = TSOM.TicketSourceId
LEFT JOIN dbo.tbl_tp_GroupMaster SGM (NOLOCK) ON SGM.GroupId = TM.AssignedGroup
LEFT JOIN dbo.UserLeads UL (NOLOCK) ON TM.EntityID = UL.ID AND TM.EntityName = ''Lead''
LEFT JOIN dbo.UserEnquiry UE (NOLOCK) ON TM.EntityID = UE.EnquiryID AND TM.EntityName = ''Enquiry''
LEFT JOIN dbo.tbl_tp_SlaReapplyHistory SRH (NOLOCK) ON TM.TicketID = SRH.TicketID AND TM.ParentId = SRH.ParentId AND SRH.IsActive=1
LEFT JOIN dbo.tbl_tp_SLADetail SLD (NOLOCK) ON SRH.slaID = SLD.SLA_ID AND TM.TicketPriority = SLD.Priority_ID AND SLD.IsActive=1
LEFT JOIN AggAttach AA ON AA.TicketID = TM.TicketID
LEFT JOIN LastHistory LH ON LH.TicketID = TM.TicketID AND LH.ParentID = TM.ParentID
LEFT JOIN TagsAgg TG ON TG.TicketID = TM.TicketID
OUTER APPLY
(
    SELECT Products = ISNULL(STRING_AGG(CAST(pm.Name AS NVARCHAR(MAX)), '',''), '''')
    FROM dbo.tbl_tp_TicketProducts ttp WITH (NOLOCK)
    JOIN ' + @ProductMasterFull + N' pm WITH (NOLOCK) ON pm.ProductID = ttp.ProductID
    WHERE ttp.ParentId = TM.ParentId AND ttp.TicketID = TM.TicketID AND ttp.IsActive = 1
) PR
ORDER BY P.SortDate DESC, TM.TicketID DESC;
';

    PRINT CAST(@DynamicSQL AS VARCHAR(MAX));
END  

EXEC sp_executesql @DynamicSQL,  
 N'  
 @Parent_ID BIGINT,  
 @Category_Id BIGINT,  
 @Product_Id BIGINT,  
 @Type_Id BIGINT,  
 @Created_Interval BIGINT,  
 @Closed_Interval BIGINT,  
 @Time_Zone NVARCHAR(400),  
 @Sort_Field NVARCHAR(20),  
 @Group_Id BIGINT,  
 @Priority_Id BIGINT,  
 @Company_Name NVARCHAR(300),  
 @Tag_Id BIGINT,
 @TpUserId BIGINT,
 @OffsetRows INT,
 @FetchRows INT',  
 @ParentID, @CategoryId, @ProductId, @Type, @CreatedInterval, @ClosedInterval, @TimeZone, @SortField, @Group, @Priority, @Company, @TagId,
 @TpUserId, @OffsetRows, @FetchRows  
   
 EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData
 @User_id = @UserId,  
 @Activity_type = 'View_manageticketmaster',  
 @ActionType = 'S',  
 @RowJson = 'NULL',  
 @Table_name = @tableName,  
 @ip_adress = @IPAdress,  
 @device_id = @DeviceId,  
 @IsImpersonation = @IsImpersonation,  
 @ImpersonatorId = @ImpersonatorId  
  
END TRY  
BEGIN CATCH  
 PRINT 'Error occurred: ' + ERROR_MESSAGE()  
END CATCH  
END   
  















GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_GetManageTicketDetails_JK_OptmzV2]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
-- exec Usp_tp_GetManageTicketDetails @SortField=N'',@ParentID=32222,@TpUserId=1,@Agent=0,@Group=0,@Priority=0,@Company=N'',@TagId=0,@CategoryId=0,@ProductId=0,@Type=0,@CreatedInterval=0,@ClosedInterval=0,@MetaData=N'{"IPAddress":"::1","MacAddress":"00FF61AD0C56","IsImpersonation":false,"ImpersonatorId":0}'         
-- exec Usp_tp_GetManageTicketDetails @SortField=N'',@ParentID=34594,@TpUserId=90,@Agent=0,@Group=0,@Priority=0,@Company=N'',@TagId=0,@CategoryId=0,@ProductId=0,@Type=0,@CreatedInterval=0,@ClosedInterval=0,@SqlWhere='',@MetaData=N'{"IPAddress":"::1","MacAddress":"00FF61AD0C56","IsImpersonation":false,"ImpersonatorId":0}'  
-- exec Usp_tp_GetManageTicketDetails @SortField=N'',@ParentID=34594,@TpUserId=110,@Agent=0,@Group=0,@Priority=0,@Company=N'',@TagId=0,@CategoryId=0,@ProductId=0,@Type=0,@CreatedInterval=0,@ClosedInterval=0,@MetaData=N'{"IPAddress":"::1","MacAddress":"00FF61AD0C56","IsImpersonation":false,"ImpersonatorId":0}'  
-- exec Usp_tp_GetManageTicketDetails @SortField=N'',@ParentID=34594,@TpUserId=110,@Agent=0,@Group=0,@Priority=0,@Company=N'',@TagId=0,@CategoryId=0,@ProductId=0,@Type=0,@CreatedInterval=0,@ClosedInterval=0, @SqlWhere=N'ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID)=2', @MetaData=N'{"IPAddress":"::1","MacAddress":"00FF61AD0C56","IsImpersonation":false,"ImpersonatorId":0}'  
-- exec Usp_tp_GetManageTicketDetails @SortField=N'Sort',@ParentID=32222,@TpUserId=1,@Agent=0,@Group=0,@Priority=0,@Company=N'',@TagId=0,@CategoryId=0,@ProductId=0,@Type=0,@CreatedInterval=86400,@ClosedInterval=0,@MetaData=N'{"IPAddress":"::1","MacAddress":"00FF61AD0C56","IsImpersonation":false,"ImpersonatorId":0}'  
-- exec Usp_tp_GetManageTicketDetails@SortField=N'Sort',@ParentID=32222,@TpUserId=1,@Agent=0,@Group=0,@Priority=0,@Company=N'0',@PageNo=1,@Pagesize=null,@TagId=0,@CategoryId=0,@ProductId=0,@Type=0,@CreatedInterval=259200,@ClosedInterval=0,@MetaData=N'{"IPAddress":"::1","MacAddress":"00FF61AD0C56","IsImpersonation":false,"ImpersonatorId":0}'  

CREATE   PROCEDURE [dbo].[Usp_tp_GetManageTicketDetails_JK_OptmzV2]  
(                                
 @SortField NVARCHAR(20) = NULL,  
 @Predinedview NVARCHAR(MAX) = NULL,  
 @ParentID BIGINT = NULL,  
 @TpUserId BIGINT = NULL,  
 @Agent BIGINT = NULL,  
 @Group BIGINT = NULL,  
 @Priority BIGINT = NULL,  
 @Company NVARCHAR(300) = NULL,  
 @TagId BIGINT = NULL,  
 @CategoryId BIGINT = NULL,  
 @Pageno NVARCHAR(100) = NULL,    
 @Pagesize NVARCHAR(100) = NULL,    
 @ProductId BIGINT = NULL,  
 @Type BIGINT = NULL,  
 @CreatedInterval BIGINT = NULL,  
 @ClosedInterval BIGINT = NULL,  
 @SqlWhere nvarchar(max) = NULL,  
 @MetaData NVARCHAR(200) = NULL  
)                                
AS                                
BEGIN  
BEGIN TRY  

--declare @SortField NVARCHAR(20) = N'',    
--  @Predinedview NVARCHAR(100) = N'',    
--  @ParentID BIGINT = 46831,  
--  @TpUserId BIGINT = 2338,    
--  @Agent BIGINT = 0,    
--  @Group BIGINT = 0,--15,    
--  @Priority BIGINT = 0,    
--  @Company NVARCHAR(300) = '',--N'test',    
--  @TagId BIGINT = 0,--54,    
--  @CategoryId BIGINT = 0,    
--  @Pageno NVARCHAR(100) = N'1',    
--  @Pagesize NVARCHAR(100) = null,    
--  @ProductId BIGINT = null,--0,    
--  @Type BIGINT = 0,--13,    
--  @CreatedInterval BIGINT = 0,    
--  @ClosedInterval BIGINT = 0,--0,    
--  @SqlWhere nvarchar(max) = N'ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) = 1', @MetaData NVARCHAR(200)=N'{"IPAddress":"::1","MacAddress":"00FF61AD0C56","IsImpersonation":false,"ImpersonatorId":0}'    
  
--declare @SortField NVARCHAR(20) = N'',@ParentID BIGINT = 34594,@TpUserId BIGINT = 91,@Agent BIGINT = 0,@Group BIGINT = 0,@Priority BIGINT = 0,@Company NVARCHAR(300) = N'',@TagId BIGINT = 0,@CategoryId BIGINT = 0,@ProductId BIGINT = 0,@Type BIGINT = 0,@CreatedInterval BIGINT = 0,@ClosedInterval BIGINT = 0,@SqlWhere nvarchar(max) = NULL,@MetaData NVARCHAR(200)=N'{"IPAddress":"::1","MacAddress":"00FF61AD0C56","IsImpersonation":false,"ImpersonatorId":0}'  
  
 DECLARE @TimeZone NVARCHAR(400), @rowJson NVARCHAR(MAX), @IPAdress NVARCHAR(50), @UserID BIGINT,   
   @DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT,   
   @ProductTableName NVARCHAR(100), @DynamicColumns NVARCHAR(MAX) = '' , @IsAdmin BIT = 0,  
   @TimeAgoCreated DATETIME = DATEADD(MINUTE, @CreatedInterval, GETDATE()),  
   @TimeAgoClosed DATETIME = DATEADD(MINUTE, -@ClosedInterval, GETDATE()),  
   @DynamicSQL NVARCHAR(MAX), @sqls NVARCHAR(MAX) = '', @status INT, @tableName NVARCHAR(MAX) = '',  
   @AccessType nvarchar(100)='', @StrGroupIds nvarchar(max)='', @StrWhere nvarchar(max)=' and 1=1 ',  
   @offset INT = 50,
   @PageNoInt INT = 1,
   @FetchRows INT = 50,
   @OffsetRows INT = 0,
   @TicketMasterFull NVARCHAR(300) = N'',
   @ProductMasterFull NVARCHAR(300) = N'',
   @DynColsSelect NVARCHAR(MAX) = N'';    
  
 SELECT @UserID = User_Id, @TimeZone = isnull(TimeZone,'India Standard Time'),   
   @IsAdmin = (CASE WHEN User_Id = ParentId THEN 1 ELSE 0 END)  
 FROM tbl_tp_UserLogin(nolock)   
 WHERE TpUser_Id = @TpUserId AND IsActive = 1  
  
 drop table if exists #tbl_tp_AgentGroupMapping  
  
 Select *  
 into #tbl_tp_AgentGroupMapping  
 from tbl_tp_AgentGroupMapping(nolock)   
 Where tpUserId=@TpUserId AND IsActive = 1  
  
 Select @AccessType=AccessType from #tbl_tp_AgentGroupMapping  
  
 If(@AccessType='GlobalAccess')  
 Begin  
  Set @IsAdmin=1  
 End  
 Else If(@AccessType='AssignedToGroup')  
 Begin  
  Select @StrGroupIds=STRING_AGG(isnull (nullif (GroupId,''),0),',') From #tbl_tp_AgentGroupMapping    
 End  
  
 print concat('@AccessType: ',@AccessType)  
 print concat('@IsAdmin: ',@IsAdmin)  
  
 IF (@CategoryId = 0)  
 SET @CategoryId = NULL                         
  
 IF (isnull(@Agent,0) = 0)  
 Begin  
  SET @Agent = NULL  
 End  
 Else  
 Begin  
  Set @StrWhere += concat(N' and TM.AssignedUser = ', @Agent)  
 End  
  
 IF (isnull(@Group,0) = 0)  
 Begin  
  SET @Group = NULL  
 End  
 Else  
 Begin  
  set @StrWhere += concat(N' and TM.AssignedGroup = ', @Group)  
 End  
  
 IF (isnull(@Priority,0) = 0)  
 Begin  
  SET @Priority = NULL  
 End  
  
 IF (@TagId = 0)  
 Begin  
  SET @TagId = NULL  
 End  
  
 IF (@ProductId = 0)  
 SET @ProductId = NULL  
  
 IF (isnull(@Type,0) = 0)  
 Begin  
  SET @Type = NULL  
 End  
  
 IF (@CreatedInterval = 0)  
 Begin  
  SET @CreatedInterval = NULL  
 End  
  
 IF (@ClosedInterval = 0)  
 Begin  
  SET @ClosedInterval = NULL  
 End  
  
 IF (@SortField = '')  
 SET @SortField = NULL  
  
 If (concat(@SqlWhere,'')='')  
 Begin  
  SET @SqlWhere=N' and 1=1 '  
 End  
 Else  
 Begin  
  SET @SqlWhere=N' and ' + @SqlWhere

-- JK-OPT: Safe paging defaults + conversions (Pagesize default 20 (client confirmed))
SET @FetchRows  = ISNULL(NULLIF(TRY_CONVERT(INT, @Pagesize), 0), 20);
SET @PageNoInt  = ISNULL(NULLIF(TRY_CONVERT(INT, @Pageno), 0), 1);
SET @OffsetRows = (@PageNoInt - 1) * @FetchRows;
SET @offset     = @FetchRows; -- keep old variable used in SortField branch

-- JK-OPT: Replace scalar UDF in @SqlWhere to join-based expression
SET @SqlWhere = REPLACE(@SqlWhere,
    'ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID)',
    'ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID)'
);
SET @SqlWhere = REPLACE(@SqlWhere,
    'ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID)',
    'ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID)'
);  
 End  
  
 EXEC @status = Usp_tp_CreateTicketMasterTableByParentID_jk @ParentID, @tableName OUTPUT

-- JK-OPT: Schema-qualified table names for dynamic SQL
SET @TicketMasterFull = QUOTENAME(N'dbo') + N'.' + QUOTENAME(@tableName);
SET @ProductMasterFull = QUOTENAME(N'dbo') + N'.' + QUOTENAME(N'tbl_productmaster_' + CAST(@ParentID AS NVARCHAR(20)));
  
  
 SELECT @DynamicColumns = STRING_AGG(column_name, ',')  
 FROM INFORMATION_SCHEMA.COLUMNS  
 WHERE table_name = @tableName  
 AND column_name NOT IN (  
 'TicketID', 'tpUser_Id', 'ParentID', 'RequesterMobileNo','CountryCode', 'RequesterEmailID',  
 'RequesterMobileNo1','CountryCode1', 'RequesterEmailID1', 'RequesterMobileNo2','CountryCode2', 'RequesterEmailID2',  
 'Subject', 'Description', 'TicketStatusID', 'Remarks', 'Note', 'UserResponse',  
 'TicketPriority', 'AssignedUser', 'AssignedGroup', 'AssignedSource', 'TicketCategoryId',  
 'TicketTypeId', 'TicketSourceId', 'ProductId', 'IsMerged', 'IsSplitted', 'IsParentTicket',  
 'IsChildTicket', 'ParentTicketID', 'LastActionDatetime', 'AssignedBy', 'AssignedDateTime',  
 'TicketTag', 'EntityID', 'EntityName', 'Company', 'IsActive', 'CreatedBy', 'CreatedOn',  
 'ModifiedBy', 'ModifiedOn', 'SplittedBy', 'SplittedOn', 'MergedBy', 'MergedOn',  
 'ClosedBy', 'ClosedOn', 'CreatedChildBy', 'CreatedChildOn',
 -- JK-FIX: Exclude TicketNo (already hardcoded in SELECT as TM.TicketNo) and
 --         SortDate (computed column exists in both TM and PageTickets CTE → ambiguous).
 --         Without this, @DynColsSelect injects unqualified 'TicketNo' and 'SortDate'
 --         causing: "Ambiguous column name 'SortDate'" + duplicate TicketNo column.
 'TicketNo', 'SortDate'
 )  
  AND column_name NOT IN (  
  SELECT JSON_VALUE([value], '$.FieldName') AS inActiveFieldNames
  FROM tbL_tp_TicketCustomFieldDisplayJson dj
  CROSS APPLY OPENJSON(dj.[DisplayJson])
  WHERE JSON_VALUE([value], '$.Active') = 'false'
);

 -- JK-OPT: Dynamic columns safe handling (avoid empty/NULL causing double commas)
 SET @DynamicColumns = ISNULL(@DynamicColumns, N'');
 SET @DynColsSelect = CASE WHEN NULLIF(LTRIM(RTRIM(@DynamicColumns)), N'') IS NULL THEN N'' ELSE N', ' + @DynamicColumns END;

 print concat('@Priority: ',@Priority)  
 print concat('@TagId: ',@TagId)  
 print concat('@Type: ',@Type)  
 print concat('@CreatedInterval: ',@CreatedInterval)  
 print concat('@ClosedInterval: ',@ClosedInterval)  
 print concat('@StrWhere: ',@StrWhere)  
   
 drop table if exists #tmpTBLSort    
    
 IF @SortField IS NOT NULL  
 BEGIN  
  print 'a'  
  
  SET @DynamicSQL = N'  
  WITH AggregatedAttachments AS  
  (  
  SELECT  
  TicketID,  
  (COUNT(TicketAttachmentID) - 1) AS TotalAttachments,  
  STRING_AGG(ISNULL(TAM.TicketAttachmentID, ''No Attachment Available''), '', '') AS TicketAttachmentID,  
  STRING_AGG(ISNULL(TAM.DisplayName, ''No Attachment Available''), '', '') AS AggregatedDisplayNames,  
  STRING_AGG(ISNULL(TAM.FileUrl, ''''), '', '') AS AggregatedFileUrls,  
  MIN(ISNULL(TAM.DisplayName, ''No Attachment Available'')) AS SingleDisplayName,  
  MIN(ISNULL(TAM.FileUrl, '''')) AS SingleFileUrl  
  FROM tbl_tp_TicketAttachment TAM (NOLOCK)  
  WHERE TAM.IsActive = 1  and TAM.ParentId=@Parent_ID
  GROUP BY TicketID  
  )  
  
  SELECT  
  ROW_NUMBER() OVER (ORDER BY ISNULL(TM.ModifiedOn, TM.CreatedOn) DESC) RecNo,  
  COUNT(*) OVER (ORDER BY TM.ParentID) TotalCount,  
  TM.TicketID,  
  TM.tpUser_Id,  
  ISNULL(TUL.Name, ''UnKnown'') AS Name,  
  TM.ParentId,  
  --tm.TicketNo ,    
  TM.EntityID,  
  TM.EntityName,  
  TM.ParentTicketID,  
  SGM.GroupName,  
  TM.AssignedGroup,  
  TM.ClosedOn,  
  CASE  
  WHEN TM.EntityName = ''Lead'' THEN UL.PersonName  
  WHEN TM.EntityName = ''Enquiry'' THEN UE.PersonName  
  ELSE ''Unknown''  
  END AS RequesterName,  
  RequesterMobileNo,
  RequesterMobileNo1,
  RequesterMobileNo2,
  TM.CountryCode,
  TM.CountryCode1,
  TM.CountryCode2,
  RequesterEmailID,
  RequesterEmailID1,
  RequesterEmailID2,
  --SGM.GroupName,    
  TM.Company,  
  TM.Subject,  
  TM.Description,  
  TM.TicketStatusID,  
  TSM.TicketStatus,  
  TM.TicketPriority,  
  TPM.PriorityName,  
  TUL.Name AS AssignedUser,  
  TM.TicketSourceId,  
  TSOM.TicketSourceName,  
  TicketTypeId,  
  TTM.Type_Name,  
  dbo.fn_ConvertDateTime(TM.CreatedOn, @Time_Zone, 0) AS CreatedOn,  
  dbo.fn_ConvertDateTime(TM.ModifiedOn, @Time_Zone, 0) AS ModifiedOn,  
  TM.IsActive,  
    		(
    SELECT
        ISNULL(
            NULLIF(
                JSON_QUERY(
                    (
                        SELECT
                            DisplayName AS ''FileName'',
                            FileUrl AS ''FilePath''
                        FROM tbl_tp_TicketAttachment
                        WHERE TicketID = TM.TicketID and ParentId= TM.ParentId
                            AND IsActive = 1
                            AND DisplayName IS NOT NULL AND DisplayName <> ''''
                            AND FileUrl IS NOT NULL AND FileUrl <> ''''
                        FOR JSON PATH
                    )
                ),
                ''[]''
            ),
            ''''
        )
) AS Attachement,
  TM.ProductId,  
  TM.TicketCategoryId,  
  IsParentTicket,  
  ISNULL(AA.AggregatedDisplayNames, ''No Attachment Available'') DisplayName,  
  ISNULL(AA.AggregatedFileUrls, '''') FileUrl,  
  ISNULL(AA.SingleDisplayName, ''No Attachment Available'') SingleAttachmentDisplayName,  
  AA.SingleFileUrl AS SingleAttachmentFileUrl,  
  AA.AggregatedDisplayNames,  
  AA.AggregatedFileUrls,  
  AA.TicketAttachmentID,  
  AA.TotalAttachments,  
  ' + @DynamicColumns + ',  
  ISNULL((SELECT STRING_AGG(Name, '','') AS Products
         FROM tbl_productmaster_' + CAST(@ParentId AS NVARCHAR(10)) + '(nolock)
         WHERE ProductID IN (
             SELECT value
             FROM STRING_SPLIT(
                 (SELECT STRING_AGG(ProductID, '','') 
                 FROM tbl_tp_TicketProducts (NOLOCK) 
                 WHERE TicketID = TM.TicketID AND IsActive = 1), '',''
             )
         )),'''') AS Products, 
  (  
  SELECT STRING_AGG(Tag, '', '')  
  FROM TagMaster  
  WHERE ID IN (SELECT value FROM STRING_SPLIT(TM.TicketTag, '',''))  
  ) AS Tags into #tmpTBLSort    
  FROM ' + @tableName + ' TM (NOLOCK)  
  LEFT JOIN tbl_tp_UserLogin TUL (NOLOCK) ON TUL.TpUser_Id = isnull(nullif(TM.AssignedUser,0),TM.CreatedBy) AND TUL.IsActive = 1  
  LEFT JOIN tbl_tp_TicketStatusMaster TSM (NOLOCK) ON TM.TicketStatusID = TSM.TicketStatus_ID  
  LEFT JOIN tbl_tp_TicketType_Master TTM (NOLOCK) ON TM.TicketTypeId = TTM.Type_ID  
  LEFT JOIN tbl_tp_TicketPriorityMaster TPM (NOLOCK) ON TM.TicketPriority = TPM.Priority_ID  
  LEFT JOIN tbl_tp_TicketSourceMaster TSOM (NOLOCK) ON TM.TicketSourceId = TSOM.TicketSourceId  
  LEFT JOIN AggregatedAttachments AA (NOLOCK) ON TM.TicketID = AA.TicketID  
  LEFT JOIN tbl_tp_GroupMaster SGM (NOLOCK) ON SGM.GroupId = TM.AssignedGroup  
  LEFT JOIN UserLeads UL (NOLOCK) ON TM.EntityID = UL.ID AND TM.EntityName = ''Lead''  
  LEFT JOIN UserEnquiry UE (NOLOCK) ON TM.EntityID = UE.EnquiryID AND TM.EntityName = ''Enquiry''  
  Left join tbl_tp_SlaReapplyHistory SRH (nolock) ON TM.TicketID = SRH.TicketID and TM.ParentId = SRH.ParentId and SRH.IsActive=1
  Left join tbl_tp_SLADetail SLD (nolock) ON SRH.slaID=SLD.SLA_ID and TM.TicketPriority=SLD.Priority_ID and SLD.IsActive=1
  WHERE  
  (@Parent_ID IS NULL OR TM.ParentId = @Parent_ID)  
  AND (@Category_Id IS NULL OR TM.TicketCategoryId = @Category_Id)  
  AND (@Type_Id IS NULL OR TM.TicketTypeId = @Type_Id)  
  AND (@Group_Id IS NULL OR TM.AssignedGroup = @Group_Id)  
  AND (@Priority_Id IS NULL OR TM.TicketPriority = @Priority_Id)  
  AND (@Company_Name IS NULL OR ISNULL(TM.Company, '''') LIKE ''%' + @Company + '%'')  
  AND (@Created_Interval IS NULL OR TM.CreatedOn >= DATEADD(MINUTE, -@Created_Interval, GETDATE()))  
  AND (@Closed_Interval IS NULL OR (TM.ClosedOn >= DATEADD(MINUTE, -@Closed_Interval, GETDATE()) AND ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) in (3,5)))  
  --AND (TM.EntityName = ''Lead'' OR TM.EntityName = ''Enquiry'')  
  AND TM.IsActive = 1  
  ' +   
  --CASE WHEN @IsAdmin = 0 THEN ' AND TM.AssignedUser = ' + CAST(@TpuserId AS NVARCHAR(MAX)) ELSE '' END + Case when @AccessType='AssignedToGroup' then ' and TM.AssignedGroup in (' + @StrGroupIds + ')' else '' end   
  @StrWhere  
  + N'  
  AND (@Tag_Id IS NULL OR TM.TicketID IN ( SELECT EntityID FROM EntityTagMapping  
  WHERE ParentID = ' + CAST(@ParentID AS NVARCHAR(MAX)) + '  
  AND TagID = ' + COALESCE(CAST(@TagId AS NVARCHAR(MAX)), 'NULL') + '  
  AND Entity = ''Ticket'')) ' + @SqlWhere + '  
  AND (@Product_Id IS NULL OR TM.TicketID IN (SELECT TicketID FROM tbl_tp_TicketProducts  
  WHERE ParentId = ' + CAST(@ParentID AS NVARCHAR(MAX)) + '  
  AND IsActive = 1))' + 
      CASE                                                      
        WHEN @Predinedview = 'Tickets raised today' THEN N' AND cast(TM.CreatedOn as DATE)=CAST(GETDATE() AS DATE)'  
        WHEN @Predinedview = 'Tickets assigned to me' THEN N' AND TM.Assigneduser=' + CAST(@TpUserId AS NVARCHAR(MAX))  
        WHEN @Predinedview = 'Tickets assigned to me today' THEN N' AND TM.AssignedUser = ' + CAST(@TpUserId AS NVARCHAR(MAX)) + N' AND CAST(TM.AssignedDateTime AS DATE) = CAST(GETDATE() AS DATE)'  
		WHEN @Predinedview = 'Tickets assigned to my group today' THEN iif(@IsAdmin =1,N'', N' AND TM.AssignedGroup in ('+@StrGroupIds+N') = AND CAST(TM.AssignedDateTime AS DATE) = CAST(GETDATE() AS DATE)')  
		WHEN @Predinedview = 'Unassigned tickets' THEN N' AND isnull(TM.AssignedUser,0)=0 and IsNull(TM.AssignedGroup,0)=0 '  
		WHEN @Predinedview = 'Tickets with response sla today' THEN N' AND isnull(TM.Remarks,'''') = '''' and  Cast(DateAdd(second,SLD.Respond_Sec,TM.CreatedOn) as Date) = Cast(getdate() as Date) '   
		WHEN @Predinedview = 'Tickets with resolution sla today' THEN N' AND ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) not in (3,5) and Cast(DateAdd(second,SLD.Resolve_Sec,TM.CreatedOn) as Date) = Cast(getdate() as Date) '                 
		WHEN @Predinedview = 'Unreplied tickets' THEN N' AND isnull(TM.Remarks,'''')='''' '                 
		WHEN @Predinedview = 'Tickets with overdue response' THEN N' AND isnull(TM.Remarks,'''') = '''' and  Cast(DateAdd(second,SLD.Respond_Sec,TM.CreatedOn) as Date) < Cast(getdate() as Date) '
		WHEN @Predinedview = 'Tickets with overdue resolution' THEN N' AND ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) not in (3,5) and Cast(DateAdd(second,SLD.Resolve_Sec,TM.CreatedOn) as Date) < Cast(getdate() as Date) '  
		WHEN @Predinedview = 'Open Tickets' THEN N' AND ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) = 2'  
        WHEN @Predinedview = 'Tickets raised by me' THEN N' AND TM.tpUser_Id='  + CAST(@TpUserId AS NVARCHAR(MAX))  
		WHEN @Predinedview = 'High Priority Tickets assigned to me' THEN N' AND TPM.PriorityName LIKE ''%High%'' AND TM.AssignedUser = ' + CAST(@TpUserId AS NVARCHAR(MAX))  
		WHEN @Predinedview = 'Tickets Awaiting Customer Response' THEN N' AND isnull(TM.Remarks,'''')!='''' and isnull(TM.UserResponse,'''')='''' '  
		WHEN @Predinedview = 'Recently Updated Tickets' THEN N' AND  cast(TM.ModifiedOn as DATE) =  CAST(GETDATE() AS DATE)'  
		WHEN @Predinedview = 'Closed Tickets' THEN N' AND ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) = 3'
		WHEN @Predinedview = 'Tickets with Feedback Requested' THEN N' AND ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) = 3 and Tf.RatingId is null '
		WHEN @Predinedview = 'Escalated Tickets' THEN N' AND ( (isnull(TM.Remarks,'''') = '''' and  Cast(DateAdd(second,SLD.Respond_Sec,TM.CreatedOn) as Date) < Cast(getdate() as Date)) OR (ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) not in (3,5) and Cast(DateAdd(second,SLD.Resolve_Sec,TM.CreatedOn) as Date) < Cast(getdate() as Date)) ) '  
		WHEN @Predinedview = 'Tickets Open for over 24 hrs' THEN N' AND ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) = 2 AND DATEDIFF(HOUR, TM.CreatedOn, GETDATE()) > 24'                 
            ELSE N''
  
     END + ' 
  ORDER BY '+  
  CASE  
  WHEN @SortField = 'DateCreated' THEN 'TM.CreatedOn'  
  WHEN @SortField = 'Status' THEN 'CAST(TM.TicketStatusID AS VARCHAR(255))'  
  WHEN @SortField = 'TicketNo' THEN 'TicketNo'  
  WHEN @SortField = 'Subject' THEN 'Subject'  
  WHEN @SortField = 'Description' THEN 'Description'  
  WHEN @SortField = 'AssignGroup' THEN 'SGM.GroupName'  
  WHEN @SortField = 'Requester' THEN 'ISNULL(UL.PersonName, UE.PersonName)'  
  WHEN @SortField = 'TicketType' THEN 'TTM.Type_Name'  
  WHEN @SortField = 'Priority' THEN 'TPM.PriorityName'  
  WHEN @SortField = 'Desc' THEN 'ISNULL(TM.ModifiedOn, TM.CreatedOn) desc'  
  WHEN @SortField = 'Asc' THEN 'ISNULL(TM.ModifiedOn, TM.CreatedOn) '  
  WHEN @SortField = 'Resolveddt' THEN 'TM.ClosedOn'  
  WHEN @SortField = 'AssignedDateTime' THEN 'TM.AssignedDateTime'  
  ELSE 'TM.TicketID DESC'  
  END + ' ; select * from #tmpTBLSort where RecNo between '  + CONVERT(NVARCHAR(max),(@Pageno - 1)*@offset + 1 ) + N' AND ' + CONVERT(NVARCHAR(max), @offset * @Pageno)        
  PRINT CAST(@DynamicSQL AS VARCHAR(MAX));  
 END  
 
ELSE  
BEGIN  
    -----------------------------------------------------------------------
    -- JK-OPT: SortField IS NULL => Page-first then enrich
    -- Goal: avoid processing/sorting all rows; do heavy work only for the page.
    -----------------------------------------------------------------------
    PRINT 'b (JK-OPT - Page first then enrich)';

    -----------------------------------------------------------------------
    -- JK-OPT: Access filter builder (keeps old behaviour)
    -----------------------------------------------------------------------
    DECLARE @AccessFilter NVARCHAR(MAX) = N'';
    IF (@IsAdmin = 0)
    BEGIN
        IF (@AccessType = 'AssignedToGroup')
        BEGIN
            IF NULLIF(@StrGroupIds,'') IS NULL
                SET @AccessFilter = N' AND 1=0 '; -- no groups => no rows
            ELSE
                SET @AccessFilter = N' AND TM.AssignedGroup IN (' + @StrGroupIds + N') ';
        END
        ELSE
            SET @AccessFilter = N' AND TM.AssignedUser = @TpUserId ';
    END

    -----------------------------------------------------------------------
    -- JK-OPT: PredinedView filter builder (fixed bug + removed UDF)
    -----------------------------------------------------------------------
    DECLARE @PredWhere NVARCHAR(MAX) = N'';
    SET @PredWhere =
    CASE
        WHEN @Predinedview = 'Tickets raised today' THEN N' AND CAST(TM.CreatedOn AS DATE)=CAST(GETDATE() AS DATE)'
        WHEN @Predinedview = 'Tickets assigned to me' THEN N' AND TM.AssignedUser = @TpUserId'
        WHEN @Predinedview = 'Tickets assigned to me today' THEN N' AND TM.AssignedUser = @TpUserId AND CAST(TM.AssignedDateTime AS DATE) = CAST(GETDATE() AS DATE)'
        WHEN @Predinedview = 'Tickets assigned to my group today'
             THEN CASE WHEN @IsAdmin = 1 OR NULLIF(@StrGroupIds,'') IS NULL
                       THEN N''
                       ELSE N' AND TM.AssignedGroup IN (' + @StrGroupIds + N') AND CAST(TM.AssignedDateTime AS DATE) = CAST(GETDATE() AS DATE)'
                  END
        WHEN @Predinedview = 'Unassigned tickets' THEN N' AND ISNULL(TM.AssignedUser,0)=0 AND ISNULL(TM.AssignedGroup,0)=0'
        WHEN @Predinedview = 'Tickets with response sla today' THEN N' AND ISNULL(TM.Remarks,'''') = '''' AND CAST(DATEADD(SECOND,SLD.Respond_Sec,TM.CreatedOn) AS DATE)=CAST(GETDATE() AS DATE)'
        WHEN @Predinedview = 'Tickets with resolution sla today' THEN N' AND ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) NOT IN (3,5) AND CAST(DATEADD(SECOND,SLD.Resolve_Sec,TM.CreatedOn) AS DATE)=CAST(GETDATE() AS DATE)'
        WHEN @Predinedview = 'Unreplied tickets' THEN N' AND ISNULL(TM.Remarks,'''')='''' '
        WHEN @Predinedview = 'Tickets with overdue response' THEN N' AND ISNULL(TM.Remarks,'''') = '''' AND CAST(DATEADD(SECOND,SLD.Respond_Sec,TM.CreatedOn) AS DATE) < CAST(GETDATE() AS DATE)'
        WHEN @Predinedview = 'Tickets with overdue resolution' THEN N' AND ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) NOT IN (3,5) AND CAST(DATEADD(SECOND,SLD.Resolve_Sec,TM.CreatedOn) AS DATE) < CAST(GETDATE() AS DATE)'
        WHEN @Predinedview = 'Open Tickets' THEN N' AND ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) = 2'
        WHEN @Predinedview = 'Tickets raised by me' THEN N' AND TM.tpUser_Id = @TpUserId'
        WHEN @Predinedview = 'High Priority Tickets assigned to me' THEN N' AND TPM.PriorityName LIKE ''%High%'' AND TM.AssignedUser = @TpUserId'
        WHEN @Predinedview = 'Tickets Awaiting Customer Response' THEN N' AND ISNULL(TM.Remarks,'''')<>'''' AND ISNULL(TM.UserResponse,'''')='''' '
        WHEN @Predinedview = 'Recently Updated Tickets' THEN N' AND CAST(TM.ModifiedOn AS DATE) = CAST(GETDATE() AS DATE)'
        WHEN @Predinedview = 'Closed Tickets' THEN N' AND ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) = 3'
        WHEN @Predinedview = 'Tickets with Feedback Requested' THEN N' AND ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) = 3 AND Tf.RatingId IS NULL'
        WHEN @Predinedview = 'Escalated Tickets'
             THEN N' AND ( (ISNULL(TM.Remarks,'''') = '''' AND CAST(DATEADD(SECOND,SLD.Respond_Sec,TM.CreatedOn) AS DATE) < CAST(GETDATE() AS DATE)) OR
                           (ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) NOT IN (3,5) AND CAST(DATEADD(SECOND,SLD.Resolve_Sec,TM.CreatedOn) AS DATE) < CAST(GETDATE() AS DATE)) )'
        WHEN @Predinedview = 'Tickets Open for over 24 hrs' THEN N' AND ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) = 2 AND DATEDIFF(HOUR, TM.CreatedOn, GETDATE()) > 24'
        ELSE N''
    END;

    -----------------------------------------------------------------------
    -- JK-OPT: Dynamic SQL - page-first then enrich
    -----------------------------------------------------------------------
    SET @DynamicSQL = N'
DROP TABLE IF EXISTS #Filtered;

-- 1) Narrow filter set first (TicketID + SortDate)
SELECT
    TM.TicketID,
    SortDate = ISNULL(TM.ModifiedOn, TM.CreatedOn)
INTO #Filtered
FROM ' + @TicketMasterFull + N' TM WITH (NOLOCK)
LEFT JOIN dbo.tbl_tp_TicketStatusMaster TSM WITH (NOLOCK) ON TM.TicketStatusID = TSM.TicketStatus_ID
LEFT JOIN dbo.tbl_tp_TicketPriorityMaster TPM (NOLOCK) ON TM.TicketPriority = TPM.Priority_ID
LEFT JOIN dbo.tbl_tp_TicketRatingFeedback Tf (NOLOCK) ON TM.TicketID = Tf.TicketID AND TM.ParentId = Tf.ParentId
LEFT JOIN dbo.tbl_tp_SlaReapplyHistory SRH (NOLOCK) ON TM.TicketID = SRH.TicketID AND TM.ParentId = SRH.ParentId AND SRH.IsActive=1
LEFT JOIN dbo.tbl_tp_SLADetail SLD (NOLOCK) ON SRH.slaID = SLD.SLA_ID AND TM.TicketPriority = SLD.Priority_ID AND SLD.IsActive=1
WHERE
    (@Parent_ID IS NULL OR TM.ParentId = @Parent_ID)
    AND (@Category_Id IS NULL OR TM.TicketCategoryId = @Category_Id)
    AND (@Type_Id IS NULL OR TM.TicketTypeId = @Type_Id)
    AND (@Group_Id IS NULL OR TM.AssignedGroup = @Group_Id)
    AND (@Priority_Id IS NULL OR TM.TicketPriority = @Priority_Id)
    AND (@Company_Name IS NULL OR ISNULL(TM.Company, N'''') LIKE N''%'' + @Company_Name + N''%'')
    AND (@Created_Interval IS NULL OR TM.CreatedOn >= DATEADD(MINUTE, -@Created_Interval, GETDATE()))
    AND (@Closed_Interval IS NULL OR (TM.ClosedOn >= DATEADD(MINUTE, -@Closed_Interval, GETDATE()) AND ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) IN (3,5)))
    AND TM.IsActive = 1
' + @StrWhere + N'
' + @AccessFilter + N'
    AND (@Tag_Id IS NULL OR EXISTS (
        SELECT 1
        FROM dbo.EntityTagMapping etm WITH (NOLOCK)
        WHERE etm.ParentId = @Parent_ID AND etm.Entity = ''Ticket''
          AND etm.EntityID = TM.TicketID AND etm.TagID = @Tag_Id
    ))
    AND (@Product_Id IS NULL OR EXISTS (
        SELECT 1
        FROM dbo.tbl_tp_TicketProducts ttp WITH (NOLOCK)
        WHERE ttp.ParentId = @Parent_ID AND ttp.TicketID = TM.TicketID
          AND ttp.IsActive = 1 AND ttp.ProductID = @Product_Id
    ))
' + @SqlWhere + N'
' + @PredWhere + N'
;

DECLARE @TotalCount BIGINT = (SELECT COUNT_BIG(*) FROM #Filtered);

;WITH PageTickets AS
(
    SELECT TicketID, SortDate
    FROM #Filtered
    ORDER BY SortDate DESC, TicketID DESC
    OFFSET @OffsetRows ROWS FETCH NEXT @FetchRows ROWS ONLY
),
AggAttach AS
(
    SELECT
        A.TicketID,
        TotalAttachments = (COUNT(*) - 1),
        TicketAttachmentID     = STRING_AGG(CAST(A.TicketAttachmentID AS NVARCHAR(MAX)), '',''),
        AggregatedDisplayNames = STRING_AGG(ISNULL(A.DisplayName, ''No Attachment Available''), '',''),
        AggregatedFileUrls     = STRING_AGG(ISNULL(A.FileUrl, ''''), '',''),
        SingleDisplayName      = MIN(ISNULL(A.DisplayName, ''No Attachment Available'')),
        SingleFileUrl          = MIN(ISNULL(A.FileUrl, ''''))
    FROM dbo.tbl_tp_TicketAttachment A WITH (NOLOCK)
    JOIN PageTickets P ON P.TicketID = A.TicketID
    WHERE A.ParentId = @Parent_ID AND A.IsActive = 1
    GROUP BY A.TicketID
),
LastHistory AS
(
    SELECT TicketID, ParentID, UserResponse, Remarks, AssignedBy,
           RemarkType = CASE WHEN Remarks IS NOT NULL THEN ''A'' ELSE ''C'' END
    FROM
    (
        SELECT TH.*,
               rn = ROW_NUMBER() OVER (PARTITION BY TH.ParentID, TH.TicketID ORDER BY TH.TicketHistoryID DESC)
        FROM dbo.tbl_tp_TicketHistory TH WITH (NOLOCK)
        JOIN PageTickets P ON P.TicketID = TH.TicketID
        WHERE TH.ParentID = @Parent_ID
          AND (TH.Remarks IS NOT NULL OR TH.UserResponse IS NOT NULL)
    ) X
    WHERE rn = 1
),
TagsAgg AS
(
    SELECT etm.EntityID AS TicketID,
           Tags = STRING_AGG(CAST(tgm.Tag AS NVARCHAR(MAX)), '','')
    FROM dbo.EntityTagMapping etm WITH (NOLOCK)
    JOIN PageTickets P ON P.TicketID = etm.EntityID
    LEFT JOIN dbo.TagMaster tgm WITH (NOLOCK) ON tgm.ID = etm.TagID
    WHERE etm.ParentId = @Parent_ID AND etm.Entity = ''Ticket''
    GROUP BY etm.EntityID
)

SELECT
    RecNo      = @OffsetRows + ROW_NUMBER() OVER (ORDER BY P.SortDate DESC, TM.TicketID DESC),
    TotalCount = @TotalCount,

    TM.TicketID,
    TM.tpUser_Id,
    ISNULL(TUL.Name, ''UnKnown'') AS Name,
    TM.ParentId,
    TM.EntityID,
    TM.EntityName,
    TM.ParentTicketID,
    SGM.GroupName,
    TM.AssignedGroup,
    TM.AssignedUser AS AssignedUserId,
    CASE
        WHEN TM.EntityName = ''Lead'' THEN UL.PersonName
        WHEN TM.EntityName = ''Enquiry'' THEN UE.PersonName
        ELSE ''Unknown''
    END AS RequesterName,
    TM.RequesterMobileNo,
    TM.RequesterMobileNo1,
    TM.RequesterMobileNo2,
    TM.CountryCode,
    TM.CountryCode1,
    TM.CountryCode2,
    TM.RequesterEmailID,
    TM.RequesterEmailID1,
    TM.RequesterEmailID2,
    TM.Company,
    TM.Subject,
    TM.Description,
    TSM.ParentStatus_Id,
    TM.TicketStatusID,
    TSM.TicketStatus,
    TM.TicketPriority,
    TPM.PriorityName,
    TUL.Name AS AssignedUser,
    TM.TicketSourceId,
    TSOM.TicketSourceName,
    TM.TicketTypeId,
    TTM.Type_Name,
    dbo.fn_ConvertDateTime(TM.CreatedOn, @Time_Zone, 0) AS CreatedOn,
    dbo.fn_ConvertDateTime(TM.ModifiedOn, @Time_Zone, 0) AS ModifiedOn,
    TM.IsActive,
    TM.ProductId,
    TM.TicketCategoryId,
    TM.IsParentTicket,
    ISNULL(LH.UserResponse, LH.Remarks) AS LastRemark,
    LH.RemarkType,
    ISNULL(LH.AssignedBy, 0) AS RemarkBy,
    ISNULL(AA.AggregatedDisplayNames, ''No Attachment Available'') AS DisplayName,
    ISNULL(AA.AggregatedFileUrls, '''') AS FileUrl,
    ISNULL(AA.SingleDisplayName, ''No Attachment Available'') AS SingleAttachmentDisplayName,
    AA.SingleFileUrl AS SingleAttachmentFileUrl,
    AA.AggregatedDisplayNames,
    AA.AggregatedFileUrls,
    AA.TicketAttachmentID,
    AA.TotalAttachments' + @DynColsSelect + N',
    TM.TicketNo,
    ISNULL(TG.Tags, '''') AS Tags,
    ISNULL(PR.Products, '''') AS Products,

    CASE
        WHEN TSM.TicketStatus = ''New'' AND DATEDIFF(HOUR, TM.CreatedOn, GETDATE()) < 24 THEN ''New Ticket''
        WHEN TSM.TicketStatus = ''Spam'' THEN ''Spam''
        WHEN TSM.TicketStatus = ''Close'' THEN ''Ticket Closed''
        WHEN TSM.TicketStatus = ''Invalid'' THEN ''Invalid''
        WHEN TSM.TicketStatus = ''Waiting on Customer'' THEN ''Waiting on Customer Response''
        WHEN TSM.TicketStatus = ''Waiting On Third Party'' THEN ''ON HOLD''
        WHEN ISNULL(TM.Remarks,'''') = '''' AND CAST(DATEADD(SECOND,SLD.Respond_Sec,TM.CreatedOn) AS DATE) = CAST(GETDATE() AS DATE) THEN ''First Response Due Soon''
        WHEN ISNULL(TM.Remarks,'''') = '''' AND CAST(DATEADD(SECOND,SLD.Respond_Sec,TM.CreatedOn) AS DATE) < CAST(GETDATE() AS DATE) THEN ''First Response Overdue''
        WHEN TM.TicketId = Tf.TicketId THEN ''Feedback Requested''
        WHEN LH.RemarkType <> ''A'' AND TPM.PriorityName LIKE ''%High%'' THEN ''High Priority''
        WHEN LH.RemarkType <> ''A'' AND TPM.PriorityName LIKE ''%Low%''  THEN ''Low Priority''
        WHEN LH.UserResponse IS NOT NULL THEN ''Customer Responded''
        WHEN ( (ISNULL(TM.Remarks,'''') = '''' AND CAST(DATEADD(SECOND,SLD.Respond_Sec,TM.CreatedOn) AS DATE) < CAST(GETDATE() AS DATE))
            OR (ISNULL(TSM.ParentStatus_Id, TM.TicketStatusID) NOT IN (3,5) AND CAST(DATEADD(SECOND,SLD.Resolve_Sec,TM.CreatedOn) AS DATE) < CAST(GETDATE() AS DATE)) ) THEN ''Escalated Ticket''
        WHEN TSM.TicketStatus = ''Reopened'' THEN ''Reopened Ticket''
        WHEN TM.AssignedUser IS NOT NULL AND LH.RemarkType <> ''A'' THEN ''Assigned to Agent''
        WHEN TSM.TicketStatus NOT IN (''Close'',''Resolved'') AND LH.RemarkType = ''A'' THEN ''Agent Responded''
        WHEN TSM.TicketStatus = ''Resolution in Progress'' THEN ''Resolution in Progress''
        WHEN TSM.TicketStatus = ''Resolution Submitted'' THEN ''Resolution Submitted''
        WHEN TSM.TicketStatus = ''SLA Breached'' THEN ''SLA Breached''
        WHEN TSM.TicketStatus <> ''Ticket Closed'' AND TM.AssignedUser IS NOT NULL AND LH.Remarks IS NULL
             AND DATEDIFF(HOUR, TM.CreatedOn, GETDATE()) > 24 THEN ''Pending Agent Action''
        ELSE ''''
    END AS TicketCustomTag,

    (
        SELECT ISNULL(
            NULLIF(JSON_QUERY((
                SELECT A2.DisplayName AS FileName, A2.FileUrl AS FilePath
                FROM dbo.tbl_tp_TicketAttachment A2 WITH (NOLOCK)
                WHERE A2.TicketID = TM.TicketID AND A2.ParentId = TM.ParentId
                  AND A2.IsActive = 1
                  AND A2.DisplayName IS NOT NULL AND A2.DisplayName <> ''''
                  AND A2.FileUrl IS NOT NULL AND A2.FileUrl <> ''''
                FOR JSON PATH
            )), ''[]''),
        '''')
    ) AS Attachement

FROM PageTickets P
JOIN ' + @TicketMasterFull + N' TM WITH (NOLOCK) ON TM.TicketID = P.TicketID
LEFT JOIN dbo.tbl_tp_UserLogin TUL WITH (NOLOCK) ON TUL.TpUser_Id = ISNULL(NULLIF(TM.AssignedUser, 0), TM.CreatedBy) AND TUL.IsActive = 1
LEFT JOIN dbo.tbl_tp_TicketStatusMaster TSM WITH (NOLOCK) ON TM.TicketStatusID = TSM.TicketStatus_ID
LEFT JOIN dbo.tbl_tp_TicketRatingFeedback Tf (NOLOCK) ON TM.TicketID = Tf.TicketID AND TM.ParentId = Tf.ParentId
LEFT JOIN dbo.tbl_tp_TicketType_Master TTM (NOLOCK) ON TM.TicketTypeId = TTM.Type_ID
LEFT JOIN dbo.tbl_tp_TicketPriorityMaster TPM (NOLOCK) ON TM.TicketPriority = TPM.Priority_ID
LEFT JOIN dbo.tbl_tp_TicketSourceMaster TSOM (NOLOCK) ON TM.TicketSourceId = TSOM.TicketSourceId
LEFT JOIN dbo.tbl_tp_GroupMaster SGM (NOLOCK) ON SGM.GroupId = TM.AssignedGroup
LEFT JOIN dbo.UserLeads UL (NOLOCK) ON TM.EntityID = UL.ID AND TM.EntityName = ''Lead''
LEFT JOIN dbo.UserEnquiry UE (NOLOCK) ON TM.EntityID = UE.EnquiryID AND TM.EntityName = ''Enquiry''
LEFT JOIN dbo.tbl_tp_SlaReapplyHistory SRH (NOLOCK) ON TM.TicketID = SRH.TicketID AND TM.ParentId = SRH.ParentId AND SRH.IsActive=1
LEFT JOIN dbo.tbl_tp_SLADetail SLD (NOLOCK) ON SRH.slaID = SLD.SLA_ID AND TM.TicketPriority = SLD.Priority_ID AND SLD.IsActive=1
LEFT JOIN AggAttach AA ON AA.TicketID = TM.TicketID
LEFT JOIN LastHistory LH ON LH.TicketID = TM.TicketID AND LH.ParentID = TM.ParentID
LEFT JOIN TagsAgg TG ON TG.TicketID = TM.TicketID
OUTER APPLY
(
    SELECT Products = ISNULL(STRING_AGG(CAST(pm.Name AS NVARCHAR(MAX)), '',''), '''')
    FROM dbo.tbl_tp_TicketProducts ttp WITH (NOLOCK)
    JOIN ' + @ProductMasterFull + N' pm WITH (NOLOCK) ON pm.ProductID = ttp.ProductID
    WHERE ttp.ParentId = TM.ParentId AND ttp.TicketID = TM.TicketID AND ttp.IsActive = 1
) PR
ORDER BY P.SortDate DESC, TM.TicketID DESC;
';

    PRINT CAST(@DynamicSQL AS VARCHAR(MAX));
END  

EXEC sp_executesql @DynamicSQL,  
 N'  
 @Parent_ID BIGINT,  
 @Category_Id BIGINT,  
 @Product_Id BIGINT,  
 @Type_Id BIGINT,  
 @Created_Interval BIGINT,  
 @Closed_Interval BIGINT,  
 @Time_Zone NVARCHAR(400),  
 @Sort_Field NVARCHAR(20),  
 @Group_Id BIGINT,  
 @Priority_Id BIGINT,  
 @Company_Name NVARCHAR(300),  
 @Tag_Id BIGINT,
 @TpUserId BIGINT,
 @OffsetRows INT,
 @FetchRows INT',  
 @ParentID, @CategoryId, @ProductId, @Type, @CreatedInterval, @ClosedInterval, @TimeZone, @SortField, @Group, @Priority, @Company, @TagId,
 @TpUserId, @OffsetRows, @FetchRows  
   
 EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData_jk
 @User_id = @UserId,  
 @Activity_type = 'View_manageticketmaster',  
 @ActionType = 'S',  
 @RowJson = 'NULL',  
 @Table_name = @tableName,  
 @ip_adress = @IPAdress,  
 @device_id = @DeviceId,  
 @IsImpersonation = @IsImpersonation,  
 @ImpersonatorId = @ImpersonatorId  
  
END TRY  
BEGIN CATCH  
 PRINT 'Error occurred: ' + ERROR_MESSAGE()  
END CATCH  
END


GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_GetManageTicketMaster]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_GetManageTicketMaster]  --335          
(            
 @ParentID bigint ,      
 @UserID bigint,      
 @MetaData nvarchar(200)      
)            
as            
Begin         
      
DECLARE  @TimeZone nvarchar (400)  ,@rowJson NVARCHAR(MAX)  , @IPAdress NVARCHAR(50),@DeviceId NVARCHAR(50),@IsImpersonation BIT ,@ImpersonatorId INT        
Select @ParentID = ParentId,@TimeZone = TimeZone  From User_Detail (noLock) Where User_Id = @UserID                
                
    SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)        
 SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)        
 SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)        
 SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)      
      
 SELECT        
       tpUser_Id            
      ,ParentId            
      ,TicketNo          
      ,RequesterEmailID 
	  ,Subject
	  ,Description
	  ,TicketStatusID
	  ,TicketPriority
	  ,AssignedSource
	  ,TicketCategoryId
	  ,TicketTypeId
	  ,TicketSourceId
	  ,IsMerged
	  ,IsSplitted
	  ,IsParentTicket
	  ,IsChildTicket
	  ,ParentTicketID
	  ,LastActionDatetime
	  ,IsActive
	  ,CreatedBy
      ,        
     -- Created_Date            
      dbo.[fn_getusertimefromindiantime](@ParentID,CreatedOn) as Created_Date        
      ,IsActive            
  FROM tbl_tp_TicketMaster where ParentId = @ParentID and IsActive=1 order by Created_Date desc       
        
  SET @rowJson  = ( SELECT *  FROM tbl_tp_TicketMaster  FOR JSON AUTO  ,INCLUDE_NULL_VALUES )                  
                  
          IF @rowJson IS NOT NULL                  
          BEGIN                  
           EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData @User_id = @UserId                  
            ,@Activity_type = 'View_TicketMaster'                  
            ,@ActionType = 'S'                  
            ,@RowJson = NULL                  
            ,@Table_name = 'tbl_tp_TicketMaster'  ,@ip_adress = @IPAdress ,@device_id = @DeviceId,@IsImpersonation = @IsImpersonation,@ImpersonatorId =  @ImpersonatorId           
          END         
      
End 



GO

/* ============================================================
   Procedure: [dbo].[usp_tp_GetMenu]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 CREATE   PROC [dbo].[usp_tp_GetMenu]
 (
	@SectionNo int=1
 )
 AS
 BEGIN
	-- declare @SectionNo bigint=7
	;with ctemenu
	AS
	(
		SELECT     *
		FROM        tbl_tp_TicketModuleMaster WITH (nolock)
		Where ParentModuleId=0 and IsActive=1
		--Order by Sequence
		union all
		select MM.* 
		from tbl_tp_ticketmodulemaster(nolock) MM inner join ctemenu
		on MM.ParentModuleId=ctemenu.ModuleId
	)

	select * 
	from  ctemenu
	Where SectionNo <= @SectionNo and IsActive=1
	Order by Sequence

 END



GO

/* ============================================================
   Procedure: [dbo].[usp_tp_GetMenuByTpuserId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 -- Exec usp_tp_GetMenuByTpuserId 1  
 CREATE   PROC usp_tp_GetMenuByTpuserId  
 (  
 @TpUserId bigint  
 )  
 As  
 Begin  
   
 declare @ParentId bigint, @IsAdmin bit=0, @UserId bigint  
  
 Select @ParentId=ParentId, @UserId=User_Id  
 from tbl_tp_UserLogin(nolock)   
 Where TpUser_Id=@TpUserId and IsActive=1  
  
 If(@ParentId > 0)  
 Begin  
  If(@UserId>0)--Internal User  
  Begin  
   Select @IsAdmin=IIF(User_ID=ParentId,1,IsAdmin) From User_Detail(nolock) Where User_ID=@UserId  
  End  
  Else--External User  
  Begin  
   select  @IsAdmin=1  
   from tbl_tp_agentrolemapping(nolock)  
   Where tpUserId=@TpUserId and Active=1 and Role_id < 3  
  End  
  
  If(@IsAdmin=1)  -- Admin user
  Begin  
   Exec usp_tp_GetMenu @SectionNo=7  
  End  
  Else if(@UserId>0) -- child user
  Begin
   Exec usp_tp_GetMenu @SectionNo=2  
  End
  Else-- External user  
  Begin  
   Exec usp_tp_GetMenu @SectionNo=1  
  End  
  
 End  
 Else  
 Begin  
  SELECT  *  
  FROM    tbl_tp_TicketModuleMaster WITH (nolock)  
  Where ModuleId<0  
 End  
  
 End  



GO

/* ============================================================
   Procedure: [dbo].[usp_tp_GetNextTicketNo]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_tp_GetNextTicketNo]
(
	@ParentId	bigint
)
AS
BEGIN
	-- declare @ParentId bigint=32222
	drop table if exists #tmpFormatFields;
	drop table if exists #tmpFormatValues;
	drop table if exists #tmpTicketNoData;
	drop table if exists #StrPos;
	drop table if exists #StrPos_n;

	declare @FormatJson nvarchar(max),@TicketNo nvarchar(100)=N'', @RowNo int=1, @RowCnt int
	declare @FieldName varchar(100),@FieldValue varchar(10),@FieldType varchar(50),@FormatField varchar(100),@FormatValue varchar(100) 
	
	select @FormatJson=FormatJson, @FormatField=FormatField, @FormatValue=FormatValue
	from tbl_tp_TicketNoFormat(nolock) 
	Where IsActive=1 and ParentId=@ParentId

	create table #tmpFormatFields
	(
		RowNo	int identity(1,1),
		[Value]	nvarchar(100),
		[type]	nvarchar(50)
	)

	create table #tmpFormatValues
	(
		RowNo	int identity(1,1),
		[Value]	nvarchar(100),
		[type]	nvarchar(50)
	)

	insert into #tmpFormatFields
	select [value],[type] 
	from openjson(@FormatJson,'$.FormatFields')
	with 
	(
		[value]	nvarchar(1000),
		[type]	nvarchar(30)	
	)

	insert into #tmpFormatValues
	select [value],[type] 
	from openjson(@FormatJson,'$.FormatValues')
	with 
	(
		[value]	nvarchar(1000),
		[type]	nvarchar(30)	
	)

	--Create table #StrPos (Sno int identity, Pos int)
	Create table #StrPos_n (Sno int identity, Pos int)

	select  F.RowNo,F.Value as Field, F.type, V.Value
	into	#tmpTicketNoData
	From	#tmpFormatFields F inner join #tmpFormatValues V
	On		F.RowNo=V.RowNo

	Select @RowCnt=count(*) From #tmpTicketNoData

	while(@RowNo<=@RowCnt)
	Begin
		Select @FieldName=Field, @FieldValue=Value, @FieldType=type 
		from #tmpTicketNoData 
		Where RowNo=@RowNo

		print '@RowNo: ' + cast(@RowNo as varchar)
		print '@FieldName: ' + @FieldName
		print '@FieldValue: ' + @FieldValue
		print '@FieldType: ' + @FieldType

		If(@FieldName='StaticText')
		Begin
			Set @TicketNo += @FieldValue
		End

		If(@FieldName='FinYear')
		Begin
			Set @TicketNo += @FieldValue
		End

		If(@FieldName='SNo')
		Begin
			declare @CurTicketNo nvarchar(100)='', @StrSql nvarchar(max)='', @FinYearValue varchar(10)
			declare @t1 nvarchar(100), @t2 nvarchar(100), @iSno int, @tempTicketNo nvarchar(100), @SNo int=1
			declare @i int, @iOcc int, @i_n int, @iOcc_n int
			

			If(charindex('FinYear',@FormatField) > 0)
			Begin
				print 'A'
				select @FinYearValue=Value from #tmpTicketNoData where Field='FinYear'

				Set @StrSql=N'Select top 1 @TktNo=TicketNo from tbl_tp_TicketMaster(nolock)_' + cast(@ParentId as varchar) + N' Where TicketNo like ''%'+@FinYearValue+'%'' order by TicketID desc'
			
				print '@strsql: ' + @strsql
				EXECUTE sp_executesql @strsql, N'@TktNo nvarchar(100) output', @TktNo = @CurTicketNo output
				print '@CurTicketNo: ' + @CurTicketNo

				If(charindex('SNo',@FormatField) > 0)
				Begin
					print 'B'
					Select @iSno=RowNo from #tmpTicketNoData where Field='SNo'
					print 'C'

					select @i=charindex('SNo',@FormatValue)-1,@i_n=charindex('SNo',@FormatValue)+3
					print 'D'

					--insert into #StrPos(Pos)
					select ROW_NUMBER()over(order by ID) Sno,ID as Pos 
					into	#StrPos
					from	dbo.[ufn_CountOccurrence](@FormatValue,'%'+ SUBSTRING(@FormatValue, @i, 1) + '%')
					print 'E'

					insert into #StrPos_n(Pos)
					select ID as Pos 
					from dbo.[ufn_CountOccurrence](@FormatValue,'%'+ SUBSTRING(@FormatValue, @i_n, 1) + '%')
					print 'F'

					Select @iOcc=Sno From #StrPos Where Pos=@i
					Select @iOcc_n=Sno From #StrPos_n Where Pos=@i_n
					print 'G'

					Select @t1=SUBSTRING(@FormatValue, 1, @i)
					Select @t2=SUBSTRING(@FormatValue, @i_n, len(@FormatValue))
					--Select @t1=STRING_AGG(Value,'') from #tmpTicketNoData where RowNo<@iSno
					--Select @t2=STRING_AGG(Value,'') from #tmpTicketNoData where RowNo>@iSno
					print 'H0'

					If(isnull(@CurTicketNo,'')='')
					Begin
						Set @CurTicketNo='00001'
					End

					print '@t1: ' + @t1
					print '@t2: ' + @t2
					print '@CurTicketNo: ' + @CurTicketNo

					Set @tempTicketNo=REPLACE(isnull(@t1,''),@CurTicketNo,'')
					Set @tempTicketNo=REPLACE(isnull(@t2,''),@tempTicketNo,'')

					print '@tempTicketNo: ' + @tempTicketNo
					
					select @SNo=Cast(@tempTicketNo as int)+1

					print '@SNo: ' + cast(@SNo as varchar)

					if(len(@tempTicketNo) = 0)
					Begin
						set @tempTicketNo=replicate(' ',len(CAST(@SNo AS VARCHAR)))
					End

					SELECT @TicketNo+=RIGHT(replicate('0',len(@tempTicketNo))+CAST(@SNo AS VARCHAR),len(@tempTicketNo))
				End

			End
			Else
			Begin
				Set @StrSql=N'Select top 1 @TktNo=TicketNo from tbl_tp_TicketMaster(nolock)_' + cast(@ParentId as varchar) + N' order by TicketID desc'
			
				print '@strsql: ' + @strsql
				EXECUTE sp_executesql @strsql, N'@TktNo nvarchar(100) output', @TktNo = @CurTicketNo output
				print '@CurTicketNo: ' + @CurTicketNo

				If(charindex('SNo',@FormatField) > 0)
				Begin
					Select @iSno=RowNo from #tmpTicketNoData where Field='SNo'

					Select @t1=STRING_AGG(Value,'') from #tmpTicketNoData where RowNo<@iSno
					Select @t2=STRING_AGG(Value,'') from #tmpTicketNoData where RowNo>@iSno

					Set @tempTicketNo=REPLACE(isnull(@t1,''),@CurTicketNo,'')
					Set @tempTicketNo=REPLACE(isnull(@t2,''),@tempTicketNo,'')

					select @SNo=Cast(@tempTicketNo as int)+1

					SELECT @TicketNo+=RIGHT(replicate('0',len(@tempTicketNo))+CAST(@SNo AS VARCHAR),len(@tempTicketNo))
				End
			End

		End

		If(@FieldName='TktCategory')
		Begin
			select top 1 @TicketNo += TicketCategoryName 
			from tbl_tp_TicketCategory_Master(nolock) Where TicketCategoryId=@FieldValue
		End

		If(@FieldName='TktSource')
		Begin
			select top 1 @TicketNo += TicketSourceName 
			from tbl_tp_TicketSourceMaster(nolock) Where TicketSourceId=@FieldValue
		End

		If(@FieldType='Separator')
		Begin
			Set @TicketNo += @FieldValue
		End

		print '@TicketNo: ' + @TicketNo

		Set @RowNo += 1
	End

	Select @TicketNo as TicketNo
END



GO

/* ============================================================
   Procedure: [dbo].[usp_tp_GetNextTicketNo_new]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_tp_GetNextTicketNo_new]  
(  
 @ParentId bigint  
)  
AS  
BEGIN 


--DECLARE @ParentId BIGINT = 32222;

DROP TABLE IF EXISTS #tmpFormatFields;
DROP TABLE IF EXISTS #tmpFormatValues;
DROP TABLE IF EXISTS #tmpTicketNoData;
DROP TABLE IF EXISTS #StrPos;
DROP TABLE IF EXISTS #StrPos_n;


DECLARE 
    @FormatJson NVARCHAR(MAX),
    @TicketNo NVARCHAR(100) = N'',
    @RowNo INT = 1,
    @RowCnt INT;

DECLARE 
    @FieldName VARCHAR(100),
    @FieldValue VARCHAR(10),
    @FieldType VARCHAR(50),
    @FormatField VARCHAR(100),
    @FormatValue VARCHAR(100),
    @iSno INT;

	SELECT @FormatJson = FormatJson, @FormatField = FormatField, @FormatValue = FormatValue
FROM tbl_tp_TicketNoFormat(NOLOCK)
WHERE IsActive = 1 AND ParentId = @ParentId;

CREATE TABLE #tmpFormatFields
(
    RowNo INT IDENTITY(1, 1),
    [Value] NVARCHAR(100),
    [type] NVARCHAR(50)
);

CREATE TABLE #tmpFormatValues
(
    RowNo INT IDENTITY(1, 1),
    [Value] NVARCHAR(100),
    [type] NVARCHAR(50)
);

INSERT INTO #tmpFormatFields
SELECT [value], [type]
FROM OPENJSON(@FormatJson, '$.FormatFields')
WITH
(
    [value] NVARCHAR(1000),
    [type] NVARCHAR(30)
);

INSERT INTO #tmpFormatValues
SELECT [value], [type]
FROM OPENJSON(@FormatJson, '$.FormatValues')
WITH
(
    [value] NVARCHAR(1000),
    [type] NVARCHAR(30)
);

CREATE TABLE #StrPos_n (Sno INT IDENTITY, Pos INT);

SELECT F.RowNo, F.Value AS Field, F.type, V.Value
INTO #tmpTicketNoData
FROM #tmpFormatFields F
INNER JOIN #tmpFormatValues V ON F.RowNo = V.RowNo;

-- Add the index 
CREATE NONCLUSTERED INDEX IX_tmpTicketNoData_RowNo
ON #tmpTicketNoData (RowNo);

SELECT @RowCnt = COUNT(*) FROM #tmpTicketNoData;
WHILE (@RowNo <= @RowCnt)
BEGIN
    SELECT 
        @FieldName = Field, 
        @FieldValue = Value, 
        @FieldType = type
    FROM #tmpTicketNoData
    WHERE RowNo = @RowNo;

    PRINT '@RowNo: ' + CAST(@RowNo AS VARCHAR);
    PRINT '@FieldName: ' + @FieldName;
    PRINT '@FieldValue: ' + @FieldValue;
    PRINT '@FieldType: ' + @FieldType;

    IF (@FieldName = 'StaticText' OR @FieldName = 'FinYear')
    BEGIN
        SET @TicketNo += @FieldValue;
    END
    ELSE IF (@FieldName = 'SNo')
    BEGIN
        DECLARE 
            @CurTicketNo NVARCHAR(100) = '',
            @StrSql NVARCHAR(MAX) = '',
            @FinYearValue VARCHAR(10),
            @t1 NVARCHAR(100),
            @t2 NVARCHAR(100),
            @tempTicketNo NVARCHAR(100),
            @SNo INT = 1,
            @i INT,
            @iOcc INT,
            @i_n INT,
            @iOcc_n INT;

        IF (CHARINDEX('FinYear', @FormatField) > 0)
        BEGIN
            PRINT 'A';
            SELECT @FinYearValue = Value FROM #tmpTicketNoData WHERE Field = 'FinYear';

            SET @StrSql = N'SELECT TOP 1 @TktNo = TicketNo FROM tbl_tp_TicketMaster_' + CAST(@ParentId AS VARCHAR) + N'(NOLOCK) WHERE TicketNo LIKE ''%' + @FinYearValue + '%'' ORDER BY TicketID DESC';

            PRINT '@strsql: ' + @StrSql;
            EXECUTE sp_executesql @StrSql, N'@TktNo NVARCHAR(100) OUTPUT', @TktNo = @CurTicketNo OUTPUT;
            PRINT '@CurTicketNo: ' + @CurTicketNo;

            IF (CHARINDEX('SNo', @FormatField) > 0)
            BEGIN
                PRINT 'I am here';
                SELECT @iSno = RowNo FROM #tmpTicketNoData WHERE Field = 'SNo';
                PRINT 'C';
                SELECT @i = CHARINDEX('SNo', @FormatValue) - 1, @i_n = CHARINDEX('SNo', @FormatValue) + 3;
                PRINT 'D';

               -- INSERT INTO #StrPos
     --            select ROW_NUMBER()over(order by ID) Sno,ID as Pos   
				 --into #StrPos  
				 --from dbo.[ufn_CountOccurrence_new](@FormatValue,'%'+ SUBSTRING(@FormatValue, @i, 1) + '%')  

				 CREATE TABLE #StrPos (Sno int identity(1,1), Pos int);

				DECLARE @pat varchar(max) = '%'+ SUBSTRING(@FormatValue, @i, 1) + '%';

				INSERT INTO #StrPos (Pos)
				SELECT n.n + 1
				FROM (SELECT TOP (LEN(@FormatValue)) ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) AS n FROM master.sys.columns) n
				WHERE SUBSTRING(@FormatValue, n.n, 1) = SUBSTRING(@pat, 2, 1);

				 PRINT 'E';

                INSERT INTO #StrPos_n
                SELECT ID AS Pos
                FROM dbo.[ufn_CountOccurrence_new](@FormatValue, '%' + SUBSTRING(@FormatValue, @i_n, 1) + '%');

                PRINT 'F';

                SELECT @iOcc = Sno FROM #StrPos WHERE Pos = @i;
                SELECT @iOcc_n = Sno FROM #StrPos_n WHERE Pos = @i_n;
                PRINT 'G';

                --SELECT @t1 = SUBSTRING(@FormatValue, 1, @i);
                --SELECT @t2 = SUBSTRING(@FormatValue, @i_n, LEN(@FormatValue));
				 Select @t1 = CASE WHEN @i > 0 THEN SUBSTRING(@FormatValue, 1, @i) ELSE '' END;
				 Select @t2 = CASE WHEN @i_n > 0 THEN SUBSTRING(@FormatValue, @i_n, LEN(@FormatValue)) ELSE '' END;


                PRINT 'H0';

                IF (ISNULL(@CurTicketNo, '') = '')
                BEGIN
                    SET @CurTicketNo = '00001';
                END;

                PRINT '@t1: ' + @t1;
                PRINT '@t2: ' + @t2;
                PRINT '@CurTicketNo: ' + @CurTicketNo;

                SET @tempTicketNo = REPLACE(ISNULL(@t1, ''), @CurTicketNo, '');
                SET @tempTicketNo = REPLACE(ISNULL(@t2, ''), @tempTicketNo, '');

                PRINT '@tempTicketNo: ' + @tempTicketNo;

                SELECT @SNo = ISNULL(TRY_CAST(@tempTicketNo AS INT), 1);

                PRINT '@SNo: ' + CAST(@SNo AS VARCHAR);

                IF (LEN(@tempTicketNo) = 0)
                BEGIN
                    SET @tempTicketNo = REPLICATE(' ', LEN(CAST(@SNo AS VARCHAR)));
                END;

                SELECT @TicketNo += RIGHT(REPLICATE('0', LEN(@tempTicketNo)) + CAST(@SNo AS VARCHAR), LEN(@tempTicketNo));
            END;
        END;
        ELSE
        BEGIN
            SET @StrSql = N'SELECT TOP 1 @TktNo = TicketNo FROM tbl_tp_TicketMaster(NOLOCK)_' + CAST(@ParentId AS VARCHAR) + N' ORDER BY TicketID DESC';

            PRINT '@strsql: ' + @StrSql;
            EXECUTE sp_executesql @StrSql, N'@TktNo NVARCHAR(100) OUTPUT', @TktNo = @CurTicketNo OUTPUT;
            PRINT '@CurTicketNo: ' + @CurTicketNo;

            IF (CHARINDEX('SNo', @FormatField) > 0)
            BEGIN
                SELECT @iSno = RowNo FROM #tmpTicketNoData WHERE Field = 'SNo';

                SELECT @t1 = STRING_AGG(Value, '') FROM #tmpTicketNoData WHERE RowNo < @iSno;
                SELECT @t2 = STRING_AGG(Value, '') FROM #tmpTicketNoData WHERE RowNo > @iSno;

                SET @tempTicketNo = REPLACE(ISNULL(@t1, ''), @CurTicketNo, '');
                SET @tempTicketNo = REPLACE(ISNULL(@t2, ''), @tempTicketNo, '');

                SELECT @SNo = CAST(@tempTicketNo AS INT) + 1;

                SELECT @TicketNo += RIGHT(REPLICATE('0', LEN(@tempTicketNo)) + CAST(@SNo AS VARCHAR), LEN(@tempTicketNo));
            END;
        END;
    END;

If(@FieldName='TktCategory')  
  Begin  
   select top 1 @TicketNo += TicketCategoryName   
   from tbl_tp_TicketCategory_Master(nolock) Where TicketCategoryId=@FieldValue  
  End  
  
  If(@FieldName='TktSource')  
  Begin  
   select top 1 @TicketNo += TicketSourceName   
   from tbl_tp_TicketSourceMaster(nolock) Where TicketSourceId=@FieldValue  
  End  
  
  If(@FieldType='Separator')  
  Begin  
   Set @TicketNo += @FieldValue  
  End  
  

    PRINT '@TicketNo: ' + @TicketNo;

    SET @RowNo += 1;
END

SELECT @TicketNo AS TicketNo;
END  


GO

/* ============================================================
   Procedure: [dbo].[usp_tp_GetNotificationValue]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec usp_tp_GetNotificationValue @ticketid=41863,@ParentID=37540,@groupid=953, @userid=2556,@Agentid=2556, @tableNm='Requester', @fldNm='Address' ,@type='Agent'           
--exec get_serv_notification_val_support1 @ticketid=41863,@ParentID=37540,@groupid=953, @userid=2556,@Agentid=2556, @tableNm='Requester', @fldNm='Address' ,@type='Requester'           
--exec get_serv_notification_val_support1 @ticketid=41873,@ParentID=37540,@groupid=0, @userid=2556,@Agentid=2556, @tableNm='Ticket', @fldNm='FeedbackURL' ,@type='Agent'         
--exec get_serv_notification_val_support1 @ticketid=41873,@ParentID=37540,@groupid=0, @userid=2556,@Agentid=2556, @tableNm='Company', @fldNm='Description' ,@type='Requester'         
--exec usp_tp_GetNotificationValue @ticketid=130,@ParentID=32222,@groupid=0, @userid=1,@Agentid=86, @tableNm='Ticket', @fldNm='AssignedBy' ,@type='Agent'        
/*        
its SLA for Resolution at #SLAResolutionDatetIme#. This is a reminder for you for the following ticket:  Subject -    <p>#Company.Description#</p>  <p>#Company.Notes#</p>  <p>#Requester.Email_ID#</p>  <p>#Ticket.Active#</p>           
<p>#Ticket.ARemindRSPNSSent#</p>  <p>#Ticket.ARemindResolveSent#</p>  <p>#Ticket.ARSPSent#</p>  <p>#Ticket.A1RSLSent#</p><p>#Ticket.A2RSLSent#</p>  <p>#Ticket.A3RSLSent#</p>  <p>#Ticket.A4RSLSent#</p>  <p>#Ticket.agrp_unassigned#</p>         
  <p>#Ticket.user_id_old#</p>  <p>#Ticket.assignedby_old#</p>  <p>#Ticket.assignto_old#</p>        
*/        
CREATE   PROCEDURE [dbo].[usp_tp_GetNotificationValue]        
(        
 @ticketid BIGINT,         
 @parentid BIGINT,         
 @groupid  BIGINT,         
 @userid   BIGINT,         
 @Agentid  BIGINT,         
 @TableNm  VARCHAR(MAX),         
 @fldNm    VARCHAR(MAX),         
 @type     VARCHAR(100),         
 @opt      INT = 1        
)        
AS        
BEGIN        
        
-- declare @ticketid BIGINT=41863, @parentid BIGINT=37540, @groupid  BIGINT=953, @userid BIGINT=2556, @Agentid  BIGINT=2556, @TableNm VARCHAR(MAX)='Requester',@fldNm VARCHAR(MAX)='name', @type VARCHAR(100)='Requester',@opt INT=1        
-- declare @ticketid BIGINT=41873, @parentid BIGINT=37540, @groupid  BIGINT=0, @userid BIGINT=2556, @Agentid  BIGINT=2556, @TableNm VARCHAR(MAX)='Ticket',@fldNm VARCHAR(MAX)='FeedbackURL', @type VARCHAR(100)='Agent',@opt INT=1        
-- declare @ticketid BIGINT=110, @parentid BIGINT=32222, @groupid  BIGINT=0, @userid BIGINT=1, @Agentid  BIGINT=1, @TableNm VARCHAR(MAX)='Ticket',@fldNm VARCHAR(MAX)='SLATimeLimit', @type VARCHAR(100)='Requester',@opt INT=1        
/*        
declare @tblnm VARCHAR(MAX)='Serv_User_Detail',@fldNm VARCHAR(MAX)='name'        
SELECT * FROM   sys.tables AS t INNER JOIN sys.columns AS c ON t.OBJECT_ID = c.OBJECT_ID WHERE  LOWER([c].[name]) = LOWER(@fldNm) AND LOWER([t].[name]) = @tblnm        
*/        
        
   print '------BEGIN----usp_tp_GetNotificationValue---------------------------'      
   print concat('@ticketid: ',@ticketid)      
   print concat('@parentid: ',@parentid)      
   print concat('@groupid: ',@groupid)      
   print concat('@userid: ',@userid)      
   print concat('@Agentid: ',@Agentid)      
   print concat('@TableNm: ',@TableNm)      
   print concat('@fldNm: ',@fldNm)      
   print concat('@type: ',@type)      
   print concat('@opt: ',@opt)      
      
 DECLARE @return VARCHAR(MAX)= '', @sqlstr NVARCHAR(MAX)= '', @strsql nvarchar(max)='';        
 DECLARE @virtual_domain as varchar(max), @TicketNo varchar(20), @virtual_domain1 as varchar(max), @randomexp NVARCHAR(10)        
 DECLARE @Randomexp1 VARCHAR(10), @ShortUrl VARCHAR(50), @tickethistoryid bigint                    
 DECLARE @word TABLE        
 (        
  [fldval] VARCHAR(MAX)        
 );        
        
 IF LOWER(@fldNm) != 'ticketurl' AND LOWER(@fldNm) != 'url' AND LOWER(@fldNm) != 'domainurl' AND LOWER(@fldNm) != 'siteurl' AND LOWER(@fldNm) != 'resetpasswordurl' AND LOWER(@fldNm) != 'forgotpasswordurl'  
 BEGIN        
        
  DECLARE @tblnm AS VARCHAR(100)= '', @flnm AS VARCHAR(100)= '';       
        
  --SELECT @tblnm = CASE WHEN LOWER(@TableNm) = 'ticket' THEN 'Serv_TicketMaster'        
 --    ELSE CASE WHEN LOWER(@TableNm) = 'agent' OR LOWER(@TableNm) = 'requester' THEN 'Serv_User_Detail'     --      ELSE CASE WHEN LOWER(@TableNm) = 'group' THEN 'Serv_Group_Mast'        
 --        ELSE CASE WHEN LOWER(@TableNm) = 'company' THEN 'Serv_User_Detail'        
 --          ELSE CASE WHEN LOWER(@TableNm) = 'domain' THEN 'serv_user_domain'        
 --         ELSE LOWER(@TableNm)        
 --         END        
 --          END        
 --        END        
 --      END        
 --    END;      
       
  SELECT @tblnm = CASE WHEN LOWER(@TableNm) = 'ticket' THEN 'tbl_tp_TicketMaster_'+cast(@parentid as varchar)     
       ELSE CASE WHEN LOWER(@TableNm) = 'agent' THEN 'tbl_tp_userLogin'  
       ELSE CASE WHEN LOWER(@TableNm) = 'group' THEN 'tbl_tp_GroupMaster'  
       ELSE CASE WHEN LOWER(@TableNm) = 'company' THEN 'tbl_tp_userLogin'  
       ELSE CASE WHEN LOWER(@TableNm) = 'domain' THEN 'tbl_tp_PortalSetting'  
       ELSE LOWER(@TableNm)  
      END  
      END        
    END        
   END        
  END;        
        
  IF LOWER(@fldNm) != 'responsetime' AND LOWER(@fldNm) != 'feedbackurl' and LOWER(@TableNm) not in ('entity','requester') and LOWER(@fldNm) not in ('slatimelimit','slaresolutiondatetime','assignto','assignedtogrouptime')    
  BEGIN        
   IF NOT EXISTS(SELECT 1 FROM   sys.tables AS t INNER JOIN sys.columns AS c        
     ON t.OBJECT_ID = c.OBJECT_ID        
     WHERE  LOWER([c].[name]) = LOWER(@fldNm) AND LOWER([t].[name]) = @tblnm)        
   BEGIN        
    SELECT '#' + @TableNm + '.' + @fldNm + '#';        
    RETURN;        
   END;        
  END;        
        
 IF LOWER(@TableNm) = 'ticket'        
 BEGIN        
  IF LOWER(@fldNm) = 'ticketno' AND @opt = 1        
  BEGIN        
   --SELECT @sqlstr = 'Select ''#ticket No:''+ ' + @fldNm + '+''#'' from dbo.Serv_TicketMaster(nolock) where TicketID = ' + CAST(@TicketId AS VARCHAR(MAX));        
   SELECT @sqlstr = 'Select ''#ticket No:''+ ' + @fldNm + '+''#'' from dbo.tbl_tp_TicketMaster_'+cast(@parentid as varchar)+'(nolock) where TicketID = ' + CAST(@TicketId AS VARCHAR(MAX));        
  END;        
  ELSE        
  BEGIN        
   IF LOWER(@fldNm) = 'responsetime'        
   BEGIN        
    SELECT GETDATE();        
   END        
   ELSE IF LOWER(@fldNm) in ('slaresolutiondatetime')    
   BEGIN    
	  select format(DATEADD(SECOND,max(SLD.Resolve_Sec),GETDATE()),'dd-MMM-yyyy hh:mm:ss')    
	  from tbl_tp_SLAMaster(nolock) SLM inner Join tbl_tp_SLADetail(nolock) SLD    
	  On SLM.SLA_Id=SLD.SLA_Id    
	  Where SLM.ParentId=@parentid and SLM.Active=1 and SLM.IsEnabled=1    
   END    
   ELSE IF LOWER(@fldNm) in ('slatimelimit')    
   BEGIN    
	  select format(DATEADD(SECOND,max(SLD.Respond_Sec),GETDATE()),'dd-MMM-yyyy hh:mm:ss')    
	  from tbl_tp_SLAMaster(nolock) SLM inner Join tbl_tp_SLADetail(nolock) SLD    
	  On SLM.SLA_Id=SLD.SLA_Id    
	  Where SLM.ParentId=@parentid and SLM.Active=1 and SLM.IsEnabled=1    
   END    
   ELSE IF LOWER(@fldNm) = 'userresponse' OR LOWER(@fldNm) = 'product' OR LOWER(@fldNm) = 'company' OR LOWER(@fldNm) = 'emailid'        
   BEGIN        
    --SELECT @sqlstr = 'Select isnull(' + @fldNm + ','''') from dbo.Serv_TicketMaster(nolock) where TicketID = ' + CAST(@TicketId AS VARCHAR(MAX));        
    SELECT @sqlstr = 'Select isnull(' + @fldNm + ','''') from dbo.tbl_tp_TicketMaster_'+cast(@parentid as varchar)+'(nolock) where TicketID = ' + CAST(@TicketId AS VARCHAR(MAX));        
   END        
   ELSE IF LOWER(@fldNm) = 'assigneddatetime' or LOWER(@fldNm) = 'update_date' or LOWER(@fldNm) = 'assignedtogrouptime'    
   BEGIN        
 --Select top 1 format(ActionDateTime,'dd-MMM-yyyy hh:mm:ss') From tbl_tp_TicketHistory(nolock) TH Where TicketID=@TicketId and ParentID=@parentid and isnull(AssignedUser,0)>0 or isnull(AssignedGroup,0)>0 order by 1 desc
 	 --Select top 1 format(AssignedDateTime,'dd-MMM-yyyy hh:mm:ss') From tbl_tp_TicketMaster_46198(nolock) TH Where TicketID=34 and ParentID=46198 and (isnull(AssignedUser,0)>0 or isnull(AssignedGroup,0)>0) order by 1 desc   

 SELECT @sqlstr = 'Select isnull(assigneddatetime,'''') from dbo.tbl_tp_TicketMaster_'+cast(@parentid as varchar)+'(nolock) where TicketID = ' + CAST(@TicketId AS VARCHAR(MAX)) +' and (isnull(AssignedUser,0)>0 or isnull(AssignedGroup,0)>0) order by 1 desc '  ;  
 
   print  (@sqlstr)
 exec (@sqlstr)

   END        
   ELSE IF LOWER(@fldNm) = 'resolved_dt'    
   BEGIN        
 --Select top 1 format(ActionDateTime,'dd-MMM-yyyy hh:mm:ss') From tbl_tp_TicketHistory(nolock) TH Where TicketID=@TicketId and ParentID=@parentid and dbo.ufn_tp_GetParentTicketStatus(TicketStatusID)=5 order by 1 desc 
 
     SELECT @sqlstr = 'Select isnull(LastActionDateTime,'''') from dbo.tbl_tp_TicketMaster_'+cast(@parentid as varchar)+'(nolock) where TicketID = ' + CAST(@TicketId AS VARCHAR(MAX)) + ' and dbo.ufn_tp_GetParentTicketStatus(TicketStatusID)=5 order by 1 desc ';  
	 exec (@sqlstr)
   END        
   ELSE IF LOWER(@fldNm) = 'assignedby' or LOWER(@fldNm) = 'update_by' or LOWER(@fldNm) = 'assignto' or lower(@fldNm) = 'assigneduser'      
   BEGIN        
  --If(LOWER(@fldNm) = 'assignto' or LOWER(@fldNm) = 'assignedby')    
  --Begin    
   set @fldNm='assigneduser'    
  --End    
    --SELECT @sqlstr = 'Select isnull((Select isnull(name,email) from serv_User_Detail(nolock) where ser_user_id in (select ' + @fldNm + ' from dbo.Serv_TicketMaster(nolock) where TicketID = ' + CAST(@TicketId AS VARCHAR(MAX)) + ')),'''')';            
