/* ============================================================
   Procedure: [dbo].[usp_tp_GetPageSectionDatesDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE [dbo].[usp_tp_GetPageSectionDatesDetails]
    @tpuserid BIGINT,
    @pageName NVARCHAR(MAX)
AS
BEGIN
--declare
--    @tpuserid BIGINT=1,
--    @pageName NVARCHAR(MAX)='Term & Condition'
    SET NOCOUNT ON;

    DECLARE @pageid INT;

    -- Get the page ID from tbl_tp_pagetheme
    SELECT @pageid = Page_Id
    FROM tbl_tp_pagetheme WITH (NOLOCK)
    WHERE PageName = @pageName AND isActive = 1;

    -- If page ID is found, get the page section details
    IF @pageid IS NOT NULL
    BEGIN
        -- Select the most appropriate record based on the current date
    SELECT *
        FROM tbl_tp_PageSectionDetail WITH (NOLOCK)
        WHERE tpuserid = @tpuserid 
          AND Page_Id = @pageid
          AND (IsActive = 1)        
       
    END
    ELSE
    BEGIN
        PRINT 'No active page found with the given page name.';
    END
END;



GO

/* ============================================================
   Procedure: [dbo].[usp_tp_GetPageSectionDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[usp_tp_GetPageSectionDetails]
    @tpuserid BIGINT,
    @pageName NVARCHAR(MAX)
AS
BEGIN
--declare
--    @tpuserid BIGINT=1,
--    @pageName NVARCHAR(MAX)='Term & Condition'
    SET NOCOUNT ON;

    DECLARE @pageid INT;

    -- Get the page ID from tbl_tp_pagetheme
    SELECT @pageid = Page_Id
    FROM tbl_tp_pagetheme WITH (NOLOCK)
    WHERE PageName = @pageName AND isActive = 1;

    -- If page ID is found, get the page section details
    IF @pageid IS NOT NULL
    BEGIN
        -- Select the most appropriate record based on the current date
    SELECT *
        FROM tbl_tp_PageSectionDetail WITH (NOLOCK)
        WHERE tpuserid = @tpuserid 
          AND Page_Id = @pageid
          AND (IsActive = 1)
          AND (StartDate IS NULL OR StartDate <= GETDATE())
          AND (EndDate IS NULL OR EndDate >= GETDATE())
        ORDER BY SectionNumber, StartDate DESC, CreatedDate DESC;
    END
    ELSE
    BEGIN
        PRINT 'No active page found with the given page name.';
    END
END;




GO

