    --    @pageName NVARCHAR(255) = 'About Us'; -- Escape single quote with double single quotes

    SET NOCOUNT ON;

    DECLARE @ParentId BIGINT;
    DECLARE @tpuserid BIGINT;

	DECLARE @SubDomain NVARCHAR(200);
            SET @SubDomain = SUBSTRING(@DomainName, LEN(@DomainName) - CHARINDEX('/', REVERSE(@DomainName)) + 2, LEN(@DomainName));
            DECLARE @FullPortalName NVARCHAR(MAX) = @DomainName + @SubDomain;

            IF EXISTS (
                SELECT 1
                FROM tbl_tp_Portalsetting WITH (NOLOCK)
                WHERE @SubDomain = PortalName
                GROUP BY PortalName
                HAVING COUNT(DISTINCT ParentId) > 1
            )
            BEGIN
                SELECT TOP 1 @ParentId = ParentId
                FROM tbl_tp_Portalsetting WITH (NOLOCK)
                WHERE @FullPortalName = @DomainName + PortalName
                ORDER BY ParentId;
            END
            ELSE
            BEGIN
                SELECT TOP 1 @ParentId = ParentId
                FROM tbl_tp_Portalsetting WITH (NOLOCK)
                WHERE @SubDomain = PortalName and IsActive=1;
            END
    -- Try to get ParentId from tbl_tp_client_domain
    --SELECT @ParentId = c.ParentId
    --FROM tbl_tp_client_domain c WITH (NOLOCK)
    --WHERE @DomainNameName = c.ClientDomain;

    ---- If ParentId is not found, try to get it from tbl_tp_Portalsetting
    --IF @ParentId IS NULL
    --BEGIN
    --    DECLARE @SubDomain NVARCHAR(200);
    --    SET @SubDomain = SUBSTRING(@DomainNameName, LEN(@DomainNameName) - CHARINDEX('/', REVERSE(@DomainNameName)) + 2, LEN(@DomainNameName));

    --    SELECT @ParentId = ParentId
    --    FROM tbl_tp_Portalsetting WITH (NOLOCK)
    --    WHERE @SubDomain = PortalName;
    --END;

    ---- If ParentId is still not found, try various replacements and pattern matching
    --IF @ParentId IS NULL
    --BEGIN
    --    SELECT @ParentId = c.ParentId
    --    FROM tbl_tp_client_domain c WITH (NOLOCK)
    --    WHERE REPLACE(@DomainNameName, 'www.', '') LIKE '%' + REPLACE(c.ClientDomain, 'www.', '') + '%';
    --END;

    --IF @ParentId IS NULL
    --BEGIN
    --    SELECT @ParentId = c.ParentId
    --    FROM tbl_tp_client_domain c WITH (NOLOCK)
    --    WHERE REPLACE(@DomainNameName, 'https://', '') LIKE '%' + REPLACE(c.ClientDomain, 'https://', '') + '%'
    --       OR REPLACE(@DomainNameName, 'http://', '') LIKE '%' + REPLACE(c.ClientDomain, 'http://', '') + '%';
    --END;

    --IF @ParentId IS NULL
    --BEGIN
    --    SELECT @ParentId = c.ParentId
    --    FROM tbl_tp_client_domain c WITH (NOLOCK)
    --    WHERE REPLACE(REPLACE(@DomainNameName, 'https://', ''), 'http://', '') LIKE '%' + REPLACE(REPLACE(c.ClientDomain, 'https://', ''), 'http://', '') + '%';
    --END;

    -- Get tpuserid based on ParentId
    SELECT @tpuserid = tpuserid
    FROM tbl_tp_pagesection WITH (NOLOCK)
    WHERE ParentId = @ParentId;


    -- Get page id from tbl_tp_pagetheme
    DECLARE @pageid INT;
    SELECT @pageid = Page_Id
    FROM tbl_tp_pagetheme WITH (NOLOCK)
    WHERE PageName = @pageName AND isActive = 1;
		pRINT @ParentId;
		print @tpuserid;
    -- If page id is found, get the page section details
    IF @pageid IS NOT NULL
    BEGIN
        -- Select the most appropriate record based on the current date
            WITH RankedSections AS (
            SELECT *, 
                ROW_NUMBER() OVER (
                    PARTITION BY SectionNumber 
                    ORDER BY 
                        CASE WHEN StartDate IS NULL THEN 1 ELSE 0 END,
                        StartDate DESC, 
                        CreatedDate DESC
                ) AS RowNum
            FROM tbl_tp_PageSectionDetail WITH (NOLOCK)
            WHERE ParentId = @ParentId 
              AND Page_Id = @pageid
              AND IsActive = 1
              AND (StartDate IS NULL OR CAST(StartDate AS DATE) <= CAST(GETDATE() AS DATE))
              AND (EndDate IS NULL OR CAST(EndDate AS DATE) >= CAST(GETDATE() AS DATE))
        )
        SELECT *
        FROM RankedSections
        WHERE RowNum = 1;
    END
    ELSE
    BEGIN
        PRINT 'No active page found with the given page name.';
    END
END;





