-- Create a stored procedure to fetch ParentId for a given ClientDomain
CREATE   PROCEDURE [dbo].[Usp_tp_GetParentIdByDomain]
    @Domain NVARCHAR(255)
AS
BEGIN
--DECLARE 
--   @Domain  NVARCHAR(200) = N'localhost',
  DECLARE @ParentId INT;
  SELECT @ParentId = ParentId
  FROM tbl_tp_client_domain WITH (NOLOCK)
   WHERE @Domain LIKE '%' + ClientDomain + '%';
 IF @ParentId IS NULL
BEGIN
    SELECT @ParentId = ParentId
    FROM tbl_tp_client_domain WITH (NOLOCK)
    WHERE REPLACE(@Domain, 'www.', '') LIKE '%' + REPLACE(ClientDomain, 'www.', '') + '%';
END;
IF @ParentId IS NULL
BEGIN
    SELECT @ParentId = ParentId
    FROM tbl_tp_client_domain WITH (NOLOCK)
    WHERE @Domain = ClientDomain;
END;
	SELECT ParentId,TpUser_Id 
    FROM dbo.tbl_tp_UserLogin
    WHERE ParentId = @ParentId;
END;


