CREATE   PROCEDURE [dbo].[usp_tp_GetPermissionbasedOnUser]  
    @tpuserId BIGINT,
    @PermissionCode VARCHAR(200),
    @MetaData NVARCHAR(200)
AS
BEGIN
--DECLARE 
--    @tpuserId BIGINT = 1,  
--    @PermissionCode VARCHAR(200) = '',
--    @MetaData NVARCHAR(200) = '{}'; 

SET NOCOUNT ON;

DECLARE @RolePermissions TABLE (
    Role_Id INT, 
    RoleName NVARCHAR(100), 
    Permission_Type NVARCHAR(200), 
    Permission_Code NVARCHAR(200),
    IsDefault BIT,
    IsPredefined BIT,
    IsAllowed BIT,
    FieldNames NVARCHAR(MAX)
);

DECLARE @AssignedUser BIGINT,  @IsAdmin BIT = 0,@UserID BIGINT, @TimeZone NVARCHAR(400),@DefaultCustomRoleId BIGINT, @DefaultPredefinedRoleId BIGINT;
 
 SELECT @UserID = User_Id, @TimeZone = isnull(TimeZone,'India Standard Time'),   
   @IsAdmin = (CASE WHEN User_Id = ParentId THEN 1 ELSE 0 END)  
 FROM tbl_tp_UserLogin(nolock)   
 WHERE TpUser_Id = @TpUserId AND IsActive = 1  
SET @AssignedUser = (
    SELECT TOP 1 tpuserid 
    FROM tbl_tp_agentrolemapping (NOLOCK) 
    WHERE tpuserid = @tpuserId and Active=1
);

if (@IsAdmin=1)
begin
    --INSERT INTO @RolePermissions (Role_Id, RoleName, Permission_Type, Permission_Code, IsDefault, IsPredefined, IsAllowed, FieldNames)
    SELECT 
        NULL AS Role_Id,
        NULL AS RoleName,
        NULL AS Permission_Type,
        Permission_Code,
        NULL AS IsDefault,
        NULL AS IsPredefined,
        NULL AS IsAllowed,
        'Userfield' AS FieldNames
    FROM tbl_tp_Permission_Master
	return
end
IF @AssignedUser > 0
BEGIN
    PRINT 'a';
    INSERT INTO @RolePermissions (Role_Id, RoleName, Permission_Type, Permission_Code, IsDefault, IsPredefined, IsAllowed, FieldNames)
    SELECT 
        arm.role_id, 
        rm.RoleName, 
        pm.Permission_Type, 
        pm.Permission_Code, 
        rm.IsDefault, 
        rm.IsPredefined, 
        pfg.IsAllowed, 
        COALESCE(STUFF((
            SELECT DISTINCT  ', ' + pfg2.FieldName
            FROM tbl_tp_PermissionField_Mapping pfg2
            WHERE pfg2.Permission_Id = pmg.Permission_Id
            FOR XML PATH('')), 1, 2, ''), '') AS FieldNames
    FROM tbl_tp_agentrolemapping (NOLOCK) arm
    INNER JOIN tbl_tp_RolesMaster (NOLOCK) rm ON arm.role_id = rm.Role_Id AND rm.IsActive = 1
    LEFT JOIN tbl_tp_Permission_Mapping (NOLOCK) pmg ON arm.role_id = pmg.Role_Id AND pmg.IsActive = 1
    LEFT JOIN tbl_tp_PermissionField_Mapping (NOLOCK) pfg ON pmg.Permission_Id = pfg.Permission_Id 
    LEFT JOIN tbl_tp_Permission_Master (NOLOCK) pm ON pmg.Permission_Id = pm.PermissionId AND pm.IsActive = 1
    WHERE arm.tpuserid = @tpuserId AND arm.Active = 1 
    AND pm.Permission_Type IS NOT NULL AND pm.Permission_Code IS NOT NULL;
END
ELSE
BEGIN
    SET @DefaultCustomRoleId = (
        SELECT TOP 1 Role_Id 
        FROM tbl_tp_RolesMaster (NOLOCK) 
        WHERE IsPredefined = 0 AND IsDefault = 1
    );

    IF @DefaultCustomRoleId > 0
    BEGIN
        PRINT 'b';
        INSERT INTO @RolePermissions (Role_Id, RoleName, Permission_Type, Permission_Code, IsDefault, IsPredefined, IsAllowed, FieldNames)
        SELECT 
            arm.role_id, 
            rm.RoleName, 
            pm.Permission_Type, 
            pm.Permission_Code, 
            rm.IsDefault, 
            rm.IsPredefined, 
            pfg.IsAllowed, 
            COALESCE(STUFF((
                SELECT  DISTINCT ', ' + pfg2.FieldName
                FROM tbl_tp_PermissionField_Mapping pfg2
                WHERE pfg2.Permission_Id = pmg.Permission_Id
                FOR XML PATH('')), 1, 2, ''), '') AS FieldNames
        FROM tbl_tp_agentrolemapping (NOLOCK) arm
        INNER JOIN tbl_tp_RolesMaster (NOLOCK) rm ON arm.role_id = rm.Role_Id AND rm.IsActive = 1
        LEFT JOIN tbl_tp_Permission_Mapping (NOLOCK) pmg ON arm.role_id = pmg.Role_Id AND pmg.IsActive = 1
        LEFT JOIN tbl_tp_PermissionField_Mapping (NOLOCK) pfg ON pmg.Role_Id = pfg.Role_Id AND pfg.IsActive = 1
        LEFT JOIN tbl_tp_Permission_Master (NOLOCK) pm ON pmg.Permission_Id = pm.PermissionId AND pm.IsActive = 1
        WHERE arm.tpuserid = @tpuserId OR arm.tpuserid = 0 AND arm.Active = 1 AND rm.IsDefault = 1
        AND pm.Permission_Type IS NOT NULL AND pm.Permission_Code IS NOT NULL;
    END
    ELSE
    BEGIN
        SET @DefaultPredefinedRoleId = (
            SELECT TOP 1 Role_Id 
            FROM tbl_tp_RolesMaster (NOLOCK) 
            WHERE IsPredefined = 1 AND IsDefault = 1
        );

        IF @DefaultPredefinedRoleId > 0
        BEGIN
            PRINT 'c';
            INSERT INTO @RolePermissions (Role_Id, RoleName, Permission_Type, Permission_Code, IsDefault, IsPredefined, IsAllowed, FieldNames)
            SELECT 
                arm.role_id, 
                rm.RoleName, 
                pm.Permission_Type, 
                pm.Permission_Code, 
                rm.IsDefault, 
                rm.IsPredefined, 
                pfg.IsAllowed, 
                COALESCE(STUFF((
                    SELECT DISTINCT ', ' + pfg2.FieldName
                    FROM tbl_tp_PermissionField_Mapping pfg2
                    WHERE pfg2.Permission_Id = pmg.Permission_Id
                    FOR XML PATH('')), 1, 2, ''), '') AS FieldNames
            FROM tbl_tp_agentrolemapping (NOLOCK) arm
            INNER JOIN tbl_tp_RolesMaster (NOLOCK) rm ON arm.role_id = rm.Role_Id AND rm.IsActive = 1
            LEFT JOIN tbl_tp_Permission_Mapping (NOLOCK) pmg ON arm.role_id = pmg.Role_Id AND pmg.IsActive = 1
            LEFT JOIN tbl_tp_PermissionField_Mapping (NOLOCK) pfg ON pmg.Role_Id = pfg.Role_Id AND pfg.IsActive = 1
            LEFT JOIN tbl_tp_Permission_Master (NOLOCK) pm ON pmg.Permission_Id = pm.PermissionId AND pm.IsActive = 1
            WHERE (arm.tpuserid = @tpuserId OR arm.tpuserid IS NULL) AND arm.Active = 1
            AND pm.Permission_Type IS NOT NULL AND pm.Permission_Code IS NOT NULL;
        END
    END
END

SELECT Role_Id, RoleName, Permission_Type, Permission_Code, IsDefault, IsPredefined, FieldNames, IsAllowed
FROM (
    SELECT Role_Id, RoleName, Permission_Type, Permission_Code, IsDefault, IsPredefined, FieldNames, IsAllowed,
           ROW_NUMBER() OVER (PARTITION BY Permission_Type ORDER BY (SELECT NULL)) AS rn
    FROM @RolePermissions
) AS T
WHERE rn = 1;
END;



