/* ============================================================
   Procedure: [dbo].[usp_tp_GetPlaceHolderFields]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


-- Exec usp_tp_GetPlaceHolderFields @TpUserId=1
CREATE   PROC usp_tp_GetPlaceHolderFields
(
	@TpUserId bigint
)
AS
BEGIN
--DECLARE @TpUserId bigint=1
DECLARE @TicketTableName NVARCHAR(MAX) = '', @Prefix varchar(50)='',@ParentID bigint

Select @ParentID=ParentID From tbl_tp_UserLogin(nolock) Where TpUser_Id=@TpUserId
                            
EXEC Usp_tp_CreateTicketMasterTableByParentID @ParentID, @TicketTableName OUTPUT      

DROP TABLE if exists #ColumnInformation;    
      
CREATE TABLE #ColumnInformation ( 
	RowId	int identity(1,1),
    TableName NVARCHAR(MAX),      
    ColumnName NVARCHAR(MAX),      
    DataType NVARCHAR(MAX),      
    FieldType NVARCHAR(MAX),      
    Choices NVARCHAR(MAX),       
    ColumnValue NVARCHAR(MAX)       
)      

Set @Prefix='Ticket.'      

INSERT INTO #ColumnInformation(TableName,ColumnName,DataType,FieldType,Choices)
SELECT DISTINCT      
    @TicketTableName AS TableName,      
    concat(@Prefix,REPLACE(I.COLUMN_NAME, 'Id', '')) AS ColumnName,      
    I.DATA_TYPE AS DataType,      
    'Main' AS FieldType,      
    '' AS Choices      
FROM      
    INFORMATION_SCHEMA.COLUMNS I      
WHERE      
    I.TABLE_NAME = @TicketTableName      
    AND I.COLUMN_NAME NOT IN (      
        'TicketID', 'tpUser_Id', 'TicketStatusID', 'ParentID', 'RequesterMobileNo1', 'RequesterEmailID1',      
        'RequesterMobileNo2', 'RequesterEmailID2', 'UserResponse', 'ProductId', 'IsMerged', 'IsSplitted',      
        'ParentTicketId', 'EntityId', 'EntityName', 'IsParentTicket', 'IsChildTicket', 'AssignedBy',      
        'TicketTag', 'IsActive', 'CreatedBy', 'ModifiedBy', 'ModifiedOn', 'SplittedBy', 'SplittedOn',      
        'MergedBy', 'MergedOn', 'ClosedBy', 'ClosedOn', 'CreatedChildBy', 'CreatedChildOn,AssignedSource'      
    )      
  
 Delete from #ColumnInformation Where ColumnName in (  
  SELECT  
  concat(@Prefix,JSON_VALUE(value, '$.FieldName')) AS ColumnName  
  FROM OPENJSON((SELECT DisplayJson FROM tbL_tp_TicketCustomFieldDisplayJson(nolock) WHERE ParentId = @ParentID))  
  WHERE JSON_VALUE(value, '$.Active') = 'false'  
 )  
  
 Update C set C.FieldType='Custom', C.Choices=T.Choices 
  -- SELECT *
  FROM OPENJSON (
	(SELECT DisplayJson FROM tbL_tp_TicketCustomFieldDisplayJson(nolock) WHERE ParentId = @ParentID)
  ) 
  WITH
  (
	ColumnName varchar(50) '$.FieldName',
	Choices varchar(max) '$.Choices',
	Active bit '$.Active'
  ) T
  inner join #ColumnInformation C
  ON	concat(@Prefix,T.ColumnName)=C.ColumnName
  WHERE T.Active = 'True'  
  
      
 ;WITH DuplicateColumns AS (    
    SELECT    
        ColumnName,    
        DataType,    
        ROW_NUMBER() OVER (PARTITION BY ColumnName ORDER BY (SELECT NULL)) AS RowNum    
    FROM    
        #ColumnInformation    
)    
    
DELETE FROM DuplicateColumns    
WHERE RowNum > 1;    
    
	--- Enquiry Columns
	--insert into #ColumnInformation(ColumnName,DataType,Choices)
	--Exec usp_GetEnquiryImportFields @UserId=@ParentID

	--Delete from #ColumnInformation Where Choices='-1'

	--Update #ColumnInformation 
	--Set Choices='',TableName='UserEnquiry',FieldType=case when Choices='0' then 'EnquiryMain' else 'EnquiryCustom' end, ColumnName=concat('Enquiry.',ColumnName)
	--Where TableName is null
   

   --- Lead Columns
	insert into #ColumnInformation(ColumnName,DataType,Choices)
	Exec usp_GetLeadImportFields @UserId=@ParentID

	Delete from #ColumnInformation Where Choices='-1'

	Update #ColumnInformation 
	Set Choices='',TableName='UserLeads',FieldType=case when Choices='0' then 'LeadMain' else 'LeadCustom' end, ColumnName=concat('Entity.',ColumnName)
	Where TableName is null
 
	set @Prefix='User.'
	INSERT INTO #ColumnInformation(TableName,ColumnName,DataType,FieldType,Choices)
	SELECT DISTINCT      
		'User_Detail' AS TableName,      
		concat(@Prefix,REPLACE(I.COLUMN_NAME, 'Id', '')) AS ColumnName,      
		I.DATA_TYPE AS DataType,      
		'UserMain' AS FieldType,      
		'' AS Choices      
	FROM      
		INFORMATION_SCHEMA.COLUMNS I      
	WHERE      
		I.TABLE_NAME = 'User_Detail'      
		AND I.COLUMN_NAME NOT IN (      
			'ID', 'M_ID', 'User_ID', 'ParentID', 'Pwd', 'Type',     
			'SType', 'ACType', 'Banner_ID', 'Banner_IDR', 'Banner_ID_Owner', 'Banner_ID_Reseller',     
			'Priority', 'DateCreated','DateUpdated','EmpUpdated','MachineName','LastModified','SmppID','R_mode',
			'userfilter','FilterMode','ServiceTypeID','ServiceType','UserGroup','Gender','Pincode','Address',
			'LoginType','Merchant_Code','Merchant_Url','User_DOB','ProfilePictureName', 'UserType', 'Office_Name',
			'Usercategory', 'OnlineStatus','DOE','DeviceID','Version','AccountType','IsInternalUser','IsAdmin',
			'ParentID','LastLogin2','LastLogin1','isverify','randomnumber','IsSuperReseller','HasVirtualCredits',
			'ParentSuperResellerId','Isdemo','resetguid','resetrequested','resetexpired','referrerid',
			'referredcontactid','Source','Medium','Campaign', 'Cloudrole','onduty','MobileCountryCode',
			'Support_Access','Image','isdemoaccount','Presence','IsBusyOnCall','OTP','OnField','MACAddress',
			'AppVersion','OSVersion','OSName','ModelName','IsForceOffFeild','wa_country_code','wa_mobile_no',
			'wa_profile_id','CompanyType','Country_ID'
		)      

	SELECT  * FROM #ColumnInformation order by 1  

END



