CREATE   PROCEDURE [dbo].[Usp_tp_GetPoliciesList]          
 @ParentId Bigint      
AS          
BEGIN      
    
    Select * From Serv_SLA_Freq where val_sec < 0      
    Select * From Serv_SLA_Freq where val_sec > 0     
     
   ---------------------------  Group Master ---------------------------------------------------                  
                     
     Select GroupId AS Group_Id,GroupName AS Group_Name From tbl_tp_GroupMaster (NOLOCK) Where ParentID =  @ParentId AND Active=1 order by Groupid asc                 
                
    ---------------------------  Agent Master ---------------------------------------------------                  
                     
     Select ParentId,TpUser_Id,Name + ('('+LoginName+')') as Name From tbl_tp_UserLogin (NOLOCK) Where ParentID =  @ParentId AND User_Id IS NOT NULL AND  IsActive = 1 order by TpUser_Id asc      
  
   ---------------------------  Priority Master ---------------------------------------------------    
  
   Select Priority_ID,PriorityName From tbl_tp_TicketPriorityMaster (NOLOCK) Where  Active = 1 AND (ParentId = @ParentId OR ParentId IS NULL)  
      
END





