/* ============================================================
   Procedure: [dbo].[Usp_tp_GetScenarioRulesList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_GetScenarioRulesList]  --1,'{}'      
(        
    @TpUserId BIGINT = NULL,        
    @MetaData NVARCHAR(200) = NULL        
)        
AS        
BEGIN   
    --DECLARE  @TpUserId BIGINT = 1,        
    --         @MetaData NVARCHAR(200)=N'{"IPAddress":"::1","MacAddress":"00FF61AD0C56","IsImpersonation":false,"ImpersonatorId":0}'  
    DECLARE @UserId BIGINT,   
         @ParentId BIGINT,  
            @TimeZone NVARCHAR(400),        
            @rowJson NVARCHAR(MAX),        
            @IPAdress NVARCHAR(50),        
            @DeviceId NVARCHAR(50),        
            @IsImpersonation BIT,        
            @ImpersonatorId INT        
        
    SELECT @UserId = User_Id, @ParentId=ParentId, @TimeZone=isnull(TimeZone,'India Standard Time') FROM tbl_tp_UserLogin (NOLOCK) WHERE TpUser_Id = @TpUserId AND IsActive = 1        
        
    SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)        
    SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)        
    SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)        
    SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)        
        
    SELECT M.Scenario_Id,M.Scenario_Name,M.Scenario_Description,M.SequenceNo,M.Active,M.ParentId,M.CreatedBy,TUL1.Name,    
    TUL1.LoginName,dbo.fn_ConvertDateTime(M.CreatedDate, @TimeZone, 0) CreatedDate,M.IsEnabled,C.Condtion_Id,C.FieldName,C.Operator,C.Value,C.Conjunction,C.SequenceNo,        
    C.Active,A.ScenarioAction_Id,A.Action_Id,A.Action_Value,A.SequenceNo,A.Active,A.ParentId,A.createdBy,A.CreatedDate,        
    CASE  WHEN A.Action_Id = 2 THEN SGM.GroupName   WHEN A.Action_Id = 1 THEN TUL.Name        
          WHEN A.Action_Id = 4 THEN TSM.TicketStatus ELSE NULL END AS ValueName,ATM.Description AS ActionTypeDescription        
    FROM tbl_tp_ScenarioMaster AS M    
    JOIN tbl_tp_ScenarioCondition AS C ON M.Scenario_Id = C.Scenario_Id    
    JOIN tbl_tp_ScenarioAction AS A ON M.Scenario_Id = A.Scenario_Id    
    LEFT JOIN tbl_tp_GroupMaster SGM ON A.Action_Id = 2 AND SGM.Groupid = A.Action_Value    
    LEFT JOIN tbl_tp_UserLogin TUL ON A.Action_Id = 1 AND TUL.User_Id = A.Action_Value    
    LEFT JOIN tbl_tp_ticketstatusmaster TSM ON A.Action_Id = 4 AND TSM.TicketStatus_ID = A.Action_Value    
    LEFT JOIN tbl_tp_ActionTypeMaster ATM ON ATM.ActionType_Id = A.Action_Id    
    LEFT JOIN tbl_tp_UserLogin TUL1 ON TUL1.User_Id = M.CreatedBy    
    WHERE (M.ParentId = @ParentId) AND M.Active = 1  
	ORDER BY M.SequenceNo
    
        
    SET @rowJson = (SELECT * FROM tbl_tp_ScenarioMaster FOR JSON AUTO, INCLUDE_NULL_VALUES)        
        
    IF @rowJson IS NOT NULL        
    BEGIN        
        EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData        
            @User_id = @UserId,        
            @Activity_type = 'View_ScenarioMaster',        
            @ActionType = 'S',        
            @RowJson = '',        
            @Table_name = 'tbl_tp_ScenarioMaster',        
            @ip_adress = @IPAdress,        
            @device_id = @DeviceId,        
            @IsImpersonation = @IsImpersonation,        
            @ImpersonatorId = @ImpersonatorId        
    END        
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_tp_GetSetTemplateCols]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_tp_GetSetTemplateCols]    
(    
 @UserId bigint,    
 @TemplateType varchar(3)='EN', --'EN' Enquiry,'LD' Lead    
 @TemplateCols Nvarchar(max)='',    
 @Mode varchar(3)='Get'    
)    
AS    
BEGIN    
declare @ParentId bigint
SET @ParentId = (SELECT ParentId 
                 FROM tbl_tp_UserLogin (NOLOCK) 
                 WHERE TpUser_Id = @UserId);
 If(@Mode = 'Get')    
 Begin    
  declare @ColList nvarchar(max)='';    
    
  Select @ColList=ColumnList From tbl_tp_ViewTickettemplate(nolock) Where TpUserId = @UserId and TemplateType=@TemplateType    
    
  select @ColList as ColList    
 End    
    
 If(@Mode = 'Set')    
 Begin    
  IF EXISTS(Select * From tbl_tp_ViewTickettemplate(nolock) Where TpUserId = @Userid and TemplateType=@TemplateType)    
  BEGIN    
   Update tbl_tp_ViewTickettemplate set ColumnList=@TemplateCols,ModifiedDate=GETDATE()  Where TpUserId = @UserId and TemplateType=@TemplateType    
  END    
  ELSE    
  BEGIN    
   insert into [tbl_tp_ViewTickettemplate] values(@TemplateCols,@UserId,@ParentId,GETDATE(),null,@TemplateType ) 
  END    
    
  select @@ROWCOUNT as ColList    
 End    
    
END 





GO

