/* ============================================================
   Procedure: [dbo].[usp_tp_GetSkillBasedValues]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_tp_GetSkillBasedValues]        
          
@TpUserId BIGINT,         
@SelectedType NVARCHAR(50)         
          
AS              
BEGIN              
              
    DECLARE  @TimeZone nvarchar (400)  ,@rowJson NVARCHAR(MAX)  , @IPAdress NVARCHAR(50),@DeviceId NVARCHAR(50),@IsImpersonation BIT ,@ImpersonatorId INT , @ParentId Bigint        
        
    Select @ParentId = ParentID,@TimeZone = TimeZone  From tbl_tp_UserLogin (noLock) Where TpUser_Id = @TpUserId AND IsActive = 1         
        
IF @SelectedType = 'Priority'       
BEGIN        
    SELECT Priority_ID AS Id,  PriorityName AS Name         
    FROM tbl_tp_TicketPriorityMaster (NOLOCK)        
    WHERE Active = 1 AND ParentId = @ParentId        
    ORDER BY Priority_ID ASC;        
END        
      
IF @SelectedType = 'Type'       
BEGIN        
    SELECT Type_ID AS Id, Type_Desc AS Name        
    FROM tbl_tp_TicketType_Master (NOLOCK)        
    WHERE Active = 1 AND ParentId = @ParentId        
    ORDER BY Type_ID ASC;        
END        
      
IF @SelectedType = 'Source'      
BEGIN        
    SELECT TicketSourceId AS Id, TicketSourceName AS Name        
    FROM tbl_tp_TicketSourceMaster (NOLOCK)        
    WHERE IsActive = 1 AND ParentId = @ParentId        
    ORDER BY TicketSourceId ASC;        
END       
IF @SelectedType = 'Group'       
BEGIN        
        
     Select  GroupName AS Name,GroupId As Id from tbl_tp_GroupMaster(nolock)        
    WHERE Active = 1 AND ParentId = @ParentId        
    ORDER BY ID ASC;        
END       
IF @SelectedType = 'Product'       
BEGIN        
    DECLARE @TableName NVARCHAR(255);        
    DECLARE @SQL NVARCHAR(MAX);        
        
    SET @TableName = CONCAT('tbl_productmaster_', @ParentId);        
        
    SET @SQL = N'SELECT ProductID As Id, Name FROM ' + QUOTENAME(@TableName) + N' WITH (NOLOCK) WHERE IsActive = 1 ORDER BY ProductID ASC';        
        
    EXEC sp_executesql @SQL;        
END;        
IF @SelectedType = 'Segment'       
BEGIN        
        
     Select  CriteriaName AS Name,ID As Id from tbl_SearchCriteria(nolock)        
    WHERE IsActive = 1 AND ParentId = @ParentId        
    ORDER BY ID ASC;        
END        
            
              
END  


