/* ============================================================
   Procedure: [dbo].[Usp_tp_GetSkillMasterDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--Exec Usp_tp_GetSkillMasterDetails 1234
--Exec Usp_tp_GetSkillMasterDetails 32222
CREATE   PROCEDURE [dbo].[Usp_tp_GetSkillMasterDetails] --32222,'{}'
(
    @UserID BIGINT,
    @MetaData NVARCHAR(200)
)
AS
BEGIN

DECLARE @ParentID BIGINT, @TimeZone NVARCHAR(400), @rowJson NVARCHAR(MAX), @IPAdress NVARCHAR(50), @DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT;
SELECT @TimeZone = TimeZone FROM User_Detail (NOLOCK) WHERE User_Id = @UserID;
SELECT @ParentID = ParentId FROM tbl_tp_UserLogin (NOLOCK) WHERE User_Id = @UserID;

SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress);
SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress);
SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation);
SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId);

DECLARE @DynamicTableName NVARCHAR(100);
SET @DynamicTableName = 'tbl_productmaster_' + CAST(@ParentID AS NVARCHAR(10));

DECLARE @SQL NVARCHAR(MAX);
SET @SQL = N'
    SELECT
        SM.Skill_Id AS TicketId,
        SM.ParentId,
        SM.SkillName AS Skill_Name,
        dbo.fn_ConvertDateTime(SM.CreatedDate, @TimeZone, 0) AS Created_Date,
        SM.Active,
        SC.SkillCondtion_Id,
        SC.FieldName,
        SC.ActionType,
		SC.Operator,
        CASE
            WHEN SC.ActionType = ''Source'' THEN Source.TicketSourceName
            WHEN SC.ActionType = ''Group'' THEN [Group].GroupName
            ELSE SC.Value
        END AS ValueName,
        SC.Conjunction,
        SC.SequenceNo,
        SC.Active AS ConditionActive,
        SC.ParentId AS ConditionParentId,
        SC.createdBy AS ConditionCreatedBy,
        dbo.fn_ConvertDateTime(SC.CreatedDate, @TimeZone, 0) AS ConditionCreatedDate
    FROM tbl_tp_SkillMaster AS SM
    LEFT JOIN tbl_tp_SkillCondition AS SC ON SM.Skill_Id = SC.Skill_Id
    LEFT JOIN tbl_tp_TicketSourceMaster AS Source ON SC.ActionType = ''Source'' AND Source.TicketSourceId = SC.Value
    LEFT JOIN tbl_tp_GroupMaster AS [Group] ON SC.ActionType = ''Group'' AND [Group].GroupId = SC.Value
    LEFT JOIN tbl_tp_TicketType_Master AS TicketType ON SC.ActionType = ''SetType'' AND TicketType.Type_ID = SC.Value
    LEFT JOIN tbl_tp_TicketPriorityMaster AS TicketPriority ON SC.ActionType = ''SetPriority'' AND TicketPriority.Priority_ID = SC.Value
    LEFT JOIN ' + @DynamicTableName + ' AS ProductMaster ON SC.ActionType = ''Product'' AND ProductMaster.ProductID = SC.Value
    WHERE (SM.ParentId = @ParentID OR SM.ParentId IS NULL)
        AND SM.Active = 1
    ORDER BY SM.CreatedDate DESC;';

EXEC sp_executesql @SQL, N'@ParentID BIGINT, @TimeZone NVARCHAR(400)', @ParentID, @TimeZone;

IF @rowJson IS NOT NULL
BEGIN
    EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData
        @User_id = @UserID,
        @Activity_type = 'View_skillmaster',
        @ActionType = 'S',
        @RowJson = 'NULL',
        @Table_name = 'tbl_tp_SkillMaster',
        @ip_adress = @IPAdress,
        @device_id = @DeviceId,
        @IsImpersonation = @IsImpersonation,
        @ImpersonatorId = @ImpersonatorId;
END

END;



GO

