/* ============================================================
   Procedure: [dbo].[Usp_tp_GetTicketCategoryStatusAndType_temp]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

                                       
CREATE   PROCEDURE [dbo].[Usp_tp_GetTicketCategoryStatusAndType_temp]          --32222                                         
                          
  @TpUserId Bigint                        
                        
As                                                        
Begin                            
                        
DECLARE @TableName NVARCHAR(100), @SQL NVARCHAR(MAX), @UserID BIGINT  ,@ParentId BIGINT                      
                
SELECT @UserID = User_Id,@ParentId = ParentId From tbl_tp_UserLogin Where TpUser_Id = @TpUserId AND IsActive = 1                       
                          
--------------- Ticket Priority ----------------------------------------------                          
                                        
 SELECT Priority_ID AS PriorityID,PriorityName AS PriorityName  FROM tbl_tp_TicketPriorityMaster (nolock)                          
 Where  Active=1 AND  ParentId = @ParentId order by Priority_ID asc                            
                          
 --------------- Ticket Category ----------------------------------------------                          
                           
  SELECT TicketCategoryId,TicketCategoryName   FROM tbl_tp_TicketCategory_Master (nolock)                          
 Where  IsActive=1 AND ParentId = @ParentId order by TicketCategoryId asc                            
                          
 --------------- Ticket Type ----------------------------------------------                          
                          
  SELECT Type_ID AS TypeID,Type_Name AS TypeDesc  FROM tbl_tp_TicketType_Master (nolock)                          
 Where  Active=1 AND ParentId = @ParentId order by Type_ID asc                            
                          
 --------------- Ticket Status ----------------------------------------------                          
                          
  SELECT TicketStatus_ID AS TicketStatusID,TicketStatus AS TicketStatus  FROM tbl_tp_TicketStatusMaster (nolock)                          
 Where  IsActive=1 AND ParentId = @ParentId order by TicketStatus_ID asc                            
                          
  --------------- Ticket Source ----------------------------------------------                          
                          
  SELECT TicketSourceId,TicketSourceName  FROM tbl_tp_TicketSourceMaster (nolock)                          
 Where  IsActive=1 AND ParentId = @ParentId order by TicketSourceId asc                            
                          
  --------------- Ticket Skill ----------------------------------------------                          
                          
  SELECT Skill_Id AS SkillId,SkillName   FROM tbl_tp_SkillMaster (nolock)                          
 Where  Active=1 AND ParentId = @ParentId  order by Skill_Id asc                        
                        
   --------------- Ticket Tag ----------------------------------------------                          
                          
  SELECT ID,Tag   FROM  TagMaster (nolock)  Where ParentID =  @ParentId AND IsActive=1 order by ID asc                        
                        
   --------------- Ticket Product ----------------------------------------------                          
   SET @TableName = CONCAT('tbl_productmaster_', @ParentId);                        
                        
   SET @SQL = N' SELECT ProductID, Name FROM ' + QUOTENAME(@TableName) + N' WITH (NOLOCK) WHERE IsActive = 1 ORDER BY ProductID ASC';                        
                        
    EXEC sp_executesql @SQL;                        
                      
 ---------------------------  Time Span ---------------------------------------------------                      
                         
     Select * From TimeIntervals                     
                    
   ---------------------------  Group Master ---------------------------------------------------                      
                         
     Select GroupId AS Group_Id,GroupName AS Group_Name From tbl_tp_GroupMaster Where ParentID =  @ParentId AND Active=1 order by Groupid asc        
   ---------------------------  Role Master ---------------------------------------------------                               
                    
    ---------------------------  Agent Master ---------------------------------------------------                      
                         
     Select ParentId,User_Id,Name  From tbl_tp_UserLogin Where ParentID =  @ParentId AND User_Id IS NOT NULL AND  IsActive = 1 order by TpUser_Id asc                  
                
      ---------------------------  Agent Master ---------------------------------------------------                
                         
         Select Role_Id AS RoleId,RoleName AS RoleName From tbl_tp_RolesMaster               
                  
                  
    ---------------------------  Country Master ---------------------------------------------------                    
                    
   SELECT Country_Name,ltrim(rtrim(CountryCode)) AS CountryCode, Country_ID FROM   m_country1 (nolock) ORDER BY Country_Name                    
                
   --------------------   User Lead Source Setting -------------------------------------------------------------------------                
                
    SELECT SourceID, NAME FROM   UserSourceSettings(nolock) WHERE  UserID = @UserID AND IsActive = 1 ORDER BY SourceID DESC                  
                
 --------------------   User Lead Follow Up Status Master -------------------------------------------------------------------------                
                
IF EXISTS (SELECT * FROM FollowUp_Status (NOLOCK) WHERE ParentId = @ParentId)                
BEGIN                
    SELECT (CAST(ID AS VARCHAR(10)) + ',' + CAST(IsCallback AS VARCHAR) + ',' + CAST(IsConvert AS VARCHAR)) AS FUPValue,                
           fus.ID,                
           fus.FollowupStatus,                
           fus.Intent,                
           OrderNumber,                
           IsCallback,                
           IsConvert,                
           IsDisabled                
    FROM FollowUp_Status (NOLOCK) AS fus                
    WHERE fus.IsActive = 1 AND IsDisabled = 0 AND fus.ParentId = @ParentId                
    ORDER BY fus.OrderNumber ASC;                
END                
ELSE                
BEGIN                
    SELECT (CAST(ID AS VARCHAR(10)) + ',' + CAST(IsCallback AS VARCHAR) + ',' + CAST(IsConvert AS VARCHAR)) AS FUPValue,                
           fus.ID,                
           fus.FollowupStatus,                
           fus.Intent,                
           OrderNumber,                
           IsCallback,                
           IsConvert,                
           IsDisabled                
    FROM FollowUp_Status (NOLOCK) AS fus                
    WHERE fus.IsActive = 1 AND ParentId IS NULL                
    ORDER BY fus.OrderNumber ASC;                
END                
                
                
--------------------   User Lead Medium Setting -------------------------------------------------------------------------                
                
 SELECT MediumID,  NAME  FROM   UserMediumSettings  WHERE  UserID = @UserID  AND IsActive = 1  ORDER BY  MediumID DESC                
                
 --------------------   User Lead Compaign Setting -------------------------------------------------------------------------             
             
  SELECT CampaignID,  NAME FROM UserCampaignSettings(nolock)  WHERE  UserID = @UserID    AND IsActive = 1  ORDER BY    CampaignID DESC                 
            
   --------------------   Filter Setting -------------------------------------------------------------------------              
     DECLARE @status INT                      
     DECLARE @TicketTableName NVARCHAR(MAX) = ''            
     EXEC @status = Usp_tp_CreateTicketMasterTableByParentID @ParentID, @TicketTableName OUTPUT           
    DECLARE @SqlQuery NVARCHAR(MAX)          
SET @SqlQuery = '          
    SELECT COLUMN_NAME          
    FROM INFORMATION_SCHEMA.COLUMNS          
    WHERE TABLE_NAME = @TicketTableName          
    AND COLUMN_NAME NOT IN (          
     ''TicketID'',          
     ''tpUser_Id'',          
  ''TicketStatusID'',          
        ''ParentID'',          
        ''RequesterMobileNo1'',          
        ''RequesterEmailID1'',          
        ''RequesterMobileNo2'',          
        ''RequesterEmailID2'',          
        ''TicketPriority'',          
        ''UserResponse'',          
        ''AssignedUser'',          
        ''AssignedGroup'',          
        ''AssignedSource'',          
        ''TicketCategoryId'',          
        ''TicketTypeId'',          
        ''TicketSourceId'',          
        ''ProductId'',          
        ''IsMerged'',          
        ''IsSplitted'',          
  ''ParentTicketId'',          
  ''EntityId'',          
  ''EntityName'',          
        ''IsParentTicket'',          
        ''IsChildTicket'',          
        ''AssignedBy'',          
        ''TicketTag'',          
        ''IsActive'',          
        ''CreatedBy'',          
        ''ModifiedBy'',          
        ''ModifiedOn'',          
        ''SplittedBy'',          
        ''SplittedOn'',          
        ''MergedBy'',          
        ''MergedOn'',          
        ''ClosedBy'',          
        ''ClosedOn'',          
        ''CreatedChildBy'',          
        ''CreatedChildOn''          
    )'          
           
EXEC sp_executesql @SqlQuery, N'@TicketTableName NVARCHAR(128)', @TicketTableName         
      
--- DID Numbers ------------------------------------------      
      
EXEC Cloud_User_Phone_distribution @ParentId = @ParentId      
          
                 
    END 



GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_GetTicketCountAndReports]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_tp_GetTicketCountAndReports]
    @TpUserId BIGINT
AS
BEGIN
--declare @TpUserId BIGINT=929
    SET NOCOUNT ON;

    DECLARE @ParentId BIGINT, @TableName NVARCHAR(100), @SQL NVARCHAR(MAX), @IsAdmin BIT = 0

    SELECT @ParentId = ParentId
    FROM tbl_tp_UserLogin
    WHERE TpUser_Id = @TpUserId AND IsActive = 1

    SET @TableName = CONCAT('tbl_tp_TicketMaster_', @ParentId);

    SET @SQL = 
        N'
       select NameOfExecutive=concat(UL.Name,''('',UL.LoginName,'')''), 
	TicketsAssignedToday=(Select count(*) From ' + @TableName + ' (NOLOCK) TM Where TM.AssignedUser=UL.TpUser_Id and cast(TM.AssignedDateTime as date)=cast(getdate() as date)), 
	TicketsAssignedThisMonth=(Select count(*) From ' + @TableName + ' (NOLOCK) TM Where TM.AssignedUser=UL.TpUser_Id and month(TM.AssignedDateTime)=month(getdate()) and year(TM.AssignedDateTime)=year(getdate())),
	TicketsClosedToday=(Select count(*) From vw_tp_LastTicketHistory(nolock) TM Where TM.AssignedUser=UL.TpUser_Id and cast(TM.ActionDateTime as date)=cast(getdate() as date) and dbo.ufn_tp_GetParentTicketStatus(TM.TicketStatusID) in (3,5,8,9,10)),
	TicketsCreatedToday=(SELECT COUNT(*) FROM ' + @TableName + ' (NOLOCK) TM WHERE  CAST(TM.CreatedOn AS DATE) = CAST(GETDATE() AS DATE) and  TM.CreatedBy= UL.TpUser_Id ) ,
	TicketsClosedThisMonth=(Select count(*) From vw_tp_LastTicketHistory(nolock) TM Where TM.AssignedUser=UL.TpUser_Id and month(TM.ActionDateTime)=month(getdate()) and year(TM.ActionDateTime)=year(getdate()) and dbo.ufn_tp_GetParentTicketStatus(TM.TicketStatusID) in (3,5,8,9,10)),
	TotalTicketsPendingOver24Hours=(Select count(*) From ' + @TableName + ' (NOLOCK)  TM Where TM.IsActive=1 and TM.AssignedUser=UL.TpUser_Id and DATEDIFF(HOUR, TM.LastActionDateTime, GETDATE()) > 24 and dbo.ufn_tp_GetParentTicketStatus(TM.TicketStatusID) in (1,2,4,6,7)),
TotalTicketsPending=(select count(*) From  ' + @TableName + ' (NOLOCK) TM Where TM.IsActive=1 and dbo.ufn_tp_GetParentTicketStatus(TM.TicketStatusID) in (1,2,4,6,7) and TM.AssignedUser = UL.TpUser_Id),
UnassignedTickets=(select count(*) From  ' + @TableName + ' (NOLOCK) TM Where TM.IsActive=1 and dbo.ufn_tp_GetParentTicketStatus(TM.TicketStatusID) in (1,2,4,6,7) and isnull(TM.AssignedUser,0)=0 and isnull(TM.AssignedGroup,0)=0 and TM.CreatedBy= UL.TpUser_Id),
	TicketsReopenedThisMonth=(select count(*) From (
		select Row_number()over(partition by TM.ParentID,TM.TicketID order by TM.TicketHistoryID desc) as Sno, count(*)over(partition by TM.ParentID,TM.TicketID) as Cnt,TM.AssignedUser,TM.ActionDateTime
		from tbl_tp_TicketHistory(nolock) TM   
		where dbo.ufn_tp_GetParentTicketStatus(TM.TicketStatusID) = 2 and TM.ParentID=@ParentId
		) as T
		Where T.Sno=1 and T.Cnt>1 and T.AssignedUser=UL.TpUser_Id and month(T.ActionDateTime)=month(getdate()) and year(T.ActionDateTime)=year(getdate())),
	AverageFeedbackFromCustomer=cast(isnull((select avg(FED.RatingPoints) From tbl_tp_TicketRatingFeedback(nolock) FED inner join tbl_tp_TicketHistory(nolock) TH On FED.TicketHistoryId=TH.TicketHistoryID Where TH.AssignedUser=UL.TpUser_Id),0) as numeric(18,2))--,*
from tbl_tp_UserLogin(nolock) UL 
Where UL.ParentId=@ParentId and UL.User_Id is not null'
        
    EXEC sp_executesql @SQL,N'@ParentId bigint',@ParentId;
	Print @SQL
END




GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_GetTicketCountAndStatusOnDashBoard]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec Usp_tp_GetTicketCountAndStatusOnDashBoard @TpUserId=77
--exec Usp_tp_GetTicketCountAndStatusOnDashBoard @TpUserId=110
--exec Usp_tp_GetTicketCountAndStatusOnDashBoard @TpUserId=446
CREATE   PROC [dbo].[Usp_tp_GetTicketCountAndStatusOnDashBoard]
(    
@TpUserId BIGINT    
)
AS    
BEGIN    
   --declare  @TpUserId BIGINT=77
	DECLARE  @ParentId Bigint,@AccessType nvarchar(100)='',@StrGroupIds nvarchar(max)='', @UserId Bigint, @TableName NVARCHAR(100),@TimeZone NVARCHAR(100), @SQL NVARCHAR(MAX) ,@IsAdmin BIT = 0, @Mobile nvarchar(40), @Email nvarchar(400)
    
	Select @ParentId = ParentId,@UserId=User_Id,@TimeZone = TimeZone,@IsAdmin=iif(ParentId=User_Id,1,0),
		   @Mobile=Mobile, @Email=Email
	From tbl_tp_UserLogin (noLock) 
	Where TpUser_Id= @TpUserId AND IsActive = 1   
		

    
	SET @TableName = CONCAT('tbl_tp_TicketMaster_', @ParentId);    
    
	If(@IsAdmin=1)-- Parent User(Internal)
	Begin
		SET @SQL =   
		N'SELECT TSM.TicketStatus, COUNT(*) AS StatusCount, ''Parent'' as Type
		  FROM ' + QUOTENAME(@TableName) + N' TM(NOLOCK) INNER JOIN tbl_tp_TicketStatusMaster TSM(NOLOCK) 
		  ON dbo.ufn_tp_GetParentTicketStatus(TM.TicketStatusID) = TSM.TicketStatus_ID
		  WHERE TM.IsActive = 1 
		  GROUP BY TSM.TicketStatus    
      
		  UNION ALL    
      
		  SELECT ''Total'', COUNT(*), ''Parent'' as Type 
		  FROM ' + QUOTENAME(@TableName) + N' AS TM WITH (NOLOCK)    
		  WHERE TM.IsActive = 1 '   
  
		EXEC sp_executesql @SQL;  
	End
	Else
	Begin
		If(@UserId is not null)-- Child User(Internal)
	        BEGIN
				drop table if exists #tbl_tp_AgentGroupMapping
		  Select * into #tbl_tp_AgentGroupMapping from tbl_tp_AgentGroupMapping(nolock) Where tpUserId=@TpUserId AND IsActive = 1
	       Select @AccessType=AccessType from #tbl_tp_AgentGroupMapping
            IF (@AccessType='GlobalAccess')
            BEGIN
                SET @SQL =   
                N'SELECT TSM.TicketStatus, COUNT(*) AS StatusCount, ''Child'' AS Type ,''global'' as Assigned
                  FROM ' + QUOTENAME(@TableName) + N' TM(NOLOCK) INNER JOIN tbl_tp_TicketStatusMaster TSM(NOLOCK) 
                  ON dbo.ufn_tp_GetParentTicketStatus(TM.TicketStatusID) = TSM.TicketStatus_ID
                  WHERE TM.IsActive = 1 
                  GROUP BY TSM.TicketStatus    
      
                  UNION ALL    
      
                  SELECT ''Total'', COUNT(*), ''Child'' AS Type ,''global'' as Assigned
                  FROM ' + QUOTENAME(@TableName) + N' AS TM WITH (NOLOCK)    
                  WHERE TM.IsActive = 1


                 --SELECT TSM.TicketStatus, COUNT(*) AS StatusCount, ''Child'' AS Type ,''Assignedtome'' as Assigned
                 -- FROM ' + QUOTENAME(@TableName) + N' TM(NOLOCK) INNER JOIN tbl_tp_TicketStatusMaster TSM(NOLOCK) 
                 -- ON dbo.ufn_tp_GetParentTicketStatus(TM.TicketStatusID) = TSM.TicketStatus_ID
                 -- WHERE TM.IsActive = 1 AND TM.AssignedUser = @TpUserId
                 -- GROUP BY TSM.TicketStatus    
      
                 -- UNION ALL    
      
                 -- SELECT ''Total'', COUNT(*), ''Child'' AS Type ,''Assignedtome'' as Assigned
                 -- FROM ' + QUOTENAME(@TableName) + N' AS TM WITH (NOLOCK)    
                 -- WHERE TM.IsActive = 1 AND TM.AssignedUser = @TpUserId';
                EXEC sp_executesql @SQL, N'@TpUserId BIGINT', @TpUserId;
            END
			IF (@AccessType = 'AssignedToGroup')
            BEGIN
                SELECT @StrGroupIds = STRING_AGG(ISNULL(NULLIF(GroupId, ''), '0'), ',') FROM #tbl_tp_AgentGroupMapping;

                SET @SQL =   
                N'SELECT TSM.TicketStatus, COUNT(*) AS StatusCount, ''Child'' AS Type, ''Assignedtogroup'' AS Assigned
                  FROM ' + QUOTENAME(@TableName) + N' TM(NOLOCK) INNER JOIN tbl_tp_TicketStatusMaster TSM(NOLOCK) 
                  ON dbo.ufn_tp_GetParentTicketStatus(TM.TicketStatusID) = TSM.TicketStatus_ID
                  WHERE TM.IsActive = 1 AND TM.AssignedGroup IN (' + @StrGroupIds + ')
                  GROUP BY TSM.TicketStatus    
      
                  UNION ALL    
      
                  SELECT ''Total'', COUNT(*), ''Child'' AS Type, ''Assignedtogroup'' AS Assigned
                  FROM ' + QUOTENAME(@TableName) + N' AS TM WITH (NOLOCK)    
                  WHERE TM.IsActive = 1 AND TM.AssignedGroup IN (' + @StrGroupIds + ')';
                EXEC sp_executesql @SQL;
            END;
            BEGIN
                SET @SQL =   
                N'SELECT TSM.TicketStatus, COUNT(*) AS StatusCount, ''Child'' AS Type ,''Assignedtome'' as Assigned
                  FROM ' + QUOTENAME(@TableName) + N' TM(NOLOCK) INNER JOIN tbl_tp_TicketStatusMaster TSM(NOLOCK) 
                  ON dbo.ufn_tp_GetParentTicketStatus(TM.TicketStatusID) = TSM.TicketStatus_ID
                  WHERE TM.IsActive = 1 AND TM.AssignedUser = @TpUserId
                  GROUP BY TSM.TicketStatus    
      
                  UNION ALL    
      
                  SELECT ''Total'', COUNT(*), ''Child'' AS Type ,''Assignedtome'' as Assigned
                  FROM ' + QUOTENAME(@TableName) + N' AS TM WITH (NOLOCK)    
                  WHERE TM.IsActive = 1 AND TM.AssignedUser = @TpUserId'   
  
                EXEC sp_executesql @SQL, N'@TpUserId BIGINT', @TpUserId;
            END
        END
		Else
		Begin-- External User
			SET @SQL =   
			N'SELECT TSM.TicketStatus, COUNT(*) AS StatusCount, ''External'' as Type
			  FROM ' + QUOTENAME(@TableName) + N' TM(NOLOCK) INNER JOIN tbl_tp_TicketStatusMaster TSM(NOLOCK) 
			  ON dbo.ufn_tp_GetParentTicketStatus(TM.TicketStatusID) = TSM.TicketStatus_ID
			  WHERE TM.IsActive = 1 and (TM.CreatedBy=@TpUserId or (TM.RequesterMobileNo=@Mobile and TM.RequesterEmailID=@Email))
			  GROUP BY TSM.TicketStatus    
      
			  UNION ALL    
      
			  SELECT ''Total'', COUNT(*), ''External'' as Type
			  FROM ' + QUOTENAME(@TableName) + N' AS TM WITH (NOLOCK)    
			  WHERE TM.IsActive = 1 and (TM.CreatedBy=@TpUserId or (TM.RequesterMobileNo=@Mobile and TM.RequesterEmailID=@Email))'   
  
			EXEC sp_executesql @SQL,N'@TpUserId bigint,@Mobile nvarchar(40),@Email nvarchar(400)', @TpUserId,@Mobile,@Email;
		End
	End
	print @SQL
END  



GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_GetTicketCountryData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_GetTicketCountryData]   
AS  
BEGIN  
    DECLARE @TableName NVARCHAR(100), @SQL NVARCHAR(MAX), @UserID BIGINT  
  
    --------------------------- Country Master ---------------------------------------------------  
    SELECT Country_Name, LTRIM(RTRIM(CountryCode)) AS CountryCode, Country_ID   
    FROM m_country1 (NOLOCK)   
    ORDER BY Country_Name  
END



