   Procedure: [dbo].[Usp_tp_GetTicketDataForChart]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



--CREATE TABLE [dbo].[tbl_tp_TicketFaqCategory_Master](
--	[FaqCategoryId] [bigint] IDENTITY(1,1) NOT NULL,
--	[FaqCategoryName] [varchar](30) NULL,
--	[FaqCategoryDesc] [varchar](200) NULL,
--	[jsonqa] [nvarchar](max) NULL,
--	[ParentId] [bigint] NULL,
--	[CreatedBy] [bigint] NULL,
--	[ModifiedBy] [bigint] NULL,
