/****** Object: StoredProcedure [dbo].[Usp_tp_GetTicketDataForChart] Script Date: 12/16/2023 8:54:44 PM ******/
CREATE   PROCEDURE [dbo].[Usp_tp_GetTicketDataForChart]
    @tpuserid BIGINT,
    @Mode NVARCHAR(max),
	@Groupby  NVARCHAR(max),
	@Sqlwhere   NVARCHAR(max)
AS
BEGIN
--declare 
--  @tpuserid BIGINT=1,
--  @Mode NVARCHAR(200)='AgentReport',
--  @Groupby  NVARCHAR(200)='',
--  @Sqlwhere   NVARCHAR(max)=''

    DECLARE  @rowJson NVARCHAR(MAX),
            @IPAdress NVARCHAR(50), @DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT;

	DECLARE  @ParentId Bigint,@AccessType nvarchar(100)='',@StrGroupIds nvarchar(max)='', @UserId Bigint, @TableName NVARCHAR(100),@TimeZone NVARCHAR(100), @SQL NVARCHAR(MAX) ,@IsAdmin BIT = 0, @Mobile nvarchar(40), @Email nvarchar(400)
    
	Select @ParentId = ParentId,@UserId=User_Id,@TimeZone = TimeZone,@IsAdmin=iif(ParentId=User_Id,1,0),
		   @Mobile=Mobile, @Email=Email
	From tbl_tp_UserLogin (noLock) 
	Where TpUser_Id= @TpUserId AND IsActive = 1   
		
		drop table if exists #tbl_tp_AgentGroupMapping
		  Select * into #tbl_tp_AgentGroupMapping from tbl_tp_AgentGroupMapping(nolock) Where tpUserId=@TpUserId AND IsActive = 1
	       Select @AccessType=AccessType from #tbl_tp_AgentGroupMapping
		   	IF (@AccessType = 'AssignedToGroup')
            BEGIN
                SELECT @StrGroupIds = STRING_AGG(ISNULL(NULLIF(GroupId, ''), '0'), ',') FROM #tbl_tp_AgentGroupMapping;
				END
    --SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress);
    --SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress);
    --SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation);
    --SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId);
	 If (concat(@SqlWhere,'')='')  
 Begin  
  SET @SqlWhere=N' and 1=1 '  
 End  
 Else  
 Begin  
  SET @SqlWhere=N' and ' + @SqlWhere  
 End  
    SET @TableName = CONCAT('tbl_tp_TicketMaster_', @ParentId);

    -- Retrieve data for all types
    DECLARE @DynamicSQL NVARCHAR(MAX);
 IF(@Mode ='created')
	begin
    SET @DynamicSQL = '
        SELECT 
            ''Priority'' AS DataType,
            TP.PriorityName AS DataName,
            COUNT(*) AS DataCount
        FROM 
            ' + QUOTENAME(@TableName) + ' AS TM
        JOIN 
            tbl_tp_TicketPriorityMaster(nolock) TP ON TM.TicketPriority = TP.Priority_ID
        WHERE
            TM.tpUser_Id = @tpuserid ' + @SqlWhere + '  
         GROUP BY '+ 
            CASE WHEN @Groupby='''TicketId''' THEN 'TM.TicketId'
                ELSE 'TP.PriorityName'
            END +'
        UNION ALL

        SELECT 
            ''Category'' AS DataType,
            TC.TicketCategoryName AS DataName,
            COUNT(*) AS DataCount
        FROM 
            ' + QUOTENAME(@TableName) + ' AS TM
        JOIN 
            tbl_tp_TicketCategory_Master(nolock)  TC ON TM.TicketCategoryId = TC.TicketCategoryId
        WHERE
            TM.tpUser_Id = @tpuserid  ' + @SqlWhere + '  
        GROUP BY '+ 
            CASE WHEN @Groupby='''TicketId''' THEN 'TM.TicketId'
                ELSE ' TC.TicketCategoryName'
            END +'          
        UNION ALL

        SELECT 
            ''Status'' AS DataType,
            TS.TicketStatus AS DataName,
            COUNT(*) AS DataCount
        FROM 
            ' + QUOTENAME(@TableName) + ' AS TM
        JOIN 
            tbl_tp_TicketStatusMaster(nolock)  TS ON TM.TicketStatusID = TS.TicketStatus_ID
        WHERE
            TM.tpUser_Id = @tpuserid ' + @SqlWhere + '  
       GROUP BY '+ 
            CASE WHEN @Groupby='''TicketId''' THEN 'TM.TicketId'
                ELSE 'TS.TicketStatus'
            END +'
  
        UNION ALL
        SELECT 
            ''Source'' AS DataType,
            TSM.TicketSourceName AS DataName,
            COUNT(*) AS DataCount
        FROM 
            ' + QUOTENAME(@TableName) + ' AS TM
        JOIN 
            tbl_tp_TicketSourceMaster(nolock)  TSM ON TM.TicketSourceId = TSM.TicketSourceId
        WHERE
            TM.tpUser_Id = @tpuserid ' + @SqlWhere + '  
      GROUP BY '+ 
            CASE WHEN @Groupby='''TicketId''' THEN 'TM.TicketId'
                ELSE 'TSM.TicketSourceName
'
            END +'

        UNION ALL

        SELECT 
            ''Type'' AS DataType,
            TYM.Type_Name AS DataName,
            COUNT(*) AS DataCount
        FROM 
            ' + QUOTENAME(@TableName) + ' AS TM
        JOIN 
            tbl_tp_TicketType_Master(nolock)  TYM ON TM.TicketTypeId = TYM.Type_ID
        WHERE
            TM.tpUser_Id = @tpuserid ' + @SqlWhere + '  
         GROUP BY '+ 
            CASE WHEN @Groupby='''TicketId''' THEN 'TM.TicketId'
                ELSE 'TYM.Type_Name'
            END +'
            

        UNION ALL

        SELECT 
            ''TicketAgentResolve'' AS DataType,
            TTM.LoginName AS DataName,
            COUNT(*) AS DataCount
        FROM 
            ' + QUOTENAME(@TableName) + ' AS TM
        JOIN 
            tbl_tp_TicketType_Master(nolock)  TYM ON TM.TicketTypeId = TYM.Type_ID
        JOIN 
            tbl_tp_TicketStatusMaster(nolock)  TSM ON TM.TicketStatusID = TSM.TicketStatus_ID
        JOIN 
            tbl_tp_UserLogin(nolock)  TTM ON TM.AssignedUser = TTM.tpUser_Id
        WHERE
            TM.tpUser_Id = @tpuserid 
            AND TSM.TicketStatus = ''Resolved''  ' + @SqlWhere + '  
        GROUP BY '+ 
            CASE WHEN @Groupby='''TicketId''' THEN 'TM.TicketId'
                ELSE 'TYM.Type_Name, TTM.LoginName'
            END +'
         
    ';
	END
 IF(@Mode = 'Resolved')
BEGIN
    SET @DynamicSQL = '
        SELECT 
            ''Priority'' AS DataType,
            TP.PriorityName AS DataName,
            COUNT(*) AS DataCount
        FROM 
            ' + QUOTENAME(@TableName) + ' AS TM (nolock)
        JOIN 
            tbl_tp_TicketPriorityMaster(nolock)  TP ON TM.TicketPriority = TP.Priority_ID
