        WHERE
            TM.ClosedBy = @tpuserid
            AND TSM.TicketStatus = ''Resolved'' OR  TSM.ParentStatus_Id=5  ' + @SqlWhere + '  
        GROUP BY '+ 
            CASE WHEN @Groupby='''TicketId''' THEN 'TM.TicketId'
                ELSE 'TP.PriorityName'
            END +'

        UNION ALL

        SELECT 
            ''Category'' AS DataType,
            TC.TicketCategoryName AS DataName,
            COUNT(*) AS DataCount
        FROM 
            ' + QUOTENAME(@TableName) + ' AS TM (nolock)
        JOIN 
            tbl_tp_TicketCategory_Master(nolock)  TC ON TM.TicketCategoryId = TC.TicketCategoryId
        JOIN
            tbl_tp_TicketStatusMaster(nolock)  TSM ON TM.TicketStatusID = TSM.TicketStatus_ID
        WHERE
            TM.ClosedBy = @tpuserid
            AND TSM.TicketStatus = ''Resolved'' OR  TSM.ParentStatus_Id=5  ' + @SqlWhere + '  
         GROUP BY '+ 
            CASE WHEN @Groupby='''TicketId''' THEN 'TM.TicketId'
                ELSE 'TC.TicketCategoryName'
            END +'
            

        UNION ALL

        SELECT 
            ''Status'' AS DataType,
