        FROM 
            ' + QUOTENAME(@TableName) + ' AS TM (nolock)
        JOIN 
            tbl_tp_TicketStatusMaster(nolock)  TS ON TM.TicketStatusID = TS.TicketStatus_ID
        JOIN
            tbl_tp_TicketStatusMaster(nolock)  TSM2 ON TM.TicketStatusID = TSM2.TicketStatus_ID
        WHERE
            TM.ClosedBy = @tpuserid
            AND TSM2.TicketStatus = ''Resolved'' OR  TSM2.ParentStatus_Id=5  ' + @SqlWhere + '  
         GROUP BY '+ 
            CASE WHEN @Groupby='''TicketId''' THEN 'TM.TicketId'
                ELSE 'TS.TicketStatus'
            END +'
        

        UNION ALL

        SELECT 
            ''Source'' AS DataType,
            TSM.TicketSourceName AS DataName,
            COUNT(*) AS DataCount
        FROM 
            ' + QUOTENAME(@TableName) + ' AS TM (nolock)
        JOIN 
