            AND TSM3.TicketStatus = ''Resolved'' OR  TSM3.ParentStatus_Id=5  ' + @SqlWhere + '  
         GROUP BY '+ 
            CASE WHEN @Groupby='''TicketId''' THEN 'TM.TicketId'
                ELSE 'TSM.TicketSourceName'
            END +'
            

        UNION ALL

        SELECT 
            ''Type'' AS DataType,
            TYM.Type_Name AS DataName,
            COUNT(*) AS DataCount
        FROM 
            ' + QUOTENAME(@TableName) + ' AS TM (nolock)
        JOIN 
            tbl_tp_TicketType_Master(nolock)  TYM ON TM.TicketTypeId = TYM.Type_ID
        JOIN
            tbl_tp_TicketStatusMaster(nolock)  TSM ON TM.TicketStatusID = TSM.TicketStatus_ID
        WHERE
            TM.tpUser_Id = @tpuserid
            AND TSM.TicketStatus = ''Resolved'' OR  TSM.ParentStatus_Id=5  ' + @SqlWhere + '  
       GROUP BY '+ 
            CASE WHEN @Groupby='''TicketId''' THEN 'TM.TicketId'
                ELSE 'TYM.Type_Name'
            END +'


        UNION ALL

        SELECT 
            ''TicketAgentResolve'' AS DataType,
            LEFT(TH.UserResponse, 200) AS DataName,
            COUNT(*) AS DataCount
        FROM 
            ' + QUOTENAME(@TableName) + ' AS TM
        JOIN 
            tbl_tp_TicketHistory(nolock)  TH ON TM.TicketID = TH.TicketID
        WHERE
            TM.ClosedBy = @tpuserid  ' + @SqlWhere + '  
            AND TH.UserResponse IS NOT NULL
      GROUP BY '+ 
            CASE WHEN @Groupby='''TicketId''' THEN 'TM.TicketId'
                ELSE 'TH.UserResponse'
            END +'
    ';
END
