IF (@Mode = 'GroupReport')
BEGIN
    SET @DynamicSQL = '
        SELECT 
            GRP.GroupName AS GroupName,
            SUM(CASE WHEN  TM.AssignedGroup = GRP.GroupId    THEN 1 ELSE 0 END) AS TicketAssigned,
            SUM(CASE WHEN TSM.TicketStatus = ''Resolved'' OR TSM.ParentStatus_Id=5  THEN 1 ELSE 0 END) AS TicketResolved,
            SUM(CASE WHEN TSM.TicketStatus = ''Open'' OR TSM.ParentStatus_Id=2 THEN 1 ELSE 0 END) AS TicketReopened,
            SUM(CASE WHEN TSM.TicketStatus = ''Reassigned'' THEN 1 ELSE 0 END) AS TicketReassigned,
		SUM(CASE WHEN TM.Remarks IS NOT NULL OR TM.Note IS NOT NULL THEN 1 ELSE 0 END) AS PrivateNotes,
       SUM(CASE WHEN TM.UserResponse IS NOT NULL THEN 1 ELSE 0 END) AS Response

        FROM 
            ' + QUOTENAME(@TableName) + ' AS TM (NOLOCK)
        JOIN 
            tbl_tp_GroupMaster (NOLOCK) GRP ON TM.AssignedGroup = GRP.GroupId    
			JOIN
			   tbl_tp_TicketStatusMaster(nolock)  TSM ON TM.TicketStatusID = TSM.TicketStatus_ID
        WHERE
            TM.tpUser_Id = @tpuserid 
            AND TM.IsActive = 1  ' + @SqlWhere + '  
        GROUP BY 
            GRP.GroupName
    ';
END
IF (@Mode = 'AgentReport')
BEGIN
    SET @DynamicSQL = '
        SELECT 
            CONCAT(TUL.Name, '' ('', TUL.LoginName, '')'') AS AgentName,
            SUM(CASE WHEN TM.AssignedUser = @tpuserid THEN 1 ELSE 0 END) AS TicketAssigned,
            SUM(CASE WHEN TSM.TicketStatus = ''Resolved'' OR TSM.ParentStatus_Id=5  THEN 1 ELSE 0 END) AS TicketResolved,
            SUM(CASE WHEN TSM.TicketStatus = ''Open'' OR TSM.ParentStatus_Id=2 THEN 1 ELSE 0 END) AS TicketReopened,
            SUM(CASE WHEN TSM.TicketStatus = ''Reassigned'' THEN 1 ELSE 0 END) AS TicketReassigned,
           		SUM(CASE WHEN TM.Remarks IS NOT NULL OR TM.Note IS NOT NULL THEN 1 ELSE 0 END) AS PrivateNotes,
       SUM(CASE WHEN TM.UserResponse IS NOT NULL THEN 1 ELSE 0 END) AS Response
        FROM 
            ' + QUOTENAME(@TableName) + ' AS TM (NOLOCK)
        JOIN 
            tbl_tp_UserLogin (NOLOCK) TUL ON TM.tpUser_Id = TUL.tpUser_Id    
        JOIN
            tbl_tp_TicketStatusMaster (NOLOCK) TSM ON TM.TicketStatusID = TSM.TicketStatus_ID
        WHERE 
		   --TUL.ParentId = 32222 AND
           TUL.User_Id IS NOT NULL
            AND TM.IsActive = 1  ' + @SqlWhere + '  
        GROUP BY 
            TUL.Name, TUL.LoginName
    ';
END
IF (@Mode = 'ArticleMaster')
BEGIN
    SET @DynamicSQL = '
       WITH CategoryHierarchyCTE AS (
    SELECT
        ArticleCate_Id,
        ParentCategoryId,
        CategoryName,
        CAST(CategoryName AS NVARCHAR(MAX)) AS Sequencehierarchy,
        1 AS CategoryLevel
    FROM
        tbl_tp_ArticleCategory
    WHERE
        ParentCategoryId IS NULL

    UNION ALL

    SELECT
        c.ArticleCate_Id,
        c.ParentCategoryId,
        c.CategoryName,
        CAST(ch.Sequencehierarchy + ''>'' + c.CategoryName AS NVARCHAR(MAX)) AS Sequencehierarchy,
        ch.CategoryLevel + 1 AS CategoryLevel
    FROM
        tbl_tp_ArticleCategory c
    INNER JOIN
        CategoryHierarchyCTE ch ON c.ParentCategoryId = ch.ArticleCate_Id
)

SELECT
     am.ArticleTitle,
           am.ArticleContent,
           am.ViewCount,
           am.ModifiedCount,
           am.LikeCount,
           am.DislikeCount,
    ta.AuthorName,
    cat.CategoryName,
    cat.Sequencehierarchy
FROM
    tbl_tp_ArticleMaster am (NOLOCK)
LEFT JOIN
    tbl_tp_Author ta (NOLOCK) ON am.Author_id = ta.Author_Id
LEFT JOIN
    CategoryHierarchyCTE cat ON am.Category_Id = cat.ArticleCate_Id
WHERE
    (am.ParentId = ' + CAST(@ParentId AS NVARCHAR(50)) + '   OR am.ParentId IS NULL) AND am.IsActive = 1 ' + @SqlWhere + '
ORDER BY
    am.CreatedDate DESC;
    ';
END

    EXEC sp_executesql @DynamicSQL, N'@tpuserid BIGINT', @tpuserid;

    EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData
        @User_id = @UserId,
        @Activity_type = 'View_TicketMaster',
        @ActionType = 'S',
        @RowJson = 'NULL',
        @Table_name = 'tbl_tp_TicketMaster',
        @ip_adress = @IPAdress,
        @device_id = @DeviceId,
        @IsImpersonation = @IsImpersonation,
        @ImpersonatorId = @ImpersonatorId;
END




GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_GetTicketDetailsBasedOnAdvanceSearch]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



-- exec Usp_tp_GetTicketDetailsBasedOnAdvanceSearch @TpUserId=345,@SqlQuery=N'dbo.ufn_tp_GetParentTicketStatus(TicketStatusID) = 1',@Mode=N'Query'  
-- exec Usp_tp_GetTicketDetailsBasedOnAdvanceSearch @TpUserId=1,@SqlQuery=N'TM.TicketStatusId =  1 ',@Mode=N'Query'
-- exec Usp_tp_GetTicketDetailsBasedOnAdvanceSearch @TpUserId=1,@SqlQuery=N'cast(TM.CreatedOn as DATE) = CAST( ''2024-01-24'' AS DATE)',@Mode=N'Query'
CREATE   PROCEDURE [dbo].[Usp_tp_GetTicketDetailsBasedOnAdvanceSearch]  
(                       
 @TpUserId BIGINT ,  
 @SqlQuery NVARCHAR(MAX) = NULL,  
 @Mode NVARCHAR(50) NULL  
)                          
AS                          
BEGIN                          
BEGIN TRY  
  --declare @TpUserId BIGINT=345, @SqlQuery NVARCHAR(MAX)=N'dbo.ufn_tp_GetParentTicketStatus(TicketStatusID) = 1', @Mode NVARCHAR(50)=N'Query'  
  --declare @TpUserId BIGINT=1, @SqlQuery NVARCHAR(MAX)='', @Mode NVARCHAR(50)=N'top10'  
 --declare @TpUserId BIGINT=1, @SqlQuery NVARCHAR(MAX)=N'dbo.ufn_tp_GetParentTicketStatus(TicketStatusID) = 1', @Mode NVARCHAR(50)=N'Internal'  
   --declare @TpUserId BIGINT=1, @SqlQuery NVARCHAR(MAX)=N'TM.Status=''Read''', @Mode NVARCHAR(50)=N'ContactFormData'  
  
   DECLARE @TimeZone NVARCHAR(400), @rowJson NVARCHAR(MAX), @IPAdress NVARCHAR(50), @UserID BIGINT,  
    @IsAdmin BIT = 0, @DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT,  
    @ProductTableName NVARCHAR(100), @DynamicColumns NVARCHAR(MAX) = '', @ParentID BIGINT,
	@AccessType nvarchar(100)='', @StrGroupIds nvarchar(max)=''     
                          
   SELECT @UserID=User_Id, @ParentID=ParentId, @TimeZone=isnull(TimeZone,'India Standard Time'),  
		@IsAdmin = (CASE WHEN User_Id = ParentId THEN 1 ELSE 0 END)   
	  FROM tbl_tp_UserLogin(nolock)   
	  WHERE TpUser_Id = @TpUserId AND IsActive = 1;            

	drop table if exists #tbl_tp_AgentGroupMapping

	Select *
	into #tbl_tp_AgentGroupMapping
	from tbl_tp_AgentGroupMapping(nolock) 
	Where tpUserId=@TpUserId AND IsActive = 1

	Select @AccessType=AccessType from #tbl_tp_AgentGroupMapping

	If(@AccessType='GlobalAccess')
	Begin
		Set @IsAdmin=1
	End
	--Else If(@AccessType='AssignedToGroup')
	--Begin
	--	Select @StrGroupIds=STRING_AGG(GroupId,',') From #tbl_tp_AgentGroupMapping
	--End
    ELSE IF (@AccessType = 'AssignedToGroup')
    BEGIN
    ;WITH grp AS
    (
        SELECT DISTINCT LTRIM(RTRIM(GroupId)) AS GroupId
        FROM #tbl_tp_AgentGroupMapping
        WHERE GroupId IS NOT NULL AND LTRIM(RTRIM(GroupId)) <> ''
    )
    SELECT @StrGroupIds = STRING_AGG(GroupId, ',')
    FROM grp;
 
    IF (@StrGroupIds IS NULL OR LTRIM(RTRIM(@StrGroupIds)) = '')
        SET @StrGroupIds = NULL;  -- ensures no "IN ()"
     END        
        DECLARE @DynamicSQL NVARCHAR(MAX)                          
        DECLARE @sqls NVARCHAR(MAX) = ''                          
        DECLARE @status INT                          
        DECLARE @tableName NVARCHAR(MAX) = ''                          
                          
        EXEC @status = Usp_tp_CreateTicketMasterTableByParentID @ParentID, @tableName OUTPUT  
                          
        SELECT @DynamicColumns = isnull(STRING_AGG(column_name, ','),' 1 as Dummy')  
        FROM INFORMATION_SCHEMA.COLUMNS                          
        WHERE table_name = @tableName                          
            AND column_name NOT IN (                          
                'TicketID', 'tpUser_Id', 'ParentID', 'RequesterMobileNo','CountryCode', 'RequesterEmailID',  
               'RequesterMobileNo1','CountryCode1', 'RequesterEmailID1', 'RequesterMobileNo2','CountryCode2', 'RequesterEmailID2',       
                'Subject', 'Description', 'TicketStatusID', 'Remarks', 'Note', 'UserResponse',                
                'TicketPriority', 'AssignedUser', 'AssignedGroup', 'AssignedSource', 'TicketCategoryId',      
                'TicketTypeId', 'TicketSourceId', 'ProductId', 'IsMerged', 'IsSplitted', 'IsParentTicket',    
                'IsChildTicket', 'ParentTicketID', 'LastActionDatetime', 'AssignedBy', 'AssignedDateTime',    
                'TicketTag', 'EntityID', 'EntityName', 'Company', 'IsActive', 'CreatedBy', 'CreatedOn',       
                'ModifiedBy', 'ModifiedOn', 'SplittedBy', 'SplittedOn', 'MergedBy', 'MergedOn',               
                'ClosedBy', 'ClosedOn', 'CreatedChildBy', 'CreatedChildOn'
            );                       
                    
  print concat('@tableName: ',@tableName)  
  print concat('@DynamicColumns: ',@DynamicColumns)  
  print concat('@TimeZone: ',@TimeZone)  
                    
  IF (@Mode = 'Internal')  
  BEGIN  
   SET @DynamicSQL = N'                    
    SELECT             
    ISNULL(TUL.Name,''UnKnown'') AS Name,               
    TicketNo,             
    TM.EntityName,                
    SGM.GroupName,  
   CASE                           
    WHEN TM.EntityName = ''Lead'' THEN UL.PersonName                              
    WHEN TM.EntityName = ''Enquiry'' THEN UE.PersonName                              
            ELSE ''Unknown'' END AS RequesterName,                              
   RequesterMobileNo,  
   RequesterEmailID,  
   SGM.GroupName,  
   TM.Company,  
   Subject,  
   Description,  
   TSM.TicketStatus,  
   TPM.PriorityName,  
   TUL.Name AS AssignedUser,  
   TSOM.TicketSourceName,  
   TTM.Type_Name,  
   TULN.Name As CreatedBy,  
   TULN.Name As ModifiedBy,  
   TM.CreatedOn AS CreatedOn,  
   ' + @DynamicColumns + ',  
   (SELECT STRING_AGG(Tag, '', '') FROM TagMaster WHERE ID IN (SELECT value FROM STRING_SPLIT(TM.TicketTag, '',''))) AS Tags  
   FROM ' + @tableName + ' TM (NOLOCK)  
   LEFT JOIN tbl_tp_UserLogin TUL (NOLOCK) ON TUL.TpUser_Id = TM.AssignedUser AND TUL.IsActive = 1  
   LEFT JOIN tbl_tp_UserLogin TULN (NOLOCK) ON TULN.TpUser_Id = TM.CreatedBy AND TULN.IsActive = 1  
   LEFT JOIN tbl_tp_UserLogin TULM (NOLOCK) ON TULM.TpUser_Id = TM.ModifiedBy AND TULM.IsActive = 1  
   LEFT JOIN tbl_tp_TicketStatusMaster TSM (NOLOCK) ON TM.TicketStatusID = TSM.TicketStatus_ID  
   LEFT JOIN tbl_tp_TicketType_Master TTM (NOLOCK) ON TM.TicketTypeId = TTM.Type_ID  
   LEFT JOIN tbl_tp_TicketPriorityMaster TPM (NOLOCK) ON TM.TicketPriority = TPM.Priority_ID  
   LEFT JOIN tbl_tp_TicketSourceMaster TSOM (NOLOCK) ON TM.TicketSourceId = TSOM.TicketSourceId  
   LEFT JOIN tbl_tp_GroupMaster SGM (NOLOCK) ON SGM.GroupId = TM.AssignedGroup  
   LEFT JOIN UserLeads UL (NOLOCK) ON TM.EntityID = UL.ID AND TM.EntityName = ''Lead''  
   LEFT JOIN UserEnquiry UE (NOLOCK) ON TM.EntityID = UE.EnquiryID AND TM.EntityName = ''Enquiry''  
   LEFT JOIN (  
   SELECT Distinct TTP.TicketID  
   FROM tbl_tp_TicketProducts (NOLOCK) TTP WHERE TTP.IsActive = 1  
   ) TP ON TP.TicketID = TM.TicketID  
   WHERE TM.IsActive=1 ' + CASE WHEN @IsAdmin = 0 THEN ' and TM.AssignedUser = ' + CAST(@TpuserId AS NVARCHAR(MAX)) ELSE ' ' END + Case when @AccessType='AssignedToGroup' then ' and TM.AssignedGroup in (' + @StrGroupIds + ')' else '' end;  
  END                  
  
  IF (@Mode = 'External')  
  BEGIN  
   SET @DynamicSQL = N'                    
   SELECT  
   ISNULL(TUL.Name,''UnKnown'') AS Name,  
   TicketNo,  
   TM.EntityName,  
   SGM.GroupName,  
   CASE  
    WHEN TM.EntityName = ''Lead'' THEN UL.PersonName  
    WHEN TM.EntityName = ''Enquiry'' THEN UE.PersonName  
   ELSE ''Unknown'' END AS RequesterName,  
   RequesterMobileNo,  
   RequesterEmailID,  
   SGM.GroupName,  
   TM.Company,  
   Subject,  
   Description,  
   TSM.TicketStatus,  
   TPM.PriorityName,  
   TUL.Name AS AssignedUser,  
   TSOM.TicketSourceName,  
   TTM.Type_Name,  
   TULN.Name As CreatedBy,  
   TULN.Name As ModifiedBy,  
   TM.CreatedOn AS CreatedOn,  
   ' + @DynamicColumns + ',  
   (SELECT STRING_AGG(Tag, '', '') FROM TagMaster WHERE ID IN (SELECT value FROM STRING_SPLIT(TM.TicketTag, '',''))) AS Tags  
   FROM ' + @tableName + ' TM (NOLOCK)  
   LEFT JOIN tbl_tp_UserLogin TUL (NOLOCK) ON TUL.TpUser_Id = TM.AssignedUser AND TUL.IsActive = 1  
   LEFT JOIN tbl_tp_UserLogin TULN (NOLOCK) ON TULN.TpUser_Id = TM.CreatedBy AND TULN.IsActive = 1  
   LEFT JOIN tbl_tp_UserLogin TULM (NOLOCK) ON TULM.TpUser_Id = TM.ModifiedBy AND TULM.IsActive = 1  
   LEFT JOIN tbl_tp_TicketStatusMaster TSM (NOLOCK) ON TM.TicketStatusID = TSM.TicketStatus_ID  
   LEFT JOIN tbl_tp_TicketType_Master TTM (NOLOCK) ON TM.TicketTypeId = TTM.Type_ID  
   LEFT JOIN tbl_tp_TicketPriorityMaster TPM (NOLOCK) ON TM.TicketPriority = TPM.Priority_ID  
   LEFT JOIN tbl_tp_TicketSourceMaster TSOM (NOLOCK) ON TM.TicketSourceId = TSOM.TicketSourceId  
   LEFT JOIN tbl_tp_GroupMaster SGM (NOLOCK) ON SGM.GroupId = TM.AssignedGroup  
   LEFT JOIN UserLeads UL (NOLOCK) ON TM.EntityID = UL.ID AND TM.EntityName = ''Lead''  
   LEFT JOIN UserEnquiry UE (NOLOCK) ON TM.EntityID = UE.EnquiryID AND TM.EntityName = ''Enquiry''  
   LEFT JOIN (  
   SELECT Distinct TTP.TicketID  
   FROM tbl_tp_TicketProducts (NOLOCK) TTP WHERE TTP.IsActive = 1  
   ) TP ON TP.TicketID = TM.TicketID  
   LEFT JOIN (  
   SELECT Distinct ETM.EntityID  
   FROM EntityTagMapping (NOLOCK) ETM WHERE ETM.Entity = ''Ticket''  
   ) ETP ON ETP.EntityID = TM.TicketID  
   WHERE TM.CreatedBy = ' + CAST(@TpUserId AS NVARCHAR(50)) + ';';             
  END                 
  
  IF (@Mode = 'Query')  
  BEGIN  
   SET @DynamicSQL = N'  

   SELECT 
   ISNULL(TUL.Name,''UnKnown'') AS Name,  
   TicketNo,  
   TM.EntityName,  
   SGM.GroupName,  
   CASE  
    WHEN TM.EntityName = ''Lead'' THEN UL.PersonName  
    WHEN TM.EntityName = ''Enquiry'' THEN UE.PersonName  
   ELSE ''Unknown'' END AS RequesterName,  
   RequesterMobileNo,  
   RequesterEmailID,  
   SGM.GroupName,  
   TM.Company,  
   Subject,  
   Description,  
   TSM.TicketStatus,  
   TPM.PriorityName,  
   TUL.Name AS AssignedUser,  
   TSOM.TicketSourceName,  
   TTM.Type_Name,  
   TULN.Name As CreatedBy,  
   TULN.Name As ModifiedBy,  
   dbo.fn_ConvertDateTime(TM.CreatedOn, @TimeZone, 0) AS CreatedOn,  
   dbo.fn_ConvertDateTime(TM.ModifiedOn, @TimeZone, 0) AS ModifiedOn,  
   
   ' + @DynamicColumns + ',  
   (SELECT STRING_AGG(Tag, '', '') FROM TagMaster WHERE ID IN (SELECT value FROM STRING_SPLIT(TM.TicketTag, '',''))) AS Tags  
   FROM ' + @tableName + ' TM (NOLOCK)  
   LEFT JOIN tbl_tp_UserLogin TUL (NOLOCK) ON TUL.TpUser_Id = TM.AssignedUser AND TUL.IsActive = 1  
   LEFT JOIN tbl_tp_UserLogin TULN (NOLOCK) ON TULN.TpUser_Id = TM.CreatedBy AND TULN.IsActive = 1  
   LEFT JOIN tbl_tp_UserLogin TULM (NOLOCK) ON TULM.TpUser_Id = TM.ModifiedBy AND TULM.IsActive = 1  
   LEFT JOIN tbl_tp_TicketStatusMaster TSM (NOLOCK) ON TM.TicketStatusID = TSM.TicketStatus_ID  
   LEFT JOIN tbl_tp_TicketType_Master TTM (NOLOCK) ON TM.TicketTypeId = TTM.Type_ID  
   LEFT JOIN tbl_tp_TicketPriorityMaster TPM (NOLOCK) ON TM.TicketPriority = TPM.Priority_ID  
   LEFT JOIN tbl_tp_TicketSourceMaster TSOM (NOLOCK) ON TM.TicketSourceId = TSOM.TicketSourceId  
   LEFT JOIN tbl_tp_GroupMaster SGM (NOLOCK) ON SGM.GroupId = TM.AssignedGroup  
   LEFT JOIN UserLeads UL (NOLOCK) ON TM.EntityID = UL.ID AND TM.EntityName = ''Lead''  
   LEFT JOIN UserEnquiry UE (NOLOCK) ON TM.EntityID = UE.EnquiryID AND TM.EntityName = ''Enquiry''  
   LEFT JOIN (  
   SELECT Distinct TTP.TicketID  
   FROM tbl_tp_TicketProducts (NOLOCK) TTP WHERE TTP.IsActive = 1  
   ) TP ON TP.TicketID = TM.TicketID  
   LEFT JOIN (  
   SELECT Distinct ETM.EntityID  
   FROM EntityTagMapping (NOLOCK) ETM WHERE ETM.Entity = ''Ticket''  
   ) ETP ON ETP.EntityID = TM.TicketID  
   WHERE ' + @SqlQuery + ' AND TM.IsActive = 1 ' + CASE WHEN @IsAdmin = 0 THEN ' AND TM.AssignedUser = ' + CAST(@TpuserId AS NVARCHAR(MAX)) ELSE '' END + Case when @AccessType='AssignedToGroup' then ' and TM.AssignedGroup in (' + @StrGroupIds + ')' else '' end;                
  END   
  
  IF (@Mode = 'top10')  
BEGIN  
    SET @DynamicSQL = N'
    select * from (   
		SELECT ROW_NUMBER()over(order by isnull(TM.ModifiedOn,TM.CreatedOn) desc) RecNo,count(*)over(order by TM.ParentID) TotalCount,
		TM.TicketID,
        ISNULL(TUL.Name,''UnKnown'') AS Name,  
        TicketNo,  
        TM.EntityName,  
        SGM.GroupName,  
        CASE  
            WHEN TM.EntityName = ''Lead'' THEN UL.PersonName  
            WHEN TM.EntityName = ''Enquiry'' THEN UE.PersonName  
            ELSE ''Unknown'' 
        END AS RequesterName,  
        RequesterMobileNo,  
        RequesterEmailID,  
        TM.Company, 
	    TM.EntityID,
        Subject,  
        Description,  
        TSM.TicketStatus,  
        TPM.PriorityName,  
        TUL.Name AS AssignedUser,  
        TSOM.TicketSourceName,  
        TTM.Type_Name,  
        TULN.Name As CreatedBy,  
        TULN.Name As ModifiedBy,  
        dbo.fn_ConvertDateTime(TM.CreatedOn, @TimeZone, 0) AS CreatedOn,  
        dbo.fn_ConvertDateTime(TM.ModifiedOn, @TimeZone, 0) AS ModifiedOn,  

        ' + @DynamicColumns + ',  
        (SELECT STRING_AGG(Tag, '', '') FROM TagMaster WHERE ID IN (SELECT value FROM STRING_SPLIT(TM.TicketTag, '',''))) AS Tags  
    FROM ' + @tableName + ' TM (NOLOCK)  
    LEFT JOIN tbl_tp_UserLogin TUL (NOLOCK) ON TUL.TpUser_Id = TM.AssignedUser AND TUL.IsActive = 1  
    LEFT JOIN tbl_tp_UserLogin TULN (NOLOCK) ON TULN.TpUser_Id = TM.CreatedBy AND TULN.IsActive = 1  
    LEFT JOIN tbl_tp_UserLogin TULM (NOLOCK) ON TULM.TpUser_Id = TM.ModifiedBy AND TULM.IsActive = 1  
    LEFT JOIN tbl_tp_TicketStatusMaster TSM (NOLOCK) ON TM.TicketStatusID = TSM.TicketStatus_ID  
    LEFT JOIN tbl_tp_TicketType_Master TTM (NOLOCK) ON TM.TicketTypeId = TTM.Type_ID  
    LEFT JOIN tbl_tp_TicketPriorityMaster TPM (NOLOCK) ON TM.TicketPriority = TPM.Priority_ID  
    LEFT JOIN tbl_tp_TicketSourceMaster TSOM (NOLOCK) ON TM.TicketSourceId = TSOM.TicketSourceId  
    LEFT JOIN tbl_tp_GroupMaster SGM (NOLOCK) ON SGM.GroupId = TM.AssignedGroup  
    LEFT JOIN UserLeads UL (NOLOCK) ON TM.EntityID = UL.ID AND TM.EntityName = ''Lead''  
    LEFT JOIN UserEnquiry UE (NOLOCK) ON TM.EntityID = UE.EnquiryID AND TM.EntityName = ''Enquiry''  
    LEFT JOIN (
        SELECT Distinct TTP.TicketID  
        FROM tbl_tp_TicketProducts (NOLOCK) TTP WHERE TTP.IsActive = 1  
    ) TP ON TP.TicketID = TM.TicketID  
    LEFT JOIN (
        SELECT Distinct ETM.EntityID  
        FROM EntityTagMapping (NOLOCK) ETM WHERE ETM.Entity = ''Ticket''  
    ) ETP ON ETP.EntityID = TM.TicketID  
    WHERE TM.TicketID > ''' + REPLACE(@SqlQuery, '''', '''''') + ''' AND TM.IsActive = 1 ' + 
    CASE WHEN @IsAdmin = 0 THEN ' AND TM.AssignedUser = ' + CAST(@TpuserId AS NVARCHAR(MAX)) ELSE '' END + 
    CASE WHEN @AccessType='AssignedToGroup' THEN ' AND TM.AssignedGroup IN (' + @StrGroupIds + ')' ELSE '' END +'
      
  ) as tbl  where RecNo BETWEEN 1 AND 10'     
   + ' ORDER BY RecNo ASC '
END

IF (@Mode = 'ContactFormData')
BEGIN
    -- Initialize @DynamicSQL with the base query
    SET @DynamicSQL = N'
    SELECT 
        TM.EntityName,   
        JSON_VALUE(TM.FormData, ''$.name'') AS Name,
        JSON_VALUE(TM.FormData, ''$.email'') AS Email,
        JSON_VALUE(TM.FormData, ''$.phone'') AS Phone,
        JSON_VALUE(TM.FormData, ''$.subject'') AS Subject,
        JSON_VALUE(TM.FormData, ''$.description'') AS Description,
        --JSON_VALUE(TM.FormData, ''$.domain'') AS Domain,
        TM.Status,
        dbo.fn_ConvertDateTime(TM.CreatedDate, @TimeZone, 0) AS CreatedOn
    FROM tbl_tp_ContactUsWebsitePortal TM (NOLOCK)
    WHERE TM.IsActive = 1 AND TM.ParentId = ' + CAST(@ParentID AS NVARCHAR(MAX));

    -- If @SqlQuery is not blank, append it to the WHERE clause
    IF ISNULL(@SqlQuery, '') <> ''
    BEGIN
        SET @DynamicSQL = @DynamicSQL + ' AND ' + @SqlQuery;
    END

    -- Finalize the query
    SET @DynamicSQL = @DynamicSQL + ';';
    
    -- Optionally execute the dynamic SQL here using sp_executesql if needed
    -- DECLARE @Params NVARCHAR(MAX) = N'@TimeZone NVARCHAR(MAX)';
    -- EXEC sp_executesql @DynamicSQL, @Params, @TimeZone = @YourTimeZoneVariable;
END



  
  PRINT CAST(@DynamicSQL AS VARCHAR(MAX))  
        EXEC sp_executesql @DynamicSQL,N'@TimeZone NVARCHAR(400)',@TimeZone;  
  
        --EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData                          
        --    @User_id = @UserId,                          
        --    @Activity_type = 'View_manageticketmaster',                          
        --    @ActionType = 'S',                          
        --    @RowJson = 'NULL',                          
        --    @Table_name = @tableName,                          
        --    @ip_adress = @IPAdress,                          
        --    @device_id = @DeviceId,                          
        --    @IsImpersonation = @IsImpersonation,                          
        --    @ImpersonatorId = @ImpersonatorId                          
                          
END TRY         
BEGIN CATCH                          
    PRINT 'Error occurred: ' + ERROR_MESSAGE()                          
END CATCH                          
END   






GO

/* ============================================================
   Procedure: [dbo].[usp_tp_GetTicketFields]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec usp_tp_GetTicketFields 32222
CREATE   PROC [dbo].[usp_tp_GetTicketFields]
(
	@ParentID bigint
)
As
Begin
	 --declare @ParentID bigint=32222
	DECLARE @status INT          
	DECLARE @TicketTableName NVARCHAR(MAX) = ''             
          
                            
	EXEC @status = Usp_tp_CreateTicketMasterTableByParentID @ParentID, @TicketTableName OUTPUT      
     
	DROP TABLE if exists #ColumnInformation; 

	CREATE TABLE #ColumnInformation (      
		TableName NVARCHAR(MAX),      
		ColumnName NVARCHAR(MAX),      
		FieldName NVARCHAR(MAX),      
		DataType NVARCHAR(MAX),      
		FieldType NVARCHAR(MAX),      
		Choices NVARCHAR(MAX),
		FieldValue NVARCHAR(MAX)  
	)      
      
	INSERT INTO #ColumnInformation      
	SELECT      
		'tbL_tp_TicketCustomFieldDisplayJson' AS TableName,      
		JSON_VALUE(value, '$.FieldName') AS ColumnName,      
		JSON_VALUE(value, '$.FieldName') AS FieldName,      
		JSON_VALUE(value, '$.DataType') AS DataType,      
		JSON_VALUE(value, '$.FieldType') AS FieldType,      
		JSON_VALUE(value, '$.Choices') AS Choices ,   
	    JSON_VALUE(value, '$.DefaultValue') AS FieldValue 
	FROM      
		OPENJSON((SELECT DisplayJson FROM tbL_tp_TicketCustomFieldDisplayJson(nolock) WHERE ParentId = @ParentID))      
	WHERE      
		JSON_VALUE(value, '$.FieldName') IS NOT NULL      
		AND JSON_VALUE(value, '$.DataType') IS NOT NULL      
		AND JSON_VALUE(value, '$.FieldType') IS NOT NULL      
		AND JSON_VALUE(value, '$.FieldType') <> ''   
	 AND JSON_VALUE(value, '$.Active') = 'true'  
	INSERT INTO #ColumnInformation      
	SELECT DISTINCT      
		@TicketTableName AS TableName,      
		REPLACE(COLUMN_NAME, 'Id', '') AS ColumnName,      
		COLUMN_NAME as FieldName,      
		DATA_TYPE AS DataType,      
		'' AS FieldType,      
		'' AS Choices,
	    '' AS FieldValue 
	FROM      
		INFORMATION_SCHEMA.COLUMNS I      
	WHERE      
		I.TABLE_NAME = @TicketTableName      
		--AND I.COLUMN_NAME NOT IN (      
		--	'TicketID', 'tpUser_Id', 'ParentID', 'AssignedSource', 'RequesterMobileNo1', 'RequesterEmailID1', 
		--	'RequesterMobileNo2', 'RequesterEmailID2', 'UserResponse', 'ProductId', 'IsMerged', 'IsSplitted', 
		--	'ParentTicketId', 'EntityId', 'EntityName', 'IsParentTicket', 'IsChildTicket', 'AssignedBy',      
		--	'TicketTag', 'IsActive', 'CreatedBy', 'ModifiedBy', 'ModifiedOn', 'SplittedBy', 'SplittedOn',     
		--	'MergedBy', 'MergedOn', 'ClosedBy', 'ClosedOn', 'CreatedChildBy', 'CreatedChildOn' 
		--)      
			AND I.COLUMN_NAME IN (      
			'TicketNo', 'RequesterMobileNo', 'RequesterEmailID', 'AssignedSource','Subject', 'Description', 'TicketStatusID', 'Remarks', 
			'Note', 'TicketPriority', 'AssignedUser', 'AssignedGroup', 'TicketCategoryId', 'TicketTypeId', 'TicketSourceId', 
			'LastActionDatetime', 'AssignedDateTime', 'Company','CreatedOn'
		)      

  
	 Delete from #ColumnInformation Where ColumnName in (  
	  SELECT  
	  JSON_VALUE(value, '$.FieldName') AS ColumnName  
	  FROM OPENJSON((SELECT DisplayJson FROM tbL_tp_TicketCustomFieldDisplayJson(nolock) WHERE ParentId = @ParentID))  
	  WHERE JSON_VALUE(value, '$.Active') = 'false'  
	 )  
  
      
	 ;WITH DuplicateColumns AS (    
		SELECT    
			ColumnName,    
			DataType,    
			ROW_NUMBER() OVER (PARTITION BY ColumnName ORDER BY FieldType DESC) AS RowNum    
		FROM    
			#ColumnInformation    
	)    
    
	DELETE FROM DuplicateColumns    
	WHERE RowNum > 1;    
    
	SELECT    
		ColumnName COLUMN_NAME,    
		FieldName,    
		DataType DATA_TYPE,    
		FieldType FIELD_TYPE,    
		MAX(Choices) AS Choices,
		FieldValue FieldValue  
	FROM    
		#ColumnInformation    
	GROUP BY    
		ColumnName, FieldName, DataType, FieldType,FieldValue;    
    
	DROP TABLE #ColumnInformation;    

End




