/* ============================================================
   Procedure: [dbo].[usp_tp_GetTicketGeneralDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec usp_tp_GetTicketGeneralDetails @TicketID=245,@EntityID=32222,@EntityName=N'User',@ParentId=32222,@TpUserId=1
 CREATE   PROCEDURE [dbo].[usp_tp_GetTicketGeneralDetails]
(
	@TicketID BIGINT,
	@EntityID BIGINT,
	@EntityName NVARCHAR(20),
	@ParentId BIGINT ,
	@TpUserId BIGINT NULL
)
AS
BEGIN
		 --declare @TicketID BIGINT=245,@EntityID BIGINT=32222,@EntityName NVARCHAR(20)='User',@ParentId BIGINT=32222,@TpUserId BIGINT=1
                            
DECLARE @DynamicSQL NVARCHAR(MAX), @status INT,@TicketActivityTable nvarchar(max)='', @tableName NVARCHAR(MAX), @TimeZone NVARCHAR(400)

EXEC @status = Usp_tp_CreateTicketMasterTableByParentID @ParentID, @tableName OUTPUT;

Select @TimeZone = isnull(TimeZone,'India Standard Time') From tbl_tp_UserLogin(noLock) Where TpUser_Id = @TpUserId AND IsActive = 1


Exec [Usp_tp_CreateTicketActivityTableByParentID] @ParentId, @TicketActivityTable out

IF (@EntityName = 'Lead')
BEGIN
	SET @DynamicSQL = N'
    --WITH CTE AS (                    
        SELECT                    
            T.TicketID,                    
            T.TicketNo,                    
            T.Subject,                    
            T.Description,                    
            T.EntityID,                    
            T.RequesterMobileNo,                    
            T.RequesterEmailID,                
            T.TicketPriority,              
            ISNULL(TSM.TicketSourceName, ''Unknown'') AS TicketSourceName,                    
            dbo.fn_ConvertDateTime(T.CreatedOn, @TimeZone, 0) AS CreatedOn,                     
            UL.PersonName,      
			concat(TUL1.Name,'' ('',TUL1.LoginName,'')'') As RespondedBy,
            TH.TicketHistoryID,                    
            TH.Remarks,                    
            TH.Note,                    
            TH.UserResponse,
            TCM.TicketCategoryName AS TicketCategoryName,
            dbo.fn_ConvertDateTime(TH.ActionDateTime, @TimeZone, 0) AS ActionDateTime,                    
            SM.GroupName AS Group_Name, 
			case when isnull(TUL.LoginName,'''') != ''''
	             then  concat(TUL.Name,'' ('',TUL.LoginName,'')'') 
	            else 
				    ''0''     
	            end
	         AS UserName,
            --concat(TUL.Name,'' ('',TUL.LoginName,'')'') AS UserName,
		  isnull(TH.AssignedUser,iif(isnull(TH.AssignedGroup,0)>0,0,T.AssignedUser)) As AssignedUser ,
         ISNULL(TH.AssignedGroup,iif(isnull(TH.AssignedUser,0)>0,0,T.AssignedGroup)) As AssignedGroup ,
            dbo.ufn_tp_DateDiffInDHMS(T.CreatedOn,getdate()) AS DaysSinceCreation,                    
            --STRING_AGG(tm.Tag, '','') AS TagList,                    
			TagList=(Select string_agg(Tag,'','') from TagMaster(nolock) Where ID in (select [value] from fn_split(T.TicketTag,'',''))),
            isnull(TSM_Status.TicketStatus,'''') as TicketStatus,
            isnull(TSM_Priority.PriorityName,'''') AS PriorityName,
            TTM.Type_Desc AS TicketType,                    
          --TA.DisplayName,                    
            --TA.FileUrl,                    
            --TA.TicketAttachmentID,  

			    		(
    SELECT
        ISNULL(
            NULLIF(
                JSON_QUERY(
                    (
                        SELECT
                            DisplayName AS ''FileName'',
                            FileUrl AS ''FilePath''
                        FROM tbl_tp_TicketAttachment
                        WHERE TicketHistoryID = TH.TicketHistoryID and IsActive = 1
                            AND DisplayName IS NOT NULL AND DisplayName <> ''''
                            AND FileUrl IS NOT NULL AND FileUrl <> ''''
                        FOR JSON PATH
                    )
                ),
                ''[]''
            ),
            ''''
        )
) AS Attachement,
	  FieldName = REPLACE(REPLACE(REPLACE(TH.FieldName, ''Id'', ''''), ''_'', '' ''), '' '', '' ''),
        OldValue = (CASE
                        WHEN TH.FieldName = ''TicketStatusID'' THEN (SELECT TOP 1 TicketStatus FROM tbl_tp_TicketStatusMaster WHERE TicketStatus_ID = CAST(TH.OldValue AS INT))
                        WHEN TH.FieldName = ''TicketPriority'' THEN (SELECT TOP 1 PriorityName FROM tbl_tp_TicketPriorityMaster WHERE Priority_ID = CAST(TH.OldValue AS INT))
                        WHEN TH.FieldName = ''AssignedGroup'' THEN (SELECT TOP 1 GroupName FROM tbl_tp_GroupMaster WHERE GroupId = CAST(TH.OldValue AS INT))
                        WHEN TH.FieldName = ''AssignedUser'' THEN (SELECT TOP 1 Name + '' ('' + LoginName + '')'' FROM tbl_tp_UserLogin WHERE TpUser_Id = CAST(TH.OldValue AS INT))
                        WHEN TH.FieldName = ''TicketAgent'' THEN (SELECT TOP 1 Name + '' ('' + LoginName + '')'' FROM tbl_tp_UserLogin WHERE TpUser_Id = CAST(TH.OldValue AS INT))
                        WHEN TH.FieldName = ''TicketTypeId'' THEN (SELECT TOP 1 Type_Name FROM tbl_tp_TicketType_Master WHERE Type_ID = CAST(TH.OldValue AS INT))
                        WHEN TH.FieldName = ''TicketCategoryId'' THEN (SELECT TOP 1 TicketCategoryName FROM tbl_tp_TicketCategory_Master WHERE TicketCategoryId = CAST(TH.OldValue AS INT))
                        ELSE TH.OldValue
                    END),
        NewValue = (CASE
                        WHEN TH.FieldName = ''TicketStatusID'' THEN (SELECT TOP 1 TicketStatus FROM tbl_tp_TicketStatusMaster WHERE TicketStatus_ID = CAST(TH.NewValue AS INT))
                        WHEN TH.FieldName = ''TicketPriority'' THEN (SELECT TOP 1 PriorityName FROM tbl_tp_TicketPriorityMaster WHERE Priority_ID = CAST(TH.NewValue AS INT))
                        WHEN TH.FieldName = ''AssignedGroup'' THEN (SELECT TOP 1 GroupName FROM tbl_tp_GroupMaster WHERE GroupId = CAST(TH.NewValue AS INT)) 
                        WHEN TH.FieldName = ''TicketAgent'' THEN (SELECT TOP 1 Name + '' ('' + LoginName + '')'' FROM tbl_tp_UserLogin WHERE TpUser_Id = CAST(TH.NewValue AS INT))
                        WHEN TH.FieldName = ''AssignedUser'' THEN (SELECT TOP 1 Name + '' ('' + LoginName + '')'' FROM tbl_tp_UserLogin WHERE TpUser_Id = CAST(TH.NewValue AS INT))
                        WHEN TH.FieldName = ''TicketTypeId'' THEN (SELECT TOP 1 Type_Name FROM tbl_tp_TicketType_Master WHERE Type_ID = CAST(TH.NewValue AS INT))
                        WHEN TH.FieldName = ''TicketCategoryId'' THEN (SELECT TOP 1 TicketCategoryName FROM tbl_tp_TicketCategory_Master WHERE TicketCategoryId = CAST(TH.NewValue AS INT))
                        ELSE TH.NewValue
                    END),
            COALESCE(TH.Note, TH.Remarks, TH.UserResponse, '''') AS CombinedColumn,
			CreatedBy=concat(TUL2.Name,'' ('',TUL2.LoginName,'')''),
			SourceColumn=case when len(TH.Note)>0 then ''Note / Forward'' 
							  when len(TH.Remarks)>0 then ''Reply''
							  when len(TH.UserResponse)>0 then ''User Response''
						 else '''' end,
			ActionOnDHMS=dbo.ufn_tp_DateDiffInDHMS(TH.ActionDateTime,getdate()),
			TH.ActionContent,
			TH.ReplyTo
        FROM ' + @tableName + ' AS T (NOLOCK)                    
        INNER JOIN UserLeads AS UL (NOLOCK) ON T.EntityID = UL.ID                    
        INNER JOIN ( Select TicketID,ParentId,ActionContent,TicketStatusID,TicketPriority,TicketHistoryID,AssignedGroup,AssignedUser,AssignedBy,Remarks,Note,UserResponse,ActionDateTime,ReplyTo,'''' as fieldname,'''' as oldvalue,'''' as newvalue 
			From tbl_tp_TicketHistory(nolock)
			Where isnull(ActionContent,'''')!=''Activity'' and TicketId=@TicketID and ParentID=@ParentId
			union
		  select TicketID,ParentId,''Activity'' as ActionContent,0 as TicketStatusID,0 as TicketPriority,ActivityId as TicketHistoryID,Case when FieldName=''AssignedGroup'' then NewValue Else null End as AssignedGroup,Case when FieldName=''AssignedUser'' then NewValue Else null End as AssignedUser,ActivityBy as AssignedBy,'''' as Remarks,ActivityDescription as Note,'''' as UserResponse,ActivityDatetime ActionDateTime,null as ReplyTo,
		  FieldName,OldValue,NewValue 
		  from tbl_tp_TicketActivity_'+cast(@ParentId as nvarchar)+'(nolock) Where IsActive=1 and TicketId=@TicketID and ParentID=@ParentId
		) AS TH ON T.TicketID = TH.TicketID and T.ParentId=TH.ParentId
		--LEFT JOIN tbl_tp_TicketActivity_'+cast(@ParentId as nvarchar)+' AS TAC (NOLOCK) ON T.TicketID = TAC.TicketID   
        LEFT JOIN tbl_tp_TicketStatusMaster AS TSM_Status (NOLOCK) ON TH.TicketStatusID = TSM_Status.TicketStatus_ID                    
        LEFT JOIN tbl_tp_TicketPriorityMaster AS TSM_Priority (NOLOCK) ON TH.TicketPriority = TSM_Priority.Priority_ID                    
        LEFT JOIN tbl_tp_TicketType_Master AS TTM (NOLOCK) ON T.TicketTypeId = TTM.Type_ID                   
        LEFT JOIN tbl_tp_TicketSourceMaster AS TSM (NOLOCK) ON T.TicketSourceId = TSM.TicketSourceId
        --LEFT JOIN tbl_tp_TicketAttachment AS TA (NOLOCK) ON TA.TicketHistoryID = TH.TicketHistoryID
        LEFT JOIN tbl_tp_GroupMaster AS SM (NOLOCK) ON T.AssignedGroup = SM.GroupId
        LEFT JOIN tbl_tp_UserLogin AS TUL (NOLOCK) ON TH.AssignedUser = TUL.TpUser_Id
		LEFT JOIN tbl_tp_UserLogin AS TUL1 (NOLOCK) ON TUL1.TpUser_Id = TH.AssignedBy
		LEFT JOIN tbl_tp_UserLogin AS TUL2 (NOLOCK) ON TUL2.TpUser_Id = T.CreatedBy
        LEFT JOIN dbo.tbl_tp_TicketCategory_Master TCM WITH (NOLOCK) 
    ON T.TicketCategoryId = TCM.TicketCategoryId
        --LEFT JOIN TagMaster AS tm ON CHARINDEX('','' + CAST(tm.ID AS NVARCHAR(MAX)) + '','', '','' + T.TicketTag + '','') > 0
        WHERE T.TicketID = @TicketID
		--GROUP BY
		--T.TicketID,
		--T.TicketNo,
		--T.Subject,
		--T.Description,
		--T.TicketPriority,
		--T.EntityID,
		--T.RequesterMobileNo,
		--T.RequesterEmailID,
		--ISNULL(TSM.TicketSourceName, ''Unknown''),
		--dbo.fn_ConvertDateTime(T.CreatedOn, @TimeZone, 0),
		--TUL1.Name,
		--UL.PersonName,
		--TH.Remarks,
		--TH.Note,
		--TH.UserResponse,
		--dbo.fn_ConvertDateTime(TH.ActionDateTime, @TimeZone, 0),
		--SM.GroupName,
		--TUL.Name,
		--DATEDIFF(DAY, T.CreatedOn, GETDATE()),
		--TSM_Status.TicketStatus,
		--TSM_Priority.PriorityName,
		--TTM.Type_Desc,
		--TA.DisplayName,
		--TA.FileUrl,
		--TA.TicketAttachmentID,
		--TH.TicketHistoryID
    --)                    
    --SELECT                    
    --    *,                    
    --    CASE                    
    --        WHEN CombinedColumn LIKE ''%'' + TRIM(Note) + ''%'' THEN ''Note / Forward''                    
    --        WHEN CombinedColumn = TRIM(Remarks) THEN ''Reply''                    
    --        WHEN CombinedColumn = TRIM(UserResponse) THEN ''User Response''                    
    --    END AS SourceColumn                    
    --FROM CTE                    
                    
 ORDER BY TH.ActionDateTime DESC;                    
';                    

	PRINT cast(@DynamicSQL as varchar(max))

END                        
ELSE IF (@EntityName = 'Enquiry')
BEGIN
SET @DynamicSQL = N'
   -- WITH CTE AS (                    
        SELECT                    
            T.TicketID,                    
            T.TicketNo,                    
            T.Subject,                    
