		LEFT JOIN tbl_tp_UserLogin AS TUL2 (NOLOCK) ON TUL2.TpUser_Id = T.CreatedBy
              LEFT JOIN dbo.tbl_tp_TicketCategory_Master TCM WITH (NOLOCK) 
  ON T.TicketCategoryId = TCM.TicketCategoryId
        --LEFT JOIN TagMaster AS tm ON CHARINDEX('','' + CAST(tm.ID AS NVARCHAR(MAX)) + '','', '','' + T.TicketTag + '','') > 0                    
        WHERE T.TicketID = @TicketID 
		--GROUP BY                    
  --          T.TicketID,                    
  --          T.TicketNo,                    
  --          T.Subject,                    
  --          T.Description,                    
  --          T.EntityID,                    
  --          T.RequesterMobileNo,                    
  --          T.RequesterEmailID,                    
  --          ISNULL(TSM.TicketSourceName, ''Unknown''),                    
  --          T.TicketPriority,              
  --          dbo.fn_ConvertDateTime(TH.ActionDateTime, @TimeZone, 0),                    
  --          UL.PersonName,      
		--	TUL1.Name,    
  --          TH.Remarks,                    
  --          TH.Note,                    
  --          TH.UserResponse,                    
  --          TH.ActionDateTime,                    
  --          SM.GroupName,                    
  --          TUL.Name,                    
  --          DATEDIFF(DAY, T.CreatedOn, GETDATE()),                    
  --          TSM_Status.TicketStatus,                    
  --          TSM_Priority.PriorityName,                    
  --          TTM.Type_Desc,                    
  --          TA.DisplayName,                    
  --          TA.FileUrl,                    
  -- TA.TicketAttachmentID,                    
  -- TH.TicketHistoryID                    
  --  )                    
  --  SELECT                    
  --      *,                    
  --     CASE                    
  --          WHEN CombinedColumn LIKE ''%'' + TRIM(Note) + ''%'' THEN ''Note / Forward''                    
  --          WHEN CombinedColumn = TRIM(Remarks) THEN ''Reply''                    
  --          WHEN CombinedColumn = TRIM(UserResponse) THEN ''User Response''                    
  --      END AS SourceColumn                    
  --  FROM CTE                    
                    
 ORDER BY TH.ActionDateTime DESC;                    
'; 
end
