            ''ParentID'',
            ''RequesterMobileNo1'',
            ''RequesterEmailID1'',
            ''RequesterMobileNo2'',
            ''RequesterEmailID2'',
            ''TicketPriority'',
            ''UserResponse'',
            ''AssignedUser'',
            ''AssignedGroup'',
            ''AssignedSource'',
            ''TicketCategoryId'',
            ''TicketTypeId'',
            ''TicketSourceId'',
            ''ProductId'',
            ''IsMerged'',
            ''IsSplitted'',
            ''ParentTicketId'',
            ''EntityId'',
            ''EntityName'',
            ''IsParentTicket'',
            ''IsChildTicket'',
            ''AssignedBy'',
            ''TicketTag'',
            ''IsActive'',
            ''CreatedBy'',
            ''ModifiedBy'',
            ''ModifiedOn'',
            ''SplittedBy'',
            ''SplittedOn'',
            ''MergedBy'',
            ''MergedOn'',
            ''ClosedBy'',
            ''ClosedOn'',
            ''CreatedChildBy'',
            ''CreatedChildOn''
        )'

    -- Execute the dynamic SQL query
