/* ============================================================
   Procedure: [dbo].[Usp_tp_GetTicketPriorityList]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_tp_GetTicketPriorityList]
(    
    @ParentId bigint,          
    @MetaData nvarchar(200)    
)
AS
BEGIN
    DECLARE @UserId BIGINT, @TimeZone nvarchar(400), @rowJson NVARCHAR(MAX), @IPAdress NVARCHAR(50), @DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT
    SELECT @UserId = User_Id, @TimeZone = TimeZone FROM tbl_tp_UserLogin (NOLOCK) WHERE ParentId = @ParentId AND IsActive = 1
                            
    SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)
    SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)
    SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)
    SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)

    -- Check the record count for the specified ParentId
    DECLARE @RecordCount INT
    SELECT @RecordCount = COUNT(*) 
    FROM tbl_tp_TicketPriorityMaster 
    WHERE ParentId = @ParentId

    -- If no records exist, call the new procedure to insert predefined priorities
    IF @RecordCount = 0
    BEGIN
        EXEC [dbo].[Usp_tp_InsertPredefinedValues] @ParentId = @ParentId, @Mode = 'TicketPriority';
    END

    -- Select all priorities for the given ParentId
    SELECT * from tbl_tp_TicketPriorityMaster(nolock)  P  WHERE ParentId = @ParentId and Active=1
    ORDER BY SequenceNo  

    -- Get the JSON representation of all priorities
    SET @rowJson = (SELECT * FROM tbl_tp_TicketPriorityMaster WHERE ParentId = @ParentId FOR JSON AUTO, INCLUDE_NULL_VALUES)

    -- Insert audit data if priorities exist
    IF @rowJson IS NOT NULL
    BEGIN
        EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData @User_id = @UserId
            , @Activity_type = 'View_TicketPriorityList'
            , @ActionType = 'S'
            , @RowJson = ''
            , @Table_name = 'tbl_tp_TicketPriorityMaster', @ip_adress = @IPAdress, @device_id = @DeviceId, @IsImpersonation = @IsImpersonation, @ImpersonatorId = @ImpersonatorId
    END
END





