/* ============================================================
   Procedure: [dbo].[usp_tp_GetUserDetailForRolePermission]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_tp_GetUserDetailForRolePermission] 
@ParentId BIGINT,
@MetaData NVARCHAR(200)
AS
BEGIN
--declare @ParentId BIGINT=32222,
--@MetaData NVARCHAR(200)='{}'
DECLARE @RecordCount INT;
SELECT @RecordCount = COUNT(*)
FROM tbl_tp_TicketPriorityMaster
WHERE ParentId = @ParentId;

-- If no records exist, call the new procedure to insert predefined priorities
IF @RecordCount = 0
BEGIN
    EXEC [dbo].[Usp_tp_InsertPredefinedValues] @ParentId = @ParentId, @Mode = '';
END;

WITH Aggregated AS (
    SELECT
        RM.Role_Id,
        RM.RoleName,
        RM.Description,
        CASE WHEN RM.Agent_Type = 1 THEN 'Support Agent' END AS AgentType,
        RM.ParentId,
        RM.CreatedBy,
        RM.CreatedDate,
        RM.IsPredefined,
        RM.Isdefault,
        RM.ParentRole_Id,
        PM.Permission_Id,
        ARM.tpuserid,
        TUL.Name + '(' + TUL.LoginName + ')' AS UserName,
        APF.PermissionCode,
        APF.PermissionValues
    FROM tbl_tp_RolesMaster AS RM
    LEFT JOIN tbl_tp_agentrolemapping AS ARM ON RM.Role_Id = ARM.Role_Id
    LEFT JOIN tbl_tp_UserLogin AS TUL ON TUL.TpUser_Id = ARM.tpuserid
    LEFT JOIN tbl_tp_Permission_Mapping AS PM ON RM.Role_Id = PM.Role_Id
    LEFT JOIN tbl_tp_Assignment_PermissionField AS APF ON RM.Role_Id = APF.Role_Id
    WHERE RM.IsActive = 1 
      AND (RM.ParentId = @ParentId OR RM.ParentId = 0)
)

SELECT
    Role_Id,
    RoleName,
    Description,
    AgentType,
    ParentId,
    CreatedBy,
    CreatedDate,
    IsPredefined,
    Isdefault,
    ParentRole_Id,
    COUNT(DISTINCT CASE WHEN COALESCE(tpuserid, '') <> '' THEN tpuserid END) AS AgentCount,
    
    -- Concatenate tpuserid list
    STUFF((SELECT DISTINCT ', ' + CAST(tpuserid AS NVARCHAR(MAX))
           FROM Aggregated
           WHERE Role_Id = a.Role_Id
           FOR XML PATH('')), 1, 2, '') AS tpuserid_list,
    
    -- Concatenate Permission_Id list
    STUFF((SELECT DISTINCT ', ' + CAST(Permission_Id AS NVARCHAR(MAX))
           FROM Aggregated
           WHERE Role_Id = a.Role_Id
           FOR XML PATH('')), 1, 2, '') AS Permission_Id,

    -- Concatenate UserName list
    STUFF((SELECT DISTINCT ', ' + UserName
           FROM Aggregated
           WHERE Role_Id = a.Role_Id
           FOR XML PATH('')), 1, 2, '') AS tpuserid_Namelist,
    
    -- Handle SPECIFIC_Group permission: concatenate PermissionValues
    STUFF((SELECT DISTINCT ', ' + CAST(PermissionValues AS NVARCHAR(MAX))
           FROM Aggregated
           WHERE Role_Id = a.Role_Id AND PermissionCode = 'SPECIFIC_Group'
           FOR XML PATH('')), 1, 2, '') AS SpecificGroupPermissionValues,

    -- Handle SPECIFIC_User permission: concatenate PermissionValues
    STUFF((SELECT DISTINCT ', ' + CAST(PermissionValues AS NVARCHAR(MAX))
           FROM Aggregated
           WHERE Role_Id = a.Role_Id AND PermissionCode = 'SPECIFIC_User'
           FOR XML PATH('')), 1, 2, '') AS SpecificUserPermissionValues

FROM Aggregated a
GROUP BY 
    Role_Id, RoleName, Description, AgentType, ParentId, CreatedBy, CreatedDate, 
    IsPredefined, Isdefault, ParentRole_Id;

END;





GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_GetUserGroupMapping]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

   
CREATE   PROCEDURE [dbo].[Usp_tp_GetUserGroupMapping]                      
                     
  @UserId BigInt,  
  @MetaData NVARCHAR(MAX)  
                    
AS                      
Begin  
  ----declare @UserId BigInt=90,  
  --    @MetaData NVARCHAR(MAX) ='{}' 
    DECLARE @TimeZone NVARCHAR(400),    
            @rowJson NVARCHAR(MAX),    
            @IPAdress NVARCHAR(50),    
            @DeviceId NVARCHAR(50),    
            @IsImpersonation BIT,    
            @ImpersonatorId INT, 
			@UserId1 BIGINT,
            @ParentId BIGINT ,
			@tpuserid BIGINT
  
    SELECT @ParentId = ParentId, @TimeZone = TimeZone,@UserId1=User_Id FROM tbl_tp_UserLogin (NOLOCK)  WHERE TpUser_Id = @userid
    
    SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)    
    SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)    
    SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)    
    SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)   
        
 SELECT Ul.AgentGroupMap_Id, UL.GroupId,Ul.tpUserId, GM.GroupName, UL.AccessType, TU.LoginName as Name
FROM tbl_tp_AgentGroupMapping UL
INNER JOIN tbl_tp_GroupMaster GM ON GM.GroupId = UL.GroupId
INNER JOIN tbl_tp_UserLogin TU ON TU.TpUser_Id = UL.tpUserId
WHERE Tu.ParentId = @ParentId and UL.IsActive=1;

         
    SET @rowJson = (SELECT * FROM tbl_tp_UserLogin FOR JSON AUTO, INCLUDE_NULL_VALUES)    
    
    IF @rowJson IS NOT NULL    
    BEGIN    
        EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData    
            @User_id = @UserId1,    
            @Activity_type = 'View_userlogin',    
            @ActionType = 'S',    
            @RowJson = NULL,    
            @Table_name = 'tbl_tp_UserLogin',    
            @ip_adress = @IPAdress,    
            @device_id = @DeviceId,    
            @IsImpersonation = @IsImpersonation,    
            @ImpersonatorId = @ImpersonatorId    
    END    
        
End 




