/* ============================================================
   Procedure: [dbo].[usp_tp_GetUserPermissions]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



 CREATE   PROCEDURE [dbo].[usp_tp_GetUserPermissions]
    @tpUserId BIGINT
AS
BEGIN
--declare  @tpUserId BIGINT=1
    SET NOCOUNT ON;

    DECLARE @ParentId BIGINT,
            @AssignedRoleId BIGINT,
            @PermissionCodes NVARCHAR(MAX),
            @PermissionValues NVARCHAR(MAX);

    -- Get the ParentId for the given tpUserId
    SELECT @ParentId = ParentId
    FROM tbl_tp_UserLogin (NOLOCK)
    WHERE TpUser_Id = @tpUserId AND IsActive = 1;

    -- Get the Assigned Role Id
    SELECT @AssignedRoleId = arm.role_id
    FROM tbl_tp_agentrolemapping arm (NOLOCK)
    WHERE arm.tpuserid = @tpUserId 
      AND arm.Active = 1;

    -- Aggregate Permission Codes and Permission Values (only for SPECIFIC_USER)
    SELECT 
        --@PermissionCodes = STRING_AGG(PermissionCode, ','), -- Permission Codes
		  @PermissionCodes = 
            STUFF((
                SELECT DISTINCT ',' + CAST(PermissionCode AS NVARCHAR(MAX))
                FROM tbl_tp_Assignment_PermissionField (NOLOCK)
                WHERE Role_Id = @AssignedRoleId
                  AND IsActive = 1
                  --AND PermissionCode = 'SPECIFIC_USER'
                FOR XML PATH(''), TYPE
            ).value('.', 'NVARCHAR(MAX)'), 1, 1, ''),
        @PermissionValues = 
            STUFF((
                SELECT DISTINCT ',' + CAST(PermissionValues AS NVARCHAR(MAX))
                FROM tbl_tp_Assignment_PermissionField (NOLOCK)
                WHERE Role_Id = @AssignedRoleId
                  AND IsActive = 1
                  AND PermissionCode = 'SPECIFIC_USER'
                FOR XML PATH(''), TYPE
            ).value('.', 'NVARCHAR(MAX)'), 1, 1, '')
    FROM tbl_tp_Assignment_PermissionField (NOLOCK)
    WHERE Role_Id = @AssignedRoleId AND IsActive = 1;
    -- Create Results Table
    DECLARE @Results TABLE (
        User_Id BIGINT, 
        Name NVARCHAR(255), 
        LoginName NVARCHAR(255), 
        TpUser_Id BIGINT
    );
	    IF @PermissionCodes IS NULL
    BEGIN
        INSERT INTO @Results (User_Id, Name, LoginName, TpUser_Id)
        SELECT User_Id, Name, LoginName, TpUser_Id
        FROM tbl_tp_UserLogin (NOLOCK)
        WHERE ParentID = @ParentId 
          AND User_Id IS NOT NULL 
          AND IsActive = 1
        ORDER BY TpUser_Id ASC;

        -- Return the final result set if PermissionCodes are NULL
        SELECT * FROM @Results;
        RETURN;
    END


    IF @PermissionCodes IS NOT NULL
    BEGIN
        DECLARE @CurrentCode NVARCHAR(50);
        DECLARE @Start INT = 1, @CommaIndex INT;

        -- Loop through each permission code
        WHILE @Start <= LEN(@PermissionCodes)
        BEGIN
            SET @CommaIndex = CHARINDEX(',', @PermissionCodes, @Start);
            IF @CommaIndex = 0 
            BEGIN
                SET @CommaIndex = LEN(@PermissionCodes) + 1; -- Last element
            END

            -- Extract the current permission code
            SET @CurrentCode = TRIM(SUBSTRING(@PermissionCodes, @Start, @CommaIndex - @Start));

            -- Handle various permission codes
            IF @CurrentCode = 'ALL_USERS'
            BEGIN
                -- If 'ALL_USERS', fetch all users under the ParentId
                INSERT INTO @Results (User_Id, Name, LoginName, TpUser_Id)
                SELECT User_Id, Name, LoginName, TpUser_Id
                FROM tbl_tp_UserLogin (NOLOCK)
                WHERE ParentID = @ParentId 
                  AND User_Id IS NOT NULL 
                  AND IsActive = 1
                ORDER BY TpUser_Id ASC;
                BREAK;
            END
ELSE IF @CurrentCode = 'GROUP_BELONG_USER'
BEGIN
    -- First, fetch the unique group IDs that the current user belongs to
    DECLARE @GroupIds TABLE (GroupId BIGINT);

    INSERT INTO @GroupIds (GroupId)
    SELECT DISTINCT agm.GroupId
    FROM tbl_tp_AgentGroupMapping agm (NOLOCK)
    WHERE agm.tpuserid = @tpUserId; 

  
    INSERT INTO @Results (User_Id, Name, LoginName, TpUser_Id)
    SELECT DISTINCT ul.User_Id, ul.Name, ul.LoginName, ul.TpUser_Id
    FROM tbl_tp_UserLogin ul (NOLOCK)
    INNER JOIN tbl_tp_AgentGroupMapping agm (NOLOCK) 
        ON ul.TpUser_Id = agm.tpuserid
    WHERE agm.GroupId IN (SELECT GroupId FROM @GroupIds)
      AND ul.IsActive = 1
    ORDER BY ul.TpUser_Id ASC;
END


            ELSE IF @CurrentCode = 'SPECIFIC_USER'
            BEGIN
                -- If 'SPECIFIC_USER', fetch users based on PermissionValues
                IF @PermissionValues IS NOT NULL AND LEN(@PermissionValues) > 0
                BEGIN
                    INSERT INTO @Results (User_Id, Name, LoginName, TpUser_Id)
                    SELECT ul.User_Id, ul.Name, ul.LoginName, ul.TpUser_Id
                    FROM tbl_tp_UserLogin ul (NOLOCK)
                    WHERE ul.TpUser_Id IN (
                        SELECT value 
                        FROM STRING_SPLIT(@PermissionValues, ',')
                    )
                      AND ul.IsActive = 1;
                END
            END
            ELSE IF @CurrentCode = 'SELF_USER'
            BEGIN
                -- If 'SELF_USER', fetch self user info
                INSERT INTO @Results (User_Id, Name, LoginName, TpUser_Id)
                SELECT User_Id, Name, LoginName, TpUser_Id
                FROM tbl_tp_UserLogin (NOLOCK)
                WHERE TpUser_Id = @tpUserId AND IsActive = 1;
            END

            -- Move to the next permission code
            SET @Start = @CommaIndex + 1;
        END
    END

    -- Return the final result set
    SELECT * FROM @Results;
END;









GO

