/* ============================================================
   Procedure: [dbo].[Usp_tp_HandlePassworChangePassword]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

           
CREATE   PROCEDURE [dbo].[Usp_tp_HandlePassworChangePassword]
    @resetGuid NVARCHAR(255)
AS
BEGIN
    DECLARE @isValid BIT, @expiryDate DATETIME, @userid BIGINT, @userLogin NVARCHAR(50), @oldPassword NVARCHAR(50);

    SELECT @isValid = isvalid, @expiryDate = expirydate, @userid = userid
    FROM ResetPassword
    WHERE guid = @resetGuid;

    IF (@@ROWCOUNT > 0)
    BEGIN
        IF (@isValid = 0 OR GETDATE() > @expiryDate)
        BEGIN
            -- Update ResetPassword table to mark it as invalid
            UPDATE ResetPassword
            SET isvalid = 0, processedon = GETDATE()
            WHERE guid = @resetGuid;
        END
        ELSE
        BEGIN
            -- Fetch User_Login for the given UserID
            SELECT @userLogin = LoginName
            FROM tbl_tp_UserLogin
            WHERE TpUser_Id = @userid;

            IF (@@ROWCOUNT > 0)
            BEGIN
                -- Fetch Old Password based on User_Login
                SELECT @oldPassword = Pwd
                FROM tbl_tp_UserLogin
                WHERE LoginName = @userLogin;
            END
        END
    END

    SELECT @isValid AS IsResetValid, @userLogin AS UserLogin, @oldPassword AS OldPassword;
END



GO

/* ============================================================
   Procedure: [dbo].[usp_tp_InsertAutoResponse]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_tp_InsertAutoResponse]  
      @tpUserId BIT,  
    @Description NVARCHAR(MAX),  
    @UserResponseTitle NVARCHAR(MAX),  
    @IsActive BIT,  
    @CreatedBy BIGINT,  
    @AvilaibleFor NVARCHAR(MAX),  
    @GroupID NVARCHAR(MAX) = NULL  
AS  
BEGIN  
    BEGIN TRY  
        BEGIN TRAN  
  
        IF EXISTS (SELECT 1 FROM [dbo].[tbl_tp_AutoResponseCannedMaster] WHERE UserResponseTitle = @UserResponseTitle)  
        BEGIN  
            SELECT 'Exists' AS Status;  
        END  
        ELSE  
        BEGIN  
            -- Insert into tbl_tp_AutoResponseCannedMaster  
            INSERT INTO [dbo].[tbl_tp_AutoResponseCannedMaster] (tpUser_Id, Description, UserResponseTitle, IsActive, CreatedBy, CreatedOn, AvilaibleFor)  
            VALUES (@tpUserId, @Description, @UserResponseTitle, @IsActive, @CreatedBy, GETDATE(), @AvilaibleFor);  
  
            DECLARE @ARID BIGINT  
            SET @ARID = SCOPE_IDENTITY()  
  
            IF (@AvilaibleFor = 'agentgroup' AND @GroupID IS NOT NULL AND @GroupID <> '')  
            BEGIN  
                -- Insert into tbl_tp_CannedGroupMapping  
                INSERT INTO tbl_tp_CannedGroupMapping (tpUserId, Group_Id, IsActive, CreatedBy, CreatedDate)  
                SELECT @CreatedBy, value, 1, @CreatedBy, GETDATE()  
                FROM STRING_SPLIT(@GroupID, ',');  
            END  
  
            SELECT 'Success' AS Status;  
        END  
  
        COMMIT  
    END TRY  
    BEGIN CATCH  
        ROLLBACK  
        SELECT 'Error occurred' AS Status;  
    END CATCH  
END  



GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_InsertCategoryMaster]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_InsertCategoryMaster]              
(            
 @TicketCategoryId Bigint,               
 @TpUserId Bigint,               
 @TicketCategoryName Nvarchar(30)='',   
 @TicketDescription Nvarchar(200)='',             
 @Option Varchar(10),                   
 @MetaData Nvarchar(200)         
)              
AS              
               
Begin              
        
      DECLARE @TimeZone nvarchar (400)  ,@rowJson NVARCHAR(MAX) ,@UserId BIGINT , @IPAdress NVARCHAR(50),@DeviceId NVARCHAR(50),@IsImpersonation BIT ,
      @ImpersonatorId INT  ,@ParentId INT  
      Select @ParentId = ParentId,@TimeZone = TimeZone, @UserId = User_id From tbl_tp_UserLogin (noLock) Where TpUser_Id = @TpUserId AND IsActive = 1                
                  
    SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)          
    SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)          
    SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)          
    SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)          
                  
              
IF @Option = 'Insert'               
Begin               
  If(Not Exists(Select 'x' from tbl_tp_TicketCategory_Master where TicketCategoryName = @TicketCategoryName and ParentId = @ParentID))              
   Begin              
  INSERT INTO tbl_tp_TicketCategory_Master (ParentId, TicketCategoryName,TicketCategoryDesc,IsActive,CreatedBy,CreatedDate)              
                                            VALUES              
                                           (@ParentID, @TicketCategoryName,@TicketDescription,1,@TpUserId,GETDATE())              
       Select 'Record has been saved' resp         
        
        SET @rowJson  = ( SELECT *  FROM tbl_tp_TicketCategory_Master  FOR JSON AUTO  ,INCLUDE_NULL_VALUES )                  
                  
          IF @rowJson IS NOT NULL                  
          BEGIN                  
           EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData @User_id = @UserId                  
            ,@Activity_type = 'Add_ticketcategory'                  
            ,@ActionType = 'I'                  
            ,@RowJson = @rowJson                  
            ,@Table_name = 'tbl_tp_TicketCategory_Master'  ,@ip_adress = @IPAdress ,@device_id = @DeviceId,@IsImpersonation = @IsImpersonation,@ImpersonatorId =  @ImpersonatorId           
          END       
  End              
 Else              
    Begin              
      Select 'Category Already Exists' resp               
                 
    End              
                
                
End              
if @Option = 'Update'               
Begin              
 IF EXISTS(select 1 from tbl_tp_TicketCategory_Master where TicketCategoryName = @TicketCategoryName and TicketCategoryId <> @TicketCategoryId)              
  Select 'Category already exist' resp              
 Else              
 Update tbl_tp_TicketCategory_Master              
  Set TicketCategoryName = @TicketCategoryName ,  TicketCategoryDesc =  @TicketDescription,ModifiedBy = @TpUserId, ModifiedDate = GETDATE()         
  Where  TicketCategoryId= @TicketCategoryId             
  Select 'Record has been updated' resp       
  SET @rowJson  = ( SELECT *  FROM tbl_tp_TicketCategory_Master  FOR JSON AUTO  ,INCLUDE_NULL_VALUES )                  
                  
          IF @rowJson IS NOT NULL                  
          BEGIN                  
           EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData @User_id = @UserId                  
            ,@Activity_type = 'Update_ticketcategory'                  
            ,@ActionType = 'U'                  
            ,@RowJson = @rowJson                  
            ,@Table_name = 'tbl_tp_TicketCategory_Master'  ,@ip_adress = @IPAdress ,@device_id = @DeviceId,@IsImpersonation = @IsImpersonation,@ImpersonatorId =  @ImpersonatorId           
          END         
End                                        
End 



