/* ============================================================
   Procedure: [dbo].[Usp_tp_InsertContactUsWebsitePortalFormData]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_tp_InsertContactUsWebsitePortalFormData]
    @formData NVARCHAR(MAX)
AS
BEGIN
--declare  @formData NVARCHAR(MAX)= N'{
--    "description": "vhjhbvhjhjhjhhjhjh bjh",
--    "domain": "localhost/aa",
--    "email": "Lead203@gmail.com",
--    "name": "leadtest",
--    "phone": "9089761235",
--    "subject": "gggu"
--}';
    SET NOCOUNT ON;

    DECLARE @ParentId BIGINT,
            @Domain NVARCHAR(MAX), 
            @Email NVARCHAR(MAX), 
            @Mobile NVARCHAR(MAX);
            
    -- Parsing the JSON data
    SELECT @Domain = Domain, 
           @Mobile = Mobile, 
           @Email = Email
    FROM OPENJSON(@formData)
    WITH 
    (
        Domain NVARCHAR(max) '$.domain',
        Mobile NVARCHAR(max) '$.phone',
        Email NVARCHAR(max) '$.email'
    );

    DECLARE @SubDomain NVARCHAR(200);
    SET @SubDomain = SUBSTRING(@Domain, LEN(@Domain) - CHARINDEX('/', REVERSE(@Domain)) + 2, LEN(@Domain));

    DECLARE @FullPortalName NVARCHAR(MAX) = @Domain + @SubDomain;

    -- Determine the ParentId based on the domain
    IF EXISTS (
        SELECT 1
        FROM tbl_tp_Portalsetting WITH (NOLOCK)
        WHERE @SubDomain = PortalName
        GROUP BY PortalName
        HAVING COUNT(DISTINCT ParentId) > 1
    )
    BEGIN
        SELECT TOP 1 @ParentId = ParentId
        FROM tbl_tp_Portalsetting WITH (NOLOCK)
        WHERE @FullPortalName = @Domain + PortalName
        ORDER BY ParentId;
    END
    ELSE
    BEGIN
        SELECT TOP 1 @ParentId = ParentId
        FROM tbl_tp_Portalsetting WITH (NOLOCK)
        WHERE @SubDomain = PortalName AND IsActive = 1;
    END

    -- Check for matching leads
    DECLARE @LeadId INT = 0;
    SELECT @LeadId = ID
    FROM UserLeads WITH (NOLOCK)
    WHERE ParentID = @ParentId AND ((@Email IN (EmailID, EmailID1, EmailID2)) OR (@Mobile IN (MobileNo, MobileNo1, MobileNo2)));

    IF @LeadId > 0
    BEGIN
        -- Insert into ContactUsWebsitePortal for Lead
        INSERT INTO tbl_tp_ContactUsWebsitePortal (FormData, ParentId,CreatedDate, EntityId, EntityName, Status)
        VALUES (@formData, @ParentId,GETDATE(), @LeadId, 'Lead', 'Read');

        SELECT 'Record Submitted successfully.';
    END
    ELSE
    BEGIN
        -- Check for matching enquiries
        DECLARE @EnquiryId INT = 0;
        SELECT @EnquiryId = EnquiryID
        FROM UserEnquiry WITH (NOLOCK)
        WHERE ParentID = @ParentId AND ((@Email IN (EmailID, EmailID1, EmailID2)) OR (@Mobile IN (MobileNo, MobileNo1, MobileNo2)));

        IF @EnquiryId > 0
        BEGIN
            -- Insert into ContactUsWebsitePortal for Enquiry
            INSERT INTO tbl_tp_ContactUsWebsitePortal (FormData, ParentId,CreatedDate, EntityId, EntityName, Status)
            VALUES (@formData, @ParentId,GETDATE(), @EnquiryId, 'Enquiry', 'Read');

            SELECT 'Record Submitted successfully.';
        END
        ELSE
        BEGIN
            -- Insert into ContactUsWebsitePortal with status 'Open'
            INSERT INTO tbl_tp_ContactUsWebsitePortal (FormData, ParentId,CreatedDate ,Status)
            VALUES (@formData, @ParentId,GETDATE(), 'Open');

            SELECT 'Record Submitted successfully.';
        END
    END
END




GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_InsertEmailNotificationSetting]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_tp_InsertEmailNotificationSetting]
    @TpUserId INT,
    @Subject NVARCHAR(MAX),
    @Description NVARCHAR(MAX),
    @NotificationId INT,
    @MetaData NVARCHAR(MAX)
AS
BEGIN
    DECLARE @ParentID BIGINT, @UserId BIGINT, @rowJson NVARCHAR(MAX), @IPAdress NVARCHAR(50), @DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT

    SELECT @ParentID = ParentId, @UserId = User_Id FROM tbl_tp_UserLogin (NOLOCK) WHERE TpUser_Id = @TpUserId AND IsActive = 1

    SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)
    SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)
    SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)
    SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)

    IF EXISTS (SELECT 1 FROM tbl_tp_TicketNotificationDetail WHERE NotificationId = @NotificationId and ParentId=@ParentID)
    BEGIN
        UPDATE tbl_tp_TicketNotificationDetail
        SET
            Subject = @Subject,
            Description = @Description,
            ModifiedBy = @UserId,
            ModifiedOn = GETDATE()
        WHERE NotificationId = @NotificationId;

        SET @rowJson = (SELECT * FROM tbl_tp_TicketNotificationDetail tm WHERE NotificationId = @NotificationId AND ParentID = @ParentId FOR JSON AUTO, INCLUDE_NULL_VALUES);
    END
    ELSE
    BEGIN
        INSERT INTO [dbo].[tbl_tp_TicketNotificationDetail] (NotificationId, Subject, Description, CreatedBy, CreatedOn,ParentId)
        VALUES (@NotificationId, @Subject, @Description, @UserId, GETDATE(),@ParentID);

        SET @rowJson = (SELECT * FROM tbl_tp_TicketNotificationDetail tm WHERE NotificationId = SCOPE_IDENTITY() AND ParentID = @ParentId FOR JSON AUTO, INCLUDE_NULL_VALUES);
    END

    IF @rowJson IS NOT NULL
    BEGIN
        EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData
            @User_id = @UserId,
            @Activity_type = 'Updt_updateNotificationDetailForMessage',
            @ActionType = 'U',
            @RowJson = @rowJson,
            @Table_name = 'tbl_tp_TicketNotificationDetail',
            @ip_adress = @IPAdress,
            @device_id = @DeviceId,
            @IsImpersonation = @IsImpersonation,
            @ImpersonatorId = @ImpersonatorId;
    END

    SELECT 'Subject has been saved successfully' AS Message;
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_InsertFaqCategoryMaster]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON




CREATE   PROCEDURE [dbo].[Usp_tp_InsertFaqCategoryMaster]
(
    @FaqCategoryId BIGINT,
    @TpUserId BIGINT,
    @jsonqa NVARCHAR(MAX),
    @FaqCategoryName NVARCHAR(30) = '',
    @TicketDescription NVARCHAR(200) = '',
    @Option VARCHAR(10),
    @MetaData NVARCHAR(200)
)
AS
BEGIN
    DECLARE @TimeZone NVARCHAR(400),
            @rowJson NVARCHAR(MAX),
            @UserId BIGINT,
            @IPAdress NVARCHAR(50),
            @DeviceId NVARCHAR(50),
            @IsImpersonation BIT,
            @ImpersonatorId INT,
            @ParentId INT;

    -- Fetch user details
    SELECT @ParentId = ParentId, 
           @TimeZone = TimeZone, 
           @UserId = User_id 
    FROM tbl_tp_UserLogin (NOLOCK) 
    WHERE TpUser_Id = @TpUserId AND IsActive = 1;

    -- Extract metadata
    SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress);
    SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress);
    SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation);
    SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId);

    IF @Option = 'Insert'
    BEGIN
        -- Check if category already exists
        IF NOT EXISTS (SELECT 'x' 
                       FROM tbl_tp_TicketFaqCategory_Master 
                       WHERE FaqCategoryName = @FaqCategoryName AND ParentId = @ParentID)
        BEGIN
            -- Insert new category
            INSERT INTO tbl_tp_TicketFaqCategory_Master (ParentId, jsonqa, FaqCategoryName, FaqCategoryDesc, IsActive, CreatedBy, CreatedDate)
            VALUES (@ParentID, @jsonqa, @FaqCategoryName, @TicketDescription, 1, @TpUserId, GETDATE());
            
            SELECT 'Record has been saved' AS resp;

            -- Audit the insert operation
            SET @rowJson = (SELECT * FROM tbl_tp_TicketFaqCategory_Master FOR JSON AUTO, INCLUDE_NULL_VALUES);
            IF @rowJson IS NOT NULL
            BEGIN
                EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData 
                    @User_id = @UserId,
                    @Activity_type = 'Add_ticketcategory',
                    @ActionType = 'I',
                    @RowJson = @rowJson,
                    @Table_name = 'tbl_tp_TicketFaqCategory_Master',
                    @ip_adress = @IPAdress,
                    @device_id = @DeviceId,
                    @IsImpersonation = @IsImpersonation,
                    @ImpersonatorId = @ImpersonatorId;
            END
        END
        ELSE
        BEGIN
            SELECT 'Category Already Exists' AS resp;
        END
    END

    IF @Option = 'Update'
    BEGIN
        -- Check if another category with the same name exists
        IF EXISTS (SELECT 1 
                   FROM tbl_tp_TicketFaqCategory_Master 
                   WHERE FaqCategoryName = @FaqCategoryName AND FaqCategoryId <> @FaqCategoryId)
        BEGIN
            SELECT 'Category already exists' AS resp;
        END
        ELSE
        BEGIN
            -- Update existing category
            UPDATE tbl_tp_TicketFaqCategory_Master
            SET FaqCategoryName = @FaqCategoryName,
                jsonqa = @jsonqa,
                FaqCategoryDesc = @TicketDescription,
                ModifiedBy = @TpUserId,
                ModifiedDate = GETDATE()
            WHERE FaqCategoryId = @FaqCategoryId;

            SELECT 'Record has been updated' AS resp;

            -- Audit the update operation
            SET @rowJson = (SELECT * FROM tbl_tp_TicketFaqCategory_Master FOR JSON AUTO, INCLUDE_NULL_VALUES);
            IF @rowJson IS NOT NULL
            BEGIN
                EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData 
                    @User_id = @UserId,
                    @Activity_type = 'Update_ticketFaqcategory',
                    @ActionType = 'U',
                    @RowJson = @rowJson,
                    @Table_name = 'tbl_tp_TicketFaqCategory_Master',
                    @ip_adress = @IPAdress,
                    @device_id = @DeviceId,
                    @IsImpersonation = @IsImpersonation,
                    @ImpersonatorId = @ImpersonatorId;
            END
        END
    END
END



GO

