   Procedure: [dbo].[Usp_tp_Insertlikedislikecount]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_tp_Insertlikedislikecount]
    @Activity NVARCHAR(50), 
    @ArticleId BIGINT         
AS
BEGIN
    SET NOCOUNT ON;

    IF @Activity = 'like'
    BEGIN
        UPDATE tbl_tp_ArticleMaster
        SET LikeCount = ISNULL(LikeCount, 0) + 1
        WHERE Article_Id = @ArticleId;
    END
    ELSE IF @Activity = 'dislike'
    BEGIN
        UPDATE tbl_tp_ArticleMaster
        SET DislikeCount = ISNULL(DislikeCount, 0) + 1
        WHERE Article_Id = @ArticleId;
    END
END;




