CREATE   PROCEDURE [dbo].[Usp_tp_InsertManageTicketMaster]  
(    
 @ParentID bigint = NULL,    
 @TpUserId BIGINT = NULL ,    
 @TicketID bigint = NULL,    
 @ParentTicketID bigint = NULL,    
 @EntitytID bigint = NULL,    
 @EntityName nvarchar(50) = NULL,    
 @MobileNumber bigint = NULL,
 @CountryCode bigint = NULL,   
 @EmailID nvarchar(MAX) = NULL,    
 @MobileNumber1 bigint = NULL,
 @CountryCode1 bigint = NULL,    
 @EmailID1 nvarchar(MAX) = NULL,    
 @MobileNumber2 bigint = NULL,  
 @CountryCode2 bigint = NULL,
 @EmailID2 nvarchar(MAX) = NULL,    
 @TcktPriority bigint = NULL,    
 @TcktStatus bigint = NULL,    
 @TcktSource bigint = NULL,    
 @TcktCategory bigint = NULL,    
 @TcktType bigint = NULL,    
 @TcktTag nvarchar(MAX) = NULL,    
 @TcktSubject nvarchar(MAX) = NULL,    
 @TcktDescription nvarchar(MAX) = NULL,    
 @CreatedBy BIGINT = NULL,    
 --@FileName nvarchar(MAX) = NULL,    
 --@FilePath nvarchar(MAX) = NULL,    
 @Attachement nvarchar(MAX) = NULL,  
 @Option nvarchar(50) = NULL ,    
 @Product nvarchar(max) = NULL,    
 @Company nvarchar(500) = NULL,    
 @AssignedGroup bigint = NULL,    
 @AssignedUser bigint = NULL,    
 @SelectedTicket nvarchar(10) = NULL ,    
 @CustomFieldValueJson NVARCHAR(max) ,    
 @MetaData nvarchar(MAX) = NULL    
)    
AS    
Begin    
SET NOCOUNT ON;    
    
--declare @ParentID bigint = 32222,    
-- @TpUserId BIGINT = 1 ,    
-- @TicketID bigint = 30346,    
-- @ParentTicketID bigint = 0,    
-- @EntitytID bigint = 34128,    
-- @EntityName nvarchar(50) = N'User',    
-- @MobileNumber bigint = 0,    
-- @EmailID nvarchar(MAX) = N'',    
-- @MobileNumber1 bigint = 0,    
-- @EmailID1 nvarchar(MAX) = N'',    
-- @MobileNumber2 bigint = 0,    
-- @EmailID2 nvarchar(MAX) = N'',    
-- @TcktPriority bigint = 4,    
-- @TcktStatus bigint = 1,    
-- @TcktSource bigint = 3,    
-- @TcktCategory bigint = 103,    
-- @TcktType bigint = 12,    
-- @TcktTag nvarchar(MAX) = N'0,',    
-- @TcktSubject nvarchar(MAX) = N'sdsdnsd nsd alert test without  number',    
-- @TcktDescription nvarchar(MAX) = N'sdsdssdsdasasnn',    
-- @CreatedBy BIGINT = 1,    
-- @FileName nvarchar(MAX) = NULL,    
-- @FilePath nvarchar(MAX) = NULL,  
-- @Attachement  nvarchar(MAX)='{}',
-- @CountryCode bigint=null,
-- @CountryCode1 bigint=null,
-- @CountryCode2 bigint=null,
-- @Option nvarchar(50) = N'Update' ,    
-- @Product nvarchar(max) = N'',    
-- @Company nvarchar(500) = N'',    
-- @AssignedGroup bigint = 0,    
-- @AssignedUser bigint = 88,    
-- @SelectedTicket nvarchar(10) = N'' ,    
-- @CustomFieldValueJson NVARCHAR(max)=N'{}',    
-- @MetaData nvarchar(MAX) = N'{"IPAddress":"::1","MacAddress":"00FFB0003F75","IsImpersonation":false,"ImpersonatorId":0}'    
    
 DECLARE @InsertedId BIGINT= 0, @UserId BIGINT, @rowJson NVARCHAR(MAX), @IPAdress NVARCHAR(50),   
  @DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT, @sqls NVARCHAR(MAX)= '',   
  @status INT, @TicketMasterTable NVARCHAR(MAX), @customfieldlist NVARCHAR(MAX),   
  @customfieldvalue NVARCHAR(MAX)= '', @DynamicQuery NVARCHAR(MAX), @Type VARCHAR(50);    
 DECLARE @ActivityId BIGINT, @EventDesc NVARCHAR(MAX),@Actitivitydesc NVARCHAR(MAX),   
  @UserCreated NVARCHAR(100), @TicketNo NVARCHAR(50), @CreatedOn DATE,@CustomFieldInsertSQL NVARCHAR(MAX) ,@CustomFieldName NVARCHAR(MAX),@EventName NVARCHAR(MAX),
  @CustomFieldsValue NVARCHAR(MAX),  @ActivityDatetime datetime=GetDate(), @TicketActivityTable nvarchar(max)    
    
 Select @UserId = User_ID, @ParentID = @ParentId, @UserCreated = isnull(Name,LoginName)     
 From tbl_tp_UserLogin(noLock) Where TpUser_Id = @TpUserId AND IsActive = 1    
    
 SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)    
 SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)    
 SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)    
 SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)    
    
 DECLARE @Keys NVARCHAR(MAX) = '';    
 DECLARE @Values NVARCHAR(MAX) = '';    
    
 DECLARE @ColumnName NVARCHAR(100) = 'TicketNo';    
 DECLARE @ColumnName1 NVARCHAR(100) = 'CreatedOn';    
 DECLARE @DynamicSQL NVARCHAR(MAX);    
    
 SELECT  @Keys = @Keys + CASE WHEN @Keys = '' THEN '' ELSE ',' END + QUOTENAME([key]),    
   @Values = @Values + CASE WHEN @Values = '' THEN '' ELSE ',' END +    
   CASE WHEN ISJSON([value]) = 1 THEN QUOTENAME([value], '"')    
     WHEN ISNUMERIC([value]) = 1 THEN [value]    
     WHEN LOWER([value]) = 'true' THEN '1'    
     WHEN LOWER([value]) = 'false' THEN '0'    
     ELSE '''' + [value] + ''''    
   END    
 FROM OPENJSON(@CustomFieldValueJson);    
    
 SET @Values = REPLACE(@Values, '"NULL"', 'NULL');    
    
 EXEC @status = Usp_tp_CreateTicketMasterTableByParentID @ParentID, @TicketMasterTable OUTPUT    
 Exec [Usp_tp_CreateTicketActivityTableByParentID] @ParentID, @TicketActivityTable out    
    
 IF @Option = 'Insert'    
 BEGIN    
  DECLARE @DynamicInsertQuery NVARCHAR(MAX);    
    
  SET @DynamicQuery =    
  N'INSERT INTO ' + QUOTENAME(@TicketMasterTable) + N' (    
  tpUser_Id, ParentId, TicketNo, RequesterMobileNo,CountryCode, RequesterEmailID,    
  RequesterMobileNo1,CountryCode1, RequesterEmailID1, RequesterMobileNo2,CountryCode2, RequesterEmailID2,    
  Subject, Description, TicketStatusID, Remarks, Note, UserResponse,    
  TicketPriority, AssignedUser, AssignedGroup, AssignedSource, TicketCategoryId,    
  TicketTypeId, TicketSourceId, ProductId, IsMerged, IsSplitted,    
  IsParentTicket, IsChildTicket, ParentTicketID, LastActionDatetime, AssignedBy,    
  AssignedDateTime, TicketTag, EntityID, EntityName, Company, IsActive, CreatedBy,    
  CreatedOn, ModifiedBy, ModifiedOn, SplittedBy, SplittedOn, MergedBy, MergedOn,    
  ClosedBy, ClosedOn, CreatedChildBy, CreatedChildOn ' +    
  CASE WHEN @Keys <> '' THEN ', ' + @Keys ELSE '' END +    
  N') VALUES (    
  ' + CAST(@TpUserId AS NVARCHAR(MAX)) + ', ' +    
  CAST(ISNULL(@ParentID, 0) AS NVARCHAR(MAX)) + ', ' +    
  '''000 - TICKET'', ' +    
  '''' + REPLACE(ISNULL(@MobileNumber, ''), '''', '''''') + ''', ' +    
    '''' + REPLACE(ISNULL(@CountryCode, ''), '''', '''''') + ''', ' +  
  '''' + REPLACE(ISNULL(@EmailID, ''), '''', '''''') + ''', ' +    
  '''' + REPLACE(ISNULL(@MobileNumber1, ''), '''', '''''') + ''', ' +    
    '''' + REPLACE(ISNULL(@CountryCode1, ''), '''', '''''') + ''', ' +  
  '''' + REPLACE(ISNULL(@EmailID1, ''), '''', '''''') + ''', ' +    
  '''' + REPLACE(ISNULL(@MobileNumber2, ''), '''', '''''') + ''', ' +   
    '''' + REPLACE(ISNULL(@CountryCode2, ''), '''', '''''') + ''', ' +  
  '''' + REPLACE(ISNULL(@EmailID2, ''), '''', '''''') + ''', ' +    
  '''' + REPLACE(ISNULL(@TcktSubject, ''), '''', '''''') + ''', ' +    
  'N''' + REPLACE(ISNULL(@TcktDescription, N''), N'''', N'''''') + N''', ' +
CAST(ISNULL(@TcktStatus, 0) AS NVARCHAR(MAX)) + ', ' +    
  'NULL, ''Ticket Created'', NULL, ' + -- Remarks, Note, UserResponse    
  CAST(ISNULL(@TcktPriority, 'Medium') AS NVARCHAR(MAX)) + ', ' + -- TicketPriority    
  CAST(ISNULL(@AssignedUser, 0) AS NVARCHAR(MAX)) + ', ' +    
  CAST(ISNULL(@AssignedGroup, 0) AS NVARCHAR(MAX)) + ', ' +    
  '''Manual'', ' +    
  CAST(ISNULL(@TcktCategory, 0) AS NVARCHAR(MAX)) + ', ' +    
  CAST(ISNULL(@TcktType, 0) AS NVARCHAR(MAX)) + ', ' +    
  CAST(ISNULL(@TcktSource, 0) AS NVARCHAR(MAX)) + ', ' +    
  'NULL, 0, 0, 0, 0, ' + -- IsMerged, IsSplitted, IsParentTicket, IsChildTicket    
  CAST(ISNULL(@ParentTicketID, 0) AS NVARCHAR(MAX)) + ', GETDATE(), ' +    
  'NULL, GETDATE(), ' + -- ParentTicketID, LastActionDatetime, AssignedBy, AssignedDateTime    
  'NULL' + ', ' + -- TicketTag (replace 'NULL' with an appropriate value)    
  CAST(ISNULL(@EntitytID, 0) AS NVARCHAR(MAX)) + ', ' + -- EntityID    
  '''' + ISNULL(@EntityName, '') + ''', ''' + REPLACE(ISNULL(@Company, ''), '''', '''''') + ''', 1, ' + -- EntityName, Company, IsActive    
