      END    
       
  CREATE TABLE #TagsData1 (    
  TagData NVARCHAR(MAX)    
  );    
    
  INSERT INTO #TagsData1 (TagData)    
  SELECT value FROM STRING_SPLIT(@TcktTag, ',');    
    
  CREATE TABLE #SplitValues1 (    
  OriginalData NVARCHAR(MAX),    
  TagIDs NVARCHAR(MAX),    
  Tags NVARCHAR(MAX)    
  );    
      
  INSERT INTO #SplitValues1 (OriginalData, TagIDs, Tags)    
  SELECT TagData AS OriginalData,    
  CASE WHEN ISNUMERIC(extracted_integers) = 1 THEN extracted_integers END AS TagIDs,    
  extracted_strings AS Tags    
  FROM     
  (    
   SELECT TagData,    
   STRING_AGG(CASE WHEN ISNUMERIC(val) = 1 THEN val ELSE NULL END, ',') AS extracted_integers,    
   STRING_AGG(CASE WHEN ISNUMERIC(val) = 0 THEN val ELSE NULL END, ',') AS extracted_strings    
   FROM     
   (    
    SELECT TagData, value AS val    
    FROM #TagsData1    
    CROSS APPLY STRING_SPLIT(TagData, ',')    
   ) AS split_values    
   GROUP BY TagData    
  ) AS aggregated_data;    
    
  DECLARE @InsertedTagMapping1 TABLE (TagID INT, EntityID INT);    
    
  DECLARE @TagMasterID1 INT;    
    
  IF EXISTS (SELECT Tags FROM #SplitValues1 WHERE Tags IS NOT NULL)    
  BEGIN    
   DECLARE @Tag1 NVARCHAR(MAX);    
    
   DECLARE cur CURSOR FOR    
   SELECT TRIM(value) AS Tag    
   FROM #SplitValues1    
   CROSS APPLY STRING_SPLIT(Tags, ',')    
   WHERE Tags IS NOT NULL;    
    
   OPEN cur;    
   FETCH NEXT FROM cur INTO @Tag1;    
    
   WHILE @@FETCH_STATUS = 0    
   BEGIN    
    INSERT INTO TagMaster (Tag, ParentID, CreatedDate, CreatedBy, IsActive)    
    VALUES (@Tag1, @ParentID, GETDATE(), @UserId, 1);    
    
    DECLARE @GeneratedTagID1 INT;    
    SET @GeneratedTagID1 = SCOPE_IDENTITY();    
    
    DELETE FROM EntityTagMapping WHERE EntityID = @TicketID AND Entity = 'TICKET'    
    
    INSERT INTO EntityTagMapping (TagID, EntityID, Entity, CreatedDate, ParentId)    
    VALUES (@GeneratedTagID1, @TicketID, 'Ticket', GETDATE(), @ParentId);    
    
    FETCH NEXT FROM cur INTO @Tag1;    
   END;    
    
   CLOSE cur;    
   DEALLOCATE cur;    
  END;    
    
  IF EXISTS (SELECT TagIDs FROM #SplitValues1 WHERE TagIDs IS NOT NULL)    
  BEGIN    
   DELETE FROM EntityTagMapping WHERE EntityID = @TicketID AND Entity = 'TICKET' AND TagID IN (SELECT TagIDs FROM #SplitValues1)and ParentId=@ParentId    
    
   INSERT INTO EntityTagMapping (EntityID, Entity, TagID, CreatedDate, ParentId)    
   SELECT @TicketID, 'Ticket', TagIDs, GETDATE(), @ParentId FROM #SplitValues1    
  END;    
    
  DROP TABLE #TagsData1;    
  DROP TABLE #SplitValues1;    
    
  DECLARE @DynamicTagUpdateQuery NVARCHAR(MAX);    
    
  SET @DynamicTagUpdateQuery =    
  N'UPDATE ' + QUOTENAME(@TicketMasterTable) + ' SET ' +    
  'TicketTag = (SELECT STRING_AGG(CONVERT(NVARCHAR(MAX), TagID), '', '') AS CommaSeparatedEntityIDs ' +    
  'FROM EntityTagMapping WHERE EntityID = ' + CAST(@TicketID AS NVARCHAR(MAX)) + ' AND Entity = ''Ticket'') ' +    
  'WHERE TicketID = ' + CAST(@TicketID AS NVARCHAR(MAX));    
    
  PRINT @DynamicTagUpdateQuery;    
  EXEC sp_executesql @DynamicTagUpdateQuery;    
    
    
  DECLARE @TicketHistoryId1 BIGINT    
    
  -- to be commented    
  --INSERT INTO tbl_tp_TicketHistory (TicketID,TicketStatusID,ParentID,ActionDateTime,Remarks,Note,UserResponse,AssignedUser,AssignedGroup,TicketPriority,AssignedSource,AssignedBy,ActionContent)    
  --VALUES (@TicketID,@TcktStatus,@ParentID,Getdate(),NULL,'Ticket Edited',NULL,@AssignedUser,@AssignedGroup,@TcktPriority,'Manual',@TpUserId,'Activity')    
    
  --Update tbl_tp_TicketHistory Set TicketPriority=@TcktPriority, @TicketHistoryId1=TicketHistoryID Where TicketHistoryID in (Select max(TH.TicketHistoryID) From tbl_tp_TicketHistory(nolock) TH Where TH.TicketID=@TicketID and TH.ParentID=@ParentID)    
    
  SET @TicketHistoryId1 = SCOPE_IDENTITY();    
    
  --IF (@FileName IS NOT NULL)    
  --BEGIN    
  -- If not exists(Select * from tbl_tp_TicketAttachment(nolock) Where TicketID=@TicketID and ParentID=@ParentID and DisplayName=@FileName)    
  -- Begin    
  --  INSERT INTO tbl_tp_TicketAttachment(TicketID,TicketHistoryID,DisplayName,FileUrl,IsActive,CreatedBy,CreatedOn,ParentID)    
  --  VALUES (@TicketID,@TicketHistoryId1,@FileName,@FilePath,1,@TpUserId,GETDATE(),@ParentID)    
  -- End    
  -- Else    
  -- Begin    
  --  Delete from tbl_tp_TicketAttachment Where TicketID=@TicketID and ParentID=@ParentID and DisplayName=@FileName    
    
  --  INSERT INTO tbl_tp_TicketAttachment(TicketID,TicketHistoryID,DisplayName,FileUrl,IsActive,CreatedBy,CreatedOn,ParentID)    
  --  VALUES (@TicketID,@TicketHistoryId1,@FileName,@FilePath,1,@TpUserId,GETDATE(),@ParentID)    
  -- End    
  --END    
IF (@Attachement IS NOT NULL)
BEGIN
    DECLARE @jsonTableUpdate TABLE (
        FileName NVARCHAR(MAX),
        FilePath NVARCHAR(MAX)
    );

    -- Insert JSON data into the table variable
    INSERT INTO @jsonTableUpdate (FileName, FilePath)
    SELECT FileName, FilePath
    FROM OPENJSON(@Attachement)
    WITH (
        FileName NVARCHAR(MAX) '$.FileName',
        FilePath NVARCHAR(MAX) '$.FilePath'
    );

    -- Delete existing records that match the criteria
    DELETE FROM tbl_tp_TicketAttachment
    WHERE TicketID = @TicketID
      AND ParentID = @ParentID


    -- Insert new records
    INSERT INTO tbl_tp_TicketAttachment (TicketID, TicketHistoryID, DisplayName, FileUrl, IsActive, CreatedBy, CreatedOn, ParentID)
    SELECT @TicketID, @TicketHistoryId1, FileName, FilePath, 1, @TpUserId, GETDATE(), @ParentID
    FROM @jsonTableUpdate;
END;
IF (@CustomFieldValueJson IS NOT NULL)
BEGIN
DECLARE @json NVARCHAR(MAX) = @CustomFieldValueJson;
DECLARE @tempTable TABLE (
    FieldName NVARCHAR(MAX),
    FieldValue NVARCHAR(MAX)
);

INSERT INTO @tempTable (FieldName, FieldValue)
SELECT [Key], [Value]
FROM OPENJSON(@json);
DECLARE json_cursor CURSOR FOR
SELECT FieldName, FieldValue FROM @tempTable;
OPEN json_cursor;
FETCH NEXT FROM json_cursor INTO @CustomFieldName, @CustomFieldsValue;

WHILE @@FETCH_STATUS = 0
BEGIN
    -- Check if the field name exists in your master table and then insert/update the value
    IF EXISTS (SELECT 1 FROM sys.columns WHERE object_id = OBJECT_ID(@TicketMasterTable) AND name = @CustomFieldName)
    BEGIN
        -- Build dynamic SQL to update each field separately
        DECLARE @UpdateSQL NVARCHAR(MAX);
        SET @UpdateSQL = '
        UPDATE ' + QUOTENAME(@TicketMasterTable) + '
        SET ' + QUOTENAME(@CustomFieldName) + ' = @CustomFieldValue
        WHERE TicketID = @TicketID;';

        -- Execute the built dynamic SQL
        EXEC sp_executesql @UpdateSQL, N'@CustomFieldValue NVARCHAR(MAX), @TicketID BIGINT', @CustomFieldsValue, @TicketID;
    END;

    FETCH NEXT FROM json_cursor INTO @CustomFieldName, @CustomFieldsValue;
END;

CLOSE json_cursor;
DEALLOCATE json_cursor;
END;

  IF @TicketHistoryId1 > 0    
  SELECT 'Ticket Updated Successfully';    
  
  DECLARE @DynamicRowJsonQuery1 NVARCHAR(MAX);    
    
  SET @DynamicRowJsonQuery = N'    
  SELECT @json_Result = (    
  SELECT *    
  FROM ' + QUOTENAME(@TicketMasterTable) + '    
  WHERE TicketID = @DynamicInsertedId    
  FOR JSON AUTO, INCLUDE_NULL_VALUES    
  )';    
    
  DECLARE @jsonResult1 NVARCHAR(MAX);    
    
  EXEC sp_executesql @DynamicRowJsonQuery1, N'@DynamicInsertedId BIGINT, @json_Result NVARCHAR(MAX) OUTPUT', @DynamicInsertedId=@TicketID, @json_Result=@jsonResult1 OUTPUT;    
  SET @rowJson = @jsonResult1;    
    
  IF @rowJson IS NOT NULL    
  BEGIN    
   EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData    
   @User_id = @UserId,    
   @Activity_type = 'Updt_manageticketmaster',    
   @ActionType = 'U',    
   @RowJson = @rowJson,    
   @Table_name = @TicketMasterTable,    
   @ip_adress = @IPAdress,    
   @device_id = @DeviceId,    
   @IsImpersonation = @IsImpersonation,    
   @ImpersonatorId = @ImpersonatorId;    
  END    
    
  SET @DynamicSQL = 'SELECT ' + QUOTENAME(@ColumnName) + ', ' + QUOTENAME(@ColumnName1) + ' FROM ' + QUOTENAME(@TicketMasterTable) +    
  ' WHERE TicketID = ' + CAST(@TicketID AS NVARCHAR(MAX))    
  DECLARE @Result1 TABLE (TicketNo NVARCHAR(50), CreatedOn DATE);    
  declare @i int=1, @rowcnt int=0, @FieldName varchar(100), @OldValue nvarchar(max), @NewValue nvarchar(max)    
    
  INSERT INTO @Result1    
  EXEC sp_executesql @DynamicSQL;    
    
  SELECT @TicketNo = TicketNo, @CreatedOn = CreatedOn FROM @Result1;    
      
  select *     
  into #tblFields    
  from dbo.fn_split('TicketNo,RequesterMobileNo,CountryCode,RequesterEmailID,RequesterMobileNo1,CountryCode1,RequesterEmailID1,RequesterMobileNo2,CountryCode2,RequesterEmailID2,Subject,Description,TicketStatusID,Remarks,Note,UserResponse,TicketPriority,AssignedUser,AssignedGroup,TicketCategoryId,TicketTypeId,TicketSourceId,TicketTag,EntityID,EntityName,Company',',')    
    
  Select @rowcnt=count(*) From #tblFields    
    
  While(@i <= @rowcnt)    
  Begin    
   Select @FieldName=value From #tblFields Where position=@i    
   print concat('@FieldName: ',@FieldName)    
    
   set @DynamicSQL=concat(N'select @OldValue1=A.',@FieldName,N',@NewValue1=B.',@FieldName,N'    
   From #tblTicketBeforeEdit A inner join #tblTicketAfterEdit B    
   On A.TicketID=B.TicketID')    
   print concat('update @DynamicSQL: ', @DynamicSQL)    
    
   EXEC sp_executesql @DynamicSQL,N'@OldValue1 nvarchar(max) output,@NewValue1 nvarchar(max) output',@OldValue1=@OldValue output,@NewValue1=@NewValue output    
    
   print concat('@OldValue: ', @OldValue)    
   print concat('@NewValue: ', @NewValue)    
    
   If(isnull(@OldValue,'') != isnull(@NewValue,''))    
   Begin      
    SELECT @EventDesc = @UserCreated + ' updated ticket ' + @TicketNo + ' for field ' + @FieldName + ' From ' + @OldValue + ' to ' + @NewValue    
      SELECT @Actitivitydesc =  'Ticket Edited '  
    print concat('@EventDesc: ',@EventDesc)    
    print '------ Exec usp_tp_AddActivity BEGIN -------'    
    Exec usp_tp_AddActivity @TicketId=@TicketID, @ParentId=@ParentID, @FieldName=@FieldName, @OldValue=@OldValue, @NewValue=@NewValue, @ActivityDescription = @Actitivitydesc ,@ActivityBy=@TpUserId, @ActivityDatetime=@ActivityDatetime, @ActivityId=@ActivityId out, @EventId=null, @EventName='Leads ticket updated', @EntityType=null, @EntityId=null    
    print '------ Exec usp_tp_AddActivity END -------' 
	 --SELECT @EventName = @EntityName + 's ticket updated';
	  SELECT @EventName = @EntityName + 's ticket updated';
	 print @EventName
    exec UspSaveEntityActivity_withid @entityname = @EntityName, @EntityID = @EntitytID, @UserID= @UserId, @ParentID = @ParentId, @EventDescription = @EventDesc, @EventName = @EventName, @reftables = @TicketActivityTable, @refid=@ActivityId   
 
           
    --exec UspSaveEntityActivity_withid @entityname = @EntityName, @EntityID = @EntitytID, @UserID= @UserId, @ParentID = @ParentId, @EventDescription = @EventDesc, @EventName = 'Leads ticket updated', @reftables = 'tbl_tp_TicketHistory', @refid= @TicketHistoryId1    
    
    --EXEC Usp_tp_SaveEntityActivity_withid @entityname = @EntityName, @EntityID = @EntitytID, @UserID = @UserId, @ParentID = @ParentId, @EventDescription = @EventDesc, @EventName = 'Agent Updates Ticket', @reftables = @TicketMasterTable, @refid = @TicketID, @refColName = 'TicketID' ,@Groupid = @AssignedGroup,@AgentId = @AssignedUser ,@Type = 'Agent'    
   End    
    
   Set @i+=1    
  End    
    
  -- exec usp_tp_ApplyScenarioUpdate @TicketID, @ParentID    
  insert into tbl_tp_ScenarioApplyHistory(TicketId,ParentID,ScenarioID,ActivityID,Mode,IsApplied,ApplyDate,IsActive,CreatedBy,CreatedDate)  
  values(@TicketID,@ParentID,null,@ActivityId,'Manual',0,null,1,@TpUserId,GETDATE())  
  
 END    
    
END









