SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec Usp_tp_InsertManageTicketMaster$  @ParentID=32222,@TpUserId=1,@TicketID=0,@ParentTicketID=0,@EntitytID=486149,@EntityName=N'Lead',@MobileNumber=7048860782,@MobileNumber1=0,@MobileNumber2=0,@EmailID=N'hiteshgohil4878@gmail.com',@EmailID1=N'',@EmailID2=N'',@TcktPriority=2,@TcktStatus=1,@TcktSource=0,@TcktCategory=101,@TcktType=1,@TcktTag=N'36',@TcktSubject=N'rgfgfhffgj',@TcktDescription=N'fgfdgfgfghgffg',@CreatedBy=32222,@FileName=default,@FilePath=default,@Option=N'Insert',@Product=N'14',@Company=N'thtrtutu',@AssignedGroup=0,@AssignedUser=0,@SelectedTicket=N'New',@CustomFieldValueJson=N'{"test":"final test","testtest3":"100","sdfsdgfd":48}',@MetaData=N'{"IPAddress":"::1","MacAddress":"00FFEBA13AD5","IsImpersonation":false,"ImpersonatorId":0}'  
CREATE   PROCEDURE [dbo].[Usp_tp_InsertManageTicketMaster$]
  @ParentID bigint = NULL,                        
  @TpUserId BIGINT = NULL ,                        
  @TicketID bigint = NULL,                                       
  @ParentTicketID bigint = NULL,                                     
  @EntitytID bigint = NULL,                                    
  @EntityName nvarchar(50) = NULL,                                    
  @MobileNumber bigint = NULL,                                    
  @EmailID nvarchar(MAX) = NULL,                                      
  @MobileNumber1 bigint = NULL,                                    
  @EmailID1 nvarchar(MAX) = NULL,                                     
  @MobileNumber2 bigint = NULL,                                    
  @EmailID2 nvarchar(MAX) = NULL,                                     
  @TcktPriority bigint = NULL,                                                  
  @TcktStatus bigint = NULL,                                                 
  @TcktSource bigint = NULL,                                                        
  @TcktCategory bigint = NULL,                                                
  @TcktType bigint = NULL,                                                  
  @TcktTag nvarchar(MAX) = NULL,                                                  
  @TcktSubject nvarchar(MAX) =  NULL,                                                   
  @TcktDescription nvarchar(MAX) = NULL,                                                  
  @CreatedBy BIGINT =  NULL,                                                
  @FileName nvarchar(MAX) = NULL,                                                  
  @FilePath nvarchar(MAX) = NULL,                                                
  @Option nvarchar(50) = NULL ,                                          
  @Product nvarchar(max) = NULL,                                        
  @Company nvarchar(500) = NULL,                                        
  @AssignedGroup bigint = NULL,                                        
  @AssignedUser bigint = NULL,                            
  @SelectedTicket nvarchar(10) =  NULL ,                         
  @CustomFieldValueJson NVARCHAR(max) ,                      
  @MetaData nvarchar(MAX) =  NULL                                                         
                                                                      
                                                             
AS                                                                      
Begin                                                                      
   SET NOCOUNT ON;                                             
                                               
                                                            
    DECLARE @InsertedId BIGINT = 0,@UserId BIGINT, @rowJson NVARCHAR(MAX) , @IPAdress NVARCHAR(50),@DeviceId NVARCHAR(50),  
 @IsImpersonation BIT ,@ImpersonatorId INT ,@sqls NVARCHAR(max) = '' ,@status INT,@TicketMasterTable NVARCHAR(max),  
 @customfieldlist nvarchar(max),@customfieldvalue nvarchar(max)= '' , @DynamicQuery NVARCHAR(MAX),@Type VARCHAR(50)          
                      
    Select @UserId = User_ID , @ParentID = @ParentId  From tbl_tp_UserLogin (noLock) Where TpUser_Id =  @TpUserId AND IsActive = 1                  
                                                           
    SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)                     
    SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)                    
    SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)                    
    SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)                     
                                           
 DECLARE @Keys NVARCHAR(MAX) = '';  
 DECLARE @Values NVARCHAR(MAX) = '';  
     
  DECLARE @ActivityId BIGINT, @EventDesc NVARCHAR(MAX), @UserCreated NVARCHAR(100), @TicketNo NVARCHAR(50), @CreatedOn DATE    
    
  SELECT @UserCreated = Name FROM tbl_tp_UserLogin WHERE TpUser_Id = @TpUserId AND IsActive = 1    
  DECLARE @ColumnName NVARCHAR(100) = 'TicketNo';    
  DECLARE @ColumnName1 NVARCHAR(100) = 'CreatedOn';    
  DECLARE @DynamicSQL NVARCHAR(MAX);    
                      
 SELECT                       
  @Keys = @Keys + CASE WHEN @Keys = '' THEN '' ELSE ',' END + QUOTENAME([key]),                      
  @Values = @Values + CASE WHEN @Values = '' THEN '' ELSE ',' END +                       
   CASE          WHEN ISJSON([value]) = 1 THEN QUOTENAME([value], '"')                      
    WHEN ISNUMERIC([value]) = 1 THEN [value]                 
    WHEN LOWER([value]) = 'true' THEN '1'                      
    WHEN LOWER([value]) = 'false' THEN '0'                      
    ELSE '''' + [value] + ''''                      
   END                      
 FROM OPENJSON(@CustomFieldValueJson);             
                      
 SET @Values = REPLACE(@Values, '"NULL"', 'NULL');                      
                                
 BEGIN                                                     
                                            
  EXEC @status = Usp_tp_CreateTicketMasterTableByParentID @ParentID                                                  
   ,@TicketMasterTable OUTPUT                       
                      
                      
  IF @Option = 'Insert'                                                              
  BEGIN                                           
                                       
   DECLARE @DynamicInsertQuery NVARCHAR(MAX);                                      
                                                           
 SET @DynamicQuery =                                             
  N'INSERT INTO ' + QUOTENAME(@TicketMasterTable) + N' (                      
   tpUser_Id, ParentId, TicketNo, RequesterMobileNo, RequesterEmailID,                       
   RequesterMobileNo1, RequesterEmailID1, RequesterMobileNo2, RequesterEmailID2,                                      
   Subject, Description, TicketStatusID, Remarks, Note, UserResponse,                                      
   TicketPriority, AssignedUser, AssignedGroup, AssignedSource, TicketCategoryId,                                      
   TicketTypeId, TicketSourceId, ProductId, IsMerged, IsSplitted,                                      
   IsParentTicket, IsChildTicket, ParentTicketID, LastActionDatetime, AssignedBy,                                      
   AssignedDateTime, TicketTag, EntityID, EntityName, Company, IsActive, CreatedBy,                       
   CreatedOn, ModifiedBy, ModifiedOn, SplittedBy, SplittedOn, MergedBy, MergedOn,                       
   ClosedBy, ClosedOn, CreatedChildBy, CreatedChildOn ' +                       
   CASE WHEN @Keys <> '' THEN ', ' + @Keys ELSE '' END +                      
  N') VALUES (                                      
   ' + CAST(@TpUserId AS NVARCHAR(MAX)) + ', ' +                      
   CAST(ISNULL(@ParentID, 0) AS NVARCHAR(MAX)) + ', ' +                
   '''000 - TICKET'', ' +                      
   '''' + REPLACE(ISNULL(@MobileNumber, ''), '''', '''''') + ''', ' +                      
   '''' + REPLACE(ISNULL(@EmailID, ''), '''', '''''') + ''', ' +                      
   '''' + REPLACE(ISNULL(@MobileNumber1, ''), '''', '''''') + ''', ' +                      
   '''' + REPLACE(ISNULL(@EmailID1, ''), '''', '''''') + ''', ' +                      
   '''' + REPLACE(ISNULL(@MobileNumber2, ''), '''', '''''') + ''', ' +                      
   '''' + REPLACE(ISNULL(@EmailID2, ''), '''', '''''') + ''', ' +                      
   '''' + REPLACE(ISNULL(@TcktSubject, ''), '''', '''''') + ''', ' +                      
   '''' + REPLACE(ISNULL(@TcktDescription, ''), '''', '''''') + ''', ' +                      
   CAST(ISNULL(@TcktStatus, 0) AS NVARCHAR(MAX)) + ', ' +                      
   'NULL, NULL, NULL, ' + -- Remarks, Note, UserResponse                      
   CAST(ISNULL(@TcktPriority, 0) AS NVARCHAR(MAX)) + ', ' + -- TicketPriority                      
   CAST(ISNULL(@AssignedUser, 0) AS NVARCHAR(MAX)) + ', ' +                      
   CAST(ISNULL(@AssignedGroup, 0) AS NVARCHAR(MAX)) + ', ' +                      
   '''Manual'', ' +              
   CAST(ISNULL(@TcktCategory, 0) AS NVARCHAR(MAX)) + ', ' +                      
   CAST(ISNULL(@TcktType, 0) AS NVARCHAR(MAX)) + ', ' +                      
   CAST(ISNULL(@TcktSource, 0) AS NVARCHAR(MAX)) + ', ' +                      
   'NULL, 0, 0, 0, 0, ' + -- IsMerged, IsSplitted, IsParentTicket, IsChildTicket                      
   CAST(ISNULL(@ParentTicketID, 0) AS NVARCHAR(MAX)) + ', GETDATE(), ' +                      
   'NULL, GETDATE(), ' + -- ParentTicketID, LastActionDatetime, AssignedBy, AssignedDateTime                      
   'NULL' + ', ' + -- TicketTag (replace 'NULL' with an appropriate value)                      
   CAST(ISNULL(@EntitytID, 0) AS NVARCHAR(MAX)) + ', ' + -- EntityID                      
   '''' + ISNULL(@EntityName, '') + ''', ''' + REPLACE(ISNULL(@Company, ''), '''', '''''') + ''', 1, ' + -- EntityName, Company, IsActive                    
   CAST(ISNULL(@TpUserId, 0) AS NVARCHAR(MAX)) + ', GETDATE(), NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL ';  -- Other field values                
                                 
IF @Values <> ''                    
BEGIN                    
    SET @DynamicQuery = @DynamicQuery + N', ' + @Values + N'); Set  @Ticket_Id=Scope_Identity()';                
END                    
ELSE                
BEGIN                
    SET @DynamicQuery = @DynamicQuery + N'); Set  @Ticket_Id=Scope_Identity()';                
END                  
                                                       
    Print @DynamicQuery                      
 EXEC sp_executesql @DynamicQuery, N'@Ticket_Id BIGINT OUTPUT', @Ticket_Id=@InsertedId OUTPUT;  
 
 print '@InsertedId: ' + cast(@InsertedId as varchar)

                                
 DECLARE @DynamicInsertedId BIGINT;                       
 DECLARE @MaxIdQuery NVARCHAR(MAX);                                
 --SET @MaxIdQuery = N'SELECT @DynamicInsertedId = MAX(TicketID) FROM ' + QUOTENAME(@TicketMasterTable);
 --EXEC sp_executesql @MaxIdQuery, N'@DynamicInsertedId BIGINT OUTPUT', @DynamicInsertedId OUTPUT;                      
                              
 Set @DynamicInsertedId=@InsertedId
                                
 DECLARE @UpdateQuery NVARCHAR(MAX);                                
 SET @UpdateQuery = N'                                
   UPDATE ' + QUOTENAME(@TicketMasterTable) + '                                
   SET TicketNo = ''000'' + CAST(@Ticket_ID AS NVARCHAR(20)) + '' - TICKET''                                
   WHERE TicketID = @Ticket_ID';                                
  EXEC sp_executesql @UpdateQuery, N'@Ticket_ID BIGINT', @Ticket_ID=@DynamicInsertedId;                                     
  DECLARE @UpdateQuery1 NVARCHAR(MAX);                          
  
                           
 IF (@SelectedTicket = 'Child' )                              
 BEGIN                              
  SET @UpdateQuery1 = N'                             
   UPDATE ' + QUOTENAME(@TicketMasterTable) + '                                      
   SET IsParentTicket =  1                                     
   WHERE ParentTicketID > 0 AND TicketID = @Ticket_ID';                                      
                                      
  EXEC sp_executesql @UpdateQuery1, N'@Ticket_ID BIGINT', @Ticket_ID=@DynamicInsertedId;
                           
  SET @UpdateQuery1 = N'                             
  UPDATE ' + QUOTENAME(@TicketMasterTable) + '                                      
  SET IsChildTicket =  1                                     
  WHERE  TicketID = @Ticket_ID';                                      
                                      
  EXEC sp_executesql @UpdateQuery1, N'@Ticket_ID BIGINT', @Ticket_ID=@DynamicInsertedId;                          
                                           
 END                              
                
 IF (@SelectedTicket = 'Merge' )                              
    BEGIN                              
  SET @UpdateQuery1 = N'                                    
   UPDATE ' + QUOTENAME(@TicketMasterTable) + '                                      
   SET IsMerged = CASE WHEN ParentTicketID > 0 THEN 1 ELSE 0 END                                    
   WHERE  TicketID = @Ticket_ID';                                      
                                      
  EXEC sp_executesql @UpdateQuery1, N'@Ticket_ID BIGINT', @Ticket_ID=@DynamicInsertedId;                           
                           
  SET @UpdateQuery1 = N'                                    
  UPDATE ' + QUOTENAME(@TicketMasterTable) + '                                      
  SET ParentTicketID = @ParentTicket_ID                                    
  WHERE  TicketID = @Ticket_ID';                                      
                                      
  EXEC sp_executesql @UpdateQuery1, N'@ParentTicket_ID BIGINT,@Ticket_ID BIGINT', @ParentTicket_ID=@ParentTicketID,@Ticket_ID=@DynamicInsertedId;                           
                  
 END                             
                      
 IF (@SelectedTicket = 'Split' )                    
 BEGIN                              
  SET @UpdateQuery1 = N'                                    
   UPDATE ' + QUOTENAME(@TicketMasterTable) + '                                      
   SET IsSplitted = 1                                    
   WHERE  TicketID = @Ticket_ID';                                      
                                      
  EXEC sp_executesql @UpdateQuery1, N'@Ticket_ID BIGINT', @Ticket_ID=@DynamicInsertedId;
                           
   SET @UpdateQuery1 = N'              
   UPDATE ' + QUOTENAME(@TicketMasterTable) + '                                      
   SET ParentTicketID = @ParentTicket_ID                                    
   WHERE  TicketID = @Ticket_ID';                                      
                                      
  EXEC sp_executesql @UpdateQuery1, N'@ParentTicket_ID BIGINT,@Ticket_ID BIGINT', @ParentTicket_ID=@ParentTicketID,@Ticket_ID=@DynamicInsertedId;                           
                                           
 END                
                          
                          
 CREATE TABLE #TagsData (                 
  TagData NVARCHAR(MAX)                                                
 );                                                
                                                
 INSERT INTO #TagsData (TagData)                                                
 SELECT value FROM STRING_SPLIT(@TcktTag, ',');                                                
                                                
 CREATE TABLE #SplitValues (                    
  OriginalData NVARCHAR(MAX),                                                
  TagIDs NVARCHAR(MAX),                                                
  Tags NVARCHAR(MAX)                                                
 );                                                
                                                
 INSERT INTO #SplitValues (OriginalData, TagIDs, Tags)                                                
 SELECT                       
  TagData AS OriginalData,                                                
  CASE WHEN ISNUMERIC(extracted_integers) = 1 THEN extracted_integers END AS TagIDs,                                               
  extracted_strings AS Tags                                          
 FROM (                                                
  SELECT TagData,                                                
      STRING_AGG(CASE WHEN ISNUMERIC(val) = 1 THEN val ELSE NULL END, ',') AS extracted_integers,                                                
      STRING_AGG(CASE WHEN ISNUMERIC(val) = 0 THEN val ELSE NULL END, ',') AS extracted_strings                                                
  FROM (                                                
   SELECT TagData, value AS val                                                
   FROM #TagsData                                                
   CROSS APPLY STRING_SPLIT(TagData, ',')                                           
  ) AS split_values                                                
  GROUP BY TagData                                                
 ) AS aggregated_data;                                                
                                                
 DECLARE @InsertedTagMapping TABLE (TagID INT, EntityID INT);                                                
                      
 DECLARE @TagMasterID INT;                                                
       IF EXISTS (SELECT Tags FROM #SplitValues WHERE Tags IS NOT NULL)                                                
 BEGIN                                                
                                                
 DECLARE @Tag NVARCHAR(MAX);                                                
                                                
 DECLARE cur CURSOR FOR                                                
 SELECT TRIM(value) AS Tag                                                
 FROM #SplitValues                                                
 CROSS APPLY STRING_SPLIT(Tags, ',')                                                
 WHERE Tags IS NOT NULL;                                                
                                                
 OPEN cur;                                                
 FETCH NEXT FROM cur INTO @Tag;                                                
                                                
 WHILE @@FETCH_STATUS = 0                                                
 BEGIN                                                
                                                
  INSERT INTO TagMaster (Tag, ParentID, CreatedDate, CreatedBy, IsActive)                                                
  VALUES (@Tag, @ParentID, GETDATE(), @UserId, 1);                                                
                                                
  DECLARE @GeneratedTagID INT;                                                
  SET @GeneratedTagID = SCOPE_IDENTITY();                                                
                                                
  INSERT INTO EntityTagMapping (TagID, EntityID, Entity, CreatedDate)                                                
  VALUES (@GeneratedTagID, @InsertedId, 'Ticket', GETDATE());                                                
                                                
  FETCH NEXT FROM cur INTO @Tag;                                                
 END;                                   
                                                
 CLOSE cur;                                                
 DEALLOCATE cur;                                                
                                                
                                 
 END;                                                
                                                
 IF EXISTS (SELECT TagIDs FROM #SplitValues WHERE TagIDs IS NOT NULL)                                                
 BEGIN                                                
  INSERT INTO EntityTagMapping (EntityID, Entity, TagID, CreatedDate)                                           
  SELECT @InsertedId, 'Ticket', TagIDs, GETDATE()                                                
  FROM #SplitValues                                                
                                              
 END;                                                
                                                                   
 DROP TABLE #TagsData;                                                
 DROP TABLE #SplitValues;                                                
                                                
 DECLARE @DynamicTicketTagUpdate NVARCHAR(MAX);                                            
 SET @DynamicTicketTagUpdate = N'                                      
  UPDATE ' + QUOTENAME(@TicketMasterTable) + N'                                            
  SET TicketTag = STUFF(                                      
   (SELECT '', '' + CONVERT(NVARCHAR(MAX), TagID)                                      
  FROM EntityTagMapping                                             
    WHERE EntityID = @Ticket_ID AND Entity = ''Ticket''                                      
    FOR XML PATH ('''')), 1, 2, '''')                           
  WHERE TicketID = @Ticket_ID;';                                      
                                      
 EXEC sp_executesql @DynamicTicketTagUpdate, N'@Ticket_ID BIGINT', @Ticket_ID=@DynamicInsertedId;
                                           
                                                                                  
    --Update  tbl_tp_TicketMaster SET TicketTag = (SELECT                                 
    --           STRING_AGG(CONVERT(NVARCHAR(MAX), TagID), ', ') AS CommaSeparatedEntityIDs FROM EntityTagMapping Where EntityID = @InsertedId AND Entity = 'Ticket')                                                
                                                
  DECLARE @TicketHistoryId BIGINT                                                
                                                    
  INSERT INTO tbl_tp_TicketHistory (TicketID,TicketStatusID,ParentID,ActionDateTime,Remarks,Note,UserResponse,AssignedUser,AssignedGroup,TicketPriority,AssignedSource,AssignedBy)                                                  
   VALUES (@DynamicInsertedId ,@TcktStatus,@ParentID,NULL,NULL,NULL,NULL,@AssignedUser,@AssignedGroup,@TcktPriority,@ParentID,@ParentID)                                                                                                                      
  
     
     
         
    SET @TicketHistoryId = SCOPE_IDENTITY();                                                
                                                
  IF (@FileName IS NOT NULL)                    
  BEGIN                                                
   INSERT INTO  tbl_tp_TicketAttachment(TicketID,TicketHistoryID,DisplayName,FileUrl,IsActive,CreatedBy,CreatedOn)                    
   VALUES (@DynamicInsertedId ,@TicketHistoryId,@FileName,@FilePath,1,@UserId,GETDATE())                    
  END                                                
                                        
  IF (@Product IS NOT NULL)                    
  BEGIN                                                
   INSERT INTO tbl_tp_TicketProducts (TicketID, ProductID, IsActive, CreatedBy, CreatedOn,ParentId)                                      
    SELECT @DynamicInsertedId , CONVERT(bigint, value), 1, @UserId, GETDATE(),@ParentId                    
    FROM STRING_SPLIT(@Product, ',')                                      
   WHERE ISNUMERIC(value) = 1;                                              
  END                                           
                    
 DECLARE @DynamicRowJsonQuery NVARCHAR(MAX);                              
                              
 SET @DynamicRowJsonQuery = N'                              
  SELECT @json_Result = (                              
   SELECT *                               
   FROM ' + QUOTENAME(@TicketMasterTable) + '                               
   WHERE TicketID = @Ticket_ID                               
FOR JSON AUTO, INCLUDE_NULL_VALUES                              
  )';                
                              
 DECLARE @jsonResult NVARCHAR(MAX);                              
                              
 EXEC sp_executesql @DynamicRowJsonQuery, N'@Ticket_ID BIGINT, @json_Result NVARCHAR(MAX) OUTPUT', @Ticket_ID=@DynamicInsertedId, @json_Result=@jsonResult OUTPUT;                                                        
 SET @rowJson = @jsonResult;                                          
                                                                                                  
 IF @rowJson IS NOT NULL                                                              
 BEGIN                                                              
  EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData                    
  @User_id = @UserId,                    
  @Activity_type = 'Inst_manageticketmaster',                    
  @ActionType = 'I',                    
  @RowJson = @rowJson,                    
  @Table_name = @TicketMasterTable,                    
  @ip_adress = @IPAdress,                    
  @device_id = @DeviceId,                    
  @IsImpersonation = @IsImpersonation,                    
  @ImpersonatorId = @ImpersonatorId;                    
 END          
                
SET @DynamicSQL = 'SELECT ' + QUOTENAME(@ColumnName) + ', ' + QUOTENAME(@ColumnName1) + ' FROM ' + QUOTENAME(@TicketMasterTable) +    
                  ' WHERE TicketID = ' + CAST(@DynamicInsertedId AS NVARCHAR(MAX));    
DECLARE @Result TABLE (TicketNo NVARCHAR(50), CreatedOn DATE);    
    
INSERT INTO @Result    
EXEC sp_executesql @DynamicSQL;    
    
SELECT @TicketNo = TicketNo, @CreatedOn = CreatedOn FROM @Result;    
    
SELECT @EventDesc = @UserCreated + ' has created ticket ' + @TicketNo + ' for ' + @EntityName +     
    ' with ' + @EntityName + ': No = ' + CONVERT(NVARCHAR(255), @EntitytID) + ' On ' +     
    CONVERT(NVARCHAR(255), @CreatedOn),    
    @ActivityId = ID    
FROM ActivityMaster (NOLOCK) AM    
WHERE AM.EventName = 'Ticket Created';    
    
--EXEC Usp_tp_SaveEntityActivity_withid @entityname = @EntityName, @EntityID = @EntitytID,     
--    @UserID = @UserId, @ParentID = @ParentId, @EventDescription = @EventDesc,    
--    @EventName = 'Ticket Created', @reftables = @TicketMasterTable,     
--    @refid = @DynamicInsertedId, @refColName = 'TicketID',@Groupid = @AssignedGroup,@AgentId =  @AssignedUser ,@Type = 'Requester'     
     
     
                  
   IF (@SelectedTicket = 'New')                        
     BEGIN                           
    SELECT 'Ticket Raised Successfully';                          
    END                        
   IF (@SelectedTicket = 'Child')                        
     BEGIN                           
    SELECT 'Child Ticket Created Successfully';                          
    END                        
   IF (@SelectedTicket = 'Merge')                        
     BEGIN                           
    SELECT 'Ticket Merged Successfully';                          
    END                        
   IF (@SelectedTicket = 'Split')                        
     BEGIN                           
   SELECT 'Ticket Splitted Successfully';                          
    END                  
    
	exec usp_tp_ApplyDispatcherRule @InsertedId, @ParentID  
                                    
  END                                           
  ELSE IF @Option = 'Update'                                                              
  BEGIN                                                     
                                               
                                           
     DECLARE @DynamicUpdateQuery NVARCHAR(MAX);    
    
     SET @DynamicUpdateQuery =     
     N'UPDATE ' + QUOTENAME(@TicketMasterTable) + ' SET ' +    
    'TicketTypeId = ' + CAST(ISNULL(@TcktType, 0) AS NVARCHAR(MAX)) + ', ' +    
    'TicketCategoryId = ' + CAST(ISNULL(@TcktCategory, 0) AS NVARCHAR(MAX)) + ', ' +    
    'ModifiedBy = ' + CAST(ISNULL(@CreatedBy, 0) AS NVARCHAR(MAX)) + ', ' +    
    'ModifiedOn = GETDATE(), ' +    
    'Subject = ''' + REPLACE(ISNULL(@TcktSubject, ''), '''', '''''') + ''', ' +    
    'Description = ''' + REPLACE(ISNULL(@TcktDescription, ''), '''', '''''') + ''', ' +    
    'TicketPriority = ' + CAST(ISNULL(@TcktPriority, 0) AS NVARCHAR(MAX)) + ', ' +    
    'AssignedSource = ''Manual'', ' +     
    'TicketSourceId = ' + CAST(ISNULL(@TcktSource, 0) AS NVARCHAR(MAX)) + ' ' +    
    'WHERE TicketID = ' + CAST(@TicketID AS NVARCHAR(MAX));    
    
PRINT @DynamicUpdateQuery;    
EXEC sp_executesql @DynamicUpdateQuery;                                       
                                                  
  CREATE TABLE #TagsData1 (                                                
  TagData NVARCHAR(MAX)                                                
 );                                                
                                                
 INSERT INTO #TagsData1 (TagData)                                                
 SELECT value FROM STRING_SPLIT(@TcktTag, ',');                                                
                               
 CREATE TABLE #SplitValues1 (                                                
  OriginalData NVARCHAR(MAX),                                                
  TagIDs NVARCHAR(MAX),                                                
  Tags NVARCHAR(MAX)                                                
 );                                                
 INSERT INTO #SplitValues1 (OriginalData, TagIDs, Tags)                                                
 SELECT                                                
  TagData AS OriginalData,                                                
  CASE WHEN ISNUMERIC(extracted_integers) = 1 THEN extracted_integers END AS TagIDs,                                                
  extracted_strings AS Tags                                                
 FROM (                                                
  SELECT TagData,                                                
      STRING_AGG(CASE WHEN ISNUMERIC(val) = 1 THEN val ELSE NULL END, ',') AS extracted_integers,                                                
      STRING_AGG(CASE WHEN ISNUMERIC(val) = 0 THEN val ELSE NULL END, ',') AS extracted_strings                         
  FROM (                                                
   SELECT TagData, value AS val                                                
   FROM #TagsData1                                                
   CROSS APPLY STRING_SPLIT(TagData, ',')                                                
  ) AS split_values                                                
  GROUP BY TagData                                                
 ) AS aggregated_data;                                                
                                                
 DECLARE @InsertedTagMapping1 TABLE (TagID INT, EntityID INT);                                                
                                                
 DECLARE @TagMasterID1 INT;                                                
                                                
 IF EXISTS (SELECT Tags FROM #SplitValues1 WHERE Tags IS NOT NULL)                                                
 BEGIN        
                                                
 DECLARE @Tag1 NVARCHAR(MAX);                                                
                                                
 DECLARE cur CURSOR FOR                                                
 SELECT TRIM(value) AS Tag                                                
 FROM #SplitValues1                                                
 CROSS APPLY STRING_SPLIT(Tags, ',')                                             
 WHERE Tags IS NOT NULL;                                                
                                                
 OPEN cur;                                                
 FETCH NEXT FROM cur INTO @Tag1;                                                
                                                
 WHILE @@FETCH_STATUS = 0                                                
 BEGIN                                                
                                                
  INSERT INTO TagMaster (Tag, ParentID, CreatedDate, CreatedBy, IsActive)                                                
  VALUES (@Tag1, @ParentID, GETDATE(), @UserId, 1);                                                
                                                
  DECLARE @GeneratedTagID1 INT;                                                
  SET @GeneratedTagID1 = SCOPE_IDENTITY();                                               
                
  DELETE FROM EntityTagMapping WHERE EntityID = @TicketID AND Entity = 'TICKET'                                              
                                                
  INSERT INTO EntityTagMapping (TagID, EntityID, Entity, CreatedDate)                                                
  VALUES (@GeneratedTagID1, @TicketID, 'Ticket', GETDATE());                                                
                                                
  FETCH NEXT FROM cur INTO @Tag1;                                                
 END;                                                
                                                
 CLOSE cur;                        
 DEALLOCATE cur;                                                
                                                
                                                
 END;                                                
                                               
 IF EXISTS (SELECT TagIDs FROM #SplitValues1 WHERE TagIDs IS NOT NULL)                                                
 BEGIN                                                
  DELETE FROM EntityTagMapping WHERE EntityID = @TicketID AND Entity = 'TICKET' AND TagID IN (SELECT TagIDs FROM #SplitValues1)                                 
                                                         
  INSERT INTO EntityTagMapping (EntityID, Entity, TagID, CreatedDate)                                                
  SELECT @TicketID, 'Ticket', TagIDs, GETDATE()                                                
  FROM #SplitValues1                                                
 END;                                                
                                                                   
 DROP TABLE #TagsData1;                                                
 DROP TABLE #SplitValues1;                                                
                                                
DECLARE @DynamicTagUpdateQuery NVARCHAR(MAX);    
    
SET @DynamicTagUpdateQuery =     
    N'UPDATE ' + QUOTENAME(@TicketMasterTable) + ' SET ' +    
    'TicketTag = (SELECT STRING_AGG(CONVERT(NVARCHAR(MAX), TagID), '', '') AS CommaSeparatedEntityIDs ' +    
    'FROM EntityTagMapping WHERE EntityID = ' + CAST(@TicketID AS NVARCHAR(MAX)) + ' AND Entity = ''Ticket'') ' +    
    'WHERE TicketID = ' + CAST(@TicketID AS NVARCHAR(MAX));    
    
PRINT @DynamicTagUpdateQuery;    
EXEC sp_executesql @DynamicTagUpdateQuery;                                              
                                                   
                                                
 DECLARE @TicketHistoryId1 BIGINT                                  
                                                    
 INSERT INTO tbl_tp_TicketHistory (TicketID,TicketStatusID,ParentID,ActionDateTime,Remarks,Note,UserResponse,AssignedUser,TicketPriority,AssignedSource,AssignedBy)                                                  
  VALUES (@TicketID,@TcktStatus,@ParentID,NULL,NULL,NULL,NULL,@ParentID,@TcktPriority,10,@ParentID)                                              
                                                
                                                
 SET @TicketHistoryId1 = SCOPE_IDENTITY();                                                
                                                
 IF (@FileName IS NOT NULL)                    
 BEGIN                                                
     INSERT INTO  tbl_tp_TicketAttachment(TicketID,TicketHistoryID,DisplayName,FileUrl,IsActive,CreatedBy,CreatedOn)                    
  VALUES (@TicketID,@TicketHistoryId,@FileName,@FilePath,1,@UserId,GETDATE())                      
 END                                                
                
 IF @@ROWCOUNT > 0                                                              
  SELECT 'Ticket Updated Successfully';                                                   
                    
   DECLARE @DynamicRowJsonQuery1 NVARCHAR(MAX);                              
                              
 SET @DynamicRowJsonQuery = N'                              
  SELECT @json_Result = (                              
   SELECT *                               
   FROM ' + QUOTENAME(@TicketMasterTable) + '                               
   WHERE TicketID = @DynamicInsertedId                               
   FOR JSON AUTO, INCLUDE_NULL_VALUES                              
  )';                              
                              
 DECLARE @jsonResult1 NVARCHAR(MAX);                            
                            
 EXEC sp_executesql @DynamicRowJsonQuery1, N'@DynamicInsertedId BIGINT, @json_Result NVARCHAR(MAX) OUTPUT', @DynamicInsertedId=@TicketID, @json_Result=@jsonResult1 OUTPUT;                                                  
 SET @rowJson = @jsonResult1;                       
                                                      
  IF @rowJson IS NOT NULL                                                          
  BEGIN                                                            
   EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData                                                   
    @User_id = @UserId,                                                            
    @Activity_type = 'Updt_manageticketmaster',         
    @ActionType = 'U',                                                            
    @RowJson = @rowJson,                                                            
    @Table_name = @TicketMasterTable,                                                    
    @ip_adress = @IPAdress,                                                  
    @device_id = @DeviceId,                                                  
    @IsImpersonation = @IsImpersonation,                                                  
    @ImpersonatorId = @ImpersonatorId;                                           
  END        
      
SET @DynamicSQL = 'SELECT ' + QUOTENAME(@ColumnName) + ', ' + QUOTENAME(@ColumnName1) + ' FROM ' + QUOTENAME(@TicketMasterTable) +    
                  ' WHERE TicketID = ' + CAST(@TicketID AS NVARCHAR(MAX))    
DECLARE @Result1 TABLE (TicketNo NVARCHAR(50), CreatedOn DATE);    
    
INSERT INTO @Result1    
EXEC sp_executesql @DynamicSQL;    
    
SELECT @TicketNo = TicketNo, @CreatedOn = CreatedOn FROM @Result1;    
    
SELECT @EventDesc = @UserCreated + ' has updated ticket ' + @TicketNo + ' for ' + @EntityName +     
    ' with ' + @EntityName + ': Id = ' + CONVERT(NVARCHAR(255), @EntitytID) + ' On ' +     
    CONVERT(NVARCHAR(255), @CreatedOn),    
    @ActivityId = ID    
FROM ActivityMaster (NOLOCK) AM    
WHERE AM.EventName = 'Ticket Updated';    
    
