CREATE   PROCEDURE [dbo].[Usp_tp_InsertManageTicketMasterForSIPApi]  
(    
 @ParentID bigint = NULL,    
 @TpUserId BIGINT = NULL ,    
 @TicketID bigint = NULL,    
 @ParentTicketID bigint = NULL,    
 @EntitytID bigint = NULL,    
 @EntityName nvarchar(50) = NULL,    
 @MobileNumber bigint = NULL,
 @CountryCode bigint = NULL,   
 @EmailID nvarchar(MAX) = NULL,    
 @MobileNumber1 bigint = NULL,
 @CountryCode1 bigint = NULL,    
