-- @Option nvarchar(50) = N'Update' ,    
-- @Product nvarchar(max) = N'',    
-- @Company nvarchar(500) = N'',    
-- @AssignedGroup bigint = 0,    
-- @AssignedUser bigint = 88,    
-- @SelectedTicket nvarchar(10) = N'' ,    
-- @CustomFieldValueJson NVARCHAR(max)=N'{}',    
-- @MetaData nvarchar(MAX) = N'{"IPAddress":"::1","MacAddress":"00FFB0003F75","IsImpersonation":false,"ImpersonatorId":0}'    
    
 DECLARE @InsertedId BIGINT= 0, @UserId BIGINT, @rowJson NVARCHAR(MAX), @IPAdress NVARCHAR(50),   
  @DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT, @sqls NVARCHAR(MAX)= '',   
  @status INT, @TicketMasterTable NVARCHAR(MAX), @customfieldlist NVARCHAR(MAX),   
  @customfieldvalue NVARCHAR(MAX)= '', @DynamicQuery NVARCHAR(MAX), @Type VARCHAR(50);    
 DECLARE @ActivityId BIGINT, @EventDesc NVARCHAR(MAX),@Actitivitydesc NVARCHAR(MAX),   
  @UserCreated NVARCHAR(100), @TicketNo NVARCHAR(50), @CreatedOn DATE,@CustomFieldInsertSQL NVARCHAR(MAX) ,@CustomFieldName NVARCHAR(MAX),@EventName NVARCHAR(MAX),
  @CustomFieldsValue NVARCHAR(MAX),  @ActivityDatetime datetime=GetDate(), @TicketActivityTable nvarchar(max)    
    
 Select @UserId = User_ID, @ParentID = @ParentId, @UserCreated = isnull(Name,LoginName)     
 From tbl_tp_UserLogin(noLock) Where TpUser_Id = @TpUserId AND IsActive = 1    
    
 SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)    
 SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)    
 SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)    
 SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)    
    

    DECLARE @TcktPriorityId BIGINT = 0
DECLARE @TcktSourceId BIGINT = 0
DECLARE @TcktCategoryId BIGINT = 0
DECLARE @TcktTypeId BIGINT = 0
DECLARE @TcktStatusId BIGINT = 1

/* PRIORITY */
IF ISNULL(@TcktPriority,'') <> ''
BEGIN

    IF ISNUMERIC(@TcktPriority) = 1
    BEGIN
        SET @TcktPriorityId = CAST(@TcktPriority AS BIGINT)
    END
    ELSE
    BEGIN
        SELECT TOP 1 @TcktPriorityId = Priority_ID
        FROM tbl_tp_TicketPriorityMaster WITH(NOLOCK)
        WHERE PriorityName = @TcktPriority
        AND Active = 1

        IF ISNULL(@TcktPriorityId,0) = 0
        BEGIN
            INSERT INTO tbl_tp_TicketPriorityMaster
            (
                PriorityName,
                ParentId,
                Active,
                CreatedBy,
                CreatedDate
            )
            VALUES
            (
                @TcktPriority,
                @ParentID,
                1,
                @TpUserId,
                GETDATE()
            )

            SET @TcktPriorityId = SCOPE_IDENTITY()
        END
    END


    IF ISNULL(@TcktPriorityId,0) = 0
BEGIN
    SELECT TOP 1 @TcktPriorityId = Priority_ID
    FROM tbl_tp_TicketPriorityMaster WITH(NOLOCK)
    WHERE PriorityName LIKE '%Medium%'
    AND Active = 1

    IF ISNULL(@TcktPriorityId,0)=0
        SET @TcktPriorityId = 1
END

END

/* SOURCE */
IF ISNULL(@TcktSource,'') <> ''
BEGIN

    IF ISNUMERIC(@TcktSource) = 1
    BEGIN
        SET @TcktSourceId = CAST(@TcktSource AS BIGINT)
    END
    ELSE
    BEGIN
        SELECT TOP 1 @TcktSourceId = TicketSourceId
        FROM tbl_tp_TicketSourceMaster WITH(NOLOCK)
        WHERE TicketSourceName = @TcktSource
        AND IsActive = 1

        IF ISNULL(@TcktSourceId,0) = 0
        BEGIN
            INSERT INTO tbl_tp_TicketSourceMaster
            (
                TicketSourceName,
                ParentId,
                IsActive,
                CreatedBy,
                CreatedDate
            )
            VALUES
            (
                @TcktSource,
                @ParentID,
                1,
                @TpUserId,
                GETDATE()
            )

            SET @TcktSourceId = SCOPE_IDENTITY()
        END
    END
END

/* CATEGORY */
IF ISNULL(@TcktCategory,'') <> ''
BEGIN

    IF ISNUMERIC(@TcktCategory) = 1
    BEGIN
        SET @TcktCategoryId = CAST(@TcktCategory AS BIGINT)
    END
    ELSE
    BEGIN
        SELECT TOP 1 @TcktCategoryId = TicketCategoryId
        FROM tbl_tp_TicketCategory_Master WITH(NOLOCK)
        WHERE TicketCategoryName = @TcktCategory
        AND ParentId = @ParentID
        AND IsActive = 1

        IF ISNULL(@TcktCategoryId,0) = 0
        BEGIN
            INSERT INTO tbl_tp_TicketCategory_Master
            (
                TicketCategoryName,
                ParentId,
                IsActive,
                CreatedBy,
                CreatedDate
            )
            VALUES
            (
                @TcktCategory,
                @ParentID,
                1,
                @TpUserId,
                GETDATE()
            )

            SET @TcktCategoryId = SCOPE_IDENTITY()
        END
    END
END

/* TYPE */
IF ISNULL(@TcktType,'') <> ''
BEGIN

    IF ISNUMERIC(@TcktType) = 1
    BEGIN
        SET @TcktTypeId = CAST(@TcktType AS BIGINT)
    END
    ELSE
    BEGIN
        SELECT TOP 1 @TcktTypeId = Type_ID
        FROM tbl_tp_TicketType_Master WITH(NOLOCK)
        WHERE Type_Name = @TcktType
        AND ParentId = @ParentID
        AND Active = 1

        IF ISNULL(@TcktTypeId,0) = 0
        BEGIN
            INSERT INTO tbl_tp_TicketType_Master
            (
                Type_Name,
                ParentId,
                Active,
                CreatedBy,
                CreatedDate
            )
            VALUES
            (
                @TcktType,
                @ParentID,
                1,
                @TpUserId,
                GETDATE()
            )

            SET @TcktTypeId = SCOPE_IDENTITY()
        END
    END
END

/* STATUS */
IF ISNULL(@TcktStatus,'') = ''
BEGIN
    SET @TcktStatusId = 1
END
ELSE
BEGIN

    IF ISNUMERIC(@TcktStatus) = 1
    BEGIN
        SET @TcktStatusId = CAST(@TcktStatus AS BIGINT)
    END
    ELSE
    BEGIN
        SELECT TOP 1 @TcktStatusId = TicketStatus_ID
        FROM tbl_tp_TicketStatusMaster WITH(NOLOCK)
        WHERE TicketStatus = @TcktStatus
        AND IsActive = 1

        IF ISNULL(@TcktStatusId,0) = 0
        BEGIN
            SET @TcktStatusId = 1
        END
    END
END



 DECLARE @Keys NVARCHAR(MAX) = '';    
