  CreatedOn, ModifiedBy, ModifiedOn, SplittedBy, SplittedOn, MergedBy, MergedOn,    
  ClosedBy, ClosedOn, CreatedChildBy, CreatedChildOn ' +    
  CASE WHEN @Keys <> '' THEN ', ' + @Keys ELSE '' END +    
  N') VALUES (    
  ' + CAST(@TpUserId AS NVARCHAR(MAX)) + ', ' +    
  CAST(ISNULL(@ParentID, 0) AS NVARCHAR(MAX)) + ', ' +    
  '''000 - TICKET'', ' +    
  '''' + REPLACE(ISNULL(@MobileNumber, ''), '''', '''''') + ''', ' +    
    '''' + REPLACE(ISNULL(@CountryCode, ''), '''', '''''') + ''', ' +  
  '''' + REPLACE(ISNULL(@EmailID, ''), '''', '''''') + ''', ' +    
  '''' + REPLACE(ISNULL(@MobileNumber1, ''), '''', '''''') + ''', ' +    
    '''' + REPLACE(ISNULL(@CountryCode1, ''), '''', '''''') + ''', ' +  
  '''' + REPLACE(ISNULL(@EmailID1, ''), '''', '''''') + ''', ' +    
  '''' + REPLACE(ISNULL(@MobileNumber2, ''), '''', '''''') + ''', ' +   
    '''' + REPLACE(ISNULL(@CountryCode2, ''), '''', '''''') + ''', ' +  
  '''' + REPLACE(ISNULL(@EmailID2, ''), '''', '''''') + ''', ' +    
  '''' + REPLACE(ISNULL(@TcktSubject, ''), '''', '''''') + ''', ' +    
  'N''' + REPLACE(ISNULL(@TcktDescription, N''), N'''', N'''''') + N''', ' +
CAST(ISNULL(@TcktStatusId, 0) AS NVARCHAR(MAX)) + ', ' +    
  'NULL, ''Ticket Created'', NULL, ' + -- Remarks, Note, UserResponse    
  CAST(ISNULL(@TcktPriorityId, 'Medium') AS NVARCHAR(MAX)) + ', ' + -- TicketPriority    
  CAST(ISNULL(@AssignedUser, 0) AS NVARCHAR(MAX)) + ', ' +    
