  '''' + ISNULL(@EntityName, '') + ''', ''' + REPLACE(ISNULL(@Company, ''), '''', '''''') + ''', 1, ' + -- EntityName, Company, IsActive    
  CAST(ISNULL(@TpUserId, 0) AS NVARCHAR(MAX)) + ', GETDATE(), NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL '; -- Other field values    
    
  IF @Values <> ''    
  BEGIN    
   SET @DynamicQuery = @DynamicQuery + N', ' + @Values + N'); Set @Ticket_Id=Scope_Identity()';    
  END    
  ELSE    
  BEGIN    
