  -- Set the dynamic inserted ID from the earlier operation
SET @DynamicInsertedId = @InsertedId;
DECLARE @UpdateQuery NVARCHAR(MAX);
DECLARE @UpdateNumberQuery NVARCHAR(MAX);
DECLARE @NextTicketNo NVARCHAR(100);
DECLARE @LastTicketNo NVARCHAR(50);
DECLARE @CurrentNumber INT;
DECLARE @Prefix NVARCHAR(50) = '';
DECLARE @Suffix NVARCHAR(50) = '';
DECLARE @ParamDefinition NVARCHAR(MAX);
DECLARE @fetchnumberSQL NVARCHAR(MAX);
DECLARE @ExtractedNumber NVARCHAR(20) = '';
DECLARE @LeadingZeros NVARCHAR(20) = '';
DECLARE @IncrementedNumber NVARCHAR(20);
DECLARE @Pattern NVARCHAR(50);
DECLARE @LastDigitPos INT;
DECLARE @FormatJson NVARCHAR(MAX);
DECLARE @Number NVARCHAR(50) = '';

-- Fetch the FormatJson from tbl_tp_TicketNoFormat
SELECT @FormatJson = FormatJson
FROM tbl_tp_TicketNoFormat
WHERE ParentId = @ParentID AND IsActive = 1;

-- Declare a table to store format values
DECLARE @FormatValues TABLE (
    [Value] NVARCHAR(50),
    [DataType] NVARCHAR(50)
);


INSERT INTO @FormatValues ([Value], [DataType])
SELECT 
    JSON_VALUE(value, '$.value') AS [Value],
    JSON_VALUE(value, '$.datatype') AS [DataType]
FROM OPENJSON(@FormatJson, '$.FormatValues');

-- Extract the prefix, number, and suffix into variables
SELECT TOP 1 @Prefix = COALESCE([Value], '') 
FROM @FormatValues WHERE [DataType] = 'prefix';

SELECT TOP 1 @Number = COALESCE([Value], '0') 
FROM @FormatValues WHERE [DataType] = 'number';

SELECT TOP 1 @Suffix = COALESCE([Value], '') 
FROM @FormatValues WHERE [DataType] = 'suffix';

-- Construct SQL to fetch the last ticket number
SET @fetchnumberSQL = N'
SELECT TOP 1 @LastTicketNo = TicketNo
FROM ' + QUOTENAME(@TicketMasterTable) + '
WHERE TicketNo LIKE @Prefix + ''%'' + @Suffix
ORDER BY TicketID DESC;';

SET @ParamDefinition = N'@LastTicketNo NVARCHAR(50) OUTPUT, @Prefix NVARCHAR(50), @Suffix NVARCHAR(50)';

-- Execute the SQL to fetch the last ticket number
EXEC sp_executesql 
    @fetchnumberSQL, 
    @ParamDefinition, 
    @LastTicketNo = @LastTicketNo OUTPUT, 
    @Prefix = @Prefix, 
    @Suffix = @Suffix;

PRINT @LastTicketNo;

-- Case 1: If @LastTicketNo is NULL and @FormatJson is NOT NULL
IF @LastTicketNo IS NULL AND @FormatJson IS NOT NULL
BEGIN
    -- If number is NULL, default to '1'
    IF @Number IS NULL
        SET @Number = '1';

    -- Generate the next ticket number
    SET @NextTicketNo = @Prefix + @Number + @Suffix;

    -- Prepare the update query to insert the ticket number
    SET @UpdateNumberQuery = N'
    UPDATE ' + QUOTENAME(@TicketMasterTable) + '    
    SET TicketNo = @NextTicketNo    
    WHERE TicketID = @Ticket_ID';
    
    -- Execute the update query
    EXEC sp_executesql @UpdateNumberQuery, N'@Ticket_ID BIGINT, @NextTicketNo NVARCHAR(50)', @Ticket_ID = @DynamicInsertedId, @NextTicketNo = @NextTicketNo;
END


ELSE IF @LastTicketNo IS NOT NULL AND @FormatJson IS NOT NULL
BEGIN
    -- Find the last digit's position in @LastTicketNo
    SET @LastDigitPos = LEN(@LastTicketNo) - LEN(@Suffix);

    -- Extract the number portion from @LastTicketNo
    SET @ExtractedNumber = SUBSTRING(@LastTicketNo, LEN(@Prefix) + 1, @LastDigitPos - LEN(@Prefix));

    -- Handle leading zeros and increment the number
    IF LEFT(@ExtractedNumber, 1) = '0'
    BEGIN
        SET @IncrementedNumber = CAST(CAST(@ExtractedNumber AS INT) + 1 AS NVARCHAR(20));
        SET @LeadingZeros = REPLICATE('0', LEN(@ExtractedNumber) - LEN(@IncrementedNumber));
        SET @Number = @LeadingZeros + @IncrementedNumber;
    END
    ELSE
    BEGIN
        SET @IncrementedNumber = CAST(CAST(@ExtractedNumber AS INT) + 1 AS NVARCHAR(20));
        SET @Number = @IncrementedNumber;
    END

    SET @NextTicketNo = @Prefix + @Number + @Suffix;

    SET @UpdateNumberQuery = N'
    UPDATE ' + QUOTENAME(@TicketMasterTable) + '    
    SET TicketNo = @NextTicketNo    
    WHERE TicketID = @Ticket_ID';

    EXEC sp_executesql @UpdateNumberQuery, N'@Ticket_ID BIGINT, @NextTicketNo NVARCHAR(50)', @Ticket_ID = @DynamicInsertedId, @NextTicketNo = @NextTicketNo;
END

ELSE IF  @FormatJson IS NULL 
BEGIN
    SET @UpdateQuery = N'    
    UPDATE ' + QUOTENAME(@TicketMasterTable) + '    
    SET TicketNo = ''000'' + CAST(@Ticket_ID AS NVARCHAR(20)) + '' - TICKET''    
    WHERE TicketID = @Ticket_ID';    
	    PRINT 'updatedqueries: ' + @UpdateQuery;
    EXEC sp_executesql @UpdateQuery, N'@Ticket_ID BIGINT', @Ticket_ID = @DynamicInsertedId;
END

  DECLARE @UpdateQuery1 NVARCHAR(MAX);    
       
  IF (@SelectedTicket = 'Child' )    
  BEGIN    
   SET @UpdateQuery1 = N'    
   UPDATE ' + QUOTENAME(@TicketMasterTable) + '    
   SET IsParentTicket = 1    
   WHERE ParentTicketID > 0 AND TicketID = @Ticket_ID';    
    
   EXEC sp_executesql @UpdateQuery1, N'@Ticket_ID BIGINT', @Ticket_ID=@DynamicInsertedId;    
    
   SET @UpdateQuery1 = N'    
   UPDATE ' + QUOTENAME(@TicketMasterTable) + '    
   SET IsChildTicket = 1    
   WHERE TicketID = @Ticket_ID';    
    
   EXEC sp_executesql @UpdateQuery1, N'@Ticket_ID BIGINT', @Ticket_ID=@DynamicInsertedId;    
  END    
    
  IF (@SelectedTicket = 'Merge' )    
  BEGIN    
   SET @UpdateQuery1 = N'    
   UPDATE ' + QUOTENAME(@TicketMasterTable) + '    
   SET IsMerged = CASE WHEN ParentTicketID > 0 THEN 1 ELSE 0 END    
   WHERE TicketID = @Ticket_ID';    
    
   EXEC sp_executesql @UpdateQuery1, N'@Ticket_ID BIGINT', @Ticket_ID=@DynamicInsertedId;    
    
   SET @UpdateQuery1 = N'    
   UPDATE ' + QUOTENAME(@TicketMasterTable) + '    
   SET ParentTicketID = @ParentTicket_ID    
   WHERE TicketID = @Ticket_ID';    
    
   EXEC sp_executesql @UpdateQuery1, N'@ParentTicket_ID BIGINT,@Ticket_ID BIGINT', @ParentTicket_ID=@ParentTicketID,@Ticket_ID=@DynamicInsertedId;    
  END    
    
  IF (@SelectedTicket = 'Split' )    
  BEGIN    
   SET @UpdateQuery1 = N'    
   UPDATE ' + QUOTENAME(@TicketMasterTable) + '    
   SET IsSplitted = 1    
   WHERE TicketID = @Ticket_ID';    
    
   EXEC sp_executesql @UpdateQuery1, N'@Ticket_ID BIGINT', @Ticket_ID=@DynamicInsertedId;    
    
   SET @UpdateQuery1 = N'    
   UPDATE ' + QUOTENAME(@TicketMasterTable) + '    
   SET ParentTicketID = @ParentTicket_ID    
   WHERE TicketID = @Ticket_ID';    
    
   EXEC sp_executesql @UpdateQuery1, N'@ParentTicket_ID BIGINT,@Ticket_ID BIGINT', @ParentTicket_ID=@ParentTicketID,@Ticket_ID=@DynamicInsertedId;    
  END    
    
    
  CREATE TABLE #TagsData (    
  TagData NVARCHAR(MAX)    
  );    
    
  INSERT INTO #TagsData (TagData)    
  SELECT value FROM STRING_SPLIT(@TcktTag, ',');    
    
  CREATE TABLE #SplitValues (    
  OriginalData NVARCHAR(MAX),    
  TagIDs NVARCHAR(MAX),    
  Tags NVARCHAR(MAX)    
  );    
    
  INSERT INTO #SplitValues (OriginalData, TagIDs, Tags)    
  SELECT TagData AS OriginalData,    
  CASE WHEN ISNUMERIC(extracted_integers) = 1 THEN extracted_integers END AS TagIDs,    
  extracted_strings AS Tags    
  FROM     
  (    
   SELECT TagData,    
   STRING_AGG(CASE WHEN ISNUMERIC(val) = 1 THEN val ELSE NULL END, ',') AS extracted_integers,    
   STRING_AGG(CASE WHEN ISNUMERIC(val) = 0 THEN val ELSE NULL END, ',') AS extracted_strings    
   FROM     
   (    
    SELECT TagData, value AS val    
    FROM #TagsData    
    CROSS APPLY STRING_SPLIT(TagData, ',')    
   ) AS split_values    
   GROUP BY TagData    
  ) AS aggregated_data;    
    
  DECLARE @InsertedTagMapping TABLE (TagID INT, EntityID INT);    
    
  DECLARE @TagMasterID INT;    
  IF EXISTS (SELECT Tags FROM #SplitValues WHERE Tags IS NOT NULL)    
  BEGIN    
   DECLARE @Tag NVARCHAR(MAX);    
    
   DECLARE cur CURSOR FOR    
   SELECT TRIM(value) AS Tag    
   FROM #SplitValues    
   CROSS APPLY STRING_SPLIT(Tags, ',')    
   WHERE Tags IS NOT NULL;    
    
   OPEN cur;    
   FETCH NEXT FROM cur INTO @Tag;    
    
   WHILE @@FETCH_STATUS = 0    
   BEGIN    
    INSERT INTO TagMaster (Tag, ParentID, CreatedDate, CreatedBy, IsActive)    
    VALUES (@Tag, @ParentID, GETDATE(), @UserId, 1);    
    
    DECLARE @GeneratedTagID INT;    
    SET @GeneratedTagID = SCOPE_IDENTITY();    
    
    INSERT INTO EntityTagMapping (TagID, EntityID, Entity, CreatedDate,ParentId)    
    VALUES (@GeneratedTagID, @InsertedId, 'Ticket', GETDATE(),@ParentID);    
    
    FETCH NEXT FROM cur INTO @Tag;    
    END;    
    
   CLOSE cur;    
   DEALLOCATE cur;    
  END;    
    
  IF EXISTS (SELECT TagIDs FROM #SplitValues WHERE TagIDs IS NOT NULL)    
  BEGIN    
   INSERT INTO EntityTagMapping (EntityID, Entity, TagID, CreatedDate,ParentId)    
   SELECT @InsertedId, 'Ticket', TagIDs, GETDATE() , @ParentID    
   FROM #SplitValues    
  END;    
    
  DROP TABLE #TagsData;    
  DROP TABLE #SplitValues;    
    
  DECLARE @DynamicTicketTagUpdate NVARCHAR(MAX);    
  SET @DynamicTicketTagUpdate = N'    
  UPDATE ' + QUOTENAME(@TicketMasterTable) + N'    
  SET TicketTag = STUFF(    
  (SELECT '', '' + CONVERT(NVARCHAR(MAX), TagID)    
