  exec usp_tp_RaiseEmailNotification @DynamicInsertedId,@ParentID,@AssignedGroup,@TpUserId,@AssignedUser,'New Ticket Created','Agent'    
  exec usp_tp_RaiseEmailNotification @DynamicInsertedId,@ParentID,0,@TpUserId,@TpUserId,'New Ticket Created','Requester'    
    
  SELECT @EventDesc = @UserCreated + ' has created ticket ' + @TicketNo + ' with subject ' + @TcktSubject + ' raised on ' + CONVERT(NVARCHAR(255), @CreatedOn) + ' for ' + @EntityName + ': No = ' + CONVERT(NVARCHAR(255), @EntitytID)     
    
  -- EXEC Usp_tp_SaveEntityActivity_withid @entityname = @EntityName, @EntityID = @EntitytID,@UserID = @UserId, @ParentID = @ParentId, @EventDescription = @EventDesc, @EventName = 'Agent Raises Ticket', @reftables = @TicketMasterTable, @refid = @DynamicInsertedId, @refColName = 'TicketID',@Groupid = @AssignedGroup,@AgentId = @AssignedUser ,@Type = 'Agent'    
