  )    
    
  select * into #tblTicketAfterEdit From #tblTicketBeforeEdit    
      
  DECLARE @DynamicUpdateQuery NVARCHAR(MAX);    
                            
  SELECT @DynamicUpdateQuery = concat(N'insert into #tblTicketBeforeEdit(TicketID, tpUser_Id, ParentID, TicketNo, RequesterMobileNo,CountryCode, RequesterEmailID, RequesterMobileNo1,CountryCode1, RequesterEmailID1, RequesterMobileNo2,CountryCode2, RequesterEmailID2, Subject, Description, TicketStatusID, Remarks, Note, UserResponse, TicketPriority, AssignedUser, AssignedGroup, AssignedSource, TicketCategoryId, TicketTypeId, TicketSourceId, ProductId, IsMerged, IsSplitted, IsParentTicket, IsChildTicket, ParentTicketID, LastActionDatetime, AssignedBy, AssignedDateTime, TicketTag, EntityID, EntityName, Company, CreatedBy, CreatedOn)    
  Select TicketID, tpUser_Id, ParentID, TicketNo, RequesterMobileNo,CountryCode, RequesterEmailID, RequesterMobileNo1,CountryCode1, RequesterEmailID1, RequesterMobileNo2,CountryCode2,RequesterEmailID2, Subject, Description, TicketStatusID, Remarks, Note, UserResponse, TicketPriority, AssignedUser, AssignedGroup, AssignedSource, TicketCategoryId, TicketTypeId, TicketSourceId, ProductId, IsMerged, IsSplitted, IsParentTicket, IsChildTicket, ParentTicketID, LastActionDatetime, AssignedBy, AssignedDateTime, TicketTag, EntityID, EntityName, Company, CreatedBy, CreatedOn    
  From ',@TicketMasterTable, N'    
