  'CountryCode1 = ' + CAST(ISNULL(@CountryCode1, 0) AS NVARCHAR(MAX)) + ', ' +   
  'RequesterEmailID1 = ''' + CAST(ISNULL(@EmailID1, 0) AS NVARCHAR(MAX)) + ''', ' +      
  'CountryCode2 = ' + CAST(ISNULL(@CountryCode2, 0) AS NVARCHAR(MAX)) + ', ' +      
