/* ============================================================
   Procedure: [dbo].[Usp_tp_InsertOrUpdateDates]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_tp_InsertOrUpdateDates]
    @tpUserId BIGINT,
    @pageName NVARCHAR(255),
    @sectionNumber NVARCHAR(255),
    @startDate DATETIME,
    @endDate DATETIME,
    @MetaData NVARCHAR(MAX) 
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
        BEGIN TRANSACTION;
        IF @tpUserId IS NULL OR @pageName IS NULL OR @sectionNumber IS NULL
        BEGIN
            SELECT 'Invalid input parameters. Please provide valid values for tpUserId, pageName, and sectionNumber.' AS Result;
            ROLLBACK TRANSACTION;
            RETURN;
        END

        DECLARE @pageId INT;
        SELECT @pageId = Page_Id
        FROM tbl_tp_PageTheme
        WHERE PageName = @pageName AND IsActive = 1;

        IF @pageId IS NOT NULL
        BEGIN

            IF EXISTS (
                SELECT 1
                FROM tbl_tp_PageSectionDetail
                WHERE Page_Id = @pageId AND SectionNumber = @sectionNumber AND tpuserid = @tpUserId
            )
            BEGIN
                DECLARE @existingStartDate DATETIME;
                DECLARE @existingEndDate DATETIME;

                SELECT @existingStartDate = MIN(StartDate),
                       @existingEndDate = MAX(EndDate)
                FROM tbl_tp_PageSectionDetail
                WHERE Page_Id = @pageId AND SectionNumber = @sectionNumber AND tpuserid = @tpUserId AND IsActive = 1;

            
                IF @existingStartDate IS NULL AND @existingEndDate IS NULL
                BEGIN
                    UPDATE tbl_tp_PageSectionDetail
                    SET StartDate = @startDate, EndDate = @endDate, ModifiedDate = GETDATE()
                    WHERE Page_Id = @pageId AND SectionNumber = @sectionNumber AND tpuserid = @tpUserId AND IsActive = 1;

                    SELECT 'Dates inserted successfully' AS Result;
                    COMMIT TRANSACTION;
                    RETURN;
                END

                -- Case 2: Start date is present, but end date is null, insert incoming end date
                IF @existingStartDate IS NOT NULL AND @existingEndDate IS NULL
                BEGIN
                    UPDATE tbl_tp_PageSectionDetail
                    SET EndDate = @endDate, ModifiedDate = GETDATE()
                    WHERE Page_Id = @pageId AND SectionNumber = @sectionNumber AND tpuserid = @tpUserId AND IsActive = 1;

                    SELECT 'End date inserted successfully' AS Result;
                    COMMIT TRANSACTION;
                    RETURN;
                END


                IF @startDate <= @existingEndDate AND @startDate > @existingEndDate
                BEGIN
 
                    SELECT 'Record with the same or overlapping start date already exists. Confirm to insert end date.' AS Result;


                    UPDATE tbl_tp_PageSectionDetail
                    SET EndDate = @endDate, ModifiedDate = GETDATE()
                    WHERE Page_Id = @pageId AND SectionNumber = @sectionNumber AND tpuserid = @tpUserId AND IsActive = 1;

                    SELECT 'End date inserted successfully' AS Result;
                    COMMIT TRANSACTION;
                    RETURN;
                END


                IF @startDate > @existingEndDate
                BEGIN

                    DECLARE @latestRecordId INT;

                    SELECT TOP 1 @latestRecordId = PageSectionDetail_Id
                    FROM tbl_tp_PageSectionDetail
                    WHERE Page_Id = @pageId AND SectionNumber = @sectionNumber AND tpuserid = @tpUserId AND StartDate IS NULL AND EndDate IS NULL
                    ORDER BY ModifiedDate DESC;

 
                    IF @latestRecordId IS NOT NULL
                    BEGIN
                        UPDATE tbl_tp_PageSectionDetail
                        SET StartDate = @startDate, EndDate = @endDate, ModifiedDate = GETDATE()
                        WHERE PageSectionDetail_Id = @latestRecordId;

                        SELECT 'Dates inserted successfully in the latest record with null dates.' AS Result;
                        COMMIT TRANSACTION;
                        RETURN;
                    END
                END

                IF @existingEndDate > GETDATE()
                BEGIN
                    SELECT 'End date has not been reached for the existing record. Cannot insert a new date.' AS Result;
                    ROLLBACK TRANSACTION;
                    RETURN;
                END
            END
            ELSE
            BEGIN
                SELECT 'No content present for the given section number and page id. Insert content first before inserting dates.' AS Result;
                ROLLBACK TRANSACTION;
                RETURN;
            END
        END
        ELSE
        BEGIN
            SELECT 'Page with name ' + @pageName + ' and IsActive = 1 not found' AS Result;
            ROLLBACK TRANSACTION;
            RETURN;
        END

        COMMIT TRANSACTION;
    END TRY
    BEGIN CATCH
        SELECT 'Error: ' + ERROR_MESSAGE() AS Result;
        ROLLBACK TRANSACTION;
        RETURN;
    END CATCH;
END;







