/* ============================================================
   Procedure: [dbo].[Usp_tp_InsertPageSectionDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_tp_InsertPageSectionDetails]
    @pageName NVARCHAR(255),
    @sectionNumber NVARCHAR(255),
    @tpUserId BIGINT,
    @sectionUrl NVARCHAR(255),
    @ArticleImageUrl NVARCHAR(255),
	@authorname NVARCHAR(255),
    @sectionTitle NVARCHAR(255),
    @sectionContent NVARCHAR(MAX),
	@MetaData NVARCHAR(MAX) 
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @pageId INT;
    DECLARE @ParentId BIGINT; 
    SELECT @ParentId = ParentId
    FROM tbl_tp_userlogin
    WHERE TpUser_Id = @tpUserId;


    SELECT @pageId = Page_Id
    FROM tbl_tp_PageTheme
    WHERE PageName = @pageName AND IsActive = 1;

    IF @pageId IS NOT NULL
    BEGIN
        UPDATE tbl_tp_PageSectionDetail
        SET IsActive = 0
        WHERE Page_Id = @pageId
		AND tpuserid=@tpUserId
          AND SectionNumber = @sectionNumber
          AND StartDate IS NULL
          AND EndDate IS NULL;

        INSERT INTO tbl_tp_PageSectionDetail (Page_Id, SectionNumber, SectionUrl,ArticlImageUrl,Authorname, tpuserId, SectionContent, SectionTitle, IsActive, CreatedDate, ModifiedDate, CreatedBy, ModifidBy, ParentId)
        VALUES (@pageId, @sectionNumber, @sectionUrl,@ArticleImageUrl, @authorname, @tpUserId, @sectionContent, @sectionTitle, 1, GETDATE(), GETDATE(), @tpUserId, @tpUserId, @ParentId);

        SELECT 'Record inserted successfully' AS Result;
    END
    ELSE
    BEGIN
        SELECT 'Page with name ' + @pageName + ' and IsActive = 1 not found' AS Result;
    END
END;





