   Procedure: [dbo].[Usp_tp_InsertPhoneSetting]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_InsertPhoneSetting]    
    @PhoneSettingId BIGINT,    
    @TpUserId BIGINT,    
    @Subject NVARCHAR(255),    
    @Description NVARCHAR(MAX),    
    @DidNumbers NVARCHAR(MAX),    
    @Option NVARCHAR(20),    
    @PriorityId INT,    
    @SourceId INT,    
    @MetaData NVARCHAR(MAX)    
AS    
BEGIN    
    DECLARE @TimeZone NVARCHAR(400), @rowJson NVARCHAR(MAX), @IPAdress NVARCHAR(50), @DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT, @UserId BIGINT, @ParentId BIGINT ,@PhoneSetInsertId BIGINT;   
    
    SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)    
    SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)    
    SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)    
    SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)    
    
   Select @TimeZone = Timezone,@UserId = User_Id,@ParentId = ParentId  
 From tbl_tp_UserLogin Where TpUser_Id = @TpUserId AND IsActive = 1  
    
    IF @Option = 'Insert'    
    BEGIN    
    
        INSERT INTO tbl_tp_PhoneSettings ( Subject, Description, PriorityId, SourceId, ParentId, CreatedOn, CreatedBy, IsActive)    
        VALUES ( @Subject, @Description, @PriorityId, @SourceId, @ParentId, GETDATE(), @UserId, 1); 
		
		    SET @PhoneSetInsertId = SCOPE_IDENTITY();

    DECLARE @DidNumbersTable TABLE (PhoneNumber NVARCHAR(MAX));

    IF CHARINDEX(',', @DidNumbers) = 0
    BEGIN
        INSERT INTO @DidNumbersTable (PhoneNumber)
        VALUES (@DidNumbers);
    END
    ELSE
    BEGIN
        INSERT INTO @DidNumbersTable (PhoneNumber)
        SELECT value
        FROM STRING_SPLIT(@DidNumbers, ', ');
    END
    INSERT INTO tbl_tp_DidNumbers (PhoneNumber, SettingId, NumberType)
    SELECT  PhoneNumber, @PhoneSetInsertId, 'Phone'
    FROM @DidNumbersTable;
    
        SELECT 'Record Inserted Successfully' AS Message    
    
    SET @rowJson  = ( SELECT *  FROM tbl_tp_PhoneSettings  FOR JSON AUTO  ,INCLUDE_NULL_VALUES )                      
                      
          IF @rowJson IS NOT NULL                      
          BEGIN                      
           EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData @User_id = @UserId                      
            ,@Activity_type = 'Inst_PhoneSetting'                      
            ,@ActionType = 'I'                      
            ,@RowJson = @rowJson                      
            ,@Table_name = 'tbl_tp_PhoneSettings'  ,@ip_adress = @IPAdress ,@device_id = @DeviceId,@IsImpersonation = @IsImpersonation,@ImpersonatorId =  @ImpersonatorId               
          END     
    END    
     IF @Option = 'Update'    
    BEGIN    
        UPDATE tbl_tp_PhoneSettings    
        SET    
            DidNumbers = @DidNumbers,    
            Subject = @Subject,    
            Description = @Description,    
            PriorityId = @PriorityId,    
            SourceId = @SourceId,    
            ModifiedBy = @UserId,    
            ModifiedOn = GETDATE()       
           WHERE PhoneSetting_Id = @PhoneSettingId;    
    
        SELECT 'Record Updated Successfully' AS Message    
    
          SET @rowJson  = ( SELECT *  FROM tbl_tp_PhoneSettings Where PhoneSetting_Id = @PhoneSettingId  FOR JSON AUTO  ,INCLUDE_NULL_VALUES )                      
                      
          IF @rowJson IS NOT NULL                      
          BEGIN                      
           EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData @User_id = @UserId                      
            ,@Activity_type = 'Updt_PhoneSetting'                      
            ,@ActionType = 'U'                      
            ,@RowJson = @rowJson                      
            ,@Table_name = 'tbl_tp_PhoneSettings'  ,@ip_adress = @IPAdress ,@device_id = @DeviceId,@IsImpersonation = @IsImpersonation,@ImpersonatorId =  @ImpersonatorId               
          END     
    END    
END; 



