/* ============================================================
   Procedure: [dbo].[Usp_tp_InsertResetPassword]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_tp_InsertResetPassword]
    @userIdentifier NVARCHAR(100)
AS
BEGIN
    Declare  @InsertedTpUserId INT
    Declare @InsertedGuid UNIQUEIDENTIFIER 
    Declare @message NVARCHAR(255)
    DECLARE @tpuserid INT
    DECLARE @ResetGuid NVARCHAR(100)
    DECLARE @ExpiryDate DATETIME
    DECLARE @UserEmail NVARCHAR(100)

    SELECT @tpuserid = TpUser_Id,
           @UserEmail = Email
    FROM tbl_tp_UserLogin
    WHERE LoginName = @userIdentifier
        OR Email = @userIdentifier
        OR Mobile = @userIdentifier

    IF (@tpuserid IS NOT NULL)
    BEGIN

        IF  Not EXISTS (
            SELECT 1
            FROM ResetPassword
            WHERE userid = @tpuserid
                AND expirydate > GETDATE()
                AND isvalid = 1
        )
        BEGIN
            SET @ResetGuid = NEWID()
            SET @ExpiryDate = DATEADD(day, 1, GETDATE())
            INSERT INTO ResetPassword (userid, guid, expirydate, isvalid, email)
            VALUES (@tpuserid, @ResetGuid, @ExpiryDate, 1, @UserEmail)
            SET @InsertedTpUserId = @tpuserid
            SET @InsertedGuid = @ResetGuid
            select @message = 'Password reset link has been sent successfully.';
        END
        ELSE
        BEGIN

            select @message = 'A password reset link has already been sent and is still valid.';
        END
    END
    ELSE
    BEGIN

        select @message = 'User not found.';
    END
    

    SELECT 'Inserted TpUser_Id: ' + CAST(@InsertedTpUserId AS NVARCHAR(10)) AS Result, @InsertedGuid AS Guid, @message AS Message;
END




GO

