CREATE   PROCEDURE [dbo].[Usp_tp_InsertResetPasswordDetails]
    @UserId INT,
    @Guid UNIQUEIDENTIFIER,
    @UserEmail NVARCHAR(100) -- Modify the length as per your field size
AS
BEGIN
    -- Calculate the expiry date: Current date + 1 day
    DECLARE @ExpiryDate DATETIME
    SET @ExpiryDate = DATEADD(DAY, 1, GETDATE())

    -- Insert the record with the calculated expiry date
    INSERT INTO ResetPassword (userid, guid, expirydate, isvalid, email)
    VALUES (@UserId, @Guid, @ExpiryDate, 1, @UserEmail)
END



