/* ============================================================
   Procedure: [dbo].[Usp_tp_InsertSelectedTheme]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_tp_InsertSelectedTheme]
    @TpUserId INT,
    @CreatedBy INT,
    @SelectedTheme NVARCHAR(MAX),
    @MetaData NVARCHAR(MAX)  -- Add the Metadata parameter
AS
BEGIN
    SET NOCOUNT ON;

    -- Extract metadata values
    DECLARE @IPAdress NVARCHAR(50),
            @DeviceId NVARCHAR(50),
            @IsImpersonation BIT,
            @ImpersonatorId INT;

    SET @IPAdress = JSON_VALUE(@MetaData, '$.IPAddress');
    SET @DeviceId = JSON_VALUE(@MetaData, '$.MacAddress');
    SET @IsImpersonation = JSON_VALUE(@MetaData, '$.IsImpersonation');
    SET @ImpersonatorId = JSON_VALUE(@MetaData, '$.ImpersonatorId');

    -- Insert the current date
    DECLARE @CreatedDate DATETIME = GETDATE();

    -- Check if the user has already selected a theme
    DECLARE @ExistingThemeCount INT;
    SELECT @ExistingThemeCount = COUNT(*) FROM tbl_tp_UserThemes WHERE UserId = @TpUserId;

    IF @ExistingThemeCount > 0
    BEGIN
        -- Update the existing theme
        UPDATE tbl_tp_UserThemes
        SET ThemeName = @SelectedTheme,
            ModifiedDate = @CreatedDate
        WHERE UserId = @TpUserId;
    END
    ELSE
    BEGIN
        -- Insert a new theme for the user
        INSERT INTO tbl_tp_UserThemes (ThemeName, IsActive, ModifiedDate, UserId)
        VALUES (@SelectedTheme, 1, @CreatedDate, @TpUserId);
    END;

    -- You can perform additional operations or validations if needed.

    -- Return the result (optional)
    SELECT 'Success' AS Result;

    -- Log metadata or perform additional actions if needed
    -- Example: Logging an audit record
      EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData     
        @User_id = @CreatedBy,
        @Activity_type = 'InsertSelectedTheme',
        @ActionType = 'I',
        @RowJson = NULL,
        @Table_name = '[tbl_tp_UserThemes]',
        @ip_adress = @IPAdress,
        @device_id = @DeviceId,
        @IsImpersonation = @IsImpersonation,
        @ImpersonatorId = @ImpersonatorId;
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_InsertSignupdetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_tp_InsertSignupdetails]
    @Domain NVARCHAR(200),
    @Name NVARCHAR(200),
    @Email NVARCHAR(200),
    @Mobile NVARCHAR(20),
    @Country NVARCHAR(200),
    @Timezone NVARCHAR(400),
    @Password NVARCHAR(200)
AS
BEGIN
    SET NOCOUNT ON;
    BEGIN TRY
		--DECLARE 
	 --   @Domain  NVARCHAR(200) = N'https://TicketPortalKit19.com/kmukesh343',
		--@Name  NVARCHAR(200) = N'Shusabhsam',
		--@Email NVARCHAR(200) = N'giubaasas51@gmail.com',
		--@Mobile NVARCHAR(20) = N'79999008009',
		--@Country NVARCHAR(200)= N'India',
		--@Timezone NVARCHAR(400)= N'IST',
		--@Password NVARCHAR(200) = N'@123shubhaM'
        DECLARE @UserExists INT, @tpuserid BIGINT;
        DECLARE @ParentId BIGINT;
        DECLARE @SourceId BIGINT;

        BEGIN
            DECLARE @SubDomain NVARCHAR(200);
            SET @SubDomain = SUBSTRING(@Domain, LEN(@Domain) - CHARINDEX('/', REVERSE(@Domain)) + 2, LEN(@Domain));
            DECLARE @FullPortalName NVARCHAR(MAX) = @Domain + @SubDomain;

            IF EXISTS (
                SELECT 1
                FROM tbl_tp_Portalsetting WITH (NOLOCK)
                WHERE @SubDomain = PortalName
                GROUP BY PortalName
                HAVING COUNT(DISTINCT ParentId) > 1
            )
            BEGIN
                SELECT TOP 1 @ParentId = ParentId
                FROM tbl_tp_Portalsetting WITH (NOLOCK)
                WHERE @FullPortalName = @Domain + PortalName
                ORDER BY ParentId;
            END
            ELSE
            BEGIN
                SELECT TOP 1 @ParentId = ParentId
                FROM tbl_tp_Portalsetting WITH (NOLOCK)
                WHERE @SubDomain = PortalName and IsActive=1;
            END
--			 IF @ParentId IS NULL
-- BEGIN
--    SELECT @ParentId = c.ParentId
--    FROM tbl_tp_client_domain c WITH (NOLOCK)
--    WHERE REPLACE(@Domain, 'www.', '') LIKE '%' + REPLACE(c.ClientDomain, 'www.', '') + '%';
--END;

--IF @ParentId IS NULL
--BEGIN
--    SELECT @ParentId = c.ParentId
--    FROM tbl_tp_client_domain c WITH (NOLOCK)
--    WHERE REPLACE(@Domain, 'https://', '') LIKE '%' + REPLACE(c.ClientDomain, 'https://', '') + '%'
--        OR REPLACE(@Domain, 'http://', '') LIKE '%' + REPLACE(c.ClientDomain, 'http://', '') + '%';
--END;

--IF @ParentId IS NULL
--BEGIN
--    SELECT @ParentId = c.ParentId
--    FROM tbl_tp_client_domain c WITH (NOLOCK)
--    WHERE REPLACE(REPLACE(@Domain, 'https://', ''), 'http://', '') LIKE '%' + REPLACE(REPLACE(c.ClientDomain, 'https://', ''), 'http://', '') + '%';
--END;
            IF @ParentId IS NOT NULL
            BEGIN
                IF EXISTS (
                    SELECT 1
                    FROM tbl_tp_userlogin
                    WHERE (Email = @Email OR Mobile = @Mobile OR LoginName = @Name)
                        AND ParentId = @ParentId
                )
                BEGIN
                    SELECT 'User already exists' AS Result;
                    RETURN;
                END

                IF NOT EXISTS (SELECT * FROM Usersourcesettings (NOLOCK) WHERE UserID = @ParentId AND IsActive = 1 AND name = 'ServiceTicketSignup')
                BEGIN
                    PRINT 'A';
                    INSERT INTO Usersourcesettings (name, UserId, IsEditable, IsActive, CreatedDate, ModifiedDate, ModifiedBy)
                    VALUES ('ServiceTicketSignup', @ParentId, 0, 1, GETDATE(), NULL, @ParentId);
                    SELECT @SourceId = SCOPE_IDENTITY();
                END
                ELSE
                BEGIN
                    PRINT 'B';
                    SELECT @SourceId = SourceId FROM Usersourcesettings (NOLOCK) WHERE UserID = @ParentId AND IsActive = 1 AND name = 'ServiceTicketSignup';
                END

                DECLARE @LeadId INT = 0;
                SELECT @LeadId = ID
                FROM UserLeads WITH (NOLOCK)
                WHERE ParentID = @ParentId AND ((@Email IN (EmailID, EmailID1, EmailID2)) OR (@Mobile IN (MobileNo, MobileNo1, MobileNo2)))

                IF @LeadId > 0
                BEGIN
                    INSERT INTO tbl_tp_userlogin (EntityID, EntityName, ParentID, Pwd, LoginName, Email, Mobile, Country_Code, Timezone)
                    VALUES (@LeadId, 'Lead', @ParentId, @Password, @Name, @Email, @Mobile, @Country, @Timezone);

                    SELECT 'User registered successfully.';
                END
                ELSE
                BEGIN
                    DECLARE @EnquiryId INT = 0;
                    SELECT @EnquiryId = EnquiryID
                    FROM UserEnquiry WITH (NOLOCK)
                    WHERE ParentID = @ParentId AND ((@Email IN (EmailID, EmailID1, EmailID2)) OR (@Mobile IN (MobileNo, MobileNo1, MobileNo2)))

                    IF @EnquiryId > 0
                    BEGIN
                        INSERT INTO tbl_tp_userlogin (EntityID, EntityName, ParentID, Pwd, Email, Mobile, Country_Code, Timezone, LoginName)
                        VALUES (@EnquiryId, 'Enquiry', @ParentId, @Password, @Email, @Mobile, @Country, @Timezone, @Name);

                        SELECT 'User inserted.';
                    END
                    ELSE
                    BEGIN
                        DECLARE @Leadno BIGINT = ISNULL((SELECT MAX(LeadNo) FROM UserLeads (NOLOCK) WHERE ParentID = @ParentId), 0) + 1;
                        SET CONTEXT_INFO 0x55555;

                        INSERT INTO UserLeads (ParentID, PersonName, MobileNo, EmailID, CountryCode, AssignedTo, SourceName, LeadNo)
                        VALUES (@ParentId, @Name, @Mobile, @Email, @Country, @ParentId, @SourceId, @Leadno);

                        SELECT @LeadId = SCOPE_IDENTITY();
                        SET CONTEXT_INFO 0x;

                        IF @LeadId IS NOT NULL
                        BEGIN
                            INSERT INTO tbl_tp_userlogin (EntityID, EntityName, ParentID, Pwd, LoginName, Email, Mobile, Country_Code, Timezone, IsActive)
                            VALUES (@LeadId, 'Lead', @ParentId, @Password, @Name, @Email, @Mobile, @Country, @Timezone, 1);
                            SET @tpuserid = SCOPE_IDENTITY();
                            --return @tpuserid
                            PRINT '@tpuserid: ' + CAST(@tpuserid AS VARCHAR);
                            SELECT 'User registered successfully.';
                        END
                    END
                END
            END
            ELSE
            BEGIN
                PRINT 'No valid ParentID found. Additional actions can be implemented.';
				 select 'Registration failed .';
            END
        END
    END TRY
    BEGIN CATCH
        DECLARE @ErrorMessage NVARCHAR(4000);
        DECLARE @ErrorSeverity INT;
        DECLARE @ErrorState INT;

        SELECT
            @ErrorMessage = ERROR_MESSAGE(),
            @ErrorSeverity = ERROR_SEVERITY(),
            @ErrorState = ERROR_STATE();
        PRINT 'Error Message: ' + @ErrorMessage;
    END CATCH
END





GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_InsertTicketFieldDisplayJson]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

        
 CREATE   PROCEDURE [dbo].[Usp_tp_InsertTicketFieldDisplayJson]              
@DisplayJson NVARCHAR(MAX),              
@ParentID BIGINT,              
@Mode VARCHAR(20) = NULL,              
@Default NVARCHAR(MAX)=NULL,              
@IsMan BIT =0,     
@IsRequired BIT =0,   
@IsActive BIT =0,   
@Choices  NVARCHAR(MAX)=NULL,        
@CustomField NVARCHAR(MAX)=NULL,      
@OldCustomField NVARCHAR(MAX)= NULL,  
@ToolTip NVARCHAR(MAX)= NULL  
  
AS              
BEGIN              
DECLARE @data Nvarchar(MAX)              
   DROP TABLE IF EXISTS #temp                        
   CREATE TABLE #temp (                        
    FieldName NVARCHAR(max),                        
    DataType NVARCHAR(Max),               
    DefaultValue NVARCHAR(Max),              
    Mandatory bit,    
    Required bit,  
    Active bit,  
    FieldType NVARCHAR(Max),              
    MaxValue NVARCHAR(Max),              
    MinValue NVARCHAR(MAX),              
    Choices NVARCHAR (MAX),  
    ToolTipValue NVARCHAR (MAX)  
    )                 
 IF @Mode='Save'              
 BEGIN              
  IF NOT EXISTS (SELECT 1 FROM tbL_tp_TicketCustomFieldDisplayJson WHERE ParentId=@ParentID)              
  BEGIN              
   Insert into tbL_tp_TicketCustomFieldDisplayJson (ParentId,DisplayJson) Values (@ParentID,@DisplayJson)              
  END              
  ELSE               
  BEGIN              
   select @data=DisplayJson from tbL_tp_TicketCustomFieldDisplayJson where ParentId= @ParentID                     
     INSERT INTO #temp (               
     FieldName                
     ,DataType                
     ,DefaultValue               
     ,Mandatory  
     ,Required  
     ,Active  
     ,FieldType                
     ,MaxValue                
     ,MinValue                
     ,Choices   
     ,ToolTipValue  
     )                        
     SELECT   FieldName                
     ,DataType                
     ,DefaultValue               
     ,Mandatory   
     ,Required  
     ,Active  
     ,FieldType                
     ,MaxValue                
     ,MinValue                
     ,Choices   
  ,ToolTipValue  
   FROM OPENJSON(@data)                        
   with (                        
    FieldName  NVARCHAR(max)   '$.FieldName',                        
    DataType  NVARCHAR(Max) '$.DataType',               
    DefaultValue NVARCHAR(Max) '$.DefaultValue',              
    Mandatory  NVARCHAR(Max) '$.Mandatory',     
    Required  NVARCHAR(Max) '$.Required',  
    Active  NVARCHAR(Max) '$.Active',  
    FieldType  NVARCHAR(Max) '$.FieldType',              
    MaxValue  NVARCHAR(Max) '$.MaxValue',              
    MinValue  NVARCHAR(MAX) '$.MinValue',              
    Choices  NVARCHAR(MAX)   '$.Choices',  
    ToolTipValue  NVARCHAR(MAX)   '$.ToolTipValue'  
   )                  
   UNION ALL              
   SELECT  
      FieldName                
     ,DataType                
     ,DefaultValue               
     ,Mandatory  
     ,Required  
     ,Active  
     ,FieldType                
     ,MaxValue                
     ,MinValue                
     ,Choices  
    ,ToolTipValue  
  
   FROM OPENJSON(@displayJson)                        
   with (                        
    FieldName  NVARCHAR(max)   '$.FieldName',                        
    DataType  NVARCHAR(Max) '$.DataType',               
    DefaultValue NVARCHAR(Max) '$.DefaultValue',              
    Mandatory  NVARCHAR(Max) '$.Mandatory',   
     Required  NVARCHAR(Max) '$.Required',  
    Active  NVARCHAR(Max) '$.Active',  
    FieldType  NVARCHAR(Max) '$.FieldType',              
    MaxValue  NVARCHAR(Max) '$.MaxValue',              
    MinValue  NVARCHAR(MAX) '$.MinValue',              
    Choices  NVARCHAR(MAX)   '$.Choices' ,  
    ToolTipValue  NVARCHAR(MAX)   '$.ToolTipValue'  
   )              
              
   SET @displayJson =(Select * from #temp for json Auto, INCLUDE_NULL_VALUES)              
   UPDATE tbL_tp_TicketCustomFieldDisplayJson SET DisplayJson=@displayJson WHERE ParentId=@parentID              
  END              
 END              
 Else IF @mode='Update'              
 BEGIN              
  select @data=DisplayJson from tbL_tp_TicketCustomFieldDisplayJson where ParentId=  @parentid                     
    INSERT INTO #temp (               
     FieldName                
     ,DataType                
     ,DefaultValue               
     ,Mandatory   
  ,Required  
  ,Active  
     ,FieldType                
     ,MaxValue                
     ,MinValue                
     ,Choices    
     ,ToolTipValue
     )   
    
     SELECT   FieldName                
     ,DataType                
     ,DefaultValue               
     ,Mandatory   
  ,Required  
  ,Active  
     ,FieldType                
     ,MaxValue                
     ,MinValue                
     ,Choices  
  ,ToolTipValue  
  
     FROM OPENJSON(@data)                        
     WITH (                        
    FieldName  NVARCHAR(max)   '$.FieldName',                        
    DataType  NVARCHAR(Max) '$.DataType',               
    DefaultValue NVARCHAR(Max) '$.DefaultValue',              
    Mandatory  NVARCHAR(Max) '$.Mandatory',  
 Required  NVARCHAR(Max) '$.Required',  
 Active  NVARCHAR(Max) '$.Active',             
    FieldType  NVARCHAR(Max) '$.FieldType',              
    MaxValue  NVARCHAR(Max) '$.MaxValue',              
    MinValue  NVARCHAR(MAX) '$.MinValue',              
    Choices  NVARCHAR(MAX)   '$.Choices' ,  
 ToolTipValue  NVARCHAR(MAX)   '$.ToolTipValue'  
   )                 
   --select * from #temp        
  if @oldcustomField is not null       
  begin      
   update #temp set FieldName=@customField where FieldName=@oldcustomField              
  end      
  if @default is not null              
  begin              
   update #temp set DefaultValue=@default where FieldName=@customField              
  end              
  if @IsMan =0              
  begin              
   update #temp set Mandatory=@IsMan where FieldName=@customField              
  end    
    if @IsRequired =0              
  begin              
   update #temp set Required=@IsRequired where FieldName=@customField              
  end   
    if @IsActive =0              
  begin              
   update #temp set Active=@IsActive where FieldName=@customField              
  end   
   if @ToolTip is not null       
  begin      
   update #temp set ToolTipValue=@ToolTip where FieldName=@customField              
  end  
  if @choices is not null         
   update #temp set Choices=@choices where FieldName=@customField           
  SET @displayJson =(Select * from #temp for json Auto, INCLUDE_NULL_VALUES)              
  UPDATE tbL_tp_TicketCustomFieldDisplayJson SET DisplayJson=@displayJson WHERE ParentId=@ParentID              
 END              
                
END 



