/* ============================================================
   Procedure: [dbo].[Usp_tp_InsertUpdateBusinessHours]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_InsertUpdateBusinessHours]    
    @Option NVARCHAR(10),   
    @BusinessHoursId BIGINT,  
    @Name NVARCHAR(255),    
    @Description NVARCHAR(255),    
    @BusinessTimeZone NVARCHAR(50),    
    @BusinessHoursType INT,    
    @SundayStartTime TIME,    
    @SundayEndTime TIME,    
    @MondayStartTime TIME,    
    @MondayEndTime TIME,    
    @TuesdayStartTime TIME,    
    @TuesdayEndTime TIME,    
    @WednesdayStartTime TIME,    
    @WednesdayEndTime TIME,    
    @ThursdayStartTime TIME,    
    @ThursdayEndTime TIME,    
    @FridayStartTime TIME,    
    @FridayEndTime TIME,    
    @SaturdayStartTime TIME,    
    @SaturdayEndTime TIME,    
    @HolidaysType NVARCHAR(30),  
    @HolidaysData NVARCHAR(MAX),  
    @TpUserId BIGINT,  
    @MetaData NVARCHAR(MAX)  
AS    
BEGIN    
    DECLARE @TimeZone NVARCHAR(400),    
            @IPAdress NVARCHAR(50),    
            @DeviceId NVARCHAR(50),    
            @IsImpersonation BIT,    
            @ImpersonatorId INT,  
            @InsertedId BIGINT,  
            @UserID BIGINT,  
            @ParentID BIGINT,  
      @rowJson NVARCHAR(MAX);  
  
    SELECT @ParentID = ParentId, @TimeZone = TimeZone, @UserID = User_Id   
    FROM tbl_tp_UserLogin (NOLOCK)    
    WHERE TpUser_Id = @TpUserId;  
  
    SET @IPAdress = JSON_VALUE(@MetaData, '$.IPAddress');  
    SET @DeviceId = JSON_VALUE(@MetaData, '$.MacAddress');  
    SET @IsImpersonation = JSON_VALUE(@MetaData, '$.IsImpersonation');  
    SET @ImpersonatorId = JSON_VALUE(@MetaData, '$.ImpersonatorId');  
  
    IF @Option = 'Insert'  
    BEGIN  
  
        INSERT INTO tbl_tp_BusinessHours (Name, Description, TimeZone, BusinessHoursType, SundayStartTime,   
                                    SundayEndTime, MondayStartTime, MondayEndTime, TuesdayStartTime,   
            TuesdayEndTime, WednesdayStartTime, WednesdayEndTime, ThursdayStartTime,   
                                          ThursdayEndTime, FridayStartTime, FridayEndTime, SaturdayStartTime,  
            SaturdayEndTime, ParentID,IsActive, CreatedDate, CreatedBy)    
  
                                          VALUES (@Name, @Description, @BusinessTimeZone, @BusinessHoursType,  
            @SundayStartTime, @SundayEndTime, @MondayStartTime, @MondayEndTime,  
            @TuesdayStartTime, @TuesdayEndTime, @WednesdayStartTime, @WednesdayEndTime,  
            @ThursdayStartTime, @ThursdayEndTime, @FridayStartTime, @FridayEndTime,   
            @SaturdayStartTime, @SaturdayEndTime, @ParentID, 1, GETDATE(), @UserID);    
  
           SET @InsertedId = SCOPE_IDENTITY();   
  
    IF @HolidaysType IS NOT NULL  
    BEGIN  
         
  
INSERT INTO tbl_tp_CreateHolidays (HolidayName, HolidayDate, HolidayType, BusinessHours_Id, IsActive, ParentId, CreatedBy, CreatedOn, ModifiedBy, ModifiedOn)  
SELECT j.HolidayName, j.HolidayDate, j.HolidayType,@InsertedId,1,@ParentID,@UserID,GETDATE(),NULL,NULL  
FROM OPENJSON(@HolidaysData)  
WITH (  
    HolidayName VARCHAR(255),  
    HolidayDate DATE,  
    HolidayType VARCHAR(50)  
) AS j;  
  
  
    END  

	Select 'Saved' as result
  
    
    SET @rowJson = (SELECT * FROM tbl_tp_BusinessHours FOR JSON AUTO, INCLUDE_NULL_VALUES);    
        
    IF @rowJson IS NOT NULL    
    BEGIN    
        EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData    
            @User_id = @UserId,    
            @Activity_type = 'Inst_BusinessHours',    
            @ActionType = 'I',    
            @RowJson = NULL,    
            @Table_name = 'tbl_tp_BusinessHours',    
            @ip_adress = @IPAdress,    
            @device_id = @DeviceId,    
            @IsImpersonation = @IsImpersonation,    
            @ImpersonatorId = @ImpersonatorId;    
    END    
  
    END  
  
    IF @Option = 'Update'  
    BEGIN  
        IF EXISTS (SELECT 1 FROM tbl_tp_BusinessHours WHERE BHid = @BusinessHoursId)    
        BEGIN     
            UPDATE tbl_tp_BusinessHours    
            SET    
                Name = @Name,  
                Description = @Description,    
                TimeZone = @BusinessTimeZone,    
                BusinessHoursType = @BusinessHoursType,    
                SundayStartTime = @SundayStartTime,    
                SundayEndTime = @SundayEndTime,    
                MondayStartTime = @MondayStartTime,    
                MondayEndTime = @MondayEndTime,    
                TuesdayStartTime = @TuesdayStartTime,    
                TuesdayEndTime = @TuesdayEndTime,    
                WednesdayStartTime = @WednesdayStartTime,    
                WednesdayEndTime = @WednesdayEndTime,    
                ThursdayStartTime = @ThursdayStartTime,    
                ThursdayEndTime = @ThursdayEndTime,    
                FridayStartTime = @FridayStartTime,    
                FridayEndTime = @FridayEndTime,    
                SaturdayStartTime = @SaturdayStartTime,    
                SaturdayEndTime = @SaturdayEndTime,    
                ParentID = @ParentID,    
                CreatedDate = GETDATE() ,   
                CreatedBy = @UserID    
                WHERE BHid = @BusinessHoursId  

IF @HolidaysType IS NOT NULL
BEGIN
    UPDATE h
SET
    h.HolidayName = j.HolidayName,
    h.HolidayDate = j.HolidayDate,
    h.HolidayType = j.HolidayType,
    h.BusinessHours_Id = @InsertedId,
    h.IsActive = 1,
    h.ParentId = @ParentID,
    h.CreatedBy = @UserID,
    h.CreatedOn = GETDATE(),
    h.ModifiedBy = NULL,
    h.ModifiedOn = NULL
FROM tbl_tp_CreateHolidays h
JOIN OPENJSON(@HolidaysData) WITH (
    HolidayName VARCHAR(255),
    HolidayDate DATE,
    HolidayType VARCHAR(50)
) AS j ON j.HolidayName = h.HolidayName; 


END

  
                SET @rowJson = (SELECT * FROM tbl_tp_BusinessHours FOR JSON AUTO, INCLUDE_NULL_VALUES);    
        
    IF @rowJson IS NOT NULL    
    BEGIN    
        EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData    
            @User_id = @UserId,    
            @Activity_type = 'Updt_BusinessHours',    
            @ActionType = 'U',    
            @RowJson = NULL,    
            @Table_name = 'tbl_tp_BusinessHours',    
            @ip_adress = @IPAdress,    
            @device_id = @DeviceId,    
            @IsImpersonation = @IsImpersonation,    
            @ImpersonatorId = @ImpersonatorId;    
    END    
        
         Select 'Record Updated Successfully !' result
       
        END    
    END         
END  



GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_InsertUpdateDispatchrRule]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

            
CREATE   PROCEDURE [dbo].[Usp_tp_InsertUpdateDispatchrRule]                              
(                              
  @DispatchrId Bigint,                              
  @ParentId Bigint,                              
  @RuleName Nvarchar(100),                            
  @Description Nvarchar(200),                     
  @SequenceNo Bigint,                                            
  @Option Nvarchar(50),                     
  @ConditionValues Nvarchar(max),                
  @ActionValueId Int,  
  @ServiceId Int,  
  @MetaData nvarchar(200)                          
)                              
as                              
Begin                            
                          
                                    
DECLARE @TimeZone nvarchar (400)  ,@rowJson NVARCHAR(MAX)  , @IPAdress NVARCHAR(50),@DeviceId NVARCHAR(50),@IsImpersonation BIT ,@ImpersonatorId INT,@UserId BIGINT ,@tpuserid BIGINT              
Select @UserId = User_Id,@TimeZone = TimeZone, @tpuserid= tpuser_id From tbl_tp_UserLogin (noLock) Where  ParentId  = @ParentId               
                                    
 SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)                            
 SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)                            
 SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)                            
 SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)                          
                          
 if(@Option = 'Insert')                              
 Begin                              
 if(NOT EXISTS (select 'x' from tbl_tp_DispatcherMaster where ParentID = @ParentID and Rule_Name = @RuleName ))              
 Begin            
                 
SELECT @SequenceNo = ISNULL(MAX(SequenceNo), 0) FROM tbl_tp_DispatcherMaster     
          
        
  INSERT INTO tbl_tp_DispatcherMaster(ParentID,Rule_Name,Rule_Description,Active,SequenceNo,CreatedBy,CreatedDate,IsEnabled)              
  values(@ParentId,@RuleName,@Description,1, @SequenceNo+1,@tpuserid,GETDATE(),1)              
              
  Set @DispatchrId= SCOPE_IDENTITY()              
                                
INSERT INTO dbo.tbl_tp_DispatcherCondition (Disptchr_Id, FieldName, Operator, Value, Conjunction, SequenceNo, Active, ParentId, CreatedBy, CreatedDate)  
SELECT @DispatchrId,   
       COALESCE(json.FieldName, 'NA'),    
       COALESCE(json.Operator, '0'),    
       COALESCE(json.Value, 'NA'),   
       COALESCE(json.Conjunction, 'OR'),  
       @SequenceNo + 1,   
       1,   
       @ParentId,   
       @tpuserid,   
       GETDATE()  
FROM OPENJSON(@ConditionValues, '$.ConditionValues') WITH (  
    FieldName nvarchar(100),  
    Operator nvarchar(100),  
    Value nvarchar(50),  
 Conjunction nvarchar(50)  
) AS json;  
  
               
                    
    
BEGIN TRY  
    INSERT INTO dbo.tbl_tp_DispatcherAction (Disptchr_Id, Action_Id, Action_Value, SequenceNo, Active, ParentId, createdBy, CreatedDate)  
    VALUES (@DispatchrId, @ActionValueId, @ServiceId, @SequenceNo+1, 1, @ParentId, @tpuserid, GETDATE())  
END TRY  
BEGIN CATCH  
    PRINT 'An error occurred: ' + ERROR_MESSAGE();  
END CATCH  
                   
  Select 'Record Saved Successfully !' resp    
    
   SET @rowJson  = ( SELECT *  FROM tbl_tp_DispatcherMaster  FOR JSON AUTO  ,INCLUDE_NULL_VALUES )                                    
                                    
     IF @rowJson IS NOT NULL                                    
          BEGIN                                    
           EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData @User_id = @UserId                                    
            ,@Activity_type = 'Inst_dispatchermaster'                                    
            ,@ActionType = 'I'                                    
            ,@RowJson = @rowJson                                    
            ,@Table_name = 'tbl_tp_DispatcherMaster'  ,@ip_adress = @IPAdress ,@device_id = @DeviceId,@IsImpersonation = @IsImpersonation,@ImpersonatorId =  @ImpersonatorId                             
          END                          
                                  
  End                              
 else                              
   Begin                                    
    select 'Dispatchr Rule Already Exists'                              
    End                           
                         
                         
   end                               
IF (@Option = 'Update')
BEGIN

    IF (NOT EXISTS (SELECT 'x' FROM tbl_tp_DispatcherMaster WHERE ParentID = @ParentID AND Rule_Name = @RuleName AND Disptchr_Id <> @DispatchrId))
    BEGIN
        BEGIN TRANSACTION;

        BEGIN TRY
            UPDATE tbl_tp_DispatcherMaster
            SET
                ParentID = @ParentID,
                Rule_Description = @Description,
                Rule_Name = @RuleName,
                ModifiedBy = @tpuserid,
                ModifiedDate = GETDATE()
                WHERE Disptchr_Id = @DispatchrId;

 DELETE FROM dbo.tbl_tp_DispatcherCondition WHERE Disptchr_Id = @DispatchrId;
INSERT INTO dbo.tbl_tp_DispatcherCondition (Disptchr_Id, FieldName, Operator, Value, Conjunction, SequenceNo, Active, ParentId, CreatedBy, CreatedDate)  
SELECT @DispatchrId,   
       COALESCE(json.FieldName, 'NA'),    
       COALESCE(json.Operator, '0'),    
       COALESCE(json.Value, 'NA'),   
       COALESCE(json.Conjunction, 'OR'),  
       @SequenceNo + 1,   
       1,   
       @ParentId,   
       @tpuserid,   
       GETDATE()  
FROM OPENJSON(@ConditionValues, '$.ConditionValues') WITH (  
    FieldName nvarchar(100),  
    Operator nvarchar(100),  
    Value nvarchar(50),  
 Conjunction nvarchar(50)  
) AS json;  




            UPDATE da
            SET
                Action_Id = @ActionValueId,
                Action_Value = @ServiceId,
                SequenceNo = @SequenceNo + 1,
                Active = 1,
                ParentId = @ParentId,
                createdBy = @tpuserid,
                CreatedDate = GETDATE()
            FROM dbo.tbl_tp_DispatcherAction AS da
            WHERE da.Disptchr_Id = @DispatchrId;

            COMMIT;
            SELECT 'Records Updated Succesfully' AS resp; 
        END TRY
        BEGIN CATCH
            ROLLBACK;
            PRINT 'An error occurred: ' + ERROR_MESSAGE();
        END CATCH;

        SET @rowJson = (
            SELECT *
            FROM tbl_tp_DispatcherMaster
            FOR JSON AUTO, INCLUDE_NULL_VALUES
        );

        IF @rowJson IS NOT NULL
        BEGIN
            EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData
                @User_id = @UserId,
                @Activity_type = 'Updt_dispatchermaster',
                @ActionType = 'U',
                @RowJson = @rowJson,
                @Table_name = 'tbl_tp_DispatcherMaster',
                @ip_adress = @IPAdress,
                @device_id = @DeviceId,
                @IsImpersonation = @IsImpersonation,
                @ImpersonatorId = @ImpersonatorId;
        END
    END
    ELSE
    BEGIN
        SELECT 'Dispatchr Rule Already Exists' AS resp;
    END
END
                            
                           
                         
                          
End 



GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_InsertUpdateEmailSettings]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_InsertUpdateEmailSettings]
    @Option NVARCHAR(10),
    @EmailSettingId INT,
    @Name NVARCHAR(255),
    @SupportEmail NVARCHAR(255),
    @AssignToGroup NVARCHAR(50),
    @LinkToProduct NVARCHAR(50),
    @MailServer NVARCHAR(50),
    @UseMailServerFor NVARCHAR(50) = NULL,
    @MailService NVARCHAR(50),
    @IncomingMailServerDomain NVARCHAR(255),
    @IncomingIMAPPort INT,
    @IncomingUseSSL BIT,
    @IncomingDeleteEmails BIT,
    @IncomingAuthentication NVARCHAR(50),
    @IncomingUsername NVARCHAR(255),
    @IncomingPassword NVARCHAR(255),
    @OutgoingMailServerDomain NVARCHAR(255),
    @OutgoingIMAPPort INT,
    @OutgoingUseSSL BIT,
    @OutgoingDeleteEmails BIT,
    @OutgoingAuthentication NVARCHAR(50),
    @OutgoingUsername NVARCHAR(255),
    @OutgoingPassword NVARCHAR(255),
    @TpUserId BIGINT,
    @MetaData NVARCHAR(MAX)
AS
BEGIN
    DECLARE @TimeZone NVARCHAR(400),
            @IPAdress NVARCHAR(50),
            @DeviceId NVARCHAR(50),
            @IsImpersonation BIT,
            @ImpersonatorId INT,
            @InsertedId INT,
            @UserID BIGINT,
            @ParentID BIGINT,
            @rowJson NVARCHAR(MAX);

    SELECT @ParentID = ParentId, @TimeZone = TimeZone, @UserID = User_Id
    FROM tbl_tp_UserLogin (NOLOCK)
    WHERE TpUser_Id = @TpUserId;

    SET @IPAdress = JSON_VALUE(@MetaData, '$.IPAddress');
    SET @DeviceId = JSON_VALUE(@MetaData, '$.MacAddress');
    SET @IsImpersonation = JSON_VALUE(@MetaData, '$.IsImpersonation');
    SET @ImpersonatorId = JSON_VALUE(@MetaData, '$.ImpersonatorId');

    IF @MailServer = 'kit19'
    BEGIN
        IF @Option = 'Insert'
        BEGIN
            IF EXISTS (SELECT 1 FROM tbl_tp_EmailSetting WHERE [Name] = @Name AND [SupportEmail] = @SupportEmail)
            BEGIN
                SELECT 'Record Exist' AS Result;
            END
            ELSE
            BEGIN
                INSERT INTO tbl_tp_EmailSetting (
                    [Name], [SupportEmail], [AssignToGroup], [LinkToProduct], [ParentID], [IsActive], [CreatedDate], [CreatedBy],[MailServer]
                )
                VALUES (
                    @Name, @SupportEmail, @AssignToGroup, @LinkToProduct, @ParentID, 1, GETDATE(), @UserID,@MailServer
                );

                SET @InsertedId = SCOPE_IDENTITY();

                IF @InsertedId IS NOT NULL
                BEGIN
                    SELECT 'Saved' AS Result, @InsertedId AS EmailSettingId;
                END;
            END;
        END;
        ELSE IF @Option = 'Update'
        BEGIN
            UPDATE tbl_tp_EmailSetting
            SET
                [Name] = @Name,
                [SupportEmail] = @SupportEmail,
                [AssignToGroup]= @AssignToGroup,
				[LinkToProduct]=@LinkToProduct,
				[ParentID]= @ParentID,
				[IsActive]= 1,
				[CreatedDate]= GETDATE(),
				[CreatedBy]=@UserID,
				[MailServer]=@MailServer
            WHERE ESid = @EmailSettingId;

            SELECT 'Updated' AS Result, @EmailSettingId AS ESid;
        END;
    END
    ELSE
    BEGIN
        IF @Option = 'Insert'
        BEGIN
            IF EXISTS (SELECT 1 FROM tbl_tp_EmailSetting WHERE [Name] = @Name AND [SupportEmail] = @SupportEmail)
            BEGIN
                SELECT 'Record Exist' AS Result;
            END
            ELSE
            BEGIN
                INSERT INTO tbl_tp_EmailSetting (
                    [Name], [SupportEmail], [AssignToGroup], [LinkToProduct], [MailServer], [UseMailServerFor], [MailService],
                    [IncomingMailServerDomain], [IncomingIMAPPort], [IncomingUseSSL], [IncomingDeleteEmails], [IncomingAuthentication],
                    [IncomingUsername], [IncomingPassword], [OutgoingMailServerDomain], [OutgoingIMAPPort], [OutgoingUseSSL], [OutgoingDeleteEmails],
                    [OutgoingAuthentication], [OutgoingUsername], [OutgoingPassword], [ParentID], [IsActive], [CreatedDate], [CreatedBy]
                )
                VALUES (
                    @Name, @SupportEmail, @AssignToGroup, @LinkToProduct, @MailServer, 
                    @UseMailServerFor, @MailService, @IncomingMailServerDomain, @IncomingIMAPPort, @IncomingUseSSL, 
                    @IncomingDeleteEmails, @IncomingAuthentication, @IncomingUsername, @IncomingPassword, 
                    @OutgoingMailServerDomain, @OutgoingIMAPPort, @OutgoingUseSSL, @OutgoingDeleteEmails, 
                    @OutgoingAuthentication, @OutgoingUsername, @OutgoingPassword, @ParentID, 1, GETDATE(), @UserID
                );

                SET @InsertedId = SCOPE_IDENTITY();

                IF @InsertedId IS NOT NULL
                BEGIN
                    SELECT 'Saved' AS Result, @InsertedId AS EmailSettingId;
                END;
            END;
        END;
        ELSE IF @Option = 'Update'
