/* ============================================================
   Procedure: [dbo].[Usp_tp_InsertUpdateGroupMasterDetail]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_InsertUpdateGroupMasterDetail]
(
    @GroupID BIGINT,
    @ParentID BIGINT,
    @Group_Name NVARCHAR(100),
    @Group_Desc NVARCHAR(200),
    @Option NVARCHAR(50),
    @UserID BIGINT,
    @MetaData NVARCHAR(200)
)
AS
BEGIN

    DECLARE @TimeZone NVARCHAR(400),
            @rowJson NVARCHAR(MAX),
            @IPAdress NVARCHAR(50),
            @DeviceId NVARCHAR(50),
            @IsImpersonation BIT,
            @ImpersonatorId INT

    SELECT @ParentID = ParentId, @TimeZone = TimeZone FROM User_Detail (NOLOCK) WHERE User_Id = @UserID

    SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)
    SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)
    SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)
    SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)

    IF @Option = 'Insert'
    BEGIN
        IF NOT EXISTS (SELECT 'x' FROM tbl_tp_GroupMaster WHERE ParentID = @ParentID AND GroupName = @Group_Name)
        BEGIN
            INSERT INTO tbl_tp_GroupMaster (ParentID, GroupName, GroupDesc, Active,CreatedDate)
            VALUES (@ParentID, @Group_Name, @Group_Desc, 1,GETDATE())

            SELECT 'Record Saved'

            SET @rowJson = (SELECT * FROM tbl_tp_GroupMaster FOR JSON AUTO, INCLUDE_NULL_VALUES)

            IF @rowJson IS NOT NULL
            BEGIN
                EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData
                    @User_id = @UserId,
                    @Activity_type = 'Add_Groupmaster',
                    @ActionType = 'I',
                    @RowJson = @rowJson,
                    @Table_name = 'tbl_tp_GroupMaster',
                    @ip_adress = @IPAdress,
                    @device_id = @DeviceId,
                    @IsImpersonation = @IsImpersonation,
                    @ImpersonatorId = @ImpersonatorId
            END
        END
        ELSE
        BEGIN
            SELECT 'Group Name Already Exists'
        END
    END
    ELSE IF @Option = 'Update'
    BEGIN
        IF NOT EXISTS (SELECT 'x' FROM tbl_tp_GroupMaster WHERE ParentID = @ParentID AND GroupName = @Group_Name AND GroupID <> @GroupID)
        BEGIN
            UPDATE tbl_tp_GroupMaster
            SET ParentID = @ParentID,
                GroupDesc = @Group_Desc,
                GroupName = @Group_Name
            WHERE GroupID = @GroupID

            SELECT 'Record Saved'

            SET @rowJson = (SELECT * FROM tbl_tp_GroupMaster FOR JSON AUTO, INCLUDE_NULL_VALUES)

            IF @rowJson IS NOT NULL
            BEGIN
                EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData
                    @User_id = @UserId,
                    @Activity_type = 'Update_Groupmaster',
                    @ActionType = 'U',
                    @RowJson = @rowJson,
                    @Table_name = 'tbl_tp_GroupMaster',
                    @ip_adress = @IPAdress,
                    @device_id = @DeviceId,
                    @IsImpersonation = @IsImpersonation,
                    @ImpersonatorId = @ImpersonatorId
            END
        END
        ELSE
        BEGIN
            SELECT 'Group Name Already Exists'
        END
    END

END



