     @roundrobin NVARCHAR(MAX),
    @agentstatus NVARCHAR(MAX)
AS
BEGIN
    BEGIN TRY
        BEGIN TRAN
        UPDATE [dbo].[tbl_tp_GroupMaster]
        SET Assigned = ISNULL(NULLIF(@roundrobin, ''), Assigned),
            AgentStatus = ISNULL(NULLIF(@agentstatus, ''), AgentStatus)
        WHERE GroupID = @groupid;

        COMMIT
    END TRY
    BEGIN CATCH
        ROLLBACK
    END CATCH
END



