AS
BEGIN

    DECLARE @UserId BIGINT, @TimeZone NVARCHAR(400), @NewHolidayId INT, @rowJson NVARCHAR(MAX), @IPAdress NVARCHAR(50), @DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT;
    SELECT @UserId = User_Id, @TimeZone = TimeZone FROM tbl_tp_UserLogin (NOLOCK) WHERE ParentId = @ParentId;

