    SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId);

IF @Option = 'Insert'
BEGIN

    INSERT INTO tbl_tp_CreateHolidays (HolidayName, HolidayDate, HolidayType, BusinessHours_Id, IsActive, ParentId, CreatedBy, CreatedOn)
    VALUES (@HolidayName, @HolidayDate, @HolidayType, @BusinessHours_Id, @IsActive, @ParentId, @CreatedBy, GETDATE());

	SET @NewHolidayId = SCOPE_IDENTITY()

	SET @rowJson = (SELECT * FROM tbl_tp_CreateHolidays tm WHERE (Holiday_Id = @NewHolidayId ) AND (ParentID = @ParentId) FOR JSON AUTO, INCLUDE_NULL_VALUES);
    IF @rowJson IS NOT NULL
    BEGIN
