            @RowJson = @rowJson,
            @Table_name = 'tbl_tp_CreateHolidays',
            @ip_adress = @IPAdress,
            @device_id = @DeviceId,
            @IsImpersonation = @IsImpersonation,
            @ImpersonatorId = @ImpersonatorId;
    END

END

ELSE IF @Option = 'Update'
BEGIN
    UPDATE tbl_tp_CreateHolidays
    SET
        HolidayName = @HolidayName,
        HolidayDate = @HolidayDate,
        HolidayType = @HolidayType,
        BusinessHours_Id = @BusinessHours_Id,
        IsActive = @IsActive,
        ParentId = @ParentId,
        ModifiedBy = @CreatedBy,
        ModifiedOn = GETDATE()
    WHERE Holiday_Id = @Holiday_Id;

	SET @rowJson = (SELECT * FROM tbl_tp_CreateHolidays tm WHERE (Holiday_Id = @Holiday_Id) AND (ParentID = @ParentId) FOR JSON AUTO, INCLUDE_NULL_VALUES);
    IF @rowJson IS NOT NULL
    BEGIN
        EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData
            @User_id = @UserId,
            @Activity_type = 'Updt_updateHolidays',
            @ActionType = 'U',
            @RowJson = @rowJson,
            @Table_name = 'tbl_tp_CreateHolidays',
            @ip_adress = @IPAdress,
            @device_id = @DeviceId,
            @IsImpersonation = @IsImpersonation,
            @ImpersonatorId = @ImpersonatorId;
        END
    END
END



