/* ============================================================
   Procedure: [dbo].[Usp_tp_InsertUpdateNewEmailSettings]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_tp_InsertUpdateNewEmailSettings]
    @Option NVARCHAR(10),
	@Mode NVARCHAR(250),
    @EmailSettingId INT,
	@Name NVARCHAR(255),
    @SupportEmail NVARCHAR(max),  
    @TpUserId BIGINT,
    @IsExistingEmail NVARCHAR(255) = NULL,
    @ForwardingEmail NVARCHAR(255) = NULL,
    @MetaData NVARCHAR(MAX)
AS
BEGIN
 -- declare  @Option NVARCHAR(10)='Update',
 --   @EmailSettingId INT=1,
	--@Name NVARCHAR(255)='abhi01_545gg',
 --   @SupportEmail NVARCHAR(max)='abhi01_545gg@support.appmails.net.in',  
 --   @TpUserId BIGINT=60,
 --   @IsExistingEmail NVARCHAR(255) = NULL,
 --   @ForwardingEmail NVARCHAR(255) = NULL,
    --@VirtualSupportEmail NVARCHAR(255) = NULL,
   -- @MetaData NVARCHAR(MAX)
    DECLARE @TimeZone NVARCHAR(400),
            @IPAdress NVARCHAR(50),
            @DeviceId NVARCHAR(50),
            @IsImpersonation BIT,
            @ImpersonatorId INT,
            @InsertedId INT,
            @UserID BIGINT,
            @ParentID BIGINT,
			@vitualexistingemail nvarchar(max),
            @rowJson NVARCHAR(MAX);

    -- Retrieve user details
    SELECT @ParentID = ParentId, @TimeZone = TimeZone, @UserID = User_Id
    FROM tbl_tp_UserLogin (NOLOCK)
    WHERE TpUser_Id = @TpUserId;

	 SELECT @vitualexistingemail = SupportEmail
    FROM tbl_tp_EmailSetting (NOLOCK)
    WHERE ParentID = @ParentID;

    -- Extract metadata information
    SET @IPAdress = JSON_VALUE(@MetaData, '$.IPAddress');
    SET @DeviceId = JSON_VALUE(@MetaData, '$.MacAddress');
    SET @IsImpersonation = JSON_VALUE(@MetaData, '$.IsImpersonation');
    SET @ImpersonatorId = JSON_VALUE(@MetaData, '$.ImpersonatorId');

    -- Insert or update logic
	    IF EXISTS (SELECT 1 FROM tbl_tp_EmailSetting WHERE [ParentID] = @ParentID AND [Name] = @Name)
    BEGIN
        SELECT 'Already exist' AS Result, 'Duplicate Name for ParentID' AS Message;
        RETURN;
    END

	   IF @Mode = 'SupportForwardMail'
    BEGIN
        -- Check if the forwarding email already exists
        IF EXISTS (SELECT 1 FROM supportmailforwarding WHERE  [usermail] = @ForwardingEmail and isactive=1)
        BEGIN
            SELECT 'Forwarding Email Already Exists' AS Result, 'This forwarding email is already associated with the ParentID' AS Message;
            RETURN;
        END
        ELSE
        BEGIN
            -- Insert new forwarding email
            INSERT INTO supportmailforwarding (
                [parentid], [usermail], [virtualmail], [isactive], [createdon], [lastmodified]
            )
            VALUES (
                @ParentID, @ForwardingEmail, @vitualexistingemail, 1, GETDATE(), GETDATE()
            );

            SELECT 'Forwarding Email Added' AS Result, 'Forwarding email has been added successfully' AS Message;
            RETURN;
        END
    END

	IF @Mode = 'ReassociateSupportForwardMail'
BEGIN
    -- Deactivate previous forwarding email entry
    UPDATE supportmailforwarding
    SET isactive = 0
    WHERE usermail = @ForwardingEmail AND isactive = 1;

    -- Insert new forwarding email
    INSERT INTO supportmailforwarding (
        [parentid], [usermail], [virtualmail], [isactive], [createdon], [lastmodified]
    )
    VALUES (
        @ParentID, @ForwardingEmail, @vitualexistingemail, 1, GETDATE(), GETDATE()
    );

    SELECT 'Forwarding Email Reassociate' AS Result, 'Forwarding email has been Reassociated successfully' AS Message;
    RETURN;
END



    IF @Option = 'Insert'
    BEGIN
        -- Check if a support email already exists for this ParentID
        IF EXISTS (SELECT 1 FROM tbl_tp_EmailSetting WHERE [ParentID] = @ParentID)
        BEGIN
            -- Delete the existing support email record for this ParentID
            DELETE FROM tbl_tp_EmailSetting WHERE [ParentID] = @ParentID;
        END

        -- Insert the new support email
        INSERT INTO tbl_tp_EmailSetting (
            [Name],[SupportEmail], [ParentID], [IsActive], [CreatedDate], [CreatedBy]
        )
        VALUES (
           @Name, @SupportEmail, @ParentID, 1, GETDATE(), @UserID
        );

        SET @InsertedId = SCOPE_IDENTITY();

        -- If forwarding email is to be added
        IF @IsExistingEmail = 'AddExisting'
        BEGIN
            INSERT INTO supportmailforwarding (
                [parentid], [usermail], [virtualmail], [isactive], [createdon], [lastmodified]
            )
            VALUES (
                @ParentID, @ForwardingEmail, @SupportEmail, 1, GETDATE(), GETDATE()
            );
        END

        -- Confirm insert
        IF @InsertedId IS NOT NULL
        BEGIN
            SELECT 'Saved' AS Result, @InsertedId AS EmailSettingId;
        END;
    END
    ELSE IF @Option = 'Update'
    BEGIN
        -- Update existing record based on EmailSettingId and ParentID match
        UPDATE tbl_tp_EmailSetting
        SET
		    [Name]=@Name,
            [SupportEmail] = @SupportEmail,
            [ParentID] = @ParentID,
            [CreatedDate] = GETDATE(),
            [CreatedBy] = @UserID
        WHERE
            ESid = @EmailSettingId
            AND [ParentID] = @ParentID;

        -- Confirm update
        SELECT 'Updated' AS Result, @EmailSettingId AS ESid;
    END;
END;




GO

