SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_tp_InsertUpdatenotificationfrommailid]
    @ParentId INT,
    @email NVARCHAR(MAX),
    @MetaData NVARCHAR(MAX)
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @TimeZone NVARCHAR(400),
            @IPAdress NVARCHAR(50),
            @DeviceId NVARCHAR(50),
            @IsImpersonation BIT,
            @ImpersonatorId INT,
            @InsertedId INT,
            @UserID BIGINT,
			@TpUserId BIGINT,
            @rowJson NVARCHAR(MAX);

    SET @IPAdress = JSON_VALUE(@MetaData, '$.IPAddress');
    SET @DeviceId = JSON_VALUE(@MetaData, '$.MacAddress');
    SET @IsImpersonation = JSON_VALUE(@MetaData, '$.IsImpersonation');
    SET @ImpersonatorId = JSON_VALUE(@MetaData, '$.ImpersonatorId');

   BEGIN
      SELECT @TpUserId = TpUser_Id, @TimeZone = TimeZone, @UserID = User_Id
    FROM tbl_tp_UserLogin (NOLOCK)
    WHERE ParentId = @ParentId;
    IF EXISTS (SELECT 1 FROM [dbo].[tbl_tp_notificationemaildetails] WHERE  ParentId = @ParentId)

    BEGIN

        UPDATE [dbo].[tbl_tp_notificationemaildetails]
        SET IsActive = 1 , email= @email,ModifiedDate=GETDATE(),ModifiedBy=@ParentId
        WHERE  ParentId = @ParentId; 
    END
    ELSE
    BEGIN
