   Procedure: [dbo].[Usp_tp_InsertUpdateNotificationStatus]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_InsertUpdateNotificationStatus]
    @NotificationId INT,
	@IsEnabled BIT,
    @TpUserId BIGINT,
    @MetaData NVARCHAR(MAX)


AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @ParentID Bigint,@UserId Bigint, @TimeZone nvarchar (400)  ,@rowJson NVARCHAR(MAX)  , @IPAdress NVARCHAR(50),@DeviceId NVARCHAR(50),@IsImpersonation BIT ,@ImpersonatorId INT 
	
    Select @ParentID = ParentId ,@UserId = User_Id From tbl_tp_UserLogin (noLock) Where TpUser_Id = @TpUserId   AND IsActive = 1
                
    SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)        
    SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)        
    SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)        
    SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)

    IF EXISTS (SELECT 1 FROM tbl_tp_TicketNotificationDetail WHERE NotificationId = @NotificationId)
    BEGIN

         UPDATE tbl_tp_TicketNotificationDetail
        SET 
            IsEnabled = @IsEnabled,
            ModifiedBy = @UserId,
            ModifiedOn = GETDATE()
           WHERE NotificationId = @NotificationId

		   	SET @rowJson = (SELECT * FROM tbl_tp_TicketNotificationDetail tm WHERE (NotificationId = @NotificationId) AND (ParentID = @ParentId) FOR JSON AUTO, INCLUDE_NULL_VALUES);
    IF @rowJson IS NOT NULL
    BEGIN
        EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData
            @User_id = @UserId,
            @Activity_type = 'Updt_updateNotificationDetail',
            @ActionType = 'U',
            @RowJson = @rowJson,
            @Table_name = 'tbl_tp_TicketNotificationDetail',
            @ip_adress = @IPAdress,
            @device_id = @DeviceId,
            @IsImpersonation = @IsImpersonation,
            @ImpersonatorId = @ImpersonatorId;
        END
		
        IF @IsEnabled = 'true'
            SELECT 'Notification has been enabled.' AS Message
        ELSE
            SELECT 'Notification has been disabled.' AS Message
		--Select 'Notification has been enabled .' AS Message
    END
    ELSE
    BEGIN

        INSERT INTO tbl_tp_TicketNotificationDetail (Subject, Description, NotificationId, IsEnabled, ParentId, IsActive, CreatedBy, CreatedOn, ModifiedBy, ModifiedOn)
        VALUES (NULL, NULL, @NotificationId, @IsEnabled, @ParentId, 1, @UserId, GETDATE(),NULL,GETDATE())

			SET @rowJson = (SELECT * FROM tbl_tp_TicketNotificationDetail tm WHERE (NotificationId = @NotificationId ) AND (ParentID = @ParentId) FOR JSON AUTO, INCLUDE_NULL_VALUES);
    IF @rowJson IS NOT NULL
    BEGIN
        EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData
            @User_id = @UserId,
            @Activity_type = 'Inst_createNotificationDetail',
            @ActionType = 'I',
            @RowJson = @rowJson,
            @Table_name = 'tbl_tp_TicketNotificationDetail',
            @ip_adress = @IPAdress,
            @device_id = @DeviceId,
            @IsImpersonation = @IsImpersonation,
            @ImpersonatorId = @ImpersonatorId;
    END
			--Select 'Notification has been disabled .' AS Message
			    IF @IsEnabled = 'true'
            SELECT 'Notification has been enabled.' AS Message
        ELSE
            SELECT 'Notification has been disabled.' AS Message

    END
END



