    @TpUserId BIGINT,          
    @LanguageId INT,          
    @PortalName NVARCHAR(MAX),          
    @PortalURL NVARCHAR(MAX),            
    @IsPortalEnabled BIT,          
    @IsManageEnabled BIT,          
    @IsCaptchaEnabled BIT,          
    @IsDisplayOn BIT,          
    @SubmittedType NVARCHAR(MAX),          
    @IsCapchaManageEnabled BIT,          
    @IsTicketAutoSuggest BIT,          
    @ViewedBy NVARCHAR(MAX),          
    @AllowUsersToView NVARCHAR(MAX),          
    @AllowUsersToFilter NVARCHAR(MAX),          
    @IsKnowladgeBaseEnabled BIT,          
    @KnowladgeToView NVARCHAR(MAX),          
    @IsKnowladgeCapchaEnabled BIT,          
    @IsDisplayAuthorName BIT,          
    @IsDisplayAgentViews BIT,          
    @LogoPath1 NVARCHAR(MAX),          
    @LogoPath2 NVARCHAR(MAX),          
    @LinkBackURL NVARCHAR(MAX),          
    @Phone NVARCHAR(MAX),          
    @MetaData NVARCHAR(MAX),          
    @SignUpFields NVARCHAR(MAX),      
    @CategoryId INT,      
    @Option NVARCHAR(10)          
AS            
BEGIN            
    DECLARE @InsertedId BIGINT, @UserId BIGINT, @rowJson NVARCHAR(MAX), @IPAdress NVARCHAR(50), @DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT, @ParentId BIGINT          
          
    SELECT @UserId = User_ID, @ParentId = ParentId FROM tbl_tp_UserLogin (NOLOCK) WHERE TpUser_Id = @TpUserId;          
 IF EXISTS (    
        SELECT 1    
        FROM tbl_tp_PortalSetting (NOLOCK)    
        WHERE ParentId = @ParentId AND PortalSettingId <> ISNULL(@PortalSettingId, 0)    
    )    
    BEGIN    
       SET @Option = 'Update'    
    END    
              
    IF @Option = 'Insert'          
    BEGIN          
   IF EXISTS (SELECT 1 FROM tbl_tp_client_domain WHERE ClientDomain = @PortalURL AND ParentId = @ParentId)        
BEGIN        
    UPDATE tbl_tp_client_domain        
    SET ClientDomain = @PortalURL        
    WHERE ClientDomain = @PortalURL AND ParentId = @ParentId        
END        
ELSE        
BEGIN        
    INSERT INTO tbl_tp_client_domain (ClientDomain, ParentId)        
    VALUES (@PortalURL, @ParentId)        
END        
        
                   
        INSERT INTO tbl_tp_PortalSetting (LanguageId, PortalName, IsPortalEnabled, IsManageEnabled, IsCaptchaEnabled, IsDisplayOn, SubmittedType, IsCapchaManageEnabled, IsTicketAutoSuggest, ViewedBy, AllowUsersToView, AllowUsersToFilter,     
  IsKnowladgeBaseEnabled, KnowladgeToView, IsKnowladgeCapchaEnabled, IsDisplayAuthorName, IsDisplayAgentViews, LogoPath1, LogoPath2, LinkBackURL, Phone, IsActive, ParentId, CreatedBy, CreatedOn,SignUpFields,CategoryId)          
        VALUES (@LanguageId, @PortalName, @IsPortalEnabled, @IsManageEnabled, @IsCaptchaEnabled, @IsDisplayOn, @SubmittedType, @IsCapchaManageEnabled, @IsTicketAutoSuggest, @ViewedBy, @AllowUsersToView, @AllowUsersToFilter,     
  @IsKnowladgeBaseEnabled, @KnowladgeToView, @IsKnowladgeCapchaEnabled, @IsDisplayAuthorName, @IsDisplayAgentViews, @LogoPath1, @LogoPath2, @LinkBackURL, @Phone, 1, @ParentId, @UserId, GETDATE(),@SignUpFields,@CategoryId);          
                  
        SET @rowJson = (SELECT * FROM tbl_tp_PortalSetting tsm WHERE tsm.ParentId = @ParentId FOR JSON AUTO, INCLUDE_NULL_VALUES);            
                            
        IF @rowJson IS NOT NULL            
        BEGIN            
            EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData             
                @User_id = @UserId,            
                @Activity_type = 'Inst_PortalSetting',            
                @ActionType = 'I',            
                @RowJson = @rowJson,            
                @Table_name = 'tbl_tp_PortalSetting',            
                @ip_adress = @IPAdress,            
                @device_id = @DeviceId,            
                @IsImpersonation = @IsImpersonation,            
                @ImpersonatorId = @ImpersonatorId;            
        END            
          
        SELECT 'Inserted' AS Message;          
    END        
              
    IF @Option = 'Update'          
    BEGIN          
        UPDATE tbl_tp_PortalSetting           
        SET LanguageId = @LanguageId,           
            PortalName = @PortalName,                 
            IsPortalEnabled = @IsPortalEnabled,           
            IsManageEnabled = @IsManageEnabled,           
            IsCaptchaEnabled = @IsCaptchaEnabled,           
            IsDisplayOn = @IsDisplayOn,           
            SubmittedType = @SubmittedType,           
            IsCapchaManageEnabled = @IsCapchaManageEnabled,           
            IsTicketAutoSuggest = @IsTicketAutoSuggest,           
            ViewedBy = @ViewedBy,           
            AllowUsersToView = @AllowUsersToView,           
            AllowUsersToFilter = @AllowUsersToFilter,           
            IsKnowladgeBaseEnabled = @IsKnowladgeBaseEnabled,           
            KnowladgeToView = @KnowladgeToView,           
            IsKnowladgeCapchaEnabled = @IsKnowladgeCapchaEnabled,           
            IsDisplayAuthorName = @IsDisplayAuthorName,           
            IsDisplayAgentViews = @IsDisplayAgentViews,           
            LogoPath1 = @LogoPath1,           
            LogoPath2 = @LogoPath2,           
            LinkBackURL = @LinkBackURL,           
            Phone = @Phone,        
            SignUpFields = @SignUpFields,       
            CategoryId = @CategoryId,      
            IsActive = 1,           
            ParentId = @ParentId,           
            ModifiedBy = @UserId,          
            ModifiedOn = GETDATE()          
        WHERE ParentId = @ParentId;          
                  
        SET @rowJson = (SELECT * FROM tbl_tp_PortalSetting tsm WHERE tsm.ParentId = @ParentId FOR JSON AUTO, INCLUDE_NULL_VALUES);            
                            
        IF @rowJson IS NOT NULL            
        BEGIN            
            EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData             
                @User_id = @UserId,            
                @Activity_type = 'Updt_PortalSetting',            
                @ActionType = 'U',            
                @RowJson = @rowJson,            
                @Table_name = 'tbl_tp_PortalSetting',            
                @ip_adress = @IPAdress,            
                @device_id = @DeviceId,            
                @IsImpersonation = @IsImpersonation,            
                @ImpersonatorId = @ImpersonatorId;            
        END            
          
        SELECT 'Updated' AS Message;          
    END            
END; 


GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_InsertUpdateScenarioRule]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

                  
CREATE   PROCEDURE [dbo].[Usp_tp_InsertUpdateScenarioRule]                                    
(                                    
  @ScenarioId Bigint,                                    
  @TpUserId Bigint,                                    
  @RuleName Nvarchar(100),                                  
  @Description Nvarchar(200),                           
  @SequenceNo Bigint,                                                  
  @Option Nvarchar(50),                           
  @ConditionValues Nvarchar(max), 
  @SelectedFiled nvarchar(max),
  @fieldconjuction nvarchar(max),
  @ActionValues Nvarchar(max),              
  @MetaData nvarchar(200)                                
)                                    
as                                    
Begin                                  
                                
                                          
DECLARE @TimeZone nvarchar (400),@ParentId BIGINT,@rowJson NVARCHAR(MAX) , @IPAdress NVARCHAR(50),@DeviceId NVARCHAR(50),@IsImpersonation BIT ,
        @ImpersonatorId INT,@UserId BIGINT                     
       Select @UserId = User_Id,@TimeZone = TimeZone ,@ParentId = ParentId From tbl_tp_UserLogin (noLock) Where  TpUser_Id = @TpUserId  AND IsActive = 1                  
                                          
 SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)                                  
 SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)                                  
 SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)                                  
 SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)                                
                                
 if(@Option = 'Insert')                                    
 Begin                                    
 if(NOT EXISTS (select 'x' from tbl_tp_ScenarioMaster where ParentID = @ParentID and Scenario_Name = @RuleName ))                    
 Begin                  
                       
SELECT @SequenceNo = ISNULL(MAX(SequenceNo), 0) FROM tbl_tp_ScenarioMaster           
                
              
  INSERT INTO tbl_tp_ScenarioMaster(ParentID,Scenario_Name,Scenario_Description,Active,SequenceNo,CreatedBy,CreatedDate,IsEnabled)                    
  values(@ParentId,@RuleName,@Description,1, @SequenceNo+1,@TpUserId,GETDATE(),1)                    
                    
  Set @ScenarioId= SCOPE_IDENTITY()                    
                                      
INSERT INTO dbo.tbl_tp_ScenarioCondition (Scenario_Id, FieldName, Operator, Value, Conjunction, SequenceNo, Active, ParentId, CreatedBy, CreatedDate)        
SELECT @ScenarioId,         
       COALESCE(json.FieldName, 'NA'),          
       COALESCE(json.Operator, '0'),          
       COALESCE(json.Value, 'NA'),         
       COALESCE(json.Conjunction, 'OR'),        
       @SequenceNo + 1,         
       1,         
       @ParentId,         
       @TpUserId,         
       GETDATE()        
FROM OPENJSON(@ConditionValues, '$.ConditionValues') WITH (        
    FieldName nvarchar(100),        
    Operator nvarchar(100),        
    Value nvarchar(50),        
 Conjunction nvarchar(50)        
) AS json;        
        
     IF (@SelectedFiled IS NOT NULL)
    BEGIN
        INSERT INTO tbl_tp_Scenariotriggeredfield (fieldName,conjunction, Scenarioid, ParentId, IsActive, CreatedDate,CreatedBy)
        SELECT value,@fieldconjuction,@ScenarioId, @ParentId, 1, GETDATE(),@TpUserId
        FROM STRING_SPLIT(@SelectedFiled, ',');
    END


BEGIN TRY
    INSERT INTO dbo.tbl_tp_ScenarioAction (Scenario_Id, Action_Id, Action_Value, SequenceNo, Active, ParentId, createdBy, CreatedDate)        
    SELECT @ScenarioId,         
        COALESCE(json.ActionId, '0'),          
        COALESCE(json.ActionValue, '0'),                     
        @SequenceNo + 1,         
        1,         
        @ParentId,         
        @TpUserId,         
        GETDATE()        
    FROM OPENJSON(@ActionValues, '$.Actions') WITH (        
        ActionId bigint '$.ActionId',        
        ActionValue nvarchar(100) '$.ActionValue'      
    ) AS json;

    SELECT 'Record Saved Successfully !' AS Message; 
END TRY        
BEGIN CATCH        
    PRINT 'An error occurred: ' + ERROR_MESSAGE();        
END CATCH
   SET @rowJson  = ( SELECT *  FROM tbl_tp_ScenarioMaster  FOR JSON AUTO  ,INCLUDE_NULL_VALUES )                                          
                                          
     IF @rowJson IS NOT NULL                                          
          BEGIN                                          
           EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData @User_id = @UserId                                          
            ,@Activity_type = 'Inst_scenariomaster'                                          
            ,@ActionType = 'I'                                          
            ,@RowJson = @rowJson                                          
            ,@Table_name = 'tbl_tp_ScenarioMaster'  ,@ip_adress = @IPAdress ,@device_id = @DeviceId,@IsImpersonation = @IsImpersonation,@ImpersonatorId =  @ImpersonatorId                                   
          END                                
                                        
  End                                    
 else                                    
   Begin                                          
    select 'Scenario Rule Already Exists' AS Result                                   
    End                                 
                               
                               
   end                                     
IF (@Option = 'Update')      
BEGIN      
      
    IF (NOT EXISTS (SELECT 'x' FROM tbl_tp_ScenarioMaster WHERE ParentID = @ParentID AND Scenario_Name = @RuleName AND Scenario_Id <> @ScenarioId))      
    BEGIN      
        BEGIN TRANSACTION;      
      
        BEGIN TRY      
            UPDATE tbl_tp_ScenarioMaster      
            SET      
                ParentID = @ParentID,      
                Scenario_Description = @Description,      
                Scenario_Name = @RuleName,      
                ModifiedBy = @TpUserId,      
                ModifiedDate = GETDATE()      
                WHERE Scenario_Id = @ScenarioId;      
      
      
 DELETE FROM dbo.tbl_tp_ScenarioCondition WHERE Scenario_Id = @ScenarioId;
INSERT INTO dbo.tbl_tp_ScenarioCondition (Scenario_Id, FieldName, Operator, Value, Conjunction, SequenceNo, Active, ParentId, CreatedBy, CreatedDate)        
SELECT @ScenarioId,         
       COALESCE(json.FieldName, 'NA'),          
       COALESCE(json.Operator, '0'),          
       COALESCE(json.Value, 'NA'),         
       COALESCE(json.Conjunction, 'OR'),        
       @SequenceNo + 1,         
       1,         
       @ParentId,         
       @TpUserId,         
       GETDATE()        
FROM OPENJSON(@ConditionValues, '$.ConditionValues') WITH (        
    FieldName nvarchar(100),        
    Operator nvarchar(100),        
    Value nvarchar(50),        
 Conjunction nvarchar(50)        
) AS json;        
    
	IF (@SelectedFiled IS NOT NULL)
    BEGIN
		 DELETE FROM dbo.tbl_tp_Scenariotriggeredfield WHERE Scenarioid = @ScenarioId;
        INSERT INTO tbl_tp_Scenariotriggeredfield (fieldName,conjunction, Scenarioid, ParentId, IsActive, CreatedDate,CreatedBy,ModifiedDate,ModifiedBy)
        SELECT value,@fieldconjuction,@ScenarioId, @ParentId, 1, GETDATE(),@TpUserId,GETDATE(),@TpUserId
        FROM STRING_SPLIT(@SelectedFiled, ',');
    END

 DELETE FROM dbo.tbl_tp_ScenarioAction WHERE Scenario_Id = @ScenarioId;
         INSERT INTO dbo.tbl_tp_ScenarioAction (Scenario_Id, Action_Id, Action_Value, SequenceNo, Active, ParentId, createdBy, CreatedDate)        
    SELECT @ScenarioId,         
        COALESCE(json.ActionId, '0'),          
        COALESCE(json.ActionValue, '0'),                     
        @SequenceNo + 1,         
        1,         
        @ParentId,         
        @TpUserId,         
        GETDATE()        
    FROM OPENJSON(@ActionValues, '$.Actions') WITH (        
        ActionId bigint '$.ActionId',        
        ActionValue nvarchar(100) '$.ActionValue'      
    ) AS json;
      
            COMMIT;      
            SELECT 'Records Updated Succesfully' AS Message;       
        END TRY      
        BEGIN CATCH      
            ROLLBACK;      
            PRINT 'An error occurred: ' + ERROR_MESSAGE();      
        END CATCH;      
      
        SET @rowJson = (      
            SELECT *      
            FROM tbl_tp_ScenarioMaster      
            FOR JSON AUTO, INCLUDE_NULL_VALUES      
        );      
        IF @rowJson IS NOT NULL      
        BEGIN      
            EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData      
                @User_id = @UserId,      
                @Activity_type = 'Updt_scenariomaster',      
                @ActionType = 'U',      
                @RowJson = @rowJson,      
                @Table_name = 'tbl_tp_ScenarioMaster',      
                @ip_adress = @IPAdress,      
                @device_id = @DeviceId,      
                @IsImpersonation = @IsImpersonation,      
                @ImpersonatorId = @ImpersonatorId;      
        END      
    END      
    ELSE      
    BEGIN      
        SELECT 'Scenario Rule Already Exists' AS Result;      
    END      
END      
                                                            
End 





GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_InsertUpdateSLAPolicies]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_InsertUpdateSLAPolicies]    
(    
  @SlaId BIGINT OUTPUT,    
  @TpUserId BIGINT,    
  @SlaName NVARCHAR(100),    
  @SlaDescription NVARCHAR(200),    
  @SequenceNo BIGINT,    
  @Option NVARCHAR(50),    
  @SLATargetData NVARCHAR(MAX),    
  @SLAConditionData NVARCHAR(MAX),    
  @SLAResponseData NVARCHAR(MAX),    
  @SLAResolutionData NVARCHAR(MAX),    
  @SLAResolvedData NVARCHAR(MAX),    
  @SLANotRespondData NVARCHAR(MAX),    
  @MetaData NVARCHAR(200)    
)    
AS    
BEGIN    
  DECLARE   
    @IPAdress NVARCHAR(50),  
    @UserId BIGINT,   
    @DeviceId NVARCHAR(50),   
    @IsImpersonation BIT,   
    @ImpersonatorId INT,   
    @rowJson NVARCHAR(MAX),   
    @ParentId BIGINT;    
      
  SELECT    
    @IPAdress = JSON_VALUE(@MetaData, '$.IPAddress'),    
    @DeviceId = JSON_VALUE(@MetaData, '$.MacAddress'),    
    @IsImpersonation = JSON_VALUE(@MetaData, '$.IsImpersonation'),    
    @ImpersonatorId = JSON_VALUE(@MetaData, '$.ImpersonatorId');    
     
  SELECT @ParentId = ParentId, @UserId = User_Id   
  FROM tbl_tp_UserLogin (NOLOCK)   
  WHERE TpUser_Id = @TpUserID AND IsActive = 1;    
    
  IF (@Option = 'Insert')    
  BEGIN    
    IF NOT EXISTS (SELECT 1 FROM tbl_tp_SLAMaster WHERE ParentID = @ParentID AND SLA_Name = @SlaName)    
    BEGIN    
      INSERT INTO tbl_tp_SLAMaster (ParentID, SLA_Name, SLA_Description, Active, SequenceNo, CreatedBy, CreatedDate, IsEnabled)    
      VALUES (@ParentId, @SlaName, @SlaDescription, 1, @SequenceNo + 1, @TpUserID, GETDATE(), 1);    
     
      SET @SlaId = SCOPE_IDENTITY();    
    
      INSERT INTO tbl_tp_SLADetail (SLA_Id, Priority_ID, Respond_Val, Respond_Unit, Respond_Sec, Resolve_Val, Resolve_Unit, Resolve_Sec, Operational_Unit)    
      SELECT    
        @SlaId AS SLA_Id,    
        COALESCE(JSON_VALUE(value, '$.priorityId'), '0') AS Priority_ID,    
        COALESCE(JSON_VALUE(value, '$.respondWithin.value'), '0') AS Respond_Val,    
        COALESCE(JSON_VALUE(value, '$.respondWithin.unit'), '') AS Respond_Unit,    
        CASE    
          WHEN JSON_VALUE(value, '$.respondWithin.unit') = 'Hours' THEN COALESCE(JSON_VALUE(value, '$.respondWithin.value'), '0') * 3600    
          WHEN JSON_VALUE(value, '$.respondWithin.unit') = 'Month' THEN COALESCE(JSON_VALUE(value, '$.respondWithin.value'), '0') * 30 * 24 * 60    
          WHEN JSON_VALUE(value, '$.respondWithin.unit') = 'Day' THEN COALESCE(JSON_VALUE(value, '$.respondWithin.value'), '0') * 24 * 60    
          ELSE 0    
        END AS Respond_Sec,    
        COALESCE(JSON_VALUE(value, '$.resolveWithin.value'), '0') AS Resolve_Val,    
        COALESCE(JSON_VALUE(value, '$.resolveWithin.unit'), '') AS Resolve_Unit,    
        CASE    
          WHEN JSON_VALUE(value, '$.resolveWithin.unit') = 'Hours' THEN COALESCE(JSON_VALUE(value, '$.resolveWithin.value'), '0') * 3600    
          WHEN JSON_VALUE(value, '$.resolveWithin.unit') = 'Month' THEN COALESCE(JSON_VALUE(value, '$.resolveWithin.value'), '0') * 30 * 24 * 60    
          WHEN JSON_VALUE(value, '$.resolveWithin.unit') = 'Day' THEN COALESCE(JSON_VALUE(value, '$.resolveWithin.value'), '0') * 24 * 60    
          ELSE 0    
        END AS Resolve_Sec,    
        COALESCE(JSON_VALUE(value, '$.operationalHrs'), '') AS Operational_Unit    
      FROM OPENJSON(@SLATargetData, '$.data');    
    
      INSERT INTO dbo.tbl_tp_SLACondition (SLA_Id, FieldName, Operator, Value, Conjunction, SequenceNo, ParentId, createdBy, CreatedDate)    
      SELECT    
        @SlaId,    
        JSON_VALUE(value, '$.fieldName'),    
        JSON_VALUE(value, '$.operator'),    
        JSON_VALUE(value, '$.value'),    
        JSON_VALUE(@SLAConditionData, '$.SLA_Conjunction'),    
        @SequenceNo + 1, @ParentId, @UserId, GETDATE()    
       FROM OPENJSON(@SLAConditionData, '$.ConditionValues');  
   
INSERT INTO tbl_tp_SLAResolutionDetail (
    SLA_Id,
    SequenceNo,
    Frequency,
    Frequency_Sec,
    ResolutionTo,
    ResolutionVal,
    IsEscalation,
    Active,
    ParentId,
    CreatedBy
)
SELECT
    @SlaId AS SLA_Id,
    ROW_NUMBER() OVER (PARTITION BY @SlaId ORDER BY (SELECT NULL)) AS SequenceNo,
    COALESCE(JSON_VALUE([value], '$.selectedSLAPolicyText'), '0') AS Frequency,
    COALESCE(JSON_VALUE([value], '$.selectedSLAPolicy'), '0') AS Frequency_Sec,
    COALESCE(JSON_VALUE([value], '$.radioValue'), 'TicketManager') AS ResolutionTo,
    CASE
        WHEN JSON_VALUE([value], '$.radioValue') = 'agent' THEN JSON_VALUE([value], '$.selectedResponseRemindAgents')
        WHEN JSON_VALUE([value], '$.radioValue') = 'group' THEN JSON_VALUE([value], '$.selectedGroupRemind')
        ELSE '0'
    END AS ResolutionVal,
    CASE WHEN JSON_VALUE([value], '$.IsEscalation') = 'true' THEN '1' ELSE '0' END AS IsEscalation,
    1 AS Active,
    @ParentId,
    @UserId
FROM OPENJSON(@SLAResolutionData);


INSERT INTO tbl_tp_SLAResolutionDetail (
    SLA_Id,
    SequenceNo,
    Frequency,
    Frequency_Sec,
    ResolutionTo,
    ResolutionVal,
    IsEscalation,
    Active,
    ParentId,
    CreatedBy
)
SELECT
    @SlaId AS SLA_Id,
    ROW_NUMBER() OVER (PARTITION BY @SlaId ORDER BY (SELECT NULL)) AS SequenceNo,
    COALESCE(JSON_VALUE([value], '$.selectedSLAPolicyText'), '0') AS Frequency,
    COALESCE(JSON_VALUE([value], '$.selectedSLAPolicy'), '0') AS Frequency_Sec,
    COALESCE(JSON_VALUE([value], '$.radioValue'), 'TicketManager') AS ResolutionTo,
    CASE
        WHEN JSON_VALUE([value], '$.radioValue') = 'agent' THEN JSON_VALUE([value], '$.selectedResponseRemindAgents')
        WHEN JSON_VALUE([value], '$.radioValue') = 'group' THEN JSON_VALUE([value], '$.selectedGroupRemind')
        ELSE '0'
    END AS ResolutionVal,
   COALESCE (JSON_VALUE([value], '$.IsEscalation'),'1')  AS IsEscalation,  
    1 AS Active,
    @ParentId,
    @UserId
FROM OPENJSON(@SLAResolvedData);

 
INSERT INTO tbl_tp_SLAResponseDetail (  
    SLA_Id,  
    SequenceNo,  
    Frequency,  
    Frequency_Sec,  
    ResponseTo,  
    ResponseVal,  
    IsEscalation,  
    Active,  
    ParentId,  
    CreatedBy  
)  
SELECT  
     @SlaId AS SLA_Id,
    ROW_NUMBER() OVER (PARTITION BY @SlaId ORDER BY (SELECT NULL)) AS SequenceNo,
    COALESCE(JSON_VALUE([value], '$.selectedSLAPolicyText'), '0') AS Frequency,
    COALESCE(JSON_VALUE([value], '$.selectedSLAPolicy'), '0') AS Frequency_Sec,
    COALESCE(JSON_VALUE([value], '$.radioValue'), 'TicketManager') AS ResponseTo,
    CASE
        WHEN JSON_VALUE([value], '$.radioValue') = 'agent' THEN JSON_VALUE([value], '$.selectedResponseRemindAgents')
        WHEN JSON_VALUE([value], '$.radioValue') = 'group' THEN JSON_VALUE([value], '$.selectedGroupRemind')
        ELSE '0'
    END AS ResponseVal,
    CASE WHEN JSON_VALUE([value], '$.IsEscalation') = 'true' THEN '1' ELSE '0' END AS IsEscalation,
    1 AS Active,
    @ParentId,
    @UserId
FROM OPENJSON(@SLAResponseData);  

INSERT INTO tbl_tp_SLAResponseDetail (  
    SLA_Id,  
    SequenceNo,  
    Frequency,  
    Frequency_Sec,  
    ResponseTo,  
    ResponseVal,  
    IsEscalation,  
    Active,  
    ParentId,  
    CreatedBy  
)  
SELECT  
     @SlaId AS SLA_Id,
    ROW_NUMBER() OVER (PARTITION BY @SlaId ORDER BY (SELECT NULL)) AS SequenceNo,
    COALESCE(JSON_VALUE([value], '$.selectedSLAPolicyText'), '0') AS Frequency,
    COALESCE(JSON_VALUE([value], '$.selectedSLAPolicy'), '0') AS Frequency_Sec,
    COALESCE(JSON_VALUE([value], '$.radioValue'), 'TicketManager') AS ResponseTo,
    CASE
        WHEN JSON_VALUE([value], '$.radioValue') = 'agent' THEN JSON_VALUE([value], '$.selectedResponseRemindAgents')
        WHEN JSON_VALUE([value], '$.radioValue') = 'group' THEN JSON_VALUE([value], '$.selectedGroupRemind')
        ELSE '0'
    END AS ResponseVal,
    COALESCE (JSON_VALUE([value], '$.IsEscalation'),'1')  AS IsEscalation,  
    1 AS Active,
    @ParentId,
    @UserId
FROM OPENJSON(@SLANotRespondData); 

      SET @rowJson = (SELECT * FROM tbl_tp_SLAMaster WHERE SLA_Id = @SlaId FOR JSON AUTO, INCLUDE_NULL_VALUES);    
     
      IF @rowJson IS NOT NULL    
      BEGIN    
        EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData   
          @User_id = @UserId,    
          @Activity_type = 'Add_SLAPolicies',    
          @ActionType = 'I',    
          @RowJson = @rowJson,    
          @Table_name = 'tbl_tp_SLAMaster',    
          @ip_adress = @IPAdress,    
          @device_id = @DeviceId,    
          @IsImpersonation = @IsImpersonation,    
          @ImpersonatorId = @ImpersonatorId;    
      END;    
  
      SELECT 'Record Saved' AS resp;    
    END    
    ELSE    
    BEGIN     
      SELECT 'Policy Name Already Exists' AS resp;    
    END;    
  END 
 
IF @Option = 'Update'
BEGIN
    IF EXISTS (SELECT 1 FROM tbl_tp_SLAMaster WHERE SLA_Id = @SlaId)
    BEGIN

	    DELETE FROM tbl_tp_SLACondition WHERE SLA_Id = @SlaId;
		   DELETE FROM tbl_tp_SLADetail WHERE SLA_Id = @SlaId;
        DELETE FROM tbl_tp_SLAResolutionDetail WHERE SLA_Id = @SlaId;
        DELETE FROM tbl_tp_SLAResponseDetail WHERE SLA_Id = @SlaId;
        UPDATE tbl_tp_SLAMaster
        SET
            SLA_Name = @SlaName,
            SLA_Description = @SlaDescription,
            SequenceNo = @SequenceNo,
            CreatedBy = @TpUserID
        WHERE SLA_Id = @SlaId;

 INSERT INTO tbl_tp_SLADetail (SLA_Id, Priority_ID, Respond_Val, Respond_Unit, Respond_Sec, Resolve_Val, Resolve_Unit, Resolve_Sec, Operational_Unit)    
      SELECT    
        @SlaId AS SLA_Id,    
        COALESCE(JSON_VALUE(value, '$.priorityId'), '0') AS Priority_ID,    
        COALESCE(JSON_VALUE(value, '$.respondWithin.value'), '0') AS Respond_Val,    
        COALESCE(JSON_VALUE(value, '$.respondWithin.unit'), '') AS Respond_Unit,    
        CASE    
          WHEN JSON_VALUE(value, '$.respondWithin.unit') = 'Hours' THEN COALESCE(JSON_VALUE(value, '$.respondWithin.value'), '0') * 3600    
          WHEN JSON_VALUE(value, '$.respondWithin.unit') = 'Month' THEN COALESCE(JSON_VALUE(value, '$.respondWithin.value'), '0') * 30 * 24 * 60    
          WHEN JSON_VALUE(value, '$.respondWithin.unit') = 'Day' THEN COALESCE(JSON_VALUE(value, '$.respondWithin.value'), '0') * 24 * 60    
          ELSE 0    
        END AS Respond_Sec,    
        COALESCE(JSON_VALUE(value, '$.resolveWithin.value'), '0') AS Resolve_Val,    
        COALESCE(JSON_VALUE(value, '$.resolveWithin.unit'), '') AS Resolve_Unit,    
        CASE    
          WHEN JSON_VALUE(value, '$.resolveWithin.unit') = 'Hours' THEN COALESCE(JSON_VALUE(value, '$.resolveWithin.value'), '0') * 3600    
          WHEN JSON_VALUE(value, '$.resolveWithin.unit') = 'Month' THEN COALESCE(JSON_VALUE(value, '$.resolveWithin.value'), '0') * 30 * 24 * 60    
          WHEN JSON_VALUE(value, '$.resolveWithin.unit') = 'Day' THEN COALESCE(JSON_VALUE(value, '$.resolveWithin.value'), '0') * 24 * 60    
          ELSE 0    
        END AS Resolve_Sec,    
        COALESCE(JSON_VALUE(value, '$.operationalHrs'), '') AS Operational_Unit    
      FROM OPENJSON(@SLATargetData, '$.data');    
    
      INSERT INTO dbo.tbl_tp_SLACondition (SLA_Id, FieldName, Operator, Value, Conjunction, SequenceNo, ParentId, createdBy, CreatedDate)    
      SELECT    
        @SlaId,    
        JSON_VALUE(value, '$.fieldName'),    
        JSON_VALUE(value, '$.operator'),    
        JSON_VALUE(value, '$.value'),    
        JSON_VALUE(@SLAConditionData, '$.SLA_Conjunction'),    
        @SequenceNo + 1, @ParentId, @UserId, GETDATE()    
       FROM OPENJSON(@SLAConditionData, '$.ConditionValues');  
   
INSERT INTO tbl_tp_SLAResolutionDetail (
    SLA_Id,
    SequenceNo,
    Frequency,
    Frequency_Sec,
    ResolutionTo,
    ResolutionVal,
    IsEscalation,
    Active,
    ParentId,
    CreatedBy
)
SELECT
    @SlaId AS SLA_Id,
    ROW_NUMBER() OVER (PARTITION BY @SlaId ORDER BY (SELECT NULL)) AS SequenceNo,
    COALESCE(JSON_VALUE([value], '$.selectedSLAPolicyText'), '0') AS Frequency,
    COALESCE(JSON_VALUE([value], '$.selectedSLAPolicy'), '0') AS Frequency_Sec,
    COALESCE(JSON_VALUE([value], '$.radioValue'), 'TicketManager') AS ResolutionTo,
    CASE
        WHEN JSON_VALUE([value], '$.radioValue') = 'agent' THEN JSON_VALUE([value], '$.selectedResponseRemindAgents')
        WHEN JSON_VALUE([value], '$.radioValue') = 'group' THEN JSON_VALUE([value], '$.selectedGroupRemind')
        ELSE '0'
    END AS ResolutionVal,
    CASE WHEN JSON_VALUE([value], '$.IsEscalation') = 'true' THEN '1' ELSE '0' END AS IsEscalation,
    1 AS Active,
    @ParentId,
    @UserId
FROM OPENJSON(@SLAResolutionData);


INSERT INTO tbl_tp_SLAResolutionDetail (
    SLA_Id,
    SequenceNo,
    Frequency,
    Frequency_Sec,
    ResolutionTo,
    ResolutionVal,
    IsEscalation,
    Active,
    ParentId,
    CreatedBy
)
SELECT
    @SlaId AS SLA_Id,
    ROW_NUMBER() OVER (PARTITION BY @SlaId ORDER BY (SELECT NULL)) AS SequenceNo,
    COALESCE(JSON_VALUE([value], '$.selectedSLAPolicyText'), '0') AS Frequency,
    COALESCE(JSON_VALUE([value], '$.selectedSLAPolicy'), '0') AS Frequency_Sec,
    COALESCE(JSON_VALUE([value], '$.radioValue'), 'TicketManager') AS ResolutionTo,
    CASE
        WHEN JSON_VALUE([value], '$.radioValue') = 'agent' THEN JSON_VALUE([value], '$.selectedResponseRemindAgents')
        WHEN JSON_VALUE([value], '$.radioValue') = 'group' THEN JSON_VALUE([value], '$.selectedGroupRemind')
        ELSE '0'
    END AS ResolutionVal,
   COALESCE (JSON_VALUE([value], '$.IsEscalation'),'1')  AS IsEscalation,  
    1 AS Active,
    @ParentId,
    @UserId
FROM OPENJSON(@SLAResolvedData);

 
INSERT INTO tbl_tp_SLAResponseDetail (  
    SLA_Id,  
    SequenceNo,  
    Frequency,  
    Frequency_Sec,  
    ResponseTo,  
    ResponseVal,  
    IsEscalation,  
    Active,  
    ParentId,  
    CreatedBy  
)  
SELECT  
     @SlaId AS SLA_Id,
    ROW_NUMBER() OVER (PARTITION BY @SlaId ORDER BY (SELECT NULL)) AS SequenceNo,
    COALESCE(JSON_VALUE([value], '$.selectedSLAPolicyText'), '0') AS Frequency,
    COALESCE(JSON_VALUE([value], '$.selectedSLAPolicy'), '0') AS Frequency_Sec,
    COALESCE(JSON_VALUE([value], '$.radioValue'), 'TicketManager') AS ResponseTo,
    CASE
        WHEN JSON_VALUE([value], '$.radioValue') = 'agent' THEN JSON_VALUE([value], '$.selectedResponseRemindAgents')
        WHEN JSON_VALUE([value], '$.radioValue') = 'group' THEN JSON_VALUE([value], '$.selectedGroupRemind')
        ELSE '0'
    END AS ResponseVal,
    CASE WHEN JSON_VALUE([value], '$.IsEscalation') = 'true' THEN '1' ELSE '0' END AS IsEscalation,
    1 AS Active,
    @ParentId,
    @UserId
FROM OPENJSON(@SLAResponseData);  

INSERT INTO tbl_tp_SLAResponseDetail (  
    SLA_Id,  
    SequenceNo,  
    Frequency,  
    Frequency_Sec,  
    ResponseTo,  
    ResponseVal,  
    IsEscalation,  
    Active,  
    ParentId,  
    CreatedBy  
)  
SELECT  
     @SlaId AS SLA_Id,
    ROW_NUMBER() OVER (PARTITION BY @SlaId ORDER BY (SELECT NULL)) AS SequenceNo,
    COALESCE(JSON_VALUE([value], '$.selectedSLAPolicyText'), '0') AS Frequency,
    COALESCE(JSON_VALUE([value], '$.selectedSLAPolicy'), '0') AS Frequency_Sec,
    COALESCE(JSON_VALUE([value], '$.radioValue'), 'TicketManager') AS ResponseTo,
    CASE
        WHEN JSON_VALUE([value], '$.radioValue') = 'agent' THEN JSON_VALUE([value], '$.selectedResponseRemindAgents')
        WHEN JSON_VALUE([value], '$.radioValue') = 'group' THEN JSON_VALUE([value], '$.selectedGroupRemind')
        ELSE '0'
    END AS ResponseVal,
    COALESCE (JSON_VALUE([value], '$.IsEscalation'),'1')  AS IsEscalation,  
    1 AS Active,
    @ParentId,
    @UserId
FROM OPENJSON(@SLANotRespondData); 



        SET @rowJson = (SELECT * FROM tbl_tp_SLAMaster WHERE SLA_Id = @SlaId FOR JSON AUTO, INCLUDE_NULL_VALUES);
        IF @rowJson IS NOT NULL
        BEGIN
            EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData
                @User_id = @UserId,
                @Activity_type = 'Update_SLAPolicies',
                @ActionType = 'U',
                @RowJson = @rowJson,
                @Table_name = 'tbl_tp_SLAMaster',
                @ip_adress = @IPAdress,
                @device_id = @DeviceId,
                @IsImpersonation = @IsImpersonation,
                @ImpersonatorId = @ImpersonatorId;
        END;

        SELECT 'Record Updated' AS resp;
    END
    ELSE
    BEGIN
        SELECT 'SLA Id not found' AS resp;
    END;
END
ELSE
BEGIN
    SELECT 'Invalid Option' AS resp;
END;

END;


