/* ============================================================
   Procedure: [dbo].[Usp_tp_InsertUpdateSLAPolicies_temp]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_InsertUpdateSLAPolicies_temp]                              
(                              
  @SLA_Id bigint OUTPUT,                              
  @ParentID bigint,                              
  @SLA_Name nvarchar(100),                            
  @SLA_Description nvarchar(200),                     
  @SequenceNo bigint,                    
  @Option nvarchar(50) = 'Insert',                   
  @SLATargetsData nvarchar(max),                
  @SLAResponseData nvarchar(max),      
  @SLAResolutionData nvarchar(max),       
  @SLAConditionData nvarchar(max),                
  @UserID bigint,                                  
  @MetaData nvarchar(200)                          
)                              
AS  
BEGIN  
  DECLARE @IPAdress NVARCHAR(50), @DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT, @rowJson NVARCHAR(MAX)  
  
  SELECT @IPAdress = JSON_VALUE(@MetaData, '$.IPAddress'),  
         @DeviceId = JSON_VALUE(@MetaData, '$.MacAddress'),  
         @IsImpersonation = JSON_VALUE(@MetaData, '$.IsImpersonation'),  
         @ImpersonatorId = JSON_VALUE(@MetaData, '$.ImpersonatorId')  
  
  IF (@Option = 'Insert')  
  BEGIN  
    IF (NOT EXISTS (SELECT 'x' FROM tbl_tp_SLAMaster WHERE ParentID = @ParentID AND SLA_Name = @SLA_Name))  
    BEGIN  
      INSERT INTO tbl_tp_SLAMaster (ParentID, SLA_Name, SLA_Description, Active, SequenceNo, CreatedDate)  
      VALUES (@ParentID, @SLA_Name, @SLA_Description, 1, @SequenceNo + 1, GETDATE())  
  
      SET @SLA_Id = SCOPE_IDENTITY()  
  
      INSERT INTO dbo.tbl_tp_SLACondition ([SLA_Id], [FieldName], [Operator], [Value], [Conjunction], [SequenceNo])  
      SELECT @SLA_Id,   
             JSON_VALUE(value, '$.fieldName'), -- Extract fieldName from JSON  
             JSON_VALUE(value, '$.operator'),   -- Extract operator from JSON  
             JSON_VALUE(value, '$.value'),      -- Extract value from JSON  
             JSON_VALUE(@SLAConditionData, '$.SLA_Conjunction'),  
             @SequenceNo + 1  
      FROM OPENJSON(@SLAConditionData, '$.ConditionValues');  
  
      INSERT INTO dbo.tbl_tp_SLAResolutionDetail ([SLA_Id], [SequenceNo], [Frequency], [Frequency_Sec], [ResolutionTo])  
      SELECT  
          @SLA_Id,  
          @SequenceNo,  
          CASE  
              WHEN JSON_VALUE([value], '$.radioValue') = 'TicketManager' THEN '-4'  
              WHEN JSON_VALUE([value], '$.radioValue') = 'handlerManager' THEN '-10'  
              ELSE NULL  
          END AS Frequency,  
          '340' AS Frequency_Sec,  
          '32222' AS ResolutionTo  
      FROM OPENJSON(@SLAResolutionData);  
  
      INSERT INTO dbo.tbl_tp_SLAResponseDetail (  
          SLA_Id,  
          SequenceNo,  
          Frequency,  
          Frequency_Sec,  
          ResponseTo,  
          ResponseVal,  
          IsEscalation,  
          Active  
      )  
      SELECT  
          @SLA_Id AS SLA_Id,  
          @SequenceNo AS SequenceNo,  
          CASE  
              WHEN JSON_VALUE([value], '$.radioValue') = 'TicketManager' THEN '-4'  
              WHEN JSON_VALUE([value], '$.radioValue') = 'admin' THEN '-1'  
              ELSE NULL  
          END AS Frequency,  
          '340' AS Frequency_Sec,  
          '32222' AS ResponseTo,  
          '32222' AS ResponseVal, -- Update this value as needed  
          'true' AS IsEscalation, -- Assuming IsEscalation is always 'true' in this case  
          1 AS Active -- You can set the Active flag as needed  
      FROM OPENJSON(@SLAResponseData);  
  
      SET @rowJson = (SELECT * FROM tbl_tp_SLAMaster WHERE SLA_Id = @SLA_Id FOR JSON AUTO, INCLUDE_NULL_VALUES);  
  
      IF @rowJson IS NOT NULL  
      BEGIN  
        EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData @User_id = @UserId,  
                                                          @Activity_type = 'Add_SLAPolicies',  
                                                          @ActionType = 'I',  
                                                          @RowJson = @rowJson,  
                                                          @Table_name = 'tbl_tp_SLAMaster',  
                                                          @ip_adress = @IPAdress,  
                                                          @device_id = @DeviceId,  
                                                          @IsImpersonation = @IsImpersonation,  
                                                          @ImpersonatorId = @ImpersonatorId;  
      END;  
  
      SELECT 'Record Saved' AS resp;  
    END  
    ELSE  
    BEGIN  
      SELECT 'Policy Name Already Exists' AS resp;  
    END;  
  END  
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_InsertUpdateTicketPriority]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE [dbo].[Usp_tp_InsertUpdateTicketPriority]            
(          
 @Priority_ID bigint OUTPUT, 
 @PriorityName nvarchar(100),
 @Active bit = 1,        
 @flOpt varchar(10) = 'Insert',      
 @tpuserid bigint,              
 @MetaData nvarchar(200)      
)            
AS            
             
BEGIN           
      
DECLARE @TimeZone nvarchar (400), @ParentID bigint, @UserId bigint, @rowJson NVARCHAR(MAX), @IPAdress NVARCHAR(50), @DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT        
SELECT @ParentID = ParentId, @UserId = USER_ID, @TimeZone = TimeZone  FROM tbl_tp_UserLogin (NOLOCK) WHERE TpUser_Id = @tpuserid                
                
SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)        
SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)        
SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)        
SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)      

IF @flOpt = 'Insert'             
BEGIN             
  IF EXISTS (SELECT 1 FROM tbl_tp_TicketPriorityMaster WHERE PriorityName = @PriorityName AND ParentId = @ParentId AND Active=1)            
  BEGIN            
    SELECT 'Priority already exists' resp
    RETURN 
  END

  INSERT INTO tbl_tp_TicketPriorityMaster            
         (ParentId, PriorityName, SequenceNo, Active, CreatedDate, CreatedBy)            
   VALUES            
         (@ParentId, @PriorityName, COALESCE((SELECT MAX(SequenceNo) + 1 FROM tbl_tp_TicketPriorityMaster WHERE ParentId = @ParentId), 1), @Active, GETDATE(), @tpuserid) 
         
  SET @Priority_ID = SCOPE_IDENTITY()

  SELECT 'Inserted' resp           
  SET @rowJson = (SELECT * FROM tbl_tp_TicketPriorityMaster WHERE Priority_ID = @Priority_ID FOR JSON AUTO, INCLUDE_NULL_VALUES)                
                
  IF @rowJson IS NOT NULL                
  BEGIN                
    EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData @User_id = @UserId                
          , @Activity_type = 'Add_TicketPriority'                
          , @ActionType = 'I'                
          , @RowJson = @rowJson                
          , @Table_name = 'tbl_tp_TicketPriorityMaster', @ip_adress = @IPAdress, @device_id = @DeviceId, @IsImpersonation = @IsImpersonation, @ImpersonatorId = @ImpersonatorId         
  END      
END            
ELSE IF @flOpt = 'Update'             
BEGIN            
  IF EXISTS (SELECT 1 FROM tbl_tp_TicketPriorityMaster WHERE PriorityName = @PriorityName AND Priority_ID <> @Priority_ID AND Active=1)            
  BEGIN            
    SELECT 'Priority already exists' resp
    RETURN 
  END

  UPDATE tbl_tp_TicketPriorityMaster            
  SET Active = @Active, PriorityName = @PriorityName ,ModifiedBy=@ParentID,ModifiedDate= GETDATE()          
  WHERE ParentId = @ParentId AND Priority_ID = @Priority_ID           
         
  SELECT 'Updated' resp
  SET @rowJson = (SELECT * FROM tbl_tp_TicketPriorityMaster WHERE Priority_ID = @Priority_ID FOR JSON AUTO, INCLUDE_NULL_VALUES)                
                
  IF @rowJson IS NOT NULL                
  BEGIN                
    EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData @User_id = @UserId                
          , @Activity_type = 'Update_TicketPriority'                
          , @ActionType = 'U'                
          , @RowJson = @rowJson                
          , @Table_name = 'tbl_tp_TicketPriorityMaster', @ip_adress = @IPAdress, @device_id = @DeviceId, @IsImpersonation = @IsImpersonation, @ImpersonatorId = @ImpersonatorId         
  END      
END           
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_InsertUpdateUserRole]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE [dbo].[Usp_tp_InsertUpdateUserRole]      
(      
    @RoleId BIGINT OUTPUT,      
    @TpUserId BIGINT,      
    @RoleName NVARCHAR(100),      
    @Description NVARCHAR(200),      
    @Option NVARCHAR(10),      
    @DataTable NVARCHAR(MAX),  
    @fieldData NVARCHAR(MAX),  
    @agentpermission NVARCHAR(MAX), 
    @grouppermission NVARCHAR(MAX), 
    @Agent NVARCHAR(MAX), 
    @AgentType BIGINT,
    @baserole BIGINT,
    @MetaData NVARCHAR(200)      
)      
AS      
BEGIN  
--declare
--    @RoleId BIGINT=0 ,      
--    @TpUserId BIGINT=1,      
--    @RoleName NVARCHAR(100)='usertetsproce3',      
--    @Description NVARCHAR(200)='askdaksdkaksdkasd3323',      
--    @Option NVARCHAR(10)='Insert',      
--    @DataTable NVARCHAR(MAX)='[null,null,null,null,null,null,null,"1","2","3",null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null]',  
--	@fieldData NVARCHAR(MAX)='[{"radioValue":0,"dropdownValue":""},{"radioValue":0,"dropdownValue":""},{"radioValue":0,"dropdownValue":""},{"radioValue":0,"dropdownValue":""},{"radioValue":0,"dropdownValue":""},{"radioValue":0,"dropdownValue":""},{"radioValue":0,"dropdownValue":""},{"radioValue":0,"dropdownValue":""},{"radioValue":0,"dropdownValue":""},{"radioValue":0,"dropdownValue":""},{"radioValue":0,"dropdownValue":""},{"radioValue":0,"dropdownValue":""},{"radioValue":0,"dropdownValue":""},{"radioValue":0,"dropdownValue":""},{"permissionId":"1","radioValue":1,"dropdownValue":""},{"permissionId":"1","radioValue":0,"dropdownValue":""},{"permissionId":"2","radioValue":0,"dropdownValue":""},{"permissionId":"2","radioValue":0,"dropdownValue":""},{"permissionId":"3","radioValue":1,"dropdownValue":""},{"permissionId":"3","radioValue":0,"dropdownValue":""},{"permissionId":"4","radioValue":0,"dropdownValue":""},{"permissionId":"4","radioValue":0,"dropdownValue":""}], ',
--	@agentgrouppermission NVARCHAR(MAX)='[]', 
--    @Agent NVARCHAR(MAX)='', 
--	@AgentType BIGINT=1,
--	@baserole BIGINT=6,
--    @MetaData NVARCHAR(200)='{}'      
    DECLARE @UserId BIGINT, @ParentId BIGINT, @TimeZone NVARCHAR(400), @rowJson NVARCHAR(MAX), @IPAddress NVARCHAR(50), @DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT;      
    SELECT @UserId = User_Id, @ParentId = ParentId, @TimeZone = TimeZone 
    FROM tbl_tp_UserLogin (NOLOCK) 
    WHERE TpUser_Id = @TpUserId AND IsActive = 1;
    
    IF (@baserole = 0) BEGIN  
        SET @baserole = NULL;
    END;

    SET @IPAddress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress);      
    SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress);      
    SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation);      
    SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId);

    -- Check if RoleName already exists
IF EXISTS (SELECT 1 
           FROM tbl_tp_RolesMaster 
           WHERE RoleName = @RoleName 
		     AND IsActive = 1
           AND (ParentId = @ParentId OR ParentId = 0)
           AND (Role_Id <> @RoleId))
BEGIN
    SELECT 'Role already exists' AS resp;
    RETURN;
END


    IF (@Option = 'Insert')      
    BEGIN 
        IF NOT EXISTS (SELECT 1 FROM tbl_tp_RolesMaster WHERE Role_Id = @RoleId)
        BEGIN    
            INSERT INTO tbl_tp_RolesMaster (
                ParentId, RoleName, Description, Agent_type, IsActive, 
                CreatedBy, CreatedDate, IsPredefined, ParentRole_Id
            )    
            VALUES (
                @ParentId, @RoleName, @Description, @AgentType, 1, 
                @UserId, GETDATE(), 0, @baserole
            );
            
            SET @RoleId = SCOPE_IDENTITY();    

            INSERT INTO dbo.tbl_tp_Permission_Mapping (Role_Id, Permission_Id, CreatedBy, CreatedOn)    
            SELECT @RoleId, value, @UserId, GETDATE()    
            FROM OPENJSON(@DataTable) AS jsonArr    
            WHERE ISNUMERIC(jsonArr.value) = 1;

            -- Handle PermissionField Mapping
            DECLARE @JsonDataTemp TABLE (
                PermissionId INT, RadioValue INT, DropdownValue NVARCHAR(MAX)
            );

            INSERT INTO @JsonDataTemp (PermissionId, RadioValue, DropdownValue)
            SELECT
                JSON_VALUE(j.value, '$.permissionId') AS PermissionId,
                JSON_VALUE(j.value, '$.radioValue') AS RadioValue,
                JSON_VALUE(j.value, '$.dropdownValue') AS DropdownValue
            FROM OPENJSON(@fieldData) j;

            INSERT INTO dbo.tbl_tp_PermissionField_Mapping (Role_Id, Permission_Id, FieldName, IsAllowed, CreatedBy, CreatedOn, IsActive)
            SELECT
                @RoleId, PermissionId, value, RadioValue, 1, GETDATE(), 1
            FROM @JsonDataTemp
            CROSS APPLY STRING_SPLIT(DropdownValue, ',')
            WHERE PermissionId IS NOT NULL AND RadioValue IS NOT NULL AND DropdownValue IS NOT NULL AND DropdownValue != '';

			--------------------------------------AssignemtPermssion-------------------------------------------------------------
			 DECLARE @JsonpermissionDataTemp TABLE (
                PermissionId INT, RadioValue NVarchar(50), DropdownValue NVARCHAR(MAX)
            );

            INSERT INTO @JsonpermissionDataTemp (PermissionId, RadioValue, DropdownValue)
            SELECT
                JSON_VALUE(j.value, '$.permissionId') AS PermissionId,
                JSON_VALUE(j.value, '$.radioValue') AS RadioValue,
                JSON_VALUE(j.value, '$.dropdownValue') AS DropdownValue
            FROM OPENJSON(@agentpermission) j;

            INSERT INTO dbo.tbl_tp_Assignment_PermissionField (Role_Id, Permission_Id,PermissionValues, PermissionCode, CreatedBy, CreatedOn, IsActive)
            SELECT
                @RoleId, PermissionId, value, RadioValue, 1, GETDATE(), 1
            FROM @JsonpermissionDataTemp
            CROSS APPLY STRING_SPLIT(DropdownValue, ',')
            WHERE PermissionId IS NOT NULL AND RadioValue IS NOT NULL;

				 DECLARE @JsonpermissionDataTemp1 TABLE (
                PermissionId INT, RadioValue NVarchar(50), DropdownValue NVARCHAR(MAX)
            );

            INSERT INTO @JsonpermissionDataTemp1 (PermissionId, RadioValue, DropdownValue)
            SELECT
                JSON_VALUE(j.value, '$.permissionId') AS PermissionId,
                JSON_VALUE(j.value, '$.radioValue') AS RadioValue,
                JSON_VALUE(j.value, '$.dropdownValue') AS DropdownValue
            FROM OPENJSON(@grouppermission) j;

            INSERT INTO dbo.tbl_tp_Assignment_PermissionField (Role_Id, Permission_Id,PermissionValues, PermissionCode, CreatedBy, CreatedOn, IsActive)
            SELECT
                @RoleId, PermissionId, value, RadioValue, 1, GETDATE(), 1
            FROM @JsonpermissionDataTemp1
            CROSS APPLY STRING_SPLIT(DropdownValue, ',')
            WHERE PermissionId IS NOT NULL AND RadioValue IS NOT NULL;



            -- Agent Role Mapping
            DECLARE @TempTable TABLE (AgentValue NVARCHAR(MAX));  

            ;WITH SplitValues AS (  
                SELECT value FROM STRING_SPLIT(@Agent, ',')  
            )  
            INSERT INTO @TempTable (AgentValue)
            SELECT value FROM SplitValues;

            INSERT INTO tbl_tp_agentrolemapping (tpuserid, role_id, Active, CreatedBy, CreatedDate)
            SELECT AgentValue, @RoleId, 1, @TpUserId, GETDATE()  
            FROM @TempTable;

            SELECT 'Role and permissions have been created successfully' AS resp;

            -- Audit logging
            SET @rowJson = (SELECT * FROM tbl_tp_RolesMaster WHERE Role_Id = @RoleId FOR JSON AUTO, INCLUDE_NULL_VALUES);
            IF @rowJson IS NOT NULL    
            BEGIN    
                EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData    
                    @User_id = @UserId,    
                    @Activity_type = 'Inst_rolemaster',    
                    @ActionType = 'I',    
                    @RowJson = @rowJson,    
                    @Table_name = 'tbl_tp_RolesMaster',    
                    @ip_adress = @IPAddress,    
                    @device_id = @DeviceId,    
                    @IsImpersonation = @IsImpersonation,    
                    @ImpersonatorId = @ImpersonatorId;    
            END
        END
        ELSE
        BEGIN    
            SELECT 'Role already exists' AS resp;    
        END
    END
    ELSE IF (@Option = 'Update')
    BEGIN      
        IF EXISTS (SELECT 1 FROM tbl_tp_RolesMaster WHERE Role_Id = @RoleId)      
        BEGIN      
            UPDATE tbl_tp_RolesMaster      
            SET      
                ParentId = @ParentId,      
                RoleName = @RoleName,      
                Description = @Description,      
                Agent_type = 1,       
                IsActive = 1,       
                CreatedBy = @UserId,      
                CreatedDate = GETDATE(),      
                IsPredefined = 0,
                ParentRole_Id = @baserole
            WHERE Role_Id = @RoleId;      

            -- Update Permission Mapping
            DELETE FROM tbl_tp_Permission_Mapping WHERE Role_Id = @RoleId;

            INSERT INTO dbo.tbl_tp_Permission_Mapping (Role_Id, Permission_Id, CreatedBy, CreatedOn)      
            SELECT @RoleId, value, @UserId, GETDATE()      
            FROM OPENJSON(@DataTable) AS jsonArr      
            WHERE ISNUMERIC(jsonArr.value) = 1;

            -- Update PermissionField Mapping
            DELETE FROM tbl_tp_PermissionField_Mapping WHERE Role_Id = @RoleId;

            DECLARE @JsonDataTemp1 TABLE (
                PermissionId INT, RadioValue INT, DropdownValue NVARCHAR(MAX)
            );

            INSERT INTO @JsonDataTemp1 (PermissionId, RadioValue, DropdownValue)
            SELECT
                JSON_VALUE(j.value, '$.permissionId') AS PermissionId,
                JSON_VALUE(j.value, '$.radioValue') AS RadioValue,
                JSON_VALUE(j.value, '$.dropdownValue') AS DropdownValue
            FROM OPENJSON(@fieldData) j;

            INSERT INTO dbo.tbl_tp_PermissionField_Mapping (Role_Id, Permission_Id, FieldName, IsAllowed, CreatedBy, CreatedOn, IsActive)
            SELECT
                @RoleId, PermissionId, value, RadioValue, 1, GETDATE(), 1
            FROM @JsonDataTemp1
            CROSS APPLY STRING_SPLIT(DropdownValue, ',')
            WHERE PermissionId IS NOT NULL AND RadioValue IS NOT NULL AND DropdownValue IS NOT NULL AND DropdownValue != '';

			---------------------------------------------------udpate assignment permission mapping-------------------------------
			  DELETE FROM tbl_tp_Assignment_PermissionField WHERE Role_Id = @RoleId;

			 DECLARE @JsonpermissionDataTemp2 TABLE (
                PermissionId INT, RadioValue NVARCHAR(50), DropdownValue NVARCHAR(MAX)
            );

            INSERT INTO @JsonpermissionDataTemp2 (PermissionId, RadioValue, DropdownValue)
            SELECT
                JSON_VALUE(j.value, '$.permissionId') AS PermissionId,
                JSON_VALUE(j.value, '$.radioValue') AS RadioValue,
                JSON_VALUE(j.value, '$.dropdownValue') AS DropdownValue
            FROM OPENJSON(@agentpermission) j;

            INSERT INTO dbo.tbl_tp_Assignment_PermissionField (Role_Id, Permission_Id,PermissionValues, PermissionCode, CreatedBy, CreatedOn, IsActive)
            SELECT
                @RoleId, PermissionId, value, RadioValue, 1, GETDATE(), 1
            FROM @JsonpermissionDataTemp2
            CROSS APPLY STRING_SPLIT(DropdownValue, ',')
            WHERE PermissionId IS NOT NULL AND RadioValue IS NOT NULL;

			
			 DECLARE @JsonpermissionDataTemp3 TABLE (
                PermissionId INT, RadioValue NVARCHAR(50), DropdownValue NVARCHAR(MAX)
            );

            INSERT INTO @JsonpermissionDataTemp3 (PermissionId, RadioValue, DropdownValue)
            SELECT
                JSON_VALUE(j.value, '$.permissionId') AS PermissionId,
                JSON_VALUE(j.value, '$.radioValue') AS RadioValue,
                JSON_VALUE(j.value, '$.dropdownValue') AS DropdownValue
            FROM OPENJSON(@grouppermission) j;

            INSERT INTO dbo.tbl_tp_Assignment_PermissionField (Role_Id, Permission_Id,PermissionValues, PermissionCode, CreatedBy, CreatedOn, IsActive)
            SELECT
                @RoleId, PermissionId, value, RadioValue, 1, GETDATE(), 1
            FROM @JsonpermissionDataTemp3
            CROSS APPLY STRING_SPLIT(DropdownValue, ',')
            WHERE PermissionId IS NOT NULL AND RadioValue IS NOT NULL;
            -- Update Agent Role Mapping

            DELETE FROM tbl_tp_agentrolemapping WHERE Role_Id = @RoleId;

            DECLARE @TempTable1 TABLE (AgentValue NVARCHAR(MAX));  

            ;WITH SplitValues AS (  
                SELECT value FROM STRING_SPLIT(@Agent, ',')  
            )  
            INSERT INTO @TempTable1 (AgentValue)
            SELECT value FROM SplitValues;

            INSERT INTO tbl_tp_agentrolemapping (tpuserid, role_id, Active, CreatedBy, CreatedDate)
            SELECT AgentValue, @RoleId, 1, @TpUserId, GETDATE()  
            FROM @TempTable1;

            SELECT 'Role and permissions have been updated successfully' AS resp;

            -- Audit logging
            SET @rowJson = (SELECT * FROM tbl_tp_RolesMaster WHERE Role_Id = @RoleId FOR JSON AUTO, INCLUDE_NULL_VALUES);
            IF @rowJson IS NOT NULL
            BEGIN
                EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData
                    @User_id = @UserId,    
                    @Activity_type = 'Updt_rolemaster',    
                    @ActionType = 'U',    
                    @RowJson = @rowJson,    
                    @Table_name = 'tbl_tp_RolesMaster',    
                    @ip_adress = @IPAddress,    
                    @device_id = @DeviceId,    
                    @IsImpersonation = @IsImpersonation,    
                    @ImpersonatorId = @ImpersonatorId;    
            END
        END
        ELSE
        BEGIN      
            SELECT 'Role does not exist' AS resp;      
        END      
    END
END



