/* ============================================================
   Procedure: [dbo].[Usp_tp_MapUserWithGroup]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 
CREATE   PROCEDURE [dbo].[Usp_tp_MapUserWithGroup]                    
                   
  @ParentId BigInt ,
  @GroupId BigInt,
  @UserId BigInt,
  @AccessLevel NVARCHAR(MAX),
  @MetaData NVARCHAR(MAX)
                  
AS                    
Begin

    DECLARE @TimeZone NVARCHAR(400),  
            @rowJson NVARCHAR(MAX),  
            @IPAdress NVARCHAR(50),  
            @DeviceId NVARCHAR(50),  
            @IsImpersonation BIT,  
            @ImpersonatorId INT  
  
    SELECT @ParentID = ParentId, @TimeZone = TimeZone  FROM User_Detail (NOLOCK)  WHERE User_Id = @UserID  
  
    SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)  
    SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)  
    SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)  
    SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId) 
      
            Update tbl_tp_UserLogin SET GroupId = @GroupId,
                            Access_level = @AccessLevel
                            Where IsActive = 1 
                            AND ParentId = @ParentId 
                            AND User_Id = @UserId

							Select 'User has been mapped with group' as msg

							
    SET @rowJson = (SELECT * FROM tbl_tp_GroupMaster FOR JSON AUTO, INCLUDE_NULL_VALUES)  
  
    IF @rowJson IS NOT NULL  
    BEGIN  
        EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData  
            @User_id = @UserId,  
            @Activity_type = 'Updt_userlogin',  
            @ActionType = 'U',  
            @RowJson = NULL,  
            @Table_name = 'tbl_tp_UserLogin',  
            @ip_adress = @IPAdress,  
            @device_id = @DeviceId,  
            @IsImpersonation = @IsImpersonation,  
            @ImpersonatorId = @ImpersonatorId  
    END  
      
End       



