/* ============================================================
   Procedure: [dbo].[Usp_tp_MegeTicketOperation]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_MegeTicketOperation]       -- 2,3,32222,32222            
(                    
@TargetTicketId nvarchar(Max),                     
@SourceTicketId bigint,                
@TpUserId bigint     
)                    
AS                    
begin        
              
        
    DECLARE   
        @DynamicSQL NVARCHAR(MAX),  
        @status INT,  
        @ParentId BIGINT,   
        @tableName NVARCHAR(MAX),  
        @tTicketNo NVARCHAR(16),  
        @sTicketNo NVARCHAR(MAX);    
  
    SELECT @ParentId = ParentId    
    FROM tbl_tp_UserLogin (NOLOCK)   
    WHERE TpUser_Id = @TpUserId AND IsActive = 1;  
      
    EXEC @status = Usp_tp_CreateTicketMasterTableByParentID @ParentId, @tableName OUTPUT;        
  
    SET @DynamicSQL =       
    'DECLARE @ParentID BIGINT, @tTicketNo NVARCHAR(16), @TpUserId BIGINT;      
          
    SELECT @TpUserId = tpUser_Id, @ParentID = ParentID, @tTicketNo = TicketNo      
    FROM ' + QUOTENAME(@tableName) + '      
    WHERE TicketID IN (' + @TargetTicketId + ');      
      
    SELECT @sTicketNo = TicketNo   
    FROM ' + QUOTENAME(@tableName) + '      
    WHERE TicketID = ' + CAST(@SourceTicketId AS NVARCHAR(MAX)) + ';      
      
    BEGIN TRY  
        UPDATE ' + QUOTENAME(@tableName) + '      
        SET IsMerged = 1,IsActive = 0, Note = ''Merged with '' + CAST(@sTicketNo AS NVARCHAR(16))      
        WHERE TicketID IN (' + @TargetTicketId + ');    
      
        UPDATE ' + QUOTENAME(@tableName) + '      
        SET       
            MergedBy = @TpUserId,     
            MergedOn  = GETDATE()  
        WHERE TicketID = ' + CAST(@SourceTicketId AS NVARCHAR(MAX)) + ' OR TicketID IN (' + @TargetTicketId + ');  
    END TRY  
    BEGIN CATCH  
        PRINT ERROR_MESSAGE();  
    END CATCH;';  
  
  
    PRINT @DynamicSQL;  
  
    EXEC sp_executesql       
        @DynamicSQL,      
        N'@SourceTicketId INT, @TargetTicketId NVARCHAR(MAX), @tableName NVARCHAR(100), @sTicketNo NVARCHAR(MAX)',      
        @SourceTicketId, @TargetTicketId, @tableName, @sTicketNo;      
      
        
 END


GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_NotifyToAgents]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_NotifyToAgents]
    @NotificationDetailId INT,
	@AgentsId NVARCHAR(MAX),
    @TpUserId BIGINT,
    @MetaData NVARCHAR(MAX)


AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @ParentID Bigint,@UserId Bigint, @TimeZone nvarchar (400)  ,@rowJson NVARCHAR(MAX)  , @IPAdress NVARCHAR(50),@DeviceId NVARCHAR(50),@IsImpersonation BIT ,@ImpersonatorId INT 
	
    Select @ParentId = ParentId ,@UserId = User_Id From tbl_tp_UserLogin (noLock) Where TpUser_Id = @TpUserId   AND IsActive = 1
                
    SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)        
    SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)        
    SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)        
    SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)

    IF NOT EXISTS (SELECT 1 FROM tbl_tp_EmailNotificationRequesterDetail WHERE NotificationDetailId = @NotificationDetailId)
    BEGIN

       INSERT INTO tbl_tp_EmailNotificationRequesterDetail(NotificationDetailId,UserId,IsActive,ParentId,CreatedBy,CreatedOn)
	   Values (@NotificationDetailId,@AgentsId,1,@ParentId,@UserId,GETDATE())

		   	SET @rowJson = (SELECT * FROM tbl_tp_EmailNotificationRequesterDetail tm WHERE (NotificationDetailId = @NotificationDetailId ) AND (ParentID = @ParentId) FOR JSON AUTO, INCLUDE_NULL_VALUES);
    IF @rowJson IS NOT NULL
    BEGIN
        EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData
            @User_id = @UserId,
            @Activity_type = 'Inst_updateNotifyAgent',
            @ActionType = 'U',
            @RowJson = @rowJson,
            @Table_name = 'tbl_tp_EmailNotificationRequesterDetail',
            @ip_adress = @IPAdress,
            @device_id = @DeviceId,
            @IsImpersonation = @IsImpersonation,
            @ImpersonatorId = @ImpersonatorId;
        END

		Select 'Selected agents has been notified .' AS Message
    END
END



