/*..                         
exec Usp_tp_PerformMassOperationTicketById @OperationType=N'InValid',@TicketIds=N'93',@Group=0,@User=0,@TpUserId=1,@ParentId=32222,@MetaData=N'{"IPAddress":"::1","MacAddress":"00FF61AD0C56","IsImpersonation":false,"ImpersonatorId":0}'
exec Usp_tp_PerformMassOperationTicketById @OperationType=N'Duplicate',@TicketIds=N'93',@Group=0,@User=0,@TpUserId=1,@ParentId=32222,@MetaData=N'{"IPAddress":"::1","MacAddress":"00FF61AD0C56","IsImpersonation":false,"ImpersonatorId":0}'
