CREATE   PROCEDURE [dbo].[Usp_tp_PerformMassOperationTicketById]
(              
	@OperationType NVARCHAR(20),
	@Group BIGINT,
	@User BIGINT,
	@TicketIds NVARCHAR(MAX),
	@ParentId BIGINT ,
	@TpUserId BIGINT,
	@MetaData NVARCHAR(MAX)
)              
AS                
BEGIN
 --declare @OperationType NVARCHAR(20)=N'Close',@Group BIGINT=0,@User BIGINT=56,@TicketIds NVARCHAR(MAX)=N'118',@ParentId BIGINT=32222 ,@TpUserId BIGINT=1,@MetaData NVARCHAR(MAX)=N'{"IPAddress":"::1","MacAddress":"00FF61AD0C56","IsImpersonation":false,"ImpersonatorId":0}'

              
	DECLARE @status INT ,@UserId BIGINT, @TicketStatusID bigint=1, @TicketPriority bigint=1
	DECLARE @DynamicQuery NVARCHAR(MAX), @strQuery NVARCHAR(MAX);
	DECLARE @TableName NVARCHAR(MAX), @TicketActivityTable NVARCHAR(MAX);
	declare @tbl table (SNo int identity(1,1),TicketId bigint)
	declare @i int=1, @rowcnt int=0, @TicketID bigint
	DECLARE @ActivityId BIGINT, @EventDesc NVARCHAR(MAX), @UserCreated NVARCHAR(100), @TicketNo NVARCHAR(50), @CreatedOn DATE, @EntityName varchar(500), @EntityId bigint, @TicketHistoryId bigint=0,@EventName NVARCHAR(MAX)
	--DECLARE @tbl_TicketHistoryId TABLE (SNo int identity(1,1),TicketId bigint,TicketHistoryId BIGINT);          

	SELECT @UserId = User_ID, @UserCreated = Name 
	FROM tbl_tp_UserLogin(NOLOCK) WHERE TpUser_Id = @TpUserId AND IsActive = 1

	EXEC @status = Usp_tp_CreateTicketMasterTableByParentID @ParentID, @TableName OUTPUT

	Exec [Usp_tp_CreateTicketActivityTableByParentID] @ParentID, @TicketActivityTable OUTPUT

	insert into @tbl(TicketId)
	select [value]
	FROM STRING_SPLIT(@TicketIds, ',')

	select @rowcnt=count(*) From @tbl

	drop table if exists #tbl_TicketHistoryId
	drop table if exists #tbl_tp_TicketHistoryBeforeEdit
		
	create TABLE #tbl_TicketHistoryId(SNo int identity(1,1),TicketId bigint,TicketHistoryId BIGINT);
	create table #tbl_tp_TicketHistoryBeforeEdit
	(
		TicketID			bigint,
		tpUser_Id			bigint,
		ParentID			bigint,
		TicketNo			nvarchar(100),	     	     
		RequesterMobileNo	nvarchar(100),	     	     
		RequesterEmailID	nvarchar(400),	     	     
		RequesterMobileNo1	nvarchar(100),	     	     
		RequesterEmailID1	nvarchar(400),	     	     
		RequesterMobileNo2	nvarchar(100),	     	     
		RequesterEmailID2	nvarchar(400),	     	     
		Subject				nvarchar(2000),
		Description			nvarchar(max),
		TicketStatusID		bigint,
		Remarks				nvarchar(max),
		Note				nvarchar(max),
		UserResponse		nvarchar(max),
		TicketPriority		bigint,
		AssignedUser		bigint,
		AssignedGroup		bigint,
		AssignedSource		nvarchar(100),
		TicketCategoryId	bigint,
		TicketTypeId		int,
		TicketSourceId		bigint,
		ProductId			bigint,
		IsMerged			bit,
		IsSplitted			bit,
		IsParentTicket		bit,
		IsChildTicket		bit,
		ParentTicketID		bigint,
		LastActionDatetime	datetime,
		AssignedBy			bigint,
		AssignedDateTime	datetime,
		TicketTag			nvarchar(2000),
		EntityID			bigint,
		EntityName			nvarchar(40),
		Company				nvarchar(800),
		CreatedBy			bigint,
		CreatedOn			datetime
	)

	--insert into #tbl_tp_TicketHistoryBeforeEdit
	--Select TicketHistoryID, TicketID, TicketStatusID, ParentID, ActionDateTime, Remarks, Note, UserResponse,
	--	AssignedUser, AssignedGroup, TicketPriority, AssignedBy
	--From vw_tp_LastTicketHistory TH 
	--Where TH.ParentID=@ParentID and TH.TicketID in (Select TicketId From @tbl)

	DECLARE @DynamicUpdateQuery NVARCHAR(MAX);
		                      
	SELECT @DynamicUpdateQuery = concat(N'insert into #tbl_tp_TicketHistoryBeforeEdit(TicketID, tpUser_Id, ParentID, TicketNo, RequesterMobileNo, RequesterEmailID, RequesterMobileNo1, RequesterEmailID1, RequesterMobileNo2, RequesterEmailID2, Subject, Description, TicketStatusID, Remarks, Note, UserResponse, TicketPriority, AssignedUser, AssignedGroup, AssignedSource, TicketCategoryId, TicketTypeId, TicketSourceId, ProductId, IsMerged, IsSplitted, IsParentTicket, IsChildTicket, ParentTicketID, LastActionDatetime, AssignedBy, AssignedDateTime, TicketTag, EntityID, EntityName, Company, CreatedBy, CreatedOn)
	Select	TicketID, tpUser_Id, ParentID, TicketNo, RequesterMobileNo, RequesterEmailID, RequesterMobileNo1, RequesterEmailID1, RequesterMobileNo2, RequesterEmailID2, Subject, Description, TicketStatusID, Remarks, Note, UserResponse, TicketPriority, AssignedUser, AssignedGroup, AssignedSource, TicketCategoryId, TicketTypeId, TicketSourceId, ProductId, IsMerged, IsSplitted, IsParentTicket, IsChildTicket, ParentTicketID, LastActionDatetime, AssignedBy, AssignedDateTime, TicketTag, EntityID, EntityName, Company, CreatedBy, CreatedOn
	From ',@TableName, N'
	Where TicketID in (', 'select [value] FROM STRING_SPLIT(''',@TicketIds,''', '',''))')

	print concat('@DynamicUpdateQuery: ',@DynamicUpdateQuery)
	EXEC sp_executesql @DynamicUpdateQuery;

	IF (@OperationType = 'Delete')
	BEGIN
		SET @DynamicQuery = '              
		UPDATE ' + @TableName + '              
			SET IsActive = 0,              
			ModifiedOn = GETDATE(),
		    LastActionDatetime = GETDATE(),     
			ModifiedBy = ' + CAST(@TpUserId AS NVARCHAR(MAX)) + '              
			WHERE TicketID IN (' + @TicketIds + ');              
                  
		SELECT ''Tickets deleted successfully'' AS Result;              
		';
		
		While (@i <= @rowcnt)
		Begin
			select @TicketID=TicketId From @tbl Where SNo=@i

			Set @strQuery=Concat(N'insert into ',@TicketActivityTable,N'(TicketID,ParentID,FieldName,OldValue,NewValue,ActivityDescription,ActivityDatetime,ActivityBy)
			values(@TicketID1,@ParentId1,''IsActive'',1,0,''Manual Mass Ticket Deletion'',getdate(),@TpUserId1); Set @ActivityId1=Scope_Identity();')

			Exec sp_executesql @strQuery,N'@TicketID1 bigint,@ParentId1 BIGINT,@TpUserId1 bigint,@ActivityId1 bigint output',@TicketID1=@TicketID, @ParentId1=@ParentId, @TpUserId1=@TpUserId, @ActivityId1=@ActivityId output

			Set @strQuery=N'SELECT @TicketNo1 = TicketNo, @CreatedOn1 = CreatedOn, @EntitytID1=EntityID, @EntityName1=EntityName
			FROM ' + @TableName + '
			Where TicketId=@TicketID1'

			Exec sp_executesql @strQuery, N'@TicketNo1 varchar(50) output, @CreatedOn1 datetime output, @EntitytID1 bigint output, @EntityName1 varchar(500) output, @TicketID1 bigint', @TicketNo1=@TicketNo output, @CreatedOn1=@CreatedOn output, @EntitytID1=@EntityId output, @EntityName1=@EntityName output, @TicketID1=@TicketID

			SELECT @EventDesc = @UserCreated + ' has deleted ticketno ' + @TicketNo + ' on ' +
			CONVERT(NVARCHAR(255), GETDATE())
			SELECT @EventName ='Ticket Deleted for ' +@EntityName

			exec UspSaveEntityActivity_withid @entityname = @EntityName, @EntityID = @EntityId, @UserID= @UserId, @ParentID = @ParentID, @EventDescription = @EventDesc, @EventName = @EventName, @reftables = @TicketActivityTable, @refid= @ActivityId

			--exec UspSaveEntityActivity_withid @entityname = @EntityName, @EntityID = @EntityId, @UserID= @UserId, @ParentID = @ParentID, @EventDescription = @EventDesc, @EventName = 'Ticket Deleted', @reftables = @TableName, @refid= @TicketID

			set @i = @i + 1
		End

	END
            
	IF (@OperationType = 'Assign')
	BEGIN
		IF (@Group > 0)          
		BEGIN
			SET @DynamicQuery = '
				UPDATE ' + QUOTENAME(@TableName) + '          
				SET AssignedUser = @User,
					AssignedGroup = @Group,          
					LastActionDatetime = GETDATE(),          
					AssignedDateTime = GETDATE(),
					AssignedBy=@TpUserId,
					ModifiedOn = GETDATE(),          
					ModifiedBy = @TpUserId          
				WHERE TicketID IN (' + @TicketIds + ');          
          
				SELECT ''Ticket Assigned to group successfully'' AS Result;';          
          
			IF CHARINDEX(',', @TicketIds) > 0          
			BEGIN
				DECLARE @TicketIdTable TABLE (TicketId BIGINT);          
          
				INSERT INTO @TicketIdTable (TicketId)          
				SELECT value          
				FROM STRING_SPLIT(@TicketIds, ',');          
          
				--INSERT INTO tbl_tp_TicketHistory (TicketID, TicketStatusID, ParentID, ActionDateTime, Remarks, Note, UserResponse, AssignedUser, AssignedGroup, TicketPriority, AssignedSource, AssignedBy, ActionContent)          
				----output inserted.TicketId,inserted.TicketHistoryId into @tbl_TicketHistoryId(TicketId,TicketHistoryId)
				--SELECT          
				--	ttt.TicketId,          
				--	isnull((select TH.TicketStatusID From vw_tp_LastTicketHistory TH Where TH.ParentID=@ParentId and TH.TicketID=ttt.TicketId),1) AS TicketStatusID,            
				--	@ParentId AS ParentID,          
				--	GETDATE() AS ActionDateTime,          
				--	NULL AS Remarks,          
				--	'Manual Mass Group Assignment' AS Note,          
				--	NULL AS UserResponse,          
				--	0 AS AssignedUser,          
				--	@Group AS AssignedGroup,            
				--	isnull((select TH.TicketPriority From vw_tp_LastTicketHistory TH Where TH.ParentID=@ParentId and TH.TicketID=ttt.TicketId),1) AS TicketPriority,            
				--	'Manual' AS AssignedSource,          
				--	@TpUserId AS AssignedBy,
				--	'Activity' as ActionContent
				--FROM @TicketIdTable ttt;          
			END
			ELSE          
			--BEGIN
			--	INSERT INTO tbl_tp_TicketHistory (TicketID, TicketStatusID, ParentID, ActionDateTime, Remarks, Note, UserResponse, AssignedUser, AssignedGroup, TicketPriority, AssignedSource, AssignedBy, ActionContent)          
			--	--output inserted.TicketId,inserted.TicketHistoryId into @tbl_TicketHistoryId(TicketId,TicketHistoryId)
			--	SELECT          
			--		CAST(@TicketIds AS INT),           
			--		isnull((select TH.TicketStatusID From vw_tp_LastTicketHistory TH Where TH.ParentID=@ParentId and TH.TicketID=@TicketIds),1) AS TicketStatusID,            
			--		@ParentId AS ParentID,          
			--		GETDATE() AS ActionDateTime,          
			--		NULL AS Remarks,          
			--		'Manual Mass Group Assignment' AS Note,          
			--		NULL AS UserResponse,          
			--		0 AS AssignedUser,          
			--		@Group AS AssignedGroup,            
			--		isnull((select TH.TicketPriority From vw_tp_LastTicketHistory TH Where TH.ParentID=@ParentId and TH.TicketID=@TicketIds),1) AS TicketPriority,           
			--		'Manual' AS AssignedSource,          
			--		@TpUserId AS AssignedBy,
			--		'Activity' as ActionContent;          
			--END;

			Set @strQuery=Concat(N'insert into ',@TicketActivityTable,N'(TicketID,ParentID,FieldName,OldValue,NewValue,ActivityDescription,ActivityDatetime,ActivityBy)
			output inserted.TicketId,inserted.ActivityId into #tbl_TicketHistoryId(TicketId,TicketHistoryId)
			Select TicketID,ParentID,''AssignedGroup'' as FieldName,AssignedGroup as OldValue,',@Group,N' AS NewValue,''Manual Mass Group Assignment'' as ActivityDescription,getdate() as ActivityDatetime,',@TpUserId,N' as ActivityBy
			From #tbl_tp_TicketHistoryBeforeEdit')

			print concat('@strQuery: ',@strQuery)
			Exec sp_executesql @strQuery

			select @rowcnt=count(*) From #tbl_TicketHistoryId
			Set @i=1

 			While (@i <= @rowcnt)
			Begin
				select @TicketID=TicketId,@TicketHistoryId=TicketHistoryId From #tbl_TicketHistoryId Where SNo=@i

				exec usp_tp_RaiseEmailNotification @TicketID,@ParentID,@Group,@TpUserId,0,'Ticket Assigned to Group','Agent'

				Set @strQuery=N'SELECT @TicketNo1 = TicketNo, @CreatedOn1 = CreatedOn, @EntitytID1=EntityID, @EntityName1=EntityName
				FROM ' + @TableName + '
				Where TicketId=@TicketID1'

				Exec sp_executesql @strQuery, N'@TicketNo1 varchar(50) output, @CreatedOn1 datetime output, @EntitytID1 bigint output, @EntityName1 varchar(500) output, @TicketID1 bigint', @TicketNo1=@TicketNo output, @CreatedOn1=@CreatedOn output, @EntitytID1=@EntityId output, @EntityName1=@EntityName output, @TicketID1=@TicketID

				SELECT @EventDesc = @UserCreated + ' has forwarded ticketno ' + @TicketNo + ' on ' +
				CONVERT(NVARCHAR(255), GETDATE()) + ' to group ' + GroupName
				From	tbl_tp_GroupMaster(nolock)
				Where GroupId=@Group

				SELECT @EventName ='Ticket forwarded to Group for ' +@EntityName

				exec UspSaveEntityActivity_withid @entityname = @EntityName, @EntityID = @EntityId, @UserID= @UserId, @ParentID = @ParentID, @EventDescription = @EventDesc, @EventName =@EventName, @reftables = @TicketActivityTable, @refid= @TicketHistoryId

