IF (@OperationType = 'reapplysla')
BEGIN


    DECLARE @SLA_Id INT;
    DECLARE cur CURSOR FOR SELECT TicketId FROM @tbl;
    OPEN cur;
    FETCH NEXT FROM cur INTO @TicketId;
    WHILE @@FETCH_STATUS = 0
    BEGIN

        EXEC usp_tp_ReApplyTicketSLA @Ticket_ID = @TicketId, @Parent_ID = @ParentId, @SLAId = @SLA_Id OUTPUT;

        -- Insert into tbl_tp_SlaReapplyHistory
        INSERT INTO tbl_tp_SlaReapplyHistory (SlaID, TicketId, ParentId, CreatedBy, IsActive, Createddate, Mode)
        VALUES (@SLA_Id, @TicketId, @ParentId, @TpUserId, 1, GETDATE(), 'Manual');

        FETCH NEXT FROM cur INTO @TicketId;
    END
    CLOSE cur;
    DEALLOCATE cur;

    SELECT 'Ticket slaReapplied successfully' AS Result;
END



            
	print concat('@DynamicQuery: ', @DynamicQuery)
