(     
	@TicketId bigint,
	@TicketStatus bigint,
	@TicketPriority int,
	@TpUserId bigint,
    @TicketGroups bigint,
	@TicketAgent bigint
)                          
AS                          
BEGIN
	--declare @TicketId bigint=20318,@TicketStatus bigint=0,@TicketPriority int=0,@TicketGroups bigint=0,@TicketAgent bigint=1,@TpUserId bigint=1


    DECLARE	@DynamicSQL NVARCHAR(MAX), @status INT, @ParentId BIGINT, @tableName NVARCHAR(MAX), @strNotes NVARCHAR(MAX)='', @strQuery NVARCHAR(MAX)
	DECLARE @ActivityId BIGINT, @EventDesc NVARCHAR(MAX), @UserCreated NVARCHAR(100), @TicketNo NVARCHAR(50), @CreatedOn DATE, @EntityName varchar(500), @EntityID bigint, @UserId bigint, @TicketHistoryID bigint=0
	Declare @OldValue nvarchar(max)='', @ActivityDatetime datetime=Getdate(),@EventName varchar(500)  
          
    SELECT @ParentId = ParentId, @UserCreated = Name, @UserId=User_id     
    FROM tbl_tp_UserLogin (NOLOCK)     
    WHERE TpUser_Id = @TpUserId AND IsActive = 1;        
            
    EXEC @status = Usp_tp_CreateTicketMasterTableByParentID @ParentId, @tableName OUTPUT;              
        
	If(@TicketStatus>0 or @TicketPriority>0 or @TicketGroups>0 or @TicketAgent>0)
	Begin
		drop table if exists #tbl_tp_TicketHistoryBeforeEdit

		create table #tbl_tp_TicketHistoryBeforeEdit
		(
			TicketID			bigint,
			tpUser_Id			bigint,
			ParentID			bigint,
			TicketNo			nvarchar(100),	     	     
			RequesterMobileNo	nvarchar(100),	     	     
			RequesterEmailID	nvarchar(400),	     	     
			RequesterMobileNo1	nvarchar(100),	     	     
			RequesterEmailID1	nvarchar(400),	     	     
			RequesterMobileNo2	nvarchar(100),	     	     
			RequesterEmailID2	nvarchar(400),	     	     
			Subject				nvarchar(2000),
			Description			nvarchar(max),
			TicketStatusID		bigint,
			Remarks				nvarchar(max),
			Note				nvarchar(max),
			UserResponse		nvarchar(max),
			TicketPriority		bigint,
			AssignedUser		bigint,
			AssignedGroup		bigint,
			AssignedSource		nvarchar(100),
			TicketCategoryId	bigint,
			TicketTypeId		int,
			TicketSourceId		bigint,
			ProductId			bigint,
			IsMerged			bit,
			IsSplitted			bit,
			IsParentTicket		bit,
			IsChildTicket		bit,
			ParentTicketID		bigint,
			LastActionDatetime	datetime,
			AssignedBy			bigint,
			AssignedDateTime	datetime,
			TicketTag			nvarchar(2000),
			EntityID			bigint,
			EntityName			nvarchar(40),
			Company				nvarchar(800),
			CreatedBy			bigint,
			CreatedOn			datetime
		)

		DECLARE @DynamicUpdateQuery NVARCHAR(MAX);
		                      
		SELECT @DynamicUpdateQuery = concat(N'insert into #tbl_tp_TicketHistoryBeforeEdit(TicketID, tpUser_Id, ParentID, TicketNo, RequesterMobileNo, RequesterEmailID, RequesterMobileNo1, RequesterEmailID1, RequesterMobileNo2, RequesterEmailID2, Subject, Description, TicketStatusID, Remarks, Note, UserResponse, TicketPriority, AssignedUser, AssignedGroup, AssignedSource, TicketCategoryId, TicketTypeId, TicketSourceId, ProductId, IsMerged, IsSplitted, IsParentTicket, IsChildTicket, ParentTicketID, LastActionDatetime, AssignedBy, AssignedDateTime, TicketTag, EntityID, EntityName, Company, CreatedBy, CreatedOn)
		Select	TicketID, tpUser_Id, ParentID, TicketNo, RequesterMobileNo, RequesterEmailID, RequesterMobileNo1, RequesterEmailID1, RequesterMobileNo2, RequesterEmailID2, Subject, Description, TicketStatusID, Remarks, Note, UserResponse, TicketPriority, AssignedUser, AssignedGroup, AssignedSource, TicketCategoryId, TicketTypeId, TicketSourceId, ProductId, IsMerged, IsSplitted, IsParentTicket, IsChildTicket, ParentTicketID, LastActionDatetime, AssignedBy, AssignedDateTime, TicketTag, EntityID, EntityName, Company, CreatedBy, CreatedOn
		From ',@tableName, N'
		Where TicketID = ',@TicketId)

		print concat('@DynamicUpdateQuery: ',@DynamicUpdateQuery)
		EXEC sp_executesql @DynamicUpdateQuery;

		SET @DynamicSQL=
		N'UPDATE ' + QUOTENAME(@tableName) + N' SET ';    
    

    
		IF isnull(@TicketStatus,0) > 0
		BEGIN    
			Select @OldValue=TicketStatusID From #tbl_tp_TicketHistoryBeforeEdit
			Exec usp_tp_AddActivity @TicketId, @ParentId, 'TicketStatusID', @OldValue, @TicketStatus, 'Ticket status Update', @TpUserId, @ActivityDatetime,  @ActivityId out, null, null, null, null

			SET @DynamicSQL = @DynamicSQL + N'TicketStatusID = @TicketStatus,  ';    

			If(len(@strNotes) > 0)
			Begin
				Set @strNotes += ' ,TicketStatus'
			End
			Else
			Begin
				Set @strNotes += ' TicketStatus'
			End
		END    
    
		IF isnull(@TicketPriority,0) > 0
		BEGIN    
			Select @OldValue=TicketPriority From #tbl_tp_TicketHistoryBeforeEdit
			Exec usp_tp_AddActivity @TicketId, @ParentId, 'TicketPriority', @OldValue, @TicketPriority, 'Ticket Priority Update', @TpUserId, @ActivityDatetime,  @ActivityId out, null, null, null, null

			SET @DynamicSQL = @DynamicSQL + N'TicketPriority = @TicketPriority,  ';   

			If(len(@strNotes) > 0)
			Begin
				Set @strNotes += ' ,TicketPriority'
			End
			Else
			Begin
				Set @strNotes += ' TicketPriority'
			End
		END    

             
		IF isnull(@TicketGroups,0) > 0
		BEGIN    
			Select @OldValue=AssignedGroup From #tbl_tp_TicketHistoryBeforeEdit
			Exec usp_tp_AddActivity @TicketId, @ParentId, 'AssignedGroup', @OldValue, @TicketGroups, 'Ticket Group Update', @TpUserId, @ActivityDatetime,  @ActivityId out, null, null, null, null
SET @DynamicSQL = @DynamicSQL + N'AssignedGroup = ''' + CAST(@TicketGroups AS NVARCHAR(MAX)) + ''', ' + N'AssignedUser =''' + CAST(@TicketAgent AS NVARCHAR(MAX)) + ''', ' + N'AssignedBy = ''' + CAST(@TpUserId AS NVARCHAR(MAX)) + ''', ' + N'AssignedDatetime = GETDATE(), ' + N'LastActionDatetime = GETDATE(), ';

			If(len(@strNotes) > 0)
			Begin
				Set @strNotes += ' ,TicketGroups'
			End
			Else
			Begin
				Set @strNotes += ' TicketGroups'
			End
		END    
    
			IF isnull(@TicketAgent,0) > 0
		BEGIN    
			Select @OldValue=AssignedUser From #tbl_tp_TicketHistoryBeforeEdit
			Exec usp_tp_AddActivity @TicketId, @ParentId, 'AssignedUser', @OldValue, @TicketGroups, 'Ticket User Update', @TpUserId, @ActivityDatetime,  @ActivityId out, null, null, null, null
SET @DynamicSQL = @DynamicSQL + N'AssignedGroup = ''' + CAST(@TicketGroups AS NVARCHAR(MAX)) + ''', ' + N'AssignedUser =''' + CAST(@TicketAgent AS NVARCHAR(MAX)) + ''', ' + N'AssignedBy = ''' + CAST(@TpUserId AS NVARCHAR(MAX)) + ''', ' + N'AssignedDatetime = GETDATE(), ' + N'LastActionDatetime = GETDATE(), ';

			If(len(@strNotes) > 0)
			Begin
				Set @strNotes += ' ,TicketUser'
			End
			Else
			Begin
				Set @strNotes += ' TicketUser'
			End
		END    
    

		SET @DynamicSQL = LEFT(@DynamicSQL, LEN(@DynamicSQL) - 1);    
    
		SET @DynamicSQL = @DynamicSQL + N' WHERE TicketID = @TicketId;';    
    
		PRINT @DynamicSQL;        
        
		EXEC sp_executesql
			@DynamicSQL,            
			N'@TicketId BIGINT, @TicketStatus bigint, @TicketPriority INT',            
			@TicketId,@TicketStatus, @TicketPriority;   


			Set @TicketHistoryID=Scope_Identity()
		
		If((select dbo.ufn_tp_GetParentTicketStatus(@TicketStatus)) in (3,5))
		Begin
			SET @DynamicSQL = '
			UPDATE ' + @tableName + '
			SET
			TicketStatusID = ' + cast(@TicketStatus as NVARCHAR(MAX)) + ',
		    --LastActionDatetime = GETDATE(),
			ClosedOn = GETDATE(),
			ClosedBy = ' + CAST(@TpUserId AS NVARCHAR(MAX)) + '
			WHERE TicketID IN (' + CAST(@TicketID AS NVARCHAR(MAX)) + ');'

			EXEC sp_executesql @DynamicSQL

			Set @strQuery=N'SELECT @TicketNo1 = TicketNo, @CreatedOn1 = ClosedOn, @EntitytID1=EntityID, @EntityName1=EntityName
			FROM ' + @tableName + '
			Where TicketId=@TicketID1'

			Exec sp_executesql @strQuery, N'@TicketNo1 varchar(50) output, @CreatedOn1 datetime output, @EntitytID1 bigint output, @EntityName1 varchar(500) output, @TicketID1 bigint', @TicketNo1=@TicketNo output, @CreatedOn1=@CreatedOn output, @EntitytID1=@EntityID output, @EntityName1=@EntityName output, @TicketID1=@TicketID

			If((select dbo.ufn_tp_GetParentTicketStatus(@TicketStatus)) in (3))
			Begin
				exec usp_tp_RaiseEmailNotification @TicketID,@ParentId,0,@TpUserId,@TpUserId,'Agent Closes the Ticket','Requester'

				SELECT @EventDesc = @UserCreated + ' has closed ticket ' + @TicketNo + ' On ' +
				CONVERT(NVARCHAR(255), GETDATE())
				print concat('@TicketStatus=3 @EventDesc: ',@EventDesc)
					SELECT @EventName =@EntityName+' Ticket Closed'

				exec UspSaveEntityActivity_withid @entityname = @EntityName, @EntityID = @EntityID, @UserID= @UserId, @ParentID = @ParentID, @EventDescription = @EventDesc, @EventName = @EventName, @reftables = 'tbl_tp_TicketHistory', @refid= @TicketHistoryID
			End

			If((select dbo.ufn_tp_GetParentTicketStatus(@TicketStatus)) in (5))
			Begin
				SET @EventName = @EntityName + 's ticket is resolved';

				exec usp_tp_RaiseEmailNotification @TicketID,@ParentId,0,@TpUserId,@TpUserId,@EventName,'Requester'

				SELECT @EventDesc = @UserCreated + ' has resolved ticket ' + @TicketNo + ' On ' +
				CONVERT(NVARCHAR(255), GETDATE())
				print concat('@TicketStatus=5 @EventDesc: ',@EventDesc)

				exec UspSaveEntityActivity_withid @entityname = @EntityName, @EntityID = @EntityID, @UserID= @UserId, @ParentID = @ParentID, @EventDescription = @EventDesc, @EventName = @EventName, @reftables = 'tbl_tp_TicketHistory', @refid= @TicketHistoryID
			End
		End

		If((select dbo.ufn_tp_GetParentTicketStatus(@TicketStatus)) in (6))
		Begin
			Set @strQuery=N'SELECT @TicketNo1 = TicketNo, @CreatedOn1 = CreatedOn, @EntitytID1=EntityID, @EntityName1=EntityName
			FROM ' + @tableName + '
			Where TicketId=@TicketID1'

			Exec sp_executesql @strQuery, N'@TicketNo1 varchar(50) output, @CreatedOn1 datetime output, @EntitytID1 bigint output, @EntityName1 varchar(500) output, @TicketID1 bigint', @TicketNo1=@TicketNo output, @CreatedOn1=@CreatedOn output, @EntitytID1=@EntityID output, @EntityName1=@EntityName output, @TicketID1=@TicketID

			SELECT @EventDesc = @UserCreated + ' has updated ticket ' + @TicketNo + ' with status as Waiting on Customer on ' + CONVERT(NVARCHAR(255), GETDATE())

			print concat('@TicketStatus=6 @EventDesc: ',@EventDesc)

				SELECT @EventName ='Ticket Waiting on Customer for' +@EntityName

			exec UspSaveEntityActivity_withid @entityname = @EntityName, @EntityID = @EntityID, @UserID= @UserId, @ParentID = @ParentID, @EventDescription = @EventDesc, @EventName = @EventName, @reftables = 'tbl_tp_TicketHistory', @refid= @TicketHistoryID
		End

	End
	Else
	Begin
		print 'Please select atleast one criteria'
	End
END; 







GO

/* ============================================================
   Procedure: [dbo].[usp_tp_RaiseEmailNotification]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec usp_tp_RaiseEmailNotification @ticketid=5,@ParentID=32222,@groupid=0, @userid=1,@Agentid=1,@event='Agent Closes the Ticket',@type='Requester'      
--exec usp_tp_RaiseEmailNotification @ticketid=41877,@ParentID=37540,@groupid=953, @userid=2589, @Agentid=2437, @event='New Ticket Created',@type='Requester'      
CREATE   PROCEDURE [dbo].[usp_tp_RaiseEmailNotification]
(        
 @ticketid bigint,        
 @parentid bigint,        
 @groupid bigint,        
 @userid bigint,        
 @Agentid bigint,        
 @event varchar(100),        
 @type varchar(100)        
)        
as        
begin        
        
begin try  
 -- declare @ticketid bigint=110,@ParentID bigint=32222,@groupid bigint=0, @userid bigint=1,@Agentid bigint=1,@event varchar(100)='New Ticket Created',@type varchar(100)='Requester'  
  
      print '------BEGIN----usp_tp_RaiseEmailNotification---------------------------'  
Declare @compsubject nvarchar(max)='', @compbody nvarchar(max)=''        
Declare @subject nvarchar(max)='', @body nvarchar(max)='', @rexist int =0,@activityid int =0        
Declare @ToEmailID nvarchar(max) = '', @FromMailID nvarchar(max) = '', @strSQL nvarchar(max) = ''        
        
--if @type = 'Agent'        
--begin        
-- select @activityid=Activity_id from Serv_Activity_Mast where Activity_Desc = @event and Access =0 and ParentID = @parentid        
--End        
--else        
--Begin        
-- select @activityid=Activity_id from Serv_Activity_Mast where Activity_Desc = @event and Access =1 and ParentID = @parentid        
--End        
  
 select @activityid=max(NM.Notification_Id), @rexist= COUNT(*), @body = max(TND.Description),@subject = max(TND.Subject)  
 from tbl_tp_NotificationMaster(nolock) NM inner join tbl_tp_TicketNotificationDetail(nolock) TND  
 On  NM.Notification_Id=TND.NotificationId  
 Where NM.IsActive=1 and NM.NotificationType=@type and TND.IsEnabled=1 and TND.IsActive=1  
   and TND.ParentId=@parentid and NM.NotificationName=@event  
        
-- exec serv_Raise_smsNotification @ticketid , @parentid , @groupid , @userid , @Agentid, @event, @type  
      
 print concat('@activityid: ',@activityid)  
 print concat('@rexist: ',@rexist)  
 print concat('@subject: ',@subject)  
 print concat('@body: ',@body)  
 print concat('@ticketid: ',@ticketid)  
 print concat('@parentid: ',@parentid)  
 print concat('@groupid: ',@groupid)  
 print concat('@userid: ',@userid)  
 print concat('@Agentid: ',@Agentid)  
 print concat('@event: ',@event)  
 print concat('@type: ',@type)  
  
if @activityid = 0        
return;        
        
--if @type = 'Agent'        
--Begin        
-- select @rexist= COUNT(*), @body = max(N_Body),@subject = max(N_Sub)--, @ToEmailID= max(Email_ID)        
-- from Serv_Notification_Agent        
-- where ParentID = @parentid and Activity_Id=@activityid and Active =1        
-- -- select * from Serv_Notification_Agent where ParentID = 32222 and Activity_Id=254        
  
-- select @ToEmailID= Email from dbo.Serv_User_Detail where ser_user_id = @Agentid and ParentID = @parentid        
      
--End        
--else        
--begin        
-- select @ToEmailID= Email from dbo.Serv_User_Detail where ser_user_id = @userid and ParentID = @parentid        
        
-- select @rexist= COUNT(*),@body = max(N_Body),@subject = max(N_Sub)        
-- from Serv_Notification_Requester        
-- where ParentID = @parentid and Activity_Id=@activityid and Active =1        
-- -- select * from Serv_Notification_Requester where ParentID = 32222 and Activity_Id=254        
--end      
  
 If @type = 'Agent'
 Begin
	If(isnull(@Agentid,0)>0)
	Begin
		select @ToEmailID+=isnull(Email,'') from tbl_tp_UserLogin(nolock) where TpUser_Id=@Agentid and ParentID=@parentid
	End

	If(isnull(@groupid,0)>0)
	Begin
		select @ToEmailID+=string_agg(isnull(Email,''),',') from tbl_tp_UserLogin(nolock) where TpUser_Id in (
		select tpUserId from tbl_tp_AgentGroupMapping(nolock) Where GroupId=@groupid and IsActive=1)
	End
 End
 Else
 Begin
	Set @strSQL = N'Select @ToEmailID1=concat(RequesterEmailID,null) From ' + concat('tbl_tp_TicketMaster_',@parentid) + N'(nolock) Where TicketId=@ticketid1'
	Exec sp_executesql @strSQL,N'@ToEmailID1 nvarchar(200) output, @ticketid1 bigint',@ToEmailID1=@ToEmailID output, @ticketid1=@ticketid
 End
  
  print concat('@ToEmailID: ',@ToEmailID)  

 If(isnull(@ToEmailID,'')='')    
 Begin    
  print 'return -> @ToEmailID not found'    
  return    
 End

if @rexist <=0  
begin  
return;  
end  
else     
Begin  
      print 'A'  
declare @link_Account as bigint, @balance as int=0        
        
-- select @FromMailID= virtual_mail,@link_Account=link_Account from dbo.serv_user_domain where ParentID = @parentid  
select @FromMailID= Email,@link_Account=ParentID from tbl_tp_notificationemaildetails(nolock) where ParentID = @parentid and IsActive=1  
  
 If(isnull(@FromMailID,'')='')  
 Begin  
  print 'return -> @FromMailID not found'  
  return  
 End  
  
print concat('@FromMailID: ',@FromMailID)  
print concat('@link_Account: ',@link_Account)  
-- select * from dbo.serv_user_domain where ParentID = 32222        
-- update dbo.serv_user_domain set virtual_mail='abhshek.kumar@Support.appmails.in.net' where ParentID = 32222        
        
declare @spos int =0 --, @subject varchar(max)        
Declare @fld varchar(max)=''        
declare @tbl varchar(max)=''        
declare @word table (fldval varchar (Max))        
        
     print concat('LEN(@subject): ',LEN(@subject))   
while LEN(@subject) > 0        
begin        
 select @spos = CHARINDEX( '#' , @subject , 0 )        
      print concat('@spos: ',@spos)  
 if @spos=0        
 begin        
  set @compsubject = @compsubject+' '+@subject        
  break;        
 end        
        
 set @compsubject =@compsubject+ SUBSTRING(@subject,0,@spos)        
 set @subject = SUBSTRING(@subject,@spos+1,LEN(@subject)-@spos)        
 select @spos = CHARINDEX( '#' , @subject , 0 )        
 set @fld = SUBSTRING(@subject,0,@spos)        
 set @subject = SUBSTRING(@subject,@spos+1,LEN(@subject)-@spos)        
 select @spos = CHARINDEX( '.' , @fld , 0 )        
 set @tbl = SUBSTRING(@fld,0,@spos)        
 set @fld = SUBSTRING(@fld,@spos+1,LEN(@fld)-@spos)       
   
 print concat('@compsubject: ',@compsubject)  
 print concat('@subject: ',@subject)  
 print concat('@spos: ',@spos)  
 print concat('@fld: ',@fld)  
 print concat('@tbl: ',@tbl)  
 print concat('@fld: ',@fld)  
        
 print '-----------------------calling usp_tp_GetNotificationValue------------------------------------'  
 insert @word        
 exec usp_tp_GetNotificationValue @ticketid, @parentid ,@groupid ,@userid,@Agentid, @tbl, @fld, @type        
 print '-----------------------returning usp_tp_GetNotificationValue------------------------------------'  
        
 select @fld=isnull(fldval,'') from @word        
 set @compsubject = @compsubject+' '+@fld+' '        
 declare @sqlstr varchar(max)=''        
        
 delete From @word        
end        
  
  print concat('LEN(@body): ',LEN(@body))   
  
while LEN(@body) > 0        
begin        
 select @spos = CHARINDEX( '#' , @body , 0)        
      print '@spos: ' + cast(@spos as varchar)  
 if @spos=0        
 begin        
  set @compbody =@compbody+' '+@body        
  break;        
 end        
        
 set @compbody =@compbody+ SUBSTRING(@body,0,@spos)        
 set @body = SUBSTRING(@body,@spos+1,LEN(@body)-@spos)        
 select @spos = CHARINDEX( '#' , @body , 0 )        
 set @fld = SUBSTRING(@body,0,@spos)        
 set @body = SUBSTRING(@body,@spos+1,LEN(@body)-@spos)        
        
 select @spos = CHARINDEX( '.' , @fld , 0 )        
 set @tbl = SUBSTRING(@fld,0,@spos)        
 set @fld = SUBSTRING(@fld,@spos+1,LEN(@fld)-@spos)        
  
   
 print concat('@compbody: ',@compbody)  
 print concat('@body: ',@body)  
 print concat('@spos: ',@spos)  
 print concat('@fld: ',@fld)  
 print concat('@tbl: ',@tbl)  
 print concat('@fld: ',@fld)  
  
      print '-----------calling 2 usp_tp_GetNotificationValue-----------------------------'  
 insert @word        
 exec usp_tp_GetNotificationValue @ticketid, @parentid ,@groupid ,@userid,@Agentid, @tbl, @fld ,@type        
      print '-----------returning 2 usp_tp_GetNotificationValue-----------------------------'  
  
 select @fld=fldval from @word        
        
 set @compbody = @compbody+' '+@fld+' '        
 delete From @word        
end        
      print '@ToEmailID: ' + isnull(cast(@ToEmailID as varchar),'')  
select @body= @compbody, @subject = @compsubject        
---- This will create a random number between 1 and 999        
drop table if exists #nomobile  
select ROW_NUMBER() over( order by item) rno,* into #nomobile        
from dbo.SplitString(@ToEmailID, ',')        
        
Declare @email_cnt as int =0        
select @email_cnt = COUNT(*) from #nomobile        
        
        
SELECT TOP 1 @balance=isnull(balance,0) FROM MailCreditDetails with(nolock) WHERE --m_id = @m_id AND        
USER_ID = @link_Account ORDER BY credit_id DESC        
-- SELECT TOP 1 * FROM MailCreditDetails with(nolock) WHERE USER_ID = 32222 ORDER BY credit_id DESC        
  
print '------------ call usp_tp_SendEmail ---------------'  
 Exec usp_tp_SendEmail @userid, @subject, @body, @ToEmailID        
end  
      print '------END----usp_tp_RaiseEmailNotification---------------------------'  
  
/*        
if (@balance-@email_cnt) < 0 and @event = 'Password Reset Email'        
Begin        
select 'Balance is not sufficient'        
End        
        
        
if (@balance-@email_cnt) > 0        
begin        
 DECLARE @Random INT;        
 DECLARE @Upper INT;        
 DECLARE @Lower INT        
        
 Declare @BatchID bigint        
        
 SET @Lower = 1 ---- The lowest random number        
 SET @Upper = 10000 ---- The highest random number        
 SELECT @Random = ROUND(((@Upper - @Lower -1) * RAND() + @Lower), 0)        
 --SELECT @Random        
        
 insert into GetBatchRecord (User_id,RandNum)        
 values(@userid,@Random)        
 select @BatchID = max(BatchID) from GetBatchRecord With (Nolock)        
 where User_id=@userid and RandNum=@Random        
 delete from GetBatchRecord where User_id=@userid and RandNum=@Random        
        
 -- declare @Path nvarchar(max) = ''        
 -- select @Path = isnull(Path,'') from spt_tkt_attach(nolock) where ticketid = @ticketid order by id desc        
 -- select @Path        
 -- select * from CloneEmailsFilter(nolock) where Mail_UserID=32222 and Source='TicketManagement'        
        
 insert into CloneEmailsFilter(        
 Mail_FromEmail,Mail_ToEmail,Mail_Subject,Mail_TempleteName        
 ,Messages,Mail_InsertedDate,Mail_UserID,Mail_ParentID        
 ,ReplyTo,Mail_BatchID,Mail_Priority,Mail_ScheduleDate,Mail_ScheduledTime        
 ,Mail_Attechement,Mail_TempleteBody,IsMonitor,TemplateID,Count,Source        
 )        
 select @FromMailID,item,@Subject,'',@body        
 , GETDATE(),@ParentID,@ParentID,@FromMailID,        
 @BatchID,2,'','','',@body ,1,0,@email_cnt,        
 'TicketManagement' from #nomobile        
end        
        
*/        
        
end try        
begin catch        
      print '------CATCH----usp_tp_RaiseEmailNotification---------------------------'  
exec usp_inserterrorinfo        
  
print concat('ErrorNumber: ', ERROR_NUMBER())  
print concat('ErrorSeverity: ',ERROR_SEVERITY())  
print concat('ErrorState: ', ERROR_STATE())  
print concat('ErrorProcedure: ' ,ERROR_PROCEDURE())  
print concat('ErrorLine: ',ERROR_LINE())  
print concat('ErrorMessage: ',ERROR_MESSAGE())  
end catch        
end        



