/* ============================================================
   Procedure: [dbo].[Usp_tp_ResponseOnTicketDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- exec Usp_tp_ResponseOnTicketDetails @TpUserId=1,@TicketID=93,@PriorityId=2,@AssignedGroup=0,@AssignedUser=0,@TcktDescription=N'add note text',@TextType=N'AddNote',@FileName=default,@FilePath=default,@MetaData=N'{"IPAddress":"::1","MacAddress":"00FF61AD0C56","IsImpersonation":false,"ImpersonatorId":0}'
-- exec Usp_tp_ResponseOnTicketDetails @TpUserId=0,@TicketID=93,@PriorityId=2,@AssignedGroup=3,@AssignedUser=0,@TcktDescription=N'forward to group2',@TextType=N'Forward',@FileName=default,@FilePath=default,@MetaData=N'{"IPAddress":"::1","MacAddress":"00FF61AD0C56","IsImpersonation":false,"ImpersonatorId":0}'
-- exec Usp_tp_ResponseOnTicketDetails @TpUserId=0,@TicketID=93,@PriorityId=2,@AssignedGroup=0,@AssignedUser=39876,@TcktDescription=N'forward to agent',@TextType=N'Forward',@FileName=default,@FilePath=default,@MetaData=N'{"IPAddress":"::1","MacAddress":"00FF61AD0C56","IsImpersonation":false,"ImpersonatorId":0}'
-- exec Usp_tp_ResponseOnTicketDetails @TpUserId=1,@TicketID=93,@PriorityId=2,@AssignedGroup=0,@AssignedUser=0,@TcktDescription=N'reply text',@TextType=N'Reply',@FileName=default,@FilePath=default,@MetaData=N'{"IPAddress":"::1","MacAddress":"00FF61AD0C56","IsImpersonation":false,"ImpersonatorId":0}'
--exec Usp_tp_ResponseOnTicketDetails @TpUserId=1,@TicketID=91,@PriorityId=3,@AssignedGroup=0,@AssignedUser=86,@TcktDescription=N'open status',@TcktStatus=2,@TextType=N'Forward',@FileName=default,@FilePath=default,@MetaData=N'{"IPAddress":"::1","MacAddress":"00FF61AD0C56","IsImpersonation":false,"ImpersonatorId":0}'
CREATE   PROCEDURE [dbo].[Usp_tp_ResponseOnTicketDetails]
(
  @TpUserId bigint,                        
  @TicketID bigint = NULL,           
  @AssignedUser bigint = NULL,        
  @AssignedGroup bigint = NULL,        
  @TcktPriority bigint = NULL,                                        
  @TcktDescription nvarchar(MAX) = NULL,           
  @TcktStatus bigint = NULL,            
  @CreatedBy BIGINT =  NULL,                  
  --@FileName nvarchar(MAX) = NULL,                    
  --@FilePath nvarchar(MAX) = NULL,   
  @Attachement nvarchar(MAX)=NULL,
  @TextType nvarchar(20) = NULL,     
  @PriorityId bigint = NULL,       
  @MetaData nvarchar(MAX)  NULL                           
)                              
AS                                        
Begin
--declare 
--  @TpUserId bigint=1,                        
--  @TicketID bigint = 20261,           
--  @AssignedUser bigint = 0,        
--  @AssignedGroup bigint = 0,        
--  @TcktPriority bigint = 0,                                        
--  @TcktDescription nvarchar(MAX) = 'testshubhamproce',           
--  @TcktStatus bigint = 126,            
--  @CreatedBy BIGINT =  NULL,                  
--  @FileName nvarchar(MAX) = NULL,                    
--  @FilePath nvarchar(MAX) = NULL,         
--  @TextType nvarchar(20) = 0,     
--  @PriorityId bigint = 0,       
--  @MetaData nvarchar(MAX) = N'{"IPAddress":"::1","MacAddress":"00FF61AD0C56","IsImpersonation":false,"ImpersonatorId":0}'      
   SET NOCOUNT ON;               
                 
                              
    DECLARE @TicketHistoryId BIGINT = 0,@UserId BIGINT, @rowJson NVARCHAR(MAX) , @IPAdress NVARCHAR(50), 
			@DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT , @EntityId BIGINT, 
			@EntityName NVARCHAR(20), @ParentID BIGINT, @RequesterMobileNumber nvarchar(100),
			@RequesterEmailID nvarchar(400), @sqls NVARCHAR(max) = '', @status INT,@EventName NVARCHAR(MAX), 
			@TicketMasterTable NVARCHAR(max) = '' , @DynamicQuery NVARCHAR(MAX), @UpdateQuery NVARCHAR(MAX);

	DECLARE @ActivityId BIGINT, @EventDesc NVARCHAR(MAX), @UserCreated NVARCHAR(100), @TicketNo NVARCHAR(100), @CreatedOn DATE
     
	Declare @AssignedUser1 BIGINT,@AssignedGroup1 BIGINT,@TicketPriority BIGINT,@Ticketstaus1 BIGINT

    SELECT @UserId = User_ID, @ParentID = ParentId,      
      @RequesterMobileNumber = Mobile, @RequesterEmailID = Email, @UserCreated = Name 
	FROM tbl_tp_UserLogin (NOLOCK)          
    WHERE TpUser_Id = @TpUserId AND IsActive = 1        
                    
	SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)
	SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)
	SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)
	SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)  

	EXEC @status = Usp_tp_CreateTicketMasterTableByParentID @ParentID ,@TicketMasterTable OUTPUT

	Set @DynamicQuery= concat(N'Select @TicketNo1=TicketNo,@AssignedUser1=AssignedUser,@AssignedGroup1=AssignedGroup,@TicketPriority=TicketPriority,@Ticketstaus1=TicketStatusID,@CreatedOn1=CreatedOn,@EntityId1 = EntityID, @EntityName1 = EntityName from ',@TicketMasterTable, N' Where TicketID=@TicketID1')

	Exec sp_Executesql @DynamicQuery,N'@TicketNo1 nvarchar(100) out,@CreatedOn1 datetime out, @EntityId1 BIGINT out,@AssignedUser1 BIGINT out,@AssignedGroup1 BIGINT out,@TicketPriority BIGINT out,@Ticketstaus1 BIGINT out,@EntityName1 NVARCHAR(20) out, @TicketID1 bigint',@TicketNo1=@TicketNo out,@CreatedOn1=@CreatedOn out,@EntityId1=@EntityId out,@AssignedUser1=@AssignedUser1 out,@AssignedGroup1 =@AssignedGroup1  out,@TicketPriority=@TicketPriority out,@Ticketstaus1=@Ticketstaus1 out, @EntityName1=@EntityName out,@TicketID1=@TicketID

    IF (@TextType = 'Reply')        
    BEGIN
		Set @TcktStatus=2 -- Re-Open ticket on reply
		INSERT INTO tbl_tp_TicketHistory
	(TicketID, TicketStatusID, ParentID, ActionDateTime, Remarks, Note, UserResponse, AssignedUser, Assignedgroup, TicketPriority, AssignedSource, AssignedBy)
		Select @TicketID, @Ticketstaus1, @ParentID, GETDATE(), @TcktDescription, NULL, NULL, 
			@AssignedUser1, @AssignedGroup1,         			
			@TicketPriority, 'Manual', @TpUserId

		SELECT 'Replied on ticket Successfully';


		SET @TicketHistoryId = SCOPE_IDENTITY();

		SET @UpdateQuery = N'
		UPDATE ' + QUOTENAME(@TicketMasterTable) + '
		SET Remarks = @TcktDescription,
		TicketStatusID = @TcktStatus,
		LastActionDatetime = GETDATE()
		WHERE TicketID = @TicketID '

		exec usp_tp_RaiseEmailNotification @TicketID,@ParentID,0,@TpUserId,@TpUserId,'Agent Adds Comment to Ticket','Requester'

		SET @EventDesc = @UserCreated + ' answered ticket with ticketno ' + @TicketNo + ' raised on ' + CONVERT(NVARCHAR(255), @CreatedOn)

		--SELECT @EventName =@EntityName+' ticket is answered'
		SET @EventName = @EntityName + 's ticket is answered';

		exec UspSaveEntityActivity_withid @entityname = @EntityName, @EntityID = @EntityId, @UserID= @UserId, @ParentID = @ParentID, @EventDescription = @EventDesc, @EventName = @EventName, @reftables = 'tbl_tp_TicketHistory', @refid= @TicketHistoryId

	END        
        
    IF (@TextType = 'AddNote')        
    BEGIN
		INSERT INTO tbl_tp_TicketHistory (TicketID, TicketStatusID, ParentID, ActionDateTime, Remarks, Note, UserResponse, AssignedUser, TicketPriority, AssignedGroup, AssignedSource, AssignedBy, ActionContent)                
		Select	@TicketID, 
				IIf(isnull(@TcktStatus,0)>0, @TcktStatus,isnull((select TH.TicketStatusID From vw_tp_LastTicketHistory TH Where TH.ParentID=@ParentID and TH.TicketID=@TicketID),2)), 
				@ParentID, GETDATE(), NULL, @TcktDescription, NULL, 
				@AssignedUser1, 
			    @TicketPriority,
				@AssignedGroup1,  
				'Manual', @TpUserId, 'Note'
           
	    SELECT 'Note added Successfully';               
                  
        SET @TicketHistoryId = SCOPE_IDENTITY();               
                   
        SET @UpdateQuery = N'                
		UPDATE ' + QUOTENAME(@TicketMasterTable) + '                
		SET Note =   @TcktDescription,          
		TicketStatusID = iif(@TcktStatus>0,@TcktStatus,TicketStatusID),  
		LastActionDatetime = GETDATE()          
		WHERE TicketID = @TicketID '        

		Select @AssignedUser=AssignedUser,@AssignedGroup=AssignedGroup From vw_tp_LastTicketHistory TH Where TH.ParentID=@ParentID and TH.TicketID=@TicketID

		exec usp_tp_RaiseEmailNotification @TicketID,@ParentID,@AssignedGroup,@TpUserId,@AssignedUser,'Note added to ticket','Agent'

		SET @EventDesc = @UserCreated + ' has added a private note to ticketno ' + @TicketNo + ' raised on ' + CONVERT(NVARCHAR(255), @CreatedOn)

		SELECT @EventName ='Ticket Note Added for ' +@EntityName

		exec UspSaveEntityActivity_withid @entityname = @EntityName, @EntityID = @EntityId, @UserID= @UserId, @ParentID = @ParentID, @EventDescription = @EventDesc, @EventName = @EventName, @reftables = 'tbl_tp_TicketHistory', @refid= @TicketHistoryId
	END
        
    IF (@TextType = 'Forward')        
    BEGIN
		INSERT INTO tbl_tp_TicketHistory (TicketID,TicketStatusID,ParentID,ActionDateTime,Remarks,Note,UserResponse,AssignedUser,AssignedGroup,TicketPriority,AssignedSource,AssignedBy,ActionContent)
		Select	@TicketID, 
				IIf(isnull(@TcktStatus,0)>0, @TcktStatus,isnull((select TH.TicketStatusID From vw_tp_LastTicketHistory TH Where TH.ParentID=@ParentID and TH.TicketID=@TicketID),2)), 
				@ParentID, GETDATE(), NULL, @TcktDescription, NULL, @AssignedUser,@AssignedGroup,
				@TicketPriority,
				'Manual',@TpUserId,'Forward'
            
		SELECT 'Ticket forwarded Successfully';               
                  
                  
        SET @TicketHistoryId = SCOPE_IDENTITY();               
                  
		SET @UpdateQuery = N'
		UPDATE ' + QUOTENAME(@TicketMasterTable) + '
		SET Note = @TcktDescription,
		AssignedGroup = @AssignedGroup,
		AssignedUser = @AssignedUser,
		TicketStatusID = iif(@TcktStatus>0,@TcktStatus,TicketStatusID),
		LastActionDatetime = GETDATE() WHERE TicketID = @TicketID '

		If(@AssignedUser>0)
		Begin
			exec usp_tp_RaiseEmailNotification @TicketID,@ParentID,0,@TpUserId,@AssignedUser,'Ticket Assigned to Agent','Agent'

			SELECT @EventDesc = @UserCreated + ' has forwarded ticketno ' + @TicketNo + ' on ' + CONVERT(NVARCHAR(255), Getdate()) + ' to agent ' + concat(Name,' (',LoginName,')')
			FROM tbl_tp_UserLogin (NOLOCK)          
			WHERE TpUser_Id = @AssignedUser AND IsActive = 1 
			SELECT @EventName ='Ticket forwarded to agent for ' +@EntityName
			exec UspSaveEntityActivity_withid @entityname = @EntityName, @EntityID = @EntityId, @UserID= @UserId, @ParentID = @ParentID, @EventDescription = @EventDesc, @EventName = @EventName, @reftables = 'tbl_tp_TicketHistory', @refid= @TicketHistoryId
		End

		If(@AssignedGroup>0)
		Begin
			exec usp_tp_RaiseEmailNotification @TicketID,@ParentID,@AssignedGroup,@TpUserId,0,'Ticket Assigned to Group','Agent'

			SELECT @EventDesc = @UserCreated + ' has forwarded ticketno ' + @TicketNo + ' on ' + CONVERT(NVARCHAR(255), getdate()) + ' to group ' + GroupName
			From tbl_tp_GroupMaster(nolock)
			Where Groupid=@AssignedGroup

			SELECT @EventName ='Ticket forwarded to Group for ' +@EntityName
			exec UspSaveEntityActivity_withid @entityname = @EntityName, @EntityID = @EntityId, @UserID= @UserId, @ParentID = @ParentID, @EventDescription = @EventDesc, @EventName = @EventName, @reftables = 'tbl_tp_TicketHistory', @refid= @TicketHistoryId
		End

	END        
          
	IF (@TextType = 'UserReply')        
    BEGIN
		Set @TcktStatus=2 -- Re-Open ticket on reply
		INSERT INTO tbl_tp_TicketHistory
	(TicketID, TicketStatusID, ParentID, ActionDateTime, Remarks, Note, UserResponse, AssignedUser, Assignedgroup, TicketPriority, AssignedSource, AssignedBy)
		Select @TicketID, @TcktStatus, @ParentID, GETDATE(), NULL, NULL, @TcktDescription, 
			IIf(isnull(@AssignedUser,0)>0, @AssignedUser,isnull((select TH.AssignedUser From vw_tp_LastTicketHistory TH Where TH.ParentID=@ParentID and TH.TicketID=@TicketID),0)),          
			IIf(isnull(@AssignedGroup,0)>0, @AssignedGroup,isnull((select TH.AssignedGroup From vw_tp_LastTicketHistory TH Where TH.ParentID=@ParentID and TH.TicketID=@TicketID),0)),
			@PriorityId, 'Manual', @TpUserId

		SELECT 'Comment on ticket Successfully';


		SET @TicketHistoryId = SCOPE_IDENTITY();

		Select @AssignedUser=AssignedUser,@AssignedGroup=AssignedGroup 
		from tbl_tp_TicketHistory(nolock) Where TicketHistoryId=@TicketHistoryId

		SET @UpdateQuery = N'
		UPDATE ' + QUOTENAME(@TicketMasterTable) + '
		SET UserResponse = @TcktDescription,
		TicketStatusID = @TcktStatus,
		LastActionDatetime = GETDATE()
		WHERE TicketID = @TicketID '

		exec usp_tp_RaiseEmailNotification @TicketID,@ParentID,@AssignedGroup,@TpUserId,@AssignedUser,'Requester Replies to Ticket','Agent'

		SET @EventDesc = @UserCreated + ' replied to ticketno ' + @TicketNo + ' raised on ' + CONVERT(NVARCHAR(255), @CreatedOn)
		SELECT @EventName =@EntityName+' replies to Ticket'

		exec UspSaveEntityActivity_withid @entityname = @EntityName, @EntityID = @EntityId, @UserID= @UserId, @ParentID = @ParentID, @EventDescription = @EventDesc, @EventName = @EventName, @reftables = 'tbl_tp_TicketHistory', @refid= @TicketHistoryId
	END   

     IF (@TextType = 'Reopen')        
    BEGIN
		INSERT INTO tbl_tp_TicketHistory (TicketID, TicketStatusID, ParentID, ActionDateTime, Remarks, Note, UserResponse, AssignedUser, TicketPriority, AssignedGroup, AssignedSource, AssignedBy, ActionContent)                
		Select	@TicketID, 
				IIf(isnull(@TcktStatus,0)>0, @TcktStatus,isnull((select TH.TicketStatusID From vw_tp_LastTicketHistory TH Where TH.ParentID=@ParentID and TH.TicketID=@TicketID),2)), 
				@ParentID, GETDATE(), NULL, @TcktDescription, NULL, 
				@AssignedUser1, 
			    @TicketPriority,
				@AssignedGroup1,  
				'Manual', @TpUserId, 'Note'
           
	    SELECT 'Ticket Reopened Successfully';               
                  
        SET @TicketHistoryId = SCOPE_IDENTITY();               
                   
        SET @UpdateQuery = N'                
		UPDATE ' + QUOTENAME(@TicketMasterTable) + '                
		SET Note =   @TcktDescription,          
		TicketStatusID = iif(@TcktStatus>0,@TcktStatus,TicketStatusID),  
		LastActionDatetime = GETDATE()          
		WHERE TicketID = @TicketID '        

		Select @AssignedUser=AssignedUser,@AssignedGroup=AssignedGroup From vw_tp_LastTicketHistory TH Where TH.ParentID=@ParentID and TH.TicketID=@TicketID

		exec usp_tp_RaiseEmailNotification @TicketID,@ParentID,@AssignedGroup,@TpUserId,@AssignedUser,'Note added to ticket','Agent'

		SET @EventDesc = @UserCreated + ' has added a private note to ticketno ' + @TicketNo + ' raised on ' + CONVERT(NVARCHAR(255), @CreatedOn)

		SELECT @EventName ='Ticket Note Added for ' +@EntityName
		exec UspSaveEntityActivity_withid @entityname = @EntityName, @EntityID = @EntityId, @UserID= @UserId, @ParentID = @ParentID, @EventDescription = @EventDesc, @EventName = @EventName, @reftables = 'tbl_tp_TicketHistory', @refid= @TicketHistoryId
	END
	
	DECLARE @Params NVARCHAR(MAX) = N'@TcktDescription NVARCHAR(MAX), @AssignedGroup BIGINT, @AssignedUser BIGINT, @TicketID BIGINT, @TcktStatus BIGINT';          
    EXEC sp_executesql @UpdateQuery, @Params, @TcktDescription, @AssignedGroup, @AssignedUser, @TicketID, @TcktStatus;        

    IF (@Attachement IS NOT NULL)
    --BEGIN
	   -- INSERT INTO  tbl_tp_TicketAttachment(TicketID,TicketHistoryID,DisplayName,FileUrl,IsActive,CreatedBy,CreatedOn)
    --    VALUES (@TicketID,@TicketHistoryId,@FileName,@FilePath,1,@TpUserId,GETDATE())                  
    --END  
	 BEGIN
        DECLARE @jsonTable TABLE (
            FileName nvarchar(MAX),
            FilePath nvarchar(MAX)
        );

        INSERT INTO @jsonTable (FileName, FilePath)
        SELECT FileName, FilePath
        FROM OPENJSON(@Attachement)
        WITH (
            FileName nvarchar(MAX) '$.FileName',
            FilePath nvarchar(MAX) '$.FilePath'
        );

        INSERT INTO tbl_tp_TicketAttachment (TicketID, TicketHistoryID, DisplayName, FileUrl, IsActive, CreatedBy, CreatedOn)
        SELECT @TicketID, @TicketHistoryId, FileName, FilePath, 1, @TpUserId, GETDATE()
        FROM @jsonTable;
    END
                                               
    SET @rowJson  = ( SELECT *  FROM tbl_tp_TicketHistory(nolock) tsm  WHERE tsm.TicketHistoryID = @TicketHistoryId  FOR JSON AUTO  ,INCLUDE_NULL_VALUES )                   

	IF @rowJson IS NOT NULL
	BEGIN
		EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData
		@User_id = @UserId,
		@Activity_type = 'Inst_Tickethistory',
		@ActionType = 'I',
		@RowJson = @rowJson,
		@Table_name = 'tbl_tp_TicketHistory',
		@ip_adress = @IPAdress,
		@device_id = @DeviceId,
		@IsImpersonation = @IsImpersonation,
		@ImpersonatorId = @ImpersonatorId;                           
    END                              
              
END   





GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_SaveAgentDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_SaveAgentDetails]
    @userId INT, -- Add @userId as a parameter
    @selectedSkills NVARCHAR(MAX),
    @selectedRoles NVARCHAR(MAX),
    @selectedGroups NVARCHAR(MAX),
    @allFlag BIT,
    @editFlag BIT,
    @viewFlag BIT,
    @assignFlag BIT
AS
BEGIN
    -- Insert Skills into tbl_tp_AgentSkillMapping
    INSERT INTO tbl_tp_AgentSkillMapping (tpUserId, Skill_Id, IsActive, CreatedBy, CreatedDate)
    SELECT
        @userId, SkillId, 1, @userId, GETDATE() -- Use @userId for both tpUserId and CreatedBy
    FROM OPENJSON(@selectedSkills)
    WITH (
        SkillId INT
    );

    -- Insert Roles into your role mapping table
    INSERT INTO tbl_tp_agentrolemapping (tpuserid, role_id)
    SELECT
        @userId, role_id -- Use @userId for tpuserid
    FROM OPENJSON(@selectedRoles)
    WITH (
        role_id INT
    );

    -- Insert Groups into group mapping table based on flags
    IF @allFlag = 1
    BEGIN
        -- Insert into group mapping table for group 1
        INSERT INTO tbl_tp_AgentGroupMapping (tpuserid, GroupId)
        SELECT
            @userId, GroupId
        FROM OPENJSON(@selectedGroups)
        WITH (
            GroupId INT
        );
    END

    IF @editFlag = 1
    BEGIN
        -- Insert into group mapping table for group 2
        INSERT INTO tbl_tp_AgentGroupMapping (tpuserid, GroupId)
        SELECT
            @userId, GroupId
        FROM OPENJSON(@selectedGroups)
        WITH (
            GroupId INT
        );
    END

    IF @viewFlag = 1
    BEGIN
        -- Insert into group mapping table for group 3
        INSERT INTO tbl_tp_AgentGroupMapping (tpuserid, GroupId)
        SELECT
            @userId, GroupId
        FROM OPENJSON(@selectedGroups)
        WITH (
            GroupId INT
        );
    END

    IF @assignFlag = 1
    BEGIN
        -- Insert into group mapping table for group 4
        INSERT INTO tbl_tp_AgentGroupMapping (tpuserid, GroupId)
        SELECT
            @userId, GroupId
        FROM OPENJSON(@selectedGroups)
        WITH (
            GroupId INT
        );
    END
END



GO

