SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_SaveAgentSkillMappingDetails]                    
                              
  @UserIDs nvarchar(Max),                    
  @SkillID bigint,                          
  @Option nvarchar(50)  ,              
  @CreatedBy BIGINT ,    
  @MetaData nvarchar(MAX)        
                    
           
AS                    
Begin                    
   SET NOCOUNT ON;                
          
    DECLARE @InsertedId BIGINT, @rowJson NVARCHAR(MAX)   , @IPAdress NVARCHAR(50),@DeviceId NVARCHAR(50),@IsImpersonation BIT ,@ImpersonatorId INT,@ParentID  BIGINT  
    Select @CreatedBy = User_ID  From tbl_tp_UserLogin (noLock) Where ParentId = @ParentID          
         
    SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)      
    SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)      
    SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)      
    SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)      
      
          
         
BEGIN            
    IF @Option = 'Insert'            
    BEGIN      
   
       DELETE FROM tbl_tp_AgentSkillMapping WHERE Skill_Id = @SkillID AND tpUserId IN(SELECT value FROM OPENJSON(@UserIDs)) 
  
  
        INSERT INTO tbl_tp_AgentSkillMapping (tpUserId, Skill_Id, IsActive, CreatedBy, CreatedDate)            
           SELECT value, @SkillID, 1, @CreatedBy, GETDATE() FROM OPENJSON(@UserIDs);        
             SELECT 'Record Saved Successfully'            
              
    SET @InsertedId = SCOPE_IDENTITY()          
          
    SET @rowJson  = ( SELECT *  FROM tbl_tp_SkillMaster tsm  WHERE tsm.Skill_Id = @InsertedId  FOR JSON AUTO  ,INCLUDE_NULL_VALUES )            
            
          IF @rowJson IS NOT NULL            
          BEGIN            
           EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData @User_id = @CreatedBy            
            ,@Activity_type = 'Updt_skillmaster'            
            ,@ActionType = 'U'            
            ,@RowJson = @rowJson            
            ,@Table_name = 'tbl_tp_AgentSkillMapping'  ,@ip_adress = @IPAdress ,@device_id = @DeviceId,@IsImpersonation = @IsImpersonation,@ImpersonatorId =  @ImpersonatorId       
     END            
          
     END     
         
END   

END
          



GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_SaveArticleMasterDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_tp_SaveArticleMasterDetails]
    @ArticleId BIGINT OUTPUT, 
    @TpUserId BIGINT,
    @Author_Id BIGINT,
    @Parent_CategoryId BIGINT,
    @startdate Datetime,
    @enddate Datetime,
    @ArticleTitle NVARCHAR(MAX),
    @ArticleContent NVARCHAR(MAX),
    @IsActive BIT,
    @Option NVARCHAR(50),
    @CreatedBy BIGINT,
    @edit_status nvarchar(50),
    @seo_title nvarchar(100),
    @seo_description nvarchar(max),
    @seo_others nvarchar(max),
    @MetaData NVARCHAR(MAX)
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @UserId BIGINT, @ParentID BIGINT, @InsertedId BIGINT, @rowJson NVARCHAR(MAX), @IPAdress NVARCHAR(50), @DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT;

    SELECT @UserId = User_ID, @ParentID = ParentId FROM tbl_tp_UserLogin (NOLOCK) WHERE TpUser_Id = @TpUserId;

    SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress);
    SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress);
    SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation);
    SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId);

    IF @Option = 'Insert'
    BEGIN
        INSERT INTO tbl_tp_ArticleMaster (ParentId, Author_id, tpuserid, ArticleTitle, Category_Id, ArticleContent, edit_status, seo_title, seo_description, seo_others, IsActive, CreatedBy, CreatedDate, startDate, endDate)
        VALUES (@ParentID, @Author_id, @tpuserid, @ArticleTitle, @Parent_CategoryId, @ArticleContent, @edit_status, @seo_title, @seo_description, @seo_others, @IsActive, @CreatedBy, GETDATE(),NULLIF(@startdate, ''), NULLIF(@enddate, ''));

        SET @InsertedId = SCOPE_IDENTITY(); -- Capture the inserted ArticleID

        SET @rowJson = (SELECT * FROM tbl_tp_ArticleMaster tap WHERE tap.Article_ID = @InsertedId FOR JSON AUTO, INCLUDE_NULL_VALUES);

        IF @rowJson IS NOT NULL
        BEGIN
            EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData
                @User_id = @UserId,
                @Activity_type = 'Inst_ArticleMaster',
                @ActionType = 'I',
                @RowJson = @rowJson,
                @Table_name = 'tbl_tp_ArticleMaster',
                @ip_adress = @IPAdress,
                @device_id = @DeviceId,
                @IsImpersonation = @IsImpersonation,
                @ImpersonatorId = @ImpersonatorId;
        END;

        -- Return the inserted ArticleID
        SET @ArticleId = @InsertedId;

        SELECT 'Inserted' AS Message, @InsertedId AS ArticleID;
    END
    ELSE IF @Option = 'Update'
    BEGIN
        UPDATE tbl_tp_ArticleMaster
        SET ArticleContent = @ArticleContent, 
		ArticleTitle=@ArticleTitle,
		--Category_Id = @Parent_CategoryId, 
		ModifiedBy = @CreatedBy, 
		ModifiedDate = GETDATE(), 
		startDate = NULLIF(@startdate, ''),
		edit_status=@edit_status,
		Author_id=@Author_id,
		endDate = NULLIF(@enddate, '')
        WHERE ParentID = @ParentID AND Article_ID = @ArticleId;

        IF @@ROWCOUNT > 0
        BEGIN
            SET @rowJson = (SELECT * FROM tbl_tp_ArticleMaster tsp WHERE tsp.Article_ID = @ArticleId FOR JSON AUTO, INCLUDE_NULL_VALUES);
            IF @rowJson IS NOT NULL
            BEGIN
                EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData
                    @User_id = @UserId,
                    @Activity_type = 'Updt_ArticleMaster',
                    @ActionType = 'U',
                    @RowJson = @rowJson,
                    @Table_name = 'tbl_tp_ArticleMaster',
                    @ip_adress = @IPAdress,
                    @device_id = @DeviceId,
                    @IsImpersonation = @IsImpersonation,
                    @ImpersonatorId = @ImpersonatorId;
            END;

            SELECT 'Updated' AS Message, @ArticleId AS ArticleID;
        END
        ELSE
        BEGIN
            SELECT 'Wrong' AS Message, @ArticleId AS ArticleID;
        END;
    END
    ELSE
    BEGIN
        SELECT 'Exists' AS Message, @ArticleId AS ArticleID;
    END;
END;





GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_SaveCategoryDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_tp_SaveCategoryDetails]
  @CategoryId BIGINT,
  @TpUserId BIGINT,
  @ParentCategoryId BIGINT,
  @Categoryname NVARCHAR(MAX),
  @Categorydescription NVARCHAR(MAX),
  @IsActive BIT,
  @IsInternal BIT,
  @Option NVARCHAR(50),
  @CreatedBy BIGINT,
  @MetaData NVARCHAR(MAX)
AS
BEGIN
  SET NOCOUNT ON;

  DECLARE @InsertedId BIGINT, @UserId BIGINT, @rowJson NVARCHAR(MAX), @IPAdress NVARCHAR(50), @DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT, @ParentID BIGINT;

  SELECT @UserId = User_ID, @ParentID = ParentId FROM tbl_tp_UserLogin (NOLOCK) WHERE TpUser_Id = @TpUserId;

  SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress);
  SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress);
  SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation);
  SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId);

  IF @Option = 'Insert'
  BEGIN
   IF @ParentCategoryId = 0
    BEGIN
        SET @ParentCategoryId = NULL;
    END

    INSERT INTO tbl_tp_ArticleCategory (ParentId, ParentCategoryId, CategoryName, CategoryDescription, IsActive, IsInternal, CreatedBy, CreatedDate)
    VALUES (@ParentID, @ParentCategoryId, @Categoryname, @Categorydescription, @IsActive, @IsInternal, @CreatedBy, GETDATE());

    SELECT 'Inserted' AS Message;
    SET @InsertedId = SCOPE_IDENTITY();
    SET @rowJson = (SELECT * FROM tbl_tp_ArticleCategory tap WHERE tap.ArticleCate_Id = @InsertedId FOR JSON AUTO, INCLUDE_NULL_VALUES);

    IF @rowJson IS NOT NULL
    BEGIN
      EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData
        @User_id = @UserId,
        @Activity_type = 'Inst_ArticleCategory',
        @ActionType = 'I',
        @RowJson = @rowJson,
        @Table_name = 'tbl_tp_ArticleCategory',
        @ip_adress = @IPAdress,
        @device_id = @DeviceId,
        @IsImpersonation = @IsImpersonation,
        @ImpersonatorId = @ImpersonatorId;
    END;
  END
  ELSE IF @Option = 'Update'
  BEGIN
    UPDATE tbl_tp_ArticleCategory
    SET CategoryName = @Categoryname,
        CategoryDescription = @Categorydescription,
        IsInternal = @IsInternal,
        ParentCategoryId = @ParentCategoryId,
        ModifiedBy = @CreatedBy,
        ModifiedDate = GETDATE()
    WHERE ParentID = @ParentID AND ArticleCate_Id = @CategoryId;

    IF @@ROWCOUNT > 0
    BEGIN
      SET @rowJson = (SELECT * FROM tbl_tp_ArticleCategory tsp WHERE tsp.ArticleCate_Id = @CategoryId FOR JSON AUTO, INCLUDE_NULL_VALUES);
      IF @rowJson IS NOT NULL
      BEGIN
        EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData
          @User_id = @UserId,
          @Activity_type = 'Updt_ArticleCategory',
          @ActionType = 'U',
          @RowJson = @rowJson,
          @Table_name = 'tbl_tp_ArticleCategory',
          @ip_adress = @IPAdress,
			  @device_id = @DeviceId,
          @IsImpersonation = @IsImpersonation,
          @ImpersonatorId = @ImpersonatorId;
      END;
      SELECT 'Updated' AS Message;
    END
    ELSE
    BEGIN
      SELECT 'Wrong' AS Message;
    END;
  END
  ELSE
  BEGIN
    SELECT 'Exists' AS Message;
  END;
END;




GO

