/* ============================================================
   Procedure: [dbo].[usp_tp_SaveEnquiryActivity_withid]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_tp_SaveEnquiryActivity_withid]                  
(                  
 @EnquiryID           BIGINT,                  
 @UserID           BIGINT,                  
 @ParentID         BIGINT,                  
 @EventDescription NVARCHAR(MAX),                  
 @EventName        NVARCHAR(500),                  
 @reftables        NVARCHAR(500),                  
 @refid            NVARCHAR(100)                  
)                  
AS                  
BEGIN                  
 DECLARE @EventID BIGINT= 0, @activityid BIGINT;                  
 SELECT @EventID = ISNULL([ID], 0) FROM   ActivityMaster WHERE  [EventName] = @EventName and EventType='Ticket Portal';      
   
 IF(ISNULL(@ParentID, 0) = 0)                  
 BEGIN                  
  SELECT @ParentID = [ParentID] FROM   User_Detail(NOLOCK) WHERE  User_ID = @UserID;                  
 END;                  
                  
  INSERT INTO tbl_EnquiryEventHistory                  
    ([ParentID], [UserID], [EnquiryID], [EventDescription], [EventDate], [EventID], [reftables], [refids])      
  VALUES (@ParentID, @UserID, @EnquiryID, @EventDescription, GETDATE(), @EventID, @reftables, @refid);          
                  
  SELECT @activityid = SCOPE_IDENTITY();                  
  
 exec usp_insertnotification @activityid,'enquiry'     
 exec usp_automationrulesapply_activity_insert @activityid,'enquiry'  
 if dbo.fn_has_active_whatsapp(@parentid)=1
begin
 exec usp_updatelastactivityinconvuser 'enquiry',@activityid  
 end
   exec  usp_executeeventcampaign1 'enquiry',@activityid  
   exec usp_insertcalculatedfields 'enquiry',@activityid,@parentid

   exec usp_insertenagagementactivity @activityid,'enquiry'   

END;   


GO

