/* ============================================================
   Procedure: [dbo].[Usp_tp_SaveLeadActivity_withid]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

-- dbo.Usp_tp_SaveLeadActivity_withid  
CREATE   PROCEDURE [dbo].[Usp_tp_SaveLeadActivity_withid]  
(                              
 @LeadID           BIGINT,                              
 @UserID           BIGINT,                              
 @ParentID         BIGINT,                              
 @EventDescription NVARCHAR(MAX),                                                                       
 @EventName        NVARCHAR(500),                              
 @reftables        NVARCHAR(500),                              
 @refid            NVARCHAR(100) ,        
 @refColName       NVARCHAR(100)        
)                              
AS                              
BEGIN                          
begin try                            
 DECLARE @EventID BIGINT= 0, @activityid BIGINT;                              
                              
 SELECT @EventID = ISNULL([ID], 0) FROM   ActivityMaster(NOLOCK) WHERE  [EventName] = @EventName and EventType='Ticket Portal';                              
                              
 IF(ISNULL(@ParentID, 0) = 0)                              
 BEGIN                              
  SELECT @ParentID = [ParentID] FROM   User_Detail(NOLOCK) WHERE  User_ID = @UserID;                              
 END;                              
 
  BEGIN                              
  INSERT INTO tbl_LeadEventHistory                              
    ([ParentID], [UserID], [LeadID], [EventDescription], [EventDate], [EventID], [reftables], [refids],[refColName])                              
  VALUES (@ParentID, @UserID, @LeadID, @EventDescription, GETDATE(), @EventID, @reftables, @refid,@refColName);  
  
   SELECT @activityid = SCOPE_IDENTITY();                        

if @eventid=37
begin
if EXISTS (select 1 from LeadInteractionHistory (nolock) lih    
 join FollowUp_Status (nolock) fup on fup.ID=lih.FollowUpStatus     
 where lih.ParentID=@ParentID and  fup.IsConvert=1 and @reftables='Leadinteractionhistory'  and cast(lih.ID as varchar)= @refid )    
BEGIN    
 Declare @scoresetting int = (select ScoreSettingType from lead_cateogy_thresholds (nolock) where parentid = @parentid)    
 Declare @ScoreAdded int     
 if @scoresetting=2    
 BEGIN    
  SET @ScoreAdded = (select top 1 CurrentScore from lead_score_history where leadid=@LeadID)    
  if(@ScoreAdded is not null)    
  BEGIN    
   Insert into lead_score_history (parentid, leadid, rule_id, ScoreAdded, CurrentScore, createdon, lead_activity_id, lsh_eventid)    
   values(@ParentID,@LeadID,0,-@ScoreAdded,0,GETDATE(),@activityid,17)     
   update UserLeads set IsScoreeligible=0 where id=@LeadID    
  End    
 END    
 if @scoresetting=3    
 BEGIN    
  SET @ScoreAdded = (SELECT TOP 1 CurrentScore FROM lead_score_history WHERE leadid=@LeadID)    
  Insert into lead_score_history (parentid, leadid, rule_id, ScoreAdded, CurrentScore, createdon, lead_activity_id, lsh_eventid)    
  VALUES(@ParentID,@LeadID,0,-@ScoreAdded,0,GETDATE(),@activityid,17)     
  update UserLeads set IsScoreeligible=1 where id=@LeadID    
 END    
 if @scoresetting=1    
 BEGIN    
  update UserLeads set IsScoreeligible=1 where id=@LeadID    
 END    
END    
end

  EXEC usp_insertleadscore @activityid;                        
                        
  exec usp_insertnotification @activityid,'lead'                  
    
  begin try        
   exec [dbo].[usp_automationrulesapply_activity_insert] @activityid,'lead'          
  end try               
 begin catch               
 exec usp_inserterrorinfo               
 end catch           
   
if dbo.fn_has_active_whatsapp(@parentid)=1
begin  
exec usp_updatelastactivityinconvuser 'lead',@activityid 
end
exec usp_executeeventcampaign1 'lead',@activityid  
exec usp_insertcalculatedfields 'lead',@activityid,@parentid

exec usp_insertenagagementactivity @activityid,'lead'   




 END;                        
 end try                        
 begin catch                        
 exec usp_InsertErrorInfo         GO

         
 end catch                                                                  
END;   

