CREATE   PROCEDURE [dbo].[Usp_tp_SaveManageTicketDetails]      --32222  ,0,5,1,0,1,18,1,'35','dfdf','assf',32222,NULL,NULL,'Insert' ,'{}'
  @ParentID bigint,                
  @TicketID bigint = NULL,            
  @TcktPriority bigint = NULL,            
  @TcktStatus bigint = NULL,           
  @TcktSource bigint = NULL,          
  @TcktProduct bigint = NULL,          
  @TcktCategory bigint = NULL,          
  @TcktType bigint = NULL,            
  @TcktTag nvarchar(MAX) = NULL,            
  @TcktSubject nvarchar(MAX) =  NULL,             
  @TcktDescription nvarchar(MAX) = NULL,            
  @CreatedBy BIGINT =  NULL,          
  @FileName nvarchar(MAX) = NULL,            
  @FilePath nvarchar(MAX) = NULL,          
  @Option nvarchar(50) NULL ,                          
  @MetaData nvarchar(MAX)  NULL
AS                                
Begin                                
   SET NOCOUNT ON;       
         
                      
    DECLARE @InsertedId BIGINT = 0,@UserId BIGINT, @rowJson NVARCHAR(MAX) , @IPAdress NVARCHAR(50),@DeviceId NVARCHAR(50),@IsImpersonation BIT ,@ImpersonatorId INT ,@TpUserId BIGINT , @EntityId BIGINT,@EntityName NVARCHAR(20),@RequesterMobileNumber nvarchar(100),@RequesterEmailID nvarchar(400) ,@sqls NVARCHAR(max) = '' ,@status INT,@TicketMasterTable NVARCHAR(max) = '' , @DynamicQuery NVARCHAR(MAX);
	
	Select @UserId = User_ID From tbl_tp_UserLogin (noLock) Where ParentId = @ParentID
	Select @TpUserId = TpUser_Id From tbl_tp_UserLogin (noLock) Where ParentId = @ParentID
	Select @EntityId = EntityID From tbl_tp_UserLogin (noLock) Where ParentId = @ParentID
	Select @EntityName = EntityName From tbl_tp_UserLogin (noLock) Where ParentId = @ParentID
	Select @RequesterMobileNumber = Mobile From tbl_tp_UserLogin (noLock) Where ParentId = @ParentID
	Select @RequesterEmailID = Email From tbl_tp_UserLogin (noLock) Where ParentId = @ParentID       
                     
	SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)
	SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)
	SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)
	SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)          
	
	BEGIN
      
		EXEC @status = Usp_tp_CreateTicketMasterTableByParentID @ParentID,@TicketMasterTable OUTPUT       
            
		IF @Option = 'Insert'
    BEGIN         
       
SET @DynamicQuery =       
    N'INSERT INTO ' + QUOTENAME(@TicketMasterTable) + N' (      
        tpUser_Id, ParentId, TicketNo, RequesterMobileNo, RequesterEmailID,      
        Subject, Description, TicketStatusID, Remarks, Note, UserResponse,      
        TicketPriority, AssignedUser, AssignedGroup, AssignedSource, TicketCategoryId,      
        TicketTypeId, TicketSourceId, ProductId, IsMerged, IsSplitted,      
        IsParentTicket, IsChildTicket, ParentTicketID, LastActionDatetime, AssignedBy,      
        AssignedDateTime, TicketTag, EntityID, EntityName, IsActive, CreatedBy, CreatedOn, ModifiedBy, ModifiedOn      
    )      
    VALUES (      
        ' + CAST(@TpUserId AS NVARCHAR(MAX)) + ', '       
        + CAST(@ParentID AS NVARCHAR(MAX)) + ', '      
        + '''000- AGENT TICKET'', '       
        + '''' + ISNULL(@RequesterMobileNumber, '') + ''', '      
        + '''' + ISNULL(@RequesterEmailID, '') + ''', '      
        + '''' + ISNULL(@TcktSubject, '') + ''', '      
        + '''' + ISNULL(@TcktDescription, '') + ''', '      
        + CAST(ISNULL(@TcktStatus, '') AS NVARCHAR(MAX)) + ', '      
        + 'NULL, NULL, NULL, '  -- Remarks, Note, UserResponse      
        + CAST(ISNULL(@TcktPriority, '') AS NVARCHAR(MAX)) + ', '  -- TicketPriority      
        + CAST(ISNULL(@UserId, '') AS NVARCHAR(MAX)) + ', '      
        + CAST(ISNULL(@ParentID, '') AS NVARCHAR(MAX)) + ', '      
        + CAST(ISNULL(@ParentID, '') AS NVARCHAR(MAX)) + ', '      
        + CAST(ISNULL(@TcktCategory, '') AS NVARCHAR(MAX)) + ', '      
        + CAST(ISNULL(@TcktType, '') AS NVARCHAR(MAX)) + ', '      
        + CAST(ISNULL(@TcktSource, '') AS NVARCHAR(MAX)) + ', '      
        + CAST(ISNULL(@TcktProduct, '') AS NVARCHAR(MAX)) + ', 0, 0, 0, 0, '  -- IsMerged, IsSplitted, IsParentTicket, IsChildTicket      
        + CAST(ISNULL(@ParentID, 'NULL') AS NVARCHAR(MAX)) + ', GETDATE(), '      
        + 'NULL, GETDATE(), '  -- ParentTicketID, LastActionDatetime, AssignedBy, AssignedDateTime       
        +  'NULL' + ', '   -- TicketTag (replace 'NULL' with an appropriate value)      
        + CAST(ISNULL(@EntityId, 'NULL') AS NVARCHAR(MAX)) + ', '  -- EntityID      
        + '''' + ISNULL(@EntityName, '') + ''', 1, '  -- EntityName, IsActive      
        + CAST(ISNULL(@CreatedBy, 'NULL') AS NVARCHAR(MAX)) + ', GETDATE(), NULL, NULL'  -- CreatedBy, CreatedOn, ModifiedBy, ModifiedOn      
    + ')      
 select @InsertedId=SCOPE_IDENTITY()      
       
 ';      
      
      
 EXEC sp_executesql @DynamicQuery, N'@InsertedId BIGINT OUTPUT', @InsertedId OUTPUT;      
      
-- Use the @InsertedId as needed      
      
      
 Print 'Dynamic Query ' + ISNULL(@DynamicQuery,'NULL VALUE')      
 PRINT 'Inserted ID: ' + CAST(@InsertedId AS NVARCHAR(MAX));      
 --Select  * From tbl_tp_TicketMaster_32222      
DECLARE @UpdateQuery NVARCHAR(MAX);      
SELECT @InsertedId As inserted      
SET @UpdateQuery = N'      
    UPDATE ' + (@TicketMasterTable) + N'      
    SET TicketNo = ''000'' + CAST(@InsertedId AS NVARCHAR(20)) + ''- AGENT TICKET''      
    WHERE TicketID = @InsertedId;'      
      
EXEC sp_executesql @UpdateQuery;       

   	exec usp_tp_ApplyDispatcherRule @InsertedId, @ParentID

      
CREATE TABLE #TagsData (          
    TagData NVARCHAR(MAX)          
);          
          
INSERT INTO #TagsData (TagData)          
SELECT value FROM STRING_SPLIT(@TcktTag, ',');          
          
CREATE TABLE #SplitValues (          
    OriginalData NVARCHAR(MAX),          
    TagIDs NVARCHAR(MAX),          
    Tags NVARCHAR(MAX)          
);          
          
INSERT INTO #SplitValues (OriginalData, TagIDs, Tags)          
SELECT          
    TagData AS OriginalData,          
    CASE WHEN ISNUMERIC(extracted_integers) = 1 THEN extracted_integers END AS TagIDs,          
    extracted_strings AS Tags          
FROM (          
    SELECT TagData,          
           STRING_AGG(CASE WHEN ISNUMERIC(val) = 1 THEN val ELSE NULL END, ',') AS extracted_integers,          
           STRING_AGG(CASE WHEN ISNUMERIC(val) = 0 THEN val ELSE NULL END, ',') AS extracted_strings          
    FROM (          
        SELECT TagData, value AS val          
        FROM #TagsData          
        CROSS APPLY STRING_SPLIT(TagData, ',')          
    ) AS split_values          
    GROUP BY TagData          
) AS aggregated_data;          
          
DECLARE @InsertedTagMapping TABLE (TagID INT, EntityID INT);          
          
DECLARE @TagMasterID INT;          
          
IF EXISTS (SELECT Tags FROM #SplitValues WHERE Tags IS NOT NULL)          
BEGIN          
          
DECLARE @Tag NVARCHAR(MAX);          
          
DECLARE cur CURSOR FOR          
SELECT TRIM(value) AS Tag          
FROM #SplitValues          
CROSS APPLY STRING_SPLIT(Tags, ',')          
WHERE Tags IS NOT NULL;          
          
OPEN cur;          
FETCH NEXT FROM cur INTO @Tag;          
          
WHILE @@FETCH_STATUS = 0          
BEGIN          
          
    INSERT INTO TagMaster (Tag, ParentID, CreatedDate, CreatedBy, IsActive)          
    VALUES (@Tag, @ParentID, GETDATE(), @UserId, 1);          
          
    DECLARE @GeneratedTagID INT;          
    SET @GeneratedTagID = SCOPE_IDENTITY();          
          
    INSERT INTO EntityTagMapping (TagID, EntityID, Entity, CreatedDate)          
    VALUES (@GeneratedTagID, @InsertedId, 'Ticket', GETDATE());          
          
    FETCH NEXT FROM cur INTO @Tag;          
END;          
          
CLOSE cur;          
DEALLOCATE cur;          
          
          
END;          

	IF EXISTS (SELECT TagIDs FROM #SplitValues WHERE TagIDs IS NOT NULL)          
	BEGIN          
		INSERT INTO EntityTagMapping (EntityID, Entity, TagID, CreatedDate)          
		SELECT @InsertedId, 'Ticket', TagIDs, GETDATE()          
		FROM #SplitValues          
        
	END;          
                             
	DROP TABLE #TagsData;          
	DROP TABLE #SplitValues;          
          
 DECLARE @DynamicTicketTagUpdate NVARCHAR(MAX);      
 SET @DynamicTicketTagUpdate = N'      
    UPDATE ' + QUOTENAME(@TicketMasterTable) + N'      
    SET TicketTag = (SELECT STRING_AGG(CONVERT(NVARCHAR(MAX), TagID), '', '') AS CommaSeparatedEntityIDs       
                     FROM EntityTagMapping       
                     WHERE EntityID = @InsertedId AND Entity = ''Ticket'')      
    WHERE TicketID = @InsertedId';      
      
EXEC sp_executesql @DynamicTicketTagUpdate, N'@InsertedId BIGINT', @InsertedId;      
                                            
      --Update  tbl_tp_TicketMaster SET TicketTag = (SELECT          
      --           STRING_AGG(CONVERT(NVARCHAR(MAX), TagID), ', ') AS CommaSeparatedEntityIDs FROM EntityTagMapping Where EntityID = @InsertedId AND Entity = 'Ticket')          
          
                  DECLARE @TicketHistoryId BIGINT          
              
                   INSERT INTO tbl_tp_TicketHistory (TicketID,TicketStatusID,ParentID,ActionDateTime,Remarks,Note,UserResponse,AssignedUser,TicketPriority,AssignedSource,AssignedBy)            
                      VALUES (@InsertedId,@TcktStatus,@ParentID,NULL,NULL,NULL,NULL,@ParentID,@TcktPriority,10,@ParentID)            
          
          
      SET @TicketHistoryId = SCOPE_IDENTITY();          
          
	IF (@FileName IS NOT NULL)
	BEGIN
		INSERT INTO  tbl_tp_TicketAttachment(TicketID,TicketHistoryID,DisplayName,FileUrl,IsActive,CreatedBy,CreatedOn)
	VALUES (@InsertedId,@TicketHistoryId,@FileName,@FilePath,1,@UserId,GETDATE())          
	END          
            
    SELECT 'Ticket Raised Successfully';             
              
    DECLARE @DynamicRowJsonQuery NVARCHAR(MAX);      
	
	SET @DynamicRowJsonQuery = N'      
    SELECT * FROM ' + QUOTENAME(@TicketMasterTable) + N' tap WHERE tap.TicketID = @InsertedId FOR JSON AUTO, INCLUDE_NULL_VALUES';      
      
	EXEC sp_executesql @DynamicRowJsonQuery, N'@InsertedId BIGINT', @InsertedId, @rowJson OUTPUT;      
            
              
    IF @rowJson IS NOT NULL                        
	BEGIN                        
            EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData               
                @User_id = @UserId,                        
                @Activity_type = 'Inst_agentraiseticketmaster',                        
                @ActionType = 'I',                        
                @RowJson = @rowJson,                        
                @Table_name = @TicketMasterTable,                
                @ip_adress = @IPAdress,              
                @device_id = @DeviceId,              
                @IsImpersonation = @IsImpersonation,         
                @ImpersonatorId = @ImpersonatorId;                   
    END                      
    END                        
    ELSE IF @Option = 'Update'                        
    BEGIN               
         
        
           UPDATE tbl_tp_TicketMaster                        
           SET  TicketTypeId = @TcktType,            
                TicketCategoryId = @TcktCategory,            
                ProductId = @TcktProduct,            
                ModifiedBy = @CreatedBy,             
                ModifiedOn = GETDATE()   ,            
                Subject = @TcktSubject,            
                Description = @TcktDescription            
                WHERE TicketID = @TicketID;          
            
    CREATE TABLE #TagsData1 (          
    TagData NVARCHAR(MAX)          
);          
          
INSERT INTO #TagsData1 (TagData)          
SELECT value FROM STRING_SPLIT(@TcktTag, ',');          
          
CREATE TABLE #SplitValues1 (          
    OriginalData NVARCHAR(MAX),          
    TagIDs NVARCHAR(MAX),          
    Tags NVARCHAR(MAX)          
);          
          
INSERT INTO #SplitValues1 (OriginalData, TagIDs, Tags)          
SELECT          
    TagData AS OriginalData,          
    CASE WHEN ISNUMERIC(extracted_integers) = 1 THEN extracted_integers END AS TagIDs,          
    extracted_strings AS Tags          
FROM (          
    SELECT TagData,          
           STRING_AGG(CASE WHEN ISNUMERIC(val) = 1 THEN val ELSE NULL END, ',') AS extracted_integers,          
           STRING_AGG(CASE WHEN ISNUMERIC(val) = 0 THEN val ELSE NULL END, ',') AS extracted_strings          
    FROM (          
        SELECT TagData, value AS val          
        FROM #TagsData1          
        CROSS APPLY STRING_SPLIT(TagData, ',')          
    ) AS split_values          
    GROUP BY TagData          
) AS aggregated_data;          
          
DECLARE @InsertedTagMapping1 TABLE (TagID INT, EntityID INT);          
          
DECLARE @TagMasterID1 INT;          
          
IF EXISTS (SELECT Tags FROM #SplitValues1 WHERE Tags IS NOT NULL)          
BEGIN          
          
DECLARE @Tag1 NVARCHAR(MAX);          
          
DECLARE cur CURSOR FOR          
SELECT TRIM(value) AS Tag          
FROM #SplitValues1          
CROSS APPLY STRING_SPLIT(Tags, ',')          
WHERE Tags IS NOT NULL;          
          
OPEN cur;          
FETCH NEXT FROM cur INTO @Tag1;          
          
WHILE @@FETCH_STATUS = 0          
BEGIN          
          
    INSERT INTO TagMaster (Tag, ParentID, CreatedDate, CreatedBy, IsActive)          
    VALUES (@Tag1, @ParentID, GETDATE(), @UserId, 1);          
          
    DECLARE @GeneratedTagID1 INT;          
    SET @GeneratedTagID1 = SCOPE_IDENTITY();         
         
 DELETE FROM EntityTagMapping WHERE EntityID = @TicketID AND Entity = 'TICKET'        
          
    INSERT INTO EntityTagMapping (TagID, EntityID, Entity, CreatedDate)          
    VALUES (@GeneratedTagID1, @TicketID, 'Ticket', GETDATE());          
          
    FETCH NEXT FROM cur INTO @Tag1;          
END;          
          
CLOSE cur;          
DEALLOCATE cur;          
          
          
END;          
          
          
          
          
                   IF EXISTS (SELECT TagIDs FROM #SplitValues1 WHERE TagIDs IS NOT NULL)          
                   BEGIN          
                
               
                    DELETE FROM EntityTagMapping WHERE EntityID = @TicketID AND Entity = 'TICKET'        
                   
                       INSERT INTO EntityTagMapping (EntityID, Entity, TagID, CreatedDate)          
                       SELECT @TicketID, 'Ticket', TagIDs, GETDATE()          
                       FROM #SplitValues1          
                   END;          
                             
                   DROP TABLE #TagsData1;          
                   DROP TABLE #SplitValues1;          
          
                                            
      Update  tbl_tp_TicketMaster SET TicketTag = (SELECT          
            STRING_AGG(CONVERT(NVARCHAR(MAX), TagID), ', ') AS CommaSeparatedEntityIDs FROM EntityTagMapping Where EntityID = @TicketID AND Entity = 'Ticket')         
             
          
                  DECLARE @TicketHistoryId1 BIGINT          
              
                   INSERT INTO tbl_tp_TicketHistory (TicketID,TicketStatusID,ParentID,ActionDateTime,Remarks,Note,UserResponse,AssignedUser,TicketPriority,AssignedSource,AssignedBy)            
                      VALUES (@InsertedId,@TcktStatus,@ParentID,NULL,NULL,NULL,NULL,@ParentID,@TcktPriority,10,@ParentID)            
          
          
      SET @TicketHistoryId1 = SCOPE_IDENTITY();          
          
           IF (@FileName IS NOT NULL)          
          
               BEGIN          
                           
               INSERT INTO  tbl_tp_TicketAttachment(TicketID,TicketHistoryID,DisplayName,FileUrl,IsActive,CreatedBy,CreatedOn)           
                      
            VALUES (@TicketID,@TicketHistoryId,@FileName,@FilePath,1,@UserId,GETDATE())          
                        
                 END          
        
        
              
        IF @@ROWCOUNT > 0                        
            SELECT 'Ticket Updated Successfully';             
         
      
                      
        SET @rowJson = (SELECT * FROM tbl_tp_TicketMaster tm WHERE tm.TicketID = @TicketID FOR JSON AUTO, INCLUDE_NULL_VALUES);              
              
        IF @rowJson IS NOT NULL                        
        BEGIN                        
            EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData               
                @User_id = @UserId,                        
                @Activity_type = 'Updt_agentraiseticketmaster',                        
                @ActionType = 'U',                        
                @RowJson = @rowJson,                        
                @Table_name = 'tbl_tp_TicketMaster',                
                @ip_adress = @IPAdress,              
                @device_id = @DeviceId,              
                @IsImpersonation = @IsImpersonation,              
                @ImpersonatorId = @ImpersonatorId;                  
        END                                  
    END                        
	END         
      
      
END   



