/* ============================================================
   Procedure: [dbo].[Usp_tp_SaveNotificationMode]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_SaveNotificationMode]    
    @NotificationId INT,      
    @Mode NVARCHAR(20),      
    @TpUserId BIGINT,      
    @MetaData NVARCHAR(MAX)      
      
      
AS      
BEGIN      
    SET NOCOUNT ON;      
      
    DECLARE @ParentID Bigint,@UserId Bigint, @TimeZone nvarchar (400)  ,@rowJson NVARCHAR(MAX)  , @IPAdress NVARCHAR(50),@DeviceId NVARCHAR(50),@IsImpersonation BIT ,@ImpersonatorId INT       
       
    Select @ParentId = ParentId ,@UserId = User_Id From tbl_tp_UserLogin (noLock) Where TpUser_Id = @TpUserId   AND IsActive = 1      
                      
    SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)              
    SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)              
    SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)              
    SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)      
    
      
      Update tbl_tp_TicketNotificationDetail  SET Mode = @Mode Where NotificationId = @NotificationId AND ParentId = @ParentID   
      
      SET @rowJson = (SELECT * FROM tbl_tp_TicketNotificationDetail tm WHERE (NotificationId = @NotificationId ) AND (ParentID = @ParentId) FOR JSON AUTO, INCLUDE_NULL_VALUES);      
    IF @rowJson IS NOT NULL      
    BEGIN      
        EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData      
            @User_id = @UserId,      
            @Activity_type = 'Inst_updateNotificationMode  ',      
            @ActionType = 'U',      
            @RowJson = @rowJson,      
            @Table_name = 'tbl_tp_EmailNotificationRequesterDetail',      
            @ip_adress = @IPAdress,      
            @device_id = @DeviceId,      
            @IsImpersonation = @IsImpersonation,      
            @ImpersonatorId = @ImpersonatorId;      
        END      
      
  Select 'Mode has been set.' AS Message      
      
END 



GO

/* ============================================================
   Procedure: [dbo].[usp_tp_SaveQuickAddSettings]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON



CREATE   PROCEDURE [dbo].[usp_tp_SaveQuickAddSettings]
    @ParentId BIGINT,
	@TpUserId bigint,
    @QuickAddsetting NVARCHAR(MAX),
    @RaiseTicketSequencesetting NVARCHAR(MAX) = NULL,
    @ManageTicketSequencesetting NVARCHAR(MAX) = NULL,
	@Mode nvarchar(500)
AS
BEGIN
    SET NOCOUNT ON;
	if(@Mode='')
	begin
    IF EXISTS (SELECT 1 FROM [dbo].[tbl_tp_QuickAddSettings] WHERE ParentId = @ParentId)
    BEGIN
        UPDATE [dbo].[tbl_tp_QuickAddSettings]
        SET QuickAddsetting = @QuickAddsetting,
            RaiseTicketSequencesetting = @RaiseTicketSequencesetting,
            ManageTicketSequencesetting = @ManageTicketSequencesetting,
            ModifiedDate = GETDATE(),
            Modifiedby = @TpUserId
        WHERE ParentId = @ParentId;
		select 'Added'
    END
    ELSE
    BEGIN
        INSERT INTO [dbo].[tbl_tp_QuickAddSettings] (
            ParentId,
            QuickAddsetting,
            RaiseTicketSequencesetting,
            ManageTicketSequencesetting,
            IsActive,
            CreatedDate,
            ModifiedDate,
            Createdby,
            Modifiedby
        )
        VALUES (
            @ParentId,
            @QuickAddsetting,
            @RaiseTicketSequencesetting,
            @ManageTicketSequencesetting,
            1,
            GETDATE(), 
            GETDATE(), 
            @TpUserId,
            @TpUserId
        );
		select 'Added'
    END
	end
	 if(@Mode='RaiseSequence')
	begin
	  UPDATE [dbo].[tbl_tp_QuickAddSettings]
        SET 
            RaiseTicketSequencesetting = @RaiseTicketSequencesetting,
            ModifiedDate = GETDATE(),
            Modifiedby = @TpUserId
        WHERE ParentId = @ParentId;
		select 'Added'
	end
    if(@Mode='ManageSequence')
	begin
		  UPDATE [dbo].[tbl_tp_QuickAddSettings]
        SET 
            ManageTicketSequencesetting = @ManageTicketSequencesetting,
            ModifiedDate = GETDATE(),
            Modifiedby = @TpUserId
        WHERE ParentId = @ParentId;
		select 'Added'
	end
END;





GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_SaveRaiseTicketDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_SaveRaiseTicketDetails]                    
                
  @AuthorId bigint,                   
  @ParentID bigint,                    
  @AuthorName nvarchar(200),                
  @IsActive  bit,               
  @Option nvarchar(50)  ,              
  @CreatedBy BIGINT,        
  @MetaData nvarchar(MAX)        
                    
           
AS                    
Begin                    
   SET NOCOUNT ON;                
          
    DECLARE @InsertedId BIGINT,@UserId BIGINT, @rowJson NVARCHAR(MAX) , @IPAdress NVARCHAR(50),@DeviceId NVARCHAR(50),@IsImpersonation BIT ,@ImpersonatorId INT      
    Select @UserId = User_ID  From tbl_tp_UserLogin (noLock) Where ParentId = @ParentID          
         
    SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)      
    SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)      
    SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)      
    SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)      
      
          
IF NOT EXISTS (SELECT AuthorName FROM tbl_tp_Author WHERE ParentID = @ParentID AND AuthorName = @AuthorName AND Author_Id <> @AuthorId)            
BEGIN            
    IF @Option = 'Insert'            
    BEGIN            
        INSERT INTO tbl_tp_Author (ParentId, AuthorName, IsActive, CreatedBy, CreatedDate)            
        VALUES (@ParentID, @AuthorName, @IsActive, @CreatedBy, GETDATE());  
  
        SELECT 'Record Saved Successfully'; -- Add a semicolon here  
  
        SET @InsertedId = SCOPE_IDENTITY();          
  
        SET @rowJson = (SELECT * FROM tbl_tp_Author tap WHERE tap.Author_Id = @InsertedId FOR JSON AUTO, INCLUDE_NULL_VALUES);  
  
        IF @rowJson IS NOT NULL            
        BEGIN            
            EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData   
                @User_id = @UserId,            
                @Activity_type = 'Inst_authormaster',            
                @ActionType = 'I',            
                @RowJson = @rowJson,            
                @Table_name = 'tbl_tp_Author',    
                @ip_adress = @IPAdress,  
                @device_id = @DeviceId,  
                @IsImpersonation = @IsImpersonation,  
                @ImpersonatorId = @ImpersonatorId;       
        END          
    END            
    ELSE IF @Option = 'Update'            
    BEGIN            
        UPDATE tbl_tp_Author            
        SET AuthorName = @AuthorName, ModifiedBy = @CreatedBy, ModifiedDate = GETDATE()            
        WHERE Author_Id = @AuthorId;            
  
        IF @@ROWCOUNT > 0            
            SELECT 'Record Updated Successfully';              
          
        SET @rowJson = (SELECT * FROM tbl_tp_Author tsp WHERE tsp.Author_Id = @AuthorId FOR JSON AUTO, INCLUDE_NULL_VALUES);  
  
        IF @rowJson IS NOT NULL            
        BEGIN            
            EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData   
                @User_id = @UserId,            
                @Activity_type = 'Updt_authormaster',            
                @ActionType = 'U',            
                @RowJson = @rowJson,            
                @Table_name = 'tbl_tp_Author',    
                @ip_adress = @IPAdress,  
                @device_id = @DeviceId,  
                @IsImpersonation = @IsImpersonation,  
                @ImpersonatorId = @ImpersonatorId;      
        END          
        ELSE            
            SELECT 'Author Name Already Exists';             
    END            
END            
ELSE            
BEGIN            
    SELECT 'Author Name Already Exists';             
END;  
         
END 



GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_SaveSkillMappingDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_SaveSkillMappingDetails]                    
                              
  @UserIDs nvarchar(Max),                    
  @SkillID bigint,                          
  @Option nvarchar(50)  ,              
  @CreatedBy BIGINT ,    
  @MetaData nvarchar(MAX)        
                    
           
AS                    
Begin                    
   SET NOCOUNT ON;                
          
    DECLARE @InsertedId BIGINT, @rowJson NVARCHAR(MAX)   , @IPAdress NVARCHAR(50),@DeviceId NVARCHAR(50),@IsImpersonation BIT ,@ImpersonatorId INT,@ParentID  BIGINT  
    Select @CreatedBy = User_ID  From tbl_tp_UserLogin (noLock) Where ParentId = @ParentID          
         
    SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)      
    SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)      
    SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)      
    SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)      
      
          
         
BEGIN            
    IF @Option = 'Insert'            
    BEGIN      
   
       DELETE FROM tbl_tp_UserSkillMapping WHERE Skill_Id = @SkillID AND tpUserId IN(SELECT value FROM OPENJSON(@UserIDs)) 
  
  
        INSERT INTO tbl_tp_UserSkillMapping (tpUserId, Skill_Id, IsActive, CreatedBy, CreatedDate)            
           SELECT value, @SkillID, 1, @CreatedBy, GETDATE() FROM OPENJSON(@UserIDs);        
             SELECT 'Record Saved Successfully'            
              
    SET @InsertedId = SCOPE_IDENTITY()          
          
    SET @rowJson  = ( SELECT *  FROM tbl_tp_SkillMaster tsm  WHERE tsm.Skill_Id = @InsertedId  FOR JSON AUTO  ,INCLUDE_NULL_VALUES )            
            
          IF @rowJson IS NOT NULL            
          BEGIN            
           EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData @User_id = @CreatedBy            
            ,@Activity_type = 'Updt_skillmaster'            
            ,@ActionType = 'U'            
            ,@RowJson = @rowJson            
            ,@Table_name = 'tbl_tp_UserSkillMapping'  ,@ip_adress = @IPAdress ,@device_id = @DeviceId,@IsImpersonation = @IsImpersonation,@ImpersonatorId =  @ImpersonatorId       
     END            
          
     END     
         
END   

END
          



