/* ============================================================
   Procedure: [dbo].[usp_tp_SaveTicketRatingFeedback]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC usp_tp_SaveTicketRatingFeedback
(                
@exp NVARCHAR(200),                
@Rating nvarchar(20),                
@Comments nvarchar(max)            
)                
as                
begin                
                
	declare @roweff int
	declare @ticket bigint
	declare @parentid bigint,@ticketid bigint,@tickethistoryid bigint

	select @parentid=parentid,@ticketid=ticketid,@tickethistoryid=TicketHistoryID from tbl_tp_TicketHistory(nolock) where TicketHistoryID in (select [value] from dbo.fn_Split(@exp,'_') where position=2)

	IF NOT EXISTS(SELECT '*' FROM tbl_tp_TicketRatingFeedback(nolock) WHERE TicketHistoryID = @tickethistoryid)
	BEGIN
		declare @id table(fdbkid bigint)
		declare @fdbkid bigint

		INSERT INTO tbl_tp_TicketRatingFeedback (TicketHistoryID,TicketId,ParentId,Rating,RatingPoints,Comments,IsActive,SUBMITDATE) output inserted.RatingId into @id
		select  @tickethistoryid, @ticketid, @parentid,	@Rating, 
				case @Rating when 'Excellent' then 5 when 'Very Good' then 4 when 'Good' then 3 when 'Average' then 2 when 'Very Poor' then 1 else 0 end, 
				@Comments, 1, GETDATE()

		select @roweff = @@ROWCOUNT
		select top 1 @fdbkid= fdbkid from @id
	END
                
	select @roweff                
     
    /* 
  /* Start Lead activity */     
    
   Begin try    
    
   Declare @TicketID_LDACTV bigint = @ticketid     
   Declare @UserID_LDACTV bigint = 0    
   Declare @ParentID_LDACTV bigint = 0    
   Declare @kit19UserID bigint = 0     
   Declare @TicketTitle_LDACTV nvarchar(500) = ''    
   Declare @TicketCreationDate nvarchar(50) = ''    
   Declare @TicketRating_LDACTV nvarchar(100) = @Rating      
    
      
   select top 1 @UserID_LDACTV = isnull(USER_ID,0),@ParentID_LDACTV = isnull(ParentID,0),@TicketTitle_LDACTV = isnull(Subject,'')    
     from Serv_TicketMaster where TicketID =  ISNULL(@TicketID_LDACTV,0)     
      
    
  Declare @LeadID_LDACTV bigint = 0    
      
  Select top 1 @LeadID_LDACTV = isnull(LeadID,0)  from Serv_User_Detail where ser_user_id = @UserID_LDACTV    
     
   if(exists(select 1 from Serv_User_Master where Service_id = @UserID_LDACTV and kit19_User = 1))    
       Begin    
        select @kit19UserID = isnull(kit19_id,0)  from Serv_User_Master where Service_id = @UserID_LDACTV    
    End    
 else    
    Begin    
       set  @kit19UserID = @ParentID_LDACTV     
    End    
        
    
  create table #tblEventDescrb    
   (    
     EVNT_Description nvarchar(max)     
   )    
    
  if( isnull(@LeadID_LDACTV,0) > 0)    
   Begin    
        
   insert into #tblEventDescrb    
      exec  Usp_EventTemplate_DynamicVarReplacement 'Lead reviews a ticket',@kit19UserID,'','',@LeadID_LDACTV,'',null    
   ,0,0,'','',0,'',0,null,null,null,null,null,null,null,@TicketTitle_LDACTV,null    
   ,null,null,null,null,null,null,null,null,    
   0,0,0,null,null,null,@TicketRating_LDACTV,null,null,null,0,null,null    
         
   declare @evntMessage nvarchar(max) = ''     
   select @evntMessage = isnull( EVNT_Description,'') from #tblEventDescrb    
     
   if(@evntMessage <> '')    
   Begin    
   exec UspSaveLeadActivity_withid @LeadID_LDACTV,@kit19UserID,@ParentID_LDACTV,@evntMessage,    'Lead reviews a ticket','Serv_ticket_feedback_tbl',@fdbkid    
   end    
    
    
   End      
    
   end try    
   Begin catch    
       
      exec usp_InsertErrorInfo    
    
   end catch    
    
   IF OBJECT_ID('tempdb..#tblEventDescrb') IS NOT NULL -- Check for table existence      
   Begin      
        DROP TABLE #tblEventDescrb     
   End      
      
    
   /*End Lead activity */    
    */
    
                
end



GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_SaveTicketSkillDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_SaveTicketSkillDetails]  
  @TicketId BIGINT,  
  @ParentID BIGINT,  
  @SkillName NVARCHAR(200),  
  @IsActive BIT,  
  @Option NVARCHAR(50),  
  @CreatedBy BIGINT,  
  @ConditionData NVARCHAR(MAX),  
  @MetaData NVARCHAR(MAX)  
AS  
BEGIN  
   SET NOCOUNT ON;  
  
   DECLARE @InsertedId BIGINT, @UserId BIGINT, @rowJson NVARCHAR(MAX), @IPAdress NVARCHAR(50), @DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT  
  
   SELECT @UserId = User_ID FROM User_Detail (NOLOCK) WHERE ParentId = @ParentID  
  
   SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)  
   SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)  
   SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)  
   SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)  
  
   IF @Option = 'Insert'  
   BEGIN  
       IF NOT EXISTS (  
           SELECT SkillName  
           FROM tbl_tp_SkillMaster  
           WHERE ParentID = @ParentID AND SkillName = @SkillName AND Skill_Id <> @TicketId  
       )  
       BEGIN  
           INSERT INTO tbl_tp_SkillMaster (ParentId, SkillName, Active, CreatedBy, CreatedDate)  
           VALUES (@ParentID, @SkillName, @IsActive, @CreatedBy, GETDATE());  
  
           SET @InsertedId = SCOPE_IDENTITY();  
  
           INSERT INTO tbl_tp_SkillCondition (Skill_Id, FieldName, ActionType, Value, Conjunction, SequenceNo,Operator, Active, ParentId, createdBy, CreatedDate)  
SELECT  
    @InsertedId,  
    j.[FieldName],  
    j.[ActionType],  
    j.[Value],  
    j.[Conjunction],  
    ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) AS SequenceNo,  
	j.[Operator],
    1,   
    @ParentID,  
    @CreatedBy,  
    GETDATE()  
    FROM OPENJSON(@ConditionData) WITH (  
    FieldName NVARCHAR(255),  
    ActionType NVARCHAR(255),  
    Value NVARCHAR(MAX),  
    Conjunction NVARCHAR(255) ,
	Operator NVARCHAR(50)
) AS j;  
  
           SELECT 'Record Saved Successfully';  
  
           SET @rowJson = (  
               SELECT *  
               FROM tbl_tp_SkillMaster tsm  
               WHERE tsm.Skill_Id = @InsertedId  
               FOR JSON AUTO, INCLUDE_NULL_VALUES  
           );  
  
           IF @rowJson IS NOT NULL  
           BEGIN  
               EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData  
                   @User_id = @UserId,  
                   @Activity_type = 'Inst_skillmaster',  
                   @ActionType = 'I',  
                   @RowJson = @rowJson,  
                   @Table_name = 'tbl_tp_SkillMaster',  
                   @ip_adress = @IPAdress,  
                   @device_id = @DeviceId,  
                   @IsImpersonation = @IsImpersonation,  
                   @ImpersonatorId = @ImpersonatorId;  
           END  
       END  
       ELSE  
       BEGIN  
           SELECT 'Skill Name Already Exists';  
       END  
   END  
IF @Option = 'Update'
BEGIN
    DECLARE @RowCount INT;

    UPDATE tbl_tp_SkillMaster
    SET SkillName = @SkillName, Active = @IsActive, ModifiedBy = @CreatedBy, ModifiedDate = GETDATE()
    WHERE Skill_Id = @TicketId AND ParentID = @ParentID;

    SET @RowCount = @@ROWCOUNT;

    IF @RowCount > 0
    BEGIN
        SELECT 'Record Updated Successfully';

        --MERGE INTO tbl_tp_SkillCondition AS target
        --USING (SELECT * FROM OPENJSON(@ConditionData) WITH (
        --    FieldName NVARCHAR(255),
        --    ActionType NVARCHAR(255),
        --    Value NVARCHAR(MAX),
        --    Conjunction NVARCHAR(255),
        --    SequenceNo INT,
        --    Active BIT,
        --    Operator NVARCHAR(255) 
        --)) AS source
        --ON target.Skill_Id = @TicketId
        --AND source.FieldName = target.FieldName
        --WHEN MATCHED THEN
        --    UPDATE SET
        --    target.ActionType = source.ActionType,
        --    target.Value = source.Value,
        --    target.Conjunction = source.Conjunction,
        --    target.SequenceNo = source.SequenceNo,
        --    target.Operator = source.Operator, 
        --    target.Active = 1
        --WHEN NOT MATCHED THEN
        --    INSERT (Skill_Id, FieldName, ActionType, Value, Conjunction, SequenceNo, Active, ParentId, createdBy, CreatedDate, Operator)
        --    VALUES (@TicketId, source.FieldName, source.ActionType, source.Value, source.Conjunction, source.SequenceNo, 1, @ParentID, @CreatedBy, GETDATE(), source.Operator); -- Insert Operator
		   DELETE FROM tbl_tp_SkillCondition
           WHERE Skill_Id = @TicketId;

		    INSERT INTO tbl_tp_SkillCondition (Skill_Id, FieldName, ActionType, Value, Conjunction, SequenceNo,Operator, Active, ParentId, createdBy, CreatedDate)  
SELECT  
    @TicketId,  
    j.[FieldName],  
    j.[ActionType],  
    j.[Value],  
    j.[Conjunction],  
    ROW_NUMBER() OVER (ORDER BY (SELECT NULL)) AS SequenceNo,  
	j.[Operator],
    1,   
    @ParentID,  
    @CreatedBy,  
    GETDATE()  
    FROM OPENJSON(@ConditionData) WITH (  
    FieldName NVARCHAR(255),  
    ActionType NVARCHAR(255),  
    Value NVARCHAR(MAX),  
    Conjunction NVARCHAR(255) ,
	Operator NVARCHAR(50)
) AS j;  
  

        -- Retrieve the updated JSON data
        SET @rowJson = (
            SELECT *
            FROM tbl_tp_SkillMaster tsm
            WHERE tsm.Skill_Id = @TicketId
            FOR JSON AUTO, INCLUDE_NULL_VALUES
        );

        IF @rowJson IS NOT NULL
        BEGIN
            EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData
                @User_id = @UserId,
                @Activity_type = 'Updt_skillmaster',
                @ActionType = 'U',
                @RowJson = @rowJson,
                @Table_name = 'tbl_tp_SkillMaster',
                @ip_adress = @IPAdress,
                @device_id = @DeviceId,
                @IsImpersonation = @IsImpersonation,
                @ImpersonatorId = @ImpersonatorId;
        END
    END
    ELSE
    BEGIN
        SELECT 'No records were updated. Skill Id not found for update.';
    END
END

END  




GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_SaveTicketSourceDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_SaveTicketSourceDetails]                
  @TicketId BIGINT,               
  @TpUserId BIGINT,                
  @TicketSourceName NVARCHAR(200),                    
  @Option NVARCHAR(50),              
  @MetaData NVARCHAR(MAX)    
AS
BEGIN                
  SET NOCOUNT ON;
      
  DECLARE @InsertedId BIGINT, @UserId BIGINT, @rowJson NVARCHAR(MAX), @IPAdress NVARCHAR(50), @DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT, @ParentID BIGINT;
  
  SELECT @UserId = User_ID, @ParentID = ParentId FROM tbl_tp_UserLogin (NOLOCK) WHERE TpUser_Id = @TpUserId AND IsActive = 1
     
  SET @IPAdress = JSON_VALUE(@MetaData, '$.IPAddress');
  SET @DeviceId = JSON_VALUE(@MetaData, '$.MacAddress');
  SET @IsImpersonation = JSON_VALUE(@MetaData, '$.IsImpersonation');
  SET @ImpersonatorId = JSON_VALUE(@MetaData, '$.ImpersonatorId');
  
  BEGIN
 IF @Option = 'Insert'
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM tbl_tp_TicketSourceMaster 
    WHERE ParentID = @ParentID AND TicketSourceName = @TicketSourceName
  )
  BEGIN
    INSERT INTO tbl_tp_TicketSourceMaster (ParentId, TicketSourceName, IsActive, CreatedBy, CreatedDate)        
    VALUES (@ParentID, @TicketSourceName, 1, @UserId, GETDATE());
    SET @InsertedId = SCOPE_IDENTITY();
    SET @rowJson = (SELECT * FROM tbl_tp_TicketSourceMaster tsm WHERE tsm.TicketSourceId = @InsertedId FOR JSON AUTO, INCLUDE_NULL_VALUES);
    
    IF @rowJson IS NOT NULL
    BEGIN
      EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData @User_id = @UserId,
        @Activity_type = 'Inst_sourcemaster',
        @ActionType = 'I',
        @RowJson = @rowJson,
        @Table_name = 'tbl_tp_TicketSourceMaster',
        @ip_adress = @IPAdress,
        @device_id = @DeviceId,
        @IsImpersonation = @IsImpersonation,
        @ImpersonatorId = @ImpersonatorId;
    END
    SELECT 'Inserted' AS Message;
  END
  ELSE
  BEGIN
    SELECT 'Exists' AS Message; 
  END
END

IF @Option = 'Update'
BEGIN
  IF  EXISTS (
    SELECT 1 FROM tbl_tp_TicketSourceMaster 
    WHERE ParentID = @ParentID AND TicketSourceName = @TicketSourceName
  )
  BEGIN
    SELECT 'Exists' AS Message;
  END
  ELSE
  BEGIN
    UPDATE tbl_tp_TicketSourceMaster
    SET TicketSourceName = @TicketSourceName, ModifiedBy = @UserId, ModifiedDate = GETDATE()
    WHERE TicketSourceId = @TicketId;

    IF @@ROWCOUNT > 0
    BEGIN
      SET @rowJson = (SELECT * FROM tbl_tp_TicketSourceMaster tsm WHERE tsm.TicketSourceId = @TicketId FOR JSON AUTO, INCLUDE_NULL_VALUES);
      IF @rowJson IS NOT NULL
      BEGIN
        EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData @User_id = @UserId,
          @Activity_type = 'Updt_sourcemaster',
          @ActionType = 'U',
          @RowJson = @rowJson,
          @Table_name = 'tbl_tp_TicketSourceMaster',
          @ip_adress = @IPAdress,
          @device_id = @DeviceId,
          @IsImpersonation = @IsImpersonation,
          @ImpersonatorId = @ImpersonatorId;
      END
      SELECT 'Updated' AS Message;
    END
    ELSE
    BEGIN
      SELECT 'Exists' AS Message;
    END
  END
END

  END
END;



GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_SaveTicketStatusDetails]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_SaveTicketStatusDetails]                    
(                
  @TicketId bigint,                   
  @TpUserId bigint,      
  @ParentTicketStatusId bigint,    
  @TicketStatusName nvarchar(200),                
  @IsActive bit,               
  @Option nvarchar(50),              
  @CreatedBy BIGINT,        
  @MetaData nvarchar(MAX)        
)                    
AS                    
BEGIN                    
   SET NOCOUNT ON;                
          
    DECLARE @InsertedId BIGINT, @UserId BIGINT, @rowJson NVARCHAR(MAX), @IPAdress NVARCHAR(50), @DeviceId NVARCHAR(50), @IsImpersonation BIT, 
	@ImpersonatorId INT ,@ParentID BIGINT
	
    SELECT @UserId = User_ID,@ParentID = ParentId FROM tbl_tp_UserLogin (NOLOCK) WHERE TpUser_Id = @TpUserId      
 
    IF (@ParentTicketStatusId = 0)  
    BEGIN  
        SET @ParentTicketStatusId = NULL  
    END  
         
    SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)      
    SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)      
    SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)      
    SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)      
          
    IF @Option = 'Insert' AND NOT EXISTS (
        SELECT 1
        FROM tbl_tp_TicketStatusMaster
        WHERE ParentID = @ParentID
        AND TicketStatus = @TicketStatusName
        AND TicketStatus_ID <> @TicketId
    )
    BEGIN

        INSERT INTO tbl_tp_TicketStatusMaster (ParentId, TicketStatus, ParentStatus_Id, IsActive, CreatedBy, CreatedDate)
        VALUES (@ParentID, @TicketStatusName, @ParentTicketStatusId, @IsActive, @CreatedBy, GETDATE())
        
        SET @InsertedId = SCOPE_IDENTITY()

		SELECT 'Inserted' AS Message
        
        SET @rowJson = (SELECT * FROM tbl_tp_TicketStatusMaster tsm WHERE tsm.TicketStatus_ID = @InsertedId FOR JSON AUTO, INCLUDE_NULL_VALUES)
        
        IF @rowJson IS NOT NULL
        BEGIN
            EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData @User_id = @UserId
            ,@Activity_type = 'Inst_statusmaster'
            ,@ActionType = 'I'
            ,@RowJson = @rowJson
            ,@Table_name = 'tbl_tp_TicketStatusMaster', @ip_adress = @IPAdress, @device_id = @DeviceId, @IsImpersonation = @IsImpersonation, @ImpersonatorId = @ImpersonatorId
        END
    END
    ELSE IF @Option = 'Update' AND NOT EXISTS (
        SELECT 1
        FROM tbl_tp_TicketStatusMaster
        WHERE ParentID = @ParentID
        AND TicketStatus = @TicketStatusName
        AND TicketStatus_ID <> @TicketId
    )
    BEGIN
        UPDATE tbl_tp_TicketStatusMaster
        SET TicketStatus = @TicketStatusName, ModifiedBy = @CreatedBy, ModifiedDate = GETDATE()
        WHERE TicketStatus_ID = @TicketId

		Select 'Updated' AS Message
        
        IF @@ROWCOUNT > 0
        BEGIN
            SET @rowJson = (SELECT * FROM tbl_tp_TicketStatusMaster tsm WHERE tsm.TicketStatus_ID = @TicketId FOR JSON AUTO, INCLUDE_NULL_VALUES)
            
            IF @rowJson IS NOT NULL
            BEGIN
                EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData @User_id = @UserId
                ,@Activity_type = 'Updt_statusmaster'
                ,@ActionType = 'U'
                ,@RowJson = @rowJson
                ,@Table_name = 'tbl_tp_TicketStatusMaster', @ip_adress = @IPAdress, @device_id = @DeviceId, @IsImpersonation = @IsImpersonation, @ImpersonatorId = @ImpersonatorId
            END
        END
       
    END
    ELSE
    BEGIN
        SELECT 'Exists' AS Message
    END
END



GO

/* ============================================================
   Procedure: [dbo].[usp_tp_SendEmail]
