-- Exec usp_tp_SendEmail 1, 'Test Email Subject', 'Test Email body', 'Mayank.nigam@pelsoftlabs.in'        
-- Exec usp_tp_SendEmail 2724, 'Test Email Subject', 'Test Email body', 'Mayank.nigam@pelsoftlabs.in'        
CREATE   PROCEDURE [dbo].[usp_tp_SendEmail]        
(            
 @tpUserId bigint,        
 @Subject varchar(max),        
 @Body varchar(max),        
 @To varchar(max)        
)            
as            
Begin            
        
-- declare @tpUserId bigint=2724,@Subject varchar(max)='Test Email Subject',@Body varchar(max)='Test Email body',@To varchar(max)='Mayank.nigam@pelsoftlabs.in'        
        
   print '@tpUserId:'+cast(@tpUserId as varchar)  
   print '@Subject:'+isnull(@Subject,'')  
   print '@Body:'+isnull(@Body,'')  
   print '@To:'+isnull(@To,'')  
  
 Declare @AdminEmailID nvarchar(max) = '', @FromMailID nvarchar(max) = ''            
 declare @link_Account as bigint, @balance as bigint=0, @ParentId bigint            
 Declare @email_cnt as int =0            
 Declare @BatchID bigint            
            
 drop table if exists #tmp_lst_EmailId        
            
 If LEN(@Subject) > 0            
 Begin            
  If LEN(@Body) > 0            
  Begin            
   --Select @ParentId=ParentId From Serv_User_Detail(nolock) Where ser_user_id=@SerUserId            
   Select @ParentId=ParentId From tbl_tp_UserLogin(nolock) Where tpuser_id=@tpUserId            
            
   select ROW_NUMBER() over( order by item) rno,*             
   into #tmp_lst_EmailId            
   from dbo.SplitString(@To, ',')            
            
   select @email_cnt = COUNT(*) from #tmp_lst_EmailId            
               
   -- select @FromMailID=virtual_mail,@link_Account=link_Account from dbo.serv_user_domain(nolock) where ParentID = @ParentId            
   If exists(Select * from tbl_tp_notificationemaildetails(nolock) where ParentID = @ParentId and IsActive=1)
   Begin
		select @FromMailID=email,@link_Account=ParentID from tbl_tp_notificationemaildetails(nolock) where ParentID = @ParentId and IsActive=1
   End
   Else
   Begin
		print 'Returned -> From EmailID not defined'
		return;
   End
          
   --if exists(select 1 from supportreplymail(nolock) where parentid=@parentid and virtualmail=@FromMailID and isactive=1)          
   --begin          
   --select top 1 @FromMailID=usermail from supportreplymail(nolock) where parentid=@parentid and virtualmail=@FromMailID and isactive=1 order by id desc          
   --end          
          
   SELECT TOP 1 @balance=isnull(balance,0) FROM MailCreditDetails(nolock) WHERE USER_ID = @link_Account ORDER BY credit_id DESC          
        
   print '@link_Account: ' + cast(@link_Account as varchar)        
   print '@balance: ' + cast(@balance as varchar)                                                                    
   print '(@balance-@email_cnt): ' + cast((@balance-@email_cnt) as varchar)                                                                    
            
   --begin tran            
   insert into GetBatchRecord (User_id,RandNum)            
   select @ParentId, round(rand()*100000,0)            
            
   select @BatchID = SCOPE_IDENTITY()            
            
   delete from GetBatchRecord where BatchID=@BatchID            
   --commit            
            
   if (@balance-@email_cnt) > 0            
   begin            
            
    insert into CloneEmailsFilter(            
    Mail_FromEmail, Mail_ToEmail, Mail_Subject, Mail_TempleteName, Messages, Mail_InsertedDate, Mail_UserID, Mail_ParentID,            
    ReplyTo, Mail_BatchID, Mail_Priority, Mail_ScheduleDate, Mail_ScheduledTime, Mail_Attechement, Mail_TempleteBody,            
    IsMonitor,TemplateID,Count,Source            
    )            
    select @FromMailID, item, @Subject, '', @Body, GETDATE(), @link_Account, @ParentId,            
    @FromMailID, @BatchID, 1, '', '', '', @Body,            
    1, 0, @email_cnt, 'New Ticket Portal'             
    from #tmp_lst_EmailId            
            
    print 'Msg: Email Queued Successfully, BatchID: ' +  cast(@BatchID as varchar) + ', MailId: ' + cast(SCOPE_IDENTITY() as varchar)            
   end            
   --else            
   --begin            
   
   -- set @Subject = 'Insufficient Balance'            
            
   -- set @Body = 'Due to insufficient balance, You are unable to generate ticket related updates on email. Please Recharge!!!'            
            
   -- select @AdminEmailID=virtual_mail from dbo.serv_user_domain(nolock) where ParentID = 335        
            
   -- insert into CloneEmailsFilter(            
   -- Mail_FromEmail, Mail_ToEmail, Mail_Subject, Mail_TempleteName, Messages, Mail_InsertedDate, Mail_UserID, Mail_ParentID,            
   -- ReplyTo, Mail_BatchID, Mail_Priority, Mail_ScheduleDate, Mail_ScheduledTime, Mail_Attechement, Mail_TempleteBody,            
   -- IsMonitor, TemplateID, Count, Source            
   -- )            
   -- select @AdminEmailID, @FromMailID, @Subject, '', @Body, GETDATE(), 335, 335,            
   -- @AdminEmailID, @BatchID, 1, '', '', '', @Body,            
   -- 1, 0, 1, 'Ticket Management'            
         -- print 'Msg: Insufficient Email Balance '            
   --end            
  End            
  Else            
  Begin            
   print 'Msg: Invalid Email Body '            
  End            
 End            
 Else            
 Begin            
  print 'Msg: Invalid Email Subject '            
 End            
            
End 



GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_ServiceTypeBasedOnAction]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[Usp_tp_ServiceTypeBasedOnAction]    
    
@SelectedText VARCHAR(20),    
@ParentId BigInt    
AS     
BEGIN    
     --Declare 
     --@SelectedText VARCHAR(20)='Operator',    
     --@ParentId BigInt=1
  IF (@SelectedText = 'Assign to Agent')    
    
   BEGIN    
    
       Select ParentId,TpUser_Id AS Id,Name + ('('+LoginName+')') as Name  From tbl_tp_UserLogin (NOLOCK) Where ParentID =  @ParentId AND User_Id IS NOT NULL AND  IsActive = 1 order by TpUser_Id 	   
    
   END    
    
   IF (@SelectedText = 'Assign to Group')    
    
   BEGIN    
    
       Select Groupid As Id,GroupName As Name From tbl_tp_GroupMaster (NOLOCK) Where ParentId = @ParentId AND Active = 1    
    
   END    
    
   IF (@SelectedText = 'Set Ticket Status as')    
    
   BEGIN    
    
       Select TicketStatus_ID As Id,TicketStatus As Name From tbl_tp_TicketStatusMaster (NOLOCK) Where ParentId = @ParentId AND IsActive = 1    
    
   END    

IF (@SelectedText = 'Operator')
BEGIN
    DECLARE @datatypes NVARCHAR(10)
    IF (@ParentId = 1)
        SET @datatypes = 't,dt'
    ELSE IF (@ParentId = 2)
        SET @datatypes = 'dt'
    ELSE IF (@ParentId = 3)
        SET @datatypes = 'd'

    SELECT ConditionId AS Id, ConditionalOperator AS Name, ConditionName
    FROM tbl_tp_ConditionalOperator (NOLOCK)
    WHERE IsActive = 1 AND DatatypeId IN (SELECT value FROM STRING_SPLIT(@datatypes, ','));
END

    
    
    
END    


GO

