CREATE   PROC [dbo].[usp_tp_TicketAction]
(
	@jsonData		nvarchar(max)
)
As
Begin
--declare @jsonData nvarchar(max) = N'{
--  "Mode":"GetTableColumns",
--  "TpUserId":1,
--  "ParentId":32222,
--  "TableName":"UserLeads",
--  "ExcludedColumns":"ID,LeadNo"
--}'

--declare @jsonData nvarchar(max) = N'{
--  "Mode":"GetTableColumns",
--  "TpUserId":1,
--  "ParentId":32222,
--  "TableName":"tbl_tp_TicketMaster_32222",
--  "ExcludedColumns":"TicketId,CreatedOn,ModifiedOn"
--}'
	-- declare @jsonData nvarchar(max) = N'{"Mode":"TicketNoFormatAdd","RowId":0,"TpUserId":1,"ParentId":32222,"FormatFields":[{"value":"StaticText","type":"Field"},{"value":"/","type":"Separator"},{"value":"FinYear","type":"Field"},{"value":"/","type":"Separator"},{"value":"TktSource","type":"Field"},{"value":"/","type":"Separator"},{"value":"SNo","type":"Field"}],"FormatValues":[{"value":"KIT","type":"Field"},{"value":"/","type":"Separator"},{"value":"2023-24","type":"Field"},{"value":"/","type":"Separator"},{"value":"Forum","type":"Field"},{"value":"/","type":"Separator"},{"value":"000001","type":"Field"}],"MetaData":"{}"}'
	-- declare @jsonData nvarchar(max) = N'{"Mode":"TicketNoFormatGet","RowId":1,"TpUserId":1,"ParentId":32222,"MetaData":"{}"}'
	-- declare @jsonData nvarchar(max) = N'{"Mode":"TicketNoFormatDelete","RowId":1,"TpUserId":1,"ParentId":32222,"MetaData":"{}"}'
	-- declare @jsonData nvarchar(max) = N'{"Mode":"GetMenu","RowId":0,"TpUserId":1,"ParentId":32222,"MetaData":"{}"}'
	-- declare @jsonData nvarchar(max) = N'{"Mode":"GetKit19User","RowId":32222,"TpUserId":0,"ParentId":0,"MetaData":"{}"}'
	-- declare @jsonData nvarchar(max) = N'{"Mode":"GetNotficationEmail","RowId":0,"TpUserId":1,"ParentId":0,"MetaData":"{}"}'
	-- declare @jsonData nvarchar(max) = N'{"Mode":"GetPlaceHolderFields","RowId":0,"TpUserId":1,"ParentId":0,"MetaData":"{}"}'
	--declare @jsonData nvarchar(max) = N'{"Mode":"GetActiveCustomFields","RowId":20290,"TpUserId":1,"ParentId":0,"MetaData":"{}"}'
--DECLARE @jsonData NVARCHAR(MAX) = N'{
--  "Mode": "UpdateSectionVisibility",
--  "TpUserId": 1,
--  "ParentId": 32222,
--  "PageName": "Home",
--  "isvisible": true,
--  "sectionNumber": 5.1
--}';
--DECLARE @jsonData NVARCHAR(MAX) = N'{
--  "Mode": "GetFaqCategoriesWebsite",
--  "TpUserId": 1,
--  "ParentId": 0,
--  "PageName": "Faq''s",
--  "Domain":"localhost/aa"
--}';

--DECLARE @jsonData NVARCHAR(MAX) = N'{
--  "Mode": "ChangeContactFormStatus",
--  "TpUserId": 1,
--  "ParentId": 32222,
--  "action": "Spam",
-- "ticketId":"8"
--  }';
	DECLARE @activity VARCHAR(MAX) = '',@action VARCHAR(1) = '',@rowJson NVARCHAR(MAX) = null, @TableName varchar(100)='' ,@ParentId bigint, @UserId bigint, @TpUserId bigint, @IsAdmin bit, @Mode nvarchar(100)=''

	Declare @RowId bigint, @Subject	nvarchar(2000), @Description nvarchar(max), @TicketId bigint
	Declare @FormatField nvarchar(1000), @FormatValue nvarchar(2000), @MetaData nvarchar(max),@Pagename nvarchar(2000),@PageId int,@SectionNumber nvarchar(250),@visibility nvarchar(250),@DomainName nvarchar (max),@CategoryId nvarchar(100),@sectioncontent nvarchar(max)
	Declare @StrSql nvarchar(max),@PageNo nvarchar(250),@Pagesize nvarchar(250),@Sortfield nvarchar(max),@SqlWhere nvarchar(max), @SourceId bigint,@LeadId bigint,@Name nvarchar(max), @Mobile nvarchar(max), @Email nvarchar(max)

	Select @Mode=Mode,@TpUserId=TpUserId,@ParentId=ParentId,@RowId=RowId
	From openjson(@jsonData)
	With 
	(
		Mode		nvarchar(100)	'$.Mode',
		TpUserId	bigint			'$.TpUserId',
		ParentId	bigint			'$.ParentId',
		RowId		bigint			'$.RowId'
	)

	select @UserId=User_Id from tbl_tp_UserLogin(nolock) Where TpUser_Id=@TpUserId

	print '@jsonData: ' + isnull(@jsonData,'')
	print '@Mode: ' + isnull(@Mode,'')
	print '@TpUserId: ' + cast(isnull(@TpUserId,0) as varchar)
	print '@RowId: ' + cast(isnull(@RowId,0) as varchar)
	print '@ParentId: ' + cast(isnull(@ParentId,0) as varchar)
	print '@UserId: ' + cast(isnull(@UserId,0) as varchar)

	If(@Mode = 'TicketNoFormatAdd')
	Begin
		Select @FormatField=FormatField,@FormatValue=FormatValue,@MetaData=MetaData
		From openjson(@jsonData)
		With 
		(
			FormatField		nvarchar(500)	'$.FormatField',
			FormatValue		nvarchar(max)	'$.FormatValue',
			MetaData			nvarchar(max) as json
		)

		if not exists(Select * from tbl_tp_TicketNoFormat(nolock) Where ParentId=@ParentId and Isactive=1)
		Begin
			Insert into tbl_tp_TicketNoFormat(FormatJson,FormatField,FormatValue,ParentId,IsActive,CreatedBy,CreatedOn)
			values(@jsonData,@FormatField,@FormatValue,@ParentId,1,@TpUserId,GETDATE())

			select @RowId=SCOPE_IDENTITY()

			Select @RowId as Code, 'Ticket No. Format added successfully' as Msg

			SET @rowJson = (SELECT * FROM tbl_tp_TicketNoFormat(nolock) WHERE RowId=@RowId FOR JSON AUTO,INCLUDE_NULL_VALUES)
			SET @activity = 'Ins_tp_TktNoFormat'
			SET @action = 'I'  
			SET @TableName = 'tbl_tp_TicketNoFormat'
		End
		Else
		Begin
			Select -1 as Code, 'Ticket No. Format already exists' as Msg
		End

	End

	If(@Mode = 'TicketNoFormatGet')
	Begin
		SELECT	TF.RowId, TF.FormatJson, TF.FormatField, TF.FormatValue, TF.ParentId, TF.IsActive, TF.CreatedBy,
				format(TF.CreatedOn,'dd-MMM-yyyy') as CreatedOn, TF.ModifiedBy, TF.ModifiedOn, UL.LoginName
		FROM	tbl_tp_TicketNoFormat(nolock) TF INNER JOIN tbl_tp_UserLogin(nolock) UL
		ON		TF.CreatedBy = UL.TpUser_Id
		Where	TF.RowId=case when @RowId=0 then TF.RowId else @RowId end and TF.IsActive=1 and
				TF.ParentId=@ParentId

		SET @rowJson = null
		SET @activity = 'View_tp_TktNoFormat'
		SET @action = 'S'
		SET @TableName = 'tbl_tp_TicketNoFormat'
	End

	If(@Mode = 'TicketNoFormatDelete')
	Begin
		Update tbl_tp_TicketNoFormat Set IsActive=0,ModifiedBy=@TpUserId,ModifiedOn=GETDATE()
		Where RowId=@RowId

		Select @RowId as Code, 'Ticket No. Format deleted successfully' as Msg

		SET @rowJson = null
		SET @activity = 'Del_tp_TktNoFormat'
		SET @action = 'U'
		SET @TableName = 'tbl_tp_TicketNoFormat'
	End

	If(@Mode = 'TicketNoFormatEdit')
	Begin
		Select @FormatField=FormatField,@FormatValue=FormatValue,@MetaData=MetaData
		From openjson(@jsonData)
		With 
		(
			FormatField		nvarchar(500)	'$.FormatField',
			FormatValue		nvarchar(max)	'$.FormatValue',
			MetaData			nvarchar(max) as json
		)

		Update tbl_tp_TicketNoFormat set FormatJson=@jsonData,FormatField=@FormatField,FormatValue=@FormatValue,ModifiedBy=@TpUserId,ModifiedOn=GETDATE()
		Where RowId=@RowId

		Select @RowId as Code, 'Ticket No. Format edited successfully' as Msg

		SET @rowJson = (SELECT * FROM tbl_tp_TicketNoFormat(nolock) WHERE RowId=@RowId FOR JSON AUTO,INCLUDE_NULL_VALUES)
		SET @activity = 'Edit_tp_TktNoFormat'
		SET @action = 'U'  
		SET @TableName = 'tbl_tp_TicketNoFormat'

	End

	If(@Mode = 'GetMenu')
	Begin
		Exec usp_tp_GetMenuByTpuserId @TpUserId

		SET @UserId = 0 -- Bypass audit entry
	End

	If(@Mode = 'GetKit19User')
	Begin
        Declare @User_Login nvarchar(500) = '' 
		select @ParentId=Parentid, @User_Login = user_Login from User_Detail(nolock) where User_id=@RowId

		DECLARE @tmpNewValue TABLE ([Msg] varchar(100))
		INSERT INTO @tmpNewValue 
		EXEC usp_tp_CreateInternalUser @Parentid=@ParentId, @Kit19UserId=@RowId

        SELECT    
            [TpUser_Id],    
            [User_Id],        
            @User_Login as LoginName,        
            [Name],        
            IsActive [Status],        
            ParentId,        
            1 as IsLoginSuccess,        
            'User Login Successfull' [Message],      
            dbo.fn_ConvertDateTime(getdate(), 'India Standard Time', 0) TimeZoneDateTime      
        FROM tbl_tp_UserLogin(NOLOCK)    
        WHERE [User_Id] = @RowId AND IsActive = 1   

		SET @rowJson = null
		SET @activity = ''
		SET @action = ''
		SET @TableName = ''
	End

	If(@Mode = 'GetNotficationEmail')
	Begin
		select @ParentId=Parentid from User_Detail(nolock) where User_id=@UserId

        SELECT *      
        FROM tbl_tp_notificationemaildetails(NOLOCK)    
        WHERE Parentid = @ParentId AND IsActive = 1   

		return
	End

	If(@Mode = 'GetPlaceHolderFields')
	Begin
		Exec usp_tp_GetPlaceHolderFields @TpUserId
		return
	End

	If(@Mode = 'TicketSubDescEdit')
	Begin
		Select @Subject=Subject,@Description=Description
		From openjson(@jsonData)
		With 
		(
			Subject			nvarchar(500)	'$.Subject',
			Description		nvarchar(max)	'$.Description'
		)

		Set @StrSql=concat('Update tbl_tp_TicketMaster_',@ParentId,' set Subject=@Subject1,Description=@Description1,ModifiedBy=@TpUserId1,ModifiedOn=GETDATE()
		Where TicketId=@RowId1')

		EXECUTE sp_executesql @StrSql, N'@Subject1 varchar(2000), @Description1 nvarchar(max), @TpUserId1 bigint, @RowId1 bigint', @Subject1=@Subject, @Description1=@Description, @TpUserId1=@TpUserId, @RowId1=@RowId

		Select @RowId as Code, 'Ticket Edited Successfully' as Msg

		--SET @rowJson = (SELECT * FROM tbl_tp_TicketNoFormat(nolock) WHERE RowId=@RowId FOR JSON AUTO,INCLUDE_NULL_VALUES)
		--SET @activity = 'Edit_tp_TktNoFormat'
		--SET @action = 'U'  
		--SET @TableName = 'tbl_tp_TicketNoFormat'

	End

	If(@Mode = 'EditTicketNote')
	Begin
		Select @Description=Note, @TicketId=TicketId
		From openjson(@jsonData)
		With 
		(
			Note		nvarchar(max)	'$.Note',
			TicketId	bigint			'$.TicketId'
		)

		Set @StrSql=concat('Update tbl_tp_TicketMaster_',@ParentId,' set Note=@Note,ModifiedBy=@TpUserId1,ModifiedOn=GETDATE()
		Where TicketId=@TicketId1')

		EXECUTE sp_executesql @StrSql, N'@Note nvarchar(max), @TpUserId1 bigint, @TicketId1 bigint',  @Note=@Description, @TpUserId1=@TpUserId, @TicketId1=@TicketId

		Update tbl_tp_TicketHistory Set Note=@Description Where TicketHistoryID=@RowId

		Select @TicketId as Code, 'Ticket Note Edited Successfully' as Msg

		--SET @rowJson = (SELECT * FROM tbl_tp_TicketNoFormat(nolock) WHERE RowId=@RowId FOR JSON AUTO,INCLUDE_NULL_VALUES)
		--SET @activity = 'Edit_tp_TktNoFormat'
		--SET @action = 'U'  
		--SET @TableName = 'tbl_tp_TicketNoFormat'

	End

    If(@Mode = 'GetActiveCustomFields')
	Begin
		Exec usp_tp_GetActiveTicketCustomFields @RowId, @TpUserId
		return
	End

	IF @Mode = 'GetPageDatesdetails'
BEGIN
    SELECT @Pagename = PageName
    FROM OPENJSON(@jsonData)
    WITH 
    (
        PageName NVARCHAR(500) '$.PageName'
    )

    EXEC usp_tp_GetPageSectionDatesDetails  @TpUserId,@Pagename
    RETURN
END
    IF @Mode = 'UpdateSectionVisibility'
BEGIN
    -- Extract values from JSON
    SELECT @Pagename = PageName, 
           @SectionNumber = SectionNumber,
           @visibility = Visibility,
		   @sectioncontent= Sectioncontent,
		   @TpUserId=tpuserid
    FROM OPENJSON(@jsonData)
    WITH 
    (
        PageName NVARCHAR(500) '$.PageName',
        SectionNumber Nvarchar(250) '$.sectionNumber',
        Visibility NVARCHAR(250) '$.isvisible',
		 Sectioncontent NVARCHAR(max) '$.sectionContent',
		tpuserid bigint '$.TpUserId'
    );

	 

    -- Retrieve PageId
    SELECT @pageId = Page_Id
    FROM tbl_tp_PageTheme
    WHERE PageName = @Pagename AND IsActive = 1;



    -- Convert visibility to BIT value
    DECLARE @visibilityBit BIT;
    SET @visibilityBit = CASE 
                            WHEN @visibility = 'true' THEN 1 
                            WHEN @visibility = 'false' THEN 0 
                            ELSE NULL 
                         END;



    -- Update visibility
 IF EXISTS (SELECT 1 FROM tbl_tp_PageSectionDetail WHERE Page_Id = @pageId AND SectionNumber = @SectionNumber and IsActive=1)
    BEGIN
        -- Update visibility if the section exists
        UPDATE tbl_tp_PageSectionDetail 
        SET IsVisible = @visibilityBit 
        WHERE Page_Id = @pageId AND SectionNumber = @SectionNumber and IsActive=1;
    END
    ELSE
    BEGIN
        -- Insert a new section with default values and IsVisible = 0
        INSERT INTO tbl_tp_PageSectionDetail (Page_Id, SectionNumber,SectionContent,IsActive,tpuserid, CreatedDate, ModifiedDate, CreatedBy, ModifidBy, ParentId, IsVisible)
        VALUES (@pageId, 
                @SectionNumber,
				@sectioncontent,
                1, 
				  ISNULL(@TpUserId, ''), 
                GETDATE(), 
                GETDATE(), 
                ISNULL(@TpUserId, ''), 
                ISNULL(@TpUserId, ''), 
                ISNULL(@ParentId, ''), 
                0);
    END

    -- Confirmation message
    SELECT 'Visibility Update Successfully' AS Msg;
END
    If(@Mode = 'GetFaqMasterdetail')
	Begin
		Exec Usp_tp_GetFaqCategory_Master @TpUserId,'{}'
		return
	End
    IF @Mode = 'GetFaqCategoriesWebsite'
BEGIN
    SELECT @Pagename = PageName,@DomainName=Domain
    FROM OPENJSON(@jsonData)
    WITH 
    (
        PageName NVARCHAR(500) '$.PageName',
		Domain NVARCHAR(max) '$.Domain'
    )
	DECLARE @SubDomain NVARCHAR(200);
	print @SubDomain
            SET @SubDomain = SUBSTRING(@DomainName, LEN(@DomainName) - CHARINDEX('/', REVERSE(@DomainName)) + 2, LEN(@DomainName));
            DECLARE @FullPortalName NVARCHAR(MAX) = @DomainName + @SubDomain;

                SELECT TOP 1 @ParentId = ParentId
                FROM tbl_tp_Portalsetting WITH (NOLOCK)
                WHERE @SubDomain = PortalName and IsActive=1;
				print @ParentId


   select FaqCategoryId,FaqCategoryName from tbl_tp_TicketFaqCategory_Master where ParentId=@ParentId and IsActive=1
    RETURN
END
    IF @Mode = 'GetFaqCategoriescms'
BEGIN
    SELECT @Pagename = PageName
    FROM OPENJSON(@jsonData)
    WITH 
    (
        PageName NVARCHAR(500) '$.PageName'

    )

   select FaqCategoryId,FaqCategoryName from tbl_tp_TicketFaqCategory_Master where ParentId=@ParentId and IsActive=1
    RETURN
END
    IF @Mode = 'GetFaqContentcms'
BEGIN
    SELECT @Pagename = PageName,@CategoryId=CategoryId
    FROM OPENJSON(@jsonData)
    WITH 
    (
        PageName NVARCHAR(500) '$.PageName',
		CategoryId NVARCHAR (100)  '$.CategoryId'

    )

   select SectionContent from tbl_tp_PageSectionDetail where Authorname=@CategoryId and SectionNumber=7 and IsActive=1
    RETURN
END
    If(@Mode = 'GetLogo')
	Begin
	SELECT @DomainName=Domain
    FROM OPENJSON(@jsonData)
    WITH 
    (
		Domain NVARCHAR(max) '$.Domain'
    )

	print @SubDomain
            SET @SubDomain = SUBSTRING(@DomainName, LEN(@DomainName) - CHARINDEX('/', REVERSE(@DomainName)) + 2, LEN(@DomainName));
         set  @FullPortalName  = @DomainName + @SubDomain;

                SELECT TOP 1 @ParentId = ParentId
                FROM tbl_tp_Portalsetting WITH (NOLOCK)
                WHERE @SubDomain = PortalName and IsActive=1;
				print @ParentId

		  select LogoPath1,LogoPath2 from tbl_tp_PortalSetting where ParentId=@ParentId AND IsActive=1 and IsEnabled=1
	
	
	End
	IF @Mode = 'GetContactFormdetails'
BEGIN
	SELECT @Sortfield=Sortfield,@Pageno=Pageno,@PageSize=PageSize,@SqlWhere=Sqlwhere
	--@StrSql =strDate
    FROM OPENJSON(@jsonData)
    WITH 
    (
		Sortfield NVARCHAR(max) '$.sortField',
		PageNo NVARCHAR(max) '$.ContactcurrentPage',
		PageSize NVARCHAR(max) '$.PageSize',
		Sqlwhere NVARCHAR(max) '$.sqlquery'
		--strDate NVARCHAR(max) '$.strDate'
    )

Exec Usp_tp_GetContactFormDetails @SortField,@ParentID,@TpUserId,@Pageno,@Pagesize,@SqlWhere,'{}'
		return
   --select * from tbl_tp_ContactUsWebsitePortal(nolock)
   -- RETURN
END
	IF @Mode = 'InsertContactLead'
BEGIN
	SELECT @Name=Name,@Mobile=Mobile,@Email=Email,@TicketId=ticketId
    FROM OPENJSON(@jsonData)
    WITH 
    (
	   ticketId bigint '$.ticketId',
		Name NVARCHAR(max) '$.Name',
		Mobile NVARCHAR(max) '$.Mobile',
		Email NVARCHAR(max) '$.Email'
    )

   BEGIN
              IF NOT EXISTS (SELECT * FROM Usersourcesettings (NOLOCK) WHERE UserID = @ParentId AND IsActive = 1 AND name = 'ServiceTicketSignup')
                BEGIN
                    PRINT 'A';
                    INSERT INTO Usersourcesettings (name, UserId, IsEditable, IsActive, CreatedDate, ModifiedDate, ModifiedBy)
                    VALUES ('ServiceTicketSignup', @ParentId, 0, 1, GETDATE(), NULL, @ParentId);
                    SELECT @SourceId = SCOPE_IDENTITY();
                END
                ELSE
                BEGIN
                    PRINT 'B';
                    SELECT @SourceId = SourceId FROM Usersourcesettings (NOLOCK) WHERE UserID = @ParentId AND IsActive = 1 AND name = 'ServiceTicketSignup';
                END
                        DECLARE @Leadno BIGINT = ISNULL((SELECT MAX(LeadNo) FROM UserLeads (NOLOCK) WHERE ParentID = @ParentId), 0) + 1;
                        SET CONTEXT_INFO 0x55555;

                        INSERT INTO UserLeads (ParentID, PersonName, MobileNo, EmailID, AssignedTo, SourceName, LeadNo)
                        VALUES (@ParentId, @Name, @Mobile, @Email, @ParentId, @SourceId, @Leadno);

                        SELECT @LeadId = SCOPE_IDENTITY();
                        SET CONTEXT_INFO 0x;
						UPDATE tbl_tp_ContactUsWebsitePortal
SET EntityID = @LeadId,
    EntityName = 'Lead',
	Status = 'Read'
WHERE id=@TicketId
   select 'Lead Inserted Succesfully'
END
		return

   -- RETURN
END
    IF @Mode = 'ChangeContactFormStatus'
BEGIN
    -- Parse JSON data
    SELECT @SqlWhere = Sqlwhere, @TicketId = ticketId
    FROM OPENJSON(@jsonData)
    WITH 
    (
        Sqlwhere NVARCHAR(MAX) '$.action',
        ticketId BIGINT '$.ticketId'
    );

    -- Update status based on the value of @SqlWhere
    IF @SqlWhere = 'Spam'
    BEGIN
        UPDATE tbl_tp_ContactUsWebsitePortal
        SET Status = 'Spam'
        WHERE Id = @TicketId;
    END
    ELSE IF @SqlWhere = 'Delete'
    BEGIN
        UPDATE tbl_tp_ContactUsWebsitePortal
        SET Status = 'Delete',
            IsActive = 0
        WHERE Id = @TicketId;
    END
    ELSE IF @SqlWhere = 'Read'
    BEGIN
        UPDATE tbl_tp_ContactUsWebsitePortal
        SET Status = 'Read'
        WHERE Id = @TicketId;
    END

    -- Return success message
    SELECT 'Status  changed successfully';
END

-- =============================================
-- GENERIC COLUMN HEADER GET SP
-- =============================================

IF(@Mode = 'GetTableColumns')
BEGIN

    DECLARE @DynamicTableName NVARCHAR(200) = ''
    DECLARE @ExcludeColumns NVARCHAR(MAX) = ''
    DECLARE @DynamicSQL NVARCHAR(MAX) = ''

    SELECT
        @DynamicTableName = TableName,
        @ExcludeColumns = ExcludedColumns
    FROM OPENJSON(@jsonData)
    WITH
    (
        TableName NVARCHAR(200) '$.TableName',
        ExcludedColumns NVARCHAR(MAX) '$.ExcludedColumns'
    )

    -- Default Empty
    IF(ISNULL(@ExcludeColumns,'') = '')
    BEGIN
        SET @ExcludeColumns = 'ID'
    END

    SET @DynamicSQL = '
        DECLARE @ColumnNames NVARCHAR(MAX);

        SELECT
            @ColumnNames = STRING_AGG(COLUMN_NAME, '','')
        FROM INFORMATION_SCHEMA.COLUMNS
        WHERE TABLE_NAME = ''' + @DynamicTableName + '''
        AND COLUMN_NAME NOT IN (
            SELECT TRIM(value)
            FROM STRING_SPLIT(''' + REPLACE(@ExcludeColumns,'''','''''') + ''','','')
        );

        SELECT @ColumnNames AS ColumnNames;
    '

    PRINT @DynamicSQL

    EXEC(@DynamicSQL)

    RETURN
END

	If(isnull(@UserId,0) > 0)
	Begin
		EXEC MySMSAudit.dbo.Usp_AuditTableDataByParentId @User_id = @UserId  
		,@Activity_type = @activity  
		,@ActionType = @action  
		,@RowJson = @rowJson  
		,@Table_name = @TableName
	End

End





GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_TicketMasterByParentId]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

          
CREATE   PROCEDURE [dbo].[Usp_tp_TicketMasterByParentId]         
  @ParentId BIGINT  = NULL          
 ,@OldCustomField NVARCHAR(max) = NULL            
 ,@CustomField NVARCHAR(max) = NULL            
 ,@DataType NVARCHAR(max) = NULL            
 ,@Default NVARCHAR(max) = NULL            
 ,@MaxValue NVARCHAR(max) = NULL            
 ,@MinValue NVARCHAR(max) = NULL            
 ,@IsMandatory BIT = 0       
 ,@IsRequired BIT = 0      
 ,@IsActive BIT = 0      
 ,@Choices NVARCHAR(max) = NULL            
 ,@FieldType NVARCHAR(max) = NULL            
 ,@DisplayJson NVARCHAR(max) = NULL            
 ,@JChoice NVARCHAR(max) = NULL            
 ,@Mode VARCHAR(20) = ''      
 ,@ToolTipValue NVARCHAR(max) = NULL      
      
AS            
BEGIN            
          
 DECLARE @sqls NVARCHAR(max) = ''            
  ,@status INT            
  ,@tableName NVARCHAR(max) = ''            
            
 DROP TABLE            
            
 IF EXISTS #temp            
  CREATE TABLE #temp (            
   FieldName NVARCHAR(max)            
   ,DataType NVARCHAR(Max)            
   ,DefaultValue NVARCHAR(Max)            
   ,Mandatory BIT        
   ,Required BIT      
   ,Active BIT      
   ,FieldType NVARCHAR(Max)            
   ,MaxValue NVARCHAR(Max)            
   ,MinValue NVARCHAR(MAX)            
   ,Choices NVARCHAR(MAX) ,      
   ToolTipValue NVARCHAR(MAX) ,  
   IsActive BIT  
   )            
            
EXEC @status = Usp_tp_CreateTicketMasterTableByParentID @ParentID, @tableName OUTPUT;           
              
 BEGIN            
  IF @Mode = 'Save'            
  BEGIN            
   IF @CustomField IS NOT NULL            
   BEGIN            
    IF EXISTS (            
      SELECT 1            
      FROM INFORMATION_SCHEMA.COLUMNS            
      WHERE TABLE_NAME = @tableName            
       AND TABLE_CATALOG = db_name()            
       AND COLUMN_NAME = @CustomField            
      )            
    BEGIN            
     SELECT 'Field Name Already Exists' AS Message            
    END            
    ELSE            
    BEGIN            
     SET @sqls = 'alter table ' + @tableName + ' add ' + @CustomField + ' ' + @DataType            
            
     PRINT @sqls            
     EXECUTE sp_executesql @sqls            
            
     IF @IsMandatory = 1            
     BEGIN            
      SET @sqls = 'update ' + @tableName + ' set ' + @CustomField + ' = 0 Where ' + @CustomField + ' IS NULL ;'            
                     
      EXECUTE sp_executesql @sqls            
            
      SET @sqls = 'alter table ' + @tableName + ' Alter column ' + @CustomField + '  ' + @DataType + ' NOT NULL'            
                 
      EXECUTE sp_executesql @sqls            
     END            
            
     IF @Default IS NOT NULL            
     BEGIN            
      IF @Default = 'getdate()'            
      BEGIN            
       SET @sqls = 'alter table ' + @tableName + ' add CONSTRAINT pm' + @CustomField + 'DateCurr Default ' + @Default + ' for ' + @CustomField            
      END            
      ELSE IF @DataType = 'DateTime'            
       AND @default <> 'getdate()'            
      BEGIN            
       SET @sqls = CONCAT (            
         'alter table '            
         ,@tableName            
         ,' add CONSTRAINT pm' + @CustomField + 'DateDef Default cast('            
         ,@Default            
         ,'as datetime)   for '            
         ,@CustomField            
         )            
      END            
      ELSE IF @DataType = 'bigint'            
      BEGIN            
       SET @sqls = CONCAT (            
         'alter table '            
         ,@tableName            
         ,' add CONSTRAINT pm' + @CustomField + 'NumDef Default '            
         ,@default            
         ,'  for '            
         ,@CustomField            
         )            
      END            
      ELSE            
      BEGIN            
       SET @sqls = CONCAT (            
         'alter table '            
         ,@tableName   
         ,' add CONSTRAINT pm' + @CustomField + 'Def Default '''            
         ,@default            
         ,'''  for '            
         ,@CustomField            
         )            
      END            
            
      PRINT @sqls      
            
      EXECUTE sp_executesql @sqls            
     END            
            
     IF @maxvalue IS NOT NULL            
     BEGIN            
      IF @DataType = 'DateTime'            
      BEGIN            
       SET @sqls = 'alter table ' + @tableName + ' add CONSTRAINT pm' + @CustomField + 'DateMax Check (' + @CustomField + ' <= cast(' + @maxvalue + '  as datetime))'            
                
       EXECUTE sp_executesql @sqls            
      END            
      ELSE            
      BEGIN            
       SET @sqls = 'alter table ' + @tableName + ' add CONSTRAINT pm' + @CustomField + 'NumMax Check (' + @CustomField + ' <= ' + @maxvalue + ' )'           
                  
       EXECUTE sp_executesql @sqls            
      END            
     END            
            
     IF @minvalue IS NOT NULL            
     BEGIN            
      IF @DataType = 'DateTime'            
      BEGIN            
       SET @sqls = 'alter table ' + @tableName + ' add CONSTRAINT pm' + @CustomField + 'DateMin Check (' + @CustomField + ' >= cast(' + @minvalue + 'as datetime) )'            
            
       --print @sqls                  
       EXECUTE sp_executesql @sqls            
      END            
      ELSE            
      BEGIN            
       SET @sqls = 'alter table ' + @tableName + ' add CONSTRAINT pm' + @CustomField + 'NumMin Check (' + @CustomField + ' >= ' + @minvalue + ' )'            
            
       --print @sqls                  
       EXECUTE sp_executesql @sqls            
      END            
     END            
            
     IF @Choices IS NOT NULL            
      AND @fieldtype <> 'multiselect'            
     BEGIN            
      SET @sqls = 'alter table ' + @tableName + ' add CONSTRAINT pm' + @CustomField + 'choice Check (' + @CustomField + ' ' + @Choices + ')'            
            
      --print @sqls                
      EXECUTE sp_executesql @sqls            
     END            
            
     IF @fieldtype IS NOT NULL            
     BEGIN            
      INSERT INTO #temp (            
        FieldName            
       ,DataType            
       ,DefaultValue            
       ,Mandatory       
       ,Required      
       ,Active      
       ,FieldType            
       ,MaxValue            
       ,MinValue            
       ,Choices       
       ,ToolTipValue  
    ,IsActive  
       )            
      VALUES (            
       @CustomField            
       ,@DataType            
       ,ISNULL(Replace(@default, '''', ''), '')            
       ,@IsMandatory, @IsRequired, @IsActive          
       ,@fieldtype            
       ,ISNULL(Replace(@maxvalue, '''', ''), '')            
       ,ISNULL(Replace(@minvalue, '''', ''), '')            
       ,ISNULL(@Choices, '') ,       
       @ToolTipValue  
    ,@IsActive  
       )            
            
      SET @DisplayJson = (            
        SELECT *            
        FROM #temp            
        FOR json Auto            
         ,INCLUDE_NULL_VALUES            
        )            
      --select * from #temp            
      EXECUTE Usp_tp_InsertTicketFieldDisplayJson @DisplayJson = @DisplayJson            
       ,@ParentId = @ParentId            
       ,@Mode = @Mode            
     END            
            
     SELECT 'Field Added Successfully ' AS Result            
    END            
   END            
  END            
IF @mode = 'Update'  
BEGIN  
    IF @CustomField IS NOT NULL  
    BEGIN  
        -- Drop the default constraint if it exists  
        IF EXISTS (  
            SELECT 1  
            FROM sys.default_constraints d  
            INNER JOIN sys.columns c ON c.column_id = d.parent_column_id  
            WHERE OBJECT_NAME(d.parent_object_id) = @tableName  
            AND c.name = @oldCustomfield  
        )  
        BEGIN  
            DECLARE @dropDefaultSQL NVARCHAR(MAX);  
            SET @dropDefaultSQL = 'ALTER TABLE ' + QUOTENAME(@tableName) + ' DROP CONSTRAINT ' + QUOTENAME('DF_' + @tableName + '_' + @oldCustomfield);  
              
            PRINT @dropDefaultSQL;  
            EXEC sp_executesql @dropDefaultSQL;  
        END  
  
        -- Drop the check constraint if it exists  
        IF EXISTS (  
            SELECT 1  
            FROM sys.check_constraints d  
            INNER JOIN sys.columns c ON c.column_id = d.parent_column_id  
            WHERE OBJECT_NAME(d.parent_object_id) = @tableName  
            AND c.name = @oldCustomfield  
        )  
        BEGIN  
            DECLARE @dropCheckSQL NVARCHAR(MAX);  
            SET @dropCheckSQL = 'ALTER TABLE ' + QUOTENAME(@tableName) + ' DROP CONSTRAINT ' + QUOTENAME('CK_' + @tableName + '_' + @oldCustomfield);  
              
            PRINT @dropCheckSQL;  
            EXEC sp_executesql @dropCheckSQL;  
        END  
  
        -- Rename the column  
        DECLARE @renameColumnSQL NVARCHAR(MAX);  
        SET @renameColumnSQL = 'EXEC sp_rename @objname = ' + QUOTENAME(@tableName + '.' + @oldCustomfield) + ', @newname = ' + QUOTENAME(@CustomField) + ', @objtype = ''COLUMN'';';  
          
        PRINT @renameColumnSQL;  
        EXEC sp_executesql @renameColumnSQL;  
    END  
  
    IF @choices IS NOT NULL AND @fieldtype <> 'multiselect'  
    BEGIN  
        -- Add a check constraint for choices  
        DECLARE @checkConstraintSQL NVARCHAR(MAX);  
        SET @checkConstraintSQL = 'ALTER TABLE ' + QUOTENAME(@tableName) + ' ADD CONSTRAINT ' + QUOTENAME('CK_' + @tableName + '_' + @CustomField) + ' CHECK (' + @CustomField + ' IN (' + @choices + '))';  
          
        PRINT @checkConstraintSQL;  
        EXEC sp_executesql @checkConstraintSQL;  
    END  
  
    IF @default IS NOT NULL  
    BEGIN  
        -- Add a default constraint based on the data type  
        DECLARE @defaultConstraintSQL NVARCHAR(MAX);  
        SET @defaultConstraintSQL = 'ALTER TABLE ' + QUOTENAME(@tableName) + ' ADD CONSTRAINT ' + QUOTENAME('DF_' + @tableName + '_' + @CustomField);  
          
        IF @default = 'getdate()'  
        BEGIN  
            SET @defaultConstraintSQL = @defaultConstraintSQL + ' DEFAULT GETDATE() FOR ' + QUOTENAME(@CustomField);  
        END  
        ELSE IF @DataType = 'DateTime'  
        BEGIN  
            SET @defaultConstraintSQL = @defaultConstraintSQL + ' DEFAULT CAST(''' + @default + ''' AS DATETIME) FOR ' + QUOTENAME(@CustomField);  
        END  
        ELSE IF @DataType = 'bigint'  
        BEGIN  
            SET @defaultConstraintSQL = @defaultConstraintSQL + ' DEFAULT ' + @default + ' FOR ' + QUOTENAME(@CustomField);  
        END  
        ELSE  
        BEGIN  
            SET @defaultConstraintSQL = @defaultConstraintSQL + ' DEFAULT ''' + @default + ''' FOR ' + QUOTENAME(@CustomField);  
        END  
  
        PRINT @defaultConstraintSQL;  
        EXEC sp_executesql @defaultConstraintSQL;  
    END  
  
    EXECUTE Usp_InsertProductFieldDisplayJson  
        @displayJson = @displayJson,  
        @parentid = @parentid,  
        @mode = @mode,  
        @CustomField = @CustomField,  
        @isman = @ismandatory,  
        @default = @default,  
        @choices = @jchoice,  
        @oldcustomField = @oldCustomfield;  
  
    SELECT 'Field Updated' AS Result;  
END  
  
           
 END            
          
            
 IF @mode = 'Select'            
 BEGIN            
  Select COLUMN_NAME, DATA_TYPE,COLUMN_DEFAULT From INFORMATION_SCHEMA.COLUMNS where TABLE_NAME=@tableName and TABLE_CATALOG='Mysms' and COLUMN_NAME not in ('TicketID','tpUser_Id','ParentID','TicketNo','RequesterMobileNo','RequesterEmailID','Requeste
rMobileNo1','RequesterEmailID1','RequesterMobileNo2','RequesterEmailID2',  
     'Subject','Description','TicketStatusID','Remarks','Note',  'ProductId' ,'IsActive' ,'CreatedBy','CreatedOn',           
    'UserResponse','TicketPriority','AssignedUser','AssignedGroup','AssignedSource','TicketCategoryId','TicketTypeId','TicketSourceId','IsMerged','IsSplitted',                  
    'IsParentTicket','IsChildTicket','ParentTicketID','LastActionDatetime','AssignedBy','AssignedDateTime','TicketTag','EntityID','EntityName','Company',        
    'ModifiedBy','ModifiedOn','SplittedBy','SplittedOn','MergedBy','MergedOn','ClosedBy','ClosedOn','CreatedChildBy','CreatedChildOn')                  
  SELECT @displayJson = DisplayJson            
  FROM tbL_tp_TicketCustomFieldDisplayJson            
  WHERE ParentId = @ParentId -- and iscatalogue = null              
            
  DROP TABLE            
            
  IF EXISTS #temp            
   CREATE TABLE #temp2 (            
    FieldName NVARCHAR(max)            
    ,DataType NVARCHAR(Max)            
    ,DefaultValue NVARCHAR(Max)            
    ,Mandatory BIT            
    ,FieldType NVARCHAR(Max)            
    ,MaxValue NVARCHAR(Max)            
    ,MinValue NVARCHAR(MAX)            
    ,Choices NVARCHAR(MAX)    
 ,ToolTipValue NVARCHAR (MAX)  
 ,Active BIT  
    )            
            
  INSERT INTO #temp2 (            
   FieldName            
   ,DataType            
   ,DefaultValue            
   ,Mandatory            
   ,FieldType            
   ,MaxValue            
   ,MinValue            
   ,Choices   
   ,ToolTipValue  
   ,Active  
   )            
  SELECT FieldName            
   ,DataType            
   ,DefaultValue            
   ,Mandatory            
   ,FieldType            
   ,MaxValue            
   ,MinValue            
   ,Choices   
   ,ToolTipValue   
   ,Active  
  FROM OPENJSON(@displayJson) WITH (            
    FieldName NVARCHAR(max) '$.FieldName'            
    ,DataType NVARCHAR(Max) '$.DataType'            
    ,DefaultValue NVARCHAR(Max) '$.DefaultValue'            
    ,Mandatory NVARCHAR(Max) '$.Mandatory'            
    ,FieldType NVARCHAR(Max) '$.FieldType'            
    ,MaxValue NVARCHAR(Max) '$.MaxValue'            
    ,MinValue NVARCHAR(MAX) '$.MinValue'            
    ,Choices NVARCHAR(MAX) '$.Choices'    
 ,ToolTipValue NVARCHAR (MAX) '$.ToolTipValue'   
 ,Active BIT '$.Active'   
    )            
            
  SELECT *            
  FROM #temp2            
 END            
END 



