/* ============================================================
   Procedure: [dbo].[Usp_tp_TicketType_Master]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_TicketType_Master]                
(              
 @TicketId bigint,                 
 @TpUserId bigint,    
 @TypeName nvarchar(40),  
 @TypeDesc nvarchar(300),                          
 @Option varchar(10) ,                       
 @MetaData nvarchar(200)          
)                
AS                
                 
BEGIN               
          
DECLARE @TimeZone NVARCHAR (400),@ParentId BIGINT ,@rowJson NVARCHAR(MAX)  , @IPAdress NVARCHAR(50),@DeviceId NVARCHAR(50),@IsImpersonation BIT ,@ImpersonatorId INT ,   @UserId BigInt        
Select @UserId = User_ID,@TimeZone = TimeZone,@ParentId = ParentId  From tbl_tp_UserLogin (noLock) Where TpUser_Id = @TpUserId AND IsActive = 1                    
                    
    SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)            
    SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)            
    SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)            
    SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)          
                
If @Option = 'Insert'                 
BEGIN                 
  IF(Not Exists(Select 'x' from tbl_tp_TicketType_Master Where Type_Name = @TypeName  AND tpUserid = @TpUserId))                
   Begin                
  INSERT INTO tbl_tp_TicketType_Master                
           (Type_Name, Type_Desc,tpUserid,Active,CreatedBy,CreatedDate,ParentId)                
     VALUES    
    
           (@TypeName,@TypeDesc,@TpUserId,1,@UserId,GETDATE(),@ParentId)    
       
            Select 'Record inserted succesfully !' resp   
     
         SET @rowJson  = ( SELECT *  FROM tbl_tp_TicketType_Master  FOR JSON AUTO  ,INCLUDE_NULL_VALUES )                    
                    
          IF @rowJson IS NOT NULL                    
          BEGIN                    
           EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData @User_id = @UserId                    
            ,@Activity_type = 'Add_tickettype'                    
            ,@ActionType = 'I'                    
            ,@RowJson = @rowJson                    
            ,@Table_name = 'tbl_tp_TicketType_Master'  ,@ip_adress = @IPAdress ,@device_id = @DeviceId,@IsImpersonation = @IsImpersonation,@ImpersonatorId =  @ImpersonatorId             
          END          
  End                
  Else                
    Begin                
      Select 'Ticket type already exists' resp                 
                   
    End                
                  
                  
End                
If @Option = 'Update'                 
Begin                
 If EXISTS(Select 1 from tbl_tp_TicketType_Master Where Type_Name = @TypeName AND Type_Desc = @TypeDesc AND Type_ID <> @TicketId)                
  Select 'Ticket type already exists' resp                
 Else     
   
 Update tbl_tp_TicketType_Master      
   
  Set  Type_Name = @TypeName,Type_Desc = @TypeDesc ,ParentId=@ParentId               
  Where  Type_ID= @TicketId               
  Select 'Record updated succesfully !' resp   
    
  SET @rowJson  = ( SELECT *  FROM tbl_tp_TicketType_Master  FOR JSON AUTO  ,INCLUDE_NULL_VALUES )                    
                    
          IF @rowJson IS NOT NULL                    
          BEGIN                    
           EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData @User_id = @UserId                    
            ,@Activity_type = 'Update_tickettype'                    
            ,@ActionType = 'U'                    
            ,@RowJson = @rowJson                    
            ,@Table_name = 'tbl_tp_TicketType_Master'  ,@ip_adress = @IPAdress ,@device_id = @DeviceId,@IsImpersonation = @IsImpersonation,@ImpersonatorId =  @ImpersonatorId             
          END          
End                
               
End 



GO

