-- Create a stored procedure for updating agent details
CREATE   PROCEDURE [dbo].[Usp_tp_UpdateAgentDetails]
    @UserId INT,
    @NewName NVARCHAR(MAX),
    @NewEmail NVARCHAR(MAX),
    @NewPhone NVARCHAR(MAX)

AS
BEGIN
    -- Update the agent's details
    UPDATE tbl_tp_UserLogin
    SET Name = @NewName,
        Email = @NewEmail,
        Mobile = @NewPhone
     
    WHERE User_Id = @UserId;
    
    -- Return success or failure information
    IF @@ROWCOUNT > 0
        SELECT 'Success' AS Status, 'Agent details updated successfully.' AS Message;
    ELSE
        SELECT 'Error' AS Status, 'Failed to update agent details.' AS Message;
END



