/* ============================================================
   Procedure: [dbo].[USP_tp_UpdateforgotTicketPassword]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON




CREATE   PROCEDURE [dbo].[USP_tp_UpdateforgotTicketPassword]
    @guid nvarchar(max),
    @NewPwd nvarchar(50)
AS
BEGIN
    DECLARE @count int
	Declare @tpUserID bigint
	SELECT @tpuserid = userid
    FROM ResetPassword
        WHERE guid = @guid;
    -- Check if the old password matches for the provided UserID
    SELECT @count = COUNT(*) FROM tbl_tp_UserLogin (NOLOCK) WHERE TpUser_Id = @tpUserID AND pwd = @NewPwd

     IF (@tpuserid IS NOT NULL)
    BEGIN
        -- Update the password for the specific user
        UPDATE tbl_tp_UserLogin SET pwd = @NewPwd WHERE TpUser_Id = @tpUserID
        SELECT 'Password changed Successfully' AS msg
    END
    ELSE
    BEGIN
        -- The old password provided is incorrect for the given user
        SELECT ' Password Already exist' AS msg
    END
END





GO

