/* ============================================================
   Procedure: [dbo].[Usp_tp_UpdateResetPasswordTable]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON


CREATE   PROCEDURE [dbo].[Usp_tp_UpdateResetPasswordTable]
    @guid NVARCHAR(255)
AS
BEGIN
    BEGIN TRY
        UPDATE ResetPassword
        SET isvalid = 0, processedon = GETDATE()
        WHERE guid = @guid;
        SELECT 'Success' AS Result;
    END TRY
    BEGIN CATCH
        SELECT 'Error' AS Result;
    END CATCH
END





GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_UpdateScenarioSequence]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_UpdateScenarioSequence]                        
                    
  @ScenarioIds nvarchar(MAX),            
  @TpUserId BIGINT,            
  @MetaData nvarchar(MAX)            
                        
               
AS                        
Begin                        
   SET NOCOUNT ON;                    
              
    DECLARE @InsertedId BIGINT,@UserId BIGINT,@ParentID BIGINT, @rowJson NVARCHAR(MAX)   , @IPAdress NVARCHAR(50),@DeviceId NVARCHAR(50),@IsImpersonation BIT ,@ImpersonatorId INT          
      Select @UserId = User_ID, @ParentID = ParentId  From tbl_tp_UserLogin (noLock) Where TpUser_Id = @TpUserId AND IsActive = 1     
             
    SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)          
    SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)          
    SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)          
    SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)          
          
              
IF (LEN(@ScenarioIds)>0)                
BEGIN                
      
DECLARE @SequenceTab TABLE(ScenarioId int, AutoSequence int IDENTITY(1, 1))      
insert into @SequenceTab(ScenarioId)      
select item from dbo.SplitString(@ScenarioIds,',')      
      
Update tbl_tp_ScenarioMaster SET SequenceNo=b.AutoSequence  
from tbl_tp_ScenarioMaster a      
INNER JOIN @SequenceTab b ON a.Scenario_Id=b.ScenarioId      
      
    SET @rowJson  = ( SELECT a.*  FROM tbl_tp_ScenarioMaster(nolock) a INNER JOIN @SequenceTab b ON a.Scenario_Id=b.ScenarioId  FOR JSON AUTO,INCLUDE_NULL_VALUES)  
                  
          IF @rowJson IS NOT NULL                
          BEGIN                
           EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData @User_id = @UserId                
            ,@Activity_type = 'Update_ScenarioSequence'                
            ,@ActionType = 'U'                
            ,@RowJson = @rowJson                
            ,@Table_name = 'tbl_tp_ScenarioMaster'  ,@ip_adress = @IPAdress ,@device_id = @DeviceId,@IsImpersonation = @IsImpersonation,@ImpersonatorId =  @ImpersonatorId           
          END           
          
    select 'Sequence Updated.'      
END                
          
END 



GO

