INNER JOIN @SequenceTab b ON a.SLA_Id=b.SLAId        
        
    SET @rowJson  = ( SELECT a.*  FROM tbl_tp_SLAMaster(nolock) a INNER JOIN @SequenceTab b ON a.SLA_Id=b.SLAId    FOR JSON AUTO,INCLUDE_NULL_VALUES)    
                    
          IF @rowJson IS NOT NULL                  
          BEGIN                  
           EXEC MySmsAudit.dbo.Usp_Audit_InsertAuditData @User_id = @UserId                  
