            ,@ActionType = 'U'                  
            ,@RowJson = @rowJson                  
            ,@Table_name = 'tbl_tp_SLAMaster'  ,@ip_adress = @IPAdress ,@device_id = @DeviceId,@IsImpersonation = @IsImpersonation,@ImpersonatorId =  @ImpersonatorId             
          END             
            
    select 'Sequence Updated.'        
END                  
            
END 



