/* ============================================================
   Procedure: [dbo].[Usp_tp_UpdateTicketPrioritySequence]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_UpdateTicketPrioritySequence]                      
                  
  @Priority_Ids nvarchar(MAX),    
  @ParentID BIGINT,    
  @UserID BIGINT,          
  @MetaData nvarchar(MAX)          
                      
             
AS                      
Begin                      
   SET NOCOUNT ON;                  
            
    DECLARE @InsertedId BIGINT,@User_Id BIGINT, @rowJson NVARCHAR(MAX)   , @IPAdress NVARCHAR(50),@DeviceId NVARCHAR(50),@IsImpersonation BIT ,@ImpersonatorId INT        
    Select @User_Id = User_ID  From User_Detail (noLock) Where ParentId = @ParentID    
           
    SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress)        
    SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress)        
    SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation)        
    SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId)        
        
            
IF (LEN(@Priority_Ids)>0)              
BEGIN              
    
DECLARE @PriorityIdsTab TABLE(PriorityId int, AutoSequence int IDENTITY(1, 1))    
insert into @PriorityIdsTab(PriorityId)    
select item from dbo.SplitString(@Priority_Ids,',')    
    
Update tbl_tp_TicketPriorityMaster SET SequenceNo=b.AutoSequence
from tbl_tp_TicketPriorityMaster a    
INNER JOIN @PriorityIdsTab b ON a.Priority_Id=b.PriorityId    
    
    SET @rowJson  = ( SELECT a.*  FROM tbl_tp_TicketPriorityMaster(nolock) a INNER JOIN @PriorityIdsTab b ON a.Priority_Id=b.PriorityId  FOR JSON AUTO,INCLUDE_NULL_VALUES)
                
          IF @rowJson IS NOT NULL              
          BEGIN              
           EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData @User_id = @UserId              
            ,@Activity_type = 'Update_TicketPrioritySequence'              
            ,@ActionType = 'U'              
            ,@RowJson = @rowJson              
            ,@Table_name = 'tbl_tp_TicketPriorityMaster'  ,@ip_adress = @IPAdress ,@device_id = @DeviceId,@IsImpersonation = @IsImpersonation,@ImpersonatorId =  @ImpersonatorId         
          END         
        
    select 'Sequence Updated.'    
END              
        
END 



GO

/* ============================================================
   Procedure: [dbo].[Usp_tp_UpdateTicketValues]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--exec Usp_tp_UpdateTicketValues @TicketId=83,@TicketType=0,@TicketStatus=3,@TicketPriority=3,@TicketGroups=0,@TicketAgent=0,@TicketProduct=0,@TpUserId=1,@Notes=N'no data'
--exec Usp_tp_UpdateTicketValues @TicketId=83,@TicketType=0,@TicketStatus=5,@TicketPriority=3,@TicketGroups=0,@TicketAgent=0,@TicketProduct=0,@TpUserId=1,@Notes=N'no data'
--exec Usp_tp_UpdateTicketValues @TicketId=83,@TicketType=0,@TicketStatus=6,@TicketPriority=0,@TicketGroups=0,@TicketAgent=0,@TicketProduct=N'',@TpUserId=1,@Notes=N'pending status updated'
CREATE   PROCEDURE [dbo].[Usp_tp_UpdateTicketValues]
(     
	@TicketId bigint,
	@TicketType int,
	@TicketStatus bigint,
	@TicketPriority int,
	@TicketGroups bigint,
	@TicketAgent bigint,
	@TicketProduct nvarchar(max),
	@TpUserId bigint,
	@Notes nvarchar(max)
)                          
AS                          
BEGIN
	--declare @TicketId bigint=10264,@TicketType int=0,@TicketStatus bigint=0,@TicketPriority int=0,@TicketGroups bigint=20,@TicketAgent bigint=0,@TicketProduct nvarchar(max)=N'',@TpUserId bigint=1,@Notes nvarchar(max)=N''

    DECLARE	@DynamicSQL NVARCHAR(MAX), @status INT, @ParentId BIGINT, @tableName NVARCHAR(MAX), @strNotes NVARCHAR(MAX)='', @strQuery NVARCHAR(MAX)
	DECLARE @ActivityId BIGINT, @EventDesc NVARCHAR(MAX), @UserCreated NVARCHAR(100),@EventName NVARCHAR(MAX), @TicketNo NVARCHAR(50), @CreatedOn DATE, @EntityName varchar(500), @EntityID bigint, @UserId bigint, @TicketHistoryID bigint=0
	Declare @OldValue nvarchar(max)='', @ActivityDatetime datetime=Getdate()  
          
    SELECT @ParentId = ParentId, @UserCreated = Name, @UserId=User_id     
    FROM tbl_tp_UserLogin (NOLOCK)     
    WHERE TpUser_Id = @TpUserId AND IsActive = 1;        
            
    EXEC @status = Usp_tp_CreateTicketMasterTableByParentID @ParentId, @tableName OUTPUT;              
        
	If(@TicketType>0 or @TicketStatus>0 or @TicketPriority>0 or @TicketGroups>0 or @TicketAgent>0 or @TicketProduct>0)
	Begin
		drop table if exists #tbl_tp_TicketHistoryBeforeEdit

		create table #tbl_tp_TicketHistoryBeforeEdit
		(
			TicketID			bigint,
			tpUser_Id			bigint,
			ParentID			bigint,
			TicketNo			nvarchar(100),	     	     
			RequesterMobileNo	nvarchar(100),	     	     
			RequesterEmailID	nvarchar(400),	     	     
			RequesterMobileNo1	nvarchar(100),	     	     
			RequesterEmailID1	nvarchar(400),	     	     
			RequesterMobileNo2	nvarchar(100),	     	     
			RequesterEmailID2	nvarchar(400),	     	     
			Subject				nvarchar(2000),
			Description			nvarchar(max),
			TicketStatusID		bigint,
			Remarks				nvarchar(max),
			Note				nvarchar(max),
			UserResponse		nvarchar(max),
			TicketPriority		bigint,
			AssignedUser		bigint,
			AssignedGroup		bigint,
			AssignedSource		nvarchar(100),
			TicketCategoryId	bigint,
			TicketTypeId		int,
			TicketSourceId		bigint,
			ProductId			bigint,
			IsMerged			bit,
			IsSplitted			bit,
			IsParentTicket		bit,
			IsChildTicket		bit,
			ParentTicketID		bigint,
			LastActionDatetime	datetime,
			AssignedBy			bigint,
			AssignedDateTime	datetime,
			TicketTag			nvarchar(2000),
			EntityID			bigint,
			EntityName			nvarchar(40),
			Company				nvarchar(800),
			CreatedBy			bigint,
			CreatedOn			datetime
		)

		DECLARE @DynamicUpdateQuery NVARCHAR(MAX);
		                      
		SELECT @DynamicUpdateQuery = concat(N'insert into #tbl_tp_TicketHistoryBeforeEdit(TicketID, tpUser_Id, ParentID, TicketNo, RequesterMobileNo, RequesterEmailID, RequesterMobileNo1, RequesterEmailID1, RequesterMobileNo2, RequesterEmailID2, Subject, Description, TicketStatusID, Remarks, Note, UserResponse, TicketPriority, AssignedUser, AssignedGroup, AssignedSource, TicketCategoryId, TicketTypeId, TicketSourceId, ProductId, IsMerged, IsSplitted, IsParentTicket, IsChildTicket, ParentTicketID, LastActionDatetime, AssignedBy, AssignedDateTime, TicketTag, EntityID, EntityName, Company, CreatedBy, CreatedOn)
		Select	TicketID, tpUser_Id, ParentID, TicketNo, RequesterMobileNo, RequesterEmailID, RequesterMobileNo1, RequesterEmailID1, RequesterMobileNo2, RequesterEmailID2, Subject, Description, TicketStatusID, Remarks, Note, UserResponse, TicketPriority, AssignedUser, AssignedGroup, AssignedSource, TicketCategoryId, TicketTypeId, TicketSourceId, ProductId, IsMerged, IsSplitted, IsParentTicket, IsChildTicket, ParentTicketID, LastActionDatetime, AssignedBy, AssignedDateTime, TicketTag, EntityID, EntityName, Company, CreatedBy, CreatedOn
		From ',@tableName, N'
		Where TicketID = ',@TicketId)

		print concat('@DynamicUpdateQuery: ',@DynamicUpdateQuery)
		EXEC sp_executesql @DynamicUpdateQuery;

		--insert into #tbl_tp_TicketHistoryBeforeEdit
		--Select TicketHistoryID, TicketID, TicketStatusID, ParentID, ActionDateTime, Remarks, Note, UserResponse, AssignedUser, AssignedGroup, TicketPriority, AssignedBy
		--From vw_tp_LastTicketHistory TH 
		--Where TH.ParentID=@ParentId and TH.TicketID=@TicketId

		SET @DynamicSQL=
		N'UPDATE ' + QUOTENAME(@tableName) + N' SET ';    
    
		IF isnull(@TicketType,0) > 0
		Begin
			set @strQuery=concat(N'Select @OldValue1=TicketTypeId From tbl_tp_TicketMaster_',@ParentId,N' Where TicketID=',@TicketId)
			Exec sp_executesql @strQuery,N'@OldValue1 nvarchar(max) output',@OldValue1=@OldValue output

			Exec usp_tp_AddActivity @TicketId, @ParentId, 'TicketTypeId', @OldValue, @TicketType, 'Ticket Type Update', @TpUserId, @ActivityDatetime,  @ActivityId out, null, null, null, null

			SET @DynamicSQL = @DynamicSQL + N'TicketTypeId = @TicketType, '; 

			If(len(@strNotes) > 0)
			Begin
				Set @strNotes += ' ,TicketType'
			End
			Else
			Begin
				Set @strNotes += ' TicketType'
			End
		End
    
		IF isnull(@TicketStatus,0) > 0
		BEGIN    
			Select @OldValue=TicketStatusID From #tbl_tp_TicketHistoryBeforeEdit
			Exec usp_tp_AddActivity @TicketId, @ParentId, 'TicketStatusID', @OldValue, @TicketStatus, 'Ticket status Update', @TpUserId, @ActivityDatetime,  @ActivityId out, null, null, null, null

			SET @DynamicSQL = @DynamicSQL + N'TicketStatusID = @TicketStatus,  ';    

			If(len(@strNotes) > 0)
			Begin
				Set @strNotes += ' ,TicketStatus'
			End
			Else
			Begin
				Set @strNotes += ' TicketStatus'
			End
		END    
    
		IF isnull(@TicketPriority,0) > 0
		BEGIN    
			Select @OldValue=TicketPriority From #tbl_tp_TicketHistoryBeforeEdit
			Exec usp_tp_AddActivity @TicketId, @ParentId, 'TicketPriority', @OldValue, @TicketPriority, 'Ticket Priority Update', @TpUserId, @ActivityDatetime,  @ActivityId out, null, null, null, null

			SET @DynamicSQL = @DynamicSQL + N'TicketPriority = @TicketPriority,  ';   

			If(len(@strNotes) > 0)
			Begin
				Set @strNotes += ' ,TicketPriority'
			End
			Else
			Begin
				Set @strNotes += ' TicketPriority'
			End
		END    
    
		IF isnull(@TicketGroups,0) > 0
		BEGIN    
			Select @OldValue=AssignedGroup From #tbl_tp_TicketHistoryBeforeEdit
			Exec usp_tp_AddActivity @TicketId, @ParentId, 'AssignedGroup', @OldValue, @TicketGroups, 'Ticket Group Update', @TpUserId, @ActivityDatetime,  @ActivityId out, null, null, null, null
SET @DynamicSQL = @DynamicSQL + N'AssignedGroup = @TicketGroups, ' + N'AssignedUser = @TicketAgent, ' + N'AssignedBy = ''' + CAST(@TpUserId AS NVARCHAR(MAX)) + ''', ' + N'AssignedDatetime = GETDATE(), ' + N'LastActionDatetime = GETDATE(), ';

			If(len(@strNotes) > 0)
			Begin
				Set @strNotes += ' ,TicketGroups'
			End
			Else
			Begin
				Set @strNotes += ' TicketGroups'
			End
		END    
    
		IF isnull(@TicketAgent,0) > 0
		BEGIN    
			Select @OldValue=AssignedUser From #tbl_tp_TicketHistoryBeforeEdit
			Exec usp_tp_AddActivity @TicketId, @ParentId, 'AssignedUser', @OldValue, @TicketAgent, 'Ticket User Update', @TpUserId, @ActivityDatetime,  @ActivityId out, null, null, null, null

			SET @DynamicSQL = @DynamicSQL + N'AssignedGroup = @TicketGroups, ' + N'AssignedUser = @TicketAgent, ' + N'AssignedBy = ''' + CAST(@TpUserId AS NVARCHAR(MAX)) + ''', ' + N'AssignedDatetime = GETDATE(), ' + N'LastActionDatetime = GETDATE(), ';


			If(len(@strNotes) > 0)
			Begin
				Set @strNotes += ' ,TicketAgent'
			End
			Else
			Begin
				Set @strNotes += ' TicketAgent'
			End
		END    
    
		IF len(@TicketProduct) > 0
		BEGIN    
			Select @OldValue=STRING_AGG(ProductID,',') From tbl_tp_TicketProducts(nolock)  WHERE TicketID = @TicketId and isactive=1
			Exec usp_tp_AddActivity @TicketId, @ParentId, 'ProductID', @OldValue, @TicketProduct, 'Ticket Product Update', @TpUserId, @ActivityDatetime,  @ActivityId out, null, null, null, null

			Delete From tbl_tp_TicketProducts WHERE TicketID = @TicketId;    

			insert into tbl_tp_TicketProducts(TicketID,ProductID,IsActive,CreatedBy,CreatedOn,ParentId)
			Select @TicketId,[value],1,@TpUserId,GETDATE(),@ParentId
			From string_split(@TicketProduct,',')

			If(len(@strNotes) > 0)
			Begin
				Set @strNotes += ' ,TicketProduct'
			End
			Else
			Begin
				Set @strNotes += ' TicketProduct'
			End
		END    
    
		IF len(@Notes) > 0
		BEGIN    
			Select @OldValue=Note From #tbl_tp_TicketHistoryBeforeEdit
			Exec usp_tp_AddActivity @TicketId, @ParentId, 'Note', @OldValue, @Notes, 'Ticket Note Update', @TpUserId, @ActivityDatetime,  @ActivityId out, null, null, null, null

			SET @DynamicSQL = @DynamicSQL + N'Note = @Notes, ';    

			If(len(@strNotes) > 0)
			Begin
				Set @strNotes += ' ,Note'
			End
			Else
			Begin
				Set @strNotes += ' Note'
			End
		END    
 
		SET @DynamicSQL = LEFT(@DynamicSQL, LEN(@DynamicSQL) - 1);    
    
		SET @DynamicSQL = @DynamicSQL + N' WHERE TicketID = @TicketId;';    
    
		PRINT @DynamicSQL;        
        
		EXEC sp_executesql
			@DynamicSQL,            
			N'@TicketId BIGINT, @TicketType INT, @TicketStatus bigint, @TicketPriority INT, @TicketGroups bigint, @TicketAgent bigint,  @Notes nvarchar(max)',            
			@TicketId, @TicketType, @TicketStatus, @TicketPriority, @TicketGroups, @TicketAgent, @Notes;   
		
		--INSERT INTO tbl_tp_TicketHistory(TicketID, TicketStatusID, ParentID, ActionDateTime, Remarks, Note, UserResponse, AssignedUser, AssignedGroup, TicketPriority, AssignedSource, AssignedBy, ActionContent)
		--SELECT @TicketId as TicketID,          
		--	IIf(isnull(@TicketStatus,0)>0, @TicketStatus, isnull((select TH.TicketStatusID From vw_tp_LastTicketHistory TH Where TH.ParentID=@ParentId and TH.TicketID=@TicketId),1)) AS TicketStatusID,            
		--	@ParentId AS ParentID,          
		--	GETDATE() AS ActionDateTime,          
		--	NULL AS Remarks,          
		--	IIF(len(@Notes)>0,@Notes,'Updated ' + @strNotes) AS Note,
		--	NULL AS UserResponse,          
		--	IIf(isnull(@TicketAgent,0)>0, @TicketAgent,isnull((select TH.AssignedUser From vw_tp_LastTicketHistory TH Where TH.ParentID=@ParentId and TH.TicketID=@TicketId),0)) AS AssignedUser,          
		--	IIf(isnull(@TicketGroups,0)>0, @TicketGroups,isnull((select TH.AssignedGroup From vw_tp_LastTicketHistory TH Where TH.ParentID=@ParentId and TH.TicketID=@TicketId),0)) AS AssignedGroup,
		--	IIf(isnull(@TicketPriority,0)>0, @TicketPriority,isnull((select TH.TicketPriority From vw_tp_LastTicketHistory TH Where TH.ParentID=@ParentId and TH.TicketID=@TicketId),1)) AS TicketPriority,
		--	'Manual' AS AssignedSource,
		--	@TpUserId AS AssignedBy,
		--	'Activity' as ActionContent

			Set @TicketHistoryID=Scope_Identity()
		
		If((select dbo.ufn_tp_GetParentTicketStatus(@TicketStatus)) in (3,5))
		Begin
			SET @DynamicSQL = '
			UPDATE ' + @tableName + '
			SET
			TicketStatusID = ' + cast(@TicketStatus as NVARCHAR(MAX)) + ',
		    --LastActionDatetime = GETDATE(),
			ClosedOn = GETDATE(),
			ClosedBy = ' + CAST(@TpUserId AS NVARCHAR(MAX)) + '
			WHERE TicketID IN (' + CAST(@TicketID AS NVARCHAR(MAX)) + ');'

			EXEC sp_executesql @DynamicSQL

			Set @strQuery=N'SELECT @TicketNo1 = TicketNo, @CreatedOn1 = ClosedOn, @EntitytID1=EntityID, @EntityName1=EntityName
			FROM ' + @tableName + '
			Where TicketId=@TicketID1'

			Exec sp_executesql @strQuery, N'@TicketNo1 varchar(50) output, @CreatedOn1 datetime output, @EntitytID1 bigint output, @EntityName1 varchar(500) output, @TicketID1 bigint', @TicketNo1=@TicketNo output, @CreatedOn1=@CreatedOn output, @EntitytID1=@EntityID output, @EntityName1=@EntityName output, @TicketID1=@TicketID

			If((select dbo.ufn_tp_GetParentTicketStatus(@TicketStatus)) in (3))
			Begin
				exec usp_tp_RaiseEmailNotification @TicketID,@ParentId,0,@TpUserId,@TpUserId,'Agent Closes the Ticket','Requester'

				SELECT @EventDesc = @UserCreated + ' has closed ticket ' + @TicketNo + ' On ' +
				CONVERT(NVARCHAR(255), GETDATE())
				print concat('@TicketStatus=3 @EventDesc: ',@EventDesc)

				SELECT @EventName =@EntityName+' Ticket Closed'
				exec UspSaveEntityActivity_withid @entityname = @EntityName, @EntityID = @EntityID, @UserID= @UserId, @ParentID = @ParentID, @EventDescription = @EventDesc, @EventName = @EventName, @reftables = 'tbl_tp_TicketHistory', @refid= @TicketHistoryID
			End

			If((select dbo.ufn_tp_GetParentTicketStatus(@TicketStatus)) in (5))
			Begin
				exec usp_tp_RaiseEmailNotification @TicketID,@ParentId,0,@TpUserId,@TpUserId,'Agent Solves the Ticket','Requester'

				SELECT @EventDesc = @UserCreated + ' has resolved ticket ' + @TicketNo + ' On ' +
				CONVERT(NVARCHAR(255), GETDATE())
				print concat('@TicketStatus=5 @EventDesc: ',@EventDesc)

				--SELECT @EventName =@EntityName+' ticket is resolved'
				SET @EventName = @EntityName + 's ticket is resolved';
				exec UspSaveEntityActivity_withid @entityname = @EntityName, @EntityID = @EntityID, @UserID= @UserId, @ParentID = @ParentID, @EventDescription = @EventDesc, @EventName = @EventName, @reftables = 'tbl_tp_TicketHistory', @refid= @TicketHistoryID
			End

			--EXEC Usp_tp_SaveEntityActivity_withid @entityname = @EntityName, @EntityID = @EntityID, @UserID = @UserId, @ParentID = @ParentId, @EventDescription = @EventDesc, @EventName = 'Leads ticket resolved', @reftables = @tableName, @refid = @TicketID, @refColName = 'TicketID',@Groupid = 0, @AgentId = @TpUserId ,@Type = 'Agent'
		End

		If((select dbo.ufn_tp_GetParentTicketStatus(@TicketStatus)) in (6))
		Begin
			Set @strQuery=N'SELECT @TicketNo1 = TicketNo, @CreatedOn1 = CreatedOn, @EntitytID1=EntityID, @EntityName1=EntityName
			FROM ' + @tableName + '
			Where TicketId=@TicketID1'

			Exec sp_executesql @strQuery, N'@TicketNo1 varchar(50) output, @CreatedOn1 datetime output, @EntitytID1 bigint output, @EntityName1 varchar(500) output, @TicketID1 bigint', @TicketNo1=@TicketNo output, @CreatedOn1=@CreatedOn output, @EntitytID1=@EntityID output, @EntityName1=@EntityName output, @TicketID1=@TicketID

			SELECT @EventDesc = @UserCreated + ' has updated ticket ' + @TicketNo + ' with status as Waiting on Customer on ' + CONVERT(NVARCHAR(255), GETDATE())

			print concat('@TicketStatus=6 @EventDesc: ',@EventDesc)
			SELECT @EventName ='Ticket Waiting on Customer for ' +@EntityName
			exec UspSaveEntityActivity_withid @entityname = @EntityName, @EntityID = @EntityID, @UserID= @UserId, @ParentID = @ParentID, @EventDescription = @EventDesc, @EventName = @EventName, @reftables = 'tbl_tp_TicketHistory', @refid= @TicketHistoryID

			--EXEC Usp_tp_SaveEntityActivity_withid @entityname = @EntityName, @EntityID = @EntityID, @UserID = @UserId, @ParentID = @ParentId, @EventDescription = @EventDesc, @EventName = 'Ticket Waiting on Customer', @reftables = @tableName, @refid = @TicketID, @refColName = 'TicketID',@Groupid = 0, @AgentId = @TpUserId ,@Type = 'Agent'
		End

	End
	Else
	Begin
		print 'Please select atleast one criteria'
	End
END; 







GO

/* ============================================================
   Procedure: [dbo].[usp_tp_ValidateUser]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 -- Exec usp_tp_ValidateUser @Username='shubhamkhuswaha',@Password='@123shubhaM'
CREATE   PROCEDURE [dbo].[usp_tp_ValidateUser]    
(            
    @Username varchar(20),        
    @Password varchar(20)        
)              
As            
Begin          
    IF EXISTS (SELECT TOP 1 1 FROM tbl_tp_UserLogin WHERE LoginName = @Username)         
    BEGIN        
        IF EXISTS (SELECT TOP 1 1 FROM tbl_tp_UserLogin WHERE LoginName = @Username AND Pwd = @Password)        
        BEGIN  
            IF EXISTS (SELECT TOP 1 1 FROM tbl_tp_UserLogin WHERE LoginName = @Username AND Pwd = @Password AND IsActive = 1)      
            BEGIN      
                SELECT    
                    [TpUser_Id],
					isnull(GroupId,0) as [GroupId],  
                    isnull(User_Id,0) as [User_Id],        
                    LoginName,        
                    [Name],
					Email,
                    IsActive [Status],        
                    ParentId,        
                    1 as IsLoginSuccess,        
                    'User Login Successfull' [Message],      
                    dbo.fn_ConvertDateTime(getdate(), 'India Standard Time', 0) TimeZoneDateTime      
                FROM tbl_tp_UserLogin(NOLOCK)    
                WHERE LoginName = @Username AND Pwd = @Password AND IsActive = 1       
            END      
            ELSE      
            BEGIN  
                SELECT             
                    [TpUser_Id],
					[GroupId]
                    [User_Id],        
                    LoginName,        
                    [Name],   
					Email,
                    IsActive [Status],        
                    ParentId,        
                    0 as IsLoginSuccess,        
                    'User is not active' [Message]  ,  
     dbo.fn_ConvertDateTime(getdate(), 'India Standard Time', 0) TimeZoneDateTime    
                FROM tbl_tp_UserLogin(NOLOCK)   
                WHERE LoginName = @Username AND Pwd = @Password AND IsActive = 0       
            END  
        END  
        ELSE  
        BEGIN        
            SELECT             
                [TpUser_Id],
				[GroupId]
                [User_Id],        
                LoginName,        
                [Name],  
				Email,
                IsActive [Status],        
                ParentId,        
                0 as IsLoginSuccess,        
                'Invalid Credentials' [Message],   
    dbo.fn_ConvertDateTime(getdate(), 'India Standard Time', 0) TimeZoneDateTime    
            FROM tbl_tp_UserLogin(NOLOCK)   
            WHERE LoginName = @Username        
        END        
    END  
    ELSE  
    BEGIN  
        SELECT    
            0 as [TpUser_Id],
			 0 as [GroupId],
            0 [User_Id],        
            @Username LoginName,        
            @Username [Name],  
			0 [Email],
            0 [Status],        
            0 ParentId,        
            0 as IsLoginSuccess,        
            'User does not exist' [Message] ,  
   dbo.fn_ConvertDateTime(getdate(), 'India Standard Time', 0) TimeZoneDateTime    
    END  
End 




GO

