/* ============================================================
   Procedure: [dbo].[Usp_tp_WhatsappInsertSetting]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_tp_WhatsappInsertSetting]  
    @WhatsAppSetting_Id BIGINT,  
    @TpUserId BIGINT,  
    @Subject NVARCHAR(255),  
    @Description NVARCHAR(MAX),  
    @DidNumbers NVARCHAR(MAX),
    @Company NVARCHAR(255),
    @DisplayName NVARCHAR(255),
    @Option NVARCHAR(20),    
    @MetaData NVARCHAR(MAX)  
AS  
BEGIN  
    DECLARE @TimeZone NVARCHAR(400), @rowJson NVARCHAR(MAX), @IPAdress NVARCHAR(50), @DeviceId NVARCHAR(50), @IsImpersonation BIT, @ImpersonatorId INT, @UserId BIGINT, @ParentId BIGINT, @WhatsappSettingId BIGINT;
  
    SET @IPAdress = (SELECT JSON_VALUE(@MetaData, '$.IPAddress') AS IPAddress);
    SET @DeviceId = (SELECT JSON_VALUE(@MetaData, '$.MacAddress') AS MacAddress);
    SET @IsImpersonation = (SELECT JSON_VALUE(@MetaData, '$.IsImpersonation') AS IsImpersonation);
    SET @ImpersonatorId = (SELECT JSON_VALUE(@MetaData, '$.ImpersonatorId') AS ImpersonatorId);
	
    SELECT @TimeZone = Timezone, @UserId = User_Id, @ParentId = ParentId
    FROM tbl_tp_UserLogin
    WHERE TpUser_Id = @TpUserId AND IsActive = 1;

IF @Option = 'Insert'
BEGIN

    INSERT INTO tbl_tp_WhatsAppSetting ( 
        Subject, 
        Description, 
        Company, 
        DisplayName,
        ParentId, 
        CreatedOn, 
        CreatedBy, 
        IsActive
    )  
    VALUES (
        @Subject, 
        @Description, 
        @Company, 
        @DisplayName, 
        @ParentId, 
        GETDATE(), 
        @UserId, 
        1
    );

    SET @WhatsappSettingId = SCOPE_IDENTITY();

    DECLARE @DidNumbersTable TABLE (PhoneNumber NVARCHAR(MAX));

    IF CHARINDEX(',', @DidNumbers) = 0
    BEGIN
        INSERT INTO @DidNumbersTable (PhoneNumber)
        VALUES (@DidNumbers);
    END
    ELSE
    BEGIN
        INSERT INTO @DidNumbersTable (PhoneNumber)
        SELECT value
        FROM STRING_SPLIT(@DidNumbers, ', ');
    END
    INSERT INTO tbl_tp_DidNumbers (PhoneNumber, SettingId, NumberType)
    SELECT  PhoneNumber, @WhatsappSettingId, 'WhatsApp'
    FROM @DidNumbersTable;

    SET @rowJson = (SELECT * FROM tbl_tp_WhatsAppSetting WHERE WhatsAppSetting_Id = @WhatsappSettingId FOR JSON AUTO, INCLUDE_NULL_VALUES);
    IF @rowJson IS NOT NULL
    BEGIN
        EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData 
            @User_id = @UserId,  
            @Activity_type = 'Inst_WhatsAppSetting',  
            @ActionType = 'I',  
            @RowJson = @rowJson,  
            @Table_name = 'tbl_tp_WhatsAppSetting', 
            @ip_adress = @IPAdress, 
            @device_id = @DeviceId, 
            @IsImpersonation = @IsImpersonation, 
            @ImpersonatorId = @ImpersonatorId;
    END;

    SELECT 'Record Inserted Successfully' AS Message;
END

    ELSE IF @Option = 'Update'
    BEGIN
        UPDATE tbl_tp_WhatsAppSetting  
        SET  
            Subject = @Subject,  
            Description = @Description,  
            Company = @Company,  
            DisplayName = @DisplayName,
            ParentId = @ParentId,
            ModifiedBy = @UserId,  
            ModifiedOn = GETDATE()     
        WHERE WhatsAppSetting_Id = @WhatsAppSetting_Id;  

        SET @rowJson = (SELECT * FROM tbl_tp_WhatsAppSetting WHERE WhatsAppSetting_Id = @WhatsAppSetting_Id FOR JSON AUTO, INCLUDE_NULL_VALUES);
        IF @rowJson IS NOT NULL
        BEGIN
            EXEC MySMSAudit.dbo.Usp_Audit_InsertAuditData 
                @User_id = @UserId,  
                @Activity_type = 'Updt_WhatsAppSetting',  
                @ActionType = 'U',  
                @RowJson = @rowJson,  
                @Table_name = 'tbl_tp_WhatsAppSetting', 
                @ip_adress = @IPAdress, 
                @device_id = @DeviceId, 
                @IsImpersonation = @IsImpersonation, 
                @ImpersonatorId = @ImpersonatorId;
        END;
        SELECT 'Record Updated Successfully' AS Message;
    END
END;



GO

