   Procedure: [dbo].[usp_trackauth_link]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC [dbo].[usp_trackauth_link]      
(      
@Parentid bigint,     
@tbl  SMSUrl_Link_auth readonly,    
@opt int      
)      
as       
begin      
if @opt=0      
begin      
 insert into User_smsLink_Track (Parentid,isactive) 
 select Parentid,1 from @tbl   
if exists(select 1 from TrackLinkRequest where Parentid =@Parentid)
begin
update TrackLinkRequest set DemoapprovalStatus=0,DemoapprovalDate=GETDATE(),DemoExpiry=DATEADD(dd,15,getdate())
where Parentid =@Parentid
end 
select 'saved'      
end      
else      
update User_smsLink_Track set isactive=0,LastDeactivatedOn=getdate() where Parentid =@Parentid       
end  







