/* ============================================================
   Procedure: [dbo].[usp_trackemailcount]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_trackemailcount]  
(@tname nvarchar(200),@tbl mail_emailsreport readonly)     
AS   
BEGIN  
begin try  
SET NOCOUNT ON;  
drop table if exists #inserted  
select * into #inserted from @tbl  
select mail_batchid batchid,@tname tablename,count(1) mailcount into #tec_mer2 from #inserted group by Mail_BatchID  
  
insert into mysms.dbo.emailcountracking(batchid,tablename,mailcount)  
select batchid,tablename,mailcount from #tec_mer2  
  
drop table if exists #tec_mer2  
drop table if exists #inserted  
end try  
begin catch  
exec mysms.dbo.usp_InsertErrorInfo  
end catch  
END  


GO

/* ============================================================
   Procedure: [dbo].[usp_trackemailcount_sent]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_trackemailcount_sent]        
(@tname nvarchar(200),@tbl emailssent_new readonly)           
AS         
BEGIN        
begin try        
SET NOCOUNT ON;        
drop table if exists #inserted        
select * into #inserted from @tbl        
select mail_batchid batchid,@tname tablename,count(1) mailcount into #tec_mer2 from #inserted group by Mail_BatchID        
        
insert into mysms.dbo.emailcountracking(batchid,tablename,mailcount)        
select batchid,tablename,mailcount from #tec_mer2        
  
  
create table #failedmails(user_login nvarchar(100),from_mailid nvarchar(200),batchid bigint, sentdate datetime,mailsubject nvarchar(200),mail_error    
nvarchar(500))    
if exists (select 1 from #inserted i where smtpserver='Karix' and mail_error <> 'Sent'    
and not exists (select 1 from emailsreportsent(nolock) where mail_batchid=i.Mail_BatchID and mail_delivereddate<i.mail_delivereddate  
and mail_error =i.mail_error))    
begin    
insert into #failedmails(user_login,from_mailid,batchid,sentdate,mailsubject,mail_error)    
select distinct user_login,Mail_FromEmail,mail_batchid,mail_inserteddate,mail_subject,Mail_Error    
from #inserted i join mysms.dbo.User_Detail(nolock) u on mysms.dbo.ufn_getuserparentid(i.mail_userid)=u.user_id    
where mail_error<>'sent' and smtpserver='karix'    
     
DECLARE @xml NVARCHAR(MAX)DECLARE @body NVARCHAR(MAX)            
    
SET @xml =CAST(( SELECT [User_Login] AS 'td','',from_mailid AS 'td','',             
batchid  AS 'td','',sentdate as 'td','',mailsubject as 'td','',mail_error    
from #failedmails FOR XML PATH('tr'), ELEMENTS ) AS NVARCHAR(MAX))            
SET @body ='<html><H1>Failed mails from Karix as on '+cast (getdate() as nvarchar)+    
'</H1><body><table border = 2><tr><th>User Login</th><th>From Email</th><th>Mail Batchid</th><th>Mail Date</th>    
<th>Mail subject</th><th>Mail Error</th></tr>'             
    
SET @body = @body + @xml +'</table></body></html>'            
EXEC usp_enqueueemail            
@profile_name='Alerts',             
@recipients='csshukla@pelsoftlabs.in;tanweer.alam@pelsoftlabs.in;vaishali.kalra@pelsoftlabs.in',            
@blind_copy_recipients='karuna@pelsoftlabs.in',            
@subject='Failed mails from Karix',            
@body = @body,            
@body_format ='HTML',            
@from_address='FailedMails, Karix <noreply@kit19.com>';      
    
end    
drop table if exists #failedmails    
drop table if exists #tec_mer2        
drop table if exists #inserted        
end try        
begin catch        
exec mysms.dbo.usp_InsertErrorInfo        
end catch        
END 



