/* ============================================================
   Procedure: [dbo].[USP_TRANS_DLR]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROC USP_TRANS_DLR
@U_ID INT,                   
@SENDER_ID NVARCHAR(100),                   
@FDATE NVARCHAR(20),                    
@TDATE NVARCHAR(20)   
as
SELECT DU.MESSAGEINSERTDATE,DU.MOBILE,ISNULL((CASE DU.MESSAGESTATUS WHEN '' THEN 'DELIVRD ERR:0'                  
 WHEN '6' THEN 'INVALID' WHEN 'NULL' THEN 'DELIVRD ERR:0'  WHEN '5' THEN 'BLACKLISTED' WHEN '9' THEN 'INVALID'                   
 ELSE MESSAGESTATUS END),'DELIVRD ERR:0')AS MESSAGESTATUS,DU.SENDERID,DU.MESSAGE FROM [MYSMSREPORT].[DBO].[SixDaysHistory]DU                   
 (NOLOCK)WHERE DU.U_ID=@U_ID AND (CONVERT(NVARCHAR,CONVERT(DATETIME,MESSAGEINSERTDATE,104),112) BETWEEN                 
CONVERT(NVARCHAR,CONVERT(DATETIME,@FDATE,104),112) AND CONVERT(NVARCHAR,CONVERT(DATETIME,@TDATE,104),112))


GO

