SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_Transfer_Acres99Entries_toEnquiries_Process]                       
@Accres99_id bigint=null                               
AS                                
BEGIN  
           
    if object_id('tempdb..#TempEnq') is not null begin drop table #TempEnq end                         
--declare @indiamartid bigint=null 
 declare @isleadcreated int=0,@leadid bigint,@LIHID bigint = 0           
declare @i bigint=(select case when @Accres99_id IS null then max(ID) else @Accres99_id end from Acres99_Leads(nolock) where isprocessed=1)                             
RETRY:      
begin try      
begin tran      
SELECT ROW_NUMBER() over (order by uere.ID) rno,                            
uere.ID,                       
isnull(nullif(ltrim(rtrim(uere.NAME)),'null'),'') PersonName,                                
  
RIGHT(uere.Phone,(len(uere.Phone)-charindex('-',uere.Phone,1))) MobileNo,  
  
--case                 
--when charindex('-',uere.Phone,1)> 0 and isnumeric(RIGHT(uere.Phone,(len(uere.Phone)-charindex('-',uere.Phone,1))))=1                 
--then RIGHT(uere.Phone,(len(uere.Phone)-charindex('-',uere.Phone,1)))   
                
--when isnumeric(REPLACE(MOB,ltrim(rtrim(m.CountryCode)),''))=1 and cast(REPLACE(MOB,ltrim(rtrim(m.CountryCode)),'') AS bigint)>0                
--then REPLACE(MOB,ltrim(rtrim(m.CountryCode)),'') end MobileNo,                
  
left(uere.Phone,charindex('-',uere.Phone,1)-1) CountryCode,  
  
--case                 
--when charindex('-',mob,1)> 0 and isnumeric(RIGHT(mob,(len(mob)-charindex('-',mob,1))))=1                 
--then left(mob,charindex('-',mob,1)-1)                 
--when isnumeric(REPLACE(MOB,ltrim(rtrim(m.CountryCode)),''))=1 and cast(REPLACE(MOB,ltrim(rtrim(m.CountryCode)),'') as bigint)>0                
--then  ltrim(rtrim(m.CountryCode)) end CountryCode,                
  
ISNULL(nullif(ltrim(rtrim(uere.Email)),'null'),'') as EmailID,                
  
--case                 
--when charindex('-',mobile_alt,1)> 0 and isnumeric(RIGHT(mobile_alt,(len(mobile_alt)-charindex('-',mobile_alt,1))))=1                 
--then RIGHT(mobile_alt,(len(mobile_alt)-charindex('-',mobile_alt,1)))                 
--when isnumeric(REPLACE(mobile_alt,ltrim(rtrim(m.CountryCode)),''))=1 and cast(REPLACE(MOBILE_ALT,ltrim(rtrim(m.CountryCode)),'') as bigint)>0                
--then REPLACE(mobile_alt,ltrim(rtrim(m.CountryCode)),'') end MobileNo1,                
--case                 
--when charindex('-',mobile_alt,1)> 0 and isnumeric(RIGHT(mobile_alt,(len(mobile_alt)-charindex('-',mobile_alt,1))))=1                 
--then left(mobile_alt,charindex('-',mobile_alt,1)-1)                 
--when isnumeric(REPLACE(mobile_alt,ltrim(rtrim(m.CountryCode)),''))=1 and cast(REPLACE(MOBILE_ALT,ltrim(rtrim(m.CountryCode)),'') as bigint)>0                
--then ltrim(rtrim(m.CountryCode)) end CountryCode1,                
--ISNULL(nullif(ltrim(rtrim(uere.EMAIL_ALT)),'null'),'') as EmailID1,                
  
  
case when isnull(nullif(ltrim(rtrim(uere.ProjName)),'null'),'')<>'' then uere.ProjName else null end as CompanyName,                
case when ISNULL(nullif(ltrim(rtrim(uere.Address)),'null'),'')<>'' and isnull(nullif(ltrim(rtrim(uere.ProjName)),'null'),'')<>'' then Address end OfficeAddress,  
  
                
 case when ISNULL(nullif(ltrim(rtrim(uere.Address)),'null'),'')<>'' and isnull(nullif(ltrim(rtrim(uere.ProjName)),'null'),'')='' then uere.Address end ResidentialAddress,   
              
-- case when nullif(ltrim(rtrim(ENQ_CITY)),'null') is not null then  substring(uere.ENQ_CITY,1,100) end City,                 
-- case when nullif(ltrim(rtrim(enq_state)),'null') is not null then substring(uere.ENQ_State,1,100) end State,                
-- m.Country_name,  
                
'Query 99Acres Details: '          
+', For Product: '+cast(ProdId as nvarchar)                
+', Product type: '+cast(ProductType as nvarchar)    
+', Product status: '+cast(ProductStatus as nvarchar)    
  
+', PROPERTY_CODE: '+cast(PROPERTY_CODE as nvarchar)    
+', Acres_IDENTITY: '+cast(Acres_IDENTITY as nvarchar)    
+', ProjID: '+cast(ProjID as nvarchar)  
+', ProjName: '+cast(ProjName as nvarchar)  
  
+', PhoneVerificationStatus: '+cast(PhoneVerificationStatus as nvarchar)    
+', EmailVerificationStatus: '+cast(EmailVerificationStatus as nvarchar)   
  
  
+', Message: '+cast(QryInfo  as nvarchar)                 
+', Subject: '+cast(SubUserName as nvarchar)    
              
+', Query id: '+cast(QueryID as nvarchar)                
+', Res Type: '+cast(ResType as nvarchar)                
  
+', Name: '+ cast (isnull(nullif(ltrim(rtrim(uere.NAME)),'null'),'') as nvarchar)                 
+', Mobile: '+isnull(cast(Phone as nvarchar),'None')                
  
--+', Alternate Mobile: '+isnull(cast(mobile_alt as nvarchar),'None')                
--+', Phone: '+isnull(cast(PHONE as nvarchar),'None')                
--+', Alternate Phone: '+isnull(cast(PHONE_ALT as nvarchar),'None')                
  
+', Email: '+isnull(cast(Email as nvarchar),'None')                
  
--+', Alternate Email: '+isnull(cast(email_alt as nvarchar),'None')                
  
+', Date: '+cast(RcvdOn as nvarchar)                
+', Company: '+cast(isnull(nullif(ltrim(rtrim(uere.ProjName)),'null'),'None') as nvarchar)                
  
 --+', City: '+ cast(isnull(ENQ_CITY,'Not Mentioned') as nvarchar)                
 --+', State: '+cast(isnull(enq_State,'Not Mentioned') as nvarchar)                
   
+', Address: '+cast(isnull(uere.Address,'Not Mentioned') as nvarchar)   
  
               
--+', Call Received By: '+cast(isnull(ENQ_RECEIVER_MOB,'Not Applicable') as nvarchar)                 
--+', Call Duration: '+cast(isnull(ENQ_CALL_DURATION,'Not Applicable') as nvarchar)                
  
+', 99Acress UserName: '+cast(uere.Acres_Username as nvarchar) as InitialRemarks,  
  
 j.Kit19ParentID,                                
 uere.RcvdOn  AS CreatedDate,                      
j.Kit19ParentId as parentid,                      
0  AS IsOpen INTO #TempEnq                                
FROM   Acres99_Leads (nolock)  AS uere                 
join   Acres99_Mapping(nolock) j on j.Acres_UserName=uere.Acres_UserName                         
  -- left join m_country1 m on ltrim(rtrim(m.Shortname))=ltrim(rtrim(uere.COUNTRY_ISO))                
 WHERE  uere.IsProcessed = 0  and uere.isvalid=1 and uere.id>@i                        
update Acres99_Leads set isprocessed=2 where id>@i          
commit      
end try      
BEGIN CATCH                                                                 
IF @@TRANCOUNT>0                                                            
ROLLBACK                                                       
EXECUTE USP_INSERTERRORINFO;                               
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number                    
BEGIN                                          
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms                                   
GOTO RETRY -- Go to Label RETRY                                          
END                                                                       
END CATCH                                      
      
                       
  --select * from #TempEnq                 
                  
  --drop table #TempEnq                
                  
--select replace(REPLACE(MOB,ltrim(rtrim(m.CountryCode)),''),'-',''),isnumeric(REPLACE(MOB,ltrim(rtrim(m.CountryCode)),'')),isnumeric(RIGHT(mob,(len(mob)-charindex('-',mob,1)))),case                 
