begin                          
 --------------------------                            
 declare @Crno bigint = 0;                            
 declare @maxno bigint = 0;                            
 select @maxno = MAX(rno), @Crno = MIN(rno) from #TempEnq                            
 declare @leadn1 as bigint  = 0                            
 declare @ParentID bigint = 0;                            
                              
  declare @MobileNo nvarchar(max)  =''                             
       -- declare @MobileNo1 nvarchar(max)  =''                               
       -- declare @MobileNo2 nvarchar(max)  =''                                
        declare @EmailID nvarchar(max)  =''                                
      --  declare @EmailID1 nvarchar(max)  =''                                
      --  declare @EmailID2 nvarchar(max)  =''                                
                                   
        declare @CountryCode  nvarchar(max)  =''                 
      --  declare @CountryCode1 nvarchar(max)  =''                              
      --  declare @CountryCode2 nvarchar(max)  =''                            
 create table #temp(leadno bigint,countrycode nchar(10),mobile varchar(100),email varchar(100))                            
 declare @EnquiryID bigint,@rawEnquiryID bigint,@source bigint ,@medium bigint                          
 declare @AutoLeadDistribution bit =0                            
while @Crno <= @maxno                            
begin                            
set @leadn1=0                        
                          
--select @ParentID = ParentID, @CountryCode= CountryCode, @MobileNo= MobileNo, @EmailID= EmailID,@CountryCode1= CountryCode1, @MobileNo1= MobileNo1, @EmailID1= EmailID1  FROM   #TempEnq  WHERE  rno = @Crno                      
                      
select @ParentID = ParentID,  @rawEnquiryID = ID,  @CountryCode= trim(CountryCode), @MobileNo= trim(MobileNo), @EmailID= trim(EmailID)  FROM   #TempEnq   
        WHERE  rno = @Crno                      
  
  
if not exists (select 1 from UserSourceSettings(nolock) where name='Paid clasifieds' and userid=@parentid)                      
begin                      
INSERT INTO UserSourceSettings                                  
       (                                  
         -- SourceID -- this column value is auto-generated                              
         NAME,                                  
         UserID,                                  
         IsEditable,                                  
         IsActive,                                  
         CreatedDate,                                  
         ModifiedDate,                                  
         ModifiedBy                                  
       )                                  
     VALUES                    
       (                                  
         'Paid clasifieds',                                  
         @ParentID,                                  
         0,                                  
         1,                                  
         GETDATE(),                                  
         GETDATE(),                                  
         335                                  
       )                       
set @source=SCOPE_IDENTITY()                      
                      
end                      
else  begin                      
select top 1 @source=sourceid from UserSourceSettings(nolock) where name='Paid clasifieds' and userid=@parentid                       
end                                
                            
if not exists (select 1 from UserMediumSettings(nolock) where name='99Acres' and userid=@parentid)                      
begin                      
INSERT INTO UserMediumSettings                              
