    -- or  (isnull(e.CountryCode1,'2') + ISNULL(e.MobileNo1,'2')=cast(t.countrycode as nvarchar)+cast(t.mobile as nvarchar) )          
    -- or (isnull(e.EmailID1,'3')=t.email)          
 )          
 and e.rno = @Crno          
                 
 ),0)                            
           
