  InitialRemarks,CreatedOn,CreatedBy)                                      
  select @leadn1,substring(PersonName,1,100),rtrim(ltrim(MobileNo)),rtrim(ltrim(EmailID)),rtrim(ltrim(CountryCode)),ResidentialAddress        
  ,OfficeAddress,CompanyName,                        
  (select top 1 value from fn_Split((select agents from CRMCampaignSettings where userid=@ParentID),'#') ORDER BY NEWID()),@source,@ParentID,@medium,InitialRemarks,GETDATE(),@ParentID                             
  from #TempEnq where rno = @Crno  OPTION (MAXDOP 1)                                 
  */                    
end                        
                      
update UserEnquiry  set LeadNo=case when @LeadN1<>0 then @leadn1 else null end, IsOpen= case when @isleadcreated=1 then 0 else 1 end where EnquiryID=@EnquiryID            
OPTION (MAXDOP 1)                           
insert into  tbl_MergeLeadsEnquiry(EnquiryNo ,LeadNo,IsOpen) 
values (@EnquiryID,@Leadn1,case when @isleadcreated=1 then 0 else 1 end)  
OPTION (MAXDOP 1)                                
