/* ============================================================
   Procedure: [dbo].[usp_Transfer_TradeIndiaEntries_to_Enquiries_Process]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_Transfer_TradeIndiaEntries_to_Enquiries_Process]  --0                             
@TradeIndia_id bigint=null                                       
AS                                        
BEGIN                                   
DROP TABLE if exists #TempEnq      
  
declare @isleadcreated int=0,@leadid bigint,@LIHID bigint = 0                              
declare @i bigint=(select case when @TradeIndia_id IS null then max(ID) else @TradeIndia_id end from TradeIndiaData where isprocessed=1)       
RETRY:  
begin try  
begin tran                                
SELECT ROW_NUMBER() over (order by uere.ID) rno,                                    
uere.ID,                               
isnull(nullif(ltrim(rtrim(uere.SENDER_NAME)),'null'),'') PersonName,                                        
case                         
              
when isnumeric(REPLACE(uere.sender_mobile,ltrim(rtrim(m.CountryCode)),''))=1 and cast(REPLACE(uere.sender_mobile,ltrim(rtrim(m.CountryCode)),'') AS bigint)>0                        
then REPLACE(uere.sender_mobile,ltrim(rtrim(m.CountryCode)),'') end MobileNo,                        
              
case                         
when isnumeric(REPLACE(uere.sender_mobile,ltrim(rtrim(m.CountryCode)),''))=1 and cast(REPLACE(uere.sender_mobile,ltrim(rtrim(m.CountryCode)),'') as bigint)>0                        
then  ltrim(rtrim(m.CountryCode)) end CountryCode,              
                        
ISNULL(nullif(ltrim(rtrim(uere.sender_email)),'null'),'') as EmailID,                        
case                         
when isnumeric(REPLACE(uere.sender_other_mobiles,ltrim(rtrim(m.CountryCode)),''))=1 and cast(REPLACE(uere.sender_other_mobiles,ltrim(rtrim(m.CountryCode)),'') as bigint)>0                    
then REPLACE(uere.sender_other_mobiles,ltrim(rtrim(m.CountryCode)),'') end MobileNo1,                        
              
case                         
when isnumeric(REPLACE(uere.sender_other_mobiles,ltrim(rtrim(m.CountryCode)),''))=1 and cast(REPLACE(uere.sender_other_mobiles,ltrim(rtrim(m.CountryCode)),'') as bigint)>0                        
then ltrim(rtrim(m.CountryCode)) end CountryCode1,              
                        
ISNULL(nullif(ltrim(rtrim(uere.sender_other_emails)),'null'),'') as EmailID1,              
                        
case when isnull(nullif(ltrim(rtrim(uere.sender_co)),'null'),'')<>'' then uere.sender_co else null end as CompanyName,                        
case when ISNULL(nullif(ltrim(rtrim(uere.address)),'null'),'')<>'' and isnull(nullif(ltrim(rtrim(uere.sender_co)),'null'),'')<>'' then uere.address end OfficeAddress,                        
case when ISNULL(nullif(ltrim(rtrim(uere.address)),'null'),'')<>'' and isnull(nullif(ltrim(rtrim(uere.sender_co)),'null'),'')='' then uere.address end ResidentialAddress,                        
case when nullif(ltrim(rtrim(uere.sender_city)),'null') is not null then  substring(uere.sender_city,1,200) end City,                         
case when nullif(ltrim(rtrim(uere.sender_state)),'null') is not null then substring(uere.sender_state,1,200) end State,                        
m.Country_name,              
isnull(uere.source,'') as Source              
,              
                        
'Query Details: '                  
-- +', For Product: '+cast(uere.product_name as nvarchar)                        
--+', Product Source: '+cast(uere.product_source as nvarchar)               
--+', Quantity: '+cast(uere.quantity as nvarchar)              
--+', Supply_Location: '+cast(uere.pref_supp_location as nvarchar)                        
+'  Message: '+cast(uere.message  as nvarchar)                         
+', Subject: '+cast(uere.subject as nvarchar)                        
+', Query id: '+cast(uere.rfi_id as nvarchar)                        
+', Query Type: '+cast(uere.inquiry_type as nvarchar)                        
+', Name: '+ cast (isnull(nullif(ltrim(rtrim(uere.SENDER_NAME)),'null'),'') as nvarchar)                         
+', Mobile: '+isnull(cast(uere.sender_mobile as nvarchar),'None')                        
+', Alternate Mobile: '+isnull(cast(uere.sender_other_mobiles as nvarchar),'None')                        
+', Fax_Number: '+isnull(cast(uere.fax_number as nvarchar),'None')                        
+', Email: '+isnull(cast(uere.sender_email as nvarchar),'None')                     
+', Alternate Email: '+isnull(cast(uere.sender_other_mobiles as nvarchar),'None')                  
+', Generated Date: '+cast(uere.generated_date as nvarchar) + ' '+cast(uere.generated_time as nvarchar)                         
+', Company: '+cast(isnull(nullif(ltrim(rtrim(uere.sender_co)),'null'),'None') as nvarchar)                        
+', City: '+ cast(isnull(uere.sender_city,'Not Mentioned') as nvarchar)                        
+', State: '+cast(isnull(uere.sender_state,'Not Mentioned') as nvarchar)                        
+', Address: '+cast(isnull(uere.address,'Not Mentioned') as nvarchar)                        
+', Call Receiver Mobile: '+cast(isnull(uere.receiver_mobile,'Not Mentioned') as nvarchar)              
+', Call Received By: '+cast(isnull(uere.receiver_name,'Not Mentioned') as nvarchar)                         
+', Receiver Company: '+cast(isnull(uere.receiver_co,'Not Mentioned') as nvarchar)                        
+', TradeIndia Key: '+cast(uere.TradeIndiaKey as nvarchar)              
+', TradeIndia UserID: '+cast(uere.Trade_UserID as nvarchar)              
+', TradeIndia ProfileID: '+cast(uere.Trade_ProfileID as nvarchar)              
as InitialRemarks,j.Kit19ParentID,                                        
uere.DateReceived AS CreatedDate,                              
j.Kit19ParentId as parentid,                              
0  AS IsOpen,0 as Procsd INTO #TempEnq                                        
FROM   TradeIndiaData  AS uere  (nolock)                       
join   TradeIndia_Mapping j(nolock) on j.TradeIndia_Key = uere.TradeIndiaKey                                 
left join m_country1 m on ltrim(rtrim(m.Country_Name))=ltrim(rtrim(uere.sender_country))                        
WHERE  uere.IsProcessed = 0  and uere.isvalid=1 and uere.id>@i                                
                  
update t set isprocessed=2 from TradeIndiaData t join #TempEnq e on t.id=e.ID
commit  
end try  
BEGIN CATCH                                                             
IF @@TRANCOUNT>0                                                        
ROLLBACK                                                   
EXECUTE USP_INSERTERRORINFO;                           
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number                
BEGIN                                      
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms                               
GOTO RETRY -- Go to Label RETRY                                      
END                                                                   
END CATCH                                  
                                
if exists(select top 1 'x' from #TempEnq)                              
begin                                  
 --------------------------                                    
 declare @Crno bigint = 0;                                    
 declare @maxno bigint = 0;                                    
 select @maxno = MAX(rno), @Crno = MIN(rno) from #TempEnq                                    
 declare @leadn1 as bigint  = 0                                    
 declare @ParentID bigint = 0;                                    
                                      
  declare @MobileNo nvarchar(max)  =''                                     
        declare @MobileNo1 nvarchar(max)  =''                                       
        declare @MobileNo2 nvarchar(max)  =''                                        
        declare @EmailID nvarchar(max)  =''                                        
        declare @EmailID1 nvarchar(max)  =''                                        
        declare @EmailID2 nvarchar(max)  =''                                        
                                           
        declare @CountryCode  nvarchar(max)  =''       
        declare @CountryCode1 nvarchar(max)  =''                                      
        declare @CountryCode2 nvarchar(max)  =''                                    
 create table #temp(leadno bigint,countrycode nchar(10),mobile varchar(100),email varchar(100))                                    
 declare @EnquiryID bigint,@rawEnquiryID bigint,@source bigint ,@medium bigint              
 declare @SourceName nvarchar(200)                                  
 declare @AutoLeadDistribution bit =0                                    
while @Crno <= @maxno                                    
begin                                    
set @leadn1=0                                
                                  
select @ParentID = ParentID, @CountryCode= trim(CountryCode), @MobileNo= trim(MobileNo), @EmailID= trim(EmailID),@CountryCode1= trim(CountryCode1), @MobileNo1= trim(MobileNo1), @EmailID1= trim(EmailID1),@SourceName=Source  FROM   #TempEnq  WHERE  rno = @Crno                              
                       
select @rawEnquiryID= ID FROM   #TempEnq where rno = @Crno OPTION (MAXDOP 1)                
                
if not exists (select 1 from UserSourceSettings where name= 'Paid clasifieds' and userid=@parentid)                              
begin                              
INSERT INTO UserSourceSettings                             
       (                                          
         -- SourceID -- this column value is auto-generated                                 
        NAME,                                          
         UserID,                                          
         IsEditable,                                          
         IsActive,                                          
         CreatedDate,                                          
         ModifiedDate,                     
         ModifiedBy                                          
       )                                          
     VALUES                            
       (                                          
         'Paid clasifieds',                                          
         @ParentID,                                          
         0,                                          
         1,                                          
         GETDATE(),                                          
         GETDATE(),                                          
         335                                          
       )                               
set @source=SCOPE_IDENTITY()                              
                              
end                              
else  begin                              
select top 1 @source=sourceid from UserSourceSettings where name='Paid clasifieds' and userid=@parentid                               
end                                        
                                    
if not exists (select 1 from UserMediumSettings where name='TradeIndia' and userid=@parentid)                              
begin                              
INSERT INTO UserMediumSettings                                      
       (                                  
         -- MediumID -- this column value is auto-generated                                      
         NAME,                                      
         UserID,                                      
         IsEditable,                                      
         IsActive,                                      
         CreatedDate,                                      
         ModifiedDate,                 ModifiedBy                                      
       )                                      
     VALUES                                      
       (                                      
         'TradeIndia',                                      
         @ParentID,                                      
         0,                                      
         1,                                      
         GETDATE(),                                      
         GETDATE(),                                  
         335                                      
       )                                 
set @medium=SCOPE_IDENTITY()                              
                              
end                              
else  begin                              
select top 1 @medium=mediumid from UsermediumSettings where name='TradeIndia' and userid=@parentid                               
end                               
                                    
                                     
                   
if not exists(select 1 from ParsedEnquiries where RawEnquiryId=@rawenquiryid and enquirysource='TradeIndia API')  begin                                  
 INSERT INTO UserEnquiry                                        
   (                                        
     PersonName,                                        
     MobileNo,                                        
     EmailID,                                        
     CountryCode,                         
     MobileNo1,                                        
    EmailID1,                                        
     CountryCode1,                        
     CompanyName,                         
     OfficeAddress,                        
     ResidentialAddress,                        
     City,                        
     State,                        
     Country,                            
     SourceName,                                        
     InitialRemarks,                                        
     ParentID,                                        
     CreatedDate,                                        
     CreatedBy,                                        
     IsOpen,                                    
     LeadNo,                            
     MediumName,                            
     Campaignname,  
  enquirysource                                       
   )                                        
 SELECT PersonName,                                        
        MobileNo,                                        
        EmailID,                                        
        trim(CountryCode),                                        
        trim(MobileNo1),                                        
     trim(EmailID1),                                        
     trim(CountryCode1),                        
     CompanyName,                         
     OfficeAddress,                        
     ResidentialAddress,                        
     City,                        
     State,                        
     Country_name,                                            
      @source,                                        
        InitialRemarks,                                        
        ParentID,                                        
        CreatedDate,                                        
        parentid,                                        
        IsOpen,                                    
        @leadn1,                            
        @medium,                            
        0,  
  (select id from enquirysources where sourcename='TradeIndia API')                                        
 FROM   #TempEnq where rno = @Crno                                       
  set @EnquiryID=SCOPE_IDENTITY()                                
  --select @rawEnquiryID= ID FROM   #TempEnq where rno = @Crno OPTION (MAXDOP 1)                   
                      
  update TradeIndiaData set isprocessed = 1,EnquiryId=@EnquiryID,Processederror='Success',Processeddate=getdate() where ID=@rawEnquiryID  OPTION (MAXDOP 1)                  
                                  
  insert into parsedenquiries(rawenquiryid,enquiryid,parentid,EnquirySource)                                
  select @rawenquiryid,@enquiryid,@parentid,'TradeIndia API'                  
                                          
seT @AutoLeadDistribution = isnull((select isnull(AutoLeadDistribution,0) FROM   CRMCampaignSettings  WHERE  UserID = @ParentID),0)                                    
  
begin try  
begin tran  
insert into #temp(leadno,countrycode,mobile,email)   
select leadno,countrycode,mobile,email from Userleads_Mobile_Email(nolock) where parentid=@ParentID
/*
select leadno,isnull(nullif(CountryCode,''),'0'),isnull(nullif(mobileno,''),'0'),'1' from UserLeads where ParentID=@ParentID and MobileNo<>''                                    
union                                    
select leadno,isnull(nullif(CountryCode1,''),'0'),isnull(nullif(mobileno1,''),'0'),'1' from UserLeads where ParentID=@ParentID and MobileNo1<>''                                    
union                                    
select leadno,isnull(nullif(CountryCode2,''),'0'),isnull(nullif(mobileno2,''),'0'),'1' from UserLeads where ParentID=@ParentID and MobileNo2<>''                                    
union                                    
select leadno,'0','0',isnull(nullif(emailid,''),'1') from UserLeads where ParentID=@ParentID   and emailid<>''                                  
union                                    
select leadno,'0','0',isnull(nullif(emailid1,''),'1') from UserLeads where ParentID=@ParentID  and emailid1<>''                                                   
union                                    
select leadno,'0','0',isnull(nullif(emailid2,''),'1') from UserLeads where ParentID=@ParentID  and emailid2<>''                                       
*/
set @leadn1 =       
isnull(      
(select top 1 t.leadno from #temp t join #TempEnq e       
on (     
 (isnull(dbo.fn_ltrimrtrim(e.CountryCode),'2') + ISNULL(dbo.fn_ltrimrtrim(e.MobileNo),'2')=cast(dbo.fn_ltrimrtrim(t.countrycode) as nvarchar)+cast(dbo.fn_ltrimrtrim(t.mobile) as nvarchar) )                       
     or (isnull(nullif(dbo.fn_ltrimrtrim(e.EmailID),''),'3')=dbo.fn_ltrimrtrim(t.email))   
  or  
   (isnull(dbo.fn_ltrimrtrim(e.CountryCode1),'2') + ISNULL(dbo.fn_ltrimrtrim(e.MobileNo1),'2')=cast(dbo.fn_ltrimrtrim(t.countrycode) as nvarchar)+cast(dbo.fn_ltrimrtrim(t.mobile) as nvarchar) )                       
     or (isnull(nullif(dbo.fn_ltrimrtrim(e.EmailID1),''),'3')=dbo.fn_ltrimrtrim(t.email))    
)  and e.rno = @Crno      
),0)          
                                    
if (@AutoLeadDistribution = 1 and @leadn1=0)                                          
  begin                               
  set @Leadn1 = isnull((select MAX(LeadNo)                                                             
  FROM   UserLeads WHERE  ParentID = @ParentID),0)+1                                          
    
   SET Context_Info 0x55555
    
  Insert into userleads (LeadNo,PersonName,MobileNo,EmailID,City,PinCode,CountryCode,                    
  AssignedTo,SourceName,ParentID,mediumname,CampaignName,                    
  InitialRemarks,CreatedOn,CreatedBy,OfficeAddress,ResidentialAddress,enquirysource)                        
  select @leadn1,substring(PersonName,1,100),trim(MobileNo), trim(EmailID),City,PinCode,trim(CountryCode),                    
  (select top 1 value from fn_Split((select agents from CRMCampaignSettings where userid=@ParentID),'#')    ORDER BY NEWID               
()),SourceName,ParentID,mediumname,CampaignName,InitialRemarks,GETDATE(),CreatedBy,OfficeAddress,ResidentialAddress,enquirysource               
from userenquiry(nolock) where enquiryid=@EnquiryID  
  
  select @leadid=scope_identity()
  Exec MySMS.dbo.usp_ExecLeadTriggerTasks @leadid

    set @isleadcreated=1

   insert into LeadInteractionHistory(LeadNo,FollowUpStatus,NextStatusDate,Remarks,Products,AmountPaid,AssignedTo,    
  ParentID,CreatedOn,CreatedBy,FollowupDate,IsReassign)    
  select LeadNo,FollowUpStatus,NextStatusDate,Remarks,Products,AmountPaid,AssignedTo,    
  ParentID,CreatedOn,CreatedBy,FollowupDate,0 from userleads u (nolock) where ID = @leadid
  
  select @LIHID=SCOPE_IDENTITY()
  Exec MySMS.dbo.usp_ExecLeadInteractionTriggerTasks @LIHID     

    --exec Usp_insertdefaultfollowup @parentid,@leadid


    SET Context_Info 0x

  /*          
  Insert into userleads (LeadNo,PersonName,MobileNo,EmailID,MobileNo1,EmailID1,City,State,Country,CountryCode,CountryCode1,ResidentialAddress    
  ,OfficeAddress,CompanyName,                                          
  AssignedTo,SourceName,ParentID,MediumName,                                          
  InitialRemarks,CreatedOn,CreatedBy)                                              
  select @leadn1,substring(PersonName,1,100),MobileNo,EmailID,MobileNo1,EmailID1,City,State,Country_Name,CountryCode,CountryCode1,ResidentialAddress    
  ,OfficeAddress,CompanyName,                                
  (select top 1 value from fn_Split((select agents from CRMCampaignSettings where userid=@ParentID),'#') ORDER BY NEWID()),@source,@ParentID,@medium,InitialRemarks,GETDATE(),@ParentID                                     
  from #TempEnq where rno = @Crno  OPTION (MAXDOP 1)                                         
  */                            
end                                
commit  
end try  
begin catch  
exec usp_inserterrorinfo  
end catch  
                              
update UserEnquiry  set LeadNo=case when @LeadN1<>0 then @leadn1 else null end, 
IsOpen= case when @isleadcreated=1 then 0 else 1 end where EnquiryID=@EnquiryID                    
OPTION (MAXDOP 1)                                   
  
if not exists(select 1 from tbl_MergeLeadsEnquiry(nolock) where enquiryno=@enquiryid and LeadNo=@leadn1)  
begin   
insert into  tbl_MergeLeadsEnquiry(EnquiryNo ,LeadNo,IsOpen)   
values (@EnquiryID,@Leadn1,case when @isleadcreated=1 then 0 else 1 end)   OPTION (MAXDOP 1)                                        
end  
/*UPDATE indiamartleads                                        
SET    isprocessed = 1  ,EnquiryId=@EnquiryID,Processederror='Success',Processeddate=getdate()                                      
WHERE  ID =(SELECT ID FROM   #TempEnq  where rno = @Crno)                    
*/                
truncate table #temp                  
ENd                                    
update #TempEnq set Procsd=1 where @Crno = @Crno                              
set @Crno = @Crno+1       
end                                      
end  
update t set isprocessed=2 from TradeIndiaData t join #TempEnq e on t.id=e.ID where e.procsd=1                                      
DROP TABLE if exists #TempEnq                                        
--update TradeIndiaData set isprocessed=1 where id>@i OPTION (MAXDOP 1)                              
END  


