/* ============================================================
   Procedure: [dbo].[Usp_TransferAndUpdateIntocustomfieldEnquiryvalueByParentID]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 CREATE   PROCEDURE [dbo].[Usp_TransferAndUpdateIntocustomfieldEnquiryvalueByParentID]
 (
   @ParentID bigint
 )
 as
 Begin
       drop table if exists ##tempTBL   

   begin try   

 	  declare @Pivot_Column nvarchar(max) = ''
	  declare @Pivot_ColumnForInsertion nvarchar(max) = ''
	 -- declare @ParentID bigint = 34594  
	  declare @Pivot_UpdateColumn nvarchar(max) = ''


	  select  top 1 @Pivot_Column =  clmnNames
	      from
		   (		      
            SELECT  STRING_AGG(QUOTENAME([fieldname]),',') as clmnNames
		    FROM (
			  SELECT DISTINCT [fieldname]
			  FROM customfields with(nolock)
			  WHERE [ParentID] = @ParentID
				AND [isActive] = 1
			  ) AS Tab   
		   ) as tab1
		
       select  top 1 @Pivot_ColumnForInsertion =  clmnNames
	   from
	    (		      
        SELECT  STRING_AGG(
	     case when datatype = 'd' 
	   	 then  ' cast( case when isdate( cast(isnull(' + QUOTENAME([fieldname]) + ','''') as nvarchar(50))) = 1 then cast( '+ QUOTENAME([fieldname]) + ' as datetime)
		              else ' + QUOTENAME([fieldname]) + '  end as nvarchar(max))  as ' + QUOTENAME([fieldname])  
		    else
      ' Cast(' +
	   QUOTENAME([fieldname]) 
	   + ' as ' + (case when datatype = 'v'  
               then '[nvarchar](max)'  
      when datatype = 'f'  
                        then '[numeric](18,2)'  
      when datatype = 'm'  
                        then '[money]'  
      --when datatype = 'd'  
      --                  then '[datetime]'  
      when datatype = 's'  
                        then '[nvarchar](max)'  
      --when datatype = 'r'  
      --                  then '[bit]'    
      else '[nvarchar](max)'  
      end   
           )   + ' ) as ' + QUOTENAME([fieldname])  end ,',') as clmnNames
		    FROM (
			  SELECT DISTINCT [fieldname],datatype
			  FROM customfields with(nolock)
			  WHERE [ParentID] = @ParentID
				AND [isActive] = 1
			  ) AS Tab   
		   ) as tab1
		 

	 --select @Pivot_Column
	-- print @Pivot_ColumnForInsertion

	 Declare @Query nvarchar(max) = N'
	  --insert into  customfieldEnquiryvalue_' + cast(@ParentID as nvarchar(50))  + ' 
	  --( EnquiryID, ' + @Pivot_Column + ', CreatedDate, CreatedBy )  
	  select EnquiryID, ' + @Pivot_ColumnForInsertion + ', Getdate() as CreatedDate, ' + cast(@ParentID as nvarchar(50)) + ' as CreatedBy into ##tempTBL from
	   (   
         select  EnquiryID,
		       
			  (
			    case when (fieldvalue = ''yes'' or  fieldvalue = ''true'') and cf.Datatype = ''rTEMP''
				     then ''1''
					 when cf.Datatype = ''rTEMP''
				     then ''0''
					 when (cf.Datatype = ''m'') and (  isnumeric(isnull(cast(fieldvalue as nvarchar(max)),0)) = 0 )
				     then ''0''
					 when (cf.Datatype = ''d'') and (isnull(fieldvalue,'''') <> '''') and isdate( cast(isnull(fieldvalue,'''') as nvarchar(50))) = 1 
					 then cast(fieldvalue as datetime)
					 else
			    	      fieldvalue
			      end    			       
			   ) as fieldvalue
			   
			   ,cf.fieldname from customfieldEnquiryvalue as CEV with(nolock)
	           left join customfields as cf with(nolock) on CEV.fieldID = Cf.field_ID
			    where  cf.ParentID = ' + cast(@ParentID as nvarchar(50)) + '
	                and  isnull(cf.IsActive,0) = 1       	 
	      ) fieldResults
	   Pivot
	     (
	       max(FieldValue) 
	       for FieldName   
		   in ( ' + @Pivot_Column + ') ' + 
	    
	     ') as PivotTable '

     -- print @Query
      exec sp_executesql @Query    
	    --declare @Query1 nvarchar(max) = N' select * from ##tempTBL '
	    --exec sp_executesql @Query1
	  --select * from ##tempTBL

	  select  top 1 @Pivot_UpdateColumn =  clmnNames
	      from
		   (		      
            SELECT STRING_AGG( + ' t1.' + QUOTENAME([fieldname]) + ' = ' + 't2.' + QUOTENAME([fieldname]) ,',') as clmnNames
		    FROM (
			  SELECT DISTINCT [fieldname]
			  FROM customfields with(nolock)
			  WHERE [ParentID] = @ParentID
				AND [isActive] = 1
			  ) AS Tab   
		   ) as tab1


      declare @InsertQuery nvarchar(max) = N' insert into  customfieldEnquiryvalue_' + cast(@ParentID as nvarchar(50))  
	             + ' ( EnquiryID, ' + @Pivot_Column + ', CreatedDate, CreatedBy ) select  EnquiryID, '
				  + @Pivot_Column + ' , CreatedDate, CreatedBy from ##tempTBL as tmp1  where tmp1.EnquiryID not in ( select EnquiryID from customfieldEnquiryvalue_' + cast(@ParentID as nvarchar(50)) + ')' 
	       
      declare @UpdateQuery nvarchar(max) = N' update t1 set ' + @Pivot_UpdateColumn 
	                            + ' from customfieldEnquiryvalue_' + cast(@ParentID as nvarchar(50))
								+ ' (nolock) as t1 join ##tempTBL as t2 on t1.EnquiryID = t2.EnquiryID '    

        --print @InsertQuery
	    exec sp_executesql @InsertQuery
	    --print @UpdateQuery
	    exec sp_executesql @UpdateQuery
	  
	  end try
	  begin catch
	    exec usp_InsertErrorInfo
      end catch
	  
	  drop table if exists ##tempTBL

End



GO

