	*/

	 Declare @QuerySelectInto nvarchar(max) = concat( N'
	  select distinct EnquiryID, LeadID ,' , @Pivot_ColumnForInsertion , ', Getdate() as CreatedDate, ' , cast(@ParentID as nvarchar(50)) , ' as CreatedBy into #tempTBL123 from
	   (   
         select distinct  EnquiryID, LeadID ,
		       
