   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[Usp_TransferAndUpdateIntoCustomFieldLeadValueByParentID_Syncing] --34594 --32222
 (
   @ParentID bigint
 )
 as
 Begin
    
     drop table if exists #tempTBL123  
	 drop table if exists #tempTBL_CreateDataType  
	  
     begin try

 	  declare @Pivot_Column nvarchar(max) = ''
	  declare @Pivot_ColumnForInsertion nvarchar(max) = ''
	 -- declare @ParentID bigint = 34594  
	  declare @Pivot_UpdateColumn nvarchar(max) = ''

	  SELECT @Pivot_Column = STRING_AGG(QUOTENAME([fieldname]),',') --as clmnNames
		    FROM (
			  SELECT DISTINCT [fieldname]
			  FROM customfields with(nolock)
			  WHERE [ParentID] = @ParentID
				--AND [isActive] = 1
		    )  as tab 		
	
	  -- print @Pivot_Column 
	
       select  top 1 @Pivot_ColumnForInsertion =  clmnNames
	   from
	    (		      
        SELECT  STRING_AGG(
	     case when datatype = 'd' 
	   	 then  ' cast( case when isdate( cast(isnull(' + QUOTENAME([fieldname]) + ','''') as nvarchar)) = 1 then cast( cast( '+ QUOTENAME([fieldname]) + ' as nvarchar) as datetime
		 )
		              else ' + QUOTENAME([fieldname]) + '  end as nvarchar)  as ' + QUOTENAME([fieldname])  
		    else
      ' Cast(' +
	   QUOTENAME([fieldname]) 
	   + ' as ' + (case when datatype = 'v'  
               then '[nvarchar](max)'  
      when datatype = 'f'  
                        then '[numeric](18,2)'  
      when datatype = 'm'  
                        then '[money]'  
      --when datatype = 'd'  
      --                  then '[datetime]'  
      when datatype = 's'  
                        then '[nvarchar](max)'  
      --when datatype = 'r'  
      --                  then '[bit]'    
      else '[nvarchar](max)'  
      end   
           )   + ' ) as ' + QUOTENAME([fieldname])  end ,',') as clmnNames
		    FROM (
			  SELECT DISTINCT [fieldname],datatype
			  FROM customfields with(nolock)
			  WHERE [ParentID] = @ParentID
				-- AND [isActive] = 1
			  ) AS Tab   
		   ) as tab1
		 

	 --select @Pivot_Column
	-- print @Pivot_ColumnForInsertion
	/*
      --insert into  CustomFieldLeadValue_' + cast(@ParentID as nvarchar(50))  + ' 
	  --( EnquiryID, ' + @Pivot_Column + ', CreatedDate, CreatedBy )  
	*/

	 Declare @QuerySelectInto nvarchar(max) = concat( N'
	  select nullif(EnquiryID,0) as EnquiryID, LeadID ,' , @Pivot_ColumnForInsertion , ', Getdate() as CreatedDate, ' , cast(@ParentID as nvarchar(50)) 
	    , ' as CreatedBy into #tempTBL123 from
	     (   
	     select 0 as EnquiryID, LeadID, fieldvalue, fieldname  
		   from
			 (
         select ROW_NUMBER() over(partition by LeadID,CEV.fieldID order by recordid asc) as SNO,  EnquiryID, LeadID ,
			  (
			    case when (fieldvalue = ''yes'' or  fieldvalue = ''true'') and cf.Datatype = ''rTEMP''
				     then ''1''
					 when cf.Datatype = ''rTEMP''
				     then ''0''
					 when (cf.Datatype = ''m'') and (  isnumeric(isnull(cast(fieldvalue as nvarchar(max)),0)) = 0 )
				     then ''0''
					 when (cf.Datatype = ''d'') and (isnull(fieldvalue,'''') <> '''') and isdate( cast(isnull(fieldvalue,'''') as nvarchar)) = 1 
					 then cast(fieldvalue as datetime)
					 else
			    	      fieldvalue
			      end    			       
			   ) as fieldvalue
			   ,cf.fieldname from customfieldLeadvalue as CEV with(nolock)
	           join customfields as cf with(nolock) on CEV.fieldID = Cf.field_ID
			    where  cf.ParentID = ' , cast(@ParentID as nvarchar(50)) , '
	 		) as T
			   where T.SNO = 1 	
	      ) fieldResults
	   Pivot
	     (
	       max(FieldValue) 
	       for FieldName   
		   in ( ' , @Pivot_Column , ') ' , 
	    
	     ') as PivotTable ')

     -- print @Query
     -- exec sp_executesql @QuerySelectInto    
	    --declare @Query1 nvarchar(max) = N' select * from #tempTBL123 '
	    --exec sp_executesql @Query1
	  --select * from #tempTBL123

	  --select  top 1 @Pivot_UpdateColumn =  clmnNames
	    --  from
		  -- (		      
            SELECT  @Pivot_UpdateColumn = STRING_AGG( + ' t1.' + QUOTENAME([fieldname]) + ' = ' + 't2.' + QUOTENAME([fieldname]) ,',') --as clmnNames
		    FROM (
			  SELECT DISTINCT [fieldname]
			  FROM customfields with(nolock)
			  WHERE [ParentID] = @ParentID
				-- AND [isActive] = 1
			  ) AS Tab   
		   --) as tab1


		 -- print @Pivot_UpdateColumn

       declare @InsertQuery nvarchar(max) = concat( N' insert into customfieldLeadvalue_' , cast(@ParentID as nvarchar(50))  
	             , ' ( EnquiryID, LeadID ,  ' , @Pivot_Column , ', CreatedDate, CreatedBy ) select EnquiryID, LeadID, '
				  , @Pivot_Column , ' , CreatedDate, CreatedBy from #tempTBL123 as tmp1  where tmp1.LeadID not in
				   ( select LeadID from customfieldLeadvalue_' , cast(@ParentID as nvarchar(50)) , ')' )
	  
	    /*
	     declare @UpdateQuery nvarchar(max) = concat( N' update t1 set ' , @Pivot_UpdateColumn 
	                            , ' from customfieldLeadvalue_' , cast(@ParentID as nvarchar(50))
								, ' (nolock) as t1 join #tempTBL123 as t2 on t1.LeadID = t2.LeadID ')
		*/
		
		/* 						
	       declare @DeleteQuery nvarchar(max) = concat(N' delete from customfieldLeadvalue_' , cast(@ParentID as nvarchar(50))
	                                    ,' where leadid not in ( select LeadID from #tempTBL123 ) ' ); 							    
         */    

      --print @InsertQuery
	  
	   -- exec sp_executesql @InsertQuery
	 
	  --print @UpdateQuery
	  
	    --exec sp_executesql @UpdateQuery
	
	   --declare @TotalFinalQuery nvarchar(max) =  Concat(@QuerySelectInto,';',@InsertQuery,';',@UpdateQuery,';' + @DeleteQuery);
	
	    declare @TruncateQuery nvarchar(max) = concat(N' truncate table customfieldLeadvalue_',cast(@ParentID as nvarchar(50)))   
	    declare @TotalFinalQuery nvarchar(max) =  Concat( @TruncateQuery ,';' , @QuerySelectInto, ';' , @InsertQuery);
	  
	  -- print @TotalFinalQuery
	   exec sp_executesql @TotalFinalQuery 

	  end try
	  begin catch
	    exec usp_insertErrorInfo 
	  end catch       
	   
	    drop table if exists #tempTBL123
		drop table if exists #tempTBL_CreateDataType  

End



