/* ============================================================
   Procedure: [dbo].[usp_TransferFeedbackKit19ToCRM]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE usp_TransferFeedbackKit19ToCRM
as
Begin

 declare @result nvarchar(50) 
  EXEC GetStatusofLinkedServerwithoutput 'CRM',@result output    
  if isnull(@result,'0') <> 'Server is currently Offline!!' --is not null 
  Begin 
   insert into crm.crmdb.dbo.FeedbackActivity  
    (  
      FID,   
      RefID ,  
      AttributeComments ,  
      ActivityFeedback ,  
      Comments      
    ) 
    select FID,   
      RefID ,  
      AttributeComments ,  
      ActivityFeedback  ,  
      Comments      
    From FeedbackActivity
     
     delete from FeedbackActivity
     
  end

End



