/* ============================================================
   Procedure: [dbo].[usp_TransferIndiamartEntriestoEnquiries_Process]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_TransferIndiamartEntriestoEnquiries_Process]                         
@indiamartid bigint=null                                 
AS                                  
BEGIN     

    --DROP TABLE if  exists #TempEnq        
    if object_id('tempdb..#TempEnq') is not null begin drop table #TempEnq end    
	                  
--declare @indiamartid bigint=null      
declare @isleadcreated int=0,@leadid bigint,@LIHID bigint = 0            
declare @i bigint=(select case when @indiamartid IS null then max(ID) else @indiamartid end from IndiamartLeads(nolock) where isprocessed=1)                               
RETRY:        
begin try        
begin tran        
SELECT ROW_NUMBER() over (order by uere.ID) rno,                              
uere.ID,                         
isnull(nullif(ltrim(rtrim(uere.SENDERNAME)),'null'),'') PersonName,                                  
case                   
when charindex('-',mob,1)> 0 and isnumeric(RIGHT(mob,(len(mob)-charindex('-',mob,1))))=1                   
then RIGHT(mob,(len(mob)-charindex('-',mob,1)))                   
when isnumeric(REPLACE(MOB,ltrim(rtrim(m.CountryCode)),''))=1 and cast(REPLACE(MOB,ltrim(rtrim(m.CountryCode)),'') AS bigint)>0                  
then REPLACE(MOB,ltrim(rtrim(m.CountryCode)),'') end MobileNo,                  
case                   
when charindex('-',mob,1)> 0 and isnumeric(RIGHT(mob,(len(mob)-charindex('-',mob,1))))=1                   
then left(mob,charindex('-',mob,1)-1)                   
when isnumeric(REPLACE(MOB,ltrim(rtrim(m.CountryCode)),''))=1 and cast(REPLACE(MOB,ltrim(rtrim(m.CountryCode)),'') as bigint)>0                  
then  ltrim(rtrim(m.CountryCode)) end CountryCode,                  
ISNULL(nullif(ltrim(rtrim(uere.senderemail)),'null'),'') as EmailID,                  
case                   
when charindex('-',mobile_alt,1)> 0 and isnumeric(RIGHT(mobile_alt,(len(mobile_alt)-charindex('-',mobile_alt,1))))=1                   
then RIGHT(mobile_alt,(len(mobile_alt)-charindex('-',mobile_alt,1)))                   
when isnumeric(REPLACE(mobile_alt,ltrim(rtrim(m.CountryCode)),''))=1 and cast(REPLACE(MOBILE_ALT,ltrim(rtrim(m.CountryCode)),'') as bigint)>0                  
then REPLACE(mobile_alt,ltrim(rtrim(m.CountryCode)),'') end MobileNo1,                  
case                   
when charindex('-',mobile_alt,1)> 0 and isnumeric(RIGHT(mobile_alt,(len(mobile_alt)-charindex('-',mobile_alt,1))))=1                   
then left(mobile_alt,charindex('-',mobile_alt,1)-1)                   
when isnumeric(REPLACE(mobile_alt,ltrim(rtrim(m.CountryCode)),''))=1 and cast(REPLACE(MOBILE_ALT,ltrim(rtrim(m.CountryCode)),'') as bigint)>0                  
then ltrim(rtrim(m.CountryCode)) end CountryCode1,                  
ISNULL(nullif(ltrim(rtrim(uere.EMAIL_ALT)),'null'),'') as EmailID1,                  
case when isnull(nullif(ltrim(rtrim(GLUSR_USR_COMPANYNAME)),'null'),'')<>'' then GLUSR_USR_COMPANYNAME else null end as CompanyName,                  
case when ISNULL(nullif(ltrim(rtrim(ENQ_ADDRESS)),'null'),'')<>'' and isnull(nullif(ltrim(rtrim(GLUSR_USR_COMPANYNAME)),'null'),'')<>'' then ENQ_ADDRESS end OfficeAddress,                  
case when ISNULL(nullif(ltrim(rtrim(ENQ_ADDRESS)),'null'),'')<>'' and isnull(nullif(ltrim(rtrim(GLUSR_USR_COMPANYNAME)),'null'),'')='' then ENQ_ADDRESS end ResidentialAddress,                  
case when nullif(ltrim(rtrim(ENQ_CITY)),'null') is not null then  substring(uere.ENQ_CITY,1,100) end City,                   
case when nullif(ltrim(rtrim(enq_state)),'null') is not null then substring(uere.ENQ_State,1,100) end State,                  
m.Country_name,                  
'Query Details: '            
+', For Product: '+cast(PRODUCT_NAME as nvarchar)                  
+', Message: '+cast(ENQ_MESSAGE  as nvarchar(max))                   
+', Subject: '+cast(Subject as nvarchar(max))                  
+', Query id: '+cast(QUERY_ID as nvarchar)                  
+', Query Type: '+cast(QTYPE as nvarchar)                  
+', Name: '+ cast (isnull(nullif(ltrim(rtrim(uere.SENDERNAME)),'null'),'') as nvarchar)                   
+', Mobile: '+isnull(cast(mob as nvarchar),'None')                  
+', Alternate Mobile: '+isnull(cast(mobile_alt as nvarchar),'None')                  
+', Phone: '+isnull(cast(PHONE as nvarchar),'None')                  
+', Alternate Phone: '+isnull(cast(PHONE_ALT as nvarchar),'None')                  
+', Email: '+isnull(cast(senderemail as nvarchar),'None')                  
+', Alternate Email: '+isnull(cast(email_alt as nvarchar),'None')                  
+', Date: '+cast(DATE_TIME_RE as nvarchar)                  
+', Company: '+cast(isnull(nullif(ltrim(rtrim(GLUSR_USR_COMPANYNAME)),'null'),'None') as nvarchar)                  
+', City: '+ cast(isnull(ENQ_CITY,'Not Mentioned') as nvarchar)                  
+', State: '+cast(isnull(enq_State,'Not Mentioned') as nvarchar)                  
+', Address: '+cast(isnull(ENQ_ADDRESS,'Not Mentioned') as nvarchar)                  
+', Call Received By: '+cast(isnull(ENQ_RECEIVER_MOB,'Not Applicable') as nvarchar)                   
+', Call Duration: '+cast(isnull(ENQ_CALL_DURATION,'Not Applicable') as nvarchar)                  
+', Indiamart Key: '+cast(uere.Indiamartkey as nvarchar) as InitialRemarks,                  j.Kit19ParentID,                                  
DateReceived AS CreatedDate,                        
j.Kit19ParentId as parentid,                        
0  AS IsOpen INTO #TempEnq                                  
FROM   indiamartleads(nolock)  AS uere                   
join   IndiamartMapping(nolock) j on j.IndiamartId=uere.INDIAMARTKEY                           
left join m_country1 m on ltrim(rtrim(m.Shortname))=ltrim(rtrim(uere.COUNTRY_ISO))                  
WHERE  uere.IsProcessed = 0  and uere.isvalid=1 and uere.id>@i                          
update indiamartleads set isprocessed=2 where id>@i            
commit        
end try        
BEGIN CATCH                                                                   
IF @@TRANCOUNT>0                                                              
ROLLBACK                                                         
EXECUTE USP_INSERTERRORINFO;                                 
IF ERROR_NUMBER() = 1205 -- Deadlock Error Number                      
BEGIN                                            
WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms                                     
GOTO RETRY -- Go to Label RETRY                                            
END                                                                         
END CATCH                                        
        
                         
  --select * from #TempEnq                   
                    
  --drop table #TempEnq                  
                    
--select replace(REPLACE(MOB,ltrim(rtrim(m.CountryCode)),''),'-',''),isnumeric(REPLACE(MOB,ltrim(rtrim(m.CountryCode)),'')),isnumeric(RIGHT(mob,(len(mob)-charindex('-',mob,1)))),case                   
--when charindex('-',mob,1)> 0 and isnumeric(RIGHT(mob,(len(mob)-charindex('-',mob,1))))=1                   
--then RIGHT(mob,(len(mob)-charindex('-',mob,1)))                   
--when isnumeric(REPLACE(MOB,ltrim(rtrim(m.CountryCode)),''))=1 and cast(REPLACE(MOB,ltrim(rtrim(m.CountryCode)),'') as bigint)>0                  
--then REPLACE(MOB,ltrim(rtrim(m.CountryCode)),'')                   
--end MobileNo,* from IndiamartLeads uere                  
--left join m_country1 m on ltrim(rtrim(m.Shortname))=ltrim(rtrim(uere.COUNTRY_ISO))                  
--where uere.ID=216                  
                          
if exists(select top 1 'x' from #TempEnq)                        
begin                            
 --------------------------                              
 declare @Crno bigint = 0;                              
 declare @maxno bigint = 0;                              
 select @maxno = MAX(rno), @Crno = MIN(rno) from #TempEnq                              
 declare @leadn1 as bigint  = 0                              
 declare @ParentID bigint = 0;                              
                                
  declare @MobileNo nvarchar(max)  =''                               
        declare @MobileNo1 nvarchar(max)  =''                                 
        declare @MobileNo2 nvarchar(max)  =''                                  
        declare @EmailID nvarchar(max)  =''       
        declare @EmailID1 nvarchar(max)  =''                                  
        declare @EmailID2 nvarchar(max)  =''                                  
                                     
        declare @CountryCode  nvarchar(max)  =''                   
        declare @CountryCode1 nvarchar(max)  =''                                
        declare @CountryCode2 nvarchar(max)  =''                              
 create table #temp(leadno bigint,countrycode nchar(10),mobile varchar(100),email varchar(100))                              
 declare @EnquiryID bigint,@rawEnquiryID bigint,@source bigint ,@medium bigint                            
 declare @AutoLeadDistribution bit =0  
                             
while @Crno <= @maxno                              
begin                              
set @leadn1=0                          
                            
select @ParentID = ParentID, @CountryCode= CountryCode, @MobileNo= trim(MobileNo), @EmailID= EmailID,@CountryCode1= CountryCode1, @MobileNo1= trim(MobileNo1), @EmailID1= EmailID1  FROM   #TempEnq  WHERE  rno = @Crno                        
                        
if not exists (select 1 from UserSourceSettings(nolock) where name='Paid clasifieds' and userid=@parentid)                        
begin                        
INSERT INTO UserSourceSettings                                    
       (                                    
         -- SourceID -- this column value is auto-generated                                
         NAME,                                    
         UserID,                                    
         IsEditable,                                    
         IsActive,                                    
         CreatedDate,                                    
         ModifiedDate,                                    
         ModifiedBy                                    
       )                                    
     VALUES                      
       (                                    
         'Paid clasifieds',                                    
         @ParentID,                                    
         0,                                    
         1,                                    
         GETDATE(),                                    
         GETDATE(),                                    
         335                                    
       )                         
set @source=SCOPE_IDENTITY()                        
                        
end                        
else  begin                        
select top 1 @source=sourceid from UserSourceSettings(nolock) where name='Paid clasifieds' and userid=@parentid                         
end                                  
                              
if not exists (select 1 from UserMediumSettings(nolock) where name='Indiamart' and userid=@parentid)                        
begin                        
INSERT INTO UserMediumSettings                                
       (                            
         -- MediumID -- this column value is auto-generated                                
         NAME,                                
         UserID,                                
         IsEditable,                                
         IsActive,                                
         CreatedDate,                                
         ModifiedDate,                 ModifiedBy                                
       )                                
     VALUES                                
       (                                
         'Justdial',                                
         @ParentID,                                
         0,                                
         1,                                
         GETDATE(),                                
         GETDATE(),           
         335                                
       )                           
set @medium=SCOPE_IDENTITY()                        
                        
end                        
else  begin                        
select top 1 @medium=mediumid from UsermediumSettings(nolock) where name='Indiamart' and userid=@parentid                       
end                         
                              
                               
             
if not exists(select 1 from ParsedEnquiries(nolock) where RawEnquiryId=@rawenquiryid and enquirysource='IndiamartLeads API')          
begin                            
 INSERT INTO UserEnquiry                                  
   (                                  
     PersonName,                          
     MobileNo,                                  
     EmailID,                                  
     CountryCode,                   
     MobileNo1,                                  
     EmailID1,                                  
     CountryCode1,                  
     CompanyName,                   
     OfficeAddress,                 
     ResidentialAddress,                  
     City,                  
     State,                  
     Country,                      
     SourceName,                                  
     InitialRemarks,                                  
     ParentID,                                  
     CreatedDate,                                  
     CreatedBy,                                  
     IsOpen,                              
     LeadNo,                      
     MediumName,                      
     Campaignname,      
  enquirysource                                 
   )                                  
 SELECT PersonName,                                  
        rtrim(ltrim(MobileNo)),                                  
        ltrim(rtrim(EmailID)),                                  
       rtrim(ltrim(CountryCode)),                                  
       rtrim(ltrim(MobileNo1)),                                  
     rtrim(ltrim(EmailID1)),                                  
     rtrim(ltrim(CountryCode1)),                  
     CompanyName,                   
     OfficeAddress,                  
     ResidentialAddress,                  
     City,                  
     State,                  
     Country_name,                                      
      @source,                                  
        InitialRemarks,                                  
        ParentID,                                  
        CreatedDate,                                  
        parentid,                                  
        IsOpen,                              
        @leadn1,                      
        @medium,                      
        0,      
  (select id from enquirysources where sourcename='Indiamart API')                                  
 FROM   #TempEnq where rno = @Crno                                 
  set @EnquiryID=SCOPE_IDENTITY()                          
  select @rawEnquiryID= ID FROM   #TempEnq where rno = @Crno OPTION (MAXDOP 1)             
                
  update IndiamartLeads set isprocessed = 1,EnquiryId=@EnquiryID,Processederror='Success',Processeddate=getdate() where ID=@rawEnquiryID  OPTION (MAXDOP 1)            
                            
  insert into parsedenquiries(rawenquiryid,enquiryid,parentid,EnquirySource)                          
  select @rawenquiryid,@enquiryid,@parentid,'Indiamart API'                                
                                    
seT @AutoLeadDistribution = isnull((select isnull(AutoLeadDistribution,0) FROM   CRMCampaignSettings  WHERE  UserID = @ParentID),0)                              
      
begin try      
begin tran      
insert into #temp(leadno,countrycode,mobile,email)    
select leadno,countrycode,mobile,email from Userleads_Mobile_Email(nolock) where parentid=@ParentID
/*                          
select leadno,isnull(CountryCode,'0'),isnull(nullif(mobileno,''),'0'),'1' from UserLeads(nolock) where ParentID=@ParentID and MobileNo<>''                              
union                              
select leadno,isnull(CountryCode1,'0'),isnull(nullif(mobileno1,''),'0'),'1' from UserLeads(nolock) where ParentID=@ParentID and MobileNo1<>''                              
union                              
select leadno,isnull(CountryCode2,'0'),isnull(nullif(mobileno2,''),'0'),'1' from UserLeads(nolock) where ParentID=@ParentID and MobileNo2<>''                              
union                              
select leadno,'0','0',isnull(nullif(emailid,''),'1') from UserLeads(nolock) where ParentID=@ParentID   and emailid<>''                            
union                              
select leadno,'0','0',isnull(nullif(emailid1,''),'1') from UserLeads(nolock) where ParentID=@ParentID  and emailid1<>''                                             
union                              
select leadno,'0','0',isnull(nullif(emailid2,''),'1') from UserLeads(nolock) where ParentID=@ParentID  and emailid2<>''                                 
*/
set @leadn1 = isnull(            
  (select top 1 t.leadno from #temp t join #TempEnq e on            
    (            
  (isnull(dbo.fn_ltrimrtrim(e.CountryCode),'2') + ISNULL(dbo.fn_ltrimrtrim(e.MobileNo),'2')=cast(dbo.fn_ltrimrtrim(t.countrycode) as nvarchar)+cast(dbo.fn_ltrimrtrim(t.mobile) as nvarchar) )                           
     or (isnull(nullif(dbo.fn_ltrimrtrim(e.EmailID),''),'3')=dbo.fn_ltrimrtrim(t.email))       
  or      
   (isnull(dbo.fn_ltrimrtrim(e.CountryCode1),'2') + ISNULL(dbo.fn_ltrimrtrim(e.MobileNo1),'2')=cast(dbo.fn_ltrimrtrim(t.countrycode) as nvarchar)+cast(dbo.fn_ltrimrtrim(t.mobile) as nvarchar) )                           
     or (isnull(nullif(dbo.fn_ltrimrtrim(e.EmailID1),''),'3')=dbo.fn_ltrimrtrim(t.email))        
  /*      
        (isnull(e.CountryCode,'2') + ISNULL(e.MobileNo,'2')=cast(t.countrycode as nvarchar)+cast(t.mobile as nvarchar) )                         
     or (isnull(nullif(e.EmailID,''),'3')=t.email)                   
     or  (isnull(e.CountryCode1,'2') + ISNULL(e.MobileNo1,'2')=cast(t.countrycode as nvarchar)+cast(t.mobile as nvarchar) )            
     or (isnull(e.EmailID1,'3')=t.email)            
  */      
 )            
 and e.rno = @Crno            
                   
 ),0)                              
                              
if (@AutoLeadDistribution = 1 and @leadn1=0)                                    
  begin                         
  set @Leadn1 = isnull((select MAX(LeadNo)                                                       
  FROM   UserLeads WHERE  ParentID = @ParentID),0)+1                                 
/*        
  Insert into userleads (LeadNo,PersonName,MobileNo,EmailID,City,PinCode,CountryCode,                        
  AssignedTo,SourceName,ParentID,mediumname,CampaignName,                        
  InitialRemarks,CreatedOn,CreatedBy,OfficeAddress,ResidentialAddress,enquirysource)                            
  select @leadn1,substring(PersonName,1,100),MobileNo,EmailID,City,PinCode,CountryCode,                        
  (select top 1 value from fn_Split((select agents from CRMCampaignSettings where userid=@ParentID),'#')    ORDER BY NEWID                   
   ()),SourceName,ParentID,mediumname,CampaignName,InitialRemarks,GETDATE(),CreatedBy,OfficeAddress,ResidentialAddress,enquirysource                   
  from userenquiry(nolock) where enquiryid=@EnquiryID      
 set @isleadcreated  = 1    
  */  
  
  declare @returnAgentId bigint
   exec udf_GetAgentToAssigned @ParentId = @ParentID, @AgentId = @returnAgentId output   --select @returnAgentId  
 
    SET Context_Info 0x55555
  
    Insert into userleads (LeadNo,PersonName,MobileNo,EmailID,City,PinCode,CountryCode,                        
  AssignedTo,SourceName,ParentID,mediumname,CampaignName,                        
  InitialRemarks,CreatedOn,CreatedBy,OfficeAddress,ResidentialAddress,enquirysource)                            
  select @leadn1,substring(PersonName,1,100),trim(MobileNo),EmailID,City,PinCode,CountryCode,   
   @returnAgentId ,SourceName,ParentID,mediumname,CampaignName,InitialRemarks,GETDATE(),CreatedBy,OfficeAddress,ResidentialAddress,enquirysource                   
from userenquiry(nolock) where enquiryid=@EnquiryID      
  
  select @leadid=SCOPE_IDENTITY()
  Exec MySMS.dbo.usp_ExecLeadTriggerTasks @leadid
	  
  set @isleadcreated   =1    

  insert into LeadInteractionHistory(LeadNo,FollowUpStatus,NextStatusDate,Remarks,Products,AmountPaid,AssignedTo,    
  ParentID,CreatedOn,CreatedBy,FollowupDate,IsReassign)    
  select LeadNo,FollowUpStatus,NextStatusDate,Remarks,Products,AmountPaid,AssignedTo,    
  ParentID,CreatedOn,CreatedBy,FollowupDate,0 from userleads u (nolock) where ID = @leadid
  
  select @LIHID=SCOPE_IDENTITY()
  Exec MySMS.dbo.usp_ExecLeadInteractionTriggerTasks @LIHID

  --exec Usp_insertdefaultfollowup @parentid,@leadid
   SET Context_Info 0x                   

end          
commit                      
end try      
begin catch      
exec usp_InsertErrorInfo      
end catch      
                        
update UserEnquiry  set LeadNo=case when @LeadN1<>0 then @leadn1 else null end,     
IsOpen= case when @isleadcreated=1 then 0 else 1 end where EnquiryID=@EnquiryID              
OPTION (MAXDOP 1)                             
      
if not exists(select 1 from tbl_MergeLeadsEnquiry where enquiryno=@enquiryid and LeadNo=@leadn1)      
begin       
insert into  tbl_MergeLeadsEnquiry(EnquiryNo ,LeadNo,IsOpen)     
values (@EnquiryID,@Leadn1,case when @isleadcreated=1 then 0 else 1 end)   OPTION (MAXDOP 1)                                  
end      
/*UPDATE indiamartleads                                  
SET    isprocessed = 1  ,EnquiryId=@EnquiryID,Processederror='Success',Processeddate=getdate()                                
WHERE  ID =(SELECT ID FROM   #TempEnq  where rno = @Crno)              
*/                        
truncate table #temp            
ENd                
set @Crno = @Crno+1                              
end                                
end                                   
  -- DROP TABLE if  exists #TempEnq    
    if object_id('tempdb..#TempEnq') is not null begin drop table #TempEnq end                          
update indiamartleads set isprocessed=1 where id>@i OPTION (MAXDOP 1)                        
