/* ============================================================
   Procedure: [dbo].[Usp_TransferLeadDatatoCustomFieldMapping]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

/*

Usp_TransferLeadDatatoCustomFieldMapping 7329, 'MagicBricks'--  @apiname='MagicBricks',@rawleadid= 7329  --1, 'Shopify'

select * from  userenquiry where enquiryid= 4650094

*/

CREATE   PROCEDURE [dbo].[Usp_TransferLeadDatatoCustomFieldMapping] --86528,'99acres'   --30064,'Shiksha'        --26, 'Taxo'  --1,'CarDekho'          
  @rawleadid BIGINT          
 ,@apiname NVARCHAR(max)          
           
AS          
BEGIN          
   
  --declare @rawleadid bigint=86486 ,  @apiname nvarchar(max)='99acres'          
          
 DECLARE @ParentID BIGINT = 0;          
 DECLARE @var NVARCHAR(max) = '', @tablename nvarchar(100)=''          
 declare @apikey NVARCHAR(max)=''          
 DECLARE @col1 NVARCHAR(max) = ''          
 DECLARE @col NVARCHAR(max) = ''          
          
 DECLARE @Crno BIGINT = 0;          
DECLARE @maxno BIGINT = 0;          
declare @isleadcreated int=0                 
DECLARE @leadn1 AS BIGINT = 0          
          
DECLARE @MobileNo NVARCHAR(max) = ''          
DECLARE @MobileNo1 NVARCHAR(max) = ''          
DECLARE @MobileNo2 NVARCHAR(max) = ''          
DECLARE @EmailID NVARCHAR(max) = ''           
DECLARE @EmailID1 NVARCHAR(max) = ''          
DECLARE @EmailID2 NVARCHAR(max) = ''          
DECLARE @CountryCode NVARCHAR(max) = ''          
DECLARE @CountryCode1 NVARCHAR(max) = ''          
DECLARE @CountryCode2 NVARCHAR(max) = ''          
declare @CountryCode_User nvarchar(20) = '+91'     
     
DECLARE @i BIGINT=0      
Drop Table If Exists #temp  
Drop Table If Exists #tp  
Drop Table If Exists #tp_Cardekho  
Drop Table If Exists #tp_Carlelo  
Drop Table If Exists #tp_CarWale  
Drop Table IF Exists #tp_CollegeDunia  
  
 drop table if exists #ids  
    create table #ids(id bigint)  
  
  
  
DECLARE @EnquiryID BIGINT          
 ,@rawEnquiryID BIGINT          
 ,@source BIGINT  = 0         
 ,@medium BIGINT = 0         
 ,@LIHID bigint = 0  
declare @SourceName nvarchar(200)          
DECLARE @AutoLeadDistribution BIT = 0          
 DECLARE @leadid BIGINT=null ,@isprocessed nvarchar(12)='isprocessed'   
 declare @sqls nvarchar(max)    
drop table if exists #tempenq          
          
create table #tempenq(          
rno     int,          
id     bigint,          
PersonName   nvarchar(200),          
CompanyName   nvarchar(500),          
MobileNo   varchar(1000),          
MobileNo1   varchar(1000),          
EmailID    varchar(1000),          
EmailID1   varchar(1000),          
City    varchar(1000),          
State    varchar(1000),          
Country    varchar(1000),          
pincode    bigint,          
CountryCode   varchar(1000),          
CountryCode1  varchar(1000),          
ResidentialAddress varchar(1000),          
OfficeAddress  varchar(1000),          
SourceName   bigint,          
MediumName   bigint,          
CampaignName  bigint,          
InitialRemarks  nvarchar(max),          
ParentID   bigint,          
CreatedDate   datetime,          
CreatedBy   varchar(1000),          
IsOpen    bit,          
LeadNo    int,          
enquirysource  varchar(1000),  
shiSrc nvarchar(max),  
shimed nvarchar(max),  
apikey    varchar(1000),          
)          
          
declare @usermedium nvarchar(100)='',@enqsource varchar(100)='',@updlead nvarchar(max)='',@date datetime = getdate(),  @sts varchar(8)='Success',@iscustom bit  
 if(@apiname = 'Exporter')  
  Begin   
      Select @tablename= 'tbl_exporterLeads',@usermedium='Exporter', @enqsource='Exporter API'   
   select @i = case when @rawleadid IS null then max(ID) else @rawleadid end from tbl_exporterLeads(nolock) where isprocessed=1   
 --  RETRY_EXP:                    
 -- begin try                    
 -- begin tran                    
   insert into #tempenq (rno, id, PersonName, MobileNo,CountryCode,EmailID,MobileNo1,CountryCode1,EmailID1,CompanyName,OfficeAddress,ResidentialAddress, City,State,Country          
   ,InitialRemarks, ParentID,CreatedDate,CreatedBy,IsOpen,apikey)          
   output inserted.id as id into #ids  
     
  
   SELECT ROW_NUMBER() over (order by uere.ID) rno,                                          
   uere.ID,                                     
   isnull(nullif(ltrim(rtrim(uere.name)),'null'),'') PersonName,                                              
   case                               
   when charindex('-',uere.mobile,1)> 0 and isnumeric(RIGHT(uere.mobile,(len(uere.mobile)-charindex('-',uere.mobile,1))))=1                               
   then RIGHT(uere.mobile,(len(uere.mobile)-charindex('-',uere.mobile,1)))                               
    else  
     ''  
    end MobileNo,  
    case                               
   when charindex('-',uere.mobile,1)> 0 and isnumeric(RIGHT(uere.mobile,(len(uere.mobile)-charindex('-',uere.mobile,1))))=1                               
   then left(uere.mobile,charindex('-',uere.mobile,1)-1)  
   else '+91'  
   end   CountryCode,                              
   ISNULL(nullif(ltrim(rtrim(uere.email)),'null'),'')  EmailID                              
   , ''  MobileNo1  
   , ''  CountryCode1     
   , ''  EmailID1                            
   ,case when isnull(nullif(ltrim(rtrim(uere.company)),'null'),'')<>'' then uere.company else null end as CompanyName,                              
   '' OfficeAddress,                              
   '' ResidentialAddress,                              
   case when nullif(ltrim(rtrim(uere.city)),'null') is not null then  substring(uere.city,1,100) end City,                               
   case when nullif(ltrim(rtrim(uere.state)),'null') is not null then substring(uere.state,1,100) end State,                              
   case when nullif(ltrim(rtrim(uere.country)),'null') is not null then substring(uere.country,1,100) end country,                              
   'Query Details: '                        
   +', For Product: '+ cast(isnull(uere.product,'') as nvarchar)                              
   +', Message: '+cast(isnull(uere.detail_req,'')  as nvarchar)                               
   +', Subject: '+cast(isnull(uere.subject,'') as nvarchar)                              
   +', Query id: '+cast(isnull(uere.Exporter_inq_id,'') as nvarchar)                              
   +', Name: '+ cast (isnull(nullif(ltrim(rtrim(uere.name)),'null'),'') as nvarchar)                               
   +', Mobile: '+isnull(cast(isnull(uere.mobile,'None') as nvarchar),'None')                              
   +', Email: '+isnull(cast(uere.email as nvarchar),'None')                              
   +', Date: '+cast(isnull(uere.Exporter_enq_date,'') as nvarchar)                              
   +', Company: '+cast(isnull(nullif(ltrim(rtrim(uere.company)),'null'),'None') as nvarchar)                              
   +', City: '+ cast(isnull(uere.city,'Not Mentioned') as nvarchar)                              
   +', State: '+cast(isnull(uere.state,'Not Mentioned') as nvarchar)                              
   +', Country: '+cast(isnull(uere.country,'Not Mentioned') as nvarchar)                              
   +', Exporter Key: '+cast(uere.ExporterKey as nvarchar) as InitialRemarks,            
   j.ParentID,                                              
   uere.Exporter_enq_date  AS CreatedDate,                                    
   j.ParentId as parentid,                                    
   0  AS IsOpen, uere.ExporterKey as apikey                                       
   FROM   tbl_exporterLeads(nolock)  AS uere                               
   join   tbl_ExporterMapping(nolock) j on j.ExporterKey=uere.ExporterKey                                       
   --left join m_country1 m on ltrim(rtrim(m.Shortname))=ltrim(rtrim(uere.COUNTRY_ISO))                              
   WHERE  uere.IsProcessed = 0  and uere.isvalid=1 and uere.id>@i             
     
   update i set isprocessed=2 from tbl_exporterLeads i join #ids d on d.id=i.id  
     
  
   --commit                    
 -- end try                    
  --BEGIN CATCH                                                                               
   --IF @@TRANCOUNT>0                                                                          
   -- ROLLBACK            
   -- EXECUTE USP_INSERTERRORINFO;                                             
   --IF ERROR_NUMBER() = 1205 -- Deadlock Error Number                                  
  -- BEGIN                                                
   -- WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms                                                 
   -- GOTO RETRY_EXP -- Go to Label RETRY                                                        
   --END                                                                                     
  --END CATCH     
  
  
  End -- Closing exporter          
 else IF @apiname = 'JustDial'          
 BEGIN          
           
  Select @tablename= 'Justdialleads',@usermedium='JustDial', @enqsource='Just Dial API'    
    RETRYJD:                    
  begin try                    
  begin tran    
    
  select @i = case when @rawleadid IS null then max(ID) else @rawleadid end from JUstdialleads(nolock) where isprocessed=1   
    
  insert into #tempenq (rno, id, PersonName, MobileNo,EmailID,City, CountryCode ,PinCode, InitialRemarks,ParentID,CreatedDate,CreatedBy,IsOpen,apikey)          
  output inserted.id as id into #ids  
          
  SELECT ROW_NUMBER() over (order by uere.ID) rno, uere.ID,                       
  LTRIM(RTRIM( replace(isnull(substring(uere.prefix +' ' + uere.Name,1,100),''),',',''))) PersonName                
  , case when len(uere.Mobile)>10 then right(uere.mobile,10) else uere.mobile end MobileNo,                                
        uere.Email as EmailID,                                
        substring(uere.City,1,100) City,                          
        (case when isnull(uere.Mobile,'')='' then '' else '+91' end) as CountryCode ,                               
        uere.PinCode,                          
        'New Justdial lead received through Lead id: '+cast(uere.leadid as nvarchar)+', Lead Type: '+cast(uere.leadtype as nvarchar)+             
  ', Name: '+ cast (isnull(uere.prefix,'')+' '+isnull(uere.Name,'') as nvarchar) +                      
  ', Mobile: '+cast(uere.mobile as nvarchar)+            
  ', Phone: '+cast(uere.phone as nvarchar)+            
  ', Email: '+cast(uere.email as nvarchar)+             
  ', Date: '+cast(uere.date as nvarchar)+            
  ', Category: '+cast(uere.category as nvarchar)+            
  ', City: '+ cast(uere.city as nvarchar)+            
  ', Area: '+cast(uere.Area as nvarchar)+            
  ', Branch Area: '+cast(uere.brancharea as nvarchar)+            
  ', Is Mobile DND: '+cast(uere.dncmobile as nvarchar)+                      
  ', Is Phone DND: '+cast(uere.dncphone  as nvarchar) +            
  ' Company: '+cast(uere.company as nvarchar)+            
  ', Pincode: '+cast(uere.pincode as nvarchar)+         
  ', Time: '+cast(uere.time as nvarchar)+            
  ', Branch Pin: '+cast(uere.branchpin as nvarchar)+            
  ', JUstDial ParentId: '+cast(uere.jdparentid as nvarchar) +            
  ', Date & Time: '+ cast(uere.ndate as nvarchar)+' '+cast(uere.ntime as nvarchar) as InitialRemarks,                                
  j.Kit19ParentID as CreatedBy,                                
  uere.DateReceived AS CreatedDate,                      
  j.Kit19ParentId as parentid,                    
        1  AS IsOpen , uere.jdparentid as apikey                               
  FROM   JUstdialleads(nolock)  AS uere     join   JDMapping j(nolock) on j.JDParentId=uere.jdparentid                         
  join user_detail(nolock) u on u.User_ID=j.Kit19ParentId            
  join Price_UserSubscriptionDetails(nolock) p on p.UserID=j.Kit19ParentId and p.isnewplan=1 and PlanEndDate>getdate()            
  and u.status=1            
  WHERE
    uere.IsProcessed = 0    
    and uere.isvalid=1   
   --and uere.id = case when @rawleadid is not null then @rawleadid else uere.id end                      
   and 
   uere.id >=  @i                      
   update i set isprocessed=2 from JUstdialleads i join #ids d on d.id=i.id  
     
   commit                    
  end try                    
  BEGIN CATCH                                                                               
   IF @@TRANCOUNT>0   
    ROLLBACK            
    EXECUTE USP_INSERTERRORINFO;                                             
   IF ERROR_NUMBER() = 1205 -- Deadlock Error Number                                  
   BEGIN                                                        
    WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms                                                 
    GOTO RETRYJD -- Go to Label RETRY                                                        
   END                                                                                     
  END CATCH              
          
 END          
          
 Else IF @apiname = 'IndiaMart'          
 BEGIN          
          
  Select @tablename= 'IndiamartLeads',@usermedium='Indiamart', @enqsource='IndiaMart API'          
          
  select @i = case when @rawleadid IS null then max(ID) else @rawleadid end from IndiamartLeads(nolock) where isprocessed=1    
 -- select @i,@rawleadid  
  RETRY:                    
  begin try                    
  begin tran                    
   insert into #tempenq (rno, id, PersonName, MobileNo,CountryCode,EmailID,MobileNo1,CountryCode1,EmailID1,CompanyName,OfficeAddress,ResidentialAddress, City,State,Country          
   ,InitialRemarks, ParentID,CreatedDate,CreatedBy,IsOpen,apikey)          
     
   output inserted.id as id into #ids  
     
   SELECT ROW_NUMBER() over (order by uere.ID) rno,                                          
   uere.ID,                                     
   isnull(nullif(ltrim(rtrim(uere.SENDERNAME)),'null'),'') PersonName,                                              
   case                               
   when charindex('-',mob,1)> 0 and isnumeric(RIGHT(mob,(len(mob)-charindex('-',mob,1))))=1                               
   then RIGHT(mob,(len(mob)-charindex('-',mob,1)))                               
   when isnumeric(REPLACE(MOB,ltrim(rtrim(m.CountryCode)),''))=1 and cast(REPLACE(MOB,ltrim(rtrim(m.CountryCode)),'') AS bigint)>0                              
   then REPLACE(MOB,ltrim(rtrim(m.CountryCode)),'') end MobileNo,                              
   case                               
   when charindex('-',mob,1)> 0 and isnumeric(RIGHT(mob,(len(mob)-charindex('-',mob,1))))=1                               
   then left(mob,charindex('-',mob,1)-1)                               
   when isnumeric(REPLACE(MOB,ltrim(rtrim(m.CountryCode)),''))=1 and cast(REPLACE(MOB,ltrim(rtrim(m.CountryCode)),'') as bigint)>0                              
   then  ltrim(rtrim(m.CountryCode)) end CountryCode,                              
   ISNULL(nullif(ltrim(rtrim(uere.senderemail)),'null'),'') as EmailID,                              
   case                               
   when charindex('-',mobile_alt,1)> 0 and isnumeric(RIGHT(mobile_alt,(len(mobile_alt)-charindex('-',mobile_alt,1))))=1                               
   then RIGHT(mobile_alt,(len(mobile_alt)-charindex('-',mobile_alt,1)))                               
   when isnumeric(REPLACE(mobile_alt,ltrim(rtrim(m.CountryCode)),''))=1 and cast(REPLACE(MOBILE_ALT,ltrim(rtrim(m.CountryCode)),'') as bigint)>0                              
   then REPLACE(mobile_alt,ltrim(rtrim(m.CountryCode)),'') end MobileNo1,                              
   case                               
   when charindex('-',mobile_alt,1)> 0 and isnumeric(RIGHT(mobile_alt,(len(mobile_alt)-charindex('-',mobile_alt,1))))=1                               
   then left(mobile_alt,charindex('-',mobile_alt,1)-1)                               
   when isnumeric(REPLACE(mobile_alt,ltrim(rtrim(m.CountryCode)),''))=1 and cast(REPLACE(MOBILE_ALT,ltrim(rtrim(m.CountryCode)),'') as bigint)>0                              
   then ltrim(rtrim(m.CountryCode)) end CountryCode1,                              
   ISNULL(nullif(ltrim(rtrim(uere.EMAIL_ALT)),'null'),'') as EmailID1,                              
   case when isnull(nullif(ltrim(rtrim(GLUSR_USR_COMPANYNAME)),'null'),'')<>'' then GLUSR_USR_COMPANYNAME else null end as CompanyName,         
   case when ISNULL(nullif(ltrim(rtrim(ENQ_ADDRESS)),'null'),'')<>'' and isnull(nullif(ltrim(rtrim(GLUSR_USR_COMPANYNAME)),'null'),'')<>'' then ENQ_ADDRESS end OfficeAddress,                              
   case when ISNULL(nullif(ltrim(rtrim(ENQ_ADDRESS)),'null'),'')<>'' and isnull(nullif(ltrim(rtrim(GLUSR_USR_COMPANYNAME)),'null'),'')='' then ENQ_ADDRESS end ResidentialAddress,                              
   case when nullif(ltrim(rtrim(ENQ_CITY)),'null') is not null then  substring(uere.ENQ_CITY,1,100) end City,                               
   case when nullif(ltrim(rtrim(enq_state)),'null') is not null then substring(uere.ENQ_State,1,100) end State,                              
   m.Country_Name,                              
   'Query Details: '                        
   +', For Product: '+cast(isnull(PRODUCT_NAME,'') as nvarchar)                              
   +', Message: '+cast(isnull(ENQ_MESSAGE,'')  as nvarchar)                               
   +', Subject: '+cast(isnull(Subject,'') as nvarchar)                              
   +', Query id: '+cast(isnull(QUERY_ID,'') as nvarchar)                              
   +', Query Type: '+cast(isnull(QTYPE,'') as nvarchar)                              
   +', Name: '+ cast (isnull(nullif(ltrim(rtrim(uere.SENDERNAME)),'null'),'') as nvarchar)                               
   +', Mobile: '+isnull(cast(isnull(mob,'') as nvarchar),'None')                              
   +', Alternate Mobile: '+isnull(cast(isnull(mobile_alt,'') as nvarchar),'None')                              
   +', Phone: '+isnull(cast(isnull(PHONE,'') as nvarchar),'None')                              
   +', Alternate Phone: '+isnull(cast(isnull(PHONE_ALT,'') as nvarchar),'None')                              
   +', Email: '+isnull(cast(isnull(senderemail,'') as nvarchar),'None')                              
   +', Alternate Email: '+isnull(cast(isnull(email_alt,'') as nvarchar),'None')                              
   +', Date: '+cast(isnull(DATE_TIME_RE,'') as nvarchar)                              
   +', Company: '+cast(isnull(nullif(ltrim(rtrim(GLUSR_USR_COMPANYNAME)),'null'),'None') as nvarchar)                              
   +', City: '+ cast(isnull(ENQ_CITY,'Not Mentioned') as nvarchar)                              
   +', State: '+cast(isnull(enq_State,'Not Mentioned') as nvarchar)                              
   +', Address: '+cast(isnull(ENQ_ADDRESS,'Not Mentioned') as nvarchar)                              
   +', Call Received By: '+cast(isnull(ENQ_RECEIVER_MOB,'Not Applicable') as nvarchar)                               
   +', Call Duration: '+cast(isnull(ENQ_CALL_DURATION,'Not Applicable') as nvarchar)                              
   +', Indiamart Key: '+ cast(isnull(uere.Indiamartkey,'') as nvarchar) as InitialRemarks,            
   j.Kit19ParentID,                                              
   DateReceived AS CreatedDate,                                    
   j.Kit19ParentId as parentid,                                    
   0  AS IsOpen, uere.INDIAMARTKEY  as apikey                                       
   FROM   indiamartleads(nolock)  AS uere                               
   join   IndiamartMapping(nolock) j on j.IndiamartId=uere.INDIAMARTKEY                                       
   left join m_country1 m on ltrim(rtrim(m.Shortname))=ltrim(rtrim(uere.COUNTRY_ISO))                              
   WHERE uere.IsProcessed = 0 
   and
   uere.isvalid = 1
   and uere.id >= @i             
     
   update i set isprocessed=2 from indiamartleads i join #ids d on d.id=i.id  
   --update indiamartleads set isprocessed=2 where id>@i   
  
  
   commit                    
  end try                    
  BEGIN CATCH                                                                               
   IF @@TRANCOUNT>0                                                                          
    ROLLBACK            
    EXECUTE USP_INSERTERRORINFO;                                             
   IF ERROR_NUMBER() = 1205 -- Deadlock Error Number                                  
   BEGIN                                                        
    WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms                                                 
    GOTO RETRY -- Go to Label RETRY                                                        
   END                                                                                     
  END CATCH                                                    
             
            
 END          
          
 Else IF @apiname = 'TradeIndia'          
 BEGIN          
  Select @tablename= 'TradeIndiaData',@usermedium='TradeIndia', @enqsource='TradeIndia API'           
  set  @i =(select case when @rawleadid IS null then max(ID) else @rawleadid end from TradeIndiaData (nolock) where isprocessed=1)            
  RETRYTrade:            
  begin try            
  begin tran                                          
             
   insert into #tempenq (rno, id, PersonName, MobileNo,CountryCode,EmailID,MobileNo1,CountryCode1,EmailID1,CompanyName,OfficeAddress,ResidentialAddress, City,State,Country,enquirysource          
   ,InitialRemarks, ParentID,CreatedDate,CreatedBy,IsOpen,apikey)          
  --declare @i int =1          
   output inserted.id as id into #ids  
     
   SELECT ROW_NUMBER() over (order by uere.ID) rno,                                              
   uere.ID,                                         
   isnull(nullif(ltrim(rtrim(uere.SENDER_NAME)),'null'),'') PersonName,                                                  
   case                                   
                           
   when isnumeric(REPLACE(ltrim(rtrim(uere.sender_mobile)),ltrim(rtrim(m.CountryCode)),''))=1 and cast(REPLACE(ltrim(rtrim(uere.sender_mobile)),ltrim(rtrim(m.CountryCode)),'') AS bigint)>0                                  
   then REPLACE(ltrim(rtrim(uere.sender_mobile)),ltrim(rtrim(m.CountryCode)),'') end MobileNo,                                  
                           
   case                                   
   when isnumeric(REPLACE(ltrim(rtrim(uere.sender_mobile)),ltrim(rtrim(m.CountryCode)),''))=1 and cast(REPLACE(ltrim(rtrim(uere.sender_mobile)),ltrim(rtrim(m.CountryCode)),'') as bigint)>0                                  
   then  ltrim(rtrim(m.CountryCode)) end CountryCode,                        
                                     
   ISNULL(nullif(ltrim(rtrim(uere.sender_email)),'null'),'') as EmailID,                                  
   case                                   
   when isnumeric(REPLACE(uere.sender_other_mobiles,ltrim(rtrim(m.CountryCode)),''))=1 and cast(REPLACE(uere.sender_other_mobiles,ltrim(rtrim(m.CountryCode)),'') as bigint)>0                              
   then REPLACE(uere.sender_other_mobiles,ltrim(rtrim(m.CountryCode)),'') end MobileNo1,                                  
                           
   case                                   
   when isnumeric(REPLACE(uere.sender_other_mobiles,ltrim(rtrim(m.CountryCode)),''))=1 and cast(REPLACE(uere.sender_other_mobiles,ltrim(rtrim(m.CountryCode)),'') as bigint)>0                                  
   then ltrim(rtrim(m.CountryCode)) end CountryCode1,                        
                                     
   ISNULL(nullif(ltrim(rtrim(uere.sender_other_emails)),'null'),'') as EmailID1,                        
                                     
   case when isnull(nullif(ltrim(rtrim(uere.sender_co)),'null'),'')<>'' then uere.sender_co else null end as CompanyName,                                  
   case when ISNULL(nullif(ltrim(rtrim(uere.address)),'null'),'')<>'' and isnull(nullif(ltrim(rtrim(uere.sender_co)),'null'),'')<>'' then uere.address end OfficeAddress,                  
   case when ISNULL(nullif(ltrim(rtrim(uere.address)),'null'),'')<>'' and isnull(nullif(ltrim(rtrim(uere.sender_co)),'null'),'')='' then uere.address end ResidentialAddress,                                  
   case when nullif(ltrim(rtrim(uere.sender_city)),'null') is not null then  substring(uere.sender_city,1,200) end City,                                   
  case when nullif(ltrim(rtrim(uere.sender_state)),'null') is not null then substring(uere.sender_state,1,200) end State,                                  
   m.Country_name,                        
   isnull(uere.source,'') as enquirysource                        
   ,                        
                                     
   'Query Details: '                            
   -- +', For Product: '+cast(uere.product_name as nvarchar)                                  
   --+', Product Source: '+cast(uere.product_source as nvarchar)                         
   --+', Quantity: '+cast(uere.quantity as nvarchar)                        
   --+', Supply_Location: '+cast(uere.pref_supp_location as nvarchar)                                  
   +'  Message: '+cast(uere.message  as nvarchar)                                   
   +', Subject: '+cast(uere.subject as nvarchar)                                  
   +', Query id: '+cast(uere.rfi_id as nvarchar)                                  
   +', Query Type: '+cast(uere.inquiry_type as nvarchar)                                  
   +', Name: '+ cast (isnull(nullif(ltrim(rtrim(uere.SENDER_NAME)),'null'),'') as nvarchar)                                   
   +', Mobile: '+isnull(cast(uere.sender_mobile as nvarchar),'None')                                  
   +', Alternate Mobile: '+isnull(cast(uere.sender_other_mobiles as nvarchar),'None')                                  
   +', Fax_Number: '+isnull(cast(uere.fax_number as nvarchar),'None')                                  
   +', Email: '+isnull(cast(uere.sender_email as nvarchar),'None')                               
   +', Alternate Email: '+isnull(cast(uere.sender_other_mobiles as nvarchar),'None')                            
   +', Generated Date: '+cast(uere.generated_date as nvarchar) + ' '+cast(uere.generated_time as nvarchar)                                   
   +', Company: '+cast(isnull(nullif(ltrim(rtrim(uere.sender_co)),'null'),'None') as nvarchar)                                  
   +', City: '+ cast(isnull(uere.sender_city,'Not Mentioned') as nvarchar)                                  
   +', State: '+cast(isnull(uere.sender_state,'Not Mentioned') as nvarchar)                                  
   +', Address: '+cast(isnull(uere.address,'Not Mentioned') as nvarchar)                                  
   +', Call Receiver Mobile: '+cast(isnull(uere.receiver_mobile,'Not Mentioned') as nvarchar)                        
   +', Call Received By: '+cast(isnull(uere.receiver_name,'Not Mentioned') as nvarchar)                                   
   +', Receiver Company: '+cast(isnull(uere.receiver_co,'Not Mentioned') as nvarchar)                                  
   +', TradeIndia Key: '+cast(uere.TradeIndiaKey as nvarchar)                        
   +', TradeIndia UserID: '+cast(uere.Trade_UserID as nvarchar)                        
   +', TradeIndia ProfileID: '+cast(uere.Trade_ProfileID as nvarchar)                        
   as InitialRemarks,j.Kit19ParentID,                                                  
   uere.DateReceived AS CreatedDate,                                        
   j.Kit19ParentId as parentid,                                        
   0  AS IsOpen ,uere.TradeIndiaKey                                          
   FROM   TradeIndiaData(nolock) AS uere                             
   join   TradeIndia_Mapping(nolock) j  on j.TradeIndia_Key = uere.TradeIndiaKey                                           
   left join m_country1(nolock) m on ltrim(rtrim(m.Country_Name))=ltrim(rtrim(uere.sender_country))                                  
   WHERE
      uere.IsProcessed = 0  and uere.isvalid=1 and
       uere.id>@i
        --uere.id = @i
             
   update i set isprocessed=2 from TradeIndiaData i join #ids d on d.id=i.id  
   --update TradeIndiaData set isprocessed=2 where id>@i                           
     
   commit            
  end try            
  BEGIN CATCH                                                                       
   IF @@TRANCOUNT>0                                                    
    ROLLBACK                                                             
    EXECUTE USP_INSERTERRORINFO;                                     
   IF ERROR_NUMBER() = 1205 -- Deadlock Error Number                          
