 BEGIN          
  Select @tablename= 'Acres99_Leads',@usermedium='99Acres', @enqsource='99Acres API'          
          
  select @i = case when @rawleadid IS null then isnull(max(ID),0) else @rawleadid end from Acres99_Leads(nolock) where isprocessed=1       
   
  RETRYAcres:              
  begin try              
  begin tran              
            
            
  insert into #tempenq (rno, id, PersonName, MobileNo,CountryCode,EmailID,CompanyName, OfficeAddress,ResidentialAddress          
  ,InitialRemarks, ParentID,CreatedDate,CreatedBy,IsOpen,apikey)          
   
   output inserted.id as id into #ids  
   
 SELECT ROW_NUMBER() over (order by uere.ID) rno,                                    
  uere.ID,                               
  isnull(nullif(ltrim(rtrim(isnull(uere.NAME,''))),'null'),'') PersonName,                                        
            
  RIGHT(isnull(uere.Phone,''),(len(isnull(uere.Phone,''))-charindex('-',isnull(uere.Phone,''),1))) MobileNo,          
  left(isnull(uere.Phone,''),charindex('-',isnull(uere.Phone,''),1)-1) CountryCode,          
            
  ISNULL(nullif(ltrim(rtrim(isnull(uere.Email,''))),'null'),'') as EmailID,                        
            
  case when isnull(nullif(ltrim(rtrim(isnull(uere.ProjName,''))),'null'),'')<>'' then uere.ProjName else '' end as CompanyName,                        
  case when ISNULL(nullif(ltrim(rtrim(isnull(uere.Address,''))),'null'),'')<>'' and isnull(nullif(ltrim(rtrim(isnull(uere.ProjName,''))),'null'),'')<>'' then Address  end as OfficeAddress,          
                            
   case when ISNULL(nullif(ltrim(rtrim(isnull(uere.Address,''))),'null'),'')<>'' and isnull(nullif(ltrim(rtrim(isnull(uere.ProjName,''))),'null'),'')='' then uere.Address  end  as ResidentialAddress,           
          
                          
  'Query 99Acres Details: '                  
  +', For Product: '+cast(isnull(ProdId,0) as nvarchar)                        
  +', Product type: '+cast(isnull(ProductType,0) as nvarchar)            
  +', Product status: '+cast(isnull(ProductStatus,1) as nvarchar)            
            
  +', PROPERTY_CODE: '+cast(isnull(PROPERTY_CODE,'') as nvarchar)            
  +', Acres_IDENTITY: '+cast(isnull(Acres_IDENTITY,'') as nvarchar)            
  +', ProjID: '+cast(isnull(ProjID,'') as nvarchar)          
  +', ProjName: '+cast(isnull(ProjName,'') as nvarchar)          
            
  +', PhoneVerificationStatus: '+cast(PhoneVerificationStatus as nvarchar)            
  +', EmailVerificationStatus: '+cast(EmailVerificationStatus as nvarchar)           
            
            
  +', Message: '+cast(isnull(uere.QryInfo,'')  as nvarchar)                         
  +', Subject: '+cast(isnull(uere.SubUserName,'') as nvarchar)            
                        
  +', Query id: '+cast(isnull(uere.QueryID,'') as nvarchar)                        
  +', Res Type: '+cast(isnull(uere.ResType,'') as nvarchar)                        
            
  +', Name: '+ cast (isnull(nullif(ltrim(rtrim(uere.NAME)),'null'),'') as nvarchar)                         
  +', Mobile: '+isnull(cast(uere.Phone as nvarchar),'None')                        
            
  +', Email: '+isnull(cast(uere.Email as nvarchar),'None')                        
            
  +', Date: '+cast(uere.RcvdOn as nvarchar)                        
  +', Company: '+cast(isnull(nullif(ltrim(rtrim(isnull(uere.ProjName,''))),'null'),'None') as nvarchar)                        
            
  +', Address: '+cast(isnull(isnull(uere.Address,''),'Not Mentioned') as nvarchar)           
            
  +', 99Acress UserName: '+cast(isnull(uere.Acres_Username,'') as nvarchar) as InitialRemarks,          
            
   j.Kit19ParentID,                                        
   uere.RcvdOn  AS CreatedDate,                              
  j.Kit19ParentId as parentid,                              
  0  AS IsOpen,uere.Acres_UserName                                        
  FROM   Acres99_Leads (nolock)  AS uere                         
  join   Acres99_Mapping(nolock) j on j.Acres_UserName=uere.Acres_UserName                                 
    -- left join m_country1 m on ltrim(rtrim(m.Shortname))=ltrim(rtrim(uere.COUNTRY_ISO))                        
   WHERE  uere.IsProcessed = 0  and uere.isvalid=1 and uere.id > @i    
        --uere.id = @i
   update i set isprocessed=2 from Acres99_Leads i join #ids d on d.id=i.id  
  
   --update Acres99_Leads set isprocessed=2 where id>@i                  
    
  commit              
  end try              
  BEGIN CATCH                                                                         
  IF @@TRANCOUNT>0                                                                    
  ROLLBACK                                                               
  EXECUTE USP_INSERTERRORINFO;                                       
  IF ERROR_NUMBER() = 1205 -- Deadlock Error Number                            
  BEGIN                                                  
  WAITFOR DELAY '00:00:00.05' -- Wait for 5 ms                                           
  GOTO RETRYAcres -- Go to Label RETRY                                                  
  END                                                                               
  END CATCH                                              
 END          
      
