  begin tran              
        --select 1    
  Select  @i id, PersonName, isnull(MobileNo1,MobileNo) as MobileNo, CountryCode,EmailID,City,State,@parentid parentid, @createdate createdate,@parentid createdby,0 IsOpen, SourceName Src, MediumName Med into #tp from OpenJson(@datajson)   
 With(  
 PersonName nvarchar(max) '$.PersonName',  
 MobileNo nvarchar(max) '$.MobileNo',  
 MobileNo1 nvarchar(max) '$.MobileNo1', 
 CountryCode nvarchar(max) '$.CountryCode',  
 EmailID nvarchar(max) '$.EmailID',  
 City nvarchar(max) '$.City',  
 State nvarchar(max) '$.State',  
 SourceName nvarchar(max) '$.SourceName',  
 MediumName Nvarchar(max) '$.MediumName'  
 )  
   
 --select * from #tp  
  
 insert into #tempenq (rno, id, PersonName, MobileNo,CountryCode,EmailID,City,State ,ParentID,CreatedDate,CreatedBy,IsOpen,apikey,shiSrc,shimed)   
 select ROW_NUMBER() over(order by id) rno, id,   
 isnull(nullif(ltrim(rtrim(PersonName)),'null'),'') PersonName ,   
 MobileNo, CountryCode, EmailID, City, State , ParentID, createdate, CreatedBy, IsOpen, ParentID, Src, Med  from #tp        
           
  commit              
  end try              
  BEGIN CATCH                                                                         
