 Else IF @apiname = 'Taxo'            
 BEGIN           
 Declare @datajson_Taxo nvarchar(max)    
  Select @tablename= 'tbl_GetJsonData',@usermedium='TaxoApi', @enqsource='Taxo'         
      
 Declare @createdate_Taxo datetime    
 select @i = @rawleadid     
 select @datajson_Taxo=JObjectJson , @ParentID=ParentID, @createdate_Taxo=CreatedOn from tbl_GetJsonData (nolock) where Id=@i and isprocessed=0     
    
  RETRYTaxo:                
  begin try                
  begin tran                
     
     
   select top 1 @CountryCode_User = countrycode from user_detail with(nolock) where user_id = @parentid  
  
  Select  @i id, first_name + ' ' + last_name as PersonName, @CountryCode_User as  CountryCode,phone as MobileNo, email as EmailID   
  , state as State , city as City,country as Country ,@parentid parentid, @createdate_Taxo createdate,@parentid createdby    
          ,0 IsOpen, @enqsource as  Src, zip_code as pincode ,user_name ,  company_name as CompanyName, address_1 , address_2  
    into #tp_Taxo from OpenJson(@datajson_Taxo)     
 With(    
 first_name nvarchar(max) '$.first_name',  
 last_name nvarchar(max) '$.last_name',  
 --CountryCode nvarchar(max) '$.CountryCode',    
 phone nvarchar(max) '$.phone',    
 email nvarchar(max) '$.email',    
 state nvarchar(max) '$.state',    
 city nvarchar(max) '$.city',  
 --Source nvarchar(max) '$.Source' ,   
  country nvarchar(max) '$.country',  
  zip_code nvarchar(max) '$.zip_code',  
  user_name nvarchar(max) '$.user_name',  
  company_name nvarchar(max) '$.company_name',  
  address_1 nvarchar(max) '$.address_1',  
  address_2 nvarchar(max) '$.address_1'  
  
 )    
 --select * from #tp_CollegeDunia    
 insert into #tempenq (rno, id, PersonName, MobileNo,CountryCode,EmailID,State,City,Country,ParentID,CreatedDate,CreatedBy,IsOpen,apikey,shiSrc,InitialRemarks  
 ,pincode , OfficeAddress, ResidentialAddress,CompanyName )     
 select ROW_NUMBER() over(order by id) rno, id,     
 isnull(nullif(ltrim(rtrim(PersonName)),'null'),'') PersonName ,  
 MobileNo, CountryCode, EmailID , State, City,Country, ParentID, createdate, CreatedBy, IsOpen, ParentID, Src,    
 'user_name: ' + isnull(user_name,'')  as InitialRemarks, pincode,address_1,address_2,CompanyName  from #tp_Taxo   
                 where   
           (  
          (  
        1 =  case when  CountryCode = '+91'  and len(isnull(MobileNo,'')) = 10  
                  then 1    
               when CountryCode != '' and CountryCode != '+91' and len(isnull(MobileNo,'')) >= 5 and len(isnull(MobileNo,'')) <= 15  
            then 1  
            else 0  
         end  
        )  
           or   
  
                          ( 1 = case when isnull(EmailID,'') != '' and  EmailID  LIKE '_%@__%.__%'  
