   begin  
    set @alterTempColumn = concat(' alter table #tempenq add [', @enquir_col_name, '] nvarchar(255) ')  
    execute sp_executesql @alterTempColumn  
   end  
  
   set @sqlJsonFetch = concat('update #tempenq set  ', @enquir_col_name, ' = json_value(N''',    
     @datajson_Wix, ''', ''$.', @wix_field_path,''') where id = ', @i)  
  
   print @sqlJsonFetch  
   execute sp_executesql @sqlJsonFetch  
  end try  
  begin catch  
   print error_message()  
  end catch  
  update #tempWixEnquiry set isproccessed = 1 where Sno =@Sno  
  select @Sno = 0, @country_code = '',  @wix_field_name = '', @wix_field_path = '',  
   @enquir_col_name = '', @sqlJsonFetch = '', @alterTempColumn = ''  
