      DROP TABLE IF EXISTS #temp3               
                   
 declare @ii int = 1 ,@aas nvarchar(max)   
 create table #temp3 (field_ID nvarchar(max),datatype varchar(2),value nvarchar(max), status nvarchar(max))  
  --select @aas= STRING_AGG(''''+value+'''',',') from dbo.fn_Split((select value from #custtp),',')  
   select @aas= STRING_AGG(''''+value+'''',',')   from #custtp   
  
set @sql=N'INSERT INTO #temp3  
 SELECT cf.field_ID,cf.datatype,tp.value, (case                
  when cf.datatype = ''f''                 
   then IIF(CAST(TP.value AS BIGINT) >= ISNULL(CAST(cf.minvalue as  BIGINT),-2222222222222222) AND CAST(TP.value AS BIGINT) <= ISNULL (CAST(cf.maxvalue as BIGINT),2222222222222222),1,0)                
  when cf.datatype = ''d''                 
  then IIF(CAST(TP.value AS date) >= CAST(ISNULL (cf.minvalue,'''') as date) and                
  CAST(TP.value AS date) <= IIF ( ISNULL(cf.maxvalue,'''') <> '''', cast(cf.maxvalue as date),cast (''9999-01-01''as date)) ,1,0)                
  when cf.datatype in (''r'',''s'',''l'') and cf.choices is not null                 
   then IIF('+cast(@ii as varchar)+' = (select distinct 1 from dbo.fn_Split(cf.choices,'','') splt where CAST(splt.value AS nvarchar(max)) in ('+@aas+')),1,0)                
  when cf.datatype in (''r'',''s'',''l'') and  cf.choices IS NULL                
   then 1                
  when cf.datatype in (''m'',''c'',''v'')                
   then 1                
   else 0 end ) as [status]             
 FROM #custtp tp (nolock)                
  join tbl_ApiCustomFieldMapping acfm (nolock) on cast( tp.fieldid as varchar) = cast(acfm.Field_id as varchar)                
  join customfields cf (nolock) on cast(cf.field_ID as varchar) = cast(acfm.Field_id as varchar)           
  where acfm.ApiKey='''+@apikey+'''          
  AND acfm.ParentId = '+cast (@ParentID   as varchar)  
  
  --print @sql  
  exec sp_executesql @sql  
 -- select * from #temp3  
 --select *, 'temp3' from #temp3     
 --select *,'custtp' from #custtp  
                    
 if  exists( select distinct 1 from #temp3 (NOLOCK) where status = 0 )                    
