           -- select '1'  
  insert into ErrorLogApiCustomField (ApiDataId,ApiName,ApiKey,Fieldid,FieldName,ErrorMsg, UserId,EntryDate,FieldValue)                    
  Select @rawleadid,@apiname,@apikey,field_ID,                    
         (CASE datatype                        
             WHEN 'd'                        
           THEN 'Date'                        
           WHEN 'f'                        
           THEN 'Numeric'                        
           WHEN 'v'                        
           THEN 'Text'                        
           WHEN 'r'                        
           THEN 'Radio'                        
           WHEN 'm'                        
           THEN 'Multiline'                        
           WHEN 's'                        
           THEN 'Select'                        
           WHEN 'c'                        
           THEN 'Checkbox'                            
           WHEN 'l'                        
           THEN 'List'                    
          END) AS FieldType,                    
          (CASE datatype                    
           WHEN 'd'                        
           THEN 'Date not in Custom Field Range'                        
           WHEN 'f'                        
           THEN 'Number not in Custom Field Range'                           
           WHEN 'r'                        
           THEN 'Value not matches with Custom Field Choices'                            
           WHEN 's'                        
           THEN 'Value not matches with Custom Field Choices'                        
           WHEN 'c'                        
           THEN 'Value not matches with  Custom Field Choices'                        
           WHEN 'l'                        
           THEN 'Value not matches with Custom Field Choices'                     
           else 'Wrong Input Value'                    
          END) AS ErrorMsg,                    
          @ParentID,getdate(),value                  
    from #temp3  (NOLOCK)                  
    where status = 0                      
  end                     
