   begin  
    Select top 1 @source=CampaignID from UserCampaignSettings (nolock) where name=@value and UserID=@ParentID  
    SELECT @sql = 'UPDATE UserEnquiry SET ' + @fieldname + ' = ' +CAST( @source as varchar) + ' where EnquiryID= ' + cast(@enquiryid AS VARCHAR)  
   end  
   else  
   begin  
    SELECT @sql = 'UPDATE UserEnquiry SET ' + @fieldname + ' = ''' +CAST( @value as varchar) + ''' where EnquiryID= ' + cast(@enquiryid AS VARCHAR)  
    --print  @sql+' -- '+@fieldname+'--'+ @value  
    end  
   EXEC sp_executesql @sql   
   END  
     END          
      set @min = @min + 1          
    END          
          
    if(exists (select 1 from #custtp))  
 begin  
    begin try  
        INSERT INTO customfieldEnquiryvalue ( EnquiryID, fieldID, fieldvalue ) Select  @EnquiryID, fieldid, cast(value as nvarchar) as value from #custtp (NOLOCK)   
    end try  
    begin catch  
      exec usp_inserterrorinfo  
    end catch  
 end          
         
    seT @AutoLeadDistribution = isnull((select isnull(AutoLeadDistribution,0) FROM   CRMCampaignSettings (nolock)  WHERE  UserID = @ParentID),0)    
 --select @AutoLeadDistribution,'auto'  
   
    begin try                
   -- begin tran    
 CREATE TABLE #temp (  leadno BIGINT, countrycode NCHAR(100), mobile VARCHAR(100), email VARCHAR(100) )          
     insert into #temp(leadno,countrycode,mobile,email)   
  select leadno,countrycode,mobile,email from Userleads_Mobile_Email(nolock)  where ParentID=@ParentID     
    
  /*  
     select leadno,isnull(CountryCode,'0'),isnull(mobileno,'0'),'1' from UserLeads(nolock) where ParentID=@ParentID                            
     union                            
     select leadno,isnull(CountryCode1,'0'),isnull(mobileno1,'0'),'1' from UserLeads(nolock) where ParentID=@ParentID               
     union                            
     select leadno,isnull(CountryCode2,'0'),isnull(mobileno2,'0'),'1' from UserLeads(nolock) where ParentID=@ParentID                            
     union                            
     select leadno,'0','0',isnull(nullif(emailid,''),'1') from UserLeads(nolock) where ParentID=@ParentID                            
     union                            
     select leadno,'0','0',isnull(nullif(emailid2,''),'1') from UserLeads(nolock) where ParentID=@ParentID                            
     union                            
     select leadno,'0','0',isnull(nullif(emailid2,''),'1') from UserLeads(nolock) where ParentID=@ParentID                               
    */  
 set @leadn1 = isnull(                  
       (select top 1 t.leadno from #temp t join #TempEnq e on                  
         (                  
       ( cast( isnull(dbo.fn_ltrimrtrim(e.CountryCode),'2') as nvarchar(20)) + cast( ISNULL(dbo.fn_ltrimrtrim(e.MobileNo),'2') as nvarchar(100))=cast(dbo.fn_ltrimrtrim(t.countrycode) as nvarchar(20)) + cast(dbo.fn_ltrimrtrim(t.mobile) as nvarchar(100)) )
                                     
          or (isnull(nullif(dbo.fn_ltrimrtrim(e.EmailID),''),'3')=dbo.fn_ltrimrtrim(t.email))                 
       /*                
         (isnull(e.CountryCode,'2') + ISNULL(e.MobileNo,'2')= cast(t.countrycode as nvarchar)+cast(t.mobile as nvarchar) )                       
            or (isnull(nullif(e.EmailID,''),'3')=t.email)                  
          */                
       ) and e.rno = @Crno                   
        )                  
      ,0)            
   /*  
     insert into #temp(leadno,countrycode,mobile,email)                            
     select leadno,isnull(CountryCode,'0'),isnull(mobileno,'0'),'1' from UserLeads where ParentID=@ParentID                            
     union                            
   select leadno,isnull(CountryCode1,'0'),isnull(mobileno1,'0'),'1' from UserLeads where ParentID=@ParentID                            
     union                            
     select leadno,isnull(CountryCode2,'0'),isnull(mobileno2,'0'),'1' from UserLeads where ParentID=@ParentID                            
     union                            
     select leadno,'0','0',isnull(nullif(emailid,''),'1') from UserLeads where ParentID=@ParentID                            
     union                            
     select leadno,'0','0',isnull(nullif(emailid2,''),'1') from UserLeads where ParentID=@ParentID                            
     union                            
     select leadno,'0','0',isnull(nullif(emailid2,''),'1') from UserLeads where ParentID=@ParentID                               
     set @leadn1 = isnull(                  
       (select top 1 t.leadno from #temp t join #TempEnq e on                  
         (                  
       (isnull(dbo.fn_ltrimrtrim(e.CountryCode),'2') + ISNULL(dbo.fn_ltrimrtrim(e.MobileNo),'2')=cast(dbo.fn_ltrimrtrim(t.countrycode) as nvarchar)+cast(dbo.fn_ltrimrtrim(t.mobile) as nvarchar) )                                     
          or (isnull(nullif(dbo.fn_ltrimrtrim(e.EmailID),''),'3')=dbo.fn_ltrimrtrim(t.email))                 
       /*                
         (isnull(e.CountryCode,'2') + ISNULL(e.MobileNo,'2')= cast(t.countrycode as nvarchar)+cast(t.mobile as nvarchar) )                       
            or (isnull(nullif(e.EmailID,''),'3')=t.email)                  
          */                
       ) and e.rno = @Crno                   
        )                  
      ,0)                            
            */                     
	if (@AutoLeadDistribution = 1 and @leadn1=0)                                  
	begin                                  
         
		declare @returnAgentId bigint  
		exec udf_GetAgentToAssigned @ParentId = @ParentID, @AgentId = @returnAgentId output   --select @returnAgentId    
   
		declare @CurrentDatetime datetime = getdate() ;          
		SET Context_Info 0x55555  
  
		begin try  
		begin transaction  
  
			Set @leadid=0
			select @leadid=UL.ID from UserLeads(nolock) UL inner join userenquiry(nolock) UE ON UL.ParentID=UE.ParentID and UE.enquiryid=@EnquiryID where UL.ParentID = @ParentID and (isnull(UE.MobileNo,'') in (nullif(UL.MobileNo,''),nullif(UL.MobileNo1,''),nullif(UL.MobileNo2,'')) or isnull(UE.EmailID,'') in (nullif(UL.EmailID,''),nullif(UL.EmailID1,''),nullif(UL.EmailID2,'')))

			if isnull(@leadid,0)=0 
			Begin
				set @Leadn1 = isnull((select MAX(LeadNo) FROM   UserLeads with (UPDLOCK,HOLDLOCK) WHERE  ParentID = @ParentID),0)+1        

				Insert into userleads (LeadNo, PersonName, MobileNo, EmailID, City, State, Country, PinCode, CountryCode, AssignedTo, SourceName, ParentID, mediumname, CampaignName,
				InitialRemarks, CreatedOn, CreatedBy, OfficeAddress, ResidentialAddress, enquirysource, LastFollowupCreatedBy, LastFollowupCreatedOn)                                      
				select @leadn1, substring(PersonName,1,100), MobileNo, EmailID, City, State, Country, PinCode, CountryCode, @returnAgentId, SourceName, ParentID, mediumname, CampaignName,
				InitialRemarks, @CurrentDatetime, CreatedBy, OfficeAddress, ResidentialAddress, enquirysource, CreatedBy, @CurrentDatetime
				from userenquiry(nolock) where enquiryid=@EnquiryID

				Set @leadid  = SCOPE_IDENTITY()
			end
          
		commit   
		end try  
		begin catch  
			IF @@TRANCOUNT>0                                                                  
					ROLLBACK                                                             
				EXECUTE USP_INSERTERRORINFO;       
		end catch  
  
		If(@leadn1 > 0)
		Begin
			INSERT INTO customfieldLeadvalue (leadid,  fieldID, fieldvalue )    
			Select  @leadid, fieldid, cast(value as nvarchar) as value  from #custtp (NOLOCK)   
    
			set @isleadcreated=1    
  
			if not exists(select 1 from tbl_MergeLeadsEnquiry(nolock) where EnquiryNo=@EnquiryID and leadno=@leadn1)                
			begin                
				insert into  tbl_MergeLeadsEnquiry(EnquiryNo ,LeadNo,IsOpen) 
				values (@EnquiryID,@Leadn1,case when @isleadcreated=1 then 0 else 1 end)           
				exec usp_ims_UpgradeEnquiryToLead @EnquiryID             
			end      
    
			Exec MySms.dbo.usp_ExecLeadTriggerTasks @leadid  
     
			insert into LeadInteractionHistory(LeadNo,FollowUpStatus,NextStatusDate,Remarks,Products,AmountPaid,AssignedTo,      
			ParentID,CreatedOn,CreatedBy,FollowupDate,IsReassign,id_lead)      
			select LeadNo,FollowUpStatus,NextStatusDate,Remarks,Products,AmountPaid,AssignedTo,      
			ParentID,CreatedOn,CreatedBy,FollowupDate,0,id from userleads u (nolock) where ID = @leadid  
    
			select @LIHID=SCOPE_IDENTITY()  
			Exec MySms.dbo.usp_ExecLeadInteractionTriggerTasks @LIHID  
  
			update UserEnquiry  set LeadNo=case when @LeadN1<>0 then @leadn1 else null end, IsOpen= case when @isleadcreated=1 then 0 else 1 end where EnquiryID=@EnquiryID   
			-- exec Usp_insertdefaultfollowup @parentid,@leadid+  
  
			SET Context_Info 0x    
		End
		/*                                
		Insert into userleads (LeadNo,PersonName,MobileNo,EmailID,City,PinCode,CountryCode,                                  
		AssignedTo,SourceName,ParentID,mediumname,CampaignName,                               
		InitialRemarks,CreatedOn,CreatedBy)                                      
		select @leadn1,substring(PersonName,1,100),MobileNo,EmailID,City,PinCode,CountryCode,                                  
		(select top 1 value from fn_Split((select agents from CRMCampaignSettings where userid=@ParentID),'#')    ORDER BY NEWID                             
		()),SourceName,ParentID,mediumname,CampaignName,InitialRemarks,GETDATE(),CreatedBy                             
		from userenquiry(nolock) where enquiryid=@EnquiryID                
		--from #TempEnq where rno = @Crno                                   
			*/                  
    
	end      --endif autoleaddistribution
	else  
	begin  
      update UserEnquiry  set IsOpen= 1 where EnquiryID=@EnquiryID       
	end  
     --commit     
  drop table if exists #temp  
    end try                
    begin catch    
 --Rollback  
  SET Context_Info 0x    
     exec usp_inserterrorinfo                
  drop table if exists #temp  
    end catch                   
                                                   
               
          
    set @updlead = 'UPDATE '+ @tablename+' SET '+ @isprocessed+' = 1  ,EnquiryId='+cast(@EnquiryID as varchar)+' ,Processederror=@sts ,Processeddate=@date          
        WHERE  ID ='+cast(@rawEnquiryID as varchar)          
     
    begin try  
   print @updlead  
     
    execute sp_executesql @updlead, N'@sts varchar(10),@date datetime',@sts,@date          
 --Select 'Sucess'  
   end try   
   begin catch  
 exec usp_inserterrorinfo  
 end catch  
     
   drop table if exists #temp   
   
    END          
            
  END          
	set @Crno = @Crno+1            
   END -- while end    
     
 END     
       drop table if exists #ids  
  
END          



GO

/* ============================================================
   Procedure: [dbo].[usp_TransferRawEntriestoEnquiries]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_TransferRawEntriestoEnquiries]            
AS            
BEGIN    
declare @isleadcreated int=0 ,@leadid bigint       
 SELECT ROW_NUMBER() over (order by uere.EnquiryID) rno,        
  uere.EnquiryID,            
        substring(uere.PersonName,1,100) PersonName,            
         substring(uere.CompanyName,1,100) CompanyName,            
        uere.MobileNo,            
        uere.MobileNo1,            
        uere.MobileNo2,            
        uere.EmailID,            
        uere.EmailID1,            
        uere.EmailID2,            
        substring(uere.City,1,100) City,      
        substring(uere.State,1,100) [State],            
        substring(uere.Country,1,100) Country,          
        (case when isnull(uere.MobileNo,'')='' then '' else uere.CountryCode end) as CountryCode ,           
        (case when isnull(uere.MobileNo1,'')='' then '' else uere.CountryCode1 end) as CountryCode1,          
        (case when isnull(uere.MobileNo2,'')='' then '' else uere.CountryCode2 end) as CountryCode2,           
        --uere.CountryCode,            
       -- uere.CountryCode1,            
        --uere.CountryCode2,            
        uere.PinCode,      
        substring(uere.ResidentialAddress,1,500) ResidentialAddress,            
        substring(uere.OfficeAddress,1,500) OfficeAddress,            
        uere.SourceName,            
        uere.MediumName,            
        uere.CampaignName,            
        uere.InitialRemarks,            
        uere.ParentID,            
        GETDATE()              AS CreatedDate,            
        uere.CreatedBy,            
        1  AS IsOpen INTO #TempEnq            
 FROM   UserEnquiryRawEntries  AS uere (nolock)           
 WHERE  uere.IsValid = 1            
        AND uere.IsTransfered = 0         
             
        
 --------------------------        
 declare @Crno bigint = 0;        
 declare @maxno bigint = 0;        
 select @maxno = MAX(rno), @Crno = MIN(rno) from #TempEnq        
 declare @leadn1 as bigint  = 0        
 declare @ParentID bigint = 0;        
          
  declare @MobileNo nvarchar(max)  =''         
        declare @MobileNo1 nvarchar(max)  =''           
        declare @MobileNo2 nvarchar(max)  =''            
        declare @EmailID nvarchar(max)  =''            
        declare @EmailID1 nvarchar(max)  =''            
        declare @EmailID2 nvarchar(max)  =''            
               
        declare @CountryCode  nvarchar(max)  =''           
        declare @CountryCode1 nvarchar(max)  =''          
        declare @CountryCode2 nvarchar(max)  =''        
 create table #temp(leadno bigint,countrycode nchar(10),mobile varchar(100),email varchar(100))        
 declare @EnquiryID bigint,@rawEnquiryID bigint        
 declare @AutoLeadDistribution bit =0        
while @Crno <= @maxno        
begin        
select @leadn1=0,@leadid=0        
select @ParentID = ParentID, @CountryCode= CountryCode, @CountryCode1=CountryCode1,        
    @CountryCode2=CountryCode2, @MobileNo= MobileNo, @MobileNo1=MobileNo1,        
    @MobileNo2= MobileNo2,@EmailID= EmailID, @EmailID1= EmailID1,        
    @EmailID2=EmailID2  FROM   #TempEnq  WHERE  rno = @Crno            
         
insert into #temp(leadno,countrycode,mobile,email) 
select leadno,countrycode,mobile,email from Userleads_Mobile_Email(nolock)  where ParentID=@ParentID        
/*      
select leadno,isnull(CountryCode,'0'),isnull(mobileno,'0'),'1' from UserLeads where ParentID=@ParentID        
union        
select leadno,isnull(CountryCode1,'0'),isnull(mobileno1,'0'),'1' from UserLeads where ParentID=@ParentID        
union        
select leadno,isnull(CountryCode2,'0'),isnull(mobileno2,'0'),'1' from UserLeads where ParentID=@ParentID        
union        
select leadno,'0','0',isnull(emailid,'1') from UserLeads where ParentID=@ParentID        
union        
select leadno,'0','0',isnull(emailid1,'1') from UserLeads where ParentID=@ParentID        
union        
select leadno,'0','0',isnull(emailid2,'1') from UserLeads where ParentID=@ParentID           
*/
set @leadn1 = isnull((select top 1 t.leadno from #temp t join #TempEnq e on (  
(isnull(dbo.fn_ltrimrtrim(e.CountryCode),'2') + ISNULL(dbo.fn_ltrimrtrim(e.MobileNo),'2')=dbo.fn_ltrimrtrim(t.countrycode)+dbo.fn_ltrimrtrim(t.mobile) )   
or (isnull(dbo.fn_ltrimrtrim(e.CountryCode1),'2') + ISNULL(dbo.fn_ltrimrtrim(e.MobileNo1),'2')=dbo.fn_ltrimrtrim(t.countrycode)+dbo.fn_ltrimrtrim(t.mobile) )   
or (isnull(dbo.fn_ltrimrtrim(e.CountryCode2),'2') +  ISNULL(dbo.fn_ltrimrtrim(e.MobileNo2),'2')=dbo.fn_ltrimrtrim(t.countrycode)+dbo.fn_ltrimrtrim(t.mobile) )   
or (isnull(dbo.fn_ltrimrtrim(e.EmailID),'3')=dbo.fn_ltrimrtrim(t.email))   
or (isnull(dbo.fn_ltrimrtrim(e.EmailID1),'3')=dbo.fn_ltrimrtrim(t.email))   
or (isnull(dbo.fn_ltrimrtrim(e.EmailID2),'3')=dbo.fn_ltrimrtrim(t.email))) WHERE  rno = @Crno ),0)        
       
          
        
 INSERT INTO UserEnquiry            
   (            
     PersonName,            
     CompanyName,            
     MobileNo,            
     MobileNo1,            
     MobileNo2,            
     EmailID,            
     EmailID1,            
     EmailID2,            
     City,            
     [State],            
     Country,            
  CountryCode,            
     CountryCode1,            
     CountryCode2,            
     PinCode,            
     ResidentialAddress,            
     OfficeAddress,            
     SourceName,            
     MediumName,            
     CampaignName,            
     InitialRemarks,            
     ParentID,            
     CreatedDate,            
     CreatedBy,            
     IsOpen,        
     LeadNo           
   )            
 SELECT PersonName,            
        CompanyName,            
        MobileNo,            
        MobileNo1,            
        MobileNo2,            
        EmailID,            
        EmailID1,            
        EmailID2,            
        City,            
        State,            
        Country,            
        CountryCode,            
        CountryCode1,            
        CountryCode2,            
        PinCode,            
        ResidentialAddress,            
        OfficeAddress,            
        SourceName,            
        MediumName,            
        CampaignName,            
        InitialRemarks,            
        ParentID,            
        CreatedDate,            
        CreatedBy,            
        IsOpen,        
        @leadn1            
 FROM   #TempEnq where rno = @Crno           
  set @EnquiryID=SCOPE_IDENTITY()    
  select @rawEnquiryID= EnquiryID FROM   #TempEnq where rno = @Crno    
      
  insert into parsedenquiries(rawenquiryid,enquiryid,parentid)    
  select @rawenquiryid,@enquiryid,@parentid          
              
seT @AutoLeadDistribution = isnull((select isnull(AutoLeadDistribution,0) FROM   CRMCampaignSettings(nolock)  WHERE  UserID = @ParentID),0)        
        
if (@AutoLeadDistribution = 1 and @leadn1=0)              
  begin              
  set @Leadn1 = isnull((select MAX(LeadNo)                                 
  FROM   UserLeads(nolock) WHERE  ParentID = @ParentID),0)+1              

  declare @returnAgentId bigint,@lihid bigint
   exec udf_GetAgentToAssigned @ParentId = @ParentID, @AgentId = @returnAgentId output   --select @returnAgentId  
 
    SET Context_Info 0x55555
  
    
  Insert into userleads (LeadNo,PersonName,MobileNo,EmailID,City,PinCode,CountryCode,                    
  AssignedTo,SourceName,ParentID,mediumname,CampaignName,                    
  InitialRemarks,CreatedOn,CreatedBy,OfficeAddress,ResidentialAddress)                        
  select @leadn1,substring(PersonName,1,100),MobileNo,EmailID,City,PinCode,CountryCode,                    
  (select top 1 value from fn_Split((select agents from CRMCampaignSettings where userid=@ParentID),'#')    ORDER BY NEWID               
()),SourceName,ParentID,mediumname,CampaignName,InitialRemarks,GETDATE(),CreatedBy,OfficeAddress,ResidentialAddress               
from userenquiry(nolock) where enquiryid=@EnquiryID  
select @leadid=scope_identity()

Exec MySMS.dbo.usp_ExecLeadTriggerTasks @leadid
	  
  set @isleadcreated   =1    

  insert into LeadInteractionHistory(LeadNo,FollowUpStatus,NextStatusDate,Remarks,Products,AmountPaid,AssignedTo,    
  ParentID,CreatedOn,CreatedBy,FollowupDate,IsReassign)    
  select LeadNo,FollowUpStatus,NextStatusDate,Remarks,Products,AmountPaid,AssignedTo,    
  ParentID,CreatedOn,CreatedBy,FollowupDate,0 from userleads u (nolock) where ID = @leadid
  
  select @LIHID=SCOPE_IDENTITY()
  Exec MySMS.dbo.usp_ExecLeadInteractionTriggerTasks @LIHID

  --exec Usp_insertdefaultfollowup @parentid,@leadid
   SET Context_Info 0x                   


/*
set @isleadcreated=1

exec Usp_insertdefaultfollowup @parentid,@leadid
            
  Insert into userleads (LeadNo,PersonName,MobileNo,EmailID,City,PinCode,CountryCode,              
  OfficeAddress,AssignedTo,SourceName,MediumName,CampaignName,ParentID,              
  Remarks,CreatedOn,CreatedBy)                    
  select @leadn1,substring(PersonName,1,100),MobileNo,EmailID,'','','+91',      
  substring(OfficeAddress,1,500),              
  (select top 1 value from fn_Split((select agents from CRMCampaignSettings where userid=@ParentID),'#')    ORDER BY NEWID         
()),SourceName,MediumName,'',@ParentID,'',GETDATE(),@ParentID         
  from #TempEnq where rno = @Crno               
  */  
end    
  
update UserEnquiry  set LeadNo=case when @LeadN1<>0 then @leadn1 else null end, 
IsOpen= case when @isleadcreated=1 then 0 else 1 end where EnquiryID=@EnquiryID         
insert into  tbl_MergeLeadsEnquiry(EnquiryNo ,LeadNo,IsOpen) 
values (@EnquiryID,@Leadn1,case when @isleadcreated=1 then 0 else 1 end)
               
UPDATE UserEnquiryRawEntries            
SET    IsTransfered = 1  ,userenquiryid=@EnquiryID          
WHERE  EnquiryID IN (SELECT EnquiryID FROM   #TempEnq  where rno = @Crno)                  
      
        
truncate table #temp        
set @Crno = @Crno+1        
END           
             
DROP TABLE #TempEnq            
END


GO

/* ============================================================
   Procedure: [dbo].[usp_TransferRawEntriestoEnquiries1]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

--sp_helptext usp_TransferRawEntriestoEnquiries  
--sp_helptext UspInsertUserEnquiryDetails  
CREATE   PROCEDURE [dbo].[usp_TransferRawEntriestoEnquiries1]      
AS      
BEGIN
 declare @isleadcreated int=0      
 SELECT ROW_NUMBER() over (order by uere.EnquiryID) rno,  
  uere.EnquiryID,      
        uere.PersonName,      
        uere.CompanyName,      
        uere.MobileNo,      
        uere.MobileNo1,      
        uere.MobileNo2,      
        uere.EmailID,      
        uere.EmailID1,      
        uere.EmailID2,      
        uere.City,      
        uere.[State],      
        uere.Country,    
        (case when isnull(uere.MobileNo,'')='' then '' else uere.CountryCode end) as CountryCode ,     
        (case when isnull(uere.MobileNo1,'')='' then '' else uere.CountryCode1 end) as CountryCode1,    
        (case when isnull(uere.MobileNo2,'')='' then '' else uere.CountryCode2 end) as CountryCode2,     
        --uere.CountryCode,      
       -- uere.CountryCode1,      
        --uere.CountryCode2,      
        uere.PinCode,      
        uere.ResidentialAddress,      
        uere.OfficeAddress,      
        uere.SourceName,      
        uere.MediumName,      
        uere.CampaignName,      
        uere.InitialRemarks,      
        uere.ParentID,      
        GETDATE()              AS CreatedDate,      
        uere.CreatedBy,      
        1  AS IsOpen INTO #TempEnq      
 FROM   UserEnquiryRawEntries  AS uere      
 WHERE  uere.IsValid = 1      
        AND uere.IsTransfered = 0   
       
  
 --------------------------  
 declare @Crno bigint = 0;  
 declare @maxno bigint = 0;  
 select @maxno = MAX(rno), @Crno = MIN(rno) from #TempEnq  
 declare @leadn1 as bigint  = 0  
 declare @ParentID bigint = 0;  
    
  declare @MobileNo nvarchar(max)  =''   
        declare @MobileNo1 nvarchar(max)  =''     
        declare @MobileNo2 nvarchar(max)  =''      
        declare @EmailID nvarchar(max)  =''      
        declare @EmailID1 nvarchar(max)  =''      
        declare @EmailID2 nvarchar(max)  =''      
         
        declare @CountryCode  nvarchar(max)  =''     
        declare @CountryCode1 nvarchar(max)  =''    
        declare @CountryCode2 nvarchar(max)  =''  
 create table #temp(leadno bigint,countrycode nchar(10),mobile varchar(100),email varchar(100))  
 declare @EnquiryID bigint  
 declare @AutoLeadDistribution bit =0  
while @Crno <= @maxno  
begin  
set @leadn1=0  
select @ParentID = ParentID, @CountryCode= CountryCode, @CountryCode1=CountryCode1,  
    @CountryCode2=CountryCode2, @MobileNo= MobileNo, @MobileNo1=MobileNo1,  
    @MobileNo2= MobileNo2,@EmailID= EmailID, @EmailID1= EmailID1,  
    @EmailID2=EmailID2  FROM   #TempEnq  WHERE  rno = @Crno      
   
insert into #temp(leadno,countrycode,mobile,email)  
select leadno,isnull(CountryCode,'0'),isnull(mobileno,'0'),'1' from UserLeads where ParentID=@ParentID  
union  
select leadno,isnull(CountryCode1,'0'),isnull(mobileno1,'0'),'1' from UserLeads where ParentID=@ParentID  
union  
select leadno,isnull(CountryCode2,'0'),isnull(mobileno2,'0'),'1' from UserLeads where ParentID=@ParentID  
union  
select leadno,'0','0',isnull(emailid,'1') from UserLeads where ParentID=@ParentID  
union  
select leadno,'0','0',isnull(emailid1,'1') from UserLeads where ParentID=@ParentID  
union  
select leadno,'0','0',isnull(emailid2,'1') from UserLeads where ParentID=@ParentID     
set @leadn1 = isnull((select top 1 t.leadno from #temp t join #TempEnq e on ((isnull(e.CountryCode,'2') + ISNULL(e.MobileNo,'2')=t.countrycode+t.mobile ) or (isnull(e.CountryCode1,'2') + ISNULL(e.MobileNo1,'2')=t.countrycode+t.mobile ) 
or (isnull(e.CountryCode2,'2') + ISNULL(e.MobileNo2,'2')=t.countrycode+t.mobile ) or (isnull(e.EmailID,'3')=t.email) or (isnull(e.EmailID1,'3')=t.email) or (isnull(e.EmailID2,'3')=t.email)) WHERE  rno = @Crno ),0)  
      
/*  create table #temp(mobile varchar(100),email varchar(100))                    
    
  insert into #temp(mobile,email)                  
  select (cast(isnull(CountryCode,0) as nvarchar)+ cast(isnull(NULLIF(MobileNo,''),0) as nvarchar)),  
  isnull(NULLIF(EmailID,''),0) from UserLeads where ParentID=@PARENTID                    
  union                     
  select (cast(isnull(CountryCode1,0) as nvarchar)+ cast(isnull(NULLIF(MobileNo1,''),0) as   
   nvarchar)),isnull(NULLIF(EmailID1,''),0) from UserLeads where ParentID=@PARENTID                  
  union                     
  select (cast(isnull(CountryCode2,0) as nvarchar)+ cast(isnull(NULLIF(MobileNo2,''),0) as   
   nvarchar)),isnull(NULLIF(EmailID2,''),0) from UserLeads where ParentID=@PARENTID                  
    
  declare @leadn as bigint  = 0  
  
    
  if exists(select 1 from UserLeads where ParentID=@ParentID and (cast(isnull(@CountryCode,1) as   
   nvarchar)+ cast(isnull(@MobileNo,1) as nvarchar) in (select Mobile from #temp)))     
  BEGIN                  
   select @leadn = leadno from UserLeads where ParentID=@ParentID and     
   (cast(isnull(@CountryCode,1) as nvarchar)+ cast(isnull(@MobileNo,1)   
   as nvarchar) in (select Mobile from #temp))    
  end  
  if (isnull(@leadn,0)=0)     
  begin                  
   if exists(select 1 from UserLeads where ParentID=@ParentID and   
    (cast(isnull(@CountryCode1,1) as   
    nvarchar)+ cast(isnull(@MobileNo1,1) as nvarchar) in (select Mobile from #temp)))    BEGIN                   select @leadn = leadno from UserLeads where ParentID=@ParentID and     
   (cast(isnull(@CountryCode1,1) as nvarchar)+ cast(isnull(@MobileNo1,1) as nvarchar) in (select   
   Mobile from #temp))                    
   END     
  end    
  if (isnull(@leadn,0)=0)     
  begin                  
   if exists(select 1 from UserLeads where ParentID=@ParentID   
   and (cast(isnull(@CountryCode2,1) as nvarchar)+ cast(isnull(@MobileNo2,1) as nvarchar)   
   in (select Mobile from #temp)))                    
   BEGIN  
                    
    select @leadn = leadno from UserLeads where ParentID=@ParentID and     
    (cast(isnull(@CountryCode2,1) as nvarchar)+ cast(isnull(@MobileNo2,1) as nvarchar)   
    in (select Mobile from #temp))                    
   END     
  end     
  if (isnull(@leadn,0)=0)     
  begin                
  if exists(select 1 from UserLeads where ParentID=@ParentID   
    and (cast(isnull(NULLIF(@EmailID,''),1) as nvarchar) in (select email from #temp)))                    
   BEGIN                  
    select @leadn = leadno from UserLeads where ParentID=@ParentID      
    and (cast(isnull(NULLIF(@EmailID,''),1) as nvarchar) in (select email from #temp))               
   END    
  end  
  if (isnull(@leadn,0)=0)     
  begin                  
  if exists(select 1 from UserLeads where ParentID=@ParentID and  
   (cast(isnull(NULLIF(@EmailID1,''),1) as nvarchar) in (select email from #temp)))                    
   BEGIN                  
    select @leadn = leadno from UserLeads where ParentID=@ParentID      
    and (cast(isnull(NULLIF(@EmailID1,''),1) as nvarchar) in (select email from #temp))                     
   END    
  end  
  if (isnull(@leadn,0)=0)     
  begin                   
  if exists(select 1 from UserLeads where ParentID=@ParentID   
   and (cast(isnull(NULLIF(@EmailID2,''),1) as nvarchar) in (select email from #temp)))             
   BEGIN                  
    select @leadn = leadno from UserLeads where ParentID=@ParentID      
    and (cast(isnull(NULLIF(@EmailID2,''),1) as nvarchar) in (select email from #temp))                  
   END      
  end*/                     
  
 INSERT INTO UserEnquiry      
   (      
     PersonName,      
     CompanyName,      
     MobileNo,      
     MobileNo1,      
     MobileNo2,      
     EmailID,      
     EmailID1,      
     EmailID2,      
     City,      
     [State],      
     Country,      
     CountryCode,      
     CountryCode1,      
     CountryCode2,      
     PinCode,      
     ResidentialAddress,      
     OfficeAddress,      
     SourceName,      
     MediumName,      
     CampaignName,      
     InitialRemarks,      
     ParentID,      
     CreatedDate,      
     CreatedBy,      
     IsOpen,  
     LeadNo     
   )      
 SELECT PersonName,      
        CompanyName,      
        MobileNo,      
        MobileNo1,      
        MobileNo2,      
        EmailID,      
        EmailID1,      
        EmailID2,      
        City,      
        [State],      
        Country,      
        CountryCode,      
        CountryCode1,      
        CountryCode2,      
        PinCode,      
        ResidentialAddress,      
        OfficeAddress,      
        SourceName,      
        MediumName,      
        CampaignName,      
        InitialRemarks,      
        ParentID,      
        CreatedDate,      
        CreatedBy,      
        IsOpen,  
        @leadn1      
 FROM   #TempEnq where rno = @Crno     
  set @EnquiryID=SCOPE_IDENTITY()     
        
seT @AutoLeadDistribution = isnull((select isnull(AutoLeadDistribution,0) FROM   CRMCampaignSettings  WHERE  UserID = @ParentID),0)  
  
if (@AutoLeadDistribution = 1 and @leadn1=0)        
  begin        
  set @Leadn1 = isnull((select MAX(LeadNo)                           
  FROM   UserLeads WHERE  ParentID = @ParentID),0)+1        
    
    
  Insert into userleads (LeadNo,PersonName,MobileNo,EmailID,City,PinCode,CountryCode,                    
  AssignedTo,SourceName,ParentID,mediumname,CampaignName,                    
  InitialRemarks,CreatedOn,CreatedBy,OfficeAddress,ResidentialAddress)                        
  select @leadn1,substring(PersonName,1,100),MobileNo,EmailID,City,PinCode,CountryCode,                    
  (select top 1 value from fn_Split((select agents from CRMCampaignSettings where userid=@ParentID),'#')    ORDER BY NEWID               
()),SourceName,ParentID,mediumname,CampaignName,InitialRemarks,GETDATE(),CreatedBy,OfficeAddress,ResidentialAddress               
from userenquiry(nolock) where enquiryid=@EnquiryID  
set @isleadcreated=1    
  /*    
  Insert into userleads (LeadNo,PersonName,MobileNo,EmailID,City,PinCode,CountryCode,        
  OfficeAddress,AssignedTo,SourceName,MediumName,CampaignName,ParentID,        
  Remarks,CreatedOn,CreatedBy)              
  select @leadn1,PersonName,MobileNo,EmailID,'','','+91',OfficeAddress,        
  (select top 1 value from fn_Split((select agents from CRMCampaignSettings where userid=@ParentID),'#')    ORDER BY NEWID   
()),SourceName,MediumName,'',@ParentID,'',GETDATE(),@ParentID   
  from #TempEnq where rno = @Crno         
  */  
end  
  
update UserEnquiry  set LeadNo=@LeadN1, 
IsOpen= case when @isleadcreated=1 then 0 else 1 end where EnquiryID=@EnquiryID   
insert into  tbl_MergeLeadsEnquiry(EnquiryNo ,LeadNo,IsOpen) 
values (@EnquiryID,@Leadn1,case when @isleadcreated=1 then 0 else 1 end)         
UPDATE UserEnquiryRawEntries      
SET    IsTransfered = 1  ,userenquiryid=@EnquiryID    
WHERE  EnquiryID IN (SELECT EnquiryID FROM   #TempEnq  where rno = @Crno)    
truncate table #temp  
set @Crno = @Crno+1  
END     
       
DROP TABLE #TempEnq      
END 


GO

/* ============================================================
   Procedure: [dbo].[usp_TransferRawEntriestoEnquiries2]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_TransferRawEntriestoEnquiries2]
@MinId bigint =null,  
@MaxId bigint=null  
AS                      
BEGIN           
declare @isleadcreated int=0    
declare @enqid bigint=(select max(enquiryid) from  UserEnquiryRawEntries(nolock) where userenquiryid is not null)             
                   
 SELECT ROW_NUMBER() over (order by uere.EnquiryID) rno,                  
  uere.EnquiryID,                      
        substring(uere.PersonName,1,100) PersonName,                      
         substring(uere.CompanyName,1,100) CompanyName,                      
        uere.MobileNo,                      
        uere.MobileNo1,                      
        uere.MobileNo2,                      
        uere.EmailID,                      
        uere.EmailID1,                      
        uere.EmailID2,                      
        substring(uere.City,1,100) City,                
        substring(uere.State,1,100) [State],                      
        substring(uere.Country,1,100) Country,                    
        (case when isnull(uere.MobileNo,'')='' then '' else uere.CountryCode end) as CountryCode ,                     
        (case when isnull(uere.MobileNo1,'')='' then '' else uere.CountryCode1 end) as CountryCode1,                    
        (case when isnull(uere.MobileNo2,'')='' then '' else uere.CountryCode2 end) as CountryCode2,                     
        --uere.CountryCode,                      
       -- uere.CountryCode1,                      
        --uere.CountryCode2,                      
        uere.PinCode,                
        substring(uere.ResidentialAddress,1,500) ResidentialAddress,                      
        substring(uere.OfficeAddress,1,500) OfficeAddress,                      
        uere.SourceName,                      
        uere.MediumName,                      
        uere.CampaignName,                      
        uere.InitialRemarks,                      
        uere.ParentID,                      
        GETDATE()              AS CreatedDate,                      
        uere.CreatedBy,                      
        1  AS IsOpen INTO #TempEnq                      
 FROM   UserEnquiryRawEntries  AS uere                      
 WHERE  uere.IsValid = 1                      
        AND uere.IsTransfered = 0      
  --and enquiryid>@enqid               
  and mail_id between @MinId and @MaxId  
                       
                  
 --------------------------                  
 declare @Crno bigint = 0;                  
 declare @maxno bigint = 0;                  
 select @maxno = MAX(rno), @Crno = MIN(rno) from #TempEnq                  
 declare @leadn1 as bigint  = 0                  
 declare @ParentID bigint = 0;                  
                    
  declare @MobileNo nvarchar(max)  =''                   
        declare @MobileNo1 nvarchar(max)  =''                     
        declare @MobileNo2 nvarchar(max)  =''                      
        declare @EmailID nvarchar(max)  =''                      
        declare @EmailID1 nvarchar(max)  =''                      
        declare @EmailID2 nvarchar(max)  =''                      
                         
        declare @CountryCode  nvarchar(max)  =''                     
        declare @CountryCode1 nvarchar(max)  =''                    
        declare @CountryCode2 nvarchar(max)  =''                  
  
--drop table if exists #temp  
  
 --create table #temp(leadno bigint,countrycode nchar(10),mobile varchar(100),email varchar(100))    
  
  
   
 declare @EnquiryID bigint,@rawEnquiryID bigint                  
 declare @AutoLeadDistribution bit =0                  
while @Crno <= @maxno                  
begin                  
 declare @temp as table (leadno bigint,countrycode nchar(10),mobile varchar(100),email varchar(100))  
  
set @leadn1=0                  
select @ParentID = ParentID, @CountryCode= CountryCode, @CountryCode1=CountryCode1,                  
    @CountryCode2=CountryCode2, @MobileNo= MobileNo, @MobileNo1=MobileNo1,                  
    @MobileNo2= MobileNo2,@EmailID= EmailID, @EmailID1= EmailID1,                  
    @EmailID2=EmailID2  FROM   #TempEnq  WHERE  rno = @Crno                      
                   
 INSERT INTO UserEnquiry                      
   (                      
     PersonName,                      
     CompanyName,                      
    MobileNo,                      
     MobileNo1,                      
     MobileNo2,                      
     EmailID,                      
     EmailID1,                      
     EmailID2,                      
     City,                      
     [State],                      
     Country,                      
  CountryCode,                      
     CountryCode1,                      
     CountryCode2,                      
     PinCode,                      
     ResidentialAddress,                      
     OfficeAddress,                      
     SourceName,                      
     MediumName,                      
     CampaignName,                      
     InitialRemarks,                      
     ParentID,                      
     CreatedDate,                      
     CreatedBy,                      
     IsOpen,                  
     enquirysource      
   )                      
 SELECT PersonName,                      
        CompanyName,                      
        MobileNo,                      
        MobileNo1,                      
        MobileNo2,                      
        EmailID,                      
        EmailID1,                      
        EmailID2,                      
        City,                      
        State,                      
        Country,                      
        CountryCode,                      
        CountryCode1,                      
        CountryCode2,                      
        PinCode,                      
        ResidentialAddress,                      
        OfficeAddress,                      
        SourceName,                      
        MediumName,                      
        CampaignName,                      
        InitialRemarks,                      
        ParentID,                      
        CreatedDate,                      
        CreatedBy,                      
        IsOpen,                  
        (select id from enquirysources(nolock) where SourceName='Mail')                      
 FROM   #TempEnq where rno = @Crno                     
  set @EnquiryID=SCOPE_IDENTITY()              
  select @rawEnquiryID= EnquiryID FROM   #TempEnq where rno = @Crno              
  
declare @leadid bigint                
  insert into parsedenquiries(rawenquiryid,enquiryid,parentid,EnquirySource)              
  select @rawenquiryid,@enquiryid,@parentid,'Mail'                    
                        
seT @AutoLeadDistribution = isnull((select isnull(AutoLeadDistribution,0) FROM   CRMCampaignSettings  WHERE  UserID = @ParentID),0)                  
      
begin try      
--begin tran      
--insert into #temp(leadno,countrycode,mobile,email)  
insert into @temp(leadno,countrycode,mobile,email)  
select leadno,countrycode,mobile,email from Userleads_Mobile_Email(nolock)  where ParentID=@ParentID                  
/*select leadno,isnull(CountryCode,'0'),isnull(mobileno,'0'),'1' from UserLeads(nolock) where ParentID=@ParentID                  
union                  
select leadno,isnull(CountryCode1,'0'),isnull(mobileno1,'0'),'1' from UserLeads(nolock) where ParentID=@ParentID                  
union                  
select leadno,isnull(CountryCode2,'0'),isnull(mobileno2,'0'),'1' from UserLeads(nolock) where ParentID=@ParentID                  
union                  
select leadno,'0','0',isnull(emailid,'1') from UserLeads(nolock) where ParentID=@ParentID                  
union                  
select leadno,'0','0',isnull(emailid1,'1') from UserLeads(nolock) where ParentID=@ParentID                  
union                  
select leadno,'0','0',isnull(emailid2,'1') from UserLeads(nolock) where ParentID=@ParentID                     
 */     
        
 set @leadn1 = isnull(        
  (select top 1 t.leadno from @temp t join #TempEnq e on        
    (        
  (isnull(dbo.fn_ltrimrtrim(e.CountryCode),'2') + ISNULL(dbo.fn_ltrimrtrim(e.MobileNo),'2')=cast(dbo.fn_ltrimrtrim(t.countrycode) as nvarchar)+cast(dbo.fn_ltrimrtrim(t.mobile) as nvarchar) )                           
     or (isnull(nullif(dbo.fn_ltrimrtrim(e.EmailID),''),'3')=dbo.fn_ltrimrtrim(t.email))       
  ) and e.rno = @Crno         
   )        
 ,0)                  
if (@AutoLeadDistribution = 1 and @leadn1=0)                        
  begin                        
    SET Context_Info 0x55555  
begin transaction     
 set @leadn1=isnull((select max(leadno) from userleads with (UPDLOCK,HOLDLOCK) where parentid=@parentid),0 )+1   
 declare @returnAgentId bigint,@LIHID bigint  
   exec udf_GetAgentToAssigned @ParentId = @ParentID, @AgentId = @returnAgentId output   --select @returnAgentId    
   
  If not exists(Select * from MySMS.dbo.UserLeads(nolock) UL inner join (select EmailID=isnull(nullif(EmailID,''),'e1'),EmailID1=isnull(nullif(EmailID1,''),'e2'),EmailId2=isnull(nullif(EmailId2,''),'e3'),MobileNo=isnull(nullif(MobileNo,''),'m1'),MobileNo1=isnull(nullif(MobileNo1,''),'m2'),MobileNo2=isnull(nullif(MobileNo2,''),'m3'),ParentID From mysms.dbo.userenquiry(nolock) Where EnquiryId=@EnquiryID) UE on UL.ParentID=UE.ParentID and (UL.EmailID in (UE.EmailID,UE.EmailID1,UE.EmailID2) or UL.EmailID1 in (UE.EmailID,UE.EmailID1,UE.EmailID2) or UL.EmailID2 in (UE.EmailID,UE.EmailID1,UE.EmailID2) or UL.MobileNo in (UE.MobileNo,UE.MobileNo1,UE.MobileNo2) or UL.MobileNo1 in (UE.MobileNo,UE.MobileNo1,UE.MobileNo2) or UL.MobileNo2 in (UE.MobileNo,UE.MobileNo1,UE.MobileNo2)))
	Begin
  
	Insert into userleads (LeadNo,PersonName,MobileNo,EmailID,City,PinCode,CountryCode,                          
	  AssignedTo,SourceName,ParentID,mediumname,CampaignName,                          
	  InitialRemarks,CreatedOn,CreatedBy,OfficeAddress,ResidentialAddress,enquirysource,companyName,Remarks)           
	  select @leadn1,substring(PersonName,1,100),MobileNo,EmailID,City,PinCode,CountryCode,                          
	  (select top 1 value from fn_Split((select agents from CRMCampaignSettings where userid=@ParentID),'#')    ORDER BY NEWID                     
	()),SourceName,ParentID,mediumname,CampaignName,InitialRemarks,GETDATE(),CreatedBy,OfficeAddress,ResidentialAddress,enquirysource,companyName,InitialRemarks                     
	from userenquiry(nolock) where enquiryid=@EnquiryID  
	select @leadid=SCOPE_IDENTITY()  
  
	set @Leadn1 = isnull((select LeadNo  FROM   UserLeads(nolock) WHERE id = @leadID),0)
	
	end

  commit  
  
Exec MySMS.dbo.usp_ExecLeadTriggerTasks @leadid  
     
  set @isleadcreated   =1      
  
  insert into LeadInteractionHistory(LeadNo,FollowUpStatus,NextStatusDate,Remarks,Products,AmountPaid,AssignedTo,      
  ParentID,CreatedOn,CreatedBy,FollowupDate,IsReassign,id_lead)      
  select LeadNo,FollowUpStatus,NextStatusDate,Remarks,Products,AmountPaid,AssignedTo,      
  ParentID,CreatedOn,CreatedBy,FollowupDate,0,id from userleads u (nolock) where ID = @leadid  
    
  select @LIHID=SCOPE_IDENTITY()  
  Exec MySMS.dbo.usp_ExecLeadInteractionTriggerTasks @LIHID  
  
  --exec Usp_insertdefaultfollowup @parentid,@leadid  
   SET Context_Info 0x                     
end              
end try      
begin catch      
exec usp_InsertErrorInfo      
end catch      
            
update UserEnquiry  set LeadNo=case when @LeadN1<>0 then @leadn1 else null end,     
IsOpen= case when @isleadcreated=1 then 0 else 1 end where EnquiryID=@EnquiryID                   
if not exists(select 1 from tbl_MergeLeadsEnquiry(nolock) where enquiryno=@enquiryid and LeadNo=@leadn1)      
begin       
insert into  tbl_MergeLeadsEnquiry(EnquiryNo ,LeadNo,IsOpen)     
values (@EnquiryID,@Leadn1,case when @isleadcreated=1 then 0 else 1 end)                         
end      
UPDATE UserEnquiryRawEntries                      
SET    IsTransfered = 1  ,userenquiryid=@EnquiryID                    
WHERE  EnquiryID = (SELECT EnquiryID FROM   #TempEnq  where rno = @Crno)                            
                
--truncate table #temp     
  
set @Crno = @Crno+1                  
END                     
                       
DROP TABLE #TempEnq                      
END



GO

/* ============================================================
   Procedure: [dbo].[Usp_TrasferEMailReportFromKit19ToCRM]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE dbo.Usp_TrasferEMailReportFromKit19ToCRM
as
Begin

    CREATE TABLE #TempLinked                                  
    (                                  
      Result VARCHAR(200)                                  
    )   


	 INSERT INTO #TempLinked                                  
     EXEC GetStatusofLinkedServer 'CRM'                                  
     IF NOT EXISTS(                                  
        SELECT 'x'                                  
        FROM   #TempLinked                                  
    )
    Begin
	 
	  select
	   [SentMail_ID]
      ,[Mail_GUID]
      ,[Mail_ID]
      ,[Mail_FromEmail]
      ,[Mail_ToEmail]
      ,[Mail_Attechement]
      ,[Mail_TempleteName]
      ,[Mail_InsertedDate]
      ,[Mail_UserID]
      ,[Mail_Subject]
      ,[Mail_Priority]
      ,[Messages]
      ,[Mail_ScheduleDate]
      ,[Mail_DeliveredDate]
      ,[Mail_BatchID]
      ,[Mail_IsSent]
      ,[ReplyTo]
      ,[Mail_TempleteBody]
      ,[Mail_Invalid]
      ,[Mail_Error]
      ,[IsCRMEntry] into #temp  From MYSMS.dbo.[Mail_CRM_Emails_Report] where IsCRMEntry = 0 
	  


	insert into CRM.CRMDB.dbo.Mail_CRM_Emails_Report
	 (
	   [Mail_GUID]
      ,[Mail_ID]
      ,[Mail_FromEmail]
      ,[Mail_ToEmail]
      ,[Mail_Attechement]
      ,[Mail_TempleteName]
      ,[Mail_InsertedDate]
      ,[Mail_UserID]
      ,[Mail_Subject]
      ,[Mail_Priority]
      ,[Messages]
      ,[Mail_ScheduleDate]
      ,[Mail_DeliveredDate]
      ,[Mail_BatchID]
      ,[Mail_IsSent]
      ,[ReplyTo]
      ,[Mail_TempleteBody]
      ,[Mail_Invalid]
      ,[Mail_Error]
	  
	  )
	  select
	  [Mail_GUID]
      ,[Mail_ID]
      ,[Mail_FromEmail]
      ,[Mail_ToEmail]
      ,[Mail_Attechement]
      ,[Mail_TempleteName]
      ,[Mail_InsertedDate]
      ,[Mail_UserID]
      ,[Mail_Subject]
      ,[Mail_Priority]
      ,[Messages]
      ,[Mail_ScheduleDate]
      ,[Mail_DeliveredDate]
      ,[Mail_BatchID]
      ,[Mail_IsSent]
      ,[ReplyTo]
      ,[Mail_TempleteBody]
      ,[Mail_Invalid]
      ,[Mail_Error] From MYSMS.dbo.[Mail_CRM_Emails_Report]  where IsCRMEntry = 0

	  update m set IsCRMEntry = 1 from MYSMS.dbo.[Mail_CRM_Emails_Report] m join #temp t on t.mail_id=m.Mail_ID where m.IsCRMEntry = 0


	  drop table #temp

	End
 
	drop table #TempLinked;  

End


GO

/* ============================================================
   Procedure: [dbo].[usp_truncatetable]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------

---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------


CREATE   PROC dbo.[usp_truncatetable]  --12511,2   
           @batchid      BIGINT, 
           @ProcessTable INT 
AS 
  BEGIN
	set nocount on  
    DECLARE  @countrow BIGINT 
     
    IF (@ProcessTable = 1) 
      BEGIN 
        TRUNCATE TABLE processtablefirst 
         
        SET @countrow = @@ROWCOUNT 
         
        EXEC Usp_inserbatchtrachrecord 
          @batchid , 
          1 , 
          'USP_TruncateTable' , 
          1 , 
          'ProcessTableFirst' , 
          '' , 
          'TruncateTable' , 
          @countrow 
      END 
    ELSE 
      IF (@ProcessTable = 2) 
        BEGIN 
          TRUNCATE TABLE processtabletwo 
           
          SET @countrow = @@ROWCOUNT 
           
          EXEC Usp_inserbatchtrachrecord 
            @batchid , 
            1 , 
            'USP_TruncateTable' , 
            1 , 
            'ProcessTableTwo' , 
            '' , 
            'TruncateTable' , 
            @countrow 
        END 
      ELSE 
        IF (@ProcessTable = 3) 
          BEGIN 
            TRUNCATE TABLE processtablethree 
             
            SET @countrow = @@ROWCOUNT 
             
            EXEC Usp_inserbatchtrachrecord 
              @batchid , 
              1 , 
              'USP_TruncateTable' , 
              1 , 
              'ProcessTableThree' , 
              '' , 
              'TruncateTable' , 
              @countrow 
          END 
        ELSE 
          IF (@ProcessTable = 4) 
            BEGIN 
              TRUNCATE TABLE processtablefour 
               
              SET @countrow = @@ROWCOUNT 
               
              EXEC Usp_inserbatchtrachrecord 
                @batchid , 
                1 , 
                'USP_TruncateTable' , 
                1 , 
                'ProcessTableFour' , 
                '' , 
                'TruncateTable' , 
                @countrow 
            END 
  END 






GO

