   Procedure: [dbo].[USP_TRUNCATETABLEajay]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

 /****************************************************************************                                  
SP_NAME        : USP_TRUNCATETABLE                                                     
AUTHOR         : AJAY SINGH                                  
CREATED ON     : 30/06/2012 04:30 PM                                                      
LOCATION       :                                    
SP DESCRIPTION : THIS SP IS USED TO drop table                                                
****************************************************************************/    
 CREATE   PROCEDURE USP_TRUNCATETABLEajay --'dnddirectory'  
 @tablename nvarchar(20)  
  as   
 begin  
   declare @query varchar(50)  
   
  set @query='';  
 set  @query ='drop TABLE '+ @tablename+''  
 if(@tablename ='DndDirectory')  
 begin  
 select 'No Record Deleted'  
 end  
 else  
 begin  
 exec(@query)  
 select 'Record Deleted'  
 end  
   
  end 


GO

/* ============================================================
   Procedure: [dbo].[usp_ts_CheckTagIsExists]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ts_CheckTagIsExists](
	@Tags nvarchar(max),
	@UserId bigint
)
as
begin
	-- declare @Tags nvarchar(max) = 'rakesh, hark, sdiwf, dfiwfe, wfwiefowef, abcd, fwfwiefwofkwf, wfwifwfewkefw, fewfeiwofewfw, wfwof'
	drop table if exists #tempTagToInsert
	select *, 0 as [IsExists]  into #tempTagToInsert from fn_Split(@Tags, ',')

	update ti set ti.[IsExists] = 1 from #tempTagToInsert ti 
		inner join TagMaster(nolock) tag on lower(trim(tag.Tag)) = lower(trim(ti.value)) 
		and tag.ParentID = (select top 1 ParentID from User_Detail(nolock) where User_ID = @UserId)

	select * from #tempTagToInsert

end



GO

/* ============================================================
   Procedure: [dbo].[usp_ts_SaveTagsFromTagMaster]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ts_SaveTagsFromTagMaster](
	@Tags nvarchar(max),
	@UserId bigint
)
as
begin
	declare @ParentId bigint = (select top 1 ParentID from User_Detail(nolock) where User_ID = @UserId)

	insert into TagMaster( Tag, ParentID, CreatedDate, CreatedBy, IsActive )
		select trim([value]), @ParentId, getdate(), @UserId, 1  from fn_Split(@Tags, ',')

end



GO

/* ============================================================
   Procedure: [dbo].[usp_ts_UpdateTagStatusById]
   ============================================================ */

SET ANSI_NULLS ON
SET QUOTED_IDENTIFIER ON

CREATE   PROCEDURE [dbo].[usp_ts_UpdateTagStatusById](
	@TagId bigint,
	@Status bit
)
as
begin
	update TagMaster set IsActive = @Status where ID = @TagId
end



GO


